    [14090489] = "Kẻ Nghiền Vương Miện",
    [14305855] = "Chạm",
    [14328937] = "Sức Bền Của Ngọn Lửa",
    [14510634] = "Áo Thuật Sĩ Hắc Ám",
    [14817893] = "Chúng ta đã thề sẽ bảo vệ Nữ hoàng và vùng đất của người, và không bao giờ để dòng máu hoàng gia phải đổ xuống. Ngay cả bây giờ, khi người không còn trị vì nữa, lời thề đó vẫn ràng buộc chúng ta.\n\nKhông ngạc nhiên khi không nhiều người trong chúng ta sẵn lòng làm đổ máu của Vorgoth, điều đó sẽ khiến chúng ta mất đi tước hiệu. Họ gọi chúng ta là những kẻ phản kháng vì chúng ta từ chối làm ngơ. Họ nói rằng vung kiếm chống lại dòng máu hoàng gia là cái chết của danh dự, nhưng có danh dự nào trong sự thờ ơ.\n\nHòn đảo đã đày ải chúng ta. Tu viện của nó sẽ không bao giờ mở cửa đón chúng ta một lần nữa, nhưng chúng ta sẽ không im lặng. Chúng ta sẽ không cúi đầu. Chúng ta sẽ bảo vệ những gì mình tin tưởng cho đến giây phút cuối cùng.\n\nVì Nữ hoàng mà chúng ta đã thề trung thành. Vì vương quốc mà người hằng yêu dấu.",
    [14982129] = "Bí Ẩn Đập Eldermere",
    [14986493] = "Màu Tóc Và Vấn Đề Trí Nhớ",
    [15009260] = "Vây Lấp Lánh",
    [15404528] = "Dao Găm Nữ Tước",
    [15653583] = "Ốc Đảo",
    [16425529] = "Ta không thể đứng ngoài này mà không có mái che trên đầu được! Giúp ta xây một cửa hàng đi, được chứ?",
    [16594266] = "San Phẳng Mặt Đất L",
    [16743141] = "Áo Giáp Kẻ Phá Phép",
    [17043627] = "Bạn đã đến khu đất cũ từng thuộc về gia đình Reed. \n\nLook around and search for valuables!",
    [17166390] = "Một vòng xoáy năng lượng rạng rỡ cần thiết để khảm ngọc vào vũ khí. \n\nBan đầu được sử dụng bởi các Cổ Nhân, nó đã bị phe Fell chiếm lấy để nuôi dưỡng bầy đàn của chúng cho đến khi bạn giải phóng nó khỏi nhà tù hữu cơ mới. \n\nBiến thể này có thể được tìm thấy ở Springlands.",
    [17289158] = "ST Đánh lén",
    [18022687] = "Phụ Kiện",
    [18299655] = "Giày Hắc Vệ",
    [18413736] = "Một loại gel bảo vệ, trọng lượng nhẹ. Mang đặc tính ma thuật của phe Fell.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ các Nữ Thần Báo Tử Fell, ban đầu được tìm thấy ở Springlands.",
    [19089800] = "Một không gian lưu trữ lớn hơn cho các vật phẩm số lượng lớn.\n\nCác vật phẩm được cất giữ ở đây có thể được sử dụng để chế tạo từ bất kỳ đâu trong căn cứ!",
    [19146867] = "Một nhạc cụ gõ đơn giản dùng để chơi nhạc. Những tiếng chuông nhỏ tạo thêm điểm nhấn thú vị cho bất kỳ bài hát nào.",
    [19313599] = "Mặt trời đã thiêu rụi những chiếc lá. Những gì lẽ ra là trái cây và ngũ cốc của năm ngoái thì nay chỉ còn là tro bụi. Ta là người duy nhất còn có thể canh tác trên mảnh đất này (dù cũng chẳng được bao nhiêu). Ta đã cho đi những khẩu phần cuối cùng, nướng những ổ bánh mì cuối cùng. Không còn nước để nấu súp, hay bia để phục vụ. Không còn khách hàng, chỉ còn những người khốn khổ... bị mù lòa và phồng rộp bởi ánh mặt trời.\n\nLiệu đợt hạn hán này có thực sự là lời nguyền của Cổ Nhân...? Có phải chúng ta đã làm họ thất vọng...? Làm họ tức giận...? Ta không thể để đức tin của mình lung lay... Đó là tất cả những gì ta còn lại. \n— Emily Fray",
    [19336545] = "Một người bạn đồng hành nhỏ bé soi sáng con đường của bạn.",
    [19344817] = "ST Định hướng",
    [19727963] = "Chẳng Bao Giờ Trọn Vẹn",
    [20501193] = "Tiền Đồn Vukah",
    [20522164] = "Quy Tắc Tiền Đồn Thương Mại",
    [20641038] = "Bạn đã đến <location>Sapphire Strand</location>. Bây giờ hãy tìm con mèo và thuần hóa nó để tiếp tục!",
    [21056021] = "Embervale đã thay đổi. Trước thời đại của chúng ta, tộc Cổ Nhân đã xây dựng những ngọn tháp để quan sát vùng đất này... Các Tòa Tháp Cổ Nhân. Có một tòa tháp ở gần đây. Hãy leo lên đó và khám phá thế giới một lần nữa!",
    [21977973] = "Đến Lăng Mộ Rùng Rợn",
    [22135498] = "Nhẫn Ấn Của Vệ Binh Trưởng Lão",
    [22190145] = "Cảm ơn vì đã lấy những <craftingstation>Dụng Cụ Nề</craftingstation> đó cho ta, nhà vô địch! Giờ thì bắt tay vào chế tạo thôi!",
    [22334906] = "Tiếp tục",
    [23349135] = "<lorename>Jezmina</lorename>",
    [23411742] = "Đũa Phép Băng Điện",
    [23706651] = "Cánh tay",
    [23836599] = "Một cây búa lớn và đầy uy lực đã bị tha hóa bởi Sương độc. Rất tốt để đập tan lũ bọ!",
    [24090297] = "Cào Cỏ",
    [24788801] = "<location>Willow Crush</location>",
    [25413375] = "Bàn Đầu Giường Gỗ Cọ",
    [25505185] = "Sắc xanh xám kết hợp với màu hồng bụi.\n\nBảng màu này có thể được tạo ra bằng các vật liệu từ Springlands.",
    [25516000] = "Quần Bóng Của Núi",
    [25997470] = "Giày Pháp Sư Băng Mưa",
    [26452003] = "Cửa Hầm Mộ Lớn",
    [27227473] = "Những bụi cây thấp của Revelwood ẩn chứa sự điên rồ bên trong. Cái nôi của Tiên dược, cội rễ của sự thối nát — hạt giống của sự loạn trí. Một mê cung của bệnh tật và hỗn loạn, nằm sâu trong trái tim của lùm cây.",
    [27997557] = "Da Bò Sát",
    [28157340] = "Khi bạn tiêu diệt kẻ thù bằng vũ khí ma thuật, mọi tiêu tốn MP sẽ được bỏ qua trong 10 giây.",
    [28891729] = "Chất lượng DLSS",
    [29105538] = "Màu hiện tại",
    [29109414] = "Bạn đã lấy được ống thổi từ bên trong lò rèn! Chúng có thể được dùng để chế tạo lò luyện kim.\n\nHãy quay trở lại căn cứ và <b>chế tạo lò luyện kim bằng ống thổi</b> để tiếp tục!",
    [29187602] = "Hỏa Nhân! Ngươi có tia sáng đó... chúng ta có chung niềm đam mê, đúng chứ? Kiến trúc! Nghệ thuật! Đào mộ! Ờ, ý ta là <i>bảo tồn vẻ đẹp bị lãng quên!</i> Có tin đồn rằng Nữ hoàng của chúng ta đã được chôn cất, dù không ai biết ở đâu, cùng với những món đồ cổ quái của bà ấy. Giờ bà ấy chẳng cần đến chúng nữa đâu. Bà ấy chết rồi! Ha! Vậy nên, tại sao không đi khám phá nhỉ?",
    [29735264] = "Lò Nung",
    [29930757] = "<location>Pondsworth</location>",
    [30168743] = "Emily Fray",
    [30587450] = "Đổ bóng môi trường (SSAO) quyết định xem các vật thể có đổ bóng phụ hay không, giúp tăng chất lượng bóng đổ tổng thể. Tắt SSAO sẽ tăng hiệu suất.",
    [30691177] = "Đũa Phép Drak Gần Đây",
    [30712108] = "Nhiệt Độ Cơ Thể",
    [30857235] = "<location>Diadwyn</location>",
    [31082611] = "Cúp Danh Năng Rồng Con Sa Ngã Bằng Sắt",
    [31108081] = "Tủ Ly Gỗ Cọ Lớn",
    [31294973] = "Một loại kẹo thay thế ngọt ngào làm từ sợi thực vật. Cơn sốt đường này được biết đến là giúp hồi phục SP trong một thời gian ngắn.",
    [31525374] = "Linh Hồn Dân Làng Thất Lạc",
    [31762014] = "Ngươi vẫn chưa nhận ra sức mạnh của Ngọn Lửa bên trong mình. Nó kết nối ngươi với mạng lưới các Ngọn Lửa và cho phép ngươi xuất hiện tại các Tháp Cổ hoặc Đàn Tế Lửa trong chớp mắt. Hãy du hành đến Tháp Cổ này bằng cách mở bản đồ và chọn vị trí của nó.",
    [32152275] = "Tạo trò chơi công khai",
    [32227651] = "Gừng Ngào Đường",
    [32246916] = "Ếch",
    [32748615] = "Tìm kiếm theo IPv4 / Tên miền",
    [32785939] = "Đồn Trú Lửa Tai Ương \"Sương Tơ\"",
    [33102618] = "Thảm Rơm Phủ Lông Lớn",
    [33404240] = "Một chiến tích quý giá của loài Drak, dễ nhận biết bởi số lượng lớn lông vũ trang trí trên đó. Có lẽ là vật kỷ niệm của một trận chiến huyền thoại, hoặc một cuộc thảm sát tàn bạo.",
    [33442514] = "Một nguyên liệu phổ biến với kết cấu mịn màng. Cần thiết cho mọi loại thiết bị chiếu sáng.",
    [33986307] = "Ôi, người bạn được Ngọn lửa chạm đến. Ta rất thích sự đồng hành của ngươi, nhưng đôi khi, ngày tháng của ta thật cô đơn... ngươi sẽ mang đến cho ta một người bạn nhỏ chứ?",
    [34995204] = "Nó được coi là một trong những vật liệu nguy hiểm nhất thế giới! Chạm trực tiếp vào nó thường không phải là một ý hay.",
    [36082878] = "Bạn không sở hữu trò chơi này trên Steam!",
    [36652888] = "Khi có từ ba kẻ địch trở lên trong vòng <b>20</b> mét, ngươi sẽ nhận ít hơn <b>10%</b> sát thương vật lý.",
    [37574446] = "Những đỉnh núi thật khắc nghiệt. Ngươi phải chuẩn bị sẵn sàng chống lại cái lạnh nếu muốn mạo hiểm đi xa. Ngươi có thể chế tạo một số bộ giáp ấm hơn với bộ lót giữ nhiệt, nhưng một bụng đầy súp thịt cũng có thể giải quyết vấn đề. Nếu mọi cách khác đều thất bại, một ngọn đuốc cũng có thể cung cấp hơi ấm. Lửa là bạn của ngươi. Càng sử dụng nhiều lựa chọn, kết quả càng tốt.",
    [38274832] = "Pháo Sáng Dính",
    [38304538] = "Đá Vụn Vùng Đất Mùa Xuân",
    [38335068] = "Chà, để quay lại sự nghiệp âm nhạc, ta sẽ cần nhiều hơn là cảm hứng! Thật đáng buồn, ta đã bỏ rơi cây đàn lute cũ của mình từ lâu rồi. Đừng lo lắng, ta không muốn lấy lại nó đâu! Tâm hồn ta cần thứ gì đó mới mẻ và tươi tắn — một chiếc handpan huyền thoại sẽ hiệu quả đấy! Một vật phẩm hiếm có như vậy chỉ có thể được giấu bên trong đền thờ Drak! Ta đã nghe thấy những giai điệu ám ảnh của chúng từ sâu trong bụi rậm!",
    [38357681] = "Sống Sót Trở Về",
    [38397774] = "Hồ Huyết Tâm",
    [38427590] = "Trăng Non",
    [38576393] = "Chuyên Hóa Hạng Nặng",
    [38587212] = "Đêm nay ta đã đầu hàng trước sự nghi ngờ của mình và lẻn lên tàu. Những tên lính đã quay lưng lại, nhìn chằm chằm vào khoảng không, dán mắt vào một điểm ngoài đường chân trời... bất động. Đó là thời điểm hoàn hảo để hành động.\n\nMột quản đốc bến cảng nên biết những gì đi qua bến cảng của mình, bất kể nó mang con dấu của ai, ta nói vậy đấy! Vì vậy, ta đã lẻn vào khoang chứa hàng, cẩn thận không để nắp lưới sắt trượt khỏi đôi bàn tay run rẩy của mình. Không khí bên dưới bốc mùi thối rữa. <i>Bị nhiễm bệnh</i>. Có thể là lũ chuột, hay một kẻ đi lậu vé đã chết nào đó? Ta che mũi và miệng bằng một chiếc khăn tay rồi tiến tới, đi về phía sau khoang chứa nơi các thùng hàng được xếp chồng lên nhau.\n\nKhi đến đó, ta đã phá vỡ con dấu của một thùng và lùi lại trước cảnh tượng hiện ra trước mắt.\nCác thùng không chứa đầy ngũ cốc hay bột, mà là một loại sương mù gây ngạt — bị phong ấn bên trong như một sinh vật sống, ép vào vách ngăn, nổi loạn. Không có dấu hiệu, không có cảnh báo. Chỉ là một làn sương mù nhợt nhạt đang mưng mủ trên một lớp thịt nấm hôi thối.\n\nLiệu Lãnh chúa có đang tìm cách gieo rắc bệnh tật đến những bờ biển xa xôi? Những con tàu của ta nên vận chuyển thực phẩm và quần áo, chứ không phải một hình thức chiến tranh mới tàn độc hơn cả sắt thép! \nNgày mai ta sẽ từ chức... cầu mong kẻ khốn khổ tiếp theo sẽ chứng kiến những gì sắp xảy ra.",
    [38690511] = "Chúc ngươi nhiều may mắn và thịnh vượng.",
    [39281390] = "Việc tiếp xúc liên tục với độc tố đã làm máu của ngươi đặc lại, khiến ngươi suy yếu đáng kể.\n\nNgươi nên <b>hỏi Nhà Giả Kim</b> về phương thuốc để đảm bảo căn bệnh mới này không ảnh hưởng lâu dài đến sức sống của ngươi.",
    [39341559] = "Cửa Cẩm Thạch Đỏ Bí Mật",
    [40033398] = "Ta có thể giúp ích rất nhiều cho ngươi nếu có một căn phòng — một chiếc giường, một nơi trú ẩn — để ta thực hiện nghệ thuật của mình. Có lẽ ngươi có thể xây cho ta một vài thứ?",
    [40562649] = "Đầu Đấu Sĩ Vukah",
    [40681746] = "Nếu bất kỳ kẻ nào dám cận chiến với ngươi, chúng sẽ được nếm mùi những tấm đệm vai gai góc đang quất mạnh của ngươi. Sự phòng thủ của ngươi sẽ là bất khả xâm phạm, và những vết cắt ngươi để lại sẽ rất sâu.",
    [40742788] = "Trò Chuyện Với Ai Đó Về Sự Sống Và Sự Đổi Mới",
    [40893632] = "Một cây chùy với thân phân đoạn, gợi nhớ đến một cột vật tổ vươn tới bầu trời. Phần đầu được tăng cường bằng một vương miện đá tỏa sáng ra bên ngoài.",
    [41382545] = "Bạn đã tìm thấy một chiếc nhẫn đẹp sau khi đánh bại một Fell Banshee. Có biểu tượng Song Tử ở bên trong.",
    [41583915] = "Mồi Thức Ăn Bò Tây Tạng",
    [42107287] = "Ta Phải Ghi Nhớ Điều Này",
    [42146829] = "Khối Xây Giếng",
    [42157784] = "Một lựa chọn lưu trữ cải tiến với dung lượng được nâng cao.\n\nCác vật phẩm được lưu trữ ở đây có thể được sử dụng để chế tạo từ bất kỳ đâu trong căn cứ!",
    [42238902] = "Sự Thoải Mái",
    [42280920] = "Kho chứa cho 8 vật phẩm.",
    [42455446] = "Vũ khí và áo giáp có thể có độ hiếm khác nhau. Vũ khí có độ hiếm cao hơn có thể được <b>phân rã</b> trong túi đồ để nhận Cổ Tự. Cổ Tự có thể được sử dụng để <b>cường hóa vũ khí với các đặc tính</b> tại <npc>Thợ Rèn</npc>.\n\nTrang bị tìm thấy bên dưới Sương độc cực kỳ hiếm và mạnh mẽ.",
    [42845275] = "Chìa Khóa Sảnh Hollow Lưu Vực Veilwater",
    [43878477] = "Nhạc Cụ Sử Thi",
    [44095029] = "Có lẽ việc triển khai gây bối rối và bất thường như vậy cho cái <b>nút</b> của ta gây ra nhiều vấn đề hơn dự kiến. Ta đã nghĩ việc khóa <b>cửa phòng thí nghiệm</b> của mình theo cách này sẽ hữu ích, nhưng cơn đau lưng của ta lại nói điều ngược lại. \n\nMuội than làm bẩn lông vũ của ta, và cột sống của ta đau nhức. Đây là một trong những ý tưởng tồi tệ nhất của ta.",
    [44117685] = "Khói Nơi Đường Chân Trời",
    [44194536] = "Đổi Mới. Làm Tươi. Khởi Đầu Lại.",
    [45025732] = "Ta cần một xưởng rèn tử tế — chỉ khi đó ta mới có thể chế tạo trang bị phù hợp cho hành trình của ngươi! Đừng lo lắng, không khó để <b>xây dựng một cái</b> đâu. Ngươi sẽ cần một <b><craftingstation>Bàn Chế Tác</craftingstation></b>, một số <b>khối xây dựng</b> và một <b>Búa Xây Dựng</b>. Hãy bắt tay vào việc nào!",
    [45354812] = "Giờ Dùng Búa",
    [45786436] = "Rơi ra từ kẻ địch ở Revelwood",
    [46542607] = "Găng tay nặng, thường được mang bởi những ngón tay gầy guộc hoặc thối rữa lạnh như băng.",
    [46762466] = "Khung Cửa Sổ Chạm Khắc Tròn Lớn",
    [46957208] = "Xóa",
    [47119879] = "Định vị",
    [47254149] = "Quăng dây câu và đợi cá cắn câu. Khi cá đã cắn, hãy nhấn nhanh <b>%k</b> để bắt đầu kéo vào.\n\nKhi bạn đã có cá trên lưỡi câu, bạn cần làm giảm SP của cá bằng cách điều khiển ngược lại chuyển động của nó bằng <b>%k</b> và <b>%k</b>. \nKhi một phần SP của nó cạn kiệt, bạn có thể kéo cá lại gần hơn bằng <b>%k</b>.\nHãy làm cạn kiệt SP của nó trước khi dây câu của bạn bị đứt!",
    [47433040] = "Sau khi đánh bại một kẻ địch <b>Fell</b> bằng một <b>Cú Bắn Kỹ Năng</b>, nhóm của bạn sẽ nhận thêm <b>5</b> Điểm Kinh Nghiệm.\n\n<b>Cú Bắn Kỹ Năng</b>\nTấn công vào các điểm yếu của kẻ địch, chẳng hạn như đầu hoặc tim bị lộ ra, được coi là một Cú Bắn Kỹ Năng.",
    [48035228] = "Cho Thợ Cắt Tóc Xem Một Bông Calla Luna",
    [48459330] = "Sự Hỗn Loạn Trên Hết",
    [48765980] = "Một loài chân bụng cô độc, ngồi yên bình trên một tảng đá. Hậu duệ của biến thể này vẫn cư ngụ ở bờ biển Embervale cho đến gần đây. Vỏ đầy màu sắc và chất nhầy trơn trượt của chúng đã được nghiền nát thành sắc tố óng ánh dùng để nhuộm vải.\n\nVật phẩm thu thập này được tìm thấy ở Revelwood.",
    [48836331] = "Nhặt",
    [48930488] = "Quần Đỡ Đòn",
    [49360864] = "Nhảy Đánh",
    [49627827] = "Làm yếu hiệu ứng của các trạng thái bất lợi <b>Ẩm Ướt</b> và <b>Sũng Nước</b>.\n\nSP và Hồi phục SP bị giảm <b>10%</b> thay vì <b>20%</b>.\n\n<b>Ẩm Ướt</b> \nGiảm SP và Hồi phục SP đi <b>30%</b> trong <b>15</b> phút. Hơi ấm làm giảm thời gian còn lại.\n\n<b>Sũng Nước</b> \nGiảm SP và Hồi phục SP đi <b>30%</b> trong <b>30</b> giây. Đồng thời giảm <b>Kháng Băng và Kháng Sốc</b> đi <b>30%</b> nhưng tăng <b>Kháng Hỏa</b> thêm <b>30%</b>.\n<b>Sũng Nước</b> có thể áp dụng lên kẻ địch.\nThời gian <b>Sũng Nước</b> không thể bị giảm bởi hơi ấm, và sẽ chuyển sang trạng thái bất lợi <b>Ẩm Ướt</b> sau khi kết thúc.",
    [50172651] = "Bướm Đêm",
    [50209482] = "Được rồi các cậu, chuyện này không vui đâu",
    [50230909] = "Tủ Gỗ Chạm Khắc Lớn",
    [51628914] = "Trò Đùa Nghịch Của Anh Em",
    [51648239] = "Một mũi tên được tăng cường bằng các mảnh Xương Hóa Thạch. Đẹp một cách nổi bật và chết chóc.",
    [51792468] = "Trò Chuyện Với Ai Đó Về Sự Đố Kỵ Và Sự Bất Tử",
    [51803488] = "Một chiếc áo trông rất thể thao làm từ vải rực rỡ, được giữ lại bằng các dây da. Kiểu cắt ngắn cho phép bạn khoe vóc dáng của mình!",
    [52286582] = "Tìm Chiếc Handpan Huyền Thoại",
    [52503126] = "Chúng tôi tự hào thông báo rằng chúng tôi sẽ tổ chức lại cuộc thi lượn hàng năm! \n\nNhư lần trước, mục tiêu là <b>nhảy khỏi bục gỗ lớn bên ngoài khu nhà ngủ</b> và lượn theo một đường cong nhẹ về phía bục hạ cánh ở <b>phía bên phải.</b>\nĐừng bỏ lỡ những <b>luồng khí bốc lên</b>, nếu không bạn sẽ không tới được bục đâu! Người lượn giỏi nhất sẽ nhận được phần thưởng vào cuối cuộc thi!\nNếu bạn sẵn sàng chấp nhận thử thách, hãy viết tên mình xuống dưới! \n\n<i>Kip Dipper \nRyan the Ragged \n\"Lucky\" Chester Loft\nAbraham Walz</i>",
    [52545612] = "Đánh bại một kẻ địch vào ban đêm có %k cơ hội tạo ra Quả cầu Mặt trăng. Thu thập Quả cầu Mặt trăng sẽ cho bạn %k Máu và %k MP cũng như một hiệu ứng thức ăn đặc biệt cho bạn %k Máu tối đa, %k MP tối đa, %k SP tối đa và %k ST Cận chiến trong %k.",
    [53065508] = "Nguồn nước đã cạn kiệt",
    [53189724] = "Tượng Đầm Lầy Đen V",
    [53345828] = "Nông Dân",
    [53720510] = "Một khối gỗ làm từ những cái cây đã chết từ lâu. Chúng cực kỳ phổ biến ở các khu vực có Sương độc.",
    [53765574] = "Mở Cánh Cửa Đêm Và Khám Phá Thánh Đường",
    [53889903] = "Thiết lập chất lượng Mô phỏng Nước. Giảm chất lượng sẽ cải thiện hiệu suất.",
    [54744677] = "Ẩn nhện",
    [54913227] = "Một chiếc áo chẽn kim loại thắt dây tạo ra một khung lồng kiểu váy phồng. Ngươi đừng để những xiềng xích này đánh lừa. <i>Không xiềng xích nào, và không dòng máu nào có thể kìm hãm cơn thịnh nộ của Hoa Hồng Máu.</i>",
    [55305867] = "Sườn nướng từng là một món cao lương mỹ vị vào thời đó, cung cấp một lượng HP đáng kể cho người ăn.",
    [55982399] = "Pháo Sáng",
    [56015203] = "Sảnh Hollow",
    [56679678] = "Áo Khoác Nhà Thám Hiểm",
    [56921174] = "Một vài Khối Xây Giếng đã được tìm thấy bên trong Giếng Tiên Dược. <npc>Thợ Mộc</npc> chắc hẳn sẽ hài lòng.",
    [57037487] = "Nhóm Săn Bắn",
    [57273970] = "Xây dựng <location>Diadwyn</location>",
    [57291995] = "Tìm Trại Thứ Hai Của Jezmina Tại Lưu Vực Veilwater",
    [57378198] = "Tốc Độ Mũi Tên",
    [58272332] = "[Chuỗi Giao Diện Không Hợp Lệ]",
    [58631375] = "Một bộ dao găm được nhặt nhạnh từ tàn tích của thế giới cũ. Nó bẩn thỉu và đầy bụi bặm, nhưng vẫn hoạt động tốt.\n\n<b>Tinh Tế:</b>\nSát thương gây ra bởi vũ khí này tỉ lệ với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc nhất sau khi đỡ đòn.",
    [58863854] = "Phiên Không Tên",
    [59101271] = "Bạn cần chế tạo bảng màu để tô màu cho các vật phẩm.",
    [59199371] = "Tùy chỉnh",
    [59419280] = "Đầu Hydrak'Dal mà ngươi đã thu thập có thể được sử dụng để <b>nâng cấp Ngọn Lửa.</b>\n\nHãy thu thập tất cả các nguyên liệu cần thiết khác để hoàn thành việc nâng cấp. Sau đó, ngươi sẽ có thể tiến sâu hơn vào Lưu Vực Veilwater.",
    [60562579] = "Túi Đồ & Rương Ma Thuật trong Căn Cứ này",
    [60609642] = "Hướng Camera",
    [60944457] = "Bình Nhỏ",
    [61140021] = "Bắt Đầu Chương Mới",
    [61160921] = "Cửa Lâu Đài Bí Mật",
    [61318647] = "Đá Đồng Trống",
    [61440388] = "Ma-nơ-canh Nữ",
    [61450567] = "Lò Rèn Đá Quý Vùng Kindlewastes",
    [61759415] = "Một chiếc <keyitem>Ấm</keyitem> kim loại có thể treo trên <craftingstation>Trạm Nấu Ăn</craftingstation>.",
    [61793076] = "Hầm Mộ Mistbury",
    [62245536] = "Một vật phẩm hữu ích để tưới nước cho hoa và cây cỏ đang khát.",
    [63579343] = "Bát Đĩa",
    [63745043] = "Giày Hiệp Sĩ",
    [63785216] = "Đào qua những tấm ván sàn gần cối xay ở <location>Willow Crush</location> đã phát hiện ra hài cốt. Một chiếc nhẫn được tìm thấy giữa đống tro tàn.",
    [64102015] = "Sẽ Quay Lại Ngay!",
    [64525539] = "Claudy, tôi thách cậu tham gia cùng tôi để <i>quậy phá một chút!</i> Chúng ta sẽ gặp nhau tại Vịnh Skimmer tối nay cùng với June và Ricky. June muốn trộm đèn lồng của cha cô ấy để chúng ta có thể đến đó khi màn đêm buông xuống... Tôi biết cách vượt qua lính gác từ mùa hè năm ngoái rồi, nên đừng lo. \nRicky nói cậu ấy sẽ hét thật to để làm rung chuyển vịnh và <i>dụ lũ sinh vật thằn lằn ra ngoài!</i> Nhưng tôi nghĩ cậu ta không dám đâu. Đồ nhát gan! \n\nLeo ra ngoài cửa sổ vào lúc nửa đêm nếu cậu dám tham gia. Tôi đã để lại vài chiếc đèn lồng cho cậu. Chúng tôi cũng có đồ ăn nhẹ nữa! HOẶC LÀ: Hãy nói với Ricky rằng cậu thích cậu ta đi! Cậu sẽ không dám đâu!! Vì cậu cũng là đồ nhát gan mà thôi!",
    [65055072] = "Một lớp vỏ sống bao bọc khuôn mặt người mặc như một trinh nữ sắt.\n\nCung cấp sự bảo vệ tăng cường chống lại Sương độc.",
    [65079529] = "Hỏa Kỷ Nhân — ngươi sống sót như thế này sao? Không có gì bảo vệ? Hãy xây cho chúng ta một nơi trú ẩn! Sau đó ta có thể chế tạo nhu yếu phẩm cho cuộc săn.",
    [65254543] = "Nấm Penny Bun Nướng",
    [65781975] = "Tăng số lượng nguyên liệu trong mỗi chồng vật phẩm nhặt được.",
    [65796027] = "Áo Giáp Kẻ Săn Mỹ Nhân Ngư",
    [65920700] = "Đền Thờ Mặt Trời",
    [65944862] = "Dù hắn đã trốn đi đâu — nếu thực sự có — <lorename>Gormander</lorename> giờ chỉ có một mình. Hoặc cùng với một kỹ nữ khác. \n\nThành phố đã chìm trong biển nước. <b>Chúng đã phá hủy bức tường của chúng ta vào sáng sớm</b> và giờ đây bao phủ thị trấn bằng một lớp tinh vân dày đặc, ngột ngạt có màu như lông đà điểu. Tôi co rúm ở đây — cô độc, lần đầu tiên sau nhiều năm. Như một cô bé vậy.\nTim tôi đập loạn xạ như một con chim yến bị nhốt trong lồng. Lẽ ra tôi nên bỏ chạy và thuê một con tàu. Chiếm lấy nó. Dù sao thì tôi cũng biết đấu kiếm và đọc bản đồ mà! Có lẽ vẫn chưa quá muộn.\nTôi vẫn có thể thức dậy giữa màu xanh của đại dương và cảm nhận vị muối trên da mình. Thấy những nàng tiên cá và hát vang tại bến cảng, thật lớn, cuối cùng cũng được làm vậy! <i>Tôi muốn kết thúc trong một cơn bão, trong một ngọn lửa rực cháy, chứ không phải trong một tòa tháp nhỏ bé cô đơn!</i>\nĐừng cười nhạo tôi. Tôi cảm thấy mình thật nhỏ bé",
    [65969336] = "Đổ Bóng Tiếp Xúc",
    [65991013] = "Một con bướm đêm mờ nhạt bị tách khỏi hệ sinh thái tự nhiên để dùng làm nguyên liệu giả kim.\n\nChỉ có thể tìm thấy vào ban đêm trên các cánh đồng ở Revelwood.\nCó thể dùng làm mồi câu cá, khả năng cao sẽ bắt được những loại cá hiếm.",
    [66089788] = "Thế giới này xứng đáng để chúng ta chiến đấu!",
    [66649546] = "Đồn Trú Balefire \"Thông Trắng\"",
    [66712770] = "Một Sinh Vật Không Tên",
    [66736550] = "Cờ Lệnh Hành Lang Khô Cốt Khổng Lồ",
    [66876951] = "Tạo phòng máy chủ",
    [67356638] = "Tỉ lệ Chí mạng của vũ khí cận chiến tăng thêm <b>10%</b>. ",
    [68510497] = "Vẫn sử dụng",
    [69313269] = "Hàng Rào Gỗ Tốt",
    [69379047] = "Sử Dụng Điểm Kỹ Năng",
    [69908772] = "Quần Giáo Sĩ Sinh Ra Từ Sóng",
    [70307728] = "Tôi Đang Mất Ngủ",
    [70681904] = "Giáp Băng",
    [70749503] = "Mở một chiếc rương đang khóa.",
    [70750021] = "Đội Quân Xác Sống Tiến Bước",
    [70834620] = "<b>Bản Nhạc</b>: \nBản Nhạc sẽ dạy cho bạn một bài hát mới sau khi nhặt được. Bạn không cần phải giữ bản nhạc trong túi đồ để chơi bài hát đó. Tặng nó cho người khác cũng sẽ giúp họ học được bài hát.",
    [72456724] = "Tham gia (Nhập mật khẩu)",
    [72521156] = "Tăng SP thêm %k cho mỗi Điểm Thuộc tính.",
    [72796386] = "ST Cắt mỗi giây",
    [72996497] = "Tăng Hồi phục MP",
    [73174665] = "Nhật ký số 03\nLần ăn cuối: Thứ Sáu, xương và thức ăn thừa (nó không ăn)\nGhi chú: Trông khá kỳ lạ đối với một con sói, không biết có đúng không. Cứ khóc và sủa suốt đêm. Chỉ cần quát lại là nó sẽ im.",
    [73234899] = "Biểu Tượng Tường Hình Khiên II",
    [73592548] = "Bỏng Lạnh",
    [73655548] = "Một khối xây dựng giúp dễ dàng tạo ra các góc cạnh sắc sảo và bắt mắt.",
    [74060006] = "Bạn đã đến vị trí của Lò Rèn Đá Quý, nhưng có kẻ địch ở gần đó. Hãy tiêu diệt kẻ địch bên trong Lò Rèn Đá Quý trước khi quan sát xung quanh!",
    [74722034] = "Khai Quật Kho Báu Của Người Nông Dân",
    [74854715] = "Chuột Trái",
    [75073135] = "Thức ăn Tatu Cát bổ dưỡng cho các loài vật đã thuần hóa trong trang trại của bạn.\n\nPhải được đặt bên trong máng ăn phù hợp.",
    [75197992] = "Tiêu hao SP khi leo trèo giảm <b>50%</b>. ",
    [75303242] = "Bộ giáp này có thể được tìm thấy trong các hầm mộ ở Lưu vực Veilwater.",
    [75439718] = "Pheromone Gây Lú Lẫn Sa Ngã",
    [75471398] = "ST Lén lút",
    [75537637] = "Khối Xây Dựng",
    [75630766] = "Giá Treo Đũa Phép Gắn Tường",
    [75986883] = "Từng Viên Gạch Một",
    [76483553] = "Một viên gạch đất sét tối màu, được phơi khô dưới nắng.",
    [76593460] = "Cọc Hàng Rào Tre",
    [77156321] = "Chào mừng trở lại!",
    [77433505] = "Quả thực, <b>đài tưởng niệm</b> này có cùng những ký tự như những cái chúng ta đã nghiên cứu ở Kindlewastes. Điều này cho thấy một hệ thống chữ viết chính thức, bao gồm các chữ biểu ý và chữ biểu âm, xác thực giả thuyết của tôi. Một số từ vựng được lặp lại, gợi ý về một sự đồng thuận về chủ đề. Hoặc có thể là vốn từ vựng hạn hẹp. \n\nTuy nhiên, tôi thấy những dấu hiệu độc nhất so với các đài tưởng niệm ở phía đông... Một phương ngữ chăng? \nNhư thường lệ, tôi không thể giải mã được ngôn ngữ này. Tôi thất vọng nhưng không ngạc nhiên.\n— <lorename>Loraine Crim</lorename>",
    [77830720] = "Tài Nguyên",
    [78288571] = "Tăng sát thương gây ra bằng đũa phép.",
    [78424052] = "Mỏ Ternion",
    [78778605] = "Một Khu Mộ Được Chọn",
    [80005217] = "Sơ Đồ Điều Khiển",
    [80260056] = "Thêm Một Đôi Tay Giúp Đỡ",
    [80518435] = "Bạn đang bị chảy máu.",
    [80558527] = "Di Chuyển Camera Cánh Lượn",
    [80608477] = "Ghi Chú Của Chester Loft",
    [81188922] = "Tôi đã nghe câu chuyện về một ống tên luôn đầy ắp, bất kể đã rút ra bao nhiêu mũi tên. Đôi khi, có một hạt nhân sự thật trong những câu chuyện kỳ ảo nhất, bạn biết đấy?",
    [82045377] = "Chế Tạo Gậy Phép Của <npc>Nhà Giả Kim</npc>",
    [82161908] = "Tất cả sát thương <b>Va Chạm</b> cận chiến tăng thêm <b>20%</b>. ",
    [82464920] = "\n<b>Mũi Tên Vĩnh Cửu:</b> Mũi tên vĩnh cửu <b>không bao giờ cạn kiệt.</b> Trang bị mũi tên vĩnh cửu và sử dụng <b>MP</b> để bắn bằng <b>cung.</b>",
    [82483349] = "Chất Kết Dính Chướng Khí",
    [82609475] = "Nắm Đấm Trần",
    [83123010] = "ST Cận chiến",
    [83216412] = "Sống Lưng Gai Nướng",
    [83647880] = "Một con bù nhìn rơm thường bị nhầm lẫn với sinh vật từ Sương độc khi mặt trời lặn.",
    [83808350] = "Một chiếc gối hình trái tim bằng nhung mềm mại, không chỉ mang lại sự thoải mái mà còn tạo vẻ sang trọng, thanh lịch cho bất kỳ không gian nào.",
    [83938824] = "Găng Tay Người Tiên Phong",
    [84159199] = "Thùng Gỗ Nằm Ngang",
    [85135446] = "Phím Nhấn Để Nói: ",
    [85349132] = "<location>Netherton</location>",
    [85887708] = "Một loài hoa huệ biển lớn và mảnh mai, vươn cao về phía mặt nước và bầu trời. Nếu nó có tri giác, nó sẽ có thể cảm nhận được sự lên xuống của biển cả, cũng như sự thay đổi sắp tới của dòng nước.\n\nVật phẩm thu thập này được tìm thấy ở Cao Nguyên Du Mục.",
    [85895509] = "Dê Thường",
    [86500404] = "Bằng cách sử dụng ma thuật Sương độc, Thời gian trong Sương độc của bạn bị giảm đi 5 phút.",
    [86730500] = "Nhanh chóng lao đến giải cứu trong đôi ủng thoải mái và vừa vặn này!",
    [87079195] = "<location>Woodgard</location>",
    [87285710] = "Thợ Cắt Tóc tin rằng đôi mắt là cửa sổ tâm hồn. May mắn thay, bạn có thể khám phá những màu mắt mới để tùy chỉnh diện mạo của mình bằng cách tìm cảm hứng và đọc những câu chuyện tham khảo. Các màu mới sẽ được thêm vào danh mục của Thợ Cắt Tóc. \n\nHơn nữa, Thợ Cắt Tóc khẳng định ông từng chứng kiến màu mắt của ai đó thay đổi. Một khách hàng cũ của ông được cho là có đôi mắt xanh điên dại sau một tai nạn tại một công trường xây dựng bị nguyền rủa. Màu mắt của anh ta mờ đi sau khi hồi phục từ sự cố đó. \n\nThợ Cắt Tóc khăng khăng rằng công trường đó bị ám. Hãy tìm kiếm công trường xây dựng để tìm hiểu thêm!",
    [87494646] = "Gây sát thương lên kẻ địch sẽ để lại một dấu ấn <img gemeffect_soulreaping> lên chúng trong %k. Kẻ địch bị đánh dấu <img gemeffect_soulreaping> khi chết sẽ rơi ra một bình linh hồn, có thể phá hủy để hồi máu cho bạn và đồng minh thêm %k trong bán kính 5m, đồng thời cũng được tính là một lần hạ gục kẻ địch cho các hiệu ứng khác.",
    [87510049] = "Đôi mắt xanh sáng rực luôn có điều gì đó huyền bí, bạn có nghĩ vậy không?",
    [88039389] = "Oscar Godwin",
    [88303880] = "Thuốc Nổ",
    [89678704] = "Gửi tất cả những ai từng câu cá ở vùng nước này: có một tai ương đang diễn ra ở thượng nguồn. Thỉnh thoảng tôi thấy gia súc và sinh vật rừng trôi qua trong dòng nước xiết... tuy nhiên, hôm qua tôi cứ ngỡ mình đã câu được một mẻ lớn. Khi kéo lên, đó là <i>một xác chết thối rữa</i> bị biến dạng bởi một loại bệnh dịch nào đó, da thịt và xương cốt vặn vẹo đến mức khó lòng nhận ra. Khi tôi đứng đó trong bàng hoàng, thêm hai cái xác nữa nổi lên và trôi qua chỗ tôi. \n\nLoại hủy diệt nào đang giáng xuống vùng đất này vậy?",
    [90026966] = "Được ban phước bởi Ngọn Lửa và tắm mình trong ánh sáng vinh quang, đôi găng tay này sẽ đảm bảo rằng mọi đòn đánh của bạn đều được dẫn dắt bởi chính các Cổ Nhân.",
    [90387428] = "Một chiếc khiên hình bầu dục mang hào quang vương giả. Khi kẻ thù thấy mắt bạn lấp ló sau sự an toàn của chiếc khiên, chúng chỉ còn vài giây nữa là trút hơi thở cuối cùng.",
    [90733947] = "Một loại khoáng sản tuyệt đẹp, thường được tìm thấy bên dưới Sương độc. Màu sắc của nó có thể dao động từ màu tím hoàng gia đậm và bão hòa đến sắc tím oải hương nhạt.",
    [90905840] = "Lan Can Gỗ I",
    [91060700] = "Khiên Chiến Binh Quật Khởi",
    [91117612] = "Quầy Bar Bằng Tre",
    [91281434] = "Những chiếc sừng vặn xoắn và xù xì. Chúng chứa đựng năng lượng Sương độc đậm đặc.\n\n<b>Nguyên liệu Chế tạo:</b> Chủ yếu dùng để chế tạo giáp trụ.\n<b>Nguồn gốc</b>: Rơi ra từ Fell Thunderbrutes, ban đầu được tìm thấy ở Springlands.",
    [91536945] = "Khối Cột Đá",
    [91917683] = "Trò Chuyện Với <npc>Thợ Mộc</npc>",
    [91926467] = "Ngọc Đầu Lâu",
    [92440670] = "Sinh Tồn",
    [92972976] = "Bia Mộ \"Bên Nhau Lần Nữa\"",
    [93363999] = "Lỗi dữ liệu lưu trữ. Không thể đọc dữ liệu.",
    [93389944] = "Bí Ngô",
    [93575182] = "Đang tìm kiếm...",
    [93620645] = "Thú Rừng Nướng",
    [93641903] = "Dieter vẫn ổn, đừng lảm nhảm nữa! Hắn có xẻng và lòng can đảm, hắn sẽ sớm ra khỏi <i>hầm mỏ</i> thôi. Có lẽ tên ranh con đó đang trêu đùa chúng ta.\n\nNói ta nghe, ngươi có để ít lương thực vào đó không, Hans..?\n\nDù sao thì, hắn sẽ sống sót thôi.\n\nPhải, cái rương đó là mồi nhử ngon... dù chúng ta cũng cần đến nó... phiền thật, đáng lẽ phải tính đến chuyện này trước đó...",
    [94411040] = "Đã chán ta chưa? Ha! Vậy thì còn gì nữa nào?",
    [94437072] = "Nhanh Nhẹn",
    [94624404] = "Tạo Nhân Vật",
    [94678721] = "Máu Trước Trí Tuệ",
    [94722962] = "Lối Chơi",
    [95940382] = "Thảm Treo Tường I",
    [96654351] = "Giáp Trụ",
    [96838616] = "Hiệu Năng",
    [96841703] = "Một chú ếch nhỏ xíu. Nó có thể là người bạn tốt nhất của ngươi nếu ngươi không định dùng nó làm mồi câu cá. \n\nTìm thấy ở Lưu vực Veilwater và đặc biệt hữu ích để câu cá sử thi.",
    [96872122] = "Chế Tạo Lò Luyện Kim Với Ống Thổi",
    [96939071] = "Găng Tay Thuật Sĩ Hắc Ám",
    [97389160] = "Tìm Kiếm Hầm Trú Ẩn Cổ Đại",
    [97872911] = "Chuyến Hàng Mũ Bị Thất Lạc",
    [98015022] = "Trượng Nước Trong",
    [98025688] = "Thuốc Giải Lời Nguyền Sa Ngã",
    [98156460] = "Đỉnh Pikemead",
    [99495955] = "Một phiên bản vĩnh cửu của Mũi Tên Băng. Phép thuật gây sát thương lên kẻ địch khi va chạm và làm chậm chúng sau đó.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không tiêu hao.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để thi triển bằng <b>Gậy phép.</b>",
    [99954327] = "Tái Lập Toàn Bộ",
    [100864839] = "Đổi Tên",
    [101062096] = "Tùy Chỉnh",
    [101659096] = "Sát Thương Đâm Sau Lưng",
    [101989246] = "Trò Chuyện Với Marianne Reed",
    [102093346] = "Gỗ Cứng",
    [102836292] = "Thợ Cắt Tóc, Elio Ricci, cho phép ngươi thay đổi diện mạo.",
    [103139896] = "Đuốc Đứng Phế Liệu",
    [103440210] = "ST Đánh lén",
    [103525580] = "Bảo vệ ngón tay khỏi bẫy và vết cắt. Người bạn tốt nhất của kẻ trộm!",
    [104025206] = "Vật Liệu Địa Hình",
    [104752207] = "Tóc",
    [104875176] = "Mũ Thời Trang",
    [104919736] = "Găng Tay Nanh Sói",
    [105747713] = "Những chiếc găng tay này được chắp vá từ hai loại vải khác nhau. Chúng tái hiện lại hình dáng của \"móng guốc\".",
    [106001521] = "Thay Đổi",
    [106152563] = "Lục Soát Hầm Mỏ Gần Đó",
    [106314166] = "Sát Thương Va Chạm",
    [106340978] = "Triệu Hồi Tinh Linh Lửa",
    [106913089] = "Đã Thu Thập <craftingstation>Khung Cửi</craftingstation>",
    [107187970] = "Nồi Phế Liệu VI",
    [107236707] = "Người Chơi",
    [107633673] = "Một Căn Phòng Bí Mật",
    [107637757] = "Một cây đũa phép huyền thoại được tạo ra quanh lõi xương sống uốn lượn. Nó tấn công với độ chính xác chết người.\n\n<b>Đa Tiễn:</b> \nBắn ra nhiều tia đạn nhưng giảm sát thương.",
    [107939189] = "Vây Vàng",
    [107987289] = "Ngọn Lửa cảm nhận được một rào chắn, được xây dựng bởi các Cổ Nhân tiền bối, thứ ngăn cản tầm nhìn và tầm với của nó. Bất cứ thứ gì ẩn sau rào chắn đều vô hình trước Ngọn Lửa — điều này càng khiến nó trở nên thú vị đối với ngươi.\n\n<b>Hãy tiếp cận và điều tra rào chắn hắc ám!</b>",
    [108540411] = "Nguồn gốc của Chất Độc nguy hiểm.",
    [108947275] = "Xin chào.",
    [109067555] = "Theo Ngữ Cảnh",
    [109549313] = "Lộ Điểm Yếu",
    [109601470] = "Đen Tối Là Khi Thiếu Vắng Người, U Ám Là Đêm Của Ta",
    [109784070] = "Lịch Sử Của Drak",
    [109899339] = "Đàn Tế %k",
    [109911251] = "Những Hình Khối Chuyển Động",
    [110886442] = "Trà Gia Vị",
    [110981205] = "Loại bỏ Lời Nguyền Fell khi sử dụng.\n\nĐồng thời áp dụng một bùa lợi ngăn chặn lời nguyền ảnh hưởng đến người dùng trong một giờ.",
    [111008723] = "Tìm Kiếm Bộ Trang Phục Mùa Đông",
    [111275974] = "Tất cả các vật phẩm có thể nâng cấp từ túi đồ và thanh hành động của ngươi đều được liệt kê ở đây.",
    [111902605] = "Nhà Sa Mạc",
    [112807411] = "Bên Dưới Những Guồng Nước",
    [112835763] = "Với chiếc <craftingstation>Máy Cưa Bàn</craftingstation> mới này, ta đang \"rần rần\" với những ý tưởng chế tạo mới đây... ngươi hiểu chứ! Phải, ta có thể vận hành nó bằng 1H. Không sao cả!",
    [113761803] = "Một chiếc dùi cui chết chóc sẽ tiêu diệt bất kỳ kẻ thù nào.",
    [113807708] = "Gối Ôm Động Vật Nông Trại Lớn",
    [114165524] = "Đã ghi lại %k mục.",
    [114678955] = "Ghi Chép Của Tướng Cướp Dịp Tết Nguyên Đán",
    [115251224] = "<lorename>Sameth</lorename>, lòng tham Elixir của ngươi không bao giờ có thể thỏa mãn! Ngươi giữ nó cho riêng mình trong khi đã hứa sẽ chia sẻ! Đồ DỐI TRÁ!\n\nChúng ta, những người của ngươi, đã CHẾT vì ngươi trong những đường hầm đó! Vì cái gì chứ? Chúng ta trục xuất ngươi khỏi đây! Đi ngay — hoặc chúng ta sẽ cho ngươi thấy sức mạnh của số đông! Hãy tìm Elixir của ngươi ở nơi khác! Đây là mỏ của CHÚNG TA!",
    [115305275] = "The <npc>Thợ Săn</npc> cần nơi trú ẩn để chế tạo nhu yếu phẩm và vật tư. Hãy xây một ngôi nhà cho Nữ Thợ Săn và cho cô ấy sử dụng một <b>chiếc giường có mái che gần đó nếu ngươi chưa làm vậy!</b>\n\nĐể che chở cho những người sống sót, hãy <b>chế tạo một chiếc giường phù hợp.</b> Đặt giường ở khu vực được bảo vệ mà những người sống sót có thể dễ dàng tiếp cận. Nó sẽ tự động được chỉ định cho người sống sót tự do gần nhất sau khi được đặt. Nếu ngươi muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu Hồi và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho ngươi khi những người sống sót không còn nơi trú ẩn.",
    [115457208] = "Khi sự tĩnh lặng của màn đêm bắt đầu bao trùm những ngọn núi, tốt nhất ngươi không nên bước chân ra ngoài bóng tối. Nỗi kinh hoàng ẩn nấp nơi ánh sáng không chạm tới.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Đỉnh Albaneve.",
    [115561267] = "Đôi mắt xanh có thể sâu thẳm như đại dương, hoặc trong vắt như bầu trời! Ta yêu sự huyền bí mà chúng tỏa ra!",
    [115605210] = "Đỉnh Albaneve",
    [116017990] = "Ngọn Tháp Cổ Đại, Những Ngọn Hải Đăng Ánh Sáng",
    [116126815] = "Cúp Danh Năng Quái Vật Mắt Một Sa Ngã",
    [117194924] = "Bức Tường Bậc Thang",
    [117373431] = "Đũa Phép Thần Thoại",
    [117552416] = "Một ngày đẹp trời để câu cá, phải không?",
    [117989402] = "Hoa Sương độc",
    [118384000] = "Robert Gibson Cần Giúp Đỡ",
    [118481861] = "Dao Găm Diễu Hành",
    [118875771] = "Tăng thời gian ngươi có thể lặn.",
    [118886038] = "Cọc Hàng Rào Nhà Tù",
    [119145828] = "Chém xuyên qua tất cả. Rẽ lối Sương độc. Cắt bỏ khối u.",
    [119914184] = "Áo Crop Top Trò Chơi Mùa Hè",
    [120734496] = "Embervale vẫn có thể được cứu... Nơi nào có tro tàn, nơi đó có than hồng, nhóc ạ! Sương độc đang bóp nghẹt các thung lũng, vì vậy hãy tìm Giếng Elixir với trang bị mới của ngươi và san phẳng cội nguồn của nỗi khổ đau này! Hãy thắp sáng vực sâu và thiêu rụi cái ác này! Đi đi, ta trông cậy vào ngươi đấy, Flameborn!",
    [121605669] = "Cường Hóa Ngọn Lửa",
    [121949315] = "Ngày xưa, khi còn là một thợ may, ta có một vị khách khá nổi tiếng — chính là vị Thuyền trưởng già đó!\n\nTa sẽ không bao giờ quên buổi bình minh khi ông ấy loạng choạng bước qua cánh cửa đang mở của ta, bộ râu chưa bạc trắng như bây giờ, trên người chỉ có độc chiếc áo sơ mi lấm bẩn.\n<i>\"Chào buổi sáng, cô gái trẻ!\"</i> Ông ấy kêu lên với giọng khàn khàn, <i>\"Ta muốn một chiếc áo khoác mới! Xanh thẳm như biển cả, có vàng và lộng lẫy, ta muốn thế — hức!</i>\"\n\nTrong khi lấy số đo, ta đã quan sát ông ấy kỹ lưỡng. Ông ấy nồng nặc mùi rượu và không chỉ mất áo khoác mà còn mất một chiếc giày... Khi ta hỏi về chuyện đó, ông ấy nói:\n<i>\"Không, rượu chỉ là một nửa câu chuyện thôi — Xem này, khi ta đang ở ngoài muộn trên con kênh, một con quỷ già sinh ra từ bọt biển xanh ngắt đã gọi ta từ bên dưới! Hắn nói hắn sẽ đổi cho ta một chai rượu ngon nhất của hắn lấy một chiếc cúc áo khoác của ta! Một chai rượu đổi một chiếc cúc áo? Ta nghĩ: Tại sao không? Nhưng khi ta cúi xuống để nhận rượu, sinh vật tinh quái đó đã kéo ta xuống bằng khuy măng sét và biến lại thành bọt biển! Hức! Ta đã rơi xuống nước, cấp cứu, cấp cứu! Họ đã phải vớt ta và con thuyền của ta lên — còn chiếc áo khoác của ta, nó đã biến mất theo những con sóng! Hức!\"</i>\n\nTa đã chuẩn bị xong chiếc áo khoác mới cho ông ấy trong vòng ba ngày, nhưng ta luôn tự hỏi làm thế nào mà quần áo cũ của ông ấy không dạt vào bờ. Liệu chúng cũng biến thành bọt biển sao?",
    [123043861] = "Pháo Đài Balefire \"Trái Tim Sắt\"",
    [123296829] = "Tạm biệt, người bạn của ta.",
    [123350096] = "Những Đại Sảnh đã vẫy gọi ta từ lâu. Ta đã phớt lờ tiếng gọi của chúng trong quá khứ, nhưng giờ đây, ta đứng đây với sự khích lệ từ những người đàn ông phía sau mình. Những người lính dũng cảm, kiên cường, được trang bị tận răng. Họ nói họ sẽ theo ta đến bất cứ đâu, vào bất kỳ bóng tối nào, bất kỳ độ sâu nào.\n\nThánh địa bị nguyền rủa này sẽ không còn làm ô uế những đỉnh núi của chúng ta nữa. Đừng lo lắng, người anh em. Nếu chúng ta ngã xuống, chúng ta sẽ ngã xuống cùng nhau.\n\nTa dự định sẽ trở về vào lúc bình minh — Nếu mặt trời mọc mà không có ta, hãy gửi viện trợ.\n\nBerhtolf, Con trưởng của dòng họ Dimweald",
    [123505336] = "Ngọc Xuyên Thủng",
    [123518252] = "Nâng Cấp",
    [124113649] = "Một cây cung thượng hạng lấy cảm hứng từ gạc hươu. Có kẻ sẽ gọi nó là một tác phẩm nghệ thuật.",
    [124321232] = "+ Sương độc",
    [124875476] = "Những Vết Nứt Trong Băng",
    [125190687] = "Lối Mòn Sàn Gỗ Giả",
    [125200029] = "Việc chế tác cần thời gian! Hãy nghỉ ngơi đi!",
    [125256155] = "Thật đấy! Những đốm sáng lung linh, đang ăn mừng!! Nhảy múa vui vẻ, hân hoan dưới những con sóng! \n\nVào lúc bình minh, sâu bên dưới mặt nước lấp lánh, tôi đã thấy những ánh sáng! Tỏa sáng từ vực thẳm... ngay sau khi <i><lorename>Pikemead</lorename></i> băng hà!! \n\nMọi người chế nhạo và cười nhạo, nhưng tôi biết mình đã thấy gì. Đó có phải là một điềm báo? <i>Liệu bà ấy sẽ trở lại?</i> Có lẽ vận may cuối cùng cũng mỉm cười với thế giới này!",
    [125562964] = "Những Lưỡi Đao Độc Tố",
    [125651213] = "Mồi Câu Cá Ít Gặp",
    [126139993] = "Tiếng Gõ Cửa Trong Đêm",
    [126290295] = "Đôi găng tay vàng lấp lánh là dấu ấn của một Học Giả đang hành động, tư duy nhạy bén và trái tim rạng ngời.",
    [126667594] = "Chất Lượng Mô Phỏng Nước",
    [127113952] = "Sinh Tố Coconana",
    [127513559] = "Sói Quái Vật Hydra",
    [127559959] = "Vũ Khí Tầm Xa",
    [128827571] = "Bắt Điểm: Kích Hoạt",
    [129583216] = "Chuyển Động Camera Khi Chiến Đấu",
    [129744492] = "Tìm thấy trong Sương độc Revelwood",
    [130343986] = "Tôi không thể ngừng nghĩ về vẻ ngoài ấn tượng của những \"Gã Xương Xẩu\" đó. Thật đáng sợ, nhưng cũng thật mê hoặc! Tôi yêu cái vẻ ma mị này!",
    [130616092] = "Bọ Ba Thùy",
    [130620898] = "Chiếc rương nhỏ ma thuật này cung cấp thêm không gian lưu trữ vật phẩm. \n\nCác vật phẩm cất giữ ở đây có thể được sử dụng để chế tác từ bất kỳ đâu trong căn cứ!",
    [130670844] = "Thu Thập Khối Mái Ngói Sa Mạc",
    [130673656] = "Giết một kẻ địch bằng ST Đập có %k cơ hội tạo ra các mảnh xương tự dẫn đường, gây %k ST Đập, với cơ hội tạo ra tối đa 4 viên đạn.",
    [130819088] = "Tôi thức dậy trong mùi máu tươi thoang thoảng. Tôi nhìn ra ngoài cửa sổ, nơi một kẻ săn mồi vừa hạ gục 2 con Hươu Tiên. Có lẽ là không tốn sức, nhưng chắc chắn là không hề không đau đớn.\n\nLúc đầu, tôi hét lên vì kinh hãi. Nhưng rồi tôi nhận ra: 2 con Hươu Tiên. 8 phần sườn. Có lẽ là 10, 12 khúc xúc xích. Tiết canh làm món tráng miệng. Cả gallon súp hầm! Thứ này sẽ nuôi sống cả làng. Đội ơn các Đấng Cổ Xưa!",
    [130971941] = "Thông Điệp Phía Trên",
    [131140650] = "Mọi ánh sáng chiếu tới đều bị khúc xạ trên bề mặt của lưỡi kiếm thanh tao này, tạo nên một vũ điệu của những sắc màu trôi lơ lửng. Nó thực sự toát lên vẻ xuất chúng.",
    [132494502] = "Đó là cái gì vậy...? Thứ mà ngươi đang mang theo. Hệ sợi nấm? Hỏa Nhân, ta khuyên ngươi nên cẩn trọng. Thứ ngươi đang cầm cực kỳ nguy hiểm. Nó là mầm bệnh. Nó là sự đau khổ. Nó là một loại nấm nhằm mục đích nuốt chửng thế giới của chúng ta... con người đã thấy tiềm năng trong xác thịt của loài thực vật này, nhưng họ chỉ mang lại tai ương. Làm ơn, hãy tránh xa thứ đó ra. Nó đánh dấu sự diệt vong.",
    [132620819] = "Hỏa Nhân! Bạn của ta, có một thứ ta cần từ ngươi!",
    [133025857] = "Bình Sinh Tồn Chướng Khí",
    [133140698] = "Đạn ma thuật phun axit theo hình nón phía trước người thi triển, gây độc cho tất cả kẻ địch trúng đòn.\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để thi triển bằng <b>Gậy phép.</b>",
    [133375501] = "Cờ Lệnh Hành Lang Khô Cốt Vừa",
    [133486553] = "Tìm Xưởng Ủ Rượu Nhỏ",
    [133775804] = "Ma Thuật",
    [134359125] = "Không có người chơi nào ở đây.",
    [134397963] = "Tăng tốc độ lẻn của bạn.",
    [134429462] = "Ngoài Tầm Với",
    [134827235] = "Con Đường Đến Dấu Ấn Của <lorename>Sameth</lorename>",
    [135183480] = "Một chiếc quần chỉnh tề. Những chi tiết kim loại tinh xảo quanh thắt lưng gợi nhớ đến mặt trăng và thủy triều.",
    [135876029] = "Đĩa Gỗ Thô Sơ",
    [135954114] = "<location>Morwenna</location>",
    [136038067] = "Mũ Trùm Lông Xù",
    [136652009] = "Viên ngọc xanh biển này trong vắt như một hồ nước pha lê dưới bầu trời xanh rực rỡ.",
    [136661484] = "Không tìm thấy các tệp nội dung. Vui lòng cài đặt lại trò chơi.",
    [136750940] = "Một miếng phi lê cá được áp chảo trên Ngọn lửa hồng cho đến khi lớp vỏ ngoài hơi giòn, giúp tăng giá trị dinh dưỡng của nó.",
    [136805343] = "Cây Giống Nghệ Tây",
    [137081512] = "Đất Lưu Vực Vực Nước",
    [137851898] = "Không còn nhiều thời gian nữa. Thứ lỗi cho sự thẳng thắn của ta, người anh em.\n\n<b>1. Gormander không gây nguy hiểm</b>\nThủ đô của hắn gần như không có phòng thủ. Không có dấu hiệu của \"Vũ khí Cổ xưa\" hay âm mưu nào cả. Tiên dược chỉ khiến đồng loại của hắn béo tốt và tham lam, chứ không phải khát máu... mặc dù chúng đã trở nên hoang tưởng, giống như hầu hết mọi người.\n\n<b>2. Chúng ta đã bị lừa</b>\nTên <i>kẻ lãng du</i> đó đang đầu độc tâm trí của Chúa tể chúng ta. Chúng ta không thể tin một lời nào từ cái lưỡi xảo quyệt của hắn. \n\n<b>3. Hãy đi cùng ta</b>\nTừ bỏ vị trí của đệ đi. Hãy cùng ta đi về phía nam. Hãy quay lưng lại với chiến tranh, Sương độc và cái chết. Hãy gột rửa bàn tay đệ trong những dòng nước yên bình hơn.\n\n<b>4. Hãy hủy bức thư này</b>\n...Trừ khi đệ muốn máu của em gái mình phải đổ.\n\n— Athalan",
    [139525349] = "<keyitem>Dụng Cụ Khoa Học</keyitem> Cho Phòng Thí Nghiệm",
    [139713076] = "Áo Vest Thiện Xạ",
    [139969294] = "Trợ lý của Nhà Sưu Tập muốn chiêm ngưỡng một viên ngọc có vẻ đẹp sánh ngang với mặt trăng. Một thứ như vậy có thể được tìm thấy bên trong Thánh Đường Đêm.\n\nHãy đến Thánh Đường Đêm được đánh dấu trên bản đồ của bạn để lấy viên ngọc!\n\nNếu bạn được bạn bè tặng viên ngọc, nhiệm vụ cũng sẽ tiếp tục!",
    [140354886] = "Ngày xửa ngày xưa, có một nàng công chúa nhỏ với đôi má hồng hào và mái tóc màu tro, nàng không thích gì hơn là chơi đùa bên hồ nước của lâu đài với quả cầu vàng của mình.\n\nMột ngày nọ, quả cầu tuột khỏi tay nàng và chìm xuống dưới mặt nước. Quá đau buồn, công chúa khóc nức nở cho đến khi một giọng nói ồm ồm vang lên từ bụi sậy:\n<i>\"Đừng khóc, công chúa nhỏ. Ta sẽ lấy quả cầu vàng cho nàng — đổi lấy một nụ hôn từ đôi môi anh đào của nàng!\"</i>\n\nCô gái ngước nhìn lên và thấy một con ếch xù xì trên lá sen. Dù thấy ghê tởm, nàng vẫn gật đầu, khao khát lấy lại kho báu của mình. Sinh vật đó lặn xuống và trở lại với quả cầu — nhưng ngay khi công chúa lấy lại được món đồ chơi, nàng đã chạy biến vào lâu đài mà không một lời cảm ơn.\n\nĐêm đó, con cóc đến gõ cửa cổng thành. Nhà vua, khi nghe về lời hứa của con gái, đã yêu cầu nàng phải giữ lời. Nhưng công chúa vẫn tỏ ra miễn cưỡng, và trong cơn tuyệt vọng, nàng đã ném con vật đáng ghét đó vào tường. \nKhi con cóc xanh nhợt nhạt văng vào những viên gạch, lời nguyền trói buộc nó đã bị phá vỡ, và nó được giải thoát khỏi xiềng xích của hình hài máu lạnh. Được tái sinh, nó lộ diện là một hoàng tử.\n\nVà thế là, theo tục lệ, nàng công chúa chưa tuổi vị thành niên đã bị gả cho một người lạ trưởng thành, kẻ đã lừa nàng để có một nụ hôn — nhưng hắn ta khá đẹp trai, nên mọi chuyện đều ổn thỏa.",
    [140834452] = "Ấm hơn và chắc chắn hơn vải thông thường.",
    [140853385] = "Hàng Rào Tre Buộc Dây I",
    [141264174] = "Thánh Đường Đêm Của Các Trưởng Lão",
    [141405636] = "Một thiết bị cho ăn chứa thức ăn của Hophare.\n\nNó sẽ cho động vật của bạn ăn khi được đổ đầy loại thức ăn tương ứng.",
    [141861195] = "Bản đồ hiển thị vị trí của <npc>Thợ Săn</npc> trong một Cung Điện Cổ Xưa. Cô ấy rất thành thạo trong chiến đấu tầm xa và sinh tồn.",
    [141910407] = "Trang Phục Thợ Rèn",
    [142235144] = "Trà Thảo Mộc Miền Núi",
    [143289854] = "Vật liệu xây dựng đặc trưng được sử dụng bên trong Sảnh Hollow. Những người khởi xướng phong cách kiến trúc này không rõ danh tính và đã bị lãng quên.",
    [143316742] = "Mũi Tên Thép Tẩm Độc",
    [143604440] = "Hình Khối Lớn",
    [143753974] = "Cây Cảnh Trang Trí",
    [143872811] = "Tìm tất cả các đền thờ Ngọn lửa và thánh đường ở Đỉnh Albaneve.",
    [144214740] = "Đã Nhận Được Nâng Cấp",
    [144458064] = "Chọn Bài Hát",
    [144678736] = "Chung",
    [145314177] = "Thêm người chơi vào danh sách đen",
    [145922503] = "Ta đã đợi ngươi.",
    [145949192] = "Thánh Đường Đêm",
    [146676275] = "Một hộp quà được gói trang trọng.",
    [146806107] = "Nhổ cỏ vùng Springland",
    [146889324] = "<npc>Thợ Rèn</npc> Oswald Anders chế tác và nâng cấp giáp trụ cũng như vũ khí.",
    [146897323] = "Khu Vực Xây Dựng",
    [147025699] = "Nghe ta này. Ta cần một <craftingstation>Xưởng Thuộc Da</craftingstation> để bảo quản lông thú. Có lẽ ai đó ở Cao Nguyên Du Mục có thể có một cái. Việc chuẩn bị lông và da thú dễ dàng hơn nhiều ở những vùng đất đầy nắng đó... mà không có những trận bão tuyết như ta vẫn thường thấy. Có lẽ những <npc>Thợ Săn</npc> trong khu vực đó sẽ có <b>một <craftingstation>Xưởng Thuộc Da</craftingstation>.</b> Hãy hỏi thăm xung quanh để tìm manh mối!",
    [147082745] = "Hành Trình Cuối Cùng Của Ta",
    [147565551] = "Kệ Nhạc Cụ",
    [148081630] = "Nền Tảng Nổi Bằng Khí Của Philipp",
    [148234503] = "Trục Xuất Người Chơi",
    [148720309] = "Rìu Nhà Vô Địch",
    [148991262] = "Một cây chùy dễ dàng xé toạc kẻ thù như một đàn sói đói.",
    [149437292] = "Trống Tay Tinh Xảo",
    [149489233] = "Âm Nhạc",
    [149661368] = "Xung Phong!",
    [150098281] = "Ta không thể làm gì được nếu không có một số <keyitem>Dụng Cụ Khoa Học</keyitem>!",
    [150433757] = "Tiền vàng, lý tưởng để làm lóa mắt, khoe khoang và hối lộ.",
    [150713183] = "Mỏ Muối Egerton",
    [150769360] = "Một chiếc trống sử thi với những đường nét màu xanh được vẽ tinh xảo. Hoa văn phía trên giống như một ngôi sao đối xứng.",
    [150858094] = "Tiếng Anh",
    [151048076] = "Giày Chiến Binh Rắn",
    [151306681] = "Mũ Trưởng Lão",
    [151937318] = "Đôi ủng sũng nước đã bước qua lớp tuyết cao đến đầu gối của Đỉnh Albaneve dưới ánh cực quang phương Bắc đầy điềm gở. Sau khi hành quân qua vô số giờ nửa đêm, Chúa tể <lorename>Vorgoth</lorename> cuối cùng đã đến được cổng của <location><lorename>Pikemead</lorename>'s Reach</location>, vũ khí giơ cao.",
    [151959141] = "<b>Dingo Tự Phụ</b>\nNgười mẹ trại đáng kính\n\n<b>Lelldon</b>\nChết đuối trong đống bừa bộn\n\n<b>Sereene</b>\nNgười tạo ra những Ngôi Làng Ngớ Ngẩn\n\n<b>Galaxy Lychita</b>\nMột hạt cát, một thế giới.\n\n<b>Ella Lapêche</b>\nTiếp đất không thành công.",
    [152189229] = "Mồi câu cá rất đơn giản được làm từ Bộ Phận Sinh Vật. Có thể dùng để câu các loại cá thông thường, nhưng không nhiều loài thích hương vị đó đâu.",
    [152544799] = "Lên đi, hạ gục chúng!",
    [153052553] = "Quan Tài Hầm Mộ Đứng",
    [154857609] = "Tất cả kẻ địch <b>Fell</b> trong vòng <b>5</b> mét nhận <b>1 sát thương Lửa</b> mỗi điểm Trí Tuệ mỗi giây.",
    [155019495] = "Mật Snapjaw",
    [155410424] = "Đến Thành Phố Phía Sau Dãy Núi",
    [155446583] = "Tăng tốc độ sản xuất cho các vật phẩm trong xưởng.",
    [155824333] = "Chà, xem ai đã trở lại này!",
    [156076466] = "Vật phẩm thu thập này được tìm thấy ở Springlands.",
    [156293701] = "Đây là nơi trưng bày các Cổ Vật Hollow thường được tìm thấy trong các Sảnh Đường Hollow.",
    [156740272] = "Một loại trà thảo mộc đậm đà. Nó giúp tăng MP và SP của bạn.",
    [158068989] = "Tìm Các Khối Đá Mài Bóng",
    [158163169] = "Tìm Tất Cả Các Mảnh Phù Điêu Drak",
    [159167599] = "Điều chỉnh tần suất xuất hiện của thời tiết khắc nghiệt.",
    [159855939] = "Thư Đã Chuyển",
    [160083430] = "Ràng Buộc Bằng Máu",
    [162481422] = "Đèn Chùm Bạc Treo",
    [162688596] = "Sát thương rơi giảm một nửa. Tốc độ leo tường và thang tăng gấp đôi.",
    [162888775] = "Mật mã",
    [163291491] = "Móng Vuốt Kền Kền Bị Phủ Bóng",
    [163388145] = "Tinh chất Sương độc dạng lỏng, thu hoạch từ các chồi non Sương độc bao phủ của quần xã sinh vật Lò xo.\n\nDung dịch màu nâu tỏa ra hơi màu tím và được sử dụng cho nhiều mục đích giả kim thuật mạnh mẽ.",
    [163730354] = "Ghi chép từ nhà nghiên cứu <lorename>Loraine Crim</lorename> chi tiết vị trí của các đài tưởng niệm tại Revelwood, Nomad Highlands và Kindlewastes.\n\nHãy đọc đài tưởng niệm tại Nomad Highlands để tiếp tục!\n\nĐọc tất cả các đài tưởng niệm nêu trên để hoàn thành nhiệm vụ!",
    [163820404] = "Một Chiếc Đèn Lồng Cho Mei",
    [164352157] = "Đường Ván Lưu Vực Vực Nước I",
    [164569412] = "Cung Ngắn Rừng Hoang",
    [164611558] = "Thời Gian Hiệu Ứng",
    [164969788] = "Những mặt sáng và tối của đá mài bóng. Chúng gợi nhớ đến nghề thợ đá, hoặc bi thảm hơn là những bức tượng nơi nghĩa trang.\n\nBảng màu này có thể được chế tạo từ các nguyên liệu ở Springlands.",
    [165484064] = "Anh trai thân mến: Hãy bình tâm — em vẫn bình an vô sự. Những cung thủ không bao giờ theo kịp tốc độ của em và Đội Tuần Tra Biên Giới đầy rẫy sơ hở. Em đã thoát khỏi Đỉnh Howling và đến được Revelwood trước khi quân đội kịp điều động.\n\nLãnh chúa <lorename>Vorgoth</lorename> đã phát điên rồi, <lorename>Talion</lorename>. Tâm trí ông ta đã bị Sương độc nuốt chửng! <i>Ông ta đã lừa dối chúng ta.</i> Vua <lorename>Gormander</lorename> không phải là mối đe dọa! Em không thể chiến đấu vì điều này, và những vết sẹo của em là minh chứng cho điều đó. Em mang chúng với niềm tự hào, vì biết mình đã làm điều đúng đắn.\n\nPlease come. Hãy từ bỏ chiến tranh. Hãy quay lưng lại với tất cả những thứ này.\n\nEm nhớ anh, đồ lùn.\n\n— Athalan",
    [166034160] = "Lưỡi Kiếm Băng",
    [166056844] = "Tốc Độ Sản Xuất Của Xưởng",
    [166154735] = "Rochelle Anders",
    [166221347] = "Một khối xây dựng làm từ cẩm thạch mài bóng. Nó đen tối như bầu trời đêm.",
    [166344778] = "Các thế giới lưu cục bộ",
    [166417752] = "Rơm",
    [166902427] = "Trong Sương độc Chết Chóc",
    [167090898] = "Bình Đất Sét II",
    [167786867] = "Cây Giống Hoa Hoang Mạc Lửa",
    [168482466] = "Tiên Đan Cho Tất Cả",
    [168780918] = "Áo Giáp Trinh Sát",
    [168815743] = "Embervale đã sụp đổ, bị nuốt chửng bởi \"Sương độc\". Hãy mang ánh sáng trở lại và <b>giành lại vùng đất bằng cách thiết lập một Tế Đàn Ngọn lửa</b> nơi hoang dã!\n\nMột địa điểm đầy hứa hẹn để thiết lập Tế Đàn Ngọn lửa đã được đánh dấu trên bản đồ của bạn. Hãy đến đó để tiếp tục.",
    [169960447] = "Kho báu của <lorename>Gormander</lorename> được đồn đại là đã bị chôn vùi đâu đó trong Ngự Uyển của <location><lorename>Pikemead</lorename>'s Reach</location>. Hãy tìm nó!",
    [170054225] = "Tìm Các Khối Đá Hắc Diệu",
    [170589749] = "Cường hóa vật phẩm sẽ mở khóa các đặc kỹ mới.",
    [171151508] = "Một chiếc mũ cối chắc chắn bảo vệ người đội khỏi những nhát chém, vết cắt và sẹo.",
    [171181682] = "Một phần của Bộ Giáp Pháp Sư.",
    [171309650] = "Răng Gỗ",
    [171575355] = "Choáng Váng",
    [171591903] = "Trích Huyết",
    [172028728] = "Chọn hình dạng bạn muốn xây dựng.",
    [172370558] = "Cùng Nhau Sinh Tồn",
    [172514387] = "Người Mang Ánh Sáng",
    [172780723] = "<lorename>Sameth</lorename> Yêu Cầu Điều Đó",
    [172985029] = "Chậu Đất Sét I",
    [173088825] = "Dao Băm Thịt",
    [173106287] = "Các đòn tấn công của bạn gây hiệu ứng trúng độc lên kẻ địch.",
    [173396256] = "Khả năng kích hoạt tế đàn",
    [174290110] = "Đĩa Đồng Đỏ",
    [174350025] = "Kiên nhẫn và cẩn trọng nhé, bạn hữu!",
    [175186722] = "<lorename>Braelyn</lorename>",
    [175730818] = "Trang trí",
    [175862259] = "Săn Màu Tóc: Gia Vị Đỏ Thắm",
    [175997141] = "Một Lá Thư Kỳ Lạ",
    [176006952] = "Sát thương",
    [176089346] = "Những phát bắn của bạn sẽ luôn trúng đích với đôi găng tay này.",
    [176227438] = "Em trai của ta, mọi hy vọng dường như đã vụt tắt với ta. Cô y tá, Helên, nói rằng ta chẳng thể làm gì ngoài việc nghỉ ngơi... Nhưng ta sẽ không chấp nhận điều đó. \n\nNgười dân vùng Kindlewastes, họ nói về các Cổ Nhân như thể họ có thể làm được mọi thứ... <i>em có nhớ đài tưởng niệm không? Nơi chúng ta thường chơi đùa khi còn nhỏ? Ta sẽ tìm đường đến đó, bất kể thế nào.</i> \nCó lẽ vẫn còn phương thuốc cho ta. Đừng đi theo — em không thể ngăn cản ta đâu. \n\n— Vettel",
    [176356021] = "Sử dụng Ngọn Lửa để thay đổi Kỹ năng và hoàn lại Điểm Kỹ năng của bạn.",
    [176586953] = "Tân Tinh",
    [177013481] = "Bảo Vệ Tầm Xa",
    [177394311] = "Ấm áp, nhẹ nhàng và linh hoạt. Mảnh giáp này rất phù hợp cho những nhà thám hiểm! Chiếc khăn quàng đỏ trông đặc biệt táo bạo.",
    [177733451] = "<npc>Thợ Mộc</npc> đã mượn <b>chiếc rương</b> của <npc>Thợ Rèn</npc>. Anh ta đã mang nó đến một <b>khu cắm trại cũ</b> để hoàn thành một số dự án. ",
    [178592034] = "Sức mạnh cổ xưa đang ngủ say trong lưỡi kiếm này. Nó cộng hưởng, thì thầm và hát vang với những ai dám lắng nghe.",
    [178825512] = "Trang Bị Chất Lượng",
    [178850269] = "Tùy chỉnh",
    [179125471] = "Kẻ thống trị Scavenger",
    [179212074] = "Vương quốc đã sụp đổ, bị nuốt chửng bởi Sương độc. Thế giới cũ giờ chỉ còn là đống đổ nát. Ngươi đã được đánh thức bởi Ngọn Lửa vĩnh cửu. Còn nhiều điều phải học lắm, đứa trẻ ạ. Hãy tiến lên.",
    [179269006] = "Tần Suất Kẻ Địch Tấn Công",
    [179845092] = "https://Sương độc bao phủ.zendesk.com/hc/en-us/requests/new?ticket_form_id=13781260232861",
    [179979559] = "Ta Cần Sự Giúp Đỡ Của Ngươi",
    [180578954] = "Trở Lại Làm Việc",
    [180895696] = "Một Ánh Sáng Chói Lòa Trên Bầu Trời",
    [180998672] = "Tinh thần hoang dã của Blackmire vẫn chưa bị khuất phục. \n\nNhững rễ cây uốn lượn quấn lấy chúng ta, vặn xoắn mọi nỗ lực của đồng bào ta. Mọi thứ dần tan biến vào âm thanh của màn đêm, một bản giao hưởng của những giai điệu ngọt ngào và u sầu. \n\nChúng ta chìm đắm trong đó như lũ côn trùng trong đầm lầy nước đen, bị những dây leo kéo xuống dưới. Một nguồn năng lượng không giới hạn, tỏa sáng rực rỡ như những vì sao.",
    [181067973] = "À, ngươi đã mang theo một ít trà thảo mộc cay nồng. Màu sắc này... trông quen lắm. Đó là gì nhỉ? Nghệ- không, đừng nói cho ta biết. Nghệ tây, loại gia vị đỏ tươi, tất nhiên rồi! Mhhh... đỏ tươi hả? Nghe có vẻ là một màu mới tuyệt vời để tạo ra đấy! Ồ, tạ ơn các vì sao! Và cả ngươi nữa, dĩ nhiên rồi! Hãy cầm lấy trà và ngồi xuống ghế salon của ta! Ngươi nên thưởng thức hương vị đó trong khi ta thực hiện phép thuật màu sắc lên ngươi!",
    [181823558] = "Vườn Bí Ngô",
    [181835471] = "Ta Không Phù Hợp Với Việc Này",
    [182207873] = "Về Thuốc Tiên",
    [182212632] = "Một cây Gậy phép ma thuật, sử dụng sức mạnh của bóng tối để thi triển những phép thuật mạnh mẽ hơn. Một công cụ hùng mạnh khiến mọi pháp sư đều phải khiếp sợ.\nGậy phép có thể thi triển <b>phép thuật</b> bằng cách sử dụng tích năng phép và MP. Hãy trang bị <b>tích năng phép</b> để thi triển.",
    [182655195] = "Đang Ngủ",
    [182692030] = "Bờ Biển Ngọc Lục Bảo Và Biển Đỏ Thắm",
    [182841896] = "Lưỡi của những con dao găm này có hình dạng như mỏ của một con đại bàng đang bay lượn, sẵn sàng lao xuống tấn công kẻ thù.\n\n<b>Sự Tinh Tế:</b>\nSát thương gây ra bởi vũ khí này tỉ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công đặc biệt sau khi đỡ đòn thành công.",
    [183111499] = "Các Xưởng",
    [183574580] = "Ahhh, ta cảm thấy thật sảng khoái! Cứ như thể ta đã ngủ hàng thế kỷ vậy! Ồ, tên ta là Anton Godwin! Rất vui được gặp ngươi, người bạn mới của ta!",
    [183940555] = "Chiến Lợi Phẩm",
    [184273621] = "Một Bài Kiểm Tra Kỹ Năng",
    [184436152] = "Thợ Làm Bánh Xe",
    [184500412] = "Đó có phải là một trong những người dì của ta không? Tuyệt vời! Thật kỳ diệu! Và không chỉ là bất kỳ người dì nào - Braelyn, người dì yêu thích của ta! Cảm ơn ngươi, Hỏa Nhân! Khi ta giao nhiệm vụ tìm kiếm gia đình cho ngươi, ta chỉ nói đùa một nửa thôi!",
    [185394912] = "Trong Một Thế Giới Định Sẵn Sẽ Sụp Đổ\n",
    [186143519] = "Có thể sử dụng với",
    [186550217] = "https://twitch.Sương độc bao phủ.com/en-US",
    [187118275] = "Quần dài được làm từ một loại chất liệu rất cứng.",
    [187678498] = "Bờ Đá",
    [187769471] = "Chỉnh sửa Sơ đồ Điều khiển Tùy chỉnh hiện có",
    [187880439] = "Vẻ Quyến Rũ U Ám",
    [188479250] = "Trang Phục Thợ Săn",
    [188663588] = "Ngươi đã đến được ngôi mộ rùng rợn. Bên trong là những mảnh vỡ rải rác của một bộ giáp trang trí đáng sợ!\n\nHãy khám phá bên trong để thu thập lại tất cả các mảnh! Có tổng cộng 5 mảnh.",
    [188848285] = "Tăng hệ số sát thương của <b>Đòn Tấn Công Tàn Nhẫn</b> và <b>Đòn Tấn Công Lén Lút</b> thêm <b>+100%</b>. ",
    [189188866] = "Hàng Rào Gỗ Đơn Giản",
    [189690851] = "Sử Dụng Tường Leo",
    [190307047] = "Ngươi đã đến được thành phố bên hồ. Một phần của bến cảng đã bị Sương độc nuốt chửng, nhưng một đôi mắt tinh tường có thể nhận ra đỉnh của một ngọn hải đăng không xa.\n\nHãy đến ngọn hải đăng và tìm kiếm bên trong để tìm thấy một nguồn tri thức mới!",
    [191456997] = "Quặng Thiếc",
    [191518443] = "Cái cống này sẽ thoát sạch nước bên trên nó. Có thể đặt trên sàn.",
    [192514812] = "Khối Giếng",
    [192668025] = "Bạn tìm thấy một mảnh giấy ghi rằng chủ nhân của một ngôi nhà tại <location>Sapphire Strand</location> đã dự định lợp mái ngói. Vì cộng sự của ông ta phản đối, các Khối Xây Dựng hẳn vẫn còn ở đâu đó quanh đây.\n\nHãy tìm Khối Mái Ngói Sa Mạc.",
    [192934388] = "1m",
    [193242426] = "Hộp 4m",
    [193930668] = "Ký Ức Của Thợ Cắt Tóc",
    [194570746] = "Cây Giống Tre",
    [194695046] = "Tên",
    [195132648] = "Sắc màu lạnh nhạt của chiếc quần này tạo nên sự tương phản rõ rệt với những điểm nhấn rực lửa trên phần còn lại của bộ giáp.",
    [195942317] = "Địa điểm",
    [195947633] = "Ahh... thật nhiều linh hồn... nhưng quá ít thời gian... Giá như ta có một người chăn dắt đồng hành để trợ giúp. Một kẻ mà cuộc đời và diện mạo đã bị gột rửa, một cái vỏ để ta lấp đầy — một khối đất sét đậm chất người để ta nhào nặn lại. Ta có thể cảm nhận được nó: Nó đang lảng vảng ở khoảng không giữa thế giới này và thế giới bên kia. Hãy mang nó đến đây!",
    [196186667] = "Tiên Dược",
    [196985122] = "Tôi tưởng tượng \"<location>Morwenna</location>\" sẽ thật tĩnh lặng và yên bình... nếu không có lũ <b>sâu bọ</b> đó!\n\nChúng gặm nhấm mọi thứ tôi xây dựng! Từ chuồng trại đến dinh thự, đài tưởng niệm đến trang viên... đều bị lũ <b>dã thú</b> xé nát! Cứ như thể chúng đang cười nhạo nghệ thuật của tôi vậy!\n\nChúng không phải lúc nào cũng hung dữ như thế. Có lẽ do bị ép phải rời bỏ môi trường sống tự nhiên? Hay là do <i>mầm bệnh đang lan rộng</i> mà mọi người vẫn xì xào? Dì <lorename>Irvetta</lorename> nói rằng chúng trông có vẻ \"sợ hãi\" hơn bất cứ điều gì khác. Dì yêu quý bảo tôi không thể thấy được sự thật này — vì tôi chỉ có một mắt. Tôi chẳng thấy lời đùa này buồn cười chút nào.\n\nCade Hawthorn",
    [197806245] = "Dành cho Thủy thủ đoàn & Người bốc xếp\n\nHÀNG HÓA ĐẾN / ĐI:\n\nPrincess Sue (Dự kiến: Thứ Ba)\n- Bốc 12 thùng (đinh & gỗ) từ Kho bên trái\n\nDainty Beluga (Đến hôm nay – Dừng chân ngắn)\n- Chuyển các bao ngũ cốc ngay khi cập bến\n\nOceanwasp (Dự kiến: Chưa rõ)\n- Tàu nhỏ. Đơn hàng đặc biệt: 1x Trống Handpan – Hiện đang ở trên bệ nâng (Lưu ý: Bệ lại bị kẹt – cần bảo trì gấp)\n\nGormander's Seascaper (Đang chờ đến – ngày chưa xác định)\n- Cần, trích nguyên văn: \"Càng nhiều hạt cà phê càng tốt – ta còn cả một vương quốc phải điều hành đấy!\"\n- Các vật liệu bổ sung cần được lưu kho cho đến khi tàu đến. Kho bên phải.\n- Dave & Darrel được phân công xử lý kho bãi\n\nLƯU Ý:\n<i>Gần đây có ai thấy Dave hay Darrel không? Họ đáng lẽ phải đang quản lý kho, nhưng mấy ngày nay không thấy xuất hiện trên bến tàu. Nếu tìm thấy, hãy bảo họ đến gặp chúng tôi.</i>\n\n– Văn phòng Bến tàu",
    [198525660] = "Tỉ lệ Văn bản",
    [198979796] = "Thời gian trong Sương độc tăng lên.",
    [200284783] = "Thảm Rơm",
    [200997355] = "Lại đây nào, ta cùng uống! Một bài ca tặng Nữ hoàng thời trẻ!\n3 đứa trẻ trên tay, chén rượu đầy tràn\nNghĩ gì nói nấy, bà đã hát vang:\n\nThà là mật ong trong chén,\nhay chén đầy rượu rum\nuống cho thật say,\ncòn hơn là ngừng nghỉ!\n\nKhông thể chỉ uống một chút,\nNên hãy chia sẻ cùng nhau,\nuống cho thật say,\ncòn hơn chỉ uống một ly!\n\nThà là mật ong trong đầu,\nvà đầu óc quay cuồng\nCòn hơn đầu trên ngọn giáo\nmà chẳng có giọt nào!\n\nLấy rượu rum, và mật ong\nĐổ mật ong vào chén\nNâng chén lên đầu\nuống cạn đi nào!",
    [201086259] = "Ô Thanh Hành Động 6",
    [201159754] = "Trận chiến cuối cùng với lũ Fell đã để lại sẹo cho bạn. Bạn vẫn chưa thể nắm bắt được tình hình, nhưng mỗi khi bước vào Sương độc, làn sương mù ngột ngạt sẽ khiến bạn nghẹt thở nhanh hơn nhiều.\n\nBạn nên <b>hỏi Nhà Giả Kim</b> về phương thuốc để đảm bảo căn bệnh mới này không ảnh hưởng lâu dài đến sinh lực của bạn.",
    [201220032] = "Cấp Ngọc Tối Đa: %k",
    [201398150] = "Gần đây, tôi không khỏi thắc mắc... lũ Vukah vốn luôn là những sinh vật ủ rũ — gắn liền với hang động của chúng. Nhưng chúng lại đang di chuyển về phía đông, đầy giận dữ... Có lẽ điều này cần được điều tra. Có thể tại <b>địa điểm tập trung</b> của chúng, bạn sẽ tìm thấy câu trả lời. Sẽ rất hữu ích nếu biết chúng đang âm mưu chuyện gì...",
    [203546037] = "Khối Đá Lửa Thô",
    [204358933] = "Mở",
    [204367538] = "Điều tra điểm dừng thứ hai trên lộ trình vận chuyển của Kaori để tìm chiếc mũ tiếp theo!",
    [204809230] = "Mở rộng Khu vực Xây dựng lên 75m × 75m.",
    [204871984] = "Tham gia Discord của chúng tôi",
    [205089533] = "Một quả mìn nổ, sẽ phát nổ khi chạm vào dù là đồng minh hay kẻ thù. Tốt nhất nên xử lý cẩn thận.",
    [205291266] = "ST Dao",
    [205628871] = "FSR3",
    [205730463] = "Một Khối Đá Sa Thạch Thông Thường. Rất tiết kiệm chi phí.",
    [205731294] = "Máy Nghiền Tiên Dược",
    [206225976] = "Lưỡi Kiếm Độc",
    [207045032] = "Bạn hiện đang thực hiện lại một Nhiệm vụ Embervale. Một số dấu mốc trên bản đồ sẽ không hiển thị cho đến khi bạn khám phá ra chúng hoặc rời khỏi chế độ tiến trình cá nhân.",
    [207427885] = "Khung Cửa Sổ Chạm Khắc Tròn",
    [207605515] = "Bùn Sương độc",
    [207698719] = "Một Thông Điệp Hay Một Cơn Ác Mộng?",
    [208009821] = "Nấm Russula Xanh Nướng",
    [208013665] = "Các Vị Thần Drak",
    [208093901] = "Độ Trễ Hồi Phục HP",
    [208180149] = "Lao mình vào trận chiến và vinh quang với sự bảo vệ của chiếc khiên này!",
    [208262853] = "Giày Quân Vương U Ám",
    [208427318] = "Nghi ngờ của ta về Helga là đúng – cô ta đã không chung thủy. Lại còn với Rodrick, tên tội phạm ngu xuẩn đó!\n\nChúng nhắm vào tài sản của ta, nên ta sẽ dẫn dụ Helga vào bẫy. Ta đã đăng một mẩu quảng cáo trên tờ Tuần báo The Pike, khẩn cầu cô ta đến uống rượu tại phòng riêng của nhà trọ nơi chúng ta gặp nhau lần đầu. Ở đó, cô ta sẽ tìm thấy thứ mà mình không thể cưỡng lại: một ly rượu vang pha thuốc độc. Ta sẽ kết liễu người đàn bà khốn khiếp đó!",
    [209244666] = "Bộ Xạ Thủ",
    [209463384] = "Một chất độc hại, ngày nay được coi là hiếm do quy trình chiết xuất nguy hiểm.",
    [210364347] = "Thịt",
    [210438441] = "Bình Đất Sét VI",
    [211066688] = "Nơi Trú Ẩn",
    [211178072] = "Giày Mùa Đông",
    [211378410] = "Ngọn lửa bên trong bạn <b>bảo vệ bạn khỏi Sương độc, nhưng không phải là vô thời hạn.</b> Hãy để ý thời gian còn lại của bạn <b>khi bị Sương độc bao phủ và rời đi để phục hồi.</b> Khi hết giờ, bạn sẽ chết.\n\nTìm <b>vỏ nang đồng hồ cát phát sáng</b> bên trong Sương độc để có một cú hích và bổ sung tức thời. Vỏ nang đồng hồ cát sẽ bị tiêu thụ khi tương tác, và không thể nhặt hoặc mang theo.",
    [211643480] = "Chúc bạn có một chuyến hải trình tốt đẹp.",
    [211944889] = "Cường Hóa Ngọn Lửa",
    [212200432] = "Ô Hình Dạng Xây Dựng 9",
    [213221710] = "Bia mộ: không có",
    [213924049] = "Gunther đã kể cho bạn về một tấm thảm treo tường bị rách mà ông ấy đã làm trước khi được điều động đến trạm gác cuối cùng. Mảnh đầu tiên hẳn được giấu trong Đồn trú Balefire.\n\nHãy đến Đồn trú Balefire và tìm mảnh thảm treo tường!",
    [214017802] = "Một giàn giáo cho phép bạn chạm tới những điểm cao hơn khi xây dựng căn cứ.",
    [214204725] = "Nếu chúng ta nhận nuôi một con Chuột lang nước, mình sẽ đặt tên nó là Carmyn. Hay là Thuyền trưởng Capybara? Hay có lẽ là Capoodle the Oodle? Ôi, nhiều lựa chọn quá...",
    [214536660] = "Linh Hồn Dân Làng Thất Lạc",
    [215103596] = "Ngọn lửa của chúng ta vẫn cháy.",
    [215332943] = "Phòng Ngai Vàng Cromville",
    [215602876] = "Phải kích hoạt ít nhất một vai trò để bắt đầu phiên chơi nhiều người!",
    [215909228] = "Chặt Và Băm",
    [216679055] = "Bộ Bài Tarot Phụ",
    [216908413] = "Bạn đã đến khu định cư của người Vukah bên cái cây khổng lồ. Hãy leo lên đỉnh cây và lục soát khu định cư để tìm chiếc trống tay bị mất!",
    [217690477] = "Quặng Bạc",
    [217854403] = "Vị Khách Kỳ Lạ Nhất",
    [218307395] = "Phao va phải vật cản.",
    [218932295] = "Tìm Tất Cả Công Thức Chế Tạo Ẩn Trong Blackmire",
    [219181722] = "Chủ đề trò chuyện mới!",
    [219452026] = "Đại Úy Melville Fontane",
    [219658121] = "Ta Phải Bảo Vệ Vũ Khí",
    [219934874] = "Đạn ma thuật cải tiến tạo ra một tia băng duy nhất, gây sát thương cho kẻ địch khi va chạm và làm chậm chúng sau đó.\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để thi triển bằng <b>gậy phép.</b>",
    [220849195] = "Rìu Cánh Vực Thẳm",
    [221249541] = "Những Thứ Xa Hoa Trong Đời",
    [221620524] = "Chiến Tích Của Ngọn Lửa",
    [222354776] = "Bộ trang phục này được giữ cố định bằng những chiếc cúc gỗ sồi, một chiếc thắt lưng dệt và chính ma thuật! Tuy nhiên, những chiếc cúc mới là thứ gánh vác phần lớn công việc.",
    [222844170] = "Một mảnh giấy đề cập đến những âm thanh bất thường phát ra từ một giếng nước gần đó, nơi một người mang theo chiếc búa lớn đã đến để điều tra. <b>Hãy lục soát khu vực và cố gắng tìm chiếc búa!</b>",
    [222914513] = "Tắt Giọng Nói",
    [223089639] = "Một hóa thạch cúc đá lớn ấn tượng. Di tích của loài động vật chân đầu biển này từng là nơi trú ngụ của một sinh vật biển lớn có xúc tu. Theo mê tín ở Embervale, mỗi vành có thể nhận dạng kéo dài từ tâm vòng xoắn được cho là sẽ ban tặng một ngày may mắn.\n\nVật phẩm thu thập này được tìm thấy ở Springlands.",
    [223249526] = "Mặt trời sẽ không chìm nghỉm trong bóng đêm. Nó sẽ lại trỗi dậy.",
    [224291287] = "Mũ Giáp Chim Ưng",
    [224344578] = "Trung bình",
    [224862728] = "Chùy Bất Hạnh",
    [225044621] = "Thưa Ngài,\n\nNgài đang thử thách ý chí của <lorename>Kẻ Hành Khất Bí Ẩn</lorename>. <i>Bóng ma biết tâm trí ngài vốn hay thay đổi.</i>\n\nLời đề nghị của tôi rất công bằng, nhưng sự im lặng của ngài đã nói lên tất cả. Mặc dù tôi tìm đến nhà ngài với ý định hòa bình, ngài lại đe dọa tôi bằng bạo lực! Tôi mang đến thông điệp từ các vị thần, đồ ngốc ạ! Bất kể câu trả lời của ngài là gì — tôi phải thu hồi nguồn tài nguyên quý giá nằm sâu trong lòng đất. Nó sẽ không còn là đất của ngài nữa! Ngài sẽ thấy sự trừng phạt của tôi trông như thế nào!\n\n<i>Bóng ma sẽ đan xen sợi dây định mệnh của ngài với chính bóng tối.</i> Ngài không thể quay đầu lại được nữa. Sợi chỉ đã được dệt xong.\n\n— CM",
    [225366372] = "Tủ Búp Phê Hầm Mộ Lớn",
    [225880741] = "Kháng Sương độc",
    [226093048] = "Chỉ số này tăng sát thương khai thác. Sát thương khai thác cao hơn dẫn đến khả năng biến đổi địa hình tăng lên và thu được nhiều tài nguyên hơn sau mỗi lần đập.",
    [226136376] = "https://www.Sương độc bao phủ.com/privacypolicy",
    [226289461] = "Hãy Giữ Kín Chuyện Này Giữa Chúng Ta!",
    [227110894] = "Tăng Giáp Kháng Đòn Đập",
    [227393282] = "Cổng Hàng Rào Nhà Tù",
    [227627831] = "Thế giới này chứa nhiều thực thể và/hoặc nước hơn mức phần cứng có thể xử lý ổn định. Vui lòng liên hệ bộ phận hỗ trợ khách hàng.",
    [228740524] = "Thay đổi",
    [228970950] = "Bất kể họ nói gì, anh không thể từ bỏ em. Anh biết em vẫn còn ở ngoài kia, Sophie, bị giam cầm bởi trái tim của Sương độc.\n\nNgọn tháp này không còn là nhà nếu thiếu em. Những đầu ngón tay anh lần theo những trang giấy mục nát mà chúng ta đã thề sẽ giữ an toàn. Những con chữ mờ dần trôi khỏi tâm trí anh như ký ức về em khi Sương độc kéo đến.\nBut không giống như em, anh không thể trốn thoát. Anh không bao giờ có thể chạy trốn khỏi những điều anh đã nói với em... bởi vì mỗi khi anh soi gương, anh lại thấy em nhìn lại mình, em gái à.\n\nKhi vạn vật im lìm trong đêm tĩnh mịch, anh nghe tiếng em khóc vang vọng khắp những sảnh đường trống vắng này.\nCó lẽ linh hồn em sẽ trở về ám ảnh anh. Và có lẽ anh xứng đáng với điều đó.\n\nEm là một nửa của anh. Một hình ảnh phản chiếu qua gương. Sự hối tiếc và mất mát lớn nhất của anh.\nAnh nhớ em, Sophie. Hãy quay về đi.",
    [229575803] = "Pha Lê Tối Lấp Lánh",
    [229794162] = "Lên",
    [230062192] = "Máy Nạo Vét",
    [230116953] = "Lũ cướp đã bao vây chúng ta suốt hai ngày qua, tấn công từ phía cây cầu. Đôi mắt của chúng... thật điên cuồng... Chúng ta đã cầm cự được cho đến nay — nhưng cũng chỉ vừa đủ.\n\nChúng ta có thể không sống sót qua đợt tấn công tiếp theo. Ta đã ra lệnh gài bẫy con đèo bằng những khí giới cuối cùng. Nếu lũ <b>Scavenger<b> quay lại, CHÚNG TA ĐÃ SẴN SÀNG.\n\n— <lorename>Thuyền trưởng Arkwright</lorename>",
    [230751919] = "Tìm Chiếc Búa",
    [231003241] = "Quần Thuật Sĩ",
    [231303717] = "Mái Phẳng",
    [231515802] = "Góc Vải Bạt",
    [231578948] = "%k chào hỏi",
    [232423837] = "Khối Đá Sa Thạch Pha Trộn",
    [232746048] = "Samuel",
    [233043481] = "Một nguồn sáng bền bỉ và lâu dài làm từ sáp. Hãy trang bị nó trước khi bắt đầu cuộc thám hiểm vào cõi vô định!",
    [233325786] = "Nắp Quan Tài Lớn",
    [234516336] = "Đã nhận được Lông Thú",
    [234961633] = "Định mệnh của Thống soái <lorename>Cyrus</lorename>",
    [235247107] = "Thú nhồi bông dễ thương này khiến những sinh vật đáng sợ trở nên gần gũi hơn nhiều.",
    [235328862] = "Ngọn Lửa đã báo hiệu cho bạn về một con đường mới mở dẫn vào vùng đất hoang vu của Revelwood. Hãy đến khu vực được đánh dấu trên bản đồ để khám phá vùng hoang dã chưa được thuần hóa!",
    [235335158] = "Còn thở? Kiểm tra xong. Chân? Nguyên vẹn. Thậm chí còn đá được. Mũi? Hết gãy rồi. Đầu óc... chắc là đang ảo giác! Ngươi có thật không đấy? Rất vui được gặp! Ta là Braelyn Hawthorn — một lữ khách, thợ mộc, và là một người cô đáng tự hào. Ngươi xây nơi này à...? Kiến trúc đá thật tuyệt vời! Ta đã học được vài kỹ thuật trong những chuyến đi của mình. Nếu cần giúp một tay xây dựng — cứ gọi ta một tiếng!",
    [235477921] = "Bộ Đồ Quản Ngục",
    [235741656] = "Một chiếc Cào được gia cố bằng kim loại phế liệu để tăng độ bền và tốc độ. Một công cụ tốt để san bằng những vùng đất đồi núi.",
    [235954927] = "Đàn Lute là nhạc cụ cổ điển được các thi sĩ lựa chọn. Chúng có thể được dùng để chơi những giai điệu tuyệt đẹp cùng bạn bè hoặc độc tấu.",
    [236211332] = "Tìm Kiếm Người Sống Sót",
    [236275063] = "Khi tung đòn chí mạng bằng vũ khí tầm xa, bạn gây gấp đôi sát thương.",
    [236477635] = "Mũ Giáp Kẻ Săn Đầu Lâu",
    [236644739] = "Hành Trình Qua Vùng Đất Hoang",
    [237268185] = "Mặc định",
    [237371236] = "Điều chỉnh xẻng",
    [237794594] = "Tìm thấy vào ban đêm",
    [238305500] = " <npc>Thợ Rèn</npc> Oswald Anders giải thích rằng việc ăn uống và nghỉ ngơi trong một <b>môi trường ấm áp và được che chắn là rất quan trọng để chuẩn bị cho cuộc phiêu lưu.</b>\n\nDành thời gian trong một ngôi nhà <b>thoải mái</b> sẽ kích hoạt <b>hiệu ứng nghỉ ngơi tốt</b>.",
    [238546823] = "Sắc Màu Của Lưu Vực Veilwater",
    [238603296] = "Thay thế",
    [238958103] = "Đuốc Đứng Hầm Mộ",
    [239377906] = "Bàn Hầm Mộ Nhỏ",
    [239437521] = "Móc Đu",
    [239545926] = "Sơ đồ điều khiển",
    [239662826] = "Cây Tầm Ma Non",
    [239722252] = "Bao Tải Tiếp Tế IV",
    [241360404] = "Tinh thần dẫn lối bạn.",
    [241628831] = "Đặt <craftingstation>Xưởng Thuộc Da</craftingstation>",
    [241636231] = "Nước quá nông.",
    [241679472] = "Mũ bảo hiểm thợ mỏ có gắn đèn.",
    [242100243] = "Đặt các vật phẩm từ hành trang của bạn vào đây để cung cấp cho nhà máy.",
    [242155680] = "Trên Những Đỉnh Núi Lộng Gió Này",
    [244324677] = "Bạn nhận được 5 phút hiệu ứng Nghỉ Ngơi. Chỉ có thể sử dụng mỗi 30 phút một lần.",
    [244490799] = "Bạn thấy nó hiện ra trước mắt: Một gã khổng lồ, chìm sâu trong đại dương xanh thẳm, điều khiển thủy triều bằng mỗi hơi thở ra nặng nề, kéo dài. Vực thẳm đang vẫy gọi. Liệu bạn có đáp lời?",
    [244698257] = "Hỗ trợ tiếp cận",
    [245443349] = "Tinh thần thì thầm. Hãy lắng nghe thật kỹ.",
    [245494810] = "Một bảng màu xanh lá tươi sáng, gợi nhớ đến tảo, bụi rậm và ẩm thực của tộc Drak.\n\nBảng màu này có thể được chế tạo bằng nguyên liệu từ Lưu Vực Veilwater.",
    [245716860] = "Ta biết ngươi đang bận, bạn hữu ạ. Nhưng, cái <craftingstation>Cối Giã</craftingstation> của ta... nó sẽ giúp ích biết bao!",
    [245977173] = "Đối mặt với sự diệt vong, Cổ Nhân và loài người đã hợp lực để rèn nên Hỏa Tộc.",
    [246018736] = "Một bộ dao thô sơ, vũ khí phụ được lựa chọn bởi các cung thủ.\n\n<b>Tinh tế:</b>\nSát thương gây ra bởi vũ khí này tăng theo chỉ số khéo léo của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [246217533] = "Bạn biết được rằng một nô lệ đã lên kế hoạch trốn thoát khỏi Mỏ Đá Cẩm Thạch Hồ Camellia.\n\nCuộc đào tẩu của hắn chắc chắn đã bị ngăn chặn. Hãy tìm kiếm khu vực được đánh dấu trên bản đồ để tìm kẻ đào tẩu!",
    [246594698] = "Giá Để Vũ Khí Trượng",
    [246761917] = "Những ngọn tháp này vươn tới tận vòm trời và từ chối những kẻ không xứng đáng bước vào. Giống loài cổ xưa tiến vào, nhưng ta chưa bao giờ thấy họ trở ra... Ta có 2 giả thuyết: 1. Các Ngọn Tháp Cổ Đại bằng cách nào đó được kết nối với nhau, và những kẻ thầm lặng <i>du hành giữa chúng</i> theo ý muốn. \n2. Các Ngọn Tháp Cổ Đại đóng vai trò như một nơi chôn cất, tương tự như Đền Thờ Ngọn Lửa. Các Cổ Nhân lưu trữ tất cả <i>tri thức của vùng đất</i> vào Ngọn Lửa tại đây khi họ rời bỏ cõi trần.\n\nDù thế nào đi nữa, ta cũng không thể vào được. Khi ta <b>bước lên tấm phiến trang trí</b>, chẳng có chuyện gì xảy ra cả. Thật đáng tiếc.\n— Balthazar",
    [247447687] = "Bạn đã đánh thức đồng loại của mình! Ngọn Lửa rất hài lòng. Hãy tìm kiếm thêm những người sống sót đang say ngủ ở <b>Springlands</b>.",
    [248083880] = "• Lão Fen đã trộm lại vật phẩm cúng tế của chính mình. Lão ta đang trở nên tham lam.\n• Ta thấy Học Giả lại rời thị trấn. Ông ta không đi một mình — và cũng không đi cùng vợ.\n• Eldon không còn cầu nguyện nữa. Chỉ giả vờ khi có người khác đang nhìn.\n• Mira không còn—\n\n(Ghi chép kết thúc đột ngột. Có những vết máu bắn tung tóe trên trang giấy.)",
    [248329690] = "Hàng Rào Đá",
    [248388558] = "Một phần của Bộ Giáp Fowler.",
    [248956774] = "Điểm Kinh Nghiệm",
    [249031791] = "Cửa Gỗ Thô Sơ",
    [250512733] = "Một bản nhạc cho một bài hát u sầu để chơi dưới ánh trăng.\n\n<b>Bản Nhạc</b>: \nCác Bản Nhạc sẽ dạy bạn một bài hát mới ngay khi nhặt được. Bạn không cần phải giữ bản nhạc trong hành trang để chơi bài hát đó. Tặng nó cho người khác cũng sẽ giúp họ học được bài hát.",
    [251741923] = "Bạn đã chạm vào một chất nhờn. Bạn bị làm chậm và nhận sát thương theo thời gian.",
    [251901540] = "Điều Tra Nguồn Gốc Của Những Nhát Sét Đánh",
    [253509848] = "Trại Đoàn Xe Phía Bắc",
    [253514306] = "Thật nhiều hóa thạch! Nhìn vẻ đẹp này xem... những tàn tích cổ xưa nhỏ bé từ những thời đại đã bị lãng quên... thật thú vị làm sao!",
    [253565184] = "Một lò nung công nghiệp thô sơ để thiêu kết và nung nóng.",
    [253679976] = "Emily",
    [253872839] = "Trang Phục Thợ Săn (Làm Đẹp)",
    [254877753] = "Ta nghĩ đã đến lúc ngươi đối mặt với nỗi sợ hãi và dọn sạch Sương độc khỏi một trong những Giếng Elixir đó. Hãy chiến đấu đáp trả nào!",
    [256108686] = "Nguồn Gốc Của Ngọc Vũ Khí",
    [256259080] = "Khi còn nhỏ, ta không có nhiều thứ, nên ta đành bằng lòng với bất cứ thứ gì xung quanh mình. Thú vui yêu thích của ta là thu thập những viên đá và sơn chúng bằng những màu sắc rực rỡ, nhưng có những viên để không thôi cũng đã quá đẹp rồi. Đá cẩm thạch đỏ, thạch anh, hay thậm chí là đá bazan đều sở hữu một vẻ đẹp tự nhiên, ngươi có nghĩ vậy không? Ta muốn một bảng màu phản chiếu sự tĩnh lặng đó. Nơi nào sẽ có nhiều đá nhỉ...? Có lẽ là ở Đỉnh Albaneve!",
    [256646925] = "Một vật dụng chiếu sáng có thể đặt trong nhà của bạn.\n\nCung cấp sự <b>thoải mái</b> giúp tăng thời gian hiệu ứng nghỉ ngơi.",
    [256803229] = "Một phần của Bộ Giáp Thiện Xạ.",
    [256992026] = "Bạn đã sống sót rời khỏi thủy đền, nhưng bạn vẫn chưa tìm thấy kho báu cuối cùng của nó.\n\nHãy quan sát xung quanh tầng trên của ngôi đền để tìm <b>rương vàng ẩn giấu!</b>",
    [257001576] = "Chế Tạo & Nhuộm",
    [257225848] = "Mái 2m",
    [257350466] = "Đá vôi là một nguồn tài nguyên dồi dào thường được sử dụng trong kiến trúc.",
    [257418438] = "Cải Tạo Đất - Xóa L",
    [258815038] = "Quản Ngục",
    [259753160] = "Athalan Skree",
    [259790736] = "Tâm hồn ta đã tan vỡ. \n\nTa có thực sự trách được mọi người khi họ quay lưng lại với những lọ thuốc của ta trong cơn tuyệt vọng không? Hầu hết khách ghé thăm ta dạo này là lũ chuột và những loài sâu bọ đáng buồn khác... cho đến nay, chúng vẫn chưa chứng tỏ mình là những cộng sự phòng thí nghiệm tuyệt vời.\n\n<i>Chắc chắn phải có một cách tốt hơn để dọn sạch Sương độc... để vượt qua nó. Có lẽ ta nên xem xét lại những nỗ lực của mình. </i>",
    [260723886] = "Bình Của Kẻ Sa Ngã",
    [260967876] = "Cho đến khi máu ngươi đông cứng.",
    [261004719] = "Mắt Nhện Mẹ",
    [261079781] = "Tác Động Thiên Thạch",
    [261941322] = "Tiếp tục chỉnh sửa",
    [262115523] = "Đỡ đòn",
    [262538528] = "Có vẻ như ngươi đã bắt được thứ gì đó...",
    [262606260] = "Khi tiêu diệt kẻ địch bằng vũ khí ma thuật, bạn nhận thêm 20% kinh nghiệm.",
    [262791240] = "Cây cung này có lực căng rất lớn, khiến việc sử dụng nó cực kỳ tốn sức. Đổi lại, nó gây ra sát thương cực lớn.",
    [263042887] = "Một mái nhà che đầu",
    [263146832] = "Đài Lửa Đỉnh Albaneve Lớn",
    [263187722] = "Điều tra <location>Pháo Đài Kelvin</location>",
    [263508159] = "Như ánh mặt trời buổi sớm, phản chiếu trên mặt nước tĩnh lặng của một chiếc bát ngà.\n\nBảng màu này có thể được chế tạo bằng nguyên liệu từ Kindlewastes.",
    [263744061] = "Quặng Sắt",
    [263894479] = "Thu thập một Quả Cầu sẽ hồi phục <b>10%</b> tài nguyên tương ứng.",
    [264026451] = "Hiệu ứng ngọc của bạn đang trong thời gian hồi chiêu trước khi có thể kích hoạt lại.",
    [264540580] = "<location>Rattlebleak</location>",
    [264756145] = "Ta có thể rèn đủ thứ hữu ích cho ngươi, nhưng không phải ở ngoài trời trống trải như thế này!",
    [264875744] = "Vàng được nghiền thành bột. Nó lấp lánh còn đẹp hơn cả trước đây.",
    [265336000] = "Bát Pha Lê",
    [265387788] = "Găng Tay Hoàng Gia",
    [265544426] = "Nitrat",
    [265913157] = "Giày Thầy Thuốc",
    [265970005] = "Nhà",
    [266129791] = "Một công nhân từ Công Trường \"Maelstrom\" đã bị ảo giác nặng và đã ghi chép lại chúng khi dấn thân vào Sương độc.\n\nHãy lần theo dấu chân của anh ta và tìm xem anh ta đã đi đâu!",
    [266642089] = "Kho chứa đồ đã đầy",
    [267339174] = "Đòn Tấn Công Tàn Bạo",
    [267411506] = "Độ Khó Câu Cá",
    [268856025] = "Búa Tù Trưởng",
    [269119834] = "Trái Tim Đại Dương",
    [269141370] = "Nhận",
    [269282190] = "Quyền Hạn Máy Chủ",
    [269359298] = "Tro Tàn Vĩnh Cửu",
    [269420781] = "Máy Ảnh",
    [269908005] = "H- H- Hỏa Kỷ Nhân...",
    [270457945] = "Trò Chuyện Với Nông Dân Emily",
    [270570243] = "Những bộ quần áo này nồng nặc mùi mục rữa.",
    [270707019] = "Súp Cá Cà Chua",
    [270776832] = "Quần tĩnh lặng để bước đi êm ái.",
    [271612798] = "Gửi <lorename>Lupa</lorename> thân mến —\n\nKhi chúng ta bị chia cắt, tôi đã vô cùng sợ hãi. Tôi đã tìm kiếm và tìm kiếm suốt những ngày dài... chỉ để gặp Rodalton, một tên trộm từ Umber Hollow, kẻ nói rằng <b>bạn đã bị Kẻ thầu bắt đi.</b> Tại sao hắn lại đưa trẻ con xuống nơi khốn khổ đó? Bất chấp sự tàn nhẫn của hắn, tên trộm này đã đảm bảo với tôi rằng bạn vẫn còn sống — dù là tù nhân.\n\nHắn đã hứa sẽ chuyển bức thư này cho bạn. Em gái! Tôi biết bạn đủ rõ để nói rằng <b>bạn sẽ không bị xiềng xích lâu đâu.</b> Khi bạn trốn thoát, hãy trở về nhà và chúng ta sẽ trả thù!\n\nThân ái,\nKendal",
    [272226531] = "Các đòn đánh hồi lại một phần trăm sát thương gây ra thành SP",
    [272522599] = "Mọi hy vọng đều phù du, như ảo ảnh nơi chân trời. Cây Gậy phép này khiến người sở hữu nó từ bỏ mọi đức tin để bước vào vực thẳm.",
    [272630979] = "Than Đá",
    [272648194] = "Trống Handpan Huyền Thoại",
    [272668717] = "Đài Lửa",
    [272960944] = "Thật vui khi gặp bạn.",
    [273385160] = "Một vật phẩm trang trí để thiết kế và làm đẹp cho ngôi nhà của bạn.",
    [273483938] = "Gợi Ý Tượng <lorename>Pikemead</lorename>",
    [273702079] = "Những chiếc vảy nặng trĩu bùn đất và cáu bẩn, làm mờ đi ánh sáng của nó. Thật khó tin rằng một sinh vật như vậy đã từng chiếu sáng những bông hoa súng dưới sự cai trị huy hoàng của <lorename>Pikemead</lorename>.\n\nThu thập nhiều Đầu Rồng Sương độc để chế tạo Cúp Đồng.",
    [274394104] = "Đừng bảo tôi phù phiếm, nhưng tôi nhớ thời trang của thế giới cũ. Những màu sắc rực rỡ, vải vóc sang trọng, những người đẹp khoác lên mình chúng, và cả sự giàu sang còn đẹp đẽ hơn thế nữa... Có lẽ bạn vẫn có thể tìm thấy vài bộ y phục ngoài kia chứ? Tìm thử cũng chẳng mất gì!",
    [274525865] = "Đường Về Nhà Xa Xôi",
    [274677864] = "Trang Trại Rượu Mùa Đông",
    [274759538] = "Tỉ lệ Chí mạng của vũ khí phép thuật tăng thêm <b>10%</b>. ",
    [275955387] = "Một phiên bản đã được mài giũa của Khối Đá Thô. Do tác động của thời tiết, những viên đá đã mất đi vẻ xù xì theo thời gian.",
    [276322608] = "Tôi nghe nói Cade đã cử bạn đến cứu tôi. Anh ấy là một người bạn cũ và là khách hàng thường xuyên, người luôn ngưỡng mộ hàng hóa của tôi mỗi khi tôi ghé thăm Đồng Cỏ Thấp. Anh ấy thậm chí đã từng mua một chiếc đèn lồng từ tôi. Nếu tôi có thể xem lại nó, tôi có thể chế tạo thêm nhiều cái nữa. Làm ơn hãy hỏi Cade về việc này.",
    [276368785] = "Cướp Phá Ngôi Mộ Ẩn Giấu",
    [276434165] = "Nơi Ẩn Nấp Của Kẻ Buôn Lậu",
    [276482982] = "HP Trùm",
    [276787675] = "Những tia sét thiêu rụi bầu trời. Đó là nguồn sáng duy nhất của tôi kể từ khi ngọn lửa bị dập tắt bởi trận mưa xối xả không thương tiếc này. Tất nhiên, tôi đã thấy mây tụ lại trước khi lên đường tìm kiếm <b>ngôi mộ ẩn giấu</b>. Tôi đã nếm trải sự đe dọa trong làn gió. Bất chấp những dấu hiệu cảnh báo, hắn vẫn thúc ép tôi dấn thân.\n\n<i>Ngươi có thể chờ cơn bão đi qua, nhưng nước có thể vùi lấp kho báu của chúng ta trong bùn đấy! Ngươi có nỡ nhìn thấy đế chế của chúng ta bị cuốn trôi không, Gerith?</i> Ôi, tên ác quỷ khéo mồm khéo miệng đó. <b>Ngôi mộ ở ngay gần đây</b>, nhưng gió và mưa ngăn cản tôi tiến xa hơn! Những cái cây cọt kẹt này chẳng thể che chở cho tôi, nên chắc chắn tôi sẽ bị ướt—\n\n<i>(Văn bản kết thúc đột ngột.)</i>",
    [277034183] = "Hồi phục %k HP mỗi 5 giây.",
    [277079075] = "Bia Mộ \"Trong Ký Ức Yêu Thương\"",
    [277087144] = "Tại đây bạn có thể tìm thấy các yêu cầu và nguyên liệu cho mỗi công thức.",
    [277088711] = "Thay Đổi Nguyên Liệu",
    [277649871] = "Chuyến hàng đó quá hời để chia sẻ với lũ sát thủ gầm gừ còn lại, nên tôi đã giấu những món nguy hiểm nhất ở nơi cuối cùng mà bất kỳ ai cũng thèm ngó tới… bạn biết rõ cái hang đó mà.",
    [278016658] = "Ghế Dài Mộc Mạc",
    [278102739] = "Đòn Đánh Mạnh",
    [278411384] = "Kinh Nghiệm Khai Thác",
    [278491109] = "Hãy giữ vững trọng tâm và cảm nhận mặt đất dưới chân mình. Kết nối với lõi ma thuật của thế giới bằng đôi ủng thanh thoát này và đứng vững trước kẻ thù của bạn.",
    [278556481] = "Dùng hết",
    [279368442] = "Kể từ khi tôi bắt đầu sử dụng chiếc cần câu cũ của cha mình, tôi đã câu được… những thứ kỳ lạ.\n\nRương kho báu. Sự lấp lánh và vàng bạc. Những cổ vật, ướt sũng nhưng vẫn còn sức sống, cầu xin được giải cứu khỏi vực thẳm. Là do dòng nước, hay do chiếc cần câu?\n\nTôi cũng kéo lên được nhiều ủng ướt hơn. Vào những ngày tồi tệ, tôi trở về nhà với cả tá ủng. Ai ở đây cứ làm mất hết giày thế nhỉ? Tôi đã bắt đầu xếp chồng chúng lên, ghép đôi khi có thể, nhưng tôi đã mệt mỏi với cảnh tượng đó rồi.\n\nCha tôi luôn trân trọng công cụ của mình, và tôi cũng đã cố gắng làm như vậy — nhưng chiếc cần câu này… tôi nên vứt nó đi. Tôi không thể đủ kiên nhẫn chờ đợi từng chuyến hàng lớn... Tôi thích quay lại với những kết quả có thể dự đoán và đáng tin cậy hơn. Tôi đã đóng gói và cất nó trong tầng hầm của nhà mình. Một ngày nào đó, tôi sẽ quay lại với nó... vào lúc cần thiết, có lẽ vậy.",
    [279441318] = "Khối Lập Phương 4m",
    [279790438] = "Đôi giày đơn giản với gót bằng, rất hợp với tất đen.",
    [279922731] = "Điểm Thuộc Tính",
    [280436012] = "Bạn đã đặt con dê. Bây giờ, bạn nên chế tạo và đặt các tiện nghi cần thiết. \nĐể đáp ứng nhu cầu của vật nuôi, nó sẽ cần một <b>Máng ăn cho Dê thông thường và một chiếc gối cho gia súc.</b> \n\nNếu bạn có <b>2 con vật hạnh phúc ở gần nhau</b> và một chiếc <b>giường dự phòng,</b> chúng có thể <b>sinh sản</b>.\n\nHãy chế tạo máng ăn cho dê và gối cho gia súc!</b>",
    [280720812] = "Những ngày họp chợ là lúc tôi thích nhất. Vào ngày định mệnh đó, tôi đã đổi rau củ trong trang trại để lấy những câu chuyện và bí mật cho đến khi một giai điệu quen thuộc khiến tôi khựng lại. Chính giai điệu đã gọi tôi vào rừng từ rất lâu trước đây đang vẫy gọi tôi một lần nữa. Tôi đánh rơi những bao ngũ cốc và đi theo nó.\n\nTôi tìm thấy một nhạc công giữa đám đông đang đung đưa, thổi một bản giao hưởng mê hoặc bằng sáo. Một thứ gì đó bên trong tôi nảy nở như một hạt giống bị lãng quên.\n\n<i>\"Bớt mơ mộng hão huyền đi!\"</i> Cha tôi quát lên tối hôm đó, nhổ cả khoai tây nghiền lên bàn ăn.\n<i>\"Mày mang nhầm dòng máu rồi! Nhìn tay mày xem — Chúng to khỏe và thô kệch, không phải để làm mấy trò gảy đàn vớ vẩn đâu!</i> Ông nhồi vào miệng một miếng bánh mì khô và uống một ngụm nước giếng.\n<i>\"Mày là một nông dân, nhóc ạ. Không thay đổi được đâu.\"</i>\n\n<i>Valory</i>",
    [280794842] = "Đâm xuyên kẻ thù từ phía sau bằng những mũi tên bắn ra từ Cung Xuyên Thấu Ma (Fell Impaler Bow) chuẩn xác này, hoàn hảo cho những ai muốn kết liễu kẻ thù từ một khoảng cách an toàn.",
    [280847559] = "Vây Râu Nướng",
    [280904270] = "ST Đập Cận chiến",
    [281008299] = "Tượng Chú Lùn Sân Vườn Cầm Xẻng",
    [281475151] = "Một chiếc rìu với lưỡi sắt rất chắc chắn. Nó hiệu quả hơn nhiều!",
    [281769534] = "<lorename>Rochelle Anders</lorename>",
    [282081970] = "Mảnh Tượng <lorename>Pikemead</lorename>",
    [282416998] = "Lắp Ráp Lại Tượng <lorename>Pikemead</lorename>",
    [282708604] = "Nơi Yên Nghỉ Của Những Người Chiến Thắng Đại Hội Thể Thao Mùa Hè",
    [282798827] = "Bình Rót Nước Bembel",
    [283003193] = "Ngọn Lửa có thể được cường hóa tại Đàn Tế Lửa. Điều này giúp bạn <b>tiến sâu hơn vào Sương độc,</b> và <b>xây dựng thêm nhiều căn cứ</b> để bảo vệ Embervale khỏi tầm ảnh hưởng của nó.\n\nĐể <b>cường hóa Ngọn Lửa, cần có Tia Lửa</b> và các nguyên liệu khác. Tìm kiếm Tia Lửa tại các <b>Thánh Điện Lửa</b> và <b>Đền Thờ Lửa</b>.",
    [283195076] = "Nâng Cấp Đàn Tế",
    [283490239] = "Cường Hóa Ngọn Lửa",
    [283713533] = "Bạn có thể dịch chuyển tức thời khi đang bị choáng. Điều này sẽ giải trừ trạng thái choáng. ",
    [284119531] = "Mũ Giáp Khô Cốt Độc Quyền",
    [284793715] = "Bạn đã tìm thấy một món đồ chơi nhồi bông của một Sinh vật Fell.\n\nBây giờ hãy nói chuyện với Nông dân Emily để xoa dịu nỗi sợ hãi của cô ấy!",
    [285117027] = "Độ Hiếm Trang Bị, Phân Tách và Đặc Quyền",
    [285615321] = "Mồi Nhử Vàng",
    [285787528] = "Đế Lót Ly",
    [285869323] = "...vừa quét qua biên giới và tràn thẳng đến quảng trường, những con sóng êm đềm của nó sủi bọt tại các bậc thang lớn. <i>\"Một thủy triều hăm hở\",</i> họ nói. <i>\"Chắc hẳn một vật cản nào đó ở thượng nguồn đã bị bung ra\"</i>... Nhưng tôi không nghĩ vậy. Nước có vị khác lạ. Nó quất vào những bức tường bên ngoài của chúng ta, dâng cao... dưới triều đại của Nữ hoàng <lorename>Pikemead</lorename>, điều này sẽ không bao giờ xảy ra. Vương quốc của chúng ta đang xói mòn dưới thời <lorename>Gormander</lorename>... chúng ta đã trở nên yếu đuối.",
    [287158465] = "Tiền Đồn Cửa Ngõ \"Nước Tối\"",
    [287375810] = "Phòng Thủ Của Cổ Nhân",
    [288223030] = "Vùng Đất Khô Ráo",
    [288412504] = "Lời Khuyên Của Nông Dân",
    [288477986] = "Tấn công kẻ thù không cảnh giác sẽ gây thêm %k sát thương.",
    [288867398] = "Nền Tảng",
    [289179376] = "Những Câu Chuyện Ở Tửu Quán",
    [289694788] = "Đá Phủ Rêu",
    [289712490] = "Khiên Nguyên Tố",
    [290173355] = "Thắp Sáng Ngọn Lửa Hiệu Đầu Tiên",
    [290618944] = "Máu Bao Phủ",
    [290691309] = "Một khối xây dựng được chế tác từ Chất Phát Sáng Trắng. Ánh hào quang của nó làm bừng sáng bất kỳ không gian nào.",
    [290727359] = "Kiểm Lâm",
    [290871250] = "Tiện Nghi - Danh Mục Giường",
    [291210166] = "<keyitem>Lưỡi Cưa Tròn</keyitem> Chất Lượng Cao Nhất",
    [291844943] = "Lối Vào Thị Trấn Dưới Nước Ẩn Giấu",
    [293176168] = "Từ hàng thiên niên kỷ trước, chúng đã từng rất nhiều — bay lượn trên những đỉnh núi tuyết trắng và qua những thung lũng đẹp như tranh vẽ. Bây giờ, chỉ còn lại một. Ôi, bạn đã rơi xa đến mức nào khi bay cao.\n\nThu thập nhiều Đầu Rồng Con non Fell để chế tạo Cúp Đồng.",
    [293182419] = "Chế Độ Kích Hoạt Trò Chuyện Bằng Giọng Nói",
    [293293944] = "Vũ Khí Cận Chiến 2H",
    [293505223] = "Tăng sát thương gây ra bằng dao găm.",
    [293611697] = "Bộ Hộ Vệ",
    [293650723] = "Nhà Giả Kim giải thích rằng Cổ Nhân và con người đã cùng nhau tạo ra \"Hỏa Kỷ Nhân\", những sinh vật được rèn giũa trong lửa. Họ được bảo vệ bởi <b>Linh Hồn Lửa</b> và do đó có thể tiến vào Sương độc mà không để lại hậu quả lâu dài. <b>Sự bảo vệ của Ngọn Lửa không kéo dài mãi mãi</b>, và cần được phục hồi khi ở bên ngoài Sương độc.",
    [294005378] = "Điều Tra Địa Điểm Tập Trung Của Bộ Tộc Vukah",
    [294131948] = "Trượng Của Darya",
    [294426592] = "Nhạc công Valory muốn bạn tìm kiếm hóa thạch trên khắp Embervale. Có ba hóa thạch ở Kindlewastes. Mỗi hóa thạch có thể được tìm thấy nhiều lần ở những nơi khác nhau. Nhạc công khuyên bạn nên tìm kiếm trong các hầm mỏ, địa điểm đào bới và các mỏ quặng để tìm thấy tất cả các hóa thạch.",
    [295075792] = "Tiếng Nhật",
    [295855826] = "Khối Đường Đá Nhám",
    [296352701] = "Tìm Kiếm Và Che Chở Cho Dân Làng",
    [296491672] = "Đèn Lồng Giấy II",
    [296581760] = "Mảnh Khảm Ngọn Lửa VI",
    [297550044] = "Lò Rèn Đá Quý",
    [297995111] = "Tủ Trưng Bày B",
    [298144756] = "Tăng ST Phép thuật thêm 5% cho mỗi Điểm Thuộc tính.",
    [298311968] = "Hoa Gentian Lấp Lánh",
    [298338377] = "Chúc buổi trình diễn thành công!",
    [298482250] = "Lối Vào Mộ Cổ Bí Mật",
    [298517559] = "Chiến Đấu Tầm Xa Và Phép Thuật",
    [299056728] = "<i>\"Hãy nhìn vào quả cầu,\"</i> Nhà Tiên Tri nói, mắt dán chặt vào cây Gậy phép. <i>\"Nó hiển thị quá khứ, hiện tại và tương lai — và tất cả đều Sương độc bao phủ trong sự thối rữa xanh biếc\".</i>\n\n<b>Thấm Nhuần Màn Sương</b>: \nVũ khí này đã bị bao phủ bởi Màn Sương và gây ST Sương độc cực lớn. Chỉ có thể tìm thấy nó bên trong các Hang Ổ Màn Sương.",
    [299242030] = "Bồn Tắm Đá Granite",
    [299555289] = "Vị trí ngôi mộ bí mật của Nữ hoàng đã được tìm thấy. Di hài và kho báu của bà hẳn nằm sau cánh cửa trung tâm, nhưng nó đã bị khóa. Chắc chắn phải có cách nào đó để mở cửa.",
    [299556103] = "Cường Độ Hiệu Ứng Viền Băng Giá",
    [299871646] = "Bộ",
    [300234156] = "Về Chuyến Hàng Số 047",
    [300371245] = "Chưa Chọn Vật Phẩm.",
    [300865795] = "Thịt Cua Nướng",
    [300866196] = "Sức Bền",
    [300991780] = "Bùng cháy khi hoàn thành nghi lễ. Tiếng hú kinh hoàng. Mùi hôi thối? Còn tệ hơn. Tuy nhiên, bộ xương vẫn còn hữu dụng. Kết luận: Không dùng nến cháy vĩnh cửu. Hãy dùng nến thường thay thế.",
    [301427980] = "Ôi chao, nhìn kìa! Ngươi đã tìm thấy thứ gì đó phản chiếu làn nước, lấp lánh dưới ánh mặt trời thật đẹp đẽ! Ôi, ta có thể ngắm nhìn viên pha lê này mãi mãi… Ta cảm thấy tràn đầy cảm hứng — bắt tay vào việc thôi!",
    [301440512] = "Trở thành một \"Scavenger\" thật hạn chế, tẻ nhạt và... <i>bẩn thỉu.</i>\n\nCó lẽ bạn không nên dành cả ngày để uống rượu và đánh nhau. Điều gì sẽ xảy ra nếu một người đàn ông muốn đi tắm? Một bồn tắm thơm ngát, đẹp đẽ, yên tĩnh, thơm ngát tại Suối nước nóng Cromville?\n\nTôi không muốn cắt xé, tôi khao khát được té nước và tung bọt — được tận hưởng một bồn tắm sủi bọt ấm áp cùng các chàng trai của tôi, ở một khoảng cách thoải mái nhưng hợp lý! Chúng ta thậm chí có thể <b>lặn tìm kho báu!</b> Đó là \"nam tính\", phải không? Sẽ rất vui!\n\nMọi người cho rằng vóc dáng vạm vỡ của tôi nên quyết định sở thích của tôi, nhưng tại sao lại phải dính đầy dầu mỡ khi bạn có thể có mùi như nước hoa hồng? Tôi từ chối nhượng bộ trước một sự giả tạo như vậy!",
    [302021415] = "Đã Trưng Bày",
    [302021758] = "Nó bốc mùi hôi thối và mục rữa, vì vậy tốt nhất nên thông gió cho sảnh của bạn đúng cách.\n\nThu thập nhiều Mũ Scavenger Matron để chế tạo Cúp.",
    [302396555] = "Quăng dây câu và đợi cá cắn câu. Khi cá đã cắn, hãy nhanh tay nhấn <b>%k</b> để bắt đầu kéo dây vào.",
    [302477978] = "Sương độc",
    [302838948] = "Lực phản đòn",
    [302880945] = "Tiền vàng! Cuối cùng cũng thấy! Hãy lấp đầy cả cái chậu này bằng vàng và nhảy vào thôi!",
    [303766531] = "Đến giờ, ngươi hẳn đã chạm trán lũ <b>Hollow</b>. Những xác xương khô, được hồi sinh bởi cơn thịnh nộ và <b>lời nguyền của Ngọn Lửa</b>. Truyền thuyết kể rằng chúng đã bị trục xuất vào những <b>đại sảnh dưới lòng đất</b> không rõ nguồn gốc... Ta đã phát hiện ra một sảnh đường như vậy trong quá trình nghiên cứu, nhưng không thể vào được. <i>Có lẽ ngươi có thể.</i> Tốt nhất hãy tập hợp <b>một đội</b> nếu có thể để cùng xuống đó!",
    [304273059] = "Thoáng Nhìn Vĩnh Hằng",
    [304358795] = "Hầm Chứa Tàn Tro",
    [304554340] = "Các bụi rậm có thể che giấu ngươi. Khi ở trong đó, hãy nhấn <b>%k</b> để cúi người và ẩn nấp. Hãy tận dụng chúng để lẻn ra sau kẻ thù.",
    [304832897] = "Đôi găng tay này hơi cứng và hầu như không có tác dụng gì. Điều quan trọng nhất là chúng trông rất ấn tượng đối với đám dân đen. Dù sao thì ngươi cũng chẳng cần phải làm việc chân tay.",
    [304915741] = "Tấn Công Mảnh Văng",
    [305878608] = "Mũ Trùm Xạ Thủ",
    [306116273] = "Triệu hồi các thế lực của thế giới ngầm để tạo ra các tia năng lượng truy đuổi kẻ thù.\n\n<b>Phép Vận Nội Lực:</b> Giữ nút để vận nội lực <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để thi triển bằng <b>Gậy phép.</b>",
    [306158314] = "Có vẻ như Dì Braelyn đã mạo hiểm tiến vào các ngôi đền ẩn giấu ở Blackmire để nghiên cứu kiến trúc đá. Có lẽ ngươi có thể tìm thấy thêm dấu vết của bà ấy ở các ngôi đền khác!",
    [306183877] = "Sử Dụng Vật Phẩm",
    [306616025] = "Những người sống sót có thể yêu cầu <b>nơi trú ẩn để mở khóa các công thức chế tạo.</b> Hãy xây dựng nơi trú ẩn cho họ và chế tạo giường ngủ!\n\nNgoài ra, các công thức chế tạo mới có thể được mở khóa bằng cách <b>thu thập các tài nguyên quan trọng.</b> Một số công thức nhất định yêu cầu xưởng chế tạo. Các xưởng phải được tạo ra và đặt trong căn cứ trước khi sử dụng. <b>Các vật phẩm then chốt</b> cần cho <b>xưởng</b>, hoặc chính các xưởng đó, có thể nhận được thông qua một số <b>nhiệm vụ của người sống sót.</b>\n\nTất cả các công thức đã biết có thể được xem lại trong <b>tab Xưởng trong nhật ký.</b> Các công thức quan trọng có thể được <b>ghim lại.</b>",
    [307570612] = "Viên <npc>Thợ Rèn</npc> cảm nhận được một sự hiện diện đen tối tại kinh đô, <location><lorename>Pikemead</lorename>'s Reach</location>. Ông lo lắng rằng số phận của thị trấn có thể đã bị định đoạt bởi chiến tranh, hoặc tệ hơn, một luồng sáng kỳ lạ và huyền bí từ sâu dưới đáy sông.",
    [307739868] = "Hóa Thạch Cua",
    [307802768] = "Sẽ dễ thôi nếu ngươi chăm chỉ luyện tập.",
    [308029703] = "Đền Thờ Mặt Trời",
    [308598778] = "Đôi ủng này vẫn sẽ giữ nguyên hình dáng ngay cả khi ngươi đánh rơi một chiếc búa lên chúng. Hoặc một cái kẹp. Hoặc cả một cái đe. Thật tiện lợi làm sao!",
    [309004211] = "Cấp Độ Ngọn Lửa %k",
    [309488673] = "Chuyển Tab",
    [309594410] = "Thùng Nổ",
    [309809319] = "Áo Giáp Thợ Săn Hươu",
    [309817588] = "Khu vực được Ngọn Lửa bảo vệ",
    [310708574] = "Cây chùy này là nỗi khiếp sợ và kẻ xua đuổi tất cả các sinh vật bất tử.\n\n<b>Tiếng Vọng Hollow:</b>\nVũ khí giải phóng một tiếng vang tà ác giúp kéo dài tầm tấn công bằng phép thuật.",
    [310944369] = "Sát Thương Va Đập",
    [311062488] = "Những chiếc móng vuốt nhân tạo đã được thêm vào đôi găng tay pháp sư đơn giản này để khiến chúng trông oai vệ và thời thượng hơn.",
    [311141304] = "À! Ta đang khao khát được sáng tạo! Hãy giúp ta luyện một số vật liệu mới nhé?",
    [311879190] = "Một phép vận nội lực vĩnh cửu giúp hồi máu cho tất cả đồng minh đang cần. \n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không bị tiêu hao.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để thi triển bằng <b>Gậy phép.</b>",
    [312246787] = "Đã Kích Hoạt",
    [312319604] = "Mũ Giáp Bóng Của Núi",
    [313229555] = "Không có mối đe dọa nào gần đây",
    [313289287] = "Định Vị Điểm Dịch Chuyển",
    [313556750] = "Chiếc mũ của bậc thầy phá phép này được trang trí bằng một viên ngọc xanh thẳm, có khả năng thu hút và lưu trữ các mảnh vỡ rải rác của Ngọn Lửa. Sức mạnh của chúng sau đó sẽ được giải phóng trong những trận cận chiến nghẹt thở.",
    [313589137] = "Vào thời xưa, những đôi găng tay này được đeo bởi những học giả thông thái nhất vương quốc, thường để che giấu làn da nhăn nheo và xám xịt bên dưới.",
    [313600395] = "Cho biết khả năng chịu đựng của cơ thể ngươi đối với môi trường băng giá.",
    [314051675] = "Yêu Cầu Chat Văn Bản",
    [314378718] = "Khi được nghe kể về truyền thuyết Merphisz, Fyraszh đã bước ra từ đám đông Drakling. \n\n<i>\"Tại sao phải vẫy vùng trong nước mãi mãi? Tại sao phải thuận theo ý muốn của những con sóng nếu ngươi có thể tự rèn giũa con đường của riêng mình trong lửa?\"</i> Hắn hỏi, đỏ rực vì giận dữ. Quyết tâm vượt qua người anh trai dâng trào trong hắn, vì vậy Fyraszh không đi xa, mà đi sâu. Hắn lên đường để chiếm lấy lõi của ngọn núi, để rèn giũa vinh quang của mình trong kim loại nóng chảy và sức nóng lỏng. \n\nKhi họ gặp lại hắn, vảy của hắn đã cứng lại như than, và lớp da bên dưới rực sáng như mặt trời. Khoác trên mình tro tàn và vàng son, hắn hét lên từ đỉnh núi: <i>\"Thấy chưa? Ngọn núi đang rung chuyển và phun trào, nó đang xướng tên chúng ta và tên của gia tộc chúng ta! Drak' Fyr! Drak'Fyr!\"</i>\n\nVà khi ngọn núi thực sự gầm rú và phun trào, một vòi phun sáng rực như ánh hoàng hôn đã bùng nổ phía sau hắn. Ánh sáng hổ phách nuốt chửng cơ thể hắn, nhưng đã nâng linh hồn hắn lên Ark Morgo, nơi hắn sẽ là thủ lĩnh cho đến muôn đời.",
    [315164138] = "Sức Mạnh Khai Thác Kim Loại",
    [315659262] = "Nơi Trú Ẩn",
    [315958594] = "Cây cung bị ám này chứa đựng sức mạnh hùng mạnh của Sương độc.",
    [316389499] = "Quần Sừng Núi Tuyết",
    [316629291] = "Thêm <b>25%</b> cơ hội tạo ra một <i>Mũi Tên Thường</i> bổ sung khi sử dụng <b>Mưa Tên</b> từ kỹ năng <b>Đa Tiễn</b>.\n\nMũi tên <i>Thường</i> bổ sung này không tiêu tốn đạn dược của ngươi. ",
    [317154082] = "Giấu các lối đi trong căn cứ của ngươi đằng sau cánh cửa bí mật này.",
    [317193095] = "Thời Gian Còn Lại Trong Ngưỡng Sương độc",
    [317234752] = "Phân Tích Sự Phát Triển Của Drak",
    [317496520] = "Lối Đi Đến Blackmire",
    [317685997] = "Di Chuyển Camera Móc Leo",
    [317790795] = "Mang cho Thợ Cắt Tóc thứ gì đó màu xanh và có dạng pha lê",
    [317830712] = "Quản Lý Danh Sách Đen (%k)",
    [318138879] = "Một bộ trang phục truyền thống, thoải mái phù hợp với một nhà giả kim tương lai.",
    [318147791] = "Sảnh Đường Hollow",
    [318159451] = "Tăng tất cả ST Sương độc Phép Thuật ",
    [318459440] = "Nàng Thơ đã kể cho ngươi nghe về mong muốn được chơi đàn handpan của mình. Đàn handpan rất phổ biến ở Lưu Vực Veilwater, và đôi khi được vận chuyển cùng với các hàng hóa khác qua các tuyến đường thương mại quan trọng.\n\nCó một thang máy chở hàng ở Lưu Vực Veilwater kết nối nơi đó với Revelwood và <location><lorename>Pikemead</lorename>'s Reach</location>. Hãy bắt đầu tìm kiếm ở đó!",
    [318775095] = "Thợ Cắt Tóc muốn ngươi kiểm tra các trạm giao thương bỏ hoang để tìm hàng hóa còn sót lại như <b>bảng màu.</b>\n\nÔng ấy gợi ý nên tìm ở <b>\"Nomad's Drop\",</b> một trạm giao thương ở Cao Nguyên Nomad.",
    [318810073] = "Thật là một linh hồn nhỏ bé xinh đẹp mà ngươi đã mang đến. Đừng lo lắng về cuộc sống của nó ở đây... Ta sẽ nhào nặn nó thành một thứ gì đó hữu ích.",
    [318966959] = "Hiệu Suất Cực Cao",
    [319146511] = "Ghế Dài Bằng Tre",
    [319253163] = "Giáp Chân",
    [321331288] = "Phần Thưởng",
    [321642499] = "Cuốc Thép",
    [322195532] = "Khối Hành Lang Khô Cốt",
    [322633183] = "Xương Sườn Quái Vật",
    [322719966] = "Ta đã đi lang thang khắp các vùng đất, bị mê hoặc bởi sắc tím phong phú và rực rỡ mà thiên nhiên đã dệt nên một cách dễ dàng vào những cánh hoa và quả mọng. Độ sâu ấy, sự rực rỡ ấy - ta phải chiếm lấy nó cho riêng mình. Ta đã đun sôi rễ cây và nghiền nát những đóa hoa, trộn lẫn các khoáng vật và thì thầm những câu thần chú, nhưng màu sắc ấy vẫn lẩn tránh ta. Sắc thái đó trượt khỏi tầm tay ta như sương mù lúc bình minh.\nNhưng ta sẽ không nghỉ ngơi. Ở đâu đó trong lòng đất hoặc trong tinh hoa, bí mật đang chờ đợi. Và khi ta nắm giữ được nó, nó sẽ không chỉ đơn thuần là sắc tố. Nó sẽ là sức mạnh, vẻ đẹp và chính là vận may.",
    [323698836] = "Còn gì tuyệt hơn <i>một</i> cuốn sách? ",
    [324504977] = "<keyitem>Dụng Cụ Rèn</keyitem>",
    [324586616] = "Nhân loại đã đào những Giếng Tiên Tửu, xé nát vùng đất và xâu xé lẫn nhau để giải tỏa cơn khát của họ.",
    [324706861] = "Tìm thấy ở Springlands, vào ban đêm",
    [324810057] = "Giáp Thân Dưới",
    [325840982] = "Cây Giống Tảo",
    [326184360] = "Khiên",
    [326231556] = "Vô Hiệu Hóa",
    [326399065] = "Mũ Giáp Chiến Binh",
    [328508399] = "Đưa Dâu Tây Cho <npc>Nông Dân</npc>",
    [329125301] = "Sắc xanh thẳm chiếm vị trí chủ đạo trong bảng màu này có thể được tìm thấy bên kia những bãi biển đá, hoặc vào những ngày mưa bên vách đá.\n\nBảng màu này có thể được chế tạo bằng vật liệu từ Revelwood.",
    [329343787] = "Đạo Cụ Rương Gian Lận I",
    [329602845] = "Về Ngọn Lửa Và Những Tiếng Thì Thầm Của Nó",
    [329927532] = "Hắc Ín",
    [330426893] = "Nhận Phước Lành",
    [330976268] = "Màu da",
    [331738527] = "Tùy chỉnh này kiểm soát số lượng kẻ địch trong thế giới.",
    [332095516] = "Trọng Kiếm Của Người Bảo Vệ",
    [332512156] = "Ánh mặt trời dẫn lối bước chân bạn.",
    [332532085] = "Chú mèo vằn này là một thợ săn đáng sợ, luôn rình rập con mồi. Nó tĩnh lặng, duyên dáng, độc lập — và tự hào dâng tặng chiến lợi phẩm cho bạn sau một cuộc săn thành công! Tuy nhiên, sau một ngày dài phiêu lưu, nó không thích gì hơn là được rúc vào lòng và ngủ.",
    [332664817] = " <craftingstation>Bình Huân Khói Tổ Ong</craftingstation> đã bị đánh cắp và đưa đến Đồi Tế Lễ Vukah, cùng với mật ong và sáp. \n\nHãy lần theo dấu vết và tiêu diệt tên trộm Vukah để lấy lại <craftingstation>Bình Huân Khói Tổ Ong</craftingstation>. Điều này sẽ mở khóa <craftingstation>Tổ Ong Mật</craftingstation> và việc sản xuất mật ong.",
    [333125156] = "Bên Bờ Sông",
    [333413868] = "Bụi Ngọc Xanh Biển",
    [333584390] = "Đặt mật khẩu",
    [333755473] = "Trên Mặt Nước",
    [333827968] = "Một ngày mới. Một cơ hội mới.",
    [333918372] = "Cờ Lệnh Treo Tường Dài",
    [334023434] = "Chứng Minh Bản Thân Xứng Đáng",
    [334470460] = "Đôi ủng đơn giản dành cho những người dân cần cù.",
    [334495602] = "Giáp của bạn vẫn chưa dính lông mèo, nghĩa là bạn vẫn chưa kết thúc cuộc tìm kiếm. Chuyện này rất quan trọng đối với tôi. Làm ơn hãy cân nhắc nó!",
    [334918179] = "Từ Hoàng Hôn Tới Bình Minh",
    [334998728] = "ITA",
    [335075432] = "Ô Thanh Hành Động 9",
    [335219474] = "Người Tuyết",
    [335233126] = "Thor đã trở về từ nhiệm vụ trinh sát tối qua. Hắn ném cái <b>túi bụi bặm chứa các cuộn giấy</b> này vào tôi, và nói đó là thứ duy nhất họ có thể thu thập được. Tôi thừa hiểu tên ngốc đó để biết khi nào hắn đang nói dối trắng trợn! \n\nNgười bạn cũ của tôi đã bỏ túi riêng một kho báu, nhưng tôi sẽ không tố cáo hắn đâu. Thay vào đó, chúng ta sẽ dâng <b>cuốn niên giám đó cho bà quản gia</b> như một lễ vật. \n\nCòn kho báu — chà, Thor sẽ phải chia sẻ thôi. Bất cứ thứ gì hắn <i>cướp được từ lều của Nữ hoàng <lorename>Jezmina</lorename> sẽ được cất giấu</i> tại địa điểm yêu thích của hắn, tôi đoán vậy. Sau ngần ấy thời gian, hắn vẫn chưa tìm thấy <i>nơi ẩn náu nào tốt hơn đỉnh của tháp canh cũ đó.</i>",
    [335327402] = "Khiên Đạo Tặc",
    [335489568] = "Ta Chẳng Bao Giờ Tin Những Kẻ Lầm Lì",
    [335499531] = "Mở các cánh cửa trong Đại Sảnh Hollow ở Lưu Vực Veilwater.",
    [335711988] = "Câu Cá",
    [335992002] = "Chính",
    [336567216] = "Kháng tính",
    [336983576] = "Ngôi Đền Ẩn Giấu",
    [337596245] = "Rơi ra từ cây chết, trong Sương độc",
    [337738695] = "Tại Sao Ta Phải Lãng Phí Thời Gian Làm Một Cận Vệ?",
    [337794558] = "Mỏ Đá Cẩm Thạch Fletcher",
    [338637032] = "Đá",
    [340113203] = "Bốc Cháy",
    [340621445] = "Một loại quặng chứa dấu vết của thiếc. Cần thiết để chế tạo Thỏi Thiếc.",
    [340832931] = "Cách tốt nhất để nâng tầm trang phục của bạn là thêm thật nhiều thắt lưng và dây đeo đến mức thái quá, hoặc ít nhất họ nói vậy. Một biểu tượng vàng trên ngực minh chứng cho sự tận hiến của bạn với Ngọn Lửa. ",
    [340928360] = "Đến Hố Nhựa Đường",
    [341261058] = "Trong tab Hành Trang, hãy đặt một vũ khí vào Thanh Hành Động và chọn nó. Nhấn %k để tấn công.\n\nNhấn <b>%k để khóa mục tiêu</b> vào kẻ địch. Camera và các đòn tấn công của bạn sẽ tập trung vào chúng.\n\nDi chuyển ra phía sau kẻ địch để <b>đâm sau lưng</b> nhằm gây sát thương lớn hơn. \n\nMở khóa thêm các kỹ năng chiến đấu trong <b>thực đơn kỹ năng.</b>",
    [341595916] = "Ch- Chào...",
    [341701023] = "Quần Hắc Vệ",
    [341955696] = "Bạn có thể bơi và lặn qua các vùng nước. Hãy chú ý đến lượng Oxygen của bạn khi chìm dưới nước.",
    [342667578] = "Thảm Treo Tường",
    [342957999] = "Hình phạt tốc độ di chuyển từ giáp giảm 50%",
    [343256108] = "Hồ Bittermelt",
    [343368802] = "Làm đầy",
    [343644610] = "Đến <location>Thornhold</location>",
    [344288827] = "Ngọn Lửa",
    [344671798] = "Mọi người dựa dẫm vào bạn vì họ tin tưởng bạn, nhưng lòng dũng cảm lớn lao thường khơi dậy sự đố kỵ. Tôi đang nghĩ về những... \"Gã Xương Xẩu\" đó. À, ý tôi là lũ \"Hollow\", dĩ nhiên rồi. Chúng đang sục sôi lòng đố kỵ, và ánh sáng ma mị của chúng luôn mê hoặc tôi! Khi còn trẻ và nổi loạn hơn, tôi thậm chí còn lảng vảng quanh một nghĩa trang gần thủ đô để nhìn trộm — nhưng tôi chưa bao giờ dám bước vào hầm mộ. Tôi tự hỏi bên trong có gì nhỉ?",
    [344742036] = "Đã đến ngọn tháp cổ đại ở Đỉnh Albaneve.",
    [345087428] = "Nhà Giả Kim muốn bạn tìm ra một cách hiệu quả hơn để nghiền nguyên liệu. Có lẽ bạn có thể tìm thấy một cỗ máy hoạt động mà không cần lao động thủ công như vậy!\n\nHãy quan sát xung quanh khi bạn tiến vào Lưu Vực Veilwater. Ngọn Lửa kêu gọi bạn hướng tới một thị trấn nhất định đang nắm giữ câu trả lời mà bạn tìm kiếm.",
    [345753143] = "Ghế Gỗ",
    [345929460] = "Tháp Canh Nhỏ",
    [346071351] = "Bộ Chiến Binh",
    [346283725] = "Một bản nhạc cho một bài hát nhẹ nhàng với những âm hưởng thiên đường.\n\n<b>Bản Nhạc</b>: \nBản Nhạc dạy cho bạn một bài hát mới sau khi nhặt được. Bạn không cần giữ bản nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác sẽ giúp họ cũng học được bài hát đó.",
    [346588884] = "Oscar Godwin đang lạc mất người em họ của mình, Anton Godwin. Hãy đi đến nhà tù nơi anh ta bị giam giữ, Tiền Đồn Cửa Ngõ \"Drifa\", và lục soát nó!\n\nHãy tìm em họ của Oscar và đưa anh ta trở về với gia đình!",
    [346623164] = "Nhật Ký Người Gác Hải Đăng I",
    [346805748] = "Một cây đũa phép gây ST Hỏa đáng kể, tiêu diệt mọi thứ trên đường đi.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương bổ sung lên đến phần trăm <i>quá tải</i>.",
    [346930508] = "FRA",
    [347682690] = "Đi Đến <location>Surat's Rest</location>",
    [348003632] = "Ẩn Nhập Mật Khẩu",
    [348169855] = "Linh Hồn Dân Làng Thất Lạc",
    [349301213] = "Nhà Kho Phần Thưởng",
    [350295721] = "Bị Đâm Thủng",
    [350477710] = "Bí Ngô Đêm Khô Cốt Lớn II",
    [351489394] = "Ồ, được ngủ dưới một mái nhà thực thụ sẽ mang lại điều kỳ diệu cho sự sáng tạo và tâm trí của tôi! Cảm ơn bạn!",
    [351769886] = "Chất liệu của cây Gậy phép được khắc vô số những đường nét mê cung gợi nhớ đến dòng chảy hỗn loạn của trận chiến. Tuy nhiên, một vầng hào quang kim loại bao quanh khoảng không bên trong, giữ lại cảm giác bình yên, như thể người ta đang ở trong mắt bão.",
    [352143953] = "Những tàn tích bụi bặm của vật liệu xây dựng.",
    [352618923] = "Một loại thảo mộc có vị đắng có thể tìm thấy ở những vùng khô hạn. Nó được cho là có khả năng khai sáng.",
    [353479528] = "Xương Sống Của Dalszul",
    [353930974] = "Cây Giống Nấm Shiitake",
    [354066467] = "Nhân vật",
    [354207400] = "Đừng Cố Tìm Tôi",
    [354435462] = "Rương Phép Thuật Khổng Lồ",
    [354570887] = "Khai thác mọi nguyên liệu quý giá ở Đỉnh Albaneve.",
    [354840692] = "Em Họ Của Oscar Godwin",
    [354885310] = "Móng Vuốt Drak",
    [355117262] = "Hỡi Hỏa Nhân! Cách đây một thời gian, một chuyện kỳ lạ đã xảy ra... Tôi nhận được một bức thư. Hãy xem này. \"Từ Reagan, gửi lời chào từ nhà Conway.\"... Tôi chưa bao giờ gặp ai tên Reagan, nhưng tôi biết nhà Conway. Những người đưa thư từ phương đông. Họ chắc hẳn đã đi qua Tiền Đồn Thương Mại \"Đá Rực Cháy\" để chuyển tin nhắn. Bạn có thể điều tra không?",
    [355351044] = "Găng Tay Kẻ Gọi Thủy Triều",
    [355439759] = "Một luống đất trồng sẽ cho ra Nấm Russula Xanh Lam.",
    [355649964] = "Hang Ổ Sương độc",
    [356362427] = "<craftingstation>Vạc Đen</craftingstation>",
    [356773030] = "Áo Chẽn Thầy Thuốc",
    [357186345] = "<location>Thủy Triều Xuống</location>",
    [357190895] = "Lũ Vukah đã tạo ra một nhà vô địch tại trại của chúng. <b>Hãy đánh bại Đấu Sĩ Vukah</b> tại Đồi Nghi Lễ Vukah để trả lại sự bình yên!",
    [357593546] = "Cờ Lệnh Ngang I",
    [357903463] = "Quan Tài Hầm Mộ Nâng Cao Lớn I",
    [359000512] = "Mở Cửa Hầm Mộ <lorename>Pikemead</lorename>",
    [359084951] = "Chưa Chọn Ngọc",
    [360343571] = "Lò Rèn Ngọc Đỉnh Albaneve",
    [360563641] = "Ngọn Lửa canh giữ vùng đất lụi tàn và ban cho Hỏa Nhân sức mạnh để chống lại Sương độc. Hãy thắt chặt mối liên kết của bạn với Ngọn Lửa bằng các vật phẩm hiến tế, và phước lành của nó sẽ càng được khuếch đại.",
    [361030361] = "Tai Ương Đã Giáng Xuống Gia Đình Chúng Ta",
    [361834197] = "MP tối đa được tăng lên.",
    [361869328] = "Thời Gian Lặn",
    [361969115] = "Kẻ Phá Vỡ Lời Thề",
    [362554097] = "Có khám phá mới nào không?",
    [362605492] = "Đũa Phép Vật Tổ",
    [362682247] = "Bản Đồ Của Ony",
    [362763534] = "Cây Giống Lá Xanh Rừng Revel",
    [362846377] = "Búa Bộ Lạc",
    [362904867] = "Dữ liệu sao lưu hiện có:",
    [363593833] = "<b>Nâng cấp</b> Đàn Thờ Lửa sẽ mở rộng <b>phạm vi bảo vệ</b> của bạn. Nâng cấp Đàn Thờ Lửa yêu cầu Lõi Sương độc. Lõi Sương độc nhận được bằng cách tiêu diệt các kẻ thù thủ lĩnh.\n\n<b>Hiến tế</b> giúp tăng Cấp Độ Ngọn Lửa và cộng <b>một điểm vào tất cả thuộc tính cho mọi Hỏa Nhân.</b> Chúng cũng tăng <b>Cấp Độ Vượt Sương độc</b> của bạn, điều cần thiết để tiến sâu hơn vào Sương độc. Hiến tế yêu cầu <b>Tia Lửa</b>. Hãy tìm Tia Lửa trong các Thánh Điện Lửa và Đền Thờ Lửa.",
    [363695247] = "Người giữ bí mật Rừng Revel",
    [364107038] = "Bộ Trang Bị Lính Thuê",
    [364270591] = "Núi cao là nôi, gió là lời ru\nĐỉnh Hú là dạ, ăn bánh bí ngô đi\n\nTrứng nở tìm trẻ biếng ăn\nĂn hết đồ mẹ nấu kẻo thành mồi ngon\n\nTiếng hú gọi tên, tiếng vọng biết ngươi\nĂn nhanh đi kẻo chết uổng công",
    [364682795] = "Đầu Hồi Thanh Mảnh",
    [364709476] = "Quá trình này nhanh hơn nhiều khi không ở trong trò chơi. \nChúng tôi khuyên bạn nên để nó hoàn tất trước khi bắt đầu hành trình.",
    [364775227] = "Tìm Kiếm Chú Lùn Sân Vườn",
    [364906778] = "Lửa Trại",
    [364976925] = "Chiếc quần này được dệt từ lụa mềm mại, chỉ dành cho những bậc đại pháp sư đáng kính nhất.",
    [365165298] = "Mở Rộng / Thu Gọn",
    [365328006] = "Khai thác tại Sương độc Vùng Đất Cháy (Kindlewastes)",
    [365629175] = "Chế Tạo Mồi Thức Ăn Cho Chó",
    [365793637] = "Lại đây, Hỏa Kỷ Nhân. Ta có một thỉnh cầu dành cho ngươi.",
    [366335265] = "%k nói Không!",
    [367350393] = "Một chiếc áo choàng trắng vàng rực rỡ đan xen với những sợi chỉ ngũ sắc. Được mặc bởi \"Học giả Ngọn Lửa Trẻ\", nó tượng trưng cho khát vọng rực cháy muốn soi sáng những điều chưa biết.",
    [367533159] = "Tìm thấy ở Vùng Đất Cháy (Kindlewastes) vào ban đêm",
    [367765371] = "Cửa Drak'Dal Lớn",
    [367811170] = "Một vòng xoáy năng lượng rạng rỡ cần thiết để khảm ngọc vào vũ khí. \n\nBan đầu được sử dụng bởi Cổ Nhân, nó đã bị lũ Fell chiếm lấy để nuôi dưỡng bầy đàn cho đến khi ngươi giải phóng nó khỏi ngục tù hữu cơ mới của nó. \n\nBiến thể này có thể tìm thấy ở Rừng Revel.",
    [367815224] = "<npc>Thợ Săn</npc> đã băng qua Rừng Revel để đến <location>Westcott</location>. <craftingstation>Con Quay Tay</craftingstation> của cô ấy đã bị bỏ lại ở một trại khác.",
    [367862380] = "Lăng Mộ Và Kho Báu",
    [368079463] = "Cúp Danh Năng Hộp Sọ VI",
    [368328749] = "Kết nối tay cầm",
    [368874997] = "Đang biên dịch shader %k%%",
    [369162936] = "Bị bắt giữ bởi <lorename>Lupa</lorename>",
    [369557449] = "Đường Cắt Xoắn Ốc",
    [369733604] = "Hàng Rào Đá Mịn",
    [369843225] = "Một món ăn nhẹ cho chuyến hành trình. Sức mạnh cần để đập vỡ lớp vỏ sẽ được bù đắp khi tiêu thụ.",
    [369874444] = "Cúi người, né tránh và lăn khỏi nguy hiểm với chiếc áo vest nhẹ này.",
    [370113730] = "Khi tiêu diệt kẻ địch bằng vũ khí tầm xa, đòn tấn công tiếp theo của ngươi sẽ gây ST Chí mạng.",
    [371258557] = "Thu Hồi Cối Đá Trong Khi Dòng Nước Đã Ngắt",
    [371418426] = "Những cạnh sắc nhọn của đôi găng tay này kéo dài về phía đầu ngón tay người mặc, nhô ra như răng nanh hổ mang.",
    [371466742] = "Một loại vật liệu tuyệt đẹp nổi tiếng với màu sắc ấm áp và tươi sáng. Các nghệ nhân trên khắp thế giới đã ưa chuộng nó trong nhiều thế kỷ nhờ đặc tính dễ chế tác.",
    [371773118] = "Tia Chớp Giấc Ngủ",
    [371782285] = "Món hầm thịt nóng hổi. Tăng khả năng kháng lạnh cực độ, cải thiện lượng HP và khả năng hồi phục HP.",
    [371826483] = "Con quái thú tuy hùng mạnh nhưng không phải là bất bại. Hãy đỡ các vật thể bay tới hoặc sử dụng tên gây choáng để buộc con rồng phải hạ cánh.",
    [371864017] = "Tìm Áo Khoác Của Thuyền Trưởng",
    [371973461] = "Quần Chim Ưng",
    [373027222] = "Xem Các Nâng Cấp",
    [373375724] = "Kho chứa được 24 vật phẩm.",
    [373436142] = "Tiệm Của Thợ Cắt Tóc",
    [373507950] = "Một mũi tên có đầu bằng đồng.",
    [373642226] = "%k đã đánh dấu %k.",
    [373861296] = "Đá Granite",
    [373940370] = "Ngòi Châm",
    [374331375] = "Hiện tại ngươi không có Nhiệm Vụ nào chưa hoàn thành",
    [374409826] = "Có vẻ như chúng ta đã tập hợp đủ. Một nhóm ít ỏi, ít hơn nhiều so với dự kiến... Hầm Tro Cốt của chúng ta chỉ có thể canh giữ bấy nhiêu... nhưng chúng ta vẫn đứng vững. Cùng nhau, chúng ta sẽ thổi bùng ngọn lửa của ngươi, người bạn ạ. Mong ánh sáng của ngươi chạm đến những góc xa xôi nhất của vùng đất này!",
    [375374373] = "Rào chắn đã mở",
    [375606066] = "Tu Sĩ Sóng Triều",
    [376187027] = "Quần Lữ Khách",
    [376226756] = "Hai con Drak đối xứng được khắc trên cây chùy này. Dù vẻ ngoài giống nhau, chúng có thể không chung số phận — vì tính lưỡng diện của Mẫu Thể đòi hỏi kẻ yếu phải trở thành bữa tiệc cho kẻ mạnh.",
    [376299544] = "Đôi găng tay đáng tin cậy bảo vệ cánh tay người mặc khỏi những móng vuốt.",
    [376521840] = "Tỉ lệ xảy ra đòn tấn công chí mạng.",
    [376848573] = "Xây Dựng Thêm Căn Cứ",
    [377083065] = "Hôm Nay, Ta Đã Gặp Kiến Trúc Sư Giếng Tiên Dược",
    [377731364] = "Gậy phép Tết Nguyên Đán?",
    [378124154] = "Menu Xây Dựng Nhanh",
    [378530759] = "Kẻ Gây Tai Họa Băng Mưa",
    [378978068] = "Tia Nắng",
    [379187080] = "Ao Thợ Ren",
    [379757061] = "Thịt thú rừng chưa nấu. Phải được nướng trên lửa.",
    [379855537] = "Một loại vật liệu thực vật xanh lá, mọc tự nhiên ở Đầm Lầy Đen (Blackmire). Nó có thể được sử dụng để tạo ra mê cung hàng rào hoặc nghệ thuật sân vườn.",
    [379918413] = "Sảnh Đường Hollow",
    [380319108] = "Nhìn xuống",
    [381352676] = "Một chiếc quần màu xám. Chúng rất hợp để mặc lót bên dưới lớp giáp vải cầu kỳ của phần thân trên.",
    [381587469] = "Lén Lút",
    [382208174] = "Giày Rách Nát",
    [382595869] = "Cấp độ Hollow Đồng minh",
    [382674602] = "Một tập hợp các loại đá có kích thước khác nhau thường thấy trên các cánh đồng.",
    [383228163] = "Một đầu canh tóc giả giúp mở khóa thêm nhiều kiểu tóc khi nhặt được. Nó cũng có thể được đặt trong căn cứ của ngươi như một vật trang trí.",
    [384400286] = "Giày Chim Ưng",
    [384431990] = "Ngươi quên mất vũ khí của mình rồi sao? Ta đang đợi đây. Ngươi cần phải có khả năng chống trả — thế giới ngoài kia đáng sợ lắm, nhóc ạ!",
    [385989618] = "Tiến Vào Đền Thờ Và Cướp Phá Thợ Lặn Mất Tích",
    [386173540] = "Chiếc mũ giáp này kết hợp giữa mặt nạ, vải và sừng. Với hầu hết kẻ thù, đó sẽ là thứ cuối cùng chúng nhìn thấy khi bị ngươi đánh úp bất ngờ.\n\nBộ giáp này có thể tìm thấy trong các lăng mộ ở Lưu Vực Veilwater.",
    [386285988] = "Vĩnh Hằng Lộ Diện",
    [386645131] = "Nhà Sưu Tầm đã giao phó cho ngươi một nhiệm vụ. Sảnh Đường Hollow ở Cao Nguyên Du Mục đang che giấu 3 cổ vật ma thuật bên trong. Hãy tìm chúng để trưng bày trong căn cứ của ngươi!\n\nCó nhiều điểm ẩn giấu cổ vật. Hãy tìm kiếm các lối đi bí mật và luôn mở to mắt!\n\nVị trí của Sảnh Đường Hollow Cao Nguyên Du Mục sẽ xuất hiện trên bản đồ khi ngươi tìm thấy nó thông qua thám hiểm hoặc chấp nhận nhiệm vụ tiếp theo của Nhà Sưu Tầm. Nhiệm vụ sau sẽ khả dụng khi ngươi đạt cấp độ đủ cao.",
    [386976463] = "Tấn Công",
    [386981647] = "Làm Gì Với Những Tù Nhân?",
    [387127890] = "Chuột 5",
    [387128218] = "Phạm Vi Di Chuyển",
    [387636192] = "Kệ Gắn Tường Lâu Đài",
    [388036767] = "Mất Một Chút Tiến Trình",
    [388130378] = "Vukah",
    [388192829] = "Thêm nữa sao? Cứ lên tiếng đi!",
    [388454667] = "Chuông Trang Trí II",
    [388492663] = "Những Con Chó Của Cô Ấy Đâu?",
    [388805645] = "Đào",
    [389211585] = "Thiếu Nguyên Liệu",
    [389286001] = "Cuốc Đồng Đỏ",
    [389420307] = "Rìu Bóng Râm",
    [389462612] = "Bộ Trinh Sát",
    [389957518] = "Sửa Chữa Vật Phẩm",
    [389975481] = "Làm đầy bằng Vật liệu xây dựng bằng Gỗ.",
    [390224871] = "Tốc độ chạy nước rút tăng <b>10%</b> và tiêu hao SP giảm <b>10%</b>. ",
    [390336851] = "Hầm Tro Cốt",
    [390443400] = "Kiểm Tra Màu Sắc",
    [391373278] = "Trợ lý của nhạc công, Chester Loft, đã viết trong một mảnh giấy về việc tiến đến lâu đài tráng lệ của Lãnh chúa.\n\nCó lẽ ngươi có thể tìm thấy điều gì đó thú vị ở đó có ích cho mình. Hãy đến phòng ngai vàng của Lãnh chúa Vorgoth và lục soát nó!",
    [391471343] = "Những người tình này đã tìm kiếm sự trú ẩn trong Ngọn Lửa, nhưng nó không còn sưởi ấm họ nữa. Hãy dâng Tia Lửa của nó tại Đàn Thờ Lửa trong nhà của ngươi.",
    [391614053] = "Con trai ta, Jasper, khẳng định nó đã bị một bóng đen ghé thăm trong đêm tối. Lúc đầu, ta chỉ coi đó là giấc mơ của trẻ con, nhưng rồi, chưa đầy nửa tháng sau, chính ta cũng gặp phải hiện tượng tương tự. Cảm giác thật chân thực — một bóng người mặc áo choàng, lơ lửng và ám ảnh tâm trí ta bằng một từ duy nhất: \"Đào.\"",
    [391620973] = "Bụi Vàng",
    [391709372] = "Sự Thật Hay Thử Thách?",
    [391818554] = "Lò Sưởi Đất Sét",
    [392463228] = "Một cây cung được tiếp sức bởi ánh sáng mờ ảo hắc ám của Sương độc. ",
    [393219820] = "Những Cột Đá Cổ Đại",
    [393744561] = "Hỡi Hỏa Nhân, người bạn thân mến — mặt đất đang rung chuyển bởi sự phẫn nộ! Hãy xuống đó và dập tắt cơn thịnh nộ vĩnh cửu ấy!",
    [393746980] = "Khi kỹ năng của ngươi được mài giũa, sức mạnh của Ngọn Lửa sẽ lớn dần. Ngươi phải quyết định con đường tốt nhất cho kỹ năng của mình trong nỗ lực đầy gian khổ chống lại Sương độc.",
    [393874466] = "Chinh Phục Ngọn Tháp Cổ Đại Ở Đỉnh Albaneve",
    [394406936] = "Quần Mùa Đông",
    [394549512] = "Nhẫn Ánh Sáng Cháy Bỏng",
    [395261705] = "Ô Hình Dạng Công Trình 7",
    [395716004] = "Làm yếu hiệu ứng bất lợi <b>Ẩm Ướt</b> và <b>Sũng Nước</b>.\n\nSP và Hồi phục SP bị giảm <b>20%</b> thay vì <b>30%</b>.\n\n<b>Ẩm Ướt</b> \nGiảm SP và Hồi phục SP đi <b>30%</b> trong <b>15</b> phút. Hơi ấm sẽ làm giảm thời gian còn lại.\n\n<b>Sũng Nước</b> \nGiảm SP và Hồi phục SP đi <b>30%</b> trong <b>30</b> giây. Đồng thời giảm <b>Kháng Băng và Kháng Lôi</b> đi <b>30%</b> nhưng tăng <b>Kháng Hỏa</b> thêm <b>30%</b>.\n<b>Sũng Nước</b> có thể áp dụng lên kẻ thù.\nThời gian tác dụng của <b>Sũng Nước</b> không thể bị giảm bởi hơi ấm, và sẽ chuyển thành hiệu ứng <b>Ẩm Ướt</b> sau khi kết thúc.",
    [396279673] = "Thiên Thạch Giáng Thế Đã Sẵn Sàng",
    [396718452] = "Cấp Độ Vượt Sương độc",
    [397395555] = "Mã Tấu Của Nhà Thám Hiểm",
    [398033330] = "Đừng Quất Con, Mẹ Ơi",
    [398459901] = "Tùy Chỉnh",
    [398810179] = "Dân Làng",
    [398867974] = "Sử dụng tại rương chứa đồ và một số trạm chế tác",
    [399247197] = "Hôm Nay Ta Đã Có Một Khoảng Thời Gian Tuyệt Vời Nhất",
    [399488387] = "Đèn Bạc Gắn Tường Nhỏ",
    [400095027] = "Sự Tinh Tế",
    [400447424] = "Tăng mạnh độ phóng đại khi ngắm bắn bằng Cung.\n\nĐể ngắm, hãy giữ %k khi Cung đang được chọn trong thanh Hành động.\n(Hoặc giữ %k để ngắm bằng Cung đang trang bị.) ",
    [400780545] = "Bộ Sưu Tập Sách II",
    [400793651] = "Mũ Ba Góc",
    [400960383] = "Ủng nhẹ. Phần mũi hơi nhọn.",
    [401033447] = "Công Trường \"Maelstrom\"",
    [401110455] = "Năng lượng của người sử dụng tan chảy bên trong lớp vỏ rỗng của đũa phép và tái tạo để bắn ra một luồng năng lượng nguyên tố vô tận.\n\n<b>Quá Tải:</b>\nĐũa phép này có cơ hội khuếch đại sát thương đầu ra. Các đòn tấn công gây thêm sát thương lên đến tỷ lệ phần trăm <i>quá tải</i>. ",
    [401192728] = "Nông dân Fenrig giải thích rằng dân làng cần thức ăn và một chiếc giường ấm áp, có mái che để làm việc tốt nhất và cảm thấy hạnh phúc. Ngươi có thể chỉ định một chiếc giường trống cho những người đi theo bằng cách sử dụng Gậy phép triệu hồi và nhắm vào giường.\n\n<b>Hãy chỉ định một chiếc giường có mái che cho Fenrig để tiếp tục!</b>",
    [401918342] = "Tiêu diệt kẻ thù khi không có Hollow thiết giáp đồng minh nào đang hoạt động sẽ có cơ hội triệu hồi một Hollow thiết giáp đồng minh cấp %k.",
    [402472730] = "Chân phải của một tên Cyclops hoang dã. Bộ xương vẫn còn nguyên vẹn.\n\nVật phẩm sưu tầm này được tìm thấy ở Đỉnh Albaneve. Nó có thể được lắp ráp lại để tạo thành Bộ Xương Cyclops trên Đế Trưng Bày Cyclops.",
    [402642014] = "Ngươi sẽ quay lại thôi. Bọn họ luôn như vậy.",
    [402803034] = "Thay Đổi Bản Thiết Kế",
    [402997844] = "Miếng da này đã được làm cho chắc chắn và bền bỉ hơn.",
    [403019033] = "Thêm <b>mỏ neo kéo</b> này vào công trình của ngươi để <b>kéo bản thân về phía trước</b> và lên các nền tảng khác. Yêu cầu Móc Leo để kích hoạt.",
    [403215392] = "Lăng Mộ Ma Quái",
    [403309470] = "Biểu Tượng Tường Hình Kim Cương II",
    [403380532] = "Một chiếc gối đầy màu sắc sẽ khiến bất kỳ căn phòng nào cũng trở nên ấm cúng hơn.",
    [403633489] = "Cơn hưng phấn từ đường sẽ tăng cường khả năng hồi phục SP của ngươi trong một thời gian ngắn.",
    [404131034] = "Song Kiếm Song Hỏa",
    [404414285] = "Xoay Tinh Chỉnh",
    [404431541] = "Vị Khách Đặc Biệt Trong Đêm Hollow",
    [404947250] = "<npc>Thợ Săn</npc> Cần Nơi Trú Ẩn",
    [405373933] = "Chế tạo một chiếc máy quay sợi không khó đâu. Ta có thể chỉ cho ngươi cách làm!",
    [405443641] = "Tìm Tất Cả Vật Phẩm Trang Điểm Mùa Đông",
    [405792403] = "Đá Vụn Rừng Revel",
    [406519618] = "Gạo Sống",
    [406815638] = " <npc>Nông Dân</npc> muốn làm tổ ong và mật ong, nhưng thiếu một <craftingstation>Bình Hun Khói Tổ Ong</craftingstation>. Cách đây rất lâu, bà ấy đã đặt một chiếc <craftingstation>Bình Hun Khói Tổ Ong</craftingstation> cho quán trọ của mình ở <location>Brittlebush</location>, nhưng chuyến hàng đã không đến trước khi bà ấy rời đi. <craftingstation>Bình Hun Khói Tổ Ong</craftingstation> mở khóa khả năng chế tạo <craftingstation>Tổ Ong Mật</craftingstation>.\n\nHãy tìm kiếm <b>quán trọ của Emily Fray ở <location>Brittlebush</location></b> để tìm manh mối và thu hồi <craftingstation>Bình Hun Khói Tổ Ong</craftingstation>.",
    [406935694] = "Đến Lúc Thu Hoạch",
    [407185611] = "Việc ngài nộp đầu Cyclops sẽ mang lại lợi ích lớn cho chúng ta, và sự tận tụy của ngài đã được ghi nhận, Thượng sĩ. Chúng tôi đã ra lệnh vận chuyển cái đầu đến phòng thí nghiệm gần đó.\n\nChúng tôi đã lưu ý yêu cầu thanh toán thêm vàng của ngài, vì hai thành viên trong đội của ngài, như ngài đã mô tả, <i>\"bị Cyclops xé xác, chỉ còn lại nội tạng, chết tiệt thật!!\"</i>\n\nChúng tôi sẽ xem xét yêu cầu của ngài với sự cẩn trọng cao nhất. \nĐừng liên lạc với chúng tôi, chúng tôi sẽ liên lạc với ngài.\n\nTrân trọng,\nVăn phòng Trung úy Arlington, Giám sát viên thứ nhất của Chương trình Mở rộng",
    [407278929] = "Ô Thanh Hành Động 2",
    [408273107] = "Một sự im lặng kỳ quái bao trùm The Pike. Hãy điều tra lâu đài để xác định nguồn gốc của những cơn ác mộng, và những ánh sáng từ bên dưới.",
    [408623051] = "Chợ Ngày Mùa Đông",
    [408634061] = "Trại <npc>Thợ Săn</npc> Bỏ Hoang",
    [409768096] = "Sậy Giấy",
    [410080115] = "Găng Tay Trinh Sát",
    [410213683] = "Ngươi đã tìm thấy một ghi chú đề cập đến một chiếc cần câu bị nguyền rủa, được ngư dân cất giữ trong một tầng hầm ở <location>Pondsworth</location>.\n\nHãy tìm cách đi xuống lòng đất và thu hồi chiếc cần câu đó!",
    [410276216] = "Nước Đang Dâng",
    [410438428] = "Theo Sắc Lệnh Hoàng Gia ",
    [410464760] = "Thu Thập Máy Nghiền",
    [410497184] = "Giường",
    [410789107] = "Ngươi đã tìm thấy đèn lồng giấy chưa?",
    [411407153] = "Cây Tầm Ma Độc",
    [412630378] = "Bừa Cào",
    [412784746] = "Nâng Cấp Ngọn Lửa Lưu Vực Veilwater",
    [412903288] = "Khả năng bảo vệ của ngươi chống lại các đòn tấn công ma thuật. Mỗi điểm giúp giảm 1 sát thương nhận vào.",
    [413138221] = "https://Sương độc bao phủ.com/privacy-policy-for-Sương độc bao phủ",
    [413149552] = "Ngươi đã bắt được:",
    [413181217] = "Đôi ủng này được làm bởi những thợ đóng giày tài ba nhất và có giá trị cực kỳ đắt đỏ.",
    [413188686] = "Găng Tay Kẻ Phá Phép",
    [413502374] = "Nâng Cấp",
    [413737516] = "Chạm",
    [413995014] = "Cay và nóng! Thức uống tốt nhất cho những vùng oi bức, vừa giải khát vừa làm mát cơ thể cùng một lúc.",
    [414272780] = "Áo Giáp Sừng Núi Tuyết",
    [414276885] = "<b>Thay mặt Đức Ngài, Lãnh chúa Vorgoth, Hộ vệ Phương Bắc</b>\nĐức Ngài theo đây tuyên bố bằng sắc lệnh hành pháp:\n\n<i>Tất cả các đơn vị đồn trú của Chương trình Mở rộng phải kiềm chế việc nhắc đến Lãnh chúa Vorgoth bằng những cách khiếm nhã hoặc không phù hợp một cách sáng tạo.\n\nTất cả các đơn vị đồn trú của Chương trình Mở rộng phải báo cáo những lời đồn thổi và những kẻ hay chửi bới để chúng có thể bị đưa ra công lý bằng gông kìm, hoặc, nếu tái phạm, sẽ bị giam giữ trong ngục tối với thời gian thay đổi tùy theo phán quyết tốt nhất của giám sát viên.\nHình phạt bổ sung, thích hợp nhất là xử lý bằng một ngọn giáo gỗ vót nhọn có đường kính và chiều dài phù hợp, có thể được thực hiện tùy ý —</i>\n\n(Phần còn lại của sắc lệnh quá rách nát để có thể giải mã.)",
    [414697743] = "Cây Giống Xô Thơm",
    [415317243] = "Đóng",
    [415443856] = "Loại chuối lá này, không nên nhầm lẫn với chuối thông thường, không thể ăn sống. Nó chứa nhiều tinh bột và có thể được dùng làm thực phẩm chính trong nhiều món ăn sau khi nấu chín.",
    [415577035] = "Mồi Thức Ăn Tê Tê Cát",
    [415684054] = "Toàn Cầu",
    [415892580] = "<b>Vua <lorename>Gormander</lorename></b>, con trai của <lorename>Pikemead</lorename> vinh quang, người bảo hộ vĩ đại của Revelwood và Springlands, dõi theo tất cả. <i>Ánh mắt cảnh giác</i> của ngài gắn kết chúng ta thành một, che chở chúng ta khỏi tai ương và <i>đưa chúng ta vào một kỷ nguyên thịnh vượng mới.</i>",
    [416109840] = "Ta tự hỏi chuyện gì đã xảy ra với đội cận vệ hoàng gia, và liệu còn sót lại thứ gì hay ai trong số họ không.",
    [416314364] = "Những Bài Hát Và Tiếng Cười",
    [416640019] = "Bình Cốt Vàng Đính Đá",
    [417180994] = "Ủng rừng làm từ các dây da được xếp lớp cẩn thận.",
    [418057230] = "Bạn đã lấy được con dao của tôi! Bạn có biết lưỡi dao này từng là tăm xỉa răng của người khổng lồ trước khi tôi mượn nó không? Giữ lấy con dao! Nó nên được nhìn thấy thế giới nhiều hơn là nằm trong miệng người khổng lồ.",
    [418496118] = "Thợ Cắt Tóc Elio cần thỏa mãn cơn nghiện cà phê của mình và đã nhờ ngươi giúp đỡ.\n\nAnh ta đã hướng dẫn ngươi thu hồi một chiếc máy rang hạt cà phê và nghi ngờ rằng thứ đó có thể được tìm thấy ở Vịnh Stillwater, một thị trấn có bến cảng lớn và các đồn điền cà phê lân cận.\n\nHãy đến Vịnh Stillwater để bắt đầu cuộc tìm kiếm!",
    [418839867] = "Khi được bảo quản, Quả Mọng Tím Khô không hồi phục nhiều HP như Quả Mọng Tím tươi. Tuy nhiên, thời gian tác dụng kéo dài hơn.",
    [419100135] = "ms",
    [419188603] = "Với giáp ngực này, ngươi có thể băng qua rừng một cách dễ dàng, không bị phát hiện khi chuẩn bị cho đòn tấn công tiếp theo.\n\nBộ giáp này có thể được tìm thấy trong các lăng mộ ở Lưu Vực Veilwater.",
    [419522066] = "Những Người Sống Sót Hiện Có",
    [419570074] = "Hồi phục SP tăng ",
    [419580207] = "Tủ Chén",
    [419663694] = "Một vương quốc bị lãng quên đầy rẫy những tàn tích, ẩn giấu trong bụi rậm này! Cháu trai ta, kẻ đam mê thiết kế đó, chắc chắn sẽ trợn tròn con mắt duy nhất của nó khi nhìn thấy cảnh này! \n\nNhững vết cắt trên những tảng đá không rõ nguồn gốc này tuy thô sơ nhưng gọn gàng. Liệu bộ lạc Vukah địa phương có tạo ra những... <i>vật phẩm hiến tế</i> này không?\n\n Ta sẽ không nán lại để tìm hiểu đâu! \n\n— Braelyn",
    [420241415] = "Ngươi đã đến nơi được cho là bị ma ám mà Thợ Cắt Tóc đã nhắc tới: Công Trường \"Maelstrom\".\n\n<b>Hãy điều tra khu vực này</b> để thu thập thông tin về \"lời nguyền\" và những <b>đôi mắt xanh sáng</b> điên dại!",
    [420344910] = "Một dấu vết bọ ba thùy chi tiết. Cấu trúc bộ xương ngoài của nó vẫn có thể được nhìn thấy rõ ràng.\n\nVật phẩm sưu tầm này được tìm thấy ở Revelwood.",
    [420375616] = "Một cây gậy phép ma thuật cơ bản được cung cấp năng lượng bởi tinh thần của người sử dụng.\nCác cây gậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các điểm niệm phép và MP. Trang bị <b>điểm niệm phép</b> để niệm phép.",
    [420841242] = "Tất cả sát thương <b>Băng</b> được tăng thêm <b>10%</b>. ",
    [422448498] = "Đèn Đứng Đom Đóm",
    [423742349] = "Ta đã mài dao, vá lỗ thủng trên quần, và quan trọng nhất là gắn lại những chiếc chuông nhỏ leng keng vào mũ! Sân khấu trông cũng ổn. Ta không nghĩ khoảng cách ném sẽ là vấn đề lớn. Mọi thứ đã sẵn sàng cho buổi biểu diễn.\n\nƯớc gì ta có thêm thời gian để luyện tập, nhưng điều tồi tệ nhất có thể xảy ra là gì chứ? Ta đã diễn tiết mục này vô số lần rồi, nên ta chắc chắn mọi chuyện sẽ ổn thôi.",
    [423786095] = "Hoa Nở Chạng Vạng",
    [423979022] = "Khung Dệt",
    [424096490] = "Tốc Độ",
    [424131956] = "Gia súc Trang trại",
    [424268961] = "Mũ Giáp Hắc Vệ",
    [424520266] = "Đỉnh Albaneve",
    [425171566] = "Ghế Đá",
    [425376009] = "Ngọc Linh Hoạt",
    [425415170] = "Hỡi Hỏa Nhân, hãy hạ giọng. Ngươi có nghe thấy tiếng thủy triều đang dần xâm lấn, lúc đầu nhỏ bé, rồi sau đó nghiền nát mọi thứ? Ngươi có nếm được vị muối biển và mồ hôi? Ẩn sâu trong thung lũng xanh rì, ta thấy thấp thoáng sắc xanh. Nhưng có một gợn sóng trong làn nước tĩnh lặng này: Một giọt máu từ những năm xa xưa đã làm vẩn đục biển cả và giờ đây đang vỗ vào bờ vai chúng ta, triệu hồi những Tinh thần thù hận... bị lãng quên, nhưng vẫn hiện hữu. Để kiên trì, chúng ta cần ai đó dẫn lối — và những lưỡi kiếm sắc bén.",
    [425830809] = "Triệu hồi Tinh linh\n\nSau khi gây ST Phép chí mạng, một quả cầu MP sẽ được tạo ra tại mục tiêu.",
    [425836161] = "Định hình Embervale",
    [425948899] = "Một thanh đoản kiếm cơ bản được thiết kế cho các cuộc chiến trong không gian hẹp. Cực kỳ linh hoạt với mũi kiếm sắc lẹm.",
    [426667087] = "Mở rộng nhà của bạn bằng cách <b>nâng cấp Tế Đàn Ngọn lửa</b> để tăng phạm vi bảo vệ. Nâng cấp Tế Đàn Ngọn lửa yêu cầu Lõi Sương độc, vật phẩm nhận được bằng cách đánh bại <b>kẻ thù thủ lĩnh</b>.\n\nTăng phạm vi sẽ cho bạn thêm không gian để xây dựng.",
    [427549457] = "Găng Tay Sừng Núi Tuyết",
    [427891923] = "Hầm Ngục Cổ Đại — <npc>Thợ Rèn</npc>",
    [427991871] = "Tìm thấy trong Hang Sương độc Đỉnh Albaneve",
    [428350649] = "Hút Linh Hồn",
    [428697935] = "Đấu Sĩ Vukah",
    [428815059] = "Độ rung màn hình",
    [429028140] = "Bạn tìm thấy một bức thư đề cập đến hầm mộ bí ẩn. <b>Hãy đến nghĩa trang dưới lòng đất</b> và điều tra lối vào!",
    [429583415] = "Một làn hơi dày đặc, cuộn xoáy được chiết xuất từ những kẻ dùng phép Fell. Nó chứa đựng ma thuật Sương độc thanh khiết, khiến nó trở nên vô giá để chế tạo áo giáp ma thuật và cường hóa các phép thuật tàn phá.\n\n<b>Nguyên liệu chế tác:</b> Chủ yếu dùng để chế tạo áo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Fell Sicklescythes, ban đầu được tìm thấy ở Kindlewastes.",
    [429619629] = "Cho Thợ Cắt Tóc Thấy Băng Giá Sương Độc Bao Phủ",
    [429656397] = "Trang trại",
    [429714917] = "Nhặt lên",
    [429733614] = "Hình dạng địa hình",
    [430069400] = "Nhớ tìm những bản nhạc đó... nếu ngươi không quá bận rộn với cái công việc \"tái thiết vương quốc\".",
    [430954543] = "Lũ Vukah tổ chức các nghi lễ vô nhân đạo tại <location>Pháo Đài Kelvin</location>. Marianne Reed báo cáo rằng lũ Vukah thường xuyên đẩy dân làng xuống vách đá, và cô ấy muốn tìm hiểu thêm.\n\nHãy điều tra hố hiến tế!",
    [431025654] = "Xương Rải Rác",
    [431307437] = "<location>Westcott</location>",
    [431414535] = "Nữ hoàng của chúng đã ngã xuống. Thuốc tiên và máu làm vẩn đục bùn lầy. Một sự im lặng êm dịu cuối cùng cũng bao trùm màn đêm.\n\nThu thập nhiều Mũ Mẫu Thân Scavenger để chế tạo Cúp Sắt.",
    [431425185] = "Bùn Dưới Nước",
    [431491375] = "Đôi ủng của kẻ lữ hành, đã sờn cũ nhưng vẫn đủ chắc chắn để gánh vác hành trình của ngươi.",
    [431914833] = "Một Phép Thuật Quyền Năng",
    [432097339] = "Sinh Vật Không Mặt Đó",
    [432829027] = "Đao Băm Đen Tối",
    [433911171] = "Chế tạo Bảng Màu",
    [434063828] = "Thế giới",
    [434571276] = "Quán rượu \"Muối Và Tiêu Già\"",
    [434799573] = "Nhẫn Thối Rữa",
    [434824818] = "Thuốc Tiên Sương độc này chứa đựng sức mạnh to lớn... nhưng phải trả giá.\n\nTăng sát thương của bạn lên Fell nhưng giảm thời gian tồn tại trong Sương độc.",
    [435022271] = "Khu định cư Vukah trên ngọn cây",
    [435177233] = "Ngươi đã đọc một ghi chú đề cập đến một nhóm săn bắn gần đây từ Kindlewastes! Hãy tìm kiếm tàn tích của nhóm săn để tìm các thành viên của họ!",
    [435663445] = "Đất đai ngày càng khô cằn. Nó vỡ vụn giữa những ngón tay ta thành cát bụi. Ta lau những giọt mồ hôi trên trán. Những giọt lệ nhợt nhạt, sầu muộn thấm xuống cánh đồng. Ta nghi ngờ liệu chúng có tìm được đường vào lòng đất để nuôi dưỡng mùa màng hay không. \n\nTa cầu nguyện, trong thầm lặng, vì đôi môi ta đã quá khô để thốt nên lời... nhưng ta vẫn cố mỉm cười khi phục vụ chút ít những gì ta có. <b>Ta đã tự tay xây dựng quán rượu này...</b> vì vậy, ta không thể nghỉ ngơi, cũng không thể rời đi. Ta sẽ canh tác mảnh đất này cho đến cuối cùng, như tổ tiên ta đã làm trước đây. \n— Emily Fray",
    [436243286] = "Xưởng Bia Nhỏ",
    [436247944] = "Ngươi không có quyền nâng cấp Ngọn Lửa.",
    [436301920] = "Tìm Kẻ Đào Tẩu Bất Thành",
    [436954807] = "Vừa đủ để bảo vệ người mặc khỏi những tia lửa.",
    [437104598] = "Vậy là những hầm mộ rùng rợn nơi trú ngụ của Hollow là có thật sao? Dì <lorename>Elin</lorename> của ta thường kể những câu chuyện — nhưng mà, ngươi biết dì ấy rồi đấy. Luôn là một kẻ kể chuyện hão huyền. Nếu lão Balthazar đã tận mắt nhìn thấy chúng.... thì đó là sự thật. Ôi, hãy nghĩ về các nguyên liệu! Kiến trúc! Kho báu!! Ta ước đôi chân ngắn ngủi này cũng có thể đưa ta đến đó!",
    [437595155] = "Trong tất cả các vương quốc dưới bầu trời bao la, ta đã bị đè nặng bởi vương quốc hoang dã nhất. Một nửa lãnh thổ của ta bị bóp nghẹt trong những dây leo; mọi rễ cây và tảng đá đều âm mưu chống lại quyền sở hữu của ta.\n\nQuân lính của ta quá yếu hèn để kiểm soát những tàn tích cổ xưa. Một cái bẫy đặt trong ngôi mộ ngập nước khiến chúng chạy tán loạn như lũ chuột nhắt. Không một kẻ nào trong số chúng dám vung búa vào các đền thờ, để nghiền nát chúng thành tro bụi để trật tự có thể ngự trị một lần nữa. Có lẽ rẽ về phía đông sẽ khôn ngoan hơn... những đỉnh núi không bị ám ảnh bởi ký ức.\n\nTrong khi đó, <i>anh chị em thân mến</i> của ta đã triệu tập ta đến buổi dạ vũ hàng năm — một màn kịch lịch sự mệt mỏi, buộc ta phải bỏ mặc ngai vàng không người canh giữ. Họ không thấy mối nguy hiểm sao? Biên giới của ta là lá chắn duy nhất chống lại <i>những vị thần lừa lọc xảo quyệt!</i> Có lẽ lời mời của họ lại là một cái bẫy khác, một ngôi mộ khác để chết chìm...!\n...Thật là suy nghĩ ngu ngốc. Những dây leo mê hoặc tâm trí ta, bao bọc ta trong sự hoang tưởng. Ta sẽ tham dự, như nghĩa vụ bắt buộc — và ta sẽ thúc giục họ xây dựng máy bắn đá, chứ không phải \"Thánh Đường Đêm\". Mang lại sự khôn ngoan cho một đám đông không lời... Thật sự, dòng tộc của ta đã trở nên nuông chiều bản thân, bị mê hoặc bởi sự bí ẩn của các Cổ Nhân.\n\nTa phải nghỉ ngơi. Trước bình minh, ta sẽ tiếp kiến một <i>kẻ lữ hành</i> đã len lỏi vào triều đình của ta. Hắn tuyên bố mang theo một món quà từ <i>thế giới bên kia.</i> Ta sẽ lắng nghe hắn. Hắn hứa hẹn một sự tiêu khiển. \n\n— Lãnh chúa <lorename>Vorgoth</lorename>, Hộ vệ phương Bắc",
    [437606117] = "Thẻ:",
    [437753367] = "Một khuôn mặt kinh hoàng được khắc trên cây chùy, nhìn xuống kẻ thù khi ngươi đập nát chúng xuống đất.",
    [438330928] = "Hãy Cùng Lập Ban Nhạc",
    [438666209] = "Trọng Kiếm Sương Mai",
    [438870575] = "Sự Kết Thúc Của Thuyền Trưởng",
    [439231010] = "%k điểm",
    [439231035] = "Sử dụng Dịch Chuyển Nhanh và trò chuyện với Ngọn Lửa của Tòa Tháp Cổ Đại",
    [439355090] = "Một loại thuốc giúp tăng cường thị lực của ngươi trong Sương độc.",
    [439465165] = "Lối tắt",
    [439633353] = "Chuông Trang Trí I",
    [439786454] = "Mọi Chuẩn Bị Đã Hoàn Tất!",
    [439910014] = "Đảo Câu Cá",
    [439970621] = "Bắt buộc cho phép vai trò Bạn bè công khai",
    [440129080] = "Mũ Thuật Sĩ",
    [440541024] = "Gia nhập",
    [441032272] = "Tia Sáng Bùng Nổ",
    [441507783] = "Hiện/Ẩn Chi Tiết Vật Phẩm",
    [441596595] = "Ngay lập tức hồi phục một lượng lớn SP.",
    [441634443] = "Một phần của Bộ Giáp Mắt Đại Bàng.",
    [441653928] = "Nhà Vệ Sinh Đá",
    [441679388] = "Tỉ lệ Chí Mạng Phép Thuật",
    [442058783] = "Một chiếc mũ trùm đầu giúp bảo vệ thêm khỏi ánh mặt trời, cho phép ngươi tập trung tầm nhìn mà không bị quấy rầy.",
    [442103584] = "Đối mặt với kẻ thù của ngươi, một chọi một, và chứng minh sự thống trị của ngươi một lần và mãi mãi.",
    [442247002] = "Không có hơi ấm gần đây",
    [442383829] = "Những Con Người Mềm Yếu",
    [443029615] = "Tế Đàn Ngọn lửa Cấp 1",
    [443421535] = "Một cây cung chạm khắc tiêu chuẩn gợi nhớ về những ngôi đền bị lãng quên và những lăng mộ rêu phong. Nó khiến ngươi muốn đi thám hiểm những kho báu ẩn giấu!\n\nTrộm mộ là hành vi xấu, và ngươi không nên làm điều đó khi có ai đang nhìn.",
    [443499820] = "Tài nguyên để thi triển phép thuật.",
    [443694696] = "Kền Kền Long Tộc Đã Bắt Hắn",
    [443810880] = "Nội Thánh Đường",
    [443869447] = "Đang chơi: %k",
    [443986545] = "Điều chỉnh chất lượng ánh sáng gián tiếp. Giá trị thấp hơn sẽ cải thiện hiệu suất.",
    [444220465] = "<lorename>Trưởng lão Dwyn</lorename>",
    [444667636] = "Vừng ơi mở ra!",
    [444710359] = "Tiếng Ý",
    [445154061] = "Một con Chim Cánh Buồm Mỏ Tròn trưởng thành, sẵn lòng hiến tặng những chiếc lông vũ tươi mới cho mục đích của ngươi.",
    [445222884] = "Tòa Tháp Cổ Đại",
    [445831046] = "Alden",
    [445884249] = "Đến Vịnh Stillwater",
    [446548615] = "Một chiếc khung hữu ích có thể chứa các mảnh ghép của tranh khảm Ngọn Lửa. Nó phải được đặt trên mặt đất.",
    [446596603] = "Cá nhân:%k + Ngọn lửa ban phước:%k + Tăng cường tạm thời:%k",
    [447135127] = "Bảng màu này có thể được chế tạo bằng các nguyên liệu từ Springlands.",
    [447236431] = "Vấn Đề Đặt Tên Mèo",
    [447263172] = "Nó chưa được nấu chín kỹ. Ăn sống thứ này sẽ gây buồn nôn.",
    [447323050] = "Rương Vừa",
    [447467182] = "Sự Ra Đời Của Các Vị Thần Mới - Fyraszh",
    [447558924] = "Một chiếc khiên sẽ mang lại sự an toàn và hỗ trợ. Với một cái giá phải trả.",
    [447634027] = "Ngai Vàng Hầm Mộ",
    [447638775] = "Ngươi đã tìm thấy một mảnh của bức thảm treo tường. Mảnh thứ hai không còn xa nữa.\nĐến địa điểm thứ hai để lấy mảnh thảm treo tường còn lại!",
    [447797698] = "Khả năng hồi phục HP được tăng lên bởi Hào Quang Nước gần đó.",
    [447863660] = "Công Thức Chế Tạo Ẩn — Blackmire",
    [448619021] = "Giày Hoa Hồng Máu",
    [448855328] = "Nó được viết bởi Người Cổ Đại. Tiếng gọi kỳ lạ và du dương của họ xuyên thủng khoảng không im lặng và mang đến những người xứng đáng và công chính. Ta không thể đọc nó. Ta chỉ thấy một mờ ảo... thông điệp không dành cho ta, ta e rằng. Ta cố gắng nghiên cứu nó, để hiểu nó... Nhưng càng học, ta càng khám phá ra mình không biết bao nhiêu.\n\nTa có thể quan sát Thành Phố Chìm từ đây, nhưng không hoàn toàn yên bình. Gần đây có kẻ đã làm gián đoạn nghiên cứu của ta bằng một <i>tiếng huýt sáo đau đớn</i>. Ban đầu ta nghĩ đó là một tên Scavenger, nhưng may mắn thay, ta đã nhầm. Có lẽ <i>họ</i> sẽ hiểu ý nghĩa của thông điệp các vì sao.\n\nGửi đến tất cả những ai đã nghe theo tiếng gọi: Hãy nhận lấy những mũi tên của ta, và để chúng dẫn đường cho các ngươi.",
    [449066415] = "Bị Quấn Chặt Và Ngạt Thở",
    [449243605] = "Các tấm phiến kim loại giúp tăng cường bảo vệ chống lại những mũi tên răng cưa hoặc tẩm độc.",
    [449306898] = "Một bức phù điêu chi tiết về lịch sử của tộc Drak.\n\nNhân loại được khắc họa là những kẻ chiến thắng! Họ đẩy lùi những kẻ tấn công, và tộc Drak buộc phải rút lui qua đại dương đến một quần đảo.",
    [449619763] = "Liệu Ta Có Thể Tận Hưởng Cái Ôm Cuối Cùng?",
    [450032192] = "Thức ăn bổ dưỡng dành cho thú cưng đã thuần hóa.\n\nPhải được đặt vào máng ăn phù hợp.",
    [451676798] = "Ôi trời ơi, con bé có thể ở đâu được chứ? Con gái tôi, tôi đã lạc mất Marianne bé bỏng rồi! Tôi không thể tìm thấy con bé ở bất cứ đâu, nó đã biến mất theo làn gió! Làm ơn hãy giúp tôi!",
    [452066296] = "Kích hoạt <b>Tấn Công Lén Lút</b> sẽ hồi phục <b>10%</b> SP.",
    [452203209] = "Đoản Kiếm Thần Tốc",
    [452347774] = "Đã thu thập <craftingstation>Dụng Cụ Nề</craftingstation>",
    [452956745] = "Bí Ngô Đêm Khô Cốt Vừa I",
    [453678623] = "Đũa Phép Phát Sáng",
    [453688736] = "Giao Thương Vũ Khí",
    [453782947] = "Ta sẽ cầu nguyện cho sự bình an của ngươi!",
    [453799582] = "Thiết Lập Sẵn A",
    [454533370] = "Đến Khu Định Cư Vukah",
    [454831315] = "Kẻ Sống Sót",
    [455556640] = "Thợ Cắt Tóc, Elio Ricci, muốn tìm một bảng màu đại diện cho sự trù phú trước kia của Hoang Mạc Rực Lửa.\n\nNữ Nông Dân, Emily Fray, đã nói với ông ấy rằng những bảng màu như vậy có thể tìm thấy gần các trang trại hoặc thị trấn nơi người dân thường tự nhuộm quần áo.\n\nElio muốn ngươi thám hiểm một <b>trang trại</b> như vậy để tìm kiếm <b>bảng màu!</b>",
    [455733745] = "Một Màn Trình Diễn Hiểm Độc",
    [456239649] = "Ramone Jones từng là một phóng viên tại <location><lorename>Pikemead</lorename>'s Reach</location>, chuyên viết về những sai lầm của Tân Vương Gormander, con trai của Pikemead. Ông ta kể rằng Vua Gormander đã cho tháo dỡ và thay thế bức tượng của Nữ Hoàng Pikemead, nhưng các mảnh của bức tượng có thể vẫn còn đâu đó. Ramone Jones có một manh mối sẽ dẫn ngươi đến vị trí của một mảnh như vậy. \n\nHãy đi theo manh mối của Ramone và tìm mảnh đầu tiên của bức tượng!",
    [457079821] = "Không Có Sự Trợ Giúp Nào Đâu",
    [457399776] = "Cắn câu rồi!",
    [457473793] = "Xây Dựng",
    [458188164] = "Tinh Linh Sốc Điện",
    [458251143] = "Ánh Sáng Gián Tiếp",
    [458399795] = "Hôm Nay Chúng Ta Trở Về Với Đất Mẹ",
    [458624921] = "Tìm Trống Cầm Tay",
    [458940593] = "Yêu Cầu Trò Chuyện Bằng Giọng Nói",
    [458985903] = "Đất nhiễm Sương độc thoạt nhìn có vẻ nguy hiểm. Tuy nhiên, khi được sử dụng trong môi trường kiểm soát, nó có thể tạo ra một môi trường sinh học mạnh mẽ thúc đẩy sự phát triển nhanh chóng.\n\n<b>Thoát Nước</b>\nVật liệu này <b>thoát một lượng nhỏ nước</b> khi bị tràn.",
    [459316054] = "Đã học được kiến thức về nguyên liệu!",
    [459661235] = "Đâm xuyên tim.",
    [460151880] = "Trại Khai Quật Bộ Xương \"Ony\"",
    [460330634] = "Một vũ khí hung bạo làm từ thủy tinh đen. Lưỡi kiếm dường như đang sống, tối tăm như hư không và sắc bén như vảy rồng Drak.",
    [460351593] = "Tiếng Hàn",
    [460961135] = "Đấu Trường Sinh Tử",
    [461068498] = "Cái giếng này đủ sâu để chạm tới cả những túi nước ẩn giấu nhất. \n\nNó đã được cải tiến và có thể tiếp cận mạch nước ngầm nhanh hơn.",
    [461863332] = "Tinh Hoa Cổ Xưa",
    [461950388] = "Ta Cảm Thấy Vận May Đang Đến",
    [462215017] = "Cromville",
    [462293136] = "Một chiếc chùy với những chiếc gai dài nhô ra được rèn từ thép tắm ánh trăng. Những vệt máu loang lổ dễ dàng được nhìn thấy trên vũ khí này.",
    [462522592] = "Đặt Lại Mặc Định",
    [462586570] = "Trong một ghi chép, ngươi đọc được rằng một ngư dân kỳ lạ đã hái vô số quả u sầu ở Rừng Revel và làm phiền những vị khách gần đó. Ngươi tự hỏi gã ngư dân đó dùng quả u sầu để làm gì và gã sống ở đâu.\n\nHãy đi xuôi dòng sông về phía ngôi làng của gã ngư dân và tìm kiếm những vật phẩm giá trị ở đó!",
    [462723110] = "Quần Ảo Thuật Gia",
    [462967185] = "Chúng ta không nên nán lại ở những vùng nước hoang dã! Ai biết được những hiểm họa nào đang rình rập dưới mặt nước?",
    [462985653] = "Tìm Hóa Thạch Rừng Revel",
    [462996908] = "Đôi ủng của một kẻ lãng du được tìm thấy bên cạnh một thi thể, dường như được chế tác thủ công từ rất lâu trước đây. Dù đã sờn cũ và mòn theo thời gian, nhưng chúng vẫn còn khá chắc chắn.",
    [463035367] = "Cây Giống Lá Đỏ Rừng Revel",
    [463495679] = "Lượng Vật Phẩm Thu Thập",
    [464019990] = "Chúng Ta Đang Nghỉ Ngơi",
    [464613121] = "Tìm Kiếm Đôi Cánh Lượn Huyền Thoại",
    [465520064] = "Ngươi đã làm rất tốt khi khai quật được những thần chú vĩnh cửu đó.",
    [465858241] = "Một cây Gậy phép nghi lễ đã được thanh tẩy trong một dòng suối tĩnh lặng dưới ánh trăng lưỡi liềm. Nó giúp người sử dụng dẫn dắt những kẻ bất tử trở về cõi hư vô.",
    [466393665] = "Tương tác với lửa trại để nấu thức ăn hoặc ngồi gần chúng bằng %k để được Nghỉ Ngơi giữa nơi hoang dã.",
    [466604245] = "Tiền Đồn Cửa Ngõ \"Ngọn Lửa Cuối\"",
    [466643214] = "Điều Chỉnh Âm Lượng",
    [466746041] = "Đọc tất cả các văn bia tại Hoang Mạc Rực Lửa.",
    [467066152] = "Một ly sữa lắc thơm ngon. Hãy cẩn thận với cơn say đường! Nó sẽ hồi phục sinh mệnh và SP của ngươi.",
    [467227756] = "Tăng lượng sinh mệnh tối đa của người chơi.",
    [467311386] = "Chậu Gốm",
    [467938574] = "Một chiếc rìu lạnh lẽo như băng với viên ngọc rực rỡ ở giữa. Lưỡi rìu được trang trí bằng những chiếc gai nhỏ để gây sát thương tối đa. Khi chiếc rìu này giáng xuống kẻ thù, nó phản chiếu ánh mặt trời một cách tuyệt đẹp.",
    [468431265] = "Khi chúng tôi được đưa đến đây để đào, nhiệm vụ rất rõ ràng — mặc dù bản thiết kế cho công trình của chúng tôi đến theo từng giai đoạn, và không có chú thích. Tôi chưa bao giờ làm việc trong ngành xây dựng với tư cách là người khảo sát mà không biết kiến trúc sư cho đến bây giờ. Tôi đã không hỏi danh tính của họ, vì nhiều kiến trúc sư thích sự cô độc, và một số không muốn tên của họ gắn liền với một thứ gì đó khó coi — chẳng hạn như một nhà tù cho tù binh chiến tranh.\n\nNgay cả nhà tù cũng có phòng y tế. Bất cứ thứ gì <i>chúng tôi</i> đang xây dựng <i>không có,</i> nhưng chúng tôi đã được giao nhiều y tá được chỉ dẫn lưu trữ bất kỳ sự cố \"bất thường\" nào và \"triệu chứng\"... Kể từ đó tôi đã biết lý do. Nhiều công nhân hơn đang gặp tai nạn kỳ lạ, vì vậy chúng tôi đã biến đơn vị lưu trữ bên dưới thành một bệnh xá tạm thời.\n\nTôi có thể giữ im lặng về nhiều thứ. Tôi biết vị trí của mình. Nhưng khi đột nhập vào một hang động Sương độc bao phủ và được yêu cầu <i>tiếp tục tiến lên,</i> không thể ngăn công nhân đặt câu hỏi. Chúng ta đang xây dựng cái gì? Chúng ta đang <i>hướng tới điều gì?</i> Tôi không thể trả lời, nhưng bất cứ điều gì, nó cũng bắt giữ và giam cầm tâm trí công nhân của tôi hơn bất kỳ nhà tù nào có thể.",
    [468467290] = "Hang Ổ Sương độc",
    [468658832] = "%k (thêm +%k)\ntại %k",
    [470088396] = "Rodrick là một kẻ ngốc và đã để lộ chuyện tình vụng trộm của chúng tôi. Florian, gã chồng khờ khạo của tôi, phải chết để tôi và Rodrick cuối cùng cũng được bình yên! Tôi đã trả lời mẩu quảng cáo mà rõ ràng hắn đã đăng trên tờ Tuần báo The Pike và biết hắn định giết tôi. Tôi sẽ gặp hắn tại căn phòng đó với một con dao găm giấu trong ngực áo!",
    [470173863] = "Mũi Tên Nổ",
    [470995332] = "Tủ Ly Hầm Mộ Nhỏ",
    [471028221] = "Không thể kết nối với máy chủ.",
    [472008064] = "Một chiếc sáo tinh xảo, được trang trí bằng những nét vẽ màu ngọc xanh biển thanh thoát, mang âm hưởng bay xa như những làn gió bạc.",
    [472675162] = "<i>Đầu tiên, người là vị cứu tinh của ta.</i> Những đứa trẻ khác đã cười nhạo ta khi ta không biết đọc biết viết. Người đã đẩy chúng ngã xuống bùn, cười đáp trả, và đọc cho ta nghe những câu chuyện cho đến khi ta thuộc mặt chữ. Người thông minh và dũng cảm hơn.\n\n<i>Sau đó, người là tình yêu của ta.</i> Nắm tay nhau bên bờ sông, ta đã thổ lộ. Người đã làm tan nát trái tim ta, hỡi cơn lốc lửa rực cháy. Ta đã tha thứ cho người. Sao ta có thể không chứ? Ít nhất người đã thành thật với ta.\n\nGiờ đây, người là gì? Một cái xác rỗng tuếch, bị thiêu rụi bởi cơn giận dữ. Chẳng còn lại gì từ người phụ nữ mà ta từng yêu quý. \n<b>Cuối cùng, ta đã bảo người đừng làm thế. Nhưng người chưa bao giờ lắng nghe, đúng không?</b>",
    [472720683] = "Chúng ta có thể chơi nhiều nhạc hơn nếu ngươi tìm thấy một số bản nhạc! Có lẽ ngươi sẽ may mắn tìm thấy chúng khi thám hiểm các thị trấn và quán rượu đấy!",
    [472957238] = "Đã Uống Tiên Dược",
    [473907764] = "Tôi đã làm việc trong khu mỏ gần đây mỗi ngày, nhưng dạo này, tôi không thể ngừng nghĩ rằng những tinh thể ngọc xanh biển đó có thể làm được nhiều việc hơn là chỉ khuân chúng ra khỏi đá. Tôi đã nghiền một ít bằng một chiếc máy nghiền nhỏ và thu được loại bột mịn nhất, rực rỡ nhất mà tôi từng thấy.\n\nSau khi trộn nó với một vài nguyên liệu có sẵn ở nhà, tôi nghĩ mình đã tạo ra một loại sắc tố hoàn hảo. Ngày mai, tôi sẽ chuẩn bị một mẻ nhỏ và cho Casper xem.\n\nCó lẽ đây là cơ hội để tôi rời bỏ khu mỏ mãi mãi. Đây có thể là khởi đầu của một điều gì đó lớn lao hơn nhiều.",
    [473977521] = "<location>Surat's Rest</location>",
    [474567983] = "Kho chứa được 56 vật phẩm.",
    [475189086] = "Kho Báu Ngọc Lục Bảo",
    [475467519] = "Dịch Chuyển Nhanh đến Đàn Thờ vừa ghé thăm",
    [475814494] = "Bản Đồ",
    [475927874] = "<location>Moth's Grove</location>",
    [475962070] = "Khiên Hắc Hóa",
    [475967340] = "Đam mê của ta là nghề cắt tóc.",
    [476035395] = "Khả năng kháng lửa tự nhiên của cây cung này khiến nó trở nên hoàn hảo để bắn ra những loạt tên lửa.",
    [476054059] = "Vùng Nước Hiểm Nguy",
    [476909054] = "Một cặp song đao huyền bí được sử dụng cho những nghi thức bói toán không thể tiết lộ dưới ánh trăng rằm.\n\n<b>Tinh Tế:</b>\nSát thương gây ra bởi vũ khí này tỉ lệ thuận với chỉ số Nhanh nhẹn của ngươi. Ngươi có thể thực hiện một đòn tấn công đặc biệt sau khi đỡ đòn thành công.",
    [477103527] = "Lưu Huỳnh",
    [477234431] = "Flint, Carter — Dữ Liệu Bệnh Nhân, Đã Lưu Trữ — Báo Cáo Số A.053",
    [477410908] = "Công cụ cải tiến này sẽ giảm độ bền chậm hơn nhờ lưỡi cắt bằng thép. Hãy cẩn thận với những ngón tay của ngươi khi làm mộc!",
    [477659106] = "Găng Tay Thợ Săn Quetzal",
    [479250570] = "Ốc Đảo?",
    [479311823] = "Tinh Hoa Cổ Xưa",
    [479760298] = "POL",
    [479816628] = "Quần Xuyên Dương",
    [480027142] = "Giàn Giáo Xây Dựng",
    [480708436] = "Những Chú Chó Của <lorename>Lupa</lorename>",
    [480745391] = "Cối Giã Nhỏ",
    [480758717] = "Người Kế Vị",
    [480798613] = "Đũa Phép Vặn Xoắn",
    [480987224] = "Một chiếc áo dài thoáng mát, hoàn hảo cho một ngày bên bờ biển.",
    [481329806] = "Cửa Bí Mật Giả",
    [481645955] = "Tôi đã biết có gì đó không ổn khi bế con bé lên lần trước! Cô bé Pompom của tôi đã mang thai rồi! \n\nTôi đã chuẩn bị một không gian nhỏ, ấm cúng dưới tầng hầm cho con bé. Nó trông có vẻ mệt mỏi, nhưng tôi tin mọi chuyện sẽ ổn thôi. Tôi vẫn còn nhớ khi mình chăm sóc mẹ nó, nhặt những mảnh kim loại vụn ra khỏi bộ lông đốm. Gia đình nó rất kiên cường, và họ đã vượt qua những điều tồi tệ hơn thế! Nếu may mắn, chúng thậm chí sẽ sống lâu hơn cả bà già này! \n\nTôi sẽ phải đặt thêm nhiều bát ăn cho chó nữa. Tôi muốn chúng được bình an vô sự ngay cả khi tôi đã đi xa!",
    [482506773] = "Cắt",
    [482684931] = "Cuốc Đồng Thiếc",
    [483104930] = "Nhu Cầu Của Dân Làng",
    [483658243] = "Đôi ủng này hoàn hảo để giữ vững tư thế khi nhắm, bắn và kết liễu kẻ thù.",
    [483750912] = "Cây Giống Bụi Quả Mọng",
    [484037531] = "Tìm kiếm Lò Rèn",
    [484195116] = "Trượng Của Cừu Đực",
    [484221110] = "Cây Giống Hồng Trà Nam Phi",
    [485310899] = "Một chiếc lò phức tạp được các học giả về bí ẩn giả kim sử dụng.",
    [486660816] = "Đèn Sàn Tím II",
    [486862004] = "Mảnh vỡ của một bản đồ kho báu bị xé rách, tìm thấy trên bộ xương rồng ở Đỉnh Albaneve. Có lẽ bạn có thể khôi phục bản đồ nếu tìm đủ các mảnh?\n\nCó dòng chữ ở mặt sau:\n\n<b>Hồi ức của Orpheus:</b>\n<i>Sinh ra là kẻ lãng du, ta tìm kiếm sự rạng rỡ và hạnh phúc\nGiờ đây ta bị đóng băng trong thời gian, thân xác bị xiềng xích\nĐã quen với biển bóng tối, sâu thẳm trong vực thẳm\nMắt ta đau đớn trong ánh sáng, nên chẳng còn tia sáng nào sót lại</i>",
    [486912432] = "Một bình sữa thơm ngon. Uống nó sẽ tăng SP và hồi phục SP nhanh hơn!",
    [487092108] = "Chester Loft",
    [487624723] = "Khối Đỡ Đường",
    [489024808] = "Găng Tay Lông Thú",
    [489571138] = "Anders",
    [490098776] = "Khi tiêu diệt kẻ thù bằng vũ khí Phép thuật, bạn có <b>10%</b> cơ hội triệu hồi một <b>Đồng hành Đầu lâu</b> thân thiện.",
    [490234349] = "Đệm nhún",
    [490356749] = "The <npc>Thợ rèn</npc> muốn có một cửa hiệu tử tế để rèn và làm việc. Khi ông ấy có một <b>chiếc giường có mái che</b> bên trong xưởng, ông ấy có thể chế tạo thêm nhiều vật phẩm.\nA <b><craftingstation>Bàn thợ</craftingstation></b>, một số <b>Khối xây dựng</b> và một <b>Búa xây dựng</b> là cần thiết để xây dựng cửa hiệu cho <npc>Thợ rèn</npc>. \n\nTrước tiên bạn sẽ cần một <b><craftingstation>Bàn thợ</craftingstation></b>. Chế tạo và đặt một <craftingstation>Bàn thợ</craftingstation> từ tab Chế tạo Thủ công. Chế tạo <craftingstation>Bàn thợ</craftingstation> yêu cầu Dây thừng và Gỗ khúc.",
    [490381586] = "Giảm Chuyển động Camera Động",
    [490488725] = "Không tìm thấy gói tài nguyên cốt lõi. Vui lòng cài đặt lại trò chơi.",
    [490499833] = "Dạ dày Đồ ngọt",
    [490762173] = "Thời lượng (Phút)",
    [490858614] = "Xoay 90°",
    [490862035] = "MP",
    [491913761] = "Dữ liệu lưu game đã bị hỏng",
    [492718290] = "Một số nút bấm có thể nằm ngoài tầm với. Hãy bắn chúng bằng mũi tên để kích hoạt.",
    [492798761] = "Ngọn Tháp Cổ Đại sừng sững trên vùng đất bị tàn phá. Chắc chắn phải có cách để vào bên trong.",
    [493250103] = "Công thức",
    [493299055] = "Thu thập Ếch",
    [493564252] = "Bạn đang bị phơi mình và cảm thấy lạnh. Hãy trang bị quần áo để bảo vệ bản thân.",
    [493917713] = "Làm mượt Camera",
    [494038326] = "Gối",
    [494355700] = "Căn cứ",
    [494619041] = "Đồn trú Lửa Hung Tàn \"Hướng Gió\"",
    [494676496] = "Sắc Xanh Rực Rỡ",
    [495471184] = "Lồng bốn chiều xung quanh lõi của cây chùy tạo thành một vương miện tỏa ra bên ngoài khi được nâng lên trên đầu người sử dụng. Điều này đóng vai trò như một khúc nhạc cuối cùng cho các nạn nhân trước khi họ bị nghiền nát dưới chân kẻ thống trị.\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n",
    [496430443] = "Ô chứa",
    [496436189] = "Mồi nhử",
    [497448513] = "Lò Đốt Than",
    [498328511] = "Bàn Giả Kim",
    [498660719] = "Một tuyến hữu cơ nhỏ tiết ra chất lỏng dính có mùi hăng.",
    [498680614] = "Hãy nhìn xa hơn bản thân, nhìn vào ngọn lửa. Mọi thứ sẽ được hé lộ. Giờ hãy tiến lên và khám phá.",
    [498847806] = "Tăng thuộc tính Thông minh của bạn thêm 1.\n\nTăng ST Phép thuật thêm 5% cho mỗi Điểm Thuộc tính.",
    [499519562] = "Tường Gỗ II",
    [499727048] = "Còn gì nữa không?",
    [500664509] = "Cuộc Điều tra Hoàng gia",
    [500866020] = "Bắn hạ các tổ ong từ trên cây để lấy mật và sáp. Hãy cẩn thận! Các tổ ong thường được bảo vệ bởi đàn của chúng.",
    [501981664] = "Chuột Lang Nước",
    [502658115] = "Bạn đã nghe tin đồn về một hang rồng huyền bí ở Cao nguyên Du mục. Hãy khám phá khu vực được đánh dấu trên bản đồ để điều tra!",
    [502715942] = "Một vòng xoáy năng lượng rạng rỡ cần thiết để khảm ngọc vào vũ khí. \n\nBan đầu được người Cổ đại sử dụng, nó đã bị phe Fell chiếm lấy để nuôi dưỡng bầy đàn của chúng cho đến khi bạn giải phóng nó khỏi nhà tù hữu cơ mới. \n\nBiến thể này có thể được tìm thấy ở Đỉnh Albaneve.",
    [503381585] = "Khung Cửa Sổ Gỗ Chạm Khắc Tinh Xảo",
    [503403102] = "Lò Sưởi",
    [503851905] = "Một đôi Ủng Lính đánh thuê bị trầy xước. Hãy đá kẻ thù khi chúng đang gục ngã!",
    [504044852] = "Tường Rào Gỗ VI",
    [504398020] = "Máng Ăn Bò Tây Tạng",
    [504759528] = "Lớp da cứng và có vảy của một loài bò sát.",
    [504764536] = "Tốc độ di chuyển cơ bản của bạn.",
    [504958501] = "Vị trí <craftingstation>Con thoi Thủ công</craftingstation>",
    [504974337] = "Bàn Đầu Giường Gỗ Phương Bắc",
    [505086607] = "Chiếc Nhẫn Bị Mất của Emily Fray",
    [505362788] = "Một lưỡi kiếm được rèn từ đồng nguyên chất, phản chiếu thường thấy ở Revelwood. Mặc dù bạn có thể thấy một chút lớp gỉ trên thân kiếm, nhưng không có sự đổi màu đáng kể nào.",
    [505424592] = "Đồi Scavenger",
    [505536045] = "Ngọc Đốm Lửa Hy Vọng",
    [505696605] = "Bột Mì",
    [506021681] = "Cái Cày",
    [506648481] = "Hàng Rào Gỗ Nhiệt Đới Đơn Giản Buộc Dây I",
    [507626809] = "Hầm Chứa Tro Tàn",
    [508099409] = "Di chuyển",
    [508883599] = "Đã Đến Lúc Chế Tạo <craftingstation>Lò Luyện</craftingstation>",
    [509021784] = "Tiến Xuống Sảnh Đường Hollow",
    [509262565] = "Đã thêm %k điểm đánh dấu.",
    [509523461] = "Suỵt, người bạn sành điệu của tôi. Lại gần đây. Tôi cần chia sẻ một bí mật!",
    [510283203] = "Bản đồ",
    [510339090] = "Bánh Mì Kẹp Mở",
    [510586931] = "Giày Phu Đào Mộ",
    [510906219] = "Rễ Sương độc",
    [511191001] = "Đến",
    [511202882] = "Mực nước",
    [511538109] = "Chào đằng ấy! Có phải tôi vừa thấy bạn cầm một con cá không? Tôi đoán vậy. Tôi có một mẹo hữu ích cho bạn đây.",
    [511658605] = "Cúp Danh Năng Đấu Sĩ Vukah Sắt",
    [511741646] = "Từ chối",
    [511891650] = "Nồi Phế Liệu V",
    [512519936] = "Tôi chắc là mình đã ngủ quên, vì khi tôi thức dậy, tôi đã ở đây. Miệng có vị máu, nên tôi đã nhổ một chiếc răng thối khác ra khỏi hàm và nghiền nát nó dưới gót chân. Tôi ghét tất cả bọn họ. Ước gì tôi có thể nghiền nát cổ họng của chúng nữa.\n\n<i>\"Hình ảnh là tất cả — Nhìn đi, đừng mất bình tĩnh!\"\n\"Daniel, đồ quái dị! Bình tĩnh lại! Bạn sẽ làm mọi người khó chịu!\"\n\"May mắn ở khắp mọi nơi, bạn ơi! Chỉ cần đừng buồn bã!\"\n</i>\nMọi người luôn lải nhải! Làm cái này, làm cái kia! Thêm một cái nữa, và tôi sẽ đập đầu chúng bằng Trống Tay của mình! Đặc biệt là Chester! Nhân danh Ngọn lửa, tôi ghét Chester! May mắn ngu ngốc của hắn sẽ sớm cạn kiệt... Ông già đó đang lao thẳng về phía một pháo đài Scavenger trên đường lên phía Bắc. Thật là một kẻ ngốc... may mắn của hắn sẽ không cứu hắn lần này!!",
    [513225188] = "Những Gì Tôi Để Lại",
    [513733749] = "Đại Úy Melville Fontane",
    [513798612] = "Lồng Tre II",
    [514005178] = "Cung Ma Quỷ",
    [514136191] = "Kệ Gỗ Thô Sơ Cao",
    [514316147] = "Tăng tất cả ST Hỏa Phép ",
    [514447742] = "Mũ Trùm Lưới Hoa Hồng Máu",
    [514514451] = "Một chiếc rìu thép, được trang trí bằng các điểm nhấn bằng vàng. Nó khiến bạn cảm thấy mạnh mẽ hơn nhiều, mặc dù bản thân lưỡi rìu rất có thể không được cải thiện là bao.",
    [514772092] = "Thời gian cơ bản cho hiệu ứng Nghỉ Ngơi được tăng thêm <b>5</b> Phút.\n\nĐộ thoải mái trong nhà cao hơn sẽ giúp tăng thêm thời gian hiệu ứng.",
    [514797140] = "Rất vui được gặp bạn.",
    [516519483] = "Hơn Cả Chất Độc",
    [516623174] = "Vật phẩm Twitch Drop",
    [516716530] = "Sát thương Độc theo thời gian",
    [516754206] = "Ghế Dài Hầm Mộ",
    [517035452] = "Cầu Braelyn",
    [517070074] = "Một món ăn nhẹ tuyệt vời giúp kích thích trí não.\n\nTăng ST Phép thuật của bạn thêm một lượng nhỏ.",
    [518052603] = "Một nguồn sáng Ám khí được, sẽ kích hoạt khi chạm đất, ngay cả dưới nước. Không mạnh bằng các nguồn sáng khác.",
    [518259171] = "Sàn nhà",
    [518368038] = "<npc>Thợ cắt tóc</npc>",
    [519533691] = "Cổ tự Drak Nâng cao",
    [520291386] = "Wickmouth",
    [520573370] = "Rỉ Sét",
    [520718193] = "Có lẽ chúng có thể dùng làm dây chừng? Trông chúng khá là bền chắc.",
    [520823467] = "Những kẻ vung chiếc Rìu Thủ lĩnh Drak'Dal khiến vạn người khiếp sợ — một nhát chém là đủ để khuất phục cả một bộ tộc. Nó đã tước đi vô số sinh mạng, và vẫn đang khao khát thêm nhiều hơn nữa.",
    [521280279] = "Các loại ẩn: %k",
    [521683459] = "Dữ liệu nhân vật bị lỗi!",
    [521687162] = "<i>(Nét chữ đã phai mờ, như thể mảnh giấy này đã được viết từ rất lâu rồi.)</i>\n\nHôm nay họ lại gõ cửa nhà anh khi anh đi vắng. Em đã trốn đi như lời anh dặn, nhưng em vẫn nghe thấy tiếng lầm bầm của họ từ trên lầu. Đám lính gác nói họ sẽ quay lại.\n\nChe chở cho em chỉ mang lại đau khổ cho anh, em biết điều đó. Em quyết định sẽ không lẩn trốn nữa. Em sẽ tự nguyện đến <b>Hollow Halls bên dưới East Lapis.</b> Nếu em không tuân lệnh sớm, đám lính gác sẽ không chỉ dừng lại ở việc gõ cửa đâu.\n\nCảm ơn anh vì tất cả. Em xin lỗi vì bấy nhiêu vẫn là chưa đủ. Anh không thể bảo vệ em khỏi lính gác, hay khỏi sự chuộc tội.",
    [521725693] = "Bảng Trưng Bày Thảm Treo Tường",
    [521964885] = "Kháng Độc",
    [522080959] = "Cho phép bạn bắt một sinh vật từ Sương độc.",
    [522384413] = "Bạn đã đến điểm của Nông dân gần trạm dừng đoàn xe và thu thập Calla Lunas.\n\nHãy quay lại gặp Thợ cắt tóc với Calla Lunas trong hành trang để cho ông ấy thấy vẻ rực rỡ của chúng!",
    [522674894] = "Đá lạnh bên trong, cùng với long đởm thảo — một nỗ lực thất bại trong việc pha trà thảo mộc đá? Sức mạnh của nó chắc chắn không nằm ở hương vị rồi.",
    [522767364] = "Nơi trú ẩn, bạn của tôi ơi. Độc dược của tôi, công cụ của tôi — tất cả đều vô dụng nếu thiếu <b>nơi trú ẩn</b>. Làm ơn hãy xây cho tôi một căn phòng để tôi có thể làm việc tử tế, và nhớ kê thêm một chiếc giường nữa nhé!",
    [522784485] = "Tạm biệt.",
    [522813375] = "Tiêu hao Thời gian Sương độc",
    [522936058] = "Tăng HP tối đa thêm 1 ",
    [522948230] = "Đòn Chí mạng bằng Cung hồi <b>20</b> MP. ",
    [523378079] = "Một <craftingstation>Vạc Đen</craftingstation>! Tuyệt vời lắm, bạn của tôi! Cùng nhau, chúng ta sẽ hưng thịnh!",
    [523506585] = "Tải máy chủ cao:",
    [524055565] = "Bậc thầy Dao",
    [524400955] = "Thêm Cộng dồn (%k)",
    [524444737] = "Mảnh Hắc diệu thạch",
    [524733946] = "Hầm ngục Cổ đại — <npc>Nông dân</npc>",
    [525074054] = "Nhiễu động Diều lượn",
    [525106373] = "Ngư dân nghĩ rằng đánh bại một thủ lĩnh Drak trong một cuộc đấu tay đôi sẽ làm suy yếu kẻ thù của bạn. Để thách thức một trong những chỉ huy của chúng, trước tiên bạn phải chứng tỏ bản thân.\n\n<b>Hãy tiêu diệt 25 Drak để thu hút sự chú ý của các thủ lĩnh của chúng.</b>\n\nBạn có thể tìm thấy Drak ở bất cứ đâu trong trung tâm Veilwater Basin, hoặc xa hơn về phía Tây. Chúng chỉ xuất hiện ở phía trên Sương độc. <b>Một địa điểm thuận tiện đã được đánh dấu trên bản đồ.</b>",
    [525155073] = "Rắn",
    [525570081] = "Giường Đôi Lớn",
    [525891123] = "Những pháo hoa này được mang đến cho bạn nhờ sự kỳ diệu của giả kim thuật!",
    [526280127] = "Hang động",
    [526425344] = "Sự thay đổi của thủy triều đã không nương tay với sinh vật này. Có lẽ cuối cùng nó cũng có thể yên nghỉ.\n\nThu thập nhiều Đầu Fell Wispwyvern để chế tạo Vật phẩm Trang trí.",
    [526694005] = "Áo Giáp Ngực Khô Cốt Tinh Nhuệ",
    [527041517] = "Một Thử thách Cuối cùng",
    [527129133] = "Nhẫn 1",
    [527406423] = "Chất lượng Đổ bóng",
    [527456639] = "Trọng Kiếm Thú Sấm Sa Ngã",
    [527642679] = "Hiển thị máy chủ chuyên dụng",
    [527689331] = "Ngọc Tha Hóa",
    [528137708] = "Có quyền trục xuất & cấm người chơi",
    [528536234] = "Ta thấy ngươi đã dọn sạch được Giếng Elixir đó. Cứ tiếp tục phát huy và ngươi có thể bắt đầu trở nên nổi tiếng quanh đây đấy! ",
    [528905616] = "Mái nhà 4m",
    [530158799] = "Phòng thí nghiệm Cải tiến",
    [530438742] = "Tại đây bạn có thể đặt các vật phẩm vào thanh hành động để truy cập nhanh trong trò chơi.",
    [530834664] = "Nhật ký của Martha, Mục 2",
    [531401836] = "Chế tạo một <b>Móc kéo</b>",
    [531404697] = "Vai trò Máy chủ không hợp lệ.",
    [531676369] = "SP tiêu hao khi <b>chạy nước rút trên đường đất</b> giảm từ <b>90% xuống 80%</b>.\n\nSP tiêu hao khi <b>chạy nước rút trên đường đá</b> giảm từ <b>75% xuống 50%</b>. ",
    [532117532] = "Chào mừng bạn đến với bản demo Sương độc bao phủ!",
    [532217646] = "Xây một chiếc Giường có Mái che cho Balthazar",
    [532293896] = "Sự lạnh lẽo và vô hồn nơi vực sâu của Hollow Halls đã là nhà của ta quá lâu rồi. Hơn nữa, trong ký ức xa xăm của ta, vào thời điểm trước khi suy tàn, ta nhớ nhịp đập của những cơn gió phương bắc lung linh... Ta đã chịu đủ những cơn run rẩy và xiềng xích rồi. Ta cầu xin ngươi một mái nhà tử tế và một lò sưởi để thắp sáng linh hồn già cỗi này, bạn của ta.",
    [532348715] = "Có vẻ như lưỡi kiếm của ngươi đã tìm thấy cổ của một thủ lĩnh Drak. Nơi một kẻ ngã xuống, vô số kẻ khác sẽ nỗ lực chiếm lấy vị trí đó, bị cuốn vào vũ điệu tranh giành quyền lực, bị xích lại bởi quy luật của nó. Ngày mai, những con non mới sẽ trỗi dậy từ dòng máu đổ này, nhưng hôm nay, nó sẽ làm chúng ta mạnh mẽ hơn.",
    [532999033] = "Mở khóa Cường hóa",
    [533188470] = "Tăng Tỷ lệ Chí mạng ",
    [533581080] = "Trại Khai quật Mảnh xương",
    [533944126] = "Sự Phát Triển Phát Sáng",
    [535260872] = "Thêm vào Yêu thích",
    [535344843] = "Pompom Jr.",
    [535569412] = "Một cây Đũa phép kỳ lạ được nhặt từ cái xác lạnh lẽo của một sinh vật Fell trong một Sân sau rậm rạp.",
    [535670933] = "Hải sản Nướng cho Nông dân",
    [536310497] = "Thùng Đồng Thiếc",
    [536360043] = "Đã tìm thấy Thư gốc",
    [536607433] = "Ngươi có muốn xem qua các món đồ ta làm không?",
    [537054004] = "Triệu hồi",
    [537102657] = "Hũ Đồng Đỏ Đóng",
    [537121003] = "Hãy để mắt tới ta.",
    [537288639] = "Giải cứu Dì Braelyn",
    [537503523] = "Độ khó",
    [537708668] = "Vải của chiếc áo khoác này đủ dày để bảo vệ khỏi những đòn tấn công. Ngoài ra, lớp lót bên trong chạy dọc theo các mạch máu của cơ thể, cho phép người mặc thi triển ma pháp tầm ngắn dễ dàng hơn.",
    [537716951] = "Mảnh Khảm Ngọn Lửa VII",
    [538603994] = "Khám phá Đền thờ Ngọn lửa Bị lãng quên",
    [538687448] = "Tiếng Ukraine",
    [538782237] = "Một chiếc mũ trùm lông thú bảo vệ khuôn mặt người mặc khỏi những cơn gió núi mạnh mẽ và sắc lẹm.",
    [539007688] = "Tăng <b>Kháng Băng</b> của bạn thêm <b>5%</b>, giúp giảm lượng sát thương <b>Băng</b> nhận vào. ",
    [539934660] = "Springlands",
    [540212036] = "Bàn Thờ Ngọn Lửa",
    [540433527] = "Sinh vật Fell",
    [540696573] = "Đang chờ nhập liệu...",
    [540753917] = "Điều tra Bức thư Kỳ lạ",
    [540912473] = "Nhiệm vụ Lặn",
    [541239122] = "Tiêu diệt kẻ thù bằng vũ khí Phép thuật sẽ hồi HP bằng <b>3</b> lần Trí tuệ của bạn cho tất cả người chơi trong phạm vi <b>15</b> mét quanh mục tiêu. ",
    [541257555] = "Một cây Đũa phép khai thác sức mạnh của nhật thực. Nó hoạt động tốt nhất khi mặt trời hoàn toàn chìm trong bóng tối, và chỉ có một vành sáng mờ nhạt chiếu qua.\n\n<b>Quá tải:</b>\nCây gậy này có cơ hội khuếch đại sát thương đầu ra. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.\n\n<b>Nhân bản Hư ảo:</b>\nMa thuật độc đáo của cây gậy mang lại cho nó 30% cơ hội tự phát tạo ra thêm một tia đạn.\n\n<b>Đa tiễn:</b> \nBắn ra nhiều tia đạn nhưng giảm sát thương. ",
    [541848437] = "Khám phá từ Văn bia Cổ đại",
    [542257363] = "Thu phóng",
    [542278984] = "Tiếp cận và Cướp bóc Vịnh nhỏ",
    [542670172] = "Áo Giáp Pháp Sư",
    [542736114] = "Bảo vệ khỏi Lời nguyền Fell",
    [542789341] = "Quặng Đồng Đỏ",
    [543240623] = "NVIDIA Reflex giảm độ trễ hệ thống và tăng khả năng phản hồi của PC",
    [543450782] = "Cung",
    [543732718] = "Máy Kéo Sợi",
    [544044765] = "Giày Thánh Kỵ Sĩ Rực Rỡ",
    [544303147] = "Kiếm dài Chạm khắc Đồng",
    [545058634] = "Triệu hồi một kẻ thù Fell",
    [546505064] = "Tiếp cận Văn bia",
    [546687512] = "Một chiếc áo khoác lông dài, thường được mặc bởi cư dân vùng Albaneve Summits. Nó rất ấm áp.",
    [547082169] = "Chìa Khóa Đồng Thiếc",
    [547294565] = "Sự hiểu biết của <npc>Nhà sưu tầm</npc> về Flameborn",
    [547295002] = "Bảo vệ Ngọn lửa",
    [547742918] = "Một Ngôi nhà Đẹp",
    [548120118] = "Làm sao bầu trời đêm có thể giữ được sự tĩnh lặng khi nó phải đối mặt với một biển những kẻ dối trá?\n\nTôi cảm thấy như mình đang nhìn thấy những vì sao lần đầu tiên. Như thể một tấm màn nhung đen tối đã được nhấc khỏi mắt tôi, cho phép tôi được chứng kiến.\n\nChưa từng có vũ khí cổ đại nào ở đây cả.\nChúng ta luôn là những kẻ xâm nhập.\nHọ còn điều gì khác không muốn tôi biết nữa?\n\nTất cả những năm qua, bị lãng phí bởi sự mù quáng\nLén lút vượt qua các quy luật của thế giới vật chất, mà không nhận ra tâm trí mình cũng bị giam cầm y như vậy\nTôi đã tự cho mình là khôn ngoan khi đặt cược mù quáng vào những lá bài mình được trao... nhưng thật là một trò chơi ngu ngốc khi ngồi chung bàn với những kẻ dối trá và lừa lọc.\n\nTôi phải biến mất\nTôi phải chấm dứt sự điên rồ này, sự truyền bá này\nVà tôi không thể để lại bất kỳ manh mối hay nhân chứng nào\nHọ luôn báo hiệu rắc rối\nÍt nhất thì tôi cũng biết rõ điều đó\n\n<i>Darya</i>",
    [548219714] = "Tăng cường Ma pháp Lửa",
    [548717594] = "Bát Đất Sét",
    [548871684] = "Cầu gió đưa lối.",
    [549496426] = "Tăng giá trị tốc độ phát triển của thực vật.",
    [549720620] = "Cây cung này tinh xảo đến mức có thể chẻ đôi một bông tuyết ở xa.",
    [550132618] = "Bàn Góc Gỗ Cọ",
    [550150265] = "Nạp Nhanh",
    [550150754] = "Bộ giáp này cung cấp sự bảo vệ hoàn hảo khi mạo hiểm vào rừng sâu.",
    [550618145] = "Những thỏi vàng nguyên chất vừa là vật liệu chế tạo, vừa là biểu tượng địa vị.",
    [550646890] = "Gửi tất cả những ai chiêm ngưỡng kỳ công của ta — không, hãy để ta bắt đầu lại. \n\nGửi tất cả lữ khách — Ta đã chinh phục vùng đất này bằng sự vĩ đại của mình! Ta e rằng điều đó cũng không đúng lắm... \n\nCây cầu gần hoàn thành và ta không thể tìm được lời lẽ nào để diễn tả niềm vui của mình, chết tiệt thật! Thật may mắn khi chúng ta có một <b>mỏ</b> dồi dào vật liệu và <b>quặng!</b> Có một điều ta biết chắc: Ta sẽ đặt tên cây cầu này là <b><lorename>Braelyn</lorename></b>, theo tên người Dì thứ 5 yêu quý đã khuất của ta! Mặc dù nếu bà ấy còn sống, ta không chắc bà ấy có thấy vinh dự không... vì bà ấy và cây cầu không chỉ chung cái tên, mà còn chung cả bản tính ngông cuồng. \n\nKý tên,\nCade Hawthorn",
    [551102048] = "Làm mới",
    [551407756] = "Một bộ dao đôi thanh lịch với các chi tiết vàng lộng lẫy. Nó đủ mỏng để có thể giấu dưới váy ngủ mà không bị phát hiện vào bất kỳ căn phòng nào.\n\n<b>Tinh tế:</b>\nSát thương gây ra bởi vũ khí này tăng theo chỉ số khéo léo của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [552468468] = "Rìu Tân Binh Hoàng Kim",
    [552916859] = "Đao của Nam Tước",
    [553059462] = "Bạn có ăn mừng Tết Nguyên Đán không? Có lẽ bạn đang tìm mua vài món đồ trang trí mới? Trên đường đến thung lũng, tôi đã bán một vài cây cảnh trang trí cho người dân ở <location>Pháo Đài Kelvin</location>, nhưng vẻ đẹp của chúng sẽ trở nên vô ích nếu không có ai chiêm ngưỡng. Chúng ta có thể thay đổi điều đó!",
    [553181842] = "Đinh",
    [553295865] = "Kiếm Băng Giá",
    [553794375] = "Hãy tự cắt lấy! Có được một góc nhìn mới!",
    [553882328] = "Một phiên bản Mũi Tên Gỗ được cải tiến nhẹ, gia cố bằng những mảnh đá lửa nhỏ ở đầu mũi.",
    [554529576] = "Mũ Phu Đào Mộ",
    [554550521] = "Súp Sáng",
    [554703691] = "Một chiếc mũ trùm đầu màu kem dễ chịu để giữ ấm và thoải mái cho bạn. Đôi tai nhỏ rủ xuống hoàn toàn chỉ để trang trí, nhưng chúng không dễ thương sao?",
    [554963841] = "Hạ xuống Sảnh Hollow",
    [555039331] = "Chế Tạo Búa Xây Dựng",
    [555499556] = "Khúc Gỗ Thông",
    [555559870] = "Giày Chiến Binh Quật Khởi",
    [555699352] = "Yêu Cầu Nâng Cấp",
    [555773910] = "SP Khi Đánh Trúng",
    [556254094] = "Tên Bạn Bè / Máy Chủ",
    [556857528] = "Tăng sát thương lên kẻ địch bay. ",
    [557054482] = "Tháp Đó Không Đáng",
    [557315157] = "Giây Thời Gian Duy Trì",
    [557383926] = "Hàng Rào Tre Buộc Dây II",
    [558374009] = "Răng Ngọt",
    [559188704] = "Tiện Nghi - Phúc Lợi",
    [559219101] = "Tia Nước",
    [559467122] = "Chào Hỏi",
    [559530348] = "Ngọn Lửa không cho ngươi mọc cánh đâu, nhóc! Hãy <b>Chế Tạo một Dù Lượn</b> tại <craftingstation>Bàn Chế Tạo</craftingstation> — nó sẽ giúp việc di chuyển dễ dàng hơn một chút. Hoàn hảo cho những người dũng cảm như ngươi. Đừng quên rằng <b>sử dụng Dù Lượn sẽ tiêu hao SP</b> — nhưng theo những gì ta thấy, ngươi có đủ khả năng đó!",
    [559596204] = "Để trở nên Được Nghỉ Ngơi, cần có <b>sự an toàn, hơi ấm, nơi trú ẩn và tiện nghi</b>. Dành thời gian trong một môi trường hoặc căn cứ an toàn, được sưởi ấm và che chắn để nghỉ ngơi. Thời gian duy trì hiệu ứng Được Nghỉ Ngơi sẽ được tích lũy trong khi nghỉ ngơi. Thời gian tối đa là <b>1 Phút cho mỗi cấp độ tiện nghi.</b>",
    [559818954] = "Áo Giáp Huyền Bí",
    [560170754] = "Ngươi chưa thấy lần cuối cùng của ta đâu.",
    [560239629] = "Nhập phím để tìm kiếm",
    [561533855] = "Khi những chiến binh bị thương nhìn thấy chiếc mũ này nhô lên từ đường chân trời, họ biết sự cứu rỗi đã đến gần. Sau đó họ nhận ra chiếc mũ hơi có hình nón. Tuy nhiên, họ thường không nói gì về điều đó.",
    [561685478] = "Ngọc Độc Phản Bội",
    [562053191] = "Củ Cải Rừng",
    [562140073] = "Chúng ta đã đi được bao xa",
    [562186441] = "Chuột Lang Nước",
    [562395685] = "Thuyền trưởng dường như đã làm mất quần áo của mình ở Vịnh Stillwater vào một thời điểm nào đó. \n\n<b>Hãy tìm chiếc áo khoác bị mất của hắn và nhận lấy nó!</b>",
    [562495513] = "Chùy 1H",
    [562596189] = "Mỏ",
    [562734930] = "Duu, duu, duu, du-du-du, duu, duu, duu... À, ta không để ý đến ngươi ở đó! Chào mừng đến với giai điệu của ta. Có lẽ ngươi có thể giúp ta? Ta không có nhạc cụ phù hợp cho giai điệu này, nhưng ta tin rằng một cây đàn handpan sẽ là hoàn hảo! Chúng có nguồn gốc từ Lưu vực Veilwater, vì vậy chúng khó tìm được ở nơi khác. Có lẽ ngươi có thể tìm thấy một cái ở trung tâm thương mại?",
    [563137962] = "+ 1",
    [563725505] = "Giày Dân Du Lâm",
    [563890149] = "Ta không thể tin được! Con gái ta, con đã mang con gái ta về cho ta!",
    [564548050] = "Sắp tham gia:",
    [564949593] = "Khi ngươi tiêu diệt kẻ địch bằng vũ khí cận chiến, ngươi nhận được thêm 20% kinh nghiệm.",
    [565463481] = "Đền Drak'Dal",
    [565516930] = "Cầu Thang Lối Mòn Giả",
    [565839133] = "JPN",
    [565948699] = "Mũi Tên Pháo Sáng",
    [566020410] = "Fell đã mang Tinh chất Cổ xưa vào một hang động quanh co, bị Sương độc bao phủ. Mục đích của chúng là gì?\n\n<b>Khám phá sâu trong Hang ổ Sương độc</b> để tiếp tục! Hãy cân nhắc thu thập thêm Tinh chất Cổ xưa khi bạn đi để đòi lại nó từ Sương độc!",
    [566424883] = "Giữ cho cần câu cong!",
    [566480354] = "Đặt <craftingstation>Máy Xông Ong</craftingstation>",
    [566626283] = "Áo Vest Xạ Thủ",
    [566946648] = "Hãy đến cảm nhận ánh sáng của chiếc đèn lồng.",
    [566963843] = "Đồi Nghi Lễ Vukah",
    [567516204] = "Không có vật phẩm phù hợp",
    [567729887] = "Không có Hiệu Ứng Kích Hoạt",
    [567933737] = "Kiếm Rồng",
    [568099308] = "Thợ Săn kể cho ta nghe về lần bắt đầu tiên của ngươi! Thật là một thành tựu tuyệt vời. Ngươi biết không, ngươi nên nướng chúng lên để làm nổi bật những lợi ích tốt nhất. Ta thậm chí còn nghe nói chúng có thể tăng cường Oxygen của ngươi khi lặn!",
    [568735957] = "Người Hát Rong bảo ngươi tìm kiếm trong đống đổ nát của Trái Tim Đại Dương để tìm nhạc cụ cuối cùng. Một Nữ Hoàng tên là Jezmina đã học chơi đàn hạc từ Valory ở đó. \n\nHãy đến địa điểm đó và tìm kiếm nhạc cụ!",
    [568769156] = "Bức Tường",
    [568985110] = "CHÚNG TA ĐÃ XUYÊN QUA bức tường!! <lorename>Lupa</lorename> đã thổi bay tảng đá!! Phía sau đống đổ nát, THỰC SỰ CÓ một cái hang!!\nChúng tôi lao thẳng vào một nhóm Vukah... nhưng con mẹ nó, trong cơn thịnh nộ bệnh hoạn của nó, nó đã GẦN NHƯ lột da chúng sống!! Nó thuần hóa tất cả các loài thú! Chúng KHIẾP SỢ và LÙI BƯỚC trước SỰ NỔI TIẾNG của nó!\n\nChúng ta sẽ không dừng lại ở đây! Chúng ta sẽ chiếm lấy thế giới! <location>Pháo đài Quạ</location> chỉ là khởi đầu! Em gái của <lorename>Lupa</lorename> sẽ chiếm <location>Nơi an nghỉ của Surat</location> trong khi chúng ta xây dựng một SÀO HUYỆT của riêng mình để che khuất Umber Hollow! VINH QUANG cho mẹ <lorename>Lupa</lorename>!",
    [569267723] = "Vạc",
    [569398461] = "Khi trang bị vũ khí Cận chiến, bạn có thể thực hiện một cú Đá bằng cách tấn công trong khi đang đỡ đòn.\n\nĐá gây sát thương nhỏ, nhưng đánh vào mục tiêu với lực cực mạnh và đẩy chúng lùi lại, lấp đầy <i>Thanh Choáng</i> của chúng.\n\nViệc tăng <i>Thanh Choáng</i> tỷ lệ thuận với Nhanh nhẹn.\nThời gian choáng phụ thuộc vào kích thước của kẻ địch.\n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang đỡ đòn hoặc đỡ đòn tấn công của chúng sẽ lấp đầy <i>Thanh Choáng</i> của chúng cho đến khi chúng bị <b>áp đảo</b>.\nKẻ địch <b>Bị Áp Đảo</b> sẽ mở ra cho các Đòn Tấn Công Tàn Nhẫn.",
    [569614527] = "Giàn Phơi",
    [569665980] = "Có Thích Thành Quả Của Cây Nho Không?",
    [570164330] = "Tinh Chế Ngọc",
    [570226374] = "Tạm biệt",
    [570394710] = "Revelwood",
    [570933107] = "Những con đom đóm phát sáng bay thành đàn",
    [571107835] = "Một số Vai trò có cùng mật khẩu.",
    [571344870] = "Một màn trình diễn mê hoặc về sức mạnh áp đảo, và ít trí tuệ.\n\nThu thập nhiều Đầu Cyclops Fell để chế tạo Cúp Đồng.",
    [571526344] = "Săn mồi trong những đôi ủng này hầu như không gây ra tiếng động. Không ai nghe thấy ngươi đến gần.",
    [572581147] = "\"Thật là một túp lều\", ta nghĩ. Một lũ cướp, những tên lừa đảo thối nát, và những kẻ nửa mùa, ngứa ngáy muốn đâm lén người khác vì một ván bài. Băng đảng ồn ào, nhưng vài ngày đào bới trong <b>mỏ</b> cũng làm dịu đi cả những kẻ côn đồ cứng cỏi nhất. \n\nA. Một lời hứa duy nhất ràng buộc chúng ta lại với nhau. <i>\"Thuốc tiên cho tất cả\"</i>.\nTa hy vọng <i><lorename>Sameth</lorename></i> giữ lời hứa của mình.",
    [572696894] = "Lò Cao",
    [572803998] = "Tháo Rỡ Và Tăng Cường",
    [573262612] = "Tab Tiếp Theo",
    [573701365] = "Bộ trang phục Hollow Cao cấp",
    [574645420] = "Một cây đũa phép kỳ lạ được bao phủ bởi tro tàn. Thân của nó uốn lượn và xoắn lại, nhưng không bao giờ gãy.\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sát thương đầu ra của nó. Các đòn tấn công gây thêm sát thương lên đến tỷ lệ <i>quá tải</i>.\n\n<b>Đa Phát Bắn:</b> \nBắn ra nhiều vật thể phóng ra nhưng với sát thương giảm đi.",
    [576086069] = "Bảng màu này có thể được làm bằng vật liệu của Lưu vực Veilwater.",
    [576182806] = "<craftingstation>Máy Cưa Bàn</craftingstation> Cho <npc>Thợ Mộc</npc>",
    [576481790] = "Những chiếc găng tay này che chắn cánh tay của bạn khi bạn đuổi theo trong bụi rậm, tấn công kẻ thù từ xa.",
    [576687977] = "Tinh Hoa Cổ Xưa",
    [577373853] = "Xin chào người thân yêu.",
    [577788719] = "Được sử dụng để xây dựng mái nhà tranh. Một giải pháp cơ bản và đáng tin cậy để giữ cho đầu bạn không bị ướt.\n\nSử dụng <b>Búa Xây Dựng</b> để xây dựng <b>cấu trúc</b> xung quanh Bàn Thờ Ngọn lửa bằng khối xây dựng này.",
    [577910666] = "Một ngọn lửa nhỏ, một ánh sáng nhỏ\n xua tan bóng tối và mọi tai ương",
    [578373654] = "Khung Cửa Sổ Vàng Lớn",
    [578405699] = "Một loại kem dưỡng bảo vệ bạn khỏi cái lạnh thấm vào. Nó ban cho người dùng +1 giáp băng cho mỗi cấp độ nhân vật.",
    [581008972] = "Những con dao găm này sắc sảo và nhanh nhẹn. Lưỡi dao sắc như mọi khi.\n\n<b>Khéo Léo:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Khéo Léo của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [581140196] = "Hollow",
    [581680174] = "Thợ Cắt Tóc tuyên bố rằng hắn lại một lần nữa đang tuyệt vọng cần cảm hứng. Hắn yêu cầu ngươi thu thập thứ gì đó gợi cho hắn nhớ về bầu trời nhuốm màu cam lúc bình minh.\n\n<b>Thu thập Hoa Huệ Tây Cam từ Đồng Bằng Sương Nước và mang chúng trở lại cho hắn.</b>",
    [582070024] = "Cao Nguyên Du Mục, đan xen những lời hứa phiêu lưu và của cải bị lãng quên. Phần dưới của nó là một vùng đất hoang, một bãi săn cho những kẻ bị kết án. Những kẻ bên dưới ngước nhìn ánh bình minh lấp lánh phía trên, dùng đầu ngón tay lần theo những vệt vàng xa xôi của ánh sáng ban mai. \"Đủ rồi\" luôn nằm ngoài tầm với.",
    [582117982] = "Tiếp tục luyện tập, một ngày nào đó ngươi sẽ có thể bắt được những con cá lớn hơn!",
    [582452216] = "Găng Tay Điềm Báo",
    [582748444] = "Hoa Gắn Tường Đỏ",
    [582974177] = "Mang đôi găng tay này làm chậm nhịp tim một cách bí ẩn trước khi ra đòn kết liễu, nhờ đó giúp ổn định đôi tay.",
    [583910983] = "Hàng Giờ Trong Bồn Tắm?",
    [583932783] = "Sát thương gây ra lên kẻ địch <b>bay</b> được tăng thêm <b>30%</b>. ",
    [584421969] = "Tủ Trưng Bày Hóa Thạch (3 Khe Nhỏ, 2 Khe Vừa)",
    [584696893] = "Thổi Tiêu",
    [585486353] = "Một chiếc nhẫn lấp lánh, được nhặt từ xác của kẻ đã nhận nhiều hơn những gì hắn mặc cả.",
    [586327163] = "Nạp Năng Lượng",
    [586560281] = "Cánh Đồng Dâu Tây",
    [586728776] = "Áo Choàng Học Giả Ngọn Lửa Trẻ",
    [586962099] = "Khi trang bị vũ khí 2H, kích hoạt một đòn tấn công xoáy ở cuối chuỗi đòn tấn công.\n\n<b>Tiêu hao:</b> 75 SP ",
    [587457165] = "MP mỗi giây",
    [587526695] = "Chiếc quần này thoạt nhìn có vẻ bình thường, nhưng kỹ thuật chế tác cho phép người mặc tạo ra và giữ lại nhiều hơi ấm hơn từ bên trong.",
    [587664009] = "Hỡi Người Sinh Ra Từ Lửa, quê hương của chúng ta đang đơm hoa kết trái. Nó khơi dậy hy vọng mới trong ta — Ngươi có nhớ bức thư bí ẩn và những công cụ ngươi đã lấy về cho ta không? Chỉ có một người có thể đã cố gắng tiếp cận ta từ bên kia Umber Hollow. Ta biết tất cả có thể là vô ích... nhưng nếu con gái ta Rochelle đang ở ngoài kia, ta phải nhờ ngươi tìm kiếm nàng.",
    [587786176] = "Bản Đồ Của Loài Rồng",
    [588224639] = "Ghế Tựa Gỗ Phương Bắc",
    [588439558] = "Cửa Đá Bí Mật",
    [589023276] = "1H",
    [589119890] = "Cyclops Fell",
    [589403513] = "Phải, đã kéo ta lên từ vực sâu, phải không?",
    [589653180] = "Găng tay to và cồng kềnh, thường được mặc khi sử dụng vũ khí lớn và khiên.",
    [589660855] = "Một cây rìu rèn từ thép bóng tối được đội vương miện bằng một viên ngọc duy nhất, mảnh dẻ. Cán được bọc bằng gỗ phương bắc.",
    [590047477] = "Sát thương gây ra lên kẻ địch Tầm Xa ",
    [591080302] = "(Ngân Nga)",
    [591135515] = "Hổ Phách Yêu Dấu Của Chúng Ta",
    [591337098] = "Ngươi đã tìm thấy Sảnh Đường Hollow Tuếch trong Kindlewastes. Hãy đi xuống và đi đến cuối để làm hài lòng <npc>Người Sưu Tầm</npc>.",
    [591622703] = "Giày Thợ Săn Hươu",
    [591982231] = "Một lượng nhỏ tinh chất từ Ngọn Lửa! Bằng cách nuôi nó trở lại <Altar>Bàn Thờ Lửa</Altar> có lẽ nó có thể trở nên mạnh mẽ hơn và cháy sáng hơn nữa.",
    [592238544] = "Công Thức",
    [592311026] = "Với một mái che trên đầu, ta có thể chế tạo công cụ để sinh tồn. Ta thích một cái hang động hơn... nhưng ta sẽ xem xét một nơi <b>trú ẩn</b> thông thường. Hiện tại thì vậy.",
    [592660828] = "Dây Leo Dưới Nước",
    [592674203] = "<b>ChristopherD</b>\nNgười Gốc Flameborne\n\n<b>Ec the Goblin</b>\nMãi mãi trong đá\n\n<b>Jonar-Pal Passal’Akwa</b>\nChồng, cha, nghệ sĩ\n\n<b>Stephen Nhà Thám Hiểm</b>\nNhà thám hiểm cho đến chết\n\n<b>Kneppig Kẻ Điên</b>\nTrò nghịch ngợm của Baunk đã gây ra hậu quả\n\n<b>Llop Ferotge</b>\nThổi mạnh, biến mất còn mạnh hơn\n\n<b>Leise</b>\nKhông bao giờ làm cho chiếc tàu lượn hoạt động\n\n<b>Titus Volcatius</b>\nThăng thiên lên các vì sao\n\n<b>Traaajhgsne</b>\nPhần còn lại là sự im lặng\n\n<b>Dominicus Wallarian</b>\nLãnh Chúa Thợ Xây của Pháo Đài Dài",
    [592852940] = "Những miếng chuối sấy khô được bảo quản này không hồi phục nhiều HP như trái cây tươi. Tuy nhiên, thời gian hiệu lực của chúng kéo dài hơn — và tiếng giòn cũng rất tuyệt.",
    [593132370] = "Một bộ trang phục thực sự tinh thần cho các pháp sư và người niệm chú. Vải được nhuộm công phu bằng sắc tố màu xanh coban đậm có nguồn gốc từ hoa nở ban đêm nhập khẩu.",
    [593691373] = "Lan Cánh Xanh",
    [593708432] = "Lối Mòn Sàn Gỗ Bí Mật",
    [594107027] = "Kệ Gỗ Chạm Khắc",
    [594842992] = "Tăng ST Cắt ",
    [594879927] = "Xóa",
    [594917888] = "Hollow",
    [595411170] = "Bộ Giáp Tank",
    [595796740] = "Số Lượng Người Chơi Tối Đa",
    [596052506] = "Chọn một thuộc tính từ bộ sưu tập để được tăng thêm $$arg0$$.",
    [596236338] = "Chế Độ Cửa Sổ",
    [596734513] = "Sương độc đã nuốt chửng ngươi...",
    [596757845] = "Một luống đất trồng nấm Penny Bun.",
    [596765961] = "Bình Máu Tối Thượng",
    [597286468] = "Thu Hồi",
    [597323587] = "Mũ Giao Ước Lửa",
    [597775764] = "Bồn Rửa Đá Granite",
    [597816222] = "Gửi phản hồi",
    [597911323] = "Thêm các nguyên liệu có sẵn bằng các nút này để sản xuất công thức 1 hoặc 10 lần.",
    [598068852] = "Tăng ST Sương độc",
    [599049678] = "Nguyên Liệu Nguồn",
    [599127375] = "Công Thức Latte",
    [599391747] = "Thật tàn nhẫn khi loại bỏ cả mang cá khỏi những con cá không phòng bị này, nhưng kết quả sẽ biện minh cho phương tiện.",
    [599400988] = "Một cây con sẽ phát triển thành cây khi được gieo trồng trong đất thích hợp. Cây này cần được đặt trong nước, để rễ luôn được bao phủ.",
    [599782074] = "Kẻ địch <b>Bị Áp Đảo</b> nhận thêm <b>100%</b> ST Cận chiến trong <b>3</b> giây.\n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang phòng thủ hoặc đỡ đòn của chúng sẽ lấp đầy <i>Thanh choáng</i> của chúng cho đến khi chúng bị <b>Bị Áp Đảo</b>.\nKẻ địch <b>Bị Áp Đảo</b> sẽ mở cho các Đòn tấn công Kết liễu.",
    [600260169] = "Kẻ Xé Xác Sương độc",
    [600558593] = "Đài Lửa Bạc Lớn",
    [600586066] = "Khối Đường Đất",
    [600662818] = "Đá Lửa (Nguyên Lioo5)",
    [600968591] = "Cần câu móc phải được chế tạo và trang bị trước khi sử dụng. Để sử dụng Cần câu móc, hãy định vị bản thân gần một Điểm neo và nhấn %k để phóng hoặc đu qua. Sử dụng Cần câu móc <b>yêu cầu SP.</b>\n\nChế tạo Cần câu móc yêu cầu Mảnh kim loại. Nhận Mảnh kim loại từ Scavenger.",
    [600977197] = "Hỡi Người Sinh Ra Từ Lửa! Ta đã có khám phá vĩ đại nhất! Vâng, bạn của ta, các vì sao đang mỉm cười với chúng ta cuối cùng! Một chiếc <b>Tàu Lượn</b> huyền thoại để bay lên và vượt qua các luồng gió, quý giá hơn bất kỳ thứ gì khác! Hãy tìm kiếm nó và lướt đi như chim giẻ cùi, bạn của ta!",
    [601080672] = "Chim Đuôi Đỏ Không Thể Bay",
    [601450932] = "<keyitem>Ấm Đun Nước</keyitem> Đã Tìm Thấy",
    [601575249] = "Thêm tất cả (%k)",
    [601948899] = "Trại Khai Quật Bộ Xương \"Mae\"",
    [602278245] = "Răng Cá Mập Cùn",
    [602933521] = "Một Thị Trấn Của Những Kẻ Xa Lạ",
    [603389926] = "Thu Thập Tinh Chất Cổ Đại",
    [603523182] = "Kháng Sốc",
    [603615098] = "Một chiếc ủng ướt sũng, bị hư hại do nhiều năm tiếp xúc với nước. Có lẽ bộ lông trên đó có thể hữu ích.",
    [603934226] = "Việc Cần Làm:",
    [604017726] = "Thương nhân Mei nói với ngươi rằng bà ta từng bán một chiếc đèn lồng giấy cho thợ mộc, Cade. Nếu bà ta nhìn thấy thiết kế của chiếc đèn lồng một lần nữa, bà ta có thể tái tạo chúng và cung cấp chúng để chế tạo. \n\nHãy nói chuyện với Thợ Mộc và hỏi ông ta về chiếc đèn lồng!",
    [605325311] = "Nghiêng người về phía sau",
    [605436158] = "Cây Thường Xanh Nhà Tiên Tri",
    [605746873] = "Bộ Giáp Diều Hâu",
    [606437200] = "Nâng Cấp Bàn Thờ",
    [606675806] = "Trượng",
    [607401127] = "Hổ Phách",
    [607680140] = "Ngươi có chắc chắn muốn xóa %k khỏi máy chủ của mình không?",
    [608424102] = "Các Hầm Mộ Cổ Chứa đựng những giọng nói bị Shroud bịt miệng. Tuy nhiên, một vài tia lửa vẫn còn sót lại, lập lòe trong Sương độc. Một <npc>Thợ Săn</npc>, từng là kẻ hung dữ nhất vùng, và một <npc>Nhà Giả Kim</npc>, với kiến thức của các thời đại. Hãy đánh thức họ, vì họ sẽ giúp ngươi trên hành trình của mình.",
    [609031145] = "Một bộ sưu tập các dụng cụ và công cụ tinh xảo để tăng cường các lựa chọn của một <npc>Nhà Giả Kim</npc>. ",
    [609089899] = "Khối Gạch Nung",
    [609157750] = "Tháp Canh Nhỏ",
    [609224054] = "Cưỡi nhanh như chim giẻ cùi với đôi ủng da chắc chắn này.",
    [609674671] = "Trọn Đời",
    [609793628] = "Vòi Sen Đá Granite",
    [610355330] = "Chúng cho phép ngươi chạy nước rút xuyên qua bụi rậm với tốc độ của đôi cánh.",
    [610357958] = "Tìm kiếm khu vực này",
    [610410750] = "Embervale bảo vệ những người bạn đồng hành xung quanh ngươi. ",
    [611079782] = "Ngươi cần dịch vụ của ta?",
    [611088051] = "Cái chết từ trên cao",
    [611088923] = "Trại mà <npc>Nhà Giả Kim</npc> đã đề cập nằm ngay cạnh một Ngôi Đền Mặt Trời cổ xưa. Chiếc <b>Tàu Lượn</b> huyền thoại phải ở bên trong.",
    [611113500] = "Buồm theo gió!",
    [611282453] = "Ôi trời ơi! Ngài đã mang đến cho ta THE Chester Loft ư? Ta là fan cuồng nhiệt các tác phẩm của anh ấy trong The Honeydews! Giờ chúng ta có thể lập một ban nhạc mới cùng nhau!",
    [612387111] = "Sông mục rữa",
    [612407914] = "Bầy côn trùng",
    [612418603] = "Áo Giáp Ảo Thuật Gia",
    [612442195] = "Ta đã mệt mỏi khi phải làm ban nhạc một người. Ta đang tìm kiếm ai đó để chơi cùng ta! Một người chuyên nghiệp, nếu ngài muốn. Chắc không khó để tìm người có nhịp điệu ở Thung lũng Veilwater. Ta biết có rất nhiều nhạc sĩ ở Cromville, biểu diễn trên đường phố. Đó là những gì ta đã làm trước khi được gọi để hát cho Chúa! Nhưng đó là câu chuyện cho một ngày khác...",
    [612827069] = "Giày cổ thấp. Lộ mắt cá chân thật quyến rũ!",
    [613211905] = "Quả Nhựa Ruồi Và Quả Mọng",
    [613479136] = "Thay đổi hành động xẻng",
    [614072574] = "Đèn Gắn Tường Tím I",
    [615109024] = "Bí Ngô Đêm Khô Cốt Lớn III",
    [615348474] = "Giờ",
    [615355783] = "Cả phép thuật lẫn những đòn đánh tàn bạo đều dễ dàng đối phó với đôi Găng Tay Thuật Sĩ tuyệt vời này.",
    [615619208] = "Suy nghĩ của một người lính trẻ",
    [615787844] = "Tiện nghi - Lò sưởi",
    [615836906] = "Đói khát",
    [616195605] = "Bình Năng Lượng Tối Thượng +",
    [616723830] = "Đúng như ta đã nói! Thêm những người sống sót. Tốt. Sức mạnh nằm ở số đông. Đừng nghỉ ngơi. Tiến lên.",
    [616784421] = "Nhớ người phụ nữ đó, Kaori Conway không? Nhớ ta đã bảo ngươi không được tin tưởng giao hàng hóa của chúng ta cho cô ta chứ? \n\nChà, hôm nay cô ta đã gửi một người đưa tin — <b>vâng, văn phòng của cô ta ở gần đây,</b> nhưng cô ta không dám lộ mặt — và người đưa tin nói với ta rằng lô hàng quần áo của chúng ta đã \"bị mất đâu đó\". Vậy là đơn hàng mũ đó đã biến mất. Chúng ta nên chuẩn bị một lô hàng mới... và lần tới, ngươi hãy nghe lời ta và chi TIỀN THẬT cho một NGƯỜI ĐƯA THƯ THẬT SỰ! \nTa hy vọng người phụ nữ đó bị chuột ăn thịt.",
    [617448742] = "Chứa quá nhiều:",
    [617604519] = "Nó lơ lửng trong gió — với mỗi hơi thở trong lành ta hít vào, một mùi hôi thối không rõ nguồn gốc lắng đọng trong phổi ta. Đây là gì? Một lời nguyền khác? Ngươi nói là Màn che? Một màn sương độc ác để dìm chết kẻ ngu ngốc và kẻ dũng cảm... những vấn đề trần tục như vậy khó lòng làm lay chuyển những kẻ đã vượt lên trên. Ngươi và ta, những kẻ được Ngọn lửa chạm vào, sẽ vẫn tiếp tục.",
    [617864487] = "Hôm nay chúng ta cảm thấy thế nào?",
    [617972788] = "Tháp canh bị bỏ hoang",
    [618260530] = "Ngọn lửa cuối cùng",
    [619033696] = "Chiếc búa của ta sẽ sửa nó!",
    [619175013] = "Túp lều phù thủy",
    [620255483] = "Ngươi đã tìm thấy lối vào Hầm mộ Cổ đại. Người sống sót chắc hẳn đang ở đâu đó bên trong. \n\n<b>Đi đến cuối Hầm mộ Cổ đại để đến được người sống sót đang ngủ!</b>",
    [620463763] = "+ Lửa",
    [620513533] = "Người nông dân có công thức làm các loại mồi câu động vật khác nhau cần thiết để thuần hóa động vật. Hãy làm mồi câu dê với Người nông dân để thuần hóa động vật nông nghiệp đầu tiên của bạn!\n\nBạn có thể sẽ cần ít nhất 3 mồi câu dê để tiến triển một cách có ý nghĩa.",
    [620520908] = "Khi bạn bị trúng đòn không phải ST Cận chiến, bạn có 20% cơ hội bỏ qua sát thương đó và thay vào đó mất 15 MP.",
    [620551849] = "Cờ hiệu",
    [620896953] = "UKR",
    [621457471] = "Mithridatist",
    [621687412] = "Tiện nghi (Cấp độ %k)",
    [622025293] = "Nhiệt cơ thể",
    [622698221] = "Tất bị mất",
    [622860618] = "Thang Tre II",
    [623658181] = "Sát thương tầm xa & dao găm",
    [623815971] = "Bất kỳ ai cũng sẽ khó nghỉ ngơi trong một cái lều ọp ẹp như vậy vào ban đêm. Gió rít lên không thương tiếc, không bị thuyết phục bởi những lời cầu xin bình yên và tĩnh lặng của ta. Tuy nhiên, mỗi sáng ta lại lê bước đến mỏ đá để kéo đá về.\n\nSự kiệt sức cuối cùng đã chiếm lấy ta khi ta đang vận hành ròng rọc, nâng một khối đá cẩm thạch. Ta không thể tập trung và ngủ thiếp đi trong giây lát, để khối đá cẩm thạch rơi xuống đất.\nMột tiếng động lớn đã đánh thức ta khỏi giấc ngủ và thu hút sự chú ý của ta đến khối đá giờ đã bị nghiền nát một phần. Trong trạng thái nửa mơ nửa tỉnh, bột lấp lánh dưới chân ta đã mê hoặc ta, nhưng ta nhanh chóng rút lui khỏi cảm giác đó khi ta bắt đầu tỉnh táo.\n\nTa được phép nghỉ ngơi khỏi mỏ đá, nhưng ta đã dành thời gian rảnh rỗi của mình để nghiền đá thành bụi. Ta thấy việc nhìn ngắm những sắc thái xám khác nhau của bụi đá một cách kỳ lạ là điều êm dịu.",
    [623874729] = "Tìm và khám phá Lăng mộ tiếp theo",
    [624818007] = "Làm đầy",
    [624980895] = "Chỉ báo bạn có thể bơi dưới nước trong bao lâu.",
    [625012728] = "Đũa Phép Bão Tuyết",
    [626129028] = "Triệu hồi một đàn côn trùng chiến đấu bên cạnh bạn.\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [626552450] = "Trượng Đuốc Sáng",
    [626706617] = "Huynh đệ! Ngươi phản bội ta cùng với những kẻ còn lại. Các ngươi đều là những kẻ hèn nhát — Ta sẽ tự mình đào Giếng Elixir và sở hữu tất cả Elixir trong Embervale! Ta sẽ không còn dựa vào những cách cũ, những cái tên cũ nữa. Đây là buổi bình minh của một kỷ nguyên mới: Kỷ nguyên của <lorename>Sameth</lorename>!",
    [626806896] = "Đây là nụ của một loại cây tảo. Chúng không ăn được khi còn tươi, nhưng có thể sấy khô.",
    [627157926] = "Súp Rau Củ",
    [627481713] = "Khu vực nghiên cứu trong Trụ cột Sáng tạo chứa một cấu trúc khổng lồ, kỳ lạ. Các trại khai quật rải rác khắp nơi. Một trong những trại này chắc chắn chứa <craftingstation>Dụng cụ xây đá</craftingstation>.",
    [627566837] = "Thức ăn để thu hút và thuần hóa Dê.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Khi đã thuần hóa, con vật có thể được nhặt lên.",
    [627963240] = "Thịt của nấm khổng lồ mọc ở Đầm lầy Đen. Nó hơi dai, nhưng đủ chắc chắn để xây dựng.",
    [628114525] = "Trang bị độc nhất",
    [628276520] = "Sắp xếp kho đồ",
    [628362428] = "Yêu cầu Dụng cụ Thảm thực vật từ Người nông dân",
    [628559517] = "Bạn cảm thấy ấm áp và hạnh phúc!",
    [628772109] = "Bộ sưu tập",
    [628806899] = "Tiếp theo:",
    [628989471] = "Hoàn hảo để xây dựng một ngôi nhà tạm thời ở những khu vực nóng bức. Gỗ dừa là một sự thay thế tuyệt vời cho gỗ thông thường, mô phỏng sự quyến rũ và độ bền của nó.",
    [629049322] = "V-Sync",
    [629159438] = "Gửi những người bạn giữ lửa của ta",
    [629901893] = "Thà chạy còn hơn chiến đấu",
    [629985392] = "Quần vải bị rách và tả tơi. Một con mắt tinh tường có thể phát hiện những vệt máu khô trên đó.",
    [630288596] = "Tìm công thức cà phê",
    [630706767] = "Với bình thuốc này, việc giữ an toàn cho bản thân sẽ dễ dàng hơn nhiều.",
    [631366082] = "Liên tục hồi máu cho mục tiêu trong một chùm tia lên đến 20 mét.\n\n\n<b>Phép thuật Kênh dẫn:</b> Giữ nút để kênh dẫn <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>\n\n<b>Phép thuật Vĩnh cửu:</b> <b>Không tiêu hao.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [631535020] = "Chiếc Rìu Thợ mỏ Scavenger này sẽ cho phép bạn cạy quặng từ đá vào ban ngày và đâm vào lưng kẻ phản bội vào ban đêm.",
    [632213035] = "Kể từ khi công ty tăng cường sản xuất, tôi nhận thấy có điều gì đó không ổn với nước. \nCó một chuyển động kỳ lạ trong dòng chảy. Một chuyển động không tự nhiên — nặng hơn, chậm hơn. Một quầng sáng màu tím nhảy múa ở khóe mắt tôi mỗi khi tôi nhìn chằm chằm vào dòng sông.\n\nTôi từng uống từ nó mà không hề suy nghĩ. Tất cả chúng tôi đều vậy.\n\nBây giờ, chúng tôi đã bị ngăn cản mạnh mẽ việc uống nước sông. Ban quản lý nói đó là \"biện pháp phòng ngừa\", nhưng <i>Timberwolf Logging & Co.</i> lại tự mình cung cấp nước đóng chai — với một cái giá. Tất nhiên là không công khai. Họ chỉ trừ vào lương của chúng tôi. Lặng lẽ, tự động. Như thể đó là một phần chi phí kinh doanh.\n\nTôi cứ nghĩ: nếu tôi không thể uống nước từ vùng đất tôi làm việc, nếu tôi phải mua nước từ chính những người có thể làm ô nhiễm nó, thì đó là loại tự do nào? Đó là loại tương lai nào?",
    [632403161] = "Nhẫn Song Tử",
    [632541617] = "Bạn không có quyền dập tắt các Bàn thờ.",
    [632691265] = "Điều tra lô hàng bị mất",
    [633400860] = "4m ",
    [633466444] = "Giày Lính Canh Phương Bắc",
    [634335624] = "Rơi ra từ kẻ địch Fell ở Thung lũng Veilwater",
    [634733752] = "Bộ Lọ Lớn",
    [635177283] = "Giếng Elixir Albaneve Summits",
    [635961106] = "Cánh đồng Lô hội",
    [636513242] = "Bạn đã tìm thấy một món đồ trong bộ giáp trang phục Fluffy. Tất cả các món đồ đều nằm rải rác khắp các trang trại dê trong Dãy núi Albaneve. Tìm kiếm rương gần các trang trại dê để tìm các món đồ khác của bộ giáp trang phục!",
    [637375453] = "Đo lường tốc độ vũ khí của bạn bị hỏng.",
    [637966390] = "Mũ Trùm Thợ Săn",
    [638032107] = "Kiểm tra",
    [638926099] = "Một lò sưởi ấm áp và mời gọi được làm từ gạch đỏ.",
    [638971379] = "Phòng Thí Nghiệm",
    [639240753] = "Đạt cấp 10.",
    [639241368] = "Hẹn gặp lại!",
    [640156177] = "Giường Gỗ",
    [640182789] = "Tôn vinh các Tiền nhân, ngươi đã lấy được <keyitem>Ấm đun nước</keyitem> của ta! <lorename>Raúl</lorename> thế nào? ...Ồ. Thời gian của họ đã hết khi thời gian của ta đứng yên. Vậy chúng ta thực sự là những người cuối cùng... thật lạnh lẽo. Hãy thắp một ngọn lửa để vinh danh họ. Chế tạo một <b>lò sưởi</b> với <keyitem>Ấm đun nước</keyitem> đó sẽ làm chúng ta ấm lên.",
    [640908721] = "Hiểu về Kẻ thù Cổ đại",
    [640987657] = "Máy Xay Thịt",
    [641078763] = "Vô số vết loét mọc ra từ bộ giáp da này, do đó rèn nó thành một hình ảnh mới.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [641145208] = "1... 2.... 3... 4... \nKhông hiệu quả! Đếm <i>không</i> làm ta bình tĩnh lại. Ta <i>phát điên</i>.\nTa là Học giả của ngôi làng này. Nhiệm vụ của ta là thu thập các lá thư, sách, bất kỳ vật phẩm dâng cúng nào mà mọi người muốn để lại trong các Thánh địa Đêm. Nhưng Garrick... mỗi lần ta đến, hắn đều đưa cho ta một chồng thư. Ta biết hắn là một tín đồ chân chính — tuyệt vọng vì sự ưu ái của các Tiền nhân.\nTa cũng biết rằng việc mở những lá thư được giao cho ta là hoàn toàn cấm kỵ.\nNhưng ta chỉ là con người — và hôm nay ta đã nhượng bộ.\nVà đoán xem ta tìm thấy gì?\nGarrick đã tuôn ra <i>tất cả mọi thứ</i> cho các Tiền nhân! Mọi lời thì thầm nhỏ nhặt hắn nghe được, mọi khoảnh khắc riêng tư hắn không nên chứng kiến. Và giờ là phần hay nhất: hắn đã viết rằng ta đã ngoại tình với vợ mình.\nVâng, đúng vậy.\nVâng, ta biết điều đó là sai nhưng <i>LÀM SAO HẮN DÁM</i> viết điều đó xuống? Điều gì sẽ xảy ra nếu lá thư đó rơi vào tay kẻ xấu?\nKhông thể tin được. Ta cần phải giải quyết chuyện đó.",
    [641377160] = "Bộ Sưu Tập Sách III",
    [641430945] = "Sữa dừa béo ngậy này là một thức uống giải khát tuyệt vời vào một ngày nắng bên bờ biển! Nó cũng có thể được sử dụng làm nguyên liệu trong nấu ăn.",
    [641478060] = "Thảm",
    [641989626] = "Một chiếc áo kép thoải mái và quý phái với một chiếc áo choàng nhỏ đính kèm. Mọi yếu tố thiết kế đều được lựa chọn cẩn thận để tạo ra một vẻ ngoài đáng kính.",
    [642060573] = "Xóa",
    [642303492] = "Chế tạo Máy quay với Thợ săn",
    [642312121] = "Khối tường thành phố",
    [642391969] = "Một cây Đũa phép đơn giản, được định hình bởi sự trỗi dậy của Drak. Những vũ khí như thế này từng nắm giữ sức mạnh to lớn trong quá khứ, nhưng kiến thức nguyên thủy xung quanh việc tạo ra chúng đã bị mất. Do đó, những cây Đũa phép được chế tạo gần đây mang tính nguyên thủy hơn, và chỉ là những bản sao nhái của sức mạnh và sự thống trị không thể phủ nhận của các loài thú trong quá khứ.\n\n<b>Quá tải:</b>\nCây Đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.",
    [642723681] = "Đòn chí mạng bằng vũ khí cận chiến hồi HP cho bạn <b>5%</b> HP tối đa.",
    [643169533] = "Sửa đổi XP",
    [643300679] = "Trang phục Thân Trên",
    [643658426] = "Cửa Đôi Gỗ Phương Bắc",
    [644389324] = "Linh Thể",
    [644649134] = "Thu thập thực vật ban đêm tại Nơi Ẩn Ná của Nông Dân, hoặc bất cứ đâu",
    [645149401] = "Giáp Chitin",
    [645543665] = "Một cây Gậy phép ma thuật đơn giản được làm từ xương hóa thạch. Thô sơ, nhưng hiệu quả.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng điểm niệm phép và MP. Trang bị <b>điểm niệm phép</b> để niệm.",
    [645720635] = "Liên tục hồi máu cho mục tiêu bằng một luồng sáng trong phạm vi 20 mét.\n\n\n<b>Niệm phép Kênh dẫn:</b> Giữ nút để niệm phép <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm bằng <b>Gậy phép.</b>",
    [645752319] = "Người chơi chưa đăng nhập",
    [646164785] = "Tầm xa\nSức tấn công",
    [647830689] = "Bảng màu này có thể được tạo bằng vật liệu từ Đỉnh Albaneve.",
    [648348876] = "Một vòng xoáy năng lượng rực rỡ cần thiết để gắn đá quý vào vũ khí.\n\nBan đầu được người Cổ đại sử dụng, nó đã bị Kẻ Fell chiếm đoạt để nuôi dưỡng bầy con của chúng cho đến khi bạn giải thoát nó khỏi nhà tù hữu cơ mới của chúng.\n\nBiến thể này có thể được tìm thấy ở Lưu vực Veilwater.",
    [648463005] = "Chiếc handpan này là một vật phẩm cực kỳ hiếm, được trang trí bằng những tông màu đỏ rực rỡ.",
    [648650658] = "Cuốc",
    [649377813] = "Luôn cảnh giác như chim ưng với chiếc mũ trùm đầu kỳ lạ này.",
    [649513624] = "Khai thác mọi vật liệu quý giá ở Vùng Đất Mùa Xuân.",
    [650078583] = "Giường Gỗ Phương Bắc Lớn",
    [650160393] = "Đổi tên",
    [650446643] = "Trang trại Bí Ngô của Patty Xinh Đẹp",
    [651078527] = "Trại Nữ Hoàng Jezmina",
    [651941740] = "Bắt bài ở đâu?",
    [651942623] = "Một thế giới rộng lớn đang chờ bạn, chứa đầy bí mật và hiểm nguy. Nhấn <b>%k</b> và điều hướng đến bản đồ để theo dõi những khám phá của bạn.",
    [651966019] = "Ngọn Lửa muốn bạn chinh phục Tháp Cổ trong Lưu vực Veilwater.\n\nĐến đỉnh Tháp Cổ để mở khóa <b>điểm Dịch chuyển Nhanh trong khu vực và các điểm quan tâm mới</b> trên bản đồ của bạn.",
    [652175769] = "Một dân làng kể cho bạn nghe về kho hàng của một ngư dân kỳ lạ ở <location>Pondsworth</location>. Ông ta luôn bán cả đồ bỏ đi và kho báu, nhưng hiếm khi bán cá. Có lẽ có điều gì đó kỳ lạ về ngư dân này cần được điều tra.\n\nĐến <location>Pondsworth</location> và tìm kiếm manh mối ở đó!",
    [652959984] = "Trang trại Dê Đồng Cỏ Xanh",
    [653108674] = "Mũi Tên Thép",
    [653150001] = "Để Chó Ngủ Yên",
    [653199531] = "Di chuyển sang phải",
    [653278663] = "Máy phát lực không hoạt động.",
    [653329838] = "Chim non",
    [653977772] = "Hẹn gặp lại!",
    [654635497] = "Một Khối Đá Tinh Luyện, đã từng trát lên vô số tòa nhà quý tộc thời xưa.",
    [654663457] = "Chọn một người sống sót khi vật phẩm này đang được sử dụng.",
    [654996701] = "Vây Sốc",
    [655669525] = "Một khuôn mặt rực lửa tô điểm cho chiếc mũ bảo hiểm này, đốt cháy cả chiến trường lẫn trái tim.",
    [655733097] = "Một bài kiểm tra kỹ năng",
    [655769603] = "Rìu Tù Trưởng Drak'Dal",
    [656253758] = "Nhẫn Người Thừa Kế",
    [656641813] = "Kiếm Ngắn Rỉ Sét",
    [656715882] = "Cửa Đôi Thép Tinh Xảo",
    [656954820] = "(%k sợi chỉ)",
    [656974103] = "Vải Rách",
    [657556489] = "Hoa Gentian",
    [657704910] = "Chữa thương theo thời gian",
    [658256298] = "Hoa Treo Tường Màu Hồng",
    [658623543] = "Cho phép bạn thực hiện một cú lướt né khi bơi hoặc lặn.\n\n<b>Chi phí</b>: 40 SP",
    [659193124] = "Điều khiển Menu Chung",
    [659421699] = "Bức thư do <lorename>Rochelle Anders</lorename> viết đã được trao cho cha cô, Oswald Anders. <npc>Thợ Rèn</npc> sẽ trân trọng món quà này.",
    [659693777] = "Đánh dấu tùy chỉnh",
    [660512705] = "Bù Nhìn",
    [660827711] = "Một viên ngọc quý hiếm nổi tiếng với đặc tính ma thuật làm chất xúc tác. Rất tuyệt vời để dẫn truyền và che chắn!",
    [662288715] = "Những vùng đất cằn cỗi này giờ đây bị tàn phá bởi những chồi non đang bò lan!!\n\nChúng trồi lên khỏi mặt đất nhanh hơn tôi có thể cắt hạ chúng! Những thứ ghê tởm, phun mật đắng và nước mặn! Tất cả cánh đồng đều thối rữa, và sự mục nát lan sâu... Không còn cứu vãn được đồng cỏ nữa!\n\nChết tiệt! Tôi sẽ bắt đầu lại ở nơi khác. <i>Trao nó cho Otto, thằng ngốc đó.</i> Dù sao thì tôi cũng chẳng ưa gì nó. Thằng nhóc kiêu căng.",
    [662799041] = "Ồ, hương vị món ăn của chúng ta thật tuyệt vời! Và chúng cũng sẽ bảo vệ bạn khỏi cái lạnh nữa!",
    [663488809] = "Hỡi Hỏa Sinh, hãy cho ta một phút.",
    [663490536] = "Bạn đã thấy Sứ giả Hoàng gia chưa?",
    [663583965] = "Bị Sương độc Cản Trở",
    [663933470] = "Nhẫn Thể Lực Nhỏ",
    [664089503] = "Kể từ khi đoàn xe của chúng ta chia làm hai, mỗi ngày đều trở nên tuyệt vọng hơn. Tôi ước gì Nữ hoàng <lorename>Jezmina</lorename> đã ở lại — sự duyên dáng và vẻ đẹp của bà sẽ là liều thuốc an ủi cần thiết. Chỉ ngày hôm qua tôi đã nghe Lazlo khóc trong lều của anh ấy.\n\nChúng tôi đã thấy dấu hiệu của những người sống sót tại một Thánh địa Ngọn lửa. Đó là một chuyến đi cả ngày — và vô ích. Mặc dù Sương độc đang xâm lấn họ, những kẻ ngu ngốc này không cảm thấy cần phải gia nhập hàng ngũ của chúng ta. Hãy để họ cầu nguyện các Vị Thần Cổ đại của họ và xem họ tồn tại được bao lâu. Chúng ta phải giữ vững mục tiêu... <location><lorename>Pikemead</lorename>'s Reach</location> còn cách hàng tuần lễ.\n\n— Chỉ huy <lorename>Cyrus</lorename>.",
    [664928518] = "Nhạc công muốn có một người phụ tá để chơi song tấu.\n\nBà ấy tin rằng Cromville, một thị trấn ở Lưu vực Veilwater, nên có nhiều nhạc sĩ có thể là những ứng cử viên đầy hứa hẹn.\n\nĐến Cromville để tiếp tục!",
    [665074346] = "Điểm Dịch Chuyển",
    [665331245] = "May Mắn Ngư Dân",
    [665772915] = "Cô Gái Drakonian Ngon Ngọt",
    [666657602] = "Scavenger",
    [666756400] = "Khe Cắm Đá Quý Trống",
    [667011620] = "Bị Lật Đổ",
    [668325580] = "Với đôi đế nặng này, ngay cả mặt đất không ổn định hoặc không bằng phẳng cũng sẽ không làm gián đoạn mục tiêu của bạn.",
    [668400459] = "Chưa đặt",
    [668887494] = "Giày Khô Cốt Tinh Nhuệ",
    [669008328] = "Đá Ngọc Bích",
    [669497907] = "Bạn không thể hoàn tiền cho một nút mà người khác phụ thuộc vào.",
    [670040882] = "Đá quý",
    [670191754] = "Làm theo tiếng gọi",
    [670255714] = "Thức ăn để thu hút và thuần hóa Chó.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Khi đã thuần hóa, con vật có thể được nhặt lên.",
    [670399025] = "Sự thoải mái và nghỉ ngơi",
    [670622169] = "Một chiếc khiên bị dòng sông cuốn vào một hang động. Nó hẳn thuộc về một anh hùng dũng cảm.",
    [670851276] = "Khối Đền Sa Mạc",
    [671385391] = "Nơi An Nghỉ Của Những Người Chiến Thắng Thế Vận Hội Mùa Hè",
    [671762050] = "Đèn Gắn Tường Phòng Ngai Vàng",
    [672026043] = "Làm chủ các Sảnh Đường Hollow của Cao Nguyên Du Mục",
    [672434546] = "Một cây nấm nướng hun khói giúp tăng cường sức mạnh ma thuật của bạn tạm thời khi ăn.",
    [672464674] = "Tìm Bảng Màu trong Trại Buôn Lậu",
    [672616651] = "Trí tuệ",
    [672683977] = "Mọc lan",
    [672843305] = "Đôi ủng này luôn ẩm ướt, ngay cả bên trong. Đi bộ trong đó giống như lội qua một đầm lầy.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [673005589] = "Tủ Búp Phê Hầm Mộ Nhỏ",
    [673369734] = "Sương độc trỗi dậy từ các Giếng Tinh chất trên khắp Embervale. Hãy tiêu diệt Rễ Sương độc ở nơi sâu thẳm nhất của chúng để nhận <b>điểm kỹ năng</b> cho tất cả những ai thuộc Dòng Lửa ở gần.\n\nNhững người thuộc Dòng Lửa đã thu hoạch Rễ Sương độc một lần sẽ không thể nhận thêm điểm kỹ năng từ cùng một rễ sau khi nó hồi sinh.\n\n<b>Giếng Tinh chất luôn bị bao phủ bởi Sương độc và đầy thử thách. Hãy chuẩn bị sẵn sàng.</b>",
    [673730832] = "Nhà Ẩn Sĩ",
    [674005339] = "Túi Nước",
    [674140452] = "Vật thể",
    [674506720] = "Hóa Thạch Loa Kèn Biển Nhỏ Hơn",
    [674541029] = "Bạn biết không? Tôi thực sự mệt mỏi với súp cá. Tôi sẵn sàng mở rộng tầm nhìn ẩm thực của mình và thử các loại hải sản khác. Bạn có thể săn một vài sinh vật biển khác cho tôi không? Có lẽ là cua? Như vậy, tôi sẽ biết mình đang làm việc với loại thịt nào.",
    [674704535] = "Sau khi thực hiện hành động né tránh, đòn đánh tiếp theo gây thêm %k ST Cắt và hồi phục \n%k SP trong đòn đánh tiếp theo.",
    [675024689] = "Lò Cao",
    [675374754] = "Máy Rang Cà Phê Hình Trống",
    [675655908] = "Tất cả sát thương <b>chém</b> cận chiến đều tăng <b>20%</b>.",
    [675679262] = "Đạn dược",
    [675951684] = "Tìm tất cả các đền thờ và thánh địa Ngọn lửa trong Kindlewastes.",
    [677008930] = "Kỹ thuật của Lão Ông",
    [677257400] = "Thích mái tóc của bạn. Bạn có thích nó không?",
    [677355980] = "Không đủ dung lượng để tạo dữ liệu lưu mới.",
    [677420416] = "Một cây sáo được khắc từ xương. Bạn có thể dùng nó để tạo ra âm nhạc.",
    [677428187] = "Dù có hao mòn đến đâu, chiếc quần này vẫn có thể được vá lại! Điều đó khiến chúng phù hợp với những nhà thám hiểm táo bạo.",
    [677533105] = "Khi bạn bị nhắm mục tiêu bởi một đòn tấn công, <b>Vukah</b> trong phạm vi <b>50</b> mét sẽ tấn công kẻ địch.",
    [678766080] = "Mũ Trùm Người Tiên Phong",
    [678857559] = "AA Bản Địa",
    [679380986] = "Tàn Tích Drak'Dal",
    [679425180] = "Sát thương dao găm tăng <b>15%</b>.",
    [679871236] = "Mở tất cả các cánh cửa trong \"The Pike\", lâu đài thuộc <location><lorename>Pikemead</lorename>'s Reach</location>.",
    [679889897] = "Ngọn lửa bên trong bạn đã phát triển vượt ngoài tầm hiểu biết. Bạn đã mang về một trợ lý chế tạo, không bị ảnh hưởng bởi Sương độc hay Thuốc Tiên. Triệu hồi họ bằng một cây Gậy phép Triệu Hồi để xây dựng lại thế giới này và cai trị một cách công bằng!",
    [680027096] = "Nguyên liệu không đủ",
    [680045404] = "Có thể chỉnh sửa địa hình và đạo cụ trong căn cứ",
    [680595655] = "<location>Brightwich</location>",
    [681076966] = "Nhà Tiên Tri",
    [681915214] = "Một nguồn sáng có thể ném để <b>đánh dấu một địa điểm</b> cho người chơi khác, và để thắp sáng những khu vực tối tăm phía trước. Kéo dài 24 giây.",
    [682250598] = ".",
    [682355081] = "Đoạn Dốc Cao 4m",
    [682431860] = "Một cây Gậy phép ban cho người sử dụng khả năng làm tan chảy các chỏm băng và dòng sông đóng băng. Nước ngọt thu được được coi là tinh khiết và Chữa thương đặc biệt.",
    [682641514] = "\n\n\n\nNhiều bàn tay, vươn ra \n\nNắm lấy, níu giữ, cào cấu \n\nLấy ý nghĩa, lấy ký ức \n\nLấy tất cả, lấy hư vô",
    [682998021] = "Áo Giáp Đại Pháp Sư",
    [683400034] = "Bộ Giáp Lông",
    [683932059] = "Tìm Chó Trong <location>Thornhold</location>",
    [684136996] = "Chậu Cây",
    [684931217] = "Các Hiện Tượng Thời Tiết Khắc Nghiệt",
    [685078901] = "Chọn một bản thiết kế đang hoạt động trước khi sử dụng lần đầu.",
    [685275625] = "Găng Tay Dân Du Lâm",
    [685575440] = "Vai trò Bạn bè yêu cầu mật khẩu.",
    [685626748] = "Trượng Chói Lọi",
    [685730047] = "Hiệu ứng Tiêu Cực",
    [686106191] = "Tượng Đầm Lầy Đen Lớn I",
    [686342709] = "Nhẫn Năng Lượng Tuyệt Hảo",
    [686685778] = "Mặt Trời Buổi Sáng",
    [687166534] = "Một bát thức ăn nhỏ cho Chó của bạn.\n\nNó sẽ cho động vật ăn khi được đổ đầy thức ăn tương ứng.",
    [687859826] = "Phần Thân Dưới",
    [688339492] = "Khung Cửa Sổ Gỗ Tròn",
    [688456099] = "Vì Gia Đình Đang Lớn Mạnh Của Tôi",
    [689173187] = "ST Cắt",
    [689659930] = "Tên Người Dùng",
    [690260970] = "Khi bạn bị nhắm mục tiêu bởi một đòn tấn công, <b>Động Vật Hoang Dã</b> trong phạm vi <b>50</b> mét sẽ tấn công kẻ địch.",
    [690948885] = "Tăng ST Cận chiến thêm 5% cho mỗi Điểm Thuộc Tính.",
    [691084597] = "Bình Năng Lượng +",
    [691336990] = "Có nhiều trang trại bí ngô hơn xung quanh. Ghé thăm địa điểm tiếp theo để lấy một quả bí ngô khắc cỡ vừa!",
    [691445350] = "Thu Hoạch Tốt",
    [691742795] = "ST Phép",
    [691854607] = "Thuốc Sát Trùng",
    [691925769] = "Ngôi Đền Ẩn",
    [692780092] = "Kiếm Sư Tử",
    [693044550] = "Rồng Fell Non",
    [693067628] = "Pha Lê Đen Lớn",
    [694105720] = "Khối Mái Rơm",
    [694110312] = "Một lưỡi kiếm xanh lấp lánh, cân bằng hoàn hảo giữa tính thẩm mỹ của sự phản bội và tinh thần của Tết Nguyên Đán.",
    [694270618] = "Sát thương chống lại Drak",
    [694334871] = "Mạng Nhện III",
    [694533349] = "Khám phá Hầm mộ Hollow Ẩn",
    [694913407] = "Nó Sẽ Ổn Thôi Ở Đó!",
    [694997189] = "Bạn Nấm",
    [695359022] = "Giày Nữ Vắt Sữa",
    [695861166] = "Nghỉ Ngơi Tốt",
    [696833656] = "Xóa Điểm Dẫn Đường",
    [697084547] = "Cần giúp đỡ?",
    [697684533] = "Chọn độ hiếm vật phẩm yêu cầu xác nhận khi xóa hoặc bán lại vật phẩm. Có thể tắt.",
    [697963655] = "Một món ăn nhẹ giàu protein bổ dưỡng. Màu sắc trông thật hoàn hảo...",
    [698136803] = "Vô Dụng",
    [698989520] = "Tôi vẫn cảm nhận được răng của nó trong thịt mình. Miếng cắn đầu tiên chỉ là một khúc dạo đầu cay đắng cho vô số miếng cắn sau đó. Tôi sợ thời khắc của mình đã đến. Cơ bắp của tôi căng cứng, da tôi căng ra. Tôi có thể nhìn thấy chúng dưới ánh nến, háo hức đẩy ra ngoài... <b>Hầm mộ</b> đã nguyền rủa tôi, vì lồng ngực trống Hollow của tôi là nơi trú ngụ của hàng ngàn vết cắn gặm nhấm.",
    [699289813] = "Salad Tảo",
    [699355640] = "Tạo Đánh Dấu",
    [699413234] = "Giáp được trang bị tăng thêm <b>10%</b> Giáp Vật Lý.",
    [699746684] = "Lối Đi Hang Động",
    [699990510] = "Sốc Điện",
    [700088067] = "Một hơi ấm dễ chịu tỏa ra từ những tảng đá nên tôi sẽ không cần lửa tối nay. Tôi nghe thấy chúng từ xa, đang tìm kiếm, đang hú hét. Chính cơn gió mang sự điên cuồng của chúng đến với tôi, một luồng gió từ <b>mỏ.</b> Chúng đang đào bới thứ gì? Tiếng hét của chúng xé toạc màn đêm và xua đuổi mọi con mồi. Tôi đang chết đói.\n\nLẽ ra tôi nên tích trữ tài nguyên khi ở gần <b><location>Glennwood's End</location>?</b> Không. Cả nơi đó bốc mùi máu và sự phản bội. Tôi biết mùi đó rõ. Tôi sẽ bước đi với cơn đói trong tim nếu phải vậy.",
    [700784132] = "Bật Micrô",
    [701088998] = "Tôi nghĩ chúng ta không còn gì để mất khi xé toạc đường vào đầm lầy. Giờ đây, với hang động sụp đổ phía sau, tôi không còn chắc chắn nữa.\n\nToàn bộ nhiệm vụ của chúng ta đã hỏng bét. Chúng ta đã mất vài trinh sát lẽ ra phải trở về hai đêm trước. Họ sẽ không trở lại. Có thứ gì đó đã bắt họ và kéo họ đi. Thứ duy nhất kéo mọi người xung quanh phải là chúng ta!!\nTôi không sợ bất cứ thứ gì... không thể cảm thấy sợ hãi nữa kể từ khi dùng Thuốc Tiên... nhưng có điều gì đó không ổn. Đầm lầy chết tiệt này khiến tôi rùng mình... À, cũng có thể là do cai nghiện nữa.\n\nChúng ta chỉ cần bắt người của mình và chuồn thôi. Quên nhiệm vụ trinh sát đi. Tôi chỉ muốn dìm mình trong rượu dâu từ <location>Glennwood's End</location> thân thương.",
    [701181428] = "Một cối xay tốt. Điều này sẽ cho phép một <npc>Nhà Giả Kim</npc> mở rộng phạm vi chế tạo của họ khi đặt trong tầm tay.",
    [701536421] = "Trạng Thái",
    [702058000] = "Bản Phác Thảo",
    [702168625] = "Nước",
    [702544872] = "Giày Xuyên Dương",
    [702637288] = "Chiến Thắng",
    [702902349] = "Chiếc mũ bảo hiểm không khí mà bạn mang về có vẻ là một thiết bị thú vị. Có lẽ tôi sẽ mượn nó vào lúc nào đó.",
    [703202779] = "HP",
    [703437488] = "Dịch Chuyển Tức Thời",
    [704286237] = "Đá",
    [704533554] = "Đánh bại kẻ địch bằng Cung có <b>30%</b> cơ hội tạo ra một Quả Cầu SP.\n\nThu thập một Quả Cầu phục hồi <b>10%</b> tài nguyên tương ứng.",
    [704784392] = "Độ Phân Giải Kết Cấu",
    [704869439] = "Kỹ Năng Nhân Vật",
    [705001777] = "Nhân Vật",
    [705124005] = "Kiếm Cực Quang",
    [705124936] = "Ồ, bạn có một làn da đẹp.",
    [705194827] = "Một chiếc mũ đội đầu rực rỡ có thể nhìn thấy từ xa. Không chỉ khi ánh mặt trời rực rỡ phản chiếu vào nó.",
    [705308868] = "Loại Trò Chuyện Thoại: ",
    [705558693] = "Tìm Nơi An Nghỉ Của Người Đào Mộ",
    [705813316] = "Gạch Vữa",
    [706247436] = "Tôi sẽ gặp bạn trong giấc mơ của bạn.",
    [706792199] = "Khách Thăm Ở Gloomsbury",
    [706837903] = "Loại cá sống ở tầng đáy này nổi tiếng với bộ ria dài, dùng để cảm nhận chuyển động và thức ăn trong nước. Rõ ràng, nó cũng cảm nhận được mồi câu của bạn.\n\nLoại cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả lại vào nước và nuôi trong ao.",
    [707223511] = "ST Xuyên",
    [707780789] = "\"Glimmer Gentian\" là một biến thể của cây long đởm chỉ có thể tìm thấy ở Đỉnh Albaneve vào ban đêm.\n\nNó phát ra ánh sáng màu hồng rực rỡ và có thể được sử dụng để tạo ra bảng màu sống động.",
    [708084770] = "Bình Đất Sét I",
    [708507653] = "Pháo Đài Balefire \"Đầu Giáo\"",
    [708600607] = "Lan Can Gỗ II",
    [708969660] = "Xóa Cấm",
    [709060732] = "Sống Động Như Lá Xanh",
    [709233597] = "Cây chùy này không thể ngăn cản khi đã vào đà.",
    [709348410] = "Mũ Tiệc Màu Tím",
    [709360662] = "Khối Phát Sáng Trắng",
    [709395090] = "Chiếc rương nhỏ này cung cấp không gian lưu trữ vật phẩm tăng thêm.",
    [709543918] = "Vật Liệu Làm Tổ Của Vukah",
    [709692711] = "Những người sống sót cho phép bạn <b>chế tạo các vật phẩm đa dạng và tiên tiến hơn</b>. Chúng rất quan trọng để cải thiện trang bị, vật tư và kho chứa của bạn.\n\nNhững người sống sót phải được giải cứu khỏi các Hầm Mộ Cổ và triệu hồi bằng <b>Gậy phép Triệu Hồi.</b> Gậy phép Triệu Hồi có thể được chế tạo trong tab Chế Tạo Thủ Công.",
    [709747966] = "Đôi găng tay xếp lớp đơn giản cho phép sự linh hoạt tối ưu và nhanh nhẹn khi sử dụng phép thuật.",
    [710079074] = "Quái Vật Fell",
    [710318763] = "Chưa nghỉ ngơi",
    [710568305] = "Tức thời hồi phục một lượng nhỏ MP, và liên tục bổ sung MP trong 10 giây.",
    [710620794] = "Tiếp xúc lặp đi lặp lại với độc tố đã làm đặc HP của bạn, gây ra cục HP đông không kiểm soát. Hồi phục HP bị đình chỉ.\n\nHiệu ứng xấu kéo dài này ảnh hưởng đến bạn vĩnh viễn cho đến khi được loại bỏ bằng thuốc giải độc độc tố.",
    [710653433] = "Sự bảo vệ Sương độc của bạn đã cạn kiệt.\nHãy nhớ để nó phục hồi bên ngoài Sương độc.",
    [711122870] = "Luôn sẵn lòng phục vụ!",
    [711720223] = "Kendal",
    [711845468] = "Cánh Hoa Khăn Liệm Giòn Mỏng",
    [711852935] = "Ai sợ những con quái vật bay? \nNhững sinh vật có cánh, trên bầu trời!\n\nAi sợ những con quái vật bay? \nSau những đám mây, chúng ẩn mình trên cao!\n\nAi sợ những con quái vật bay?\nLà bạn, hay là tôi?\n\nNhững kẻ sợ hãi sẽ ngủ trong nỗi buồn\nVà những kẻ dũng cảm sẽ ngủ trong bình yên!",
    [711914735] = "Vukah",
    [712072845] = "Có Thể Có Thêm Màu Sắc Không?",
    [712205185] = "Cuồng Chiến Thỏa Mãn",
    [712629470] = "Giao diện người dùng",
    [712631936] = "Nó phát sáng trong bóng tối. Một nguồn sáng tâm trạng thường được tìm thấy trong hoặc xung quanh hang động.",
    [713021153] = "Bạn có một trái tim bằng thép đấy, nhóc.",
    [713100383] = "Quần Thợ Săn Hươu",
    [713152224] = "Đèn Đứng Xanh Dương II",
    [713574122] = "Chiếc rìu khổng lồ này hút sức mạnh từ những kẻ nó làm bị thương, đánh cắp sinh lực của chúng với mỗi đòn đánh.",
    [713681238] = "Mũ Giáp Vệ Binh",
    [713741200] = "Các đòn tấn công của đũa phép có <b>30%</b> cơ hội tạo ra gấp đôi số lượng tên lửa. Các tên lửa phụ được tạo ra gây sát thương ít hơn <b>50%</b>.",
    [713841793] = "Phần đệm vai trên Áo Giáp Tay Súng này cực kỳ sắc bén và nhọn như đầu mũi tên.",
    [714231825] = "<craftingstation>Trục Quay Tay</craftingstation>",
    [714464257] = "Nồi Đồng Đỏ",
    [714696977] = "Kế Hoạch Dự Phòng Của Tôi",
    [715159620] = "Hành Trình Khờ Khạo",
    [716239448] = "Nấm Mốc Đen Sau Tường Khô",
    [716426028] = "Một đôi quần có ống chân bằng da. Chúng không kêu lạch cạch khi di chuyển và làm giảm mọi tiếng động nhỏ khi lén lút.",
    [716593699] = "Ngọc Rạn Nứt",
    [716780855] = "Công khai",
    [716957964] = "Đừng quên những cổ vật ma thuật, người giữ Ngọn lửa... Chúng đang gọi bạn.",
    [717029934] = "Cung Hỏa Ngục",
    [717272842] = "Mũ Giáp Xuyên Dương",
    [717951322] = "Sát thương vũ khí tầm xa tăng <b>20%</b>.",
    [718960691] = "Địa điểm: Tàn Tích Đền Thờ Chìm Dưới Nước – Tọa Độ Đã Xác Nhận\nThời Gian Lặn Ước Tính: 008 Giờ, có thể nổi lên\n\n<b>Buổi Họp Trước Khi Lặn</b>\n\nThời gian: Trước hoàng hôn. Cập bến diễn ra suôn sẻ bất chấp thảm thực vật dày đặc và các mảnh vỡ rải rác bên dưới.\nĐịa điểm: Bỏ hoang, một nửa bị hồ nuốt chửng. Lý tưởng cho việc khám phá!\n\nQuan sát các thông số của tàn tích xác nhận các báo cáo trước đó. Nhiều cầu thang phủ đầy rêu hướng lên trên, về phía miệng đền thờ há hốc. Tính toàn vẹn cấu trúc là không chắc chắn. Tốt nhất chúng ta nên nhanh chóng và phá kỷ lục của chính mình!\n\nTôi chắc chắn chúng ta sẽ tìm thấy căn phòng đầu tiên như đội trước đã mô tả: ngập nước, nhiều rong rêu hơn đá, bịt kín các lối đi ngập nước phía sau. Một cơ chế hoặc câu đố đã ngăn cản họ đột nhập vào các đường hầm. Đó là nơi chúng ta đến!\n\nĐội ngũ vững chắc. Tinh thần cao. Tôi tin tưởng Edd Exley — anh ấy sắc sảo, điềm tĩnh và biết cách xử lý những không gian chật hẹp.\n\nThời gian là yếu tố then chốt. Chúng ta sẽ bắt đầu xuống tàu vào lúc bình minh. Nếu may mắn, <b>mặt trời</b> sẽ đủ cao để xuyên qua các song sắt và <b>đánh dấu các khu vực nổi lên.</b>\n\n<b>Tuy nhiên, chúng ta sẽ không bỏ qua việc chuẩn bị bữa sáng</b>. Trên đường đi đã bắt được vài con cá; chúng sẽ ổn khi được nướng!",
    [719559989] = "Hàng Rào Gỗ Nhiệt Đới Chạm Khắc Buộc Dây I",
    [719768179] = "Cúp Danh Năng Hộp Sọ I",
    [719816450] = "Mũ Nhạc Sĩ Lang Thang",
    [720321412] = "Phạm Vi Thoại Gần",
    [720874252] = "Ugh, tôi chán chết đi được! Tôi cần một anh hùng dũng cảm để cứu tôi khỏi sự nhàm chán này!",
    [721094633] = "Hàng Tồn Kho Địa Phương",
    [721988669] = "Sử dụng cây Gậy phép này để đốt cháy con đường cho đàn gia súc của bạn vượt qua vùng đất hoang giá băng và giúp chúng chinh phục những dòng suối băng giá nhất và những vách đá lởm chởm nhất.",
    [722055543] = "Hoàn hảo, bạn của tôi! Bạn luôn hoàn thành nhiệm vụ. Nếu chúng ta có thể xây dựng một Phòng Thí Nghiệm với <keyitem>Dụng Cụ Khoa Học</keyitem>, thì chúng ta có thể <b>chế tạo các vật phẩm Chữa thương</b> vượt xa mọi tưởng tượng!",
    [722175316] = "Quán Rượu \"Bình Rượu Xanh\"",
    [722564471] = "Khai thác mọi vật liệu quý giá trong Vùng Đất Cháy.",
    [722589416] = "Thợ săn <npc>Athalan Skree</npc> đã kiểm tra Lông thú. Bà tin rằng ngay cả những sinh vật khỏe mạnh cũng có thể bị ảnh hưởng bởi Sương độc, vì nó lan xa hơn mắt có thể nhìn thấy. Bà đã chia sẻ vị trí của <b>khu vực săn bắn bí mật</b> của mình và yêu cầu bạn săn thay cho bà.",
    [723135905] = "Đũa Phép",
    [723147940] = "Găng Tay Thuật Sĩ",
    [723270364] = "Một màn trình diễn kỳ lạ về lực giãn nở của hơi nước. Các trường hợp sử dụng không rõ ràng lắm... hay là có?",
    [723301547] = "Cúp Danh Năng Quái Vật Sa Ngã Bằng Vàng",
    [723357053] = "Ám khí",
    [723637513] = "Ugh, tôi khát nước! Cổ họng tôi khô như đã mấy năm trời... Nhân danh <lorename>Pikemead</lorename>, tôi đã quên giới thiệu bản thân với vị cứu tinh của mình. Tôi là Ramone Jones, biên tập viên của \"The Pike Weekly\". Có lẽ bạn đã đọc tác phẩm của tôi?",
    [723643929] = "Chiến đấu",
    [724124143] = "Một Thế Giới Kỳ Diệu Của Kiến Trúc Bị Lãng Quên!",
    [724141670] = "Len",
    [724185351] = "Rau Nghiền",
    [724243188] = "Máy Chém",
    [724915996] = "Tìm Tờ Nhạc Thứ Tư",
    [725466433] = "Rương Gỗ",
    [725623869] = "Cánh Đồng Nghệ Tây",
    [725835376] = "Phóng To",
    [725947799] = "Một chiếc búa gỗ được chạm khắc tinh xảo và truyền thống do các thợ thủ công Vukah chế tạo. Trông giống như một chiếc răng lớn và rất hiệu quả trong việc loại bỏ chúng.",
    [726868752] = "Một mảnh giáp ngực chắc chắn, được trang trí bằng bộ lông của một con sói trắng. Màu sắc hòa quyện tốt với những ngọn núi phủ đầy tuyết, màu xám.",
    [726908428] = "Áo Giáp Mắt Đại Bàng",
    [727214976] = "Thay Đổi Khu Vực Điều Khiển Cuộn",
    [727997362] = "Khôi phục Thời gian trong Sương độc",
    [728015242] = "Răng Drak",
    [728137033] = "Chậu Địa Lan Trống",
    [728416469] = "Người Chữa Trị",
    [728551876] = "Găng Tay Nhà Thám Hiểm",
    [728757302] = "Đến Tháp Cổ",
    [728933486] = "Tôi cá là bạn không thể ngừng ăn cá nướng bây giờ.",
    [730291607] = "Thay Đổi Vật Liệu Xây Dựng",
    [730571181] = "Về Sự Biến Mất Của Nước",
    [730758641] = "Đền Thờ Ngọn lửa",
    [730810354] = "Một phần của bộ Giáp Phù Thủy.",
    [731430755] = "Không tìm thấy máy chủ",
    [732205786] = "Tiếp tục tìm kiếm tàn tích ma thuật của gã điên đó.",
    [732303995] = "Mặc định",
    [732814609] = "<location>Shorewatch</location>",
    [732928795] = "Bảo mật",
    [733256009] = "Đang tải...",
    [733506126] = "Ngôi Đền Lãng Quên",
    [733935507] = "Mũ Kẻ Gọi Thủy Triều",
    [734201088] = "Một bộ xương sườn Cyclops ấm cúng với đủ chỗ cho bạn và người bạn thân nhất của bạn cuộn tròn trong đó.\n\nBộ sưu tập này được tìm thấy ở Đỉnh Albaneve. Nó có thể được lắp ráp lại để tạo thành một Bộ Xương Cyclops trên Đế Tượng Cyclops.",
    [735011665] = "Nền Tảng Thô Sơ",
    [735228633] = "Bình Thuốc SP Lớn Hơn",
    [735970483] = "Đến Thang Máy Vận Chuyển",
    [736410293] = "Gỗ",
    [736570049] = "Mẫu Cúp Dọn Dẹp Mẫu Hệ Bằng Vàng",
    [736724578] = "Chiến Đấu Tổng Quát",
    [737170231] = "Sẵn Sàng Kích Hoạt",
    [737563000] = "Hồi Phục HP",
    [737661862] = "Đừng làm việc quá sức!",
    [737787321] = "Các khúc gỗ cọ vừa đốn hạ, sẵn sàng để chế biến thành vật phẩm tùy chọn.",
    [738817916] = "Đường",
    [739381763] = "Bộ Sát Thủ",
    [740145993] = "MP",
    [740592460] = "Tiếp Cận Đền Drak",
    [740973770] = "ngày,giờ,phút,giây",
    [741025706] = "Biến đi!",
    [741125039] = "Các báo cáo từ dưới lòng <location>Pháo đài Kelvin</location> là sự thật! Những sinh vật chưa từng thấy đang đào bới ở đây và trở thành mối đe dọa cho sự sinh tồn của chúng ta! Chúng đào lên trên, làm rung chuyển mặt đất... Chúng ta có nên bỏ vị trí của mình để chạy ra vùng hoang dã mờ mịt bên ngoài tường thành — hay đứng lên chiến đấu với những sinh vật đang trồi lên từ lòng đất?\n\nChúng ta phải giữ nơi này an toàn! Sau tất cả, <location>Pháo đài Kelvin</location> là nơi ẩn náu cuối cùng của chúng ta!",
    [741221070] = "Vùng Đất Mờ Mịt",
    [741454084] = "Đọc Tháp Obelisk Cao Nguyên Du Mục",
    [741534611] = "Hàng Rào Cọc Gỗ Thấp II",
    [742032861] = "Mật Ong Cay Đắng",
    [742045324] = "Tăng ST Cắt ",
    [742127427] = "Ô Kỹ Năng Hành Động 8",
    [742444916] = "Tôi từng sống ở <location><lorename>Thung Lũng Pikemead</lorename></location>, giống như bao người khác... Tôi có một cảm giác tồi tệ về nơi đó. Tôi nghĩ có điều gì đó khủng khiếp đang xảy ra ở đó bây giờ.",
    [742515992] = "Chớp nhoáng trong chớp mắt, những con dao găm này có thể cắt cổ bất kỳ ai một cách nhanh chóng và lặng lẽ.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [743052459] = "Ở đâu có lửa, ở đó có hy vọng.",
    [743339767] = "Bánh Dâu Tây",
    [743812820] = "Tạo ra một tia sáng, đủ sáng để đẩy lùi kẻ địch xung quanh người niệm phép.\n\nTăng <i>thanh choáng</i> của kẻ địch Sương độc dựa trên chỉ số trí tuệ của bạn.",
    [744017469] = "Twitch Drops",
    [744627539] = "Cải tạo cảnh quan",
    [745510175] = "Nước là nguồn sinh lực tuyệt vời. Uống nó để tăng cường SP và phục hồi nhanh hơn.",
    [745732325] = "Một phép thuật vĩnh cửu giải phóng một tia sét mạnh mẽ làm sốc kẻ địch và lan sang những kẻ khác ở gần, gây thêm <b>sát thương SP.</b>\n\nSát thương SP làm đầy <b>thanh choáng</b> của kẻ địch.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng một cây <b>gậy phép.</b>",
    [746530535] = "Một bông hoa màu xanh lá cây chỉ mọc ở những nơi sâu nhất của Sương độc. Một nguyên liệu hiếm mà chỉ những chiến binh mạnh mẽ nhất mới có thể nhìn thấy.",
    [746694746] = "Một chiếc áo vest thoáng khí mặc bên ngoài áo sơ mi dài. Khóa thắt lưng bổ sung đeo chéo ngực giữ một vài lưỡi dao dự phòng.",
    [746696323] = "Thu thập tài nguyên có <b>10%</b> cơ hội nhận thêm một tài nguyên.",
    [746880177] = "Nhận <craftingstation>Trạm thuộc da</craftingstation> Từ <location><lorename>Hang Lupa</lorename></location>",
    [746935889] = "Mõm Sói",
    [747564750] = "Một nơi làm việc cho <npc>Thợ mộc</npc> thực hiện công việc xây đá.",
    [747679342] = "Đã khám phá địa điểm",
    [748681342] = "Một chất hóa học nguy hiểm được sử dụng để sản xuất chất nổ. Tốt hơn hết là nên cẩn thận!",
    [748995641] = "Một loại trái cây ngọt ngào mọc ở những vùng khô hạn, cần ít nước. Mặc dù vậy, nó khá sảng khoái!",
    [749592866] = "Trò Chơi Vĩ Đại Nhất",
    [749934487] = "Một vật phẩm trung tâm cho <craftingstation>Trạm giả kim</craftingstation>.",
    [750659901] = "Ghế Dài Thô Sơ",
    [750706951] = "Xé toạc",
    [750946250] = "Xóa Dấu Mốc",
    [751019618] = "Những chiếc vòng tay bất đối xứng giúp người xem phân biệt rõ ràng chuyển động tay của bạn khi bạn lao qua họ về đích.",
    [751451254] = "Mảnh Khảm Ngọn Lửa V",
    [751585901] = "Nguyên liệu",
    [751616716] = "Găng Tay Nhà Thám Hiểm",
    [751862054] = "Mang Viên Ngọc Lycanthropy Đến Trợ Lý Thu Thập",
    [752078674] = "Thật là một kẻ may mắn!",
    [752270399] = "Lớp Đệm Ấm",
    [754053094] = "<craftingstation>Trạm thuộc da</craftingstation>",
    [754582677] = "Tìm Rương của <lorename>Người Du Hành Bí Ẩn</lorename>",
    [754794286] = "Hoàn thành",
    [754923965] = "Cảnh quan",
    [756000996] = "Cháu luôn là đứa cháu trai ta yêu quý nhất — trẻ trung và nhanh nhẹn! Otto, xương cốt già nua của ta kêu răng rắc. Ta hầu như không thể chăm sóc <b>Thảo Nguyên Xanh Tươi</b> nữa rồi... thật đáng tiếc! Những cánh đồng trải dài, chín mọng và bội thu! Hoàn hảo cho một chàng trai trẻ như cháu.\n\nTa sẽ giao lại ngôi nhà yên bình này vào bàn tay chăm sóc của cháu!",
    [756165741] = "Thang Gỗ",
    [756307459] = "Ớt Chuông",
    [756382949] = "Cửa Bí Mật",
    [756702991] = "Bạn đã tìm thấy một <craftingstation>Nồi Hầm Cũ</craftingstation>. Sử dụng nó để chế tạo một <craftingstation>Trạm Giả Kim</craftingstation> và đặt nó trong căn cứ của bạn để mở khóa nhiều khả năng chế tạo hơn.",
    [757037723] = "Tìm Trợ Lý Thu Thập",
    [757428723] = "Giác Quan Thợ Săn",
    [757870210] = "Tăng ST Kết liễu ",
    [757923124] = "Vũ khí được lựa chọn bởi kẻ lừa dối.",
    [757982335] = "Khi bạn đọc được những dòng này, tôi đã trốn đi dưới màn đêm.\n\nTôi sẽ không bao giờ là người con gái cha muốn. Ngoan ngoãn, im lặng và nhàm chán... Tôi không còn lời xin lỗi nào để đưa ra nữa. Tôi sinh ra để làm những điều vĩ đại hơn! Phiêu lưu! Để mọi người gọi tên tôi! Tôi muốn trở thành nhiều hơn là \"Eryn cô gái nông dân\". Cha sẽ nghe tin về tôi lần nữa! Một ánh sáng rực rỡ trên bầu trời đêm! <i>Khi tôi ôm chặt lấy thứ gì đó có giá trị — thứ gì đó đặc biệt, đẹp đẽ như sương mai —... tôi sẽ không buông ra!</i>\n\n— Eryn",
    [758297709] = "Giáp Đầu",
    [758586620] = "Chúng ta có rất nhiều khuôn mặt ở đây bây giờ. Làm tôi cảm thấy như ở nhà — tôi có 7 dì, bạn biết đấy? Dì Braelyn là người tôi thích nhất. Bà ấy thường gửi cho tôi những bản phác thảo kiến trúc đẹp nhất về các ngôi đền, cầu và tháp từ những chuyến đi của bà ấy! Một ngày nọ, bà ấy đến Blackmire khi tôi còn nhỏ, ý tôi là, rất nhỏ, và không bao giờ trở về... Bà ấy nên quay lại giúp đỡ! Tôi có 7 dì, rất nhiều việc, và chỉ có một tay, sau tất cả! Ha!",
    [758616907] = "Bùa Hộ Mệnh Chữa thương",
    [758700778] = "Chặt",
    [759330687] = "Một bản nhạc cho bài hát để chơi bên lò sưởi trong khi kể những câu chuyện phiêu lưu.\n\n<b>Bản Nhạc:</b> \nBản nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ bản nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát.",
    [759345312] = "Cõi Siêu Nhiên",
    [759354232] = "Hoa Thạch Nam",
    [759458468] = "Khối Cẩm Thạch Đỏ",
    [759520611] = "Xây Dựng <craftingstation>Bàn Thợ</craftingstation>",
    [759608383] = "Nhận Nhẫn",
    [759627390] = "Nơi Trú Ẩn",
    [759781903] = "Thợ Rèn tò mò về vùng Cao Nguyên Albaneve. Phương Bắc từng mở rộng đến đó để xây dựng thêm Giếng Thuốc và chế tạo vũ khí từ vật liệu địa phương để bảo vệ họ. Những vật liệu này chỉ có thể được nấu chảy bằng nhiệt lượng tỏa ra từ một lò rèn phù hợp.\n\n<b>Tìm lò rèn</b> và chiếm lấy nguồn nhiệt của nó! Điều này sẽ cho phép bạn chế tạo một lò cao.",
    [759808415] = "Một <b>mũi tên đặc biệt</b> mang đến một bất ngờ bùng nổ. Tấn công với sức mạnh hỏa lực được cải thiện.",
    [760777128] = "Tìm Người Sống Sót Đang Ngủ",
    [760815282] = "Đôi ủng nặng nề với mũi kim loại, hoàn hảo để đá tung cửa hoặc nghiền nát sọ dưới gót chân của bạn.",
    [761086081] = "Chúng tôi bị kẹt trong một cơn bão tuyết trên đường đến ngọn tháp. Tôi đã vượt qua những cơn gió gào thét, bị ám ảnh bởi mục tiêu của mình, nhưng khi tôi quay lại để kéo người trợ lý mới của mình, khuôn mặt hồng hào của cô ấy đã biến mất sau những đốm trắng.\n\n<i>\"Fran!\"</i> Tôi hét lên. Câu trả lời của cô ấy vang vọng, nghe như cách xa hàng dặm. Rồi, một tiếng kêu kinh hoàng làm tôi run rẩy đến tận xương tủy. Tôi lao về phía cô ấy, xuyên qua màn tuyết. Khi cuối cùng tôi nhìn thấy cô ấy một lần nữa, cô ấy đang co rúm người dưới một con kền kền ẩn mình trong cơn gió xoáy.\nTôi thấy những ngón tay lạnh cóng của mình quấn quanh một tảng đá và ném nó hết sức có thể. Con kền kền rơi xuống, mất phương hướng, và tôi giẫm đạp lên nó cho đến khi cảm thấy hộp sọ của nó vỡ vụn. Rồi, tôi đông cứng lại.\nTôi nghĩ Fran đã nói gì đó với tôi khi cô ấy lấy một mẫu xương, vội vàng quệt tay lên cánh của nó, nhưng tôi không nghe thấy gì. Tôi nhìn vào khuôn mặt cô ấy và thấy má cô ấy đỏ bừng chảy máu, bị cào xé bởi móng vuốt. <i>\"Cô ấy sẽ không bao giờ như xưa nữa,\"</i> tôi nghĩ. <i>\"Và tôi cũng vậy.\"</i> \n\n— <lorename>Loraine Crim</lorename>",
    [761127869] = "Rothstep",
    [761438801] = "Bộ pháp là kỹ năng quan trọng nhất của kiếm thuật. Những đôi ủng này sẽ giúp việc học những bước đi đầu tiên dễ dàng hơn.",
    [761469919] = "Địa Điểm Sản Xuất Thuốc Tiên",
    [761567837] = "Phục Kích",
    [761637056] = "Cùng với nó đến là sức mạnh, sự nghi ngờ và nỗi khao khát nhiều hơn.",
    [761744424] = "Thức ăn chim bổ dưỡng cho động vật thuần hóa trong trang trại của bạn. Nó có thể được cho cả Chim Đuôi Đỏ Không Bay và Chim Sẻp Mỏ Tròn.\n\nNó phải được đặt vào máng ăn phù hợp.",
    [761876830] = "(Điểm Dẫn Đường)",
    [762033214] = "Bột Than",
    [762199016] = "Hũ Gốm",
    [762599928] = "Quần da với vân rõ rệt biến thành các sợi nấm mịn.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [762926061] = "Sẵn sàng để chế tạo:",
    [762961274] = "Phần Cuối Đỉnh Mái Thẳng",
    [763080379] = "Đi Qua Lối Đi Sông Veilwater",
    [763421096] = "Đá Người Chơi & Cấm",
    [763802120] = "Ghế Dài Đá",
    [764383150] = "Cái <craftingstation>Cối Giã</craftingstation> đáng tin cậy của tôi đã bị mất. Tôi nghi ngờ nó nằm trong <b>tháp của tôi ở <location>Lone Thistle</location>, ở những tầng sâu nhất. </b>... Xin hãy tìm nó giúp tôi. Khả năng của tôi sẽ lớn hơn nhiều khi có nó trong tay!",
    [764741146] = "Đường Ván Lưu Vực Vực Nước II",
    [765229771] = "<location>Midhollow</location>",
    [765415468] = "Hỏa Sinh",
    [765533725] = "Giày Thuật Sĩ Hắc Ám",
    [765770559] = "Bạn đã tìm thấy tất cả các mảnh ghép của bức tượng <lorename>Pikemead</lorename>.\nBạn có thể lắp ráp lại các mảnh ghép bằng cách sử dụng một tủ trưng bày tượng.\n\nHoàn thành bộ sưu tập sẽ mở khóa các công thức chế tạo mới!",
    [765787553] = "Athalan Skree",
    [766330407] = "Dra'Nak chết với danh dự. \nVì vậy móng vuốt, vảy, máu của hắn — chúng đi vào bùa hộ mệnh. \nCách cũ của Drak. Luôn luôn như vậy. \nChúng ta giữ những kẻ mạnh ở gần — ngay cả khi hơi thở đã tắt. Hắn đứng cùng chúng ta, canh gác. \nDrak tự hào trở thành bùa hộ mệnh. Thủ lĩnh Drak'Dal sẽ là Bùa Gỗ, Hydrak'Dal Bùa Đá.\nNghĩa là họ sẽ gia nhập Dalszul ở thế giới bên kia. \nNhưng nếu chết trong hổ thẹn... không vàng, không tên... không thế giới bên kia... chỉ bị lãng quên.",
    [766488996] = "Vách Ngăn Phòng \"Rắn\"",
    [766607885] = "Chúng ta đã nghe thấy chúng đêm qua! Không phải là do tôi tưởng tượng đâu... những dòng chữ, những bộ xương— Vukah đang quay trở lại từ vực sâu hang động của chúng! Chúng ta phải rời bỏ địa điểm khai quật của mình... nơi này ngày càng nguy hiểm... <i>Chúng ta sẽ bỏ lại tất cả các di vật.</i> \nTôi không muốn chọc giận chúng! \n\n— <lorename>Loraine Crim</lorename>",
    [766644192] = "Bạn đã không quên về dì <lorename>Elin</lorename> của tôi và câu chuyện của bà ấy, phải không? Có điều gì đó tồi tệ đang xảy ra ở Đền Thờ Mặt Trời Ma Ám!",
    [766751997] = "Gương Tiệm Salon Nhỏ",
    [767200957] = "Sự bảo vệ đơn giản nhưng đáng tin cậy cho đôi tay.",
    [767297282] = "Ứng dụng Steam của bạn chưa được chạy!",
    [767897347] = "Thu thập Cổ vật Ma thuật",
    [769186014] = "Ngọn Lửa đã giao cho ngươi nhiệm vụ tiêu diệt con quái vật bị tha hóa ẩn náu bên trong Đỉnh Núi U Hồn. \n\nChiến thắng sinh vật này sẽ mang lại hòa bình cho vùng đất và mở khóa một <b>nâng cấp Ngọn Lửa</b> mới, cho phép các Bệ Thờ Lửa <b>giữ cho cái lạnh không thể tiếp cận khi xây dựng.</b> \nĐể đánh thức và lôi con quái vật ra, ngươi phải <b>thắp sáng những ngọn lửa hiệu triệu (\"Lửa Hận Thù\")</b> bao quanh ngọn núi sâu nhất. \n\n<b>Ngọn lửa hiệu đầu tiên đã được đánh dấu trên bản đồ của ngươi.</b> Hãy đến địa điểm đó để tiếp tục!",
    [769198734] = "Bắt đầu Lặn",
    [769381700] = "Dụng cụ Xây dựng",
    [769522705] = "Găng Tay Thợ Tiều Phu",
    [769765658] = "Cây Mã Đề",
    [770293934] = "Cúp Danh Năng Khổng Lồ Khô Cốt Bằng Vàng",
    [770667400] = "Gỗ Rương Gian lận",
    [771175330] = "Một cối xay có thể dùng để nghiền vật liệu thành bột mịn.\n\nCối xay này <b>chỉ hoạt động khi có máy phát lực</b> ở gần. Cánh buồm cối xay gió hoặc bánh xe nước đặt một phần dưới nước đều được tính là máy phát lực. \n\n<b>Máy phát lực</b> không nhất thiết phải kết nối với cối xay; nó <b>có thể được đặt tự do ở gần.</b>",
    [771186319] = "Mũi Tên Đá Lửa",
    [771189543] = "Nâng cấp Vũ khí",
    [771233239] = "Rau Xào",
    [771501552] = "Khi nằm trong tay những kẻ thiện nghệ, cây cung có sừng này có thể bắn ra một phát đạn mạnh đến mức có thể gây ra tuyết lở, và chôn vùi thung lũng trong tuyết vĩnh cửu.",
    [771782680] = "Lặn đầu tiên",
    [772783663] = "Tìm và thắp sáng tất cả Lửa Hận Thù",
    [772986945] = "Một con bọ hung vàng. Nó có thể được tìm thấy ở Vùng Đất Nhen Nhóm, và được dùng làm mồi câu cá, đặc biệt hữu ích để bắt cá hiếm.",
    [772996969] = "Ngôn ngữ Hệ thống",
    [773199352] = "Chỉ riêng cái đầu của nó đã nặng một cách khủng khiếp. Những chiếc vảy lấp lánh lạnh như băng.\n\nThu thập nhiều Đầu Rồng Con non Fell để chế tạo Cúp.",
    [774460662] = "Chọn một Công thức",
    [775141737] = "Mở cửa trong Sảnh Hollow Revelwood.",
    [775577569] = "Đền Drak'Dal",
    [775705527] = "Tiện nghi - Thẩm mỹ",
    [778183897] = "Tạo",
    [778298459] = "Vị trí Mỏ Muối",
    [778401293] = "Một mảnh nhỏ của bức tranh khảm Ngọn Lửa bị vỡ. Có lẽ ngươi có thể ghép lại nếu tìm thấy tất cả các mảnh!\n\nBộ sưu tập này được tìm thấy ở Đỉnh Albaneve. Bộ sưu tập đầy đủ bao gồm 8 mảnh. Chúng có thể được ghép lại thành một bức tranh khảm bên trong Khung Tranh Khảm Ngọn Lửa. Khung phải được đặt trên mặt đất.",
    [778653318] = "%k mục đã hoàn thành.",
    [778781752] = "Ánh sáng Tinh linh",
    [779042939] = "Ngươi đã phát hiện ra rằng <b>bảng màu</b> trong trại buôn lậu <b>được cất giữ ở trên cao và xa mặt đất.</b>\n\nTìm kiếm bảng màu ở độ cao lớn hơn!",
    [779584848] = "Tinh chất Sự sống",
    [780941781] = "Ngươi đã tìm thấy dấu hiệu của Athalan Skree khi đi qua Rừng Rậm Revelwood. Chắc hẳn cô ta có một trại gần đây. Khám phá trại của <npc>Thợ săn</npc> và nhìn xung quanh!",
    [781254016] = "Trầm Tích",
    [781395781] = "Thành lũy của <lorename>Pikemead</lorename>",
    [781432773] = "Một bánh xe nước lớn. Nó có thể được đặt dưới nước để tạo lực cho cối xay.\n\n<b>Phải đặt gần cối xay.</b>",
    [781554633] = "Bạn khỏe chứ?",
    [782138017] = "Khổng lồ, chắc chắn và lạnh thấu xương.",
    [782750303] = "Một bức phù điêu kể về lịch sử của Drak.\n\nNhững con thú đứng chiến thắng, sự thống trị của chúng không thể tranh cãi. Chúng bị khóa trong một cuộc chiến không ngừng để giành quyền lãnh đạo, đổ máu trong một nỗ lực tuyệt vọng để giành được sự ưu ái của Cổ nhân và trở thành thần thánh ở thế giới bên kia.",
    [782774422] = "Tìm chiếc \"Rìu Sát Long\"",
    [782785803] = "Củng cố",
    [782818332] = "Lò Rèn",
    [783911534] = "ST Xuyên Tầm bắn ",
    [784078518] = "Gửi Shortstack",
    [784489932] = "Một bông hoa huệ tây màu cam. Những cánh hoa rực rỡ đủ để dùng làm thuốc nhuộm.",
    [785350582] = "Bộ Giáp Học Giả Thiên Giới",
    [785813456] = "Ta đã sống lâu lắm rồi, nhóc. Chẳng còn gì làm ta sợ nữa, và <npc>Người sưu tầm</npc> cũng không ngoại lệ. Một đồng minh mạnh mẽ, bất kể bí mật của họ là gì. Tất cả những lời nói về bức màn, về sự sống và cái chết... Liệu họ có thể mang ai đó trở về từ cõi âm? Ta sẽ trả bất cứ giá nào...",
    [786049551] = "Tiền đồn Thương mại \"Đá rực lửa\"",
    [786451566] = "Chỉ định %k",
    [787216754] = "Đỡ đòn bằng khiên có 20% cơ hội tăng thời gian choáng.",
    [787361553] = "Hoan hô, màu tóc mới! Ôi trời, cuối cùng cuộc sống cũng đáng sống trở lại!",
    [787392050] = "Sẵn sàng chiến đấu",
    [787896188] = "Chi phí nâng cấp vũ khí",
    [787994534] = "Rất vui được gặp",
    [788548171] = "Cúp Danh Năng Rồng Con Sa Ngã",
    [788620763] = "Một chiếc búa lớn, được làm từ sự kết hợp giữa đá và thép. Sự pha trộn vật liệu làm cho nó đặc biệt nặng.",
    [789023988] = "Tiếng Vang Tĩnh Lặng",
    [789040113] = "https://store.steampowered.com/app/1203620/Sương độc bao phủ/",
    [789057659] = "Ta đã làm việc không ngừng nghỉ quá lâu... Ta là người cuối cùng ở lại và cố gắng níu giữ bất cứ thứ gì... \n\nÔng nội thân mến, con đã ngu ngốc. Con không thể cứu lấy ngôi nhà mà ông đã xây dựng bằng chính đôi tay mình... Khói từ con sông làm đá giòn tan... xương cốt ta mục rữa. Một nỗi buồn sâu sắc đã len lỏi vào trong ta... Nó bám vào xương sống, co giật trong lồng ngực ta... \n\nTa phải ngồi... nghỉ ngơi... chỉ một chút thôi.",
    [789402433] = "Quần Xạ Thủ",
    [789585025] = "Amelie Reyk",
    [790014259] = "Quần Bò Tót Đồng",
    [790801464] = "Khiên Dũng Cảm",
    [791284669] = "Chứa nồng độ Sương độc cao hơn so với các Hạt Sương độc.",
    [791660198] = "Khe Xây dựng Hình dạng 10",
    [791894689] = "Vua của ngọn núi",
    [791986946] = "Đàn Luýt Tinh Xảo",
    [792077597] = "Quần Lính Canh Phương Bắc",
    [792845338] = "Giáp Thân Áo Da",
    [792945420] = "Bay",
    [793428882] = "Đổi chỗ",
    [793577216] = "Chuột xuống",
    [793960580] = "Cửa Kệ Sách Bí Mật",
    [794244259] = "Chỉ vậy thôi sao?",
    [794256892] = "Con đường của trinh sát trở nên dễ dàng hơn một chút trên đôi giày im lặng.",
    [794818564] = "Đặt lại Thiết lập sẵn",
    [794969812] = "Vách Ngăn Phòng II",
    [795335834] = "Một mái nhà thoáng đãng làm từ vật liệu tự nhiên. Nó khiến bạn muốn đi nghỉ mát ở vùng nhiệt đới.",
    [795770250] = "Thảm sát bất ngờ",
    [795865351] = "Không yên ổn cho cái đầu đội vương miện.",
    [796384057] = "Len thô. Nó mềm mại, dễ bị rối và có mùi hơi đất. Nó cần được xử lý thêm để sử dụng làm quần áo và giáp.",
    [796614761] = "Cửa Đôi Gỗ Chạm Khắc",
    [796756171] = "Mở rộng Ba lô",
    [796823625] = "Aye, nhóc con! Ta thấy ngươi đang câu cá. Câu cá thì tốt đấy, nhưng đôi khi, việc móc được một kho báu cũng thú vị lắm phải không? Khiến ngươi cảm thấy như một tên cướp biển, đào vàng! Chà, nếu ngươi muốn có thêm cảm giác đó, ta biết vị trí của một kho báu cũ của thủy thủ. Để ta chỉ cho ngươi...",
    [796881724] = "Hố hiến tế Vukah",
    [797056666] = "Bạn đã đến lò rèn, nhưng nó đang bị tràn ngập bởi Scavenger đang bảo vệ thiết bị của chúng. Hãy đến trung tâm của lò rèn và đánh bại kẻ địch ở đó!",
    [797231188] = "Cảm ơn bạn đã chơi bản demo Sương độc bao phủ!",
    [798106055] = "Đặc biệt",
    [798124216] = "Yêu cầu nâng cấp:",
    [798845409] = "Trọng Kiếm Ganh Đua",
    [799320233] = "Phần này chứa các Nhiệm vụ Embervale đã hoàn thành. \nBạn có thể chơi lại chúng để trải nghiệm cốt truyện một mình và nhận phần thưởng mà các nhiệm vụ này mang lại.\n\nKích hoạt một Nhiệm vụ Embervale bị bỏ lỡ sẽ tạm thời đặt lại mục tiêu nhiệm vụ và các điểm đánh dấu bản đồ của bạn về trạng thái kiến thức cá nhân. \nKích hoạt Nhiệm vụ Embervale bị bỏ lỡ hoặc hủy kích hoạt Nhiệm vụ Embervale bị bỏ lỡ để quay lại trạng thái kiến thức của máy chủ.\n\n<b>Nếu không có nhiệm vụ bị bỏ lỡ nào khả dụng, bạn đã bắt kịp</b> tiến trình nhiệm vụ của máy chủ. <b>Kích hoạt Nhiệm vụ Embervale thông thường</b> để chuyển lại về trạng thái kiến thức của máy chủ hoặc <b>thực hiện Nhiệm vụ Hóa thân Lửa</b> để tiếp tục.",
    [799468018] = "Một chiếc áo tunic nhẹ, uy nghi như sức mạnh mà nó ban tặng khi bạn dang rộng hai tay.",
    [799555829] = "Hoa Cúc Chamomile",
    [799562366] = "Thời gian cần thiết để bắn cung giảm 50%",
    [799922778] = "Tìm vật liệu ở đâu?",
    [800065601] = "Thực vật nhổ nước bọt",
    [800326856] = "Đá cối xay",
    [800655078] = "Khám phá",
    [800761369] = "Lùi lại một chút.\nLặp lại quá trình cho đến khi động vật hoàn toàn tin tưởng bạn.",
    [801178415] = "Thỏ Nhảy",
    [801218620] = "Gắn nó vào trong sảnh của bạn để tôn vinh Ngọn lửa!\n\nThu thập nhiều Đầu Sấm Sét Fell để chế tạo Cúp.",
    [802696974] = "Di chuyển Camera Khi Không Hoạt Động",
    [803213515] = "Hào Quang Nước",
    [803504262] = "Được sửa đổi để tăng khả năng kiểm soát MP, cây đũa phép này bắn ra các viên đạn băng với lực mạnh hơn một chút.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương bổ sung lên đến phần trăm <i>quá tải</i>.",
    [803998943] = "%k đã tham gia.",
    [804352371] = "Những Vị Khách Say Xỉn Và Những Khoản Thanh Toán Kỳ Lạ",
    [804672854] = "Chiếc nhẫn này sẽ tăng MP và khả năng hồi phục của bạn. ",
    [804826439] = "Giải phóng một quả cầu lửa mang đến một bất ngờ bùng nổ.\n\n<b>Phép Thuật: Tiêu Hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng một <b>cây Gậy phép.</b>",
    [805073159] = "Cảm ơn.",
    [805545764] = "Triệu hồi những tảng băng lạnh lẽo giáng xuống kẻ thù của ngươi.\n\n<b>Phép Thuật: Tiêu Hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng một <b>cây Gậy phép.</b>",
    [805807980] = "Trái Đất Rung Chuyển",
    [805860488] = "Bí Ngô Đêm Khô Cốt Nhỏ I",
    [806347250] = "Hành Động",
    [807030369] = "Obsidian dễ dàng vỡ ra thành những cạnh sắc bén. Tùy thuộc vào kích thước, mảnh vỡ có thể được sử dụng cho mục đích chế tạo hoặc tạo hình thành đầu mũi tên.",
    [807683414] = "Nhật Ký Của Người Gác Hải Đăng",
    [807973445] = "Nguyên Liệu",
    [808353937] = "Bất cứ khi nào một kẻ địch trong phạm vi 30 mét nhắm vào một đồng minh trong phạm vi 30 mét, có 30% cơ hội kẻ địch sẽ nhắm vào bạn thay thế.",
    [809024171] = "Ma-nơ-canh \"Tạo Dáng Nào\"",
    [809121498] = "Vũ Khí Cận Chiến",
    [809209352] = "Tạp Nhạp",
    [809364372] = "Một vũ khí thường được người Vukah sử dụng trong các trận chiến nghi lễ.",
    [809799057] = "Vô Hiệu Hóa",
    [810003095] = "Đòn Chí Mạng bằng Dao Găm tăng sát thương gây lên kẻ địch thêm <b>25%</b> trong <b>3</b> giây. ",
    [810005015] = "Không biết tôi đã ngủ bao lâu. Trong giấc mơ, tôi thấy những con sóng xanh mượt như nhung, trong khi những giọng nói hát ru tôi gia nhập họ dưới đáy sâu. Giấc mơ kỳ lạ. Chắc là do tôi đập đầu khi bị ngã. La hét cầu cứu. Tôi đang chết đói. Ăn giấy. Dạ dày đau. Không cảm thấy cánh tay mình.\n\n<b>Ngày thứ 5</b>\nGiọng tôi đã mất. Cổ họng cảm giác như đang đóng lại.\nCó thứ gì đó có mùi thối\nKhông thể biết đó là giấy hay lưỡi tôi\n\n<b>Ngày thứ 6</b>\nCố gắng leo ra ngoài lần nữa. Ngã. Tay phồng rộp.\nMặt trời đốt cháy tôi. Những giọng nói khóc than.\nTrong một khoảnh khắc, tôi nghĩ thang máy đang di chuyển\nĐầu tôi quay cuồng\n\n<b>Ngày</b>\nHôm nay là ngày nào\nTôi không biết\nVẫn đói\nTôi khao khát được ăn thịt\n\n<b>??</b>\nNó ở trong không khí\nBao quanh tôi\nNhững giọng nói, sự thối rữa\nKhông có lối thoát\nKhông có không khí\nTôi đang chìm mãi mãi",
    [810190744] = "Sát thương vũ khí cận chiến tăng.",
    [810580509] = "Một cây chùy sáu cạnh làm từ kim loại nặng. Đầu của vũ khí này giống như một ngôi sao.",
    [810779326] = "Bạn đã tìm thấy cả hai mảnh thảm treo tường. Bạn có thể đặt chúng vào khung ở căn cứ của mình để sửa chữa tấm thảm.\n\nHoàn thành bộ sưu tập sẽ mở khóa các công thức chế tạo mới!",
    [811588443] = "Khung Cửa Sổ Mộc Mạc",
    [811716485] = "Việc thay đổi cài đặt trong khi chơi hiện đang bị vô hiệu hóa.\nVui lòng thay đổi cài đặt trong menu chính.",
    [811802919] = "Nơi An Nghỉ Cuối Cùng Của Amber",
    [811849405] = "Một lọ thuốc MP được pha chế chính xác, ngay lập tức phục hồi một lượng lớn MP khi sử dụng.",
    [812088611] = "Bàn Thờ Ngọn lửa",
    [812759707] = "Trứng Luộc",
    [812791305] = "Quần Quân Vương U Ám",
    [813221057] = "Họ che giấu nỗi kinh hoàng của mình bằng nước hoa nồng nặc, hầu như không che giấu được mùi mồ hôi khó chịu bên dưới. Không ai tiết lộ lý do. Chỉ có một bà lão, với mái tóc bạc rơi lơ đãng trên khuôn mặt hiền lành, dám gọi tên điều mà tất cả họ đều sợ hãi.\n\nMột \"cơn rung chuyển trong lòng đất\" mà họ cảm nhận vào ban đêm khiến họ không ngủ được. Họ đã báo cáo điều này với <location><lorename>Pikemead</lorename>'s Reach</location> nhưng không có kết quả. Là một người con của thủ đô vinh quang, tôi thừa nhận rằng tôi cũng chưa bao giờ nghe câu chuyện này. Thừa nhận nó vượt ra ngoài một báo cáo sẽ khắc sâu nỗi sợ hãi của họ vào đá, vì vậy hầu hết mọi người đều chọn cách im lặng.\nTrong giấc ngủ sâu của mình, những âm thanh đáng lo ngại không đến được với tôi - tuy nhiên, tôi vẫn bồn chồn. Ánh sáng từ giấc mơ của tôi rực cháy hơn ở đây.\n\nTôi đã đóng cửa hàng thẩm mỹ trong vài ngày để phục hồi và dành thời gian pha trộn các loại bột màu. Thuốc nhuộm đỏ mà tôi đã pha chế lấp lánh dưới ánh mặt trời như máu tươi. Tôi hy vọng đó không phải là điềm xấu. Liệu các vì sao có gọi tôi đến đây để chịu đựng một cuộc tàn sát khác theo ý thích của chúng không?",
    [813576914] = "Thường xuyên",
    [814340633] = "Mặt đất vững chắc dưới chân? Bầu trời quang đãng phía trên? Không có tiếng rít và tiếng quạ kêu? Ác quỷ nào đã đưa ta đến đây?",
    [814658355] = "Cúp Danh Năng Khổng Lồ Khô Cốt Bằng Sắt",
    [814667020] = "Những con chim xanh không còn bay lơ đãng trong không trung một cách vô tư. Có điều gì đó đang thay đổi.\n\nMột tinh vân đang chảy về phía chúng ta, trào dâng từ vực thẳm như một cơn sóng thần. Họ gọi nó là <i>Sương độc</i>. Nó mang theo bệnh tật và đau khổ, thay đổi đất đai và con người. Tôi phải hiểu sự điên rồ này, nhưng việc tìm ra phương thuốc sẽ rất khó khăn khi <i>các tuyến cung ứng bị binh lính cắt đứt.</i>\n\n— Balthazar",
    [814748464] = "Ảo Ảnh",
    [815262223] = "Người chơi của bạn sẽ có trải nghiệm dưới mức trung bình.",
    [815420165] = "Một món súp rất bổ dưỡng được làm bằng cách luộc gà trong một khoảng thời gian. Món ăn của một bà lão giúp bảo vệ cơ thể khỏi bệnh tật.",
    [815506144] = "Vị trí bên dưới",
    [815566871] = "Bạn đã lần theo dấu vết của những tên cướp đã cướp bóc của Mei. Cuộc điều tra của bạn đã dẫn bạn đến một bức thư tiết lộ địa điểm được cho là của mỗi vũ khí bị đánh cắp.\n\nThanh kiếm Tết Nguyên Đán dự kiến sẽ được trao cho một người mua ở một góc yên tĩnh của <location>Willow Crush</location>. Hãy đến địa điểm đó và tìm kiếm manh mối ở đó!",
    [815751032] = "Một chú chó năng động, vui vẻ với bộ lông màu nắng, khao khát được kết nối. Chiếc đuôi của nó chưa ngừng vẫy kể từ khi bạn giải cứu nó khỏi lồng. Những Scavenger trước đây đã nuôi chú chó này gọi nó là \"Ruffles\".",
    [816685647] = "Sức Mạnh Rồng",
    [817490139] = "Con Đường Của Chiến Binh",
    [817581046] = "Phản Hồi",
    [817688507] = "Ngay lập tức phục hồi một lượng lớn MP và liên tục bổ sung nó trong 10 giây.",
    [819175663] = "Vị <npc>Thợ Rèn</npc> yêu cầu điều tra một <b>lá thư kỳ lạ</b> mà ông ấy nhận được, ký tên bởi một người mà ông ấy không nhận ra. Bức thư được vận chuyển bởi Conways, những người đưa thư từ Cao Nguyên Du Mục. Lô hàng của họ chắc hẳn đã đi qua Trạm Giao Dịch \"Đá Rực Lửa\".\n\n<b>Giải quyết bí ẩn này sẽ cho phép bạn chế tạo áo giáp tốt hơn.</b>",
    [819445580] = "Đến The Revelwood",
    [819467280] = "Nhạc Cụ Hiếm — Đàn Lute",
    [819991886] = "Không ai có thể phủ nhận thẩm quyền của bạn khi bạn mặc bộ đồ màu trắng thánh thiện và màu hoa cà hoàng gia.\n\nBảng màu này có thể được tạo bằng vật liệu từ Đỉnh Albaneve.",
    [820595272] = "Cây Lanh",
    [820609346] = "Bạn đã đọc một ghi chú mô tả cách Draklings cần nguồn sáng ấm áp để nở và cách chúng tạo ra ánh sáng rực lửa này bằng hoa huệ.\n\n<b>Hãy quay lại gặp Thợ Mộc và nói cho ông ấy biết về những gì bạn đã phát hiện.</b>",
    [820639682] = "Giếng Nước Cải Tiến",
    [820932378] = "Gạch Nung",
    [821040784] = "PC của bạn dưới yêu cầu hệ thống tối thiểu và bạn có thể gặp sự cố hoặc trải nghiệm hiệu suất kém. Bạn có vẫn muốn tiếp tục không?",
    [821436085] = "Shadowbloom là một trong số ít loài cây có khả năng chống chịu nhiệt độ khắc nghiệt của Kindlewastes. Những cánh hoa màu cam rực rỡ của chúng chỉ có thể nhìn thấy vào ban đêm và được sử dụng để tạo ra màu sắc rực rỡ.",
    [821932357] = "Vũ khí cận chiến 1H và Dao găm có <b>20%</b> cơ hội không bị mất độ bền.",
    [822158463] = "Người ta nói rằng chủ nhân ban đầu của chiếc mũ bảo hiểm này đã đội nó để che giấu nhiều vết sẹo trên khuôn mặt. Liệu điều này có đúng hay không thì không chắc chắn.",
    [822614567] = "ST Cắt",
    [822956774] = "Lõi Chướng Khí",
    [823186136] = "Mũi tên <b>đặc biệt</b> này gây ít sát thương, nhưng đánh trúng mục tiêu với lực mạnh để tăng <i>Thanh choáng</i> của kẻ địch.\n\n<i>Tăng Thanh choáng</i> tăng theo độ khéo léo.\nThời gian choáng phụ thuộc vào kích thước của kẻ địch.\n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang phòng thủ hoặc đỡ đòn của chúng sẽ lấp đầy <i>Thanh choáng</i> của chúng cho chúng bị <b>Bị Áp Đảo</b>.\nKẻ địch <b>Bị Áp Đảo</b> sẽ mở cho các Đòn tấn công Kết liễu.",
    [823263243] = "Một kim loại dùng để tạo đồng. Nó có thể được tìm thấy ở Cao Nguyên Du Mục.",
    [823783522] = "Sự hiện diện dai dẳng của Ngọn Lửa có thể cảm nhận được mạnh mẽ trong vũ khí này. Nó lấp lánh với sức mạnh.",
    [824269283] = "%k & %k",
    [824474198] = "Tăng sát thương chí mạng lên kẻ địch bị ướt ",
    [824681424] = "Tăng tốc độ chạy nước rút của bạn.",
    [825239607] = "Giữa Những Chú Chim Xanh",
    [825391530] = "Thanh Hành Động",
    [826518631] = "Hai cối xay đá nặng dùng để nghiền nát mọi thứ. Hoàn hảo để xay bột.",
    [826582686] = "Giày Tuyết",
    [826631741] = "Sử dụng trưng bày này để lắp ráp lại bức tượng Nữ Hoàng <lorename>Pikemead</lorename>.",
    [826758840] = "Xem tài liệu tham khảo",
    [826760876] = "Đạn phép thuật tiên tiến để đốt cháy một quả cầu lửa mạnh mẽ, nổ tung khi va chạm, gây sát thương trong một khu vực trung bình.\n\n<b>Phép Thuật: Tiêu Hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng một <b>cây Gậy phép.</b>",
    [826957090] = "Sấm Sét",
    [827352437] = "Trông ngươi có vẻ ốm yếu, Hỏa Thần! Ngươi không khỏe sao? Để ta giúp ngươi!",
    [827973489] = "Những gì chúng ta làm trong đời sẽ vang vọng đến cõi vĩnh hằng.",
    [828655756] = "Đĩa Nóng",
    [829093603] = "Cây Giống Cọ Ngọc Giá",
    [829272156] = "Bạn đã tìm thấy tất cả các bản nhạc! Bạn thực sự là một nhạc sĩ đích thực, phải không?",
    [829780417] = "Một loài hoa có cánh hình ngôi sao. Nó lấp đầy các thung lũng dưới ánh trăng của Đỉnh Albaneve bằng mùi hương của cái chết.\n\nMàu sắc đen sâu của nó có thể được sử dụng để tạo ra bột màu đen như mực.",
    [829893897] = "Truyền Thuyết Về Kẻ Săn Lùng Nàng Tiên Cá",
    [830068343] = "Trống Chảo Tinh Xảo",
    [830326636] = "Một Quá Khứ Đầy Màu Sắc",
    [830583164] = "Đốt Cháy Giếng Thuốc Lạnh Nhất",
    [830675754] = "Rìu Cánh Băng",
    [831045107] = "Bất cứ lúc nào!",
    [831180328] = "Quần Kỵ Sĩ. Tấm vải đính kèm được trang trí bằng sợi chỉ vàng rực rỡ.",
    [833003914] = "Đã trang bị",
    [833038703] = "Tham gia thất bại. Phiên chơi đã đầy.",
    [833797508] = "Một Bộ Sưu Tập Khổng Lồ Bộ Xương",
    [834672918] = "Vâng",
    [834742379] = "Túi Độc",
    [835033848] = "Người giữ bí mật của Cao Nguyên Du Mục",
    [835143642] = "Một đống lửa trại nhỏ để nấu thức ăn có thể mang lại nhiều lợi ích. Đó là một nơi tuyệt vời để nghỉ ngơi và thư giãn.",
    [835572798] = "Bạn Có Thể Giúp Tìm Kiếm Không?",
    [835780923] = "Thợ Cắt Tóc muốn nhớ cách tạo ra màu nhuộm tóc xanh hoàn hảo. Ông ấy không chắc mình đang tìm kiếm điều gì nhưng nghĩ rằng mình cần một chút \"màu chàm\".\n\nCó lẽ mang cho ông ấy một <b>cây chàm</b> sẽ giúp ông ấy nhớ lại!",
    [835803322] = "Tăng cường bằng Mảnh Kim Loại để bảo vệ tốt hơn. ",
    [836595367] = "Bộ phận của Giáp Đạo Tặc.",
    [836605822] = "Đôi khi, khi những cơn gió nhiệt đới của Lưu Vực Sương Mù cuộn về phía không khí lạnh giá của núi non, một cơn bão tuyết sấm sét sẽ ra đời.\nNhững bông tuyết rơi mềm mại tiếng gầm của nó, nhưng nó để lại dấu vết trên bề mặt băng giá vừa nứt của những ao hồ đóng băng.",
    [836631681] = "Khối đã thu hồi",
    [836645936] = "Chiếu Chỉ Hoàng Gia",
    [837341968] = "<location>Thành Ngân</location>",
    [837599209] = "Ghế Dài",
    [838032705] = "Nghiền than thành bột, tạo ra một loại bột dễ cháy.",
    [838614706] = "Khiên Đội",
    [838638508] = "Bọ Hung",
    [838791535] = "Rìu 1H",
    [839272299] = "Tàn tích Đền thờ",
    [839609194] = "Tìm kiếm Trụ cầu Braelyn",
    [839891617] = "Tìm thấy trong Rừng Khải Hoàn, vào ban đêm",
    [840644486] = "Chậm hồi phục HP",
    [841560689] = "Thật là một vinh dự!",
    [841639186] = "Thuốc nhuộm đỏ ",
    [842628670] = "Bắn",
    [842979026] = "Gặt hái",
    [843063209] = "Nhà máy Chế tạo",
    [843120006] = "Thức Ăn Thỏ Nhảy",
    [843254034] = "Tiện nghi - Bồn tắm",
    [843281577] = "Kênh Hồi Máu",
    [843404167] = "Điều chỉnh lượng kinh nghiệm nhận được khi khám phá và hoàn thành nhiệm vụ.",
    [843458767] = "Ôi, ta khao khát được làm mới!",
    [843672667] = "Chúng ta phải di chuyển thôi. Thời gian không chờ đợi ai cả, phải không?",
    [843883642] = "Một vật liệu chế tạo đã được tẩm hoặc bị Sương độc chiếm lấy.",
    [844190585] = "Chìa Khóa Xương Cao Nguyên Du Mục",
    [844399889] = "Tên gọi Cá Vảy Nắng bắt nguồn từ ánh lấp lánh đặc trưng của vảy chúng, bắt lấy ánh mặt trời.\n\nLoại cá này có thể nướng hoặc dùng trong công thức nấu ăn.\nNó cũng có thể được thả lại xuống nước và nuôi trong ao.",
    [844648631] = "Người Bạn Tốt Nhất Của Con Người",
    [844832606] = "Bước Đường Cùng",
    [844889897] = "Quả Cầu Pha Lê",
    [844921048] = "Có thể sẽ có một vài trục trặc.",
    [845292075] = "Cấp độ",
    [845560032] = "Người Sống Sót Hiện tại",
    [846371023] = "Cốc Xanh Dương",
    [846744002] = "Có lẽ \"<i>Kiến trúc sư\"</i> là một thuật ngữ quá hoa mỹ — dù sao thì bản thiết kế cũng do người lữ hành cung cấp. Các kỹ sư và thợ xây chỉ việc tuân theo.\n\nCấu trúc đồ sộ này có hai phần, vươn dài về phía mặt trời lặn và về phía lõi đang ngủ say. Một vương miện Hollow tuếch ngự trị phía trên để giam giữ ánh sáng của mặt trăng đang tàn lụi. Bóng của nó đen như đá của nó.\n\nTừ bên dưới dâng lên làn sương huyền thoại. Hầu hết không nhìn thấy nó, hoặc giả vờ không thấy. Khi tôi chú ý đến nó, những người thợ im bặt. Vị <i>\"Kiến trúc sư\"</i> lắp bắp trong hơi thở, ánh mắt lảng tránh... cái đầu cúi xuống đã phản bội lời nói của hắn. Hắn nhầm tôi là kẻ điên.\n\nNgười lữ hành của tôi xuất hiện từ bên phải tôi và cất lời phá vỡ sự im lặng.\n\"Một chút sương mù là điều có thể đoán trước. Sẽ không có hại gì. Trên thực tế, chúng ta có thể chào đón sự xuất hiện của nó.\" Lời nói vang vọng trong đầu tôi. <i>Chúng ta có thể chào đón sự xuất hiện của nó.</i>\n\nVâng, có lẽ nó sẽ dẫn đường cho chúng ta. Dẫn đường cho bàn tay chúng ta. Bàn tay run rẩy của chúng ta\nLuôn run rẩy, để lại những dấu vết. Những dấu vết của một bóng ma mờ ảo, rung động\nMột bóng ma bị xiềng xích vào chính dư ảnh của nó, đuổi theo nó, quay một đoạn phim ngắn về màu xanh lam đang phai dần\nVới mí mắt kéo về phía mặt trăng\nPhân biệt thật giả, một vòng xoắn ốc trôi nổi của quá khứ\nvà hiện tại, và tương lai, và vĩnh cửu\nChúng ta có thể chào đón sự xuất hiện của nó\n\n— Lãnh chúa <lorename>Vorgoth</lorename>, Vệ binh phương Bắc",
    [846816685] = "Cà Chua",
    [847085243] = "Quần Trưởng Lão",
    [847537338] = "Những quả mọng ngon và tươi, kích thích khả năng tái tạo cơ thể bằng vitamin tươi trong một thời gian ngắn.",
    [848217128] = "Hóa thạch có những cái tên thật trữ tình... Am-mô-nit... tri-lô-bit... Tôi khá chắc mình đã từng quen một nhạc sĩ tên là Trillobythe. Ông ấy cũng già rồi.",
    [848622143] = "Màn Đêm Buông Xuống",
    [848730556] = "Một bộ găng tay tối tăm và ảm đạm. Chúng khiến việc niệm phép trở nên đáng sợ!",
    [848866969] = "Một luống đất sẽ cho ra Quả mọng Tím.",
    [848976570] = "Thú Rừng Nướng Kèm Cơm Dừa",
    [849604151] = "Kẻ địch ở gần",
    [850109681] = "Trông như sắp mưa...",
    [850405124] = "Trước khi tôi, ờm, đi nghỉ mát sau song sắt, tôi từng là một nghệ sĩ xiếc tung hứng và ném dao! Anh họ tôi đã hỗ trợ tôi trong các màn biểu diễn, nhưng than ôi, những câu chuyện cười và những con dao của tôi không hẳn là trúng đích như tôi mong muốn. Đặc biệt là cái sau... Tôi không muốn đào sâu vào nó, nhưng tôi đã gặp một tai nạn nhỏ trong một buổi biểu diễn. Đầu tiên, chúng tôi cười. Sau đó, họ tống chúng tôi vào tù. À, những ngày xưa tươi đẹp. Dù sao thì tôi cũng ước mình vẫn còn chiếc mũ hề đó. ",
    [850431045] = "Cửa Cổ Đại Bên Trong",
    [850669934] = "Giá Treo Dao Găm Gắn Tường",
    [851318596] = "Chúng tôi đã lội qua bùn, thân cây và đầm lầy cho đến khi đến một khoảng trống. Phía bên kia, nhựa đường biến thành nước, và lau sậy nhường chỗ cho tre và cây cọ.\n\nTôi cúi xuống rửa tay bên một ao nước có hoa huệ, vươn về phía những dây leo và gốc cây phủ đầy rêu ở xa hơn. Sức sống và mùi hương của chúng gợi cho tôi nhớ về tình yêu của mình. Có lẽ khoảnh khắc bất cẩn này đã định đoạt số phận của tôi.\n\nMột gia đình ếch nhảy ra từ bụi rậm, mỗi con hoảng loạn hơn con trước. Tôi ngước lên, và ánh mắt tôi chạm phải mũi một ngọn giáo lao ra từ bụi rậm tối tăm — hình ảnh phản chiếu của nó bên dưới bị phá vỡ bởi làn nước.\nTin đồn đã thành sự thật. Drak đã trở lại... và trong khoảnh khắc này, tôi đang đối mặt với cơn đói máu của chúng.\n\nKhi tôi nín thở, tên Drak cầm giáo liếc nhìn xung quanh. Khi ánh mắt hắn tìm thấy những vị Thần Cổ đại xung quanh, hắn đứng thẳng người, hét lên và thả vũ khí xuống với một tiếng bắn tung tóe. Cơ thể hắn cuộn lại thành tư thế cầu nguyện, quỳ xuống trong đầm lầy trước mặt tôi. Tôi lùi lại, nắm lấy một tảng đá sắc nhọn làm công cụ phòng thủ tạm thời khi tôi vấp ngã — không cần thiết, vì những con quái vật tôn kính những người đồng hành của tôi như sứ giả của thần linh của chúng, và những người gác cổng của Ark Morgo, vùng đất của người chết của chúng.\n\nLàm thế nào mà sự hiểu lầm định mệnh này ra đời, tôi không rõ. Nhưng hôm nay, nó đã cứu tôi khỏi việc đi vào Ark Morgo. Nếu tôi một mình, tôi sẽ không may mắn như vậy.\n\n— Nữ hoàng Jezmina",
    [852446979] = "Đã đến ngọn tháp cổ trong Rừng Khải Hoàn.",
    [853318581] = "Một khối được làm từ Lá Cọ, lan tỏa một bầu không khí ấm áp.\n\nSử dụng <b>Búa Xây dựng</b> để xây dựng <b>cấu trúc</b> xung quanh một Bàn thờ Ngọn lửa với khối xây dựng này.",
    [853657366] = "Các đòn chí mạng bằng vũ khí phép thuật sẽ tự động đánh trúng kẻ địch thứ hai trong phạm vi <b>15</b> mét với <b>5 sát thương Sốc</b> mỗi điểm Trí tuệ.",
    [853826126] = "Đá Vôi Vỏ Sò",
    [853862685] = "Chuyển đổi giữa các công thức bạn đã mở khóa cho nhà máy này tại đây.",
    [854021161] = "Cùng nhau sinh tồn",
    [854338814] = "Bạn đã tìm thấy một ghi chú giải thích rằng một người đàn ông tên Otto đã thừa hưởng một số trang trại. Hãy tìm trang trại và điều tra nó!",
    [854553298] = "Fenrig Người nông dân tin rằng cuộc sống hoàn toàn vô nghĩa nếu không có một vài người lùn làm vườn. Anh ta không được phép có bất kỳ ai, nhưng những trang trại khác có thể có những người lùn làm vườn làm vật trang trí.\n\nHãy ghé thăm một trang trại như vậy và tìm một người lùn làm vườn!",
    [854776191] = "HP",
    [854812771] = "Bác Dreadbane",
    [854874333] = "Tê Tê Cát Nướng",
    [854970765] = "Này Davis, tôi hy vọng anh khỏe. Tôi có một yêu cầu khẩn cấp.\n\nAnh có biết ẩn sĩ trên núi phía sau hẻm núi, người thỉnh thoảng ghé qua không? <i>Gã già kỳ lạ, mặc da thú, người trao đổi đá thạch anh lấy đồ tiếp tế?</i>\nÔng ta lại ghé qua nhưng không xin thảo mộc, gia vị hay rau củ. Gã đàn ông van xin thuốc men, nhưng chúng tôi đã hết sạch. Ngay cả túi đá thạch anh mà ông ta nắm chặt trong bàn tay nhăn nheo cũng không thể thay đổi điều đó.\n\nKhi chúng tôi nhận được hàng mới, anh có thể để dành một ít thuốc sắc cho ông ta không? Lính của chúng tôi được ưu tiên, nhưng ông già tội nghiệp đã tuyệt vọng, vì vậy hãy dành một ít khi chúng ta gặp lại ông ta.\nHoặc đúng hơn, <i>nếu</i> chúng ta gặp lại ông ta. Một hành trình như vậy không hề dễ dàng cho xương già của ông ta.",
    [855101339] = "Bạn đã nói rằng họ sẽ đến vào thứ Hai lúc trưa! Chà, tôi đã đợi MÃI để nhận bưu kiện cho Oswald Anders... chuẩn bị cả một chiếc xe ngựa, vì bạn nói nó sẽ nặng. Tất cả đều vô ích!\n\nHãy bảo anh em nhà Conway gửi một con quạ khi họ đến. Mặc dù... nếu họ cố gắng cắt qua Umber Hollow, chúng ta có thể từ bỏ họ mãi mãi. Để tự bào chữa: <b>Tôi đã bảo họ không đi tuyến đường đó. Đó có thể là tuyến đường cuối cùng của họ.</b>",
    [855712181] = "Hãy Trang trí lại!",
    [855933356] = "Khi tiêu diệt kẻ địch bằng vũ khí cận chiến, tất cả người chơi trong phạm vi 15 mét tính từ mục tiêu sẽ nhận được 20 SP.",
    [856279983] = "Tên Máy Chủ",
    [856421139] = "Cứu rỗi! Người dân <location>Lapis Đông</location> đã tập hợp những người sống sót cho một đoàn xe... do chính nữ hoàng <lorename>Jezmina</lorename> dẫn đầu. Khi tôi nghe bài phát biểu của bà, nhìn thấy gió lướt qua mái tóc bà... tôi biết mình sẽ đi theo. Với ngọn lửa sùng kính và lòng dũng cảm, một ánh sáng chiếu rọi rực rỡ về phía những khởi đầu mới.\n\nNữ hoàng là một kỳ quan, kiên quyết và bền bỉ. Rạng rỡ. Xinh đẹp. Tôi khao khát được giống như bà... để truyền cảm hứng cho mọi người và nâng đỡ họ như bà làm. Thật đau lòng khi phải rời xa quán rượu của mình, nhưng chừng nào trái tim tôi còn đập, tôi sẽ xây dựng. Tôi sẽ phát triển.... và kiên trì. Đặc biệt là với <i>nữ hoàng của tôi</i> dũng cảm dẫn đường.\n— Emily Fray",
    [857109241] = "Tôi muốn rèn với vật liệu mới! Nào, mang cho tôi một ít vàng!",
    [857625257] = "Chậu cây rỗng VI",
    [858171822] = "Tham gia (có đạo đức) khai quật mộ",
    [858223085] = "Thịt Thú Rừng Sống",
    [858241017] = "Hồi còn đi học, tôi được dạy rằng Thuyền trưởng Melville thích kể chuyện. Chuyện bịa đặt. Loại chuyện nghe giống mùi ủng cũ hơn là sự thật. Là một người lao động, tôi luôn biết quán rượu của ông ta, \"Ol’ Salt ’N Pepper\", không chỉ được đặt tên theo bộ râu phong trần của ông ta, mà còn vì người ta được cho là phải coi mọi lời ông ta nói với một nhúm, không, một gánh muối.\n\n<i>Vậy mà, mọi người vẫn tin sái cổ.</i>\n\nHọ chen chúc quanh ông ta như thể ông ta là một nhà tiên tri sinh ra từ biển cả, chăm chú lắng nghe từng lời nói méo mó. Tại sao? Gã đàn ông này là một kẻ nói dối. Một hóa thạch. Ông ta đã không ra khỏi vịnh trong nhiều năm. Tại sao lại tin một lời ông ta nói — tệ hơn nữa, tại sao lại mua cá của ông ta? Đặc biệt là khi chúng tôi bán cá ngon hơn, rẻ hơn, và không có màn kịch đó!\n\nNgay tuần trước, ông ta lao ra quảng trường, tóc tai bù xù, la hét, <i>\"Drak! Tôi đã thấy chúng, chúng đã trở lại!\"</i> Kịch tính. Luôn luôn là kịch tính với ông ta.\n\nĐó chỉ là một trong những câu chuyện của ông ta, được dệt nên để kiếm tiền và vinh quang. Vậy mà, mọi người vẫn tin sái cổ.\nLũ ngốc, tất cả bọn họ.",
    [858909570] = "Tại đây, bạn có thể theo dõi quy trình sản xuất. Nhà máy sẽ sản xuất công thức đã chọn cho đến khi hết nguyên liệu hoặc kho của nhà máy đầy.",
    [859269740] = "Một cây Đàn Hạc Hiếm cho Nhạc sĩ",
    [859434233] = "Vật phẩm sưu tầm này được tìm thấy ở Đỉnh Albaneve. Bộ sưu tập đầy đủ bao gồm 8 món. Chúng có thể được lắp ráp lại thành một bức tranh khảm bên trong Khung tranh khảm Ngọn lửa. Khung phải được đặt trên mặt đất.",
    [859797755] = "Rèn Lối Đi Qua Vùng Hoang Dã",
    [860234770] = "Hannah Reed Cần Giúp Đỡ",
    [860319463] = "Cuộn xuống",
    [860482655] = "Tôi thấy người chết.",
    [860834834] = "Mặt đất phủ",
    [861014185] = "MMB",
    [861161044] = "%k đang buồn",
    [861589268] = "Từng bị che giấu bởi các Vị Thần Cổ đại, sức mạnh của nó đã được giải phóng.",
    [861611040] = "Giấc Mơ Hoa Oải Hương",
    [861856147] = "Vũ khí chứa ngọc không thể bị phá hủy!",
    [862215501] = "Bài ca Bóng tối Lướt tới",
    [862714379] = "Kẻ gọi Thủy triều",
    [862834977] = "Hmm… có lẽ nếu tôi niệm phép này lên bản thân đủ lâu, tôi có thể đóng băng cơ thể mình — và sau đó tan băng bất cứ khi nào tôi muốn. Bằng cách đó, tôi có thể kéo dài sự sống của mình… phải không? Phải?!\nTôi đã làm được! <i>Tôi đã làm được!</i>",
    [863203309] = "Chọn Vũ khí",
    [863759103] = "Di chuyển",
    [864294183] = "Bộ phận của Giáp Hiệp sĩ.",
    [864739346] = "Những Sứ giả Cổ đại của Ark Morgo",
    [865006739] = "Ban đầu không có nhiều thứ, nhưng bây giờ chỉ còn lại cái vỏ rỗng. Hãy khoe niềm kiêu hãnh của bạn với chiếc cúp vàng này.\n\nThu thập nhiều Đầu Quái vật Fell để chế tạo Cúp Vàng.",
    [865078365] = "Giữ liên lạc.",
    [865323944] = "Xây dựng",
    [865374584] = "Cái <craftingstation>Cối giã</craftingstation> của tôi! Anh đã mang nó theo. Nó không gây rắc rối gì cho anh, phải không? Làm ơn, <b>đặt nó vào căn cứ của chúng ta</b> cho tôi, được chứ?",
    [865634153] = "Lối đi đến Lưu vực Sương mù",
    [866734307] = "Kiếm Rắn Thần",
    [867206475] = "Tổ chim Kền kền Rồng",
    [867455489] = "Kẹp, Tony — Dữ liệu Bệnh nhân, Lưu trữ — Báo cáo Số A.051",
    [867639497] = "Cảnh báo Kền kền Rồng",
    [867923179] = "Ngươi từ đâu tới vậy? Xuống mau! XUỐNG MAU! Kền kền ở khắp nơi — đưa ta một mũi tên! Ta sẽ hạ chúng, còn ngươi thì kết liễu! ...Khoan đã, bầu trời đã quang đãng. Ta không còn ở cái tổ kinh khủng đó nữa... nhờ có ngươi. Tên ta là Galen. Ta đi săn. Ta sẽ là cây cung của ngươi nếu ngươi là nơi trú ẩn của ta.",
    [868601186] = "Nâng cấp",
    [869865123] = "Lời Hứa Bằng Ngón Út",
    [869909599] = "Một chiếc mũ nhỏ xinh cho những bữa tiệc nhỏ vui nhộn!",
    [870395078] = "Đũa Phép",
    [870679286] = "Nhận",
    [870767360] = "Đừng hỏi nữa cho đến lần tới ta mở menu này.",
    [871228146] = "Cầu Lửa I",
    [871263641] = "Công cụ sẵn sàng",
    [871626117] = "Một bộ giáp ngực nặng nề đã mất đi vẻ sáng bóng, nhưng không mất đi sự khét tiếng.",
    [871997548] = "Thời gian trong Sương độc",
    [872012757] = "Chào mừng!",
    [872078887] = "Thật là một ngôi đền ẩn tuyệt đẹp! Căn phòng này thật đáng sợ và bụi bặm, nhưng ta lại vô cùng tò mò về lối vào của nó...\n\nLiệu các Tiền nhân có chế tạo những cánh cửa khổng lồ này cho giống loài của họ? Hay nguồn gốc của chúng còn vượt xa cả Tiền nhân...? Liệu những người sống ở đây từ hàng thế kỷ trước có chỉ đơn giản là... <i>rất cao hay sao?</i> Những kẻ cao lớn bị đánh giá quá cao. Ta thích một vị vua lùn, thấp bé hơn. Với vóc dáng đó, họ sẽ hoàn toàn phù hợp với phần còn lại của gia đình chúng ta.\n\nChắc chắn phải có nhiều đền thờ hơn nữa! Ta tự hỏi còn có thể tìm thấy gì nữa...? Ta mỏi nhừ vì những chuyến đi, nhưng thêm một chuyến phiêu lưu nữa cũng không hại gì!\n\n— Braelyn",
    [872365198] = "Hơi cổ xưa, nhưng tốt hơn vải.",
    [872511004] = "Cẩn thận với \"Đồ dùng cho trẻ sơ sinh\"",
    [872682358] = "Thổ Nhĩ Kỳ",
    [873289147] = "Không có nơi trú ẩn",
    [873383836] = "Kindlewastes",
    [873470275] = "Giày Vệ Binh",
    [873602628] = "Trà Cúc Chamomile",
    [874178003] = "Thợ săn <npc> đã giải thích rằng <b>Bánh xe quay có thể được sử dụng để tạo ra vải lanh và dây thừng</b> một cách <b>hiệu quả hơn về chi phí</b>. \n\n<b>Chế tạo Bánh xe quay tại Thợ săn</b> và đặt nó để kích hoạt các tùy chọn chế tạo hiệu quả hơn về chi phí.",
    [874329289] = "Tỷ lệ chí mạng tầm xa",
    [874637193] = "Găng tay kim loại khung bạc với các tấm ngón tay cầu kỳ. Phần bọc đầu ngón tay nhọn dần thành móng vuốt.",
    [874873251] = "Thợ săn cần nơi trú ẩn",
    [874948229] = "Đã đạt giới hạn thú cưng tối đa",
    [874966932] = "Tàn tích Drak'Dal",
    [875192197] = "Tủ Trưng Bày Hóa Thạch (2 Khe Nhỏ)",
    [876098532] = "Anh em họ đến cuối đời",
    [876601180] = "Một chiếc ngà răng sắc nhọn đã bị Sương độc làm ô nhiễm. Đang rung động với những dấu vết mờ nhạt của năng lượng độc hại\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Lợn rừng Fell, ban đầu tìm thấy ở Revelwood.",
    [876815821] = "Kiếm Kép Bão Cát",
    [877009392] = "Bộ trang phục Độc quyền của Hollow",
    [877638643] = "Trò chơi vĩ đại nhất",
    [877798135] = "Bước đi trong đôi giày này, nhanh nhẹn như MP của ngươi hồi phục.",
    [877936092] = "Mất thời gian của ngươi. Bắt đầu làm việc thôi.",
    [878431229] = "Vật phẩm sưu tầm này được tìm thấy ở Kindlewastes.",
    [878528490] = "Cổng Nước",
    [878541722] = "Âm lượng chính",
    [878875673] = "Đến Pháo đài Balefire",
    [878891692] = "Trang bị hiệu quả",
    [878928346] = "Vảy Mặt Trời Nướng",
    [880430870] = "Một bộ sưu tập răng hình nón. Drak đánh rơi chúng rất nhiều trong suốt cuộc đời, và lấp đầy những chỗ trống vĩnh viễn bằng cấy ghép vàng hoặc sự tức giận.",
    [880522481] = "Mở cửa trong Sảnh đường Hollow của Albaneve Summits.",
    [880562696] = "Tàn tích Đá Tù",
    [881008181] = "Một đôi găng tay dày, nhồi đầy lông trắng ấm áp. Khu vực xung quanh mu bàn tay được che chắn bằng một tấm kim loại nhỏ.",
    [881102151] = "Bánh Mì Cán Phẳng",
    [881554267] = "Tinh Vân Đêm",
    [881609730] = "Rơi ra từ các trùm Fell",
    [882243161] = "Xạ thủ",
    [882374168] = "Tại sao ta không ở vị trí của mình? Và ngươi là ai? \"Một Hỏa sinh\"? Chào mừng, vậy thì! Ta là Gunther Galeforth, một \"người lính\", ta đoán vậy. Ta tự coi mình giống một nhà thơ hơn, có lẽ là một người làm vườn. Hãy cho ta biết nếu ta có thể giúp được gì!",
    [882376446] = "Uống",
    [882705236] = "Thiếu Oxygen",
    [882830393] = "Lượng sát thương vật lý tối đa mà giáp của bạn có thể giảm thiểu được tăng thêm <b>10%</b>.",
    [883151492] = "Vậy, ngươi đã tìm ra bất kỳ \"mánh khóe bí mật\" nào của bọn Drak chưa?",
    [883708396] = "Rơi ra từ Banshees, trong Sương độc",
    [884181371] = "Xây một chiếc giường có mái che cho Oswald Anders",
    [884711890] = "Găng Tay Bóng Của Núi",
    [885049077] = "Chà, một cú bắt tuyệt vời! Ta đã đánh giá thấp ngươi Cá sinh - ừm ý ta là Hỏa sinh ha ha!",
    [885088362] = "Một quả ớt chuông đỏ tươi, giòn tan với hương vị ngọt ngào, mọng nước và lớp vỏ bóng loáng.",
    [885262836] = "Tất cả kiến thức bị lãng quên của thế giới sẽ nằm trong tầm tay bạn với đôi găng tay được săn lùng này.",
    [885622378] = "Một sinh vật hữu cơ phát sáng rực rỡ trong vùng nước sâu, tối tăm.",
    [885776421] = "Hình Nhân Tập Luyện III",
    [885804398] = "Lời kêu gọi của chúng ta đã được đáp lại!",
    [886388448] = "Cấp độ Ngọn lửa",
    [886582610] = "Hoa Trắng",
    [887136486] = "Tìm tất cả các mảnh giáp \"vệ binh phương bắc\" bị lãng quên.",
    [887806327] = "Tăng cường giáp xuyên thủng",
    [887850383] = "Khi nhìn vào bề mặt của viên pha lê, bạn cảm thấy hình ảnh phản chiếu bị biến dạng và thay đổi thành một thứ gì đó... đáng lo ngại.",
    [888013589] = "Khiên Vệ Binh",
    [888077029] = "Ta chưa bao giờ thấy thứ gì tối tăm đến vậy, nhưng lại mê hoặc. Cảm giác như nó đang thì thầm với ta, cầu xin ta chiếm lấy nó. Ta phải sở hữu <b>Khối Đá Obsidian</b>, đó là một ham muốn mà ta không thể bỏ qua. \nNhưng cất giữ chúng ở đâu cho an toàn? Có lẽ là <b>phía trên các hồ dung nham</b> — ai dám mạo hiểm mạng sống để đến đó? Chỉ có kẻ ngốc mới dám thử. \n\nDù có bị bắt hay không, việc lấy những khối đá này chắc chắn sẽ là con đường dẫn đến bóng tối của ta — nhưng ít nhất ta sẽ có được thứ mình mong muốn.",
    [888320051] = "Mọi người học việc đều biết rằng Gậy phép đen ẩn chứa những bí mật đen tối. Cố gắng khám phá chúng dẫn đến chứng đau đầu, buồn nôn và hoang tưởng.",
    [889874453] = "Linh hồn đóng băng",
    [889886576] = "Va phải chướng ngại vật.",
    [890452360] = "Đất Cao Nguyên Du Mục",
    [890584624] = "Đi theo dấu chân của Jezmina",
    [891799467] = "Khối Lâu Đài",
    [892262011] = "Công thức Cà phê đen",
    [892819095] = "Trang trại Gai dầu",
    [892912208] = "Tiện nghi - Ghế",
    [892956876] = "Thợ mộc đã giấu một kho báu nhỏ trong trụ giữa của Cầu <lorename>Braelyn</lorename> như một dấu ấn. Bản thân cây cầu nằm ở Springlands.",
    [893305624] = "Máy chủ chuyên dụng",
    [893463725] = "Lô đất Mayfair",
    [893516656] = "<i>Nhà giả kim đã có một bài giảng về \"Sợi nấm\". Đó là phần thịt của nấm lan truyền Sương độc khắp thế giới. Người ta từng tin rằng nó có thể mang lại sự cứu rỗi, nhưng thay vào đó, nó đã biến thế giới thành đống tro tàn.</i>",
    [893690469] = "Một loại cây thường thấy ở Albaneve Summits. Nó có đặc tính chữa bệnh.",
    [893724951] = "Sát thương độc mỗi giây",
    [893799057] = "Ngươi ước điều gì?",
    [893894227] = "Trọng Kiếm Gai",
    [894023349] = "Để lại sự mục nát phía sau",
    [894054026] = "Tìm hàng cấm",
    [894396207] = "Thịt Mỡ Sống",
    [894423101] = "Kẻ cắt da của <lorename>Lupa</lorename>",
    [895799829] = "Phước lành cuối cùng",
    [895985197] = "Chúng ta, những người duy nhất",
    [896183971] = "Kết hợp các mảnh ghép vào khung",
    [896455997] = "Ngăn xếp mới",
    [897749921] = "Ngươi đã tìm thấy Sảnh đường Hollow ở Cao nguyên Du mục. Hãy xuống và đến cuối để làm hài lòng <npc>Nhà sưu tầm</npc>.",
    [899036349] = "Những người sống sót khác",
    [899163284] = "Vật phẩm ngoài nước",
    [899690196] = "Vinh quang thay!",
    [900621396] = "Cơ thể của bạn đang hồi phục theo thời gian",
    [900686414] = "Bậc Thầy Hiểu Biết",
    [900743291] = "Chúng ta vẫn chưa xong, phải không?",
    [901057086] = "Bạn đã tìm thấy một ghi chú đề cập đến hang ổ của Cyclops gần một cây cầu.\n\nHãy điều tra hang ổ và đánh bại Cyclops bên trong!",
    [901157408] = "Tập Trung Pháp Thuật",
    [901230567] = "Tấn công với lực nghiền nát, chiếc búa này hủy diệt Kẻ Hollow bằng cách nghiền nát xương cốt của chúng thành tro bụi.\n\n<b>Tiếng Vọng Kẻ Hollow:</b>\nVũ khí giải phóng một tiếng vọng tà ác, tự động kéo dài phạm vi tấn công.",
    [901241245] = "Fell",
    [901329636] = "Chọn Nguyên Liệu",
    [901860171] = "Hoa Hồng",
    [902568020] = "Thêm nhiều hình dạng...",
    [902904328] = "Vách Ngăn Phòng \"Rồng\"",
    [903765132] = "Bạn đã đến địa điểm mà Rochelle đã nói.\n\nĐi vào lăng mộ và tìm kiếm để lấy trang phục thợ rèn thẩm mỹ!",
    [903890183] = "Tủ Trưng Bày Hành Lang Khô Cốt (2 Khe Nhỏ)",
    [904152683] = "Vòng Tay Trò Chơi Mùa Hè",
    [904245959] = "Khối Phát Sáng Xanh Lá Cây",
    [904392496] = "Lối tắt qua Umber Hollow là một quyết định tồi tệ, nhưng chúng tôi không còn lựa chọn nào khác! Hank lười biếng ngủ gật, nên chúng tôi sẽ muộn giờ đến Trạm giao dịch \"Đá rực lửa\" nếu không có suy nghĩ nhanh chóng... Và tôi sẽ mất đồng vàng của mình! Chúng ta không thể để điều đó xảy ra, hiểu không?\n\nTất nhiên, Hank đã ngủ quên trong ca gác đêm của mình khi nghỉ ngơi ở <location>Quần đảo Jasper</location>... <i>Ngu ngốc! Liều lĩnh!</i> Chúng tôi <b>đã mất hàng hóa khi bỏ chạy...</b> không sao cả. Chúng tôi sẽ tự viết thư! Và <b>món quà,</b> ừm... <npc>Thợ rèn</npc> sẽ không biết nó bị mất.\n\nTôi sẽ ký một cái gì đó đáng yêu, và để dòng sáng tạo của tôi tuôn chảy... Hank có thể giúp. Gã đó sẽ không biết gì cả. <i>Dễ dàng, bạn thấy không?</i>",
    [904686863] = "Nếu các mẫu dữ liệu không khớp, tôi sẽ coi lý thuyết này như một trò đùa tệ hại. <i>Nhưng chúng lại khớp.</i>\n\nCấu trúc của những bộ xương khổng lồ này tương tự như mẫu Chim Kền Kền Trắng mà chúng ta lấy trong cơn bão tuyết đó. Có một mối quan hệ lịch sử ở đây, cùng một dòng máu tổ tiên. Không chỉ những bộ xương ở đây, mà cả ở Vùng Đất Cháy nữa.\n<i>Tất cả đều chỉ về loài rồng.</i>\n\nTất cả những điều này làm xao nhãng <b>nghiên cứu tháp đá</b> của tôi, nhưng tôi hy vọng sẽ sớm quay lại giải mã chúng. Chỉ khi loài rồng không bắt được tôi trước đó.\n\n— <lorename>Loraine Crim</lorename>",
    [905917022] = "Khối Lăng Mộ Nửa Đêm",
    [906203891] = "Chùy Đầu Vật Tổ",
    [906345658] = "Màu sắc của rượu vang đỏ, máu khô và những lời hứa tan vỡ.\n\nBảng màu này có thể được tạo ra từ các nguyên liệu ở Vùng Đất Cháy.",
    [906418332] = "Quả Bóng Vàng",
    [906950138] = "Giữ %k",
    [907135395] = "Tháp Đá Cổ Đại",
    [907376930] = "Thế giới là phép thuật của chính nó.",
    [907399716] = "Triều Dâng",
    [907771151] = "Nữ Hoàng Quái Vật Fell",
    [907848829] = "Băng Bị Phủ Bóng",
    [908788329] = "Tìm Kiếm Trợ Lý Nhạc Sĩ",
    [908946621] = "Tặng Quà",
    [909003160] = "Những chiếc găng tay bắn cung cải tiến này giúp bạn dễ dàng bắn hạ chim từ trên trời! Tuy nhiên, ngày nay hầu như không còn chim nữa.",
    [909114768] = "Vật Phẩm Triệu Hồi",
    [909245737] = "Thợ Mộc",
    [909688939] = "Lướt Nhanh",
    [909696867] = "Điều Tra Quán Rượu Emily Fray Ở <location>Brittlebush</location>",
    [909799871] = "XÂY CAO HƠN! Tháp phải vươn tới đỉnh cao và sánh ngang với sự duyên dáng của mặt trời! Nữ Vương Leandra yêu cầu như vậy! Ta đã tìm được đá lâu đài tốt nhất... tìm thấy rất nhiều ở phía sau tháp. Chỉ những gì tốt nhất cho Nữ Vương Leandra!",
    [910281009] = "Với đôi giày này, sức mạnh Chữa thương của đất mẹ chảy xuyên qua bạn — bạn có cảm nhận được không?",
    [910289079] = "<b>Cuồng Nộ Máu</b> \nTăng sát thương vũ khí cận chiến lên <b>20%</b> trong <b>10</b> giây.",
    [911047023] = "Dụng Cụ Mở Khóa",
    [911093563] = "Chọn Cài Đặt Phiên",
    [911602828] = "Hãy an toàn, bạn của tôi!",
    [912231391] = "Vải Màu Cam",
    [912389721] = "Rìu Chắp Vá",
    [912747760] = "Nâng Cấp Ngọn Lửa",
    [913001574] = "Thức Ăn",
    [913229137] = "Vào Và Cướp Bóc Ngôi Đền",
    [913253162] = "Di chuyển xuống một voxel",
    [913732092] = "Đất Vùng Đất Mùa Xuân",
    [914011642] = "Giọng nói này chắc chắn xứng đáng được trao giải.",
    [914331918] = "Trạng Thái Điều Khiển",
    [914500388] = "Một Cơn Rung Chuyển Trong Hầm Mộ",
    [914728051] = "Cây Con Edelweiss",
    [915026953] = "Khai Thác",
    [915572234] = "Tùy Chỉnh",
    [915582837] = "Lò Rèn Ngọc Cao Nguyên Du Mục",
    [915630485] = "Đó là một mái nhà tươm tất! Dạo này không thể kén chọn được. Dù sao thì, có lẽ chúng ta có thể làm một ít đồ gỗ, phải không?",
    [915786011] = "Bạn đã chế tạo thức ăn cho mèo cần thiết để thuần hóa một con mèo hoang. Bây giờ hãy đến <location>Cỏ thiếc</location> và tìm kiếm tòa tháp của Nhà giả kim phía trên Sương độc để tìm và thuần hóa một con mèo!",
    [916614588] = "Sát Thương Cung",
    [916625307] = "Nước Sự Sống",
    [916860750] = "Một liều thuốc giải độc sẽ chữa khỏi bệnh nhiễm độc.",
    [917302344] = "Xương sườn lớn của Quái Vật Fell độc địa nhất.\n\n<b>Nguyên Liệu Chế Tạo:</b> Chủ yếu dùng để chế tạo áo giáp.\n<b>Nguồn Gốc</b>: Rơi ra từ Quái Vật Fell Khổng Lồ, lần đầu tiên tìm thấy ở quần xã sinh vật Cao Nguyên Du Mục.",
    [917709315] = "Bị một cú đánh trả từ những chiếc găng tay gai này sẽ khiến ngay cả kẻ tấn công cảnh giác nhất cũng phải quỳ gối.",
    [917744342] = "Tường Rào Gỗ V",
    [917960445] = "Khi bạn chiến đấu với Rồng Con Fell hết lần này đến lần khác, bạn có thể quan sát thấy hy vọng của nó dần tan biến thành tuyệt vọng.\n\nThu thập nhiều Đầu Rồng Con Fell để chế tạo Cúp Vàng.",
    [918097904] = "Một chiếc giường ấm cúng cho các loài động vật trang trại lớn đã được thuần hóa, chẳng hạn như Yak hoặc Armadillo Sa Mạc.",
    [919275644] = "Chế Độ Góc Nhìn Thứ Nhất",
    [919350498] = "Oswald",
    [919532360] = "Rơi ra từ kẻ địch Fell ở Cao Nguyên Du Mục",
    [919556316] = "Chú Armadillo Sa Mạc con này đã bắt đầu hình thành sừng, sau này dùng để đào đường hầm — nhưng không bao giờ khi bạn đang nhìn. Thật kỳ lạ khi nó hoạt động như vậy.",
    [919562149] = "Một cốc đầy rượu mật, và một trái tim đầy bài hát!",
    [920337222] = "Vì Ngọn lửa và vinh quang!",
    [920449905] = "Đến Ốc Đảo",
    [920607736] = "Chim Kền Kền Phía Trên",
    [922078539] = "Cây Con Giấy Papyrus",
    [922540792] = "Mũi Tên",
    [922722885] = "Tìm Kiếm Tổ Chim Kền Kền Mỏ Đá",
    [922810103] = "Bạn Bè",
    [922811349] = "Nhà giả kim <npc>muốn <b>chế tạo một Cây quyền trượng Tinh thần</b>. Gậy phép sử dụng các điểm niệm phép, kênh hoặc phép thuật vĩnh cửu làm đạn dược và là vũ khí ma thuật mạnh mẽ. Chế tạo gậy phép yêu cầu Gỗ Sương độc, có thể tìm thấy dưới Sương độc.",
    [922879658] = "Chiến Binh Máu",
    [923042563] = "Quần Khô Cốt Độc Quyền",
    [923149976] = "Thợ Săn",
    [923363493] = "Hang Cyclops",
    [923597542] = "Vì Quetzal không còn lang thang ở Embervale, lá cọ nhuộm được sử dụng thay cho lông vũ của chúng để tái tạo lại vẻ ngoài.",
    [923640193] = "Bình Năng Lượng Siêu Cấp +",
    [923691751] = "Chúng ta chỉ là những hạt bụi trong cơn lốc xoáy của các vì sao, bạn của tôi. Bạn có dám vươn tới, mong muốn nắm lấy một <i>mảnh vĩnh cửu?</i> Có lẽ việc sở hữu một <b>phép thuật vĩnh cửu</b> sẽ phù hợp với bạn! Tôi biết có một cái đã được chôn trong một ngôi mộ dưới lòng đất cùng với chủ nhân khủng khiếp của nó. Bạn có thể sử dụng nó để làm rất nhiều điều tốt!",
    [923765692] = "Thợ rèn <npc>muốn chiến đấu chống lại Sương độc, làn sương mù hủy diệt đã chiếm lấy Embervale. Sương độc phun trào từ các Giếng thuốc tiên.\n\nĐến Giếng thuốc tiên gần đó để tìm hiểu thêm về Sương độc.",
    [923904862] = "Qua nhiều năm, không ai chạm vào, xương của tất cả các loại sinh vật ma thuật đã cứng lại và hóa đá. Một vật liệu quý hiếm do sự khan hiếm và khả năng ma thuật cao.",
    [924259694] = "Một ánh sáng mới vươn ra. Đôi mắt sáng của tôi nhìn xa hơn đường chân trời, vượt qua những rễ cây xoắn vặn của Rừng Khải Hoàn. Tai thính của tôi nghe thấy những lời thì thầm từ bên dưới, một giọng nói nhẹ nhàng nhảy múa trong gió như tiếng chuông gió. Du hành qua biển văn minh đã mất của chúng ta và giải phóng chim ca bị mắc kẹt bên dưới nó!",
    [924350199] = "Một con Chim Đuôi Đỏ Không Biết Bay với bộ lông đầy màu sắc và chiếc mỏ mạnh mẽ, uy nghiêm. Bạn có thể nuôi nhốt nó vô thời hạn để lấy trứng, và nó thậm chí không thể bay đi.",
    [924671382] = "Sự Dồi Dào Của Màu Sắc",
    [924737765] = "Khe Thanh Hành Động 1",
    [924802020] = "Gác Mái Ẩn",
    [925018335] = "ST Băng",
    [925362969] = "Nán lại và chiêm ngưỡng sự vĩnh cửu.",
    [925672142] = "Lò Nướng",
    [926078188] = "Nghiên Cứu Tháp Đá",
    [926106057] = "Một bữa ăn ngon với hương vị đất.",
    [926260808] = "Tháp Đá Cổ Đại",
    [927198451] = "Không có công thức nào được chọn",
    [927514816] = "Tấn công một kẻ địch không để ý bằng vũ khí tầm xa sẽ tăng cơ hội chí mạng của bạn lên 30%.",
    [927935696] = "ST Đánh lén",
    [928077568] = "Mở Chat Văn Bản",
    [928563902] = "Chặn / Đỡ đòn",
    [928831733] = "Một Bộ Trang Phục Hầu Gái Khác",
    [929228147] = "Cây Giống Gỗ Đoạn",
    [929267657] = "<b>Sương độc là một làn sương hủy diệt</b> đã làm ô nhiễm gần như toàn bộ Embervale. Tiếp xúc lâu với Sương độc là chết người, ngay cả đối với bạn.\n\nThám hiểm vào Sương độc là <b>nguy hiểm, nhưng bổ ích.</b> Kho báu và vật liệu tìm thấy bên trong Sương độc rất hiếm và có giá trị.\n\nSương độc trở nên dày đặc và chết người hơn ở các khu vực sau của Embervale. Cần có <b>Cấp Độ Vượt Sương độc cao hơn</b> để đi qua.",
    [929286330] = "Giày Lính Đánh Thuê",
    [930992339] = "Giường có sẵn",
    [931304421] = "Mức Độ Thoải Mái",
    [931429929] = "Đèn Treo Màu Cam I",
    [931556949] = "Cây Chuối",
    [931798533] = "Tiếng Trung",
    [931819118] = "CHỈ HÔM NAY: \"Hành Động Đâm Xuyên\" Tuyệt Vời Của Godwin!",
    [931899641] = "Mở",
    [932383763] = "Hãy táo bạo, hãy sắc bén!",
    [932721238] = "Nhiều người sống sót hơn...",
    [932783608] = "Khiên Thành Lũy Hoàng Kim",
    [932831472] = "ST Băng Ma Thuật",
    [932915758] = "Tùy chỉnh cuộc phiêu lưu của bạn.",
    [933232183] = "Bàn Thợ Cấp 1",
    [933302809] = "Nếu bạn yêu thích trải nghiệm chiến đấu đầy thử thách, cài đặt này là dành cho bạn. Có nhiều kẻ địch hơn trong thế giới trò chơi, chúng tấn công thường xuyên hơn và gây sát thương nhiều hơn.",
    [933337945] = "Xây Dựng Căn Cứ",
    [934215426] = "Chúc bạn một ngày tốt lành!",
    [934984411] = "Đĩa Tròn 3m",
    [935028296] = "Phản Ứng Chuỗi",
    [935626102] = "Phòng Thí Nghiệm Cải Tiến",
    [935725049] = "Những Câu Chuyện Về Đền Thờ Mặt Trời",
    [935875797] = "Nhổ cỏ ở Cao Nguyên Du Mục",
    [936064426] = "Món quà của bạn dành cho tôi là món quà ngọt ngào nhất! Hãy đặt <craftingstation>Lò Hun Khói Ong</craftingstation> và có lẽ chế tạo một vài <craftingstation>Tổ Ong Mật</craftingstation>! Khi đến lúc thu hoạch, chúng ta có thể nấu một món gì đó thật đặc biệt! Hy vọng bạn thích khoai mì nướng mật ong?",
    [936402290] = "Bạn đã tìm thấy một ghi chú mô tả một chiếc rương bí mật trên mái của Trạm Gác \"Alba\".\n\nPhía sau <b>cái chiêng trên mái nhà</b> sẽ có một căn phòng nhỏ chỉ có thể tiếp cận bằng cách nhảy và tìm một cánh cửa bí mật. Tìm căn phòng và mở chiếc rương bên trong!",
    [936500414] = "Leo Lên Tháp Canh",
    [936881318] = "Bạn đã tìm thấy bia mộ của một chú chó tên Ikko. Dòng chữ ghi:\n\n\"Ký ức của bạn sẽ sống mãi mãi.\"",
    [936999141] = "Trạm Gác Bỏ Hoang",
    [937051981] = "Vận động viên",
    [937128450] = "Quyết định xem các hành động như tấn công, đỡ đòn, v.v. có nên được thực hiện theo hướng nhân vật đang đối mặt hay theo hướng máy ảnh đang chỉ hay không.",
    [937462441] = "Chúng gần như không thể gọi là giày.",
    [937470732] = "Tội Ác Của <location>Cuối Glennwood</location>",
    [937483232] = "Phong cách của bạn là nghề của tôi!",
    [937885730] = "Đặt lại tất cả các phím tùy chỉnh thành:",
    [937960922] = "Hiệu Suất Tối Đa",
    [937980026] = "Mảnh Bản Đồ Của Polaris",
    [938039478] = "Những Khách Hàng Mới Của Tôi Bất An",
    [938093439] = "Khai thác mọi vật liệu quý giá trong Lưu Vực Nước Lấp Lánh.",
    [938377748] = "Bột mịn làm từ việc nghiền vỏ sinh vật.",
    [938494577] = "Khung Cửa Sổ Bằng Thép Tròn",
    [938498561] = "Thế Giới Của Tôi",
    [939074024] = "Mở Khóa Kỹ Năng Nhân Vật",
    [939850503] = "Rượu Và Truyện",
    [939964148] = "Hồi phục SP rất nhiều khi tiêu thụ. Ngon và ngọt.",
    [940172457] = "Nhiệm vụ được cập nhật",
    [940287878] = "Tỷ Lệ Chí Mạng Cận Chiến",
    [941313883] = "Một loài thực vật dưới nước chỉ mọc ở nơi ánh trăng phủ lên đáy biển. Nó có một ánh sáng quyến rũ, báo hiệu sự diệt vong cho bất kỳ thợ lặn nào sẵn sàng quên mình trong cuộc truy tìm ánh sáng dưới vực sâu.\n\nNó có thể được tìm thấy dưới nước trong Lưu Vực Nước Lấp Lánh.",
    [941623524] = "Tìm Kiếm Một Con Búp Bê Trong <location><lorename>Phạm Vi Của Pikemead</lorename></location>",
    [942078433] = "Không đủ dung lượng trống",
    [942244193] = "Găng tay được đeo bởi những pháp sư tài năng, nổi tiếng và thành công nhất vương quốc.",
    [942278966] = "Bạn đọc được một câu chuyện về một bà lão bí ẩn, sống một mình như một người chữa bệnh bằng thảo dược gần Driftwood Wake. Có điều gì đó về bà ta không ổn. \n\nHãy đến thăm nơi ở của bà ta và lục soát để tìm vật có giá trị!",
    [942352214] = "Thợ Săn",
    [942803752] = "Trợ Lý",
    [943009934] = "Linh Hồn Làng Mất Tích",
    [943039008] = "<location><lorename>Hang Của Lupa</lorename></location>",
    [943298100] = "Tìm Hóa Thạch Suối Khoáng",
    [943606274] = "Tôi chưa bao giờ nói với bạn về những con mèo quanh tháp của tôi, phải không? Chúng khá hữu ích để dọn dẹp lũ chuột sống - cả những con đã chết nữa. Chúng như một lũ hổ con vậy!",
    [943818294] = "Thuần Hóa Chó Hoang",
    [943987461] = "Làm Việc Tăng Ca",
    [943994935] = "Cuối cùng, không khí trong lành. Không nặng mùi phấn hoa hay sự phân hủy ngọt ngào, buồn nôn. Đầu óc tôi quay cuồng. <b>Tôi đã không ngủ mấy ngày rồi. Kể từ khi tôi để lại con suốt của mình trong Rừng Revel trên đỉnh vách đá đó</b>. Giờ đã xa quá... nhưng tôi không thể quay lại.\n\nTôi phải chạy trốn. Có thứ gì đó độc ác đang ẩn giấu trong lùm cây... lan ra khắp bụi rậm như rễ cây. Nó ôm lấy và quấn lấy, bóp nghẹt và làm ngạt thở. Lấp lánh trong bóng tối, giữa các cành cây, dưới lớp da: mạng tơ lụa của một con nhện săn mồi hai vuốt.\n\nNhững cơn ác mộng như thế này là do con người tạo ra, tôi đã học được.",
    [944594283] = "Một cách tự nhiên để trang trí mái nhà.\n\nSử dụng <b>Búa Xây Dựng</b> để xây <b>cấu trúc</b> xung quanh Bàn Thờ Ngọn lửa với khối xây dựng này.",
    [945197819] = "Chuột Chũi Cao Nguyên Du Mục",
    [945204929] = "Một loại quặng phổ biến cần thiết để tạo Thanh Đồng.",
    [945732883] = "Quá Tải",
    [945787352] = "Dịch Nhầy Tinh Khiết",
    [946007614] = "Xóa",
    [947053494] = "Chế tạo tại Giá Phơi",
    [947223904] = "Đỡ đòn thành công một đòn tấn công của kẻ địch sẽ hồi phục <b>20</b> MP.\n\n<b>Đỡ đòn</b>\nKhi trang bị Khiên, một cú đỡ đòn đúng lúc sẽ <b>đỡ đòn</b> tấn công.",
    [947920908] = "Bàn Lâu Đài Lớn",
    [948026709] = "Đũa Phép Cơn Bão Nghi Lễ",
    [949012756] = "Một bộ giáp ngực tinh xảo cho phép bạn ẩn mình trong bóng tối và tấn công từ trong bóng tối.",
    [949145625] = "Chế Tạo Thủ Công",
    [950017952] = "Giảm thiểu chuyển động camera động và thay đổi FOV giúp tăng cường sự nhập vai nhưng cũng có thể gây say tàu xe.",
    [950613571] = "Cái gì?",
    [950712559] = "Được bọc trong da sẫm màu và bao phủ trong bí ẩn, đôi giày này mang người mang chúng như thể đang đi trên mây.",
    [950749903] = "Tìm Kho Báu Của Scavenger",
    [951074646] = "Đặt",
    [951220202] = "Tăng <b>Kháng Độc</b> của bạn thêm <b>5%</b>, giúp giảm lượng sát thương <b>Độc</b> nhận vào.",
    [951357032] = "Rỉ Sét Và Hoa Hồng",
    [951829319] = "Tách Trà Đất Sét",
    [952031785] = "Vệ binh phương bắc — Lãnh chúa <lorename>Vorgoth</lorename>, kẻ thù bệnh hoạn, điên rồ của ta. <i>Ngươi là một bóng ma lãnh đạo điên cuồng, gào thét!</i> Ta muốn ngươi biết rằng <i>tuân theo mệnh lệnh của ngươi khiến ta phát ốm; một cái giá mà ta đã trả bằng máu.</i>\n\nKhông có quân đội nào bảo vệ được ngươi. Ta sẽ vượt qua mọi vực thẳm, leo lên mọi ngọn núi, và chống chọi với cái lạnh khắc nghiệt. Ta sẽ đẩy bản thân vượt quá khả năng thể chất của con người để tìm thấy ngươi. Và khi ta tìm thấy ngươi, mục tiêu của ta sẽ chính xác. <b>Ta thề bằng danh dự của anh trai ta.</b>\n\n— Athalan Skree",
    [952227108] = "Hút HP",
    [952609214] = "Hiệu Suất",
    [953066351] = "Sách IV",
    [953240508] = "Đạn ma thuật cải tiến, giải phóng một làn sóng Chữa thương và nhảy sang đồng minh ở gần.\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép bằng <b>gậy phép.</b>",
    [953523858] = "Đây là Nhiệm vụ Anh hùng Lửa của bạn. Chúng có thể dẫn bạn đến kho báu hoặc địa điểm ẩn giấu trong thế giới!",
    [953551034] = "Tức thời hồi phục một lượng HP nhỏ, và liên tục hồi HP trong 10 giây.",
    [953997836] = "Đài Lửa Đá Cao",
    [954356335] = "Tên tôi là Kaori Conway. Tôi là người đưa thư theo nghề. Anh đã cứu tôi, phải không? Tôi muốn tặng anh một món quà tử tế, nhưng có vẻ như tôi đã chết, nên tôi chẳng còn gì... chúng ta nên thay đổi điều đó!",
    [954396291] = "Một ghi chú bạn tìm thấy tiết lộ sự tồn tại của một căn phòng ủ bia nhỏ bí mật tại Địa điểm Sản xuất Elixir. Tìm căn phòng và lục soát nó để tìm vật có giá trị!",
    [956275841] = "Động vật này có thể cung cấp cho bạn sữa tươi.",
    [956617566] = "Obelisk Cổ Đại",
    [957359882] = "Sức Mạnh Khai Thác Đá",
    [958122960] = "Gửi Theo Chồng",
    [958193915] = "Ngọc Xanh Biển",
    [958242798] = "Không thiếu nguyên liệu",
    [958393126] = "Kẻ Nghiền Xương",
    [958490090] = "Lâu đài Gloomsbury",
    [959079868] = "Trượng Triệu Hồi",
    [959523141] = "Rất vui được gặp bạn!",
    [960107940] = "Vị trí Tờ nhạc",
    [960344506] = "Nữ hoàng Jezmina đã từng ở đây, và các Đồng minh Cổ xưa của bà đã triệu hồi ánh sáng dẫn lối cho ta!\n\nThật là một cuộc hội ngộ kỳ lạ! Ta vẫn nhớ bà ấy khi còn là một chú chim non trong lòng mẹ. Bàn tay yếu ớt của bà ấy khó lòng giữ được cây đàn lia của ta. Bà ấy đã khóc khi làm đứt sợi dây ở giữa... Ta đã tha thứ cho bà ấy.\nBà ấy muốn làm bạn mãi mãi và niêm phong lời hứa đó bằng máu. <i>Thật là một phong tục kỳ lạ của Kindlewaste</i>, ta đã nghĩ, nhưng tại sao không chấp nhận nó? Ta nhớ mình đã tạo ra một vết cắt nông. Sau đó, ta đã thay dây đàn lia và bà ấy tiếp tục chơi — má ướt đẫm nước mắt và lòng bàn tay lấm tấm những đốm đỏ anh đào. Ta vẫn còn vết sẹo từ ngày đó.\n\nCon đường của chúng ta lại giao nhau, cách biệt bởi thời gian. Mục tiêu của bà ấy là của ta, và vết sẹo của ta là của bà ấy. Ta tin rằng hành trình của mình sẽ không kết thúc khi ta bước vào cỗ máy đó... Rốt cuộc, còn vô số cuộc phiêu lưu đang chờ đợi!\n\n<i>Valory</i>",
    [961124147] = "<lorename>Cyrus</lorename>",
    [962059085] = "Chúng ta cần một <craftingstation>Trạm thuộc da</craftingstation>. Chắc không khó để kiếm được đâu nhỉ?",
    [962159050] = "Tôi tin rằng bạn có thể uống tới 21 ly cà phê mỗi ngày mà không gặp bất kỳ hậu quả tiêu cực nào! Ồ, tôi không có bằng chứng. Đó giống như một lời khẳng định cá nhân hơn. Đây là không gian không phán xét, đúng không?",
    [962177151] = "Đóng",
    [962177827] = "Bóng Tuyết",
    [963035939] = "Bạn đã phát hiện ra một ghi chú nhắc đến một người nông dân tên là Fenrig. Hãy đi theo ông ta đến hang sói mà ông ta đã mạo hiểm và khám phá khu vực!",
    [963426112] = "Kẻ ngắm sao Kindlewastes",
    [963620000] = "Tùy chỉnh Ngoại hình <img vanity>",
    [964247756] = "Cơ thể này thật phi thực tế... Như mơ. Được nhổ ra từ hư không. Bạn là ai? Tôi là gì? Họ gọi bạn là Kẻ mang Lửa? Tôi không hiểu. Tôi xin lỗi, tôi nghĩ - tôi không có tên. Người Sưu tầm đã nói... những người hầu không cần tên. Xin đừng đưa tôi trở lại bóng tối...",
    [964924468] = "Bạn đã đến trang trại Kindlewastes.\n\n<b>Khám phá địa điểm để tìm bảng màu!</b>",
    [964959766] = "Khiên Nanh Sói",
    [965070077] = "Che vết thương, cho phép cơ thể lành lại.",
    [966186599] = "Điều tra Con đường Vách đá",
    [966396516] = "Hộp Đựng Bằng Tre II",
    [966532651] = "Khuôn mặt của chúng thật đáng sợ, nhưng chúng chủ yếu chỉ muốn chăn dắt dê và bò yak. Con người chỉ chiếm một phần nhỏ trong chế độ ăn của chúng.\n\nThu thập nhiều Đầu Người Khổng Lồ để chế tạo Cúp Đồng.",
    [966798799] = "Nên nấu chín trước khi ăn.",
    [967186670] = "Ai Sợ Hãi Sinh Vật Bay Ghê Tởm?",
    [967326389] = "Đỏ rực, đỏ thẫm như một nụ hôn nồng cháy — hoặc máu của một trái tim đang khóc, bị đâm bởi một ngọn giáo.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Bồn nước Veilwater.",
    [967732766] = "Chọn một mẫu có sẵn để làm cơ sở cho tùy chỉnh liên kết của bạn",
    [968095863] = "Bồn Rửa Gỗ",
    [968114406] = "Đây rồi!",
    [968344048] = "Nhân vật",
    [968415160] = "Tôi đã vào bụi rậm. Có nhiều chỗ ẩn nấp, nhưng quá nhiều bùn — tôi đang để lại dấu chân. Tôi nhớ những con đường núi đá vững chắc và đá sỏi rơi xuống vực thẳm để chờ tiếng vọng.\n\nMùi hương kỳ lạ lơ lửng trên đầm lầy. Nồng và lên men, nó gợi cho tôi nhớ đến các nhà máy chưng cất gần Đỉnh Howling. Tôi quyết định tránh xa <b><location>Điểm cuối Glennwood</location>...</b> Quá nhiều hoạt động và tôi nếm vị đồng trong nước... Điềm xấu. Tôi sẽ rời khỏi đây càng sớm càng tốt.",
    [970237145] = "Ghế Lười Bằng Tre",
    [970378779] = "Thanh hành động hiện tại",
    [970872192] = "Sự khởi đầu của kết thúc",
    [970953122] = "Bạn đã chế tạo một số mồi nhử động vật! Bây giờ là lúc tìm một con dê.\n\nĐể thuần hóa một con vật, bạn phải tiếp cận nó cẩn thận. Lén lút để tránh làm động vật cảnh giác. Chọn mồi nhử và ném nó gần con vật để thu hút sự chú ý của nó. Chờ con dê ăn, và cố gắng vuốt ve nó khi nó đang ăn để thiết lập mối liên kết. Bạn sẽ cần phải ở gần để vuốt ve con vật.\n\nLặp lại quá trình cho đến khi con vật bắt đầu tin tưởng bạn. Một khi nó cảm thấy thoải mái, bạn có thể nhấc nó lên.",
    [971610410] = "Hành động theo ngữ cảnh",
    [971904965] = "Rơi ra từ các trùm Kindlewastes Fell",
    [972139413] = "<craftingstation>Trạm nấu ăn</craftingstation>",
    [972166677] = "Tàu đắm",
    [972566172] = "Rìu Đồng Đỏ",
    [972620686] = "Chúng ta sẽ không chia sẻ hơi thở của mình với bạn",
    [972935479] = "Công thức chế tạo ẩn — Sảnh Hollow",
    [974407216] = "Cấu trúc kỳ lạ",
    [974442587] = "Đủ dũng cảm?",
    [975439446] = "(giữ) Tích lũy",
    [975680175] = "Thịt Chim Sống",
    [976035702] = "<location>Longkeep</location>",
    [976134141] = "Bộ Sửa Chữa",
    [976574044] = "Tia Sáng Hy Vọng",
    [977487346] = "Bộ Warlock",
    [977743583] = "Ba lô",
    [978464516] = "Khối Giếng",
    [978517292] = "Tăng số lượng người theo dõi và Cấp độ Ngọn lửa của bạn",
    [978792522] = "Lối Mòn Sàn Đá Giả",
    [979471501] = "Niên giám",
    [979477019] = "<b>Skillshot</b>\nĐánh trúng điểm yếu của kẻ địch, chẳng hạn như đầu hoặc tim lộ ra, được coi là Skillshot.",
    [979609854] = "Đoàn lữ hành phương Bắc",
    [979617068] = "Dọn sạch tất cả rễ Sương độc khỏi Springlands.",
    [980772996] = "Nhanh nhẹn",
    [980987233] = "Đến Orville",
    [981599500] = "\"Giữ chặt căn phòng cho đến hơi thở cuối cùng.\" Đó là lời của Cổ nhân, trước khi ông ta bước vào cùng một số chiến binh giỏi nhất của chúng ta. Đó là lần đầu tiên tôi nhìn thấy một người thuộc chủng tộc của ông ta, và tôi mong đó sẽ là lần cuối cùng. Khuôn mặt ông ta đã khắc sâu trong tâm trí tôi. Cuộc đời tôi, và những người lính còn lại của tôi, đều được cống hiến cho nhiệm vụ thiêng liêng này.\n— <lorename>Đội trưởng Arkwright</lorename>",
    [981973413] = "Lối vào Mộ ẩn",
    [982132847] = "Tôi đã nhìn thấy nó từ xa bên trong hang động — vàng rực trong bóng tối, nó gọi mời tôi.\nTôi không biết cây này là gì, nhưng nó đẹp. Phi tự nhiên. Và cách nó phát sáng... nó gần như có cảm giác muốn được tìm thấy.\nTôi chưa bao giờ thấy thứ gì như vậy. Tôi *phải* biết thêm.\nTôi đang tiến vào bây giờ. Nếu nguy hiểm — thì cứ để nó xảy ra. Một số thứ đáng để mạo hiểm.",
    [982367909] = "Bà Mẹ Người Tuyết",
    [982584940] = "Một món súp cà chua kem và thơm ngon, được làm thơm hơn với một miếng cá.",
    [983378498] = "mailto:datenschutz@keengames.com",
    [983484704] = "Thánh địa Ngọn lửa",
    [983521789] = "Vảy dài bằng đêm. Giá trị nhỏ hơn tương ứng với đêm ngắn hơn.",
    [984082292] = "Đế giày gia cố cho phép người mặc lén lút xuyên qua lớp cây cối rậm rạp mà không bị phát hiện, và nhanh chóng tiếp cận các điểm quan sát. Hoàn hảo cho một cuộc phục kích!",
    [984230246] = "Bảng màu này tràn đầy năng lượng và lễ hội, gợi lên tán lá tươi tốt và những lễ kỷ niệm vui vẻ.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Bồn nước Veilwater.",
    [984656212] = "Vật phẩm liên quan",
    [985192232] = "Cối Xay Nước Cải Tiến",
    [985302742] = "Đến Hầm mộ",
    [986460771] = "Trại buôn lậu",
    [986796361] = "Sảnh Hollow",
    [987219607] = "Một con Dê Frizzy trưởng thành có thể cung cấp sữa.",
    [987585682] = "Khai thác mọi vật liệu có giá trị trong Rừng Revel.",
    [987586667] = "Mẫu có sẵn",
    [987985355] = "Bột này có nguồn gốc từ cây Rễ Sáng, chỉ mọc vào ban đêm ở Thung lũng Veilwater.",
    [988426906] = "Bạn đã phát hiện ra địa điểm mà Ngư dân đã nói với bạn.\n\nNhìn xung quanh để tìm chiếc rương ẩn chứa bộ đồ câu cá!",
    [988517930] = "Đi theo Bọn cướp",
    [988847591] = "Cốc gốm",
    [988927788] = "Này Kẻ mang Lửa, muốn học điều gì đó mới không?",
    [989598518] = "Giường bị thiếu",
    [989788372] = "Bảng màu này có thể được tạo ra bằng vật liệu từ Cao nguyên Du mục.",
    [990347972] = "Giấc Mơ Ngọc Xanh Biển",
    [990370803] = "Tôi cứ nghĩ về \"Những người bạn Xương\". Chúng thật ma quái!",
    [990439633] = "Lưng Bạc Nướng",
    [991077534] = "Các <keyitem>Lưỡi cưa tròn</keyitem> đã bị Scavenger lấy đi đến một trại gần đó. Bây giờ, <b><keyitem>Lưỡi cưa tròn</keyitem> phải được chế tạo thành <craftingstation>Máy cưa bàn</craftingstation>.</b> Thợ mộc <npc>biết cách.</npc>",
    [991489221] = "Rơi ra từ kẻ địch Revelwood Fell",
    [991515352] = "Dao Găm",
    [991893827] = "Luống Trồng Cây",
    [994450359] = "Ba Lô Vừa",
    [994492409] = "Bò Hầm",
    [994541424] = "Một chiếc áo tunic được xếp lớp cẩn thận, buộc quanh ngực bằng sợi chỉ vàng. Vải dày, nhưng bồng bềnh. Nó sẽ cho phép thực hiện các bước di chuyển phép thuật nhanh chóng trong khi bảo vệ bạn khỏi cái lạnh buốt giá.",
    [995420380] = "Đũa Phép Ràng Buộc Chướng Khí",
    [995611920] = "<h2>1. Bộ điều khiển và liên hệ</h2>\n\nKeen Games GmbH\nDreieichstr. 59\n60594 Frankfurt am Main\n\nNếu bạn có bất kỳ câu hỏi hoặc đề xuất nào về chủ đề bảo vệ dữ liệu, vui lòng liên hệ với chúng tôi qua e-mail theo địa chỉ sau:",
    [995681912] = "Rơi ra từ nấm trong Sương độc của Springlands",
    [995872830] = "75 m × 75 m",
    [996107943] = "Tôi không thể lười biếng trong yên bình sao?",
    [997498006] = "Tổ hợp ban đầu",
    [998066477] = "Bình chưng cất",
    [999193110] = "Chăn nuôi",
    [999465844] = "Ngọc Khát Máu",
    [999730899] = "Bên dưới cây cầu cổ xưa này là một cây cung, nằm rải rác giữa xác chết của chiến trường này. Nó hẳn thuộc về một vị chỉ huy không may mắn bị Sương độc nuốt chửng.",
    [999843974] = "Tháo trang bị",
    [1000022148] = "<b>Đa Xạ:</b> \nBắn nhiều loạt đạn nhưng sát thương giảm.",
    [1000308541] = "%k (thêm %k)",
    [1000370940] = "Bình Đá Vôi Chạm Khắc II",
    [1001857067] = "Tìm kiếm Mỏ Aquamarine Gần Đây",
    [1001900675] = "Quân Cờ Vua",
    [1002269382] = "Hôm qua chúng lại kéo đến ầm ầm. Lũ mọi rợ cháy nắng. Chúng vặn vẹo và làm biến dạng cơ thể mỗi khi cúi đầu trước các vị thần của chúng, những thần tượng của chúng, những Kẻ Cổ Đại. Quá nhiều miệng ăn. Chúng chỉ muốn xin bố thí. Ta sẽ tống cổ chúng về Vùng Đất Lửa.\n\n<i>Chúng sẽ không lừa được ta đâu. Ta đã chôn kho báu của mình trong mảnh đất có rào chắn dưới mái che nhỏ, không xa đây. Chúng sẽ không tìm thấy nó khi nó bị vùi dưới bùn.</i> Đêm nay, ta sẽ ngủ ngon lành.",
    [1002565020] = "Một loại cây phổ biến nhờ sợi dai của nó. Có thể dùng để làm vải lanh.",
    [1002596840] = "Bộ trang phục thầy thuốc cổ điển với túi rộng để đựng thuốc bổ.",
    [1002706119] = "Thiết kế theo kiểu lông vũ của mũi tên, vũ khí này thể hiện sự tàn bạo thực sự khi đánh bại bạn bè hay kẻ thù.",
    [1003072345] = "Bạn đã khám phá ra vị trí của Sảnh Hollow Lò xo. Hãy xuống — khi bạn sẵn sàng — để tiết lộ những gì nằm bên dưới. <b>Nên tập hợp một đội nếu bạn không chơi một mình.</b>",
    [1003083482] = "Trên Nấm",
    [1003468541] = "Chúng ta nên nấu món gì đó ngon và ấm bụng, bạn thấy sao?",
    [1003591017] = "Chiếc quần có thể trông không có gì đặc biệt, nhưng chúng thực sự làm tốt nhiệm vụ bảo vệ mạng sống của bạn trong trận chiến.",
    [1003723547] = "Tốc độ hồi phục SP từ đồ ngọt tăng <b>50%</b>.",
    [1004160854] = "Kiếm dài Hoàng Hôn",
    [1004357945] = "Nói chuyện với Emily Fray về Lời Nguyền của <lorename>Elin</lorename>",
    [1004435994] = "Mũ Hề",
    [1004629962] = "XeSS là một kỹ thuật khử răng cưa tiên tiến. Giảm chất lượng sẽ tăng hiệu suất.",
    [1005014530] = "Đánh trúng kẻ địch sẽ đặt một dấu <img gemeffect_stormseye> lên chúng trong %k. Đánh trúng kẻ địch bị đánh dấu <img gemeffect_stormseye> sẽ gửi một tia sét đến kẻ địch bị đánh dấu <img gemeffect_stormseye> khác, gây %k sát thương. Đòn tấn công có thể lan sang nhiều kẻ địch bị đánh dấu.\n\nSau khi sét đánh trúng, hiệu ứng sẽ có %k thời gian hồi trước khi có thể kích hoạt lại từ cùng một kẻ địch. Sau thời gian hồi, dấu <img gemeffect_stormseye> sẽ được làm mới.",
    [1005123782] = "Một đôi ủng nhẹ cho phép di chuyển nhanh nhẹn khi lội qua tuyết và bão tuyết. Bạn có thể trinh sát các rìa băng giá của núi hàng dặm khi đi đôi giày này!",
    [1005494525] = "Kẻ Lang Thang <lorename>Bí Ẩn</lorename> Xuất Hiện",
    [1005569231] = "Bao Quanh Bởi Sự Hèn Nhát Và Bí Mật",
    [1006278772] = "Thoáng Nhìn Về Cõi Vĩnh Hằng",
    [1006865167] = "Khai thác ngọc tại Lò Rèn Ngọc trước khi xóa hoặc bán nó.",
    [1007858054] = "Tăng lượng HP được Chữa thương khi hồi HP cho nhân vật.",
    [1008381543] = "Đã tìm thấy Máy Chủ",
    [1008605143] = "Âm nhạc gợi lên những tia nắng rực rỡ và hơi nóng bỏng chân trên một cuộc hành trình ngàn dặm.\n\n<b>Bản Nhạc:</b> \nBản nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ bản nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ giúp họ học được bài hát.",
    [1008755443] = "Đèn Treo Thép",
    [1009726516] = "Mũ Thợ Lặn",
    [1010071858] = "Lưỡi Hái Fell",
    [1010173521] = "Nông dân Emily có vẻ sợ Sinh Vật Fell. Bạn của cô ấy, thợ cắt tóc Elio, muốn xoa dịu nỗi sợ hãi của cô ấy!\n\nAnh ta nghĩ rằng những sinh vật này có thể không đáng sợ đến vậy nếu được miêu tả như những chú gấu bông mềm mại, và anh ta đã đề cập rằng anh ta thường thấy trẻ con chơi với đồ chơi như vậy ở thủ đô.\n\n<b>Hãy đến thành phố chính và tìm một con thú nhồi bông ở đó để cho Emily xem!</b>",
    [1010386680] = "Khi bạn nhận sát thương <b>Phép thuật</b>, bạn có <b>10%</b> cơ hội hồi <b>1</b> MP cho mỗi điểm HP bị mất.",
    [1010441717] = "Ký ức của bạn sẽ sống mãi.",
    [1010457083] = "Ta có thể sửa sang lại nơi này... Nếu ta có một ít <craftingstation>Dụng Cụ Xây Dựng</craftingstation>! Nhưng ta không thể, vì ta đang đứng đây tay không! Giúp ta một tay nhé, được không?",
    [1010873457] = "Về Hàng Hóa",
    [1011074247] = "Một bộ dao găm với kỹ thuật chế tác phương Đông cổ xưa. Những tên đạo tặc thời đó sẽ vung chiếc đoản kiếm ngắn này trong trận chiến, khiến cát xung quanh xoáy lên và làm mù kẻ địch.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1011078558] = "Nửa Thùng Gỗ",
    [1011085755] = "Bể III",
    [1011544581] = "<craftingstation>Phòng Thí Nghiệm</craftingstation>",
    [1011956831] = "Ta không biết làm sao để liên lạc với ngươi, Ramone. Ngươi đã biến mất khỏi trái đất này... nhưng ít nhất ngươi biết nơi tìm ta, nên ta để lại cho ngươi thứ này.\n\nBức tượng của nữ hoàng quá cố của chúng ta, Nữ hoàng <lorename>Pikemead</lorename>, sẽ bị ném một cách thô bạo xuống biển và chìm xuống đáy đại dương khi đồng hồ điểm mười hai. Ta không thể ngăn chặn sự điên rồ này, nhưng ta đã giữ lại một mảnh. Những người công nhân cảng cũng vậy. Vua Gormander sẽ không nghe lời yêu cầu của ta. Ông ta muốn xóa bỏ hình ảnh của bà khỏi \"khu vườn\" mới của mình.\n\nXin hãy đốt lá thư này sau khi đọc, và mang theo mảnh tượng. Ta không thể để thư từ của chúng ta khiến ta gặp rắc rối. Chúc ngươi may mắn. Vinh quang cho Nữ hoàng <lorename>Pikemead</lorename>, mãi mãi.",
    [1012042169] = "Giáp Sốc",
    [1012220082] = "Chỉ bước đi nơi bạn không bị nhìn thấy, tấn công những kẻ bị ánh sáng của bạn làm mù mắt trong ánh sáng lờ mờ.\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n<b>Khéo léo:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính khéo léo của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.\n\n",
    [1012360226] = "Sở hữu chiếc cúp vàng này chứng tỏ bạn đã né tránh mọi nhát kiếm và đánh bại đối thủ bằng lực tập trung.\n\nThu thập nhiều Đầu Sấm Sét Fell để chế tạo Cúp Vàng.",
    [1012404994] = "Về Hỏa Sinh",
    [1013028145] = "Xe Kéo",
    [1013318740] = "Với những tấm lợp chắc chắn này, ngôi nhà của bạn được bảo vệ tốt.",
    [1013681207] = "Chúng Ta Phải Chọn!",
    [1013721757] = "Máng Ăn Mèo",
    [1014002999] = "Mảnh Khảm Ngọn Lửa I",
    [1014060790] = "Truyện Kể Xứ Xa",
    [1016188023] = "Tiền Đồn Thương Mại \"Rye Cũ\"",
    [1016622292] = "Hỡi Hỏa Sinh! Ngươi mang theo Thuốc Tiên. Làm ơn, ta cầu xin ngươi hãy cẩn thận. Nó mang đến sự mục nát và cái chết! Ta đã chứng kiến nó xảy ra. Ban đầu, nó có vẻ làm cơ thể mạnh mẽ hơn, nhưng nó làm mục nát tâm trí! <b>Xin đừng uống Thuốc Tiên!</b>",
    [1016667052] = "Trái Tim Sa Ngã",
    [1016760121] = "Đặt vào Trưng Bày",
    [1016892911] = "Bạn có %k cơ hội nhận sát thương bạn gây ra dưới dạng MP.",
    [1016968452] = "Xin chào!",
    [1017009506] = "Ta thậm chí sẽ không phàn nàn về việc bị \"nguyền rủa phải chịu đựng và mục ruỗng trong cái lạnh khắc nghiệt\". Ta đã từng ở sau song sắt, ta hiểu.\n\nNhưng chúng ta có thể <i>làm ơn thêm một ít đèn được không?</i> Ta không nhìn thấy xa hơn năm bước, và ta cứ vấp phải xương cốt vương vãi. Không biết ta có làm bong gân mắt cá chân không, nhưng ta vẫn giật mình mỗi lần.\nChỉ vì chúng ta đã bị định đoạt không có nghĩa là chúng ta không thể có thêm một ít <b>đuốc</b> ở đây, phải không?",
    [1017032174] = "Một Ngôi Mộ Cho Tất Cả Những Ai Đã Mất",
    [1017137810] = "Ẩn/Hiện Mật Khẩu",
    [1017329811] = "Bia Mộ \"Mãi Mãi Trong Tim Chúng Ta\"",
    [1017376611] = "Khe Ngọc Trống (khóa)",
    [1017578324] = "Sữa Dê Lông Xù",
    [1018183401] = "Đền Drak'Dal",
    [1018710728] = "Bạn có muốn nghe một bài hát không?",
    [1018754584] = "Tủ Quần Áo Gỗ Thô Sơ",
    [1018956519] = "Nỗi Kinh Hoàng",
    [1018964376] = "Trượng Của Người Chăn Cừu",
    [1020046723] = "Dâu Tây",
    [1020082128] = "Cây Xương Rồng Con",
    [1020337831] = "Nến Hầm Mộ",
    [1021163939] = "Đạn Băng I",
    [1022330315] = "Đài Lửa Thép Gắn Tường Nhỏ",
    [1022360938] = "Lửa Trại",
    [1023561067] = "Nhà Giả Kim đã cảnh báo về việc sử dụng Thuốc Tiên <b>Tuyệt đối không được uống nó, bất chấp những lợi ích của nó.</b>",
    [1023579753] = "Một món ăn chính trong nhiều món ăn truyền thống của Revelwood. Nó có tác dụng phục hồi.",
    [1023855816] = "Bồn Tắm Đồng Thiếc",
    [1024738990] = "Obelisk Cổ Đại",
    [1024868911] = "Khởi Hành",
    [1024880174] = "Chế Tạo Thủ Công",
    [1026044439] = "Cửa Đôi Đá",
    [1026194080] = "Tìm kiếm Máy Chủ",
    [1026732273] = "Cài đặt Máy Chủ hiện tại không hợp lệ. Vui lòng cấu hình chúng trước khi bắt đầu một phiên.",
    [1027382388] = "A-hô-y!",
    [1027458360] = "Áo Chẽn Người Khôn Ngoan",
    [1028242286] = "Hồi phục HP",
    [1028452660] = "Xác nhận",
    [1028532530] = "Từng khối một!",
    [1028623165] = "Đánh bại Vòi Rễ của Vực Thẳm",
    [1028731270] = "Chiếc khiên này, được tẩm bởi Ngọn lửa, cho phép bạn <b>Đỡ</b> các đòn tấn công vật lý. Đỡ làm tiêu hao SP.",
    [1028857372] = "Lựa chọn thiết bị",
    [1028941083] = "Quần Mắt Đại Bàng",
    [1029351504] = "Nhắm mục tiêu vào một cây để xem trạng thái của nó.",
    [1029517674] = "Lối Vào Hang Động",
    [1029636775] = "Đôi ủng đơn giản, thoải mái này rất phù hợp để đi dạo vào một ngày hè ấm áp.",
    [1029685887] = "Cấu hình",
    [1029945500] = "Một chiếc mũ đầy màu sắc và hào nhoáng, thường được đội bởi các nhà thơ, nhạc sĩ, hoặc thương nhân hàng hóa xa xỉ.",
    [1030324141] = "Sự Thấu hiểu Sương độc của <npc>Nhà sưu tầm</npc>",
    [1030393623] = "Hãy bám sát con đường, kẻo lũ tay sai của Sương độc bắt được ngươi. Sự cứu rỗi nằm thẳng phía trước.",
    [1030438664] = "Một kim loại hiếm và quý giá nhờ khả năng dẫn nhiệt của nó. Nó thường được dùng để chế tạo những vật phẩm đòi hỏi nhiệt độ cao.",
    [1030492424] = "Một bức tượng của nữ hoàng quá cố <lorename>Pikemead</lorename>. Một dòng khắc dưới đáy đọc rằng:\n\nQuây quần lại nào, ta nâng cốc!\nBài ca ca ngợi Nữ hoàng, khi còn trẻ!\n3 đứa con trên tay, cốc đầy tràn.\nSuy nghĩ vu vơ, nàng đã hát!",
    [1031263826] = "Nửa sau của một bức treo tường, mô tả mối quan hệ cộng sinh phức tạp giữa tự nhiên và ma thuật. Khi ghép với nửa còn lại, có lẽ trí tuệ cổ xưa này sẽ được thấu hiểu.",
    [1031737790] = "Mặc dù ngươi đã chứng kiến cảnh tượng này vô số lần, nó vẫn toát lên vẻ đe dọa và phấn khích cùng một lúc.\n\nThu thập nhiều Đầu Quái Vật Fell để chế tạo Cúp Vàng.",
    [1032425994] = "Lăng mộ của Nữ hoàng",
    [1032529895] = "Tăng cường phép thuật Băng",
    [1033427593] = "Dân làng",
    [1034126426] = "<lorename>Talion</lorename>!",
    [1034646645] = "Ốc đảo Capybara",
    [1034672282] = "Ngươi đã lần theo dấu vết của bọn cướp đã cướp bóc của Mei. Cuộc điều tra đã dẫn ngươi đến một bức thư tiết lộ địa điểm được cho là của từng vũ khí bị đánh cắp.\n\nCây Gậy phép chúc mừng Tết Nguyên Đán được cất giữ dưới ngôi nhà lớn ở <location>Netherton</location> bên trong một hầm rượu bí mật gần mặt nước, có thể tiếp cận từ bên ngoài.\n\nTìm địa điểm và lấy lại cây Gậy phép!",
    [1034918088] = "Tìm <craftingstation>Cối</craftingstation> của <npc>Nhà Giả Kim</npc> để mở khóa <b>nhiều công thức chế tạo hơn.</b> Nó được giấu trong <b>Tháp Nhà Giả Kim ở <location>Lone Thistle</location></b>, đâu đó dưới lòng đất.",
    [1034920497] = "Đặt <keyitem>Dụng Cụ Rèn</keyitem>",
    [1034971325] = "Gia Vị",
    [1035568991] = "Mảnh Cắt Linh Thể",
    [1035843244] = "Cờ Lệnh Dọc II",
    [1036027155] = "Hoàn thành",
    [1036387881] = "Điều tra Khu vực Biểu diễn",
    [1036502870] = "Khát máu",
    [1036592380] = "Tăng sát thương lên kẻ địch tầm xa.",
    [1037374948] = "<craftingstation>Sách Cây Cối và Hạt Giống</craftingstation>",
    [1037575058] = "Quần Học Giả Ngọn Lửa Trẻ",
    [1038063438] = "Chế tạo Móc Leo Cải Tiến",
    [1038065508] = "Tiền đồn bị Chuột Hoành hành",
    [1038091306] = "Trong Bệnh Tật Và HP",
    [1038099033] = "Trang trại Cloverbrook",
    [1038891554] = "Chùy Lông Vũ",
    [1039649390] = "Quần Dân Du Lâm",
    [1039698881] = "Nhảy",
    [1040193035] = "Bánh xe vật phẩm nhanh",
    [1040792021] = "Vách Ngăn Phòng III",
    [1040860542] = "Rìu Sấm Sét Lớn",
    [1041384293] = "Công cụ & Linh kiện",
    [1041754737] = "Một chút che chắn khỏi thời tiết sẽ giúp tôi rất nhiều. Khi nào có dịp, tôi sẽ rất cảm kích.",
    [1042231101] = "Quần Lông Thú",
    [1042277883] = "Chọn một cần analog",
    [1042424692] = "Xuyên thủng kẻ thù qua tim — không cần dùng sừng của ngươi.",
    [1042427302] = "Dê Lông Xù Con",
    [1042465877] = "Ma thuật Hắc ám",
    [1042738409] = "Đấng cứu thế của ta, ta đã nhìn thấy cả thế giới rộng lớn — nhưng ngay lúc này, ta chỉ muốn được nằm trên một chiếc giường ấm áp dưới mái nhà khô ráo. Ta chắc chắn ngươi có thể tạo ra thứ gì đó tuyệt vời cho ta!",
    [1042854961] = "Đền Ngọn lửa",
    [1043455202] = "Một băng đô thể thao với các chi tiết vàng. Nó hợp với thắt lưng của bộ đồ và khiến bạn cảm thấy như người cai trị Thế vận hội Mùa hè!",
    [1043571392] = "Kích hoạt cơn đói và suy dinh dưỡng. Ngươi sẽ cần ăn hoặc uống thường xuyên để tồn tại.",
    [1044246098] = "Làm chủ các Sảnh Đường Hollow của Đỉnh Albaneve",
    [1044557523] = "Mạng Nhện I",
    [1045097969] = "Trại khai quật Obelisk",
    [1045648853] = "Đũa Phép Của Học Giả",
    [1045707585] = "Một nơi làm việc sẽ cho phép những khả năng chế tạo mới cho <npc>Thợ Rèn</npc>.",
    [1045912032] = "Vào Chế độ Xây dựng",
    [1046431269] = "Ngay cả sau nhiều tuần trên đường, chiếc quần này vẫn sẽ thoải mái và còn nguyên vẹn.",
    [1046665473] = "Ta cá là ngươi sẽ bắt được một con lớn đấy!",
    [1048066026] = "Vuốt Sói",
    [1048722968] = "Có Thích Lãng Mạn Một Ngày Bão Tố Không?",
    [1049191788] = "Một đôi ủng được chế tác tinh xảo. Chúng được trang trí bằng những chiếc khiên phun Ngọn lửa, một đám cháy rừng dữ dội chỉ được ngăn chặn bằng sự cảnh giác.",
    [1049437747] = "Những bộ xương này lớn hơn bình thường rất nhiều và cực kỳ chắc chắn.",
    [1050665477] = "Ngọc Hắc Ám",
    [1050799072] = "Song Sắt",
    [1050919394] = "Ngươi đã thắp lên Ngọn Lửa trên Đỉnh Tháp Cổ. Ngươi biết rằng, mặc dù xa xôi, những vùng đất hoang vu đóng băng không hề bị bỏ mặc. Lính phương Bắc đã mở rộng lãnh thổ của họ đến đây và xây dựng Giếng Thuốc làm ô nhiễm tuyết và cư dân cổ đại của núi.\n\nNgươi phải tìm Giếng Thuốc chính và tiêu diệt thế lực xấu xa bị tha hóa ẩn náu bên trong để giành lại núi non! \n\n<b>Đừng đi mà không chuẩn bị. Ngươi sẽ cần quần áo ấm, thức ăn, hoặc đuốc để giữ ấm</b> trong cái lạnh khắc nghiệt.\n<b>Bộ đồ len và bộ đệm ấm</b> sẽ hữu ích cho việc <b>chế tạo giáp ấm.</b>",
    [1051328333] = "Tốc độ chạy khi bơi",
    [1051356023] = "Tìm Kho Hàng của Thương Gia",
    [1051537456] = "Đọc Obelisk Springlands về Ngọn lửa",
    [1051641239] = "Xương Khổng Lồ Băng Giá",
    [1051681927] = "Hủy bỏ",
    [1051944337] = "Một quả dừa tươi, hái trực tiếp từ cây dừa. Nước bên trong có thể uống trực tiếp hoặc chế biến thành sữa.",
    [1052853466] = "Tàn tích Scavenger",
    [1052864132] = "Oxygen Tối đa",
    [1052948332] = "Chọn Bản Thiết Kế",
    [1053367547] = "Đũa phép Phù Thủy",
    [1053423452] = "Sau khi tấn công một kẻ địch không đề phòng bằng đòn tấn công tầm xa, ngươi có 50% cơ hội tránh bị phát hiện. 100% nếu mục tiêu bị tiêu diệt.",
    [1053561812] = "Lưỡi Dao Rùng Mình",
    [1055132861] = "Khung Cửa Sổ Bằng Thép Tròn Lớn",
    [1055523887] = "Bánh Xe Kéo Sợi",
    [1055792217] = "Thợ săn đã chia sẻ địa điểm săn bắn bí mật của cô ấy với ngươi. <b>Hãy điều tra khu vực</b> để xem có gì ở đó!",
    [1056099193] = "Sạc & Ném",
    [1056636654] = "Sáng sớm, ta đang vận hành cối xay... Nó kêu cọt kẹt ghê lắm. Ta cố gắng hơn nữa — có thứ gì đó chặn cối xay.\n\nThật kinh hoàng, một kẻ ngốc nào đó đã leo vào bên trong, bị rễ cây vùi lấp! Cơ thể hắn sưng phồng lên. Nước thịt thực vật rỉ ra từ môi hắn.\n\nTa moi ra những gì còn sót lại của hắn và giấu <b>dưới ván sàn cạnh cối xay</b> trước khi tiếng chuông buổi sáng vang lên. Nếu người đứng đầu bộ phận vệ sinh phát hiện ra, ta sẽ mất khoản tiền thưởng của mình.",
    [1056862708] = "Đánh thức Người Sống Sót",
    [1057273797] = "Hãy tóm lấy một con thú nhồi bông!",
    [1057316703] = "Sửa đổi hoặc Đặt lại Cây Kỹ năng",
    [1057487838] = "Đôi găng tay tuyệt vời để đào bới bí mật, khám phá kho báu hoặc lập bản đồ những vùng đất chưa từng được biết đến!",
    [1057940447] = "Olric luôn có một cách nhìn nhận kỳ lạ. Nơi ta thấy nguy hiểm, hắn thấy kỳ diệu. Đặc biệt là với những loài cây chết tiệt đó — những Dây leo Độc hại. Những thứ độc dược, đầy chất độc, bắn thứ gì đó không rõ vào bất cứ thứ gì di chuyển.\nHắn đã kéo ta ra tận đây, cười toe toét như một đứa trẻ. Nói rằng hắn chưa bao giờ thấy nhiều như vậy ở một nơi. Bảo ta xem – rồi hắn để một cái đánh trúng hắn. Ngay trên đầu. Cười xòa như không có gì.\nTa nghĩ hắn bị điên. Nhưng hắn trông… ổn. Hơn cả ổn, như thể hắn đã đạt được điều gì đó từ nó.\nTa cũng định thử. Thật đấy, ta đã định.\nTa không thể làm được – có lẽ ta chỉ là một kẻ hèn nhát.",
    [1058132198] = "<b>Nhà thờ ở <location>Woodgard</location> giấu các khối xây dựng</b> bên trong. Dân làng muốn dùng các khối để <b>sửa mái nhà</b>. Tìm các khối để có được vật liệu xây dựng mới!",
    [1058567321] = "Nấu một số món ăn giữ ấm",
    [1058706812] = "Ở <location>Brightwich</location>, ngươi tìm thấy một bức thư chi tiết về cuộc đấu tay đôi của Gabrielle Fairburn với \"Kẻ Hủy Diệt <location>Brightwich</location>\".\n\nBức thư mô tả rằng bất kỳ ai thua cuộc đấu sẽ bị ràng buộc không bao giờ \"nhìn thấy ánh sáng ban ngày\" nữa. Gabrielle nói với ngươi rằng cô ấy đã thắng cuộc đấu, nhưng nói thêm rằng đối thủ của cô ấy sẽ không chết hẳn.\n\nTìm nơi kẻ thù đang ẩn náu ở <location>Brightwich</location>!",
    [1058833715] = "Vậy, bạn còn chờ gì nữa? Hãy thử nướng một con cá và xem nó ngon như thế nào!",
    [1058873782] = "Tôi nghiên cứu những tác động tích cực của các bản giao hưởng! Tôi giả thuyết rằng sự hiếm có và uy tín của nhạc cụ có ảnh hưởng tâm lý đến — à, điều đó không quan trọng. Tôi muốn bạn tìm những nhạc cụ hoành tráng! Tôi nghe nói các ngôi đền Kindlewastes đang giấu một vài cái. Tôi biết địa điểm, nhưng không biết cái nào có nhạc cụ... làm ơn giúp tôi!",
    [1059397242] = "Cúp Danh Năng Khổng Lồ Mắt Một Bằng Đồng",
    [1059803488] = "Tuyết trắng như bột. Cách nó át đi âm thanh của sự hỗn loạn khiến thế giới có vẻ yên bình hơn một chút.\n\n<b>Thoát nước</b>\nChất liệu này <b>thoát một lượng nhỏ nước</b> khi bị tràn.",
    [1060686569] = "Ngay cả một chiếc khiên đơn giản như thế này cũng có thể cứu mạng ngươi khi ngươi bị bao vây, hoặc bất ngờ.",
    [1060770439] = "Một mũi tên gắn một mảnh Obsidian sắc bén.",
    [1061106125] = "Ngươi cũng có thể truy cập các công thức Chế tạo Thủ công và ba lô của mình tại các trạm chế tạo.",
    [1061171932] = "Một cuộc hạ cánh khá phiêu lưu, nhưng tôi khá hài lòng về mặt khác. Sau tất cả, tôi đã tìm thấy một <b>Đền Lửa.</b>\n\nTôi suy đoán rằng các Tiền Nhân để lại một Tia Lửa sau khi họ qua đời. Ánh sáng của họ hòa vào <i>ngọn lửa và thấm nhuần mọi kiến thức</i> thu thập được trong suốt cuộc đời họ. Tuy nhiên, đôi khi, họ nghỉ ngơi trong những đền thờ này, trên đỉnh vách đá hoặc giữa những hang động xa xôi... Họ đang che giấu những lời thì thầm trí tuệ nào?\n\n...Ngoài ra, làm thế nào để xuống khỏi đây?\n— Balthazar",
    [1061235319] = "Quần Thợ Tiều Phu",
    [1061702235] = "Kiếm Rỉ Sét",
    [1061758466] = "Hóa thạch nhỏ",
    [1062249381] = "Hiển thị Văn bản Thuộc tính Sát thương",
    [1062440003] = "Sát thương vũ khí tầm xa tăng <b>10%</b>.",
    [1062678289] = "Dụng cụ để phác thảo. Cái này nên để trong tầm tay của một <npc>Thợ Mộc</npc>.",
    [1063448339] = "Quần Thợ Săn Chim",
    [1063450392] = "Sát thương Vũ khí Cắt bổ sung",
    [1064571239] = "Hút SP",
    [1064968607] = "Khối Mái Lá Cọ",
    [1064989776] = "ST Lén lút",
    [1065168470] = "Ghế Dài Gỗ Phương Bắc",
    [1066643235] = "Pháp Sư",
    [1067070608] = "Hữu ích cho các mục đích giả kim và ma thuật.",
    [1067304795] = "Khoai Môn Sống",
    [1067500236] = "Đôi khi ta cảm thấy như cá mắc cạn.",
    [1067982698] = "Nơi này cần một quán rượu!",
    [1068677185] = "Ma-nơ-canh \"Lùi Lại\"",
    [1069508910] = "Quả bom này chứa một chất lỏng dễ cháy, sẽ thiêu rụi một khu vực rộng lớn khi được triển khai.",
    [1069960446] = "Ngươi vẫn còn ở đây à?",
    [1070099176] = "Kiểm tra cây trồng trong khu vực được bảo vệ bởi Ngọn lửa.",
    [1070575352] = "Chim Đuôi Đỏ Mỏ Tròn",
    [1070888780] = "Tượng Chú Lùn Sân Vườn Cầm Kiếm",
    [1071164389] = "Làm đầy bằng đạo cụ",
    [1071314529] = "Ta có thể yếu đuối một chút được không? Khi ta bị ném qua mỏm đá đó ở <location>Pháo Đài Kelvin</location>, ta đã đập đầu, nên đầu óc ta hơi mơ hồ. Ta nhớ tên mình, nghề nghiệp của mình, và đã bò về phía một... \"ánh sáng thiên đường\"? Đó là tất cả. Điều tệ nhất: ta quên cách làm thuốc nhuộm tóc! Ta thậm chí còn không nhớ cách làm màu \"đỏ\" cơ bản! Nếu ngươi tìm thấy bất kỳ ghi chép nào về màu tóc, hãy báo cho ta biết, được chứ?",
    [1071482069] = "Rơi ra từ Sấm Sét Fell trong Sương độc",
    [1071689193] = "Một <craftingstation>Lò Luyện Kim</craftingstation> đã được nâng cấp với ống thổi để tạo ra kim loại tốt hơn.",
    [1071829137] = "Trở Về Từ Vực Sâu",
    [1071911622] = "Thú Cưng",
    [1072444774] = "Tăng cường mũi tên xuyên phá",
    [1072716331] = "<location>Suối Muối</location>",
    [1072972830] = "Một công cụ khá tốt được rèn từ đồng. Ít nhất thì làm việc cũng không trở thành gánh nặng vì thiết bị tồi.",
    [1073228234] = "Thanh Tẩy",
    [1073570213] = "Không có gì là thiêng liêng. Ba mũi tên găm vào sườn Casper — và cột sống của Marcus chắc chắn bị nứt... chúng tôi đã đưa anh ấy đến nơi an toàn, trong khi lửa mưa xuống chúng tôi. \nChúng tôi đã bị Fell tấn công vào lúc chạng vạng khi Fell bò vào. Than ôi, chúng tôi được ban phước vô cùng. Trong khi được bao phủ trong ánh sáng thánh, Fell sẽ không đến gần... Hoặc có lẽ nơi trú ẩn của chúng tôi là kết quả của lời chúc phúc của Emily Fray.\n\nTôi cầu nguyện <b>tuyến đường vận chuyển phía nam</b> của họ sẽ ít nguy hiểm hơn của chúng tôi. Tôi phải đặt bút xuống. Casper khóc. Anh ấy cần được an ủi.\n— <lorename>Raúl</lorename>",
    [1074334563] = "Trạng Thái",
    [1074650272] = "Nhật ký đã cập nhật!",
    [1074938150] = "Kháng Cự",
    [1075219715] = "Ngươi có con mắt tinh tường đấy, Hỡi Kẻ Lửa!",
    [1075367671] = "Sửa Chữa",
    [1075481875] = "Nói ngắn gọn thôi!",
    [1075626368] = "Tất cả sát thương <b>Đâm Lén</b> đều tăng thêm <b>25%</b>.",
    [1076044437] = "Bãi Rác <location>Cuối Đường Glennwood</location>",
    [1076091705] = "Rìu Tia Chớp",
    [1076151935] = "Rất tốt. Đừng bao giờ đánh giá thấp sợi chỉ! Khi đủ mạnh, nó có thể vá mọi vết thương... hoặc bịt kín mọi cổ họng. Đặt <craftingstation>Khung Cửi</craftingstation> nếu ngươi muốn đi thẳng vào vấn đề.",
    [1076315989] = "Tăng ST Đập Thường",
    [1076367991] = "Tạo Khóa Tùy Chỉnh",
    [1076491361] = "Một món cà ri thơm ngon với nhiều vị cay và đậm đà. Nó sẽ khiến bạn cảm thấy ấm áp và dễ chịu!",
    [1076794261] = "Nghiêng về phía trước/sau",
    [1077149706] = "Cẩn trọng",
    [1077222728] = "Bàn Thờ Ngọn lửa Cấp 2",
    [1077724719] = "Đài Lửa Gắn Tường Phòng Ngai Vàng",
    [1078258141] = "Một chất lỏng dễ bay hơi, có tính axit thu hoạch từ Kẻ địch Fell yếu. Đặc tính ăn mòn của nó làm cho nó trở thành một nguyên liệu có giá trị trong việc chế tạo bộ sửa chữa, nơi hóa học độc đáo của nó được khai thác để khôi phục độ bền của các vật phẩm đã hao mòn.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Kẻ săn mồi Fell, ban đầu tìm thấy ở Cao nguyên Du mục.",
    [1078725208] = "Chế tạo tại Lò Than",
    [1079470751] = "Một vài <keyitem>Lưỡi Cưa Tròn</keyitem> đã được tìm thấy. Chúng có thể được chế tạo thành <craftingstation>Máy Cưa Bàn</craftingstation> với <npc>Thợ Mộc</npc> để cho phép các công thức chế tạo nâng cao hơn.",
    [1079691446] = "Lại đây một chút, được không? Nghe này, ta phải hỏi... những tàn tích đền thờ bị ngập nước đó: tại sao lại xây dựng ở nơi hoang dã nhất và hồ sâu nhất nếu không có gì để giấu? Có lẽ... ồ, ta không biết: tiền vàng, nháy mắt nháy mắt? Ta phải nói \"nháy mắt nháy mắt\" thành tiếng vì ta chỉ có một mắt. Có thể trông như ta đang chớp mắt. Ngoài ra, ta nghe nói tất cả các doanh nhân đều nháy mắt. Ta không đặt ra luật lệ!",
    [1080115672] = "Ngươi đã đến tổ của lũ kền kền. Nửa còn lại của tấm treo tường không còn xa.\n\nTìm kiếm tổ kền kền được đánh dấu trên bản đồ của ngươi!",
    [1080279016] = "Manocanh",
    [1080468510] = "Da Bò Sát Thuộc",
    [1080930308] = "Đạt cấp 15.",
    [1081282550] = "Một quả chuối chín vàng. Nó có thể ăn sống hoặc dùng trong món ăn khác — tất nhiên là không có vỏ.",
    [1081449798] = "Đặt Chó Vào Nhà Của Ngươi",
    [1081878541] = "Chúng ta sẽ gặp lại nhau.",
    [1082008733] = "Ngươi đã tìm thấy địa điểm của ngôi đền rắn bị lãng quên từ lâu. Chắc chắn có những vật có giá trị bên trong.\n\nTìm kiếm ngôi đền và cướp bóc nó để nhận được cây cung Tết Nguyên Đán!",
    [1082175187] = "Kiếm Chế Tác Đá",
    [1082484557] = "Chìa Khóa Bạc",
    [1082558359] = "Len Sống",
    [1082979017] = "Oxygen",
    [1083413532] = "Bình Tưới Nước",
    [1083539465] = "Trúng Độc",
    [1083601982] = "Ta mất ba ngày để vá sàn nhà cho Lão Olson. Ta đã đề nghị sửa bánh xe trên chiếc xe ngựa của ông ta, nhưng ông ta quyết tâm ở lại cho đến cuối cùng.\n\nMọi chuyện bắt đầu trong khu vườn của ông ta. Mặt đất mềm đi, dịch chuyển, và cuối cùng bị nuốt chửng cùng với những đám cỏ chết bởi một vết nứt nhỏ. Khi ánh sáng ban mai chiếu vào, sân sau của ông ta đã bị thay thế bởi một cái miệng há hốc. Ta vội vàng xây hàng rào và gia cố cấu trúc, nhưng khi mặt trời lặn, ngay cả chúng cũng chìm xuống dưới. Cái hố đã lớn hơn. Lẽ ra ta nên đuổi ông ta đi lúc đó, dù có xe ngựa hỏng hay không.\n\nSáng nay, căn nhà của Olson đã biến mất không còn dấu vết, bị bóng tối nuốt chửng. Ban đầu, ta hy vọng ông ta đã trốn thoát — vì ta không nghe thấy tiếng khóc hay la hét nào. Nhưng hóa ra, cái miệng há hốc còn nuốt cả âm thanh.\n\nTa đặt búa xuống và đóng gói hành lý. Ta sẽ không đợi để bị nuốt chửng như Olson và đám cỏ.",
    [1083853523] = "Tạm dừng sản xuất để thay đổi công thức",
    [1084077747] = "Nhìn chiếc mũ bảo hiểm này khiến người khác cảm thấy an toàn và yên tâm.",
    [1084236782] = "<npc>Thợ Mộc</npc>",
    [1084419255] = "Ngươi có muốn thêm máy chủ này không?",
    [1084567140] = "Vực Thẳm Nuốt Chửng Tất Cả",
    [1085074901] = "Số Lượng Người Chơi + Giao Tiếp",
    [1085091156] = "<craftingstation>Bàn Chế Tạo</craftingstation>",
    [1085144994] = "Chiếc quần có dây đeo này sẽ tạo dáng hoàn hảo cho dù ngươi ăn thịt nai hay cháo cho bữa tối.",
    [1085591847] = "Sức Mạnh Gậy Phép",
    [1085947007] = "Khối Gỗ Half-Timbered Của Ta",
    [1086304340] = "Găng Tay Kẻ Săn Mỹ Nhân Ngư",
    [1086354706] = "Suỵt! Im lặng nào, cưng! Ta phải làm cho màu đỏ máu hoàn hảo!",
    [1086560884] = "Áo Giáp Thuật Sĩ",
    [1086854624] = "Dê Thường Con",
    [1086953715] = "Trục Xuất",
    [1087312513] = "Tìm Đền Thờ Tiếp Theo Của Dì Braelyn",
    [1088018549] = "Một cuốn sách cũ bí ẩn không thể mở được. Dù kéo mạnh thế nào ở bìa đá, cuốn sách dường như không sẵn lòng tiết lộ bí mật của nó.",
    [1088680447] = "Ngày 3",
    [1088981530] = "Ramone Jones",
    [1089149929] = "Lối Vào Hầm Mộ Bí Mật",
    [1089276567] = "Thánh Địa Ngọn lửa",
    [1089355553] = "Cài đặt càng khó, càng có nhiều địa điểm xuất hiện kẻ địch trong thế giới trò chơi.",
    [1089468207] = "Rìu 2H",
    [1090018724] = "Ta sợ hãi. Chúng ta đến để điều tra Thánh Địa Ngọn lửa, nhưng khi băng qua các hang động, chúng ta đã tìm thấy những gì trông giống như dấu hiệu của Vukah trên tường... cùng với những chiếc ngà rời rạc và những mảnh xương, mặc dù đây không phải là lãnh thổ của Vukah theo lịch sử! \n\nTa đã dịch một số chữ khắc... chúng liên quan đến <i>Trụ Sáng Tạo</i> vĩ đại có thể nhìn thấy từ xa. Theo truyền thuyết của Vukah, các Cổ Nhân đã xé toạc một trong những Trụ bằng một vụ nổ lớn. Vukah dâng ngà của họ trong một buổi lễ đặc biệt để tránh một <i>vụ phun trào</i> khác.\n\nTa không biết những chữ khắc này có ý nghĩa gì, nhưng ta cầu nguyện với chính những Cổ Nhân đó rằng những sinh vật đó sẽ không làm gián đoạn khu vực khai quật của chúng ta! \n\n—<lorename>Loraine Crim</lorename>",
    [1090130052] = "Tìm Thấy Sảnh Đường Hollow",
    [1091066078] = "<npc>Nhà Giả Kim</npc> Cần Nơi Trú Ẩn",
    [1091559223] = "+ Sốc",
    [1092021118] = "Đừng quên ta.",
    [1092026782] = "<b>Bắt buộc: </b>\nMột cây đũa phép. Câu thần chú (tìm thấy bên dưới). Hình ảnh rõ ràng về người đã chết mà ngươi muốn nói chuyện.\n\n<b>Tùy chọn:</b> Nến hương cam quýt. (Khi ngươi trở về từ thế giới bên kia, ngươi sẽ có mùi thịt cháy.)\n\nĐọc chậm những lời sau:\n<i>Một giờ trước bình minh, và ta chia sẻ nó với ngươi\nHai lần thời gian trên Trái Đất này sẽ không chứng minh tình yêu của ta là thật\nCái chết không thể chia cắt chúng ta, ta sẽ tìm thấy ngươi ở bất cứ đâu\nPhá vỡ bóng tối ba lần, để chúng ta cùng nhau mù quáng\nCát thời gian trôi đi, ta ngã xuống làn sóng của ngươi\nDang rộng bàn tay, hãy để thực tại sụp đổ\nTa hy sinh ánh sáng, vô số hơi thở ta lãng phí\nChỉ cần kéo ta vào một lần, để cái ôm cuối cùng</i>\n\n<b>Xin lưu ý:</b>\nNếu người mà ngươi đưa đến thế giới bên kia không BUÔNG BỎ cái ôm của người đã khuất, ngươi sẽ tan thành tro bụi. Nến hương cam quýt sẽ không giúp được gì, lúc đó. Hãy cẩn thận!",
    [1092196533] = "Thời Gian Độc Dược Phản Bội",
    [1092705225] = "Nhà Tù Đỉnh Albaneve",
    [1093300179] = "Nhảy Đôi",
    [1093779301] = "Hồi Sinh Và Vật Phẩm Bị Mất",
    [1093853478] = "Những chiếc găng tay này ngăn dây cung cắt vào da khi ngắm bắn.",
    [1093989849] = "Cây cung trông giống rồng này thường bị sợ hãi vì cặp sừng cong có nguồn gốc không rõ. Dân làng tin rằng những chiếc sừng xoắn như vậy sẽ luôn mang lại xui xẻo.",
    [1093993537] = "Đèn Chùm Đom Đóm",
    [1094062588] = "Bạn cũ, lại gần đây. Ta có một câu chuyện để kể.",
    [1094439981] = "Tìm Hầm Của Paulette Leclair",
    [1094625766] = "Mọi Người Ở Đâu Rồi?",
    [1094722241] = "Một cái cào làm từ những vật liệu đơn giản nhất. Một công cụ cơ bản dùng để san phẳng mặt đất cho các công trình sắp tới.",
    [1094906739] = "Một <craftingstation>Lò luyện kim</craftingstation> có thể hữu ích. Tin tôi đi, rất đáng để tìm <keyitem>Lò nung</keyitem> của tôi để chế tạo nó.",
    [1094953775] = "Bộ Trang Phục Bóng Tối Núi",
    [1095216000] = "Quần Hoa Hồng Máu",
    [1095290929] = "Một <craftingstation>Máy hun ong</craftingstation>",
    [1095418282] = "Công Cụ Phân Hủy",
    [1095530199] = "Một ngọn lửa nhỏ, một ánh sáng nhỏ\nđánh tan bóng tối và mọi tai ương của nó",
    [1096244256] = "Khiên Gỗ",
    [1096262948] = "Lá Cọ",
    [1097338814] = "Tất cả các ô thức ăn đã được lấp đầy",
    [1097667750] = "Tìm Cảm Hứng Màu Tóc Tại <location>Pháo Đài Kelvin</location>",
    [1097842417] = "Sự đơn giản của thanh kiếm này thật đánh lừa! Một sức mạnh ma thuật mờ nhạt tỏa ra từ viên đá màu xanh pastel được rèn vào lưỡi kiếm. Nghề thủ công này rất phổ biến với những pháp sư trẻ tuổi và các chiến binh pháp thuật.",
    [1098994381] = "Bạn đã tìm thấy một công thức chế tạo ẩn trong Đầm Lầy Đen! Thu thập tất cả 5 công thức nằm rải rác trong khu vực để mở khóa các tùy chọn di chuyển cho ngôi nhà của bạn, cũng như các hiệu ứng tăng cường và đồ trang trí!",
    [1099282047] = "Cuối cùng tôi cũng có thể xem lại hàng hóa của Mei! Chúng ta cùng xem xét kỹ năng chế tạo nhé? Tôi thích ngắm đồ!",
    [1099308988] = "Trang Trại Nấm Russula Xanh",
    [1099373319] = "Đảo Ngược X",
    [1099512253] = "Trí Tuệ",
    [1099844831] = "<location><lorename>Pháo Đài Pikemead</lorename></location>",
    [1100010245] = "Một thứ nước lạ phát ra ánh sáng xanh lam... Không ai biết rõ tại sao.",
    [1100091430] = "Ám khí",
    [1100291030] = "Bạn có đôi mắt tinh tường nhất. Hãy để mắt đến anh trai tôi nhé? Tôi không nghe tin gì về Gerith kể từ cơn bão. Lần cuối chúng tôi nói chuyện, anh ấy định <b>lục soát ngôi mộ ẩn này.</b> Tôi không biết chính xác ở đâu, nhưng anh ấy nói nó không quá xa đây.\n\nVì vậy, làm ơn, nếu bạn nhìn thấy một chàng trai gầy gò ở phía chân trời, đừng bắn! Hãy báo cho tôi biết. Có thể đó là anh trai tôi Gerith!",
    [1100296820] = "Thổi Sáo",
    [1100772346] = "Đã nghỉ ngơi",
    [1101739532] = "Nhật ký số 01\nCho ăn lần cuối: Thứ Hai, Tay (vô tình)\nLưu ý: Cắn rất đau. Nhắc Rafael mang kìm. Có thể cần nhổ răng.",
    [1102078504] = "Dương Xỉ",
    [1102605316] = "Ngai Vàng Đá Granite",
    [1102679930] = "Tàn Tích Răng Sắc",
    [1102748965] = "Hãy tạo ra một thứ gì đó thật vĩ đại!",
    [1102902815] = "Kẻ săn lùng Sương độc",
    [1103027618] = "Bạn đã làm rất tốt trong việc thu hồi tất cả các phép thuật đó. Tôi phải nói rằng, tôi rất ấn tượng! Bây giờ tôi đã nghiên cứu chúng tận mắt, tôi có thể cố gắng tái tạo phép thuật của chúng cho bạn.",
    [1103129430] = "Tặng chồng",
    [1104213668] = "Mục Tiêu Gắn Tường",
    [1104474666] = "\"Bình Hoa\"",
    [1104581967] = "Đầu Thú Sấm Sa Ngã",
    [1104593561] = "Lộ ra",
    [1104919713] = "Thời Gian Hiệu Lực Buff Thức Ăn",
    [1105264948] = "Khung Xương Chậu Quái Vật Một Mắt",
    [1105286715] = "Bộ Trang Phục Sát Thủ",
    [1105326475] = "Đoàn Lữ Hành Phương Nam",
    [1105760443] = "Giờ đây tôi thấy rằng đây là hồi kết.\nTôi đã chứng kiến các chị em của mình chết. Tôi đã thấy họ bị xé xác, bị nuốt chửng bởi một trong những con quái vật khủng khiếp đó. Tôi vẫn có thể nghe thấy tiếng hét của họ. Tôi nghĩ rằng họ sẽ ám ảnh tôi khi chết.\n\nHọ đã cảnh báo tôi về những rủi ro. Dù vậy, tôi vẫn đi, gạt bỏ những nghi ngờ.\nNgay cả bây giờ, bao quanh bởi máu, tôi không thể nói rằng đứng về phía họ là sai. Tôi thà chết biết rằng tôi đã không bỏ rơi các chị em của mình còn hơn sống biết rằng tôi đã làm.\n\nChính nghĩa của chúng ta là chính đáng, và ý định của chúng ta là thuần khiết. Hãy chắc chắn, tôi sẽ chọn con đường này một lần nữa.\nCuối cùng, chúng ta đã đoàn tụ với nữ hoàng đích thực của mình.\nVinh quang cho Nữ hoàng Pikemead.\n\n- Celia, Vệ binh của Hoa Hồng Máu",
    [1105992896] = "Thạch Anh Tím",
    [1106007475] = "Mũ Thương Nhân",
    [1106642895] = "Trượt Giảm SP",
    [1106725999] = "Hỡi Ngọn Lửa Sinh, nghệ sĩ tài ba của ta! Khi ngươi chơi nhạc cụ bên lửa, nó làm ta nhớ đến ban nhạc yêu thích của ta: The Honeydews! Việc ta không thể xem <B>nhạc cụ hiếm</B> của họ trực tiếp trong buổi biểu diễn cuối cùng tại <location>Nơi Nghỉ Ngơi Surat</location> sẽ ám ảnh ta mãi mãi... ban nhạc đã tan rã! Ồ, và có lẽ họ đã chết. Nhưng nhạc cụ của họ có thể vẫn còn ở đâu đó!",
    [1106810196] = "Các học giả phương Bắc từng nghiên cứu việc sử dụng phép thuật lửa chống lại mùa đông khắc nghiệt. Phải mất vô số thí nghiệm nổ mới khám phá ra lợi ích tương tự mà hầu hết mọi người có thể đạt được với một đống lửa trại. Những nhược điểm, chẳng hạn như bỏng độ ba, là phổ biến, vì vậy nghiên cứu đã nhanh chóng bị dừng lại.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.",
    [1106849697] = "Sát thương lên Vukah",
    [1106897315] = "Một bông hoa hình ngôi sao nở trên những ngọn núi cao. Nó mang lại nhiều MP hơn khi tiêu thụ.",
    [1107030713] = "Ugh, tôi cảm thấy kinh khủng. Mỏ đâu rồi? Chuyện gì đã xảy ra ở Embervale vậy? Gia đình tôi đâu?",
    [1108101310] = "Tăng Kháng Băng của bạn để chịu lạnh lâu hơn. Tìm hơi ấm của lửa để phục hồi nó.",
    [1108126282] = "Muốn trông giống như một cục vàng nằm dưới đáy hồ? Với bảng màu này, bạn sẽ hiện thân chính xác như vậy - màu xanh lam rực rỡ, phong phú với một chút vàng lấp lánh.\n\nBảng màu này có thể được tạo bằng vật liệu từ Bồn Rửa Mặt Nước Che Phủ.",
    [1108380928] = "Thanh tẩy Lời nguyền Fell",
    [1108471111] = "Hươu Tiên",
    [1108478535] = "Tường Rào Gỗ II",
    [1108662743] = "Mũ Thợ Rèn",
    [1109147964] = "Alden Crowley",
    [1109600640] = "Bạn đang bốc cháy!",
    [1109614752] = "Muốn nghe một phiên bản sớm?",
    [1109956923] = "Bồn Tắm Của Thủy Thủ",
    [1109987889] = "Chậu Cây Trống V",
    [1110320032] = "Ngọn Tháp Cổ Đại này ở Rừng Revel sẽ mở ra những con đường mới cho tất cả chúng ta. Đừng quên về nó!",
    [1110350981] = "<b>Nghề nghiệp: </b> Công nhân xây dựng, <i>tôi đoán vậy</i>\n\n<b>Nơi cư trú:</b> Công trường xây dựng \"Maelstrom\"\n\n<b>Tiền sử bệnh:</b> Không rõ. Bệnh nhân không nói.\n\n<b>Sự cố:</b> Trạng thái catatonic liên tục, ảo giác rõ rệt, tâm thần phân liệt?\n\n<b>Ghi chú của bác sĩ:</b> <i>Không phản hồi câu hỏi. Dành hai giờ vẽ hình xoắn ốc trên tường quay lưng lại với tôi. Mắt mở to bất thường, không chớp, có màu xanh sáng bất thường. Tôi đã thấy màu này trước đây chưa? Tôi làm việc quá sức, tôi không thể nói nữa. Sẽ hỏi y tá sau về các triệu chứng, có lẽ họ biết.</i>\n\n*Chú thích! <i> Bệnh nhân biến mất sau khi tôi đi lấy một y tá đồng nghiệp, mặc dù tôi nghĩ tôi đã khóa cửa phòng bệnh tạm thời. Trong tình trạng hiện tại, bệnh nhân Walker không thể tự chăm sóc mình!</i>",
    [1111008516] = "Tăng ST Hỏa",
    [1111090115] = "Sao Bắc Đẩu",
    [1111353014] = "Thầy Thuốc",
    [1111382891] = "Đi Theo Người Công Nhân Ảo Tưởng",
    [1112208766] = "<b>Điểm Kỹ Năng</b> có thể được chi tiêu trong <b>Cây Kỹ Năng</b>. Mở Cây Kỹ Năng và chi tiêu một Điểm Kỹ Năng để có được các khả năng mới.",
    [1112602672] = "ST Phép",
    [1113152135] = "Trang Bị",
    [1113404862] = "Thi triển phép thuật",
    [1114841377] = "Tôi đến đây với một đoàn lữ hành từ Kindlewastes xa xôi... Chúng tôi được dẫn dắt bởi <lorename>Jezmina</lorename>, con gái của nữ hoàng quá cố <lorename>Pikemead</lorename>. Tôi đã đi theo cô ấy bất cứ đâu... nhưng cuối cùng, cô ấy đã rời đi. Các Tiền Nhân đã nhìn thấy những con đường khác cho chúng tôi. Tôi ước gì họ đã không làm vậy. Tôi sẽ cho bất cứ thứ gì để được đi bên cạnh cô ấy một lần nữa.",
    [1114929946] = "Đá Đánh Bóng",
    [1116276338] = "Eldermere",
    [1116364837] = "Dù đau lòng, chúng ta cũng phải tạm dừng hành trình.\n\nNguồn cung cấp đang cạn kiệt, mặc dù đôi khi tôi dường như là người duy nhất ăn. Ít nhất thì những nỗi kinh hoàng của thế giới mới này cũng không làm giảm khẩu vị của tôi... Mặc dù tôi thừa nhận, bánh mì cũ và trái cây đắng lấp đầy bụng tôi hầu như không thỏa mãn. Ồ, tôi khao khát một món khoai mì nướng cay... để mật ong chảy xuống môi và ngón tay tôi, để mùi hương ngọt ngào hơn của những người bạn đồng hành đáng yêu — Thật khó để làm sạch tâm trí khi trái tim đang đau đớn.\n\nMột khi chúng ta đã lấy lại sức, chúng ta sẽ rời khỏi nơi trú ẩn của công trình cổ xưa này. Không ai biết những bất ngờ mà lãnh địa của Chúa tể Vorgoth có thể chứa đựng. Anh vẫn còn ở đó, phải không em trai? Hồn ma của anh có ám ảnh vùng đất hoang này không?\nKhi tôi nán lại bên bờ vực của ngày mai, những ký ức mà tôi tưởng đã chôn vùi ùa về. Một cơn đau nhói xé toạc má tôi. Tôi cảm thấy tác động của bàn tay bọc thép của anh, như thể nó chưa bao giờ rời khỏi tôi. Tôi nhớ lại cú ngã sau đó, những sàn nhà bằng đá cẩm thạch lạnh lẽo, máu rỉ ra từ mũi và môi tôi.\n\nBất cứ nơi nào anh đi, anh đều để lại dấu vết... trong sông, trong gió, trong con người — Mong muốn sâu sắc nhất của tôi là làm cho dấu vết của mình có ý nghĩa.\n\n— Nữ hoàng Jezmina",
    [1116466874] = "Ồ, một khuôn mặt xa lạ! Bạn là thành viên mới của khoa sao? Tên tôi là Hugo Vanderhall — tôi là một học giả ở đây! Thực ra... \"ở đây\" là đâu? Nơi này trông không giống thư viện của tôi...",
    [1116789060] = "Đuôi Bóng Tối Nướng",
    [1116896188] = "Oswald Anders",
    [1117067695] = "Ghế Bành Thanh Lịch Cao",
    [1117180651] = "Tiệc Tùng",
    [1117412344] = "Tăng sát thương gây ra với vũ khí cận chiến 1H.",
    [1117441751] = "Đàn Khúc Cầm Tuyệt Hảo",
    [1118505596] = "Trò chuyện bằng giọng nói",
    [1119181297] = "Cây Giống Gừng",
    [1119238236] = "Tăng cường Ngọn Lửa để có thêm",
    [1119452231] = "Tôi chưa bao giờ nghĩ mình sẽ lại nhìn thấy hoàng hôn ở phía bên kia Trụ Cột Sáng Tạo này. Buổi chiều tà rực rỡ hơn khi tôi còn trẻ. Một làn sương mù tím hoặc nho rực rỡ, một sự pha trộn giữa cam và cúc vạn thọ, một chút hồng hào trước bóng tối. Bây giờ, màu xám.\nTôi cầu nguyện các Tiền Nhân bảo vệ <b>đoàn lữ hành phương bắc</b> bằng vinh quang và ánh sáng của họ. Tôi đặt niềm tin vào <lorename>Cyrus</lorename>.\n<location>Longkeep</location> đã ở trong tầm mắt... Dân ta mệt mỏi, nhưng chúng ta không thể nghỉ ngơi. Chúng ta phải cố gắng hơn nữa, vì mỗi linh hồn chúng ta đã mất. Bước chân của chúng ta phải nhanh nhẹn, tôi đã học được.\n\nTôi có một cảm giác kỳ lạ. Nỗi sợ hãi này. Rằng tôi sẽ không thể nán lại, rằng tôi sẽ lại bước đi một mình... Tại sao tôi không thể rũ bỏ nỗi sợ hãi này? Không, sự... <i>báo trước?</i>\n— Nữ hoàng <lorename>Jezmina</lorename>",
    [1120266539] = "SP",
    [1120289068] = "Một bộ dao găm tự nhiên với tay cầm bằng gỗ uốn lượn. Lưỡi dao hơi cong và lý tưởng để lột da động vật.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1120359044] = "dsb@keengames.com",
    [1120618466] = "Một dụng cụ cạo và sàng bằng tay có thể dùng để khai thác vàng và các vật liệu khác dưới nước.",
    [1121961510] = "Bạn đã tìm thấy và giải cứu một người nông dân tên là Fenrig Mills. Anh ta tự hỏi mọi người đang ở đâu. Trước khi anh ta qua đời, thị trấn <location>Pháo Đài Kelvin</location> được cho là một nơi an toàn cho du khách.\n\nAnh ta đề nghị bạn tìm kiếm trong thị trấn xem có còn người sống sót nào không, hoặc những người giống anh ta mà bạn có thể hồi sinh!",
    [1122168394] = "Cây Giống Cọ Dừa",
    [1122237029] = "Tổ tiên của bạn phù hộ cho bạn.",
    [1122450933] = "<b>Đỡ đòn</b>\nKhi được trang bị Khiên, một lần chặn đúng lúc sẽ <b>đỡ đòn</b> tấn công.",
    [1123228246] = "ST Lôi Vũ Khí Bổ Sung",
    [1123390364] = "Scavenger",
    [1123474476] = "Nước",
    [1123476448] = "Những trải nghiệm khác biệt nhất được thu thập và mô tả trên một cuộn giấy.\n\nNhận một lượng kinh nghiệm nhỏ khi hấp thụ nội dung.",
    [1123669347] = "Vị <npc>Nhà giả kim</npc> Balthazar chế tạo thuốc và các hỗn hợp khác.",
    [1123816277] = "Cây Thường Xuân",
    [1124193267] = "Hàng Rào Tàng Hình",
    [1124210473] = "Quần Thiện Xạ",
    [1124515505] = "Kiếm Chắp Vá",
    [1124604811] = "Tìm Tất Cả Vật Phẩm Trang Phục Thợ Săn Hải Tặc",
    [1124633149] = "Áo Giáp Hắc Vệ",
    [1125150306] = "Tháp",
    [1125187806] = "Cây Bám Leo",
    [1125293908] = "Cho phép / Vô hiệu hóa nhiễu loạn trong khi lượn.",
    [1125321516] = "Ta đã tìm kiếm bí mật của sự vĩnh cửu trong nhiều thập kỷ nay. Mỗi phép thuật ta tạo ra, ta đều thử nghiệm trên những bộ xương không yên nghỉ lơ lửng trong bóng tối. Những sinh vật vô tri - nhưng tuân theo ý chí của ta - phục vụ như những học trò của ta trong nhiệm vụ này.\n\nVà thế mà... Lời hứa về cuộc sống vĩnh cửu của ta vẫn lẩn tránh ta. Ta bỏ chúng lại nơi chúng ngã xuống, bị vứt bỏ, làm chứng câm cho thiên tài của ta, hoặc ít nhất là những nỗ lực của ta.\n\nKhông quan trọng, còn nhiều ngôi mộ để khám phá. Với mỗi căn phòng, ta lại tiến gần hơn đến sự hoàn hảo. Những thất bại chỉ là bước đệm. Ta sẽ không dừng lại, vì sự hủy diệt của mọi thứ khác đáng giá cho sự vĩnh cửu.\n\nCho thí nghiệm tiếp theo của ta, ta đã nghe những lời thì thầm về một ngôi mộ ẩn mình giữa những lùm chuối rậm rạp. Từ mặt nước, ta sẽ vượt qua Tiền Đồn Cổng \"Nước Đen\" và dấn thân vào rừng rậm để tìm kiếm nó.",
    [1125830499] = "Thời Gian Hồi Phục Trong Sương độc",
    [1125879887] = "Gia đình ta và ta đã dành phần lớn một năm để tìm kiếm vùng đất này. Ta biết khi ta tìm thấy loại đất màu mỡ phù hợp nhất - nhưng ta vẫn chưa hài lòng. Rồi một ngày, chúng ta đi qua ngọn đồi này và ta thấy cách những cây non nảy mầm. Ta có thể nếm được dinh dưỡng trong đất trên đầu ngón tay mình. Mùa đầu tiên đó cha ta lo lắng ta đã đưa ra lựa chọn sai lầm, nhưng khi lúa mì đến và chúng ta có bánh mì cho mùa đông (và tiền trong túi ông) ông đã nói với ta ông tự hào như thế nào.\n\nTuy nhiên, ta đã vượt quá trang trại. Ta đã đóng gói đồ đạc và dự định mở quán rượu của riêng mình ở <location>Cây Bụi Gai</location> và ta không thể hào hứng hơn khi chia sẻ tài nấu nướng của mình với du khách từ khắp nơi. Trước khi ta đi, mẹ ta muốn tặng ta một món quà. Ta tự hỏi đó có thể là gì?\n\n— Emily Fray ",
    [1125930209] = "Quan Tài Đơn Giản",
    [1126179090] = "Cửa Mộc Mạc",
    [1126219310] = "<b>Động vật hoang dã</b> trong phạm vi <b>50</b> mét sẽ không còn tấn công bạn trừ khi bị khiêu khích.\n\nKhông ảnh hưởng đến động vật bị Sương độc làm ô nhiễm.",
    [1126301612] = "Câu Chuyện Về Sự Thối Rữa",
    [1126545804] = "Giáp Thân",
    [1126667093] = "Gạch",
    [1127015645] = "Thảm Tường A",
    [1127183212] = "Thủy Triều Lên",
    [1127712421] = "Đèn Chùm Hầm Mộ",
    [1127987067] = "Hành Động Phụ",
    [1128561537] = "Mũi Tên Thép Vàng",
    [1128797520] = "Một miếng băng kết hợp với thuốc sát trùng.\n\nMón đồ này hồi 60% HP trong 10 giây nếu được bôi lên vết thương.\n\nNhận bất kỳ sát thương nào sẽ làm gián đoạn hiệu ứng Chữa thương.",
    [1129574425] = "Tích Tụ",
    [1130131205] = "Đồi Hy Sinh Vukah",
    [1130301962] = "Hàng Rào Thép",
    [1131881389] = "Một chiếc cần câu chắc chắn hơn, giúp dễ dàng kéo cá vào và bạn cũng có thể chịu đựng cuộc chiến lâu hơn.",
    [1133044277] = "Một lớp vỏ cứng như đá, được xé ra từ Kẻ Rình Rập, một sát thủ tàn nhẫn của Sương độc. Cấu trúc gần như không thể phá vỡ của nó làm cho nó trở thành một vật liệu quan trọng để rèn giáp cứng và đàn hồi.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Kẻ Rình Rập Sương độc, ban đầu tìm thấy ở Cao Nguyên Du Mục.",
    [1133059280] = "Thợ Cắt Tóc muốn nhớ cách tạo ra màu nhuộm tóc xanh hoàn hảo. Ông tin rằng chìa khóa để có được màu sắc hoàn hảo nằm ở sự lưỡng tính của chính màu sắc đó. Nó cần phải vừa tươi mát và tự nhiên, vừa bí ẩn.\n\nThợ Cắt Tóc yêu cầu bạn <b>nói chuyện với ai đó am hiểu</b> hơn về các khía cạnh tự nhiên của màu xanh lá cây đại diện cho <b>sự sống và sự tái sinh.</b>",
    [1134212179] = "Tiếp Cận Mỏ Đá",
    [1134538272] = "ST Kết liễu",
    [1134611410] = "Thợ Rèn đang thiếu <b>Áo Giáp</b> của ông ấy. Ông ấy tin rằng ai đó đã lấy nó, và bảo bạn hỏi xung quanh.",
    [1134735691] = "Sử Dụng",
    [1134838443] = "Quan Tài",
    [1134843874] = "Người Sống Sót Và Chế Tạo",
    [1135062980] = "Dao Găm Pha Lê",
    [1135137649] = "Ta biết chắc rằng Drak đã tìm ra cách sử dụng những thứ khác để làm cho đèn của chúng có màu khác nhau. Nếu bạn lục lọi một chút ở chỗ chúng, có lẽ bạn sẽ tìm thấy một ghi chú hay gì đó về cách chúng làm được điều đó.",
    [1135206171] = "Sinh Vật Biển",
    [1135487137] = "Chính Xác",
    [1135721696] = "Tượng Chú Lùn Sân Vườn",
    [1135821193] = "Nhẫn Của Thợ Săn",
    [1136092957] = "Một đặc sản của Vùng Đất Nóng Bỏng — khách hàng yêu thích nó vì lợi ích HP!",
    [1136348279] = "Khi chế tạo vật phẩm hoặc tài nguyên với nhà giả kim, có 20% cơ hội nhận được thêm một vật phẩm",
    [1136820034] = "Điều Tra Gợi Ý Của Ramone",
    [1138216256] = "ST Hỏa Ma Thuật",
    [1138264064] = "Đá Mài",
    [1138756099] = "Vách Ngăn Phòng \"Cá\"",
    [1139470994] = "Manathor",
    [1139890184] = "Mỗi phát bắn chính xác khiến máu chảy nhanh hơn.",
    [1140389153] = "Chuẩn Bị Cho Thời Tiết Lạnh",
    [1141048796] = "Quá xa",
    [1141539493] = "Khối Đá Vôi",
    [1141701637] = "Cần Câu Đơn Giản",
    [1141952320] = "Chìa Khóa Vàng",
    [1142859021] = "Tìm Bộ Đầy Đủ Học Giả Thiên Giới",
    [1142865120] = "Tiếng Vọng Vang Khắp Nơi",
    [1144158450] = "Nhạc Cụ",
    [1144299943] = "Bàn Góc Gỗ Thô Sơ",
    [1144361212] = "Bạn sắp đá %k",
    [1144680181] = "Mỏ Muối",
    [1144996323] = "Điều Chỉnh",
    [1145234613] = "Găng Tay Quý Tộc",
    [1146269195] = "Nhân Vật Mới",
    [1146407032] = "Gợi Ý Kho Báu Nông Dân",
    [1146416107] = "Cát mịn đã được truyền nhiễm bào tử Sương độc. Thường tìm thấy ở quần xã sinh vật Kindlewastes.",
    [1146777702] = "Thợ Mộc có thể được cứu! Anh ta cần được triệu hồi và đặt trong căn cứ.",
    [1146823288] = "Thang Tre III",
    [1147062689] = "Giày Kẻ Gọi Thủy Triều",
    [1147476361] = "Giáp Ngực Cai Ngục",
    [1147705187] = "Heureka! Bạn đã làm được! Ôi, những điều kỳ diệu chúng ta có thể tạo ra!",
    [1147750168] = "Dòng Sông Vỡ Bờ",
    [1147911813] = "Đầu Quái Vật Mắt Một Sa Ngã",
    [1148227120] = "Ta ước có một người bạn săn. Có lẽ bạn cũng vậy. Một con chó cũng không phải là một sự bổ sung tồi!",
    [1148573788] = "Khoảng Cách Máy Ảnh",
    [1148913508] = "Một Lời Cảm Ơn Nhỏ",
    [1149164918] = "Chọn",
    [1149346299] = "Khôi Phục Sao Lưu",
    [1149513493] = "Quần Kẻ Săn Đầu Lâu",
    [1149676139] = "Cần bất kỳ sự trợ giúp nào?",
    [1149715292] = "Thiết Bị Lặn",
    [1149835082] = "Ngày xưa các chiến binh dùng máu kẻ thù để nhuộm quần áo. Cách này dễ hơn, nhưng hiệu quả tương tự.",
    [1150203515] = "Quần Áo Thợ Rèn Đã Thu Hồi",
    [1150705081] = "Trạm Nấu Ăn Cho Nông Dân",
    [1150710914] = "ST Hỏa Tác Động",
    [1150943310] = "Một lưỡi kiếm trang nghiêm, dùng để bảo vệ danh dự và mạng sống của kẻ yếu.",
    [1152130496] = "Biển Hiệu Gắn Tường",
    [1152156445] = "Ta từng đi câu cá trong mắt bão.",
    [1152647447] = "Tất cả sát thương Sương độc tăng 20%.",
    [1152983858] = "Bạn tìm thấy một ghi chú đề cập đến một hang động Khổng Lồ gần Thác Polaris.\n\nĐiều tra hang động và đánh bại Khổng Lồ bên trong!",
    [1153173641] = "Đòn Bắn Nhanh",
    [1153564596] = "Nhận Bảo Vệ Frost trong căn cứ ở cấp độ %k",
    [1153575007] = "Tăng tối đa MP thêm 1",
    [1153679635] = "Giải thích cách trồng tất cả các loại cây con.",
    [1154441782] = "Người Thu Thập đã tiết lộ vị trí của Sảnh Hollow ở Đỉnh Albaneve. Để vào, bạn sẽ cần một chiếc chìa khóa.\n\n<b>Chế tạo Chìa khóa với Người Thu Thập</b> để tiếp tục.",
    [1154469044] = "Trình điều khiển GPU của bạn đã lỗi thời. Vui lòng cập nhật để có trải nghiệm chơi game lý tưởng.",
    [1154624630] = "Bí Mật Bị Tràn",
    [1155115460] = "Kỹ năng hiện đang trong Thời gian hồi chiêu và không thể hồi MP.",
    [1155464809] = "Ngọn Lửa giải thích rằng sức mạnh của bạn đã tăng lên rất nhiều. Giờ đây, bạn có thể thu hồi linh hồn của những người đã chết mà không bị Sương độc hoặc Thuốc Tiên chạm vào. Điều tra khu vực được đánh dấu trên bản đồ của bạn để tìm kiếm manh mối!",
    [1155864202] = "Cơ Hội Chí Mạng Cận Chiến",
    [1156004882] = "Cúc Đá Lớn",
    [1156623894] = "Giáp Lửa",
    [1157106028] = "Trà Hồng Trà Nam Phi",
    [1157128549] = "Quái Vật Một Mắt",
    [1157245874] = "Sa Thạch",
    [1157472585] = "Kẻ Tử Đạo",
    [1157683326] = "Được mạ vàng hoàn toàn, bạn không còn nhận thấy bụi bẩn và mùi hôi, vì vậy bạn có thể treo nó trong phòng khách của mình mà không do dự.\n\nThu thập nhiều Đầu Scavenger Matron để chế tạo Cúp Vàng.",
    [1157781373] = "Bảng màu này có thể được tạo ra từ các vật liệu của Vùng Đất Thiêu Đốt.",
    [1158262954] = "Điểm Nhìn Vũng Nước Che Mặt",
    [1159119755] = "Chuối",
    [1159181173] = "Hang Rồng",
    [1159293844] = "Một khối xây dựng được trang trí bằng các chòm sao sáng lấp lánh trên nền xanh nửa đêm, được viền bởi các tấm vàng.",
    [1159807243] = "Hẹn gặp lại.",
    [1159819340] = "Dù Lượn",
    [1160195697] = "Gậy phép Tết Nguyên Đán",
    [1160444249] = "Một ghi chú tiết lộ rằng một <b>lưỡi kiếm bị nguyền rủa</b> đã được chôn cất tại <location>Cỏ Đơn</location> cùng với chủ nhân trước đây của nó. Bạn sẽ làm ơn cho những người đang yên nghỉ tại nghĩa trang bằng cách lấy lại món đồ bị bỏ rơi đó. Nó được chôn dưới một cái cây.",
    [1160637996] = "Mức Độ Thoải Mái",
    [1160785693] = "Vùng Đất Mùa Xuân",
    [1160998321] = "Một phần của Giáp Thợ Săn Hươu.",
    [1162300225] = "Chế tạo",
    [1162360309] = "Một loại năng lượng kỳ lạ. Hiện tại nó có vẻ không ổn định, nhưng có lẽ nó có thể được tinh chế.\n\n<b>Nguồn gốc</b>: Rơi ra từ những Kẻ Fell thông thường, bắt đầu từ quần xã sinh vật Vùng Đất Mùa Xuân.",
    [1162466267] = "Cá Cắt Khúc Áp Chảo",
    [1163517035] = "Chậu Đất Sét IV",
    [1163699128] = "Một công cụ khai thác cơ bản, được làm từ những vật liệu đơn giản nhất. Nó không bền hoặc hiệu quả lắm, nhưng nó làm đúng những gì nó được cho là làm.",
    [1164209519] = "Bạn không có quyền loại bỏ nước xung quanh Bàn Thờ Ngọn lửa.",
    [1164254146] = "Tay Vịn",
    [1164572851] = "Phiên bản xây dựng của bạn không khớp với phiên bản xây dựng của lời mời. Vui lòng đảm bảo trò chơi của bạn đã được cập nhật.",
    [1164859054] = "Sói",
    [1165092216] = "Daniel the Damned hóa ra đã thực sự bị ảnh hưởng bởi lời nguyền của Hollow. Trước khi biến đổi, anh ta đã viết trong lá thư cuối cùng rằng anh ta ghét người bạn cùng ban nhạc cũ của mình, Chester Loft the Lucky Lute, người đang hướng thẳng đến một pháo đài Scavenger gần đó. Daniel hy vọng Chester sẽ gặp một số phận đen tối ở đó.\n\nHãy đến pháo đài Scavenger và tìm cây đàn lute quý hiếm của Chester ở đó!",
    [1165247070] = "Kiến Thức Cá Nhân",
    [1165253893] = "Không Có Tin Tức Gì Từ Orville",
    [1165314306] = "Nhạc sĩ phiêu lưu, Valory, chế tác nhạc cụ và chia sẻ những câu chuyện thú vị từ những chuyến du hành của cô ấy qua Embervale.",
    [1165421246] = "Thuốc Đường",
    [1165479862] = "Đừng để bị đánh lừa bởi cái tên của nó, chiếc rìu này được rèn trong sự thách thức và tấn công với sự cuồng nộ không ngừng.",
    [1165816952] = "Linh Hồn Ngọn lửa",
    [1165921845] = "Một Ghi Chú Gửi Kendal",
    [1166033458] = "Đầm Lầy Đen",
    [1166264743] = "Chọn Bộ Lọc Máy Chủ",
    [1166662911] = "Tôi biết Bộ Mã Hiệp Sĩ như lòng bàn tay của mình.\n- Hãy <i>\"kiên nhẫn.\"</i> Luyện tập. <i>Chăm chỉ.</i> Mỗi ngày chết tiệt.\n- Nắm vững các nguyên tắc phòng thủ cơ bản. Chú ý đến đòn quét xuống của bạn. Đảm bảo cổ tay của bạn xoay nhanh như chớp.\n- Chăm sóc thiết bị của bạn, coi nó như một chi khác, một phần mở rộng của chính bạn.\n\nTôi biết tất cả, cả trên chiến trường lẫn ngoài đời. Tôi có thể trả lời mọi câu hỏi và đỡ mọi đòn tấn công. Tâm trí tôi là một pháo đài, tư thế phòng thủ của tôi không thể xuyên thủng.\nTuy nhiên, tại sao người thầy lại khăng khăng nhốt tôi trong tháp? Ông ấy không thấy tôi đã sẵn sàng sao? Có phải vì tôi né tránh nhiều hơn là đỡ đòn? Hay vì tôi đánh bóng tấm giáp của mình thay vì giày của người thầy?\n\nTôi phát ốm vì phải <i>kiên nhẫn</i>! Đã đến lúc tôi phải tự đặt ra luật lệ của mình:\n\n- Hãy dũng cảm.\n- Né tránh thắng đỡ, đỡ thắng đánh. Nhảy múa nơi người khác gục ngã.\n- Tỏa sáng rực rỡ như mặt trời. Chói lọi bằng lòng dũng cảm và sự duyên dáng\n... Trở về như một hiệp sĩ, hoặc không bao giờ.\n\n<i>Fairburn</i>",
    [1166905156] = "Hãy tin tôi đi - bạn sẽ sống sót lâu hơn nhiều ở đây nếu bạn xây cho tôi một căn phòng. Một nơi trú ẩn nào đó, bạn nghe thấy chứ!",
    [1167292501] = "Tăng sát thương Cung và Dao găm thêm 5% cho mỗi Điểm Thuộc Tính.",
    [1167715455] = "Xô Gỗ",
    [1167734361] = "Đã trang bị",
    [1168571855] = "Một viên đá nhỏ mềm đã trở nên nổi tiếng vì khả năng tạo ra tia Ngọn lửa. Nó đã gắn liền với Ngọn lửa kể từ đó.",
    [1169210658] = "Tìm Nút Ẩn",
    [1169246056] = "Đang phát triển...",
    [1170147463] = "Khóa - Không thể sử dụng",
    [1170528349] = "Một bông hoa vàng xinh đẹp với các đặc tính ma thuật giúp tăng MP cho người sử dụng.",
    [1170874627] = "Bạn đã đến <location>Vọng Gác Bờ Biển</location>. Bây giờ hãy nhìn xung quanh để tìm một chú chó đi lạc để thuần hóa bằng thức ăn cho chó! Hãy cân nhắc tìm kiếm bên trong các ngôi nhà!",
    [1171220188] = "Lửa",
    [1171567122] = "\"Người bạn mới nhất\" của bạn là của riêng bạn. Chúng có mùi hôi thối của sự mục rữa, tỏa ra từ áo choàng và hơi thở của chúng. Tôi theo dõi chúng. Chúng lảng vảng gần Bàn Thờ. Nhìn chằm chằm vào ngọn lửa, vào than hồng và tro tàn. Tôi không thấy hình ảnh phản chiếu trong mắt chúng, không có ánh sáng. Điều đó khiến tôi rùng mình như đỉnh Núi Sói Xưa.",
    [1172880815] = "Thỏ Nhảy Con",
    [1172969436] = "Bàn Góc Gỗ Đánh Bóng",
    [1173564078] = "Hỡi Hỏa Sinh! Ta mệt rã rời! Ta cần chút caffeine! Ngươi sẽ không giúp một linh hồn khốn khổ sao?",
    [1173825618] = "Kích hoạt Tiến Trình Cá Nhân",
    [1174105532] = "Hút MP",
    [1174136130] = "Bộ Xương Rồng",
    [1174239615] = "Bạn là Hỏa Sinh, ngọn hải đăng hy vọng cuối cùng của nhân loại. <b>Ngọn Lửa bên trong bạn bảo vệ bạn khỏi Sương độc trong một thời gian giới hạn</b> và cho phép bạn dấn thân sâu vào Embervale.\n\nĐánh bại những sinh vật từ dưới lên, xây dựng đế chế của bạn và đòi lại vùng đất!",
    [1174243392] = "Câu Cá",
    [1174298845] = "Ảnh Phản Chiếu",
    [1174625027] = "Cúp Danh Năng Thú Sấm Sa Ngã Bằng Sắt",
    [1175899659] = "Ồ, Hỏa Sinh.",
    [1175929984] = "Chế tạo ×%k",
    [1176535920] = "Thu Thập Lông Cừu",
    [1176719986] = "Khi con vật đang ăn, hãy lẻn lại gần để vuốt ve nó.\nDừng lại khi con vật phát hiện ra bạn. <img taming_questionmark>\nRút lui khi con vật cảnh giác. <img taming_exclamation>",
    [1176925575] = "Lò Rèn Obsidia",
    [1177292215] = "Bạn đã có được một món đồ chơi nhồi bông! Bây giờ, chúng ta có nên cho Emily thân mến của chúng ta xem không? Cô ấy là bạn thân nhất của tôi ở đây, bạn biết đấy? Tôi hy vọng cô ấy thích món quà!",
    [1177295841] = "Một Thất Bại Khác",
    [1177833654] = "Cái <craftingstation>Bẫy Ong</craftingstation> đã được gửi từ <location>Lapis Đông</location>, nhưng đã không đến nơi. Điều tra tuyến đường thương mại sẽ tiết lộ thêm manh mối. Địa điểm đã được đánh dấu trên bản đồ.",
    [1178182419] = "Thạch Anh Tím Chạng Vạng",
    [1178378873] = "Giày Cung Thủ",
    [1178711581] = "Tìm Trại Vũng Nước Đầu Tiên Của Jezmina",
    [1178953801] = "Tỷ Lệ Khung Hình HUD",
    [1179044959] = "Bạn đã biết rằng có những vật có giá trị được giấu bên trong Trái Tim Đại Dương, pháo đài nhỏ ở <location>Lapis Đông</location>. Hãy đến đó và lấy <b>vật liệu xây dựng</b> được sử dụng cho pháo đài! Bạn có thể cần phải dùng một chút <b>sức mạnh.</b>",
    [1180113775] = "Bình thường",
    [1180286096] = "Bạn có thể nhanh chóng điều hướng các danh mục khác nhau bằng cách chọn các biểu tượng này.",
    [1180509836] = "Từng được coi là con đường dẫn đến sự cứu rỗi lại trở thành con đường dẫn đến sự đọa đày. May mắn thay, Ngọn lửa đủ mạnh để ngăn chặn những thảm họa lớn hơn nhiều lần.\n\nThu thập nhiều Đầu Rồng Sương độc để chế tạo Cúp Vàng.",
    [1180658880] = "Tôi có một tầm nhìn về những sắc xanh lục đẹp đẽ và phong phú! Cảm ơn bạn đã giúp tôi nhớ lại bằng cách cho tôi xem cả hai nguyên liệu. Bạn đã kiếm được một suất cắt tóc miễn phí trọn đời! Cái gì? Tóc tôi đã miễn phí rồi? Thật sao? ...Bạn đang thừa nhận rằng bạn đã lợi dụng lòng tốt và chứng động kinh của tôi bấy lâu nay sao? Chỉ đùa thôi! Nụ cười của bạn là đủ phần thưởng rồi!",
    [1180876877] = "Yêu Cầu Của <npc>Thợ Rèn</npc>",
    [1180978921] = "Sự sắc sảo, mũi tên còn sắc hơn.",
    [1181163482] = "Các lựa chọn thay thế: ",
    [1181223038] = "Tốc Độ Ban Ngày",
    [1181287899] = "Bộ giáp này được thiết kế để kiềm chế và kiểm soát năng lượng ma thuật đang bốc cháy bên trong người mặc. Nếu được mặc bởi một người học việc thay vì một người lớn tuổi, nó có thể khiến tim họ ngừng đập!",
    [1182317882] = "Giày Kẻ Săn Đầu Lâu",
    [1182836667] = "Đến Sảnh Hollow Cao Nguyên Du Mục",
    [1182855239] = "Áo Ngực Barbarian",
    [1183316394] = "Một chiếc rìu mạnh mẽ khát máu. ",
    [1183839516] = "Cây Giống Cây Thân Rộng Cao Nguyên Du Mục",
    [1183857048] = "Oswald Anders",
    [1185166748] = "Reverb Động",
    [1185319687] = "Một cây cần câu bị nguyền rủa, có khả năng cao sẽ câu được đồ có giá trị hoặc đồ bỏ đi. Chà, rác của người này là kho báu của người khác!",
    [1185655670] = "%k bị sốc",
    [1185704071] = "Một bộ dao găm lạnh lẽo được cho là thấm đẫm linh hồn của những người đã chết trong những mùa đông lạnh giá nhất.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1186501685] = "Đèn Treo Màu Cam II",
    [1186641809] = "Độ trễ sau đó quá trình tái tạo trở nên hoạt động.",
    [1186711998] = "Cửa Sổ Tre II",
    [1186917209] = "Hấp thụ",
    [1186971873] = "Hồng Trà Nam Phi",
    [1187067312] = "Vị Trí Bản Nhạc",
    [1187338674] = "Người dân ở đây đang lo lắng. Đầu tiên là Vịnh Nước Lặng, sau đó là Yên Ngựa Vàng. Chúng ta đã mất dấu từng khu định cư một, và những người thực hiện hành trình về phía Tây Bắc dạt vào bờ như những con cá chết.\nNhững chàng trai từ xưởng gỗ cũ có gia đình và bạn bè làm thợ lặn ở Orville, nhưng không ai nhìn thấy họ gần đây. Họ không gửi lời nhắn hay ngọc trai nào. Họ đã đi rồi, tôi nói vậy!\n\nTôi đã bảo họ đừng ở trọ trong các thung lũng. Tôi đã làm. Nhưng không ai nghe. Họ đã quên hết những câu chuyện sao?\n\nNhiều năm trước, trước khi vương miện bị chia thành ba, không, trước khi vương quốc được hình thành, chúng tôi đã bị phục kích.\nNhững con thú hoang dã, nửa người nửa thú, lao ra từ bờ biển để làm tối nước của chúng bằng máu của chúng ta. Chúng ghen tị với mối liên kết của chúng ta với các Cổ Nhân, những người mà chúng tin là sứ giả của các vị thần của chúng. Đó là một kỳ công của kỹ thuật và chiến lược của con người mà chúng ta đã từng đánh bại chúng.\n\nNgày nay, hầu hết chúng ta đã di chuyển đi - nhưng Drak không bao giờ quên. Tôi tin rằng chúng đã trở lại, tôi tin vậy, nhưng không ai lắng nghe một bà già xương xẩu.",
    [1187601768] = "Thức ăn Yak bổ dưỡng cho động vật được thuần hóa trên trang trại của bạn.\n\nNó phải được đặt bên trong máy cho ăn phù hợp.",
    [1188162181] = "Nâng cấp",
    [1188190124] = "Khai thác trong Sương độc Cao nguyên Du mục",
    [1188287089] = "Một tảng đá magma sâu thẳm chủ yếu bao gồm fenspat, thạch anh và mica.",
    [1188425534] = "Đây là cài đặt dễ dàng và thư giãn nhất. Số lượng và độ khó của kẻ địch được giảm bớt, trong khi lượng tài nguyên thu được lại tăng lên. Nếu bạn chủ yếu yêu thích việc xây dựng những căn cứ khổng lồ, đây chính là chế độ dành cho bạn.",
    [1188940956] = "Rút lui",
    [1189276523] = "Một bài hát lấy cảm hứng từ vẻ đẹp khắc nghiệt của phương Bắc. Bất cứ khi nào máu tươi đổ xuống, những bông tuyết sẽ nhảy múa từ trên trời để rửa sạch vết máu.\n\n<b>Tờ nhạc</b>: \nTờ nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ tờ nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ giúp họ học được bài hát đó.",
    [1189412010] = "Thảm",
    [1189563819] = "Một phần mở rộng cho ba lô của bạn, giúp tăng thêm ba hàng kho đồ.",
    [1189666570] = "Nhà giả kim",
    [1189865385] = "Sảnh Đường Hollow",
    [1190175415] = "Tìm hiện vật trong Sảnh Đường Hollow của Vùng Đất Lửa",
    [1190578592] = "Hỡi Hỏa Sinh, ngươi làm việc không ngừng nghỉ mỗi ngày, dệt nên từng phút, từng giờ, từng ngày. Hãy sử dụng một Bàn Quay để chế tạo vải lanh và sợi chỉ hiệu quả hơn! Chúng ta hãy cùng nhau chế tạo một cái nhé!",
    [1191109487] = "Ta có vài thứ quý hiếm cho ngươi.",
    [1191564376] = "Tấn công kẻ địch từ phía sau sẽ gây thêm %k sát thương.",
    [1191806499] = "Đến Mỏ và Lấy Muối",
    [1191854922] = "Chiếc quần làm từ vải xanh thẫm và da vá. Các lớp lót bên trong cung cấp khả năng cách nhiệt tốt chống lại cái lạnh buốt giá.",
    [1192522172] = "Cung Gió Đêm",
    [1192757233] = "Trình điều khiển đồ họa quá cũ, vui lòng cập nhật trình điều khiển.",
    [1192765669] = "Được ngâm trong chất chống thấm, khối đá này chủ yếu được sử dụng cho Giếng Thuốc Tiên.\n\nSử dụng <b>Búa Xây Dựng</b> để xây dựng <b>cấu trúc</b> xung quanh một Bàn Thờ Ngọn lửa bằng khối xây dựng này.\n\n",
    [1193416340] = "Thịt Tê Tê Cát Sống",
    [1194106733] = "Một vũ khí được đồn đại là rơi từ các vì sao. Người tìm thấy nó không bao giờ cảm thấy trọn vẹn, luôn tìm kiếm một mảnh ghép còn thiếu.",
    [1194380990] = "Không thể đặt trong nước.",
    [1194843784] = "Đội Tuần Tra Phân Tán",
    [1195288756] = "Cuộc thám hiểm trước đây của chúng ta đến <b>Nghĩa Địa Cổ</b> đã thành công lớn. Ta sẽ luôn mang ơn <i>người lạ</i> đó. Cuộc gặp gỡ định mệnh của chúng ta đã hé lộ nhiều hơn ta có thể hy vọng, mặc dù ta tự hỏi làm sao hắn biết những dòng chữ khắc cổ xưa đó...\n\nTa cảm thấy vô cùng cảm hứng. Các ký tự trong thư viện có những điểm tương đồng với <i>chữ viết cổ xưa,</i> vì vậy ta đã bắt đầu phân tích các Đài Thiên Văn Cổ để xác minh giả thuyết của mình!\n\nChỉ có một vấn đề. Ta có thể đã để quên <keyitem>Dụng Cụ Khoa Học</keyitem> của mình tại Đập Eldermere khi lũ Vulture Rồng bay lượn tới — chỉ một bóng đen và ta đã đánh rơi chúng trong cơn hoảng loạn! Chà, tạm thời, cuốn từ điển và kính của ta sẽ phải làm nhiệm vụ. Nó không thể quá khó, phải không?",
    [1195666693] = "Một luồng năng lượng xoáy rực rỡ cần thiết để gắn đá quý vào vũ khí.\n\nBan đầu được người Cổ Đại sử dụng, nó đã bị phe Fell chiếm giữ để nuôi dưỡng bầy đàn của chúng cho đến khi ngươi giải thoát nó khỏi nhà tù hữu cơ mới của chúng.\n\nBiến thể này có thể được tìm thấy ở Vùng Đất Lửa.",
    [1196253287] = "Sát thương Boss",
    [1196298549] = "Hiện vật Sảnh Đường Lớn Hollow",
    [1196445929] = "Tìm Hầm Mộ Nữ Hoàng",
    [1196799992] = "Vũ khí này có hoa văn lồng vào nhau của bóng tối và ánh sáng bằng cách che một phần rãnh của nó bằng lớp vỏ ngoài màu đen. Hai bên của thanh kiếm không đối xứng, khiến một bên lý tưởng cho việc chém, trong khi bên kia lại xuất sắc trong việc cạy hoặc chặt xuyên qua phần phụ giống móng vuốt rõ rệt của nó.",
    [1196848004] = "Khối Sắt",
    [1200001227] = "Tìm Kiếm Hang Sương Độc",
    [1200264392] = "Cái <craftingstation>Con Quay Tay</craftingstation> của ta",
    [1200521139] = "Đã đạt số lượng thế giới tối đa.",
    [1200538297] = "Bình Thuốc MP",
    [1200552836] = "Tranh Tường C",
    [1200886470] = "Chúng ta cần phải tiêu diệt con quái vật một mắt để thăng thiên. Hãy lấy đầu, Tinh thần và ý chí của nó nếu ngươi muốn nếm trải sự vĩnh cửu.",
    [1201111512] = "Một <b>rương trang bị?</b> ...giữ yên lặng chút nào! Vâng, vâng, ta đã mượn nó. Muốn hoàn thành vài dự án cũ, ngươi biết đấy? Nhưng ừm, nếu ngươi nói với lão Oswald, ta có thể mất thêm một bàn tay nữa! Nghe này: Ta sẽ cho ngươi biết nơi tìm thấy nó nếu ngươi giữ im lặng, được chứ?",
    [1201371615] = "Cơ hội Hút Máu khi chống lại Sinh Vật Hollow",
    [1201507666] = "Bạn chưa mở khóa bất kỳ vật phẩm Twitch Drop nào.\nXem các luồng đủ điều kiện để mở khóa và nhận Vật phẩm Twitch tại đây.\nKiểm tra Liên kết Tài khoản Twitch của bạn bên dưới.",
    [1201726446] = "Một con châu chấu kiên cường đã thích nghi với màu sắc ấm áp của Cao Nguyên Du Mục. Nó có thể được sử dụng làm mồi câu cá, có khả năng cao bắt được cá không phổ biến.",
    [1203181181] = "Cấp Độ Bàn Thờ",
    [1203395701] = "Một cây nấm hương nướng. Hương vị khói mới mang lại hương vị umami đậm đà.",
    [1203720797] = "Sương độc bao phủ®, Keen® và Holistic Engine® là các thương hiệu đã đăng ký của Keen Games GmbH ©2024-2026",
    [1203754773] = "Một nhiệt kế. Hữu ích cho nghề mộc.",
    [1204742882] = "Dụng Cụ Hiếm",
    [1204830564] = "Một Khởi Đầu Gập Ghềnh",
    [1206059200] = "Bột obsidian xay mịn. Nó có thể được giả kim hóa dễ dàng hơn ở dạng này.",
    [1207669401] = "Vũ khí",
    [1208134529] = "Sông Vươn Tới",
    [1208435065] = "Lời Kêu Gọi Người Xứng Đáng",
    [1208678332] = "Một Công Cụ Để Khai Thác Dưới Nước",
    [1208708954] = "Một Phép Thuật Vĩnh Cửu",
    [1209171872] = "Kệ Đá Thô Sơ",
    [1209311449] = "Những Giọt Mật",
    [1209887398] = "Tìm Vật Phẩm Ẩn Trong Gác Xép",
    [1209976196] = "Cuộc Tái Thiết Drak'Dal",
    [1210601620] = "Dao Găm Rèn Sáng",
    [1211199781] = "Tượng Nữ Hoàng <lorename>Pikemead</lorename>",
    [1211388938] = "Sử dụng <b>công cụ cải tạo địa hình</b> hoặc <b>chất nổ</b> để tạo lối đi xuyên qua đống đổ nát. <b>Quả Cầu Bột Nổ</b> có thể được <b>ném</b>. <b>Thùng Nổ</b> được kích nổ từ <b>xa</b>.",
    [1211475725] = "Vị <npc>Nhà Giả Kim</npc> cần một <craftingstation>Nồi Hắc Ám</craftingstation> để thiết lập một <craftingstation>Trạm Giả Kim</craftingstation>. Ông ta nghe những câu chuyện về một pháp sư tên là <lorename>Ikora</lorename> từ <npc>Người Nông Dân</npc>, Emily Fray. Có lẽ bà ta biết nhiều hơn.",
    [1211565236] = "Một số nông dân tin rằng các pháp sư lưu trữ năng lượng ma thuật của họ trong những chiếc mũ vành rộng. Những tin đồn này lan truyền rộng rãi nhưng không đúng sự thật. Hầu hết.",
    [1212663413] = "Quan Tài Hầm Mộ Nâng Cao Lớn II",
    [1213107569] = "Phế Liệu Kim Loại",
    [1213171722] = "Khối Tường Thành",
    [1213603317] = "Một Tờ Giấy Trắng",
    [1214290701] = "Ngươi có thấy Nữ Hoàng mới ở Obsidia không? Ôi, nàng thật ám ảnh.\n\nĐó là cách nàng quất roi vào lưng ta khiến ta phát điên. Nàng vui sướng thế nào trong món quà đau đớn. Nụ cười độc ác của nàng, hàm răng xiêu vẹo của nàng... ôi, nó khiến ta rùng mình.\n\nTa ước gì nàng không quất ta, ôi không không. <i>Ta chắc chắn hy vọng nàng không tìm thấy ta ở đây, lười biếng, để rồi quất ta.</i>\nTa sẽ làm gì nếu <i>nàng tìm thấy ta ở đây và quất ta như một cậu bé hư, hư đốn mà ta là</i>.",
    [1214622222] = "Ta đã quá già rồi... ngay cả việc chăm sóc những cây chuối cũng trở nên khó khăn. Ta đã mơ ước sửa sang lại ngôi nhà của mình, thổi luồng sinh khí mới cho nó, nhưng sức lực của ta đã cạn kiệt.\n\nNhững khối xây dựng để sửa mái nhà của chúng ta vẫn nằm trên gác xép, phủ bụi. Ta đoán chúng sẽ ở đó mãi mãi, không bao giờ được chạm tới — giống như bao kế hoạch ta từng có.\n\nThế nhưng... vợ ta tự hào về tất cả những gì ta đã làm. Suy nghĩ đó mang lại cho ta sự an ủi. Có lẽ thế là đủ. Ta là đủ.",
    [1214695666] = "Hàng Rào Gỗ Thô Sơ III",
    [1215005605] = "Một phần mở rộng cho ba lô của bạn, giúp tăng thêm hai hàng kho đồ.\n\n<b>Lỗi thời</b>\nMón đồ này có thiết kế cũ. Hãy đến gặp thợ thủ công của bạn để tìm phiên bản ba lô cải tiến với một hàng bổ sung.",
    [1215082508] = "Giày Huyền Bí",
    [1215588622] = "Mũi Tên Băng Vĩnh Cửu I",
    [1217377132] = "Cứ tiếp tục nào!",
    [1217601385] = "Một di vật hùng mạnh, có khả năng mang lại sự an ủi giữa sự hỗn loạn. Chủ nhân trước đó có thể là một anh hùng đã nghỉ hưu.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các điểm niệm phép và MP. Trang bị <b>điểm niệm phép</b> để niệm.",
    [1217694950] = "Cỏ Thấp Sao",
    [1217722569] = "Khối Phát Sáng Xanh Dương",
    [1217733010] = "Quặng vàng hấp dẫn nhất thường ẩn dưới mặt nước, nhưng hãy cẩn thận khi nhìn thấy ánh vàng lấp lánh dưới đáy suối. Cơn sốt vàng có thể nuốt chửng bạn nếu sóng biển không làm vậy.",
    [1217966695] = "Thầy Thuốc III",
    [1218324269] = "Nghi Lễ Vukah",
    [1218385719] = "Chế tạo Chìa Khóa Sảnh Đường Hollow Vùng Đất Lửa",
    [1218422411] = "Một nguồn tài nguyên thiên nhiên, được nén qua nhiều năm dưới lòng đất, hấp thụ năng lượng ma thuật trong thời gian đó. Nhờ đó, nó có thể tạo ra nhiệt độ cao hơn và được sử dụng cho các quy trình tiên tiến hơn.",
    [1218484468] = "Một Hình Bóng Trên Đường",
    [1218685684] = "Vật Liệu Mọc Hoang",
    [1219296461] = "Rau củ",
    [1219749289] = "Một loài hoa kỳ diệu được biết đến với nhiều ứng dụng tiềm năng, nhưng chủ yếu được sử dụng cho mục đích chữa bệnh.",
    [1220369789] = "Hết Cà Phê",
    [1220636136] = "Khám Phá Đài Obelisk Sương Độc",
    [1220802912] = "Tìm Kho Báu Với Bản Đồ Kho Báu",
    [1221732014] = "Để Chơi Đàn Handpan",
    [1221809074] = "Hãy cân nhắc các đề nghị của ta.",
    [1221867007] = "Sát thương lên Wildlife và Wildbeasts",
    [1222128551] = "Ngọn Lửa",
    [1222489077] = "Hộp Trang Trí Màu Xanh Lá Cây",
    [1222960475] = "Tập Hợp Những Người Sống Sót",
    [1223061795] = "Đôi giày này lý tưởng để rình mồi.",
    [1223141111] = "Chuyển Nước",
    [1223248233] = "Một cái đầu Cyclops bằng xương ghê rợn. Bạn có thể nhét cả nắm tay vào hốc mắt khổng lồ của nó!\n\nBộ sưu tập này được tìm thấy ở Đỉnh Albaneve. Nó có thể được lắp ráp lại để tạo thành một Bộ Xương Cyclops trên Đế Tượng Cyclops.",
    [1223965162] = "Tìm Kiếm Trại Buôn Lậu",
    [1224259888] = "Bàn Gỗ Cọ",
    [1224504796] = "Cửa Cổ Bí Mật",
    [1224688324] = "Sát thương Đũa phép",
    [1224714584] = "Chiếc mũ này còn tăng cường thị lực của bạn và khiến ánh mắt bạn rực cháy hơn cả ngàn mặt trời.",
    [1225016199] = "Hỡi Hỏa Sinh! Ta cần sự giúp đỡ của ngươi… Ta không thể ăn thêm thìa súp cá nào nữa.",
    [1225124855] = "Hãy Đi Câu Cá",
    [1225260811] = "Dao Găm Cho Nghệ Sĩ",
    [1225416091] = "Tia Lửa Của Rừng Revel",
    [1225554294] = "Đèn Hiệu Pháo Sáng",
    [1226782072] = "Chúng ta cần thêm hoa huệ cho đèn ấp trứng Rồng Con.\nChỉ ánh sáng rực lửa mới khiến Rồng Con muốn chui ra khỏi trứng.\n\nTha'Riel nói với ta rằng Rồng Con nghĩ đó là mặt trời trên đường chân trời.\nTa hy vọng tất cả chúng sẽ nở sớm, trước khi Kra'Thul đến và đập vỡ trứng.\n\nThật là một cuộc đổ máu khủng khiếp — thật nhiều việc phải dọn dẹp.",
    [1227181089] = "Sảnh Hollow Bí Ẩn",
    [1229692676] = "Thời Gian Hồi Chiêu Phép Thuật Huyết",
    [1230812543] = "<craftingstation>Trạm Nhuộm Màu</craftingstation>",
    [1231439532] = "Khối Gỗ Quét Hắc Ín",
    [1231783785] = "Để ta làm mới cho ngươi.",
    [1232557801] = "Khu Vực Săn Bắn Bí Mật",
    [1233237070] = "Đây là một loại trà thảo mộc có thêm hoa long đởm lấp lánh. Những bông hoa tạo ra kết cấu mịn màng và kéo dài Thời gian của bạn trong Sương độc.",
    [1233364333] = "Cảng Pike",
    [1234512657] = "Khai thác trong Sương độc Đỉnh Albaneve",
    [1234656933] = "Nhiều loài ba thùy cổ đại, hoàn toàn tĩnh lặng và được bảo quản trong lớp trầm tích hóa đá.\n\nBộ sưu tập này được tìm thấy ở Rừng Revel.",
    [1234859601] = "Tôi chưa bao giờ biết rằng Người xưa từng xây dựng các công trình ở đây. Mẹ tôi, Nữ hoàng Pikemead, gọi Đầm lầy Đen là vùng đất vô chủ. Liệu bà có giữ bí mật với tôi sau tất cả?\n\nChúng tôi đã đặt một chiếc bình vào tòa nhà chính và học được ý nghĩa của việc <i>\"gửi tín hiệu đến những người xứng đáng\"</i>.\n\nNgười xưa đã tạo thành một vòng tròn và vươn tay về phía bầu trời. Một người nói bằng một ngôn ngữ xa lạ khi chòm sao trên bầu trời đêm <i>thay đổi.</i>\nĐầu tiên, các vì sao bắt đầu nhấp nháy, rồi giật giật. Tôi nghĩ mình đã thấy bầu trời vỡ tan thành hàng nghìn mảnh, tất cả đều lấp lánh phía trên, phản chiếu ánh sáng từ chính mắt tôi như một chiếc kính vạn hoa. Một sự khúc xạ rõ ràng của tất cả, đối xứng và thần thánh. Ánh sáng làm lóa mắt tôi khi đầu tôi bắt đầu quay cuồng, và tôi ngã xuống đất, nơi tôi tỉnh dậy sau đó.\n\nCó lẽ đây là những bí mật mà cả mẹ tôi và tôi đều phải giữ.\n\n— Nữ hoàng Jezmina",
    [1235303239] = "Công Thức Chế Tạo",
    [1235361556] = "Đang chờ vật liệu...",
    [1235589325] = "Bạn đã tìm thấy Sảnh Hollow tại Đỉnh Albaneve. Hãy xuống và đến cuối để làm hài lòng <npc>Nhà Sưu Tầm</npc>.",
    [1235745756] = "Sát thương lên Wildlife",
    [1236166011] = "Bức Tường Bậc Thang Đảo Ngược",
    [1236179855] = "Kính gửi Giám sát,\nTôi đã hy vọng viết lá thư này một cách tôn trọng để cảm ơn ngài vì cơ hội được làm việc ở đây, nhưng tôi không thể tiếp tục giả vờ nữa. Sự thật là, công việc này đang hủy hoại tôi. Lao động quá sức: ngày qua ngày vung vẩy công cụ cho đến khi cơ thể tôi kiệt sức, chỉ để gục ngã trong những chiếc lều tồi tàn hầu như không che chắn cho chúng tôi. Thật là vô nhân đạo.\n\nVà bây giờ, sương mù. Cái sương mù chết tiệt đó bò vào từ các trục phía sau. Không ai trong chúng tôi biết đó là gì, nhưng tất cả chúng tôi đều cảm nhận được nó. Những cơn đau đầu, bàn tay run rẩy, những giấc mơ kỳ lạ — đừng nói với tôi rằng đó là vô hại vì tất cả chúng tôi đều biết nó không phải vậy. Một số người đàn ông trông đã như bóng ma của chính họ.\n\nTôi sẽ không phải là người tiếp theo. Tôi sẽ không đợi cho đến khi mỏ và sương mù hoàn toàn nuốt chửng tôi. Tôi nghỉ việc. Hãy để người khác làm việc cật lực và mất trí vì ngài. Nếu quặng quan trọng với ngài đến vậy, ngài có thể tự mình đào nó lên.",
    [1236353292] = "Những ghi chép từ nhà nghiên cứu <lorename>Loraine Crim</lorename> chi tiết về vị trí của các đài kỷ niệm ở Rừng Revel, Cao nguyên Du mục và Vùng Đất Cháy.\n\nĐọc đài kỷ niệm ở Rừng Revel để tiếp tục!\n\nĐọc tất cả các đài kỷ niệm đã đề cập ở trên để hoàn thành nhiệm vụ!",
    [1236418522] = "%km",
    [1236716836] = "Tăng thêm cơ hội chí mạng cho vũ khí cận chiến.",
    [1237221737] = "Đài Lửa Hầm Mộ Bằng Sắt",
    [1237250642] = "Đã nghỉ ngơi",
    [1238256254] = "À, cảm giác thật tuyệt khi đặt chân trở lại đất liền! Giả dạng một người lính là một quãng nghỉ thú vị, nhưng nhảy múa với gió như một người sành diều mới là điều hấp dẫn nhất, ta tin! \n\nTuy nhiên, sâu thẳm trong tim, ta vẫn là một nhạc sĩ khiêm tốn — một nô lệ của giai điệu tuôn trào từ trái tim đau khổ của ta! Vâng, ta tuyên bố: Chính khát khao sáng tạo đã đưa ta trở về — đó là lời của nỗi sợ kền kền mới phát hiện của ta. Chúng ám ảnh không chỉ những đỉnh cao quanh tiền đồn cũ của ta, mà cả những giấc mơ của ta nữa... dù sao đi nữa!\n\nTa đã trở về với tình yêu của đời mình: âm nhạc! Và thế là, nữ thần của ta yêu cầu ta thử vận may tại triều đình của Chúa! Ta nghe nói người này có gu thẩm mỹ tốt và một cái lưỡi sắc bén với những kẻ xúc phạm đến nó. Ta có thể tham gia bữa tiệc của hắn, <i>hoặc chiêm ngưỡng bộ sưu tập chiến tích săn bắn của hắn</i> — nhưng sự lo lắng không phù hợp với ta. Hơn nữa, nguy hiểm đối với một kẻ liều lĩnh cũng giống như một giọt mưa trên cánh hồng. \nNó chỉ làm cho buổi tối thêm ngọt ngào.\n- \"May mắn\" Chester Loft",
    [1238480401] = "Hộp Trang Trí Màu Lục Lam",
    [1238489531] = "Sát thương Kiếm dài",
    [1238655365] = "Bóng Đêm",
    [1240248283] = "Tiền Đồn",
    [1240792923] = "Kháng Lửa Lạnh",
    [1241318146] = "Ta từng có một món đồ trang sức rất đặc biệt: một chiếc lược chải tóc quý giá với tay cầm bằng gỗ khắc và lông từ loài vật dễ thương nhất trên đời — Capybara. Ta đã nghĩ mình sẽ không bao giờ nhìn thấy chúng ngoài đời, nhưng suối nước nóng mà chúng ưa thích lại gần hơn bao giờ hết! Chúng ta nên nhận nuôi một vài con. Elio cũng sẽ đồng ý! Ngay cả khi chúng ta dùng lông của chúng cho nhiều việc hơn là chăm sóc tóc!",
    [1241436627] = "Chọn Ngọc",
    [1241874935] = "Trang Bị",
    [1241957677] = "Chọn một thuộc tính để biết thêm thông tin.",
    [1242109230] = "Tab Trước (Trình Xem Vật Phẩm)",
    [1242736817] = "Cái đầu bị chặt lìa của một gã khổng lồ đáng sợ. Nó nhìn xuống ngươi với vẻ khinh bỉ.\n\nThu thập nhiều Đầu Khổng Lồ để chế tạo Tượng Đài.",
    [1242751931] = "Chịu Đựng Sương Độc",
    [1243015678] = "Trứng Tráng Nấm",
    [1244032328] = "Giáp Phép Thuật",
    [1244076063] = "Tia Hồi Máu",
    [1245220746] = "Vật Tư",
    [1245443831] = "Để lại dấu ấn",
    [1245723465] = "Đã hoàn thành tất cả nhiệm vụ Embervale bị bỏ lỡ",
    [1245864171] = "Ngừng Canh Gác",
    [1246440187] = "Tường Rào Gỗ IV",
    [1246642742] = "Tàu Đốt đã bị hỏng trong quá trình thử nghiệm. Con chuột ta dùng bên trong đã bị cháy đen bởi ngọn lửa ngưng tụ. Một tia sáng chói lòa, rồi không còn gì nữa. May mắn thay, tác dụng phụ gây mù chỉ là tạm thời.\n\nTa đã có một đối tượng mới. Một con chuột khác, Igni. Hy vọng, con đường cứu rỗi của chúng ta. Ta không thể chấp nhận thêm bất kỳ thất bại nào nữa. <i>Ta sẽ đảm bảo Tàu Đốt giữ vững như thể mạng sống của ta phụ thuộc vào nó. Có lẽ nó thực sự vậy.</i>\n\nBalthazar",
    [1246760120] = "Thu thập vật liệu cho bản thiết kế Địa hình bằng cuốc chim.",
    [1246868327] = "Khúc Ca Tán Tụng <lorename>Pikemead</lorename>",
    [1247085407] = "Phóng to/thu nhỏ",
    [1247090206] = "Tay Vịn Thép",
    [1247235110] = "Máy Cưa Bàn",
    [1247289881] = "Hút SP",
    [1247526827] = "Đất Nóng Rừng Revel",
    [1247859890] = "Giày Lông Xù",
    [1248074154] = "Ngươi có thể nâng cấp ngọc để cải thiện sức mạnh hiệu ứng của chúng.\n\nĐặt một viên ngọc vào vũ khí đã được nâng cấp hoàn chỉnh để sử dụng hiệu ứng của nó.\nNgươi cũng có thể tháo ngọc khỏi vũ khí, vì vậy lựa chọn của ngươi không phải là cố định!\n\nCuối cùng, ngươi có thể tái chế những viên ngọc không sử dụng để nhận Tinh Hoa Cổ Đại. Tinh Hoa Cổ Đại được sử dụng để nâng cấp và đặt ngọc.",
    [1248312700] = "Găng Tay Đại Pháp Sư",
    [1248880136] = "Đã nhận Nhẫn",
    [1249149348] = "Fyraszh",
    [1249198906] = "Chúng ta ngồi giữa những mỏm đá và mũi dao găm, được thánh hóa bởi tuyết tinh khiết. Để tìm kiếm sự thấu hiểu, để đòi lại sự đoàn kết mà giống loài chúng ta đã mất trong sương mù.\n\nThật là một vùng đất rộng lớn và lộng gió. Thật là một tiếng vọng tĩnh lặng, bất lực và tan vỡ. Tâm trí chúng ta bị đóng băng tại chỗ, không thể lay chuyển, không thể tiếp cận bằng lý trí hay lòng trắc ẩn. Chúng ta bị chia cắt như những thung lũng, được bao bọc bởi những vách đá ngà voi đâm xuyên qua cơ thể chúng ta, làm biến dạng bản thể chúng ta và buộc tay chúng ta.\n\nMột số chúng ta sẽ trỗi dậy. Một số chúng ta sẽ ở lại. Những người lớn tuổi sẽ tinh khiết, những người trẻ tuổi sẽ lạc lối và tan chảy thành những hình dạng mới.\nChúng ta không còn là một. Chúng ta là hai ngọn lửa song sinh nhảy múa theo những giai điệu khác nhau.",
    [1249264755] = "Hồi phục một phần HP khi ngủ.",
    [1249337478] = "Ngắm bắn",
    [1249480266] = "Một cây đàn hạc thiên đường với dây đàn bằng bạc, được yêu mến bởi dân thường và cả vua chúa.",
    [1250030892] = "Bộ sưu tập",
    [1250573523] = "Nhận Khối Gạch Giếng",
    [1250587022] = "Vui lòng đảm bảo bạn đã nhập đúng địa chỉ IPv4.",
    [1250680293] = "Quần Người Khôn Ngoan",
    [1250734937] = "Thợ săn <npc> không ở trong quán trọ ở <location>Westcott</location>. Cô ấy tránh tiếp xúc với con người. Thay vào đó, cô ấy hẳn đã dựng <b>trại gần đó</b>. <craftingstation>Cây Suốt Tay</craftingstation> của cô ấy không còn xa.",
    [1250811204] = "Coi chừng Hollow",
    [1251131988] = "Cung Tết Nguyên Đán",
    [1251219733] = "Ném chiếc bình huyền bí này để triệu hồi tạm thời một người bạn đồng hành là đầu lâu.",
    [1251675824] = "Một phần của Giáp Chiến Binh.",
    [1251754964] = "Thật là một câu chuyện hùng tráng!",
    [1251850534] = "<lorename>Lupa</lorename> —\n\nTa không thể chờ đợi thêm nữa. Với hơi thở dồn dập, ta đã đến Umber Hollow để <b>đối mặt với Nhà Thầu.</b> Dưới lưỡi dao, hắn nói với ta rằng ngươi đã thoát khỏi chảo lửa và rơi vào đám cháy! Hắn nói ngươi đã bị bắt và nhốt trong <location>Nhà Tù Quạ</location>! <i>Đừng lo lắng. Họng hắn đã bị cắt, cơ thể lạnh ngắt. Hắn sẽ không làm phiền gia đình ta nữa.</i> Tất cả đều héo úa và chết đi như nhau... những mảnh gương vỡ của cùng một câu đố.\n\n<b><location>Nhà Tù Quạ</location> không thể giam giữ ngươi, chị gái.</b> Ta sẽ giải thoát cho ngươi. Hãy cảnh giác và sẵn sàng cho cuộc giải cứu của ta. Chúng ta sẽ trả thù và thống nhất vùng đất này.\n\nBên cạnh ngươi,\nKendal",
    [1251995069] = "Bảo vệ người mặc khỏi tia lửa bắn ra, những luồng gió lạnh đột ngột và các vụ nổ lửa bất ngờ.",
    [1253079539] = "Lò Sưởi",
    [1253421919] = "Trò Chơi Mới",
    [1253809282] = "Một vật liệu làm tổ phức tạp và đan xen, dùng để xây dựng những ngôi nhà trên cây xa hoa.",
    [1253986012] = "Một lưỡi kiếm lạnh lẽo được ban cho sức mạnh của băng giá. Chạm trực tiếp vào nó sẽ làm đóng băng đầu ngón tay của ngươi.",
    [1254033311] = "Vừa là nguyên liệu nấu ăn vừa là hạt giống cho đồng ruộng.",
    [1254369553] = "Những Quái Vật Dưới Lòng Đất",
    [1254562583] = "Vô hiệu hóa",
    [1254838802] = "Đài Phun Nước Bằng Vàng Đính Khắc",
    [1254916399] = "Kẻ Sống Trong Tường",
    [1254955470] = "Tái Chinh Phục Hoang Dã",
    [1255090875] = "Ngươi đã phát hiện một ghi chú tại Nhà Weaver nói rằng Kaori Conway có một văn phòng ở <location>East Lapis</location>. Tìm kiếm khu vực được đánh dấu trên bản đồ của ngươi để điều tra văn phòng của cô ấy!",
    [1255506984] = "Chọn Bài Hát Trước",
    [1255742914] = "Rất vui được gặp ngươi!",
    [1255868766] = "Hiển thị trên Bản đồ",
    [1257228944] = "Trại Nữ Hoàng Jezmina",
    [1257241764] = "Tìm Kiếm Thanh Kiếm Lửa Lớn",
    [1257431220] = "Bình Máu",
    [1257724286] = "Làm Chủ Tháp Lòng Chảo Cổ Đại",
    [1257793250] = "Nhận Ngọc Sói",
    [1258591374] = "Sát thương lên kẻ địch Phép thuật",
    [1258687766] = "Ghi Chú Từ Một Người Bạn Mới",
    [1259136051] = "Nhận một điểm Thể lực cho mỗi hai cấp độ của Ngọn Lửa.",
    [1259601940] = "Kháng Độc",
    [1259973504] = "Màu nâu sẫm và xanh lá cây tạo cảm giác như một khu vườn mọc um tùm hoặc một khoảng trống huyền bí.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Cao nguyên Du mục.",
    [1260054281] = "Đang hồi sinh...",
    [1260161312] = "Các mẫu hàng hóa mới trông có vẻ ổn. Nếu chúng ta cử Eryn đi thì có thể dễ dàng tuồn hàng qua lính canh đất liền. Cô nàng liếc mắt đưa tình có thể vượt qua hầu hết các cuộc tuần tra, đúng là chim đẹp. Kẻ tiếp tay của chúng ta ở The Pike sẽ lo phần còn lại. Hàng hóa sẽ sớm được đưa ra biển.\n\n...Than ôi, hết giẻ rách rồi. Ta không nghĩ chúng có thể chống đỡ được nhiều, nhưng thủy thủ đoàn cảm thấy yên tâm hơn khi có thứ gì đó che miệng. Không khí dơ bẩn dạo gần đây. Ta sẽ xé một chiếc áo khác và bỏ qua chuyện này.",
    [1260169355] = "Lọc tên máy chủ: ",
    [1260179821] = "Một phiên bản cải tiến nhẹ của Mũi tên Gỗ, được gia cố bằng một mảnh kim loại phế liệu ở đầu.",
    [1260462400] = "Tủ Đầu Giường Gỗ Thô Sơ",
    [1260505617] = "Sau khi nhặt một Quả cầu HP, mỗi đòn tấn công gây thêm sát thương. Có cơ hội tạo ra Quả cầu HP khi tiêu diệt kẻ địch.",
    [1260605557] = "Trại Thợ săn <npc> bị bỏ hoang</npc>",
    [1260875638] = "Nhìn Vào Hư Vô",
    [1262017188] = "Thời gian hồi chiêu",
    [1262121710] = "Mũi Tên Xương",
    [1262250750] = "Xây Giường Che Chắn Cho Athalan Skree",
    [1262594484] = "Đuốc Đầu Lâu Hầm Mộ",
    [1262705580] = "Găng Tay Đạo Tặc",
    [1262708000] = "Mũ Giáp Thuật Sĩ Hắc Ám",
    [1262776524] = "Có câu chuyện phiêu lưu mới nào cho ta không?",
    [1263389434] = "Cánh cửa này bị khóa trong bản demo. Nếu bạn muốn xem những gì ẩn giấu phía sau, hãy cân nhắc chơi bản đầy đủ. Hãy theo dõi!",
    [1263719879] = "Khối Ngói Lợp Quét Hắc Ín",
    [1263947284] = "Vật liệu óng ánh tự nhiên tạo nên ngọc trai, có thể tìm thấy ở lớp lót bên trong một số vỏ sò và được đánh giá cao vì ánh sáng lấp lánh của nó.",
    [1264519439] = "Tất cả sát thương <b>Lửa</b> tăng thêm <b>10%</b>.",
    [1265128244] = "Đánh bại Kẻ địch bên trong Lò rèn",
    [1265131432] = "<i>(Các hình khắc rất tinh xảo, và mỗi nét vẽ dường như được đặt cẩn thận. Một tấm bảng ở dưới cùng ghi: Ví dụ về chữ viết Drak tiên tiến, được phục hồi từ một ngôi đền bị ngập lụt. Tuổi ước tính: Cổ đại)</i>\n\nKính chào Vesztah, Đại Mẫu Nòi Giống.\n\nNàng, người đã lớn lên từ một giọt máu duy nhất.\nNàng, người đã trỗi dậy từ biển hỗn loạn trong mắt bão.\n\nNàng, người đã dệt nên những con sóng cho Merphisz.\n\nNàng, người đã thắp lên trái tim của Fyraszh.\n\nNàng, người đã ban cho Arisztar đôi cánh.\n\nNàng, người đã ban cho Dalszul vàng và giá treo cổ.\n\nNàng, người vừa là mẹ vừa là cái miệng.\nCái tử cung và nấm mồ.\nNgười ban tặng và Kẻ hủy diệt.\nĐấng cai trị vĩ đại của Ark Morgo.\n\nTrong lòng nàng, chúng ta lớn lên.\nTrong lòng nàng, chúng ta bắt đầu.\nDưới sự giám sát của nàng, chúng ta chịu đựng hoặc thành công.\nVà trong vòng tay nàng, chúng ta sẽ kết thúc.",
    [1265250736] = "Ta luôn có năng khiếu về phép thuật, nhưng ta đã từ bỏ con đường đó từ nhiều năm trước.\nKhi còn trẻ, ta thường lảng vảng gần Ao Dệt Mạng ở phía Đông Bắc. Cái lạnh buốt không làm phiền ta, vì ta quá tập trung vào cảnh tượng diễn ra mỗi khi các <i>phù thủy</i> đến luyện tập.\nVới một cái vẫy tay, họ khâu những tinh thể băng vào không khí và thêu lên hồ băng một mạng lưới các vết nứt tinh tế.\n\nMột buổi tối nọ, một học viên mà ta không nhận ra đã nghiêng người quá mạnh vào phép thuật của mình, làm trượt băng dưới chân. Chắc là một tân binh - vừa thêu ánh sáng phương bắc trên bầu trời trong một khoảnh khắc, vừa trượt xuống nước trong khoảnh khắc tiếp theo.\nTa đứng ở mép ao, chờ anh ta nổi lên, nhưng <i>thiết bị phép thuật ướt sũng</i> của anh ta đã kéo anh ta khỏi cực quang và chìm xuống đáy. Nếu đêm lạnh không kéo ta đi, ta vẫn sẽ chờ đợi.\n\nĐó là cách ta chọn một cuộc sống yên tĩnh, chìm đắm trong hơi ấm của lửa thay vì vực sâu của hồ băng giá.",
    [1265842096] = "Động vật",
    [1266042214] = "Thành phố Cổ đại bị nhấn chìm",
    [1266153663] = "Ahhh, một chỗ khô ráo để nghỉ ngơi xương cốt mệt mỏi... Ta gần như cảm nhận được hơi ấm thấm vào.",
    [1267198579] = "Đừng rời xa ta!",
    [1267654062] = "Sương độc ban sức mạnh không chỉ cho Fell, mà còn cho bất kỳ ai uống từ bình này.\n\nTăng SP thêm 20.",
    [1267717875] = "Ốc đảo?",
    [1267928071] = "Có sai không khi có một người dì yêu thích? Có lẽ. Nhưng nó cũng rất con người. Thật sâu sắc, phải không? Ta có nên quay lại làm thơ không? ",
    [1268561355] = "Rìu Anh Hùng Chiến Tranh Hoàng Kim",
    [1268819259] = "Nhắc nhở: Không được ăn cho đến khi có thông báo khác!!",
    [1269067881] = "%k × %k (Bản địa)",
    [1269184758] = "Đã tạm dừng...",
    [1269456538] = "Hồ Cao nguyên Du mục",
    [1269490998] = "Sương độc chết chóc đang dập tắt bạn. Chẳng mấy chốc bạn sẽ chết.",
    [1269524269] = "Đã đến điểm định vị",
    [1269680284] = "Bạn đã đến Vịnh Stillwater. Chắc chắn phải có thiết bị pha cà phê phù hợp ở đây.\n\nNhìn xung quanh để tìm một dụng cụ pha cà phê phù hợp!",
    [1269798340] = "Cuộn Kinh Nghiệm",
    [1270640949] = "Phần trang trí sáng bóng trên món giáp này tỏa sáng rực rỡ và nhằm tôn vinh Ngọn lửa vinh quang.",
    [1271156335] = "Đỉnh Mái Thẳng",
    [1271690092] = "Cây Nấm Kim",
    [1271903327] = "Khói và Ngọt",
    [1272369477] = "Chiếc mặt nạ che giấu khuôn mặt, nhưng không che giấu ý định. Bạn ở đây để bảo vệ một người.",
    [1272657066] = "Chiếc cúp này chứng minh rằng bạn đã đánh bại thủ lĩnh của chúng một lần nữa. Trong mắt chúng, bạn hẳn trông giống như một vị thần. Tuy nhiên, chúng sẽ không tôn thờ bạn, chúng sẽ chỉ càng khinh ghét bạn hơn.\n\nThu thập nhiều Đầu Hydrak'Dal để chế tạo Cúp Vàng.",
    [1272887757] = "Không có vật phẩm nào có thể nâng cấp",
    [1272984971] = "Thức Ăn Cho Mèo",
    [1274351197] = "Tìm Sáo Hiếm Gần Đó",
    [1275500579] = "Ám khí",
    [1276186835] = "Triệu hồi <npc>Nông dân</npc>",
    [1277314041] = "Những chiếc găng tay này mang lại cho bạn sự bảo vệ đầy đủ khi tham gia chiến đấu cận chiến.",
    [1277448274] = "Vukah và Wildlife",
    [1277459343] = "Ta tưởng đèo nghĩa địa an toàn, nhưng \"<lorename>Lupa</lorename>\" đã nắm giữ mọi tuyến đường thương mại trong tay sắt! Chúng nhảy ra từ phía sau một cột đá, hung dữ và hoang dại. Run rẩy vì giận dữ. Chúng nhận ra mặt ta... tìm thấy \"Đồ dùng cho trẻ sơ sinh\" ở <location>Nơi trú ẩn của Surat</location>. Ta biết ngày nào đó chúng sẽ là sự diệt vong của ta.\n\nCatherine đã đúng - không thể nào lọt qua các cuộc tuần tra mới. Chúng ở khắp mọi nơi. Chúng đã tịch thu <i>hầu hết</i> hàng hóa của ta... Ít nhất thì ta cũng giấu <b>chiếc rương</b> của mình trước khi chúng bắt được ta. Nhưng làm sao ta có thể thoát khỏi đây bây giờ?\n\n— Benni",
    [1277796187] = "Nấu ăn bên lửa trại",
    [1278139922] = "Bạn đã mang cho tôi một số <craftingstation>Dụng cụ Mộc</craftingstation>! Tuyệt vời! Hãy đặt chúng ở gần đây để tôi có thể bắt đầu công việc!",
    [1278706163] = "Chất lượng",
    [1278784991] = "Biểu thị cấp độ của Sương độc mà bạn có thể vào.",
    [1278912229] = "Đòn chí mạng bằng vũ khí Phép thuật gây thêm <b>2 Sát thương Sốc</b> cho mỗi điểm Trí tuệ lên tất cả kẻ địch trong phạm vi <b>20</b> mét tính từ mục tiêu.",
    [1279131909] = "Đèn Gắn Tường Xanh Dương II",
    [1279412662] = "Tỷ lệ thời gian nhân vật người chơi có thể ở trong Sương độc.",
    [1279693982] = "Cúp Danh Năng Lưỡi Hái Sa Ngã",
    [1279753548] = "Bình sinh tồn Sương độc",
    [1280199970] = "Kho chứa thô sơ, nhưng dễ chế tạo. Nó có không gian cho một vài vật phẩm.",
    [1281100830] = "Tăng ST Xuyên ",
    [1281514523] = "Thợ rèn đã rèn Lưỡi kiếm Than khóc cho con gái mình, một chiến binh vĩ đại. Cô ấy đã từ chối mang thanh kiếm.",
    [1283048737] = "Một khối xây bằng đá được làm từ đá granite. Nhiều khoáng chất bên trong mang lại cho nó một vẻ ngoài lốm đốm đặc biệt.",
    [1283713994] = "Một mảnh vải đặc biệt đã được thêm vào chiếc mũ sát thủ này để che giấu khuôn mặt của người đội và nụ cười đáng sợ nhất của họ.",
    [1283742881] = "Con người & Địa điểm",
    [1283747971] = "Vì vinh quang của <lorename>Pikemead</lorename>, miệng ta khô hơn cả Vùng đất Khô cằn. Ta nhớ cơn khát và cái hầm tồi tàn này... nhưng giờ ta đã an toàn, nhờ có ngươi! Ta là Ramone Jones! Nhà văn, phóng viên, biên tập viên và người nói sự thật bị buộc tội phản quốc! Thông thường, ta không khoe khoang về điều sau, nhưng nếu mọi lính canh đều chết, thì kiểm duyệt cũng vậy!",
    [1284161822] = "Giày Mặc Nhà Ngày Nắng",
    [1284284178] = "Đã khóa",
    [1285319923] = "Đỉnh Albaneve",
    [1285392115] = "Ánh sáng của đài phun nước màu hổ phách rực rỡ bao phủ bầu trời đêm khi Arisztar nở ra. Anh ngước nhìn lên, và thấy Fyraszh biến từ thịt thành Ngọn lửa.\n\n<i>\"Tại sao lại bị giới hạn trong đá và cơn thịnh nộ rực Ngọn lửa?\"</i> Arisztar thì thầm. <i>\"Để bản thân bị nuốt chửng bởi Ngọn lửa trong khi ở gần mây - Kẻ hèn nhát đó nên nhảy đi! Bay đến nơi người khác rơi xuống là kỳ tích vĩ đại nhất!\"</i>\n\nVì vậy, anh ta cất cánh và hướng tầm mắt về những vách đá xa xôi. Anh sống trên cao hơn tất cả trong nhiều năm, săn chim, kền kền và rồng trên cao, cho đến khi tinh thần của Đại Mẫu ban cho anh đôi cánh của riêng mình.\nAnh trở thành một thủ lĩnh không bị ràng buộc bởi gió và sớm chỉ huy bộ tộc Drak'Ari - nhưng anh sẽ không hài lòng cho đến khi thực sự bay cao hơn tất cả.\n\nKhi anh ta thực hiện bước nhảy cuối cùng của niềm tin, anh ta kêu lên: <i>\"Đất đai của chúng ta trải dài theo chiều gió thổi! Đôi cánh của ta sẽ che bóng tất cả bên dưới trong bóng tối của chúng!\"</i>\nVới những lời này, anh ta bay đến gần mặt trời hơn. Lông vũ lụa rơi xuống khi anh ta bước vào sảnh của Ark Morgo.",
    [1285730715] = "Giết Quái vật Bị Hủ hóa",
    [1287045623] = "<lorename>Elin</lorename>",
    [1287822179] = "Được rồi, ta thừa nhận",
    [1288318029] = "Trọng Kiếm Chắp Vá",
    [1288483701] = "Chậu Đất Sét III",
    [1288992732] = "Rìu Rèn Sáng",
    [1289181057] = "Lưng Gai Đỏ Nướng",
    [1289859023] = "Bạn chưa khám phá ra cách tạo ra màu này.",
    [1290549880] = "Bột Sinh vật",
    [1290774654] = "Trái tim pha lê, đặt giữa đôi cánh, đập với cơn đói lạnh lẽo của vực thẳm.",
    [1290829995] = "Ngọn hải đăng bị bỏ hoang",
    [1290942101] = "Một thiết bị cho ăn giữ thức ăn cho Hươu Tiên.\n\nNó sẽ cho động vật của bạn ăn khi được đổ đầy thức ăn tương ứng.",
    [1291278884] = "Ngọn lửa",
    [1291742861] = "Cọc Hàng Rào Gỗ Nhiệt Đới Chạm Khắc",
    [1291769286] = "Ôi, người bạn được lửa ban phước của ta: Hollow thì thầm tên ngươi trong đêm khuya. Những cột đá cẩm thạch che giấu nỗi kinh hoàng của chúng. Hãy đến Cao Nguyên Du Mục và gieo rắc nỗi sợ hãi của chúng như cháy rừng! Nhiệm vụ này sẽ gian nan. Hãy chuẩn bị sẵn sàng.",
    [1292198455] = "Hơn một thập kỷ mặc cả, thương lượng và trau dồi kỹ năng của ta",
    [1292434111] = "Khối Mái Sợi Cây",
    [1293127268] = "Obelisk cổ đại",
    [1293164183] = "Không có",
    [1294731129] = "Vô hiệu hóa Tiến trình Cá nhân",
    [1294838716] = "Cải thiện khả năng phòng thủ của bạn trong trường phái sát thương tương ứng.\nMỗi điểm giáp giảm 1 điểm sát thương nhận vào.\nMỗi điểm kháng giảm 1% sát thương nhận vào.",
    [1294920832] = "Phù Điêu Drak III",
    [1295307967] = "Biển báo có thể viết",
    [1295320127] = "Mộ Myrtle",
    [1295662804] = "Cầu mong Ngọn lửa dẫn lối cho bạn!",
    [1297111311] = "*ho* Ai đang làm gián đoạn buổi tập của ta vậy?",
    [1297385883] = "Tăng sát thương lên Wildlife.",
    [1298201795] = "Loài cá này có thể nướng hoặc dùng trong công thức nấu ăn.\nNó cũng có thể được thả về nước và nuôi trong ao.",
    [1298232211] = "Cuộc Săn Tóc: Bình Minh và Hoàng Hôn",
    [1298440525] = "Bình Đền Drak VII",
    [1298709309] = "Phép Thuật | Đạn Gậy phép",
    [1298883318] = "Chờ Đợi Mãi Mãi",
    [1299341428] = "+ Tầm Xa",
    [1299404515] = "Cuộc Săn Mèo",
    [1299539868] = "Khi Thủy Triều Cuối Cùng Giải Phóng Chúng Ta",
    [1299575622] = "Mục Đích Của Đá Quý Vũ Khí",
    [1299627433] = "Một chất axit cần thiết trong sản xuất da, dùng để ổn định và bảo quản lông thú.",
    [1299693315] = "Phát Tiếng Mẫu",
    [1300547034] = "Ngày thứ 4?",
    [1301119427] = "Khóa Mục Tiêu",
    [1301280840] = "Hào Quang Rạng Ngời",
    [1301436537] = "Sức Mạnh",
    [1301767796] = "Cuối cùng, ta có thể bắt tay vào việc! Sản phẩm của ta có thể giúp ngươi, bạn của ta — ta không nghi ngờ gì.",
    [1301780591] = "Đã đến ngọn tháp cổ trong Cao Nguyên Du Mục.",
    [1301877695] = "Sợi nấm đang hoạt động của nấm hấp thụ các đặc tính ma thuật của Sương độc. Liệu điều này có thể được sử dụng cho mục đích giả kim thuật không?",
    [1301970100] = "Bộ Chiến Binh Trỗi Dậy",
    [1302436143] = "Vậy là ngươi đã thu thập được <craftingstation>Trạm Thuộc Da</craftingstation>...? Làm tốt lắm, ta ấn tượng đấy! Đừng chậm lại bây giờ. Hãy chế tạo một vài trang bị nào!",
    [1302469814] = "Sử Dụng Bánh Xe Quay",
    [1302818897] = "Sức Bền Câu Cá",
    [1303017845] = "Nhẫn Thể Lực Siêu Cấp",
    [1303346748] = "Nhận Bảo Vệ Khỏi Băng Giá Trong Căn Cứ",
    [1303516623] = "Giỏ VI",
    [1303802647] = "Ngọn Lửa mang lại sự bảo vệ tạm thời khỏi Sương độc. Nếu sự bảo vệ hết hạn, ngươi phải lập tức thoát khỏi Sương độc. Sự bảo vệ của Sương độc sẽ tự nạp lại khi ở bên ngoài Sương độc.",
    [1304150334] = "Vật Phẩm Thông Thường",
    [1304219471] = "Sử Dụng Móc Leo Núi",
    [1304222732] = "Mở menu phụ để chọn từ các danh mục hình dạng khác nhau.",
    [1304232536] = "Tóc Lấy Cảm Hứng Từ Hoàng Hôn",
    [1304326367] = "Một vũ khí nguyên thủy, nhưng được chế tác tinh xảo để nghiền nát xương kẻ thù.",
    [1304473335] = "Lấy",
    [1304482184] = "Tê Tê Cát Con",
    [1305335963] = "Sát Thương Ném",
    [1305490323] = "Trận chiến bên <B>cầu</B> — ta biết ngươi chắc hẳn đã ở đó! Những kẻ bỏ chạy mang nỗi kinh hoàng trong mắt. \"Sương độc,\" chúng nói với giọng run rẩy. \"Sương độc đã bao phủ tất cả.\"\n\nThế nhưng, quân đội của <lorename>Vorgoth</lorename> vẫn tiếp tục chiến đấu. Xin hãy cho ta biết: ngươi có hít phải nó không? Ngươi vẫn còn ở đó chứ, em trai bé bỏng của ta? Dẫn dắt bầy đàn với tư cách Tư Lệnh?\n\nTa quan sát thung lũng khi mặt trời lên cao nhất, nhưng không phát hiện bất kỳ chuyển động nào. Ta áp tai xuống đất nhưng không nghe thấy tiếng bước chân nặng nề. Nếu ngươi ở đó, xin hãy cho ta một dấu hiệu, <lorename>Talion</lorename>. Ta sẽ cõng ngươi ra ngoài, giống như những ngày xưa.\n\n— Chị gái của ngươi, Athalan",
    [1305932590] = "Cọc Hàng Rào Thép",
    [1306612614] = "Tự Động",
    [1307796195] = "Một đôi ủng vừa vặn để hoàn thiện bộ giáp Pháp Sư. Các chi tiết màu tím tạo nên tổng thể hài hòa.",
    [1308750107] = "Không có thiết bị chế tạo nào khả dụng.",
    [1309161699] = "Hộp Đựng Bằng Tre I",
    [1309215333] = "Thép — một trong những vật liệu quan trọng và linh hoạt nhất.",
    [1309293289] = "Dù đêm có tăm tối đến đâu, với ánh bình minh sẽ đến giọt sương mai ngọt ngào.",
    [1309630108] = "Hạ Lưu Của Thứ Gì Đó Độc Hại",
    [1309642708] = "Đũa Phép Nổ Lách Tách",
    [1309663640] = "Học",
    [1310400781] = "Tạm Biệt!",
    [1310741889] = "Cột Tổ Tiên Gỗ Drak I",
    [1311467275] = "ST Tầm xa",
    [1312495400] = "Gừng",
    [1313189443] = "Sát thương lên Scavenger",
    [1313374317] = "Đặt ra lượng nước được mô phỏng cho mỗi lần cập nhật. Mô phỏng nước chỉ chạy trên máy chủ.",
    [1313642047] = "Quần Lính Đánh Thuê",
    [1314644360] = "Độ gần của ngươi hiện tại với việc bị hạ thân nhiệt.",
    [1315318910] = "Du Hành Nhanh",
    [1315548166] = "Trạm Phối Màu",
    [1316379079] = "Găng Tay Học Trò <npc>Giả Kim Sư</npc>",
    [1316923662] = "Một cho những chiến binh dũng mãnh:\n\nLấy hạt rang, xay mịn như bụi,\nvà trộn chúng với nước nóng.\nĐể nước cốt đậm đặc và đắng — một loại thuốc mạnh\nđể khơi dậy tinh thần và làm tỉnh táo tâm trí.\n",
    [1317200649] = "Mở",
    [1317366020] = "Cần triệu hồi <npc>Giả Kim Sư</npc> trong căn cứ để hắn cung cấp dịch vụ! Triệu hồi yêu cầu một Gậy phép Triệu Hồi.",
    [1317860733] = "Sử Dụng Búa Xây Dựng",
    [1318118640] = "Tìm Marianne Reed",
    [1318371482] = "Trái Tim Sắt",
    [1318555627] = "Cuốn <craftingstation>Sổ Tay Cây Cối và Hạt Giống</craftingstation> có thể được tìm thấy tại <location>Nơi Nghỉ Ngơi Của Surat</location>. Nó nên được đặt trong căn cứ để trồng trọt tốt hơn.",
    [1318589865] = "Tải trọng máy chủ",
    [1318738495] = "Đánh Dấu Tử Hình",
    [1318905399] = "Tủ Trưng Bày Hành Lang Khô Cốt (3 Khe Nhỏ, 2 Khe Vừa)",
    [1319061858] = "Giày Ướt",
    [1319436432] = "Khi đàn con phát sáng của nó lướt qua những con sóng gần <location><lorename>Tầm Với Của Pikemead</lorename></location>, nó được coi là một điềm lành. Thật không may, không một sinh vật nào, dù nhỏ bé đến đâu, thoát khỏi vòng tay mục nát của Sương độc.",
    [1320175237] = "Chết Không Oan",
    [1320423667] = "Tăng Sát Thương Chí Mạng",
    [1320660016] = "Cây Đũa phép này ban cho sức mạnh lửa cho bất kỳ ai đủ dũng cảm để sử dụng nó.\n\n<b>Quá Tải:</b>\nCây Đũa phép này có cơ hội khuếch đại sát thương đầu ra của nó. Các đòn tấn công gây sát thương cộng thêm lên đến phần trăm <i>quá tải</i>.\n\n<b>Đa Phát:</b> \nBắn nhiều loạt đạn nhưng với sát thương giảm.",
    [1320843741] = "Khung Cửa Sổ Gỗ Chạm Khắc",
    [1321467959] = "Nguồn Nhiệm Vụ",
    [1321622375] = "Ngươi đã tìm thấy một mảnh trang phục tiều phu trong Hầm Mỏ. Có thể còn những mảnh khác ở xung quanh.\n\n<b>Tìm kiếm rương trong Hầm Mỏ để hoàn thành bộ trang phục tiều phu của ngươi!</b>",
    [1321630256] = "Người Nông Dân đã chán món súp cá. Bà ấy muốn ngươi săn lùng những con Cua sống ở Lưu Vực Veilwater, trong và xung quanh các vùng nước, để bà ấy biết mình có thể làm gì.\n\n<b>Hãy quay lại gặp Người Nông Dân với Thịt Cua trong túi của ngươi.</b>",
    [1321742100] = "Tăng ST Sương độc.",
    [1322080402] = "Tuy nhiên, Chạm và Giữ đều bắt đầu bằng Nhấn, và được phân biệt bằng thời điểm Thả. \n\nVì vậy, các liên kết không thể chia sẻ cùng một phím hoặc nút với các cặp này:",
    [1322143076] = "Giếng Tiên Dược là một cái hố bị cây cối mọc um tùm, phun ra sự mục nát và khói từ bên dưới. Hãy vào Giếng Tiên Dược để tìm gốc rễ của cái ác này và tiêu diệt nó.",
    [1322910879] = "Ta vẫn nhớ khi mỗi chiếc gương vỡ có nghĩa là xui xẻo gấp đôi. Hồi đó, ta đổi cái khóa thắt lưng cũ của mình lấy một chiếc kéo mới và dành nhiều ngày sửa mái nhà tiệm làm tóc trong khi ngắm nhìn những vì sao. Ta lần theo các chòm sao như thể chúng sẽ tiết lộ con đường của ta, để ánh sáng bạc của mặt trăng khắc sâu vào tâm trí ta. Nó chào đón ta mỗi khi ta nhắm mắt, <i>cả khi thức và trong mơ.</i> \n\nĐó là định mệnh của ta để làm cho khách hàng của ta tỏa sáng hơn cả mặt trời, nhưng các vì sao đã khắc một số phận mới cho ta. \n\n<i>Khi chiến tranh đến gần, ánh sáng dẫn ta về hướng <location>Pháo Đài Kelvin</location></i>. Những bức tường của chúng ta sẽ không ngăn được cuộc tấn công, và lưỡi dao của ta cũng vậy, vì vậy thần thánh trên trời yêu cầu ta rời khỏi tiệm làm tóc của mình. Đây có phải là một sự hy sinh mà ta có thể thực hiện không? Ta ước gì mình có thể vươn tới các vì sao và tự vướng mình vào mạng lưới chòm sao của chúng, sắp xếp lại các sợi chỉ — áp đặt <i>ý chí của ta</i> lên <i>chúng,</i> chỉ một lần này thôi.",
    [1323089370] = "Búa 2H",
    [1323306868] = "Lông Thú Đã Cho",
    [1323367194] = "Nhẫn Giả Kim Thuật",
    [1323737392] = "Giấc Ngủ Ngon",
    [1324782323] = "Giếng Tiên Dược",
    [1325090553] = "Một ghi chú tiết lộ rằng <lorename>Loraine Crim</lorename> đã điều tra một <b>Đập Cổ Đại</b> trước khi nghiên cứu các Đài Thiên Văn Cổ Đại. Cô ấy đã đánh rơi <keyitem>Dụng Cụ Khoa Học</keyitem> của mình khi trại của cô ấy <b>bị kền kền tấn công.</b> Vị trí đó được đánh dấu trên bản đồ.",
    [1325305471] = "ST Kết liễu",
    [1325409365] = "Xanh Tươi Thật Sự",
    [1325549243] = "Hồi Máu Chiến Đấu",
    [1325847701] = "Tẩm nhựa đường cho các khúc gỗ làm chúng có khả năng chống chịu tốt hơn và hoàn hảo cho mái nhà.\n\nSử dụng <b>Búa Xây Dựng</b> để xây dựng <b>cấu trúc</b> xung quanh Bàn Thờ Ngọn lửa với khối xây dựng này.",
    [1326608301] = "Sàng Khai Thác Mỏ",
    [1326726485] = "Cơ <npc>Thợ Mộc</npc> tiết lộ rằng ông ta đã <b>giấu một kho báu bên trong trụ giữa của Cầu Braelyn</b> như một dấu ấn đặc trưng của mình. Hãy xác định trụ giữa và phá tan đống đổ nát để tìm chiếc rương đó!",
    [1326893252] = "Chùy Đáng Sợ",
    [1327813882] = "Thử nghiệm quá mức đã chứng minh rằng việc trộn chất nhờn và thạch tạo ra bùn. \nTất cả các chất này đều hoàn toàn khác nhau và xứng đáng với đặc điểm riêng của chúng do độ nhớt khác nhau.",
    [1327888182] = "Bạn đã đến trại Scavenger đang giam giữ con mèo. Hãy tìm và thuần hóa con mèo để tiếp tục!",
    [1328411626] = "Yếu tố sự sống dưới hình thức chết chóc nhất của nó. \n\n<b>Phép Thuật Kênh Dẫn:</b> Giữ nút để kênh dẫn <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>Gậy phép.</b>",
    [1328524346] = "Ngươi đã thuần hóa và nhặt một con vật nuôi trong trang trại! Hãy mang chúng về căn cứ của ngươi và đặt chúng xuống! \n\nCon vật nuôi trong trang trại của ngươi sẽ đi lang thang, vì vậy hãy cân nhắc xây dựng một hàng rào!",
    [1328552490] = "Đồng Cỏ Thấp",
    [1329143331] = "Cầu Gai Nước Nâng Cao",
    [1329742258] = "Đá Vụn Lưu Vực Vực Nước",
    [1330036372] = "Một chậu cây trống chờ được lấp đầy đất và sự sống mới. Hãy để hoa nở hoặc cây xanh mọc lên.",
    [1330531706] = "Chỉ ra thời gian Ngọn Lửa có thể bảo vệ bạn trong Sương độc.",
    [1330935251] = "Giày Trò Chơi Mùa Hè",
    [1331308904] = "Cuộc Chạm Trán Vukah ",
    [1331326470] = "Dao Găm Kiêu Hãnh",
    [1331591420] = "Bạn đã khám phá ra rằng nhạc cụ đầu tiên, một cây sáo quý hiếm, có thể vẫn còn ở gần địa điểm <location>Nơi Nghỉ Ngơi Của Surat</location>. Người chủ quán trọ đã từ chối cho các thành viên cũ của ban nhạc ở lại chỗ ông ta sau khi ban nhạc tan rã. Trong đêm, ông ta nghe thấy những giai điệu bên ngoài, nhưng không thể nhìn thấy bất kỳ ai biểu diễn trên đường phố.\n\nĐiều tra khu vực xung quanh quán trọ và tìm kiếm manh mối, cũng như cây sáo quý hiếm!",
    [1331672704] = "Cánh Lượn Bóng Ma",
    [1332152192] = "Hướng tới những chân trời mới",
    [1332608900] = "Tín dụng",
    [1333119680] = "Túi Quà Tặng",
    [1333528877] = "<lorename>Ikora</lorename>, hoặc những gì còn sót lại của bà, đã bị đánh bại. <craftingstation>Cái Vạc Đen</craftingstation> hẳn là nằm trong số tàn tích của bà ta. <npc>Nhà Giả Kim</npc> sẽ có ích với nó.",
    [1334014665] = "Trao đổi để lấy Bảng Màu",
    [1334039316] = "Các điểm nhấn màu đỏ hồng trên nền màu ngà tạo thêm nét lãng mạn, miêu tả người mặc như một anh hùng quyến rũ, dũng cảm.\n\nBảng màu này có thể được chế tạo bằng vật liệu từ Vùng Đất Mùa Xuân.",
    [1334286101] = "Thứ duy nhất Thợ Rèn của bạn cần bây giờ là một chiếc giường có mái che. Hãy cho anh ta tiếp cận <b>một chiếc giường có mái che gần đó nếu bạn chưa làm!</b>\n\nĐể che chở cho những người sống sót của bạn, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở một khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót trống gần nhất khi được đặt. Nếu bạn muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu Hồi của bạn và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho bạn khi những người sống sót của bạn không còn được che chở nữa.",
    [1334617041] = "Rất vui được giúp đỡ.",
    [1334975950] = "Cung Rắn Đuôi Chuông",
    [1335252772] = "Cấp độ",
    [1335349984] = "Tìm Đá Hầm Mộ",
    [1336049564] = " <npc>Thợ Săn</npc>, Athalan Skree, đã cung cấp vị trí của một <b>mỏ muối</b> gần đó. Muối là cần thiết để bảo quản lông thú.",
    [1336059720] = "Được chế tạo từ các thành phần giàu MP, Thuốc MP phục hồi một lượng MP đáng kể.",
    [1336106719] = "Máy Ép Chất Nhờn cho <npc>Nhà Sưu Tầm</npc>",
    [1336162498] = "+ Băng",
    [1336331493] = "Khoảng Thời Gian Ném",
    [1336784596] = "Một khối ngói màu xanh lam, được sử dụng trên các mái nhà dốc của Vùng Đất Lửa.",
    [1337942804] = "Nghi Lễ Đoàn Tụ — Tái Hiện!",
    [1338415011] = "Một chiếc rìu 1H đa năng. Thường được sử dụng để chẻ sọ kẻ th địch.",
    [1338765288] = "Đánh bóng",
    [1338862307] = "Khối Mái Đền Drak",
    [1339541831] = "Một Mảnh Trái Tim Của Ta",
    [1340165596] = "Chiếc tủ lạnh này sẽ giữ cho băng của bạn luôn lạnh vĩnh viễn.",
    [1340984079] = "Áo Vest Thợ Săn",
    [1341201941] = "Không có quyền",
    [1341271902] = "Áp dụng",
    [1341313468] = "Một công cụ giao tiếp truyền thống nhưng mạnh mẽ. Dùng để lưu giữ kiến thức.",
    [1341882996] = "Một vật liệu dễ uốn, đặc biệt hữu ích cho mục đích xây dựng.",
    [1342060758] = "Mồi câu làm tăng cơ hội bắt cá thông thường.",
    [1342181085] = "Một phần của Bộ Giáp Nhà Mạo Hiểm.",
    [1342292461] = "Obelisk Cổ Đại",
    [1342453723] = "Tường Rào Gỗ VIII",
    [1343156648] = "Đất Cao Nguyên Du Mục",
    [1343220600] = "Cối Xay",
    [1343363206] = "Cửa Sổ",
    [1343567949] = "Hiếm khi",
    [1343768464] = "Tiến về phía trước",
    [1343971588] = "Bạn cần một Búa Xây Dựng để xây <b>nơi trú ẩn</b>.\n\n<b>Chế tạo một Búa Xây Dựng</b> trong tab Chế tạo Thủ công. Chọn các khối và bản thiết kế mong muốn để xây dựng khi sử dụng Búa Xây Dựng.\n\nBạn có thể chế tạo các khối xây dựng tại <craftingstation>Bàn Chế Tạo</craftingstation>.",
    [1345047837] = "Trích xuất",
    [1345454442] = "Rơi ra từ nấm trong Sương độc Cao nguyên Du mục",
    [1345552695] = "Sét Dây Chuyền",
    [1345665982] = "Cột Cờ I",
    [1345969953] = "Tăng sát thương lên Drak.",
    [1346663743] = "Dalszul trẻ tuổi đã chứng kiến những chiếc lông vũ rơi từ trên trời xuống, để lại những bóng mờ ảo bên dưới chúng khi chúng nhảy múa.\nAnh ta suy ngẫm: <i>\"Chinh phục bầu trời để làm gì? Đất đai rộng lớn và giàu kho báu! Chúng ta nên tiến về đất liền và hủy diệt trái tim của nó! Hãy để máu của nó nuôi dưỡng đất đai và cơ thể chúng ta!</i>\n\nThế là anh ta cắm móng vuốt của mình vào khối đất lớn nhất có thể tìm thấy, và tạo ra các khối từ đất sét và đá để xây dựng những ngôi đền vinh quang cho chính mình.\nVô số Drak đã làm việc và chết dưới những bức tường của hắn, và khi công trình vĩ đại nhất của hắn hoàn thành với viên gạch cuối cùng, hắn đã cười: <i>\"Mẹ Rồng, hãy nghe ta nói đây! Mọi dải đất, từ cánh đồng đến rừng rậm, đều rên rỉ dưới chân ta! Ngọn giáo của ta có thể chỉ bất cứ nơi nào mắt ta nhìn thấy, và vẫn không thấy được giới hạn nào của lãnh thổ ta!</i>\n\nKhi hắn tiếp tục lời lẽ hung hăng của mình, không thể ngăn cản như một tảng đá lăn xuống dốc, những Drak-Dal trong bộ tộc của hắn từ từ lùi lại. Họ cảm thấy một tiếng rung chuyển trong lòng đất, và trước khi họ kịp nhận ra, một vết nứt lớn trước mặt họ đã xé đôi Trái Đất.\nCông trình dưới chân thủ lĩnh của họ sụp đổ, và Dalszul bị chôn vùi dưới đống đổ nát và bụi bặm, máu của hắn mãi mãi đánh dấu trái tim lãnh thổ của hắn.\nArk Morgo đã lấy đi hắn.",
    [1348073923] = "Khe Hình Dạng Tòa Nhà 2",
    [1348325630] = "Thảm Treo Tường B",
    [1348356083] = "Lưỡi Hái Lửa có khả năng tung ra những đòn tấn công lửa tàn khốc đồng thời phản lại một phần cơn thịnh nộ của kẻ thù về phía chúng.",
    [1348537908] = "Đầu Hydrak'Dal",
    [1348698346] = "Mèo Tinh Nghịch",
    [1349026055] = "Đến Thủ Đô, <location><lorename>Thủ Đô Của Pikemead</lorename></location>",
    [1349376146] = "Hầm Kho Cổ Đại",
    [1349391240] = "Nghỉ ngơi đầy đủ. Bạn cảm thấy tuyệt vời!",
    [1349631948] = "Bộ Trang Phục Chiến Binh Trỗi Dậy",
    [1350064531] = "<lorename>Pikemead</lorename>",
    [1350131898] = "Đầu Nấm Fell",
    [1350605639] = "Công dụng của nó ngay cả người tạo ra cũng không biết, nhưng chắc chắn nó không giúp ích gì cho lớp da của Fell!",
    [1350779692] = "NHÀ Cấp 3",
    [1351314249] = "Khó",
    [1351672962] = "Một dạng năng lượng ổn định. Đốt nó tại Bàn Thờ Lửa có thể bảo vệ chống lại Sương độc.",
    [1351881698] = "<b>Những tên lính bộ binh hẳn đang hành quân ra cảng. Chắc chắn là đang xâm phạm cổng thành.</b> Tôi thật may mắn khi đã kịp lên gác mái bí mật của mình. Tôi không thể nhìn thấy từ đây, nhưng tôi nghe thấy chúng. <i>Chúa tể của chúng, Vệ Binh Phương Bắc, đang niệm chú. Một thứ gì đó tăm tối và ô uế.</i> Bầu trời bên ngoài đang chuyển động? Không, đó là những đám mây! Một tấm màn sương với những dải ánh sáng xanh, nhiều màu sắc. Cái quái gì vậy...\n\nTôi đang nhìn trộm. Tôi thấy rồi. Những viên đá cuội nứt ra như thịt thối rữa. Hắn đang nhấc thứ gì đó lên từ dưới lòng đất...? Tôi không thể nhìn thấy. Tôi phải nghiêng người thêm một chút nữa.",
    [1352292445] = "Lại đây nào!",
    [1352477221] = "Móc Đu Cải Tiến",
    [1352497267] = "Lạc Giữa Sương Độc",
    [1352977194] = "Bạn đã đánh bại Fell Banshee và tìm thấy một viên ngọc vũ khí! \n\nMang viên ngọc mới thu được, một vũ khí phù hợp và Tinh chất Cổ xưa trở lại Lò Rèn Ngọc. \n<b>Sử dụng các thành phần này để gắn một viên ngọc vào vũ khí để tăng sức mạnh cho nó!</b>",
    [1353227567] = "Nhẫn Thu Hồi",
    [1353252917] = "Sương Độc",
    [1353623952] = "Ta Muốn Cưỡi Gió!",
    [1353634178] = "Mục tiêu",
    [1354717587] = "Trang này chưa được khám phá.",
    [1354892010] = "Lửa, con xin tha thứ. Con chỉ muốn chiêm ngưỡng vẻ đẹp và sức mạnh của Người, hãy tin con. Con chưa bao giờ <i>mơ</i> đến việc chiếm đoạt tia lửa của Người. Những lời buộc tội này là <b>sai sự thật!</b>\n\n<i>Ta từng là một thẩm phán, ngươi biết không?</i> Nổi tiếng và được kính trọng! Ta yêu luật pháp như vợ mình, và ta sẽ không bao giờ phản bội một mối liên kết thiêng liêng như vậy.\n\nNhưng ta đã trở thành kẻ bị ruồng bỏ, buộc phải rời bỏ quê hương... Không có bếp lửa, vợ hay người tình nào có thể sưởi ấm ta. Hãy nhấc bỏ lời nguyền Hollow này. Ta thề trước gia đình ta rằng ta là một người tốt.\n\n— Darius ",
    [1355159201] = "Một thương nhân đã bị cướp khi đang đi qua Cao Nguyên Du Mục. Cái chết của hắn có thể dẫn đến thành công của bạn! Hãy tìm <b>chiến lợi phẩm bị bỏ lại gần những bộ xương khổng lồ!</b>",
    [1355507059] = "Còn cần gì nữa không?",
    [1355566275] = "Đỉnh Mái Nhọn",
    [1355571617] = "Ngọn Lửa",
    [1355926917] = "Những chiếc ủng này được tăng cường bằng các tấm kim loại, cung cấp thêm khả năng phòng thủ cho phần ống chân nhạy cảm của bộ xương đang mang chúng.",
    [1356288573] = "Một sự pha trộn rực rỡ của màu xanh pha lê và màu ngọc lam dịu nhẹ nắm bắt được chiều sâu lấp lánh của làn nước trong. Bình tĩnh nhưng sống động, bảng màu này tỏa ra sự tươi mát và rõ ràng của đá aquamarine, toát lên vẻ thanh lịch thầm lặng.\n\nBảng màu này có thể được chế tạo bằng vật liệu từ Lưu Vực Nước Lặng.",
    [1356328562] = "Bạn cảm thấy buồn nôn... SP giảm.",
    [1356871304] = "Lễ Hội Thu Hoạch",
    [1357139338] = "Triệu hồi một bùa hộ mệnh nhỏ dưới chân bạn, hồi máu cho nhóm của bạn định kỳ.",
    [1357387038] = "Dọn cỏ Albaneve Summits",
    [1357391945] = "Ta đang ở đâu...? Này, cẩn thận đấy! Vẫn có thể có sói ở gần đây! Ôi trời, phù hộ cho con! Con không phải là chiến binh — chưa bao giờ, và sẽ không bao giờ!",
    [1357547316] = "Súp Gà",
    [1357660514] = "Cuối cùng! Những con Yak bông xù, lông lá! Ôi, ta sẽ chọn tên cho chúng! Và trong lúc đó, bạn có thể... làm việc, ta đoán vậy!",
    [1358494829] = "Nghiêng trái",
    [1359267444] = "Tên Lửa Xanh Dương",
    [1359652692] = "Bàn Chải",
    [1359689125] = "Gió Trắng",
    [1359818398] = "Những chiếc găng tay da này đã được trang trí bằng kim loại để bảo vệ khớp ngón tay của người đeo.",
    [1361193949] = "Một mũi tên làm từ xương.\n\nSức mạnh của mũi tên này cho phép nó <b>xuyên qua mục tiêu</b> để gây hại cho nhiều kẻ địch.",
    [1361251136] = "Thoải mái - Ngồi",
    [1361999368] = "Chế tạo",
    [1362105023] = "Bạn đã ăn gì chưa?",
    [1362112717] = "Bạn đã khám phá ra vị trí của một Đền Thờ Ngọn lửa bị lãng quên ở Vùng Đất Ngọn lửa. Hãy đến và khám phá địa điểm để thu thập một Tia Ngọn lửa!",
    [1362171641] = "<keyitem>Dụng Cụ Khoa Học</keyitem> Cho Phòng Thí Nghiệm",
    [1362301338] = "Nơi sản xuất",
    [1362332634] = "Một con mắt khổng lồ, không chớp, tràn đầy sức mạnh của Sương độc. Năng lượng áp đảo của nó là một yếu tố quan trọng trong việc chế tạo giáp cao cấp kỳ lạ.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Quái vật Fell Cyclops khổng lồ, ban đầu được tìm thấy ở Albaneve Summits.",
    [1362381818] = "Bộ nhớ đồ họa quá nhỏ.",
    [1362602434] = "Không thể nhuộm màu vật phẩm",
    [1362883290] = "Nếu bạn tìm thấy thứ gì đó giúp tôi nhớ lại công thức nhuộm tóc xanh của mình, xin hãy cho tôi biết!",
    [1363002576] = "Nhẫn Thể Lực",
    [1363711164] = "Muốn đối đầu với những con thú lớn? Hãy mang cho tôi <craftingstation>Trục Quay Tay</craftingstation> của tôi.",
    [1363983014] = "Dù bạn nhìn về đâu, những vách đá thiên thể của sườn núi luôn phủ bóng tối lên các thung lũng. Với món giáp này, bạn có thể hòa mình vào bóng tối và di chuyển nhẹ nhàng như một cơn gió lạnh buốt để tìm kẻ thù.",
    [1364657321] = "Một chiếc rìu có khắc tên được tìm thấy bên cạnh một xác chết. \"Fenrig.\"",
    [1364920283] = "Bạn đã đến tiền đồn bỏ hoang. Các vật phẩm mỹ phẩm bạn tìm kiếm chắc hẳn phải được cất giữ ở đâu đó tại đây.\n\nTìm bộ trang phục hầu gái mỹ phẩm trong tiền đồn!",
    [1364939768] = "Khi còn là một cô bé, hình ảnh phản chiếu chào đón tôi mỗi sáng trên mặt sông dường như thật xa vời. Tôi khi đó thật nhỏ bé. Tôi hạ thấp người, dang rộng tay để cảm nhận dòng chảy dễ chịu luôn thay đổi khi mọi người đi ngang qua. Tôi hầu như không chạm tới đáy.\n\nHình ảnh phản chiếu mệt mỏi của tôi giờ đây ngày càng gần hơn. Dòng nước xoáy lên đầy đe dọa. Có lẽ chẳng bao lâu nữa tất cả chúng ta sẽ chìm vào vòng tay lạnh lẽo của nó. <i>\"Cứ bán nhà đi và chuyển đi\"</i>, họ nói. Bán cho ai? Tất cả những người khác cũng muốn chạy trốn!",
    [1365351697] = "Nó có vị cực kỳ đắng khi còn sống, nhưng lại phát triển một mùi thơm hấp dẫn khi được nấu chín.",
    [1365592009] = "Một phiên bản cải tiến nhẹ của Gậy, được gia cố bằng gai.",
    [1365745710] = "Hạt giống Nghi ngờ",
    [1365979371] = "Bị Tấn Công Bởi Một Cây Dây Leo Độc Ác",
    [1366030286] = "Chúng tôi đã giữ hy vọng, đào bới qua đống đổ nát, môi thì thầm cầu nguyện với các Cổ Thần. Luôn có một con mắt cảnh giác hướng về đường chân trời. Ngay cả ở góc xa xôi nhất của thế giới này, Sương độc vẫn đe dọa nhấn chìm chúng ta và che giấu mọi tia hy vọng.\n\nKhi không khí đặc quánh bởi làn sương nguyền rủa đó, chúng tôi đã kiên cường. Khi lửa bùng cháy trên đường chân trời, tro bụi rơi như tuyết trên Đỉnh Sóng Gió, chúng tôi đã cố gắng hết sức. <b>Mong rằng ngôi nhà này, đã được gìn giữ từ lâu, sẽ đưa chúng ta vào kỷ nguyên tươi sáng.</b>",
    [1366218716] = "Mong muốn chiến đấu chưa được thỏa mãn của bạn đã vô hiệu hóa khả năng hồi phục HP, MP và SP của bạn.",
    [1366658799] = "Bạn thân mến của tôi, có một sự xáo trộn trong xương cốt mà tôi không thể bỏ qua được nữa. Một cái lạnh khô héo còn đọng lại trong lồng ngực, bám lấy phổi tôi, và đóng băng hơi thở của tôi. Bụng tôi trống Hollow như nhà kho của người nông dân sau vụ thu hoạch bị hỏng do sương giá sớm... và nó đòi hỏi một bữa tiệc thịnh soạn. Hãy lấy chìa khóa của tôi và đốt cháy các Đại Sảnh Lạnh Giá.",
    [1366669719] = "Cuối cùng — Tàn tích của một thời đại khó nắm bắt, bị vứt bỏ.\n\nChìm trong sóng nước. Một cái ác khác — một sai lầm — đã bị gạt bỏ, và niêm phong.\n\nHãy để nước cuốn trôi mọi thứ ô uế. Sau chúng ta, là lũ lụt.",
    [1366694124] = "Khu Trại Khai Quật Đập Eldermere",
    [1366882411] = "Đây là một phiên bản nâng cấp của Rìu Phương Bắc. Đầu rìu có thiết kế phức tạp, điển hình cho nghề thủ công phương Bắc.",
    [1367170792] = "Cửa Sổ Tre Cao",
    [1367250800] = "Cóc Khách",
    [1367512075] = "Giỏ Lá Cọ",
    [1368924854] = "Trại Lụi Tàn",
    [1370165367] = "Thiết yếu cho một nơi ở ấm cúng.",
    [1370173313] = "Nấm Acidic được khai thác ở Cao nguyên Du mục.",
    [1370230607] = "Đòn Chí Mạng với vũ khí 2H tăng <b>10%</b> Tỷ lệ Chí mạng của bạn cho đòn đánh tiếp theo.",
    [1370524748] = "Sốc",
    [1370730236] = "Một sự kết hợp của các sắc xám và nâu ấm áp, gợi nhớ đến một con suối bùn được bao quanh bởi những bụi cây phỉ.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Springlands.",
    [1371087116] = "Vật liệu Địa hình",
    [1371215016] = "Điều tra <lorename>Ikora</lorename>'s Tung Tích",
    [1373875819] = "Cá Waveleaper nhảy múa trên sóng với sự nhanh nhẹn vô song, hiện thân sống động của tinh thần hoang dã của nước.\n\nLoại cá này có thể nướng hoặc dùng trong công thức nấu ăn.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [1374713010] = "Công cụ này chỉ có thể được sử dụng bên trong khu vực xây dựng xung quanh Bàn Thờ Ngọn lửa. Nó có thể giúp bạn nhanh chóng xây dựng căn cứ mong muốn với các cấu trúc được xác định trước.",
    [1374866072] = "Về Gậy Phép và Phép Thuật",
    [1375513245] = "Cất Giữ Chiến Lợi Phẩm Của Chúng Ta",
    [1375582230] = "Công Cụ Xây Dựng",
    [1377388712] = "Trạm Phối Màu",
    [1377733346] = "Nhạc Cụ Hoàng Gia",
    [1377905090] = "Riêng tư",
    [1378537305] = "Lấy hết",
    [1378862755] = "\"Chuột Nhảy\"",
    [1378870054] = "Khối Ngói Lợp Đá",
    [1379558220] = "Một nguyên liệu được sử dụng trong các công thức chế tạo.",
    [1379965547] = "Răng Cá Mập Sắc Nhọn",
    [1380123687] = "Một quả Cà chua đỏ mọng! Nếu được xử lý cẩn thận, nó có thể có tác dụng tăng cường.",
    [1380174447] = "Đói Khát Một Câu Chuyện?",
    [1380294702] = "Những viên ngói đá granite này mang lại nét quyến rũ của núi rừng cho ngôi nhà ấm cúng của bạn.",
    [1380308883] = "Đã đạt dung lượng Bàn Thờ tối đa",
    [1380583413] = "Đất Thảo Nguyên Thấp",
    [1380840508] = "Tia Lửa Từ Kindlewastes",
    [1381375287] = "Váy Quý Tộc",
    [1381432538] = "Bạn đã đến tháp canh bỏ hoang. Hãy tìm những chú chó có thể thuần hóa!",
    [1381620685] = "Trần Phân Phối Nước",
    [1381669911] = "Một loại thuốc nổ có sức công phá đáng kinh ngạc có thể ném được.",
    [1382047869] = "Không có gì!",
    [1382099785] = "Trại <npc>Thợ Săn</npc> Bỏ Hoang",
    [1382257698] = "À, vị cứu tinh của tôi đã đến! Cảm ơn bạn một lần nữa vì đã cứu tôi khỏi cái... \"vũng lầy\" đó! Tôi hứa sẽ không bao giờ làm phiền bạn nữa, và tôi sẽ niêm phong điều đó bằng máu! Giờ thì, đâu là... ồ, đúng rồi... tôi đã để lại những con dao găm yêu thích của mình ở Hố Nhựa sau khi trốn thoát khỏi một con quái vật hung tợn! Bạn có thể lấy lại chúng cho tôi không? Đây sẽ là điều cuối cùng tôi yêu cầu bạn! Chắc vậy...",
    [1383107476] = "Chiến Lợi Phẩm Của Scavenger",
    [1383426581] = "<npc>Nhà Giả Kim</npc>'s <craftingstation>Cối Xay</craftingstation>",
    [1383847531] = "Câu cá là giữ một tấm gương phản chiếu thiên nhiên.",
    [1385618978] = "Một vật liệu quan trọng và là một trong những thành phần hóa học cơ bản tìm thấy trong tự nhiên.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Sinh vật Fell Gây Nổ, ban đầu được tìm thấy ở Kindlewastes.",
    [1385798889] = "Kích hoạt <b>Đòn Tấn Công Tàn Nhẫn</b> hồi phục <b>10%</b> MP.",
    [1386103103] = "(Không tên)",
    [1386134531] = "<keyitem>Ấm Đun Nước</keyitem> Cho <craftingstation>Trạm Nấu Ăn</craftingstation>",
    [1386167737] = "Nhẫn",
    [1386298088] = "Thêm",
    [1386312028] = "Tiến Bước",
    [1386490914] = "Chùy Gai Bóng Tối",
    [1386497701] = "Đuốc Sáp",
    [1387128622] = "Nói Chuyện Với Nhà Giả Kim",
    [1387129823] = "Đường sá cung cấp sự di chuyển thoải mái và giảm lượng SP cần thiết để chạy nước rút.",
    [1387550685] = "Mũ Giáp Thợ Săn Quetzal",
    [1387657634] = "Tôi có một yêu cầu khẩn cấp dành cho bạn!",
    [1387718630] = "<b>Áp Đảo</b> \nTấn công kẻ địch đang phòng thủ hoặc đỡ đòn của chúng sẽ làm đầy <i>Thanh Bị Choáng</i> của chúng cho đến khi chúng bị <b>Bị Áp Đảo</b>.\n<b>Kẻ địch Bị Áp Đảo</b> sẽ bị hở để thực hiện các Đòn Tấn Công Tàn Nhẫn.",
    [1387852291] = "Bậc Thầy Độc Dược",
    [1388419382] = "Hỡi Kẻ Sinh Ra Từ Lửa, lại đây! Ta có một lời đề nghị kinh doanh cho ngươi! Nháy mắt nháy mắt!",
    [1388480526] = "Công Cụ Phá Dỡ Khối",
    [1389042351] = "Một viên đá quý đa diện được làm từ ectoplasm băng giá tinh chế.",
    [1390316556] = "(Cá nhân: %k + Được ban phước bởi Ngọn lửa: %k)",
    [1390402688] = "Phép thuật này được cung cấp bởi Ngọn lửa vĩnh cửu và đóng vai trò như một loại đạn ma thuật không giới hạn để tạo ra một quả cầu Ngọn lửa mạnh mẽ bùng nổ khi va chạm, gây sát thương trên diện rộng.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [1390639071] = "Thợ Mộc cần vài người giúp đỡ quanh căn cứ. Anh ta đã nhắc đến dì Braelyn của mình và tự hỏi liệu bà có thể được hồi sinh như những người dân làng khác không. Anh ta từng nhận thư từ bà khi bà đi phiêu lưu, nhưng bà đã mất tích từ lâu khi đang trinh sát Blackmire để tìm kiếm kiến trúc thú vị.\n\nBà đặc biệt quan tâm đến <i>đền thờ, tháp và cầu.</i> Có rất nhiều đền thờ ẩn trong vùng Blackmire, vì vậy hãy bắt đầu tìm kiếm ở đó!",
    [1390773965] = "Một chiếc mũ bảo hiểm làm từ chân côn trùng hóa đá được lắp ráp để bám vào mặt người đội như móng vuốt.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [1390942392] = "Cát kết chủ yếu bao gồm các hạt cát lớn - một vật liệu tự nhiên tuyệt đẹp và một kỳ quan thiên nhiên khác để chiêm ngưỡng.",
    [1390951585] = "Đồng mang lại sự ấm áp công nghiệp cho ngôi nhà của bạn với màu sắc và độ bóng đặc trưng.",
    [1390952450] = "Nhìn sang phải",
    [1391723623] = "Cùng nhau phát triển mạnh mẽ",
    [1391841244] = "Sinh tồn là quan trọng. Phát triển là thanh lịch.",
    [1392152923] = "Một phiên bản nhỏ của cối xay nước. Nó có thể được đặt dưới nước để tạo lực cho cối xay.\n\n<b>Phải đặt gần cối xay.</b>",
    [1392191108] = "Những Nguy Hiểm Của Thuốc Tiên",
    [1392465350] = "Đèn Lồng",
    [1392946488] = "Sương độc ngủ yên bên trong. Rotblood được định hình bởi nó, thay đổi, và bản chất của nó bị vấy bẩn mãi mãi.",
    [1392960737] = "Tinh thần",
    [1393407522] = "Giường Gỗ Cọ",
    [1393764819] = "Cấp 15",
    [1394744536] = "Kho đồ: Chế tạo",
    [1395361990] = "Phù, một chuyến đi dài. Chắc hẳn bạn đã cứu tôi khỏi cái... \"vỏ\" đó! Tôi là Elio Ricci, một thợ cắt tóc và làm tóc! Tôi sẽ mời bạn đến tiệm tạm thời của tôi ở <location>Fort Kelvin</location>, nhưng tôi e rằng nó đã không tồn tại được lâu. Kể từ khi tôi bị một đám... \"quái vật chó-gấu\" ném qua vách đá? May mắn cho bạn, người hùng dũng mãnh của tôi, tôi đã sống sót - chỉ hơi mất phương hướng một chút, nhưng vẫn rạng rỡ như trước! Dịch vụ của tôi sẽ giúp cộng đồng lý tưởng của bạn tỏa sáng!",
    [1395434102] = "Bộ Trang Phục Hầu Gái Mỹ Phẩm",
    [1395722233] = "Bình Nước Đồng Thiếc",
    [1395764535] = "Tăng Adrenaline",
    [1396359123] = "Cơ bản",
    [1396613432] = "Nến Hộp Sọ",
    [1396698012] = "Tông màu bạc sáng này đã trang trí cho nhiều chiếc cốc lộng lẫy của vương quốc. Nó được biết là kết hợp tốt với màu đỏ máu của rượu vang hoặc ánh sáng xanh lá cây nguy hiểm của sự lừa dối và độc dược.\n\nBảng màu này có thể được chế tạo bằng vật liệu từ Cao Nguyên Du Mục.",
    [1397250135] = "Bắn <i>Mũi Tên Thường</i> có <b>20%</b> cơ hội tạo ra một <b>Cơn Mưa Mũi Tên</b> lan tỏa nhẹ.\n\n<i>Mũi Tên Thường</i> được bắn theo cách này sẽ trừ vào số lượng đạn của bạn.\n\n<b>Cơn Mưa Mũi Tên</b> không kích hoạt trên <i>Mũi Tên Đặc Biệt</i>.",
    [1397925450] = "Khám phá Thành Phố Cổ Đại Chìm Đắm",
    [1398364293] = "Một Khối Đồng Thau thường được sử dụng trong nghệ thuật và khoa học. Nó truyền cảm hứng vĩ đại khi được sử dụng làm vật liệu xây dựng.",
    [1398483917] = "Một cây Gậy phép uy nghi được trang trí bằng một con rắn hổ mang làm từ ngọc bích xanh. Nó hoàn hảo để tôn vinh năm con rắn.",
    [1398522264] = "Nếu bạn đang đi về phía <location>Thornhold</location>, hãy cẩn thận. Tôi có thông tin rằng thị trấn đã bị tàn phá bởi những con chó hoang đói khát từ nhiều thế kỷ trước. Tình hình tồi tệ đến mức dân làng gần như đã ăn thịt chúng trong những vụ thu hoạch ít ỏi. Thật đáng tiếc khi phải ăn thịt một người bạn săn có giá trị như vậy... và một người bạn. Nếu còn bất kỳ con chó nào, hãy mang chúng đến đây!",
    [1398864720] = "Mang đôi ủng này khiến mỗi bước đi như được nâng đỡ trên đôi cánh bạc.",
    [1398875501] = "Một loại rễ cây tràn đầy năng lượng, nhưng không hiệu quả lắm ở dạng thô. Cải thiện sự Nhanh nhẹn của người tiêu dùng.",
    [1398915229] = "Rừng Gãy Đổ",
    [1400036554] = "Lời Nguyền Fell",
    [1400718735] = "Tìm Kiếm Di Vật Vukah",
    [1401203337] = "Bạn đã mang đến cho Thợ Cắt Tóc hai nguyên liệu khác nhau đại diện cho bản chất của màu xanh lá cây.\n\n<b>Nói chuyện với Thợ Cắt Tóc</b> lần cuối để mở khóa màu tóc mới!",
    [1401390165] = "Chế tạo tại Phòng Thí Nghiệm",
    [1401763946] = "Ghế Gỗ Cọ",
    [1401779364] = "Dấu Ấn Bọ Ba Thùy",
    [1401936829] = "Chế Độ Xây Dựng",
    [1402447465] = "Lấy cảm hứng từ Quetzal, một loài chim tuyệt đẹp từng bay lượn trên bầu trời Embervale, bộ giáp tuyệt đẹp này cho phép bạn cảm nhận sự tự do và chính xác của chuyến bay khi mặc nó.",
    [1402579345] = "Giảm Thời Gian Ướt",
    [1403042010] = "Ta có thể tiếp tục!",
    [1404630491] = "Trống Tay",
    [1405310997] = "Găng tay làm từ vật chất mục rữa, bất tử. Chúng cào vào cánh tay trên của người mặc như muốn mọc lên.",
    [1405337535] = "Cuối cùng ta cũng hiểu tại sao những ký tự trên tháp đá lại làm ta gặp nhiều rắc rối đến vậy.\nNgôn ngữ của chúng đã thay đổi. Nó phân thành các phương ngữ khác nhau, một trẻ, một già. Hai phe phái trong giống Cổ Đại, và hai lý tưởng:\n\nNhững Người Cổ Đại trẻ tuổi muốn cứu nhân loại khỏi... <i>thứ gì đó</i>. Họ nhắm đến việc chia sẻ ngọn lửa của mình để giúp chúng ta chống chọi với một thảm họa đang cận kề. Thứ gì đó mà họ vô tình mang đến, hoặc đánh thức.\n\nNhững Người Cổ Đại già hơn muốn bảo tồn sự thuần khiết của Ngọn Lửa. Họ phấn đấu cho sự thăng hoa khắc kỷ, phân lập, trung lập và sức mạnh tiếp tục. Họ sẽ tự nhốt mình trong vương quốc của họ và... \"thăng hoa\".\n\nSớm hay muộn, chúng sẽ đạt đến điểm bùng phát và những sinh vật khổng lồ này sẽ tan vỡ thành hai.\nNhưng ta không biết khi nào\nVà ta không biết điều gì sẽ xảy ra, hoặc liệu xúc xắc có rơi về phía chúng ta không\nTa không còn biết gì nữa\nTa còn đang tìm kiếm điều gì vậy?",
    [1405824995] = "Cờ Lệnh Dọc III",
    [1406220893] = "Bụng ta đang réo lên. Ước gì một trong những trạm thức ăn gần đó được lấp đầy!",
    [1406337642] = "Nhiều",
    [1407039392] = "Những tên cướp đã lấy đi những món hàng quý giá nhất của tôi khi chúng tấn công xe ngựa của tôi như chim ưng. Sau khi những mũi tên của chúng xé toạc tôi khỏi xe ngựa và ghim tôi xuống đất, chúng lục lọi trong hàng hóa và lấy đi cây gậy phép của tôi cùng những thứ khác. Quằn quại trong đau đớn, tôi buộc phải nhìn chúng bỏ chạy khi mọi thứ mờ dần... nhưng tôi nhớ chúng đã chạy trốn đến đâu.",
    [1407061378] = "Tức thời hồi phục một lượng MP vừa phải, và liên tục bổ sung trong 10 giây.",
    [1407116621] = "Được tạo ra trong cuộc truy cầu sự bất tử, nó đã cướp đi vô số sinh mạng và hứa hẹn sẽ còn nhiều hơn nữa.\n\n<b>Hút HP</b>: \nHút HP có cơ hội (được liệt kê ở trên) kích hoạt trên mỗi đòn đánh.\nKhi kích hoạt, đòn đánh hút HP sẽ hồi phục 50% sát thương gây ra dưới dạng HP.",
    [1407669789] = "Chế Tạo Một Máy Cho Gia Súc Ăn Và Giường",
    [1407829040] = "\"Đừng bao giờ để than hồng lụi tàn\", họ nói. Hãy tìm những người giống chúng ta!",
    [1407958022] = "Chìa Khóa Xương Rừng Revel",
    [1408777920] = "Khóa Mục Tiêu Khi Chạy Nhanh",
    [1409118192] = "Con gái tôi Rochelle có thể vẫn còn ở ngoài kia. Nếu bạn tìm thấy viên đá nhỏ của tôi, viên sỏi ngọt ngào của con gái tôi... hãy mang cô bé đến đây. Ít nhất là mang hài cốt của cô bé về. Tôi sẽ chôn cất cô bé nếu không còn gì khác.",
    [1409505684] = "Một Bước Nhảy Đáng Thương",
    [1409861138] = "Nhập văn bản...",
    [1410527159] = "Giày Đêm Khô Cốt",
    [1410738479] = "Sát thương lên kẻ địch <b>tầm xa</b> tăng <b>15%</b>.",
    [1410753809] = "Tôi cần một bộ quần áo mới để thay. Nghề nghiệp của tôi có rất nhiều máu, mồ hôi và nước mắt. Chủ yếu là mồ hôi! Tôi đã có những bộ khác trước khi đến trang trại, nhưng tôi đã xé chúng ra trong một chuyến thám hiểm khi thấy nhện bò khắp nơi!! Tôi không thể quay lại đó. Không, không, không. Bạn làm đi!",
    [1411197518] = "Chúng ta có thể làm nhiều hơn. Trở nên mạnh mẽ hơn. Tôi có một ý tưởng... nhưng tôi sẽ cần một chút giúp đỡ và một <craftingstation>Trạm Da</craftingstation>!",
    [1411469339] = "Thợ Mộc <npc>Carpenter</npc> cần <craftingstation>Dụng Cụ Mộc</craftingstation> để mở khóa thêm các trạm chế tạo. <craftingstation>Dụng Cụ Mộc</craftingstation> có thể thu thập từ một <b>khu vực nghiên cứu tại Trụ Cột Sáng Tạo.</b>",
    [1411674571] = "Cào Cỏ Cao Cấp",
    [1411946509] = "Dịch chuyển về phía trước",
    [1412503866] = "Ta có một nhiệm vụ mà ta chỉ có thể giao phó cho một người bạn... lại đây một chút, để ta có thể chia sẻ với ngươi.",
    [1412524098] = "Băng Đô Thợ Săn",
    [1412619126] = "Một bức phù điêu mô tả lịch sử của Drak.\n\nHình ảnh gói gọn một khoảnh khắc thay đổi: Một vụ đắm tàu trên bờ biển xa xôi báo trước sự diệt vong của nhân loại. Họ thấy Vùng Đất Cổ Đại trỗi dậy trên đường chân trời— một dấu hiệu cho thấy các vị thần cuối cùng đã quay lưng lại với nhân loại. Đối với Drak, đã đến lúc phản công.",
    [1412703006] = "Bạn đã chứng tỏ mình là người đáng tin cậy và có năng lực. Có lẽ ta có thể giao cho bạn một thử thách khác. Ban đầu, vũ khí Tết Nguyên Đán là một bộ ba, nhưng ta chưa bao giờ có thể lấy được cây cung — chiếc cuối cùng trong bộ ba. Nó vẫn ngủ yên bên trong một ngôi đền ở Cao Nguyên Du Mục. Ngôi đền của loài rắn rất nguy hiểm, nhưng bạn đã sẵn sàng. Hãy tiến lên.",
    [1412879535] = "Một Khối Đá Thường được sử dụng cho việc xây dựng hàng ngày.",
    [1412952560] = "Tìm Rương Giấu Kín Ở Alba",
    [1413395929] = "Làm Chậm Băng Giá",
    [1413778089] = "Bị đàn áp bởi vai trò công khai dễ dãi hơn",
    [1414095088] = "Ngọn lửa của Ngọn Lửa cháy trong bạn.",
    [1414116745] = "Chu kỳ khóa mục tiêu (phải)",
    [1414339862] = "Hành Trình Của Jezmina Qua Lưu Vực Veilwater",
    [1414487500] = "%k đã bị Sương độc nuốt chửng.",
    [1414708099] = "Len tinh chế. Nó có thể được sử dụng để dệt quần áo và lớp đệm ấm áp.",
    [1414716342] = "Luống Trồng Cây",
    [1414874048] = "Trượng",
    [1414987007] = "Đặt Máy Quay Sợi",
    [1415061256] = "Mái Bên",
    [1415212397] = "Trong Tầm Tay",
    [1415506526] = "Tòa nhà to lớn! Tháp cao! Ánh sáng rực rỡ!\n\nChỉ có thể được tạo ra bởi Hậu Duệ của Ark Morgo, vâng — Người Cổ Đại phải là sứ giả! Kết nối với Ark Morgo ở trên! Chiếu sáng lên bầu trời phía trên những đám mây! Một con đường cho người xứng đáng!\n\nNhưng nền tảng phát sáng không hoạt động đúng! Rah!\nDrak'Dal sẽ chứng tỏ bản thân dù sao! Sẽ tiến vào! Nghiền nát Ngọn Lửa trong trận chiến! Giành được sự ưu ái của các vị thần!",
    [1415924279] = "Một lò sưởi sẽ cung cấp hơi ấm khi được đặt trong nhà bạn. Nó đơn giản, nhưng đủ để nấu các bữa ăn một thành phần và nhận hiệu ứng Nghỉ Ngơi.",
    [1415946388] = "Mũ Giáp Bò Tót Đồng",
    [1416507504] = "Nếu bạn bị giết, bạn sẽ kích hoạt một vụ nổ tàn khốc gây sát thương cho tất cả kẻ địch trong phạm vi 50 mét.",
    [1416708753] = "Tiếng Rì Rầm Trong Tường",
    [1417248147] = "Sức mạnh",
    [1417264744] = "Giày Xạ Thủ",
    [1417296759] = "Chiếc rìu 1H này kêu lách tách với năng lượng điện giật kể từ khi nó được sạc bằng sét trong một cơn bão sa mạc hiếm hoi.",
    [1417890521] = "Được bảo vệ",
    [1418005532] = "Đọc tất cả các bia đá trong Lưu Vực Veilwater.",
    [1418846804] = "Kháng Sương Độc",
    [1419590243] = "Đất Ưu Tiên",
    [1419716320] = "Một luống đất trang trại sẽ cho ra Ngô.",
    [1419910595] = "Di Sản Rải Rác",
    [1420019323] = "KOR",
    [1420035817] = "Ngươi Thật Ngu Ngốc",
    [1420407569] = "Bạn đã tiếp xúc với Bùn Sương Mù, gây ra ST Sương độc. ",
    [1421437640] = "Phát Bắn Chết Chóc",
    [1421696882] = "Kẻ Nghiền Hàm",
    [1422214743] = "Chớp Mắt Khẩn Cấp",
    [1422293787] = "Bạn đã đến một địa điểm được gọi là \"Thánh Địa Đêm\". Rào cản mà bạn đã đặt ra để điều tra đã lộ ra là một cánh cửa. Tuy nhiên, sự kết hợp của sao và mặt trăng trang trí mặt tiền của nó cho thấy đây không phải là một cánh cửa bình thường, và nó dường như không dễ bị tác động bởi vũ lực.\n\n<b>Tìm cách mở cánh cửa đêm và khám phá bên trong ngôi đền!</b>",
    [1423691321] = "Nó... ổn... khi bạn... trở về...",
    [1423746549] = "Băng Giá",
    [1424181999] = "Rơi ra từ kẻ địch Fell đứng yên",
    [1424535747] = "Tìm Một Viên Ngọc Khát Máu",
    [1424724888] = "Lò Nung",
    [1424767493] = "Ta còn có thể giúp gì nữa?",
    [1424854615] = "Bạn có thể đu qua một số vực thẳm bằng Móc Leo. Hãy để mắt đến những địa điểm này.",
    [1424864512] = "Mũi Tên Ban Phước",
    [1425026151] = "Một khối xây dựng được chế tạo từ chất nhờn tinh khiết. Nó chiếu sáng căn phòng bằng ánh sáng xanh lá cây ma quái.",
    [1425447622] = "Khúc Gỗ",
    [1427169441] = "Người Yêu Mắt Xanh",
    [1428811227] = "Nghiền Xương Hóa Thạch thành bụi sẽ giải phóng các thuộc tính ma thuật vốn có của nó và làm cho nó tiện dụng hơn cho các bước sản xuất tiếp theo.",
    [1429310852] = "Gunther Galeforth, một cựu binh, tin rằng chúng ta nên cải thiện khả năng phòng thủ của mình. Ông ước gì có vũ khí tốt hơn để giúp đỡ, và đề cập rằng một trong những tổ tiên của ông được chôn cất cùng một vũ khí vĩ đại.\n\nĐiều tra khu vực được đánh dấu trên bản đồ của bạn và lấy vũ khí!",
    [1429800417] = "Đến Yên Ngựa Đá Vàng",
    [1430310502] = "Bàn Tiệc Đá",
    [1430484437] = "Tủ Cúp Gỗ Phương Bắc Lớn",
    [1430735148] = "Tăng Sự Thoải Mái",
    [1431391670] = "Tới Vệ Binh Phương Bắc",
    [1431792114] = "Lối Vào Đền Thờ Bí Mật",
    [1432402229] = "Này Steph, tôi không gặp cậu được ở chỗ hẹn nên để lại tờ giấy này. Vụ cối xay gió cứ bám riết lấy tôi, cậu biết đấy?\nXin lỗi vì phải nhắc đến công việc, nhưng cậu có biết một người tên là \"Loft\" không? Chúng tôi tìm thấy hắn lang thang trong tuyết. Hắn nói hắn đến từ một đội đốn gỗ và bị lạc. Giờ hắn đang sửa mái tháp, nhưng trông hắn có vẻ... lơ đãng.\nTôi đã yêu cầu danh sách từ Pháo Đài Everfrore về tất cả những người đốn gỗ đang làm việc, nhưng họ lại bị ngập trong giấy tờ một lần nữa.\nNhớ John không? Anh ta làm việc ở đó bây giờ. Chắc là chết trong tâm hồn rồi.\n\nKhông sao đâu. Cậu có thích loại bia tôi để lại cho cậu không? Nó có một <i>\"cú hích\"</i>, phải không? Đó là nguyên liệu bí mật mới của tôi. Tôi còn nhiều ở xưởng bia bí mật của chúng ta. Đừng lo, chưa ai phát hiện ra đâu. Chúng ta có nên mời cậu nhóc mới đến uống một ly không? - Kent",
    [1432644246] = "Hoàng Tử Ếch",
    [1432804222] = "Cuối Cùng Cũng Đoàn Tụ",
    [1432815183] = "Giao Diện Người Dùng",
    [1434042739] = "Mũ Ba Góc",
    [1434200478] = "Cơ Hội",
    [1434238128] = "Kiếm Và Khiên Giá Treo",
    [1434411782] = "Nước lặng sâu, người ta nói vậy. Những sắc xanh êm dịu này nhắc nhở chúng ta rằng mọi thứ không phải lúc nào cũng như vẻ ngoài của chúng — cả vực sâu và bụi rậm đẫm sương đều ẩn chứa những cuộc gặp gỡ định mệnh.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Hồ Veilwater.",
    [1434420350] = "Sự kết hợp giữa xanh lá cây nhạt và tím rực rỡ của bảng màu này lấy cảm hứng từ hoa lan đã tuyệt chủng.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Vùng Đất Kindlewastes.",
    [1434542181] = "Đo lường thời gian bạn có thể sống sót trong môi trường lạnh giá.",
    [1434778373] = "Một Chuyến Bay Thanh Lịch",
    [1435923169] = "Ngươi cần ta giúp sao?",
    [1436036793] = "Nghỉ Ngơi",
    [1436454320] = "Tôi tin vào bản năng khoa học của mình, nhưng không ai khác tin cả.\n\nNhững người khác không tin vào sự tồn tại của <b>Kiếm Rồng.</b> Họ nghĩ đó chỉ là một câu chuyện cổ tích từ thời xa xưa. <i>Nhưng sự tồn tại của rồng thật sự sẽ giải thích nguồn gốc của các mỏ xương hóa thạch lớn của chúng ta và có thể lấp đầy những khoảng trống trong giả thuyết về tổ tiên của Kền Kền Rồng.</i>\n\nNếu tôi tìm thấy <b>Kiếm Rồng và lấy nó ra khỏi hang động bị lãng quên,</b> tôi có thể thêm bằng chứng cho lý thuyết của mình. Cho đến lúc đó, tôi sẽ trở thành trò cười cho đồng nghiệp nếu tiết lộ luận án thật sự của mình...",
    [1436806619] = "Chiếc quần màu nâu sẫm. Chúng ít bị sờn rách hơn phần còn lại của bộ giáp Omen.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [1437244183] = "Dê Lông Xù",
    [1437521881] = "Heh, làm tốt lắm. Giờ đến lượt tôi làm mấy cái đèn này.",
    [1437725946] = "Toàn bộ Cây Kỹ Năng sẽ được đặt lại, và Điểm Kỹ Năng sẽ được hoàn trả (<b>%k</b>). Hành động này không thể hoàn tác!",
    [1437764636] = "Khám Phá Bí Mật Của Lăng Mộ Bí Ẩn",
    [1437842965] = "Tôi không theo kịp nữa. Tôi nghỉ! Tôi nghỉ! \n\nĐơn chấp thuận B12, không phải đơn 812\nCần theo dõi, chữ ký để trống, mọi thứ đều quá hạn\nThiết kế tòa nhà Cổng Mới D không tuân thủ quy tắc. Không ai quan tâm, họ cứ xây\nbất cứ thứ gì\nTại sao mọi người lại cần giấy chứng tử? Thật sự tại sao\nCó ít nhất 12 yêu cầu chính thức mỗi ngày\n7 từ Alba, 4 từ Bora, 2 từ Celeste\nLàm thế nào mà Tiền Đồn A có thể gửi 7 Yêu Cầu\nVÀ HAI TRONG SỐ ĐÓ là vì không đủ tất?! TỰ LÀM TẤT ĐI CHẾT TIỆT, tại sao đó lại là vấn đề hành chính?\n\nCông việc bàn giấy này sẽ giết chết tôi. Họ trả bao nhiêu cũng không quan trọng! Tôi đi đây! Và tôi sẽ NÉM CÁI THÙNG ĐỒ THẤT LẠC & TÌM THẤY từ ban công nữa!",
    [1438357368] = "Tạm Dừng",
    [1438520815] = "Gối Ôm Hình Mèo",
    [1438664827] = "Một chú Dê Xù Lông đáng yêu. Lông của nó dễ bị rối, nhưng nó dường như không bận tâm.",
    [1438904207] = "Tên: Ruffles",
    [1439247434] = "Đó là cái gì vậy? Eek! Cút ra xa tôi! Ồ, nó không có thật sao? Chỉ là một con thú nhồi bông nhỏ thôi... Những sinh vật này không đáng sợ lắm khi chúng mềm mại và ấm áp! Aww, chúng thực ra khá đáng yêu, phải không? Hãy đặt cậu bé này xuống đâu đó. Tôi muốn mọi người thấy nó dễ thương như thế nào! ",
    [1440373099] = "Áo Giáp Kẻ Săn Đầu Lâu",
    [1440812545] = "Nơi làm việc này sẽ cho phép <npc>Thợ Săn</npc> sản xuất hàng loạt da.",
    [1441029413] = "Một chiếc gối mềm cho mèo của bạn.",
    [1441077456] = "Mũ Trùm Sát Thủ Băng Giá",
    [1441277977] = "Để Chữa Lành Vết Thương Cũ",
    [1441833135] = "Cho phép nhảy lần thứ hai khi đang ở trên không.\n\n<b>Chi phí:</b> 10 SP ",
    [1442456054] = "Chất Lượng",
    [1442941902] = "Ước gì tôi có nhiều nhạc cụ hơn để chơi... một nhịp trống hay sẽ tuyệt vời bên lò sưởi, phải không?",
    [1443647673] = "Chiếc mặt nạ kim loại đáng sợ chỉ được che một phần bởi mũ trùm, để lộ hầu hết các cạnh sắc nhọn và đường nét của nó cho con mồi của bạn.",
    [1443710905] = "Thời Trang Sa Ngã",
    [1443997728] = "Cung Rắn Thần",
    [1444307497] = "Lưới Quả Cầu Thuốc Nổ",
    [1444452584] = "Tìm thấy ở Springlands và các Sảnh Đường Revelwood Hollow",
    [1444581576] = "Khung Cửa Sổ Bằng Sắt",
    [1445089236] = "Không còn nâng cấp nào nữa.",
    [1446269359] = "Tài Nguyên",
    [1446807967] = "Kệ",
    [1446897900] = "Đạt cấp 2.",
    [1446983076] = "Nhật Ký Thuyền Trưởng, Ngày Hai Mươi",
    [1447229023] = "Dê Thường",
    [1447662697] = "Dao Găm",
    [1447735073] = "Mảnh Bản Đồ Của Mae",
    [1448299425] = "Lao thẳng vào trận chiến với Mũ Chiến Binh này!",
    [1448416060] = "Một thanh kiếm bị lãng quên từ những ngày xa xưa. Thường được tìm thấy trong tro tàn của Embervale.",
    [1448549454] = "Đào",
    [1449094900] = "Một cây cung có thể thắp lên niềm vui rực lửa cho những con bọ lửa và những người đam mê hỏa công.",
    [1449254141] = "Tìm Dưới Ván Sàn Cối Xay Ở <location>Willow Crush</location>",
    [1449319713] = "Khi MP của bạn giảm xuống dưới <b>20%</b>, bạn hồi phục tối đa <b>35%</b> MP tối đa với chi phí <b>1</b> HP cho mỗi MP được hồi phục.\n\nHiệu ứng này dừng lại ở <b>1</b> HP.\n\n<b>Thời gian hồi chiêu:</b> 2 phút ",
    [1450381453] = "Cánh Rồng",
    [1450401226] = "Di Chuyển",
    [1450504986] = "Chỉ một lâu đài danh giá mới có thể được xây dựng từ những viên đá chắc chắn như vậy.",
    [1451485548] = "Một phần của Bộ Giáp Giám Hộ.",
    [1451893241] = "Hành Trình Đoàn Lữ",
    [1452069450] = "Khi bạn bị kẻ địch giết, tất cả đồng minh trong phạm vi <b>30</b> mét sẽ được hồi HP <b>50%</b> HP tối đa.\n\nHọ cũng nhận được hiệu ứng <b>Phước Lành Cuối Cùng</b>, tăng HP tối đa của họ thêm <b>100</b> điểm trong <b>15</b> phút. ",
    [1452482347] = "Ma Cà Rồng",
    [1452615611] = "Tăng sát thương lên Fell ",
    [1452696996] = "Những phát bắn từ cây cung gai này có thể xuyên thủng mọi thứ.",
    [1453416563] = "%km<u+00d7>%km<u+00d7>%km",
    [1453474826] = "Tiện Nghi Cơ Bản",
    [1453540048] = "Nào, cái này! Đây mới là cái tôi gọi là màu xanh tuyệt vời! Nó trong vắt như bầu trời không mây hay suối nước ngọt! Được rồi, tôi nhớ cách tạo ra màu tóc này rồi. Cảm ơn bạn rất nhiều! Bạn có muốn thử kiểu tóc mới ngay lập tức không? Tôi sẵn sàng khi bạn sẵn sàng!",
    [1453685855] = "Chỉ báo mức độ bạn sử dụng vật phẩm phép thuật tốt như thế nào.",
    [1453928757] = "Tượng Đầm Lầy Đen II",
    [1454031162] = "Vỏ cây từ những cây khổng lồ ở Blackmire. Nó có cảm giác thô ráp nhưng có thể trông khá ấm cúng.",
    [1454033488] = "Trợ lý Giả kim thuật Paulette muốn chào đón tất cả các loại Tinh thần trong Lễ Hội Hollow bằng cách thêm những quả bí ngô khắc vào căn cứ của bạn! Bạn nên tìm một vài trang trại bí ngô ở Cao Nguyên Albaneve để học cách làm chúng!",
    [1454515729] = "Cái lạnh đã chiếm lấy ngươi...",
    [1454555456] = "Trang Trước",
    [1455543691] = "Cài Đặt Sẵn B",
    [1455619636] = "Dùng <b>Điểm Kỹ Năng</b> bạn thu thập được trên hành trình trong <b>Cây Kỹ Năng</b>.",
    [1455976739] = "Con Rồng Đáng Sợ",
    [1456112494] = "Rơi Vào Hủy Diệt",
    [1456214061] = "Một chiếc mũ trùm của cung thủ. Lớp viền da cung cấp thêm sự bảo vệ và ngụy trang cho người mặc giữa các lùm cây.",
