    [1460448757] = "Gắn Thần Gậy phép Triệu Hồi",
    [1460732671] = "Đóng Cửa Lũ Ở Riverreach",
    [1461196888] = "Hoàn Trả Tất Cả",
    [1461870978] = "Tinh Hoa Cổ Xưa",
    [1461927428] = "Mưa Đá",
    [1462374513] = "Tuyết không làm chậm bước chân bạn.",
    [1462792145] = "Tàn Tích Drak'Dal",
    [1462914857] = "Tìm Bảng Màu Trong Mỏ Đá",
    [1463186634] = "Nếu cài đặt này bị tắt, vũ khí sẽ không còn bị vỡ nữa.",
    [1463262981] = "Tổ Kền Kền",
    [1463271173] = "Các <keyitem>Dụng Cụ Khoa Học</keyitem> đã được thu hồi! Chúng phải được mang trở lại cho <npc>Nhà Giả Kim</npc> và chế tạo thành một Phòng Thí Nghiệm để mở khóa thêm công thức và phương pháp chữa bệnh tốt hơn.",
    [1463631920] = "Crimsonback, từng là một con Silverback phổ biến đã sống sót qua vô số cuộc di cư, có lớp vảy cháy với màu đỏ sẫm. Người ta nói rằng nó tượng trưng cho sức mạnh và sức bền, và nó được những người câu cá dày dạn kinh nghiệm coi trọng vì sức mạnh và vẻ đẹp của nó.\n\nLoại cá này có thể được nướng hoặc sử dụng trong công thức.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [1463660614] = "Hoa Hoang Mạc Lửa",
    [1463781235] = "Buồn",
    [1464309022] = "Gỡ bỏ",
    [1465473079] = "Hầm Cổ — Nhạc Sĩ",
    [1465546699] = "Đi theo dấu vết của <lorename>Ikora</lorename>",
    [1465725832] = "Một chiếc mũ vui tươi và lanh lảnh. Những chiếc chuông nhỏ làm cho việc nhảy múa thêm phần vui vẻ.",
    [1465918570] = "Túi đồ: Nhật ký",
    [1465967062] = "Mật khẩu phiên",
    [1466039803] = "Điều tra Tháp Bỏ Hoang",
    [1466091116] = "Tia Lửa Vĩnh Cửu",
    [1466462235] = "Giọng nói người chơi",
    [1466972175] = "Một chiếc khăn trùm đầu bảo vệ hộp sọ nhạy cảm của bạn khỏi chấn thương nghiêm trọng. Đủ để trì hoãn điều không thể tránh khỏi trong một thời gian.",
    [1466980154] = "Thu nhỏ",
    [1467147614] = "Bí Ngô Đêm Khô Cốt Lớn I",
    [1467213215] = "Sự pha trộn giữa màu nâu đất và xám, thể hiện cả sự khôn ngoan và vững chắc.\n\nBảng màu này có thể được tạo ra từ các vật liệu của Vùng Đất Mùa Xuân.",
    [1467841482] = "Thanh kiếm này chiếu sáng vực sâu của Sương độc, thách thức đến cùng.",
    [1468097282] = "Cây Khoai Môn",
    [1468143296] = "Ahhh... thật đẹp... thật thanh bình... Tôi cảm thấy mình được nhìn thấy. Như thể tôi đã từng quen với việc... ngủ... dưới ánh trăng... với n- không gì cả... và không- không ai xung quanh... cảm ơn bạn.",
    [1470285508] = "Đánh bại Mẹ Scavenger",
    [1470654136] = "Màu đỏ u ám làm cho bảng màu này lý tưởng cho một cuộc hành trình đêm đầy tâm trạng.\n\nBảng màu này có thể được tạo ra từ các vật liệu của Bồn Nước Veil.",
    [1471022408] = "Tìm Bộ Đồ Lông Vũ Mỹ Phẩm",
    [1471248470] = "Kẻ Tách Tóc",
    [1471573502] = "Di chuyển lên",
    [1471925859] = "Vòng xoáy kéo vào trong\nCuốn xuống \nCấu hình không thể biết, mỗi đường cong xoắn hơn đường trước\nMột cái vít xoắn từ từ đào vào thịt\nMột con rắn ăn cả thế giới\nVà tự nuốt chửng, cho đến khi nó không thể ăn nữa\n<i>Lại nữa, và lại nữa, và lại nữa. Cho đến khi thế giới quên lãng, vì nó không để lại dấu vết nào ngoài một sức hấp dẫn dai dẳng.</i>\n\nÁp lực tăng lên khi tôi di chuyển xuống dưới. Một thế giới không còn thuộc về tôi vươn lên trên đầu tôi, bóp nghẹt tôi, đẩy tôi xuống. Tôi đặt tay lên thành của vòng xoáy để không bị lạc mất mình trong cuộc hành trình xuống.\nHai bên của nó ẩm ướt và bóng loáng.\n\nNó xoắn lại nhiều hơn với mỗi vòng quay, không đều, bất thường và bị xoắn vặn quanh chính nó. Nó dẫn tôi đi xuống mãi. Càng lặn sâu, tôi càng hiểu nhịp điệu của nó. Nó có thịt, thở, rung động.<i> Nó trở nên sống động ở độ sâu.</i>",
    [1472113667] = "Đó là gì?",
    [1473247896] = "Đàn Khúc Cầm Tinh Xảo",
    [1473410171] = "Độ phân giải",
    [1473536062] = "Nhật ký Thuyền trưởng",
    [1473759835] = "Nhìn xem này — bạn đã trục vớt được một số vật phẩm. Giờ bạn có thể dùng một số <b>Bùa Chú</b> để tăng cường vũ khí của mình. Muốn thử không?",
    [1473875498] = "Thư Viện Bị Lãng Quên",
    [1474375203] = "Hãy cháy sáng như những vì sao!",
    [1474670010] = "Mũ Giáp Khô Cốt Tinh Nhuệ",
    [1475251787] = "Các đường gờ dọc theo phần đế của thanh kiếm này, làm tăng thêm sức nặng cho mỗi cú vung. Hình dáng không đều gợi nhớ đến xương sống nhô ra.",
    [1475337367] = "Đó là một đường hầm quyến rũ, một hang động, một cái miệng há rộng. Đó là một bóng tối ấm áp và bao trùm hứa hẹn một ánh sáng nội tâm thiêng liêng. Nhân loại chỉ là những đứa trẻ, còn non nớt với Trái Đất, mặt non nớt và ngây thơ, háo hức khám phá. Chúng ta là những con thiêu thân lao vào ngọn lửa xanh, bị cuốn hút để đi vào.\n\nChúng ta bước đi nơi đáng lẽ phải bò, và đứng thẳng nơi đáng lẽ phải quỳ. Ai đã cho phép chúng ta phá vỡ bóng tối? Để đi vào và đi xuống mãi mãi, một vòng xoáy không bao giờ kết thúc trơn trượt với bóng tối lỏng, xuống, một mảnh vụn thời gian và vật chất nhỏ bé trượt vào bụng của một con quái vật?\n\n<i>Tôi thấy điều này lặp đi lặp lại, và lặp đi lặp lại, và lặp đi lặp lại.</i>\nĐôi khi, tôi là đứa trẻ, ngây thơ cho đến cuối cùng.\nNhững lúc khác, tôi là bóng tối. Tham lam và chờ đợi, quan sát mặt nước tĩnh lặng từ dưới lên — kẻ săn mồi im lặng đông đúc những cơ thể vô hình dưới đáy biển không có ánh mặt trời. Bình tĩnh, và rất, rất xa.\n\n<i>Lặp đi lặp lại, và lặp đi lặp lại, và lặp đi lặp lại.</i>",
    [1475539787] = "Sản xuất dưới nước bị dừng",
    [1475793794] = "Trục vớt vật phẩm",
    [1475877352] = "Bí Ngô Đêm Hollow",
    [1475995949] = "Chơi",
    [1476449052] = "Ahh, xương cốt tôi đau quá. Giá như có một vị cứu tinh nhân từ tạo ra nơi trú ẩn cho tôi, tôi sẽ biết ơn mãi mãi!",
    [1476469456] = "Luống Cày",
    [1476510375] = "Giày Điềm Báo",
    [1476794942] = "Áo Giáp Lính Đánh Thuê",
    [1477267224] = "Một cặp dao xiếc có thể gây sát thương lớn nếu rơi vào tay những kẻ thiếu kinh nghiệm! Tốt hơn hết là hãy cẩn thận!\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1477267856] = "Nên có kết nối internet nhanh và ổn định cùng hiệu năng PC cao hơn để lưu trữ nhiều người chơi.",
    [1477991047] = "Tái tạo nhiệt cơ thể",
    [1478541961] = "Rìu tìm thấy",
    [1478825114] = "Một chồng giấy da cũ, bị mòn và rách bởi sự tàn phá của thời gian. Một người khôn ngoan có thể trục vớt được điều gì đó từ những tàn tích này.",
    [1479148793] = "Một bộ trang phục dài, bay bổng. Đường viền dưới lơ lửng một cách dễ dàng quanh mắt cá chân khi bạn đi bộ.",
    [1479790444] = "Một cục than cứng. Nó là nhiên liệu tuyệt vời!",
    [1479986479] = "Gừng tươi, hoàn hảo để pha trà nóng giữ ấm cơ thể khỏi bị cảm lạnh.",
    [1480241028] = "Một cây Gậy phép có sừng được trang trí bằng lông cừu trắng. Nó mềm mại khi chạm vào.",
    [1480280918] = "Chum Đất Sét Lớn",
    [1480593128] = "Tăng tốc độ bơi của bạn.",
    [1481454326] = "Tiền tệ",
    [1481539772] = "Kẻ Đập Đầu",
    [1481584533] = "Mũ Thợ Mỏ",
    [1481896389] = "Đừng ngại — tôi còn có thể làm gì cho bạn nữa không?",
    [1481917543] = "Ngọc Bích",
    [1482175351] = "Một khối tuyết lổn nhổn. Nó vô hại miễn là bạn không cho bất kỳ viên đá nào vào đó!",
    [1482698557] = "Cát Nóng Hoang Mạc Lửa",
    [1483367910] = "Cung Đánh Lửa",
    [1483921815] = "Nhận",
    [1484904994] = "Phổ biến",
    [1485048187] = "Ván Gỗ",
    [1485095545] = "Bền, dẻo và có khả năng tái tạo: Tre là vật liệu lý tưởng cho bất kỳ Flameborn nào muốn xây dựng một ngôi nhà nhiệt đới.",
    [1485592924] = "Đế Cột Đá",
    [1485730355] = "Tăng <b>Kháng Lửa</b> của bạn thêm <b>5%</b>, giúp giảm lượng sát thương <b>Lửa</b> nhận vào.",
    [1485760016] = "Bạn có biết về Lễ Hội Hollow không? Đó là mùa của người chết, kẻ bị nguyền rủa và những kẻ táo bạo! Chúng ta chào đón các Tinh thần từ thế giới bên kia bằng những quả bí ngô khắc và ánh đèn trong các lễ hội! Cái gì? Bạn nói chúng ta phải xua đuổi họ đi? Tôi thà mời họ vào! Chúng ta đi tìm vài quả bí ngô nhé?",
    [1485851928] = "Bản đồ",
    [1485991491] = "Các Tinh thần đã tiên đoán sự xuất hiện của bạn.",
    [1486489679] = "Nhu cầu đi vệ sinh",
    [1486652745] = "Cần có những chiếc ống thổi này để chế tạo lò cao.",
    [1486660190] = "Nhẫn 2",
    [1487283290] = "Cây Giống Cây Bắt Ruồi Chướng Khí",
    [1487314488] = "Học việc",
    [1487594371] = "Chế tạo tại Lò nung",
    [1487994446] = "Sảnh Hollow Albaneve Summits",
    [1488028122] = "Vật liệu cứng nhất được biết đến. Khó chế tác, nhưng xứng đáng với công sức!",
    [1488053163] = "Tình trạng: Kinh khủng. Tác động hôm nay: 17 \n<i>(Phần dưới đây được viết nguệch ngoạc vội vã)</i>\n\nNó đã biến mất. Bị xé toạc như bông gòn. Máy bắn đá của chúng - sự tàn ác thuần túy. Lửa nguyền rủa, màu xanh lam rực rỡ và mờ ảo. Một mùi hôi thối. Số lượng không xác định. Quá nhiều. <b>Dẫn đầu bởi <lorename>Vorgoth</lorename>.</b> Hắn đang đến.\n\nGiày nặng trịch. Đập nát sọ Caden. Lạc lối dưới này. Bùn lầy. Tất cả đều đỏ. Một làn sóng thép, <b>tràn về phía quảng trường chợ</b>. Anh em của tôi ở dưới - la hét. <i>Không còn đường xuống. Mọi thứ thật ồn ào - những tiếng hét. Tôi không thể chịu đựng được. Lạy các vị thần.</i>\n\nLàm ơn. Tôi chỉ là một người hầu cận. Xin đừng đập nát đầu tôi\nCaden, tôi xin lỗi",
    [1488198470] = "Người Cuồng Lửa",
    [1488260997] = "Đòn đánh không trúng nước.",
    [1488274649] = "Tấm Kim Loại",
    [1488540424] = "Nghiên cứu sự cố",
    [1490543036] = "Chiếc quần đáng chú ý. Điều gì làm cho chúng trở nên đáng chú ý? Chủ yếu là người mặc.",
    [1491891837] = "Bạn có cần thuốc không?",
    [1492387235] = "Pháp sư",
    [1492738204] = "Những người sống sót cần tìm:",
    [1492913444] = "<craftingstation>Vạc Đen</craftingstation>",
    [1493098022] = "Vậy là xong. Những người bạn Honeydew của tôi không còn nữa... Chúng tôi đã chia tay nhiều lần, nhưng có điều gì đó mách bảo tôi rằng đêm qua là lần cuối cùng. Điều tồi tệ hơn là những kẻ khốn nạn ở quán rượu đó sẽ không cho tôi một phòng sau khi những người bạn cùng ban nhạc của tôi - những người bạn cũ, tôi đoán vậy - đã làm náo loạn nơi này trong lúc đánh nhau. Harper và Daniel chưa bao giờ hòa hợp, nhưng lần này thì khác hẳn. Lẽ ra tôi nên cố gắng ngăn <b>Harper bỏ đi về phía cái pháo đài đó,</b> nhưng tôi đã quá bận né tránh những cú vung của Dan đến nỗi tôi hầu như không thể tập trung vào bất cứ điều gì khác.\n\nHiện tại, tôi không có ban nhạc, không có tiền công, và không có giường. Người pha chế thậm chí còn xúc phạm tôi. TÔI! Miles Rapore! Họ không biết tôi là một thiên tài âm nhạc sao? Đồ ngu. Sáng mai, tôi sẽ lại lên đường. Có vẻ như tôi không cần đóng gói sáo của mình. Có lẽ tôi nên thử lại nghề làm giày.",
    [1493112198] = "Đuốc Đầu Lâu Đứng Hầm Mộ",
    [1493279624] = "Phản đòn",
    [1493609710] = "Rơi ra từ kẻ địch Fell",
    [1493622382] = "Hãy để ngọn lửa trong huyết quản dẫn lối bạn!",
    [1493891755] = "Tiêu diệt 25 Drak",
    [1494225569] = "Sát thương lên kẻ địch Phép thuật",
    [1494636617] = "Thức ăn để thu hút và thuần hóa một Lạc Đà Voi. \n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vỗ về con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Một khi đã thuần hóa, con vật có thể được nhặt lên.",
    [1495005133] = "Chân Người Khổng Lồ bên trái này cao hơn bạn rất nhiều. Bạn hầu như chỉ với tới đầu gối.\n\nBộ sưu tập này được tìm thấy ở Đỉnh Albaneve. Nó có thể được lắp ráp lại để tạo thành một Bộ Xương Người Khổng Lồ trên Chân Đế Tượng Người Khổng Lồ.",
    [1495144421] = "Chào Emma. Thật kỳ lạ khi gặp bạn ở chợ — một nơi mà lẽ ra bạn không nên có mặt ngay từ đầu. Nhưng tôi đã kịp nhét mảnh giấy này vào lô hàng đến Umber Hollow và hy vọng bạn tìm thấy nó trước khi người khác làm. Mặc dù chúng ta chỉ nói chuyện ngắn ngủi, tôi có thể nói bạn là một người phụ nữ tốt bụng. Vậy nên những tin đồn về Umber Hollow là một nơi tồi tàn nơi sự tàn ác lan tràn không thể đúng sự thật, phải không? Tôi đã nghe rất nhiều câu chuyện về trộm cắp và tham nhũng...\n\nTôi chân thành hy vọng cả hai chúng ta có thể hiểu nhau hơn khi thế giới đang thay đổi trước mắt chúng ta. Chúng ta có thể cần nhau để tồn tại. Xin hãy viết thư lại cho tôi.\n\nTừ Carlos",
    [1495641750] = "Làm ơn! Hãy xem xét!",
    [1495678280] = "Phép thuật",
    [1496579217] = "Tìm Mảnh Tượng Thứ Hai",
    [1497176330] = "Thêm vào Danh sách Ước muốn trên Steam",
    [1497434496] = "Rừng Rực Lửa",
    [1498178285] = "Vỏ Sò Nổi Loạn",
    [1498858600] = "Đặt Lại",
    [1499385103] = "Khi bạn giảm xuống dưới 20% SP, bạn tự động nhận được 20% SP tối đa, tiêu tốn 1 MP cho mỗi SP.",
    [1499391285] = "Thùng Gỗ Đứng",
    [1499939340] = "Cuộn giấy triệu hồi một Tinh Linh Lửa đi theo, hỗ trợ bạn trong chiến đấu và cung cấp ánh sáng.",
    [1500455681] = "Trại Vukah",
    [1500992301] = "Tốt lắm khi đưa ta trở về, nhưng chúng ta không thể câu cá với những... thứ lảng vảng dưới nước đó. Ta đã cố cảnh báo chúng, ngươi biết đấy? Nhưng không ai tin ta... Ngươi đã thấy chúng chưa? Miệng há như hàm kẹp, móng vuốt như kền kền, và cơn khát máu như chính lãnh chúa điên loạn! Chúng ta phải đẩy lùi chúng - ta nợ chúng điều đó. Nhưng trước hết, chúng ta nên xem chúng ta đang đối mặt với cái gì! Một kỷ vật từ chúng là đủ!",
    [1501564447] = "Độ Bền Vũ Khí",
    [1502098705] = "Hy vọng hôm nay chúng sẽ cắn câu.",
    [1502135660] = "Tấm Rèm Gắn Tường Rách Nát Của Nhà Giả Kim",
    [1502386336] = "Cha ta là một người lính, nhưng ta thì chẳng giống chút nào. Ta đang tự lừa dối bản thân, khi bị đóng quân ở đây cùng với những người đàn ông vai rộng, dũng cảm, bạo lực đó? Đôi mắt họ không có ánh sáng. Những hố obsidian đơn giản nuốt chửng ta, phản chiếu sự yếu đuối của chính ta trở lại, pha lẫn sự khinh bỉ.\nHọ không có lòng tốt... cảm xúc duy nhất họ biết là sự tức giận lan tỏa, một sức nóng nội tại ăn mòn họ và sưởi ấm lớp vỏ của họ trong khi bùng cháy qua tuyết và băng.\n\nKhi cha ta qua đời, trái tim của tiền đồn này đã bị xé toạc. Và trái tim ta cũng vậy.\nHọ biết ta. Họ biết ta sẽ bỏ chạy và ẩn nấp ngay khi gặp rắc rối. Đó là cách họ chế giễu ta, cách họ gầm gừ tên ta. Đó là lý do tại sao họ ép ta làm nhiệm vụ canh gác... ngay cả điều đó cũng khiến ta sợ hãi.\n\nCó lẽ nó không tệ đến vậy. Cha ta luôn nói <i>\"Kẻ hèn nhát sống lâu hơn.\"</i>",
    [1503141200] = "Ngọc Cú Đập Sao Băng",
    [1505455811] = "Trại Đoàn Xe Phía Bắc",
    [1505467257] = "Một mũi tên thép tẩm độc, hoàn hảo cho việc săn bắn.\n\n<b>Mũi Tên Tẩm Độc</b>: Wildlife và Wild Beast trúng mũi tên này sẽ bị nhiễm độc và nhận 20 sát thương mỗi giây trong 5 giây.",
    [1505725832] = "Bình Máu Tối Thượng +",
    [1505733516] = "Cây Đêm",
    [1505988771] = "Giày Người Tiên Phong",
    [1506412801] = "Ghế Đá Granite Tráng Lệ",
    [1506924436] = "Điều cuối cùng ta biết là ta đang nghiêng người qua một trong những <i>thứ nảy bật</i> đáng sợ đó, cố gắng nhìn rõ hơn. Ta khá chắc rằng Jeff, thằng ngốc đó, đã đẩy ta - vì đột nhiên, ta bị phóng lên không trung, xoay tròn và lộn vòng. Rồi, ta tiếp đất, chân trước. Mắt cá chân ta kêu răng rắc và khuỵu xuống, ta cảm thấy một cơn rùng mình đau đớn lan khắp cơ thể... và bất tỉnh.\n\nKhi ta tỉnh dậy, ta bị bao phủ bởi những vết nhựa đường... Ta lau những giọt nước trên mặt và gọi Jeff, nhưng vô ích. Hóa ra hắn hẳn đã nhảy theo ta nhưng lại rơi vào vũng nhựa. Hắn không ngóc cái đầu rỗng tuếch ngu ngốc của mình lên khỏi nhựa đường... đáng đời hắn.\n\nTa sẽ băng bó mắt cá chân và rời đi ngay khi có thể di chuyển chân lại.",
    [1507188727] = "Ta từng bị chuột hoành hành trong tòa tháp cũ của mình. Ban đầu, chúng hữu ích cho các thí nghiệm, nhưng số lượng chuột nhanh chóng vượt quá tầm kiểm soát của ta. Chẳng bao lâu sau, ta thấy một vài con mèo hoang bị thu hút bởi các đối tượng thử nghiệm của ta... Cơ hội là mong manh, nhưng có lẽ chúng vẫn còn sinh sống trong khu vực. Ta có thể dùng một người bạn đồng hành mới cho phòng thí nghiệm!",
    [1507392829] = "Búa Chọc Ngoáy Ánh Nhìn",
    [1508466375] = "Đỡ đòn tấn công của kẻ địch bằng khiên sẽ tiêu hao SP. Mức tiêu hao được giảm bởi giá trị Đỡ của khiên.",
    [1508607428] = "Công cụ này có thể dùng để chải len thô. Nó có thể được tích hợp vào quy trình kéo sợi.",
    [1508666071] = "Ngạt thở",
    [1509300805] = "Một bộ phận mở rộng nhỏ cho các bình chưng cất để tách hóa chất trong khi đun nóng chúng.",
    [1509362315] = "Bạn đang ở trên không.",
    [1509617400] = "Nướng trên vỉ hoàn hảo, hãy thưởng thức miếng phi lê cá hảo hạng này.",
    [1509862525] = "Bước chân của bạn sẽ nhanh và im lặng, và đòn tấn công của bạn sẽ chí mạng.",
    [1510314656] = "Nhẫn Của Người Cổ Đại",
    [1510899938] = "Rìu Đá Hắc Diên Răng Cưa",
    [1510907607] = "Nước",
    [1511245831] = "Thỏi Bạc",
    [1511803114] = "Áo Giáp Chim Ưng",
    [1512020818] = "Bạn đã nhặt được con mèo đi lạc từ tòa tháp của Nhà Giả Kim! Đặt nó vào nhà để chào đón nó!",
    [1512025872] = "Khám phá <craftingstation>Dụng Cụ Thợ Mộc</craftingstation> Trong Các Trại Nghiên Cứu",
    [1512359993] = "Xô Thép",
    [1512875192] = "Cái miệng đói khát gọi tên ta. Cô đơn. Khao khát, giống như ta. Ta không có lựa chọn và nó biết điều đó.\n\nBị kẹt giữa những chiếc răng sắc như dao cạo - hai bên sườn ta bị cắt và xé toạc. Ta trượt dưới lưỡi nó, xoay tròn. Ngạt thở trong hơi ấm của nó. Nó giữ ta bên trong. Chúng ta giống nhau. Chúng ta là một.\n\nTại sao thân xác ta lại trống Hollow\nMột cái hố. Ta là một cái hố, trống Hollow, đói khát\nTa là hư vô, sự vắng mặt, khoảng không\nMột vài, nhiều, tất cả\nChính vực thẳm",
    [1512933167] = "Làm Sạch",
    [1515161204] = "Tự do lựa chọn từ nhiều loại vũ khí, kỹ năng và áo giáp để chọn con đường của riêng bạn. Bạn không bị giới hạn bởi một bộ lớp nhân vật định sẵn và có thể chế tạo cuộc phiêu lưu của mình theo mong muốn của riêng bạn.",
    [1515481517] = "Bạn nhận thêm một ô Thực phẩm.",
    [1515503068] = "Trụ Tạo Thế",
    [1515617726] = "Bạn đã đến đền Drak, nơi bạn nghi ngờ chứa cây đàn handpan huyền thoại.\n\n<b>Tìm kiếm trong đền thờ và tìm nhạc cụ để tiếp tục!</b>",
    [1515764152] = "Đổi Mật Khẩu",
    [1515786127] = "Một Kho Báu Trên Gác Mái",
    [1516189890] = "Chùy Móng Vuốt Sắt",
    [1516802541] = "Chế tạo hoặc kiếm được một chiếc móc neo.",
    [1517307072] = "Ta nghe những lời thì thầm về một pháp sư mạnh mẽ đã mất trí. Ta có thể kể cho ngươi nhiều hơn về hắn.",
    [1517410376] = "Một chiếc áo sơ mi bình thường, được bao phủ một phần bởi một chiếc áo khoác tinh vi hơn.",
    [1517526175] = "Sự Thăng Hoa của <lorename>Jezmina</lorename> được tìm thấy sau khi đánh bại Vukah Brawler trong Trụ Tạo Thế.",
    [1517641513] = "Khối Mái Ngói Sa Mạc",
    [1517709546] = "Cá Phi Lê",
    [1518161813] = "Ánh Sáng Lỏng",
    [1518244296] = "Quái Vật Fell",
    [1518252483] = "Hỡi Kẻ Sinh Ra Từ Lửa, lại đây! Ta có một thông điệp cho ngươi! Ta có lý do để tin rằng có thể có những con chó săn ở gần đây!",
    [1518474281] = "Cây Giống Cây Lanh",
    [1518826013] = "Ta có thể giúp gì?",
    [1519090482] = "Một con chim Redtail nhỏ, tròn, không biết bay. Ngay cả ở độ tuổi này, mỏ của chúng cũng có thể gây ra một số tổn thương. Đừng để bị mổ!",
    [1519272896] = "Scavenger",
    [1519364471] = "Cúp Danh Năng Quái Vật Sa Ngã",
    [1519543965] = "Mẹ Scavenger Gorger",
    [1519742008] = "Giày Thợ Rèn",
    [1519945420] = "Trại Drak'Dal",
    [1519975021] = "Tuần San Pike: Không Có Gì Vĩ Đại Về <lorename>Gormander</lorename>",
    [1520273806] = "Linh Hồn Làng Mất Tích",
    [1520673110] = "Một Thời Gian Tuyệt Vời Với Quả Mọng",
    [1520715932] = "<i>Ngươi nhìn thấy những trụ đá chìm trên đường chân trời, bị che khuất bởi những gò đất. Chúng vươn lên trời như những ngón tay xương lạnh lẽo của người khổng lồ. <b>Dấu ấn của một ngôi mộ ẩn giấu!</b> Cầu thang bên trong dẫn vào bóng tối. Cầm đuốc, ngươi trượt xuống sự không chắc chắn. Vào nỗi kinh hoàng. Tuy nhiên, cuộc tìm kiếm của ngươi thúc đẩy ngươi đi sâu hơn. Một kho báu bệnh hoạn gọi tên ngươi, bị bỏ lại để mục rữa trong bụi bặm! Đó có phải là trang sức gia đình? Báu vật từ những bờ biển xa xôi?</i> Dù đó là gì, bạn của ta, nó sẽ là <b>nền móng cho đế chế của chúng ta!</b> Viên đá góc cho một pháo đài được xây dựng từ máu đã đổ!\n\nNghe hay chứ? Ta biết vị trí đại khái. Nếu ngươi nhận nhiệm vụ tìm kiếm, Gerith, ta sẽ chia đôi chiến lợi phẩm. Thỏa thuận nhé?",
    [1520852152] = "Chủ sở hữu đã đá bạn khỏi phiên.",
    [1520924387] = "Cột Đá Cổ Đại",
    [1521677849] = "Việc làm đầy <i>Thanh Bị Choáng</i> của kẻ địch tăng thêm <b>20%</b> khi tấn công kẻ địch đang phòng thủ bằng vũ khí cận chiến.\n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang phòng thủ hoặc đỡ đòn của chúng sẽ làm đầy <i>Thanh Bị Choáng</i> của chúng cho đến khi chúng bị <b>Bị Áp Đảo</b>.\n<b>Kẻ địch Bị Áp Đảo</b> sẽ bị hở để thực hiện các Đòn Tấn Công Tàn Nhẫn.",
    [1521927834] = "Hãy để ta chế tạo cho ngươi thứ gì đó!",
    [1522106378] = "Một cây chùy chắc chắn, vung từ hoàng hôn đến bình minh, gieo rắc tai ương khắp nơi nó đánh trúng.",
    [1522126428] = "Kiên Định",
    [1522142393] = "Hồi phục %k Nhiệt Cơ thể mỗi giây.",
    [1522340672] = "Giáp Ngực Thành Lũy Hoàng Kim",
    [1522570141] = "Vào Giếng Thuốc Tiên",
    [1522693208] = "Một chiếc áo khoác huyền bí tinh xảo làm từ chất liệu nhuộm cao cấp. Chỉ riêng các khóa kim loại đã có giá trị cao.",
    [1522857561] = "Ngươi có vần với \"Flameborn\" không…?",
    [1522984058] = "Sát Thương Gậy phép",
    [1523011741] = "Áo Giáp Trưởng Lão",
    [1523241505] = "Găng Tay Đóng Băng",
    [1523545508] = "<lorename>Vorgoth</lorename>",
    [1524267889] = "Cây Giống Chàm",
    [1525023830] = "Thay đổi công thức (%k)",
    [1525316746] = "Ngươi tin được không? Ta muốn gặm miếng thịt nướng của mình thì đột nhiên, từ đâu không biết, con mèo này xuất hiện và giật mất thức ăn của ta!\n\nTa thề, nó tấn công ta với sự hung dữ của một con hổ răng kiếm! Ta đuổi theo nó một lúc lâu, nhưng con vật chết tiệt đó quá nhanh. Hơn nữa, ta không đuổi theo một con mèo đến tận <location>Bãi Biển Sapphire</location>! Ta không đói đến mức đó! \nVì vậy, về cơ bản, ta đang hỏi: Ta có thể xin thêm một khẩu phần ăn nữa không...?",
    [1525325686] = "Những chiếc gai của cây chùy gai này có thể nghiền nát vô số túi thịt thành bùn.",
    [1525497606] = "Không có Móc Neo Kéo nào trong tầm với.",
    [1525544573] = "Thợ cắt tóc muốn bạn tìm kiếm trong Nhà Thợ Mỏ để tìm dấu vết của nguồn cảm hứng - ghi chú, bài viết hoặc suy nghĩ từng được các cư dân sáng tạo để lại.",
    [1525658206] = "Khung Cửa Sổ Đá Granite",
    [1526026063] = "Không Vũ Khí",
    [1527266720] = "Thức Ăn Cho Chó",
    [1527521143] = "Châu Chấu",
    [1527944368] = "ST Cận chiến",
    [1528038143] = "Được ban phước bởi Ngọn Lửa, Cung Lửa này sẽ rất hữu ích trong cuộc chiến chống lại Sương độc.",
    [1528573661] = "Liên Kết Tài Khoản Twitch",
    [1528714725] = "Bạn đã khám phá nơi ẩn náu được cho là của Ramone. Trong một bức thư, hắn nói về việc sống trong hầm rượu bí mật của bạn mình. Tìm kiếm tầng hầm dưới ngôi nhà để tìm Ramone!",
    [1529083238] = "Găng Tay Ẩn",
    [1529490787] = "Bắt đầu một trò chơi công khai, được lưu cục bộ",
    [1530129581] = "Địa điểm",
    [1530805902] = "Vỏ Cây Đầm Lầy Đen",
    [1532243373] = "Kháng Phép",
    [1532346137] = "<craftingstation>Lò Rèn</craftingstation>",
    [1532640750] = "Trò Chơi Trực Tuyến",
    [1532678383] = "Ở đây, ngươi có thể thấy những con sói tru lên, và sợi dây ràng buộc chúng với mặt trăng trên cao — tất cả được khắc họa qua ẩn dụ bằng những lựa chọn thiết kế đơn giản.",
    [1532986898] = "Cắn: Sẵn sàng",
    [1533001765] = "Hả? Một cuộc phục kích? Nhưng ta đã xóa dấu vết của mình! Sao binh lính lại có thể...? À, nhện, ngươi nói vậy sao? ...Vậy thì mặc kệ ta đi. <b>Đặt <craftingstation>Cây Suốt Tơ</craftingstation> đó xuống, </b> và chúng ta sẽ tiếp tục. Im lặng nào trong khi chúng ta chế tạo. Bí mật của ta là của ta.",
    [1533087310] = "<b>Rễ Sương Độc</b> sâu bên trong Giếng Tinh Hoa cần phải bị phá hủy để ngăn chặn nó lan rộng.",
    [1533286785] = "Ta... Ta c-cần một viên ngọc... sánh ngang vẻ đẹp của mặt trăng... Ta k-không biết tại sao... nó lại gọi ta. Làm ơn... giúp ta. Làm ơn hãy cho ta thấy nó... Cảm ơn, chủ nhân.",
    [1533695532] = "Thợ Cắt Tóc vẫn không thể nhớ cách pha chế thuốc nhuộm tóc màu xanh lam, nhưng có điều gì đó đã trỗi dậy trong ký ức của ông ta. Ông ta nhớ về một \"lâu đài\" mà ông ta thường đi qua khi thu thập nguyên liệu, và đã chỉ cho ngươi địa điểm đó.\n\n<b>Hãy đến thăm lâu đài và tìm nguyên liệu </b> để kích hoạt ký ức của Thợ Cắt Tóc!\nNgươi cũng có thể <b>thu thập nguyên liệu ở những nơi khác trong Rừng Khải Hoàn </b> và mang chúng trả lại cho Thợ Cắt Tóc trong khi <b>chúng trong hành trang của ngươi.</b>",
    [1533989792] = "Khung Cửa Sổ Vàng",
    [1534647203] = "Một cây rìu 2H nặng nề, thường được các nhà vô địch đấu trường sử dụng! Những cây rìu như thế này thường là biểu tượng địa vị và đại diện cho chiến thắng.",
    [1534660054] = "Người Mất Tích: Rolf Mantacore",
    [1535067855] = "Với Giường Che Đã Được Giao",
    [1535650592] = "Hỡi Hỏa Sinh, hãy đến nói chuyện với ta — ta lại cần cảm hứng, và chỉ có ngươi mới có thể giúp ta!",
    [1536027520] = "Bao Tải Tiếp Tế II",
    [1536768210] = "Vào ngày đầu tiên, Lãnh chúa vĩ đại Vorgoth đã đặt mắt lên Dãy núi Albaneve.\nNgài phán: \"Những đỉnh núi như vậy xứng đáng với sự vĩ đại của quốc gia chúng ta. Những thung lũng như vậy sẽ mang lại trái cây từ Giếng Tinh chất của chúng ta.\"\n\nVào ngày thứ hai, Lãnh chúa hành quân về phía chân trời, tạo ra một con đường xuyên qua vẻ đẹp hiểm trở của những ngọn núi hoang dã cho dòng dõi của mình.\n\nVào ngày thứ ba, bóng tối đã chờ đợi ngài tại Đỉnh Sói hú. Những con rồng đã thức tỉnh để ngăn cản Vua của chúng ta thực hiện yêu sách chính đáng của mình!\nLãnh chúa Vorgoth giơ tay chống lại những con thú có cánh và gầm lên: \"Các ngươi không phải là đối thủ của đại bàng đỏ, và các ngươi sẽ chết dưới tay lòng dũng cảm và thép của chúng ta!\"\n\nVào ngày thứ tư, ngài đã bổ đôi sọ của rồng mẹ, <b>cắm chiếc rìu của mình giữa mắt nó khi nó rơi khỏi bầu trời.</b> Như vậy, các đỉnh núi đã được giải phóng khỏi cái ác, và vương quốc ăn mừng.",
    [1537209311] = "Chất Lượng Lưới Voxel",
    [1537603397] = "Trống Chảo",
    [1537822510] = "Trại Lữ Hành Phía Nam",
    [1537940296] = "Mồi Câu Cá Hiếm",
    [1537986927] = "Mỏ Đá Cẩm Thạch Hồ Camellia",
    [1538068805] = "Gần đây, Maynard đã có thói quen tắm rửa trong giờ nghỉ. \n\nTa không phiền lắm — ta thích hắn có mùi nước hoa hồng và sáp nến hơn là mùi cáu bẩn và càu nhàu thường ngày của hắn. Nhưng hắn tắm MẤT HẾT HẾT GIỜ, bỏ ta một mình để chăn dắt những kẻ khốn khổ trong các phòng giam! \n\nHắn nghĩ mình là cáo già lắm đấy — như thể ta không thấy cuốn sách hắn giấu dưới khăn tắm mỗi khi hắn đi vậy. Ta không quan tâm hắn đọc thứ gì, nhưng hắn không thể nhanh hơn một chút sao?",
    [1538474927] = "Không có nguồn năng lượng gần đó (%km).",
    [1538712877] = "Cửa Đá Granite Đánh Bóng Bí Mật",
    [1538761625] = "Công Thức Đêm Khô Cốt",
    [1539221170] = "Móc Đu Dưới Nước",
    [1539553673] = "Lưng Gai Đỏ",
    [1539948162] = "Nhạc Sĩ",
    [1540021032] = "Bị Nuốt Chửng Bởi Sự Tăm Tối",
    [1540201438] = "Ngươi đã tìm thấy ngôi mộ chôn giấu chứa một <b>phép thuật vĩnh cửu</b>. Hãy vào mộ và tìm phép thuật để sở hữu sức mạnh của nó!",
    [1540268545] = "Việc đỡ đòn trở nên dễ dàng trong đôi găng tay này, và những viên pha lê bắt lấy ánh mặt trời với mỗi cử động.",
    [1541025446] = "Lời Nguyền",
    [1541302232] = "Ngươi có thể giữ hoặc mất tất cả vật phẩm trong túi đồ khi chết. Trong cài đặt mặc định, ngươi chỉ mất nguyên liệu. Vật phẩm đã mất được lưu trữ trong một bia mộ và có thể được phục hồi tại đó.",
    [1541388445] = "Nhẫn Chỉ Huy",
    [1542000257] = "Luống Trồng Cây Trống",
    [1542051209] = "Thời Gian Trong Sương độc",
    [1542366158] = "Một trạm chế tạo đặc biệt cho phép những kẻ dùng nó một cách xảo quyệt tạo ra các nguyên liệu ngoài thế giới này.",
    [1542473255] = "Hạ Thân Nhiệt",
    [1542759827] = "Người Câu Cá đã kể cho ngươi một câu chuyện khó tin về việc ông ta từng mọc vây để bơi nhanh hơn. Mặc dù ông ta có lẽ đang phóng đại rất nhiều, nhưng có thể có một chút sự thật trong câu chuyện của ông ta.\n\nCâu chuyện của ông ta diễn ra gần Yên Ngựa Vàng. Hãy đến đó để tiếp tục!",
    [1543143329] = "Có <b>hàng lậu được giấu ở đâu đó trong <location>Nơi Nghỉ Ngơi Của Surat</location>.</b> Hãy tìm địa điểm đó và thu hồi chiến lợi phẩm!",
    [1543250540] = "Cuốc Mạ Vàng",
    [1543553695] = "Bên trong, ngươi không thấy gì cả. Sự vắng mặt của vật chất — của sự tỉnh táo và thánh địa.\n\nThu thập nhiều Đầu Quái Vật Fell để chế tạo Tượng Đài.",
    [1543702145] = "Thú Sư",
    [1543943212] = "Giữa Bụi",
    [1544172582] = "Chơi Trò Quậy Phá",
    [1544221807] = "Vuk'harbinger",
    [1544681045] = "Ong Chích",
    [1544811248] = "Thảm Rơm Phủ Lông Thú",
    [1545230699] = "Tranh Tưởng Nhớ Drak Slurp",
    [1545709617] = "Khối Đường Đá Vôi",
    [1545958063] = "Chậu Cây Lớn",
    [1546328346] = "Sức Mạnh",
    [1546424133] = "Sát Thương",
    [1546482832] = "Chuyển Đổi",
    [1546641658] = "Rìu Điềm Báo Máu",
    [1547154108] = "Thức Ăn Cho Thú Cưng",
    [1547438253] = "Đánh Bại Ma Cà Rồng Trong Đền Thờ Mặt Trời Ma Ám",
    [1547768194] = "Trại Nữ Hoàng Jezmina",
    [1547835388] = "Đôi ủng có gai này có thể gây ra nhiều sát thương khi dùng để đâm động mạch bằng một cú đá xoay nhanh.",
    [1547894139] = "Màu nâu cát, mềm mại và màu tro sáng tạo nên bảng màu này có vẻ ngoài bụi bặm nhưng sang trọng.\n\nBảng màu này có thể được tạo bằng nguyên liệu Rừng Khải Hoàn.",
    [1548161553] = "Chữa thương",
    [1549430699] = "Nạp Lại Chồng",
    [1549814314] = "Ông Bố Người Tuyết",
    [1549994986] = "Một khả năng an toàn để tiếp xúc với nhiệt mà không làm cháy.",
    [1550518186] = "Bọ Cuộn",
    [1550850198] = "Bàn Thờ Ngọn lửa Cấp 3",
    [1551259494] = "Người sống sót này sẽ là một bổ sung xứng đáng cho mục tiêu của chúng ta. Hãy đặt họ vào thế giới bằng một <b>Gậy phép Triệu Hồi</b>, thứ mà ngươi có thể chế tạo từ những <b>Cành Cây</b> đơn giản.",
    [1551270780] = "Thời Gian Thi Triển",
    [1551576926] = "Ngươi đã tìm thấy một ghi chú tiết lộ rằng Nữ Hoàng Jezmina đã đi qua Lưu Vực Nước Ve. \n\nHãy đi theo dấu chân của nàng trong cuộc hành trình này và khám phá tất cả các trại của nàng! Một số vật tư còn sót lại của nàng vẫn có thể giúp ngươi.",
    [1552165377] = "Bờ Biển Sao Biển",
    [1552636706] = "Obelisk Cổ Đại II",
    [1552833175] = "Kỹ Năng",
    [1552905517] = "Lưỡi Kiếm Than Khóc",
    [1553225192] = "Cánh Cửa Đêm Cổ Đại",
    [1553312705] = "Chùy Gai Sáng Chói",
    [1553606637] = "Ân Huệ Của Thủy Triều",
    [1553623971] = "Ôi trời! Mùi hương ngọt ngào đó... Ngươi mang theo một ít quả mọng! Ôi, ta thà chết còn hơn là không có một bát quả mọng tuyệt đẹp ngay bây giờ... nói xem, ngươi có thể mang cho ta một ít dâu tây được không? Nó sẽ làm sáng bừng ngày của ta! Ta thậm chí sẽ chia sẻ một bí mật nhỏ với ngươi!",
    [1553937580] = "Khu Vực Điều Khiển Cuộn Thay Đổi",
    [1554073849] = "Trang Bị",
    [1554677565] = "Một chiếc mũ thương gia sẽ thu hút sự chú ý ở quảng trường chợ khi kết hợp với GIỌNG NÓI ĐỦ LỚN và các giao dịch tốt!",
    [1555041658] = "Ta không thể tin được! Cuối cùng ta đã tạo ra một phép Chữa thương! Nhưng... nó lại Chữa thương cho <b>người khác</b>?! Ngươi có tin được không? Ta phải làm gì với cái này? Nó có ích gì cho ta nếu người khác sống lâu hơn? .. nhưng ít nhất ta đang đi đúng hướng. Ngôi mộ tiếp theo đang chờ đợi. Ta đã nghe những câu chuyện về những người trẻ tuổi dám chạy đua qua đó, vượt qua những thử thách của nó. Bất cứ ai đến được phía bên kia... thì họ sẽ sống. Nó được cho là ở gần Khe Nứt Khai Thác về phía Đầm Đen.",
    [1555837898] = "Vật liệu địa hình không phù hợp",
    [1557496885] = "Xoay lại",
    [1557787336] = "Găng Tay Rực Lửa",
    [1557877754] = "Sử Dụng Vật Phẩm",
    [1558243065] = "Ngươi đã tìm thấy linh hồn của Melville Fontane, một thuyền trưởng đã nghỉ hưu trở thành chủ quán trọ và ngư dân. \n\nTriệu hồi ông ta để tìm hiểu thêm về Lưu Vực Nước Ve!",
    [1558345563] = "Những đôi găng tay hở ngón này cho phép người đeo cảm nhận từng chiếc lá và rễ cây trước khi hái, cho phép đánh giá đúng.",
    [1559269657] = "<keyitem>Nồi Nấu</keyitem> Cần Thiết Cho <craftingstation>Lò Nung</craftingstation>",
    [1559362896] = "Emily Fray nói rằng cô ấy đã làm mất chiếc nhẫn của mẹ mình ở đâu đó trong Vùng Đất Khô Cằn. Hãy giúp cô ấy tìm nó bằng cách tìm kiếm khu vực được đánh dấu trên bản đồ.",
    [1559496176] = "Cái lạnh thấm qua từng thớ thịt của ta. Mọi sợi dây, mọi khía cạnh của linh hồn ta đều bao phủ bởi sương sớm. Làm ơn, hãy tạo nơi trú ẩn cho người bạn mới của ngươi, người mang lửa. Hãy cân nhắc điều đó.",
    [1559524352] = "Một sinh vật nhỏ bé nhút nhát với bộ lông lốm đốm. Nó được tìm thấy trong một ngôi nhà trống ở Vùng Đất Khô Cằn. \n\nNgười phụ nữ từng sống trong ngôi nhà đó có rất nhiều chó, và con chó yêu thích của bà là \"Pompom\". Có lẽ con chó này là một trong những hậu duệ của nó!",
    [1559666791] = "Bình",
    [1560363786] = "Cá",
    [1560566769] = "Thang Tre",
    [1560582624] = "Một Khởi Đầu Đầy Hy Vọng",
    [1561116515] = "Trò Chuyện Thoại",
    [1561405397] = "Một <npc>Thợ Mộc</npc>'s <keyitem>Lưỡi Cưa Tròn</keyitem>",
    [1561878035] = "Khí Hậu",
    [1562265689] = "Câu chuyện tiếp diễn",
    [1563476781] = "Được đánh dấu qua hàng trăm giờ chịu đựng sức mạnh của lửa, cây đũa phép này có kết nối với nguyên tố và có khả năng sử dụng nó.\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương bổ sung lên đến phần trăm <i>quá tải</i>.",
    [1563507428] = "Các nhà nghiên cứu đã để lại di vật Vukah tại Thánh địa Ngọn lửa ở Cao nguyên Du mục. Hãy tìm kiếm địa điểm và <b>thu hồi di vật Vukah!</b>",
    [1564041838] = "Một chú chuột lang Capybara bé nhỏ. Nó thích được vuốt ve, nhấm nháp hoa huệ, ngâm mình trong suối nước nóng và được ôm chặt trong vòng tay ấm áp của bạn.",
    [1564219229] = "Một phần của Giáp Xe tăng.",
    [1564325585] = "Một khối bạc trông đắt tiền, tốn nhiều tài nguyên. Hãy gây ấn tượng với bạn bè bằng tất cả sự giàu có của bạn thông qua khối kim loại sáng bóng này!",
    [1564495193] = "Cái nhìn sâu sắc của Nhà giả kim",
    [1564527794] = "Cẩn thận nhé. Hãy luôn tử tế.",
    [1565163434] = "Tham gia",
    [1565250129] = "Thật ư, bây giờ ư?",
    [1565822445] = "Đầu Ma-nơ-canh \"Tóc Bò Liếm\"",
    [1566220864] = "Ta có thứ mới cho ngươi đây, sếp.\nMột trong những nô lệ mới, gã Oscar đó — ta nghĩ hắn đang lên kế hoạch trốn khỏi mỏ đá! Ta thấy hắn giấu một mảnh đá cẩm thạch vào giày mấy ngày trước để tuồn ra ngoài qua lính canh của ngươi. Ta cứ nghĩ hắn chỉ muốn đổi nó, ngươi biết đấy, lấy một chút trà thảo mộc hoặc một lần cạo râu sạch sẽ. Nhưng đêm qua ta tỉnh giấc bởi tiếng đá va vào xiềng xích kim loại. Hắn đang cố gắng thoát khỏi xiềng xích của ngươi!\n\nĐó là tất cả những gì ta có thể nói. Chắc chắn, nó xứng đáng được thưởng, phải không? Làm ơn, giờ ngươi có thể cho ta đi chưa? Ta đã làm đủ cho ngươi rồi ư?",
    [1566614382] = "Giày Ảo Thuật Gia",
    [1566637140] = "Cái guồng quay",
    [1567270250] = "Không có gì đáng ngờ ở đây!",
    [1567538788] = "Ikko",
    [1567954055] = "Được che chở",
    [1568465208] = "Bạn cũ của ta, chia sẻ ngọn lửa của ngươi cho những người cần, được không?",
    [1568652290] = "Nhận Khối đá Tường Thành",
    [1570579580] = "Khối Đường Đá Nhẵn",
    [1570723590] = "Để xuyên thủng trái tim bằng một mũi tên ma thuật... Ta không cần phải nhìn cận cảnh lần nữa, nhưng ta muốn nghe thêm về nó!",
    [1570798904] = "Tăng ST Xuyên ",
    [1570933594] = "Thật là một vinh dự",
    [1571349004] = "Dao Găm Drak Nhỏ",
    [1571518430] = "Tuyết",
    [1571950856] = "(Không có gì để thảo luận)",
    [1572202097] = "Vào cài đặt để điều chỉnh loại vật phẩm nào cần xác nhận để xóa hoặc bán.",
    [1572370215] = "Sẵn sàng chế tạo công thức đã ghim",
    [1572431093] = "Sốc",
    [1573503036] = "Tham gia vào việc cướp bóc (có đạo đức)",
    [1574387123] = "Trông như chúng ta đã chạm đúng dây đàn!",
    [1574645013] = "Người giữ bí mật của Bể nước Veil",
    [1574700452] = "Thay đổi",
    [1574944492] = "Một chú chó vui vẻ và vô tư thích ngủ nướng. Nó yêu thích việc được xoa bụng và lao về phía bạn một cách điên cuồng mỗi khi nhìn thấy bạn.\n\nBạn đã tìm thấy chú chó này trong một tòa tháp bị thống trị bởi những con chó săn Hollow và một Pháp sư Hollow. Pháp sư dường như đã cố gắng tạo ra một vật chứa cho một người bạn đồng hành tên là \"Ikko\". Bạn đã gián đoạn nghi lễ của họ - nhưng cái tên vẫn còn đó.",
    [1575070622] = " <npc>Thợ mộc</npc> quan tâm đến cách các Giếng thuốc được xây dựng. Ông ấy đề nghị khám phá một Giếng thuốc ở Kindlewastes. Có lẽ một số <b>vật liệu xây dựng</b> hữu ích có thể được tìm thấy ở đó.",
    [1575824087] = "Một chiếc mũ bảo hiểm đơn giản nhưng đáng tin cậy. Bạn vẫn có thể bị va đập nếu bị đánh, nhưng đó là một phần của niềm vui.",
    [1575857088] = "Các tế bào không chỉ làm ô nhiễm. Chúng <i>hấp thụ</i>. Bằng cách phân hủy vật chất tự nhiên và biến nó thành một thứ gì đó mới... chúng tạo ra một chu kỳ cho năng lượng và sự phát triển! Ta phải hiểu nó... thử nghiệm nhiều hơn với <i>Bào tử Sương độc,</i> và tìm hiểu chính xác cách nó hoạt động. Ta thà ở đây còn hơn ở với dân làng... họ hút cạn năng lượng của ta.\n\nDịch trong <craftingstation>Nồi đen</craftingstation> — quay và quay... và quay... Hòa tan nó, từ từ ăn mòn. Thay đổi nó.\n\nCó lần, ta đã nhìn quá lâu vào nó khi nó quay... và ta nghĩ ta cảm thấy nó nhìn lại ta. Có lẽ ta đã già đi vì tuổi tác. Hoặc cô đơn.\n— <lorename>Ikora</lorename>",
    [1576808202] = "Trọng Kiếm Trái Tim Sắt",
    [1576891922] = "Điểm Kỹ Năng",
    [1576936045] = "Lọc kết cấu",
    [1577030615] = "Trường Cung Rừng Xanh",
    [1577128416] = "Một ngọn đuốc tiên tiến cung cấp ánh sáng trong thời gian dài hơn. Sử dụng nó để khám phá sâu hơn vào vực thẳm!",
    [1577594738] = "Bạn thân Ngọn lửa của ta, sự tức giận đang sôi sục trong ta. Nó cần được xoa dịu... nó cần máu đổ ra và xương trắng.",
    [1577711826] = "Thu hoạch",
    [1578244050] = "Máy Pha Cà Phê",
    [1578582536] = "Kẹo",
    [1578665197] = "Dọn sạch Kindlewastes khỏi tất cả rễ cây Sương độc.",
    [1578681745] = "Vật phẩm không thể sửa chữa.",
    [1578708576] = "+ Đập",
    [1579190516] = "Thực hiện các hành động phòng thủ để ngăn chặn hoặc giảm thiểu sát thương nhận vào. Hầu hết chúng đều tốn SP, vì vậy hãy để ý <b>vòng tròn SP</b> của bạn.\n\nThực hiện <b>Lăn né</b> bằng cách nhấn <b>%k</b> để né tránh các đòn tấn công của kẻ địch.\n\nKhi được trang bị khiên, <b>chặn</b> các đòn tấn công bằng %k. Một pha chặn đúng lúc sẽ <b>phản đòn</b> đòn tấn công của kẻ địch. Phản đòn không tốn SP, ngắt đòn tấn công của kẻ địch và làm đầy thanh choáng của chúng.\n\nKhi đầy, kẻ địch sẽ bị <b>Bị Áp Đảo</b> và bị <b>choáng tạm thời</b>.",
    [1579423602] = "Đến Thành phố Cổ đại bị nhấn chìm",
    [1579483555] = "<npc>Thợ săn</npc>",
    [1579505409] = "Cá Cắt Khúc",
    [1579539317] = "Cỏ dại đã đủ tệ rồi!",
    [1579855031] = "Tăng HP thêm %k mỗi Điểm thuộc tính.",
    [1579859619] = "Trọng Kiếm Lưỡi Hái",
    [1580060742] = "Kể từ khi chúng ta bắt đầu xây dựng Giếng thuốc này, mặt đất đã có xu hướng rung chuyển dữ dội.\n\nTuyết có màu xám. Tiếng vọng thì thầm những lời chưa bao giờ được nói ra. <i>Chúng ta có thể nghe thấy thứ gì đó bên trong núi.</i>\n\nTa nghĩ chúng ta đang làm ô nhiễm thứ gì đó mà chúng ta thậm chí còn chưa hiểu. Dù đó là gì, ta không muốn ở gần khi nó thức dậy... Ta chỉ hy vọng các tiền đồn hoàn thành máy bắn đá của họ.",
    [1581002920] = "Hành trình cuối cùng",
    [1581623992] = "Các vật phẩm được lưu trữ ở đây có thể được sử dụng cho mục đích chế tạo từ bất kỳ đâu trong căn cứ!",
    [1581646002] = "Giường Gỗ Thô Sơ",
    [1581698556] = "Cái sàng đào mỏ này sẽ cho phép bạn đào quặng dưới nước! Bạn muốn sử dụng nó để làm gì? Giáp? Một thanh kiếm? Một vương miện? Hãy cho ta biết và ta sẽ làm cho bạn!",
    [1581867845] = "Kẻ tấn công Fell",
    [1581870470] = "Trại Lạc đà Cát",
    [1582456351] = "Bạn có thể được hồi sinh bởi người chơi khác.",
    [1582642773] = "Bụi Ngà Nước",
    [1582769044] = "Một miếng thịt nấm tươi màu hồng. Nó có nhiều ứng dụng.",
    [1582889564] = "Các ràng buộc được đề xuất bị thiếu. Nếu không có chúng, trải nghiệm chơi game có thể bị ảnh hưởng tiêu cực.",
    [1583143415] = "Giày Đạo Sư Băng Ngọc",
    [1583741505] = "Giấu mũ",
    [1583950546] = "Chảy máu",
    [1584626042] = "Đá từ nhà tù ngục tối. Nó đã chuyển sang màu vàng theo thời gian do khí thoát ra từ xác chết đang phân hủy của cư dân.",
    [1584713029] = "Bể nước Veil",
    [1584753013] = "Cảm ơn bạn đã chơi bản demo Sương độc bao phủ! \nBạn đã đạt đến cuối tiến trình nhiệm vụ có sẵn cho bản demo. \nBạn có thể tiếp tục chơi cho đến khi hết giờ, hoặc cho đến khi chúng tôi gỡ bỏ bản demo vào ngày 22 tháng 10. \nNếu bạn thích những gì đã thấy cho đến nay, hãy thêm Sương độc bao phủ vào danh sách yêu thích của bạn để được cập nhật về bản phát hành Truy cập sớm và các tin tức khác!",
    [1584930986] = "Chào mừng đến với <location>Pháo đài Kelvin</location>!",
    [1585428458] = "Chuyển đổi",
    [1586000711] = "Chọn Biểu cảm",
    [1586810538] = "Sức bền",
    [1587326234] = "Khi rơi từ độ cao lớn, bạn có thể thực hiện một đòn tấn công cận chiến đặc biệt bằng <b>%k</b>. Một đòn đánh thành công sẽ gây gấp đôi sát thương và giảm 50% sát thương khi rơi.",
    [1587429587] = "Vị trí rương được tiết lộ",
    [1587452666] = "Vì vậy, bạn đã gặp \"Drak\". Chúng đã ám ảnh vùng đất này từ lâu trước khi chúng ta đuổi chúng khỏi bờ biển và quay trở lại biển xanh, nơi chúng thuộc về... Nhưng chúng là những con thú báo thù, vì vậy khi chúng ngửi thấy máu, nỗi sợ hãi và sự thối rữa của chúng ta, chúng đã quay trở lại. Điều tồi tệ nhất về nó? Ta hiểu. Nếu ai đó đã làm ô nhục bộ tộc của ta, ta cũng sẽ trả thù cho họ. Để đánh bại chúng, chúng ta phải hiểu rõ chúng... và đổ máu như chúng!",
    [1587764251] = "Trang trại dê Wickmouth",
    [1587815576] = "Khu vực tìm kiếm Mái nhà Vảy rồng",
    [1588586638] = "Thật là một sự khác biệt mà một mái nhà tạo ra.",
    [1589069107] = "Bạn đã đến lối đi dẫn đến Bể nước Veil gần đó. \n\n<b>Tiến qua lối đi và đến phía bên kia</b> để có cái nhìn thoáng qua về những chân trời xanh mới, lấp lánh phía xa!",
    [1589289082] = "Được thợ rèn sử dụng để nấu chảy và hợp kim kim loại.",
    [1589412618] = "Đây là một cây cung rất tinh vi với độ căng cao.",
    [1589448086] = "Thịt nấm tươi, dai. Tốt nhất là không nên ăn nó như thế này.",
    [1589774623] = "Tiệc Capybara",
    [1589824194] = "Vị trí vật phẩm trang trí",
    [1589890446] = "Sương độc",
    [1590550689] = "Cầu Gai Biển Tròn",
    [1590900147] = "Đất Đỉnh Albaneve",
    [1591318877] = "Kem Chống Băng Giá",
    [1591333236] = "Cánh đồng u sầu",
    [1591488855] = "Rãnh Xương II",
    [1592413581] = "Cửa Lâu Đài Giả",
    [1592479762] = "Suốt đời ta, biển luôn ở bên ta.\n\nKhuôn mặt nàng lấp lánh dưới ánh ban ngày, được trang trí bởi những đốm sáng xoay tròn, được mặt trời nhẹ nhàng vuốt ve. Những nỗi buồn của ta sẽ tan biến khi nhìn thấy. Ngay cả khi nàng dâng lên và cuộn trào bên bờ... Nàng đã cuốn trôi mọi nỗi buồn và đau khổ cũ. Giờ đây, ánh sáng trong mắt ta đang mờ dần. Ta nghe tiếng sóng vỗ trong tai, như tiếng thì thầm của một chiếc vỏ sò. Chúng đang đến gần hơn.\n\n<b>Ta đã giấu tất cả những gì còn lại của mình bên dưới</b> để nàng mang đi. Món quà chia tay của ta dành cho một người bạn cũ.",
    [1592577063] = "Quá khứ, hiện tại và tương lai đều mở ra trước mắt bạn như những bông hoa huệ nở rộ khi nhìn qua chiếc mũ bảo hiểm này.",
    [1593417295] = "Chất lượng FSR2",
    [1593482045] = "Bạn đã tìm thấy Lưỡi kiếm Than khóc! Nó được khắc bởi thợ rèn bậc thầy của thủ đô. Nói chuyện với Oswald Anders để tìm hiểu thêm.",
    [1593527274] = "Một Mũi Tên Gỗ được làm từ những nguyên liệu cơ bản nhất.",
    [1593783778] = "Cầu Cổ Đại",
    [1593859748] = "Ngươi đã tìm thấy hai mảnh của bức tượng, nhưng phần còn lại đã bị ném xuống vùng nước gần đó. Hãy đến những góc xa nhất của bến cảng để lấy lại mảnh cuối cùng của bức tượng Nữ Hoàng <lorename>Pikemead</lorename>.\n\nĐến đó và lấy nó khỏi ngôi mộ dưới nước!",
    [1594095129] = "Xây Dựng Một Giường Che Chắn Cho <npc>Nhà Sưu Tầm</npc>",
    [1594101983] = "Đá Quý Mới",
    [1594157406] = "Trong tay",
    [1594304683] = "Bình Sinh Tồn Chướng Khí Lớn",
    [1594390339] = "Vây Vàng Nướng",
    [1595248671] = "Chiếc cuốc thép này đã được tinh chế thêm bằng cách bổ sung các chi tiết trang trí bằng vàng.",
    [1596084075] = "Xem Nhiệm Vụ Được Tham Chiếu",
    [1596442203] = "Ngươi đã biết rằng chủ nhân của căn gác mái đã cố gắng vượt qua ngưỡng cửa giữa sự sống và cái chết để đoàn tụ ai đó với người thân đã khuất. \"Nghi Lễ Đoàn Tụ\" dường như là phát minh của \"Bà Leclair\" tại <location>Glennwood's End</location>.\n\nTìm nhà của Bà Leclair tại <location>Glennwood's End</location> và điều tra nó!",
    [1596534068] = "Kiếm 1H",
    [1597412291] = "Người của ta là những kẻ giản dị. Tất cả những gì chúng ta cần là chút thức ăn và một chiếc giường ấm áp, che chắn! Nếu ngươi có một chiếc dư, ta sẽ vui lòng nhận lấy. Hãy chọn một chiếc và giao nó cho ta bằng Gậy phép Triệu Hồi của ngươi!",
    [1597793034] = "Tục Lệ Hắc Ám",
    [1598332240] = "Điều chỉnh chất lượng của Sương độc. Giảm chất lượng sẽ tăng hiệu suất.",
    [1598707957] = "Cánh cửa dẫn đến phòng thí nghiệm dưới lòng đất của <npc>Nhà Giả Kim</npc> dường như bị khóa, nhưng <craftingstation>Cối Nghiền</craftingstation> của ông ta hẳn là ở bên trong. Chắc chắn phải có một loại <b>cơ chế ẩn</b> nào đó để mở nó ở đâu đó trong tòa tháp.",
    [1598732175] = "Ngọn Lửa kêu gọi ngươi tìm kiếm căn phòng thức tỉnh ẩn chứa một cổ vật mạnh mẽ bên trong. Đây sẽ là chuyến đi cuối cùng của ngươi lúc này, nhưng ngươi vẫn có thể chơi bản demo sau đó nếu muốn.",
    [1598757789] = "Nước Cốt Dừa",
    [1599040963] = "Găng Tay Quân Vương U Ám",
    [1599101165] = "Cây Chàm",
    [1599447933] = "Áo Giáp Nhà Thám Hiểm",
    [1599547184] = "Hình Nhân Tập Luyện I",
    [1599621180] = "Đá 2m",
    [1599728289] = "Vùng Đất Tro Tàn",
    [1599831956] = "Đỉnh Cao Albaneve",
    [1600388327] = "Những dầm gỗ lộ ra tạo nên sự tương phản đẹp mắt với bề mặt thô ráp, tạo cảm giác ấm áp.",
    [1600533453] = "Giày Bóng Của Núi",
    [1600692814] = "Phục hồi tức thời một lượng HP vừa phải, và hồi HP liên tục trong 10 giây.",
    [1600763889] = "Đêm Đã Tàn!",
    [1601110851] = "Vật Phẩm Tiêu Hao",
    [1601346495] = "Việc đào mộ cũng có những lợi ích riêng. Dưới gốc cây gia đình tại <location>Lone Thistle</location>, một <b>báu vật gia truyền</b> bị nguyền rủa đã được tìm thấy. Một năng lượng kỳ lạ tỏa ra từ nó.",
    [1601811163] = "Ngươi đang bay!",
    [1601893192] = "Dao Găm Vukah Hiến Tế",
    [1602446467] = "Thợ Săn",
    [1602727398] = "Leo lên đỉnh núi cao nhất và nhìn qua rìa núi phủ tuyết. Nhìn vào khoảng không xoáy tròn, vào vực thẳm xoắn ốc. Ngay bên kia đường chân trời, được chiếu sáng bởi ánh sáng mặt trời mọc, là đất đai của chúng ta — và cánh cổng dẫn đến các vì sao của chúng ta, giờ đã bị chặn.\n\nHãy nghe đây: Chúng ta nhắm đến việc thăng thiên, vươn lên, trốn thoát — để rời bỏ những vùng đất mục nát bên dưới, bị vấy bẩn bởi rễ cây và những bông hoa của một hạt giống quen thuộc đang lan rộng.\nChúng ta khao khát trở về ánh sáng thiên thể và sự thuần khiết của dòng máu vũ trụ.\n\nBất cứ thứ gì — hoặc bất kỳ ai — hoang dã, ô uế, hoặc ngu ngốc đều phải ở lại, ngay cả những ngọn lửa non trẻ nhất của chúng ta. Cửa của chúng ta đóng lại với ngươi.\nĐừng cố mở chúng ra.",
    [1602788002] = "Mũ trùm đầu dành cho người hái thuốc. Chữa thương cho người khác thật khó khăn một cách đáng ngạc nhiên khi ngươi không thể nhìn thấy họ.",
    [1603151649] = "Ngươi đang được hồi sinh...",
    [1603191297] = "Ngươi có một lời mời!",
    [1603759721] = "Báo Thù",
    [1604251349] = "Một chiếc búa khổng lồ chỉ có thể được sử dụng bằng cả hai tay. Đầu búa được rèn từ một khối thép nguyên khối, đòi hỏi kỹ thuật chế tạo tiên tiến.",
    [1605323410] = "Khối Đá Thô",
    [1605479480] = "Cúp Danh Năng Quái Vật Mắt Một Sa Ngã Bằng Đồng",
    [1605575767] = "Túi Da",
    [1605931517] = "Cổ Nhân. Phải. Từ Ark Morgo, họ giáng xuống. Được gửi đến như những sứ giả từ các vị thần. Vesztah! Merphisz! Fyraszh! Arisztar! Dalszul! Để chọn ra những vị thần mới, phải. Kẻ mạnh nhất trong chúng ta!\n\nNhưng lũ ngu! Lũ ngu!\nChúng chọn con người! Đầu lâu yếu đuối, dễ vỡ! Bụng mềm nhũn, mềm và nhão! Những kẻ tạo lửa nhỏ bé. Hừ! Lửa là yếu đuối.\nChúng ta dập tắt tia lửa, chúng ta nuốt chửng ngọn lửa, chúng ta mang đến sự trỗi dậy bằng cơn bão máu tím!\n\nNhưng con người đã lừa dối chúng ta. Đánh bại chúng ta trong trận chiến — bằng máy móc và sự ma quỷ! Không công bằng!\n\nChúng ta đã tắm trong sự xấu hổ và bóng tối quá lâu! Ngọn lửa của con người giờ đã yếu! Không nên cháy gần Ark Morgo! Cơ thể chúng đang mục rữa. Xương mềm, thịt thối — Thời điểm đã đến. Drak trỗi dậy. Drak'Dal nắm lấy cơ hội trong cái chậu đáng thương. Ngai vàng đang chờ. Ark Morgo lại là của chúng ta!",
    [1606327052] = "Trượng Đồng Hoang",
    [1606680939] = "Kẻ Tai Ương",
    [1606895766] = "Ngươi đang bay lượn trên những đám mây.",
    [1606911592] = "Bỏ Qua Văn Bản",
    [1606999098] = "Một bản đồ được phục dựng, bao gồm 4 mảnh bản đồ cũ. Nó mô tả một hồ nước có đảo, một con sông, một tháp đá và các bộ phận của một bộ xương lớn. Toàn bộ chữ viết ở mặt sau giờ đọc là:\n\n<b>Hồi Ức của Mae:</b>\n<i>Ngày đầu tiên của mùa xuân không giống những ngày khác\nNhững đỉnh núi nằm im lìm, liếm vết thương của mùa đông\nKhi ánh mặt trời lặn ở phía tây xa xôi\nTrên những cánh đồng nơi nụ hoa đang ngủ say thức dậy thành những bông hoa </i>\n\n<b>Hồi Ức của Ony:</b>\n<i>Ta bay quá cao, có lẽ ta sẽ không bao giờ hạ cánh\nTa nhảy múa trên mặt trời, cả cơ thể bốc cháy\nCốc của ta luôn đầy, ta sẽ uống cho đến khi chết đuối\nTrong ánh sáng lỏng và sự mê đắm, cho đến khi ta cảm thấy choáng váng</i>\n\n<b>Hồi Ức của Orpheus:</b>\n<i>Từng sinh ra là một kẻ lang thang, ta tìm kiếm sự rực rỡ và hạnh phúc\nGiờ ta bị đóng băng trong thời gian, cơ thể ta bị xiềng xích\nĐã quen với biển bóng tối, sâu trong vực thẳm\nMắt ta đau nhói trong ánh sáng, vì vậy không có ánh sáng nào có thể còn lại</i>\n\n<b>Hồi Ức của Polaris:</b>\n<i>Ta là một ngôi sao sáng, trôi dạt cao trên bầu trời\nĐể tìm đường đi của mình, ngươi chỉ cần nhìn ta\nNhìn xuống thế giới, thật khó để phủ nhận\nKhông có ai bên cạnh khiến tinh thần ta cô đơn</i>",
    [1607141311] = "Tăng cường mũi tên Chữa thương",
    [1607161052] = "<b>Búa Xây Dựng</b> có thể được sử dụng để xây dựng một cửa hàng cho <npc>Thợ Rèn</npc>. Sau khi chọn Búa Xây Dựng, có thể chọn Bản Vẽ và Vật Liệu mong muốn.",
    [1607543700] = "Thật là một cú bắn! Con chim rơi xuống, vẫy vùng và kêu chíp chíp.\n\nMóng vuốt của nó quấn chặt lấy mảnh giấy này... một ghi chú! Phải dùng sức để mở chúng ra. Ngươi có tin được không?",
    [1607563180] = "Một phép thuật vĩnh cửu phân phối sự Chữa thương tuyệt vời nhảy đến những người bạn ở gần.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [1608297120] = "Bắn hoặc nhắm Cung của ngươi khi đang trên không sẽ làm chậm quá trình rơi của ngươi trong giây lát. Mỗi phát bắn sẽ nâng ngươi lên một chút, cho phép bay lâu hơn.\n\n<b>Chi phí:</b> 10 SP mỗi giây",
    [1608581660] = "Một ghi chú tiết lộ rằng vụ buôn bán vũ khí đã đổ bể khi người mua bỏ đi cùng với hàng hóa. Họ đã đi về hướng một thị trấn tên là <location>Glennwood's End</location>.\n\nHãy đến <location>Glennwood's End</location> và lấy lại hàng hóa bị đánh cắp từ đó!",
    [1609249189] = "Gửi <lorename>Jezmina</lorename> thân mến,\n\nMọi thứ thật hoàn hảo đêm qua. Ta vô cùng phấn khích khi biết rằng nàng đã thích món ăn của ta! Và vì nàng đã yêu cầu công thức, ta nghĩ ta sẽ để nó ở đây trước khi chăm sóc cho cái bụng đói của đoàn lữ... hãy thử đoán xem <i>nguyên liệu bí mật</i> là gì nhé.\n\n<b>CÂY KHOAI MÌ NƯỚNG CỦA NỮ HOÀNG</b>\n\n1 quả khoai mì, bổ đôi, thái lát, bỏ hạt. \nDầu\nMuối\nTiêu\nNước cốt chanh\nMật ong\nỚt thái hạt lựu\n\nLoại bỏ hạt và thái khoai mì thành lát dày 1 inch. Phủ đều tất cả các nguyên liệu theo khẩu vị (Đừng ngại! Càng nhiều càng ngon!). Nướng trên Ngọn lửa lớn cho đến khi mềm. Trong khi nướng, dùng chảo để rang hạt khoai mì cho đến khi chúng có màu vàng nâu. Dùng nóng và với tất cả tình yêu!",
    [1609548666] = "Trang Bị",
    [1609769881] = "Chà, ngươi thật tài năng! Ta không dám đến quá gần những móng vuốt đó! Ta nghĩ chúng ta cần một cái vỉ nướng để làm những chiếc bánh cua giòn tan thơm ngon. Ngươi giỏi về vũ khí và công cụ. Ta có thể chỉ cho ngươi cách làm vỉ nướng dễ dàng! Ta có một tầm nhìn về một chiếc vỉ nướng đẹp mắt, theo chủ đề cá. Ta sẽ cho ngươi thấy tầm nhìn của ta, và ngươi có thể biến nó thành hiện thực. Đồng ý chứ?",
    [1609946428] = "Áo Vest Xạ Thủ",
    [1610736406] = "Thông thường, <location>Willow Crush</location> rất yên tĩnh khi ta lẻn ra khỏi cửa sổ phòng ngủ. Thị trấn chìm trong giấc ngủ sâu khi ta trèo xuống những dây leo trên bức tường phía nam, cẩn thận tránh cửa sổ phòng của cha mẹ ta.\n\nLén lút đã trở thành bản năng thứ hai của ta. Hôm nay, điều đó đã hữu ích.\n\nGiữa những cành cây, ta bắt gặp thoáng thấy hai bóng người được chiếu sáng bởi ánh trăng lưỡi liềm nhạt. \nBóng người nhỏ hơn rút một vật ra khỏi áo ghi lê của họ, bọc trong vải để che giấu khỏi những ánh mắt tò mò. Khi bóng người cao hơn nhìn trộm dưới lớp vải, một ánh phản chiếu kim loại lướt qua khuôn mặt họ. Bóng người cao gật đầu và rút ra một chiếc túi nhỏ.\n\nCó điều gì đó không ổn. Bóng người nhỏ hơn ném chiếc túi xuống đất để lộ ra hàng chục đồng xu lấp lánh, kêu lách tách — nhưng giọng nói của họ đã bị dập tắt khi bóng người cao lớn nhấc họ lên bằng cổ.\n\nBóng người cao lớn rời đi về phía <location>Glennwood's End</location>, nhưng ta sẽ không đi theo. Để yên cho chó ngủ.",
    [1610912579] = "Vỏ Xà Cừ",
    [1611176773] = "Khối Đá Sương Độc Axit",
    [1612086741] = "Được tổ chức bởi",
    [1612543525] = "Tô Màu Vật Phẩm",
    [1613024965] = "Tìm Các Bộ Phận Xương Chu Tinh Tại Đỉnh Cao Albaneve",
    [1613178105] = "%k\ntại %k",
    [1613290480] = "Quần Pháp Sư",
    [1613581777] = "Tìm Thấy Sảnh Đường Hollow Revelwood",
    [1614989394] = "Những Vùng Đất Này",
    [1615028283] = "Argon,\n\nHãy cẩn thận với lô hàng mới này từ thung lũng. Thương gia nói rằng nó rất dễ bay hơi. Rõ ràng, <i>\"chất nổ sẽ nổ\" </i> nếu bị rung lắc hoặc ném lung tung. Ai mà biết được?\n\nDù sao, ta đã trả một cái giá khá đắt cho thứ này. TUYỆT ĐỐI không đùa với nó. Ta không đủ khả năng để sửa thêm một lỗ trên tường nữa!",
    [1615252637] = "Giày Kẻ Phá Phép",
    [1615403514] = "Ngươi đã vào ngọn hải đăng và tìm thấy một nửa bức treo tường. Hình ảnh của nó mô tả cấu tạo của các dung dịch giả kim thuật phức tạp... hoặc ít nhất ngươi nghĩ vậy. \nNếu không có nửa còn lại, ngươi không thể giải mã hoàn toàn ý nghĩa, nhưng kết hợp cả hai mảnh sẽ tiết lộ nhiều <b>công thức chế tạo mới</b>, bao gồm cả vải màu tím để chế tạo <b>áo giáp pháp sư</b> tốt hơn!\n\nNgọn hải đăng dường như đã bị tấn công bởi những con kền kền. Có lẽ chúng đã mang một phần bức treo tường về tổ của chúng.\n\n<b>Hãy đến tổ kền kền để tìm nửa còn lại của bản thiết kế!</b>",
    [1615960826] = "Màu lông mày",
    [1616775787] = "Di chuyển sang trái",
    [1617700124] = "Một <keyitem>Ấm Đun Nước</keyitem> đã được phát hiện, nằm giữa những tàn tích trong một Thánh Địa Ngọn lửa. Một hình khắc ở đáy đọc \"Giữ an toàn, <lorename>Raúl</lorename>! — Emily Fray\". \n\n<keyitem>Ấm Đun Nước</keyitem> phải được sử dụng để chế tạo <craftingstation>Bàn Nấu Ăn</craftingstation>. Điều này sẽ cho phép các công thức nấu ăn tốt hơn.",
    [1618482614] = "Độ Trễ Hồi Phục SP",
    [1618526395] = "Ngược dòng",
    [1618587623] = "Cảm Ơn Vì Đã Phục Vụ",
    [1618678419] = "Chúng ta đã thông báo về sự hiện diện của mình tại Đỉnh Cao Albaneve, và chiếm giữ Giếng Tinh Hoa sâu nhất của họ... nhưng có điều gì đó tăm tối vẫn đang âm ỉ bên trong Đỉnh Núi Gào Thét. Một sinh vật bị tha hóa, khao khát hủy diệt và bị hủy diệt. Chúng ta phải lôi nó ra bằng cách thắp sáng những ngọn lửa báo hiệu xung quanh ngọn núi, do đó đánh thức cơn thịnh nộ của nó. Ta sẽ chỉ cho ngươi đường đi.",
    [1619380793] = "Tấn Công",
    [1619507245] = "Thông Tin Về Quái Vật Một Mắt",
    [1620778313] = "Nấm",
    [1621406580] = "Ta có thể biết chúng đang tiến đến từ làn khói trên đường chân trời. Nhiều người đã bỏ chạy, nhưng ta ở lại.\n\nChúng đang gầm gừ bên ngoài cửa. Ta sẽ giữ ngôi nhà này, như tổ tiên ta đã từng làm. <i>Ta đã giấu kho báu của chúng ta dưới cầu thang đá. Nó sẽ an toàn và âm thầm, cách xa tầm tay của chúng.</i>\n\nKhi chúng đến, ta sẽ sẵn sàng.",
    [1621428487] = "Sở hữu chiếc cúp này cho mọi người thấy rằng ngươi không nằm trong thực đơn của Chu Tinh — mà là ngược lại!\n\nThu thập nhiều Đầu Chu Tinh để chế tạo Cúp Vàng.",
    [1621547660] = "Kẻ Săn Đầu Lâu",
    [1621604197] = "Chi tiết trạng thái...",
    [1621770593] = "Tuyệt vời, ngươi đã làm được! <craftingstation>Trạm Da Thuộc</craftingstation> này sẽ là chìa khóa cho sự sinh tồn của chúng ta! Nào, <b>đặt nó xuống</b> để chúng ta có thể bắt tay vào làm việc!",
    [1621883880] = "Thùng Da",
    [1622023175] = "Nghiêng về phía trước",
    [1622100254] = "Đến Đền Thờ Drak",
    [1622538701] = "Những con dao gai này thường được các binh sĩ đeo quanh thắt lưng trong các cuộc diễu hành để thể hiện sức mạnh. Đôi khi, trẻ em được tặng một phiên bản đơn giản hơn làm vũ khí đầu tiên của chúng.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của ngươi. Ngươi có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1622641794] = "Đa Sát Thương",
    [1623179797] = "Đừng để tóc ngươi mọc quá dài.",
    [1623307965] = "Kho Báu Ẩn",
    [1623453786] = "Đền Thờ Ẩn",
    [1623558221] = "Tăng ST Phép.",
    [1623659593] = "<i>Chúng thực sự hơn cả truyền thuyết.</i>\nHalls Hollow tồn tại, và bên trong chúng vang vọng những giai điệu của một thời đại đã qua... những ký ức về một thời kỳ bầu trời quang đãng, và Sương độc vẫn đang ngủ yên dưới đáy.\n\nNhững Halls có nguồn gốc không rõ này đã tồn tại hàng thiên niên kỷ, nhưng kiến trúc của chúng khác với Người Cổ Đại. Thật kỳ lạ.\n\nNgười ta nói rằng những hầm mộ này từng là nơi trục xuất những kẻ thấp kém nhất trong xã hội. Ta tự hỏi liệu những cư dân bị nguyền rủa đó có còn lang thang trên cõi trần này không...",
    [1623746200] = "(không có)",
    [1623885231] = "Một tác phẩm nghệ thuật tuyệt vời, đẹp và mạnh mẽ.",
    [1623944586] = "Ôi các vị thần, ta có thể di chuyển tự do! Các người đã cởi trói cho ta! Tạ ơn Chúa vì những Scavenger đó không còn ở đây... Ta nhớ thứ chất lỏng hôi thối rỉ xuống từ trên cao, nhỏ giọt vào xà lim của ta... Hãy giữ chúng tránh xa, và ta sẽ làm bất cứ điều gì!",
    [1624207377] = "Nhẫn Sinh Lực Tuyệt Hảo",
    [1624433254] = "Tiếng đập dẫn đường! Một nhịp đập mạnh mẽ, tuyệt đẹp! Nó rung chuyển xương cốt ta, nhưng lại kích thích vị giác của ta! \n\nNhững người đồng hành nhút nhát của ta chẳng có chút gu thưởng thức nào cả - hoặc ít nhất là có vẻ như vậy - vì họ đã bỏ đi khi ta đang ngủ. Chúng ta vừa đột nhập vào đường hầm, nơi sâu thẳm cuối đường hầm, tiếng vo ve tuyệt vời dường như đang hát vang.\n\nKhông sao cả! Càng nhiều cho Bertram, ta nói! Tiến lên!\n\nBERTRAM",
    [1624914245] = "Những dòng sông lấp lánh, những con tàu đắm... Ta tự hỏi kho báu nào ẩn giấu dưới làn nước? Có lẽ chúng ta có thể tìm vàng dưới vực sâu! Nhưng chúng ta cần công cụ phù hợp để khai thác nó... Nếu ta không nhầm, hầu hết các chuyến tàu chở vàng mà chúng ta nhận được ở Thủ Đô đều có cùng một biểu tượng. Một viên ngọc trai lớn, với dòng chữ \"Orville\" bên dưới. Có lẽ điều đó hữu ích?",
    [1625449642] = "Cúp Danh Năng Đấu Sĩ Vukah",
    [1625468616] = "Mất kết nối với máy chủ.",
    [1625841543] = "Tìm Người Phụ Nữ Dũng Cảm",
    [1626508755] = "Yêu cầu nước:",
    [1627262523] = "Cho phép bạn điều khiển một dòng nước trong chiến đấu.\n\n\n<b>Phép Thuật Điều Khiển:</b> Giữ nút để điều khiển <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép với một <b>gậy phép.</b>",
    [1627287992] = "Người Drak trang trí các khu định cư của họ bằng những chiếc cúp như vậy. Thật ấn tượng khi họ thậm chí còn rửa sạch máu - họ chắc chắn sẽ tái sử dụng nó cho các mục đích khác...",
    [1627333851] = "Tìm thấy trong Hang Ổ Revelwood Sương độc",
    [1627586968] = "Mũ Nhà Thám Hiểm",
    [1628023108] = "<b>Ngài Flummi</b>\nFell chết khi đang xây dựng\n\n<b>Vonza</b>\nThích kiến trúc\n\n<b>Solstrem</b>\nThích nhà tranh, không thích haggis\n\n<b>Cleo con Pin, 16 tuổi</b>\nCô bé tốt nhất trong thị trấn\n\n<b>Chiselchip</b>\nNgười xây dựng ấm cúng\n\n<b>Areelanir von den Lunituns</b>\nPhá bỏ, xây dựng lại!\n\n<b>Bibes Mc Mặn</b>\n\n<b>Lilibat Phù Thủy</b>\n\n<b>CistaDusa</b>\nKhông phải tất cả các linh hồn đều bị lãng quên\n\n<b>Gấu Xanh Già</b>\nMột người bạn đồng hành trung thành và được yêu mến",
    [1628056980] = "Bức Xạ Chướng Khí",
    [1628267187] = "Khối Ngói Lợp Mái",
    [1628393113] = "Nhân vật",
    [1629059025] = "Kiếm dài Lưỡi Đồng",
    [1629594761] = "Khi bạn nhận sát thương độc, bạn sẽ hồi phục lượng sát thương đó.",
    [1629979660] = "Phóng to",
    [1631891925] = "Những mảnh ghép che hai bên của chiếc quần này đã được rèn cẩn thận để phòng thủ chống lại các đòn tấn công từ hai bên.",
    [1631972527] = "Một phép màu! Ta lại được sống. Ta là Balthazar, một nhà giả kim. Ta <b>chế tạo</b> các loại thuốc và các vật phẩm khác.",
    [1632157105] = "Thuốc Giải Độc",
    [1632158796] = "<location>Midhollow</location> Bị Xé Toạc",
    [1632288417] = "Đôi ủng nặng trịch. Chúng sẽ để lại những dấu chân đáng kể trên mặt đất khi bạn bảo vệ những người gặp khó khăn.",
    [1632319992] = "Kẻ Kích Hoạt Tuyết Lở",
    [1632564474] = "Trực tuyến",
    [1633110739] = "Hãy nhớ ba quy tắc của chúng ta về an toàn và năng suất tại nơi làm việc:\n\n<b>1. </b>Tuân thủ lịch trình!\n<b>2.</b> Nâng bằng chân, không phải lưng! Hỗ trợ lẫn nhau với hàng hóa nặng!\n<b>3.</b> Trong trường hợp thang máy trục trặc, báo cáo cho người giám sát ca làm việc!\n\n(Phần chữ nhỏ ghi: <i>Nếu bạn đến sớm, bạn đang đúng giờ. Nếu bạn đúng giờ, bạn đang muộn. Nếu bạn muộn, bạn bị sa thải. Không có lương làm thêm giờ. Giỏ trái cây được bổ sung hai tuần một lần.</i>)",
    [1633143123] = "Anton Godwin đã kể cho bạn về công việc cũ của ông ấy với tư cách là một chú hề ném dao. Ông ấy ước gì mình vẫn còn chiếc mũ chú hề đó.\n\nĐi đến tiền đồn được đánh dấu trên bản đồ của bạn và tìm kiếm chiếc mũ chú hề!",
    [1633416585] = "Trà Hoa Gentian Lấp Lánh",
    [1633796550] = "Áo Choàng Học Giả Thiên Giới",
    [1634129996] = "Tìm Kiếm Vùng Đất Cổ Đại",
    [1634239323] = "Tuyệt vọng, căm ghét, cô đơn... nó bám víu vào bất cứ thứ gì để lấp đầy khoảng trống và không để lại gì ngoài tro bụi.",
    [1634760648] = "Phần trang trí kim loại trên chiếc mũ trùm đầu này thoạt nhìn giống mỏ của chim ưng.",
    [1634794720] = "Độ Trễ Hồi Phục SP",
    [1635067720] = "Sát thương Kiếm dài tăng thêm <b>10%</b>.",
    [1635228704] = "Drak",
    [1635865517] = "Bình Năng Lượng Siêu Cấp",
    [1636718036] = "Lưng Bạc",
    [1636882422] = "Chế tạo một <craftingstation>Lò Nung</craftingstation>",
    [1636956726] = "Chào mừng trở về!",
    [1637197239] = "Tủ Gỗ Chạm Khắc",
    [1638191858] = "Bảo vệ bổ sung chống lại sát thương vật lý cùn, ngoài khả năng kháng vật lý chung.",
    [1638599739] = "Sát thương vật lý nhận vào được giảm.",
    [1638661353] = "Dọn sạch rễ cây Sương độc khỏi các đỉnh Albaneve.",
    [1638755194] = "Bể II",
    [1638764723] = "Không ai thực sự biết nó là gì. Họ chỉ gọi nó là \"Gia Vị\". Tuy nhiên, nó làm cho thức ăn ngon hơn nhiều, vì vậy nó rất được săn lùng!",
    [1639825793] = "Các vụ nhìn thấy <lorename>Kẻ Lang Thang Bí Ẩn</lorename>",
    [1640246377] = "Lời Nguyền Phản Bội Ta",
    [1640714013] = "Các tinh thể Aquamarine được nghiền mịn lấp lánh tuyệt đẹp.",
    [1640832255] = "Bay",
    [1640845348] = "Một cơn <b>bão cát chói mắt đã ập vào trại của tôi</b> ngày hôm qua và chôn vùi đồ tiếp tế của tôi!! Những cơn gió khủng khiếp... chưa từng có! Tôi vẫn còn ho sặc sụa cát, và tôi không chắc mình đã hạ cánh ở đâu... mọi thứ đã bị cuốn trôi! Tất cả đã mất, nhưng <i>tôi không thể quay lại ngay bây giờ! Tôi đã bán hết mọi thứ mình có để tìm Ốc Đảo đó!</i>\n\nCái gì thế này...? Dường như có một <i>sự lấp lánh</i> ở phía xa. Tôi có thể quay lại, nhưng có lẽ tôi đã gần mục tiêu hơn tôi nghĩ! Gió có mang tôi đến gần đây không...? Một phước lành trong cái rủi?\n\nTôi không sợ hãi! Tôi sẽ điều tra xem điều gì sẽ là sự cứu rỗi hay sự hủy diệt của tôi!",
    [1640932545] = "SP",
    [1640935018] = "Sẵn sàng cho những vùng đất mới",
    [1641307815] = "Bạn phát ra một hào quang Chữa thương, hồi phục cho bạn và tất cả đồng minh bị thương trong phạm vi <b>15</b> mét.\n\nKhả năng hồi HP tỷ lệ thuận với chỉ số Trí Tuệ của bạn và hồi phục <b>1</b> HP cho mỗi <b>2</b> điểm Trí Tuệ.",
    [1641435171] = "Những đôi ủng này lặp lại kỹ thuật dệt tương tự như Găng Tay Bóng Đêm Núi. Chúng che đầu gối và cung cấp sự bảo vệ lý tưởng khi đi qua các hang động tối tăm, băng giá hoặc các pháo đài bị lãng quên.",
    [1641652837] = "Lối tắt",
    [1642189485] = "Nạp lại các chồng vật phẩm trong hành trang của bạn.",
    [1642285813] = "Tia Sáng Bùng Nổ Vĩnh Cửu",
    [1642311137] = "Dấu hiệu",
    [1642702258] = "Sự Thăng Hoa của <lorename>Jezmina</lorename>",
    [1643166853] = "Đến được Lối đi Bồn địa Veilwater",
    [1643201554] = "Trống Tay Dành Cho Nhạc Công",
    [1643214981] = "Vũ Khí Tổ Tiên",
    [1643215313] = "Trinh sát Trại Scavenger",
    [1643317063] = "Bạn đã thu thập được Vảy Drak trong khi phiêu lưu. Chúng sẽ là một kỷ vật tốt và bằng chứng chiến thắng.\n\n<b>Nói chuyện với người đánh cá để tiếp tục.</b>",
    [1643332309] = "Viên đạn ma thuật đốt cháy một quả cầu lửa, phát nổ khi va chạm và gây sát thương trong một khu vực nhỏ.\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép với một <b>gậy phép.</b>",
    [1643332952] = "Đồ Ăn Đặc Biệt",
    [1643371419] = "Nền Gỗ",
    [1644095430] = "Bạn đã không làm tôi thất vọng! Cái <craftingstation>Lò Rèn</craftingstation> này sẽ xứng đáng với công sức của bạn, tôi xin đảm bảo.",
    [1644310671] = "Đồng Cỏ Thấp",
    [1644323593] = "Làm Bộ Đệm Ấm",
    [1644348435] = "Hỡi Kẻ Mang Lửa, có những rào cản vượt quá khả năng hiểu biết của chúng ta che chắn các căn phòng bên trong khỏi ánh sáng. Những ngôi đền tối đen như mực, được mơ ra bởi các Cổ Nhân - bao phủ trong bí ẩn. Sự bí mật của chúng che khuất tầm nhìn của ta, nhưng nó sẽ không hạn chế tầm nhìn của ngươi. Hãy lao vào và vén bức màn bóng tối!",
    [1644400557] = "Những lưỡi kiếm này đã bị ăn mòn do ngâm trong độc quá lâu.\n\n<b>Tinh Tế:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1644903590] = "Trang Cốt Truyện Mới: %k",
    [1645041368] = "Thợ <npc>Săn</npc> cần một <craftingstation>Khung Cửi</craftingstation> để chế tạo bộ đệm cho giáp tốt hơn. Cô ấy gợi ý tìm một <b>nhà tranh của thợ dệt ở <location>Lapis phía Đông</location></b>. Khu vực chung được đánh dấu trên bản đồ. Ngôi nhà tranh nên dễ nhận biết vì nó <b>được trang trí bằng cờ hiệu.</b>",
    [1645342259] = "Chìa Khóa Xương Hoang Mạc Lửa",
    [1645480550] = "Người Nông Dân đã tìm thấy nguồn cảm hứng mới cho các món ăn hải sản. Bà ấy đã chỉ cho bạn cách chế tạo Lò Nướng Hải Sản.\n\n<b>Chế tạo và đặt một Lò Nướng Hải Sản để bà ấy có thể bắt đầu chuẩn bị các món ăn ngon hơn.</b>",
    [1645609871] = "Máy Móc Nặng",
    [1645635320] = "Bí Mật Của Drak'Dal",
    [1645689311] = "Sự Nhanh Nhẹn Của Mèo",
    [1645768686] = "Đạt cấp 30.",
    [1645997181] = "Rất hân hạnh!",
    [1646058090] = "Đèn Đứng Xanh Dương I",
    [1646272121] = "Cứu lấy linh hồn của bạn!",
    [1646340722] = "Để thuần hóa một con vật, hãy tiếp cận nó một cách cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Khi đã thuần hóa, con vật có thể được nhặt lên.",
    [1646463287] = "Tiếng Nga",
    [1646761175] = "Ma Thuật Máu",
    [1647011941] = "Tìm Chiếc Rương Dưới Cầu Thang",
    [1647036025] = "Nắp Quan Tài Đơn Giản",
    [1647084269] = "Cụm Ectoplasm",
    [1647988020] = "Sự sống vẫn nở rộ khắp nơi.\n\nBảng màu này có thể được tạo bằng vật liệu từ Cao Nguyên Du Mục.",
    [1648862138] = "Hiệu Ứng Tạm Thời",
    [1649010111] = "Trường Cung Tiếng Sói Gầm",
    [1649289207] = "Bạn đã tìm thấy một bài hát bị phân tán ở các đỉnh Albaneve! Ghé thăm địa điểm tiếp theo được đánh dấu trên bản đồ của bạn để khám phá thêm các bản nhạc!",
    [1649766916] = "Sử dụng tên nhân vật của bạn trong thế giới. Khi tắt, tên tài khoản của bạn sẽ được hiển thị thay thế.",
    [1650608149] = "Xin Thông Báo Cho Nữ Hoàng",
    [1650621832] = "Khung Cửa Sổ Gỗ",
    [1650743887] = "Bản Demo Sương độc bao phủ",
    [1651476748] = "Một chai Nước sảng khoái giúp tăng thêm SP. Hãy giữ đủ nước.",
    [1651830522] = "Lớp da này mượt mà và chống nước. Nó thường được thu thập từ các loài lưỡng cư ưa thích môi trường ẩm ướt hoặc ngập nước.",
    [1652178933] = "Tươi, lành mạnh, vui để ăn, và tốt cho tâm hồn. Bạn còn mong gì hơn từ một bữa ăn?",
    [1652251567] = "Tàn bạo",
    [1652698237] = "Thức ăn để thu hút và thuần hóa Mèo.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó thuần phục. Một khi đã thuần phục, con vật có thể được nhặt lên.",
    [1653050676] = "Tên Thế Giới",
    [1653202257] = "Gỗ từ cây bị Sương độc xâm nhập. Cấu trúc và đặc tính của nó đã thay đổi mãi mãi.",
    [1655463711] = "Gợi ý Demo",
    [1655588143] = "Bạn đã tắt thành công dòng chảy của sông Riverreach. Điều này cho phép bạn lấy cối xay.\n\n<b>Đi vào trong để lấy bộ phận cối xay.</b> Hãy nhớ rằng tất cả dòng chảy của nước cần phải được dừng lại để giữ cho máy tắt.",
    [1655867057] = "Tẩm MP vào <b>Vũ khí Nổ của bạn.</b> Chúng giờ đây làm choáng kẻ địch trong tối đa <b>1</b> giây.\n\n<b>Chi phí:</b> 5 MP cho mỗi kẻ địch bị choáng.",
    [1657088425] = "Đang chờ xử lý...",
    [1658105872] = " Đá quý có sẵn",
    [1658370694] = "Không có vật liệu nào có sẵn.",
    [1658522719] = "Người khởi xướng \"Nghi Lễ Đoàn Tụ\", Phu nhân Leclair, đã thay đổi câu thần chú để trượt vào cõi chết và tìm kiếm sự sống vĩnh cửu. Trong ghi chú của bà, bà đề cập đến một tầng hầm. Tìm lối vào tầng hầm của bà và mang Phu nhân Leclair về!",
    [1659215267] = "Không có mồi nhử",
    [1659332237] = "Bạn đã tìm thấy ngôi đền Drak mà Thợ săn đã đề cập. Tìm cách vào trong và chứng tỏ tài năng của bạn.\n\nMột phần của ngôi đền dường như bị ngập nước. <b>Nên tăng lượng Oxygen tối đa của bạn trước khi vào.</b>\n\nMột khi bạn đã vào trong ngôi đền, bạn phải khám phá số phận của những người đã lặn ở đây trước bạn và <b>thu hồi trang bị của họ.</b>",
    [1659692886] = "Tên Lửa Xanh Lá Cây",
    [1660103147] = "Nghỉ ngơi",
    [1661055469] = "Địa chấn",
    [1661244498] = "Hồi phục SP",
    [1661316689] = "Sự khác biệt giữa các sinh vật này không nên được coi là sự biến đổi tự nhiên, mà là dấu ấn của một nguồn gen chung, bị chia cắt thành các nhánh mới và cô lập được mang bởi các bộ lạc. \nSự cô lập đó, cùng với xung đột liên tục giữa các chủng tộc và giả định tỷ lệ cận huyết tăng lên, có thể giải thích sự suy thoái nhận thức và ngôn ngữ được nhận thấy của Drak.\n\n<b>Suy thoái văn hóa và ngôn ngữ:</b> \n<i>Các văn bản Drak thu hồi được từ các lớp trầm tích gần đây hơn — thường được nạo vét từ vùng nước ven biển hoặc xác tàu — có xu hướng thể hiện cấu trúc đơn giản hơn, từ vựng giảm sút và cú pháp suy thoái khi so sánh với các mẫu sớm hơn được khai quật trong các ngôi đền địa phương. Điều này cho thấy sự mất mát về sự phức tạp ngôn ngữ theo thời gian.\n\nDường như quỹ đạo tiến hóa xã hội của họ có thể đã bị đình trệ — hoặc thậm chí thoái lui. Ngoài ra, nếu tôi hiểu đúng, có thể giả định rằng họ giữ mối hận thù hoặc một sự ác cảm tự nhiên đối với các tiến bộ công nghệ và kỹ thuật. Họ coi hầu hết các phát minh của con người hiện đại là sự thừa nhận sự yếu đuối hơn là giải pháp. Cần nghiên cứu thêm.</i>",
    [1661501279] = "Tạm biệt!",
    [1662115245] = "Bạn đã đến Mộ Hollow Ẩn được người Thợ hớt tóc đề cập.\n\n<b>Xuống</b> sâu vào hầm mộ để tìm <b>cảm hứng màu sắc!</b>",
    [1662290067] = "Cổ nhân và Ngọn lửa",
    [1662597084] = "Đọc",
    [1663258027] = "Phi Tiêu Xiếc",
    [1663462933] = "Bỏ qua tất cả các hình phạt di chuyển từ giáp.",
    [1663587951] = "Nước đã rút và tàu của chúng ta không còn đáng giá từng con tán giữ chúng lại. Tôi nhớ những ngày tôi có thể câu cá hàng giờ với cha. Chúng ta đã gắn kết như thế nào, chúng ta đã cười như thế nào. Thế giới đã phong phú và giữ cho chúng ta sống. Bây giờ chúng ta chắc chắn sẽ xé xác nhau. \n\nKhi nào thì vùng đất hoang này sẽ ngừng sự tàn khốc của nó đối với chúng ta? ",
    [1664049496] = "Giọng nói",
    [1664292269] = "Bạn không có quyền nâng cấp các Bàn thờ.",
    [1664381255] = "Mồi Thức Ăn Thỏ Nhảy",
    [1664427119] = "Một Quả cầu Lửa Bẫy có thể được sử dụng làm đạn dược phép thuật.\n\n<b>Phép thuật:</b> Bị tiêu hao sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng một <b>cây Gậy phép.</b>",
    [1665108543] = "Một Giao dịch Tốt, Bạn của tôi!",
    [1665256949] = "Kháng cự chỉ tỷ lệ phần trăm mà loại sát thương nhận được được giảm thiểu.",
    [1665585413] = "Rương Phép Thuật Vừa",
    [1666058682] = "Với đôi giày này, hãy giữ vững tư thế và hồi phục trước khi tung ra đòn tấn công tiếp theo.\n\nBộ giáp này có thể được tìm thấy trong các hầm mộ của Thung lũng Veilwater.",
    [1666484779] = "Tìm kiếm manh mối để tìm một Linh hồn dẫn đường",
    [1666603052] = "Kẻ săn mồi Fell",
    [1666967622] = "Bật",
    [1667170909] = "Bằng cách leo lên Tháp Cổ đại, bạn đã mở khóa khả năng di chuyển nhanh đến đó.\n\nSử dụng Di chuyển Nhanh và nói chuyện với Ngọn lửa trên đỉnh Tháp Cổ đại ở Vùng đất Mùa xuân sau đó để tiếp tục.\n\nBạn có thể di chuyển nhanh đến bất kỳ Tháp Cổ đại nào bạn đã leo và các Bàn thờ Ngọn lửa của riêng bạn.",
    [1667177320] = "Triệu hồi Nghệ sĩ",
    [1667308748] = "Bạn không có Nhiệm vụ nào bị bỏ lỡ. Chơi Nhiệm vụ của Người mang Lửa hoặc Embervale để tiếp tục!",
    [1667663373] = "Mái nhà Rộng",
    [1667930560] = "Tìm Mảnh Vải Thảm Tường Thứ Hai",
    [1668245227] = "Kền kền Draconian",
    [1668603214] = "Ánh sáng đầy màu sắc",
    [1668962037] = "Chậu cây vuông",
    [1669242375] = "Hầm Mỏ Muối",
    [1670045472] = "Ngòi Độc",
    [1670435875] = "Cấp độ Đồng hành Đầu lâu",
    [1671018518] = "Khối đá này thường được sử dụng ở Thung lũng Veilwater.",
    [1671649007] = "Sách Cũ",
    [1671649732] = "Cuốn Sách Của Sự Đau Đớn",
    [1671736725] = "Đạn dược",
    [1672126860] = "Cục than",
    [1672370236] = "Thịt Nạc Sống",
    [1672402039] = "Góc Mái Bên Ngoài",
    [1672868642] = "Thị trấn bỏ hoang",
    [1673921918] = "Tẩm nhựa đường",
    [1674841614] = "Tìm cách vào Tháp Cổ đại",
    [1675240948] = "Rào Cản Nước Bằng Tường",
    [1675659343] = "Khi đỡ đòn tấn công của kẻ địch, bạn sẽ lấp đầy thanh choáng của kẻ địch. Lượng này phụ thuộc vào giá trị đỡ đòn của khiên hoặc vũ khí 2H của bạn.",
    [1677349201] = "Cửa Đồng Đỏ",
    [1677859860] = "Sau khi làm khô Lông động vật trên Giá phơi, nó sẽ trở nên chắc chắn và bền hơn trong một thời gian dài hơn.",
    [1677948094] = "Di chuyển (giữ để điều chỉnh)",
    [1678252073] = "-1",
    [1678280781] = "Công Cụ Phủ Lớp Tăng Trưởng",
    [1678633045] = "Nghi Lễ Đoàn Tụ — bởi Lady Leclair của <location>Glennwood's End</location>",
    [1678939589] = "Sống Lưng Gai",
    [1679052884] = "Trận chiến càng lớn, câu chuyện càng vĩ đại!",
    [1679113421] = "Hoa hồng Alpine",
    [1679270452] = "Nếu bạn ngã, bạn sẽ trỗi dậy tại Điểm hồi sinh cuối cùng của mình.",
    [1680032608] = "Một thanh đại kiếm gần như quá lớn để có thể vung thoải mái. Chủ nhân ban đầu chắc hẳn phải là một người khổng lồ.",
    [1681285007] = "Giá Đỡ Gỗ Đơn Giản",
    [1681451197] = "Biển chỉ hướng mà bạn có thể viết lên.",
    [1681603243] = "Cao nguyên Du mục",
    [1681713437] = "Cuốc Chắp Vá",
    [1681782081] = "Bạn đã bị ngắt kết nối khỏi máy chủ.",
    [1682058678] = "Khả năng hiển thị phiên",
    [1682087822] = "Một người sống sót khác có thể được phát hiện! Một <npc>Nông dân</npc> sẽ hữu ích cho việc sản xuất lương thực khi được đặt trong căn cứ.",
    [1682420754] = "Vượt xa",
    [1682518975] = "Đồng cỏ tươi tốt",
    [1682899096] = "Một loại nước dùng sền sệt làm từ tinh thể ectoplasm nghiền nát. Nó \"an toàn để tiêu thụ\".",
    [1683307675] = "Ngọn lửa đã nói về \"Cột đá Cổ đại\" tiết lộ thông tin về thế giới. Các Cột đá hiển thị những sự thật ẩn giấu, và một số được kết nối với <b>Ngọn lửa.</b>\n\nVị trí của một Cột đá như vậy được đánh dấu trên bản đồ. Hãy tìm Cột đá và khám phá những bí mật mà nó nắm giữ. Những bí mật của Cột đá sẽ chỉ được tiết lộ cho những ai tìm kiếm chúng.",
    [1683480277] = "Chi phí điều hòa thêm.",
    [1683786285] = "Hãy nhẹ nhàng trên đôi chân của bạn!",
    [1683802374] = "Nhấn đúp vào nút đỡ đòn để tạo ra một lá chắn toàn diện, có thể hấp thụ 1 đòn đánh. Người chơi niệm phép không thể di chuyển hoặc thực hiện bất kỳ hành động nào khác, nếu không lá chắn sẽ bị tan rã.\nChi phí: 50 MP\nThời gian hồi chiêu: 30 giây",
    [1684917630] = "Chế tạo tại Máy ép Ectoplasm",
    [1686444015] = "Gỗ Chướng Khí",
    [1686580104] = "Quy mô tốc độ làm mới các khu vực nếu không có người chơi ở gần.",
    [1686761175] = "Bạn tìm thấy trại của tôi gần <location>Morwenna</location>? Thật hạnh phúc, phải không...? Chúng tôi đã cố gắng làm cho những vùng đất đó có thể sinh sống được. Hồ nước trong xanh và một khung cảnh tuyệt vời... Nhưng khi chúng tôi đến định cư, wildlife đã phản kháng - dữ dội. Cuối cùng, chúng tôi đã từ bỏ nỗ lực của mình. Thế giới đã bắt đầu sụp đổ... và tôi quyết định bước vào Hầm Cinder để xây dựng tương lai, không chỉ sửa chữa hiện tại.",
    [1687283067] = "trống",
    [1688052499] = "Bản dựng Beta kín",
    [1688359720] = "Khối Gỗ Chướng Khí",
    [1688477201] = "Bạn đang chờ đợi gì? Hãy chế tạo <b>Móc leo</b> nếu bạn muốn khám phá thêm Embervale. ",
    [1688491324] = "Ma-nơ-canh \"Để Tôi Phục Vụ Bạn\"",
    [1688529671] = "Bảo vệ tăng cường chống lại sát thương vật lý xuyên thấu, ngoài kháng vật lý chung.",
    [1688698722] = "Ghế Tre",
    [1689069329] = "Kẻ Không Kích",
    [1689160425] = "Hai người yêu này đã gặp một kết cục bi thảm – cổ họng anh ta bị cắt và miệng cô ta sủi bọt vì độc dược. ",
    [1689201202] = "Người ngắm sao trên đỉnh Albaneve",
    [1689770606] = "Bạn sẽ khiến mọi người run sợ khi bạn tiếp cận bằng đôi giày ma quái này!",
    [1689853202] = "Nhà máy bia bí mật",
    [1690244921] = "<b>Thời gian trong Sương độc</b> được tăng thêm <b>5</b> phút, cho phép bạn khám phá lâu hơn.\n\n<b>Thời gian trong Sương độc</b>\nNếu thời gian này hết, Sương độc sẽ nuốt chửng bạn.",
    [1690470712] = "Chế tạo Chìa khóa Sảnh Hollow Gỗ Revel",
    [1690649094] = "Không quan trọng đích đến, quan trọng là hành trình.",
    [1691135771] = "Một công cụ chắc chắn có thể giúp vượt qua nhiều vực thẳm trên đường đi.",
    [1691178352] = "Đoạn Dốc Cao 2m",
    [1691560519] = "Tìm Mèo Lạc Ở <location>Bãi Biển Sapphire</location>",
    [1691990190] = "Được thiết kế để lén lút, chiếc quần trung lập này giúp việc lẻn qua bụi rậm trở nên dễ dàng.\n\nBộ giáp này có thể được tìm thấy trong các lăng mộ của Thung Lũng Nước Veil.",
    [1692212518] = "Ngọc Độc Phản Bội",
    [1692476272] = "Tiện nghi - Ngai vàng",
    [1692631118] = "Đèn Đom Đóm",
    [1693288000] = "Nó đang rỉ ra, to lớn một cách bất thường, và vẫn đập mỗi khi bạn dám nhìn đi chỗ khác. Tinh chất mạnh mẽ của trái tim này là một nguyên liệu quan trọng trong việc chế tạo áo giáp kiên cố.",
    [1693518459] = "Tôi vẫn nhớ những năm tháng ngây thơ của mình, dại dột đi xa hơn những người khác. Chiều sâu khơi dậy sự tò mò của tôi, đầy kỳ diệu và kinh ngạc. Tôi vươn tới, khao khát kiến thức, được che chở trong hơi ấm của Ngọn Lửa. Tôi còn trẻ và không sợ sai lầm. Trong vực thẳm, tôi cảm nhận được sự vĩnh cửu.\n\nTôi không còn cảm nhận được nó nữa. Cát trong đồng hồ cát của tôi đang trôi đi. Khi tôi nghe Ngọn Lửa gọi tên người lớn tuổi nhất — tên tôi — tôi tràn đầy hối tiếc. Lõi hành tinh của chúng ta đã thay đổi... hiệu ứng lan tỏa từ những khám phá của tôi đã xé nát thung lũng và người trẻ nhất của chúng ta. Sự <i>thất bại</i> lẽ ra phải làm tôi sợ hãi, không phải sự thay đổi. Vực thẳm là tất cả những gì còn lại, và nó có nghĩa là sự lãng quên.\nTôi đã khắc tên mình vào đá — ghi lại tất cả những thất bại của mình trên các Đài tưởng niệm, gánh nặng để tồn tại lâu hơn tôi. Sợ bị lãng quên, tôi đã ký tên mình lên cái cuối cùng... thật là <i>con người</i> làm sao. Tò mò, cảm giác cuối cùng này. Thật trống Hollow. Thật lạnh lẽo.\n\n— Manathor",
    [1693806198] = "Tổ Ong",
    [1693913893] = "Râu",
    [1694072222] = "Uống Thuốc Độc",
    [1694199864] = "Tiện nghi - Tủ quần áo",
    [1694547792] = "Thăm <npc>Người Nông Dân</npc>",
    [1694785897] = "Khi có ba kẻ địch trở lên trong phạm vi <b>20</b> mét, bạn nhận ít hơn <b>15%</b> sát thương <b>Phép thuật</b>.",
    [1697774486] = "Đôi ủng này được nhồi thêm lớp lông dày, giữ cho đôi chân của bạn ấm áp trong tuyết.",
    [1698490656] = "SP Người chơi",
    [1698702878] = "Tôi đã cạn kiệt kiến thức của mình. Chúng ta phải đi xa hơn, và bằng cách nào đó khám phá kiến thức mới...",
    [1698922803] = "Cổ nhân",
    [1700084697] = "Huyền thoại về Kẻ Sát Long",
    [1700791347] = "Khi bạn tiêu diệt một kẻ địch bằng vũ khí tầm xa, bạn có thể giữ nút tương tác trong 2 giây để dịch chuyển đến vị trí của kẻ địch.",
    [1701346326] = "Làn da của bạn phát ra nhiệt, mang lại cho bạn 2 Giáp Băng mỗi Điểm Thể lực.",
    [1701636768] = "Vậy sao?",
    [1701793303] = "Mở rộng Khu vực Xây dựng thành 175m × 175m.",
    [1702667426] = "Nhà Chưng Cất",
    [1702671750] = "Đầu tiên, không có gì cả. Gió và nước vẫn lặng, đất đai nằm im lìm và chưa được khai phá.\n\nNhưng chẳng bao lâu, một làn gió nổi lên, và sự im lặng dâng cao thành một khúc nhạc. Một đám mây bão, phun sấm sét, lan tỏa khắp bầu trời — và từ trái tim nó bắt đầu tuôn rơi một thác nước máu tím.\n\nKhi những giọt nước tấn công những bông hoa và dây leo bên dưới, chúng đã phá hủy mọi bông hoa và dây leo, cho thấy sự mỏng manh của chúng. Cơn mưa đã biến những vùng đất bằng phẳng thành chiến trường trước tiên, và sau đó, một đại dương.\n\nKhi sự yếu đuối bị thanh tẩy, cơn bão đã lắng xuống, nhưng biển máu còn sót lại đã trở thành một thứ súp nguyên thủy sinh ra một kẻ chiến thắng trong sự hỗn loạn. Broodmother Vesztah đã ra đời.\n\nNàng, Drak đầu tiên, thống trị tất cả — nhưng ngồi cô đơn trên ngai vàng, nàng nói, <i>\"Tham lam là gì nếu không phải là một cái hố để chết đuối? Thống trị là gì nếu không có sự thống trị?\"</i> và chọn chia sẻ vương quốc và máu của mình.\nMẹ chúng ta đã đẻ 100 quả trứng dưới vòm trời đầy sao, và khi Drakling đầu tiên thức tỉnh, nàng đã nhìn chúng vỡ ra khỏi vỏ... và cho kẻ yếu nhất ăn cho kẻ mạnh, để chúng có thể mang đến một cơn bão máu mãi mãi.",
    [1702807344] = "Nhà thờ đã bị phá hủy!",
    [1702813962] = "Chiếc quần này không có gì đặc biệt ở bên ngoài, nhưng bên trong, chúng được lót bằng một lớp lông.",
    [1702886289] = "Công tắc",
    [1703191962] = "Cần Câu May Mắn",
    [1703356892] = "Tôi thực sự ấn tượng — tôi không ngờ bạn lại bắt được con cá đầu tiên dễ dàng như vậy. Bạn sẽ không quên lần đó. Tuy nhiên, hãy tiếp tục luyện tập — những con cá khó hơn sẽ đến, và bạn sẽ cần mọi kỹ năng có thể có.",
    [1703880156] = "Tuyến độc",
    [1703887068] = "Các thuộc tính nhân vật có thể được quan sát trong menu nhân vật. Các thuộc tính chính là <b>Thể chất để có nhiều HP hơn, Tinh thần ảnh hưởng đến MP, và SP cung cấp Thể lực.</b>\n\nSức mạnh ảnh hưởng đến ST Cận chiến, Nhanh nhẹn ảnh hưởng đến ST Tầm xa, và Trí tuệ liên quan đến ST Phép thuật.\n\nMàn hình nhân vật liệt kê <b>kháng cự, Cấp độ khu vực Sương độc và Thời gian trong Sương độc</b> trong Sương độc. Di chuột qua các thuộc tính để tìm hiểu thêm.",
    [1704201355] = "Kháng Cắt",
    [1704231557] = "Đuôi Sọc",
    [1704265720] = "Chăm sóc tóc của bạn!",
    [1704416466] = "Một phần của Bộ giáp Y tá.",
    [1704667947] = "À, bạn đây rồi! Bạn đã tìm thấy gì chưa — một món đồ để khơi nguồn sáng tạo tiếp theo của tôi?",
    [1704740061] = "Dạo này thật ồn ào, vậy mà tôi cảm thấy cô đơn. Tôi không ngừng nghĩ về gia đình mình... bạn có thể giúp tôi không?",
    [1704811384] = "Xoay đẹp",
    [1705343626] = "Bình chưng cất",
    [1705407368] = "Hãy ẩn mình và tấn công từ trong bóng tối với chiếc mũ của cung thủ đáng gờm này.",
    [1705475384] = "Tay Vịn Đá Mịn",
    [1705831037] = "Cung Gỗ Tinh Xảo",
    [1705913774] = "Nhảy múa dưới ánh mặt trời",
    [1706740630] = "Một chiếc móc neo có thể sử dụng dưới nước.",
    [1706740706] = "\"Vật tư cho trẻ sơ sinh\"",
    [1706798863] = "Lật",
    [1707016214] = "Hóa Thạch Cá",
    [1707032878] = "Hướng dẫn",
    [1707252966] = "Phù thủy",
    [1707912821] = "Hàng Rào Gỗ Nhiệt Đới Đơn Giản Buộc Dây II",
    [1707985309] = "Nhìn lên",
    [1709925921] = "Hãy xem tôi có gì để cung cấp!",
    [1710028625] = "Vây Lấp Lánh Nướng",
    [1710252243] = "Nhật ký trò chuyện",
    [1710755608] = "Phòng thí nghiệm này đã được cải tiến bằng cách thêm một bình chưng cất.",
    [1711594347] = "Lấy",
    [1711611016] = "Bạn đã tìm thấy nguồn cảm hứng nhuộm tóc nào chưa? Nào, tôi nóng lòng muốn nhuộm tóc!",
    [1711720505] = "Bạn đã tìm thấy một ghi chú đề cập đến một trang trại dê bên một cái bể bị nhện xâm chiếm.\nScavenger không muốn đến gần đó nhưng biết rằng trang trại có một gác mái chứa đầy chiến lợi phẩm.\n\nKhám phá trang trại và thu thập chiến lợi phẩm từ gác mái!",
    [1712126222] = "Marianne Reed",
    [1713191552] = "Bạn đã tìm thấy một người sống sót đang ngủ trong lòng Đền Thờ Đêm! \n\n<b>Triệu hồi người sống sót bằng Gậy phép Triệu hồi để tiếp tục!</b>",
    [1714005549] = "Chó của Gertrude",
    [1714923418] = "\"Heo Rừng Tại Gia\"",
    [1715001803] = "Khi bạn đứng đối diện với khuôn mặt này, bạn nhớ lại tiếng hét của nó. \"Zzzrrr Krrrraallllll Hrrrrggg\" nó vang vọng trong đầu bạn, lần này bạn không cần phải run sợ.\n\nThu thập nhiều Đầu Rồng Hydrak'Dal để chế tạo Cúp Sắt.",
    [1715153637] = "Sức mạnh",
    [1715495968] = "Sơn mặt",
    [1715600007] = "Quay lại trò chơi",
    [1715664450] = "Phụ kiện 2",
    [1716044624] = "Một bộ dao găm cùn. Đơn giản, nhưng vẫn hiệu quả trong lúc cần thiết.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tăng theo thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [1716467475] = "Bàn Thờ Ngọn Lửa",
    [1716556284] = "Chiến lợi phẩm vĩ đại nhất trong tất cả là thứ đã khơi dậy sự kinh ngạc... và sợ hãi. Làm tốt lắm, bạn của ta. Cơn giận của ta đã dịu đi.",
    [1716893270] = "Chúng ta nên cải thiện khả năng của mình! Lão xương của ta đang trở nên giòn yếu.",
    [1717345855] = "Độ sáng của tông màu vàng khiến nó trông gần như phát quang. Trong khi tỏa sáng hơn mặt trời, suy nghĩ về thất bại tan biến trong ánh sáng rực rỡ.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Kindlewastes.",
    [1717467694] = "Hang Sương độc",
    [1717577608] = "Đèn Gắn Tường Xanh Dương I",
    [1717834923] = "Thùng gỗ",
    [1717875766] = "Cung cấp khả năng miễn nhiễm với ngộ độc.",
    [1718783371] = "Gừng Trong Rừng Rậm",
    [1719603885] = "Một vật liệu xây dựng cơ bản. Không đẹp lắm, nhưng nó hoàn thành công việc.",
    [1719678077] = "Giáp chân da",
    [1719881255] = "Bạn đã tìm thấy một ghi chú mô tả một ẩn sĩ trao đổi đá thạch anh tím để lấy hàng hóa.\n\nÔng ta sống ở một khu vực hẻo lánh không xa Pháo đài Balefire \"Lance Point\".\n\nTìm kiếm nhà của ẩn sĩ và tìm những vật có giá trị ở đó!",
    [1720308766] = "Áo Giáp Lông Thú",
    [1720608974] = "Thợ săn <npc>Thợ săn</npc> còn sống! Có lẽ cô ấy có thể tiết lộ một vài điều về việc sinh tồn ở Vùng đất Màn Sương.",
    [1720739002] = "Một phòng thí nghiệm để chữa bệnh",
    [1720904102] = "Kền kền cánh trắng",
    [1722591368] = "Ẩn địa chỉ IP",
    [1722642500] = "Xây một chiếc giường trú ẩn cho Valory",
    [1722973548] = "Người nông dân từng nhìn thấy những bông hoa xanh tươi gần một trại xe ngựa ở Cao nguyên Du mục vào ban đêm.\n\nĐến địa điểm mà Người nông dân đã đề cập và thu thập cây trước khi quay lại gặp Thợ cắt tóc với chúng trong kho đồ của bạn! Bạn cũng có thể tìm thấy cây ở các khu vực khác của Cao nguyên Du mục.",
    [1723514899] = "Bạn có muốn xóa chồng vật phẩm này không?\nNó không thể phục hồi!",
    [1725549464] = "Được sử dụng trong Bản đồ và Cây kỹ năng",
    [1725598439] = "Ngộ độc thực phẩm",
    [1725996768] = "Khối Mái Đơn 0,5m",
    [1726160042] = "Cửa Gỗ Bí Mật",
    [1726702716] = "Bình Bạc",
    [1727251319] = "Điểm Kết Nối Chướng Khí",
    [1727480558] = "Tay Vịn Gỗ Đơn Giản",
    [1729110731] = "Hồi máu",
    [1729112111] = "Bộ Cung Thủ",
    [1729858237] = "Trả Nợ",
    [1730257446] = "Bạn có thể hoàn toàn tránh giao tranh bằng cách <b>lén lút.</b> Cúi người bằng cách nhấn %k và vào <b>bụi rậm</b> để ẩn mình khỏi tầm mắt kẻ địch. <b>Tất cả</b> bụi rậm đều che giấu bạn.\n\nBạn có thể dùng điểm kỹ năng để học Tấn công lén lút. Lẻn ra phía sau kẻ địch không cảnh giác và tung ra Tấn công lén lút bằng cách nhấn %k khi đang ẩn mình.",
    [1730457212] = "Vị trí Kiếm Đôi Ngọn lửa Nhỏ",
    [1730529828] = "Một chiếc búa 2H nặng nề có thể phá vỡ mọi cánh cửa nhờ các gai nhọn phía trước. Đập, xé và chém đều không thành vấn đề với vũ khí này!",
    [1730908530] = "Ngọc Gặt Hồn",
    [1730919567] = "Cúp Danh Năng Đấu Sĩ Vukah Bằng Vàng",
    [1730971280] = "Tìm thấy trong vùng nước Thung lũng Sương Mù",
    [1731026012] = "Đèn Lồng Tuyết",
    [1731978157] = "Cấu hình Thế giới",
    [1732521158] = "Chiếu sáng",
    [1732909669] = "Hỡi Hỏa Dũng Sĩ, ta nghĩ chúng ta nên dang rộng vòng tay chào đón thêm nhiều gia súc đến với trang trại của chúng ta! Ngươi nghĩ sao? Ta thậm chí còn có vài ý tưởng đặt tên sẵn sàng đây!",
    [1733133423] = "Bụi Sắt",
    [1733616178] = "Trọng Kiếm Rỉ Sét",
    [1734244687] = "Quần xám được tinh chế với các bộ phận kim loại được chế tác tinh xảo.",
    [1735346843] = "Lỗi nội bộ. Vui lòng cài đặt lại trò chơi.",
    [1735602647] = "Tên Nhân Vật",
    [1736170759] = "Obelisk Cổ Đại",
    [1736240608] = "Mũi tên của bạn không thể bị chặn nữa.",
    [1736693458] = "Cúp Danh Năng Quái Vật Mắt Một Sa Ngã Bằng Sắt",
    [1736914485] = "Tay Vịn Gỗ Tốt",
    [1737034070] = "Đã thu thập được vật thể sống tươi. Sẽ bổ sung ghi chú sau khi nghi lễ hoàn thành.",
    [1737409223] = "Rãnh Xương I",
    [1737739782] = "Đánh Thức Người Sống Sót",
    [1738331584] = "Chụp lấy",
    [1738360416] = "Câu chuyện của ngươi mới chỉ bắt đầu!",
    [1738682623] = "Bỏ qua",
    [1739178505] = "Sử dụng trực tiếp",
    [1739602652] = "Tay ta đang bận nhưng ngươi cần gì?",
    [1740582673] = "Bao Tải Tiếp Tế III",
    [1740700739] = "Hoa Bả Sói",
    [1741017850] = "Tên gọi 'Kẻ Chẻ Sọ' bắt nguồn từ bản chất tàn nhẫn của nó — chẻ đôi sọ trong mỗi cú vung.",
    [1741045064] = "Áo Giáp Chiến Binh",
    [1741426667] = "Nước Vị Khác Lạ",
    [1741684857] = "Một chiếc rìu làm từ kim loại phế liệu với độ bền và hiệu quả được cải thiện so với Rìu.",
    [1741847098] = "Thịt Sói Sống. Phải nấu chín để tiêu thụ đúng cách.",
    [1742376863] = "Tăng chỉ số Sức mạnh của bạn lên 1.\n\nTăng ST Cận chiến thêm 5% cho mỗi Điểm chỉ số.",
    [1742577218] = "Ngươi có gì cho ta?",
    [1742782947] = "Búa Rừng Âm U",
    [1743608970] = "Một món trang sức đầu lộng lẫy, phô trương, rộng lớn như khả năng ma thuật của ngươi — nhưng ngươi có thể bị kẹt ở cửa.",
    [1743745820] = "Găng tay chắc chắn che giấu lòng bàn tay và ý định thực sự của người mặc.",
    [1743898682] = "Dụng cụ rèn?",
    [1743923456] = "Tươi tốt và sống động như hệ thực vật của Cao nguyên Du mục trước hạn hán.\n\nBảng màu này có thể được tạo bằng vật liệu từ Cao nguyên Du mục.",
    [1744215380] = "Ngươi đã tìm thấy một ghi chú do cư dân trước để lại. Trong đó, ông ta than thở vì không bao giờ tìm thấy sức mạnh để sửa mái nhà. Những viên gạch ông ta đã chuẩn bị cho công việc được cho là vẫn còn ở trên gác mái.",
    [1744401594] = "Cờ Lệnh Chiến Tranh Của Vorgoth II",
    [1745029562] = "Thiếu nguyên liệu",
    [1746158999] = "Một thanh kiếm rực lửa, tỏa sáng sức mạnh. Nó nóng đến mức làm giảm MP của con mồi trong mỗi đòn đánh.",
    [1746656349] = "Bình minh chấm dứt cả những đêm tối nhất. Hãy ngẩng cao đầu. Ánh sáng của ngươi không thể bị dập tắt.",
    [1747213617] = "Bỏ qua người chơi",
    [1747312316] = "Sát thương lên Vukah",
    [1747627432] = "Thịt Mỡ Nướng",
    [1748054309] = "Chúng Sống Dưới Lòng Đất!",
    [1748120872] = "Tìm Bản Nhạc Đầu Tiên",
    [1748294387] = "Ý Kiến Về <npc>Nhà Sưu Tầm</npc>",
    [1748353866] = "Hồi phục MP",
    [1748435950] = "Thực đơn Muối Tiêu",
    [1749507695] = "Ngươi đã có cả hai phần của bức tranh treo tường! \n\nĐể giải mã ý nghĩa của bức tranh, ngươi phải trở về nhà và đặt cả hai mảnh vào khung!\n\nKết hợp các mảnh sẽ tiết lộ thêm công thức chế tạo và cho phép ngươi tạo ra bộ giáp pháp sư tốt hơn với vải màu mận chín và tím!",
    [1752505228] = "Tích Tụ Băng Giá",
    [1752803673] = "Màu Đỏ Nhạt Mất Trí",
    [1752974292] = "<i>\"Tham lam là gì nếu không phải là một cái hố để chết chìm?\"</i>",
    [1753184279] = "Giết một kẻ địch bằng Tấn công lén lút hoặc Tấn công tàn nhẫn có %k cơ hội sinh ra một bộ xương đồng minh cấp %k.",
    [1753475797] = "Lửa Trại Kẻ Thu Lượm",
    [1753875962] = "Sự Thiếu Ngủ Của Ta Đang Bắt Kịp",
    [1754284336] = "Thợ săn yêu cầu ngươi thu thập một vài đom đóm. Cô ấy không nói sẽ làm gì với chúng, nhưng tốt nhất là cứ làm theo. \nĐom đóm có thể tìm thấy ở Vùng Đất Mùa Xuân vào ban đêm.\n\n<b>Trả lại cho cô ấy cùng với đom đóm trong hành trang của ngươi.</b>",
    [1754749871] = "Tin Đồn Là Thật",
    [1755380926] = "Cúp Tiện Nghi",
    [1755601787] = "Đỡ",
    [1755792495] = "Tốc độ tấn công chậm",
    [1756007691] = "Đạn phép thuật đốt cháy một quả cầu lửa, gây sát thương lên một mục tiêu.\n\n\n<b>Phép thuật:</b> Bị tiêu hao sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép bằng <b>gậy phép.</b>",
    [1756686245] = "Suối Nước Nóng Cromville",
    [1756970829] = "Cây Giống Nấm Russula Xanh",
    [1757559871] = "Nơi Chế Tạo Bù Nhìn",
    [1757565558] = "Sát thương phép thuật nhận vào được giảm.",
    [1758599250] = "Sửa chữa trang bị của bạn khi đang di chuyển. Dần dần khôi phục một lượng nhỏ độ bền theo thời gian.",
    [1758756166] = "Khả năng tiếp nhận thêm hàng hóa để sửa chữa của <location><lorename>Pikemead</lorename>'s Reach</location> đã ngừng hoạt động. Chúng ta phải giữ lại bưu kiện quá hạn cho đến khi có thông báo mới... <b>Ta đã đặt nó trên sàn cẩu.</b>",
    [1758901599] = "Bạn đã bị Fell nguyền rủa. Thời gian của bạn trong Sương độc bị giảm đáng kể.\n\nHiệu ứng suy yếu dài hạn này ảnh hưởng đến bạn vĩnh viễn cho đến khi được loại bỏ bằng thuốc giải độc.",
    [1758917594] = "Thỏi Vàng",
    [1759180723] = "Một khối kiến trúc theo phong cách cổ đại, đại diện cho các yếu tố kiến trúc của các ngôi đền sa mạc.",
    [1759805840] = "Cờ Lệnh Ngang II",
    [1760062145] = "Tỷ lệ Độ bền",
    [1760173592] = "Hoàn hảo để lội qua tro tàn và đất mục nát.",
    [1760240384] = "Tìm Gợi Ý Về Nơi Ở Của Dì Braelyn",
    [1760410433] = "Lò Sưởi Đá Granite",
    [1760968766] = "Bạn không thể thêm nhiều điểm đánh dấu. Hãy xóa một điểm đánh dấu để thêm điểm mới.",
    [1761650968] = "Những chiếc vảy khổng lồ, cứng rắn. Nhẹ nhưng cực kỳ bền chắc, chúng là vật liệu chính để chế tạo giáp bền và linh hoạt.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Chúa tể Sinh vật Fell, ban đầu tìm thấy ở Revelwood.",
    [1762391947] = "Trưng bày A",
    [1762527374] = "Rìu Của Kẻ Lưu Manh",
    [1762720475] = "Nhập tin nhắn của bạn...",
    [1763439860] = "Tìm Gạch Xây Mái Nhà",
    [1763740993] = "Đồi Tiếng Sói",
    [1764004029] = "Không có con cá nào cắn câu.",
    [1764041492] = "Vật phẩm Trang trí Thợ Săn Rải Rác",
    [1764068832] = "Điều tra Nơi Ở Của Kaori Conway",
    [1764283204] = "Có rất nhiều cá trong biển!",
    [1764973280] = "Phát hiện sự cố",
    [1765635168] = "Lấy tất cả",
    [1765704814] = "Bát Lửa",
    [1765934927] = "Một loại trái cây tổng hợp ngon miệng, chủ yếu tìm thấy ở Rừng Rách Nát.",
    [1766273110] = "Trọng Kiếm Ảo Ảnh",
    [1766518980] = "Rìu Bị Phủ Bóng",
    [1767239186] = "Sự Lừa Dối",
    [1767422988] = "Chi phí",
    [1767429586] = "Cuộn Giấy Bộc Phát Ánh Sáng",
    [1768120956] = "Những Sảnh Đường này trông thật ảm đạm... ai đã nói rằng sự đau khổ vĩnh cửu lại phải tẻ nhạt đến vậy? Chúng ta có thể dễ dàng thêm chút lộng lẫy, phải không?\n\nTa có một ý tưởng: Một ngai vàng làm từ <i>Xương</i>. Hãy tưởng tượng xem. Đáng sợ. Uy hiếp. <i>Gothic.</i>\nPhải, nó hơi lộ liễu... nhưng tại sao lại để chỗ cho sự tinh tế khi bạn có thể ngả lưng trên tàn tích của đối thủ? À, ta thật xuất sắc. Ta đã bỏ lỡ sự nghiệp trang trí nội thất của mình. Ước gì ta không phải là xác sống.",
    [1768637850] = "Khối Rơm Quét Hắc Ín",
    [1768735019] = "Cây Giống Dâu Tây",
    [1769061413] = "Chỉ Một Lần Ôm Nữa",
    [1769096116] = "Tăng ST Đập",
    [1770190174] = "Hóa Thạch Tôm",
    [1770442500] = "Găng Tay Binh Lính",
    [1770964310] = "Bình Máu Phục Hồi",
    [1771635528] = "Kiếm Đôi Rực Lửa Lớn",
    [1771721440] = "Khi đi qua vùng đất này, ta đã khám phá ra vô số loài thực vật và động vật đa dạng. Tuy nhiên, không có loài nào đáng yêu và kiên cường bằng những loài gặm nhấm nhỏ bé nhảy nhót khắp cảnh quan này, mà ta đã gọi chúng là \"Chuột Nhảy\". Có lẽ chính tình trạng thê thảm của Embervale đã tạo ra một khoảng trống trong trái tim ta dành cho những sinh vật bé nhỏ mong manh này... nhìn chúng ăn côn trùng nhỏ và trốn tránh những kẻ săn mồi khác mang lại cho ta niềm vui nơi vốn chỉ có nỗi buồn.",
    [1771904944] = "Bệ Hạ, vị Vua nhân từ <lorename>Gormander</lorename> đòi công lý cho vụ sát hại Thanh tra Hoàng gia Lachlan. Việc giao đầu của hắn đến Tòa án của Nhà Vua là một hành động gây hấn sẽ bị trừng phạt nhanh chóng. Cầu mong sự báo thù của Nhà Vua sẽ là một bài học nhanh chóng rằng luật pháp của Embervale vẫn còn hiệu lực!",
    [1772044311] = "Dao Găm Sừng",
    [1772124578] = "Sát Thương Đạn Đánh",
    [1772439737] = "À, vị ngọt này làm ta nhớ đến thiên đường thực vật mà ta gọi là nhà trước khi hạn hán ập đến... chúng ta sống lay lắt trong khi các thành phố khác được đồn đại là có quá nhiều. Ví dụ, <location>Glennwood's End</location> nổi tiếng về sự sung túc. <b>Ngay cả bãi rác của họ cũng lấp lánh những của cải</b>. Thật đáng tiếc khi dân làng đã hơi điên rồ. Họ đã làm rượu dâu tây tuyệt vời!",
    [1772990165] = "Rừng Mùa Vui",
    [1773111296] = "Lá Xô Thơm",
    [1773433268] = "Các Sự Cố Tại Công Trường \"Maelstrom\"",
    [1773480608] = "Đài Phun Nước Đỏ",
    [1773519125] = "Mũ Giáp Điềm Báo",
    [1773829809] = "<location>Bãi Biển Sapphire</location>",
    [1774413044] = "Tượng Đầm Lầy Đen Lớn II",
    [1774802855] = "Giày Nhà Thám Hiểm",
    [1775034797] = "Đã Khai Quật",
    [1775993469] = "Không đẹp lắm, nhưng hữu ích khi tạo ra sự bảo vệ khỏi các yếu tố.",
    [1776166207] = "Cờ Lệnh Chiến Tranh Của Jezmina II",
    [1776434630] = "Những Câu Chuyện Của Thuyền Trưởng Già",
    [1776469466] = "Bạc là một kim loại quý thường được tìm thấy kết hợp với các khoáng chất khác. Quặng bạc thô này sẽ cần được xử lý để trở nên hữu ích.",
    [1776593601] = "Găng tay được trang trí bằng đá quý màu xanh lá cây lấp lánh. Bất kể bạn đang xây dựng lại hay phá dỡ thứ gì — bạn sẽ luôn trông thật thời trang với những món đồ này!",
    [1776605469] = "Dê Lông Xù",
    [1776670010] = "Chìa Khóa Tới The Pike",
    [1776934417] = "Đền Ouroboros",
    [1776960829] = "Gia đình ta đã làm việc không mệt mỏi để đục những trục đường quanh co vào đá, mặc dù tất cả chúng đều xám xịt và xỉn màu. Ta khó có thể tưởng tượng một cuộc sống khác, trừ khi ta nhìn vào mặt nước gần đó và nhớ lại tuổi trẻ của mình.\n\nTa nhớ đã đọc về một nàng tiên cá: Một thiếu nữ cô đơn có trái tim tan chảy vào sóng biển khi hóa thành bọt biển. Nhiều năm trong mỏ đã khiến ta quên lãng, khiến ta trưởng thành. Nhưng không phải ai cũng từ bỏ những câu chuyện cổ tích như vậy.\n\nCó lần, ta gặp một người đàn ông có đôi chân lẽ ra phải là vây cá. Họ gọi anh ta là \"Kẻ Săn Tiên Cá\" — luôn vuốt ve biển như thể đó là người tình của mình, để thủy triều bao bọc lấy anh ta khi anh ta lặn xuống tìm kho báu.\nAnh ta đang nhặt những vỏ sò bị tẩy trắng dưới ánh mặt trời khi ta hỏi:\n<i>\"Ngươi tìm kiếm điều gì dưới nước mà không tìm thấy trên cạn? Lẽ ra ngươi nên tìm một công việc đàng hoàng và ổn định cuộc sống chứ?\"</i>\n\nKhông ngẩng đầu lên, anh ta lẩm bẩm mỉm cười: <i>\"Ta tìm kiếm nụ hôn của một nàng tiên cá — người giấu giọng nói của mình trong vỏ ốc và lời nói trong những thông điệp đóng chai. Ta sẽ cứu nàng khỏi hóa thành bọt biển, và cứu ta khỏi chìm vào màu xám.\"</i>\n\nNgày nay, ta nhớ lại lời của Kẻ Săn Tiên Cá, lần theo những trang sách cổ tích trong tâm trí. Ta hiểu rồi. Gia đình ta đã làm việc không mệt mỏi để đục những trục đường quanh co vào đá, tất cả đều xám xịt và xỉn màu. Ta ước gì mình đã không quên phép màu của những năm tháng xưa. Ta ước gì mình đã tự khắc con đường của riêng mình và ra khơi.",
    [1776993295] = "Quả Ngọc Giá",
    [1777632805] = "Tuyến Vận Chuyển <craftingstation>Máy Xông Ong</craftingstation>",
    [1777735248] = "Cổng Lưới Thép",
    [1777767119] = "Xương Vùi Lấp Dưới Cát Thời Gian",
    [1778512005] = "Nhẫn của <lorename>Thuyền Trưởng Arkwright</lorename> đã được tìm thấy. Nó được mang bởi một bóng người kỳ lạ lảng vảng qua các thung lũng, bị biến dạng bởi Sương độc.\n\nChiếc nhẫn đã được giật lấy từ bàn tay đang phân hủy của nó, giữa một biển binh lính đã ngã xuống.",
    [1778936709] = "Công Thức Tình Yêu",
    [1778966356] = "Một mũi tên bằng thép tinh xảo được trang trí bằng vàng. Với nó, bạn có thể chiến đấu thật phong cách.",
    [1779181461] = "Găng Tay Thợ Săn",
    [1779190938] = "Được tạo ra qua nhiều năm hóa đá, nó đã trở thành một vật liệu tuyệt đẹp được sử dụng cho sản xuất.",
    [1780047884] = "Chỉ hiển thị các phiên chơi của bạn bè",
    [1780525011] = "Chí mạng",
    [1780636003] = "Sẵn sàng vũ khí tầm xa",
    [1780664491] = "Hugo Vanderhall muốn nghiên cứu tác động của việc chơi nhạc bằng các nhạc cụ sử thi! Ông ấy nghĩ rằng các nhạc cụ tiên tiến hơn có tác động cao hơn đến tinh thần của mọi người.\n\nÔng ấy nghi ngờ rằng một số <b>nhạc cụ sử thi có thể nằm rải rác trong các ngôi đền ẩn của Kindlewastes</b>, nhưng ông ấy không biết ở đâu. Ông ấy đã tiết lộ cho bạn vị trí của các ngôi đền ẩn.\n\nTìm kiếm các ngôi đền ẩn được đánh dấu trên bản đồ của bạn từng cái một để thu thập các nhạc cụ sử thi!",
    [1781204873] = "Cấp cho bạn %k cơ hội cơ bản để tạo ra một quả cầu HP khi tiêu diệt kẻ địch. Thu thập một quả cầu HP sẽ tăng thêm %k ST Cắt cho các đòn tấn công và tăng cơ hội tạo ra quả cầu HP lên %k trong %k.",
    [1781755472] = "Mảnh Xương Sống",
    [1781791052] = "Cống Thoát Nước Gắn Tường",
    [1782214983] = "Áo Khoác Đại Úy",
    [1782332094] = "Một mũi tên có đầu bằng thép.",
    [1782340714] = "Áo Giáp Chiến Binh Quật Khởi",
    [1782370626] = "Vị Trí Trống Tay",
    [1783169563] = "Cảm ơn bạn một lần nữa vì đã nhắc tôi cách nhuộm tóc màu đỏ. Gần đây, tôi đã yêu thích... từ gì nhỉ? \"Indigoon\"? Không... \"Indigo\"! Xanh Biển Tuyệt Đẹp! Sự Phô Trương Đại Dương! Tôi đoán tôi có thể làm thuốc nhuộm tóc màu xanh nếu có chút cảm hứng, một gợi ý — một màu chàm!",
    [1783376180] = "Vị Trí Vật Phẩm Trang Trí",
    [1783788228] = "Bộ Đồ Hollow's Eve",
    [1784128345] = "Bạn đã đến địa điểm nơi những kẻ ly khai của Hoa Hồng Máu đã chiến đấu trận cuối cùng. Nếu có bất cứ điều gì, bạn có thể tìm thấy áo giáp bị mất ở đây.\n\nTìm Bộ Giáp Hoa Hồng Máu hoàn chỉnh.",
    [1785116193] = "TWN",
    [1785191634] = "Vũ khí mà bạn mang về này khiến tôi suy nghĩ. Tôi không phải là một chiến binh giỏi. Tôi nói năng quá nhỏ nhẹ, quá nhạy cảm. Nhưng tôi có thể hữu ích theo những cách khác! Tôi đã bắt đầu tấm thảm treo tường này khi còn đóng quân ở các vị trí cũ. Hãy để tôi cho bạn biết các mảnh ghép ở đâu!",
    [1785885614] = "Bước Đi Duyên Dáng",
    [1785973408] = "Trượng Của Kim Ngưu",
    [1786885447] = "Bạn bè & Yêu thích",
    [1787451131] = "Lính Gác",
    [1788654528] = "Rào Cản Nước Dưới Đất",
    [1788731597] = "<i>Ta không thể yên lòng.</i>\n\nMột tiếng rên rỉ hàng đêm từ phía sau những bức tường làm tai ta đau nhói. Một tiếng lạch cạch, nghiến ken và nặng nề. Một tiếng rên rỉ từ cổ họng khô như cát của Kindlewastes. Một tiếng gõ trống Hollow vào hộp sọ của ta... gắn liền với cột sống của ta và rung chuyển cốt lõi của ta với mỗi rung động. Ta không thể chịu đựng được.\n\nTa đã mang theo <i>gỗ và đinh.</i> Dù đó là gì đi nữa... nó sẽ không vào được.",
    [1788795796] = "Ta đã nhìn thấy các Tiền Nhân như một khối đá nguyên khối. Một mạng lưới ánh sáng, như những vì sao trên bầu trời đêm, kết nối qua trí tuệ và Ngọn Lửa... nhưng chúng phân mảnh hơn ta tưởng.\n\nCác Tiền Nhân \"trẻ\" cùng ta giải thích rằng Thánh Địa Đêm này là sự sáng tạo của các trưởng lão của họ, \"empyrian\". Nó có trước Sương độc và từng chứa đựng một kho tàng kiến thức nhân loại được dâng làm vật hiến tế, hoặc để trao đổi. Cả Ngọn Lửa lẫn ánh sáng mặt trời đều không thể chạm tới, khiến nó trở nên hoàn hảo cho một trong những Tàu Chở Tro Khẩn Cấp của chúng ta. Chúng ta đã cài đặt bẫy để kích hoạt sau khi tàu được lấp đầy. Hy vọng, điều đó sẽ bảo vệ nó ngay cả khi Sương độc lấp đầy thung lũng.\n\nKhi ta lần theo các chòm sao trên cánh cửa, ta cảm nhận được một nỗi khao khát tuyệt vọng — một sự kéo về phía bầu trời. Ta không thể đọc được biểu cảm của người đồng hành, nhưng sự im lặng của họ đã phản bội họ. Họ cũng cảm nhận được điều đó. Thật tiếc là ta sẽ không sớm nhìn thấy một Thánh Địa Đêm nào nữa. Các Tiền Nhân nói về một nơi ẩn náu còn bí ẩn hơn... sâu trong Blackmire, một vùng đất mà ta từng cho là bị bỏ hoang.\n\nCàng học hỏi, ta càng dường như hiểu ít đi...\n\n— Nữ Hoàng Jezmina",
    [1788877311] = "Lồng Phế Liệu",
    [1789012053] = "Bạn đã đạt đến cuối tiến trình nhiệm vụ demo",
    [1789131853] = "Chùy Sói",
    [1789823910] = "Một <craftingstation>Trạm Giả Kim</craftingstation> cung cấp tất cả các công cụ cần thiết để chế tạo các sản phẩm giả kim tốt hơn.",
    [1789850746] = "Trọng Kiếm Chiến Binh Mọi",
    [1790334884] = "Đánh Bại \"Con Mắt Quỷ\" Bên Trong Giếng Thuốc",
    [1790504732] = "Đến đây, xem ta đã lấy được gì nào - hóa thạch này không truyền cảm hứng sao? Ôi, những câu chuyện mà nó có thể kể...",
    [1790568434] = "Hàng Rào Gỗ Thô",
    [1790778573] = "Bạn đã chế tạo một loại thuốc cho phép bạn chiến đấu chống lại Drak hiệu quả hơn.\n\n<b>Uống thuốc</b> trước hoặc trong trận chiến để cảm nhận tác dụng tăng cường của nó. Sau khi tiêu thụ, bạn cũng sẽ có thể <b>đọc chữ viết của Drak.</b>",
    [1790874956] = "Trắng như tuyết mới rơi, ở một nơi nào đó bên rìa thế giới.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Đỉnh Albaneve.",
    [1791923242] = "Cấp Độ Vật Phẩm Cốt Lõi:",
    [1792214374] = "Nói Chuyện Với Ngọn Lửa",
    [1792645468] = "Thảm Treo Tường III",
    [1793012424] = "Trí Tuệ Giả Kim",
    [1793328733] = "Miệng Vực Bên Dưới",
    [1794117663] = "Bắt Được Tuyệt Vời!",
    [1794542552] = "Mũ Thương Nhân",
    [1794909299] = "Mọi người đi theo sự dẫn dắt của bạn, người bạn mắt sáng. Tại sao? Ta thấy một ánh sáng nhấp nháy bên trong lồng ngực bạn, được giữ bởi thịt và xương. Thật thú vị. Có lẽ bạn đã làm điều mà ta không thể. Họ gọi bạn là Flameborn? Vậy là Ngọn Lửa ban cả phước lành và lời nguyền. Ôi, sợi chỉ định mệnh xoay vần để đưa chúng ta đến với nhau, <i>bạn của ta</i>.",
    [1795051943] = "Chúc May Mắn!",
    [1795604804] = "Lượng HP nhận được từ các phép thuật Chữa thương tăng thêm <b>20%</b>.",
    [1795716520] = "Di chuyển ra xa/lại gần",
    [1796077956] = "Khối Đá Tinh Chế",
    [1796779741] = "Hầm Cổ — <npc>Nhà Giả Kim</npc>",
    [1796941849] = "Quần Trò Chơi Mùa Hè",
    [1797186395] = "Bạn đã chế tạo một Máy Quay. Bây giờ hãy đặt nó vào căn cứ của bạn để <b>kích hoạt quy trình tinh chế len!</b>\n\nSau đó, bạn nên <b>tạo len đã tinh chế</b> để làm bộ đệm ấm áp và áo giáp tốt hơn!",
    [1798980966] = "Đôi tất cuối cùng của chúng tôi đã ở trên chân Milton khi anh ta bị tấn công bởi con hổ răng kiếm tuyết đó. Kể từ đó, anh ta đã mất cả chân và tất của chúng tôi.\n\nTôi đã gửi báo cáo đến Pháo Đài Everfrore — lần nữa — nhưng tôi nghi ngờ họ sẽ gửi thêm hàng.\nCó thể có một ít trong <i>chiếc rương ẩn sau chiếc chiêng trên mái nhà,</i> nhưng <i>nhảy qua các ván gỗ và luồn lách qua cánh cửa ẩn đó</i> thật là phiền phức... \nTôi sẽ chỉ nói với những người khác là chúng tôi đã hết sạch. Dù sao thì Milton cũng không cần chúng.",
    [1799531400] = "Chiếc <craftingstation>Khung Cửi</craftingstation> đã được thu hồi. Nó nên được đặt trong căn cứ để mở khóa các bộ đệm cho áo giáp tốt hơn.",
    [1799662394] = "Một bức phù điêu mô tả lịch sử của Drak.\n\nNgọn lửa nuốt chửng một thị trấn, và bầu trời bốc cháy. Hỗn loạn ngự trị khi Drak xuất hiện trở lại ở Lưu Vực Veilwater. Không có người bảo vệ nào xuất hiện.",
    [1799797698] = "Cột Biển Chỉ Đường",
    [1800462088] = "Tất cả chúng ta đều nhớ nhà, kể cả tôi... nếu bạn có thể xây cho tôi một căn phòng, tôi có thể giúp bạn làm cho nơi này có cảm giác giống nhà hơn một chút. Sao nào?",
    [1800804814] = "Kháng Băng Giá",
    [1801047402] = "Cảnh Báo Tatu Sa Mạc",
    [1801185386] = "Hỡi Hỏa Sinh, ta đã nói chuyện với Emily và ta đã yêu! Không, không phải nàng, mà là Hỏa Vực! Những cảnh hoàng hôn rực lửa, bầu trời quang đãng, vụ mùa bội thu trước hạn hán... Ta muốn tự mình chứng kiến sự sống động này! Emily nghĩ rằng ngươi có thể tìm thấy những màu sắc như vậy ở một thị trấn hoặc gần một trang trại. Bất cứ nơi nào có người nhuộm quần áo hoặc vải vóc khác! Có lẽ một bảng màu như vậy sẽ mang đến cho chúng ta một chút sa mạc!",
    [1801863557] = "Nhẫn Năng Lượng Tối Thượng",
    [1802125681] = "Tìm Tất Cả Các Tờ Nhạc Bị Thất Lạc",
    [1802139945] = "Vảy",
    [1802160119] = "Hiển Thị Số Sát Thương",
    [1802784075] = "Máng Ăn Cho Chuột Lang Nước",
    [1802800663] = "(Giữ) Làm Phẳng",
    [1803046554] = "Cúp Danh Năng Hydrak'Dal Bằng Đồng",
    [1803052572] = "Trang Phục Thợ Săn Siren Tối Thượng",
    [1803221910] = "Cúp Danh Năng Rồng Con Sa Ngã Bằng Đồng",
    [1803927951] = "Quá tải máy chủ:",
    [1804124810] = "Rìu Mạ Vàng",
    [1804330091] = "Chế tạo tại Bàn Dệt",
    [1804431287] = "Da Thuộc",
    [1804479463] = "Xin chào! Có phải ta là người chàng đang tìm?",
    [1804646020] = "Kháng Độc",
    [1804958701] = "Không có hai kiểu tóc nào giống nhau.",
    [1805093420] = "Thức Ăn Nhanh Nhẹn",
    [1805717483] = "Bình Máu Siêu Cấp +",
    [1806528901] = "Cổng Hầm Mộ",
    [1806566341] = "Sửa Chữa Bức Thảm Tường Bằng Khung",
    [1807087202] = "Cỏ",
    [1807194919] = "Ném",
    [1807204395] = "Loot Đền Rắn",
    [1807972345] = "Thùng Thép Lớn",
    [1807986033] = "Một bản nhạc cho bài hát mang lại sự khích lệ nhỏ.\n\n<b>Tờ Nhạc</b>: \nTờ nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ tờ nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát.",
    [1808234844] = "Bảng Trưng Bày Mảnh Khảm Ngọn Lửa",
    [1808342757] = "Loài cây này đáng chú ý vì màu sắc điện giật tuyệt đẹp, những cánh hoa mỏng manh và chất độc chết người của nó.",
    [1808849027] = "Thu Hoạch Quả U Ám Vào Ban Đêm Tại Rừng Revel",
    [1809093266] = "Chữa thương tức thì",
    [1809326259] = "Chế tạo hoặc nhận Bình Tinh chất Hồn Rồng",
    [1809811991] = "Vị trí <npc>Thợ Săn</npc>",
    [1809843942] = "Đại Úy Melville Fontane",
    [1810057698] = "Xóa Bộ Lọc",
    [1810224006] = "Một chiếc khiên nhẹ cho phép người mặc dễ dàng giữ sự nhanh nhẹn khi bị tấn công.",
    [1810411809] = "Merphisz",
    [1810974551] = "Rào Chắn Tre III",
    [1811301676] = "Bộ Deadeye",
    [1811347182] = "Sử dụng %k",
    [1811364600] = "Bộ Xạ Thủ",
    [1811658538] = "Mắt Chúng Ta Hướng Về Các Vì Sao, Mãi Mãi Nhắm Lại",
    [1812174460] = "Vị trí <craftingstation>Cối Xay</craftingstation>",
    [1812197853] = "Đỉnh Sóng Gầm",
    [1812264898] = "Da Phơi Khô",
    [1812872703] = "Giếng Thuốc Tiên",
    [1813086194] = "Tiền Đồn Của Scavenger",
    [1813645705] = "Áo Chẽn Kẻ Gọi Thủy Triều",
    [1813842092] = "Đồ Ngốc!",
    [1815430063] = "Màu tím hoàng gia đậm chiếm ưu thế trong bảng màu này. Màu sắc dường như thu hút bạn như ánh sáng lấp lánh bên trong một viên đá thạch anh tím.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Đỉnh Albaneve.",
    [1815725117] = "Nhớ ta chứ, hả?",
    [1815840334] = "Đề Xuất Kinh Doanh Hoàn Hảo",
    [1815909239] = "\"Orville\" hẳn đã từng là một nơi tốt đẹp. Ước gì ta có thể đưa con gái đến đó nghỉ dưỡng.",
    [1815993220] = "<location>Cây Gai Góc</location>",
    [1816214782] = "Tăng tất cả ST Băng thuật",
    [1816681717] = "Đền Thờ Ẩn",
    [1817473233] = "Nền tảng cho mọi cuộc phiêu lưu mới là một giấc ngủ ngon.",
    [1818240721] = "Rương trong tầng hầm bị ngập nước",
    [1818658851] = "Lớp da bổ sung mang lại sự bảo vệ vượt trội khỏi đá sắc nhọn, vỏ cây xù xì và mũi tên bay tới.",
    [1819204726] = "Quần Thành Lũy Hoàng Kim",
    [1820350753] = "Kẻ Dệt Chướng Khí",
    [1820566125] = "Địa hình Rương Gian Lận",
    [1821262998] = "Cánh Đồng Ngô",
    [1821940950] = "Nhấn Phím",
    [1822009000] = "Gặp lại bạn.",
    [1823127284] = "Bò Tây Tạng",
    [1823621204] = "Giáp",
    [1823735378] = "Thảo mộc",
    [1824165553] = "Tiện nghi - Ghế đẩu",
    [1824196293] = "Chế tạo và đặt một Cối Xay",
    [1824250694] = "Cờ Lệnh Chiến Tranh Của Jezmina I",
    [1824333122] = "Chuột Phải",
    [1824375145] = "Mũi Tên Nổ II",
    [1824654366] = "Không",
    [1824947903] = "Những món ăn ngon của sa mạc bị đánh giá thấp do môi trường khắc nghiệt mà chúng phải sinh tồn. Quả Yucca nổi tiếng là chứng minh mọi định kiến sai lầm. Nó mọng nước như vẻ ngoài của nó!",
    [1825557606] = "Tất cả sát thương cận chiến <b>Chém</b> được tăng thêm <b>10%</b>.",
    [1826468988] = "Một Bài Kiểm Tra Kỹ Năng",
    [1826583845] = "Sức Mạnh Khiên",
    [1826764071] = "Gió bắc mang chúng trôi xuống. Chúng đến từ những vách đá xa xôi, đồ sộ và vững chãi — ánh mắt cyclops nhìn về phía những luồng sáng nhảy múa trên đường chân trời. Bị thu hút bởi ánh sáng như thiêu thân lao vào Ngọn lửa, và tham lam một cách định mệnh. Chúng đã từng chạy trốn, bị thiêu rụi và rỗng tuếch bởi lời nguyền. Đừng thương xót chúng. Chúng sẽ nghiền nát bạn thành bụi nếu có cơ hội.",
    [1826916620] = "Không thể tương tác khi đang di chuyển",
    [1827081182] = "Cuốn <craftingstation>Sổ Tay Cây Cối và Hạt Giống</craftingstation> đã bị Scavenger cướp mất. Chúng mang chiến lợi phẩm của mình đến <location>Nơi Nghỉ Ngơi Của Surat</location>.",
    [1827141962] = "Vị <npc>Nhà sưu tầm</npc>, Alden Crowley, có thể cảm nhận được điều gì đó đã thay đổi ở thế giới bên trên khi họ vắng mặt. Sương độc là một hiện tượng mới đối với họ.\n\nHọ coi những \"vấn đề trần tục\" như vậy là không đáng kể và tỏ ra không ấn tượng trước mối họa sắp xảy ra.",
    [1827628745] = "Nấm Penny Bun",
    [1828867212] = "Sự Đình Chỉ Vô Thời Hạn",
    [1829328812] = "Trại Ẩn Sĩ",
    [1829506903] = "Về Mèo Và Chuột",
    [1830130744] = "Không thể khởi tạo Hệ thống Bộ nhớ.",
    [1830262357] = "Một cây đũa phép xoắn phát ra ánh sáng xanh mờ ảo. Nó đòi hỏi phải được sử dụng!\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sức mạnh sát thương của nó. Các đòn tấn công gây thêm sát thương lên tới phần trăm <i>quá tải</i>.\n\n<b>Đa Đạn:</b> \nBắn nhiều viên đạn nhưng với sát thương giảm.",
    [1830348731] = "Cột Cờ III",
    [1830629859] = "Sự Khéo Léo Của Thợ Mỏ",
    [1831064114] = "Chọn Công Thức",
    [1831116736] = "Với sự đơn giản của mình, chiếc quần này mang lại sự cân bằng cho bộ trang phục và cho phép sự hiện diện của người mặc tỏa sáng.",
    [1831238294] = "Mầm tri thức đã bùng cháy bên trong. Hãy sẵn sàng để khám phá những bí mật của quá khứ. Tìm <location>cột đá</location> của Vùng Suối để tìm hiểu số phận của thế giới, một câu chuyện về sự mục nát và lửa. Chỉ những ai tìm kiếm sự thật mới tìm thấy nó.",
    [1831926442] = "Hãy để ta làm cho ngươi tỏa sáng!",
    [1832583005] = "Đền Thờ Mặt Trời Bị Ám Ảnh? Trời ơi, tôi đã sống gần một cái - Thật kinh khủng! Thấy đó, đền thờ của chúng tôi là những sảnh đường linh thiêng và nơi chôn cất, tôn vinh Người Cổ Đại! Tia lửa ở đó được nuôi dưỡng bằng lời cầu nguyện và che chắn cho người chết của chúng tôi khỏi tổn hại! Nhưng khi Sương độc lan rộng, ánh sáng của nó mờ đi. Có lẽ đức tin của chúng tôi đã lung lay khi <i>hầm mộ sống lại.</i> Tiếng kim loại va chạm! Những lời thì thầm đen tối! Tôi đã giữ lời cầu nguyện của mình trong quán rượu kể từ đó. Thật ma quái!",
    [1832608218] = "Hủy Diệt Hàng Loạt",
    [1832956592] = "Là một hợp kim của cả sắt và carbon, thép có khả năng chống chịu tốt hơn và do đó cung cấp sự bảo vệ tốt hơn khi được sử dụng trong áo giáp.",
    [1833057167] = "Nhà Thợ Dệt",
    [1833085744] = "Tầm Bắn",
    [1833341925] = "Ngư dân đã nói về một thế lực tàn phá Thung Lũng Nước Ve với những cái hàm như hàm cá sấu, móng vuốt như kền kền và khát máu.\n\nÔng ấy muốn bạn giết một trong những con quái vật này và mang về một kỷ vật để bạn có thể hiểu rõ hơn về kẻ thù mới của mình.\n\n<b>Bạn có thể tìm thấy những con quái vật này ở bất kỳ đâu, nhưng một địa điểm thuận tiện đã được đánh dấu trên bản đồ.</b>",
    [1833722156] = "Một món giáp đầu giúp bảo vệ hộp sọ của bạn khi lao vào trận chiến.",
    [1833733701] = "Gabrielle Fairburn, sẵn sàng phục vụ và bảo vệ! Hãy đưa cho ta một kẻ xấu để đánh bại - hoặc tốt hơn nữa, một con rồng để tiêu diệt - và ta sẽ xử lý chúng để giữ cho ngươi an toàn!",
    [1834216971] = "Đã chọn",
    [1834519059] = "Cửa Cổ Giả",
    [1834705020] = "Cửa Đá Granite Bí Mật",
    [1834705559] = "Thú cưng",
    [1835195332] = "Chuyển động",
    [1835600599] = "Bảng Cúp Cá",
    [1835621188] = "Chuyển Đổi Yêu Thích",
    [1835827290] = "Gặt Hái",
    [1835938065] = "Cây Giống Bụi Hạt Phỉ",
    [1837024512] = "Cấp Độ Vượt Qua Sương Độc",
    [1837062309] = "Xoay Tinh Tế",
    [1837349923] = "GIÁP\nMỗi điểm \"Giáp Vật Lý\" sẽ giảm 1 sát thương cho tất cả các loại sát thương vật lý.\n\nKHÁNG CỰ\nMỗi phần trăm \"Kháng Cự Vật Lý\" sẽ tiếp tục giảm sát thương vật lý.",
    [1837386303] = "Thứ gì đó từ dưới lòng đất đã thức tỉnh. Một thế lực tà ác, một căn bệnh... sự mục rữa từ bên trong. Với đôi tay run rẩy, ta đã nới lỏng một viên đá cuội trên bức tường khô của tầng hầm, để lộ ra một lớp nấm mốc đang thối rữa. Nguồn gốc của sự mục nát... đã ở dưới đây suốt thời gian qua... <i>Ta đã chôn nó dưới đống đổ nát và tro bụi,</i> nhưng điều đó là chưa đủ... Rễ cây mục nát nằm quá sâu để có thể đào lên.",
    [1837550837] = "<keyitem>Lò Luyện Kim</keyitem>",
    [1837606335] = "Bạn đã phát hiện ra rằng một nhóm Scavenger ở Cao Nguyên Du Mục đã tìm thấy một con mèo. Chúng muốn đặt tên cho nó nhưng cũng dự định ăn thịt nó nếu hết lương thực.\n\nĐến trại Scavenger tiếp theo và thuần hóa con mèo để giải cứu nó!",
    [1837730845] = "Bạn có lẽ chưa bao giờ mang một món giáp chân nhẹ như vậy, nhưng hãy thử xem - trọng lượng của giáp ngực cần được cân bằng ở đâu đó.",
    [1837789494] = "Bàn Tiệc Gỗ Cọ",
    [1838045315] = "Đũa Phép Của Đa Năng Học Giả",
    [1838151107] = "Đôi bốt da đơn giản - vừa vặn hoàn hảo.",
    [1838472252] = "Nắp Quan Tài",
    [1838621308] = "Tảng đá này là tâm điểm của một cối xay.",
    [1838658322] = "Cây Trầu Bà",
    [1838677660] = "Chim Đuôi Đỏ Không Cánh Con",
    [1838995518] = "Được thắp sáng bởi chính Ngọn Lửa, cây cung này rung động với sức mạnh của lửa.",
    [1840194203] = "Chiếc quần được làm từ nhiều loại vật liệu khác nhau và bảo vệ đầy đủ tất cả các khu vực quan trọng nhất.",
    [1841068401] = "Giày Trinh Sát",
    [1841086179] = "Nói Chuyện Với Thợ Hớt Tóc",
    [1841255856] = "Gửi Helên thân mến của em",
    [1841768724] = "Các Cột Trụ Cổ Đại Và Dịch Chuyển Nhanh",
    [1841815962] = "Mái tóc của bạn, danh tính của bạn.",
    [1841858182] = "Chữa thương",
    [1841975946] = "Các tông màu nâu ấm và xanh lá cây bụi bặm gợi cho bạn nhớ đến những cuốn sách bọc da cũ với những dấu trang sờn và khóa đồng.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Cao Nguyên Du Mục.",
    [1842112896] = "Giày Xạ Thủ",
    [1842159430] = "Không hoạt động",
    [1843173391] = "Tảo",
    [1843503518] = "Chuyến Xe Ngựa Đến <location>Longkeep</location>",
    [1845012470] = "Thay đổi bản thiết kế đang hoạt động khi vật phẩm này được chọn.",
    [1845641135] = "Tìm Các Khối Xây Dựng Tại <location>Diadwyn</location>",
    [1845660574] = "Tìm Hóa Thạch Kindlewastes",
    [1846273843] = "Chế Tạo Chìa Khóa Sảnh Đường Hollow Albaneve Summits",
    [1846372481] = "Ngọc Trai",
    [1846667189] = "Tạo không gian trong kho nhà máy",
    [1846889770] = "Nhà Sưu Tập đã giao cho bạn một nhiệm vụ. Sảnh Đường Hollow Kindlewastes ẩn giấu 3 cổ vật ma thuật bên trong. Hãy tìm chúng để trưng bày trong căn cứ của bạn!\n\nCó nhiều vị trí ẩn cho các cổ vật. Hãy tìm kiếm các lối đi bí mật và luôn để mắt tới!\n\nĐịa điểm của Sảnh Đường Hollow Kindlewastes sẽ xuất hiện trên bản đồ của bạn khi bạn tìm thấy nó thông qua khám phá hoặc chấp nhận nhiệm vụ Nhà Sưu Tập tiếp theo. Nhiệm vụ sau sẽ có sẵn khi bạn đạt đến cấp độ đủ cao.",
    [1846998243] = "Đã đến một cột trụ cổ đại ở Thung Lũng Veilwater.",
    [1847669666] = "Vật Thể Xa Xôi",
    [1847835017] = "Mảnh bản đồ kho báu bị xé rách, tìm thấy trên bộ xương rồng ở Đỉnh Albaneve. Có lẽ bạn có thể ghép lại bản đồ nếu tìm thấy tất cả các mảnh?\n\nCó chữ viết ở mặt sau:\n\n<b>Hồi Ký của Polaris:</b>\n<i>Ta là một vì sao sáng, trôi dạt cao trên bầu trời\nĐể tìm đường đi của mình, ngươi chỉ cần nhìn vào ta\nNhìn xuống thế giới, thật khó để phủ nhận\nKhông có ai bên cạnh khiến tâm hồn ta cô đơn</i>",
    [1848417270] = "Thảm Lông Lớn",
    [1848866937] = "Bạn đã đến địa điểm được chỉ định để thuần hóa một con Bò Yak. <b>Bây giờ hãy thuần hóa Bò Yak bằng mồi nhử thức ăn</b> bằng cách tiếp cận cẩn thận, cho ăn và vuốt ve nó.\n\nKhi Bò Yak đã thoải mái, nó có thể được <b>bắt và mang về nhà để lấy len!</b>",
    [1848897992] = "Bạn có muốn bơi nhanh hơn không? Bạn nên ghé thăm Yên Ngựa Goldrock!",
    [1849259692] = "Một loài thực vật tự nhiên, tàn dư của nền nông nghiệp bỏ lại, mọc trên thế giới. Nó mang lại sự bảo vệ khỏi các yếu tố khi được sử dụng làm vật liệu xây dựng.",
    [1849288617] = "Hãy để ta kể cho ngươi một câu chuyện, lữ khách!",
    [1849463696] = "Chìa Khóa Xương Đỉnh Albaneve",
    [1849771276] = "Trạng Thái Nhà Máy",
    [1849863930] = "Cửa Đôi Gỗ Đánh Bóng",
    [1850023596] = "Câu cá bị gián đoạn.",
    [1850791545] = "Đơn Xin Nghỉ Việc",
    [1851500742] = "Tìm <npc>Nhà Giả Kim</npc>",
    [1851832209] = "Lộ ra",
    [1852314507] = "Cuộn Giấy",
    [1852497963] = "Nhạc Cụ",
    [1852712396] = "Bàn Hầm Mộ Vừa",
    [1852719772] = "Trà Gừng",
    [1853207546] = "Đôi găng tay chắc chắn bảo vệ đôi tay khi khám phá. Các dấu màu đỏ trên đó tượng trưng cho lòng dũng cảm.",
    [1853317408] = "Hóa Thạch Loa Kèn Biển Lớn Hơn",
    [1853591883] = "Tán Lá",
    [1854046571] = "Bạn có thể mở rộng ngôi nhà của mình theo nhiều cách khác nhau. Nâng cấp Bàn Thờ Lửa sẽ tăng phạm vi xây dựng. <b>Tăng cường Ngọn Lửa</b> sẽ tăng cường sự bảo vệ của bạn chống lại Sương độc và cho phép bạn xây dựng nhiều <b>căn cứ</b> hơn.\n\nXây dựng một Bàn Thờ Lửa thứ hai ở vùng hoang dã bên ngoài bất cứ đâu bạn muốn.",
    [1854195236] = "Tìm <npc>Thợ Săn</npc>",
    [1854219275] = "Hãy sửa nó.",
    [1854279265] = "Vịnh Stillwater",
    [1854642479] = "Khác",
    [1854932277] = "Vải Đỏ",
    [1855278674] = "Khai thác trong Sương độc",
    [1855445542] = "Cột Tổ Tiên Đá Drak I",
    [1855518694] = "Giàn Giáo I",
    [1856081602] = "Ta đang nghe.",
    [1856201749] = "Một chiếc mũ trụ được chế tác tinh xảo, thường được đeo bởi những chiến binh và tướng lĩnh đáng sợ nhất của vương quốc.",
    [1856477078] = "Ánh Sáng Chói Lòa",
    [1857529754] = "Hành Động Hiện Tại",
    [1858004163] = "Chùy Linh Hồn Kép",
    [1858135011] = "Nông Trang Bình Yên",
    [1858234698] = "Tự động sử dụng nguyên liệu thay thế:",
    [1858980286] = "Thỏi Thép",
    [1859147858] = "Mối đe dọa",
    [1859427174] = "Thuốc Súng Đen",
    [1859645347] = "Nhà Giả Kim tin rằng một Hầm Kho Cổ Đại khác có thể chứa những người sống sót có thể giúp xây dựng căn cứ và lưu trữ.\n\nTìm Hầm Kho Cổ Đại mà ông ta đã đề cập!",
    [1859722203] = "Nhẫn Băng Giá",
    [1860578690] = "Những nụ tảo biển nướng này có thể rắc lên thức ăn của bạn để tối đa hóa hương vị. Chúng còn có thêm lợi ích cho HP nữa!",
    [1860725233] = "Mỹ Phẩm Tay Áo",
    [1861218498] = "Mũi tên bằng thép mạ vàng này đã được nhúng trong độc dược. Một cú đánh với nó sẽ cực kỳ chết người.\n\n<b>Mũi Tên Tẩm Độc</b>: Wildlife và Wild Beast trúng mũi tên này sẽ bị nhiễm độc và nhận 24 sát thương mỗi giây trong 5 giây.",
    [1861313541] = "Thuốc Tiên, Một Cơn Lũ Sầu Bi",
    [1861742485] = "Đã Đến Lúc Thay Đổi Thương Hiệu!",
    [1862085022] = "Tàn bạo",
    [1862909474] = "Chỉ những người chơi sử dụng mật khẩu này mới có thể tham gia.",
    [1863376396] = "Đá Cối Xay",
    [1863726952] = "Đồng Tiền Vàng",
    [1863782178] = "<craftingstation>Khung Cửi</craftingstation>",
    [1864305582] = "Thức Ăn Bò Tây Tạng",
    [1864440588] = "Nhà Giả Kim đã thông báo cho bạn rằng bạn đang bị nhiễm Độc Tố Huyết. Để chế tạo thuốc giải cho căn bệnh này, bạn phải thu thập tuyến nhện và bướm đêm. \n\nBướm đêm chỉ có thể bắt được vào ban đêm.\n\n<b>Chế tạo thuốc giải độc tố huyết và sử dụng nó!</b>",
    [1865149579] = "Chế độ Đói Khát",
    [1865379849] = "Ngôi Sao Tổ Tiên",
    [1865818160] = "Nhấn",
    [1866173678] = "Vòng Xoắn Ốc",
    [1866625493] = "Một Nửa",
    [1866753290] = "Kiếm Đồng Đơn Giản",
    [1867200194] = "Sét và băng hợp nhất để giải phóng một lực đột phá.\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương bổ sung lên đến phần trăm <i>quá tải</i>. ",
    [1867436607] = "Cây Giống Cây Bụi",
    [1868066443] = "Ngay cả Súp Ectoplasm được nấu cẩn thận nhất vẫn có vị hơi... lên men.",
    [1868096263] = "Chiến Đấu",
    [1868119398] = "Mũi Tên Xương Khổng Lồ II",
    [1868243621] = "Một vật liệu xây dựng làm từ Đá Cát, phù hợp với màu sắc của sa mạc. Nó được tạo ra cho các công trình kiến trúc.",
    [1868552349] = "Hạ Thân Nhiệt Sắp Xảy Ra",
    [1868573858] = "Chúng ta cần một <craftingstation>Máy Cưa Bàn</craftingstation>",
    [1868683607] = "Những sợi lông capybara này có thể được dệt vào quần áo của bạn để giúp bạn lướt đi trên mặt nước dễ dàng hơn và ngăn bạn bị lạnh quá nhanh.",
    [1869242955] = "Hầm Mỏ",
    [1869338134] = "Một liên kết khác sử dụng cùng các đầu vào theo thứ tự khác.\n\nSử dụng cẩn thận.",
    [1869478678] = "Bạn không đơn độc. Có những người sống sót khác, đang ngủ yên trong các Hầm Cổ gần đó. Hãy tìm họ để họ có thể giúp đỡ trong hành trình của bạn. Đi nhẹ nhàng — có một người đang gọi gần đây, ngay bên ngoài tầm với của Sương độc.",
    [1869713311] = "Cuộn Lên",
    [1869963591] = "Thủ Lĩnh Drak'Dal",
    [1870268693] = "Một chiếc khiên được chế tác tinh xảo, được đánh dấu bằng mặt trời vàng. Mạnh mẽ, đáng tin cậy và rạng rỡ — được chế tạo để giữ vững phòng tuyến khi mọi thứ khác sụp đổ.",
    [1870380748] = "Góc Bề Mặt Không Phù Hợp",
    [1870885237] = "Từ hàng thế kỷ trước, cõi của chúng ta đã cằn cỗi. Những vùng đất hoang vô tận trải dài về mọi hướng, và bầu trời phía trên bị bao phủ bởi một lớp hắc ín dày đặc.\n\nRồi, bầu trời nứt ra để lộ một biển lấp lánh. Một trận mưa sao băng tuôn trào, để lại những vệt màu sắc và gió khi chúng vẽ nên đường chân trời của chúng ta.\nKhi va chạm, chúng đẩy và kéo mặt đất của chúng ta tan nát. Chẳng bao lâu, vùng hoang dã của chúng ta đã được đánh dấu bởi núi, thung lũng và nước. Nhưng không phải tất cả các vì sao đều mang lại sự sống. Một số tìm cách chiếm đoạt nó.\n\n<b>Hai thanh kiếm</b> đã trút xuống từ trên cao — một thanh nhỏ hơn, một thanh lớn hơn — và va vào những đỉnh núi ngọc bích của chúng ta. <b>Một thanh ngủ yên dưới lớp tuyết mới và những bông hoa gentian, một thanh khác bị nuốt chửng bởi cái miệng háo hức của một hang động.</b>\n\nChúng có phải là điềm xấu? Di vật từ một cuộc đấu tay đôi trong khoảng không vô tận? Một món quà từ các Vị Thần Cổ Đại? Chúng ta có lẽ sẽ không bao giờ biết.",
    [1870888149] = "Quần Thợ Săn",
    [1870961742] = "Hồi máu cho mục tiêu đầy máu có %k cơ hội phục hồi một lượng MP tương đương.",
    [1871329916] = "Vị Trí Hoa Hồng Máu",
    [1871333983] = "Huyền Thoại",
    [1871825283] = "Chiếc rìu này có độ chính xác kỳ lạ. Lông trên cánh tay bạn dựng đứng khi bạn sử dụng nó.",
    [1871890043] = "Từng Người Một",
    [1872211651] = "Chúng ta đã bị chia cắt. Bị xé toạc như một con lươn hai đầu.\n\nSự bất hòa trong nội bộ chúng ta đã tách những người trẻ nhất của chúng ta khỏi bầu trời — cuối cùng là một chương mới. Họ muốn bảo vệ ngọn lửa phù du, lấy cảm hứng từ ánh lửa lò sưởi và đom đóm của loài người.\n\nChúng ta sẽ thay đổi và sụp đổ. Cuối cùng, chúng ta vấp ngã.",
    [1872501483] = "Đến Trang Trại Kindlewastes",
    [1872823049] = "Máy Kéo Sợi",
    [1872905532] = "Nhật Ký Emily Fray, Mục 2",
    [1872928582] = "Thứ Gì Đó Đã Gọi Tôi Đến Đây",
    [1873175024] = "Bất cứ thứ gì, tôi có thể phù phép nó!",
    [1873250211] = "Cây Giống Sậy",
    [1873551638] = "Người Chơi",
    [1873699305] = "Hoa Hồng Leo",
    [1873833327] = "Bàn Mộc Mạc",
    [1874414603] = "Tàn tích của kim loại, đã chứng kiến sự sụp đổ của nhân loại. Chúng có thể hữu ích.",
    [1874468387] = "Nhìn Thấy Màu Đỏ",
    [1874647095] = "Thị Trấn <location>Diadwyn</location>",
    [1876202639] = "Sự Sáng Tạo Một Hồ Nước",
    [1876935780] = "Tượng Đá Lớn \"Kiếm\"",
    [1877050735] = "Nhẫn Thể Lực Tối Thượng",
    [1877600769] = "Tìm Kiếm Ngôi Nhà",
    [1878177249] = "Ngồi",
    [1878462986] = "Kháng Phép",
    [1878625958] = "Một phần của Giáp Pháp Sư.",
    [1878705554] = "Da Cứng",
    [1879102163] = "Bảo vệ bổ sung chống lại phép thuật loại Sương độc, ngoài khả năng kháng phép nói chung.",
    [1879503004] = "Bạn có biết tại sao tôi trở thành phóng viên không? Tôi đã thấy tất cả sự quản lý yếu kém, những lời dối trá, sự suy tàn của quê hương tôi — <location><lorename>Pikemead</lorename>'s Reach</location> — sau khi Gormander tiếp quản. Hắn ta đã cố gắng xóa sạch mọi dấu vết của mẹ mình và thậm chí còn tháo dỡ bức tượng của bà! Tôi có một manh mối về một trong những mảnh ghép. Bạn có muốn lấy lại di sản của bà ấy không?",
    [1879748856] = "Lưỡi kiếm này sắc bén như răng nanh của những sinh vật đáng sợ lang thang ở Cao Nguyên Du Mục.",
    [1880116539] = "Nó đã cuốn trôi <b>nơi ẩn náu</b> của chúng tôi như một cơn sóng thần, sủi bọt và gầm rú! Chúng tôi đã rung chuông báo động và cố gắng cứu lô hàng... Giữa cơn hỗn loạn, Reynauld đứng chết trân tại chỗ và chỉ nhìn chằm chằm vào đám mây khi nó ập đến! Dismas đưa tay ra với anh ta, lắc anh ta, cố gắng kéo anh ta đi... cả hai đều bị cuốn đi!\n\nEryn lướt qua tôi để lấy một trong những <b>chiếc rương.</b> Tôi quay lại, hét tên cô ấy khi cô ấy lao vào... cô ấy liều lĩnh. Cô ấy không trả lời, chỉ im lặng.\n\nTôi không ngừng chạy cho đến khi chân tôi khuỵu xuống.",
    [1880188729] = "Hậu Duệ Lửa",
    [1881352372] = "Một thanh kiếm nhẹ và nhanh với màu sắc tuyệt đẹp. Tuy nhiên, nó nhanh chóng bị cùn.",
    [1881674369] = "Mọi chút giúp đỡ đều có giá trị!",
    [1881793353] = "Mơ Hồ",
    [1882292469] = "Kẻ Vô Danh",
    [1882775799] = "Cây Xô Thơm",
    [1883400798] = "Đọc tất cả các bia đá ở Vùng Suối.",
    [1884041589] = "ENG",
    [1885337176] = "Hang Rồng",
    [1886264604] = "Cây Giống Mía",
    [1886462165] = "Giảm tốc độ di chuyển.",
    [1886949341] = "Một vật thể cho phép bạn trưng bày các nhạc cụ của mình.",
    [1887045016] = "Chưa mở khóa công thức nào",
    [1887181333] = "Tìm Mũi Tên Phép Thuật",
    [1887827561] = "Điều Tra Các Đền Thờ Ẩn",
    [1887859125] = "Chiếc handpan trang trí công phu này thật hoàn hảo. Bây giờ, giai điệu nào tôi định chơi? Duu, duu, duu, du-du-du, duu, duu, duu...",
    [1888032193] = "Một bản nhạc chứa đựng một giai điệu sâu lắng. Tuyết rơi thật chậm khi suy ngẫm về quá khứ.\n\n<b>Bản Nhạc</b>: \nBản nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ bản nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát.",
    [1888919950] = "Thực hiện một <b>Tấn Công Lén Lút</b> bằng cách lẻn đến một kẻ địch không cảnh giác và nhấn <b>%k</b>.\n\n<b>Tấn Công Lén Lút</b> gây thêm <b>+900%%</b> sát thương.",
    [1888986304] = "Thịt Chim Nướng",
    [1889435529] = "Một loại bột mịn được làm từ các bộ phận của sinh vật.",
    [1889659390] = "Đảo Ngược Trục Y",
    [1889824609] = "Hẹn gặp lại!",
    [1889967825] = "Sữa",
    [1890292800] = "Đến Và Tìm Kiếm Nơi Nghỉ Ngơi Của Thuyền Trưởng",
    [1890546096] = "Bạn đã đến địa điểm đầu tiên có lửa thiêng.\n\n<b>Tiếp cận ngọn lửa trên đỉnh tháp ở cuối đồn và thắp sáng nó để tiếp tục!</b>",
    [1890741088] = "Quần Hoàng Gia",
    [1892187154] = "Ăn Diện Để Gây Ấn Tượng",
    [1892610673] = "Trang Trại Dê Fairfield",
    [1894259576] = "Mặc dù có vẻ ngoài thiên thần, chú mèo màu quế ngọt ngào này là một kẻ nghịch ngợm vui vẻ thích gây rắc rối! Tuy nhiên, bạn không bao giờ có thể quá tức giận. Chỉ cần nhìn vào đôi mắt xanh sapphire tuyệt đẹp đó!",
    [1894354609] = "Có Thể Hoàn Tiền",
    [1894433323] = "Quần da bình thường.",
    [1894719816] = "Một Lời Cầu Nguyện Được Đáp Lời",
    [1895275492] = "Người Băng",
    [1895735072] = "Hồi Phục HP",
    [1895866075] = "Sát thương chống lại Scavenger",
    [1896231058] = "<craftingstation>Khung Cửi</craftingstation> Cho Giáp Đệm",
    [1896493732] = "Tìm Quả Bóng Vàng Dưới Nước",
    [1896966823] = "Tìm Kiếm Tiền Đồn Bỏ Hoang",
    [1897391731] = "Quần thoải mái cho những chuyến đi dài.",
    [1897855744] = "Tìm Khối Đá Cát Hỗn Hợp",
    [1898007950] = "Có màu như kim loại gỉ, đá phiến và đồng.\n\nBảng màu này có thể được tạo ra từ vật liệu Kindlewastes.",
    [1898522189] = "Griffin Bamford",
    [1899038102] = "Hannah Reed",
    [1899064116] = "Một miếng thịt béo, mềm, sống. Nó chưa được nấu chín, do đó không thể tiêu thụ.",
    [1899267414] = "Uống",
    [1899308900] = "Kệ Gỗ Phương Bắc",
    [1899620765] = "Găng Tay Chiến Binh Rắn",
    [1899681764] = "Một đôi quần chắc chắn sẽ đưa bạn đến bất cứ nơi nào trái tim mong muốn.",
    [1900404177] = "Chọn Bài Hát",
    [1900640107] = "Kẻ Ngắm Sao Cao Nguyên Du Mục",
    [1901144838] = "Ấm Áp - Ngọn lửa",
    [1901721627] = "Nhấp một ngụm trà nóng sẽ khơi dậy dòng chảy sáng tạo của tôi, tôi biết chắc mà!",
    [1901755919] = "Thật hấp dẫn, phải không?",
    [1901978078] = "Sử Dụng Kẹp",
    [1902638095] = "Đói",
    [1902682550] = "Găng Tay Trưởng Lão",
    [1903080185] = "Aye, nhóc con! Lại đây! Ta có chuyện muốn kể cho ngươi nghe!",
    [1903381862] = "Tải máy chủ cao:",
    [1903759601] = "Tủ Hầm Mộ Lớn",
    [1903802057] = "Găng Tay Đạo Sư Băng Ngọc",
    [1904086934] = "Hỡi người bạn được Ngọn lửa ban phước, ta phải đề xuất một nhiệm vụ. Chắc chắn... chắc chắn ngươi cũng ghét chúng. Lũ Cyclops ám ảnh cả những đỉnh cao nhất và những vực sâu thẳm nhất. Ta muốn xương của chúng, dựng trên một bệ nhỏ, trắng bóng, tinh khiết như phấn. Lột sạch thịt và tội lỗi. Ngươi đã xoa dịu cơn giận bừng cháy của ta trước đây, nên ta chắc chắn ngươi có thể làm được điều đó một lần nữa.",
    [1904833679] = "Tìm Kiếm Trong Ngọn Hải Đăng",
    [1905059348] = "Đôi găng tay đen và vàng này từng nắm giữ kiến thức và bí mật của loài người. Đừng để bị choáng ngợp bởi sức mạnh mà chúng từng nắm giữ.",
    [1905072954] = "Trọng Kiếm Đêm Bạc",
    [1905451891] = "Những kẻ khốn nạn, du côn và kẻ ác trong quá khứ thường sử dụng những lưỡi kiếm tương tự. Có lẽ vũ khí này được rèn trong bóng tối của một con hẻm và đổi chủ trên thị trường chợ đen.",
    [1905595684] = "Lượng HP Chữa thương từ phép hồi HP tăng thêm <b>10%</b>.",
    [1905610341] = "Chùy Bậc Thầy",
    [1905947454] = "Cân Bằng",
    [1906072408] = "Cung Kẻ Xuyên Thủng Sa Ngã",
    [1906088017] = "Được sử dụng trong ba lô, kho chứa, trang bị và một số trạm chế tạo",
    [1906647853] = "Đuốc Đứng",
    [1907445091] = "Trái Cây",
    [1907541164] = "Những tông màu xanh lá đậm, phong phú gợi lên hình ảnh rừng rậm và lùm cây bạn phải điều hướng. Một chút đỏ được thêm vào, giống như những bông hoa gừng đỏ xuất hiện ở đây đó, phá vỡ biển xanh.\n\nBảng màu này có thể được tạo bằng vật liệu từ Bồn Nước Màn Che.",
    [1907787839] = "Nấm",
    [1907860003] = "Bộ Trang Phục Nhà Thám Hiểm",
    [1908203599] = "Đá Hầm Mộ",
    [1908424321] = "Đánh bại kẻ địch để khôi phục Độ bền",
    [1908686705] = "Bạn đã đặt con mèo vào nhà! Bây giờ hãy chế tạo <b>một bát cho mèo và một chiếc giường cho mèo</b> để làm cho thú cưng mới của bạn vui vẻ!",
    [1908828868] = "Thay Đổi",
    [1909149758] = "Mất Trang Bị",
    [1909329686] = "Lời Cuối",
    [1909739078] = "Loại thức ăn đã được kích hoạt",
    [1910440901] = "Một thanh Kiếm dài cũ đã bắt đầu mục nát. Sự tinh khiết của thép đã bị gỉ sét làm mất đi.",
    [1910497691] = "Vật phẩm đã trang bị (xem Menu Trang bị)",
    [1910807874] = "Liều thuốc chữa đó đã có tác dụng kỳ diệu với bạn, bạn của tôi! Trông bạn đã trở lại là chính mình.",
    [1911186824] = "Đồ Hâm Mộ Chính Thức",
    [1911460930] = "Cây đũa phép này ẩn chứa một lõi băng hiếm bên trong, cho phép chủ nhân tung ra ST Băng cực lớn vào kẻ thù.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sát thương đầu ra của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.\n\n<b>Đa Đạn:</b> \nBắn nhiều loạt đạn nhưng với sát thương giảm.",
    [1911932788] = "Đòn chí mạng với ST Cắt gây ra hiệu ứng <img gemeffect_bleeding> chảy máu cho kẻ địch, gây %k sát thương mỗi giây trong %k.",
    [1911986904] = "Một mũi tên tiên tiến với đầu bằng đồng.",
    [1912172491] = "Hiển thị trống",
    [1912660030] = "Một bữa ăn đơn giản, mang lại hiệu ứng tăng ST Cận chiến kéo dài khi tiêu thụ. Tuy nhiên, nó ngon hơn khi kết hợp với những thứ khác.",
    [1913566152] = "Ngọn Lửa",
    [1914427745] = "Máu Ăn Mòn",
    [1914496366] = "Găng Tay Trọng Kiếm",
    [1914721479] = "Thay thế khả năng Lăn Né bằng một dịch chuyển tầm ngắn.",
    [1915541923] = "Kính",
    [1915549602] = "Hẹn gặp lại.",
    [1915603887] = "Chậu Cây Rỗng VII",
    [1915685755] = "Một đôi quần ống rộng màu đen than. Hình dáng rộng rãi hơn bắt nguồn từ lớp đệm len dày bên trong.",
    [1916219535] = "Vũ Khí Thách Đấu Sảnh Đường Hollow",
    [1916600044] = "Bạn đã đến lối vào Đền Thờ Mặt Trời Ma Ám. Bây giờ là lúc bước vào và giải lời nguyền! Tìm bất cứ thứ gì đang ám ảnh Đền Thờ Mặt Trời Ma Ám và đánh bại nó!",
    [1916728742] = "Bể I",
    [1916901964] = "Chiếu Chỉ Hoàng Gia",
    [1916923569] = "Bình Đền Drak VI",
    [1917318113] = "Ngôn Ngữ Vukah",
    [1917341247] = "Thêm Máy Chủ",
    [1917870618] = "Một loài cá bóng bẩy với vây vàng rực rỡ, còn được biết đến với khả năng tăng tốc đột ngột.\n\nLoài cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [1918309829] = "Cột Đá Cổ Đại",
    [1918537722] = "Họ gọi thứ này là \"Băng Giá Sương Độc Bao Phủ\"? Tuyệt vời. Nó không tan chảy hay mất hình dạng, và nó mãi mãi nhuốm màu xanh ngọc lam... đang thở này. Thiên tài! Tất nhiên là màu ngọc lam! Được rồi, đến lúc cất băng giá sương độc bao phủ này đi. Nó sẽ không phải là một bổ sung tốt cho trà của tôi - và tôi cần trà của mình để tập trung, bởi vì thân mến, tôi sắp pha chế màu sắc sảng khoái nhất thế kỷ!",
    [1918938349] = "Mở khóa công thức bằng cách thu thập vật phẩm và tích lũy kiến thức.",
    [1919662600] = "<i>Cạch cạch, cạch cạch</i> — Bạn có thể nghe thấy tiếng gót giày cao của cô ấy từ xa hàng dặm, đâm xuyên mặt đất với âm thanh dồn dập không ngừng. Khi bước chân cô ấy nhanh hơn, nhịp thở của bạn cũng vậy. Đừng để bị cuốn vào đường đi của cô ấy.",
    [1919712339] = "Tốt. Ngay cả một công cụ nhỏ bé cũng nắm giữ sức mạnh để tạo ra phương thuốc... hoặc chất độc. Hãy chế tạo một số trang bị tốt hơn.",
    [1920350377] = "Tất cả các công cụ mất độ bền <b>50%</b> chậm hơn.",
    [1920586591] = "Một Mùa Mới",
    [1920620096] = "Con cá đã mạnh hơn.",
    [1921122485] = "Màu vàng của hoa được bảo quản dưới dạng bột.",
    [1921460989] = "Một bộ sưu tập các công cụ — trái tim của mọi lò rèn.",
    [1921843767] = "Hàm Răng",
    [1922218137] = "Bộ Trang Phục Hiền Giả",
    [1922785506] = "Một phần của Bộ Giáp Thợ Săn.",
    [1923062225] = "Bạn đã tìm hiểu về một thuyền trưởng già. Có lẽ người này sẽ lý tưởng để dẫn dắt bạn vượt qua vùng nước xa lạ và những nguy hiểm ẩn giấu bên dưới.\n\nThuyền trưởng thường xuyên đi đến một hòn đảo gần đó. <b>Hãy đến hòn đảo và tìm kiếm tàn tích của một linh hồn thuần khiết ở đó!</b>",
    [1923212309] = "Một lọ MP có nồng độ cao hơn, ngay lập tức phục hồi một lượng lớn MP khi sử dụng.",
    [1923450716] = "Trên Đường",
    [1923852908] = "Luôn là một niềm vui!",
    [1923902076] = "Hãy cho tôi biết bạn cần gì.",
    [1924783477] = "Sương độc đã xé nát Embervale. Giờ thì ngươi đã đưa ta trở lại sự sống, ta thậm chí còn không nhận ra nơi này. Hãy thử nhìn rõ hơn từ đỉnh Tháp Cổ xưa kia. ",
    [1924862841] = "Khi tôi cho rằng việc ở lại qua đêm tại công trường xây dựng là khôn ngoan, tôi đã lầm.\nTôi đã làm việc cật lực, tự mình vác những thanh gỗ rất lâu sau khi những người khác đã rời đi. Vua <lorename>Gormander</lorename> muốn hoàn thành tòa tháp này trước khi quân đội phương Bắc sụp đổ... Tôi đoán nó sẽ không thay đổi nhiều, nhưng không phải là việc của tôi để lên tiếng.\n\nTrong một khoảnh khắc nghỉ ngơi ngắn ngủi, tôi đã ngủ gật. Điều xảy ra tiếp theo hoặc là một giấc mơ hoặc là một lời cảnh báo. Mặt đất rung chuyển. Một rung động sâu, nhịp nhàng và xa xăm, vang vọng vào tai tôi và vọng qua đầu tôi như một cơn sóng thần.\n\nNgày mai tôi sẽ ở lại. Tôi phải xác nhận rằng đó chỉ là một giấc mơ.",
    [1925021674] = "Ngôn Ngữ",
    [1926186474] = "Một cây cung thực tế và nhanh chóng làm từ gỗ thông mộc mạc. Độ căng của nó yếu, vì vậy sử dụng nó đòi hỏi ít SP.",
    [1926381685] = "Tìm kiếm trang phục ăn mừng của bạn đã dẫn bạn đến một tàn tích đền thờ.\n\nKhám phá cấu trúc để có được các vật phẩm trang trí!",
    [1926393637] = "Bộ Trang Phục Vệ Sĩ Đen",
    [1926823378] = "Vào Và Lấy Đồ Từ Căn Phòng Khóa",
    [1927054710] = "Trượng Bay Hơi",
    [1927185094] = "Một nguyên liệu được sử dụng trong các công thức chế tạo.",
    [1927710634] = "Cửa hàng của <lorename>Ikora</lorename> trống rỗng, và <location>Rattlebleak</location> tràn ngập những bức tượng kỳ lạ, hóa đá. Có lẽ điều này liên quan đến <b><lorename>Ikora</lorename>'s thí nghiệm với <craftingstation>Nồi Đen</craftingstation></b>. Đi theo dấu vết của những bức tượng có thể dẫn đến chỗ bà ấy.",
    [1928381530] = "Khi chúng tôi tìm thấy nơi trú ẩn khỏi cơn bão tuyết ở đây, chúng tôi chỉ đơn giản là vui mừng vì có nơi trú ẩn. Những mỏm đá bên trái và bên phải trông giống như những kiến tạo đá qua làn gió mờ ảo. Chỉ đến bây giờ tôi mới nhận ra rằng chúng tôi không bị bao quanh bởi đá, mà là xương sườn.\n\nNhững xương sườn thật, khổng lồ, được bảo quản tốt, màu ngà — nằm giữa một bộ 6 chi. Chúng tôi quyết định định cư và lấy mẫu, chủ yếu vì Fran rất vui mừng được nghiên cứu bộ xương. Cô ấy gọi nó là \"Ony\" vì <i>\"các chữ cái trông giống như một loài động vật có đuôi với 6 chi, cúi mình để uống.\"</i>\nCô ấy đang cười toe toét trong khi phủi bụi khỏi sụn, nhưng tôi hầu như không thể nhìn cô ấy. Những vết sẹo trên mặt cô ấy vẫn còn mới, và tôi sợ rằng đó là lỗi của tôi. Có lẽ tôi đã tự mình làm sẹo mặt cô ấy. Có lẽ để cô ấy ở lại sẽ cho phép tôi chuộc lỗi.\n\n— <lorename>Loraine Crim</lorename>",
    [1928393170] = "Nếu bạn đã nhìn thấy tôi quanh quẩn, bạn có thể nhận thấy rằng tôi đã thay một bộ quần áo mới! Hãy nhìn những màu sắc này — bạn chỉ có thể có được sự rực rỡ này từ Cao Nguyên Du Mục. Có lẽ bạn có thể tìm thấy nhiều hơn nếu bạn nhìn! Có rất nhiều tiền đồn bỏ hoang vẫn còn đầy hàng hóa!",
    [1928790801] = "Hỡi Hỏa Sinh, lại đây! Chúng ta nên làm một sở thú thú cưng!",
    [1929141211] = "Tăng sát thương lên Scavenger.",
    [1929513050] = "Khối Tường 1m",
    [1930071615] = "Một viên ngọc màu xanh lam, một cái chắn cong và một cạnh được trang trí bằng hoa văn vàng tô điểm cho thanh kiếm này. Tất cả trong tất cả, nó vừa đẹp vừa chết chóc.",
    [1930537057] = "Giếng Nước",
    [1930616658] = "Cao Nguyên Du Mục",
    [1930659553] = "Chế Tạo Hoặc Nhận 3 Mồi Dê Từ Người Nông Dân",
    [1931413348] = "Hồi %k SP mỗi 5 giây.",
    [1931609206] = "Thay đổi hành động biến đổi địa hình khi vật phẩm này được chọn.",
    [1931958666] = "Ta biết chúng ta sẽ hợp nhau!",
    [1932126489] = "Cái <craftingstation>Con quay tay</craftingstation> thất lạc của ta — nó hẳn phải ở trong <b>Rừng Rừng</b>, gần nơi ta nghỉ chân lần cuối. Đi đi! Cùng nhau, chúng ta có thể đánh bại mọi khó khăn với <b>trang bị</b> tốt hơn!",
    [1932469638] = "Kiếm Rực Lửa",
    [1932728555] = "Đặt nhân vật",
    [1933040701] = "Còn nhiều vật phẩm trang trí ẩn giấu trong Rừng Rừng. Nếu bạn đã ghé thăm The Pike, bạn có thể cân nhắc ghé thăm địa điểm đó một lần nữa.",
    [1933066058] = "Hãy hoàn thành nó.",
    [1933439340] = "Tiếp cận Đền Thờ Mặt Trời Ma Ám",
    [1933537998] = "Thanh kiếm này chém xuyên không khí như một tiếng hú sắc bén lúc nửa đêm.",
    [1933551374] = "Tiếp cận Cột Sáng Tạo",
    [1933902234] = "Cầu Lửa II",
    [1933962119] = "Chúng ta đã đến <location>Rookmore</location>. Cuối cùng cũng thoát khỏi Vùng Đất Bị Che Phủ. Đó là một hành trình khó khăn từ những ngọn núi. Ta đã hy vọng có một bệnh viện dã chiến ở đây... nhưng hầu như không có gì. Ta phải tự mình giải quyết, như ta đã làm ở tiền tuyến. Ta sẽ dựng trại ở <b><location>Woodgard</location></b>.",
    [1933993775] = "Hiển thị Hướng dẫn",
    [1934200027] = "Dừa",
    [1934398874] = "Thêm Tăng Cường",
    [1935083298] = "Cơm Rang",
    [1935454291] = "Một loại vật liệu làm đường làm từ đá vôi. Nó nhẹ hơn và có tông màu ấm hơn nhiều so với các vật liệu làm đường tương tự.",
    [1935846623] = "Khiên Sa Ngã",
    [1936051025] = "Găng Tay Bò Tót Đồng",
    [1936092116] = "Đuốc Đứng",
    [1936311363] = "Cuối cùng cũng trở về! Ta là một thợ rèn khiêm tốn, sẵn sàng phục vụ. Hãy chuẩn bị cho ngươi những gì sắp tới.",
    [1936666757] = "Buff",
    [1936673813] = "Trò chuyện Văn bản",
    [1936987488] = "Phép thuật",
    [1937284975] = "Bữa Ăn Cuối Cùng",
    [1937471943] = "Khiên Anh Hùng",
    [1937863356] = "Đèn Gắn Tường Màu Cam II",
    [1938109334] = "Theo phong tục ở miền Bắc xa xôi, người ta mang người chết đến mộ trong khi vung vẩy một cây chùy thép. Sự thể hiện sức mạnh kiên cường này trước cái chết và sự kinh hoàng sẽ xua đuổi tà ma và dẫn dắt người chết an toàn đến Phương Bắc của thế giới bên kia.",
    [1938328006] = "Phóng To",
    [1938858724] = "Mồi Thức Ăn Cho Chó",
    [1938990335] = "(Giữ) Xóa",
    [1939515481] = "Ta để mắt đến ngươi! Ha!",
    [1939635080] = "Bảng Thông Báo",
    [1939753029] = "<lorename>Talion</lorename>",
    [1940084068] = "Tân Binh Bí Ẩn",
    [1940087803] = "Tượng Đầm Lầy Đen VI",
    [1940091230] = "Ngai Vàng Cát",
    [1940111252] = "Điều tra Tuyến Vận Chuyển Mật Ong",
    [1941153725] = "Còn gì nữa?",
    [1941693318] = "Cửa Tròn Chạm Khắc",
    [1942298414] = "Một ghi chú tiết lộ rằng một vị khách bí ẩn đã ghé thăm một ngôi mộ Sương độc bao phủ gần đó ở Dãy Alps Albaneve. Họ trông có vẻ nửa sống nửa chết.\n\nTìm ngôi mộ và nhìn vào bên trong!",
    [1943370821] = "ST Phép",
    [1946113877] = "Nấu ăn là một nghệ thuật tinh tế. Món súp cơ bản này sẽ giúp bất kỳ ai trên con đường trở thành một đầu bếp xuất sắc.",
    [1946156030] = "Thay Đổi Vật Liệu Xây Dựng",
    [1946246567] = "Cuối cùng, một chút nghỉ ngơi khỏi công việc tẻ nhạt. Xương cốt ta đau nhức... nhưng <b>hơi ấm của lửa, một chút nơi trú ẩn và giấc ngủ</b> sẽ cho phép ta <b>nghỉ ngơi đầy đủ.</b> Thực phẩm ngày càng khan hiếm... Ta nghe nói họ đang lên kế hoạch cho một chuyến thám hiểm. May mắn thay, ta đã giấu một ít khẩu phần dưới giường. Chúng sẽ tạo thành một bữa ăn ngon khi <b>nấu trên lửa.</b>",
    [1946694099] = "Thuốc Tiên",
    [1946722745] = "Mũi Tên Gỗ",
    [1947385378] = "Đánh khi sắt còn nóng!",
    [1947685653] = "Áp Dụng Thay Đổi",
    [1947908660] = "Kẻ Dạo Bước Vực Thẳm",
    [1948039569] = "Cốc Đồng Thiếc",
    [1948683328] = "Cao Nguyên Du Mục",
    [1948977911] = "Một cái đầu Cyclops bị chặt đứt, vẫn còn đội mũ bảo hiểm, mặc dù giờ đây điều đó chẳng còn cần thiết nữa.\n\nThu thập nhiều Đầu Cyclops để chế tạo Cúp.",
    [1949081840] = "Cầu Lửa Vĩnh Cửu I",
    [1949313965] = "Trang Trại Cá",
    [1949371968] = "Giao diện Người dùng",
    [1949799312] = "Một đôi ủng được bao phủ bởi lớp vảy bạc. Mắt cá chân của bạn sẽ an toàn với chúng.",
    [1950238011] = "Cờ Lệnh Chiến Tranh Của Vorgoth I",
    [1950243898] = "Vật Bất Di Dịch",
    [1950278359] = "Tìm thấy ở Cao Nguyên Du Mục, vào ban đêm",
    [1950936023] = "Hy vọng ngươi sẽ trở lại!",
    [1951162618] = "Chiếu Sáng Ban Đêm",
    [1951356454] = "Đàn Luýt",
    [1951523043] = "Địa Điểm Cuối Cùng Của The Honeydews",
    [1951655628] = "Nhiệm Vụ Hậu Duệ Lửa",
    [1951888778] = "Ngọn Lửa đã thông báo cho bạn về một sự xáo trộn ở vùng nước lân cận. Những vùng đất mới chưa biết cần sự giúp đỡ của bạn — nhưng để hiểu mối đe dọa đang hoành hành bờ biển, bạn sẽ cần sự giúp đỡ.\n\n<b>Đầu tiên, bạn phải đến được lối đi dẫn vào thung lũng mới mở!</b>",
    [1952089825] = "Hệ Thống",
    [1952108311] = "Ruồi Lửa",
    [1952330574] = "Cà Phê Đen",
    [1952739341] = "Mũi Tên Phế Liệu",
    [1952884755] = "Cú đỡ đòn của bạn đánh kẻ địch gây <b>20 sát thương Đập</b>. Sát thương <b>Đập</b> được tăng cường bởi thuộc tính Sức mạnh của bạn.\n\n<b>Đỡ đòn</b>\nKhi trang bị Khiên, một pha chặn đúng lúc sẽ <b>đỡ đòn</b> tấn công.",
    [1953042883] = "Viên Thuốc Súng Đen",
    [1953111356] = "Ruồi Lửa",
    [1953220917] = "Có quá nhiều thứ màu xanh lá cây, và giờ tóc bạn cũng có thể như vậy! Thật là một ngày vui vẻ!",
    [1953227924] = "Tìm Bộ Trang Phục Đầy Đủ Học Giả Ngọn lửa Trẻ",
    [1953473674] = "Bộ Trang Phục Thợ Săn",
    [1953965742] = "Khăn Trùm Đầu Thầy Thuốc",
    [1954654045] = "Mũ Trùm Thiện Xạ",
    [1954829185] = "Ô Hành Động 7",
    [1955267339] = "Hạt Cà Phê Rang",
    [1955556840] = "Nhà Sưu Tầm đã giao cho bạn một nhiệm vụ. Sảnh Hollow Revelwood ẩn giấu 3 cổ vật ma thuật bên trong. Hãy tìm chúng để trưng bày trong căn cứ của bạn!\n\nCó nhiều vị trí ẩn cho các cổ vật. Hãy tìm kiếm những lối đi bí mật và để mắt tới!\n\nVị trí của Sảnh Hollow Revelwood sẽ xuất hiện trên bản đồ của bạn khi bạn tìm thấy nó thông qua khám phá hoặc chấp nhận nhiệm vụ Nhà Sưu Tầm tiếp theo. Nhiệm vụ sau sẽ có sẵn khi bạn đạt đủ cấp độ.",
    [1955826202] = "Khúc Cường Âm Gió Lốc",
    [1955859682] = "Một lõi sắt nằm ẩn bên trong vỏ lưỡi kiếm, ló ra từ những tấm màn bạc trên mặt phẳng của lưỡi kiếm.",
    [1956276775] = "Thủy tinh vỡ vụn tạo ra nhiều cạnh sắc dùng để nâng cấp vũ khí.",
    [1956688826] = "Công Thức Được Mở Khóa!",
    [1956977417] = "Menu Chính",
    [1957018647] = "Giữ",
    [1957027559] = "Khối Mái Lá Cọ",
    [1957336616] = "Đặt lại phím",
    [1957626018] = "Kho Xe Ngựa Bị Cướp Phá",
    [1957840314] = "Đòn đánh trúng kẻ địch sẽ áp dụng một dấu <img gemeffect_corruption> Hủ hóa có thể cộng dồn tối đa 5 lần. Kẻ địch bị đánh dấu sẽ phát nổ khi không còn dấu <img gemeffect_corruption> Hủ hóa nào được thêm vào trong %k hoặc nếu kẻ địch chết. Vụ nổ gây %k ST Sương độc trong bán kính 1m. Mỗi cộng dồn thêm 0,5m và %k sát thương cơ bản vào vụ nổ.",
    [1958189082] = "Chế Tạo Hoặc Nhận Mồi Câu Capybara",
    [1960224515] = "Bùng Nổ Sự Sống",
    [1960652201] = "Bồn Nước Hoang Dã",
    [1960808576] = "Xóa Tìm Kiếm",
    [1960913024] = "Rơi Tự Do",
    [1960996955] = "Ta đang đứng ngay trước lối vào, cố gắng thúc đẩy bản thân tiến lên. Đi đi lại lại, nhưng ta không thể làm được.\nCũng như những loài cây phát sáng đó mê hoặc ta — Sương độc cũng làm ta sợ hãi.\nVà không chỉ có Sương độc — không khí có vẻ đặc quánh một thứ gì đó ta không thể gọi tên.\nCó lẽ ta đã tình cờ đến một Hang ổ Hắc ám.\nTa đoán ta sẽ không bao giờ biết được nó có gì để cung cấp.\nCó lẽ ai đó dũng cảm hơn ta sẽ dám bước vào.",
    [1961667870] = "Kẻ Đi Bộ Mạnh Mẽ",
    [1961991909] = "Mũ Nữ Hầu",
    [1962219713] = "Tiếp cận Trại Du Mục Tiếp Theo",
    [1962262709] = "Máng Ăn Cho Chim",
    [1962617355] = "Kế hoạch đã thay đổi, Filbert. Ta không thể lấy cây Gậy phép cho ngươi mà không bị lính canh để ý. Tờ giấy nhỏ này là tất cả những gì ta có thể để lại cho ngươi.\n\nChúng đã thay đổi lộ trình, nên ta đã thích nghi. Ta đã giấu chiến lợi phẩm từ xe ngựa của thương nhân <b>dưới ngôi nhà lớn cạnh kênh đào.</b>\n\nNếu ngươi muốn hàng hóa, ngươi sẽ phải tự lấy. Đừng để bị bắt trên đường đi! Và đừng rơi xuống nước. Dòng chảy dạo này thật nguy hiểm...\n\nNhân tiện, ta đã tìm được người mua thanh kiếm. Sẽ gặp họ vào đêm mai. Hãy đến gặp chúng ta ở phía bên kia <location>Willow Crush</location> nếu ngươi muốn có mặt trong thương vụ.",
    [1963344317] = "Tất cả những gì ta yêu cầu chỉ là một căn phòng — thậm chí không cần đồ ăn! Ta có thể tự làm những thứ đó. Hiểu chứ?",
    [1963553201] = "Eureka! Một cỗ máy xay sẽ giúp ích cho chúng ta rất nhiều. Quan trọng nhất, nó sẽ giúp ích cho cái lưng tồi tệ của ta. Cảm ơn!",
    [1963597801] = "Đầu bếp",
    [1963764541] = "Điểm Giáp Phép Thuật",
    [1964056832] = "Rất Dễ",
    [1964468097] = "Tức thì hồi phục nhiều HP, và hồi HP liên tục trong 10 giây.",
    [1965689420] = "Bàn Tiệc Mộc Mạc",
    [1965962464] = "Các cạnh của lưỡi kiếm này bị khía và do đó giống như những vết cắt được tạo ra bởi vây sắc như dao cạo hoặc hàng răng cá mập.",
    [1966441650] = "Dọn sạch mọi rễ cây Sương độc khỏi Rừng Khải Hoàn.",
    [1966815733] = "Bát Bạc",
    [1966891595] = "\"Tĩnh Vật\"",
    [1967007878] = "Nhiệm Vụ Giải Cứu Scavenger",
    [1968125122] = "Vũ Khí Có Sẵn",
    [1968147558] = "Áo Chẽn Lông Xù",
    [1968454609] = "Gửi Em Gái Sophie",
    [1968721469] = "Tia Chớp Vĩnh Cửu",
    [1969032259] = "Bạn đã tìm thấy một cuốn sách truyền thuyết đề cập đến hai thanh kiếm Ngọn lửa song sinh đã Fell vùng núi từ các vì sao.\n\nCuốn sách đề cập rằng một thanh đang ngủ yên trong một hang động. Hãy đến đó và tìm kiếm thanh kiếm!",
    [1969174301] = "Kiên cường và không thể lay chuyển, cây Gậy phép này giống như thành trì hy vọng cuối cùng của vương quốc.",
    [1969240023] = "Bạn có thể sử dụng các phím tắt để sắp xếp kho đồ và chuyển vật phẩm nhanh chóng.",
    [1970239988] = "Chúng ta sẽ làm gì với tất cả những tù nhân này!?\n\nTa có một ý tưởng: Chúng ta đang thiếu lương thực và nhiên liệu cho lửa. Nghe có vẻ là một vấn đề có thể giải quyết, phải không?",
    [1970321202] = "Khối Phát Sáng Vàng",
    [1970531326] = "Tìm Tất Cả Công Thức Chế Tạo Trong Sảnh Đường Hollow",
    [1970773921] = "Hoa Bóng Tối",
    [1972002447] = "Tìm Kaori Conway",
    [1973141360] = "Tìm <npc>Thợ Mộc</npc>",
    [1973188069] = "Thảm Lông Thú",
    [1973626290] = "Đố Ta Đi",
    [1974452187] = "Cọp",
    [1974690206] = "Cung Sương độc bao phủ",
    [1974930797] = "Sức mạnh của những viên đá quý này không giống bất kỳ phép thuật thông thường nào, vậy mục đích của chúng là gì? Chà, Người Cổ Đại đã nghiên cứu các nguồn năng lượng tự nhiên như dung nham và lửa để cung cấp năng lượng cho các cấu trúc của họ. Có lẽ những viên đá quý này là một loại \"lưu trữ\" năng lượng — những vật chứa có lực hút từ tính bám vào năng lượng tự nhiên chảy xung quanh chúng, ghi nhớ nó, được định hình bởi nó... Nhưng phát minh vĩ đại nào lại cần \"nhiên liệu\" mạnh mẽ như vậy?",
    [1974930888] = "Phong cách có mục đích!",
    [1974974969] = "Trái Cây",
    [1975138289] = "Một nhạc cụ thiên đường, trước đây thuộc sở hữu của Harper Langley của The Honeydews. Thân đàn có hoa văn chạm khắc tuyệt đẹp gợi nhớ đến chiếc đuôi cá của nàng tiên cá, phù hợp với hình ảnh nàng thơ của Harper.",
    [1975139649] = "Săn Tóc: Xanh Lá Rùng Rợn",
    [1975454390] = "Bản Phác Thảo",
    [1975552371] = "Đền Ngọn lửa",
    [1975619718] = "Nhựa Cây",
    [1975730324] = "Bắt đầu một trò chơi riêng, lưu cục bộ",
    [1975894352] = "Bạn đã lấy lại quần áo của tôi! Cảm ơn, nhưng... trên đó vẫn còn nhện không? Không? Chắc chứ? Thực ra, tại sao bạn không giữ chúng đi? Cứ giữ lấy. Giữ lấy. Và... cất chúng thật xa tôi.",
    [1975980226] = "Kích Thước Phiên Chơi: %k người chơi",
    [1976004343] = "Cài Đặt Trò Chơi",
    [1976234806] = " <npc>Thợ Rèn</npc> nhìn thấy tiềm năng ở <npc>Nhà Sưu Tầm</npc>, đồng minh mới mà bạn cùng chia sẻ.\n\nÔng ta tự hỏi về mối liên hệ của họ với sự sống và cái chết và hy vọng họ có thể mang mọi người trở lại sự sống.",
    [1976358094] = "Chọn Nhân Vật",
    [1976424278] = "Chúng ta hoàn toàn đơn độc trong cái hố hoang tàn này! Họ đã BỎ RƠI CHÚNG TA để mục ruỗng trong xà lim... hy vọng tất cả họ sẽ chết vì bụi bặm!! Và cả ta nữa — TA! Ta đã nói ta VÔ TỘI!\n\nSẽ có hỗn loạn nếu không có BÀ TA. Họ gọi bà ta là quản giáo, <lorename>Lupa</lorename>. Ngay cả những con chuột hung hãn nhất cũng rên rỉ khi bà ta bước đến gần — bà ta phun ra khi nói. Chất lỏng rỉ ra từ môi bà ta, có tính axit và độc hại. Luôn có một chút mùi ethanol trong không khí...\n\nBà ta có một kế hoạch. Không thể phá cổng, nhưng.... những bức tường Hollow, bà ta nói — một cái hang phía sau xà lim của bà ta. Bà ta có <i>sự giúp đỡ từ bên ngoài... nghe nói có một người chị em.</i> Có lẽ chúng ta có thể đột phá!",
    [1976435095] = "Vị Trí <npc>Thợ Rèn</npc>",
    [1976606390] = "Nhật Ký Cảng — Ghi Chú Cá Nhân",
    [1976619745] = "Chiếc quần thoải mái và giản dị này rất phù hợp cho các học viên muốn có kinh nghiệm phiêu lưu thực tế.",
    [1976730150] = "Cúp Danh Năng Hộp Sọ Quý Giá",
    [1976954524] = "Sữa Hươu Tiên Nấu Chín",
    [1977245550] = " <npc>Thợ Săn</npc> muốn một ít Lông Động Vật, như một bài kiểm tra kỹ năng. ",
    [1977262406] = "Bộ Phận Bọ",
    [1977560761] = "Hệ thống thoát nước của hồ bơi lại gặp trục trặc. Mỗi khi tôi cố gắng hạ mực nước, dòng chảy phải mất một thời gian dài mới lắng xuống... Giống như các đường hầm bên dưới lại bị chặn.\nTôi đã tự nhủ sẽ gọi kỹ thuật viên, nhưng nói thật, tôi đã trì hoãn. Những người đàn ông bám lấy hồ bơi đó như thể đó là mảnh ghép cuối cùng của ngôi nhà mà chúng tôi có ở đây. Lấy nó đi, ngay cả để sửa chữa, cũng sẽ làm giảm một nửa tinh thần.\n\nTuy nhiên... có điều gì đó không ổn. Một âm thanh, trầm và liên tục, như đá dịch chuyển dưới mặt nước. Chắc là một tảng đá hoặc một con chuột chết, va vào đường ống. Chắc là không có gì. Chỉ là sỏi trong bộ lọc thôi, tôi cá là vậy. Nhưng mỗi đêm, khi tiếng ầm ầm đánh thức tôi dậy, tôi không thể rũ bỏ suy nghĩ rằng có thứ gì đó ở dưới đó.",
    [1978025926] = "Thang Hàng",
    [1978186315] = "Chọn độ khó này nếu cài đặt \"Khó\" quá dễ dàng. Trong \"Sinh Tồn\", bạn sẽ nhận được ít XP hơn và có ít HP hơn. Các cơ chế sinh tồn bổ sung như đói được giới thiệu.",
    [1978571564] = "Một bệnh nhân ốm yếu đã hành trình từ <location>Woodgard</location> đến một Đài Thiên Cổ trong Vùng Suối. <b>Hãy đến Đài Thiên Cổ</b> và khám phá những gì bạn có thể tìm thấy ở đó!",
    [1978929926] = "Đĩa Phế Liệu",
    [1979380827] = "Xin hãy nén nước mắt và ngồi lại bên ta. Chúng ta hãy cùng ngắm nhìn thung lũng, như chúng ta đã từng làm. Mặt trời lặn và lá rơi giống như khoảng thời gian ngắn ngủi và quý giá của chúng ta. Hãy cùng chia sẻ những giờ phút này trước khi chúng bị cuốn trôi bởi Sương độc.\n\nLại đây tựa đầu lên vai ta, đóa thủy tiên của ta.\n\nMãi mãi là của ngươi,\nSalim",
    [1979469231] = "Nâng cấp <b>Hào Quang Rạng Rỡ</b> để gây <b>2 sát thương Lửa</b> mỗi Điểm Trí Tuệ. ",
    [1979671802] = "Ngọc Cuồng Chiến",
    [1980284978] = "Không có người nhận nào xung quanh",
    [1980483146] = "Bình thường",
    [1980574461] = "Một con Nai Tiên trưởng thành. Nó thích được vuốt đầu!",
    [1980627840] = "Bộ Điều Khiển",
    [1981534439] = "Sẽ không ai xuyên qua được bạn khi bạn đứng vững trên đôi ủng hoàng gia này.",
    [1981577696] = "Mồi Thức Ăn Hươu Tiên",
    [1982662196] = "Loại gỗ này có từ thế kỷ trước, được tìm thấy bên ngoài lớp vỏ của những cây Blackmire khổng lồ.",
    [1982684344] = "Có thể truy cập rương và nhà máy",
    [1984222758] = "Chậu Cây Nhỏ",
    [1984316167] = "Bất cứ khi nào một đồng minh thu hút sự chú ý của kẻ địch, bạn sẽ thu hút gấp đôi.",
    [1985036949] = "Không có khe trống trong Ba Lô.",
    [1985603943] = "Hoa Treo Tường Màu Hồng",
    [1986028496] = "Bạn có biết rằng từng có một đội cận vệ hoàng gia trung thành với Nữ hoàng <lorename>Pikemead</lorename> trước đây không? Họ được gọi là \"Hoa Hồng Máu\". Sau cái chết của bà, mọi thứ trở nên yên tĩnh xung quanh họ, nhưng tôi nghe nói một nhóm nhỏ đã nổi dậy chống lại Lãnh chúa <lorename>Vorgoth</lorename>. Tôi không biết chuyện gì đã xảy ra với họ, nhưng tôi biết con đường của họ đã dẫn đến đâu. Nếu bạn đi theo dấu vết của họ, bạn chắc chắn sẽ tìm thấy những tàn tích chứng kiến trận chiến của họ.",
    [1986094108] = "Hàng Rào Gỗ Thô Sơ II",
    [1986158167] = "Bảo vệ khỏi ST Cận chiến.",
    [1986494707] = "Quần Pháp Sư Băng Mưa",
    [1986685072] = "Di chuyển lên/xuống",
    [1986827196] = "Tủ Trưng Bày Hóa Thạch (2 Khe Vừa)",
    [1987294010] = "Kích Hoạt Lại Bàn Thờ",
    [1988008192] = "Vòi Sen Của Thủy Thủ",
    [1988187864] = "Hàng Rào Nghĩa Trang Hỏng I",
    [1988274124] = "Chiếc mũ trùm đầu này bao gồm một mặt nạ sắt được lấy cảm hứng rất nhiều từ loài cú.",
    [1989173928] = "Lối Đi Hang Cyclops",
    [1989776016] = "Khám Phá Các Tháp Cổ Đại ",
    [1990182335] = "Tìm Capybara",
    [1990425909] = "Con Đường Đến Thế Giới Bên Kia",
    [1990860665] = "À, ta còn sống? Ta đang ở đâu? BIẾN ĐI, ta có vũ khí đây! À, ta đang đùa ai chứ... ta không phải là lính như cha ta từng là.",
    [1992199630] = "Lớp Da Cháy Bỏng",
    [1992247816] = "Khi đánh chí mạng bằng vũ khí tầm xa, tất cả các chỉ số kháng cự của mục tiêu sẽ bị giảm một nửa.",
    [1992521037] = "Vương Quốc Sao Rơi",
    [1992527822] = "Thanh kiếm từng được Lãnh chúa Vorgoth tin cậy đã bị vứt bỏ trước chiến tranh và thay thế bằng một vũ khí phù hợp hơn với những hành động tàn độc. Nó vẫn giữ một chút tỉnh táo và ánh sáng, tỏa sáng rực rỡ trong bóng tối như Sao Bắc Đẩu.",
    [1992808487] = "Được thiết kế để ngưỡng mộ gạc, cây cung này có hình ảnh uy nghiêm và đáng kinh ngạc.",
    [1993391667] = "Chế tạo tại Thợ Săn",
    [1994612255] = "Chuột Trái",
    [1994797177] = "Những chiếc răng đáng sợ của một con cá không còn đáng sợ nữa.",
    [1995291490] = "Bỏ Tiếng Nói",
    [1995430225] = "Việc mở cánh cửa đến Thánh Địa Đêm khá dễ dàng. Họ không dạy bạn trực tiếp về sự lừa gạt huyền bí tại Học Viện Cromwell, nhưng khu vực thư viện cấm không bao giờ được canh gác... và tại sao lại có khu vực cấm, nếu không phải để cho phép những sinh viên tò mò biến nó thành trọng tâm của các lớp học buổi tối của họ?\n\nTôi ngạc nhiên khi không tìm thấy vũ khí Cổ đại ở đây, nhưng kẻ thù của chúng ta rất xảo quyệt. Nếu những nghiên cứu của tôi đã dạy tôi bất cứ điều gì, vũ khí của họ phải được giấu sau một cánh cửa đêm khác.\n\nHọ đang đánh cược vào việc lãng phí thời gian của chúng ta bằng những câu đố cho đến khi chúng ta cạn kiệt, kéo dài cuộc xung đột... Nhưng tôi dám chắc họ đã không lường trước được một sinh viên tốt nghiệp có sở thích giải mã.\n\nVì vậy, hãy đặt cược tất cả vào màu đỏ.\n\n<i>Darya</i>",
    [1996186614] = "Một luống cày sẽ cho củ Cải đường.",
    [1996803292] = "Da Dày",
    [1997026006] = "Làm tốt lắm! Bạn đã thực sự tìm ra những sinh vật đó đang sử dụng cái gì. Khi bạn đi vắng, Emily không ngừng nói về những bông hoa đam mê màu hồng mọc khắp Thung Lũng Nước Ve. Tôi đoán màu của chúng sẽ hoạt động tốt như màu từ hoa huệ tây. Tôi sẽ thử xem!",
    [1997283832] = "Một cây cung được sử dụng bởi các Chỉ huy của Vệ binh Phương Bắc. Một nguồn năng lượng mạnh mẽ chảy qua người sử dụng, làm tăng nhịp tim và cho phép bắn nhanh hơn.",
    [1997354306] = "Không thể lường trước — Nhân loại thật phù du! Chẳng là gì ngoài một khoảnh khắc ngắn ngủi, một hơi thở đã tan biến, một cái chớp mắt! \n\nThế nhưng — bất chấp bản chất chóng tàn của họ — họ đã tạo ra lửa. \n\nMột Ngọn lửa của riêng mình để soi sáng buổi bình minh đang đến gần.",
    [1997525813] = "Tại Cổng Lâu đài!",
    [1997827178] = "Chào mừng bạn bè!",
    [1998487055] = "Đi theo lũ kền kền về tổ của chúng",
    [1998803445] = "Không cần phải giữ cho đôi ủng này sạch sẽ và gọn gàng. Chúng sẽ nhuốm máu. Đồng đội của bạn sẽ đảm bảo điều đó.",
    [1998930425] = "Lễ Hội Đêm Hollow",
    [1999065440] = "Người chơi",
    [1999332019] = "Đi bộ chậm",
    [1999491779] = "Nhạc cụ hiếm — Trống",
    [1999630868] = "Người thợ cắt tóc vật lộn để nhớ các kỹ thuật cắt tóc và nhuộm màu kể từ khi ông tỉnh dậy. Ông ấy vui lòng nhờ bạn chuyển bất kỳ công thức nào bạn tìm thấy trên hành trình của mình cho ông ấy. \nÔng ấy đã đề cập đến việc ở <location>Pháo đài Kelvin</location> trước khi tỉnh dậy ở \"Thánh địa Đêm\" gần đó. \n\nCó lẽ <location>Pháo đài Kelvin</location> sẽ là một khu vực tốt để tìm kiếm nguồn cảm hứng nhuộm tóc!",
    [1999981008] = "Một cành cây, dù có vẻ tầm thường đến đâu, cũng có rất nhiều tiềm năng. Mọi thứ đều bắt đầu từ đâu đó...",
    [2000250264] = "Lò Cao",
    [2000465571] = "Nhạc cụ",
    [2000494589] = "Không có vũ khí phù hợp.\nNâng cấp hoàn toàn một vũ khí có khe cắm Ngọc khóa để chèn ngọc.",
    [2001431444] = "Túi Nước",
    [2001662246] = "Cửa Kệ Sách Bí Mật Chạm Khắc",
    [2002015221] = "Điều tra điểm dừng thứ tư trên tuyến đường vận chuyển của Kaori để tìm chiếc mũ tiếp theo!",
    [2002382092] = "Trong thời cổ đại, những khối này được sử dụng để xây dựng các hầm ngục và hầm mộ. Ngày nay, chúng ở trong tình trạng tồi tệ, nhưng vẫn phục vụ mục đích của chúng.",
    [2003581017] = "Đến <location>Brightwich</location>",
    [2004160903] = "Vui lòng kiên nhẫn chờ đợi trong hàng. Lưu ý rằng công dân không có lịch hẹn không thể gửi yêu cầu. Xin chân thành cảm ơn sự thông cảm của quý vị.",
    [2004299465] = "Trượng Của Rắn",
    [2004839461] = "Một loại nấm thường được tìm thấy dưới Sương độc.\nNó không ăn được nhưng có thể được chế biến thành các nguyên liệu khác trong chế tạo.",
    [2005075149] = "Bàn Gỗ Đánh Bóng",
    [2005581985] = "Tủ Gỗ Cọ Lớn",
    [2005616187] = "Lẽ ra phải có ai đó đến, nhưng tiền đồn thì trống rỗng. Không ai trả lời lời kêu cứu của tôi. Tệ hơn nữa, tôi nghĩ tôi nghe thấy tiếng gì đó đang lạch cạch bên dưới mình. Ban đầu, <b>tôi nghĩ đó lại là bọn cướp từ cảng phía nam</b> nhưng tiếng động không giống tiếng người.\n\nNghĩ lại, người giám sát đã đề cập đến điều gì đó về Lớp Sương mù đang dâng lên. Có lẽ họ đã đóng cửa khu vực cho đến khi có thông báo mới? Vô ích thôi. Tôi sẽ phải tự cứu mình!\n\nTôi đã di chuyển một trong những chiếc xe chở hàng đến mép sân ga và chất hàng hóa lên đó. Nó không đủ cao để trèo ra, vì vậy tôi bắt đầu xếp những cuốn sách rời lên trên. Tôi đang nhanh chóng hết ánh sáng ban ngày, vì vậy tôi sẽ không cố gắng trèo ra bây giờ. Việc leo lên công trình không ổn định này đã đủ nguy hiểm, ngay cả khi không có Sương độc đang bao trùm.",
    [2005718225] = "Tấn công lén lút cải tiến",
    [2006187419] = "Bạn đã tìm vũ khí của tôi chưa? Tôi không thể cho phép người lạ làm hoen ố sự trong trắng của chúng bằng máu của những kẻ vô tội!",
    [2006231267] = "Phòng chứa đồ cho 40 vật phẩm.",
    [2006269759] = "Nghĩa trang",
    [2006618088] = "Bạn vẫn còn ốm. Bạn nên chế tạo thuốc giải độc!",
    [2006717221] = "Thương nhân Mei tiết lộ rằng vũ khí cuối cùng của Tết Nguyên Đán phải nằm trong một ngôi đền bị lãng quên ở Cao nguyên Du mục. \n\nĐể tiếp tục, hãy đến địa điểm đó và điều tra!",
    [2007262849] = "Khiên",
    [2007285243] = "Trượng Đánh Lừa",
    [2007355010] = "Ngư dân đã nói với bạn về một nơi ẩn náu đặc biệt, được đồn đại là chứa một chiếc rương với trang bị thủy thủ. \n\nTìm nơi ẩn náu mà anh ta đã đề cập! Nơi đó đã được đánh dấu trên bản đồ.",
    [2007727642] = "Khối Kim Loại",
    [2007757218] = "Xoay",
    [2008315845] = "Giá Đỡ Nhạc Cụ",
    [2008546892] = "Mũ Tiệc Đỏ",
    [2008770324] = "Tìm Thương nhân",
    [2008937987] = "Thức Ăn Chuột Lang Nước",
    [2009385696] = "Chất lượng FSR3",
    [2010902820] = "Tất cả những món ăn và thuốc bổ này... Chắc hẳn phải có cách tốt hơn để tránh chết đuối khi lặn!",
    [2011096555] = "%k × %k",
    [2011307224] = "Đền Drak'Dal",
    [2011320283] = "Nhạc cụ",
    [2011546495] = "Có thể nhận",
    [2011654163] = "Lại đây nào",
    [2012041368] = "Chiến đấu",
    [2012050564] = "Lò Đốt Than",
    [2012179523] = "%k đã gặp sự cố!\n\nMột MiniDump đã được tạo tại\n\n'%k'\n\nBạn có muốn tải lên không?",
    [2013007494] = "Nếu Mẹ ở đây",
    [2013285952] = "Trí tuệ trong các Thánh địa Đêm",
    [2013906024] = "Lăng Mộ Lớn",
    [2014223297] = "Phải có <craftingstation>Dụng cụ làm đá</craftingstation>",
    [2014279416] = "Bạn đang bị ảnh hưởng bởi tia hồi máu",
    [2014464607] = "Áo Giáp Pháp Sư Băng Mưa",
    [2014472936] = "Sẵn sàng chế tạo: %k",
    [2015060430] = "Ghi chú của <npc>Thợ săn</npc>",
    [2015859864] = "Tham gia",
    [2016012521] = "Bạn đã tìm thấy một ghi chú trong túp lều trên núi từ một người cha mơ ước cải tạo ngôi nhà của mình cho gia đình. Những Khối đá Granite đánh bóng mà ông mô tả vẫn nằm ẩn dưới cầu thang tại Tiền đồn Cổng \"Bora\", chưa được động đến. \n\n<b>Hãy lấy chúng, để chúng có thể phục vụ mục đích mà chúng được tạo ra!</b>",
    [2016396662] = "Báo cáo Xây dựng Cầu",
    [2017028299] = "<i>\"Cuộc đời tôi có thể đo bằng giờ, tôi phục vụ bằng cách bị tiêu thụ. Mỏng manh, tôi nhanh nhẹn. Béo tốt, tôi chậm chạp. Gió là kẻ thù của tôi. Tôi là gì?\"</i>\n\nĐó là câu đố tôi đã giải để trở thành một Học giả. Và đó thực sự là một câu đố đơn giản. \n<i>\"Bạn là một cây nến\"</i>, tôi nói mà không để câu hỏi dừng lại, mắt vẫn dán vào môi của vị Cổ nhân. \n\nTôi chưa bao giờ là người tin tưởng. Vâng, tôi đã trả lời câu đố của Cổ nhân — trở thành một Học giả của Thiên đình. Có lẽ tôi tò mò. Say mê viễn cảnh khám phá thế giới để tìm kiếm kiến thức. Nhưng tôi không phải là một tín đồ sùng đạo của Ngọn lửa. \nTuy nhiên, tôi đã tuân theo tiếng gọi và mang nhiều cuộn giấy cùng bí mật vào các Thánh địa Đêm, cùng với những ngọn nến được thắp sáng và kính đọc sách. \n\nNgười ta nói rằng kiến thức sẽ biến mất không dấu vết vào ban ngày, nhưng tôi chắc chắn rằng điều này sẽ chứng tỏ là một trò ảo thuật đơn giản. Một câu đố để giải. Một ngọn nến trước gió. \nTôi đã nán lại trong Thánh địa, lắng nghe ở cửa, và quan sát lối vào đóng kín khi nó đứng im lìm vào giữa trưa. \nTôi chưa bao giờ thấy một Cổ nhân hay một trò lừa bịp nào. Bất kỳ kiến thức nào tôi lưu trữ trong Thánh địa đều biến mất vào ngày hôm sau. \n\nMỗi lần, thứ duy nhất họ để lại là cây nến. Đã bị dập tắt, nằm một mình trong bóng tối, và bị tiêu thụ.",
    [2017125068] = "Tăng sát thương lên Fell.",
    [2017309669] = "Tìm Trống hiếm",
    [2017973633] = "Đá mài",
    [2018000283] = "Bình Đá Vôi Chạm Khắc I",
    [2018192817] = "Mùi máu",
    [2018646589] = "Áo Giáp Lông Huyết",
    [2019404681] = "Phòng ngai vàng của Chúa tể Vorgoth",
    [2019754006] = "Độ bền",
    [2020309485] = "Chất lượng tối đa",
    [2021582168] = "Giáp Ngực Binh Lính",
    [2021869918] = "Ngày mới, con người mới! \nChuyến thám hiểm của tôi vào Đỉnh Albaneve bắt đầu tốt đẹp! Không khí bên này núi thật sảng khoái, và tôi có thể di chuyển mà không bị gánh nặng sau khi bỏ lại ban nhạc và cây đàn lute của mình. Tôi thậm chí còn tìm thấy một tháp canh bỏ hoang và có được một ít áo giáp cũ và quần áo ấm bên trong! Chúng sẽ chuẩn bị tốt cho tôi cho hành trình phía trước... và bộ giáp khiến tôi trông giống như một người phương Bắc! \n\nTôi sẽ giả vờ như một người lính bị lạc nếu một cuộc tuần tra bắt được tôi. Bằng cách đó, có lẽ máu của tôi sẽ không đổ, và tôi sẽ sống thêm một ngày nữa! Thật truyền cảm hứng... có lẽ tôi sẽ cầm bút lên và ghi lại điều đó... Tôi không còn là một nhạc sĩ nữa, nhưng thói quen cũ khó bỏ!",
    [2021931952] = "Lớn, có quyền lực và sẵn sàng xông vào khi bạn đang bận lục lọi hang động. \n\nThu thập nhiều Đầu Người Khổng Lồ để chế tạo Cúp Sắt.",
    [2022487481] = "Mũ Nhạc Sĩ Lang Thang",
    [2022931188] = "<b>Viện Quốc phòng Đế quốc CROMVILLE</b>\nBản ghi nhớ gửi <b>Tướng Rasmus</b>\n\nThư giới thiệu cho <b>C-25-1019-DA (DARYA ARKANOV).</b>\n\nChúng tôi vui mừng giới thiệu sinh viên D. ARKANOV cho chuyến thám hiểm sắp tới đến <b>Cổng Đêm</b> ở mặt trận Đỉnh Albaneve. \nCô ấy đã chứng tỏ lòng trung thành và khả năng lãnh đạo của mình trong nhiều chuyến đi thực địa, và đứng đầu lớp về <i>\"Lịch sử Đế quốc\"</i> và <i>\"Cổ nhân: Giải phẫu Kẻ thù\"</i>. \nCô ấy thậm chí còn bày tỏ sự quan tâm đến ma thuật bí ẩn của Cổ nhân ngoài lớp học. Những sai lệch học thuyết (được dung thứ) của cô ấy có thể hữu ích cho nghiên cứu của bạn.\n\nDo đó, chúng tôi tin rằng D. ARKANOV sẽ là một sự bổ sung hữu ích cho đội của bạn. Chúng tôi sẵn sàng trả lời mọi câu hỏi hoặc yêu cầu. \n\nChúc phúc cho Chúa tể Vorgoth, Vệ binh Phương Bắc \n<i>J. Lincoln</i>, Hiệu trưởng",
    [2023324638] = "Tiếng Bồ Đào Nha",
    [2023436780] = "Hít vào, và thở ra. Hít vào, thở ra. Bình tĩnh nào, Rochelle, bình tĩnh... hít thở sạch sẽ. Không bụi, không khói? Không có hỏa ngục rực lửa? Hỡi người lạ thân mến, tôi không biết làm thế nào bạn đưa tôi ra khỏi đám cháy đó — nhưng cảm ơn bạn. Tôi là một thợ rèn — nghề của gia đình Ander. Hãy đến với tôi, và tôi sẽ là chiếc khiên của bạn.",
    [2023832657] = "Bộ Trang phục Trinh sát",
    [2023853899] = "Một sự kết hợp của các màu xám và xanh lam mát mẻ, gợi nhớ đến một dòng suối băng giá vào một ngày nhiều mây.\n\nBảng màu này có thể được tạo bằng vật liệu Revelwood.",
    [2024069960] = "Quần màu nâu nhạt. Thoải mái và sang trọng trong sự đơn giản của chúng.",
    [2024413199] = "Ma thuật Băng",
    [2024544486] = "Đồ Cổ",
    [2024609107] = "Sự trống rỗng ập đến",
    [2024910911] = "Chỉnh sửa bộ lọc",
    [2025126827] = "Mũ Giáp Lông Huyết",
    [2025250930] = "Lỗi lưu dữ liệu. Không thể ghi đè dữ liệu.",
    [2025262949] = "Hãy để tôi chia sẻ ánh sáng của mình với bạn.",
    [2025413506] = "Nhạc cụ hiếm — Đàn Hạc",
    [2025834761] = "Kiếm Tết Nguyên Đán?",
    [2026175854] = "Đôi ủng này có hoa văn vảy tinh xảo trên lớp mạ màu xanh lá cây.",
    [2026234279] = "Thú cưng trang trại",
    [2026345091] = "Tường Rào Gỗ I",
    [2026532976] = "Cúp Danh Năng Rồng Ma Trác Sa Ngã",
    [2026597705] = "Bạn đã đọc một ghi chú mô tả cách một người đào huyệt địa phương ở <location><lorename>Pikemead</lorename>'s Reach</location> muốn được chôn cất. \n\nÔng ấy ước mình được chôn dưới <i>cây sồi già, bên cạnh vợ và con trai.</i> Nghĩa trang được đề cập nằm trong khu vực Vườn Hoàng gia. Hãy tìm mộ của ông ta và đào tìm vật có giá trị!",
    [2027317019] = "Sợi nấm của những cây nấm đã hấp thụ các đặc tính ma thuật của Sương độc. Liệu thứ này có thể được sử dụng cho mục đích giả kim thuật không?",
    [2027367513] = "Bạn đã có được một đôi vây cá! Cái gì? Bạn mong đợi điều gì khác ư? Có lẽ là một chiếc đuôi nàng tiên cá thực sự? Ha ha ha! Mỗi câu chuyện tôi kể nên được xem xét một cách thận trọng, bạn biết đấy!",
    [2027521057] = "Giá Treo Cung & Mũi Tên Đóng Tường",
    [2027699428] = "Bạn đã lấy được chiếc đèn lồng! Ánh sáng của năm mới chiếu rọi bạn.",
    [2027779626] = "Bạn đã tìm thấy một người sống sót đang ngủ say dưới lòng Thành phố Cổ bị nhấn chìm. Hãy đánh thức họ bằng một cây Gậy phép Triệu Hồi!",
    [2028005643] = "<b>Chế tạo Diều Lượn</b> sẽ cho phép bạn tiếp cận những địa điểm xa xôi hoặc vượt qua những thung lũng Sương độc bao phủ mà không bị tổn hại. Nó có thể được chế tạo tại <b><craftingstation>Bàn Chế Tạo</craftingstation></b> từ <b>Gỗ Che Phủ</b>. \n\nBạn có thể kiếm Gỗ Che Phủ bằng cách dấn thân vào sâu bên dưới Lớp Che Phủ.\n\nHãy cẩn thận khi tiêu hao <b>SP</b> khi sử dụng <b>Diều Lượn</b> để đến những địa điểm mới.",
    [2028015054] = "Cà Phê Mokka Ngọt",
    [2028149042] = "Embervale",
    [2028205642] = "Cần Câu Bị Nguyền",
    [2028553213] = "Sữa Hươu Tiên Nguyên Chất. Phải nấu chín để tiêu thụ an toàn.",
    [2028814015] = "Kiếm Sói Trắng",
    [2028919011] = "Hầm Tro Tàn",
    [2029428232] = "Nhiệm Vụ",
    [2029668924] = "Một Máy Quay Cho Thợ Săn",
    [2029788315] = "Vị Trí <npc>Nông Dân</npc>",
    [2030140030] = "Đọc tất cả các bia đá ở Đỉnh Albaneve.",
    [2030665782] = "Phản Xạ Chiến Đấu",
    [2030935939] = "Vị Trí Phép Thuật Vĩnh Cửu",
    [2031199461] = "Tháo Dỡ Đồ Tạo Tác",
    [2031409518] = "Nhẫn Năng Lượng Siêu Cấp",
    [2031606992] = "Điều này làm tôi nhớ đến một câu chuyện — bạn đã bao giờ nghe về bộ quần áo mới của hoàng đế chưa?",
    [2032107380] = "Đầu mũi dao tẩm độc thường hiệu quả hơn ngoại giao.\n\nBảng màu này có thể được tạo bằng vật liệu từ Đỉnh Albaneve.",
    [2032344053] = "Đôi bốt nâu được trang bị khóa thắt lưng và dây giày. Hoàn hảo cho một chuyến đi dạo qua ngôi làng, lâu đài hoặc hầm ngầm tuyệt vời của bạn.",
    [2032592324] = "Biểu Tượng Tường Hình Kim Cương",
    [2032738235] = "Dao Găm Yêu Dấu",
    [2033170813] = "Tầm Xa",
    [2033193899] = "Thợ mộc nói rằng <b>Vukah đã có những hành vi kỳ lạ</b> từ lâu. Chúng rời hang động của mình trước khi Sương độc bùng phát, và chiếm đóng các khu vực của Vùng Đất Xuân và Cao Nguyên Du Mục. Chúng có một <b>vị trí tập kết</b> cần được điều tra.",
    [2033319437] = "Nhân Danh Ngọn Lửa! Đầu tôi đau như thể một con Vukah đã dùng nó để đo khoảng cách ném của chúng... và mọi thứ đều có vị như bùn...",
    [2034014687] = "Sương độc bao phủ",
    [2034280613] = "Menu Hệ Thống",
    [2034460220] = "Một thức uống rất tốt cho sức khỏe, giúp cơ thể phục hồi và chuẩn bị cho ngày mới.",
    [2034914489] = "Thời Khắc Thu Hoạch",
    [2035442561] = "Trước khi sụp đổ, nhiều lính canh và hiệp sĩ của Embervale đã sử dụng những thanh kiếm như thế này. Có lẽ tinh thần của họ vẫn còn sống qua những đòn tấn công chính nghĩa của bạn.",
    [2035656172] = "Nói Chuyện Với Nhà Giả Kim",
    [2035679671] = "Ôi trời, tôi mừng vì đã sống sót trở về, nhưng tôi không nhận ra mình đang ở đâu cả! Phòng của tôi không còn thấy đâu nữa. Bạn có thể chỉ cho tôi đến chỗ ở mới của tôi được không? Nếu tôi ngủ ngoài trời mà không có chỗ trú ẩn, tóc tôi sẽ bị xù lên.",
    [2035725030] = "Độc Dược",
    [2036012713] = "Thà làm búa còn hơn làm đe.",
    [2036168949] = "Nhiệm Vụ Trinh Sát Đến Bia Đá",
    [2036186309] = "Hollow",
    [2036224299] = "Hỡi Hỏa Hồn, sức mạnh của ngươi đã lớn mạnh. Đã đến lúc đối mặt với thử thách cuối cùng của ngươi trong thời điểm hiện tại. Hãy tìm kiếm Hầm Cổ Ngữ cuối cùng của ngươi và thu hồi cổ vật bên trong. Hãy chứng tỏ bản thân với Ngọn Lửa vinh quang!",
    [2036526058] = "Tôn vinh những kẻ bất tử! Một vết rách trong kết cấu thời gian — ta đã trở lại, sống khỏe mạnh! Và còn nhiều thịt hơn ta dự kiến!",
    [2036535033] = "Chào Đón Năm Mới",
    [2037334192] = "Cổng Tưới Tiêu Nhỏ",
    [2037505619] = "Sinh Tồn",
    [2038238947] = "Bộ Sưu Tập Sách I",
    [2038396624] = "Cơn Đói Trong Bóng Tối",
    [2038971428] = "Cánh Lượn",
    [2039590718] = "Sảnh Danh Dự Sự Kiện",
    [2039919790] = "Tăng sát thương lên Vukah.",
    [2040096003] = "Tìm Kiếm Nhà Của Nhà Hiền Triết",
    [2040625352] = "Sau khi nhận sát thương, có <b>20%</b> cơ hội phản lại <b>50%</b> sát thương về kẻ tấn công dưới dạng sát thương <b>Lửa</b>.\n\nĐòn tấn công phép thuật này có thể kích hoạt các kỹ năng khác.",
    [2041470739] = "Khung Cửa Sổ Đánh Bóng Tròn Lớn",
    [2041530846] = "Hộp Trang Trí Màu Tím",
    [2041594027] = "ST Đập Đơn Phép Thuật",
    [2041870541] = "Con tàu lớn mắc cạn trên bờ biển của chúng ta.\n\nThức ăn ôi thiu, gỗ mục rữa. Merphisz sẽ cười nhạo tình trạng của nó.\n\nMây cuộn tròn, xanh lam mờ ảo như sương mù trên đường chân trời, nhưng u ám. Con người bên trong, hoặc thứ gì đó từng là con người. Nhão nhoét và mềm nhũn, xé toạc để lộ trái tim phát sáng vẫn đập theo nhịp điệu xa lạ.\n\nKẻ yếu đuối! Tiền Nhân đã chọn sai nhà vô địch! Giờ là thời đại của Drak! Drak'Dal sẽ vượt biển cả và nghiền nát những kẻ yếu đuối! Xây dựng lại đế chế!\n\nVì Dalszul!\n\n",
    [2042882153] = "Không Hiệu Quả",
    [2043126023] = "Bụi Rễ Phát Sáng",
    [2043486034] = "Dãy màu đỏ, cam và xám tạo nên khả năng ngụy trang lý tưởng chống lại những ngọn núi khô cằn.\n\nBảng màu này có thể được tạo bằng vật liệu từ Vùng Đất Nung.",
    [2043828288] = "Pháo Hoa Hoa Giấy Đỏ",
    [2043850657] = "Bạn đã tìm thấy tất cả các bài hát! Ồ, và tất cả đều của Chester Loft!? Tôi là một fan hâm mộ lớn! Ôi, tôi sẽ ngất mất! Giữ lấy tôi nhé?",
    [2043943126] = "Ánh sáng và hơi ấm của tôi vươn xa hơn vào bóng tối — nhờ bạn, Hỏa Hồn. Tôi đủ mạnh để bảo vệ ngôi nhà của bạn nếu bạn chọn mở rộng nó.",
    [2043951428] = "Sử dụng <b>Móc Leo Núi</b> của bạn để kéo bản thân về phía những kẻ địch lớn trong chiến đấu.\n\n<b>Chi phí:</b> 50 SP ",
    [2044041282] = "Trong kho đồ:",
    [2044160375] = "Giới Hạn Giảm Sát Thương Tăng Lên Từ Giáp Phép",
    [2044549774] = "À, thật tốt khi thấy bạn khỏe mạnh trở lại! Hãy nhớ chăm sóc bản thân thật tốt, nhé?",
    [2044897340] = "Làm quen với nó",
    [2044981038] = "Một Giải Pháp Nhanh Chóng Và Đơn Giản",
    [2044989125] = "Mang Cá",
    [2045194752] = "Hy vọng bạn không chết trước khi chúng ta gặp lại.",
    [2045522528] = "Một món salad tảo có vị tươi mát và hơi mặn, như biển cả. Thứ gì đó xanh tươi và tự nhiên như vậy chắc hẳn rất tốt cho sức khỏe.",
    [2045925678] = "Dụng Cụ Khoa Học",
    [2046446710] = "Thời Lượng Ban Ngày",
    [2046606380] = "Đất Nông Trại",
    [2046737248] = "Tìm tất cả các đền thờ và thánh địa Ngọn lửa trong Rừng Revel.",
    [2047158819] = "Quân Cờ Vua",
    [2047505154] = "Xương Hóa Thạch",
    [2047589889] = "Mái Nhà Hòm Gian Lận",
    [2048323834] = "Bạn đã tìm thấy một bản ghi chép về các thí nghiệm mà nhà phù thủy điên đã tiến hành. Thật không may, công việc của ông ta trong ngôi mộ này đã không thành công, nhưng ông ta đã ghi lại một cách bí ẩn nơi thí nghiệm tiếp theo của mình sẽ diễn ra:\n\"Từ mặt nước, ta vượt qua Cổng Tiền Đồn \"Darkwater\" và dấn thân vào rừng rậm để tìm ngôi mộ tiếp theo.\"\n\nHãy đến ngôi mộ tiếp theo và khám phá những bí mật của nó.",
    [2048511589] = "Đầu Bếp",
    [2048580960] = "Giáp",
    [2048623738] = "Ông ta có thể <i>rất</i> đòi hỏi đôi khi.\n<i>\"Nó vẫn cần thêm những viên đá lấp lánh\"</i> ông ta nói.\n<i>\"Nó vẫn chưa cảm thấy hoàn chỉnh\"</i> ông ta nói.\nÔng ta có <i>bất kỳ</i> ý tưởng nào về những gì tôi đã trải qua để có được những viên đá chúng ta có cho đến nay không? Tôi đã đi khắp nơi, mang về cho ông ta những viên đá quý từ đông sang tây—và ông ta vẫn chưa hài lòng.\nMột đứa trẻ ngu dốt, hư hỏng.\nNghĩ rằng khoe tiền là bù đắp cho tất cả.\n\nBây giờ ông ta sẽ không hài lòng cho đến khi tôi mang về cho ông ta ít nhất một viên đá quý từ Sảnh Đường Hollow. Tin đồn kể rằng mỗi nơi đó chứa một viên đá quý hiếm. Một nơi nguy hiểm, nhưng tất nhiên ông ta không quan tâm đến điều đó.\nTôi đoán tôi không còn lựa chọn nào khác. Nếu tôi không giao hàng, ông ta sẽ tìm người khác.\nNhững gì bạn làm vì tiền.",
    [2049292061] = "Một luống cày sẽ cho ra sợi thực vật.",
    [2049518355] = "Thợ <npc>Cắt Tóc</npc> Cần Nơi Trú Ẩn",
    [2049643961] = "Cuối cùng! Ôi, tôi nóng lòng muốn pha cho mình một tách espresso sang trọng. Có lẽ tôi sẽ chuẩn bị một ít cà phê cho cả đội — một ly frappe cho bạn thân nhất của tôi, cà phê đen cho Athalan, mocha cho Balthazar, ca cao nóng cho Cade, một ly latte siêu xoắn ngọt ngào cho Ngài Khó Tính kia...",
    [2050132448] = "Tủ Gỗ Cọ Nhỏ",
    [2050201697] = "Hướng Hành Động",
    [2050492568] = "Bạn Bè",
    [2051845143] = "Một cây rìu để kết thúc mọi trận chiến — nhanh chóng.",
    [2051907950] = "Khi nhận ST Cận chiến, kẻ tấn công sẽ bị làm chậm trong <b>5</b> giây.",
    [2052442950] = "Nạp lại bằng Vật Liệu Xây Dựng Mái Nhà.",
    [2052502970] = "Vải màu đỏ ruby, vảy màu xanh lục bảo và đường viền vàng tạo nên một món giáp trang trí ấm áp và hoàng gia khi kết hợp.",
    [2052510065] = "Thợ Cắt Tóc đang tuyệt vọng tìm kiếm thứ gì đó có thể bắt được ánh sáng lấp lánh của mặt trời nhảy múa trên mặt nước.\n\n<b>Hãy tìm kiếm trong Lưu Vực Nước Lấp Lánh một thứ gì đó màu xanh lam và tinh thể.</b>",
    [2052693818] = "Thái",
    [2052896825] = "Ồ, bạn tìm thấy một cái ống thổi à? Chúng ta có thể dùng nó cho lò cao! Hãy cùng tôi chế tạo một cái, bạn thấy sao?",
    [2052908472] = "Thợ <npc>Mộc</npc> Cần Nơi Trú Ẩn",
    [2053254626] = "Bộ Hoa Hồng Máu",
    [2053716785] = "Thợ Cắt Tóc đã chán với các lựa chọn tạo kiểu hiện tại của mình và muốn tạo ra những màu tóc mới thú vị. Anh ta nghĩ rằng uống một ít <b>trà cay</b> sẽ làm cho ngày nhàm chán của anh ta thêm phần thú vị, và truyền cảm hứng cho anh ta!\n\nHãy mang cho Thợ Cắt Tóc một ít <b>trà cay</b>!",
    [2053795948] = "Mặc dù đeo băng đen che mắt như những tên cướp, chúng lại khá dễ bắt.\n\nLoại cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [2053822474] = "Găng Tay Cung Thủ",
    [2054230067] = " <lorename>Gormander</lorename> Phù Hộ Chúng Ta",
    [2054933005] = "Bạn cảm thấy bình tĩnh và được bảo vệ trong bộ giáp thân trên này — hãy cân nhắc kỹ lưỡng bước đi tiếp theo của mình.",
    [2055043385] = "Đứng",
    [2055101898] = "Hạt gạo nguyên chất. Chúng sẽ rất no bụng khi được nấu chín!",
    [2055110189] = "Không có người sống sót nào có sẵn.",
    [2055215215] = "Ảo ảnh bị bỏ rơi đã dẫn ta đi lạc xa hơn!! Ta <i>NGUYỀN RỦA kẻ đã bán cho ta tấm bản đồ này!</i> Nước! Ta cần nước!\n\nĐầu óc ta đã mục rữa! Ta thấy ảo ảnh!! Ta nhìn thấy một ốc đảo khác, thật hay ảo, ngay trên đỉnh đồi kia! Nếu ta không bán chiếc Dù lượn quý giá của mình, ta đã có thể đến đó!! \n\nBóng tối trên cao, xoay tròn. Một vòng xoáy, như một sợi chỉ đang tuột ra. Ta cứ thấy một bóng hình ở khóe mắt — một bóng ma, một hồn ma. Chế giễu ta và cái đầu mục rữa của ta!! NGHE்N RỦA! Đây không thể là lời cuối cùng ta viết! Ta phải được ghi nhớ! Xin hãy nhớ cái tên <i>\"Costner Meyers\"!</i> Ta không muốn tan biến!",
    [2055902686] = "Tiền đồn Cổng \"Celeste\"",
    [2056439636] = "Ngươi đã tìm thấy tất cả các nhạc cụ và thậm chí cả một cây đàn hạc tuyệt đẹp? Thật tuyệt vời! Điều này sẽ rất hữu ích cho nghiên cứu của ta. Tại sao không chơi một bản nhạc trong khi ta suy ngẫm? Cứ tự nhiên, ngươi đã xứng đáng được nghỉ ngơi!",
    [2056461468] = "Nói chuyện với Ngọn Lửa",
    [2056846396] = "Tham gia không mật khẩu",
    [2057253890] = "Cái đầu quý giá của một gã khổng lồ, được bảo quản trong kim loại và có thể tiếp cận với người thường. Giờ đây, mọi người có thể nhìn vào mắt nó mà không sợ hãi.\n\nThu thập nhiều Đầu Khổng Lồ Fell để chế tạo Cúp Sắt.",
    [2057895019] = "Dùng để buộc mọi thứ lại với nhau, Dây là một vật phẩm cực kỳ quan trọng.",
    [2058196866] = "Tủ Gỗ Phương Bắc Vừa",
    [2058264385] = "Bát Ăn Cho Chó",
    [2058441259] = "Đôi găng tay này tỏa ra hơi ấm và sự an toàn như thể chúng được rèn từ ánh sáng lỏng tinh khiết.",
    [2058582544] = "Đá Hắc Diên",
    [2058822126] = "Ngươi đã biết về sự tồn tại của một khối xây dựng mới ở Cao nguyên Du mục gọi là Khối Đá Cát Hỗn Hợp. \n\nTìm kiếm khu vực để lấy khối xây dựng!",
    [2059467426] = "Kháng Sương độc",
    [2060140407] = "Giường của ta bị phơi ra ngoài trời! Ta bị ướt sũng mỗi khi trời mưa! Làm ơn xây cho ta một mái che trên giường được không?",
    [2060158353] = "\"Ghen tị và bất tử\", đúng vậy. Ta biết rõ chúng. Chúng phản chiếu từ mọi mảnh pha lê bên trong Sảnh Hollow ở Cao nguyên Du mục, bóp méo ánh nhìn và ý định của ngươi, nhổ lại vào mặt ngươi với sự khinh bỉ. Nếu ngươi muốn tự mình nhìn thấy chúng, hãy biết rằng cánh cửa đến Sảnh mở ra bằng một chiếc chìa khóa của ta. Tuy nhiên, ta chỉ có thể chế tạo nó nếu ngươi đã thu thập đủ nguyên liệu từ các Sảnh trước đó.",
    [2060590120] = "Một cây cần câu may mắn khá chắc chắn và cũng có khả năng câu được nhiều kho báu hơn!",
    [2060595025] = "Thỏi Đồng Đỏ",
    [2060810685] = "Bàn thờ này đã bị vô hiệu hóa. Ánh sáng còn sót lại của Ngọn Lửa mang lại sự bảo vệ kéo dài sẽ sớm biến mất:",
    [2060851498] = "Người giữ bí mật của Vùng Đất Than Hồng",
    [2060885732] = "Phục hồi Thời gian Sương độc",
    [2060998536] = "Mang lại sự bảo vệ kéo dài chống lại Sương độc.",
    [2061052237] = "Nhiều viên đá thạch anh tím đã được sử dụng để rèn chiếc đũa phép này. Chúng cần thiết để ngăn chặn sự bốc cháy khi vũ khí này quá nóng do năng lượng tích tụ bên trong!\n\n<b>Quá tải:</b>\nChiếc đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương cộng thêm lên tới phần trăm <i>quá tải</i>.",
    [2061124874] = "Bộ Pháp Sư",
    [2061157582] = "Khiên Binh Lính",
    [2061343101] = "Thánh địa Đêm của Trưởng lão",
    [2061511697] = "Làm chủ những điều cơ bản",
    [2061522750] = "Thảm Treo Tường II",
    [2061870471] = "Vào những ngày xưa, những chàng trai trẻ thường mang những cây chùy như thế này để đánh đập và vật lộn với nhau như một cơn bão tối tăm, sấm sét. Nó giúp giải tỏa cơn giận và loại bỏ kẻ yếu.",
    [2062051336] = "Ngươi sẽ gây thêm 50% sát thương độc.",
    [2062866329] = "Nữ bá tước Leclair, học trò giả kim thuật, đã giao nhiệm vụ cho bạn tìm một \"Ngọc Huyết Khát\" ở Đỉnh Albaneve.\n\nBà ấy nói rằng viên ngọc đôi khi có thể tìm thấy trên <b>kẻ địch tinh anh phía trên Sương độc.</b> Đánh bại kẻ địch tinh anh thuộc phe Scavenger, Vukah hoặc Hollow ở Đỉnh Albaneve để có cơ hội tìm thấy viên ngọc.",
    [2062876021] = "Chiếc quần phồng được làm từ lụa tốt nhất. Chúng tạo ra một hình bóng thú vị và lộng lẫy.",
    [2064090567] = "Một loại bột màu xanh có thể dùng để tô màu cho các vật thể khác như quần áo. Nó được tạo ra từ tàn tích của côn trùng và các chất khác.",
    [2064704958] = "Mồi Chút Lang Nước",
    [2065144527] = "Trang Phục Phu Đào Mộ",
    [2065302236] = "Học giả của Empyrean của chúng ta đang lụi tàn.\nÔng ấy đi bộ chậm hơn, không thể đi thăm các Thánh địa Đêm như trước. Ông ấy đã là người dẫn đường của chúng ta trong nhiều thập kỷ—và trong nhiều thập kỷ, chúng ta đã dâng những lễ vật này. Nhưng gần đây, sự nghi ngờ ngày càng lớn trong chúng ta.\nCác Cổ nhân đã không trở lại. Đã hai mươi hai năm rồi.\nSự vắng mặt của họ từng mang lại cảm giác thiêng liêng. Giờ đây, nó mang lại cảm giác bị bỏ rơi.\n\nVà hôm nay, bị bỏ lại bởi các Cổ nhân và gánh nặng đưa ra lựa chọn một mình, vị Học giả đã đặt tên cho người kế nhiệm của mình.\nChính con trai ông.\n\nThông báo được đưa ra mà không có nghi thức, không có lời khuyên—chỉ là một sắc lệnh được truyền từ đôi môi đang lụi tàn.\nNhưng chúng ta hầu như chưa gặp cậu bé. Cậu ấy không phải là trưởng lão. Cậu ấy chưa bao giờ tự mình bước vào Thánh địa.\n\nMột số cúi đầu, vẫn bám vào sự tôn kính cũ. Nhưng nhiều người ngẩng cao đầu—mắt đầy nghi ngờ.\n\nĐây có phải là cách nó kết thúc?\nTa sợ rằng các Cổ nhân sẽ không ban phước cho chúng ta bằng sự hiện diện của họ một lần nữa.",
    [2065429067] = "Địa điểm mới đã được lập bản đồ!",
    [2066053750] = "Ngươi đã tìm thấy \"Viên ngọc khát máu\" ở Đỉnh Albaneve. Hãy quay trở lại gặp Nữ bá tước Leclair để nhận phần thưởng cho cuộc săn lùng của ngươi!\n\nNgươi không cần phải có viên ngọc trong hành trang để tiếp tục.",
    [2066380716] = "Một loại bụi ma thuật có thể phát sáng trong bóng tối, bao gồm tàn tích nghiền nát của một con đom đóm.",
    [2066409998] = "Aster! Ta tìm thấy bức thư của Jax gửi cho nàng. Hãy nghe lời cảnh báo của ta — trong tim ta, nàng đủ dũng cảm rồi, không cần phải cố gắng làm những việc ngu ngốc như vậy!\n\nTa biết nàng vừa mới chuyển đến đây từ Vùng Đất Mùa Xuân và còn nhiều điều phải học về ngôi nhà của chúng ta. Quan trọng nhất: đừng bao giờ <i>bao giờ</i> chơi đùa quanh những tảng đá trên trang trại! Bởi vì chúng không phải là đá mà là lớp vỏ bảo vệ của Tatu Cát! Chúng sẽ túm lấy nàng và kéo nàng xuống lòng đất ngay lập tức! Và ai sẽ đưa ta đến Lễ Hội Thu hoạch đây?\n\n— Myrtle",
    [2067381210] = "Đèn",
    [2068668441] = "Không",
    [2068947308] = "Có thể chỉnh sửa thế giới bên ngoài căn cứ",
    [2069063183] = "Ta luôn nghĩ công việc canh gác này là thứ nhàm chán nhất trên đời. Trời ạ, ta đã sai lầm. \n\nTa cứ thấy thứ gì đó ở phía xa — lướt đi giữa những cơn gió, bị che khuất bởi sương mù và khói. Nó <b>gần ngôi mộ của thung lũng,</b> nên ta nghĩ đó là một Kẻ Hollow khác. Một con rối vô định, xương xẩu và yếu ớt... nhưng điều đó không đúng. \n\nNó nhìn ta mỗi đêm. Ta không thể nhìn thấy nó, nhưng ta cảm nhận được nó. Nó nửa sống nửa chết... có lẽ là một vị khách từ thế giới bên kia cho Đêm Kinh Hoàng. \n\nThư xin từ chức của ta đã được gửi đi. Ta không thể chờ đợi để quay lại công việc nhàm chán.",
    [2069871972] = "Đã đặt Nguồn nước",
    [2070496617] = "Dây đai và vải quấn chặt quanh cán, gợi lên câu chuyện về một người bảo vệ không ngờ tới phải điều chỉnh tay cầm vũ khí một cách đột ngột.",
    [2070863872] = "Khổng lồ",
    [2071535815] = "Sắc Đỏ Của Bóng Tối",
    [2071668356] = "Khai thác trong Sương độc Rừng Khải Hoàn",
    [2072099715] = "Đọc Đài tưởng niệm Vùng Đất Xuân của Sương độc",
    [2072126686] = "Ta sẽ ở đây!",
    [2072492397] = "Chưa học được công thức nào.",
    [2072921877] = "Chúng ta đói. Chúng ta phải phá hủy cây cầu — và cùng với đó là sự kết nối của chúng ta với nguồn cung cấp. Nhưng nó đã hiệu quả: chúng ta không còn thấy \"Scavenger\" nào nữa. Hầm Cinder — và những kẻ bên trong nó — đều an toàn, và nên giữ nguyên như vậy.\n\nNếu chúng ta muốn tránh chết đói, chúng ta có thể phải mạo hiểm trong Sương độc khủng khiếp. Lựa chọn nào cũng là cái chết chắc chắn... \n— <lorename>Thuyền trưởng Arkwright</lorename>",
    [2073541420] = "Nhấn <b>%k</b> để phản hồi",
    [2073676427] = "Tàn tích Drak'Dal Đáng ngờ",
    [2073711142] = "Giày Nông Dân",
    [2073730330] = "Đạn ma thuật tối thượng để đốt cháy một quả cầu lửa mạnh mẽ bùng nổ khi va chạm, gây sát thương trong một khu vực trung bình. \n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng một <b>gậy phép.</b>",
    [2074075141] = "Rương Phép Thuật Khổng Lồ",
    [2074096053] = "<location>Diadwyn</location> và các khối xây dựng của nó",
    [2074599381] = "Thật kinh khủng! Bị mắc kẹt trong một cơn bão, chúng tôi đang tìm một nơi khô ráo để trú ẩn và nghỉ ngơi... Chúng tôi nghe thấy tiếng cào cấu và gầm gừ... chúng chắc hẳn đã ngửi thấy chúng tôi vì chúng đã tấn công không có lý do. Một trong số chúng đã giật phăng đầu Christophe! Cơ thể hắn rơi xuống đất như một bao tải ướt, và <b>cây gậy của hắn trượt khỏi tay</b> trước khi hắn kịp sử dụng nó.\n\nCon quái vật được bao phủ bởi bộ lông dày, bết dính, với những chiếc ngà khổng lồ nhô ra khỏi miệng nó. Và khi nó gầm lên, âm thanh thật kỳ lạ và chói tai. VUKARRRRRR!!! Ta sẽ bị ám ảnh bởi nó suốt phần đời còn lại.",
    [2074674094] = "Lan Can Gỗ III",
    [2075036374] = "Sử dụng <b>tường leo trèo</b> để đạt được độ cao lớn hơn. Leo trèo sẽ tiêu hao SP.",
    [2075344330] = "Ngươi đã làm được! Động vật trông thật hạnh phúc! Thật là một niềm vui! Cảm ơn ngươi rất nhiều, Hỏa Hồn!",
    [2075928433] = "Vật liệu",
    [2075997219] = "Cây Giống Bí Ngô",
    [2076021139] = "Trang Phục Nữ Vắt Sữa",
    [2076203917] = "Ngươi cần rút viên ngọc hiện tại ra trước khi lắp viên mới.",
    [2076271103] = "Mũ Cung Thủ",
    [2076369220] = "Mũ Giáp Đạo Tặc",
    [2076591462] = "<b>Tẩm Sương Độc</b>:\nVũ khí này đã bị Sương độc bao phủ. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n",
    [2076698176] = "Vây Than Nướng",
    [2076994214] = "Vị trí của các Sảnh Hollow Rừng Rụng Lá đã được phát hiện. Chiến đấu hết mình đến cuối cùng và tiêu diệt con quái vật một mắt để lấy nguyên liệu chế tạo mới cho <npc>Người sưu tầm</npc>.\n\n<b>Đây sẽ không phải là một nhiệm vụ dễ dàng. Hãy tập hợp sức mạnh và đồng minh của ngươi, nếu có, để chuẩn bị cho bản thân.</b>",
    [2077149887] = "Công khai",
    [2077438483] = "Hãy cho ta biết nếu ngươi cần bất cứ điều gì khác!",
    [2078113823] = "Hồi Máu Liên Chuyền Vĩnh Cửu",
    [2078352219] = "Một phần của Giáp Hiệp sĩ Rạng ngời.",
    [2078495068] = "Đến Thủ đô",
    [2078796860] = "Một chiếc Dù lượn đáng gờm có thể vượt qua cả những vực sâu nhất, cho phép ngươi trút mưa bom từ trên cao.",
    [2079492281] = "Trang trại cá",
    [2079891523] = "Phóng to",
    [2079997206] = "Phù, suýt nữa thì toi rồi! Ngươi chắc hẳn là anh hùng rắn rỏi đã cứu ta! Mh... ngươi mặc bộ đồ \"sinh tồn\" trông rất hợp. Nếu ngươi muốn thử một phong cách khác, đừng ngần ngại hỏi \"Elio Ricci!\"",
    [2080559316] = "Ngay cả những sợi dây đơn giản cũng có thể là một công cụ mạnh mẽ trong tay kẻ biết sử dụng. Dệt chúng thật chặt, và ngươi sẽ có được <b>bộ giáp đệm</b> có thể làm giảm mọi cú ngã. Tuy nhiên, một <craftingstation>Khung cửi</craftingstation> là điều cần thiết.",
    [2080713489] = "Khám phá số phận của Fenrig",
    [2080814053] = "Ta lo cho Junior. \n\nTa đã làm việc rất chăm chỉ để tạo cho nó một cuộc sống tốt đẹp — một cuộc sống che chở nó khỏi chiến tranh và cái chết... thế nhưng, dù là sự thách thức trẻ con hay mong muốn noi gương cha, Junior vẫn không chịu cảm thấy an ủi bởi sự tồn tại giản dị của chúng ta. \nNó không từ bỏ giấc mơ trở thành một người lính... một cơn ác mộng trá hình, ta e rằng. Nếu nó có thể ổn định và tiếp quản tiệm làm tóc thay thế, ta chắc chắn nó sẽ có một cuộc sống tốt đẹp hơn, hoặc ít nhất là lâu dài hơn!",
    [2080910008] = "Găng Tay Xạ Thủ",
    [2080943876] = "Nơi an nghỉ của những người xây dựng vĩ đại nhất trong Đêm Kinh Hoàng",
    [2081714994] = "Vị khách quen yêu thích của ta!",
    [2082106788] = "Được chạm khắc từ gỗ chết kiếm được và rễ cây phủ bụi, chiếc rìu này đã được làm cứng dưới ánh mặt trời để xé thịt và chẻ xương.",
    [2082260480] = "Chỉ có thể mở vào ban ngày",
    [2082316352] = "Cần Câu Tuyệt Hảo",
    [2082410920] = "Cốc Đồng Đỏ",
    [2082610097] = "Lò rèn Ngọc Revelwood",
    [2082645203] = "Tìm tất cả các mảnh giáp",
    [2082729214] = "Màu sắc của Lưu vực Veilwater",
    [2082768770] = "Hàm nứt đôi Trái Đất",
    [2082885339] = "Đền thờ ẩn",
    [2083211302] = "Bao Tải Tiếp Tế V",
    [2084261805] = "Nhà cấp 4",
    [2084423583] = "Mỗi đặc quyền đều tốn Rune. Thu thập Rune bằng cách tháo dỡ vũ khí và các trang bị khác.",
    [2084533479] = "Mồi câu làm tăng cơ hội câu được cá hiếm.",
    [2084679806] = "Ngọn lửa bên trong ngươi soi sáng con đường, ban cho <b>quyền tiếp cận các Tháp Cổ xưa</b> và cho phép <b>Du hành nhanh.</b>\nNgọn lửa có thể được tăng cường tại một <b>Bàn thờ Lửa.</b>",
    [2085362891] = "Văn Hóa Vukah",
    [2085374205] = "Đừng làm đứt dây.",
    [2085509985] = "Không có hiệu ứng bất lợi nào đang hoạt động",
    [2085676912] = "Đấu sĩ Fell",
    [2085774347] = "Mũ Giáp Mẫu Hệ Dọn Dẹp",
    [2086282188] = "Độ Khó",
    [2086347912] = "Đây là một biến thể hiếm, màu đen nửa đêm của loài Rằn Rắn. Vảy đen của nó hấp thụ ánh sáng, khiến nó gần như vô hình dưới nước. Kẻ săn mồi kiên nhẫn này tấn công từ vực sâu khi bạn ít ngờ tới nhất.\n\nLoài cá này có thể nướng hoặc dùng trong công thức nấu ăn.\nNó cũng có thể được thả về nước và nuôi trong ao.",
    [2086469248] = "Một vật liệu kỳ diệu. Nó trong suốt và mang lại nhiều ứng dụng tiềm năng, đặc biệt trong xây dựng và chế tạo!",
    [2086572758] = "Nhạc Công",
    [2086576762] = "Tháp phòng thủ tại Biên Giới Fawnsong ẩn giấu những Khối Tường Thành đặc biệt. <b>Khám phá khu vực xung quanh tháp và tìm các khối xây dựng</b> để mở khóa thêm các lựa chọn vật liệu!",
    [2086868633] = "Trái Tim Giếng Thuốc Tiên",
    [2086911074] = "Vật Phẩm Bị Mất",
    [2086957990] = "Thực Phẩm",
    [2087156068] = "Loại Bỏ Nước",
    [2087388485] = "Duy trì những điều sau đây để nghỉ ngơi:",
    [2087546166] = "Tủ Hầm Mộ Vừa",
    [2087597993] = "Tạo trò chơi thất bại",
    [2087640129] = "Đũa Phép Cuộn Xoắn",
    [2088670974] = "Hỡi Kẻ Sinh Ra Từ Lửa, ngươi là kiểu người \"hữu ích\", đúng không? Chà, ta đang tiến hành một vài \"thử nghiệm\" cần sự hỗ trợ và kín đáo của ngươi. Ta phải yêu cầu ngươi lấy một \"Viên Ngọc Khát Máu\" từ Đỉnh Albaneve. Nó tiếp thêm sự tàn bạo và xảo quyệt cho kẻ thù của chúng ta phía trên Sương độc — và không có lý do gì để không chiếm lấy lợi thế đó cho bản thân. Không cần phải giao nộp, ta chỉ cần thấy sự khát khao trong mắt ngươi sau khi tìm thấy một viên.",
    [2088984694] = "Cây Giống Củ Cải",
    [2089115300] = "Một loài vật, cũng được Ngọn lửa ban phước, lan tỏa ánh sáng trong bóng tối.\n\nTìm thấy vào ban đêm ở Vùng Suối.\nCó thể dùng làm mồi câu cá, đặc biệt được các loài cá phổ biến ưa thích.",
    [2089215825] = "Tùy Chỉnh",
    [2089419416] = "Duyệt và Xem Vật Phẩm",
    [2090995047] = "Cúp Danh Năng Hydrak'Dal Bằng Vàng",
    [2091252695] = "Bắn <i>Mũi Tên Đặc Biệt</i> giờ đây sẽ kích hoạt một <b>Cơn Mưa Mũi Tên</b> từ kỹ năng <b>Bắn Nhiều Phát</b>.\n\n<i>Mũi Tên Đặc Biệt</i> bắn theo cách này sẽ trừ vào số lượng đạn của bạn.",
    [2091919279] = "Những kẻ Scavenger đang vận chuyển chiến lợi phẩm của chúng đi bằng xe ngựa. <b><keyitem>Lưỡi cưa tròn</keyitem></b> chắc hẳn đã được đưa đến một trại gần đó. <b>Đi theo con đường</b> sẽ dẫn đến đó.",
    [2092530496] = "Ta đã xa nhà, nhưng cảm giác thật tốt khi lại bước trên cõi này. Và không có mũi tên nào găm vào sườn, thật tuyệt. Ta tên là Mei-Yin. Hãy cho ta biết: Ngươi có ăn mừng Tết Nguyên Đán không?",
    [2093435860] = "Trông nàng bớt đáng sợ hơn khi không đội mũ. Tuy nhiên, mùi axit vẫn còn vương vấn.",
    [2093673535] = "Phạm Vi Nhận Thức Kẻ Địch",
    [2093828358] = "Cát",
    [2094100546] = "Kiếm Quý Tộc",
    [2094192126] = "Kẻ Lang Thang, / — Dữ Liệu Bệnh Nhân, Đã Lưu Trữ — Báo Cáo Số A.052",
    [2094537312] = "Một loại đá vôi có nguồn gốc từ vỏ sò.",
    [2094919059] = "Chiếc quần xanh lá cây cho phép người mặc lướt đi trong đám cỏ cao một cách nhanh chóng và im lặng.",
    [2095424258] = "Đài Loan",
    [2095910005] = "Thu Thập Vật Phẩm",
    [2096166216] = "Nông Dân",
    [2096346580] = "Vai trò Quản trị viên yêu cầu mật khẩu.",
    [2097874681] = "Tăng sát thương gây ra bằng Kiếm dài.",
    [2098074440] = "Giáp Ngực Quân Vương U Ám",
    [2098110729] = "Kiếm Tết Nguyên Đán",
    [2098490384] = "Một sợi dây thần kinh bị điện giật. Đây là một nguyên liệu ma thuật được săn lùng, cần thiết trong một số công thức phép thuật.",
    [2098864001] = "Nhạc Cụ Hiếm",
    [2098959923] = "Trại Scavenger",
    [2098984186] = "Một xương chậu Cyclops đầy xương. Thật kỳ lạ.\n\nVật phẩm sưu tầm này được tìm thấy ở Đỉnh Albaneve. Nó có thể được lắp ráp lại để tạo thành Bộ Xương Cyclops trên Đế Cúp Cyclops.",
    [2099210387] = "Chúng ta đã sẵn sàng để tạo ra lớp đệm tốt hơn. Điều đó sẽ bảo vệ chúng ta khỏi cái lạnh!",
    [2099348845] = "Xin chào, người đẹp.",
    [2099599210] = "Gửi Chỉ Huy <lorename>Cyrus</lorename>:\nNữ Hoàng của chúng ta đã đi đâu? Ta đang tuyệt vọng cần lời khuyên của Người!\nKhi Người quyết định <i>chia đôi đoàn xe của chúng ta,</i> đã có quá nhiều sự bối rối và hỗn loạn đến nỗi em trai ta, Gustav, đã được xếp vào <i>đoàn xe phía nam.</i> Nó có thể trông như một người đàn ông trưởng thành, nhưng nó có tâm trí của một đứa trẻ và dễ bị bối rối!! \n\nTa đã nghĩ rằng nó đang ở trong toa xe phía sau ta, ngủ... đến khi chúng ta tỉnh dậy, ta nhận ra nó đã biến mất. Gustav sẽ làm gì khi không có ta chăm sóc nó? Xin Hãy, Chỉ Huy <lorename>Cyrus</lorename>: Ta phải đoàn tụ với Gustav trước khi chúng ta hướng về <location>Rattlebleak</location>!",
    [2099784757] = "Búa Xây Dựng",
    [2099864632] = "Bạn đã có một người bạn lông lá mới. Hãy mang chúng về nhà và đặt chúng ở căn cứ của bạn! Có lẽ chúng sẽ cho phép bạn vuốt ve chúng?",
    [2100086378] = "ST Sương độc",
    [2100177473] = "Khối Xương",
    [2100639189] = "Hạ Xuống Sảnh Đường",
    [2100824955] = "Bạc như kính biển trên những bờ biển bị lãng quên từ lâu. Điều gì đó bên trong chiếc nhẫn này mang lại hy vọng.",
    [2101423057] = "Một lưỡi kiếm dễ dàng nuốt chửng kẻ thù. Nó đã khắc tên mình vào vô số cơ thể trong trận chiến.",
    [2101464313] = "Hươu Tiên Con",
    [2101510646] = "Cúp Danh Năng Hydrak'Dal Bằng Sắt",
    [2101827370] = "Chân Vịt",
    [2102165607] = "Tuyến Bọ",
    [2102273475] = "Đầu Vào Micro Âm Lượng",
    [2102296282] = "Bàn Góc Gỗ Phương Bắc",
    [2102319975] = "Đôi ủng này chắc hẳn trước đây đã được một quý tộc trang nghiêm đi lại lặng lẽ trong vườn nhà thờ.",
    [2102397323] = "Bảo vệ tay áo công phu che chắn người mặc khỏi tuyết, băng giá và bụi bẩn. Một viên thạch anh đã được gắn vào khe đá quý, cho phép dòng chảy MP tốt hơn khi niệm phép.",
    [2102481524] = "Giày Người Khôn Ngoan",
    [2102486616] = "Đèn Treo Tím II",
    [2102503499] = "Bạn đã sẵn sàng để bắt con cá đầu tiên. Móc mồi vào cần câu của bạn và đến bất kỳ vùng nước nào đủ lớn để câu cá. Hãy quay lại để cho bà thấy bạn đã bắt được gì!",
    [2103404055] = "Thuốc Độc",
    [2103474392] = "Khối Đá Tiêu Chuẩn",
    [2103646509] = "Nấm Shiitake",
    [2103655797] = "Bạn biết rằng tôi có thể giúp bạn thay đổi màu mắt, phải không? Đôi mắt là cửa sổ tâm hồn, vì vậy chúng đại diện cho \"cái nhìn\" của bạn về cuộc sống! Hãy nghe lời khách hàng của tôi — Tên anh ta là gì nhỉ? Tony? Timo? Anh ta làm việc tại một công trường xây dựng bị nguyền rủa trước khi một tai nạn thay đổi con đường của anh ta mãi mãi. Khi tôi lần đầu nhìn thấy anh ta, đôi mắt anh ta màu xanh lam rực rỡ và đầy sự điên cuồng, nhưng ánh nhìn và thái độ của anh ta đã dịu lại khi anh ta hồi phục sau sự cố. Đó không chỉ là chuyện bà già kể lại! Đó là sự thật!",
    [2104184008] = "Thư Tình Gửi Nữ Hoàng <lorename>Jezmina</lorename>",
    [2104271168] = "Trang Tiếp Theo",
    [2104495601] = "Cánh Lượn Đỉnh Cao",
    [2104631717] = "Dưới Không Độ",
    [2104731490] = "<b>Nhân Đôi Tinh Linh:</b>\nPhép thuật độc đáo của cây đũa phép cho nó cơ hội 30% để tự động tạo ra một viên đạn bổ sung.",
    [2104794835] = "Thợ rèn <npc>Thợ rèn</npc> cần một <craftingstation>Lò luyện kim</craftingstation> để chế tạo trang bị tốt hơn. Để chế tạo một <craftingstation>Lò luyện kim</craftingstation>, cần có một <keyitem>Lò nung</keyitem>.\n\nÔng ta nghi ngờ rằng những kẻ Scavenger đang giữ <keyitem>Lò nung</keyitem> cũ của mình tại mỏ của chúng ở Rừng Khải Hoàn.",
    [2104845048] = "Máng Ăn Thỏ Nhảy",
    [2104979142] = "Chúng tôi đã phải chất đầy xe ngựa với ít nhất 6 pound muối cho <location>Suối Muối</location>, vì vậy tôi đã làm thêm giờ sau khi mặt trời lặn.\n\nTôi làm việc một cách vô hồn khi cây cuốc của tôi đột nhiên va vào thứ gì đó rắn chắc. Khi tôi kéo để nới lỏng công cụ của mình, một tảng đá lớn đã được mang ra ánh sáng lờ mờ của chiếc đèn lồng. Vẻ ngoài của nó khác với lớp muối lấp lánh xung quanh, nhưng tôi hầu như không thể nhìn thấy nó trong ánh sáng yếu ớt. Nheo mắt, tôi cố gắng tập trung vào hình dạng. Nằm gọn trong lòng đá vụn là một <i>vật thể gần như hình cầu.</i> \nTôi ra lệnh cho đôi mắt mệt mỏi của mình theo dõi những đường xoáy dẫn về trung tâm nhưng ngày càng buồn ngủ hơn. Khi tôi vươn tay để lần theo nó, tôi cảm thấy một cơn đau nhói ở vai. Tôi đã đào bao lâu rồi? Tôi quyết định nghỉ ngơi.\n\nPhải mất một thời gian để hồi phục. Khi tôi vắng mặt, <i>họ đã mở một giếng mỏ mới và chặn cái cũ lại.</i> Có lẽ vì lợi ích tốt hơn. Chúng ta không thể bị phân tâm khi có một hạn ngạch cần đạt được.",
    [2105064774] = "Mei-Yin Chen",
    [2105271763] = "Tiếp Cận Tháp Của <npc>Nhà Giả Kim</npc>",
    [2105377059] = "Bàn Thờ Đổi Tên",
    [2105696886] = "Màu mắt",
    [2106053031] = "Khung Cửa Sổ Bằng Đá Tròn",
    [2106071708] = "Sát thương lên kẻ địch cận chiến ",
    [2106727197] = "Hạt Chướng Khí",
    [2107089375] = "Mũ Mùa Đông",
    [2107184449] = "Các phép Chữa thương có thể thực hiện Đòn Chí Mạng, tỉ lệ chí mạng này tăng theo Sát Thương Chí Mạng của bạn.",
    [2107266763] = "Hắn Biết Quá Nhiều",
    [2107348837] = "Tỉ Lệ Chí Mạng Tầm Xa",
    [2107511281] = "Sự Kỳ Lạ Của Hang Động",
    [2108032095] = "Đầu Quái Vật Sa Ngã",
    [2108254378] = "Thay vì khai thác tàn tích của những thời đại đã qua, bạn thề sẽ bảo vệ chúng — để duy trì sự linh thiêng của chúng cho sự tôn kính không chỉ ngày hôm nay, mà cả ngày mai.",
    [2108507217] = "Tiếp Cận Phía Bên Kia Của <location>Willow Crush</location>",
    [2108941635] = "Người Vukah",
    [2110453639] = "Tia Lửa Từ Đỉnh Albaneve",
    [2110599655] = "Quần Đạo Sư Băng Ngọc",
    [2110949263] = "Nguyên Thủy",
    [2111467926] = "Chiến Binh Bóng Tối",
    [2111544670] = "Tìm Rương \"Mất & Tìm Thấy\"",
    [2111545145] = "Thật Là Một Kẻ Tinh Nghịch!",
    [2111821840] = "Chiếc quần dệt giữ cho người mặc không bị trầy xước đầu gối.",
    [2111958412] = "Quần Kẻ Mang Dịch Bệnh",
    [2112020966] = "Chú ý, những lữ khách mệt mỏi! Đừng tin vào những lời đồn bạo lực xung quanh vùng đất này. Bên dưới lòng đất ẩn chứa một phương thuốc chữa bách bệnh cho mọi thứ đang hành hạ bạn! Với tư cách là chủ nhân mới của vùng đất này, ta, Costner Meyers, mời các bạn nếm thử \"Tiên Dược Tuyệt Vời\" của ta — thứ đã đến với ta trong một khải tượng kỳ diệu!\n\nVới khả năng Chữa thương và trao quyền, bạn sẽ thấy mình được <i>biến đổi!</i> Hãy đến, tất cả mọi người!\n\n— Costner Meyers",
    [2112569207] = "Ta Đang Nhìn Chằm Chằm Vào Ngươi",
    [2112771647] = "Ta đã đặt chúng vào một chiếc rương bên trong lò rèn. Cẩn thận khi lấy chúng ra — chúng <i>nóng bỏng.</i> \n\nTa sẽ nghỉ ngơi bây giờ. Đừng tìm ta. Ta sẽ không làm gì khác cho đến khi những vết bỏng này lành lại.",
    [2112831085] = "Đi Theo Người Đàn Ông Câu Cá Kỳ Lạ",
    [2113165637] = "Một chất độc hại, đang phân hủy, được làm cho nửa lỏng do tình trạng phân rã của nó.",
    [2113296813] = "Tăng sát thương gây ra với vũ khí cận chiến 2H.",
    [2113549601] = "Gửi Ping",
    [2113692122] = "Giường trống",
    [2113899269] = "Mũ Giáp Chiến Binh Rắn",
    [2114650769] = "Ai đó đã lên kế hoạch cho một màn biểu diễn dao găm ở New Cromville. Điều tra khu vực để thu hồi những con dao còn sót lại!",
    [2114794281] = "Ống thoát nước này sẽ loại bỏ bất kỳ lượng nước nào phía trên nó. Có thể đặt trên tường.",
    [2114943659] = "<location>Nôi Của Hoàng Hôn</location>",
    [2115309510] = "Nhà giả kim thuật đã đề cập rằng ngôi nhà cũ của ông ở <location>Lone Thistle</location> thu hút mèo vì có lũ chuột hoành hành. Ngay cả sau tất cả những năm này, vẫn có khả năng một số con mèo vẫn còn sinh sống trong khu vực.\n\nChế tạo <b>mồi thức ăn cho mèo</b> với Nông dân để thuần hóa một con mèo hoang để tiếp tục!",
    [2115327600] = "Thuốc Tẩy Vết",
    [2115550880] = "Cuối cùng, một <craftingstation>Máy Xông Khói Ong</craftingstation>! Ong sẽ thích nó... và cuối cùng ta có thể phục vụ món khoai mì nướng cay ngọt! <b>Hãy đặt nó</b> để sau này chúng ta có thể chế tạo <craftingstation>Tổ Ong Mật</craftingstation> và xem những chú ong nhỏ nhảy múa!",
    [2115729562] = "Kho Lương Thực",
    [2115828846] = "Một khối được chế tạo từ vật liệu Tăng Trưởng Sáng, phát sáng trong bóng tối.",
    [2115846467] = "Găng Tay Sát Thủ",
    [2115929817] = "Hang ổ Sương độc",
    [2117625171] = "Tiến triển! Ngoài ra — Đau Đầu!",
    [2117722262] = "Trợ Lý Nhạc Công",
    [2117737945] = "Triều đình đã gửi tin.\nChúng ta nên chuẩn bị một con tàu mới cho chuyến ra khơi đầu tiên, nhưng con tàu sẽ được gửi đi với hàng hóa mà không ai trong chúng ta được phép kiểm tra. Việc lạ lùng. Các thùng không có dấu hiệu, không có giấy phép, không có ghi chép cho sổ cái... và chúng được niêm phong.\n\nLãnh chúa cho rằng chúng có trọng lượng lớn đến nỗi những người đàn ông của ông đã được phái đến để giám sát việc chất hàng. Ta đã nghĩ sẽ thấy những cựu binh mắt tinh tường, nhưng đám người lảo đảo vào ngày hôm qua trông như nửa chết, mắt lờ đờ và lê bước chân. Họ đang gắn đại bác lên một thân tàu buôn... <i>thân tàu của ta.</i> Chưa bao giờ thấy cảnh tượng như vậy.\n\nTa không biết mục đích của chuyến hàng này, chỉ biết rằng nó khiến ta khó chịu. Lẽ ra ta phải biết những chuyến hàng nào đến và đi như lòng bàn tay của mình?",
    [2117738615] = "Ồ, bạn đã tìm thấy ba nhạc cụ sử thi rồi! Thế là đủ cho tôi tiếp tục nghiên cứu. Thật kỳ lạ... những nhạc cụ này được chế tác rất tốt, chúng hẳn thuộc về hoàng gia! Thật không may, tôi không biết tìm nhạc cụ cuối cùng ở đâu — nhưng chẳng phải Valory Nhạc Công là \"người hát rong của các vị vua\" sao? Có lẽ bà ấy sẽ biết!",
    [2119017253] = "Nó Đến Vào Ban Đêm",
    [2119119031] = "Thay Đổi Hình Dạng",
    [2119585664] = "Tăng sát thương lên kẻ địch phép thuật.",
    [2119713903] = "Khi thời gian còn lại trong Sương độc dưới %k, kẻ địch bị đánh bại sẽ rơi ra Quả cầu Bổ sung Thời gian.",
    [2119907049] = "Trở về <i>sai lầm.</i> Có răng mọc khắp nơi. Nội tạng đã bị thối rữa vì xác quá cũ. Kết luận: Hãy cân nhắc mua một con chó sống, và giết nó để có một xác chết tươi làm vật chứa.",
    [2120541401] = "Bạn đã đến Đỉnh Albaneve! \n\nMở rộng sự hiện diện của Ngọn Lửa bằng cách <b>thắp sáng Ngọn Tháp Cổ xưa</b> tại đây để ánh sáng có thể dẫn đường cho bạn trên hành trình khám phá những vùng đất xa lạ này!",
    [2120608093] = "Sát Thương Chí Mạng Lên Kẻ Địch Bị Ướt",
    [2121121113] = "Làm Việc Tại Thang Máy Hàng Hóa",
    [2121128722] = " <location>Raven's Keep</location> Nhật Ký",
    [2122238774] = "Azure Russula — một loại nấm cổ đại, tồn tại và tiêu thụ ma thuật kể từ buổi đầu của thời gian. Thật không may, không ăn được nếu không nấu chín.",
    [2122367412] = "Quần Nhà Thám Hiểm",
    [2122392560] = "Bạn đã trở về! Bạn đã tìm thấy gì? ... Một người đàn ông, bị Vukah đâm? Thật khó hiểu! Và một mảnh báo cũ, bạn nói, được viết bởi một \"Ramone Jones\"? Tôi đã nghe cái tên này trước đây... ông ấy là một nhà văn từ thủ đô! Có vẻ như ông ấy đã gióng lên hồi chuông cảnh báo về dịch bệnh Vukah của chúng ta từ lâu rồi. Tôi ước gì tôi có thể cảm ơn ông ấy... mặc dù vô ích. Có lẽ tôi không phải làm điều này một mình, sau tất cả... Cảm ơn bạn!",
    [2122565660] = "Đơn giản nhưng bổ dưỡng. Tăng cường hồi phục HP và SP.",
    [2122727249] = "Tái chế để lấy:",
    [2122783783] = "Quần áo phù hợp cho cuộc hành quân nửa đêm. Lớp giáp kim loại đủ bóng để phản chiếu ánh trăng.",
    [2122906296] = "Sóng Gỗ Trôi",
    [2123031813] = "Cờ Lệnh Chiến Tranh Của Gormander I",
    [2123460879] = "Một lọ MP được pha chế xuất sắc, phục hồi ngay lập tức một lượng lớn MP khi sử dụng.",
    [2123603903] = "Cúp Danh Năng Hydrak'Dal",
    [2124402126] = "Trượng",
    [2125533365] = "https://www.Sương độc bao phủ.com/privacypolicy",
    [2125921158] = "Cổng Tiền Đồn \"Alba\"",
    [2126050682] = "ST Lôi Ma Thuật",
    [2126191038] = "Đền Thờ Mặt Trời Ma Ám",
    [2126507465] = "Thực Vật Hoang Dã",
    [2127110954] = "Về Đá Quý Vũ Khí",
    [2127112779] = "Không có con cá nào cắn câu.",
    [2127114674] = "<b>Tiếng Vọng Hollow:</b>\nVũ khí giải phóng một tiếng vọng bất thánh, kéo dài tầm tấn công một cách kỳ diệu.",
    [2128295991] = "Luôn nhớ cung cấp thức ăn và chỗ trú ẩn cho động vật của bạn. Chúng thậm chí có thể sinh con nếu chúng ta giữ ít nhất hai con vật hạnh phúc cùng nhau và có một chiếc giường dự phòng gần đó! Như vậy có tuyệt không?",
    [2128297504] = "Hiệp Sĩ Trong Bộ Giáp Sáng",
    [2128868381] = "Chế Độ Biến Hình",
    [2129117154] = "Nồi Phế Liệu II",
    [2129305294] = "Một luống cày nông trại sẽ cho Saffron.",
    [2129351919] = "Mannequin D",
    [2130018708] = "Cột Tạo Hóa",
    [2130309808] = "Ta Không Thể Ở Lại Đây",
    [2131159480] = "Thật Không Công Bằng, Mẹ Ơi!",
    [2132215937] = "Một cây đũa phép mà các học giả tài năng về các lực lượng huyền bí đặc biệt ưa chuộng. Nó linh hoạt và phản ánh sự xuất sắc của người sử dụng.\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sức mạnh sát thương của nó. Các đòn tấn công gây thêm sát thương lên đến tỷ lệ <i>quá tải</i>.\n\n<b>Đa Xạ:</b> \nBắn nhiều viên đạn nhưng với sát thương giảm.",
    [2132299126] = "Không có sự giúp đỡ nào đến\nNếu không có nó, chúng ta không có phòng thủ\n\nCó quá nhiều kẻ địch, nhưng chúng ta không thể rút lui\nTrinh sát nói lối đi đã sập\nKhông có lối thoát\nChỉ tiến lên, vào bẫy... vào hàm của quái vật\n\nLando, tha thứ cho ta\nTa chưa bao giờ muốn mọi thứ kết thúc như thế này\n\nBerhtolf",
    [2132357469] = "Tìm Nơi Ẩn Nấp Của Người Đi Biển",
    [2132874716] = "Cọc Hàng Rào Đá Mịn",
    [2132997084] = "Chiếc quần che chắn đôi chân khỏi bụi gai và gai nhọn khi săn mồi.",
    [2133044734] = "Những Mảnh Ghép Của Quá Khứ",
    [2133938208] = " <npc>Thợ Cắt Tóc</npc> cần một nơi thích hợp để ngủ. Xây cho ông ấy một chiếc giường có mái che để tiến triển!",
    [2134369368] = "Suối Đục",
    [2134407942] = "ST Hỏa",
    [2134422516] = "Liều Lĩnh Tất Cả",
    [2136088644] = "Tìm Kiếm Viên Ngọc Khát Máu",
    [2136355330] = "Manh Mối Từ Một Pháp Sư",
    [2136412072] = "Chất lỏng này được tạo ra bằng cách nghiền nát các mảnh ectoplasm và thu thập chất nhờn thu được. Nó đã được lọc và <i>về mặt kỹ thuật</i> là vô trùng.",
    [2136591164] = "Vị Trí <npc>Nhà Giả Kim</npc>",
    [2136738318] = "Frank, Ta Sẽ Không Thu Thập Quả Gloom Nữa",
    [2136869878] = "Leo Lên Một Ngọn Tháp Cổ Xưa",
    [2137032468] = "Bạn muốn biết về các nhạc cụ sử thi? Chúng phổ biến trong các cung điện hoàng gia — tôi đã chơi một vài bản nhạc với chúng, chủ yếu là khi tôi dạy công chúa của mình chơi đàn hạc. Jezmina là tên cô ấy! Cô gái đáng yêu. Đó là chuyện từ rất lâu rồi. Có lẽ nhạc cụ của cô ấy vẫn còn ở nhà cô ấy ở Ocean's Heart!",
    [2137712534] = "Ngọt Ngào",
    [2137739989] = "Một bộ sưu tập những quả cam tươi sáng, tỏa ra ánh sáng ấm áp và mời gọi.\n\nBảng màu này có thể được tạo bằng vật liệu từ Kindlewastes.",
    [2137818235] = "Muôn Vàn Mũ",
    [2137955700] = "Các Tòa Nhà",
    [2138103660] = "Thức ăn cho mèo bổ dưỡng cho thú cưng đã được thuần hóa.\n\nNó phải được đặt vào máng ăn phù hợp.",
    [2138297946] = "Câu Đố",
    [2138408087] = "Hệ Sợi Nấm",
    [2139045908] = "Ngôi Đền Ẩn",
    [2139440763] = "Hồi phục HP đang hoạt động.",
    [2139475916] = "Cung Của Talion",
    [2139821951] = "Tấn Công Chớp Nhoáng",
    [2140581985] = "Kho Báu Nông Dân",
    [2140733664] = "Thuốc Giải Độc Cường Hóa",
    [2140780870] = "Hoàn Thành",
    [2141470970] = " <craftingstation>Cây Quay Tay</craftingstation> đã bị bỏ lại trong một <b>trại <npc>Thợ Săn</npc></b> bỏ hoang. Nó cần được trả lại cho <npc>Thợ Săn</npc> và <b>đặt trong căn cứ.</b>",
    [2141765101] = "Chuột Lên",
    [2141966844] = "Thể lực",
    [2142698143] = "<craftingstation>Máy Xông Khói Ong</craftingstation>",
    [2142889921] = "Một chiếc đũa phép khó hiểu, bị Sương độc làm cho hư hỏng. Nó bẻ cong tâm trí của người mang.\n\n<b>Nhân đôi Tinh linh:</b>\nPhép thuật độc đáo của chiếc đũa phép cho nó 30% cơ hội tự tạo ra một viên đạn bổ sung.\n\n<b>Quá tải:</b>\nChiếc đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương cộng thêm lên tới phần trăm <i>quá tải</i>.",
    [2143254576] = "Vượt lên trên, chúng ta trỗi dậy\nÁnh sáng trang nghiêm chiếu rọi khuôn mặt ngươi trước khi ánh nến lãng du\nPhía sau tiếng cọt kẹt và nứt vỡ của gỗ sồi, nó nằm\nMột bí mật được giữ bởi xương cốt giòn tan",
    [2143452502] = "Khi được trang bị vũ khí Cận chiến, bạn có thể thực hiện một đòn tấn công né tránh, lao về phía kẻ địch và gây thêm sát thương vũ khí với <b>%k</b>.\n\n<b>Chi phí:</b> 20 SP\n\n<b>Kẻ Phá Vỡ Phòng Thủ</b> \nĐòn tấn công đặc biệt này lấp đầy <i>Thanh Choáng</i> của kẻ địch đang phòng thủ gấp đôi khi trúng đòn.",
    [2143709963] = "Ta lại có cái cảm giác tê tê dưới móng tay rồi đây... dấu hiệu không thể nhầm lẫn của sự thay đổi! Ta cảm thấy thôi thúc muốn thử một màu sắc táo bạo mới. Những tông màu rực rỡ, táo bạo trong một dải màu chuyển tiếp mượt mà... giống như bầu trời lúc bình minh!",
    [2143739972] = "Kẻ Bị Ruồng Bỏ",
    [2144554004] = "Thay đổi",
    [2144612712] = "Sát thương lên kẻ địch Tầm xa ",
    [2144853660] = "Tệp cài đặt của bạn bị lỗi và phải được sửa hoặc đặt lại về mặc định để tiếp tục.",
    [2144967521] = "Bừa bộn",
    [2145449581] = "Tìm máy chủ ( địa chỉ IPv4 )",
    [2145699323] = "Loài cá bóng bẩy, vảy bạc này nổi tiếng với lớp vảy ánh kim đặc trưng dọc sống lưng, tạo nên tên gọi của nó.\n\nLoài cá này có thể nướng hoặc dùng trong công thức nấu ăn.\nNó cũng có thể được thả về nước và nuôi trong ao.",
    [2145745396] = "Từ rất lâu trước đây, con người và một nhóm Cổ nhân đã cùng nhau tạo ra một nơi trú ẩn an toàn cuối cùng cho nhân loại. Con người được an nghỉ trong <b>Hầm Cinder</b>, nơi được cho là để bảo vệ thi thể của họ khỏi rơi vào Sương độc.\n\nHọ đã kiên nhẫn chờ đợi để được đánh thức khỏi giấc ngủ không mơ của mình bởi những người <i>sinh ra từ ngọn lửa</i>.",
    [2145835204] = "Phù thủy <lorename>Ikora</lorename>",
    [2145864696] = "Nhiệt độ cơ thể hiện tại của bạn. Thân nhiệt thấp có thể gây tử vong.",
    [2145890015] = "Giáp Ngực Đỡ Đòn",
    [2146360332] = "Sách V",
    [2146771932] = "Lễ hội",
    [2147258490] = "Đặt lại vị trí",
    [2147874873] = "Vách Ngăn Phòng Bằng Tre I",
    [2147949311] = "Đỡ đòn",
    [2148140283] = "Tủ Ly Gỗ Phương Bắc Lớn",
    [2149982356] = "Ăn mừng Giao ước Ngọn lửa",
    [2150325819] = "Chùy Thách Thức",
    [2150646894] = "Chọn NPC bạn muốn đặt.\n\nSau khi được đặt, NPC phải được chỉ định vào giường trú ẩn. Nếu không được chỉ định, họ sẽ tự động chiếm một chiếc giường trống trong phạm vi 10 mét vào ban đêm.\n\nBạn có thể chỉ định thủ công bằng cách chỉ vào giường bằng Gậy phép Triệu hồi khi đã chọn NPC.",
    [2150667319] = "Ẩn mình dưới Cao nguyên Du mục",
    [2150714212] = "Bão Lộc",
    [2150903204] = "Cát Mịn",
    [2151559821] = "Kho Scavenger",
    [2151890785] = "Đền Thờ Ngọn lửa",
    [2152398522] = "Rời đi ngay!",
    [2153062109] = "Lush'Kyss: \n<i>Ta cầu xin ngài, Ngài Lancehart, hãy tránh ánh mắt đó ra! Khi hình hài ta trần trụi trước ngài dưới vòng tay của ánh trăng, ánh nhìn của ngài khiến ta xấu hổ!</i>\n\nNgài Lancehart:\n<i>Không phải xấu hổ, mà là ham muốn dâng trào trong em, Lush bé nhỏ của ta! Đôi má ửng hồng như dâu tây của em đã phản bội em!</i>\n\nLush'Kyss: \n<i>Đừng lại gần! Dòng nước của ta sâu và ấm đến nỗi có thể nuốt chửng ngài và giam giữ ngài cho đến khi ánh sáng vàng của buổi sớm mai!</i>\n\nNgài Lancehart:\n<i>Vậy thì ta phải bị giam giữ! Hãy cuốn ta vào làn sóng của em, vì trái tim ta không khao khát điều gì hơn là được ôm chặt dưới em, để ngước nhìn vầng trăng lưỡi liềm và bộ ngực tròn đầy mà nó chiếu sáng!</i>\n\nLush'Kyss: \n<i>Ôi, được tham gia vũ điệu hoang dã và tự do của dòng sông này, Ngài Lancehart, tinh thần của ngài hẳn là đã được giải phóng – nhưng ngài có cần phải thúc đẩy em ở dưới đó bằng sự thèm muốn của mình không?</i>\n\nNgài Lancehart:\n<i>Lush thân mến, thứ em cảm nhận bên dưới là đầu ngọn giáo của ta, để giữ cho chúng ta an toàn khi chúng ta chìm đắm trong khoái lạc. Ta chưa bao giờ ra đi mà không có sự bảo vệ!</i>\n\nLush'Kyss: \n<i>Ôi, thật chu đáo! Người ta luôn nên mang theo những vật bảo vệ như vậy!</i>",
    [2153668101] = "Bật / Tắt hiệu ứng thời tiết.",
    [2153841863] = "Đĩa Bạc",
    [2154315430] = "Một loại cát trắng sáng, lấp lánh, chủ yếu bao gồm vỏ sò vỡ vụn.",
    [2154697883] = "Cấp độ khu vực",
    [2154829982] = "Ta sẽ tìm đến người",
    [2156054117] = "Cảm hứng Bắt cá",
    [2156351669] = "Mảnh vỡ đơn giản này có thể được chế biến thành một Khối đá Cẩm thạch Đỏ tuyệt đẹp.",
    [2156500192] = "Một <b>mũi tên đặc biệt</b> triệu hồi dây leo tại điểm va chạm.",
    [2157125913] = "Vật phẩm này sẽ cung cấp nước vô tận cho đến khi nó bị ngập.",
    [2157469436] = "Ngày xưa, ta là một cậu bé nghịch ngợm. Ta dành mỗi ngày đến trường ở bãi biển thay vì ngồi trên ghế nhà trường, đá vào lâu đài cát của người lạ và ném đá trên mặt nước.\n\nCó lần, ta nhìn thấy một chiếc thuyền nhỏ ở phía xa, với một bóng người lờ mờ đang đứng trên đó. Khi ta tập trung chú ý vào đó, hình dáng của họ lật úp và biến đổi thành một, làm xáo động mặt nước xung quanh. Có ai đó đã rơi xuống hồ chăng? Ta đợi để thấy người đó trồi lên, nhưng không ai xuất hiện.\n\nChỉ vài khoảnh khắc sau, một sinh vật làm từ rong biển và nước mặn trồi lên từ dưới làn sóng lăn tăn bên bờ. Nó ở gần hơn nhiều so với chiếc thuyền, và khi nó đến gần, ta bắt đầu nhìn thấy một khuôn mặt xám xịt dưới đống tảo. Đó là thuyền trưởng.\n\nTa hỏi ông ta làm thế nào mà ông ta có thể vượt biển từ con tàu đang chìm đến bãi biển nhanh như vậy. Ông ta mỉm cười và nói: <i>\"Một nụ hôn của nàng tiên cá đã cho ta đôi chân, cậu bé!\"</i> rồi đi thẳng.\n\nChỉ sau này ta mới nhận thấy rằng đôi chân của ông ta đã để lại một dấu chân kỳ lạ trên cát. Câu chuyện của ông ta có thể là thật chăng?",
    [2158531371] = "Dưới Biển",
    [2158758700] = "Chất Trắng Phát Sáng",
    [2159374763] = "Hiệu ứng Lễ hội",
    [2159546440] = "Một cây Gậy phép ma thuật lấp lánh hy vọng, có khả năng tung ra các đòn tấn công ma thuật mạnh mẽ.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các lượt niệm phép và MP. Trang bị <b>lượt niệm phép</b> để niệm.",
    [2159567450] = "Truyện mới: %k",
    [2159776773] = "Gậy phép và Phép thuật",
    [2160157766] = "+1",
    [2160308538] = "Giờ tắm dài",
    [2160511273] = "Cúp Danh Năng Quái Vật Một Mắt",
    [2161114495] = "Tiến triển ngoạn mục đang được thực hiện",
    [2161621887] = "Khác",
    [2161808318] = "Sát thương ném",
    [2161844979] = "Lên cấp!",
    [2162668518] = "Đũa Phép Học Việc",
    [2162670141] = "Kẻ Sát Nhân",
    [2162748924] = "Cân bằng tất cả SP của kẻ địch theo giá trị này. Sẽ mất nhiều thời gian hơn để làm choáng kẻ địch có SP cao hơn.",
    [2162900064] = "Chuộc tội Đỏ",
    [2163329394] = "Mảnh Khảm Ngọn Lửa II",
    [2163504061] = "Lỗi dữ liệu lưu. Xóa dữ liệu lưu thất bại",
    [2164368690] = "Cửa Hầm Mộ Khổng Lồ",
    [2164516904] = "Găng tay được làm cho các chiến binh mới bắt đầu. Chắc chắn, nhưng nhanh nhẹn. Chúng sẽ chủ yếu bảo vệ bạn khỏi bị phồng rộp khi vung kiếm.",
    [2164698404] = "Trò chơi Vĩ đại nhất",
    [2165032933] = "Rìu Băng Cực",
    [2165294394] = "Tìm mồi ngon?",
    [2165977887] = "Quà tặng",
    [2166119838] = "Kích hoạt",
    [2166446965] = "Tìm Anton Godwin",
    [2167175351] = "Rìu Rừng Âm U",
    [2167373798] = "Ôi, thật tốt khi được trở lại! Wow, nơi này thực sự đã sụp đổ khi không có tôi, phải không? Ha! Chà, hãy làm cho mọi thứ gọn gàng lại một chút nhé!",
    [2167418364] = "Kháng Sương độc",
    [2167626231] = "Cơ hội Gây nguyền",
    [2168018327] = "Cửa Gỗ",
    [2168498963] = "Thượng nguồn nguy hiểm",
    [2168656722] = "Tràn đầy sinh lực",
    [2168711686] = "Mì Spaetzle Nấm Kem",
    [2168906839] = "Xương Sống Drak'Dal",
    [2169225885] = "Bản đồ đánh dấu vị trí của <npc>Nhà giả kim</npc>, ẩn mình trong một <b>Hầm Mộ Cổ xưa</b>. Họ nắm giữ kiến thức và sự thật vĩ đại về các loại thuốc và phép thuật.",
    [2169811204] = "Cốc Tràn",
    [2169938573] = "Bạn có thể <b>leo</b> các bức tường được trang bị <b>thanh sắt.</b> Những <b>Tường Leo</b> này có thể được tìm thấy trong thế giới hoặc trong các hầm ngục. Đi đến Tường Leo để bám vào thanh sắt.\n\nLeo trèo đòi hỏi <b>SP</b>. Khi bạn hết SP khi đang leo, bạn sẽ bị rơi.",
    [2170390868] = "<b>Anh họ Rolf của tôi bị mất tích!</b>\nAnh ấy đã đến Orville để làm thợ lặn ngọc trai nhưng không bao giờ trở về.\n\nRolf có thể là một kẻ liều lĩnh, nhưng anh ấy luôn gửi tin nhắn mỗi khi anh ấy bỏ đi!\n\nBất cứ ai đã nhìn thấy anh ấy: hãy cho tôi biết anh ấy ở đâu hoặc mang anh ấy về nhà!\n\n- Willy",
    [2171292635] = "Bạn của ta, nếu ta có một <b>giường trú ẩn</b>... ta có thể thực sự phát huy hết tài năng của mình.",
    [2171782668] = "Một con dao chặt được phủ axit và mật. Nạn nhân của nó có thể chữa lành vết thương – nhưng hiếm khi ngăn chặn được độc tố lan rộng.",
    [2172061577] = "Một chiếc nhẫn tỏa ra sự giàu có và bi kịch. Nó có được giải thoát khỏi ngón tay ngà của một người bạn, một người anh em, một đứa trẻ may mắn không? Liệu lòng trung thành của nó có bị phản bội, lời hứa máu của nó có bị phá vỡ? Dù câu chuyện chiếc nhẫn này có kể gì, những chủ nhân cũ của nó đã đi xa.",
    [2172082042] = "Màu sắc Cho Vũ điệu",
    [2172716372] = "Xương của Kẻ thù Chúng ta",
    [2173330110] = "Dân làng Hannah Reed đang tìm con gái mình và hy vọng bạn có thể tìm thấy cô bé gần Đồi Lễ tế Vukah.\n\nĐiều tra khu vực và tìm kiếm những linh hồn thuần khiết ở đó!",
    [2173693875] = "Nhìn xuyên qua bức màn cùng ta.",
    [2174905947] = "Quần Cai Ngục",
    [2175501037] = "Loại cơ thể",
    [2175879473] = "Mùa ma quái đã đến! Sử dụng cuốn sách này để học cách trang trí nhà cửa của bạn bằng các đạo cụ theo chủ đề Halloween.",
    [2175881490] = "Hãy thể hiện linh hồn rực cháy của bạn và xua đuổi mọi tà ác một lần và mãi mãi! Ánh sáng sấm sét và gầm thét với mỗi nhịp đập trái tim.",
    [2176050763] = "Dao Găm Phá Vỏ",
    [2176835059] = "Hỡi Kẻ mang Lửa, ta đã đi khắp thế giới – và ta đã thu thập cả những món đồ lặt vặt lẫn truyền thống trong những chuyến đi của mình! Những kỷ vật này kể những câu chuyện về một thời đại khác – cổ xưa nhất là hóa thạch ta tìm thấy! Nếu chúng ta có nhiều hơn, chúng ta có thể tạo thành một bộ sưu tập đầy đủ và trưng bày nó một cách thích hợp!",
    [2177222232] = "Một đôi găng tay cổ điển. Chúng không khiến bạn muốn ném một quả cầu tuyết sao?",
    [2177857886] = "Xác nhận Xóa",
    [2178290533] = "Đỉnh cao của nghệ thuật bào chế thuốc. Nó có được tên sau khi cứu người dùng khỏi vô số tình huống cận kề cái chết.\n\nPhục hồi ngay lập tức một lượng HP không thể tin được.",
    [2178456289] = "Bóng của mũi tên lướt qua chiến trường. Sự hiện diện của nó nhanh chóng và thoáng qua, một giấc mơ ban ngày được mang theo bởi một cơn gió - nhưng tác động của nó lại chính xác đến mức tàn khốc.\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n",
    [2179128028] = "Chiếc nhẫn của \"Chỉ huy <lorename>Cyrus</lorename>\" được tìm thấy trong miệng của một sinh vật lớn ở The Pike.",
    [2179553496] = "Giàn Phơi Cá",
    [2179606917] = "Mei-Yin Chen",
    [2179738500] = "Găng Tay Cai Ngục",
    [2179750241] = "ST Phép",
    [2179851890] = "Nhanh Như Điện",
    [2179894365] = "Ếch Trong Cỏ",
    [2181006976] = "Bộ Lọ Nhỏ",
    [2181191283] = "Thời gian hiệu lực của Buff Nghỉ Ngơi của bạn được tăng thêm %k.",
    [2181661936] = "Nghiên cứu Phòng Nghiên cứu Hollow của Balthazar",
    [2182004973] = "Những người mới đến đã không lãng phí thời gian khai phá, xây dựng một thứ gì đó. Sự quyết tâm của họ... thật cuồng tín. Một <b>Thánh Địa Ngọn lửa</b>, Salim nói.\n\nMột vài đêm, tôi đã nán lại gần đoàn lữ hành. Salim khăng khăng. Bên bếp Ngọn lửa, họ nói về quê hương, về cát bụi, và về sự tàn lụi đang lan tràn. Quá nhiều nỗi buồn.\n\nSalim nói tôi giống như một bông thủy tiên, dấu hiệu đầu tiên của mùa xuân. Hắn là một kẻ ngốc... dù là một kẻ ngốc ngọt ngào.",
    [2182269095] = "Mũ Trùm Dân Du Lâm",
    [2182325074] = "Tìm Lò Rèn Đá Quý để lắp Đá Quý",
    [2182388374] = "Một mũi tên đơn độc có thể bị gãy, nhưng nhiều mũi tên cùng nhau thì không thể phá vỡ. Bạn nên tìm những người khác để tham gia cùng chúng ta.",
    [2182463400] = "Giày Đỡ Đòn",
    [2182491113] = "Ta có ngửi thấy mùi cá tươi không?",
    [2182540898] = "Bộ giáp ngực được trang trí bằng vàng lấp lánh và các tinh thể xanh lục rực rỡ khiến nó trở thành một tấm khiên và một tuyên bố về sức mạnh bền bỉ. Hãy cẩn thận với những miếng đệm vai có gai!",
    [2182588178] = "Đèn Sàn Màu Cam I",
    [2182942334] = "Rung Màn Hình",
    [2183363821] = "Ta không thể chờ đợi để tạo ra các món hải sản mới!",
    [2183733682] = "Vương Miện Hoàng Gia",
    [2184144198] = "Bộ Pháp Sư",
    [2184190702] = "Bạn đã đến mỏ Albaneve Summits. \n\n<b>Tìm kiếm trong mỏ</b> để tìm manh mối về bảng màu!",
    [2184488269] = "Nổi quá sâu.",
    [2184523659] = "Tìm Vật Phẩm Mỹ Phẩm Ở Vùng Đất Mùa Xuân",
    [2184550779] = "Kindlewastes",
    [2185338031] = "<craftingstation>Lò Luyện Kim</craftingstation>",
    [2185632916] = "Chậu Cây",
    [2186249930] = "Bạn đã đánh bại kẻ địch bên trong Lò Rèn Đá Quý và phát hiện ra chúng đang giữ một tài nguyên gọi là <b>\"Tinh Chất Cổ Đại\".</b> \n\nTrong khi Lò Rèn Đá Quý vẫn còn nguyên vẹn, phần còn lại của thánh địa nhỏ đã bị lục soát. Có lẽ Fell đã đến đây để chiếm lấy Tinh Chất Cổ Đại được sử dụng trong việc tăng cường vũ khí cho chính chúng.\n\n<b>Lần theo dấu chân của Fell</b> và tìm hiểu xem chúng đã mang tài nguyên năng lượng dự trữ đi đâu!",
    [2186317049] = "(%k/%k)",
    [2186499477] = "Kháng Vật Lý",
    [2187291928] = "Tất cả những <npc>Thợ Mộc</npc> khác sẽ cười nhạo tôi nếu họ biết tôi không có <craftingstation>Máy Cưa Bàn</craftingstation>! Trừ khi tất cả họ đều đã chết. Đó là trò đùa của tôi, tôi đoán.",
    [2187606260] = "Đây là một khu trưng bày các vật phẩm Sưu tập Hóa thạch thường được tìm thấy trong các mỏ đá, mạch vật liệu hoặc địa điểm khai quật.",
    [2188199961] = "Latte",
    [2188211081] = "Khai Thác Điểm Yếu",
    [2188334121] = "Thanh Kiếm Lửa Lớn Song Sinh",
    [2188478038] = "Hạt Cà Phê Xay",
    [2189251025] = "Các liên kết quan trọng bị thiếu. Một liên kết được đặt trước sẽ được sử dụng.",
    [2189302189] = "Vật Liệu Mọc Lan",
    [2189469041] = "Tối Đa",
    [2189788767] = "Nhật Ký Thuyền Trưởng, Ngày Thứ Sáu",
    [2189842473] = "Một bộ giáp ngực mạ vàng, nặng nề và uy nghiêm — xuyên thủng nó sẽ không dễ dàng.",
    [2190437338] = "Một phần của Giáp Lính Đánh Thuê.",
    [2190482863] = "Đũa Phép Bí Ẩn",
    [2190509705] = "Cửa Kệ Sách Bằng Gỗ Thô Bí Mật",
    [2190599474] = "Nhà Vệ Sinh Gỗ",
    [2190712340] = "Rìu Chặt",
    [2191463143] = "Nghỉ Ngơi Cấp 1",
    [2191601584] = "Mũ Tiệc Màu Lục Lam",
    [2191624987] = "Với mỗi mục tiêu bạn đánh trúng bằng <b>Mũi Tên Nổ</b>, sát thương của nó sẽ tăng thêm <b>1%</b>.",
    [2193749487] = "Tìm Kiếm và Giải Cứu Capybara",
    [2193814850] = "Đèn Màu Sặc Sỡ",
    [2193940605] = "Triển Vọng Giếng Kindlewastes",
    [2194399866] = "Lắp ráp lại một tấm thảm treo tường quý giá bằng khu trưng bày này.",
    [2194455532] = "Thành công!\nNhặt con vật lên và mang nó về nhà.\nXây dựng một chuồng, cho nó ăn và cung cấp chỗ ngủ.",
    [2194859247] = "Tinh Linh Ánh Sáng",
    [2195127610] = "Thêm 1",
    [2195481397] = "<npc>Nông Dân</npc> Cần Nơi Trú Ẩn",
    [2195528272] = "Đến bây giờ bạn đã biết về quán rượu cũ của Nông dân ở <location>Brittlebush</location>. Bà ấy đã tự mình xây dựng quán rượu và có thể vẫn còn vật liệu xây dựng được cất giữ ở đó. Tìm <b>quán rượu của bà ấy ở trung tâm thành phố</b> và tìm kiếm chiến lợi phẩm còn sót lại!",
    [2195773265] = "<img missing> Vô hiệu hóa",
    [2195880440] = "Hiệu Ứng Thức Ăn",
    [2196924151] = "Không Gian Đầu Ra",
    [2196925046] = "ST Đập Tăng ",
    [2197006444] = "Quần Nhà Thám Hiểm",
    [2197515479] = "Tìm Và Cứu Linh Hồn Rochelle",
    [2198265645] = "Một Căn Phòng Bí Mật",
    [2198384799] = "Sử Dụng Rương Ma Thuật",
    [2198869897] = "So Sánh Trang Bị",
    [2199047955] = "Kindlewastes Hoang Tàn",
    [2199083662] = "Lý Thuyết Mới!",
    [2199137849] = "Mở Rương Bí Mật Ở Bến Cảng",
    [2199696967] = "Một loại thuốc giải độc cải tiến sẽ chữa khỏi bệnh ngộ độc và ngăn chặn lần ngộ độc tiếp theo.",
    [2200600007] = "Găng Tay Xuyên Dương",
    [2200716819] = "Nhà Chưng Cất",
    [2200719111] = "Bắt nguồn từ Kháng Lạnh. Thời gian hiệu lực còn lại của bạn trước khi bị Hạ Thân Nhiệt.",
    [2201526852] = "ST Lôi",
    [2201753865] = "Điểm Du Lịch Nhanh Đã Mở Khóa!",
    [2201797884] = "Hàng Rào Gỗ Thô Sơ I",
    [2201901524] = "Trang Trại Dewdrop",
    [2202301438] = "Lăn Xuống",
    [2202851832] = "Chúng Ta Có Thể Thêm Đèn...?",
    [2202896200] = "Mùi thoang thoảng của ngũ cốc, những ngày hè ngọt ngào và mật ong.",
    [2203251844] = "Bàn Đá Granite Tráng Lệ",
    [2203407859] = "Làm gì đó đúng đắn",
    [2203443112] = "Ròng Rọc",
    [2203476720] = "Hỡi Kẻ Mang Lửa, ta phải làm phiền ngươi. Một <craftingstation>Sổ Tay Thực Vật và Cây Con</craftingstation> sẽ vô cùng hữu ích!",
    [2203785328] = "Mỏ Đá Glimmer Rock",
    [2203896684] = "Đến Địa Điểm",
    [2204027448] = "Sẵn sàng cho một sự thay đổi?",
    [2204266340] = "Hình dạng mái nhà",
    [2204784950] = "Chế Độ Hiển Thị",
    [2204896809] = "Đặt làm Điểm Dẫn Đường",
    [2205123703] = "Vải của chiếc quần rộng thùng thình này rủ xuống như những con sóng trên biển xanh ngắt.",
    [2205212026] = "Bình Đá Vôi Chạm Khắc III",
    [2205359525] = "Tìm Ramone Jones",
    [2205462622] = "NHÀ cấp 2",
    [2205849206] = "Phần trung tâm của một <craftingstation>Lò Rèn</craftingstation>.",
    [2206563341] = "Một Ngày Yên Bình",
    [2206611678] = "Một bộ giáp ngực nhẹ nhàng, đơn giản để bổ sung cho phần còn lại của bộ giáp.",
    [2206687650] = "Đồ Nội Thất",
    [2207005133] = "Chế Tạo Diều Lượn Cao Cấp",
    [2207183860] = "Cho phép bạn tấn công nhanh hơn với Kiếm 1H và Rìu.",
    [2207189084] = "Chiến Trường Lịch Sử",
    [2207211147] = "Một Lời Chào Lạnh Lẽo",
    [2207530326] = "Một đoàn lữ hành nhỏ gồm những người tị nạn đã đến hôm nay từ Kindlewastes. Một hành trình dài. Tôi chưa bao giờ giỏi đối phó với người lạ, nhưng không có thời gian để mách lẻo. Tôi lao vào công việc, băng bó vết thương. Một cuộc chiến sinh tử, ngay cả bây giờ. Thật không may, một số đã mất. Chúng tôi đã an táng họ <b>trong hầm mộ bên dưới</b>. Cầu mong những cơn gió phương Bắc dẫn họ đến thế giới bên kia.\n\nCó một người có thể sống sót sau tất cả. Một vết thương sâu ở chân - nhưng có lẽ chưa quá nặng. Người bị thương, Salim, cười rất nhiều. Anh ta nói anh ta nợ tôi mạng sống của mình... chỉ là may mắn, tôi nghĩ.",
    [2207694655] = "Chào mừng đến với bản Demo Sương độc bao phủ! Là một trò chơi đang trong quá trình phát triển, bạn có thể gặp phải lỗi và các vấn đề về hiệu suất.\nNếu có, vui lòng nhấn F1 trong trò chơi để báo cáo chúng.\nCảm ơn và chúc bạn vui vẻ!",
    [2209004081] = "Chế độ",
    [2209145322] = "Trại Thợ Mộc",
    [2210239028] = "Chuột của Vùng Đất Cháy",
    [2210449824] = "Bình Minh Lờ Mờ",
    [2210481993] = "Một phần của Giáp Pháp Sư.",
    [2210638222] = "Nhận một điểm Sức bền cho mỗi hai cấp độ của Ngọn Lửa.",
    [2210880541] = "Đá Hỗn Hợp",
    [2211250770] = "Ngươi cần trang bị tốt hơn, và ta cần một <craftingstation>Lò Nung</craftingstation> để chế tạo cho ngươi! Nếu ngươi có <keyitem>Nồi Nung</keyitem> cũ của ta, ngươi có thể chế tạo một <craftingstation>Lò Nung</craftingstation>. Ta nghĩ chúng ta có chung một vài mục tiêu ở đây, phải không?",
    [2211386763] = "Một cây rìu đáng sợ, mỗi nhát vung 2H nặng nề đều khiến nạn nhân run rẩy vì lạnh lẽo.\n\n<b>Tiếng Vọng Hollow Tuếch:</b>\nVũ khí giải phóng một tiếng vọng tà ác, mở rộng phạm vi tấn công một cách kỳ diệu.",
    [2211729309] = "Nghiêng trái/phải",
    [2211931593] = "Ngươi đã kích hoạt một cái bẫy. Đã đến lúc hành động!\n\n<b>Tìm tất cả các nút để mở lối thoát khỏi ngôi đền đang ngập nước!</b> Các tầng trên sẽ chứa kho báu mà ngươi tìm kiếm!",
    [2212172908] = "Đá Hòm Lừa Bịp",
    [2213009065] = "Cuộc Đào Thoát Của Công Nhân Nhà Thờ",
    [2213064818] = "Tia Lửa Chính",
    [2213261338] = "Mũ Nhà Thám Hiểm",
    [2213280788] = "Mồi Ăn Cho Chim",
    [2213670317] = "Trưng Bày C",
    [2213693638] = " <npc>Nông Dân</npc> muốn có một <keyitem>Ấm Nước</keyitem> để nấu thức ăn ngon hơn trên <craftingstation>Bếp Nấu</craftingstation>. Bà ấy gợi ý tìm người bạn của mình, một người đàn ông tên là <lorename>Raúl</lorename>, ở <b><location><lorename>Pikemead</lorename>'s Reach</location></b> để lấy lại <keyitem>Ấm Nước</keyitem> của bà ấy.\n\n<b>Để đến <location><lorename>Pikemead</lorename>'s Reach</location>, cần Cấp độ khu vực 3.</b> Tăng Cấp độ khu vực bằng cách <b>hiến tế</b> cho Ngọn Lửa.",
    [2213763568] = "Kéo Câu",
    [2214968496] = "Mei-Yin Chen",
    [2215840094] = "Khăn Trùm Đầu",
    [2216053447] = "Tìm Ngư Dân Bị Nguyền Rủa Ở <location>Pondsworth</location>",
    [2216076564] = "Khối Ánh Sao",
    [2216245404] = "Tấm Màn Xanh",
    [2216453328] = "Hoang dã sẽ khuất phục trước ý chí của ngươi ngay lập tức khi ngươi đối mặt với nó trong đôi ủng chắc chắn, chống cắn này.",
    [2216609701] = "Thức ăn Hươu Tiên Dưỡng chất cho động vật thuần hóa trong trang trại của bạn.\n\nPhải đặt trong máng ăn phù hợp.",
    [2217594087] = "Đến Lăng Mộ Bị Chôn Vùi",
    [2217972046] = "Mọi thứ đều kết thúc.",
    [2217987749] = "Một bản cập nhật của trò chơi đã có sẵn. Bạn cần tải xuống phiên bản mới nhất của trò chơi để sử dụng các tính năng trực tuyến.",
    [2218167861] = "Tái Chế Ngọc",
    [2218905432] = "Kiếm Hào Quang",
    [2219561009] = "Súp Linh Thể Cường Hóa",
    [2219733958] = "Chiếc mũ của một hiệp sĩ đã bị lãng quên từ lâu. Với một chút đánh bóng, nó sẽ tốt như mới.",
    [2220818817] = "Nền Gỗ",
    [2220896138] = "Đá Hắc Diên",
    [2221001248] = "HP",
    [2221105057] = "Một cư dân của khu cảng ở <location><lorename>Pikemead</lorename>'s Reach</location> <b>đã giấu một chiếc rương ở đâu đó trong tầng hầm gần ngập nước của mình.</b> Tìm chiếc rương và mở nó!",
    [2221277286] = "Cánh cổng này có thể hạ xuống hoặc nâng lên để kiểm soát dòng chảy của nước xung quanh nó. Nó hoàn hảo cho những người làm vườn muốn có một cách hiệu quả để tưới cây của họ!",
    [2221334969] = "Thùng Tre II",
    [2221680432] = "Một vật liệu xây dựng bị bỏ quên, thường được sử dụng để xây dựng những bức tường cao và chắc chắn. Khối này đã bảo vệ cư dân của nhiều thành phố trước khi sụp đổ.",
    [2221958356] = "Trang Phục Đầu",
    [2222446512] = "Xanh lá và nâu với một chút vàng, như lá rơi vào một ngày thu chậm rãi.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Vùng Đất Cháy.",
    [2222533807] = "Thành Công Sấm Sét",
    [2222756388] = "Cây Trầu Bà",
    [2223312061] = "Đọc Obelisk Cổ Đại Vùng Đất Cháy",
    [2223423137] = "<b>Nhà của thợ dệt</b> ở <location>East Lapis</location> đã được tìm thấy. <craftingstation>Khung Cửi</craftingstation> cho <npc>Thợ Săn</npc> hẳn phải ở đâu đó bên trong.\n\nNó phải được thu hồi để có thể chế tạo bộ đệm và giáp tốt hơn.",
    [2223627080] = " <craftingstation>Cối Xay</craftingstation> được tìm thấy bên trong phòng thí nghiệm bí mật của <npc>Nhà Giả Kim</npc> sau một cánh cửa đóng kín. Nó nên được trả lại cho chủ sở hữu xứng đáng của nó.\n\n<b>Đặt</b> <craftingstation>Cối Xay</craftingstation> vào căn cứ sẽ cho phép các công thức chế tạo mới.",
    [2224304486] = "Nhà Sưu Tập muốn xem xương nguyên vẹn của một người khổng lồ thực sự. Ghé thăm hang động và trại của họ ở Dãy Núi Albaneve để tìm các chi của những người khổng lồ này, và lắp ráp lại chúng thành một bộ sưu tập đầy đủ tại căn cứ của bạn!",
    [2225041796] = "Sửa Đổi Cây Kỹ Năng",
    [2225266883] = "Nhanh nhẹn",
    [2225386719] = "Chế tạo tại Nhà Giả Kim",
    [2225402625] = "Dễ",
    [2225462266] = "Nâng cấp",
    [2225746946] = "Ngọc Trai",
    [2225748766] = "Áo giáp của một hiệp sĩ. Nó có một hào quang anh hùng đang phai nhạt.",
    [2225775557] = "Sương độc Bao phủ",
    [2225989865] = "Một Cuộc Sống Tẻ Nhạt",
    [2226035497] = "Khám Phá <location>Quần Đảo Jasper</location>",
    [2226510127] = "Vĩnh Hằng Đóng Băng",
    [2227058349] = "Nếm máu của chúng và hạ gục từng tên một.",
    [2227103814] = "Đèn Sàn Màu Cam II",
    [2227714309] = "Vật phẩm sưu tầm này được tìm thấy ở Revelwood.",
    [2227858513] = "Bồn Rửa Mặt Sương Mù có màu sắc rực rỡ. Bầu trời xanh phản chiếu trong làn nước trong vắt — và vào ban đêm, làn nước phát sáng mờ ảo, như thể vẫn giữ lại ký ức về màu sắc của ban ngày.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Bồn Rửa Mặt Sương Mù.",
    [2227954774] = "Chế Tạo Diều Lượn",
    [2228132485] = "Dân làng Robert Gibson nhớ vị hôn thê của mình, Kaori. Lần cuối cùng cô ấy được nhìn thấy là ở <location>East Lapis</location>, đang chờ đợi một gói quần áo và vải vóc mà cô ấy dự định gửi đi.\n\nĐiều tra Nhà của Thợ Dệt ở <location>East Lapis</location> để tìm kiếm manh mối!",
    [2228729002] = "Nhấn <b>%k</b> để khóa mục tiêu vào kẻ thù của bạn. Nhấn <b>%k</b> để né tránh nguy hiểm.",
    [2229790461] = "Điều chỉnh tần suất tấn công của kẻ địch.",
    [2229933128] = "<lorename>Gormander</lorename>",
    [2229977030] = "Tìm Kiếm Tàu Đắm",
    [2230494756] = "Bình Hoa Gốm",
    [2231248394] = "Một cây cung được chế tác tinh xảo, được sử dụng bởi những thợ săn rừng dày dạn kinh nghiệm.",
    [2231349761] = "Vật phẩm đặc biệt đã nhận!",
    [2231389373] = "Kích hoạt Sóng xung kích khi bạn đỡ đòn hoặc <b>Áp Đảo</b> kẻ địch.\n\nSóng xung kích đẩy lùi kẻ địch xung quanh. Nó cũng lấp đầy <i>Thanh Bị Choáng</i> của chúng, tỷ lệ với thuộc tính Sức mạnh của bạn.\n\n<b>Đỡ đòn</b>\nKhi được trang bị Khiên, một cú đỡ đúng lúc sẽ <b>đỡ đòn</b> tấn công.\n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang đỡ đòn hoặc đỡ đòn tấn công của chúng sẽ lấp đầy <i>Thanh Bị Choáng</i> của chúng cho đến khi chúng bị <b>Bị Áp Đảo</b>.\nKẻ địch <b>Bị Áp Đảo</b> sẽ mở ra cho các Đòn Tấn Công Tàn Nhẫn.",
    [2231635858] = "Không có vật phẩm nào có thể nhuộm màu.",
    [2231704660] = "Ta không thể tin được! Dì Braelyn, còn sống! Bà ấy trông y hệt như ta nhớ! Chà, có lẽ cao hơn một chút.",
    [2231758572] = "Mồi câu cá",
    [2232346064] = "Mẹ Rồng",
    [2232961464] = "Một chiếc mũ ba góc được phóng đại một cách lộng lẫy, che chắn đầu người sử dụng khỏi tuyết rơi. Sừng uy nghiêm là một chiến tích có thể đeo được, đại diện cho linh vật của người đội.",
    [2233277701] = "Găng Tay Kẻ Săn Đầu Lâu",
    [2234084084] = "Lồng Tre I",
    [2234493293] = "Pháo Đài",
    [2234551936] = "Là con cháu của Mẹ Rồng Vesztah, tất cả chúng ta đều khao khát vinh quang. Chỉ những người vĩ đại nhất mới thăng hoa lên vùng đất phía trên cơn bão sau khi chết: Ark Morgo.\n\nNgười đầu tiên bắt đầu hành trình này là Merphisz. Nở ra trên một bờ biển đá, ngay từ đầu anh đã say mê những con sóng.\n\n<i>\"Những vùng nước hoang dã này định hình bờ biển, quyết định nơi sự sống có thể nảy mầm! Ta sẽ vượt qua bóng ma luôn thay đổi này, với sự thờ ơ và ý muốn thất thường của nó! Ta sẽ dong buồm đến những bờ biển xa xôi và gieo rắc hạt giống của chúng ta, để biến tất cả màu xanh thành biểu tượng cho vòng tay của mẹ!\"</i>\n\nĐược định hình bởi biển cả, anh đã học ngôn ngữ của nó và bắt đầu hiểu thủy triều lên xuống của nó. Quyết tâm dẫn dắt bộ tộc mới thành lập của mình, Drak'Mer, đến những bờ biển trù phú, anh ta lên đường về phía chân trời - và tìm thấy một quần đảo nằm sau một cơn bão dữ dội.\nGiơ cây đinh ba của mình lên, anh ta thách thức cơn bão trong một cuộc đấu tay đôi, nhưng sét đánh, và Tinh thần của Merphisz được gọi đến Ark Morgo. Bộ tộc của anh ta đã đến quần đảo an toàn và vẫn thống trị vùng biển khơi.",
    [2234946977] = "Tuyến Nhện",
    [2235120576] = "Một khối màu vàng phát quang thu hút ánh mắt bạn bằng những lời hứa thì thầm về sự giàu có và bí mật.",
    [2235318848] = "Kế Hoạch Bị Phá Hủy",
    [2235352509] = "Cư dân của Embervale đôi khi đầu tư vào bạc với hy vọng nó sẽ giữ giá trị trong thời kỳ khủng hoảng. Một cuộc khủng hoảng đã đến, nhưng bạc đã giúp ích rất ít.",
    [2235539593] = "- Cày ruộng\n- Dọn dẹp (loại bỏ mạng nhện!)\n- Mua nến mới -> lấy tiền xu từ <i>hòm bạc?</i>\n                                 -> Cần sửa thang tầng hầm\n- Di chuyển các thùng rượu vang về vị trí cũ",
    [2235639211] = "Găng Tay Đỡ Đòn",
    [2236071623] = "Xuyên Thấu",
    [2236228005] = "Ta Muốn Về Nhà",
    [2236982317] = "Lửa",
    [2237126631] = "Cần Câu Cải Tiến",
    [2237345642] = "Khám phá Hang ổ Sương độc",
    [2237547268] = "Athalan",
    [2237594500] = "Máu thô được chiết xuất, pha loãng và giả kim thuật. Biến đổi, biến đổi. Nóng chảy và tái sinh.\n\nSức mạnh sâu sắc, nuôi dưỡng cơ thể của những người trẻ nhất ở Embervale, làm thối rữa chúng. Chúng ta đã thất bại, bị mù quáng bởi sự khắc kỷ của mình.\n\nHãy để chúng ta hướng ánh mắt trở lại bầu trời — vì cái lõi rỗng tuếch này không thể cứu vãn được.",
    [2237652679] = "<craftingstation>Dụng Cụ Rèn</craftingstation>",
    [2238017915] = "Manocanh C",
    [2238119181] = "Thiếu Thức Ăn",
    [2238584576] = "Bạn cần những Người Sống Sót hạnh phúc để củng cố Ngọn Lửa. Tìm những linh hồn bị lạc và cung cấp cho họ những chiếc giường trú ẩn!",
    [2238973313] = "Cúp Danh Năng Rồng Ma Trác Sa Ngã Bằng Vàng",
    [2239096485] = "Quần Dài Thợ Săn",
    [2240661157] = "Vâng, vâng.",
    [2240955125] = "Đánh bại Kẻ Trộm Mật Ong Vukah",
    [2241389046] = "Một loại thuốc nhuộm màu tím, thường được sử dụng để tạo ra những bộ trang phục lộng lẫy cho hoàng gia.",
    [2241474973] = "Những ngọn núi sẽ là nấm mồ của ngươi, Loraine.\n\nNhững Tượng Đài không đáng đâu. Dù ngươi nghĩ chúng ẩn giấu bí mật gì, chúng cũng sẽ dẫn ngươi vào con đường tăm tối. Một con đường lạnh lẽo, tăm tối, Loraine. Đỉnh núi vẫn còn đầy rẫy binh lính, và ta nghi ngờ chúng sẽ để ngươi sưởi ấm đôi tay bên lửa trại của chúng. Nhưng ta không chỉ sợ con người. Ta kinh hoàng trước <i>sinh vật có cánh.</i> Ngươi chưa đọc nghiên cứu của đồng nghiệp chúng ta sao?! Ngươi không biết truyền thuyết sao? Chúng sẽ xé xác ngươi trước khi cái lạnh buốt giá làm ngươi tím tái!\n\nNgươi thậm chí còn không thể <i>chắc chắn</i> rằng <b>Những Tượng Đài sẽ dẫn ngươi đến vương quốc cổ đại.</b> Làm ơn, ở lại đây với ta. Chúng ta hãy uống trà hoa cúc bên sông như chúng ta từng làm!\n\nĐó là tự sát, Loraine. Đó là tất cả những gì ta có thể nói.\nLuôn yêu ngươi, Nala.",
    [2241885752] = "Nếu cơm trắng nấu chín quá nhạt nhẽo đối với bạn, thì cơm rang này có thể đáp ứng nhu cầu của bạn. Trứng thêm vào làm phá vỡ kết cấu hạt của cơm, và rau củ tạo ra một hương vị bùng nổ!",
    [2241966310] = "Một lưỡi kiếm nóng bỏng được truyền sức mạnh từ trái tim sa mạc. Nó có thể làm tan chảy cả tuyết và da thịt.",
    [2242128404] = "Cửa",
    [2244163136] = "Một thanh kiếm quý tộc gây ấn tượng với ánh vàng và lưỡi kiếm rộng. Có lẽ chủ nhân trước đây đang bù đắp cho điều gì đó.",
    [2244356501] = "Giấy tờ quá nhiều!",
    [2244574119] = "Giá Treo Gắn Tường Vũ Khí Cận Chiến Hai Tay",
    [2244599212] = "Rìu Mặt Trời",
    [2244623647] = "Thay đổi Vật liệu",
    [2245803979] = "Sao Băng Chướng Khí",
    [2247007898] = "Hang Ổ Buôn Lậu",
    [2247251549] = "Găng Tay Chim Ưng",
    [2247557214] = "Thay chậu",
    [2247614697] = "Các công cụ cơ bản cần thiết cho một phòng thí nghiệm.",
    [2247884711] = "Mũ Giáp Quân Vương U Ám",
    [2248837897] = "Kháng Băng",
    [2249244720] = "Một con dao găm có thể dễ dàng giấu dưới tay áo lộng lẫy hoặc váy áo sang trọng. Nó nhanh chóng và dễ dàng rút ra khi cần thiết!\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [2249605361] = "Bạn đã tìm thấy một câu chuyện cổ tích về một nàng công chúa làm rơi quả bóng vàng xuống nước, và bị buộc phải kết hôn với một hoàng tử ếch sau khi hắn nhặt đồ chơi cho nàng. Có lẽ câu chuyện còn nhiều điều hơn những gì mắt thấy. Hãy tìm kho báu dưới nước!",
    [2249940432] = "Tìm và thuần hóa một con mèo hoang",
    [2250376811] = "Xe Kéo Lớn",
    [2250737111] = "Kẻ Lừa Đảo",
    [2250969263] = "Lớp Đệm",
    [2251536357] = "Cuốn Sách Bí Ẩn",
    [2251748586] = "Còn gì nữa không?",
    [2252106853] = "Đạt cấp 35.",
    [2252623748] = "Một phần của bộ giáp Cung Thủ.",
    [2252930864] = "Hành trình ấn tượng",
    [2252949686] = "Động vật trang trại nhỏ",
    [2253547297] = "Người chơi của bạn có thể gặp phải những trục trặc.",
    [2253663002] = "Đèn Chùm Đồng Thiếc",
    [2253803732] = "Thánh địa của chúng ta giữa Hollow, bị che mắt từ bên trong",
    [2254398727] = "Dân làng, hãy cảnh giác! Các ngươi phải cầu nguyện ở nơi khác, vì những sảnh đường này bị ma ám! Ta đã tận mắt chứng kiến! \n\nTa đang chiêm ngưỡng Tia Lửa thì Ngọn Lửa đột nhiên bắt đầu nhảy múa và quất mạnh theo một nhịp điệu kỳ lạ! Ta nghĩ đó là ảo ảnh của ánh sáng, nhưng khi mắt ta điều chỉnh, ta thấy một hình dạng ghê rợn hiện ra từ mặt đất! Xoay chuyển ngọn lửa là một nỗi kinh hoàng mơ hồ, hài cốt cháy trong ánh sáng ma quái! Nó di chuyển về phía ta xuyên qua ván sàn và Ngọn Lửa, đôi môi nó rỉ ra những lời nguyền rủa và mục rữa!! \n\nHãy để ta nói cho ngươi biết: Ta chưa bao giờ chạy nhanh như vậy trong đời! Nếu ta ở lại, ta thề trên các chị em của ta, ta sẽ mất đi con mắt còn lại! \n— <lorename>Elin</lorename>",
    [2255319685] = "Hỡi Hỏa Sinh! Ta nghe những tin đồn đáng lo ngại... điều gì đó khủng khiếp và ghê tởm đang xảy ra ở Vùng Suối... một sự ghê tởm và lạm dụng Thuốc Tiên. Làm ơn, hãy chấm dứt triều đại khủng bố này trước khi quá muộn!",
    [2255516083] = "Tăng Tốc Độ Bơi",
    [2255595970] = "Một chiếc quần đen đơn giản với các chi tiết vàng tinh tế. Không nổi bật khi đứng một mình, nhưng hài hòa hoàn hảo với các bộ phận khác của bộ trang phục này. Gấu quần đã được khâu lại nhiều lần, mòn mỏng bởi những hành trình dài qua Embervale. Một tuyên bố lặng lẽ về quãng đường đã đi của \"Các Học Giả Thượng Đế\".",
    [2255692494] = "Một Lãnh Đạo Mới  ",
    [2256677550] = "Bình Máu Lớn",
    [2257966814] = "Tạm biệt!",
    [2258190947] = "Bộ <craftingstation>Dụng Cụ Thợ Mộc</craftingstation> được tìm thấy trong một trại khai quật ở Trụ Cột Sáng Tạo. Chúng nên được mang đến cho <npc>Thợ Mộc</npc> để ông ấy có thể xây dựng thêm các trạm chế tạo.",
    [2258323600] = "Ta tỉnh dậy dưới đáy xoắn ốc, tại lõi Trái Đất. Xung quanh ta, một khối vật chất quằn quại, một mớ chi, một đống thịt. Nó tạo thành xoáy nước nối liền nơi đây và quá khứ.\n\nKhối vật chất nhìn ta. Ta nhìn lại, lòng tan nát bởi sự lựa chọn của những khuôn mặt, tất cả đều tan vỡ, vỡ vụn và sắp xếp lại.\n\nĐó là một sự bắt chước sự sống một cách ghê tởm, nơi mắt chảy xuống má, môi tan chảy, và đầu tách ra để nở thành một cái gì đó mới.\n\nMột khuôn mặt có vẻ xa lạ, nhưng quen thuộc — một suy nghĩ thoáng qua, một mẩu báo, một lời thì thầm. Hắn là một, nhưng hắn là nhiều. Hắn ở khắp mọi nơi. <i>Một kẻ lang thang, giống như ta. Hắn ở khắp mọi nơi.</i>\n\nQuá giống người để sinh ra từ sương mù\nQuá ngạt thở, quá bóng bẩy để là người\nHoặc vẫn là người\n\nHắn giống như sương mai\nBình minh của một ngày mới\n<i>Khởi đầu của mỗi xoắn ốc, chờ đợi được tìm thấy</i>",
    [2258637851] = "Nó vẫn là phép thuật ngay cả khi bạn biết cách thực hiện.",
    [2258658232] = "Lấy những gì bạn cần.",
    [2258784347] = "Cá cắt thành lát dày, hãy cẩn thận với xương, nhưng bạn vẫn có thể thưởng thức nó.",
    [2259115527] = "Thời gian hiệu lực",
    [2259653494] = "Chèn Chi phí",
    [2259703910] = "Chặt cây",
    [2259756171] = "Áo Giáp Sát Thủ Băng Giá",
    [2259947478] = "Tia Lửa",
    [2260078042] = "Găng Tay Lính Đánh Thuê",
    [2260804329] = "https://discord.gg/WynEgUx6ws",
    [2260839959] = "Những chiếc găng tay nhẹ này rất phù hợp để cầm bút lông và ký các sắc lệnh.",
    [2260986480] = "Nấm Cáo",
    [2261620179] = "Sát thương Cung",
    [2261745913] = "À, vậy là ngươi có thể học được vài điều. Đừng đánh giá thấp tay nghề của chúng ta. Nó có thể cứu mạng ngươi ngoài kia!",
    [2261892615] = "Chậu cây nhỏ",
    [2262475715] = "Xin chào, Hỏa Sinh!",
    [2262491860] = "Hàng rào",
    [2262888804] = "Kiếm Dập Tắt",
    [2262899961] = "Có sẵn",
    [2262955004] = "Trang phục Thợ Rèn Mỹ Thuật",
    [2263060172] = "Thợ mộc nghi ngờ rằng Drak có thể đang giấu đủ loại của cải bên trong các ngôi đền chìm của chúng. Ông ấy đang cử bạn đi khám phá một trong số chúng với hy vọng thu thập được một vài đồng vàng.\n\nVới những đồng vàng, bạn sẽ có thể trang trí căn cứ của mình và thể hiện sự giàu có của mình.\n\n<b>Hãy đến ngôi đền và tìm kiếm kho báu!</b>",
    [2263186759] = "Băng",
    [2263201517] = "Phút",
    [2263408064] = "Bình chứa nước đầy",
    [2263582293] = "Một chiếc giường ấm cúng cho động vật trang trại.",
    [2263736961] = "Giày Quý Tộc",
    [2265109722] = "Khi được trang bị vũ khí Cận chiến, tung ra một đòn tấn công mạnh mẽ lên trên trong quá trình nhảy của bạn. \n\nSử dụng kỹ năng này để nhanh chóng thu hẹp khoảng cách với kẻ địch <b>bay</b>.\n\n<b>Chi phí:</b> 25 SP ",
    [2265484954] = "Những chiếc găng tay này khóa chặt tay bạn vào cung - nhắm vào đầu bằng cách nhắm ổn định.",
    [2266170163] = "Vinh quang cho <lorename>Pikemead</lorename>, mãi mãi",
    [2266383774] = "Lo lắng cho con",
    [2267111263] = "Một đôi quần ấm, nhuộm màu xanh đậm. Nó cung cấp sự bảo vệ đầy đủ khỏi các yếu tố.",
    [2267165463] = "Máng ăn gia súc",
    [2267425983] = "Ngọc Trả Đũa",
    [2268148329] = "Phòng Thủ Mạnh Mẽ",
    [2268257793] = "Rìu Thép",
    [2268807462] = "Mỗi tiếng gầm vang trời là một cảnh tượng, một cảnh tượng đẫm máu để chiêm ngưỡng. Chúng đã cắm răng vào những vùng đất đã bị lãng quên từ lâu... đã đến lúc đòi lại vương quốc.\n\nThu thập nhiều Đầu Đấu Sĩ Vukah để chế tạo Huy hiệu Sắt.",
    [2268933775] = "Muối",
    [2269786462] = "Cách Xây Giếng Thuốc Tiên",
    [2269860134] = "175 m × 175 m",
    [2270269178] = "Hoa Sao Stapelia",
    [2270415812] = "Hydrak",
    [2270539600] = "Cửa Đôi Sắt",
    [2270825810] = "Bạo chúa Scavenger",
    [2271314223] = "Ta có thể còn sống, nhưng không có con gái, ta không còn lý do để sống! Làm ơn, ta cầu xin ngươi, hãy tìm con gái Marianne của ta và mang cô bé trở về! Cô bé đã rời nhà để nghiên cứu Vukah trước khi chúng đột kích <location>Pháo đài Kelvin</location>! Ôi, ta lẽ ra không bao giờ nên để con bé đi... con gái bé bỏng của ta, làm ơn hãy trở về...!",
    [2271435529] = "Tìm Tiệm Cắt Tóc ở <location><lorename>Pikemead</lorename>'s Reach</location>",
    [2272426929] = "Tìm Mũ Hề của Anton",
    [2272662195] = "Hẹn hò cà phê",
    [2272770431] = "Khi gây ST Xuyên, áp dụng hiệu ứng <img gemeffect_puncturing> Xuyên thấu lên kẻ địch. Kẻ địch bị <img gemeffect_puncturing> Xuyên thấu nhận %k ST Xuyên thưởng từ BẤT KỲ nguồn ST Xuyên nào trong %k.",
    [2273241800] = "Những cuốn sách ngu ngốc, đáng nguyền rủa\nAi còn đọc sách nữa\nĐiều này không thể là thật\n\nTôi đã cố gắng leo ra ngoài lúc rạng sáng, nhưng tôi đã ngã khỏi đống đó\n\nCú ngã rất tệ\n\nVai đau nhức, đầu ong ong\nThậm chí còn tệ hơn, chiếc xe ngựa đã bị hỏng\n\nNếu người giám sát nhìn thấy điều này, tôi có thể tạm biệt vị trí của mình\n\nNgày mai thử lại\nHoặc bất cứ khi nào tôi thức dậy\nTôi phải nằm xuống\nMọi thứ quay cuồng",
    [2273419117] = "Đang biên dịch shader",
    [2273499549] = "Bàn Gỗ",
    [2274692156] = "Gabrielle Fairburn",
    [2276183481] = "Một miếng lót ly bằng gỗ để trưng bày đồ uống trên bàn.",
    [2276518262] = "Nhà sưu tập",
    [2277155432] = "Các hiệu ứng buff thức ăn của bạn vẫn tồn tại sau khi chết, nhưng chúng kéo dài bằng một nửa thời gian. ",
    [2277319470] = "Một món súp ấm nóng làm từ nhiều loại rau củ. Đầy vitamin và năng lượng.",
    [2277690431] = "Năng lượng chảy qua bạn.",
    [2277808649] = "Một kẻ Scavenger ở <location>Nơi trú ẩn của Surat</location> đã phàn nàn về việc thức dậy với những hình vẽ trên mặt và cuộc đấu tranh của anh ta để rửa chúng đi.\n\nMàu sắc được sử dụng để vẽ vĩnh viễn khuôn mặt của anh ta có thể vẫn còn xung quanh. <b>Tìm bảng màu trong <location>Nơi trú ẩn của Surat</location>!</b>",
    [2278056548] = "Đèn lồng đất (Đã thắp sáng)",
    [2278418713] = "Găng Tay Chiến Binh Quật Khởi",
    [2278509749] = "MP mỗi giây",
    [2278746795] = "Chèn",
    [2279005898] = "Cái đầu rồng cuối cùng. Chiếc đinh cuối cùng trong quan tài. Sự kết thúc của một kỷ nguyên, và sự khởi đầu của một cái gì đó mới.\n\nThu thập nhiều Đầu Rồng Con non Fell để chế tạo Cúp Sắt.",
    [2279836413] = "Hàng Rào Gỗ Nhiệt Đới Chạm Khắc Buộc Dây II",
    [2279868027] = "Điều gì đưa bạn đến đây, bạn của ta?",
    [2279874337] = "https://Sương độc bao phủ.com/privacy-policy-for-Sương độc bao phủ",
    [2280173512] = "Đầu vào không hợp lệ",
