    [2282752864] = "Một số <warning>vật phẩm trong ba lô sẽ bị rơi</warning> khi bạn chết.\nHãy quay lại đây để lấy chúng.",
    [2283472867] = "Sức bền Thần thoại",
    [2283548710] = "Giày Chiến Binh",
    [2283857107] = "Tháo dỡ",
    [2284710453] = "Điều chỉnh chất lượng bóng đổ. Giảm chất lượng hoặc tắt nó sẽ tăng hiệu suất.",
    [2284908137] = "Truyện Cổ Tích Dài",
    [2285134261] = "%k <style=mutedItalic>(Đang hoạt động )</style>",
    [2285424874] = "Đồng cỏ Thấp đẫm bệnh tật, ngập trong mật đắng và cay đắng. Chống lại Sương độc và làm sáng tỏ những đồng cỏ yên bình bị mất tích bên dưới. Những vùng hoang dã vô biên với vẻ đẹp vô tận nằm ẩn dưới sự mục nát.",
    [2285626623] = "Chế tạo Trang bị",
    [2286354548] = "Khiên Phép Thuật",
    [2287199256] = "Nơi Ẩn náu của Người Tình",
    [2288530452] = "Giữ vững sự tập trung.",
    [2288567023] = "Không ai có thể ngăn cản chúng ta ăn mặc như những vị vua nữa! Hãy lấy lại chút hào nhoáng! Nếu bạn là người cai trị mới của vương quốc, bạn nên trông xứng đáng với vai vế đó!",
    [2288717769] = "Móc Đấu sĩ",
    [2288717896] = "Máng Ăn Cho Chuột Lang Nước",
    [2288790267] = "Kiểu nút điều khiển",
    [2289039412] = "Tất cả sát thương <b>Sốc</b> được tăng thêm <b>10%</b>.",
    [2289207036] = "Dao Găm Ăn Mòn",
    [2289768981] = "Aeolipile",
    [2290309588] = "Một đòn chí mạng bằng vũ khí tầm xa sẽ đánh dấu mục tiêu trong 3 giây. Tất cả người chơi sẽ gây gấp đôi sát thương lên mục tiêu bị đánh dấu.",
    [2291065322] = "Săn tìm màu tóc: Xanh tự nhiên",
    [2291573543] = "Lưỡi kiếm Tàn tích Scavenger",
    [2291962908] = "Một tách cà phê pha theo truyền thống với một chút đường. Vị ngọt hòa quyện với hương vị đậm đà.",
    [2292006627] = "Một đôi găng tay cũ kỹ với những đốm nắng và viền lông.",
    [2292713804] = "Tìm và sử dụng Lò rèn Đá quý",
    [2292757897] = "Lông Vũ",
    [2292781673] = "Vải Lanh",
    [2293030336] = "Nghệ Tây",
    [2293207626] = "Thợ săn Quetzal",
    [2293338613] = "Tiếp cận Tháp của Nhà giả kim",
    [2294249447] = "Rơi ra từ kẻ địch trong các Sảnh đường Hollow của Đỉnh Albaneve",
    [2294727006] = "Cửa Sa Thạch Bí Mật",
    [2294975094] = "Bộ phận trung tâm của một <craftingstation>Máy cưa bàn</craftingstation>. ",
    [2295156235] = "Rìu Đàn Sói",
    [2295574992] = "Đặt bảo vệ bằng mật khẩu",
    [2296044809] = "Bộ lọc",
    [2296352283] = "A, cuối cùng rồi! Giờ thì chúng ta có thể nhuộm tóc cho cậu màu xanh rồi! Cảm ơn nhé!",
    [2296645280] = "Các lý thuyết của <npc>Nhà giả kim</npc> I",
    [2297486815] = "Giáp Sương độc",
    [2297707738] = "Thu thập tất cả tài nguyên để nhặt",
    [2298064930] = "Xuống",
    [2298102462] = "Mọi người nghĩ màu xám thật nhàm chán, nhưng nếu họ dành một chút thời gian để thực sự nhìn kỹ, họ sẽ thấy màu sắc đó duyên dáng đến nhường nào!",
    [2298121680] = "Bàn Đầu Giường Đá",
    [2298204525] = "Cấp độ vật phẩm",
    [2298483318] = "Một khối kim loại đơn giản. Mặc dù thiết kế bóng bẩy, nó khá hiếm khi được sử dụng làm vật liệu xây dựng.",
    [2299019233] = "Tàn tích của một bóng ma lang thang, bị nguyền rủa phải héo mòn trên cõi trần. Môi nó mím chặt, mắt nó nhắm nghiền mãi mãi. Cái ác đã bị trục xuất.\n\nThu thập nhiều Đầu Lưỡi hái Fell để chế tạo Cúp Sắt.",
    [2299142808] = "Khối Đá Vôi",
    [2300050059] = "Một con dao găm thô sơ, trước đây được một tên Vukah sử dụng trong một nghi lễ đẫm máu.\n\n<b>Sự tinh tế:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn. ",
    [2300487950] = "Bạn chỉ nên ăn thịt cua khi nó được nướng, vì đây là cách tốt nhất để chế biến nó.",
    [2300621469] = "Một phước lành thực sự trong cơn nóng của trận chiến.\n\n<b>Phép thuật: Cạn kiệt</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [2300782481] = "Gối Hình Trái Tim",
    [2301054038] = "Áo Giáp Thợ Săn Chim",
    [2301236933] = "Dạy một người đàn ông cách câu cá và bạn nuôi sống anh ta cả đời!",
    [2301413748] = "Obelisk cổ đại",
    [2301772761] = "Trượng Cháy Đen",
    [2302155206] = "Khối Lập Phương 1m",
    [2303010035] = "Một mầm cây sẽ phát triển thành cây khi được gieo vào đất thích hợp. \n\n<b>Cây này cần được đặt trong nước và ngập hoàn toàn.</b>",
    [2303513824] = "Bà Braelyn đã chết trong ngôi đền cuối cùng! Hãy đến xác của bà ấy và giải cứu linh hồn bà để bà có thể được triệu hồi lại trong căn cứ của bạn!",
    [2304304148] = "Thợ <npc>Thợ săn</npc> cần lại <craftingstation>Trục quay tay</craftingstation> của mình để chế tạo <b>giáp tốt hơn.</b> Bà ấy đã làm mất nó gần <b><location>Westcott</location></b>.",
    [2304422946] = "Hỡi Hỏa sinh! Ta đã mày mò với hạt giống và những thứ còn sót lại một thời gian, và ta nghĩ ta đã tạo ra một số loại thức ăn tuyệt vời cho động vật! Các ngươi có thể làm một ít, cho động vật ăn cho đến khi chúng thuần hóa, và mang chúng về căn cứ của chúng ta! Chúng ta sẽ phải làm một cái chuồng, máy cho động vật ăn, giường... chúng ta có nên bỏ phiếu chọn tên nữa không?",
    [2304662878] = "Bình Năng Lượng",
    [2305178806] = "Thuộc tính nhân vật",
    [2305351671] = "Quần Sát Thủ Băng Giá",
    [2306409847] = "Chùy Cột Vật Tổ",
    [2306764608] = "Ảo giác Tượng người làm vườn",
    [2306805219] = "Giấy",
    [2307281054] = "Chùy Vảy Xương",
    [2307499335] = "Chùy",
    [2307979640] = "Những lời dối trá của một ông già",
    [2308487550] = "Nơi trú ẩn, bạn <i>của ta.</i> Hãy giữ cho xương cốt của ta khỏi ngày càng giòn hơn, được chứ?",
    [2308780620] = "Một chiếc khăn trùm đầu đơn giản sẽ giữ cho da đầu của bạn an toàn khỏi sức nóng thiêu đốt của mặt trời trên cao.",
    [2309095322] = "Sương Mù Của Kẻ Lưỡi Hái Sa Ngã",
    [2309456180] = "Pha Lê Linh Thể",
    [2309839414] = "Đầu Rồng Con Sa Ngã",
    [2309877039] = "Cây cà chua",
    [2310040039] = "Thuốc nhuộm xanh lá cây để che vết cỏ trên quần áo.",
    [2310053197] = "Cấp 1",
    [2310115582] = "Bánh Xe Kéo Sợi",
    [2310652368] = "Giày của Học viên <npc>Nhà giả kim</npc>",
    [2311206368] = "Bảo vệ xóa vật phẩm",
    [2311254818] = "Tôi đang mang đạn dược đến máy bắn đá cùng Connor thì Đỉnh Núi Gầm Rú đột nhiên gầm lên. Nheo mắt nhìn làn khói bốc lên, tôi thấy có thứ gì đó ẩn nấp bên trong, khiến hơi nước cuộn xoáy... Khi nó thoát ra khỏi màn sương xám, tôi đông cứng lại. Tiếng la hét vang lên.\n\nGiữa sự hỗn loạn, một giọng nói quen thuộc vang lên. <i>\"George, giữ bình tĩnh! Tôi sẽ châm lửa, còn anh bắn!\"</i> Connor chộp lấy một ngọn đuốc và lao về phía cây cầu. Bầu trời tối sầm lại bởi những đôi cánh. Bóng dáng của anh ta bị nhuốm màu trong bóng tối khi anh ta biến mất vào màn đêm.\n\nVới đôi tay run rẩy, tôi bắn một mũi tên. Rồi hai. Ba - tất cả đều trượt. Không hề nao núng, con quái vật có cánh phun ra một đám mây nóng bỏng, hôi thối từ miệng nó làm tan chảy những bức tường của chúng tôi. Nó đã tóm được Connor khi anh ta đang leo lên. Đó là điều cuối cùng tôi thấy trước khi ngất đi.\n\nTôi muốn về nhà, nhưng họ không cho phép. Chúng ta không còn ở trong doanh trại nữa. Đây là chuyện thật.\n\n— George",
    [2311317359] = "Đòn chí mạng",
    [2311949867] = "Thời gian hồi sinh",
    [2312539910] = "Không có gì ở đây!!\n",
    [2312637886] = "Bẩm sinh",
    [2312860138] = "Tai Ương Giáng Xuống Như Sét",
    [2313324596] = "Nhật Ký",
    [2313675004] = "Tăng ST Lén lút ",
    [2314192093] = "Súp Linh Thể Thượng Hạng",
    [2314285341] = "Màu sắc của sự sống — một màu sắc tuyệt vời cho quần áo.",
    [2314365361] = "Mũ Hề",
    [2314938172] = "Vết Thương Cũ Lại Rách",
    [2315647632] = "Tiện Nghi - Nhà Vệ Sinh",
    [2315784904] = "Trăng Sáng Hồi Sinh",
    [2316234444] = "Tín Hiệu Hồi Về",
    [2316333456] = "Gửi Amelie thân mến, ",
    [2316475504] = "Trao Đổi Bảng Màu",
    [2316565458] = "Ta sẽ không ngủ yên với những thứ đó quằn quại. Hãy tống khứ chúng khỏi biển của ta!",
    [2316643324] = "Giường Xếp",
    [2316702912] = "Ghim",
    [2316749138] = "Khi tiêu diệt kẻ địch bằng vũ khí phép thuật, bạn sẽ trở nên vô hình trong 3 giây.",
    [2317109482] = "Chiếc đũa phép này gần như rung lên với hơi ấm và năng lượng hủy diệt. Nó trở nên bồn chồn và khó chịu khi không hoạt động quá lâu.\n\n<b>Quá tải:</b>\nChiếc đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương cộng thêm lên tới phần trăm <i>quá tải</i>.",
    [2317314682] = "Thật Là Một Ngày May Mắn",
    [2317340754] = "Trọng Kiếm Răng Cá Mập",
    [2317575873] = "Sức Bền",
    [2317578609] = "Gửi Toàn Thể Nhân Viên,",
    [2318071124] = "Thuộc Tính Chính",
    [2318297057] = "Chuyển Đổi Khả Năng Hiển Thị",
    [2318318683] = "Chuyển sang Tùy chỉnh",
    [2318970467] = "Tiếp theo",
    [2319142192] = "Nhạc sĩ Valory muốn bạn tìm kiếm tất cả hóa thạch ở Embervale. Có bốn hóa thạch ở Cao Nguyên Du Mục. Mỗi hóa thạch có thể được tìm thấy nhiều lần ở những nơi khác nhau. Nhạc sĩ khuyên nên tìm kiếm trong các mỏ, địa điểm khai quật và mỏ quặng để tìm tất cả hóa thạch.",
    [2319235101] = "Hãy cho ta biết ngươi cần gì!",
    [2319313724] = "Cần khu vực xây dựng",
    [2319388959] = "Viền Cửa Sổ/Màn Hình",
    [2319579003] = "Thảm Treo Tường V",
    [2320056562] = "Tìm Kiếm Song Hỏa Kiếm Yếu",
    [2320206684] = "Dung tích nguồn nước",
    [2320844032] = "Ngày Đẹp Để Câu Cá",
    [2320870778] = "TA NGuyền RỦ NGƯƠI, NGỌN LỬA",
    [2322051303] = "Cây Lanh",
    [2322598948] = "Đất Nông Trại Trộn Phân Bón",
    [2322718324] = "Quán Rượu Emily Fray",
    [2322761208] = "Vật liệu có sẵn:",
    [2323372018] = "Tăng ST Sương độc",
    [2324051760] = "Hãy quay lại bất cứ lúc nào!",
    [2324261309] = "Khúc Gỗ Cọ",
    [2324373348] = "Ta là sự phản chiếu trên mặt sông chảy chậm đang vẫy gọi ngươi. Không thể biết, nhưng quen thuộc. Giống nhau, nhưng khác biệt. Một lời kêu gọi quyến rũ từ vực sâu.\n\nNgươi còn đủ tinh thần để hiểu lời ta nói, không bị sự phẫn nộ làm mù quáng.\nThật là một bí ẩn hấp dẫn. <i>Tại sao ngươi không đến khai sáng cho ta, người bạn mới của ta?</i>\n\nTìm ta sau tấm gương và lặn xuống vực sâu. Mang ta đến, hướng về phía chân trời — ánh sáng — làn gió. Ngươi sẽ không hối tiếc.\n\n<i>— Người bạn mới của ngươi</i>",
    [2325769984] = "Diệt Long",
    [2325809923] = "Thể lực",
    [2325952807] = "Len tinh chế có thể được sử dụng để <b>chế tạo bộ đệm ấm</b>. Những bộ đệm này rất cần thiết để chế tạo trang bị ấm hơn.\n\n<b>Chế tạo bộ đệm ấm với thợ săn</b> để tiếp tục!",
    [2326457752] = "Một chiếc gối mềm cho chú chó của bạn.",
    [2326669969] = "Tăng/hồi thuộc tính đang hoạt động.",
    [2326747864] = "Hôm nay gặp phải một trận tệ hại. Bão cát ập đến ngay sau giữa trưa. Không có cảnh báo, chỉ là một bức tường gió và bụi. Tầm nhìn giảm xuống bằng không trong vài giây. Tôi quấn mình chặt nhất có thể, nhưng vô ích. Cát tìm thấy mọi kẽ hở.\nMắt tôi đang trong tình trạng tồi tệ. Cảm giác như vẫn còn sạn cọ dưới mí mắt. Chúng <b>đỏ</b>, sưng lên—tôi hầu như không thể mở mắt ra được nữa.\nĐêm nay sẽ không di chuyển nữa. Tôi cần đợi gió lặng và xem liệu tôi có thể nhìn thấy cột mốc tiếp theo hay không.",
    [2326811468] = "Một nguồn protein tuyệt vời giúp tăng cường khối lượng cơ bắp. Tốt nhất nên tiêu thụ trước khi tập thể dục.",
    [2327186004] = "Một con Hophare tò mò nhưng nhút nhát. Bản tính nhút nhát và phản xạ nhanh nhẹn của chúng giúp chúng tránh khỏi kẻ săn mồi!",
    [2327187966] = "Bạn bè trên Máy Chủ này",
    [2327211924] = "Ta đã quá ngây thơ khi ăn mừng khi ban nhạc tan rã. Đi du lịch một mình thật mệt mỏi. Ta không có ai bên cạnh để giữ những kẻ say xỉn này tránh xa ta! Ta không phải là siren hay đồ chơi! Ta chỉ muốn làm nhạc trong hòa bình! Giá như gã quái dị <b>Daniel Kẻ Bị Nguyền Rủa đó không làm phiền khán giả của chúng ta</b> ở quán rượu bằng cách làm rơi răng khắp nơi trong lúc nghỉ giữa hiệp... Hắn làm quá với cái chiêu \"lời nguyền\" của mình... <i>nếu nó còn là chiêu trò.</i>\n\nĐã đến lúc đổi thương hiệu. \"Harper Người Chơi Đàn Hạc\" gợi lên một hào quang <i>quyến rũ huy hoàng</i> không còn phù hợp với ta nữa. Ta lẽ ra không bao giờ nên khuất phục trước hình ảnh này... ta đã lạc lối từ khi nào? Ta từng hát và nhảy vì niềm vui, không phải vì tiền hay để nâng tầm một ban nhạc tầm thường... <i>và chưa bao giờ ta yêu thích chơi đàn hạc như viết thơ bên cửa sổ, hay lang thang trong rừng mà không đợi màn đêm che giấu khuôn mặt ta khỏi những kẻ cuồng tín.</i>\n\nTa sẽ ném nó qua mỏm đá này và bắt đầu lại vào ngày mai!",
    [2327684139] = "Tìm Kiếm Khu Vực",
    [2327903934] = "Những tia thép vươn ra từ phần bảo vệ của chuôi kiếm. Chúng giống như ánh sáng cuối cùng của mặt trời trước nhật thực.\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n",
    [2328139109] = "Tìm Kiếm Nhạc Cụ Sử Thi",
    [2328544153] = "Thoát Hàng Chờ",
    [2328856217] = "Bảo Vệ Khỏi Băng Giá",
    [2328964675] = "Nhẫn Sinh Mệnh Bất Tận",
    [2329063592] = "Thiết Bị Chế Tạo: Nhiệt Kế",
    [2329681391] = "Tường Rào Gỗ III",
    [2330156414] = "Bồn Tắm Gỗ",
    [2330800743] = "Rìu Mắt Tử Thần",
    [2330980517] = ",",
    [2331040742] = "Gửi Darrel",
    [2331059332] = "Quan Sát Tinh Tường Của Một Công Nhân Xây Dựng",
    [2331186561] = "<b>Nếu Mẹ còn ở đây, bà sẽ treo đèn chùm, thắp nến ở mọi góc, phủi bụi những cuốn sách cũ và đọc cho tôi nghe một câu chuyện.</b>\n\nGiọng nói ấm áp, du dương của bà sẽ lấp đầy căn phòng như một dòng ánh nến. Tôi sẽ lắng nghe hàng giờ, cuộn mình trong chiếc chăn màu cam do bà tự dệt nhuộm bằng nghệ tây. Tôi sẽ nhấp một ngụm trà hoa cúc ngọt ngào, và vui vẻ chìm vào giấc ngủ.\n\nNhưng Mẹ không còn ở đây. Bóng tối là ngôi nhà mới của tôi.",
    [2331292279] = "Một lưỡi kiếm lạnh lẽo khi chạm vào. Nó đè nặng lên tâm trí.",
    [2331416704] = "Lời Thú Tội Của Anh Trai",
    [2331641968] = "Tuyệt vời! Những <keyitem>Dụng Cụ Khoa Học</keyitem> này sẽ tạo ra những điều kỳ diệu khi được sử dụng cho Phòng Thí Nghiệm! Tia sáng của ngươi tỏa rạng rỡ, Flameborn!",
    [2332450390] = "Trong mỏ đá Albaneve Summits, bạn tìm thấy một ghi chú mà một công nhân đã chi tiết quy trình nghiền đá để tạo ra bột màu. \n\nBảng màu mà anh ta tạo ra từ đá nghiền vẫn nên có trong mỏ đá. <b>Tìm kiếm bảng màu</b> để tiếp tục!",
    [2332739315] = "Tìm Đài Thiên Văn Gần Đó",
    [2332827754] = "Một món súp làm từ nhiều loại rau và hoa calla luna. Nó phát sáng trong Sương độc và kéo dài Thời gian của bạn trong Vùng Che Phủ!",
    [2332935088] = "Chữa thương mỗi giây",
    [2333515647] = "Chảo Phế Liệu II",
    [2333799691] = "Tăng thuộc tính Nhân vật",
    [2334392676] = "Màu sắc của chiếc quần này cho phép người mặc hòa mình vào tán lá cây.",
    [2334529245] = "Trang bị làm Trang phục",
    [2335020446] = "Một số hiệu ứng hình ảnh có thể chưa hiển thị.",
    [2335078400] = "Chiếc quần lịch sử, từng là tâm điểm của trang phục pháp sư nghi lễ.",
    [2335334883] = "Vật phẩm sưu tầm này được tìm thấy ở Albaneve Summits. Nó có thể được lắp ráp lại để tạo thành Bộ Xương Người Khổng Lồ trên Đế Cúp Người Khổng Lồ.",
    [2335365818] = "Giày Đại Pháp Sư",
    [2336034803] = "Hủy bỏ",
    [2336088154] = "Đũa Phép Rực Lửa",
    [2336192939] = "Một loại quả mọng đặc biệt chỉ có thể thu hoạch vào ban đêm ở Revelwood. Nó có thể được sử dụng để tăng cường nhiều món ăn và tạo ra bột màu xanh đậm.",
    [2336422362] = "Dao găm có nhiều cạnh và móc sắc bén. Chúng có thể được rút ra trong chớp mắt để đỡ các đòn tấn công tới, do đó bảo vệ danh dự của bạn.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [2336521561] = "Đấu trường Scavenger",
    [2336893735] = "Một chiếc quần thảo dược đơn giản. Chúng có mùi hương của hương thảo và xạ hương.",
    [2337150506] = "Ban cho khả năng miễn nhiễm với Lời Nguyền Fell.",
    [2337271811] = "Hiển Thị Hành Động",
    [2337508817] = "Trọng Kiếm Trăng Non",
    [2337785121] = "<b><lorename>Ikora</lorename>!</b> Vâng, tôi biết cô ấy! Kín đáo. Nói rằng người khác làm cô ấy kiệt sức... cô đơn, tôi nghĩ vậy, nhưng bậc thầy về <i>pha chế thuốc!</i> Cô ấy có cửa hàng ở <b><location>Rattlebleak</location>.</b> Tôi rất muốn chiêm ngưỡng tác phẩm của cô ấy... cô ấy có thể pha chế bất kỳ loại thuốc nào như không có gì!",
    [2337786292] = "Tăng tối đa SP.",
    [2337813732] = "Sói Trước Cửa",
    [2337894274] = "Việc Này Không Hay Ho Chút Nào",
    [2338073849] = "Những mảnh vải rách nát bị bỏ lại và giờ đây được những kẻ Scavenger sử dụng làm quần áo.",
    [2338300970] = "Song Hỏa Kiếm Yếu",
    [2338575635] = "Vị <npc>Nhà Giả Kim</npc> cần nơi trú ẩn để làm việc. Hãy xây một ngôi nhà cho Nhà Giả Kim và cấp cho ông ấy quyền tiếp cận <b>giường trú ẩn gần đó nếu bạn chưa làm!</b>\n\nĐể che chở những người sống sót của bạn, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót trống gần nhất khi được đặt. Nếu bạn muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu Hồi của bạn và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho bạn khi những người sống sót của bạn không còn được che chở.",
    [2339284219] = "Rơi ra từ kẻ địch Kindlewastes Fell",
    [2339330466] = "Nồng độ năng lượng sương độc cao nhất, thậm chí còn cao hơn cả trung tâm sương độc.",
    [2339339181] = "Khối Đồng Đỏ",
    [2339464064] = "Bạn đã đến Hang ổ Sương độc. Bây giờ hãy xem tác giả của ghi chú không dám tuyên bố điều gì.",
    [2339840259] = "Cửa Đá Vôi Vỏ Sò Bí Mật",
    [2339896910] = "CHẾT TIỆT LŨ NGỐC NÀY",
    [2340475092] = "Ngươi biết đấy, ta lớn lên ở thủ đô... người ta hay kể chuyện. Những câu chuyện ta cũng kể cho con gái ta nghe. Đôi khi vào ban đêm, có những ánh sáng mờ ảo lấp lánh dưới làn sóng... dấu hiệu của sự cai trị nhân từ của Nữ Hoàng <lorename>Pikemead</lorename>. Con gái ta nói nó đã từng nhìn thấy chúng. Chuyện cổ tích của trẻ con, ta đã nghĩ vậy. Nhưng ai mà biết được? Những điều kỳ lạ hơn đã xảy ra ở Embervale.",
    [2340694788] = "ST Đập",
    [2340969932] = "Nhạc Công",
    [2341267821] = "Một số công thức bao gồm một loạt các vật phẩm. Chuyển đổi giữa các vật phẩm này tại đây.",
    [2341287035] = "Giữ cho ngón tay khéo léo của ngươi gần, đừng dấn thân vào hang động và vách đá\nMột con rồng canh giữ những đường hầm cô đơn, ngủ say, yên tĩnh, cứng đờ\n\nNó ngậm một thanh kiếm trong miệng, nhưng đừng lấy nó, bé con\nĐể giữ cho ngón tay của ngươi, từ một đến mười, ngươi sẽ phải chạy thật nhanh\n\nVì bàn tay nhỏ bé và túi tiền, thanh kiếm của nó quá lớn\nVà với những chiếc răng nhe ra để Đỡ nó, con rồng quá nhanh\n\nVì vậy, hãy tránh xa Miệng Rồng, ở nhà và gần thành phố\nĐừng lấy những gì không thuộc về ngươi và giữ cho ngón tay của ngươi xinh đẹp",
    [2341568933] = "Đền Ẩn",
    [2342402938] = "Phép thuật này được cung cấp bởi Ngọn Lửa vĩnh cửu và đóng vai trò như một loại đạn phép thuật không giới hạn để tạo ra một quả cầu lửa mạnh mẽ bùng nổ khi va chạm, gây sát thương lớn trên một khu vực rộng lớn.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không</b> bị tiêu hao. Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [2343279567] = "Cung Thợ Săn",
    [2343515384] = "Cửa Đá Vôi Bí Mật",
    [2343554748] = "Lối Vào Đền Thờ Mặt Trời Ma Ám",
    [2343846027] = "Hoa Aureolin",
    [2344821301] = "Vị trí phía trên",
    [2345505345] = "Chất nhờn đáng sợ. Nó ban cho những ai ăn nó sức mạnh to lớn.",
    [2345790153] = "Hào Quang Đất",
    [2346240105] = "Đèn Lồng Gắn Tường",
    [2346259489] = "Đánh bại kẻ địch để nhận Buff Hồi Phục SP",
    [2348197509] = "Kho Lưu Trữ",
    [2348722619] = "Hút MP",
    [2348820227] = "Linh hồn đã được phát hiện!",
    [2349253991] = "Một phương thuốc cho Lời nguyền Fell",
    [2349459908] = "Tăng tạm thời giá trị Chặn của bạn khi chặn bằng Dao găm, đảm bảo đỡ đòn suýt trượt giảm thiểu tiêu hao SP.",
    [2349667744] = "Bật/Tắt Gợi Ý",
    [2351056436] = "Ta thấy ngươi đã cường hóa vũ khí của mình bằng một viên đá quý! Ngươi có phiền cho ta mượn nó sau không? Ta muốn tiến hành một vài thí nghiệm với nó! ...Không? Ngươi chắc chứ?",
    [2351169858] = "Chào mừng.",
    [2351552849] = "Niên Giám Đã Trở Lại",
    [2351649663] = "Mầm tri thức đã bùng cháy bên trong. Hãy sẵn sàng để vén màn bí mật về quá khứ của chúng ta. Tìm hai <b>Đài Tưởng Niệm Cổ Đại</b> của Vùng Đất Mùa Xuân để biết số phận của thế giới, một câu chuyện về mục nát và lửa. Chỉ những ai tìm kiếm sự thật mới tìm thấy nó.",
    [2351870523] = "Cấp 5 Căn Nhà",
    [2353393883] = "Vị trí <craftingstation>Lò Rèn</craftingstation>",
    [2353813371] = "Bạn đã đến thang máy chở hàng.\n\nHãy nhìn xung quanh và điều tra các lô hàng để tìm chiếc đàn pan!",
    [2353939822] = "Tím L né",
    [2354034720] = "Bát Phế Liệu",
    [2354419709] = "Phao không chạm nước.",
    [2354614045] = "Một chiếc quần nhẹ. Chúng đơn giản và dễ thay thế, vì vậy không quá tệ nếu chúng bị tẩy trắng bởi ánh nắng mặt trời hoặc bị ngấm nước.",
    [2355052403] = "Những chiếc vảy cá lấp lánh. Cầu vồng phản chiếu trên bề mặt của chúng khi bạn di chuyển chúng trong ánh sáng. Bản chất bền chắc của chúng làm cho chúng lý tưởng cho việc chế tạo.",
    [2355333958] = "Phục hồi ngay lập tức một lượng lớn SP.",
    [2355760052] = "Nền Tảng Hỗ Trợ Thô Sơ",
    [2355801251] = "Sát Thương Khai Khoáng",
    [2356209048] = "Triệu Hồi <npc>Thợ Mộc</npc>",
    [2356242888] = "Tiện Nghi - Nhà Bếp",
    [2356283226] = "Đã bao giờ tự hỏi liệu có còn những người sống sót khác không? Ta có cảm giác là có.",
    [2356502831] = "Chất Lỏng",
    [2356602864] = "Một chiếc răng hóa thạch đã bị mài mòn qua các thời đại. Mặc dù những hóa thạch này từng rất nhiều, nhiều thứ giờ đây đã vĩnh viễn bị chôn vùi dưới một lớp nước dày đặc bị nhiễm độc Sương độc.\n\nBộ sưu tập này được tìm thấy ở Cao Nguyên Du Mục.",
    [2357306134] = "<b>Thời gian trong Sương độc</b> tăng thêm 5 phút, cho phép bạn khám phá lâu hơn.\n\n<b>Thời gian trong Sương độc</b>\nNếu thời gian này hết, Sương độc sẽ nuốt chửng bạn.",
    [2357427434] = "Việc Cuối Cùng",
    [2358148652] = "Giỏ II",
    [2358839255] = "Đầu Ma-nơ-canh \"Tóc Bện\"",
    [2358895684] = "Quả Cầu",
    [2358960626] = "Người trợ lý thợ rèn mới, Rochelle Anders, muốn có một bộ quần áo mới. Cô ấy đã đề cập đến việc xé toạc bộ quần áo cũ của mình trong một chuyến thám hiểm gần Trang trại Fanning khi nhìn thấy nhện bò trên đó.\n\nTiếp cận khu vực được đánh dấu trên bản đồ của bạn và lấy các vật phẩm quần áo cho Rochelle!",
    [2359086518] = "Lò Rèn Đá Quý Vùng Đất Mùa Xuân",
    [2359761241] = "<craftingstation>Nồi Hầm Đen</craftingstation> Cho <craftingstation>Trạm Giả Kim</craftingstation>",
    [2359898375] = "Ngọn lửa bên trong bạn cho phép bạn chống lại Sương độc — nhưng nếu bạn nán lại, bạn sẽ chết. Thoát khỏi Sương độc để bổ sung Thời gian trong Sương độc của bạn.",
    [2359980670] = "Số Lượng Kẻ Địch",
    [2360469699] = "Thời gian trong Sương độc",
    [2360951918] = "Bạn đã phát hiện trong một văn bản rằng các Sảnh Đường Hollow ở Đỉnh Albaneve trước đây đã được một nhóm những người thử thách ghé thăm.\n\nHãy đi theo con đường của họ và thu thập những gì bạn có thể!",
    [2361631920] = "Đòn Tấn Công Lăn Tránh Néo",
    [2361764694] = "<lorename>Sameth</lorename> đã bị tiêu diệt! \n\nThi thể hắn mục rữa, bị trói vào cây nấm như một lời cảnh báo cho tất cả! Chúng ta sẽ bầu ra một nhà lãnh đạo mới, một người sẽ không cai trị bằng nỗi sợ hãi và sự tham lam... Một người công bằng và chân thật!\n\nThuốc Tiên sẽ là CỦA CHÚNG TA!",
    [2362464641] = "Thỏi Thiếc",
    [2363312149] = "Xóa mật khẩu",
    [2363622914] = "Lời Nguyền \"Tất Tay Hay Không Tay\"",
    [2363903927] = "Bản Lưu Đã Chọn",
    [2364134688] = "Khó",
    [2364334672] = "Bạn đã nghe tin đồn về một <b>vũng nước gần thủ đô</b> đang sụp đổ. Hãy khám phá khu vực và tìm kiếm những vật có giá trị tiềm năng!",
    [2364434477] = "Ta thấy ngươi có liên hệ với Ngọn lửa, bạn của ta! Ồ, ánh sáng vinh quang! Ngươi hẳn là có khả năng sử dụng phép thuật... tại sao không thử? <b>Đũa phép</b> rất dễ sử dụng, nhưng <b>gậy phép cần phép thuật làm đạn dược</b>... Ta có thể dạy ngươi! Hãy chế tạo một cây gậy phép với ta từ gỗ chết, và cảm nhận ánh sáng chảy qua huyết quản của ngươi!",
    [2364491712] = "Đầu của ngươi đau khủng khiếp.",
    [2364679652] = "Bạn đã tìm thấy thứ dường như là một mảnh bản đồ kho báu khi khám phá tàn tích của bộ xương rồng! Có những dòng chữ khó nhận thấy ở mặt sau của cuộn giấy.\n\nCó lẽ có nhiều mảnh giống như thế này ở <i>những nơi tương tự.</i> Nếu bạn tìm thấy tất cả chúng, bạn có thể <b>kết hợp chúng thành một bản đồ kho báu được phục dựng!</b>\n\nTìm tất cả các mảnh bản đồ kho báu!",
    [2364797701] = "Sự ngụy trang hoàn hảo — ngay cả dưới ánh sáng ban ngày.",
    [2364977611] = "Tăng sát thương gây ra bởi các vụ nổ ném.",
    [2365041175] = "Một món cà ri kem làm từ chuối, gạo, nước cốt dừa và rau. Nó có vị chua, đậm đà và khá no.",
    [2365276575] = "Một mũi tên chết người được gắn đầu mũi sắt, gieo rắc nỗi sợ hãi cho kẻ thù.",
    [2365530992] = "Chiếc nhẫn này sẽ tăng cường HP và tốc độ Chữa thương của bạn.",
    [2365977272] = "Ồ, ngươi đã mang cho ta một bông hoa rực rỡ, phải không? Nó phát quang như thể tất cả vẻ đẹp của thiên nhiên đã chảy qua những chiếc lá của nó. Đó chính xác là thứ \"xanh\" tốt nên có! Đây là một trong những nguyên liệu ta cần nhớ cách làm thuốc nhuộm! Cảm ơn ngươi!",
    [2366228453] = "Thức ăn để thu hút và thuần hóa Hophare.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném mồi thức ăn gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Khi đã thuần hóa, con vật có thể được nhặt lên.",
    [2367368366] = "Bàn Gỗ Phương Bắc",
    [2367373641] = "Chúng không mang lại nhiều sự bảo vệ, nhưng tăng cường khả năng phép thuật của bạn. Thiết kế tối giản cũng ngăn bạn bị đổ mồ hôi tay.",
    [2367791805] = "Lều",
    [2367915978] = "Ngọn Đuốc Trở Về bổ sung Thời gian trong Sương độc của bạn. Đứng gần chúng để cảm nhận hiệu quả của chúng.",
    [2368270172] = "Độ nhạy Camera",
    [2368391429] = "Một đôi găng tay lạnh như tuyết trong một đêm không có nắng. Sử dụng chúng để đóng băng trái tim kẻ thù của bạn!",
    [2369774820] = "Giảm SP Đỡ",
    [2369901463] = "Bầy Scavenger đang xâm lấn, và ta sợ chúng ta đã tự đẩy mình vào chỗ chết chắc.\n\nKể từ khi chúng ta tìm nơi ẩn náu trong ngôi đền này, ta đã cố gắng vô số lần — và thất bại cũng nhiều lần — để tiếp cận căn phòng bí ẩn bên dưới. Cứ như thể các Cổ nhân đã xây dựng nó cho <i>ai đó vượt trên phàm trần, ai đó sinh ra vì một mục đích khác.</i>\n\nLàm sao ta có thể chấp nhận số phận của mình khi đức tin của ta dao động với mỗi tiếng gõ, mỗi tiếng động trong đêm?\nTa không được phép vào căn phòng. Ta phải chịu một cái chết tàn khốc dưới tay những kẻ man rợ đó. Thật là một kết thúc cay đắng cho những người sùng đạo... thật là lãng phí lời cầu nguyện.",
    [2370446978] = "Rìu Đồng Thiếc",
    [2370486177] = "Bão Tím",
    [2370956056] = "Một chiếc cần câu cá tốt giúp việc câu cá trở nên dễ dàng nhất có thể. Bạn có thể kéo cá nhanh hơn và giữ lâu hơn nếu chúng chống cự.",
    [2371579670] = "Tiếp đất sau khi lượn tạo ra một vụ nổ gây ST Hỏa %k và để lại một vệt lửa gây hiệu ứng <img gemeffect_bruning> đốt cho kẻ địch, gây sát thương %k mỗi giây trong %k. Sau va chạm ban đầu, các đòn tấn công gây thêm %k ST Hỏa trong %k.",
    [2371738661] = "Yên Ngựa Đá Vàng",
    [2372276042] = "Tốc Độ Kéo",
    [2373097202] = "Chiếc quần này bị dính bồ hóng.",
    [2373133423] = "Dao Găm Tự Chế (Shivs)",
    [2373135487] = "Trông giống như một kẻ địch Fell, nhưng hãy biến nó thành thời trang. Bảng màu xanh lam này phản chiếu tông màu của Sương độc, với một chút màu xanh ngọc lam được thêm vào.\n\nBảng màu này có thể được tạo bằng vật liệu từ Bồn tắm Nước Màn.",
    [2373456348] = "Thùng Tre I",
    [2373764039] = "Tên",
    [2373874131] = "Chúng ta không còn ở trong doanh trại nữa. Đây là chuyện thật. Mặt trận mới, tươi mới và lạnh giá! Đã đến lúc phải tỏ ra cứng rắn, nếu không người bạn mới của ta Connor sẽ bắt nạt ta.\n\nMọi người xung quanh ta đều là những người lính thực thụ, dũng cảm chịu lạnh vì quê hương. Thật thú vị!!\nNgay bây giờ, ta chỉ chặt củi và xua đuổi chuột, nhưng điều đó sẽ thay đổi, tin ta đi! Ta nghe lỏm được những người khác nói về một <i>sinh vật khổng lồ có cánh khi ngồi gần máy bắn đá...</i>\n\nHọ không nói cho ta biết đó là gì, nhưng ta sẽ sớm tự mình nhìn thấy. Và khi ta làm vậy, ta sẽ bắn thủng mắt nó bằng một phát duy nhất! Chắc chắn điều đó sẽ gây ấn tượng với Connor!\n— George",
    [2374348082] = "Ưưưư.",
    [2374848815] = "Thu nhỏ Trò chuyện Văn bản",
    [2374960955] = "Quả Ngọc Giá",
    [2375458856] = "Một chiếc bình kỳ lạ tỏa ra cảm giác sức mạnh.",
    [2376421874] = "Lối Vào Lăng Mộ Ẩn",
    [2376632056] = "Hài Cốt Trung Bình",
    [2376971100] = "Sự Sụp Đổ Của Kẻ Ngốc",
    [2376995048] = "Tăng sát thương lên Drak",
    [2377287514] = "Đầu Rồng Ma Trác Sa Ngã",
    [2377412252] = "Vảy Ý Chí",
    [2377995495] = "Thêm vào danh sách mong muốn ngay!",
    [2378029676] = "Hãy lên tiếng!",
    [2378038524] = "Bình Đất Sét V",
    [2378227332] = "Súp Cá",
    [2378268042] = "Chuột Đồng Đỉnh Cao Albaneve",
    [2378326116] = "Hàng Rào",
    [2378326325] = "Một lò sưởi ấm áp bạn có thể đặt trong nhà. Nó có thể được sử dụng để <b>nấu các món ăn đơn giản</b> và rất cần thiết để nhận Buff Nghỉ Ngơi.",
    [2378573881] = "Tắt",
    [2378748159] = "Quần Thợ Tập Sự <npc>Nhà Giả Kim</npc>",
    [2378794516] = "Tốc Độ Di Chuyển",
    [2379363461] = "Thức Ăn Cho Dê",
    [2379434804] = "Thật là một mớ hỗn độn... Ta chỉ định dựa vào tường để nghỉ ngơi, nhưng bằng cách nào đó, ta đã vô tình nhấn phải <i>nút ẩn để mở cửa bí mật!</i>\n\nNhững cánh cửa thông thường đã đủ hấp dẫn, nhưng cửa bí mật còn hơn thế nữa! Chúng thật là... <i>tuyệt vời.</i>\n\nTa thấy mình hứng thú với kỹ thuật chế tác, không, nghệ thuật của cánh cửa này hơn là kho báu mà nó có thể ẩn giấu. Cháu trai ta chắc chắn sẽ vô cùng vui mừng. Có lẽ nếu ta gửi cho nó một bản phác thảo bằng than, nó có thể tái tạo lại được. Ta tự hỏi liệu có nhiều ngôi đền giống như thế này không... và liệu chúng có kiến trúc tương tự không! Ta đoán ta sẽ tìm hiểu!\n\n— Braelyn",
    [2379581133] = "Trại Thương Gia Miền Bắc",
    [2380121466] = "Mũ Huyền Bí",
    [2380213050] = "Giáp Ngực Đạo Tặc",
    [2380387949] = "Bắt đầu",
    [2381640900] = "Khai Thác",
    [2381644517] = "Sự bảo vệ của bạn chống lại các đòn tấn công vật lý. Mỗi điểm giảm sát thương nhận được đi 1.",
    [2382206946] = "Đá Bia Mộ",
    [2382589205] = "Chiếc quần ống túm thanh lịch này thường được mặc bên dưới những chiếc váy hoặc áo dài lộng lẫy hơn.",
    [2383095139] = "Vũ khí gây ra các <b>loại sát thương khác nhau.</b> Sát thương và điểm yếu của đạn dược có thể được xem khi chọn vũ khí trong Kho đồ.\n\nKẻ địch có điểm yếu với một số loại sát thương nhất định. <b>Khai thác điểm yếu của kẻ địch</b> để giành lợi thế trên chiến trường.",
    [2383166842] = "Một chiếc nhẫn đơn giản và chắc chắn, được trang trí bằng 3 viên đá quý màu xanh lam. Dòng chữ khắc đọc là: \"Gửi <lorename>Cyrus</lorename>, vị Chỉ huy và người bạn trung thành nhất của ta\". Nó được tìm thấy bên trong hàm của sinh vật ám ảnh The Pike.",
    [2384215930] = "Các Lớp Nhân Vật và Thuộc Tính",
    [2384740046] = "Một <b>mũi tên đặc biệt</b> tẩm độc, hoàn hảo để săn bắn.\n\n<b>Mũi tên tẩm độc</b>: Wildlife và Quái vật Hoang dã bị trúng mũi tên này sẽ bị nhiễm độc và nhận 16 sát thương mỗi giây trong 5 giây.",
    [2384750478] = "Khe Xây Dựng Hình Dạng 1",
    [2384967262] = "Tổ Tiên Của Ta Và Ta Lớn Lên Trong Những Đường Hầm Này",
    [2385077834] = "Bào Tử Và Bệnh Tật",
    [2385453002] = "Bạn đã tìm thấy chiếc nhẫn bị mất của Nông dân. Hãy trả lại cho bà ấy để tiếp tục!",
    [2385818968] = "Mỗi phần trăm Kháng Độc sẽ giảm sát thương Độc nhận vào.",
    [2385919752] = "Bàn Cưa <craftingstation>",
    [2385921093] = "Một cây chùy nặng được trang trí bằng nhiều đầu sói gần tay cầm.",
    [2386049537] = "Giảm Tốc Độ Di Chuyển.",
    [2387376151] = "Đỏ Rực",
    [2387877794] = "Khối",
    [2388399707] = "Khối Mái Ngói Vỏ Đá Vôi",
    [2388522515] = "Giết Nữ hoàng Scavenger tại Đồi Scavenger đã <b>mở khóa kiến thức để chế tạo Móc neo Cải tiến.</b>\n\nDụng cụ cải tiến sẽ yêu cầu ít SP hơn để sử dụng. Chế tạo nó với sự giúp đỡ của <npc>Thợ mộc</npc>.",
    [2388529584] = "Những Người Sống Sót",
    [2388573303] = "Răng Cá",
    [2389373360] = "Băng bạn mang cho Thợ cắt tóc, than ôi, đã không truyền cảm hứng cho ông ta. Ông ta muốn bạn đi tìm ở những thung lũng bị sương độc bao phủ của Đỉnh Albaneve thay vì các đỉnh núi.\n\nÔng ta đang tìm kiếm loại băng \"không hoàn hảo\" hơn và bị biến màu.\n\nThu thập <b>băng bị sương độc bao phủ từ nấm trong các thung lũng bị sương độc bao phủ của Đỉnh Albaneve</b> và đưa nó cho Thợ cắt tóc!",
    [2389413641] = "Mặc định",
    [2390384555] = "Một viên aquamarine tuyệt đẹp lấp lánh trên bộ trang phục này, được cho là khuếch đại khả năng Chữa thương của người mặc",
    [2390736936] = "Độ Sáng",
    [2390858879] = "Các cổ vật huyền thoại được ban cho một lượng năng lượng ma thuật khổng lồ. Những cổ vật hiếm và mạnh mẽ này được sử dụng để <b>tăng cường</b> vũ khí huyền thoại, mở khóa toàn bộ tiềm năng của chúng.\n\nCác cổ vật huyền thoại trở thành một phần không thể thiếu của vũ khí sau khi được sử dụng và <b>không thể thu hồi</b>. Hãy lựa chọn cẩn thận, vì sức mạnh mà chúng ban tặng vừa phi thường vừa không thể thay thế.",
    [2391907884] = "Gỗ Nhiệt Đới",
    [2391960870] = "Áo Giáp Chiến Binh Rắn",
    [2392059660] = "<b>Thời gian trong Sương độc</b>\nNếu thời gian này hết, Sương độc sẽ nuốt chửng bạn.",
    [2392847715] = "<b>Vịnh Skimmer sụp đổ</b> và gầm rú. Đội cận vệ Hoàng gia của Vua <lorename>Gormander</lorename> nghi ngờ một <i>sự sụp đổ sắp xảy ra!</i> Hãy tránh xa vịnh hoặc mạo hiểm với rủi ro của riêng bạn. Các hoạt động tìm kiếm và cứu nạn không thể được thực hiện cho đến khi chiến tranh lắng xuống.\n\nHơn nữa: Tránh xa bờ biển vào ban đêm! Các báo cáo xác nhận <i>những rung động lạ trong nước</i>, cũng như <i>ánh sáng di chuyển</i>. Tuy nhiên, Vua <lorename>Gormander</lorename> muốn trấn an bạn <i>cá nhân</i> rằng <b>những báo cáo về một con thú dưới nước</b> vẫn chưa được xác minh. <location><lorename>Pikemead</lorename>'s Reach</location> an toàn như mọi khi!\n\n— Trưởng Higgs",
    [2392867059] = "Thợ Thủ Công",
    [2393036144] = "Sau khi đặt một Người Sống Sót, hãy nhắm vào một chiếc giường để chỉ định nó.",
    [2393097733] = "Bạn đã tìm thấy một ghi chú đề cập đến sự xuất hiện của một chiến binh dũng cảm trong đấu trường <location>Surat's Rest</location>. Cô ấy đã bị giết trong một trận chiến không công bằng và thi thể của cô ấy đã bị ném xuống vách đá. Hãy tìm thi thể của cô ấy và cứu lấy linh hồn cô ấy!",
    [2394521219] = "Đặt <craftingstation>Khung Cửi</craftingstation>",
    [2394532332] = "Màu Xanh Lá Tuyệt Vời Nhất",
    [2394899673] = "Hãy là thợ săn, không phải con mồi!",
    [2395337548] = "Linh hồn của Kindlewastes đã bị hút cạn từ lâu. Mỗi hạt cát là một lời cầu nguyện thầm lặng, mỗi hạt đều vô ích như đất chết bên dưới. Những dòng suối sự sống trong quá khứ, giờ đây không còn ai sinh sống - những hy vọng xưa kia bị chôn vùi dưới những cồn cát và bụi bặm.",
    [2395444564] = "Những quả cầu nhỏ mọc bên trong động vật có vỏ, được đánh giá cao vì vẻ đẹp thô sơ của chúng.",
    [2395521283] = "Khai thác trong Sương độc Vùng Đất Xuân",
    [2395529621] = "<npc>Nông Dân</npc>",
    [2395827811] = "Tiến Độ Trò Chơi",
    [2396080009] = "Khi đeo đôi găng tay này, Chúa tể Phương Bắc đã tự mình vượt qua các thung lũng bị sương độc bao phủ của Embervale. Những vết sẹo mà ông ta khắc lên người và đất có thể được truy dấu từ những ngọn núi ảm đạm đến tàn tích ngày nay của <location><lorename>Pháo đài Pikemead</lorename></location>.",
    [2396447004] = "Trại Mộc",
    [2396640346] = "Chân Trái Của Quái Vật Mắt Một",
    [2397063976] = "Vinh Quang Cho Mẹ <lorename>Lupa</lorename>",
    [2397999899] = "Khoảng thời gian trì hoãn sau đó quá trình tái tạo sẽ hoạt động.",
    [2398161332] = "Bạn cảm thấy ốm... HP tối đa và SP của bạn bị giảm.",
    [2398544582] = "Coi chừng dằm!",
    [2398955810] = "<i>Tin tôi đi, nhạc sống sẽ rất tuyệt vời cho quán rượu của bạn! Không, chúng tôi sẽ không bao giờ gây rắc rối! Hãy nghĩ đến lượng rượu mật ong bạn sẽ bán với The Honeydews hát cho khách hàng của bạn nghe!</i>\n\nThật là một mớ hỗn độn. Gã đó đã thao túng tôi hoàn toàn. Lẽ ra tôi nên biết ban nhạc này sẽ gây rắc rối, dù sao thì họ cũng có tiếng xấu về các vụ ẩu đả trên sân khấu! Nhưng một <b>cuộc chia tay trực tiếp?</b> Thôi nào!\nVà tên khốn Miles này còn cố gắng thuê phòng ở đây sau khi ban nhạc của hắn PHÁ HỦY cơ sở của tôi! Tôi đã đuổi hắn đi, nhưng tôi thề tôi vẫn có thể nghe thấy <b>tiếng sáo ngu ngốc của hắn đang được chơi ở đâu đó gần đây.</b> Thật là khó chịu.\n\nHắn làm vậy để chế giễu tôi khi tôi nhặt những chiếc đĩa vỡ và lật bàn lại!",
    [2399057538] = "Thêm <b>móc neo đu</b> này vào các tòa nhà của bạn để <b>vượt qua các vực thẳm.</b> Yêu cầu Móc Leo để kích hoạt.",
    [2399122100] = "Chọn một công thức để hiển thị các tài nguyên có sẵn trong các rương ma thuật gần đó.",
    [2399149509] = "Dịch chuyển đến kẻ địch sẽ kích hoạt một vụ nổ gây sát thương <b>Lửa</b> trong một bán kính nhỏ.\n\nSát thương và chi phí MP tăng theo thuộc tính Trí tuệ.",
    [2399373333] = "Khối Phản Xạ Nhanh",
    [2399527054] = "Dọn sạch kho để nhặt",
    [2399534640] = "Người chơi không có đặc quyền",
    [2400032395] = "Áo Giáp Người Tiên Phong",
    [2400184099] = "Chúng ta đang ăn mừng Vua Vorgoth đã bảo vệ thành công các đỉnh núi! Vinh quang cho Vệ binh phương Bắc!\n\nHãy mua vé ngay bây giờ trước khi hết vé! Hãy xem buổi biểu diễn ở sảnh lớn phía trên - đồ ăn nhẹ không bao gồm trong vé!!",
    [2400636994] = "Bánh Xe Nước Lớn",
