    [2404233470] = "không áp dụng",
    [2404411188] = "Bộ Sừng Tùng",
    [2404734440] = "Cây cần câu bạn tìm thấy có vẻ là một phát hiện may mắn! Bạn nên sử dụng nó đi, bạn của tôi!",
    [2404991148] = "<h2>3. Cung cấp trò chơi, tải xuống, xử lý thanh toán</h2>\n\nTrò chơi của chúng tôi được cung cấp cho bạn bởi nhà điều hành nền tảng tương ứng mà bạn tải xuống trò chơi của chúng tôi (Steam). Chúng tôi không chịu trách nhiệm về việc xử lý dữ liệu cá nhân của bạn bởi các nền tảng này, ví dụ: tài khoản người dùng, cung cấp và tải xuống trò chơi hoặc xử lý thanh toán, mà là nền tảng tương ứng. Bạn có thể tìm thêm thông tin trong chính sách bảo mật của nền tảng tương ứng.\n",
    [2405292845] = "Tôi Đã Tìm Thấy Ghi Chú Của Cô Ấy!",
    [2406433284] = "Vải",
    [2406600676] = "Bạn hiểu chữ viết của Drak và có sức mạnh tăng cường chống lại Drak.",
    [2407339926] = "Một luống cày, dùng để trồng cây con thành nông sản. ",
    [2407634096] = "Bình Máu +",
    [2408886780] = "5% cơ hội gây độc cho kẻ địch khi đánh trúng ",
    [2409835318] = "Bọn Vukah đang tập trung tại Đồng Cỏ Thấp. Có điều gì đó bí ẩn đang diễn ra. Hãy tìm trại của chúng và điều tra!",
    [2410340638] = "Lại đây nào! Chiều lòng ta đi!",
    [2410483165] = "Nhật Ký Của Martha, Mục 1",
    [2410694222] = "Chiếc quần này phối hợp hoàn hảo với áo, tạo ra sự chuyển tiếp mượt mà. Chúng đủ thoáng khí để ngăn ngừa quá nhiệt trong trận chiến.",
    [2411217911] = "Còn nhiều thứ để khám phá! Hãy leo lên một Tháp Cổ khác và xem chúng ta có thể tìm thấy gì!",
    [2411245449] = "Kiểm Lâm",
    [2411429090] = "Ta thích dong buồm trên những vùng biển cấm…",
