    [2412349305] = "Bộ Sát Lang",
    [2413048932] = "Được mô phỏng theo tường thành của thành phố Kindlewastes. Khối này là bản sao chính xác.",
    [2413720331] = "Điều chỉnh lượng kinh nghiệm nhận được qua chiến đấu.",
