    [2415763984] = "Tủ Trưng Bày Hành Lang Khô Cốt (3 Khe Nhỏ)",
    [2416006348] = "Khăn Trùm Đầu Người Chữa Lành",
    [2416049128] = "Nhẫn Sinh Lực Nhỏ",
    [2416128309] = "Cửa Gỗ Giả",
    [2417016069] = "Một thanh kiếm công phu, được trang trí bằng hoa văn vàng. Nó từ trên trời Fell như một sao băng nhiều năm trước, và rơi vào cái hàm há hốc của một hang động.",
    [2417021456] = "Màu trắng phấn và hồng rực rỡ trong bảng màu này tạo nên sự ngây thơ trẻ con.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Đỉnh Albaneve.",
    [2417158912] = "Đôi bốt thanh lịch với các điểm nhấn màu xanh lam. Chúng toát lên vẻ quyến rũ và duyên dáng.",
    [2417349738] = "Bộ lọc Máy chủ",
    [2417444013] = "Tiếng Pháp",
    [2417811521] = "Bong bóng khí giúp bạn hồi phục Oxygen.",
    [2418135834] = "Đạn phép của đũa phép có <b>25%</b> cơ hội không tiêu hao độ bền. ",
    [2418211210] = "Chất Lỏng Chướng Khí",
    [2418328578] = "Nấm này có vị nước và hơi lạ, vị kỳ lạ của nó đến từ ma thuật thuần túy chảy khắp cơ thể. Sức mạnh to lớn đang chờ đợi người tiêu thụ.",
    [2418773138] = "Mở hầu hết các cửa bị khóa.",
    [2419047914] = "Mũ Giáp Học Giả Ngọn Lửa Trẻ",
    [2419211041] = "Một trong những người sống sót trong căn cứ của bạn đã lấy <b>hòm trang bị</b> của <npc>Thợ Rèn</npc>. Hãy hỏi xung quanh để tìm ra thủ phạm!",
    [2419583357] = "Lan truyền",
    [2419670768] = "Theo Dấu Vết Của Dì Braelyn",
    [2420463286] = "Thác Polaris",
    [2420481176] = "Tối đa %k%%",
    [2420512864] = "Có đủ bản lĩnh không?",
    [2420567760] = "Ta có thể nói chuyện với ngươi cả ngày! Còn gì nữa không?",
    [2420716518] = "Cần có Bàn Thờ Ngọn lửa ở gần.",
    [2421218811] = "Tóc Màu Hoàng Hôn",
    [2421458829] = "Mũi Tên Băng Vĩnh Cửu II",
    [2422905800] = "Trang %k",
    [2423323155] = "Ta đã nói sự thật với họ, nhưng họ không tin ta! <i>Con rồng là có thật! </i>\n\nTa đã nhìn thấy nó khi đang lục lọi rượu ở rìa ngoài lãnh thổ của chúng ta. Khi ta vấp phải cái <b>hang động</b> đó và đối mặt với ánh mắt hung tợn của nó, đôi mắt rực sáng với ánh sáng huyền bí — ta đã quay người như chong chóng và bỏ chạy! \n\nNhững người khác nhổ nước bọt và cười nhạo ta! Vậy thì sao nếu ta uống một chút rượu mạnh khi đi ra ngoài? Ta biết những gì ta đã thấy!",
    [2423405420] = "Giày Trưởng Lão",
    [2423784047] = "Nhẫn Năng Lượng Nhỏ",
    [2424887308] = "Một loại vật liệu sáng bóng với kết cấu thú vị. Bất kỳ trang phục nào làm từ vật liệu này sẽ trông rất thời trang.",
    [2424908237] = "Sử Dụng Lò Rèn Ngọc",
    [2425298958] = "Cẩn thận. Lửa đang bay.",
    [2425376684] = "Ở đây trong đóa hoa trăng\nNước mắt ta phản chiếu nước mắt ngươi \nKhi tim và quan tài phơi bày",
    [2425437201] = "Hành Động Cơ Bản",
    [2425743549] = "Thu thập",
    [2426828456] = "Vườn Hoàng Gia Của <lorename>Gormander</lorename>",
    [2427244849] = "Số khe trống tối thiểu",
    [2427697673] = "Triệu hồi những người sống sót được giải cứu vào căn cứ của bạn xung quanh một Bàn Thờ Ngọn lửa.",
    [2427700731] = "Nâng Cấp Trạm",
    [2428291564] = "Bàn",
    [2428491416] = "Đang chờ...",
    [2429121861] = "Nắm đấm trần của bạn chỉ có thể gây sát thương nhỏ. Để sinh tồn, vũ khí hoặc khiên sẽ tốt hơn.",
    [2429421730] = "Sát thương chống lại Fell",
    [2429569464] = "Sử dụng các tùy chỉnh ràng buộc chưa hoàn chỉnh",
    [2430225750] = "Cẩn thận nhé.",
    [2430503181] = "Giá Treo Gắn Tường Vũ Khí Cận Chiến Một Tay",
    [2431274380] = "Pha cà phê xay với nước theo phong tục,\nsau đó làm dịu cà phê bằng sữa cho đến khi vị đắng phai đi.\nKết quả: một tách cà phê mượt mà, ấm áp và dễ chịu\nTa muốn gọi sáng tạo này là: <b>Latte</b>\n",
    [2431761491] = "Thời gian hồi sinh đồng minh giảm từ <b>6</b> xuống <b>3</b> giây. ",
    [2431762956] = "Một yếu tố trang trí tạo ra bầu không khí bùng nổ, đúng vậy.",
    [2432055509] = "Một chiếc mũ đồng bảo vệ hộp sọ của bạn khỏi bị tổn hại khi bạn bảo vệ đồng minh.",
    [2432377868] = "Ghế",
    [2433307029] = "Cây Dương Khai",
    [2434065256] = "Giá Để Sách Hầm Mộ",
    [2434335216] = "Nhà giả kim <npc>Alchemist</npc> đã đề cập rằng một số phép thuật được truyền năng lượng ma thuật vô tận. Những phép thuật như vậy được gọi là phép thuật vĩnh cửu, và chúng không bị tiêu hao khi được sử dụng làm đạn cho gậy phép. Chúng có thể được sử dụng vô thời hạn.\n\nNhững phép thuật này nằm rải rác khắp thế giới, nhưng một phép thuật đã được chôn cùng với chủ nhân trước đây của nó trong một ngôi mộ dưới lòng đất. Hãy tìm ngôi mộ bị chôn vùi và lấy lại phép thuật vĩnh cửu để sử dụng.",
    [2434342715] = "Đũa Phép Băng Giá",
    [2434523546] = "Giáp Nặng",
    [2434529888] = "Ra Khơi",
    [2434617498] = "Áo Vest Giao Ước Lửa",
    [2434666294] = "Điều chỉnh chất lượng phản chiếu. Giảm chất lượng sẽ tăng hiệu suất.",
    [2434832909] = "Chỉ người chơi sống gần đó mới nhận được vật phẩm.",
    [2434846202] = "Những chiếc Găng Tay Cung Thủ này đã được tinh chỉnh để vừa vặn và hiệu quả.",
    [2435074565] = "Đầu Ma-nơ-canh \"Tóc Cạo Sát\"",
    [2435284358] = "Cây Giống Lúa",
    [2435462762] = "https://enshroudedstore.com",
    [2437537156] = "Pháp Sư Băng Và Trang Bị Của Họ",
    [2437686267] = "Ngươi đã bắt đầu xây nhà cho ta chưa? Ta trông có vẻ khó chiều nhưng ta không kén chọn đâu!",
    [2438148843] = "Phân Công Giường Cho Fenrig",
    [2438475139] = "Vật phẩm sưu tầm này được tìm thấy ở Cao Nguyên Du Mục.",
    [2438771477] = "Mối đe dọa ở gần",
    [2438882669] = "Một chiếc băng đô kim loại xoắn thanh lịch, được tô điểm bằng một viên đá bắt mắt.",
    [2439098590] = "Huyền Thoại Về Người Khổng Lồ",
    [2439235407] = "Trại Xe Ngựa",
    [2439348819] = "Mắt cá trơn tuột, được lấy ra từ hốc mắt của một con cá bị bắt. Cảm giác như chúng đang nhìn bạn với ác ý.",
    [2439435036] = "Cửa Đá Giả",
    [2439742867] = "Bàn Thờ Ngọn lửa của bạn đã bảo vệ khu vực này quá lâu đến nỗi một số vật phẩm không thể tìm đường đến với bạn nữa.\nNgọn lửa đã giữ chúng an toàn để bạn có thể nhận, để bạn có thể tiếp tục hành trình của mình.",
    [2440347338] = "Âm nhạc minh họa ấn tượng đầu tiên đầy kinh ngạc mà dãy núi hùng vĩ để lại. Mọi tiếng vọng đều bị nuốt chửng bởi tuyết tinh khiết, trong lành. Không ai sẽ nghe thấy bạn ở đây.\n\n<b>Tập Nhạc</b>: \nNhạc Tờ dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ tờ nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát đó.",
    [2440353999] = "Mũ Giáp Cai Ngục",
    [2440612014] = "Số Lượng Người Chơi & Giao Tiếp",
    [2441095181] = "Khử răng cưa làm mượt các cạnh trong hình ảnh, làm cho chúng trông tự nhiên hơn.",
    [2441210796] = "Thang",
    [2441484613] = "<b>Bị ướt</b>\nGiảm <b>30%</b> SP và Hồi phục SP trong <b>15</b> phút. Hơi ấm sẽ giảm thời gian còn lại.",
    [2441628921] = "Caspian",
    [2441913964] = "Đầu Ma-nơ-canh (Đội Tóc Giả)",
    [2442030194] = "Thay đổi góc nhìn",
    [2442290626] = "Ghế Mộc Mạc",
    [2442607264] = "Tìm Bộ trang phục Thợ rèn Mỹ thuật",
    [2442662428] = "Neo Móc Đu Kéo Chịu Lực",
    [2443052149] = "Độc",
    [2444011745] = "Bạn có thể để dành một ít thuốc cho ẩn sĩ không?",
    [2444136734] = "Cây xương rồng",
    [2444765464] = "Tăng thuộc tính Tinh thần của bạn lên 1.\n\nTăng MP theo %k cho mỗi Điểm thuộc tính.",
    [2444880314] = "Không có Bia mật ong, không có Khoai lang nướng mật ong hoặc Trà gia vị mùa hè cho đến khi <craftingstation>Máy hun khói ong</craftingstation> và tổ ong của tôi đến từ <location>Đông Lapis</location>! Cho đến lúc đó: Súp cà chua kem, Ớt nhồi thịt VÀ tuần này chỉ có: Phi lê cánh kền kền Rồng, ăn kèm kem chua và khoai tây chiên!\n\nThưởng thức khi còn nóng!\n— Emily Fray",
    [2445208166] = "Tàn nhẫn",
    [2445371285] = "Lựa chọn",
    [2445977315] = "Tăng thêm cơ hội chí mạng cho vũ khí phép thuật.",
    [2446213868] = "Mũi Tên Thép Vàng Tẩm Độc",
