    [2447990064] = "Mô hình chi tiết Voxel",
    [2448265725] = "Cá thối từ đầu.",
    [2448449167] = "Những cây Hoa huệ trông thật tuyệt vời — chúng sẽ tạo nên một màu tóc mới TUYỆT ĐẸP! Nhưng tôi cũng đã nhìn thấy những bông hoa lạc tiên đẹp nhất vào ban đêm… bạn có thể mang cho tôi một ít được không, làm ơn?",
    [2449034054] = "Hoa Vàng",
    [2449582060] = "Hợp lệ",
    [2450167214] = "Kẻ thù truyền kiếp",
    [2450443945] = "Tường leo",
    [2451252424] = "Tia đa mục tiêu",
    [2451253964] = "Sát thủ",
    [2451604091] = "Cá đã đến quá gần bờ.",
    [2451721001] = "Hỡi Hỏa sinh, lại đây! Ta có tin thú vị muốn chia sẻ với ngươi!",
    [2452230985] = "Giá Để Khiên",
    [2452293510] = "Kho đồ",
    [2452481693] = "Tất cả nhạc cụ Sử thi đã được thu hồi",
    [2452797273] = "Nhật ký Người gác hải đăng II",
    [2453231524] = "Mọi khía cạnh của đầu búa này đều được thiết kế tỉ mỉ. Mặt trước và mặt sau có thiết kế đầy màu sắc nhưng trang nhã, trong khi hai bên có một hàng gai. Vừa hấp dẫn, vừa hữu dụng.",
    [2453442952] = "<lorename>Loraine Crim</lorename>",
    [2453664469] = "Sừng đột biến",
    [2454398605] = "Tìm một bảng màu trong Trang trại Kindlewastes",
    [2454492801] = "https://Sương độc bao phủ.featureupvote.com/",
    [2454514405] = "Kiếm dài 2H",
    [2454571019] = "Tôi biết chúng ta không đủ tiền mua quần áo mới cho Lễ hội Thu hoạch, nên tôi đã ứng biến... nhưng tôi cần sự giúp đỡ của bạn!\n\nTôi muốn làm mới màu sắc chiếc váy cũ của mình, nhưng tôi hết màu cam rồi. Bạn có thể lấy thêm từ chợ và để thuốc nhuộm trong phòng tắm cho tôi được không? Tôi sẽ sử dụng bồn tắm ở đó để không làm bẩn mọi thứ với màu sắc. Đừng lo, tôi sẽ dọn dẹp sau!!\n\nCảm ơn bạn!",
    [2454912749] = "Tìm tất cả các đền thờ và thánh địa Ngọn lửa trong Cao nguyên Du mục.",
    [2454970786] = "Một cú đấm được cường hóa bằng phép thuật, đẩy lùi và làm choáng kẻ địch.\n\nThay thế các đòn tấn công không vũ trang của bạn miễn là bạn có đủ MP cần thiết.\n\n<b>Chi phí:</b> 30 MP",
    [2455321199] = "Trại Vukah này là nơi sinh sống của một giáo phái chiến binh tự hào về bạo lực và sự hủy diệt. Tôi ước gì mình có thể đến gần hơn để quan sát kỹ hơn, nhưng tôi sợ rằng đó sẽ là dấu chấm hết cho tôi. Thỉnh thoảng, họ tụ tập trên sườn đồi này và tiến hành các trận đấu giác đấu, nơi người sống sót duy nhất được tôn vinh — điều mà tôi gọi là <b>Kẻ Đấu Sĩ</b>.\n\nNhững kẻ địch hung tợn, to lớn này có khả năng chiến đấu phi thường và thu thập sức mạnh từ <i>trụ đá mà giống loài của chúng tôn thờ</i>. Nếu bạn đủ điên rồ để đối đầu với một trong những Kẻ Đấu Sĩ này, tôi khuyên bạn nên tự mình thử một trong những <b>Tăng cường Ngà</b> này.",
    [2455737194] = "Ngọc Chảy Máu",
    [2455919178] = "Một số cánh cửa bị khóa, nhưng có thể mở bằng cách tìm và nhấn đúng nút.",
    [2456336912] = "<lorename>Thuyền trưởng Arkwright</lorename>",
    [2456664511] = "Phải có thêm",
    [2457018965] = "Chúc phúc cho các Cổ nhân!",
    [2457081052] = "<craftingstation>Cối xay</craftingstation>",
    [2457988649] = "Bộ Sát thương Băng giá",
    [2458174634] = "Chúng ta cần thêm không gian, Hỏa sinh. Và rương nữa, bạn có nghĩ vậy không?",
    [2458486080] = "Dịch chuyển lùi",
    [2459026340] = "Đất ẩm",
    [2459538714] = "Bảo vệ tăng cường chống lại sát thương vật lý cắt, ngoài khả năng chống sát thương vật lý chung.",
    [2459927182] = "Mũ Pháp Sư",
    [2460240884] = "GIÁP\nMỗi điểm \"Giáp Phép\" giảm sát thương cho tất cả các loại sát thương phép thuật đi 1.\n\nKHÁNG PHÉP\nMỗi phần trăm \"Kháng Phép\" tiếp tục giảm tất cả sát thương phép thuật.",
    [2460325185] = "Ngươi yếu đuối, nhóc! Một Hỏa sinh thực thụ sẽ tự trang bị vũ khí — để ta chỉ cho ngươi cách làm!",
    [2460757849] = "Trong Sương độc Chết chóc",
    [2460980228] = "Đuốc Treo Tường Đồng Thiếc",
    [2460995681] = "Benny đã lấy mũ của tôi\nThật không công bằng khi cậu ấy lấy mũ của tôi\nCậu ấy đã giấu nó trong một trong những chuồng dê nhỏ với những con dê hôi\nTôi thích những con dê, nhưng chúng hôi lắm, mẹ ơi\nTôi không muốn mũ của mình có mùi dê!\n\nMẹ làm cho con một chiếc mũ mới được không?",
    [2461151235] = "Gây ST Hỏa sẽ áp dụng hiệu ứng <img gemeffect_burning> đốt trong %k, gây %k mỗi giây. Sau khi kích hoạt thành công, hiệu ứng này có thời gian hồi chiêu là %k.",
    [2461464211] = "Phòng tắm",
    [2461525274] = "Tôi sẽ không cắn bạn đâu.",
    [2462070889] = "Chữ L mượt",
    [2462307050] = "Một cây Gậy phép được sử dụng bởi những người mang đuốc phép thuật của những ngày xưa. Họ thắp sáng những hang động chưa được khám phá để tuyên bố ngay cả những góc xa nhất của Đỉnh Albaneve là một phần của đế chế phương bắc. Cuộc trinh sát diễn ra tốt đẹp cho đến khi người Cyclopes phát hiện ra rằng những người mang đuốc là những pháp sư yếu ớt, ánh sáng của họ có thể bị dập tắt dễ dàng bằng một cú ném tảng đá quyết đoán.",
    [2463430836] = "Sắp xếp theo: ",
    [2463447703] = "Cờ Lệnh Dọc IV",
    [2463604968] = "Hồi sinh",
    [2463664895] = "Các đĩa nóng có thể được sử dụng để nâng cấp lò nướng.",
    [2463892563] = "Tôi không chỉ là một thợ cắt tóc, tôi là một kiến trúc sư phong cách!",
    [2464264963] = "<craftingstation>Máy hun khói ong</craftingstation>",
    [2464644421] = "Hoa Ly Màu Vàng",
    [2465934344] = "Vật liệu xây dựng",
    [2466041199] = "Xác định mức độ tiến triển thuần hóa bạn mất khi bạn làm một con vật sợ hãi.",
    [2466364423] = "Chùy Sao Kim Loại",
    [2466727648] = "Bình Phong Siêu Việt",
    [2466827924] = "Chiếc khiên gỗ tạm bợ này cho phép bạn <b>Đỡ</b> các đòn tấn công vật lý. Đỡ sẽ tiêu hao SP.",
    [2467004078] = "Phù thủy",
    [2467243837] = "Khối Gạch-Gỗ",
    [2467427052] = "MP",
    [2467854150] = "Làm thế nào để nói với sếp?",
    [2468085168] = "Thực thể đã đặt",
    [2468662114] = "Vukah",
    [2468663168] = "Chưa bị Ngọn lửa chạm vào, và bao phủ trong cái lạnh còn sót lại. Bộ giáp này từng thuộc về Lãnh chúa <lorename>Vorgoth</lorename>, người được đồn đại là có trái tim băng giá, vỡ vụn và tan vỡ với mỗi nhịp đập mệt mỏi.",
    [2468966002] = "Một cuộc điều tra quan trọng",
    [2469414413] = "Chuyển thanh hành động",
    [2470190043] = "Một tuyến dường như đang nhỏ giọt chất độc. Đừng suy nghĩ quá nhiều về nó, hoặc hình ảnh đó sẽ ám ảnh giấc mơ của bạn.\n\nTìm thấy trên những con nhện phun độc và có thể được sử dụng trong chế tạo để tạo ra thuốc giải độc Hemotoxin.",
    [2470437800] = "Khi nghi ngờ, hãy đi câu cá!",
    [2471974202] = "MP khi nhặt Quả cầu",
    [2472078179] = "Một mình trong thang máy",
    [2472311837] = "Vũ khí được tăng cường này sẽ hỗ trợ bạn trong cuộc chiến chống lại các sinh vật của Sương độc. Tăng cường vũ khí luôn yêu cầu <b>Runes</b>.",
    [2472377554] = "Tiền đồn Drak'Dal Sương độc bao phủ",
    [2472465109] = "Chân Phải Của Quái Vật Mắt Một",
    [2472488363] = "Thử lại",
    [2473213227] = "Cát mịn đã được pha trộn với bào tử Sương độc. Thường được tìm thấy trong quần xã sinh vật Kindlewastes.",
    [2473407434] = "Lẽ ra tôi phải thức. Tôi đã không.\nHọ đã tấn công trại của chúng tôi vào ban đêm với sự hung hãn bất ngờ. Bộ lông của họ lốm đốm những đốm garnet, giờ đã phai thành màu gỉ sét bết dính. Chúng tôi đã đi vào <i>lãnh thổ mới của chúng.</i>\n\nKhoảng một nửa số anh em của tôi đã ra đi. Absinthe; cây ngải đắng độc hại, một lớp phủ ghê tởm và đắng, làm tê liệt môi tôi. Tôi đã chiến đấu vì họ, tôi đã giơ rìu lên vì họ. Giáp của tôi, bị xé toạc. Tay tôi, nhuốm đỏ mãi mãi. Chúng tôi lẽ ra không bao giờ nên đi qua <location>Đấu trường Vukah</location> đó.\n\nMẹ. Xin mẹ đừng tuyệt vọng về con. Chúng ta cùng chung dòng máu. Con sẽ kiên trì, vì họ. Và con sẽ không bao giờ thất bại nữa.\n— <lorename>Jezmina</lorename>",
    [2474776629] = "Chặn sát thương có %k cơ hội để thêm %k ST Đập cộng thêm vào đòn tấn công tiếp theo trong vài giây tới và tăng lực đẩy.",
    [2474939423] = "ST Cận chiến Hai tay khi bị Sương độc bao phủ",
    [2475344154] = "<location>Longkeep</location>",
    [2475891047] = "Cung Ác Thú Có Sừng",
    [2476350723] = "Bạn đã đến một vùng đất bí ẩn mới tên là Blackmire. Sức mạnh của Ngọn Lửa ở đây yếu ớt, vì vậy bạn phải củng cố sự hiện diện của nó bằng cách thắp sáng Ngọn Tháp Cổ - Blackmire. Sau đó, Ngọn Lửa sẽ có thể dẫn đường cho bạn nhiều hơn.",
    [2477310298] = "Những loại tảo này trông có vẻ không đáng chú ý, nhưng chúng rất linh hoạt.",
    [2477563489] = "Lưỡi Kiếm Răng Nanh",
    [2477674334] = "Màu xám xỉn và ánh bạc không thể che giấu sự ghen tị màu xanh lục bảo đang sôi sục bên dưới.\n\nBảng màu này có thể được tạo bằng vật liệu từ Revelwood.",
    [2478125855] = "Vật phẩm thu hồi được",
    [2478199168] = "Chào Flameborn. Này, bạn có thể giúp tôi một việc được không? Tôi đang đau khổ! Mẹ tôi đã tặng tôi một chiếc nhẫn rất quý giá ngay trước khi tôi rời nhà để xây quán rượu của mình ở <location>Brittlebush</location>. Thật không may, tôi đã buộc phải chạy trốn khỏi một con Lạc Đà Cát trên hành trình xuyên qua Kindlewastes và làm mất chiếc nhẫn! Xin hãy giúp tôi tìm nó?",
    [2479139650] = "Một chiếc mũ mềm với lông vũ màu đỏ.",
    [2480347080] = "Chế tạo tại Người Thu Thập",
    [2480615983] = "Lưỡi Dao Than Khóc",
    [2480876917] = "Bong bóng khí",
    [2481460158] = "Đọc tất cả các bia đá trong Revelwoods.",
    [2481467166] = "Hãy quay lại sớm!",
    [2481772291] = "Hãy tưởng tượng: ",
    [2482160852] = "Đến <location>Surat's Rest</location>",
    [2484144829] = "Vũ khí ma thuật",
    [2484661437] = "Thịt Chuột Capybara Con Ngon",
    [2484991354] = "Chuyến đi bình an!",
    [2485504794] = "Biểu cảm bị vô hiệu hóa dưới nước.",
    [2485780679] = "Đèn Đứng Thép",
    [2485990969] = "Đá Lửa",
    [2486036711] = "Hàng Rào Cọc Gỗ Thấp I",
    [2486198382] = "Braelyn trở lại",
    [2486734468] = "Đừng trì hoãn nữa! Hãy leo lên Ngọn Tháp Cổ ở phía xa để khám phá các mốc quan trọng.",
    [2487363370] = "Những Làn Sóng Dũng Cảm",
    [2487401268] = "Lá cây cọ — rất hữu ích làm vật liệu xây dựng nhờ độ rộng và độ đàn hồi của chúng.",
    [2487728869] = "Một tùy chọn lưu trữ được cải tiến với dung lượng tăng cường.",
    [2487755195] = "Xoay (lớn)",
    [2488820952] = "Suối nước nóng Cromville",
    [2489592314] = "Chỉ những Drakling đủ kỹ năng mới có quyền sử dụng những con dao găm được trang trí này. Chúng thường là vũ khí đáng tin cậy trong suốt cuộc đời.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [2489728365] = "Bò Tây Tạng",
    [2489807667] = "Cột Cờ II",
    [2490005773] = "<b>Chế tạo và đặt một nhà máy</b> trong căn cứ của bạn để sử dụng nó. Nếu có nhiều công thức chế tạo khả dụng hoặc có thể, hãy chọn công thức mong muốn trong menu nhà máy ở trên cùng bằng cách <b>\"duyệt công thức\"</b> trước khi chế tạo.\n\nChọn các vật phẩm cần thiết để xử lý và <b>đặt chúng vào kho của nhà máy</b>. Nhà máy sẽ <b>xử lý</b> nguyên liệu thô thành các thành phần hoặc vật phẩm chất lượng cao hơn sau khi nhận được đầu vào vật phẩm chính xác.\n\nKiểm tra lại nhà máy của bạn sau khi <b>thời gian</b> trôi qua để lấy sản phẩm cuối cùng từ kho của nhà máy.",
    [2490112282] = "Bạn đã tặng <npc>Nông dân</npc> dâu tây. Hương vị của chúng gợi cho Emily nhớ về ngôi nhà cũ của cô ấy, nơi từng là một ốc đảo trù phú trước khi thảm họa ập đến.\n\nĐổi lại những quả mọng, cô ấy đã tiết lộ <b>vị trí của một kho báu bị chôn giấu</b> trong bãi rác của <location>Glennwood's End</location>. Khám phá địa điểm và đào lên những kho báu ẩn giấu!",
    [2490170718] = "Ô hành động 5",
    [2490343269] = "Đôi ủng này hoàn hảo cho mọi địa hình. Dễ dàng vệ sinh, chắc chắn và nhẹ.",
    [2490561241] = "Hiện thân của sự uy nghiêm vàng son với chiếc mũ trụ trang trí công phu này — và ánh nhìn kiên định như đá.",
    [2490673158] = "Chứa chất lỏng Sương độc đã được thanh tẩy, tăng cường khả năng kháng cự của người dùng.\n\nPhải uống trước khi vào Sương độc. Kéo dài Thời gian trong Sương độc thêm 2 phút. Hiệu ứng này sẽ kéo dài trong 45 phút.",
    [2490680837] = "Sát thương cơ bản ở 2 lần tích lũy",
    [2491020046] = "Sáp",
    [2491134682] = "Một chiếc mũ trùm bóng tối ẩn giấu một chiếc mặt nạ đầu lâu độc ác bên dưới. Đáng sợ!",
    [2491195780] = "Quặng Vàng",
    [2491337738] = "Xinh Đẹp Trong Màu Hồng",
    [2491815199] = "Ngọc Linh Hoạt",
    [2492084687] = "Trả lại nhẫn cho Nông dân",
    [2492989431] = "Thuốc tiên",
    [2493258644] = "Mặt trăng mỉm cười với bạn.",
    [2494157719] = "Đuốc Treo Tường",
    [2494158964] = "Thạch Anh Tím Nguyên Chất",
    [2494239002] = "Cây Chàm",
    [2494489241] = "Tôi nhìn thấy hắn khi tôi thức dậy\nMũi nhọn chiếc mũ màu xanh quỷ quyệt nhỏ bé của hắn\nVà thật là một chiếc mũ ngu ngốc\nNhọn hoắt, ngớ ngẩn, và đầy thù hận\n\nTôi nhìn thấy hắn khi tôi nhắm mắt\nNụ cười độc ác, chiếc xẻng rung rinh trong bàn tay nhỏ bé nhăn nheo của hắn\n\nTôi thấy hắn đào, đào, đào trên cánh đồng\nHắn muốn đẩy tôi xuống\nHắn muốn chôn tôi dưới đá và đất\n\nTôi sẽ không để hắn thắng, kẻ tà ác đó. Cái hố hắn đào trên cánh đồng nhỏ nhất của tôi sẽ là nấm mồ của chính hắn! Và rồi khi hắn biến mất, tôi cuối cùng cũng có thể ngủ lại, ngủ ngon, ngủ thật ngon, và không ai còn gọi tôi là kẻ điên nữa",
    [2494905451] = "Mảnh Bản Đồ Của Orpheus",
    [2495350521] = "Một chiếc khiên được tìm thấy trong một hang động sâu trong rừng. Nó đã được rửa sạch.",
    [2495450240] = "Lời kêu gọi phiêu lưu",
    [2496217612] = "Hàm rồng",
    [2496256242] = "Áo Giáp Pháp Sư",
    [2497678033] = "Một cụm tinh thể ectoplasm. Nó chứa đựng sức mạnh ma thuật to lớn bên trong.",
    [2497734086] = "Nâng cấp đáng kể này cho <craftingstation>Bếp nấu</craftingstation> mang đến các món ăn mới có thể được nấu một cách thụ động. ",
    [2497929223] = "Một <b>Móc neo</b> là rất quan trọng cho việc khám phá. Nó có thể được sử dụng để đu qua các khe núi hoặc tiếp cận các vị trí cao hơn. Tìm các điểm neo kéo của Móc neo trong thế giới sau khi bạn đã chế tạo Móc neo để sử dụng nó.\n\nBạn có thể chế tạo Móc neo tại một <b><craftingstation>Bàn chế tạo</craftingstation></b>. Móc neo là cần thiết để leo lên Ngọn Tháp Cổ!",
    [2498295797] = "Que không hợp lệ",
    [2498451527] = "Trang trại bỏ hoang",
    [2498801445] = "Đã đến ngọn tháp cổ ở Đồng cỏ thấp.",
    [2498853692] = "Cá nướng với cơm dừa hoặc khoai môn nướng (12 đồng tiền vàng)\nSúp cá cà chua, đậm đà và béo ngậy (9 đồng tiền vàng)\n\n<i>Lưu ý: Chúng tôi có rất nhiều cá, chỉ cần yêu cầu tôi bắt nó và tôi sẽ làm cho bạn! </i>\n\n<b>Dành cho những kẻ ăn lá:</b>\nSalad tảo (8 đồng tiền vàng)\nCà ri khoai môn rau củ đơn giản với cơm (10 đồng tiền vàng)",
    [2498919318] = "Tôi đang rất muốn thử một màu tóc mới cho bạn... lại đây nào! Tôi sẽ tư vấn miễn phí cho bạn!",
    [2499014780] = "Cuộn lên",
    [2499044451] = "Chúng ta chiến đấu.",
    [2499924889] = "Vòi Sen Đá",
    [2500361275] = "Sẵn sàng phản đòn",
    [2500565647] = "Chứa đầy ma thuật cổ xưa, chiếc nhẫn này mang lại ánh sáng cho bạn ở những nơi tối tăm.",
    [2500598423] = "Đang trong quá trình phát triển. Chưa có sẵn trong Closed Alpha.",
    [2501253588] = "<location>Glennwood's End</location>",
    [2501638927] = "+ Xuyên thủng",
    [2502487253] = "Mang lông thú cho <npc>Thợ săn</npc>",
    [2503412670] = "Hang sói",
    [2503812623] = "Chiếc cung này bắn dễ dàng vào các sinh vật của Sương độc.",
    [2504006139] = "Hang Cyclops gần cầu",
    [2504119209] = " <npc>Thợ mộc</npc> muốn bạn đến lăng mộ ẩn của Nữ hoàng cũ để khai quật kho báu của bà.\n\nĐịa điểm đã được đánh dấu trên bản đồ của bạn.",
    [2504171226] = "Phù Điêu Drak II",
    [2504369298] = "Kẻ trộm thuốc tiên",
    [2504468252] = "Ô hành động 3",
    [2504516322] = "Chậu hoa Tết Nguyên Đán",
    [2504750105] = "Súp Ectoplasm",
    [2505189119] = "<npc>Thợ mộc</npc> được giải cứu",
    [2505637342] = "Một mảnh giáp chân trông như đã sử dụng nhiều năm.",
    [2506077990] = "Thuốc nhuộm vàng",
    [2506222941] = "Đạt cấp tối đa",
    [2506330621] = "Lang thang",
    [2506931478] = "Tôi nhớ việc trao đổi hàng hóa. Có một số sắc tố mà tôi không thể tìm nguồn cung ứng hoặc giao dịch kể từ khi xã hội sụp đổ — nhưng vẫn còn hy vọng! Nếu các tiền đồn thương mại đã biến mất, thì những tên cướp và kẻ buôn lậu đã bao vây chúng cũng vậy. Ồ, giá như có một anh hùng ưa nhìn có thể đi đến, chẳng hạn như \"Nomad's Drop\" để tìm kiếm các bảng màu, tôi sẽ vô cùng biết ơn. Bạn có biết ai không?",
    [2507091891] = "Món súp nhờn này được cải thiện với một chút muối, nước dùng hầm chậm và thêm hương thơm của nỗi sợ chết.",
    [2507325777] = "Một mẻ lưới bị nguyền rủa",
    [2507772351] = "Bàn Góc Gỗ",
    [2507982539] = "Tìm nơi ẩn náu của Ramone Jones",
    [2508354976] = "Lửa bên trong",
    [2508495101] = "Một chiếc đĩa gỗ để trưng bày thức ăn đã nấu trên bàn.",
    [2508535580] = "Tàn tích hóa thạch của một con tôm bị mắc cạn. Hầu hết những chiếc chân nhỏ bé của nó không còn nhìn thấy được, điều này thật đáng buồn cho các nhà nghiên cứu — nhưng lại thú vị đối với những Flameborn yếu đuối.\n\nBộ sưu tập này được tìm thấy ở Kindlewastes.",
    [2508830299] = "Thùng Tre Lớn",
    [2508943453] = "Cốc Gốm",
    [2510607563] = "Bàn Thờ Ngọn Lửa",
    [2511159261] = "Điều khiển",
    [2511456764] = "Ngôi thánh đường này không còn yên bình nữa. Đã qua rồi những ngày mà sự tĩnh lặng và chiêm nghiệm tràn ngập các hành lang. Giờ đây, vào ban đêm có một tiếng lạch cạch mơ hồ mà ta không thể nào quên. Có điều gì đó đang xảy ra trong hầm mộ... và ta không muốn ở đây để chứng kiến kết cục của nó.\n\nTa đang thu dọn hành lý và lên đường. Ta cầu mong không có gì sẽ bám theo ta xuống vách đá, dù ta không còn tin rằng những lời cầu nguyện của mình sẽ được lắng nghe. Có lẽ ta sẽ đi theo <i>con đường bí mật</i> và mang theo <i>cây gậy</i> để đảm bảo an toàn.",
    [2511601020] = "Một con ếch trông ốm yếu, có màu xanh lam do tiếp xúc với bào tử.",
    [2511761184] = "Phù Điêu Drak VII",
    [2511807152] = "Kho đồ: Nhân vật",
    [2511911013] = "Tìm thấy trong các Hang ổ Sương độc của Kindlewastes",
    [2513300557] = "Thợ cắt tóc muốn bạn tìm một bảng màu gợi nhớ đến đá vụn. Ông ấy gợi ý đến thăm một mỏ đá ở Đỉnh Albaneve.\n\n<b>Đến mỏ đá Đỉnh Albaneve</b> để tìm một bảng màu xám!",
    [2513384472] = "Số lượng chế tạo: %k",
    [2513452727] = "Một màu xanh lá cây đại diện cho sự sống và sự đổi mới",
    [2513526825] = "Tủ Trưng Bày Phù Điêu Drak",
    [2513614210] = "Thanh Kiếm Nhật Thực",
    [2513682539] = "Điều chỉnh chất lượng bóng đổ. Giá trị thấp hơn sẽ cải thiện hiệu suất.",
    [2514587441] = "Bạn đã tìm thấy một mảnh của bức tranh khảm tuyệt đẹp! Có thể còn nhiều mảnh khác ở xung quanh. Hãy tìm kiếm ở Lâu đài Everfrore để tìm thêm các mảnh tranh khảm và tái tạo lại hình ảnh ban đầu!\n\n<b>Tổng cộng có 8 mảnh.</b> Chúng có thể được ghép lại tại căn cứ của bạn khi đặt vào khung.",
    [2514750179] = "Khối Đồng Thiếc",
    [2514857775] = "Tìm thấy trong các Hang ổ Sương độc của Cao nguyên Du mục",
    [2514906880] = "Khiên Bóng Ma",
    [2515081178] = "Trang tìm thấy",
    [2515455038] = "Ta sẽ giữ <keyitem>Ấm Nước</keyitem> này an toàn, cùng với ký ức về <lorename>Raúl</lorename>. Cảm ơn ngươi, Flameborn.",
    [2515531830] = "Ta chỉ chợp mắt một giây hoặc hai thôi, ta thề!! Ta tưởng em trai sẽ đánh thức ta, nhưng không! Hơi thở hôi hám của một kẻ ngoài vòng pháp luật đã kéo ta ra khỏi giấc mơ. Ta đã đánh thức Mathew, và chúng ta lao ra ngoài. Trong lúc vội vã, chúng ta thậm chí còn <b>làm rơi món quà và lá thư mà cô gái muốn chúng ta gửi đi!!</b> Giờ thì sao?\n\nÀ, mặc kệ. Thì sao chứ nếu vài kẻ xấu xúi quẩy đánh chúng ta? Thì sao chứ nếu <i>chúng ta làm mất món quà ngu ngốc đó!?</i> \"Đến lúc ứng biến rồi,\" Mathew nói. \"Chúng ta sẽ tự viết thư. Giấy đẹp đấy! Tinh tươm! Anh ta sẽ không biết đâu, thấy chưa?\"\n\nVậy là giờ chúng ta chỉ cần ký tên, nhưng có một vấn đề. Ta quên mất cái tên ngu ngốc của cô ấy rồi!! Rachel? Reagan?? Ước gì ta không làm rơi cái thư chết tiệt đó ở <location>Quần đảo Jasper</location>...",
    [2515562848] = "Ngoại hình Nhân vật",
    [2516713819] = "Bộ Đồ Học Việc Giả Kim",
    [2517121430] = "FSR3 là một kỹ thuật chống răng cưa tiên tiến. Giảm chất lượng sẽ tăng hiệu suất.",
    [2517721355] = "Băng",
    [2517828299] = "Một phần của Giáp Pháp Sư.",
    [2517994654] = "Máy Ép Linh Thể",
    [2518188756] = "Bóng Lửa Bùng Cháy",
    [2518396193] = "Chữa thương Sức Mạnh",
    [2518791243] = "Băng bó",
    [2518825428] = "Ngày Cấm",
    [2519250154] = "Bạn bị ướt sũng trong một thời gian ngắn.",
    [2519281115] = "Cài đặt Máy Chủ",
    [2519497796] = "Ta thực sự có thể giúp ngươi sửa sang lại nơi này nếu có một căn phòng cho riêng mình. Hãy xây cho ta một nơi trú ẩn, được không? Sẽ không quá khó khăn đối với một Flameborn thực thụ đâu!",
    [2519781112] = "Cánh Lượn",
    [2519985999] = "Bạn phớt lờ các cú đẩy lùi.",
    [2520033428] = "Một bộ mắt pha lê trang trí vũ khí này, tìm kiếm điểm yếu của kẻ thù. Cán cầm được trang trí bằng các dải da xếp chồng lên nhau.",
    [2520352627] = "Tia Lửa Từ Bể Veilwater",
    [2520882505] = "Một cây Gậy phép ma thuật, tràn đầy sức mạnh của chủ nhân trước đây. Truyền thuyết kể rằng linh hồn của người xưa gắn liền với nó, đôi khi ngân nga vào ban đêm.\nGậy phép có thể sử dụng <b>phép thuật</b> bằng cách dùng các vật phẩm nạp phép và MP. Trang bị <b>vật phẩm nạp phép</b> để sử dụng.",
    [2520996826] = " <location><lorename>Hang Lupa</lorename> chứa một <craftingstation>Trạm thuộc da</craftingstation> quý giá. <npc>Thợ săn</npc> sẽ rất vui khi biết về điều đó.\n\nĐặt <craftingstation>Trạm thuộc da</craftingstation> để mở khóa thêm công thức.",
    [2522454221] = "Lò Luyện Kim",
    [2522673246] = "Vẫn còn đây à? Nói đi.",
    [2523077222] = "Bàn Thờ Ngọn Lửa",
    [2523417914] = "Phòng Thủ Cận Chiến",
    [2524211916] = "Hạt Cà Phê",
    [2524361917] = "Hoa Đỏ",
    [2524935083] = "Máy Rang Cà Phê Hình Trống",
    [2525027142] = "Ngọn Lửa Everfrore Keep",
    [2525116472] = "Rất ít người đã tận mắt chứng kiến hơi thở sắc lạnh, tinh thể thoát ra từ <lorename>Vorgoth</lorename> dưới chiếc mũ giáp. Họ đã thấy tiếng hú của hắn nhảy múa trong làn khói và cảm nhận nó run rẩy dọc sống lưng, len lỏi vào tâm trí, và xoắn vặn quanh xương cốt. Nhiều người đã không sống sót để kể lại câu chuyện.",
    [2525142775] = "<b>Chiêu thức kỹ năng</b>\nĐánh trúng điểm yếu của kẻ địch, chẳng hạn như đầu hoặc tim lộ ra, được coi là Chiêu thức kỹ năng.",
    [2525421429] = "Để bổ sung cho cảnh bình minh, người thợ cắt tóc muốn có một bông hoa giống như cảnh hoàng hôn.\n\n<b>Hãy mang cho ông ấy những bông Hoa Đam mê màu hồng từ Bể Veilwater, có thể tìm thấy vào ban đêm.</b>",
    [2525447130] = "Từ lâu, một lữ khách đã mang đến một món quà quyến rũ cho người dân Embervale.",
    [2525478747] = "Máy chủ không phản hồi.",
    [2526275083] = "Một khoảnh khắc thoáng qua, đã biến mất.",
    [2527044808] = "Những đôi ủng nặng nề này mang lại khả năng kháng cự tuyệt vời và cho phép bạn giữ vững tư thế khi đối mặt với nhiều loại quái vật khổng lồ.",
    [2527358584] = "Chữ Viết Drak Thô Sơ",
    [2527502164] = "Thưởng Khi Nghỉ Ngơi",
    [2527518574] = "Thợ rèn đã đề cập đến một cách để khai thác vàng dưới nước, nhưng chỉ có công cụ phù hợp mới có thể thực hiện được.\n\nÔng ấy lưu ý rằng nhiều chuyến hàng vàng được gửi đến Thủ đô trước đây đến từ một thị trấn tên là Orville.\n\n<b>Hãy đến thị trấn này</b> và xem xét xung quanh!",
    [2528021891] = "Bất cứ ai sở hữu chiếc cúp này đã chứng tỏ rằng ngay cả Đấu sĩ Vukah mạnh nhất cũng không phải là đối thủ của họ.\n\nThu thập nhiều Đầu Đấu sĩ Vukah để chế tạo Cúp Vàng.",
    [2528462847] = "Ta sẽ biến ngươi thành một nhạc sĩ!",
    [2528584360] = "Trò chơi",
    [2528681196] = "Một cụm tinh thể tối, mọc cùng nhau. Chúng vươn ra các hướng khác nhau như những ngón tay xương của xác sống, cào cấu mình ra khỏi nấm mồ.",
    [2528729774] = "Thợ săn đã nói với bạn về một thị trấn từng bị chó hoang tràn ngập. Có lẽ vẫn còn một vài con chó ở đó.\n\n<b>Hãy chế tạo mồi thức ăn cho chó</b> để thuần hóa và giải cứu một con chó!",
    [2529014710] = "Một mảnh giáp ngực đáng gờm, được trang trí bằng nhiều yếu tố giống như thiên nhiên, dây leo và cánh hoa.",
    [2529057262] = "Sự Dũng Cảm",
    [2529939139] = "Được khai thác từ vùng đất hoang chết chóc tìm thấy trong các Sảnh Hollow. Cần cẩn trọng!",
    [2530360608] = "Elixir gây ra tác dụng phụ. Thời gian của bạn trong Sương độc bị giảm.",
    [2530441215] = "Sàn Máy Phân Phối Nước",
    [2530615754] = "Cây Giống Hoa Aureolin",
    [2530786602] = "Sự Điên Cuồng Chiến Đấu Không Hài Lòng",
    [2531410333] = "Ướt Sũng",
    [2531713129] = "Phải Sửa Hàng Rào",
    [2531842448] = "Tạm Biệt!",
    [2531871363] = "Hộp Trang Trí",
    [2531875280] = "Khối Mái Lâu Đài",
    [2532220973] = "Lực Lượng Không Đủ",
    [2532458683] = "Tàu Lượn",
    [2532462586] = "Trái Tim Lò Rèn",
    [2533830741] = "Một vũ điệu của màu xanh lam và xanh da trời.\n\nBảng màu này có thể được tạo ra từ vật liệu Revelwood.",
    [2533877053] = "Trọng Kiếm Mạ Vàng",
    [2534087107] = "Các Vị Thần Giúp Chúng Ta",
    [2534327902] = "Cài đặt độ khó chi tiết",
    [2535126509] = "Rìu Thợ Mỏ Thu Lượm",
    [2535394413] = "Được khắc với hình ảnh bằng đá, chiếc rìu này vừa là di vật vừa là vũ khí.",
    [2535415935] = "Khung Cửa Gỗ Tròn",
    [2535977852] = "À, hoàn hảo! Hoa Diên Vĩ và Hoa Đam mê cùng nhau… thật là một bữa tiệc màu sắc! Giờ thì, hãy để ta biến mái tóc của ngươi thành một kiệt tác bình minh và hoàng hôn!",
    [2536080395] = "Chất Lượng Sương Mù",
    [2536405738] = "Một nguồn nước gần như vô tận.",
    [2536420209] = "Showcase E",
    [2537207822] = "Bí Ngô Đêm Khô Cốt Vừa II",
    [2537466369] = "Lá thư sau đây đã được gửi đến <npc>Thợ rèn</npc>: \nThân gửi Oswald, anh thật đặc biệt với em theo những cách mà em không thể diễn tả. Cao lớn! Mạnh mẽ! Một <npc>Thợ rèn</npc>! Còn mong gì hơn nữa? Em nhớ anh và nghĩ về anh mỗi ngày. Thì sao chứ nếu chúng ta cách xa nhau hàng đại dương? Trái tim em chỉ thuộc về anh thôi, anh thấy đấy, bất kể khoảng cách. Cuộc đấu tranh để đặt những cảm xúc của em vào giấy khiến em thao thức dưới những đêm đầy sao.\n\nReagan",
    [2537692468] = "Bất Tỉnh",
    [2537905288] = "Những tấm lưới đánh cá cũ trải dài trên vải, vẫn mang theo chiến lợi phẩm của chúng: Sao biển, vỏ sò và chuỗi ngọc trai được trưng bày một cách tự hào như những phụ kiện. Chúng là quà tặng từ người cá và bộ tộc của họ, hay chỉ đơn giản là những phát hiện may mắn? Khó mà nói được.",
    [2538296599] = "Ngươi đã nghe nói về <b><lorename>Tia Lửa Pikemead?</lorename></b> Chúng là những ánh sáng nhảy múa trên biển. \"Điềm lành\", nhưng ta nghĩ đó chỉ là ảo ảnh của ánh sáng. Cho đến khi con gái ta nhìn thấy chúng. <i>Ánh sáng kỳ lạ này trong nước. Di chuyển. Rình rập.</i> Giờ ta cũng thấy ánh sáng tương tự khi ngủ, từ bên trong lâu đài. Nó ám ảnh ta. Đó không phải là ảo ảnh. Nó <i>sống.</i> Ngươi đã sẵn sàng thay đổi điều đó chưa, nhóc?",
    [2538490909] = "Gia Đình Thợ Rèn",
    [2538893377] = "Găng Tay Lông Huyết",
    [2538943955] = "Ngươi còn ngây thơ và trong sáng, hỡi người mang lửa, ngay cả khi đối mặt với bóng tối đang bao trùm. Ngươi muốn cứu vương quốc — hoặc có lẽ, để bảo tồn bất cứ vẻ đẹp nào còn sót lại trong đó: Con bướm đậu trên một ngôi mộ không tên, cuốn sách bọc da sờn rách viết bằng một ngôn ngữ đã bị lãng quên? Những ký ức về quá khứ, đóng băng trong thời gian... Chà, hy vọng của ngươi là bữa tiệc của ta. Từ một người chăn dắt linh hồn đồng nghiệp, hãy nghe điều này: Vực thẳm đang cào cấu những ngôi mộ của chúng ta và nuốt chửng những người ngã xuống, chỉ để lại một khoảng trống. Ngươi không thể dập tắt cơn khát của nó, nhưng ngươi có thể cắt đứt những xúc tu của nó.",
    [2538980098] = "Nơi An Nghỉ Của Người Đào Mộ",
    [2539527065] = "Loại nước bảo vệ từ cây này có nhiều công dụng. Quan trọng nhất là phục vụ cho mục đích của cây!",
    [2539604947] = "Kaori Conway",
    [2540144357] = "Trang bị để sử dụng",
    [2540294650] = " <npc>Nông dân</npc>, Emily Fray, muốn bạn chinh phục Tháp Cổ trong Revelwood.\n\nĐến đỉnh Tháp Cổ để mở khóa <b>điểm Du lịch Nhanh trong khu vực mới và các điểm quan tâm mới</b> trên bản đồ của bạn.",
    [2540463317] = "Chiếc bình vàng này có nhiều dấu ấn được khắc trên đó. Ý nghĩa của chúng vượt xa sự hiểu biết của thời hiện đại, nhưng các học giả có thể cho rằng đây là những bùa hộ mệnh ma thuật.",
    [2541155504] = "Ngươi đã hái đủ hoa chưa?",
    [2541216368] = "Vũ khí Tổ tiên",
    [2541790860] = "Một khung pha lê viền quanh những lưỡi dao ngắn này. Chúng khúc xạ ánh sáng chiếu tới và phản chiếu lại, nhuộm lưỡi dao với màu sắc của suối nguồn núi non trong lành.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tăng theo chỉ số Nhanh nhẹn của ngươi. Ngươi có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [2542139584] = "Quần Kẻ Săn Mỹ Nhân Ngư",
    [2542867674] = "Ta muốn nhảy múa dưới ánh mặt trời rực lửa cho đến khi chân ta phồng rộp! Hoặc ít nhất, nếu không làm được điều đó, ta muốn nhìn vào một bảng màu gợi nhớ về điều đó!",
    [2542911066] = "Tìm thấy trong Hang ổ Sương độc Vùng Đất Xuân",
    [2543226603] = "Hang Động Cyclops Thác Polaris",
    [2543684473] = "Không bộ giáp pháp sư nào hoàn chỉnh nếu thiếu một chiếc mũ rộng vành lớn.",
    [2543687365] = "Một phần mở rộng cho ba lô của ngươi, giúp tăng thêm bốn hàng vật phẩm.",
    [2543746815] = "Mục tiêu của chúng ta đã hiện rõ, nhưng có lẽ sẽ vô ích — <location><lorename>Pikemead</lorename>'s Reach</location> <b>đang bốc cháy trong tầm mắt.</b> Chưa có báo cáo về giao tranh ở khu vực này, nên ta tự hỏi liệu đây là do con người hay một thế lực nào khác.\n\nTa cố gắng giữ hy vọng khi nói chuyện với những người khác, nhưng trong lòng, ta cảm thấy tội lỗi vì đã dẫn dắt họ. Mặc dù có khả năng vẫn còn những người sống sót, nhưng cơ hội của họ rất mong manh. Ta nguyền rủa những kẻ sùng bái ở Thánh địa Ngọn lửa — nếu chúng ta có thể đến sớm hơn...\n\nChúng ta sẽ tiến lên và <b>xem điều gì đang chờ đợi chúng ta ở The Pike.</b>\n\n— Chỉ huy <lorename>Cyrus</lorename>.",
    [2543761104] = "Cung Gai",
    [2544522164] = "Khi còn nhỏ, chúng ta thường giả vờ đọc chúng... Nhưng giờ đây, những tháp đá giấu kín sự thật của chúng... Ta thật ngu ngốc khi nghĩ rằng mình có thể tìm thấy giải pháp cho vấn đề của mình ở đây. Không ai nghe lời cầu nguyện của ta, và ta cảm thấy thật mệt mỏi. Ta ước gì ngươi ở bên cạnh ta, anh trai.\n\nTha thứ cho ta.\n—Vettel",
    [2544622392] = "Phước lành của Ngọn lửa tăng cường các thuộc tính chính của ngươi thêm %k mỗi.",
    [2545483178] = "Những người thợ lặn ngọc trai ở Orville đã cố gắng trốn thoát khỏi cuộc xâm lược của Drak'Dal bằng cách bơi về phía bờ đối diện vịnh. Có đề cập rằng, để giữ bí mật, những người thợ lặn sẽ không thể lên mặt nước để lấy không khí. Họ dự định ẩn náu trong một tập hợp các xác tàu cho đến khi bờ biển an toàn để nổi lên.\n\n<b>Bơi đến các xác tàu gần Orville và tìm Màng lọc Khai thác ở đó!</b>",
    [2545694344] = "Một cỗ máy hủy diệt tàn độc, phun ra Ngọn lửa đỏ rực theo lệnh.",
    [2545889260] = "Giọng NPC",
    [2546010520] = "Triệu hồi Kẻ Sống Sót",
    [2546063200] = "Thợ mộc <npc>Carpenter</npc> đã để lại các khối xây dựng ở <location>Diadwyn</location>. <b>Tìm địa điểm và nhặt các khối</b> để có được vật liệu xây dựng mới!",
    [2546939339] = "Thoát về Máy tính",
    [2547254775] = "Ngay cả trong Sương độc và chiến tranh, vẫn có ánh sáng. Một tia sáng. Một tia hy vọng.\nMột nhóm các Cổ nhân đã nói chuyện với ta... <i>lần đầu tiên, trong một thời đại của những tiếng kêu than, họ đã im lặng.</i> Họ dự định xây dựng \"Hầm Cinder\", những con tàu sẽ dẫn dắt Ngọn lửa Cổ xưa vào một lớp vỏ con người. Thân và tâm, Lửa và thịt... <i>một linh hồn phàm trần sinh ra từ lửa, có khả năng xua tan sương mù.</i>\n\nHy vọng rằng, chúng ta có thể mang đến một kỷ nguyên mới theo cách này.\n— Balthazar",
    [2548056321] = "Hiển thị mật khẩu được bảo vệ",
    [2548432052] = "Trống Chảo Tuyệt Hảo",
    [2548593856] = "Ngươi đã tìm thấy một phần của bộ trang phục ngoại trang Học giả Ngọn lửa Non trong một Thánh địa Đêm Kindlewastes. \n\nCó lẽ các phần khác cũng nằm rải rác ở các Thánh địa Đêm khác trong khu vực. \n\nTìm kiếm các Thánh địa Đêm ở Kindlewastes để lấy tất cả các bộ phận của trang phục Học giả!",
    [2549756454] = "Gửi Otto,",
    [2549852873] = "Cây Gậy phép này được làm từ rễ của một cây cổ thụ. Sự khôn ngoan và bình tĩnh chảy qua nó.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các điểm niệm phép và MP. Trang bị <b>điểm niệm phép</b> để niệm.",
    [2550304099] = "Tìm Khối Đá Thường",
    [2550813707] = "Thợ mộc <npc>Carpenter</npc> cần nơi trú ẩn để chế biến gỗ. Hãy xây một ngôi nhà cho Thợ mộc và cho phép anh ta tiếp cận <b>giường trú ẩn gần đó nếu ngươi chưa làm vậy!</b>\n\nĐể che chở cho những người sống sót của ngươi, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở một khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót trống gần nhất khi được đặt. Nếu ngươi muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu hồi của ngươi và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho ngươi khi những người sống sót của ngươi không còn được che chở nữa.",
    [2551092531] = "Bộ xương khổng lồ \"Orpheus\"",
    [2552083462] = "Trân trọng.",
    [2552545351] = "Trượng Nước Pha Lê",
    [2552637402] = "Đền Thờ Vukah",
    [2553089337] = "Đoạn Dốc Thấp 4m",
    [2553105026] = "Khi ngươi bị tấn công trong cận chiến, ngươi có 10% cơ hội bỏ qua sát thương và mất 30 SP thay vào đó.",
    [2553820484] = "Trang bị như Giáp",
    [2554013076] = "Thùng Thép Nhỏ",
    [2554074070] = "Một bức phù điêu mô tả lịch sử của Drak.\n\nMảnh ghép này cho thấy Drak đến Embervale. Họ nhìn thấy các tòa nhà của Người Cổ xưa ở phía chân trời và bị thu hút khám phá chúng.",
    [2554413044] = "Lò Rèn Ngọc",
    [2554469872] = "Tăng Tối đa và Hồi phục SP",
    [2554492466] = "Mở cửa trong các Sảnh đường Hollow của Cao nguyên Du mục.",
    [2555238485] = "Linh hồn Lạc lối — Trợ lý Mộc",
    [2555382345] = "Tìm Nông dân <npc>Farmer</npc>",
    [2555433477] = "Cây Kỹ năng",
    [2555795438] = "Đến <location>Shorewatch</location>",
    [2555990406] = "Ta có Thông tin Mới!",
    [2556017051] = "<craftingstation>Trạm Giả kim</craftingstation>",
    [2556153476] = "Cắn Axit",
    [2556181294] = "Mồi câu tăng cơ hội bắt được cá sử thi.",
    [2556282559] = "Hồi kỹ năng",
    [2556651533] = "Mũ Giáp Lính Canh Phương Bắc",
    [2556829981] = "Làm tốt lắm! Đây là kế hoạch: chúng ta sẽ móc chúng vào dây câu và thử câu cá. Đom đóm có lẽ không phải là mồi ngon nhất, nhưng ta tin rằng nó sẽ hiệu quả. Ta đã học cách chế tạo một cây cần câu cơ bản từ lâu, và ta có thể chỉ cho ngươi. Hãy quay lại với ta khi ngươi sẵn sàng câu cá.",
    [2556981099] = "Một đống lửa lớn vừa ấm cúng vừa cổ xưa.",
    [2557075216] = "Kẻ lang thang đã đến, đúng như lời hứa — một luồng gió lạnh lẽo theo sau hắn. Khi hắn bước vào phòng ngai vàng của ta, một làn sương mù khó chịu lởn vởn nơi hắn bước qua.\n\nMặt hắn bị che kín để giấu đi một căn bệnh khủng khiếp... loại mà ta chưa từng thấy trước đây. Da hắn nhợt nhạt và có màu xanh lam; khuôn mặt hắn thiếu đối xứng như thể hắn đã bị đột quỵ trong quá khứ - hoặc như thể hắn được lắp ráp, chứ không phải sinh ra. Một sinh vật đáng thương như vậy.\n\nNhững bàn tay gầy gò đưa ra một bình màu xanh sáng, lấp lánh trong ánh nến. Một vũ khí, hắn gọi nó. Một bí mật... bị che giấu khỏi chúng ta bởi <i>Người Cổ xưa.</i>\nHắn không cần nói thêm. Ta đã biết từ lâu rằng những kẻ lừa đảo chỉ tiết lộ những gì chúng muốn.\n\nTa nắm lấy bình và nuốt chửng thứ bí ẩn bên trong. Các hạt bụi bắt đầu xoáy ở rìa tầm nhìn của ta. Sương mù bốc lên xung quanh ta, bao trùm mỗi hơi thở ta hít vào... len lỏi vào trong ta, xâm nhập trái tim ta, hộp sọ ta, và định cư sau mắt ta. Nó đang kéo. Kéo lên trên, về phía mí mắt ta, rung động, cho đến khi chân ta rời khỏi thảm cung điện.\n\n<i>Bay lơ lửng.</i> Ta lơ lửng trên đống đổ nát, trên lũ chuột bọ, lũ hèn nhát, lũ dối trá.\n\nMột khi ta đoàn tụ với mặt đất quen thuộc bên dưới, kẻ lang thang nở một nụ cười. Hắn đã cho ta cả phương tiện và lý do để tấn công.\nTay ta vẫn còn run... nhưng ta phải nắm chặt lưỡi kiếm của mình.\n\n— Lãnh chúa <lorename>Vorgoth</lorename>, Vệ binh Phương Bắc",
    [2557898885] = "Các sản phẩm phụ của việc đốn hạ một cây. Chỉ cần cẩn thận đừng để nó rơi trúng đầu!",
    [2558015281] = "- Đã chọn -",
    [2558527911] = "Tách chồng",
    [2559795523] = "Các Quả cầu HP, MP và SP hồi phục <b>30%</b> thay vì <b>10%</b> tài nguyên tương ứng.\n\nBình máu và Bình MP hồi phục thêm <b>20%</b> tài nguyên.",
    [2559824968] = "Thương nhân Mei-Yin Chen muốn bán cho ngươi một số hàng hóa để ăn mừng năm mới âm lịch, nhưng hầu hết hàng hóa của bà ấy đã bị cướp bởi bọn cướp. Bà ấy biết hướng mà chúng đã mang vũ khí đặc biệt của bà ấy đi.\n\nĐi theo dấu chân của bọn cướp và lấy lại hàng hóa!",
    [2560145196] = "Ngươi phát ra một hào quang bảo vệ làm giảm tất cả sát thương nhận vào <b>10%</b> cho ngươi và tất cả đồng minh trong phạm vi <b>10</b> mét.",
    [2560485664] = "Nơi trú ẩn",
    [2561561857] = "Ta khuyên ngươi nên ưu tiên thanh tẩy lời nguyền của mình.",
    [2561585516] = "Bỏ qua văn bản",
    [2561734557] = "Mũ Đại Pháp Sư",
    [2562889959] = "Khối xây dựng ẩn",
    [2563395784] = "Tỷ lệ tất cả HP của trùm theo giá trị này.",
    [2563713803] = "Quần Lông Xù",
    [2563724244] = "FXAA",
    [2563816238] = "Xoay -90°",
    [2564346778] = "Một chú Chuột Capybara đáng yêu. Nó hoàn toàn không bận tâm khi ở trong vòng tay ngươi. Lông của nó có thể được sử dụng trong chế tạo.",
    [2564436869] = "Drak'Fyr",
    [2564527996] = "Trợ lý Chế tạo",
    [2564858136] = "Tham lam vì màu xanh",
    [2565271558] = "HEUREKA! Ta, Paulette Leclair, đã trở lại là thịt và xương! Vài khoảnh khắc trước, ta chỉ là một đốm bụi nhỏ, trôi dạt vô định và chìm trong bóng tối! Bị bóp nghẹt bởi một luận án sai lầm, lạc lối ở thế giới bên kia... nhưng bằng cách nào đó, phép thuật của ngươi đã kéo ta trở lại! Ngươi không muốn giúp ta với thí nghiệm tự thân tiếp theo của mình, phải không?",
    [2566066893] = "Chỉ một lần thôi, ta muốn ngồi lại và cắn một miếng bánh sandwich ngon lành mà không có tiếng gầm gừ đáng ngại của ngọn núi ở phía sau. Mặt đất rung chuyển đến nỗi ta còn đánh rơi thức ăn.\n<i>Ý tôi là, xin lỗi? Tôi đang cố gắng ăn đây? Ngài có thực sự phải hít hà và thở phì phò mọi lúc không?</i>\n\nTôi đã nghĩ nơi này sẽ đủ xa <i>quái vật có cánh</i>, nhưng bằng cách nào đó nó vẫn tìm cách làm phiền tôi.\nĐiều tồi tệ nhất là tôi đã làm rơi bánh sandwich của mình lên đầu người giám sát. Bây giờ tôi phải chà bồn tắm trong hai tháng tới. Và bánh sandwich của tôi đã biến mất. Đây là điều tồi tệ nhất.",
    [2566701779] = "Bộ Trailblazer",
    [2567329379] = "Nhận được một chiếc dù lượn ma.",
    [2567414947] = "Khử răng cưa",
    [2567518972] = "Di chuyển lùi",
    [2567590914] = "Xoay theo bước 90°",
    [2567617978] = "Tỷ lệ chí mạng",
    [2567811577] = "Cơn Lốc Bạc",
    [2567915958] = "Đặt lại",
    [2567960285] = "Thoát khỏi Mỏ đá",
    [2568172515] = "Một chiếc mũ trùm đầu được làm từ da đầu của một con sói trắng. Những chiếc răng ở phía trước vẫn còn gắn liền.",
    [2568234838] = "Hộp Trang Sức",
    [2568253473] = "Một món đặc sản địa phương với kết cấu kem và hương vị đậm đà. Nó lấp đầy bụng và chữa lành tâm hồn, đặc biệt là khi gió bắc thổi mạnh bên ngoài.",
    [2568815983] = "Trứng",
    [2568927126] = "Dù lượn tiêu thụ ít hơn <b>30%</b> SP.",
    [2569072326] = "Rình rập",
    [2569293093] = "\"Rắn Hoa\"",
    [2569349572] = "Lakehopper là một loài cá nhanh nhẹn mà ngươi có thể thấy \"nhảy\" trên mặt nước của một hồ nước nông — nếu ngươi may mắn.\n\nLoài cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [2569497593] = "Tìm Nơi Ẩn náu của Thủy thủ",
    [2571059272] = "Khung Hình Xây Dựng 3",
    [2571368660] = "Cuộn Giấy Lời Cầu Nguyện Của Ngọn Lửa",
    [2572397617] = "Bức Tường Hẹp",
    [2572584434] = "Lần theo Bước chân của Athalan Skree",
    [2572928877] = "Đạt cấp 40.",
    [2573199074] = "Căn cứ của chúng ta có thể trở nên sống động hơn nữa! Tại sao không thuần hóa một vài con Yak?",
    [2573374170] = "Tia Hồi Máu Vĩnh Cửu",
    [2573411140] = "Tắt tiếng trong nền",
    [2573684762] = "Với sự hiện diện của Drak'Dal, ta không nghĩ việc đặt bất kỳ Lò Nung Tro Tàn nào là đúng đắn. Cư dân của nó có thể không được cứu rỗi, mà bị giam cầm trong một cái kén kim loại. Chúng có thể bị cạy mở quá dễ dàng, trở thành con mồi cho những quái vật này... và lớp vỏ bọc Cổ xưa của chúng sẽ không còn cứu được chúng nữa.\n\nVì vậy, chúng ta sẽ hướng tầm mắt về phía chân trời, như đã định. Ta hy vọng sẽ tìm được một con tàu ở Vịnh Stillwater để thuê... có lẽ khi đó, chúng ta sẽ thấy sự mục rữa đã lan rộng đến đâu, và sẽ lần theo dấu vết của nó trên bản đồ.\n\nTa tự hỏi liệu có đúng không... không quay đầu lại, không cưỡi ngựa về phía những hòn đảo bay nơi các Cổ Thần Lớn ngự trị... không bảo vệ họ bất chấp sự cứng nhắc của họ, không quỳ gối trước anh trai ta trước khi anh ta xông vào cổng của họ. Nhưng với đội quân nào? Với sức mạnh nào?\n\nChúng ta phải sống. Vì tương lai, và vì tất cả những người phụ thuộc vào chúng ta. Vào ta. Vì em, Emily.\nKhi ta trở về, ta sẽ tết những bông hoa huệ vào tóc em, và hát cho em nghe bằng cây đàn lyre của ta cho đến khi giọng ta khản đặc. Một ngày nào đó. Ta hứa.\n\n— Nữ hoàng Jezmina",
    [2573850299] = "ST Phép thuật Lửa",
    [2574355933] = "Thức Ăn Hươu Tiên",
    [2574530647] = "Một chiếc vương miện tinh xảo, bao quanh đầu người đội bằng vầng hào quang vàng và những tia lửa màu thạch anh tím. Nó tượng trưng cho mặt trời mọc, tắm ánh sáng ban mai được mong chờ từ lâu lên sườn núi.",
    [2574676585] = "Bạn đã tìm thấy một món đồ trong bộ giáp trang phục Mùa Đông. Tất cả các món đồ đều nằm rải rác khắp một thị trấn tên là Polaris Falls. Hãy tìm kiếm khu vực để tìm các rương ẩn để tìm các món đồ khác của bộ giáp trang phục!",
    [2574965074] = "Miễn cưỡng, tôi đã tham gia cuộc đoàn tụ gia đình",
    [2575207217] = "Một cỗ máy dùng để rang hạt cà phê. Cần thiết để pha cà phê.",
    [2575433234] = "Bạn đã tìm thấy những Khối Gỗ Nửa Gỗ của tôi, phải không? Giữ chúng phòng khi bạn muốn tạo ra thứ gì đó tuyệt vời với chúng... Một ngôi nhà mới, được xây dựng để tồn tại!",
    [2575564386] = "Điều tra Trang trại Thừa kế",
    [2576059555] = "Rah! Săn bắn xong, nhiều chiến lợi phẩm!\nĂn nhẹ Capybara. Lông quá cứng. Không thích <i>cảm giác trong miệng.</i>\n\nThủ lĩnh Gna'Rash được ăn con nhỏ mềm mại. Lông mềm. Vừa miệng, nuốt gọn trong một lần. Nó kêu ré lên khi bị chạm vào. Thích được vuốt ve. Nhưng không có thời gian để vuốt ve! Thời gian cho bữa tiệc!\n\nTa thách Gna'Rash: Nuốt chửng em bé kêu ré lên nguyên con. Có lẽ nó sẽ khiến Gna'Rash nặng nề và chậm chạp. Rồi Gruul có thể chiến đấu với Gna'Rash! Trở thành thủ lĩnh mới! Tinh anh mới! Sau này, trở thành Hydrak! Tự mình ăn hết tất cả em bé kêu ré lên! Giành lấy cảm giác trong miệng tốt hơn! Rah Rah!",
    [2576222063] = "Đảo ngược Trục X & Y",
    [2576672992] = "Tôi ước gì mình có một chiếc giường thoải mái để ngủ! Bạn có thể vui lòng đóng một chiếc cho tôi không? Bạn có thể sử dụng Gậy phép Triệu Hồi để cho tôi biết tôi có thể ngủ trên chiếc giường nào.",
    [2576815553] = "Đỡ đòn và Phản đòn",
    [2577051531] = "Tiếp cận Lăng mộ Lãng Quên ở Đỉnh Albaneve",
    [2577293706] = "TÔI KHÔNG THỂ TIN ĐƯỢC họ đã tịch thu con la VÀ tiền của tôi — giờ đây, tôi, một thẩm phán đáng kính, phải đi bộ. Một số phận thấp hèn, bẩn thỉu. Tôi nên xé xác từng tên một vì đã trục xuất tôi.\n\nChân tôi đã nhũn ra, nên tôi buộc phải nghỉ ngơi tại nghĩa trang này. Những Kẻ Hollow Tuếch lang thang bên ngoài, nhưng chúng đã không nhận ra tôi. <i>Trừ khi...\n\n...chúng coi tôi là một trong số họ?</i> Ôi, tôi rùng mình. Một cái lạnh không ngừng đang xâm chiếm... Không! Chắc chắn là do mái nhà bị hở! Tôi không phải là họ. Tôi sẽ không quay lại!\n\n— Darius",
    [2577363307] = "Đạn trước",
    [2577415086] = "Năng lượng, trào dâng từ sâu bên trong lõi. Một ánh sáng bùng nổ, phá vỡ ranh giới của chính không gian.\n\nMột cánh cửa để những người chạm vào Ngọn lửa mở ra — tia sáng rực rỡ nhất sẽ đi trên con đường được bao bọc bởi Ngọn lửa, và soi sáng những gì bị che khuất trong bóng tối.\n\nĐừng bao giờ để những vì sao bị dập tắt, đừng bao giờ dập tắt mặt trời. Vươn lên trên tất cả, một di sản tồn tại vĩnh cửu.",
    [2578599323] = "Tìm kiếm Hầm rượu của Nhà giả kim",
    [2578844976] = "Kết thúc câu chuyện",
    [2578922899] = "Truyền thuyết kể rằng vũ khí này từng được một anh hùng bị nghiền nát trong trận chiến sử dụng. Ông tìm một hang động băng giá để nghỉ ngơi và chữa trị vết thương, để lại một vệt máu trên tuyết.\nMột khi ông xuất hiện sau giấc ngủ trăm năm, một đàn dơi băng bay lên bầu trời đêm, báo hiệu sự trở lại của ông.",
    [2579762223] = "Đôi giày thoải mái và giản dị để thư giãn trong thư viện.",
    [2580074436] = "Bạn đã nhận được lời mời. Bạn có muốn tham gia không?",
    [2580796926] = "Sương độc",
    [2581114496] = "Chế tạo hoặc nhận mồi câu cá Bò Tót",
    [2581618763] = "Tường Gỗ I",
    [2581793121] = "Đèn Chùm Thép",
    [2582351539] = "Cây Giống Cây Sồi",
    [2582417948] = "Hàng đợi trống",
    [2582442441] = "Một chiếc rìu đồng sắc bén, có hiệu quả cao trong việc chặt gỗ. Nó cũng có thể được sử dụng để hạ gục kẻ thù.",
    [2582904188] = "Chỉ số Trí tuệ của bạn tăng tối đa HP lên gấp năm lần.",
    [2583237385] = "Ánh trăng",
    [2583508892] = "Một thiết lập cơ bản để chuẩn bị bữa ăn.",
    [2583722552] = "Bạn có muốn bán thanh vật phẩm này không?\nNó không thể phục hồi!",
    [2583975685] = "Cô Đơn Trên Đỉnh",
    [2584635512] = "Tấn công",
    [2585055526] = "\"Khúc Ca Của Sói\"",
    [2585344374] = "ST Sương độc Cơ bản",
    [2585592871] = "Hủy bỏ",
    [2585803061] = "Vũ khí, công cụ và đuốc sẽ bị giảm độ bền theo thời gian. <b>Sửa chữa vũ khí và công cụ của bạn tại bàn chế tạo</b> để bổ sung độ bền và ngăn chúng bị hỏng.",
    [2585902013] = "Hồi sinh Linh hồn",
    [2587115215] = "Găng Tay Thánh Kỵ Sĩ Rực Rỡ",
    [2587203235] = "Mở menu phụ để chọn từ các danh mục người sống sót khác nhau.",
    [2587766984] = "Nhà giả kim",
    [2587951992] = "Tạo ra một rào cản ma thuật bảo vệ khỏi đạn và giảm ST Cận chiến phải chịu.\n\nKhiên sẽ mờ đi khi HP hoặc Thời gian tồn tại của nó cạn kiệt.",
    [2588065815] = "Hoa Gắn Tường Vàng",
    [2589541903] = "Bạn đã tìm thấy tất cả các nhạc cụ quý hiếm? Vậy còn chờ gì nữa? Tôi sẽ chơi đàn lute, bạn phụ trách bộ gõ — Giọng tôi cần nghỉ ngơi, nên có lẽ Athalan có thể hát! ...Không? Chỉ một giai điệu thôi cũng được, quá.",
    [2589564171] = "Tìm kiếm",
    [2589708509] = "Bạn đã tìm thấy quán rượu của Emily! Hãy ghé vào bên trong và nhận bất kỳ khối xây dựng chưa sử dụng nào để mở rộng khả năng xây dựng căn cứ của bạn!",
    [2589764328] = "Đuôi Sọc Nướng",
    [2590091296] = "Nơi an nghỉ của những người thợ xây vĩ đại nhất trong Đêm Kinh Hoàng",
    [2590164460] = "Thằn Lằn Buồm Mỏ Tròn Con",
    [2590193237] = "Các đòn đánh hồi phục một phần sát thương gây ra dưới dạng MP",
    [2590229234] = "Rào Chắn Tre II",
    [2590238972] = "- Bạn có thể sử dụng vai trò để cấp cho người chơi trong phiên của bạn các quyền khác nhau.\n\n- Người chơi tham gia máy chủ của bạn với một trong những mật khẩu này sẽ có vai trò tương ứng.\n\n- Nếu một vai trò được bật, nhưng không có mật khẩu nào được đặt, mọi người có thể tham gia phiên của bạn với các quyền tương ứng với vai trò đó.",
    [2591095252] = "Một mái nhà vững chắc trên đầu sẽ cải thiện đáng kể công việc thủ công của tôi — và bạn sẽ có lòng biết ơn của tôi!",
    [2591096164] = "Bạn đã trở về với những màu sắc mới để nhuộm quần áo! Chúng ta nên chơi \"trò mặc đồ\"!",
    [2591626091] = "Xóa bỏ",
    [2592068079] = "Đó là một năm mới, một khởi đầu mới — và tôi đã suy nghĩ... sẽ thật tuyệt vời nếu chúng ta có thể ăn mừng khi còn có thể? Tôi từng biết một thương nhân hay ghé qua Đồng Cỏ Thấp, tên là Mei. Bà ấy có rất nhiều đồ trang trí cho Tết Nguyên Đán! Tuyến đường của bà ấy luôn như vậy. Tôi tự hỏi chuyện gì đã xảy ra với bà ấy.",
    [2592204319] = "Hollow Ghen tị",
    [2592294138] = "Sức mạnh cổ xưa rung động sâu bên trong thanh kiếm này.",
    [2592478783] = "Rương Rất Nhỏ",
    [2593549611] = "Mảnh vỡ của một bản đồ kho báu bị xé nát, tìm thấy trên bộ xương rồng ở Đỉnh Albaneve. Có lẽ bạn có thể ghép lại bản đồ nếu tìm thấy tất cả các mảnh?\n\nCó chữ viết ở mặt sau:\n\n<b>Hồi ức của Ony:</b>\n<i>Ta bay cao quá, có lẽ ta sẽ không bao giờ hạ cánh\nTa nhảy múa trên mặt trời, cả người bốc cháy\nCốc của ta luôn đầy, ta sẽ uống cho đến khi say\nTrong ánh sáng lỏng và sự mê đắm, cho đến khi ta cảm thấy choáng váng</i>",
    [2593600341] = "Một chậu cây để tô điểm cho ngôi nhà của bạn.",
    [2593849653] = "Một ngày nữa, một tiếng kêu nữa! Tôi không thể hoàn thành các phép tính của mình khi những <b>chim kền kền</b> kinh khủng này cứ bay qua! Tại sao ngọn hải đăng của chúng ta lại nằm quá gần với tuyến đường di cư của chúng? Nếu Lãnh chúa <lorename>Vorgoth</lorename> không ra lệnh đóng cửa mỏ đá, chắc chắn chúng đã làm tổ ở nơi khác... nhưng tôi sẽ khôn ngoan nếu không bao giờ nói ra suy nghĩ đó. Ít nhất là nếu tôi muốn giữ cái lưỡi của mình.\n\nNgay cả với những sự xao lãng có cánh này, công việc của tôi gần như đã hoàn thành. Sớm thôi, chúng ta sẽ có thể thắp những ngọn lửa hiệu của mình và đốt cháy dấu ấn của chúng ta vào bầu trời mùa đông. Tôi gọi chúng là \"Lửa Tai Ương\". Chúng sẽ là một hệ thống cảnh báo hữu ích khi <i>quái vật khổng lồ</i> trở lại, nhưng tôi lo ngại. Những con kền kền bay qua dường như bị nó làm cho tức giận... Tôi thà hoàn thành dự án của mình trước khi chúng quay lại.",
    [2594034150] = "Răng cá mập",
    [2594474861] = "Tăng <b>Khả năng chống Sốc</b> của bạn lên <b>5%</b>, giúp giảm lượng sát thương <b>Sốc</b> nhận vào.",
    [2595116929] = "Tuyến nhỏ chứa nọc độc",
    [2595352870] = "Hang Răng Nghiền",
    [2595474556] = "Bạn sẽ là chủ đề bàn tán của thị trấn!",
    [2596292380] = "Bạn vừa bị trúng một quả cầu tuyết. Đau đấy!",
    [2597148877] = "Sống động và cực kỳ đáng lo ngại nếu bạn cho phép nó xâm chiếm tâm trí bạn.",
    [2597428636] = "Trại mộc",
    [2597677820] = "À, nhìn xem kìa? Bạn đã mang cho tôi một loại pha lê trông có vẻ bị nguyền rủa, đại loại vậy. Nhìn nó khiến tôi cảm thấy ghen tị, thậm chí tham lam. Với thứ này, chúng ta đã tiến gần hơn một bước đến màu tóc xanh mơ ước! Bây giờ, mang cái pha lê đó đi khỏi tôi. Nó làm tôi lo lắng.",
    [2598197564] = "Chúng thậm chí còn không bằng một nửa kích thước chúng từng có — ha! Nhưng chúng cũng đủ dùng. Tôi thậm chí có thể chế tạo cho bạn một chiếc cần câu phù hợp. Sẽ không khó để kéo những con cá lớn với chiếc đó.\nChỉ có điều... nó sẽ tốn kém — har har, chỉ đùa thôi! Bạn sẽ nhận được ưu đãi đặc biệt, bạn của tôi.",
    [2598585581] = "Lối đi đến Đỉnh Albaneve",
    [2598677671] = "Bộ Trâu Bạo Chúa",
    [2599151752] = "Tôi đã giao nhiệm vụ cho bạn đến thăm Sảnh Hollow, vì vậy tôi sợ rằng <i>cộng sự</i> mới của chúng ta phần nào là do tôi gây ra. Bạn biết tôi đi trên con đường ánh sáng. Cá nhân này lẩn khuất trong bóng tối... Tất nhiên là che chở cho tất cả mọi người — nhưng tôi khuyên bạn nên cẩn thận. <i>Sinh vật</i> này bóp méo các sợi dây số phận và xoắn chúng thành một vòng xoáy hỗn loạn. Năng lượng tăm tối như vậy. Tôi tự hỏi làm thế nào họ có được sức mạnh như vậy...",
    [2599520900] = "Phản đòn",
    [2599860223] = "Giới thiệu",
    [2600297108] = "Tương tác với Obelisk Cổ đại để khám phá kiến thức của nó về vùng đất và hồi tưởng về quá khứ.",
    [2601643522] = "Không thể đặt thêm nguồn nước",
    [2601646857] = "Tham lam",
    [2602439025] = "Ikko",
    [2602825826] = "Tìm vật phẩm trang phục trong Rừng Khải Hoàn",
    [2603056752] = "Khi được trang bị vũ khí Cận chiến, bạn có thể thực hiện một đòn tấn công nhảy trong quá trình rơi xuống của cú nhảy.\n\nCrash Down gây thêm 50% sát thương vũ khí trong một phạm vi vụ nổ nhỏ và tiêu tốn SP theo trọng lượng của vũ khí.\n\n<b>Chi phí:</b> 35 - 60 SP\n\n<b>Kẻ phá vỡ phòng thủ</b> \nĐòn tấn công đặc biệt này lấp đầy <i>Thanh choáng</i> của kẻ địch đang phòng thủ gấp đôi khi trúng.\n",
    [2603687054] = "Mồi câu cá thông thường",
    [2604003882] = "Xóa yêu thích",
    [2604100553] = "Chậu Đất Sét II",
    [2604121813] = "Một vụ bắt cá đáng nhớ",
    [2604198754] = "Quần Trinh Sát",
    [2604543217] = "Tôi nghĩ <location>Thornhold</location> là nơi tốt nhất để bạn tìm lưỡi cưa... để làm cho tôi cái <craftingstation>Máy cưa bàn</craftingstation> đó! Đừng lo về việc tôi mất tay như thế nào, hoàn toàn không liên quan!",
    [2605220862] = "Trong những ngày cuối đời, tôi bị hạ gục bởi gánh nặng mà gia tộc đã đặt lên vai tôi. Giờ đây tôi nhận ra rằng mong muốn đoàn kết trong gia đình mình thật ngu ngốc. Trong số 7 người con của tôi, không ai đến bên giường bệnh của tôi — vì vậy tôi tuyên bố rằng không ai sẽ được hưởng thành quả lao động của tôi!\n\nTôi mong muốn vật sở hữu quý giá nhất của mình, một tác phẩm nghệ thuật, sẽ được truyền lại cho các con tôi. Tuy nhiên, tác phẩm sẽ bị xé nát và chia thành 8 phần. Các mảnh sẽ được chia sẻ giữa 7 người con của tôi, do đó làm cho tác phẩm nghệ thuật vô giá trở nên vô dụng.\nCuối cùng, tôi mong muốn được chôn cất cùng với mảnh cuối cùng, <i>trên đỉnh đồi gần cuối phía tây của pháo đài.</i> Hãy để đất mẹ ôm lấy tôi theo cách mà con cái tôi chưa bao giờ làm.",
    [2605472769] = "Tăng sát thương đũa phép.",
    [2605962678] = "Trại buôn phía Nam",
    [2606121853] = "Thú cưng",
    [2606176522] = "Than Củi",
    [2606460217] = "Tìm vật phẩm trang phục",
    [2606619146] = "Chị em gái",
    [2606619451] = "Một thiết bị cho ăn giữ thức ăn cho Armadillo Cát.\n\nNó sẽ cho động vật của bạn ăn khi được đổ đầy thức ăn tương ứng.",
    [2607028801] = "Về <npc>Người sưu tầm</npc>",
    [2608317861] = "Câu Cá",
    [2608846595] = "Cuồng Elixir",
    [2609090474] = "Tìm Rương Trang Bị Thất Lạc",
    [2609254901] = "Cung Sừng Hươu",
    [2609639373] = "Thời Gian Hiệu Ứng Xấu",
    [2609708105] = "Bình Đựng",
    [2610073744] = "Đang chuẩn bị...",
    [2610150672] = "Chùy Gai",
    [2610269721] = "Xin chào bằng hữu!",
    [2610640029] = "Hết Oxy",
    [2611562333] = "Tìm Mảnh Tượng Thứ Ba",
    [2611567715] = "Bạn đã tìm thấy trại đầu tiên của Nữ Hoàng Jezmina tại Thung Lũng Nước Độc. \n\nTìm kiếm trại cuối cùng của bà để lấy những vật phẩm còn sót lại!",
    [2611803759] = "Sản Phẩm Từ Ngũ Cốc",
    [2612244293] = "Vui lòng nhập theo định dạng: [Địa chỉ IPv4]:[Cổng Truy vấn] hoặc [Tên miền]",
    [2612363731] = "Ngươi đòi \"Lưỡi Hái Than Khóc\"? Ta đã rèn nó cho <i>nàng</i> cầm lấy trước khi nàng rời ta! ...Được thôi. Ngươi có thể sử dụng nó thay nàng. Đâm xuyên trái tim của Sương độc, Hỡi Hồn Lửa! Đó là điều mà <i>con gái</i> ta mong muốn.",
    [2612507706] = "Trang Bị Tất Cả Như Đồ Trang Trí",
    [2612532297] = "Bắt đầu",
    [2613387181] = "Trần Nhà",
    [2613462835] = "Một lỗi đồ họa đã được phát hiện vào cuối phiên chơi trước. Bạn có muốn bật tính năng thu thập dữ liệu lỗi đồ họa không? Tính năng này có thể giúp các nhà phát triển Sương độc bao phủ tìm ra vấn đề.\n\nVui lòng lưu ý: tính năng này có thể ảnh hưởng nhẹ đến hiệu suất. Tính năng sẽ tự động tắt khi không còn lỗi nào xảy ra.",
    [2613631566] = "Kẻ Mang Mầm Bệnh",
    [2614196659] = "Công Thức Ghim",
    [2614399032] = "Những viên đá quý dường như rất hiếm - ít nhất là ở độ cao của chúng ta! Đặc tính của chúng không hề phổ biến trên mặt đất. Ta đề xuất thế này: Các Tiền Nhân đã khai quật những viên đá quý này trong cuộc đào bới kiến thức không ngừng nghỉ của họ! Tại sao họ lại từ bỏ theo đuổi? Có lẽ họ đã bị gián đoạn bởi một bí ẩn lớn hơn, một tai họa ập đến: Sương độc?",
    [2614417638] = "Tìm Tất Cả Các Mảnh Khảm",
    [2614536158] = "Không có gì đáng chú ý.",
    [2614966818] = "Cúp Danh Năng Hộp Sọ V",
    [2615189958] = "Thao tác này sẽ loại bỏ tất cả nước mô phỏng hiện có trong khu vực được bảo vệ bởi Ngọn lửa này.",
    [2615286855] = "Chiếc áo choàng ấn tượng này mang vẻ hoàng gia, từng trải và thoang thoảng... mùi biển. Nó khiến bạn cảm thấy như đang chèo lái con tàu vượt bão tố để tìm nơi an toàn!",
    [2615459346] = "<img vanity> Mỹ Phẩm",
    [2615782470] = "Vách Ngăn",
    [2615908112] = "Tăng sát thương gây ra bằng cung.",
    [2616021299] = "Một bộ trang phục rất cơ bản.",
    [2616541531] = "Nguồn Nước",
    [2616689954] = "Quyết Tâm Sáng Ngời",
    [2616820970] = "Trở về từ cõi chết, phải không?",
    [2616952064] = "Rương của Oswald Anders",
    [2617192268] = "Tìm Đội Săn",
    [2617560317] = "Chế Tạo Máy Ép Ectoplasm",
    [2618122018] = "Một chú Bò Yak con, mềm mại và ấm áp.",
    [2618156756] = "Thiết Yếu",
    [2618184180] = "Lò Sưởi Sắt",
    [2618927671] = "Bắt đầu",
    [2619107301] = "Tiền Đồn Cổng \"Bora\"",
    [2619251418] = "Cát",
    [2619309092] = "Một thợ săn đã bị Kền Kền Rồng ăn thịt và giết chết trong tổ của nó, để lại vũ khí mạnh mẽ của mình.",
    [2619420282] = "Máy Ảnh",
    [2619437638] = "Cuối khu vực Truy cập Sớm - hãy quay lại!",
    [2619741275] = "Một chiếc răng sắc nhọn từ một sinh vật biển lớn, có thể là một biến thể megalodon. Nó được bảo quản cực kỳ tốt và, đáng ngạc nhiên, có thể tương đối gần đây. Chủ nhân của nó hẳn phải có khẩu vị khá lớn để cần đến những chiếc răng khổng lồ như vậy...\n\nBộ sưu tập này được tìm thấy ở Cao Nguyên Du Mục.",
    [2619842672] = "Hơi Thở Cuối Cùng Của Rồng",
    [2620158389] = "Ngày Đầu Tiên Của Tôi Với Chương Trình Mở Rộng",
    [2620796696] = "Một thanh Kiếm dài hùng mạnh, được rèn từ hợp kim đồng và thiếc. Người thợ đã dành thời gian cẩn thận khắc những đường nét hài hòa chảy dọc từ phần lưỡi dao về phía trung tâm của lưỡi kiếm.",
    [2621566591] = "Thuốc Mỡ Trị Thương",
    [2621765759] = "Cây Giống Thường Xanh",
    [2621951776] = "Một linh hồn rực lửa trong thân xác phàm trần, được nuôi dưỡng giữa tro tàn của một thế giới đang lụi tàn.",
    [2623105040] = "Ta luôn tự hào về trực giác của mình. Có thể phát hiện những kẻ ngứa ngáy muốn nổi loạn trước khi chúng đặt chân lên thuyền của ta, cảm nhận cơn bão sắp đến từ tiếng kêu của hải âu cách xa hàng dặm.\n\nNhưng lần này, chỉ một lần thôi, liệu ta có thể sai?\nKhi ta nghe tiếng gió tây huýt sáo một giai điệu mới, liệu ta có nhầm lẫn sự sắc bén của nó là hiểm độc?\nKhi ta kéo lên một trăm con cá với vây bị rách, liệu ta có đọc sai vết thương của chúng là một mối đe dọa?\nKhi ta nghĩ rằng ta thấy những kẻ ác từ những câu chuyện thời thơ ấu nhảy ra khỏi trang sách xuống nước, liệu mắt ta có đang phản bội ta?\n\nTa có đang bịa chuyện từ sợi chỉ của chính sự tỉnh táo của mình không? Ta nên cảnh báo những người khác, kẻo ta hoàn toàn tan rã.\nLiệu họ có tin lời của một người kể chuyện, ta không thể nói. Một số có thể cho rằng một ngư dân nên gắn bó với việc câu cá...",
    [2623218636] = "Với đôi găng tay này, mọi phép thuật của thế giới đều có thể dễ dàng chảy vào đầu ngón tay bạn để dẫn dắt cánh tay kiếm của bạn một cách chính xác.",
    [2623235510] = "Lục Lọi",
    [2624468320] = "Bạn đã xuống rồi! Bạn đã khám phá những gì thú vị? Tôi rất muốn nghe!",
    [2624887725] = "Chậu Cây Trống II",
    [2624896441] = "Một dân làng hữu ích sẽ sống và làm việc tại căn cứ của bạn.",
    [2625627558] = "Tiền đồn Scavenger Tự chế",
    [2626311972] = "%k đã chết.",
    [2626365594] = "Ánh Trăng Qua Giếng",
    [2626485246] = "Tiện Nghi ",
    [2627199057] = "Về <lorename>Ikora</lorename>",
    [2627765829] = "Thời Gian Suối Nóng!",
    [2627916996] = "Ta đã định hướng dẫn ngươi đi tìm những người giống ta, nhưng ngươi đã làm rồi! Ngươi đi trước ta xa lắm, phải không? Ta sẽ không cô đơn với những dân làng này xung quanh, nên cảm ơn ngươi! Tuy nhiên, hãy đảm bảo hoàn thành yêu cầu của những người theo dõi mới của ngươi. Họ sẽ dẫn ngươi đến nhiều người sống sót hơn! Hoặc tốt hơn nữa, những bùa may mắn và kho báu.",
    [2627926112] = "Khu Vực Tìm Kiếm Tháp Giả Kim",
    [2628100334] = "Những viên đạn ma thuật giải phóng một tia sét mạnh mẽ làm sốc kẻ địch và nhảy sang những kẻ khác ở gần, gây thêm <b>sát thương SP.</b>\n\nSát thương SP lấp đầy <b>thanh choáng</b> của kẻ địch.\n\n<b>Phép thuật: Hết hạn</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [2628115678] = "Tăng ST Lôi",
    [2628297977] = "Tức thời khôi phục 2 phút thời gian còn lại của bạn trong Sương độc.",
    [2628845048] = "Phao câu không chạm nước.",
    [2629775706] = "Năng lượng Sương độc đậm đặc, được gói gọn trong một lõi rung động.",
    [2630821839] = "<location>Quần Đảo Jasper</location>",
    [2630930308] = "Nghiền Đá Thành Bụi",
    [2631236522] = "Bơi Lên",
    [2631346607] = "Lọc Đánh Dấu Bản Đồ",
    [2631493522] = "Bắt Một Con Cá Sử Thi",
    [2631588210] = "Khám Phá Hang Động Người Khổng Lồ Gần Đó",
    [2632343248] = "Bạn đã thu thập quả mọng sương mù xanh! \n\nQuay lại gặp Thợ Cắt Tóc với những quả mọng trong hành trang để nhắc ông ta cách tạo thuốc nhuộm tóc màu xanh!",
    [2632388976] = "Tầm Xa",
    [2632429677] = "Tìm Kiếm Sứ Giả Hoàng Gia",
    [2633329399] = "Cà Ri Củ Khoai Môn",
    [2633608633] = "Cơ Hội Xuất Hiện Quả Cầu HP Khi Được Tăng Cường",
    [2634229597] = "Ta bị nỗi lo lắng bao trùm. Huy động một đội quân là một chuyện, nhưng <i>di chuyển cả thị trấn qua Embervale</i> lại là chuyện khác. Tuy nhiên, <b>ta là Nữ Hoàng của Vùng Đất Tro Tàn</b> và vương quốc của ta phụ thuộc vào sự lãnh đạo kiên định của ta. Chúng ta phải di chuyển đến những vùng đất khác. Tìm kiếm đồng cỏ màu mỡ. Tìm sự an toàn. Ngày mai, ta sẽ ra lệnh sơ tán và thành lập một đoàn lữ hành đến <location>Longkeep</location>... Ta sợ giọng nói của mình sẽ phản bội ta, run rẩy và run rẩy. Ta sẽ vượt qua, vì mẹ. \n\nChúng ta sẽ đi vào một vùng đất của dương xỉ và rêu. Cây xanh tươi tốt, đường chân trời màu ngọc lục bảo... và thế nhưng, ta chỉ thấy bóng tối. Liệu anh trai ta, <lorename>Vorgoth</lorename>, có cùng ý tưởng không? Ta không thể đối mặt với hắn sau những gì hắn đã làm với <lorename>Gormander</lorename>. Những cơn ác mộng của ta vẫn còn nhuốm màu đỏ thẫm. <i>Ta nghe thấy giọng nói của hắn, và nó thật khó nghe. Đã thay đổi. </i>\n\nTa cần nghỉ ngơi. Một ngày lớn đang chờ đợi.\n— <lorename>Jezmina</lorename>",
    [2634553926] = "Tượng Nữ Hoàng <lorename>Pikemead</lorename>",
    [2636025544] = "Rương Thất Lạc & Tìm Thấy",
    [2636794343] = "Ikko #4",
    [2637454530] = "Cây Lô Hội",
    [2638406243] = "Ánh sáng của nó thường là thứ cuối cùng mà sinh vật Fell nhìn thấy trước khi bị tiêu diệt.",
    [2638624462] = "Một sợi chỉ tốt có thể vá mọi thứ — hoặc tốt hơn nữa, giảm thiểu mọi đòn đánh. Chúng ta sẽ cần một <craftingstation>Khung Cửi</craftingstation> cuối cùng nếu muốn có <b>áo giáp mạnh hơn.</b>",
    [2638745674] = "Một người sống sót khác đã thức tỉnh! <npc>Nhà Giả Kim</npc> sẽ hữu ích bằng cách chế tạo thuốc và thuốc chữa bệnh.",
    [2638990245] = "Bảng Màu Vẽ Mặt",
    [2639996375] = "Ném dây câu ra và đợi cá cắn. Khi cá đã vào móc, nhanh chóng nhấn <b>%k</b> để bắt đầu kéo nó về.\n\n<img fishingtutorial_fishstamina>\nGiảm SP của cá bằng cách lái ngược hướng di chuyển của nó với <b>%k</b> và <b>%k</b>. \n\nKhi một phần SP của nó bị cạn kiệt, bạn có thể kéo cá lại gần hơn với <b>%k</b>.\n\nLàm cạn kiệt SP của nó trước khi dây câu của bạn bị đứt!",
    [2639998482] = "Sát Thương Vũ Khí Đập Thêm",
    [2640532110] = "Sợi tự nhiên thu được từ quá trình xử lý cây Lanh. Bước đầu tiên của việc tạo vải.",
    [2640958631] = "Sét Dây Chuyền Vĩnh Cửu",
    [2641348633] = "Một đòn tấn công quyết định, máu tươi đổ ra, và sự im lặng theo sau - đó là những ấn tượng về một cuộc lao nhanh thoáng qua.\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n",
    [2641638328] = "Thời Gian Trong Sương độc",
    [2641917526] = "Cửa Rào Sân Vườn Gỗ Phương Bắc",
    [2642165217] = "Để thuần hóa một con vật, hãy giành được sự tin tưởng của nó bằng cách <b>cho ăn và vuốt ve</b> nó. \nHãy đảm bảo bạn có <b>thức ăn mà con vật thích</b>, tiếp cận con vật trong khi <b>lén lút</b>, và ném mồi trong tầm nhìn của chúng. Khi nó đang ăn, bạn có thể lén lại gần hơn. Đừng di chuyển quá nhanh, nếu không bạn sẽ làm nó sợ hãi! \nKhi bạn đã đủ gần, bạn có thể <b>vuốt ve</b> nó. \n\nCho ăn và vuốt ve con vật <b>vài lần</b> để giành được sự tin tưởng của nó. Sau đó bạn có thể <b>bế nó lên</b> và mang nó về nhà. \nCung cấp một nơi ngủ ấm áp và thức ăn để giữ cho nó hạnh phúc và được bảo vệ khỏi kẻ săn mồi. \n\nGia súc của bạn có thể sinh sản nếu bạn có ít nhất hai con vật hạnh phúc và một chiếc giường trống dự phòng.",
    [2642276975] = "Lỗi của Ngọn Lửa!",
    [2642464801] = "Kẻ Thù Không Đội Trời Chung",
    [2642513421] = "Chúng ta còn thiếu nhiều thứ. Nếu không có nguồn cung cấp <b>muối</b> ổn định, việc bảo quản <b>da thú</b> sẽ rất khó khăn. Ta có thể không phải người nơi này, nhưng ta hiểu rõ vùng đất này. Đây. Ta sẽ đánh dấu một địa điểm thu thập muối trong nhật ký của ngươi. Đừng làm ta thất vọng.",
    [2642678480] = "Sofa Thanh Lịch Lớn",
    [2643459295] = "Một bữa ăn tương đối đơn giản nhưng đầy bổ dưỡng. Nhanh chóng và sẵn sàng để dùng!",
    [2643528271] = "Tấn Công Lén Lút",
    [2644801440] = "Xin chào, người đẹp! Có chuyện gì vậy? ...Ngươi đã học cách pha trộn sắc tố đỏ rồi sao? Tuyệt vời! Thấy chưa, đó là lý do tại sao mọi người đều tin tưởng ngươi! Ngươi thật đáng tin cậy, dũng cảm và đẹp trai! Và ngươi sẽ trông thật tuyệt với mái tóc đỏ... Muốn thử kiểu đó không?",
    [2644808673] = "Điểm Dừng: chưa đặt",
    [2645001992] = "Bụi Sáng",
    [2645401309] = "<b>Hồi Ức của Polaris:</b>\n<i>Ta là một vì sao sáng, trôi dạt cao trên bầu trời\nĐể tìm đường đi, ngươi chỉ cần nhìn về ta\nNhìn xuống thế gian, khó mà phủ nhận\nKhông có ai bên cạnh khiến tâm hồn ta cô đơn</i>",
    [2645403888] = "<craftingstation>Trạm Thuộc Da</craftingstation> Đã Tìm Thấy",
    [2645416034] = "Vương Miện Sấm Sét",
    [2645866332] = "Chiếc Dù Lượn này sẽ cho phép ngươi di chuyển những quãng đường cực kỳ xa.",
    [2646196771] = "Tạp Nhạp",
    [2646559770] = "Khối Đường Đá Vôi Vỏ Sò",
    [2646794361] = "Trưng Bày Tượng Đài <lorename>Pikemead</lorename>",
    [2647761241] = "Xây tường và mái nhà để cung cấp nơi trú ẩn cho một người sống sót.",
    [2647850149] = "Điều chỉnh độ phân giải kết xuất nội bộ của cảnh 3D. Giảm giá trị này sẽ cải thiện hiệu suất.",
    [2648305163] = "<b>Lũ khốn đã đóng cổng thành phố bên trong.</b> Chỉ bỏ mặc chúng ta nghèo khổ chết đói!! Sẽ chẳng ích gì đâu. Quân đội của <lorename>Vorgoth</lorename> sẽ tóm được chúng. Ta hy vọng chúng sẽ bị thiêu rụi. Hãy để <lorename>Gormander</lorename> nếm mùi đồng và thép!\n\nTa không dễ dàng bỏ cuộc. Ta đang ẩn mình, nhưng ta vẫn còn căn bệnh chết tiệt đó từ mùa đông năm ngoái. Nếu cơ thể ta gục ngã bây giờ, nếu ta hắt hơi, nếu ta ho - với đám người phương bắc lảng vảng bên ngoài - những cống ngầm này sẽ là nấm mồ của ta.\n\nTa đang run rẩy. Không phải do cơn sốt lạnh của ta. Có điều gì đó không ổn. Có... có gió ở đây. Không. <i>Có tiếng thở</i>. Ở đây, và sắc như dao. Không thể nhìn thấy từ đâu, hay cái gì\nNó ở trong ta\nTrong cổ họng ta, lạnh lẽo\nNó là axit. Nó tệ hơn. Tệ hơn cả cống rãnh. Cứu ta\n\nCảm giác như mùa đông lại đến",
    [2648630662] = "Dòng chữ khắc trên thanh kiếm này không thể giải mã, vì kiến thức cổ xưa về việc ghép rune đã bị thời gian lãng quên. Dù nội dung có là gì, nó cũng khiến lưỡi kiếm tràn đầy năng lượng.",
    [2648917913] = "Nói Chuyện Với Hugo Vanderhall",
    [2649110071] = "Một tấm biển treo tường mà ngươi có thể viết lên.",
    [2649170865] = "Bàn Đá",
    [2649328489] = "Ôi trời, ôi trời... ta phải làm gì đây khi không có con dao găm yêu quý của mình..? Ôi, giá như có một anh hùng dũng cảm cứu giúp ta...!",
    [2650112184] = "Máy Chủ: %k",
    [2650616495] = "Xô Phế Liệu",
    [2650965371] = "Thỏi Sắt",
    [2651291482] = "Thuốc Tiên. Đó là một phương thuốc, một phước lành, một vũ khí.",
    [2651449024] = "Các Lớp Nhân Vật",
    [2651474719] = "Khi tiêu diệt kẻ địch bằng vũ khí cận chiến, tất cả người chơi trong phạm vi 15 mét tính từ mục tiêu sẽ nhận được 20 HP.",
    [2651791780] = "Từ Điều Tra Viên Lachlan",
    [2652540776] = "Rìu Cánh Dơi",
    [2653235753] = "Dân làng và trợ lý chế tạo có thể được tìm thấy khắp Embervale. Nhiệm vụ và các câu chuyện phụ sẽ dẫn ngươi đến họ.\n\nHọ có thể tiết lộ thêm thông tin về thế giới và hướng dẫn ngươi đến những địa điểm, vật phẩm mới và kho báu ẩn giấu!\nMột khi ngươi đã tìm thấy một dân làng hoặc trợ lý chế tạo, ngươi có thể đặt họ bằng một cây Gậy phép Triệu Hồi. Những người theo ngươi mới phải có đủ thức ăn và một chiếc giường có mái che để trở nên hạnh phúc. Những người theo ngươi hạnh phúc là cần thiết để tăng Cấp Ngọn Lửa của ngươi cho mọi nâng cấp sau lần đầu tiên.\n\nMột chiếc giường được coi là có mái che khi nó nằm dưới mái nhà và được bao quanh bởi đủ tường. Chỉ định giường cho dân làng bằng cách sử dụng Gậy phép Triệu Hồi.",
    [2653371620] = "Mũi Tên Chướng Khí II",
    [2654017371] = "Một cây rìu có đầu bằng đồng. Bền hơn phiên bản Đồng.",
    [2654266728] = "Kênh Băng",
    [2654495597] = "Tăng cơ hội đầu độc kẻ địch lên <b>25%</b> khi sử dụng Dao găm với đặc điểm <b>Lưỡi Dao Độc Dược</b>.",
    [2655391413] = "Lưỡi rìu này có các cạnh sắc bén vuốt lên đỉnh. Chúng được chế tạo như vậy để phá vỡ bề mặt hồ băng hoặc tường và giống như cánh dơi.",
    [2655940489] = "ST Tầm xa Khi Sương độc bao phủ",
    [2656213723] = "Nhổ cỏ Kindlewastes",
    [2656293557] = "Cuộc sống không phải lúc nào cũng trắng đen. Đôi khi, sức mạnh đòi hỏi sự hy sinh.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Đỉnh Albaneve.",
    [2656904700] = "Khai thác mọi vật liệu quý giá ở Cao Nguyên Du Mục.",
    [2657104544] = "Nhà giả kim đã nói với ngươi về một phù thủy điên loạn bị ám ảnh bởi việc tạo ra một phép thuật trường sinh bất tử. Hắn được cho là đã tiến hành các thí nghiệm của mình sâu bên dưới lòng đất, nơi không ai có thể nhìn thấy những gì hắn thực sự đang làm. Không chắc liệu hắn có đạt được phép thuật mà hắn tìm kiếm hay không - nhưng hắn đã tạo ra một thứ gì đó. Hãy đến ngôi mộ ẩn nơi hắn được cho là đã làm việc, và tìm kiếm bất kỳ dấu vết nào của hắn.",
    [2657368196] = "Vùng Nước Chưa Biết",
    [2657486503] = "Sát Thương Chống Lại Hollow",
    [2657794443] = "Đặt mật khẩu cho phiên của bạn",
    [2657802668] = "Nông dân <npc>Emily Fray</npc> chế biến thức ăn và giúp ngươi trồng cây.",
    [2657985061] = "Tia Lửa Suối Nguồn",
    [2658018902] = "Tăng tốc độ di chuyển của ngươi khi đang <b>lén lút</b>.",
    [2658314902] = "Mắt Cá",
    [2658400053] = "Không Đáng Sợ Như Mọi Người Nghĩ",
    [2658952497] = "Ta ghét làm việc ở Thang Máy Hàng Hóa. Hóa ra, ta còn ghét làm nông hơn nữa.\n\nTa vẫn nhớ khi chúng ta bị đóng cửa vì nước nhiễm Sương độc lan đến các kênh dẫn nước phía trên. Kéo bao cát và xây dựng các rào chắn tạm thời để \"đảm bảo độ tinh khiết của nước\" ở hạ lưu, tất cả trong khi chịu đựng mùi hôi thối rữa này.\n\nRồi, bụp: Không thang máy, không việc làm, và ta bị kẹt với cổ họng khô rát. Cuộc sống mới của ta ở nông trại cô đơn như địa ngục. Tiếng ho và lũ chim xung quanh là bầu bạn duy nhất của ta... cho đến ngày hôm qua.\n\nTrong lúc cày bừa, ta thấy <i>thứ gì đó</i> lướt qua trong rừng. Thứ đó cong queo đến nỗi ta tưởng đó là một loại quái vật. Rồi, bùm! Sấm sét! Tiếng kêu của một loài chim lạ! Ta bị phân tâm bởi sự náo động phía trên, và khi ta nhìn lại <i>thứ đó</i>, nó đã di chuyển đến gần hơn.\n\nKhông còn ẩn nấp sau hàng cây, nó lộ ra là một mụ phù thủy còng lưng, kêu lên: \"Ho của con tệ lắm, con trai ạ - nhưng con thật may mắn! Ta là một thầy thuốc thảo dược. Hãy đến nhà ta, và để các loại thuốc chữa bệnh của ta làm dịu cơn ho của con.\"\nNhư để minh chứng, một đàn chim gần ta bay lên và sà qua. Ta phải che mặt và mọi thứ, chúng gần đến vậy! Vài khoảnh khắc sau, lũ chim và mụ phù thủy đã biến mất.\n\nTa sẽ đi gặp bà ấy vào ngày mai. Ta chẳng còn gì để mất.\n—J",
    [2659268157] = "Chiếc Lá Vàng",
    [2659575378] = "Bình Triệu Hồi Đầu Lâu",
    [2659661871] = "Giáp Tay",
    [2659871377] = "Cốc Bạc",
    [2660197116] = "Kho đầy",
    [2660233764] = "Xương Cá",
    [2660583380] = "Nghĩa Địa",
    [2661650397] = "Một nhà máy cho phép sản xuất bảng màu và tô màu quần áo của ngươi.",
    [2661817980] = "Bị Lạc và Lãng Quên giữa Sương độc, cây cung này giải phóng cơn thịnh nộ lên bất kỳ ai cản đường nó.",
    [2662221423] = "Một rào cản nước ma thuật để giữ nước không chảy vào.",
    [2662327749] = "Tiền Đồn Nhỏ Drak'Dal",
    [2663006120] = "Sát Thương",
    [2663198200] = "<craftingstation>Cây Suốt Sợi</craftingstation> Bị Mất",
    [2663358111] = "Đặt <craftingstation>Cây Suốt Sợi</craftingstation>",
    [2663599489] = "Ngươi đã tìm thấy một viên ngọc của bệnh người sói!\n\nHãy đến gặp Trợ Lý Nhà Sưu Tập, Kẻ Vô Danh, với viên ngọc trong hành trang và nói chuyện với hắn để tiếp tục!",
    [2663648089] = "Về Sự Sai Lầm Trong Tất Cả Chúng Ta",
    [2663891238] = "Chế Tạo Và Sử Dụng Thuốc Giải Độc Hemotoxin",
    [2664171286] = "Không có nhà máy nào có sẵn.",
    [2664510061] = "Một cây rìu rộng và uy nghiêm. Nếu ngươi muốn để lại ấn tượng đáng sợ, vũ khí này sẽ làm được điều đó.",
    [2664881954] = "Mồi Câu Cá",
    [2664918478] = "Xem Trước",
    [2665009425] = "Kẻ Xua Đuổi Bóng Đêm",
    [2665377990] = "Nanh Heo Rừng Hắc Hóa",
    [2665461345] = "Shroud, một Sương độc hủy diệt chỉ muốn lan rộng và nuốt chửng.",
    [2665786912] = "Da Bò Sát Nước Thuộc",
    [2665962635] = "Dao Găm",
    [2666337366] = "Ta Đã Làm Hỏng Hoàn Toàn",
    [2666520324] = "Móng vuốt sắc bén và lưỡi dao sắc bén không chịu im lặng - đó vừa là kiếm vừa là khiên của Hoa Hồng Máu.",
    [2666803664] = "Hộp Trang Trí Màu Vàng",
    [2666812600] = "Trái Tim Kẻ Thổi Tung Sương độc",
    [2666882692] = "Ta biết một ngư dân tuyệt vời... chính là ta!",
    [2666954678] = "Kẻ Sưu Tầm <npc>Và Ngọn Lửa Sinh Ra</npc>",
    [2667025261] = "Đọc Obelisk Revelwood",
    [2667052593] = "Ba Lô Rất Nhỏ",
    [2667566249] = "Hầm Tro",
    [2667725640] = "Cửa Sổ Tre I",
    [2668557382] = "Tìm Kiếm Đèn Lồng Trong <location>Morwenna</location>",
    [2669139744] = "Phần Thân Trên",
    [2669485273] = "Khoảng thời gian trì hoãn sau đó quá trình tái tạo sẽ hoạt động.",
    [2669638334] = "Vị Trí Thương Gia",
    [2669737483] = "Đất Trồng Hoa",
    [2670598258] = "Ta tin ở ngươi, Flameborn. Có lẽ ta là người duy nhất - nhưng ta coi ngươi như gia đình, máu mủ. Và ta chỉ nói điều đó với một người khác... Hãy nhìn về phía đất cao bất cứ khi nào ngươi gặp nguy hiểm. Ta sẽ luôn dõi theo ngươi.",
    [2670670863] = "Nồi Phế Liệu IV",
    [2670796374] = "Nữ hoàng Jezmina đã để lại một ghi chú gần một cấu trúc Cổ đại lớn giáp với Blackmire. Có vẻ như bà ấy đã mạo hiểm vào Lưu vực Veilwater sau khi tích trữ đủ vật tư.\n\nTìm các trại Veilwater Basin khác nhau của bà ấy để thu hồi vật tư còn sót lại và tiếp tục câu chuyện của bà ấy.",
    [2670880890] = "Lạc Vào Bóng Tối",
    [2670971008] = "Cái Chết",
    [2671182170] = "Kiếm Của Bậc Thầy Cổ Ngữ",
    [2671311911] = "Orville dường như bị lũ Drak'Dal xâm chiếm. Nếu từng có người ở đây, thì họ và công cụ của họ đã biến mất từ lâu.\n\n<b>Điều tra khu vực để tìm manh mối.</b>",
    [2671591343] = "Nhật ký của Emily Fray, Mục 1",
    [2672486727] = "New Cromville",
    [2672622793] = "Ta chưa bao giờ thấy Embervale như thế này. Ngươi là ai mà mở mắt ta ra, cho ta thấy vẻ đẹp này? Một Hỏa Sinh? Xin chào, ta là Mei-Yin, một thương nhân. Thế giới đã thay đổi, nhưng chúng ta vẫn còn đây. Chỉ riêng điều đó thôi cũng đủ để ăn mừng rồi. Ngươi đã nghe nói về Tết Nguyên Đán chưa?",
    [2672958936] = "Tiếp cận Đền Drak",
    [2673218472] = "Chùy Chúc Phúc",
    [2673733657] = "Sát thương lên",
    [2673880322] = "Bật",
    [2674253067] = "Tìm thấy Cung",
    [2674282090] = "Cảm ơn hoa lần nữa — để ta đền đáp bằng một lần nhuộm tóc miễn phí!",
    [2674376472] = "Là một Hỏa Sinh, linh hồn bất tử của ngươi cho phép ngươi <b>hồi sinh tại Điểm Trở Về hoặc căn cứ cuối cùng</b> sau khi chết. Tuy nhiên, điều này phải trả giá.\n\nKhi chết, ngươi sẽ <b>mất các vật phẩm không đặt trong thanh trang bị nóng</b> và để lại một <b>bia mộ.</b> Hãy đến bia mộ của ngươi để lấy lại các vật phẩm đã mất. Vị trí <b>bia mộ sẽ được đánh dấu trên bản đồ.</b>",
    [2674461288] = "Bánh Quả Mọng Tím",
    [2676040915] = "Ta nhớ cây dao găm yêu thích của mình biết bao... Ta có những cây khác, vâng, nhưng trái tim ta vẫn đau đớn...",
    [2676282547] = "Hoàn tiền",
    [2676347671] = "Cây Giống Lúa Mì",
    [2677002386] = "Cung Của Kẻ Phản Bội",
    [2677516812] = "Máy Pha Cà Phê",
    [2677521199] = "Thịt Sói Sống",
    [2677786273] = "Tăng sát thương sét.",
    [2677875593] = "Hướng Nhân Vật",
    [2678472559] = "Tiếp theo Yêu Cầu Tên Tuyển Dụng",
    [2678637287] = "Cánh tay phải của một Cyclops. Nó cao hơn cả người ngươi khi dựng đứng!\n\nBộ sưu tập này được tìm thấy ở Cao Nguyên Albaneve. Nó có thể được lắp ráp lại để tạo thành một Bộ Xương Cyclops trên Đế Tượng Cyclops.",
    [2678642616] = "Rương Phép Thuật Lớn",
    [2678661681] = "Chiếc Búa Xây Dựng Và Nơi Trú Ẩn",
    [2679035496] = "Vậy là ngươi đã cười khúc khích vẽ bậy lên mặt ta khi ta bất tỉnh. Buồn cười thật. Ngươi biết gì là <i>không buồn cười?</i> \n\n<b>Ta không thể rửa sạch lớp sơn đó đi!</b> Ta đã cố gắng hàng giờ để chà sạch những nét vẽ trẻ con của ngươi khỏi ta, nhưng vô ích!\nNói tóm lại, trò đùa tuyệt vời. <i>Tuyệt vời.</i>\n\nMuốn biết câu đùa cuối cùng là gì không?\nNếu ta tóm được tên hề đã làm điều này, ta sẽ lột mặt hắn ra để dùng làm của riêng.\n\nTa sẽ là người cười cuối cùng, ta sẽ đảm bảo điều đó!",
    [2679233870] = "Dừng lại & Hoàn tiền",
    [2679499201] = "Khung Cửa Sổ Đá",
    [2679880130] = "Nến",
    [2680061687] = "Tất Tay",
    [2680507142] = "Bàn Tiệc Gỗ",
    [2680905265] = "Vậy là, cá nhỏ, ngươi đã có đủ mọi thứ cần thiết. Đã đến lúc ra ngoài. Ta biết một chỗ tốt — thử vận may ở đó đi! Đừng quên quay lại và cho ta xem ngươi đã kiếm được gì.",
    [2681083661] = "Nâng Cấp Trang Bị",
    [2681111805] = "Cho biết bạn sử dụng vũ khí cận chiến tốt như thế nào.",
    [2681121346] = "Một chiếc quần bình thường. Trong hoàn cảnh khác, chúng sẽ cho phép người mặc dễ dàng hòa mình vào đám đông.",
    [2681946903] = "Độ Hiếm Không Xác Định",
    [2682084192] = "Ngươi đã phát hiện ra rằng một con mèo nghịch ngợm gần đây đã đánh cắp bữa ăn của ai đó và trốn thoát đến một thị trấn tên là <location>Sapphire Strand</location>. Hãy đến thành phố để tìm con mèo!",
    [2682536644] = "Hãy xinh đẹp, cả bên trong lẫn bên ngoài.",
    [2682654396] = "Thanh tra đáng kính Lachlan,\n\nTôi viết thư này cho ngài cá nhân với tin xấu. Đã có những vụ mất tích liên tục ở Revelwood, và giờ đây một tỉnh gọi là <location>Glennwood's End</location> đã ngừng mọi liên lạc với chính phủ của chúng ta. <location>Glennwood's End</location> đã thể hiện lòng trung thành với ta, vị Vua của họ, và được coi là một phần quan trọng của vương quốc ta. Với nhiều năm phục vụ tận tâm lừng lẫy của ngài, ta ra lệnh cho ngài tìm kiếm câu trả lời và báo cáo lại một cách nhanh chóng.\n\nKý tên,\nVua <lorename>Gormander</lorename>",
    [2682818431] = "Cánh Lượn",
    [2684026444] = "Nếu không có mật khẩu, mọi người đều có thể tham gia, cải tạo địa hình, sửa đổi căn cứ và truy cập các vật phẩm được lưu trữ.",
    [2684568463] = "Trang Trại Lúa Mì",
    [2684886817] = "Quần Đêm Khô Cốt",
    [2685376219] = "Oxygen của ngươi đã cạn. Hãy nhớ đừng ở quá lâu dưới vực sâu và nổi lên mặt nước thường xuyên.",
    [2686745859] = "Cửa Chào Năm Mới Âm Lịch",
    [2686836307] = "Đối với một tên trộm, ánh sáng duy nhất nhìn thấy từ trong bóng tối là ánh sáng phản chiếu trên đồng tiền vàng lấp lánh.\n\nBảng màu này có thể được tạo bằng vật liệu từ Kindlewastes.",
    [2688022777] = "Xác định lượng HP mà đồng minh được hồi sinh với.",
    [2688051825] = "Hoa Ly Hai Màu",
    [2688369223] = "Quay lại Menu Chính",
    [2688710721] = "Nhân Vật Mới",
    [2689376095] = "Một điều gì đó độc ác đã chiếm lấy <location>Glennwood's End</location>, một thị trấn lớn ở vùng xa xôi của Revelwood. <b>Tìm thành phố</b> và khám phá nó!",
    [2689802888] = "Chế Tạo & Sửa Chữa",
    [2689878280] = "Bình Đền Drak II",
    [2689937886] = "Hành Động Có Sẵn",
    [2690105890] = "Nghĩa Địa Bramblespine",
    [2690723132] = "Khung Cửi <craftingstation> cho <npc> Thợ Săn</npc>",
    [2691240727] = "Lửa Sương độc đang thiêu đốt ngươi! Ngươi đang nhận sát thương nặng!",
    [2691290568] = "Cọc Hàng Rào Gỗ Tốt",
    [2691413313] = "Áo Vest Dân Du Lâm",
    [2691681533] = "Từng lần cắt tóc một.",
    [2691929422] = "Gỗ dán là một kỹ thuật xây dựng cổ xưa rất phổ biến vì hiệu ứng trang trí của nó.",
    [2692001581] = "Rõ!",
    [2692121029] = "Vị Trí <craftingstation>Nồi Hơi Đen</craftingstation>",
    [2692250857] = "Thuần Hóa Động Vật",
    [2693011554] = "Lò Nướng",
    [2693101990] = "Nướng với hương thơm khói, đó là một niềm vui thực sự cho vị giác, có thể giải phóng tất cả các thuộc tính tăng cường của nó.",
    [2693303537] = "Cúp Danh Năng Ác Thú Sa Ngã Bằng Đồng",
    [2693484242] = "Đồi Lễ Tế Vukah",
    [2693805973] = "Găng tay nặng nhằm bảo vệ tay bạn trong chiến đấu. Bạn có thể vung kiếm mà không sợ hãi với những chiếc này.",
    [2694011894] = "Bát Ăn Cho Mèo",
    [2694305743] = "Các đòn tấn công của bạn gây thêm sát thương <b>Lửa</b>. Hiệu ứng này được kích hoạt khi tiếp đất trong khi Tác Động Thiên Thạch đã sẵn sàng.",
    [2694435449] = "Này, ta vẫn thỉnh thoảng bắt gặp cảnh ngươi lao xuống đất từ xa. Đừng lo, không có gì phải xấu hổ cả! Nhưng nếu ngươi muốn bay theo phong cách, hãy cân nhắc chế tạo một chiếc tàu lượn tốt hơn với ta!",
    [2694981228] = "Sự Dũng Cảm Đỏ Thẫm",
    [2695473891] = "Người ta không nhìn thẳng vào những người đào huyệt vì nó mang lại điềm xấu. Do đó, một số người trông coi nghĩa địa đeo mũ che mắt để tránh rắc rối.",
    [2695914912] = "Một năm đã trôi qua kể từ khi người đầu tiên trong giống loài ngươi thức tỉnh, và sức mạnh của ta đã lớn mạnh nhờ ngươi. Ánh sáng của chúng ta nhảy múa cùng nhau, gắn kết qua một giao ước vui vẻ. Điều này đòi hỏi một lễ kỷ niệm - hãy dấn thân để tìm trang phục xứng đáng với sự kiện như vậy.",
    [2696060421] = "Cổng Cầu Vồng Bằng Đá Nhỏ",
    [2696284667] = "Một chiếc áo tunic ấm áp, lót lông cừu trắng. Tay áo dài và rộng, vì vậy thật vui khi vung tay một cách vui vẻ!",
    [2698227496] = "Lò Sưởi Bỏ Túi",
    [2698572783] = "Cài Đặt Hiện Tại",
    [2698594851] = "Tên Lửa Tím",
    [2698858340] = "Bể Bơi Không Thoát Nước Đúng Cách",
    [2698865006] = "Ta đang mang <b>vật liệu xây dựng</b> thì cảm thấy một cơn rung chuyển dưới chân. Giật mình, ta vấp phải gánh nặng và ngã xuống đất. Ta chắc hẳn đã đập đầu vào đá... Khi tỉnh dậy, <i>ta cảm thấy một cơn ngứa ran trên lòng bàn tay.</i> Một con vật bò. Rồi, một vết chích. Một sinh vật hung tợn đã cắm những chiếc răng như kim của nó vào tay ta! Ta đã hất nó ra, bừng tỉnh vì sợ hãi. Ta muốn giẫm nát nó, nhưng con thú đã chui xuống đất... hãy xây dựng mà không có ta trong khi ta chăm sóc vết thương này!",
    [2699003106] = "Tiếng Hú Mặt Trăng",
    [2699114897] = "Đến Địa điểm và Sát hại Scavenger",
    [2699391807] = "Một cây non sẽ phát triển thành cây khi được gieo trên đất phù hợp.",
    [2699725643] = "Một khối được làm từ xương sườn nhạt và xương sọ. Lớp vỏ ngoài màu ngà của nó trang trí cho cả lăng mộ và đền thờ.",
    [2700463961] = "Khi bạn giết kẻ địch bằng vũ khí tầm xa, bạn nhận được thêm 20% kinh nghiệm",
    [2700531724] = "Chim Đuôi Đỏ Không Thể Bay",
    [2700667157] = "Chúng ta vẫn có thể tìm thấy bảng màu nếu chúng ta giữ cho mắt và tâm trí mình cởi mở!",
    [2701007043] = "Cây Non",
    [2701088567] = "Cho biết bạn sử dụng vũ khí tầm xa tốt như thế nào.",
    [2701733837] = "Ngươi... đã uống Thuốc Tiên! Ta thấy một chút điên rồ còn sót lại trong mắt ngươi.\nNgọn Lửa bảo vệ linh hồn ngươi. Tuy nhiên, ngươi phải hết sức cẩn thận. Quá nhiều người đã dìm nỗi buồn của họ vào thứ thuốc pha chế kỳ lạ này! Chết tiệt, những Cuộc Chiến Thuốc Tiên vĩ đại đã nổ ra vì nó!",
    [2702484273] = "Một chiếc áo vest ấm áp, có đệm. Lý tưởng để chịu đựng những đêm lạnh giá trong khi chờ đợi thời điểm tấn công.",
    [2702652472] = "Hậu Quả Giật Mình Khi Thuần Hóa",
    [2702869586] = "Cô Hầu Gái Drakonian Quyến Rũ, Chương 3: Dưới Lớp Vải",
    [2703488022] = "Xóa Dữ Liệu Lưu",
    [2703830170] = "<b>Lò Phản Ứng</b> đã được tìm thấy. Nó cần được chế tạo thành <b>Lò Luyện Kim</b> <craftingstation> với <b>Thợ Rèn</b> <npc> để mở khóa thêm công thức chế tạo.",
    [2704400132] = "Đã dọn sạch giếng thuốc tiên đầu tiên.",
    [2704416011] = "Đây là nơi nào? Lửa, vụ nổ, đám cháy đâu? Chỉ vài giây trước, phổi ta đang cháy bỏng, và da ta đang tan chảy... ai đã đưa ta khỏi nấm mồ lửa đó?",
    [2705234250] = "Nâng cấp",
    [2705995668] = "Thuyền Trưởng Whiskers",
    [2706067788] = "Rút Ra",
    [2706117185] = "Sát thương",
    [2706268888] = "<craftingstation>Aeolipile</craftingstation>",
    [2707167467] = "Springlands",
    [2707859738] = "Howling Peak",
    [2708389714] = "Được nghỉ ngơi đầy đủ",
    [2708961488] = "Bình Đất Sét IV",
    [2709237677] = "Tay to",
    [2709576387] = "Bách Khoa Toàn Thư Về Cây Và Hạt Giống",
    [2709616468] = "Hợp pháp",
    [2710058291] = "ST Phép",
    [2710362596] = "Một nền tảng mạnh mẽ để chế tạo các loại thuốc khác nhau.",
    [2710486094] = "Bàn Đầu Giường Gỗ Đánh Bóng",
    [2710628138] = "Sau khi đánh trúng kẻ địch từ phía sau, mục tiêu bị choáng trong 1 giây.",
    [2710667577] = "Headseeker",
    [2710755934] = "Một cây cung Sương độc bị nhiễm độc, có khả năng dạy cho kẻ địch ý nghĩa thực sự của nỗi đau.",
    [2710964965] = "Cây cối",
    [2710995527] = "Thức ăn để thu hút và thuần hóa Capybara.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên thuần hóa. Một khi đã thuần hóa, con vật có thể được nhặt lên.",
    [2711103985] = "Chế tạo các khối, vật phẩm mới và sửa chữa thiết bị bị hỏng.\n\n<craftingstation>Bàn chế tác</craftingstation> chỉ có thể được đặt bên trong khu vực của Bàn thờ Ngọn lửa.",
    [2711133505] = "My Little Pompom",
    [2711672313] = "Cài đặt này điều chỉnh sát thương của các đòn tấn công của trùm.",
    [2711860454] = "Đống Rơm",
    [2711920199] = "Sát thương chống lại kẻ địch bay ",
    [2711937629] = "Ồ, tôi vẫn sống — và khỏe mạnh nữa! Không bị gãy mắt cá chân vì ngã, hay mỏi chân vì những chuyến đi của tôi! Tên tôi là Robert Gibson — tôi vận chuyển hàng hóa cùng với đối tác của mình, Kaori! Cô có thể tìm cô ấy nữa không? Cô ấy quản lý mọi thứ từ <location>East Lapis</location> và gặp một chút rắc rối với một bưu kiện ở đó. Tôi sẽ biết ơn mãi mãi!",
    [2712200095] = "Khung Cửa Sổ",
    [2712619648] = "Mảnh Khảm Ngọn Lửa VIII",
    [2712894467] = "Trải thảm đỏ bất cứ khi nào bạn muốn, và bước vào một cách đầy phong cách.",
    [2713163962] = "Anything For The Applause",
    [2713186567] = "Khối mái nhà",
    [2713201091] = "Sự ra đời của các vị thần mới - Arisztar",
    [2713462276] = "Đói",
    [2713549731] = "Cột Cờ IV",
    [2713573896] = "Mũi Tên Đồng Đỏ Tẩm Độc",
    [2714401179] = "Ghế Gỗ Đánh Bóng",
    [2714532309] = "Một phiên bản thô hơn của Khối đá sa thạch tinh chế, chủ yếu được sản xuất với số lượng lớn. Do vẻ ngoài của nó, nó chủ yếu được sử dụng cho móng.",
    [2714985314] = "Găng Tay Người Chữa Lành",
    [2715112670] = "Cây Giống Đước",
    [2715417278] = "Giày Sát Thủ",
    [2715697695] = "Đang làm việc...",
    [2715838441] = "Tấm kim loại sáng bóng",
    [2716334455] = "Máng Ăn Hươu Tiên",
    [2716648676] = "Một loại khối gỗ mới để xây dựng. Các chi tiết gạch làm ấm bất kỳ không gian nào.",
    [2716977971] = "Tinh chỉnh xoay",
    [2717140646] = "Sách I",
    [2717311002] = "Trái tim cô đơn của tôi khao khát một người bạn song ca!",
    [2717520682] = "Sofa Thanh Lịch Nhỏ",
    [2717844033] = "Tàn tích hóa thạch của một loài cá vây thùy. Hậu duệ của thợ săn lướt đêm này từng được coi là món ngon và được dùng để lấp đầy các con suối. Tuy nhiên, việc tiêu thụ trở nên bất khả thi trong triều đại của Sương độc, vì một số loài cá đã phát triển các hàng răng mục rữa mới và cắn trả.\n\nBộ sưu tập này được tìm thấy ở Kindlewastes.",
    [2718224117] = "Tủ Trưng Bày Quái Vật Một Mắt",
    [2718337694] = "ST Đập",
    [2718850042] = "Henry đã không trở lại. Anh ấy không xuống để mang nước cho tôi, và tôi không dám bước ra ngoài khi biết rằng điều đó đồng nghĩa với cái chết. \nNgay bây giờ tôi vẫn đang ẩn náu, nhưng ai biết được lính canh sẽ làm gì nếu họ tìm thấy tôi. Tôi sẽ bị treo cổ vì tội phản quốc, có lẽ... chỉ vì nói sự thật. Tuy nhiên, tôi chỉ còn đủ nước cho khoảng 3 ngày nữa. \nVà điều còn đáng buồn hơn... có vẻ như những lời cuối cùng của tôi, dù viết hay hét lên, sẽ không bao giờ đến được với một linh hồn sống nào. Một cái chết vô nghĩa như vậy đối với một phóng viên... Một người khôn ngoan sẽ gọi đó là sự mỉa mai. Tôi sẽ gọi đó là sự méo mó.\n\n— Ramone Jones, Biên tập viên của The Pike Weekly từng tồn tại.",
    [2719461819] = "Cảm nhận Tinh thần của thiên nhiên.",
    [2719670862] = "Màu tóc",
    [2720156768] = "Quả Mọng Tím Sấy Khô",
    [2721348542] = "Leo lên các Cột cổ xưa và nói chuyện với Ngọn lửa trên đỉnh để tiết lộ các địa danh quan trọng trên bản đồ của bạn. Các Cột cổ xưa sẽ tiết lộ vị trí của <b>Giếng Tinh chất và Thánh địa Lửa.</b>\n\nChúng cũng hoạt động như <b>điểm dịch chuyển nhanh sau khi bị chinh phục.</b> Mở bản đồ của bạn và chọn điểm đánh dấu Cột cổ xưa để Dịch chuyển nhanh.",
    [2721731585] = "Tượng Drak",
    [2722041239] = "Thanh tẩy",
    [2722358491] = "Sunpiercer",
    [2722825132] = "Rồng bị giết",
    [2723238538] = "Quần Vệ Binh",
    [2723451763] = "Đi đến Nhật ký",
    [2723510674] = "Cảnh báo",
    [2723532847] = "Rào Chắn Tre I",
    [2723817297] = "Khối Lập Phương 2m",
    [2723913123] = "Tiện nghi - Chiếu sáng",
    [2723983863] = "Không đơn độc",
    [2724122818] = "Ngay cả cái chết cũng có trái tim.",
    [2724541585] = "Một đồng xu cho một bài hát, có lẽ?",
    [2725525796] = "Dịch Chuyển Tức Thời",
    [2726011865] = "Cung Rồng",
    [2726070257] = "Cửa Đá Lửa Bí Mật",
    [2726079953] = "Ghi chú trại Withered",
    [2726280345] = "Amber đã chết tại <location>Surat's Rest</location>. Cô ấy đã trốn thoát đến đó, hy vọng vào một cuộc sống tốt đẹp hơn... nhưng những cô gái ồn ào và chính trực như cô ấy không tồn tại lâu trong một ổ rắn độc. Cả hai chúng tôi đều đau buồn, nhưng mẹ cô ấy gần như không thể ra khỏi giường. Với tư cách là chồng và cha, tôi đã đồng ý chọn một nơi để chúng tôi có thể an táng cô ấy.\n\nTôi nghĩ cái cây sau nhà chúng ta sẽ ổn thôi. Một vườn cây ăn quả yên tĩnh bên sông... nơi cô ấy thích ngồi và suy ngẫm. Cô ấy thật sáng dạ, thật ăn nói lưu loát. Chúng tôi chẳng là gì nếu thiếu ánh sáng và sự duyên dáng của cô ấy. Quyết định viết gì lên bia mộ của cô ấy là một sự tra tấn thuần túy. Trái tim tôi nặng trĩu, có lẽ đã hóa đá.",
    [2726310218] = "Công thức nấu ăn đã ghim",
    [2727390552] = "Hiện tại",
    [2727431507] = "Độ trễ hồi phục MP",
    [2727705109] = "Một chú Hươu Fae con. Chúng mỏng manh sau khi sinh, nhưng chúng học cách đi và phi nước đại một cách đáng kinh ngạc nhanh chóng!",
    [2727829067] = "Giếng Nước",
    [2727922360] = "Một hạt giống sẽ phát triển thành cây khi gieo vào đất thích hợp. Khi cây trưởng thành hoàn toàn, nó có thể thu hoạch một lần.",
    [2728329166] = "<lorename>Sameth</lorename>",
    [2729581845] = "Du hành qua Sương độc",
    [2729818150] = "Bộ trang phục hầu gái mềm mại và thoải mái. Nó dễ dàng được làm sạch nếu bị bẩn bởi nước rửa, sữa hoặc rượu.",
    [2730279345] = "Thay đổi danh mục",
    [2730421476] = "Một hơi thở ánh sáng, đang phai nhạt",
    [2730638061] = "Bắt đầu trên con đường của một người học việc giả kim, những chiếc găng tay này sẽ làm cho cuộc sống của bạn thoải mái hơn một chút.",
    [2730912924] = "Loại gỗ nhiệt đới này có thể thu hoạch từ những cây cổ thụ. Nó rất chắc chắn!",
    [2731267222] = "Những chiếc quần này cực kỳ nhẹ và do đó cho phép di chuyển nhanh chóng và linh hoạt. Ngồi xổm, leo trèo và chạy để giành lợi thế!",
    [2731504056] = "Gọi một thiên thạch Sương độc xuống kẻ thù của bạn. Kênh dẫn năng lượng tối này làm cạn kiệt thời gian còn lại của bạn trong Sương độc. \n\n<b>Phép thuật: Bị tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [2731957446] = "Phiên bản xây dựng của máy chủ này cũ hơn của bạn. Chủ sở hữu máy chủ này cần cập nhật nó lên phiên bản mới nhất.",
    [2732102012] = "Trang trại Penny Bun",
    [2732398026] = "Ahhh, một đống lửa bốc cháy xuyên qua tuyết... một đám cháy rừng có thể sánh ngang với mặt trời! Điều này sẽ giữ ấm và no đủ cho chúng ta... cho bây giờ.",
    [2733054832] = "Đũa Phép Lửa Địa Ngục",
    [2733095719] = "Bình Triệu Hồi Đầu Lâu Của Pháp Sư Chiêu Hồn",
    [2733211010] = "The Collector đã yêu cầu bạn cung cấp thêm một người chăn dắt linh hồn cho hắn, hoặc một tấm bảng trống có thể được biến đổi thành \"thứ gì đó hữu ích\".\n\nHọ đã chỉ cho bạn một địa điểm đầy hứa hẹn, nơi có thể chứa lớp vỏ xác sống mà bạn cần.\n\n<b>Đến ngôi đền được đề cập</b> để tiếp tục.",
    [2733519685] = "Thưởng tốc độ chạy",
    [2734126858] = "Tìm tất cả các mảnh bản đồ kho báu",
    [2734290283] = "Một phần lớn thịt nướng. Chắc hẳn nó đến từ một con cua khổng lồ. Thưởng thức!",
    [2734575892] = "Độ nhạy khi ngắm",
    [2734718554] = "Lá Cọ",
    [2734807862] = "Chuột Lang Nước Con",
    [2735377792] = "Thùng Nước",
    [2735749852] = "Né tránh",
    [2736023705] = "Trang bị Chế tạo:",
    [2736128568] = "Thánh đường Ngọn lửa",
    [2736445288] = "Cửa Thép Tinh Xảo",
    [2736528844] = "Lời Kêu Cứu",
    [2736686575] = "Một miếng băng được làm thấm hút hơn nhờ rêu. Bột bạc và thuốc mỡ vết thương được thêm vào sẽ chữa khỏi độc tố.\n\nMón đồ này Chữa thương 80% HP trong 10 giây nếu được bôi lên vết thương.\n\nNhận bất kỳ sát thương nào sẽ làm gián đoạn hiệu ứng Chữa thương.",
    [2736991891] = "Một đôi ủng được gia cố bằng các vật phẩm của Drak, mang lại cho bạn lợi thế trong chiến đấu.",
    [2737273525] = "Cảm hứng cho Lò nướng Hải sản",
    [2737734608] = "Nhật ký Thám hiểm #2",
    [2737855017] = "Dãy núi Albaneve hẳn là giàu khoáng sản... bạc, obsidian, và ai biết còn gì nữa? Chúng ta cần một cách mới để nấu chảy chúng... nhiệt độ cao hơn...",
    [2738116374] = "Balthazar",
    [2738167970] = "Chi phí Nâng cấp",
    [2738453227] = "Nhật ký Người gác hải đăng III",
    [2740093268] = "Nhấn để nói",
    [2741004763] = "Không thể Du hành Nhanh khi đang ở trong Sương độc",
    [2741558270] = "Cột Tổ Tiên Gỗ Drak IV",
    [2741680252] = "<i>Họ đã chiếm lấy <location><lorename>Vươn tới Pikemead</lorename></location>. Họ đã giết Vua <lorename>Gormander</lorename>.</i>\nMột đội quân những kẻ điên, xanh xao bệnh tật, gần như không nhấc chân khỏi mặt đất đẫm máu. Chúng lê bước qua các thung lũng của chúng ta, qua màn sương độc hại, dẫn đầu bởi Vệ binh phương Bắc điên loạn, <lorename>Vorgoth</lorename>. Ta luôn biết rằng <i>Thuốc tiên</i> sẽ gieo mầm nghi ngờ.\n\nTa ngước nhìn Tháp Cổ xưa, nhìn lên bầu trời... không còn đường chạy, không còn chỗ trốn. Chúng ta phải kiên trì.\n\n— Balthazar",
    [2741781045] = "Nhà Thờ Lớn",
    [2742477278] = "Bình Máu Phục Hồi +",
    [2742503334] = "Mũi Tên Xương Khổng Lồ I",
    [2742874439] = "Không có cách nào chúng ta có thể xuyên thủng tuyến phòng thủ này.\n\nCó vẻ như những Người xưa đã thiết lập các ngọn hải đăng này để bảo vệ biên giới của họ.\nMỗi khi chúng ta đặt chân ra ngoài giới tuyến, ai đó sẽ bị giật, bị thiêu, hoặc bị nghiền nát. Chúa tể Vorgoth sẽ không thích điều này chút nào...\n\nNếu chúng ta muốn vượt qua ngưỡng cửa đến lãnh thổ của họ, chúng ta sẽ phải phá hủy một vài ngọn hải đăng... hoặc tìm cách vô hiệu hóa chúng. Nếu chúng ta chiến thắng... không, <i>khi</i> chúng ta chiến thắng, thì những cánh cổng cổ xưa sẽ nằm trong tầm tay chúng ta.\n\nPhòng làm việc của Trung úy Arlington, Giám sát viên Chương trình Mở rộng thứ nhất",
    [2743908723] = "Khuôn mặt bị Ngọn lửa ám",
    [2744048074] = "Cảnh báo Vũng Lướt sóng",
    [2744186578] = "Đuốc Gắn Tường Bằng Sắt",
    [2744412351] = "Đặt nhiệm vụ đang hoạt động",
    [2744591888] = "<location>Rookmore</location>",
    [2744977357] = "THA",
    [2745895815] = "Tinh Hoa Cổ Xưa",
    [2746498144] = "Khắc Họa Vận Mệnh",
    [2748085027] = "Hàng Rào Sắt",
    [2748421037] = "Những Gì Bạn Làm Vì Tiền",
    [2749949267] = "Một phần của Giáp Thảo dược.",
    [2750039548] = "Cài đặt này kiểm soát số lượng kẻ địch có thể tấn công cùng một lúc.",
    [2750138881] = "Nấm Russula Xanh",
    [2750152928] = "Cánh Quạt Cối Xay Gió Nhỏ",
    [2750855371] = "Chân Nến Bạc",
    [2751047656] = "<keyitem>Dụng cụ rèn</keyitem>...? Cho ta ư? Thật kỳ lạ. Chà, ta có rất nhiều thứ để dùng chúng! Đã mất bộ cũ trong một vụ hỏa hoạn... <b>Đặt chúng xuống cạnh ta</b>, được chứ? Cảm ơn rất nhiều, Hỏa sinh! Hãy dùng chúng để chế tạo giáp mới!",
    [2751081011] = "Tìm vũ khí tổ tiên của Gunther",
    [2751135748] = "Một <b>mũi tên đặc biệt</b> mang đến bất ngờ bùng nổ. Tấn công với sức mạnh hỏa lực được cải thiện đáng kể.",
    [2751468127] = "Đầu Đấu Sĩ Vukah",
    [2751593901] = "Ghế Dài Lâu Đài",
    [2752498998] = "Nói chuyện với Emily Fray",
    [2753397886] = "Bạn đã nhận được một Tia lửa. Sử dụng Tia lửa để củng cố Ngọn lửa tại Bàn thờ Lửa của bạn. <b>Củng cố Ngọn lửa</b> tại Bàn thờ Lửa để tăng Cấp độ Vượt qua Sương độc của bạn và thiết lập thêm các căn cứ.",
    [2753579098] = "Cái <npc>Nhà giả kim</npc> <craftingstation>Cối giã</craftingstation>",
    [2753600680] = "Giày Lông Huyết",
    [2754129782] = "Trái tim của Hang ổ",
    [2754487502] = "Bình thường",
    [2754521679] = "Tủ Trưng Bày Hóa Thạch (3 Khe Nhỏ)",
    [2754916476] = "Lối Mòn Sàn Đá Bí Mật",
    [2755576397] = "Không Tốt Hơn Chúng Ta!",
    [2755915841] = "Cảnh báo của <lorename>Elin</lorename>",
    [2756175310] = "Ngày 1 — Lại mắc kẹt trong thang máy",
    [2756714769] = "Xạ thủ",
    [2757043964] = "Kho mới",
    [2757267740] = "Găng Tay Hiệp Sĩ",
    [2757285164] = "Bơi xuống",
    [2757438503] = "Ánh sáng thuần khiết bao trùm kiến thức của giống loài cổ xưa, bảo vệ nó trong một lõi lửa. Trí tuệ vượt xa trí tưởng tượng của ta. Ta có thể nhìn chằm chằm vào ngọn lửa hàng giờ, tìm kiếm câu trả lời, một lời thì thầm... Nhưng ta không nghe thấy gì. <i>Mặc dù sở hữu giọng nói, nó chỉ nói với những người sinh ra từ Lửa.</i>\n\nThật đáng tiếc, vì ta tin rằng chúng ta có thể có những cuộc trò chuyện khá khai sáng.\n— Balthazar",
    [2757596941] = "Di chuyển: Nhân vật <img arrow_left_right> Kho",
    [2758504745] = "Bình hồi phục HP cải tiến",
    [2758852572] = "Trò chơi bị tạm dừng",
    [2759630823] = "Vậy là nơi mục nát đó thực sự bị ma ám, phải không? À, nếu ông già <lorename>Elin</lorename> còn sống, bà ấy sẽ nhẹ nhõm khi biết rằng nỗi kinh hoàng đã bị chặt đầu nhờ bạn! Bạn đã gửi con Lưỡi hái Susie đó trở lại mồ mả! À, chúng ta có thể cho cái đầu đó vào Ngọn lửa và nướng một vài con Hophare! ...Điều đó có phạm thượng không? Không, không, nếu không có ai nhìn thấy, tôi đoán vậy.",
    [2759724505] = "Vị trí bản nhạc",
    [2760308050] = "Bạn đang hỏi về một màu xanh lá cây đại diện cho thiên nhiên và sự tái sinh? Chà, nhiều loài thực vật có màu xanh lá cây! Thứ tươi sáng nhất mà tôi từng thấy là khi tôi đi du lịch Cao nguyên Du mục cùng đoàn lữ hành. \"Người bạn\" của tôi và tôi đang đi dạo đêm thì lạc vào cánh đồng hoa huỳnh quang này! Nhưng ngày hôm sau, chúng đã biến mất... thật kỳ lạ!",
    [2761991475] = "ST Hỏa mỗi giây",
    [2762047462] = "Trên đất màu mỡ",
    [2763318691] = "Lạnh giá",
    [2763344476] = "Lớp phủ đồng cải tiến của Giáp ngực Xe tăng này có thể chịu được nhiều đòn tấn công hơn ở tiền tuyến chiến trường.",
    [2763348501] = "Bạn đã tìm thấy một mảnh phù điêu Drak. Có lẽ còn nhiều mảnh nữa — hãy tìm kiếm các đền thờ Drak mà bạn gặp trên đường đi để tìm các mảnh bị phân tán!\n\nTìm tất cả các mảnh để lắp ráp lại phù điêu!\nMột Tủ trưng bày Phù điêu Drak để trưng bày các phù điêu có thể được chế tạo tại nhạc sĩ Valory.",
    [2763552489] = "Sức mạnh nở rộ",
    [2763820354] = "Độ trễ: %k",
    [2763934821] = "Tăng tối đa SP thêm 1",
    [2764192340] = "Tôi không nghĩ bạn sẽ tìm thấy một bộ hoàn chỉnh! Rõ ràng, họ đã không thành công lắm trong nỗ lực của mình. Tôi tự hỏi điều gì đã xảy ra với những người còn lại. Có lẽ con đường của bạn sẽ giao nhau vào một lúc nào đó và bạn có thể cho tôi biết thêm về họ.",
    [2765069591] = "Thanh Chống",
    [2765756057] = "Nhiệm vụ Embervale đại diện cho sự tiến triển của máy chủ.\n\nHoàn thành Nhiệm vụ Embervale để mở khóa các câu chuyện, công thức chế tạo và vật liệu mới cho mọi người! Nhiệm vụ Embervale giống nhau đối với tất cả người chơi trên máy chủ.",
    [2765763543] = "Nhờ kỹ thuật quấn của họ, những đôi giày này cung cấp sự hỗ trợ tốt trong khi vẫn cho phép bạn giữ sự nhanh nhẹn.",
    [2766682901] = "Bạn có khả năng gặp phải một số vấn đề.",
    [2766790054] = "Một hóa thạch hoa loa kèn biển nhỏ, chắc chắn. Bất kể bạn xoay nó như thế nào, bạn luôn được chào đón bởi một sợi tua hoặc một dấu ấn.\n\nBộ sưu tập này được tìm thấy ở Cao nguyên Du mục.",
    [2766973863] = "Nghiên cứu Đầu Cyclops",
    [2767055901] = "SSAO",
    [2767370822] = "Có những vật phẩm đặc biệt để tìm thấy tại một tổ kền kền Draconian ở Kindlewastes. Hãy tìm kiếm khu vực đó và lấy bất cứ thứ gì bạn có thể!",
    [2767545621] = "Thức ăn để thu hút và thuần hóa một con Chim đỏ không bay hoặc một con Chim mỏ tròn.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Một khi đã thuần hóa, con vật có thể được nhặt lên.",
    [2768364039] = "Truyện kể trước khi ngủ",
    [2768431154] = "Sao chép %k vào Tùy chỉnh",
    [2768817561] = "Loại gỗ đặc biệt cứng này có thể gây ra nhiều sát thương nếu nó va vào đầu bạn khi bạn đốn cây.",
    [2768903979] = "Linh hồn Làng bị mất",
    [2769408099] = "Giờ thì cút đi!",
    [2769445873] = "%k ngồi xuống",
    [2770583431] = "Coi chừng bóng tối!",
    [2770796361] = "Một chiếc búa được cải tiến thêm bằng sừng dê ở phía sau. Chỉ những chiếc sừng tốt nhất, chắc chắn nhất mới được chọn!",
    [2771701691] = "Tấm lều tạm bợ này cung cấp đủ chỗ trú ẩn khỏi các yếu tố.",
    [2772256785] = "Búa Công Thành",
    [2772647876] = "Xuyên thấu vĩnh cửu",
    [2772658068] = "Ta đang ra ngoài để thả lưới — săn lùng một <i>mẻ cá thực sự lớn,</i> hiểu chứ! Bạn sẽ thưởng thức hương vị của một mẻ cá huyền thoại khi hoàng hôn buông xuống! \n\nNếu có trường hợp khẩn cấp — hỏa hoạn đột ngột, đám say rượu đánh nhau, hết rượu, đám say rượu đánh nhau giữa Ngọn lửa vì chúng ta hết rượu (chúng ta đã từng như vậy!) — bạn biết tìm ta ở đâu: \n\n<b>Ta sẽ ở ngay bên kia hồ, cạnh bộ xương rồng tại Nơi nghỉ của Thuyền trưởng Ol'.</b>",
    [2773056671] = "Bạn biết nơi tìm thấy tôi.",
    [2773161838] = "Nhận Sổ tay của Bà chúa",
    [2773485800] = "Chiếu sáng",
    [2773634249] = "Ta đã bảo buông ra!",
    [2774012233] = "Bạn ngọt ngào như mật, nhưng tiếc là bạn không thể thay thế cho <craftingstation>Thiết bị xông khói tổ ong</craftingstation>.",
    [2774215584] = "Tìm tiền vàng",
    [2774422597] = "Cách đây một thời gian, tôi nghe những lời thì thầm về một pháp sư hùng mạnh đã phát điên vì ám ảnh. Họ nói rằng ông ta khao khát sự vĩnh cửu. Trong cơn điên loạn của mình, ông ta đã tìm cách dệt sự sống vào một câu thần chú sẽ không bao giờ phai nhạt. Liệu ông ta có thành công hay không, tôi không thể nói... nhưng tôi biết ông ta đã tiến hành các thí nghiệm của mình trong các hầm mộ ẩn giấu, sâu bên dưới lòng đất, tránh xa ánh mắt tò mò.\nTôi tình cờ biết vị trí của một trong những hầm mộ đó. Bạn sẽ làm tốt nếu điều tra — có thể có kiến thức quý giá bị chôn vùi bên trong.",
    [2774740138] = "Không ngừng nghỉ",
    [2775165548] = "Cướp Báu Đền Thờ Mặt Trời",
    [2775512311] = "Giỏ IV",
    [2776064617] = "Điều tra Điểm Đầu Tiên Trên Tuyến Vận Chuyển",
    [2776166537] = "Máy Chủ Chuyên Dụng",
    [2776185091] = "Kẻ Tham Ăn!",
    [2776726801] = "Triệu Hồi <npc>Thợ Săn</npc>",
    [2776746096] = "Lưỡi Kiếm Than Khóc",
    [2777215182] = "Mở khóa khả năng chế tạo <craftingstation>Tổ Ong Mật</craftingstation> cung cấp mật ong và sáp đều đặn.",
    [2777828283] = "Trạm Giao Dịch Lạc Đà — Quy Tắc:",
    [2777957603] = "Cọc Rào Sân Vườn Gỗ Phương Bắc",
    [2777986488] = "Lối Vào Lăng Mộ Bí Ẩn",
    [2778043060] = "Thêm một vài người nữa sẽ hữu ích cho chúng ta nếu chúng ta có kế hoạch mở rộng căn cứ! Cá nhân ta, có thể cần <b>thêm dung lượng lưu trữ cho các lọ thuốc của mình.</b> Ta tình cờ biết vị trí của một Hầm Mộ Cổ khác — tại sao không đi xem xung quanh?",
    [2778138952] = "Bạn có %k cơ hội nhận sát thương bạn gây ra dưới dạng SP.",
    [2778449604] = "Tin đồn ám chỉ sự tồn tại của một lăng mộ bí ẩn ở Vùng Đất Mùa Xuân. Tìm vị trí, đi sâu vào lòng hầm mộ và mang chiến lợi phẩm về nhà!",
    [2779750897] = "Ta cần một cưa bàn để, ờm, \"mở rộng vốn từ vựng\". Ngươi có thể làm một cái từ lưỡi cưa — ngạc nhiên chưa? Ta từng lấy lưỡi cưa từ <b><location>Thornhold</location></b> trước đây, ừm, ngươi biết đấy. Đi làm đi!",
    [2780008511] = "Quần săn ấm áp và có đệm sẽ giữ nhiệt cơ thể bạn trong những đêm lạnh giá, không sao.",
    [2781338524] = "Bắn một mũi tên với đôi găng tay này thật dễ dàng, tạo ra một dòng chuyển động mượt mà như lụa cho người đeo.",
    [2782928211] = "Cửa Gỗ Chạm Khắc",
    [2782959377] = "Được rồi",
    [2783649829] = "Không tìm thấy trò chơi nào có thể tham gia.",
    [2784175566] = "Không thể di chuyển hoặc hành động.",
    [2784530711] = "Lò Sưởi Đá",
    [2784812933] = "Phiên bản xây dựng của bạn cũ hơn phiên bản xây dựng của máy chủ này. Vui lòng cập nhật trò chơi của bạn.",
    [2784820406] = "Điều tra Những Tin Đồn Đáng Lo Ngại",
    [2785976263] = "Cánh Đồng Gloomberry",
    [2787066762] = "Chất Nhờn Độc",
    [2787211206] = "Kẻ Gọi Hư Không",
    [2787670890] = "Phòng lưu trữ cho 32 vật phẩm.",
    [2788468742] = "Một Chút Trinh Sát Sẽ Không Gây Hại",
    [2789093655] = "ST Cận chiến",
    [2790456185] = "Ngươi đã ngủ quá lâu rồi, Hỡi Hồn Lửa. Vương quốc Embervale đã sụp đổ, bị nhấn chìm bởi Sương độc. Giờ đây, ngọn Lửa bền bỉ kêu gọi ngươi. Tìm một nơi trong thế giới đổ nát và xây dựng một <b>Bàn Thờ Lửa</b> để tạo nơi trú ẩn khỏi bóng tối.",
    [2790760228] = "Cụm Cầu Gai Biển",
    [2791925189] = "Bạn đã đến điểm được chỉ định để thuần hóa một con Capybara. <b>Sử dụng mồi nhử của bạn để thuần hóa một con vật ở đó.</b> Hãy cẩn thận khi bạn tiếp cận!\n\nMột khi Capybara cảm thấy thoải mái, nó có thể được <b>nhấc lên và mang về nhà. Nó sẽ sản xuất lông cho bạn từ đó trở đi.</b>",
    [2792156081] = "Hãy cho ta biết ngươi cần gì!",
    [2792768237] = "Cho ta một chút đồ giải khát, làm ơn! Ta chán quá! ...Và khát nước!",
    [2793020701] = "Hố Sâu",
    [2793259445] = "Cờ Lệnh Dọc I",
    [2794361095] = "Hoàn tác hành động xây dựng",
    [2794979715] = "Thánh Tích Chướng Khí",
    [2795307933] = "Nó ngăn ánh nắng chiếu vào đôi mắt mệt mỏi của bạn. Đó là tất cả những gì nó cần làm!",
    [2795549076] = "Thung Lũng Hollow Cao Nguyên Lạc Đà",
    [2795774121] = "Quần tối màu cho những kẻ sử dụng ma thuật hắc ám.",
    [2795780925] = "Ngươi đã biết rằng một sứ giả hoàng gia đã bị lạc trên đường đến Tiền Đồn Cổng \"Bora\". \n\nCó lẽ họ có thể được tìm thấy ở gần đó. Tìm sứ giả hoàng gia!",
    [2795878683] = "Bàn Cờ Vua",
    [2796709856] = "ST Xuyên",
    [2796781201] = "Bất cứ khi nào một đồng minh thu hút sự chú ý của kẻ địch, bạn cũng thu hút nó theo tỷ lệ tương đương.",
    [2796807827] = "Trang phục Thân Dưới",
    [2797156306] = "Kiếm Của Học Việc Cổ Ngữ",
    [2797203022] = "Tiếp Cận Tiền Đồn Bỏ Hoang",
    [2797978482] = "Nhiệt Kế",
    [2799236144] = "Lăn Tránh Néo",
    [2799584360] = "Tái Sinh...",
    [2799754635] = "Bột tinh thể, có thể tìm thấy trong các thung lũng bị sương độc bao phủ. Hương vị của thức ăn có thể được cải thiện đáng kể khi rắc muối.",
    [2799975138] = "Một khối làm từ Gạch Nung. Nó có màu đỏ xỉn.",
    [2800075719] = "Đôi ủng chắc chắn chịu được mọi cuộc hành quân hàng trăm dặm.",
    [2800944001] = "Một chiếc mũ bạc giúp tăng lượng Oxygen tối đa khi lặn.\n\nCác đường khắc tinh xảo của nó mô phỏng dòng chảy của nước, và cửa sổ được chia thành các phần giống như vỏ sò.",
    [2801550418] = "Một nơi làm việc quan trọng cho <npc>Thợ Mộc</npc> sẽ mở ra nhiều cơ hội chế tạo mới.",
    [2801571924] = "Ngọn Lửa đã cho ngươi biết rằng nó cần một lượng tín đồ lớn hơn để trở nên mạnh mẽ hơn. Ngọn Lửa sẽ nuôi dưỡng đức tin, kiến thức và hy vọng của mọi người để tăng cường sức mạnh của nó. \n\nĐể có thêm tín đồ, ngươi phải tìm những linh hồn lang thang của dân làng.\nMột khi đã tìm thấy những linh hồn lang thang, ngươi phải cung cấp cho họ nơi trú ẩn và thức ăn để làm họ hạnh phúc. Sau đó, ngươi có thể <b>nâng cấp Ngọn Lửa lên cấp độ tiếp theo</b> và tiến sâu hơn vào thế giới!",
    [2801920915] = "Sương độc nuốt chửng tất cả, kể cả chúng ta. Chúng ta chìm vào hoàng hôn, biến mất và biến thành một biển hoàng hôn nhuốm màu hoa thanh cúc.\nChưa bao giờ ta gặp phải một căn bệnh, một lời nguyền khủng khiếp đến vậy. Sương mù đốt cháy mắt và phổi, nhưng không giết chết hoàn toàn. Nó lan rộng. Nó thao túng. Nó ăn mòn chúng ta, từ từ, chỉ để lại một cái vỏ.\n\nKhông có cách chữa trị cho điều này. Chỉ có <i>sức mạnh của Ngọn Lửa mới có thể đẩy lùi Sương độc.</i> \n\n— Balthazar",
    [2802085230] = "Ngọc Nhào Lộn",
    [2802116633] = "Ngài là pháp sư mà bạn của tôi đã nói đến, phải không? Tôi biết ngài không bao giờ trả lời cửa vì ngài bận rộn trong <b>gác xép bí mật của mình,</b> <i>nhưng tôi đã được hứa hẹn một thỏa thuận,</i> vì vậy tôi hy vọng ngài sẽ đọc điều này:\n\nNgài có biết <i>Ramone?</i> Hắn đã cử tôi đến gặp ngài. Hắn nói ngài có thể giúp đoàn tụ tôi với con trai mình.\nThằng bé Finnian của tôi đã ngã xuống trong trận chiến bên cây cầu. Nó chỉ là một đứa trẻ, không phải đàn ông, vẫn đang lớn như một cây mầm. Tôi cần được nhìn thấy khuôn mặt nhỏ bé đầy tàn nhang của nó một lần nữa. Được ôm nó vào lòng, dù chỉ một lần... thật chặt, như tôi đã từng làm khi nó còn là một cậu bé.\n\nChỉ một lần thôi. Tôi sẽ đi bất cứ đâu, và đọc bất kỳ câu thần chú nào. Tôi sẽ vượt qua ngưỡng cửa. Tôi cầu xin ngài. Đó là ước nguyện cuối cùng của tôi.",
    [2802698650] = "Găng Tay Thợ Săn Chim",
    [2802969129] = "Sự kết hợp của vải màu gỉ sét, các tấm kim loại và các chi tiết vàng. Những chi tiết sau thường khớp với răng vàng của Hollow!",
    [2803018753] = "Tiếp Cận Vùng Săn Bắn",
    [2803159330] = "Giá Để Vũ Khí Dao Găm",
    [2803319404] = "Ghi Chú Của Lãnh Chúa <lorename>Vorgoth</lorename>",
    [2803405929] = "Còn gì nữa không?",
    [2803580450] = "Thợ Mộc đã nói với ngươi về một thương nhân tên là Mei. Cô ấy có đồ trang trí và vật phẩm tập trung vào Tết Nguyên Đán.\n\nCô ấy thường ghé thăm Đồng Cỏ Thấp và luôn đi theo cùng một tuyến đường.\n\nTìm thương nhân để có quyền truy cập vào các đồ trang trí và hàng hóa mới!",
    [2803800060] = "Giường bị chiếm bởi: %k",
    [2803890617] = "Các Đỉnh Albaneve có thể rất lạnh. Khu vực có tuyết sẽ làm cạn kiệt lửa bên trong bạn, khiến bạn mất nhiệt.\n\nTốc độ cạn kiệt phụ thuộc vào <b>khả năng chống lạnh của bạn.</b> Bạn có thể tăng khả năng chống lạnh bằng cách ăn một số loại thực phẩm nhất định, trang bị áo giáp ấm áp hoặc ở gần lửa. \n\nKhi khả năng chống lạnh của bạn cạn kiệt hoàn toàn, bạn sẽ bị hạ thân nhiệt. Hạ thân nhiệt không được điều trị sẽ khiến bạn mất HP nhanh chóng.",
    [2804250856] = "Như Tất Cả Chúng Ta Đều Quên Lãng",
    [2804921009] = "Được chế tác từ một mảnh lưới đánh cá và các vật trang trí biển. Nó giữ tóc bạn không bay vào mặt khi bạn lặn.",
    [2804968849] = "Rìu Cánh Rơi",
    [2805095922] = "Một cây chùy được tắm trong nước thiêng, do đó có được lời chúc bảo vệ. Hóa ra lời chúc kém hiệu quả hơn thép lạnh khi bị phục kích.",
    [2805103385] = "Mở ra những cánh cửa có tầm quan trọng lớn.",
    [2805377246] = "Cây Giống Hoa Gentian",
    [2805602284] = "Cade",
    [2806554754] = "Ngươi đã đến Cromville. Thành phố này lớn và rộng lớn, vì vậy chắc chắn ngươi sẽ tìm thấy một linh hồn thuần khiết ở đây nếu may mắn.\n\nTìm linh hồn thuần khiết của một trợ lý nhạc sĩ ở Cromville để tiếp tục!",
    [2806648514] = "Bước chân ngươi im lặng, ánh mắt ngươi kiên định. Ngươi đã đi săn... Ta sẽ không hỏi ngươi theo dõi loài thú hoang nào, nhưng chiến lợi phẩm của ngươi, cùng lắm là tạm được. Hãy thử thu thập một ít <b>Lông Động Vật</b>. Sau đó, chúng ta có thể nói chuyện.",
    [2807209291] = "Một hình nộm có thể mặc áo giáp hoặc vật phẩm trang trí.",
    [2808099913] = "Nước",
    [2808162990] = "Vách Ngăn Phòng Bằng Tre II",
    [2808286430] = "Móc Đu",
    [2808935011] = "Chùy Khước Từ",
    [2809066324] = "Tủ Hầm Mộ Nhỏ",
    [2809517900] = "Tất cả chúng tôi đều nhảy khỏi bệ phóng ở Iron Heart. Tôi, Ryan, gã Chester mới đó, và Abraham. \nRyan không đi được xa; anh ta rơi xuống đất như một bao tải ướt. Thật nực cười. Abraham và tôi đến đây an toàn, mắt hướng về phần thưởng. Nhưng khi tôi quay lại kiểm tra Chester, tôi lại bị dán mắt vào thứ khác.\n\nChiếc tàu lượn của Chester chắc hẳn đã bị rách. Anh ta đang vật lộn trên không, lộn vòng giữa những cơn gió, lên xuống vô định.\nTuy nhiên, anh ta là một kẻ may mắn chết tiệt. Bị một con <i>kền kền băng bắt giữa không trung,</i> có lẽ nhầm anh ta với con mồi nào đó! Nó đã mang anh ta đến <i>vùng núi xa xôi.</i> \n \nĐó là cơ hội sống sót 50% cho cuộc thi lượn hàng năm. Ít nhất là tốt hơn năm ngoái.\n— Kip Dipper",
    [2809722423] = "Tìm Kiếm Lâu Đài Từ Ký Ức Của Thợ Cắt Tóc",
    [2809963887] = "Khoảng Thời Gian Đặt Lại Thế Giới",
    [2810182232] = "Thuốc Giải Độc",
    [2810272369] = "Vâng! VÂNG! Ahhh, những lời thì thầm tái tạo từ bức màn đang tan biến! Một cái nhìn thoáng qua vực sâu, sự hỗn loạn xoáy tròn của các linh hồn và những than hồng lạnh giá như băng! Quay lại với ta!",
    [2810340867] = "Vật phẩm đã được nạp đầy",
    [2811492642] = "Chỉnh Sửa Phím Nhấn Để Nói",
    [2811728660] = "Tab Tiếp Theo (Trình Xem Vật Phẩm)",
    [2811780710] = "Thuốc Giải Độc Tố Máu",
    [2811868539] = "Quần Chiến Binh",
    [2812146176] = "Thức ăn để thu hút và thuần hóa một con Fae Deer.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Một khi đã thuần hóa, con vật có thể được nhấc lên.",
    [2812174907] = "Tìm thấy trong các Hang Sương độc ở Thung Lũng Veilwater",
    [2812409353] = "Dao Găm Cùn",
    [2812416074] = "Một lưỡi kiếm trông như được phù phép với nguồn gốc không rõ. Nó bao phủ bầu trời và tâm trí trong ánh sáng xa xăm của buổi chiều tà đang dần tắt.",
    [2812623382] = "Mũi Tên Xuyên Giáp",
    [2812796692] = "Tăng sát thương lên Kẻ Hollow",
    [2813160962] = "Đó là cánh tay trái của một gã Khổng Lồ đáng sợ. Những nắm đấm xương xẩu này vẫn có thể nghiền nát bạn.\n\n Vật phẩm sưu tầm này được tìm thấy ở Đỉnh Albaneve. Nó có thể được lắp ráp lại để tạo thành một Bộ Xương Khổng Lồ trên Chân Đế Tượng Khổng Lồ.",
    [2813443058] = "Bạn đã tìm thấy một ghi chú về Olric, kẻ bị ám ảnh bởi những loài cây kỳ lạ, phun nước được gọi là Dây Leo Độc. Trong khi những người khác giữ khoảng cách, hắn lại bước lại gần – đủ gần để bị trúng.\nHắn hẳn đã thu được gì đó từ nó.\nNgười bạn của hắn không hiểu. Nhưng có lẽ bạn sẽ hiểu.\nHãy tìm Dây Leo Độc và để một sợi đánh trúng bạn.",
    [2813640287] = "Cúp Danh Năng Lưỡi Hái Sa Ngã Bằng Sắt",
    [2814221324] = "Từ chối",
    [2814577194] = "Mất vật phẩm khi chết",
    [2815296646] = "Đòn chí mạng bằng phép thuật làm choáng mục tiêu trong <b>4</b> giây.",
    [2815311636] = "Thợ rèn",
    [2815383751] = "Trong quá trình nghiên cứu, Nhà giả kim đã phát hiện ra rằng <b>Cổ nhân từng sử dụng đá quý</b> làm nguồn năng lượng tự nhiên để tăng cường sức mạnh. Các viên đá quý có nguồn gốc từ lòng đất và có những đặc tính bí ẩn cho phép chúng bám vào năng lượng xung quanh.\n\nĐể khai thác sức mạnh của một viên đá quý, trước tiên bạn sẽ cần biết vị trí của một <b>Lò Rèn Đá Quý.</b> May mắn thay, Nhà giả kim biết phải tìm ở đâu.\n\n<b>Hãy đến địa điểm</b> được đánh dấu trên bản đồ của bạn để tiếp tục.",
    [2815531011] = "Đạn Băng Vĩnh Cửu I",
    [2816392687] = "Bàn Góc Đá",
    [2816648460] = "Bùa Hộ Mệnh",
    [2818329922] = "Bình Chưng Cất",
    [2818774416] = "Thùng Gỗ",
    [2819741586] = "Cành Củi",
    [2820124884] = "Hầm Mộ",
    [2820215068] = "Thùng Lớn",
    [2820635323] = "Siêu Chất Lượng Cao Cấp",
    [2820705036] = "Scavenger Mẫu Lớn",
    [2820815423] = "Sau khi phân tích những dòng chữ khắc Drak này, phân tích của tôi như sau:\n\n<b>Cấu trúc bộ lạc:</b>\n\n<i>Người Drak hầu như không coi mình là một loài hay một nền văn hóa thống nhất, thay vào đó ưa chuộng các nhóm ngày càng cô lập và bộ lạc mặc dù có chung gốc ngôn ngữ và cấu trúc.\nQua nhiều thế hệ, những sự chia rẽ này đã dẫn đến các kiểu vảy, hình thái màu sắc, biến thể phương ngữ và các tập quán văn hóa độc đáo – đặc biệt là sự ưa thích các thần tượng/hiền nhân/anh hùng chiến tranh khác nhau định hình sự hiểu biết của họ về bản thân, và là tên gọi cho sự biến thể bộ lạc của họ.\nCác bộ lạc tuyên bố chủ quyền đối với các vùng địa lý khác nhau, bị khóa trong một cuộc xung đột lãnh thổ giữa các chủng tộc bất cứ khi nào sự bành trướng của đàn đòi hỏi.\n\nVí dụ, Drak'Dal được đặt tên theo thần tượng của họ, Dalszul, và hiện đang tranh chấp quần đảo ngoài khơi cùng với Drak'Mer; những người theo Merphisz. Cuộc xung đột này dường như bắt đầu sau khi Drak'Dal bị trục xuất khỏi Thung Lũng Veilwater.</i> \n\n<b>Các bộ lạc đáng chú ý khác bao gồm:</b>\n<i>Drak'Ari, những người theo Arisztar\nDrak'Fyr, những người theo Fyraszh</i>",
    [2820943622] = "Túi Độc",
    [2821023462] = "Thùng Gỗ Thông",
    [2821137535] = "Hoàn tác",
    [2821415324] = "Thợ Mộc nhận thấy bạn có kiến thức và phương tiện để chế tạo một <b>phiên bản cải tiến của tàu lượn.</b> Hãy thu thập vật liệu và <b>chế tạo hoặc nhận tàu lượn tiên tiến mới</b> với Thợ Mộc để ổn định chuyến bay của bạn!",
    [2821544209] = "Mũi Tên Ma Thuật",
    [2821556577] = "Đá Vụn",
    [2821855070] = "Bạn có thể nghĩ rằng <i>nữ hoàng <lorename>Jezmina</lorename></i> sẽ đi lại một cách phong cách – có chút đẳng cấp, phải không? Có chút xa hoa? Có chút Elixir, đúng không? KHÔNG GÌ CẢ! Chỉ là... sơn và gối— phù! \n\n<b>Ít nhất tôi đã tìm thấy một <craftingstation>Sổ Tay Thực Vật và Cây Con</craftingstation> trong lều của <lorename>Jezmina</lorename>.</b> Tôi sẽ giả vờ như không có <i>bất kỳ vật phẩm nào khác</i> nếu Simon hỏi. Hy vọng tôi có thể lừa được hắn... hắn tinh mắt lắm.\n\nNgoài <i>kho báu nhỏ riêng của tôi, </i> hầu như không còn gì cho <location>Nơi Nghỉ Ngơi Surat</location>... có lẽ ngoại trừ Trái Cây Yucca Khô. Đừng nói với bà chủ Kendal! Chúng cũng là của tôi!",
    [2821975695] = "Đền Thờ Ngọn lửa của Manathor",
    [2822115012] = "Xây Đền Thờ Ngọn lửa",
    [2822255068] = "Tôi quá mệt mỏi với tất cả những màu tóc nhạt nhẽo này! Tôi muốn tạo ra thứ gì đó rực rỡ hơn và làm cho mọi thứ thú vị hơn, bạn biết đấy? CHỜ ĐÃ! Tôi vừa nói điều gì đó thông minh một cách vô tình! Từ \"gia vị\" đã kích hoạt một nguồn cảm hứng đang ngủ quên trong tôi! Có lẽ một chút trà cay sẽ giúp tôi tỉnh táo?",
    [2822304665] = "Được làm từ rơm và tăng cường bằng hắc ín. Đây là phiên bản cải tiến của Khối Mái Sợi Thực Vật, đặc biệt tốt để bảo vệ khỏi các yếu tố thời tiết.",
    [2822734292] = "Hồ Rồng Mơ",
    [2822796763] = "Ghế Dài Sắt",
    [2822805263] = "Xây Một Đền Thờ Ngọn lửa Khác",
    [2823088160] = "Chỉ huy Fell",
    [2823191212] = "Thật sảng khoái khi được trở về! Bạn là ai? Có lẽ là bạn của Oscar? Ồ, anh ấy chắc hẳn đang lo lắng phát ốm. Cảm ơn bạn đã giải cứu tôi! Tôi nóng lòng muốn duỗi thẳng đôi chân mỏi mệt của mình... có lẽ tôi sẽ đi tìm vài con mèo để vuốt ve. Nghe có vẻ tuyệt vời đấy.",
    [2823543840] = "Nỗi Đau Chia Sẻ",
    [2823585365] = "Chúng tôi hết tất",
    [2823922266] = "Các bánh xe chạy bằng nước được nối với một bộ phận nghiền bên trong một tòa nhà, nhưng bạn không thể lấy cối xay khi máy đang hoạt động.\n\nCó lẽ bạn có thể khai thác sức mạnh của nước và tắt bộ phận đó.\n\n<b>Hãy ngừng dòng chảy nước ở Riverreach gần các bánh xe nước bên ngoài để tắt máy.</b>",
    [2824266034] = "Hỡi Hậu Duệ Lửa, hãy lắng nghe bài hát của ta!",
    [2824376663] = "Đã rõ. Còn gì nữa không, bạn?",
    [2825413525] = "Thăm Địa Điểm Cuối Cùng Được Biết Đến của Anton Godwin",
    [2825630008] = " <npc>Người Sưu Tầm</npc> đã tiết lộ vị trí của Sảnh Đường Hollow trong Revelwood. Để vào, bạn sẽ cần một chiếc chìa khóa.\n\n<b>Hãy chế tạo Chìa khóa với Người Sưu Tầm</b> để tiếp tục.",
    [2826009042] = " <npc>Thợ Mộc</npc> đã giao nhiệm vụ cho bạn khám phá một Giếng Elixir trong Kindlewastes. Hãy xuống Giếng và lấy các Khối Giếng từ vực sâu của nó!",
    [2826320256] = " <npc>Nông Dân</npc> muốn trao đổi một bí mật nhỏ để lấy một ít dâu tây thỏa mãn cơn thèm ngọt của cô ấy. Quả mọng có thể được trồng và thu hoạch thông qua chế tạo tiên tiến, nhưng chúng cũng xuất hiện trong Revelwood.",
    [2826405056] = "Tinh chỉnh vị trí",
    [2826563325] = "<b>Hồi ức của Mae:</b>\n<i>Ngày đầu tiên của mùa xuân khác hẳn những ngày còn lại\nNhững đỉnh núi nằm im lìm, liếm vết thương của mùa đông\nKhi ánh mặt trời lặn ở phía tây xa xôi\nTrên những cánh đồng nơi nụ hoa đang ngủ thức dậy thành đóa </i>",
    [2827307928] = "Tăng cường Elixir",
    [2827579440] = "Vô hiệu hóa Đền Thờ",
    [2827817487] = "Ám khí",
    [2827833203] = "Việc hạ gục con mồi, và thậm chí cả những kẻ săn mồi khác, trở nên dễ dàng hơn với bộ giáp thợ săn được chế tạo tinh xảo này.",
    [2828584092] = "Khối Sang Trọng Trong Trái Tim Đại Dương",
    [2828709508] = "Mặt trăng ban cho bạn một thể chất phi thường sau khi đánh bại kẻ thù",
    [2828805345] = "Màu Tím Cẩm Quỳ",
    [2828935645] = "Một băng quấn cho phép bàn chân cất cánh của bạn đạt được sức mạnh nhảy tối đa. Những lớp bọc nhẹ này giúp bảo vệ lòng bàn chân của bạn khỏi bị tổn thương khi bạn chuẩn bị phóng mình qua không khí!",
    [2829190773] = "Bùng Cháy",
    [2829792414] = "Hỡi Dân Lành, Hãy Nghe Lời Cảnh Báo Này:",
    [2829959579] = "Bộ Pháp Sư",
    [2830542486] = "Đến <location>Thornhold</location>",
    [2830604785] = "Mũ Giáp Thợ Săn Chim",
    [2831169413] = "Loại bỏ hiệu ứng suy giảm Hemotoxin khi sử dụng.\n\nCũng áp dụng một hiệu ứng tăng cường ngăn Hemotoxin ảnh hưởng đến người dùng trong một giờ.",
    [2831993264] = "Pháo Hoa Hoa Giấy Xanh",
    [2832992126] = "Hầm Mộ",
    [2833421901] = "Những mẩu xương cá nhỏ có thể dùng để chế tạo. Chúng có cảm giác giòn trong tay bạn, nhưng chúng sẽ gây đau đớn khủng khiếp nếu mắc trong cổ họng.",
    [2834800836] = "Trang trại này có thể được lấp đầy bằng đất, cát hoặc bùn để trồng cây.",
    [2834898767] = "Múc Nước",
    [2834922961] = "Hãy trồng một hạt giống!",
    [2834927771] = "Tìm Kiếm Manh Mối Ở Orville",
    [2834930758] = "Cây Gừng",
    [2834988069] = "Ghế Băng",
    [2835873951] = "Di Chuyển Nhanh",
    [2836090921] = "Một Ký Ức Về Màu Xanh",
    [2836189083] = "Rơi ra từ Kẻ Rình Rập Sương độc Cao nguyên Du mục",
    [2836216205] = "Rương Lớn",
    [2836284458] = "Người Sống Sót Chưa Được Khám Phá",
    [2836409452] = "Tìm Hiện Vật Hollow Hall Ở Cao Nguyên Du Mục",
    [2836521730] = "Bát Trái Cây",
    [2836670179] = "Lời Hứa Của Hoa Hồng Máu",
    [2836695791] = "Sát Thương Phục Kích",
    [2837068906] = "Elias —\n\nXin lưu ý rằng các thùng hàng được đánh dấu <b>\"Vật tư Vườn ươm\"</b> thực sự chứa đầy vũ khí cho <b>quân đội nổi dậy của Nhà Thầu.</b> Lính canh đang bám sát gót chúng ta. <b>Tôi đã chôn hàng hóa và đánh dấu địa điểm.</b> Không thể mạo hiểm bất cứ điều gì trong những ngày này.\n\nMột số trong số chúng được đóng gói với thuốc nổ mạnh, vì vậy hãy xử lý hết sức cẩn thận! Chúng ta không muốn tiết lộ chỗ ẩn náu của mình!\n\n<i>Giữ im lặng, được chứ? Chúng ta có thể mất đầu vì chuyện này!</i>\n\n— Benni",
    [2837485249] = "Tác Động Thiên Thạch sẽ kích hoạt khi bạn hạ cánh, tạo ra một vụ nổ nhỏ và truyền thêm sát thương <b>Lửa</b> vào các đòn tấn công của bạn.",
    [2837495747] = "Khối Đá Vôi Vỏ Sò",
    [2838312152] = "Chi phí:",
    [2838411967] = "Một loại cây trồng rất đa năng có thể phơi khô, nướng hoặc ăn sống, giúp người tiêu dùng khỏe mạnh trong một thời gian ngắn.",
    [2840549320] = "Chân Vịt",
    [2840557939] = "Một chiếc rìu 1H, vật gia truyền của gia tộc Dimweald. Vũ khí này thuộc về Lando, con thứ. Anh ấy đã trung thành cho đến cùng.",
    [2840893006] = "Băng Đô Trò Chơi Mùa Hè",
    [2841083014] = "Tăng sát thương lên kẻ địch cận chiến.",
    [2841245498] = "<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [2841466159] = "Sách II",
    [2841589608] = "Khi tiêu diệt kẻ địch bằng vũ khí tầm xa, bạn tạo ra một bản sao của chính mình với 1 điểm HP. Bản sao sẽ không tấn công hay di chuyển, nhưng kẻ địch sẽ tấn công nó.",
    [2841732649] = "Một vật liệu đường làm từ đá nhẵn. Đi trên đó là một niềm vui.",
    [2841845483] = "Một món súp thịnh soạn, kem được làm từ những miếng cá mềm và rau tươi.",
    [2841873313] = "Này, nhóc! Bức thư chúng ta đã nói ấy — cậu có xem qua nó chưa?",
    [2841884903] = "Gây sát thương cho kẻ địch bằng Đũa phép có <b>24%</b> cơ hội hồi phục <b>4%</b> Lượng MP tối đa của bạn.",
    [2842003369] = "Giày Thiện Xạ",
    [2843068578] = "Tăng 100 HP.",
    [2843832707] = " Cơ Hội Chí Mạng Với Kẻ Địch Bị Ướt",
    [2844027410] = "Người Sưu Tầm, Phục Vụ Quý Khách",
    [2844170804] = "Nơi Trú Ẩn",
    [2844239553] = "Một khối xây dựng được làm từ những cành cây đan chặt. Nó được sử dụng bên trong các tòa nhà của Vukah.",
    [2844869542] = "<b>Con nhộng đồng hồ cát</b> này sẽ bổ sung lượng <b>Thời gian trong Sương độc</b> còn lại của bạn. Nó sẽ bị tiêu hao khi sử dụng và không thể cất giữ trong hành trang.",
    [2844997178] = "Kẻ Sâu Bọ Sương độc",
    [2845057367] = "Một nguyên liệu giàu protein được tạo ra từ vỏ sinh vật bị nghiền nát.",
    [2845405453] = "Hãy xem chúng ta có thể dùng gì để chế tạo một lọ thuốc. Có lẽ là tảo, có thể là nụ hoa — ồ, một chút muối hoặc một chút nấm có thể làm tăng hương vị. Khoan đã, giờ tôi lại nghĩ đến đồ ăn, không phải thuốc...",
    [2845522054] = "Một chiếc áo khoác màu xanh lam với viền trắng tuyết mềm mại để giữ ấm. Bộ lông nhẹ và sẽ không làm bạn nặng nề khi leo lên đỉnh núi để tìm điểm quan sát.",
    [2845730271] = "Một cây cung hùng mạnh, được truyền sức mạnh của Ngọn Lửa. Những mũi tên của nó trút xuống thế giới như những tàn tro rơi rụng.",
    [2846185848] = "Aye, cảm giác như ngươi đã kéo ta ra khỏi hàm của vực sâu! Ngươi lẽ ra nên thấy con cá ta đang câu — to như cá voi! Con đó đã chiến đấu dữ dội, đưa nó lên bờ suýt chút nữa đã làm tim già này ngừng đập! Nhưng không sao! Ta là Thuyền trưởng Melville Fontane! Ta sẽ vui lòng tặng ngươi cá hồi và chuyện kể — chỉ với một đồng xu!",
    [2846611717] = "Bộ Đồ Cố Vấn Ngọc Băng",
    [2846698570] = "Cây chùy này có thể đối phó với đám đông kẻ thù, không bao giờ nao núng.",
    [2847193869] = "Chỉ dùng cho mục đích trang trí",
    [2848052855] = "Một cặp Tuyến nhờn. \n\n<b>Nguyên liệu Chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Sinh vật Fell, ban đầu tìm thấy ở Cao nguyên Du mục.",
    [2848130499] = "Bồn Rửa Tiệm Salon",
    [2848157446] = "Quần Mặc Nhà Ngày Nắng",
    [2848765707] = "Tôi từng làm trong ngành hậu cần, bạn biết đấy? Chúng tôi điều phối các lô hàng quần áo và vật liệu, nhưng trong một thời gian, chúng tôi thậm chí còn dự trữ giày ướt — Loại giày bạn câu được khi không may mắn. Tại sao...? Chà, chúng rẻ, nên tôi nghĩ... Thôi bỏ đi. Người bán hàng của chúng tôi, một ngư dân từ <location>Pondsworth</location>, có rất nhiều thứ đó. Và cả những kho báu lấp lánh. Những mẻ lưới của ông ấy luôn là \"tất cả hoặc không có gì\"... Tôi tự hỏi tại sao.",
    [2848884960] = "Tàn nhẫn",
    [2848928326] = "Điều tra Điểm thứ hai trên Tuyến đường Vận chuyển",
    [2849610173] = "Một vật phẩm trang trí, sẽ cung cấp sự ấm áp và ánh sáng trong phạm vi của nó.\n\nCung cấp <b>sự thoải mái</b> giúp tăng thời gian của Phần thưởng Nghỉ ngơi.",
    [2849876570] = "Địa hình",
    [2850636687] = "Nhật ký số 02\nLần cho ăn cuối: /\nLưu ý: Giờ đã gầy. Đừng quên cho ăn lại.",
    [2851603368] = "Một thanh kiếm cùn, được thiết kế để mở đường. Đặc biệt là xuyên qua hàng ngũ kẻ thù.",
    [2851936628] = "Rào Chắn Tre IV",
    [2852578284] = "Chi phí SP",
    [2852613187] = "Sát thương <b>Chiêu thức</b> tăng thêm <b>20%</b>.\n\n<b>Chiêu thức</b>\nĐánh trúng điểm yếu của kẻ địch, như đầu hoặc tim lộ ra, được coi là Chiêu thức.",
    [2852641969] = "Bạn đã biết rằng một trận chiến lớn đã diễn ra tại Cầu Cổ trong Rừng Rừng. Hãy khám phá khu vực và xem những loại của cải nào nằm trong Sương độc!",
    [2853303141] = "<b>Nghề nghiệp:</b> Công nhân Xây dựng\n\n<b>Nơi cư trú:</b> Công trường Xây dựng \"Maelstrom\"\n\n<b>Tiền sử bệnh:</b> Mất cân bằng thể dịch với lượng mật vàng bất thường.\nKết quả: Nóng nảy.\n\n<b>Sự cố:</b> Tuyên bố rằng anh ta bị \"say mê\" bởi một ánh sáng ảo ảnh khi đang vận chuyển gạch. \"Sự sáng chói\" đã chiếm lấy anh ta và khiến anh ta mất kiểm soát các chức năng cơ thể. Đánh rơi gạch qua lan can, làm hai giám sát viên bị thương nặng. Flint ban đầu bất động do các cơn co giật không kiểm soát được.\n\n<b>Ghi chú của Bác sĩ:</b> <i>Anh ta bị cắt khẩu phần ăn vài ngày trước, và không quan sát thấy co giật cơ bắp khi bệnh nhân được chăm sóc. Điều đáng chú ý duy nhất là sự co giật nhịp nhàng của mắt trái, màu xanh lam sáng bất thường. Liệu anh ta có đang giả vờ không? Tôi nghiêng về việc chuyển vụ việc cho cơ quan chức năng. *</i>\n\n*Chú thích! <i>Bệnh nhân tuyên bố rằng \"sự sáng chói\" đã quay trở lại trong một lần kiểm tra, và bị co giật nhiều lần sau đó. Thời gian của các cơn động kinh: 1 phút, 1 phút nữa, 2 phút, 3 phút, 5 phút, 8 phút và cuối cùng là khoảng 13 phút. Bệnh nhân rỉ mật vàng từ các lỗ tự nhiên.</i>",
    [2853642548] = "Lời Nguyền Chôn Giấu",
    [2853755751] = "Đứng thẳng lên, ngươi đang nói chuyện với một hiệp sĩ — Một ngọn hải đăng hy vọng trong bộ giáp sáng ngời, kẻ trục xuất kẻ thù vào bóng tối! ...Vâng, ta vẫn đang tập luyện, nhưng tất cả những gì quan trọng trên chiến trường là lòng dũng cảm và kỹ năng, không phải cấp bậc! Luật lệ của thế giới cũ đã chết từ lâu, và cả danh hiệu lẫn tài năng cũng không thể ra lệnh cho xác sống ở yên. Hãy lấy Vết Nhơ của <location>Brightwich</location>, chẳng hạn. Bị đánh bại, nhưng chưa bao giờ bị trục xuất. Lưỡi kiếm của ta không thể kết liễu chúng — có lẽ lưỡi kiếm của ngươi sẽ làm được?",
    [2854108614] = "Tia Hồi Máu",
    [2854482103] = "Điềm lành đã hóa tro tàn. Ánh sáng trở thành lời dối trá, không phải lời hứa. Thứ từng là dấu hiệu của may mắn đã bị dập tắt bởi một lần chạm trán định mệnh. Vinh quang của <lorename>Pikemead</lorename> đã được phục hồi.\n\nThu thập nhiều Đầu Rồng Sương độc Fell để chế tạo Tượng Sắt.",
    [2855098573] = "Nói nhanh. Và nhỏ tiếng.",
    [2855674236] = "Ảo Ảnh",
    [2856083398] = "Bia Mộ \"Luôn Được Yêu Thương\"",
    [2856739826] = "Thịt Nấm Bạc Hà",
    [2857006190] = "Hồi phục MP",
    [2857046514] = "Đến Đền Drak",
    [2857654331] = "Tăng thêm cơ hội chí mạng cho vũ khí tầm xa.",
    [2858243402] = "Bảo vệ bổ sung chống lại phép thuật hệ lửa, ngoài khả năng kháng phép nói chung.",
    [2858518618] = "Ghi chú Việc nhỏ cần làm",
    [2858736158] = "Tìm bảng màu vẽ mặt",
    [2860462039] = "Xã hội",
    [2860796888] = "Một chiếc mũ bảo hiểm nặng, được trang trí bằng sừng bò uy nghiêm và một mào cao, vươn xa. Tấm che mặt chỉ để lại chỗ cho mắt, cho phép sự tức giận đỏ rực của người đội tỏa ra bên ngoài.",
    [2860796903] = "Ngọc Ánh Sáng Tập Trung",
    [2861577748] = "Ngọn Lửa",
    [2861773478] = "Đây là một thiết lập cân bằng và được khuyến nghị là trải nghiệm đầu tiên cho hầu hết người chơi. Số lượng và độ khó của kẻ địch đầy thử thách nhưng không quá sức.",
    [2863019681] = "Chiêu thức hồi phục 10 SP",
    [2863177604] = "Tàng hình",
    [2863273687] = "ST Cận chiến 1H",
    [2863282906] = "Một công cụ nguyên thủy dùng để cắt gỗ. Nó cũng có thể được sử dụng như một vũ khí trong trường hợp khẩn cấp.",
    [2863439979] = "Hạt Giống Vinh Quang!",
    [2863632364] = "Một chiếc máy tiện dụng pha cà phê nóng. Thế giới này vẫn còn hy vọng sau tất cả.",
    [2863905010] = "Thuốc Tiên tăng cường khả năng của bạn và mang lại cho bạn Sát thương bổ sung chống lại Sinh vật Fell.",
    [2864118403] = "Xương trong Cát",
    [2864185621] = "Thu nhỏ",
    [2864203559] = "Cây và bụi sẽ cho bạn thêm một tài nguyên.",
    [2864555399] = "Nói chuyện với <npc>Thợ Rèn</npc>",
    [2864858739] = "<location>Pháo đài Kelvin</location>",
    [2864946325] = "Đừng bao giờ cố gắng, chỉ cần lấy một cái búa lớn hơn!",
    [2865071673] = " <npc>Nông dân</npc> nói rằng <lorename>Ikora</lorename> từng cư trú tại <b><location>Rattlebleak</location>,</b> một thị trấn ở Cao nguyên Du mục. Có lẽ <b><craftingstation>Nồi Hắc Ám</craftingstation></b> có thể tìm thấy tại cửa hàng của bà ấy.",
    [2865709975] = "Mái Gable Trung bình",
    [2865905267] = "Gói Tài Nguyên II",
    [2865961134] = "Giáp thân trên mạo hiểm nhưng nhanh nhẹn. Ít nhất vai của bạn sẽ an toàn khỏi bị tổn hại với những tấm giáp vai ấn tượng này!",
    [2867206249] = "Cúp Danh Năng Lưỡi Hái Sa Ngã Bằng Đồng",
    [2867365441] = "Muốn nghe một câu chuyện cười không? \"<npc>Thợ Mộc</npc> không có <craftingstation>Dụng cụ Xây Đá</craftingstation>\". Đó là tất cả, đó là câu chuyện cười. Tôi là một trò hề! Một kẻ giả mạo! Tôi cần những dụng cụ phù hợp, nhưng <npc>Thợ Rèn</npc> sẽ không cho tôi mượn của ông ta. Thật nực cười! Tuy nhiên, tôi biết nơi để lấy một ít <craftingstation>Dụng cụ Xây Đá</craftingstation> — Khu nghiên cứu tại \"Trụ cột Sáng tạo\" có quen thuộc với bạn không?",
    [2867419146] = "Cây Giống Cây Thân Mảnh Cao Nguyên Du Mục",
    [2867872794] = "Mệt mỏi",
    [2868507806] = "Khiên Phép Thuật",
    [2868782520] = "Hồi Máu Liên Chuyền II",
    [2868964086] = "Tìm Nhẫn của Nông dân",
    [2869348610] = "Quần tối màu với đường viền vàng. Chúng ấm áp và thoải mái.",
    [2869368360] = "Mảnh vỡ của một tấm bản đồ kho báu bị xé, tìm thấy trên bộ xương rồng ở Đỉnh Albaneve. Có lẽ bạn có thể ghép lại bản đồ nếu tìm thấy tất cả các mảnh?\n\nMặt sau có chữ:",
    [2869884389] = "<lorename>Raúl</lorename>",
    [2870524401] = "Một chiếc mũ trang trọng với vành gấp lại. Mặt trước được trang trí bằng một chi tiết kim loại nhỏ.",
    [2871004842] = "Khoác Lên Sự Đố Kỵ",
    [2871506345] = "Ôi, trời ơi! Bạn đã tìm thấy một <keyitem>Ấm đun nước</keyitem>! Và nó trông giống hệt cái cũ của tôi... ừm, thật kỳ lạ. Chúng ta hãy chế tạo một <craftingstation>Bếp Nấu</craftingstation> và sử dụng nó!",
    [2871553776] = "Còn nữa không?",
    [2871620214] = "Đầu Lưỡi Hái Sa Ngã",
    [2871736644] = "Máu tím. Nó lạnh lẽo, và độ đặc hơi giống siro.",
    [2871935027] = "Sử dụng Lưới Rộng",
    [2872215072] = "Ít người còn sót lại",
    [2872529593] = "Truyền thuyết kể rằng những chiếc găng tay này từng thuộc về một vị vua bóng tối mà tên tuổi đã bị xóa khỏi sách lịch sử.",
    [2872832249] = "Móc Nối Đất",
    [2873114532] = "Nôi Núi",
    [2873181687] = "ST Cận chiến 1H",
    [2873484443] = "Cú Vồ của Móng Vuốt",
    [2874292931] = "Vị trí <keyitem>Lưỡi Cưa Tròn</keyitem>",
    [2874382955] = "Thợ cắt tóc yêu cầu bạn mang cho ông ta <b>đá lạnh</b> từ Đỉnh Albaneve để \"làm mới\" ông ta. Mang vật liệu từ núi cho ông ta có thể truyền cảm hứng để ông ta tạo ra các màu tóc mới.\n\nMang cho Thợ cắt tóc <b>đá lạnh!</b>",
    [2874474241] = "Bạn trao đổi. Tôi lắng nghe.",
    [2874536055] = "Găng Tay Học Giả Ngọn Lửa Trẻ",
    [2874709223] = "À, thật vui khi gặp bạn! Nghe này — Tôi rất muốn nấu ăn cho đội của chúng ta, nâng cao tinh thần. Một <b><craftingstation>Bếp Nấu</craftingstation> với một <keyitem>Ấm đun nước</keyitem></b> sẽ giúp ích, nhưng tôi đã đưa cái của mình cho một người bạn khi đoàn xe của chúng tôi chia tách. Anh ấy đang đi đến <location><lorename>Vùng Đất Của Pikemead</lorename></location>. Có lẽ chúng ta có thể xin lại nó? Hãy gửi lời chào đến <lorename>Raúl</lorename> cho tôi khi bạn ở đó, làm ơn!",
    [2875409078] = "Tôi luôn yêu thích chim chóc. Chúng lướt đi trong gió thật dễ dàng.\nĐể ôm lấy chân trời trong những thời điểm khó khăn này... Để khám phá bất cứ điều gì bạn đang tìm kiếm, thoát khỏi mọi sự mục nát đang lan tràn bên dưới. Một hành trình tuyệt vời như vậy.\n\nCó lẽ con người có thể chinh phục bầu trời bằng phát minh? Tôi sẽ chế tạo một <b>Máy Lượn</b> và du hành đến những ngọn đồi từ đây. Bằng cách này hay cách khác, tôi sẽ hạ cánh giữa những con chim xanh.",
    [2876011035] = "Cây đũa phép này ban cho sức mạnh băng giá cho bất kỳ ai đủ dũng cảm để sử dụng nó.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.",
    [2876053411] = "Khoảng thời gian trì hoãn trước khi khả năng hồi phục bắt đầu hoạt động.",
    [2876087240] = "Dâng một lời cầu nguyện nhỏ lên Ngọn Lửa, điều này sẽ tăng ST Phép thuật và thời gian tối đa trong Sương độc trong một thời gian ngắn.",
    [2876129962] = "Tháp Canh Nhỏ",
    [2876134097] = "Hồi sinh bằng Chữa thương",
    [2876154304] = "Một tấm biển đứng mà bạn có thể viết lên.",
    [2876536124] = "Trường Nhìn",
    [2877172064] = "Săn tìm màu tóc: Nước Lấp Lánh",
    [2877410439] = "Băng",
    [2877835494] = "Bảng màu này pha trộn giữa cam dịu, tím hoa cà mềm mại và nâu đất tạo nên một bảng màu vừa cổ kính vừa duyên dáng — như hơi ấm được lưu giữ trong ánh sáng phai tàn.\n\nBảng màu này có thể được tạo ra từ vật liệu ở Bồn Địa Nước Màn.",
    [2877875559] = "Máy chủ đã chọn",
    [2878319804] = "Sâu thẳm của ngôi mộ bị lãng quên đã bị Sương độc bao phủ. Lũ Fell đang hủy diệt nơi ghi nhớ này! \n\n<b>Tìm nguồn gốc</b> của sự bùng phát và <b>chống trả nó!</b>",
    [2878621946] = "Tiếng vo ve trong tường",
    [2878653045] = "Trống Tay Tuyệt Hảo",
    [2879497984] = "Không đủ bộ nhớ hệ thống.",
    [2879519721] = "Con Mắt Hủy Diệt",
    [2879995263] = "Ăn khớp hoàn hảo với phần còn lại của trang phục, đôi giày này sẽ không để bất cứ điều gì cản đường bạn đến mục tiêu.",
    [2880901464] = "<lorename>Dwyn Trẻ</lorename>",
    [2880944072] = "<i><b>Một chiếc ở bên trái,</b> dành cho người lớn tuổi nhất và cao quý nhất.\nMỏ chim đại bàng\nXé toạc <b>mây cao</b> và da thịt,\nMáu nhuộm tuyết khi máu thịt tương tàn.\n\nĐi <b>bên phải</b> để tìm người trẻ nhất, con của cây đàn lia.\nMột giọng ca truyền cảm hứng,\n<b>vượt qua biển tuyệt vọng</b>\nvà tìm thấy trái tim đại dương ở đó.\n\n<b>Bên trong phòng chính,</b> dọc theo xương sống, nhức nhối.\n<b>Một ở trên, một ở dưới,</b> cả hai đều ẩn giấu, chờ đợi.</i>",
    [2881606954] = "Khi được cắm vào đất nông trại bị nhiễm Sương độc, cây con này có thể phát triển thành một Kẻ Hút Sương độc.\n\n<b>Nguồn gốc</b>: Rơi ra từ Kẻ Hút Sương độc, lần đầu tiên được tìm thấy ở Cao Nguyên Du Mục.",
    [2881822066] = "Nó có vị hơi đắng, nhưng được biết là làm tăng MP, khả năng hồi MP và ST Phép. Thật là một món súp ma thuật!",
    [2882017743] = "Máy cho chó ăn",
    [2882113908] = "Chọn Máy Chủ",
    [2882136423] = "Đỏ - màu của Ngọn lửa, phù hợp với Huyết Ngọn lửa!",
    [2882222719] = "Một phiên bản cải tiến của Mũi Tên Băng Vĩnh Cửu ban đầu.\n\n<b>Mũi Tên Vĩnh Cửu:</b> Mũi tên vĩnh cửu <b>không bị hao hụt.</b> Trang bị mũi tên vĩnh cửu và sử dụng <b>MP</b> để bắn nó bằng <b>cung.</b>",
    [2882315040] = "Khe Hình Dạng Tòa Nhà 8",
    [2883163889] = "Bạn đã khám phá ra truyền thuyết về Kẻ Săn Lùng Nhân Ngư! Hãy đi theo con đường của họ và lặn xuống dưới mặt nước để nhận được một bộ trang phục độc đáo!\n\nCác món đồ của Kẻ Săn Lùng Nhân Ngư có thể được tìm thấy ở các vùng nước nổi bật trong Bồn Địa Nước Màn. Hãy cân nhắc ghé thăm các khu vực sau:\nHồ Rồng Mơ, \nHồ Máu Trái Tim, \nBờ Biển Sao Biển, Suối Nước Nóng Cromville, và\nĐầm Phá Nhỏ.",
    [2883593511] = "Áo Giáp Kẻ Mang Dịch Bệnh",
    [2883855892] = "Hoang vắng",
    [2884206372] = "\"Phong Cảnh Đền Thờ\"",
    [2884230594] = "CHN",
    [2884745195] = "Đừng để hình ảnh đánh lừa bạn. Trông nó có thể giống một cây chùy, nhưng thực chất nó chỉ là một cây gậy nguyên thủy.",
    [2885948940] = "Bắt được rồi!",
    [2886237738] = "Bộ Omen",
    [2886272479] = "Một kim loại bạc lấp lánh có nhiều ứng dụng.",
    [2886677882] = "HP",
    [2886920785] = "Hydrak'Dal",
    [2887002222] = "Gợi ý bạn tìm thấy đã tiết lộ vị trí của các mảnh tượng. Tượng của Nữ hoàng quá cố <lorename>Pikemead</lorename> đã bị ném xuống nước gần bến cảng, nhưng một vài mảnh đã được cứu.\n\nCó lẽ các mảnh ghép có thể được thu hồi và lắp ráp lại. Hãy đến bến cảng và tìm kiếm một trong những mảnh ghép được cất giấu!",
    [2887149314] = "Phải",
    [2887971667] = "Khi bóng tối buông xuống, hoa lạc tiên bắt đầu nở. Trong đêm, những cánh hoa của chúng có thể chuyển sang màu hồng dịu, gần như tím, trong khi nhụy hoa tiếp tục phát sáng rực rỡ.\n\nBảng màu này có thể được tạo ra từ vật liệu ở Bồn Địa Nước Màn.",
    [2888106111] = "Chuyện này không lành chút nào",
    [2888165526] = "Bị Nguyền Rủa Bởi Sương độc",
    [2888538142] = "Một cây cung được chế tác để giống với những con thú có sừng ở Đỉnh Albaneve. Nó tạo nên một hình bóng đáng sợ.",
    [2888621285] = "Một giải pháp y tế để ngăn ngừa nhiễm trùng vết thương. Trong số những thứ khác, nó có thể được sử dụng để khử trùng băng gạc.",
    [2888645422] = "Sử dụng <b>Móc Leo Núi</b> của bạn để kéo kẻ địch có kích thước thông thường về phía bạn trong chiến đấu.\n\n<b>Chi phí:</b> 50 SP (tỷ lệ với cấp độ kẻ địch)",
    [2888750945] = "Độ bền tối đa",
    [2889134434] = "Hãy đến Mỏ Rạn Nứt để tìm <b>vật liệu xây dựng</b> mới ở đó. Bạn sẽ mở khóa thêm các khối cho căn cứ của mình!",
    [2889727860] = "Giả Kim Thuật Mạnh Mẽ",
    [2889990305] = "Một cho vinh quang, một cho băng giá, một để thống trị, và một cho sự sống",
    [2890409464] = "Chặn / Đỡ đòn",
    [2891013073] = "Một cây đũa phép tập trung sức mạnh của người sử dụng thông qua một tinh thể băng giá. Năng lượng ma thuật được khúc xạ bên trong và khuếch đại với mỗi lần phản xạ.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên tới phần trăm <i>quá tải</i>.",
    [2892350782] = "Đài Lửa Sa Thạch",
    [2892839613] = "Linh Thể Cường Hóa",
    [2893709974] = "Chứa Dịch Sương độc đã được thanh lọc, tăng cường khả năng kháng cự của người dùng.\n\nPhải uống trước khi vào Sương độc. Kéo dài Thời gian trong Sương độc thêm 4 phút. Hiệu ứng này sẽ kéo dài trong 45 phút.",
    [2893733350] = "Đòn tấn công tiếp theo của bạn gây thêm ST Đập và đẩy lùi kẻ địch.",
    [2894028855] = "Nâng cấp Vũ khí",
    [2894114632] = "Sau một đòn Chí mạng bằng Dao găm, sát thương của đòn tấn công Cung tiếp theo của bạn được tăng thêm <b>50%</b>.",
    [2894532070] = "Sắp xếp Kho đồ",
    [2894595037] = "Hoa Địa Lan Trắng",
    [2895403254] = "Một vũ khí từng nguyên sơ. Giờ đã mục nát nhưng vẫn chết chóc như xưa.",
    [2895780969] = "Những Lời Thì Thầm Của Nhà Giả Kim",
    [2896044416] = "- \"Drak Slurp\"\n<i>Cổ điển. Tảo xay nhuyễn trong nước cốt dừa hoặc sữa.</i>\n\n- \"Glorb Sizzle\"\n<i>Nước bùn sủi bọt được làm giàu với gừng và một bất ngờ giun!</i>\n\n- \"Sweet Sting\"\n<i>Sữa chuối và mật ong. Phủ trên cùng là một món ăn vặt giòn tan từ ong.</i>\n\n- Nước dừa (nguyên chất)\n<i>... với một chiếc ô nhỏ!</i>\n\n- Nước\n<i>Có ga, lũ mọi rợ!</i>\n\nĐối với ĐỒ ĂN VẶT, chúng ta có:\n- Nhiều giun hơn (sống)\n- Nhiều ong nướng giòn hơn (chết)\n- Trứng ấp dở (bạn tự phán xét)\n",
    [2896055423] = "Tham gia trò chơi thất bại. Không tìm thấy trò chơi.",
    [2896293270] = "Người tôi chôn cất không còn là cha tôi nữa. Ông ấy đã thay đổi, bị mê hoặc và biến chất bởi một thanh kiếm từ các vì sao lẽ ra không bao giờ rơi vào tay ông.\n\nÔng ấy tìm thấy nó khi tôi còn là một đứa trẻ. Sau đó, tôi thấy ông ấy còng lưng trên những tờ giấy xáo trộn mỗi đêm. Mái tóc dài, thưa thớt của ông ấy che phủ khuôn mặt bằng những sợi tóc nhờn, rủ xuống đùi, nơi ông ấy ôm lấy lưỡi kiếm. Trong mắt tôi, chiếc cổ vẹo vọ của ông ấy khiến ông ấy trông giống như một cây liễu rủ.\nÔng ấy thậm chí còn không quay lại để nhìn tôi. <i>\"Nói cho ta biết, đứa trẻ, song sinh của ngươi đâu?\"</i> Ông ấy lẩm bẩm với thanh đoản kiếm. <i>\"Lại đây, làm cho ta trọn vẹn một lần nữa.\"</i>\n\nBây giờ, nhiều năm sau, tôi cũng còng lưng trên bàn làm việc của mình như cha tôi từng làm. Ước nguyện cuối cùng của ông ấy là được chôn cất cùng thanh kiếm của mình. Tôi đã làm theo. Tôi đã làm đúng chứ? Ông ấy không chết vì lưỡi kiếm, nhưng thanh kiếm đó đã lấy đi mạng sống của ông ấy...",
    [2896588851] = "Thử thách Giếng Tiên Dược",
    [2896854837] = "Ngọn lửa của Bàn Thờ Lửa này sẽ bị dập tắt, cho phép Bàn Thờ được gỡ bỏ.",
    [2896932278] = "Phá vỡ Khóa Mục tiêu khi Giết",
    [2897073815] = "Đột phá",
    [2897276538] = "Trang trại Fenrig",
    [2897786119] = "Huyết Lửa, khí hậu ở đây vẫn còn mới mẻ với ta. Những đụn cát của Kindlewastes từng là nhà của ta. Ta tự hỏi điều gì có thể nở rộ ở đây! Với một <craftingstation>Sổ Tay Thực Vật và Cây Con</craftingstation>, chúng ta có thể <b>trồng những vụ mùa mới tuyệt vời!</b> Ta đã để quên nó ở một <b>trại khi đoàn xe của ta chạy trốn khỏi nguy hiểm.</b> Bạn có thể mang nó về cho ta được không, làm ơn?",
    [2898006559] = "Di chuyển xuống",
    [2898201259] = "Kho đồ: Xã hội",
    [2898811024] = "mailto:dsb@keengames.com",
    [2899417006] = "Đừng ngại ngùng.",
    [2899632484] = "Bỏ qua người chơi",
    [2900048157] = "Giường Tầng Cây Cọ",
    [2900488610] = "Lối đi Hang Cyclops",
    [2900495486] = "Bạn đã đến <location>Brightwich</location>, nhưng không có dấu hiệu của kẻ thù.\n\nHãy nhìn xung quanh để tìm <b>manh mối</b> xem kẻ thù đang ẩn náu ở đâu!",
    [2901656435] = "Cơn sốt đường",
    [2902119825] = "Kiếm Đôi Rực Lửa Nhỏ",
    [2902786347] = "Tiếng Vọng Của Thiên Đường Bị Lãng Quên",
    [2902992352] = "Cấp Độ Nhân Vật",
    [2903152667] = "Tăng ST Đánh lén",
    [2903259470] = "Giàn Giáo II",
    [2903331926] = "Độ trễ Tái tạo Nhiệt cơ thể",
    [2904276781] = "Một con thú nhồi bông, cho tôi ư?",
    [2904364086] = "Cặp dao găm này được trang trí bằng chi tiết đầu sói, tượng trưng cho đòn tấn công hung tợn của nó.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [2904930035] = "Đất Nóng Cao Nguyên Du Mục",
    [2905976905] = "Tạm biệt.",
    [2906909107] = "Đến Đền Thờ Cao Nguyên Du Mục",
    [2907272595] = "Giết một kẻ địch khi không có Hollow không giáp trụ đồng minh nào còn sống có cơ hội sinh ra một Hollow không giáp trụ đồng minh cấp %k.",
    [2907516584] = "Ghi chú Cuộc thi Lượn",
    [2907836509] = "Những ý tưởng của ta lại trôi tuột khỏi tầm tay... liệu ngươi có thể giúp ta nắm bắt nguồn cảm hứng không?",
    [2907871704] = "Chiếc quần được giữ với nhau một cách trang nhã bằng đường chỉ và chỉ khâu màu xanh coban. Màu sắc tượng trưng cho sự tinh tế và ưu việt của trí tuệ.",
    [2908443514] = "Được khai thác trong Hầm Mộ Hollow",
    [2908610473] = "Nhật ký Thám hiểm #1",
    [2908697173] = "Lô hàng cho <npc>Thợ Rèn</npc> đã không đến được Trạm Giao dịch \"Đá Rực Lửa\". Người ta cho rằng những người vận chuyển, nhà Conway, đã đi qua Hầm Hollow Umber để tiết kiệm thời gian.",
    [2908948740] = "Bạn không thể tham gia vì không có chỗ trống nào cho nhóm người dùng của bạn.",
    [2909239782] = "Cái <craftingstation>Cối Giã</craftingstation> của ta, đúng vậy! Làm tốt lắm, bạn của ta! Hãy xem chúng ta có thể chế tạo gì với nó!",
    [2909481568] = "Tìm kiếm Công cụ để Bơi Nhanh hơn",
    [2909740585] = "Nó bò dưới da thịt ta",
    [2910115563] = "Chúng ta có gì ở đây? Một bức thư <i>thật</i> mà ngươi tìm thấy, gửi cho ta? ...Rochelle? Cảm ơn ngươi, Huyết Lửa. Ta sẽ trân trọng điều này. Luôn luôn.",
    [2910430722] = "Nói chuyện với những người sống sót",
    [2910639868] = "Mảnh bản đồ kho báu bị xé, tìm thấy trên bộ xương rồng ở Đỉnh Albaneve. Có lẽ bạn có thể tái tạo bản đồ nếu tìm thấy tất cả các mảnh?\n\nCó chữ viết ở mặt sau:\n\n<b>Hồi ức của Mae:</b>\n<i>Ngày đầu tiên của mùa xuân không giống những ngày khác\nNhững đỉnh núi nằm yên tĩnh, liếm vết thương của mùa đông\nKhi ánh nắng mặt trời lặn ở phía tây xa xôi\nTrên những cánh đồng nơi những nụ hoa đang ngủ thức dậy nở rộ</i>",
    [2911042256] = "Đài Lửa Bạc Nhỏ",
    [2911057453] = "Cá Phi Lê Áp Chảo",
    [2911403422] = "Đánh bại Kẻ Thù của <location>Brightwich</location>",
    [2911954144] = "Khám phá Ngôi nhà Cũ của Hannah Reed",
    [2912204345] = "Không ai có thể vượt qua bạn khi bạn mang đôi ủng vững chắc này.",
    [2912545042] = "Pháo Hoa Hoa Giấy Vàng",
    [2913032039] = "Sir Lancehart: \n<i>Hỡi Lush yêu quý, bộ cải trang này sẽ phục vụ khanh thật tốt. Lớp vỏ ngoài của con người che giấu vảy xanh ngọc của khanh — với nó, mọi người sẽ thấy khanh như một cô gái chăn bò bình thường! Chỉ ta mới biết sự thật về trái tim thuần khiết và đường cong quyến rũ của khanh!</i>\n\nLush'Kyss: \n<i>Khanh muốn rời khỏi tán lá cùng nhau, sống không bị ràng buộc bởi hận thù và định kiến... nhưng tấm vải này dệt nên từ những lời dối trá! Sẽ không ai chấp nhận ta khi ta che giấu những ham muốn sâu kín nhất của mình!</i>\n\nSir Lancehart:\n<i>Đừng vứt bỏ bộ cải trang của khanh, Lush'Kyss! Chúng ta đã đi quá xa khỏi lùm cây rồi! Nói xem, khanh sẽ chịu đựng thế nào khi ánh mắt kẻ lạ chạm vào bông hoa của khanh?</i>\n\nLush'Kyss: \n<i>Vậy thì họ có thể chiêm ngưỡng sự thần thánh của nó! Những lớp vỏ này là xiềng xích ta phải phá vỡ để thoát khỏi sự xấu hổ! Hãy nhìn móng vuốt của ta lướt trên ngực run rẩy của ta, không hề che giấu! Ôi, làm sao ta có thể giấu đi một trái tim đập loạn nhịp như thế này, người yêu dấu của ta? Mỗi nhịp đập thôi thúc ta tiến về phía trước và vào vòng tay của khanh! Hãy đến, xoa dịu cơn thèm khát của ta như khanh đã làm bên bờ sông bạc!</i>\n\nSir Lancehart:\n<i>Vườn hoa của khanh đã nở rộ, em yêu! Ôi, lửa thiêu đốt ta! Ta phải làm ướt đôi môi bằng mật ngọt của em để dập tắt cơn khát!</i>\n\nLush'Kyss: \n<i>Hãy gieo hạt giống của khanh, người yêu dấu của ta! Khanh có sự đồng ý rõ ràng và bằng lời nói của ta!</i>\n\nSir Lancehart:\n<i>...Và ta sẽ không bao giờ đặt tay lên em với sự mơ hồ bao trùm mối liên kết của chúng ta, vì ta coi trọng em quá cao!</i>",
    [2913086971] = "Rơi ra từ nấm ở Đỉnh Albaneve Sương độc",
    [2913375664] = "Khanh đã lần theo bản đồ đến một ngôi đền ẩn sau thác nước, nhưng kho báu của nó lại nằm sau một cánh cửa khóa.\n\nÁnh sáng phía trên cánh cửa cho thấy nó có thể được mở bằng một cơ chế. Hãy tìm cách mở cánh cửa để lấy kho báu!",
    [2913489671] = "Chậu Loa Kèn Trống",
    [2913538556] = "Mũi Tên Xương Hóa Thạch",
    [2914121674] = "Búa Xây Dựng",
    [2914268751] = "Chùy Gai Khốn Khổ",
    [2914273987] = "Làn da của em, nhuộm màu nâu ô liu, tuyệt đẹp và mềm mại... Giọng nói của em — một tiếng gầm, một lời thì thầm — luôn là một bản tình ca ngọt ngào trên môi em. Trái tim anh nở rộ khi nhìn thấy em. Anh muốn bước đi bên cạnh em, nhìn thấy dấu chân của em bên cạnh anh trên cát... cảm nhận làn gió sa mạc, và nhảy múa cùng em trong vòng tay anh... đó là tất cả những gì anh hy vọng.\n— Emily",
    [2915235882] = "Thợ Rèn <npc> đã chia sẻ một vài câu chuyện từ Vùng Đất <lorename>Pikemead</lorename>. Hóa ra, người ta nói rằng những ánh sáng bí ẩn phát sáng dưới nước gần thủ đô là dấu hiệu cho sự cai trị huy hoàng của Nữ Hoàng <lorename>Pikemead</lorename>. Con gái của Thợ Rèn <npc> đã tuyên bố đã tận mắt nhìn thấy những ánh sáng đó.",
    [2915603471] = "Tường Thành Sa Mạc",
    [2916144054] = "Cốc Đất Sét",
    [2916325398] = "Fell",
    [2916886039] = "Băng",
    [2917124340] = "Nguyên Liệu Cá",
    [2918181916] = "Một phần mở rộng cho ba lô của bạn, tăng thêm ba hàng vào kho đồ.\n\n<b>Lỗi thời</b>\n Vật phẩm này có thiết kế cũ. Hãy ghé thăm thợ thủ công của bạn để tìm phiên bản ba lô cải tiến với một hàng bổ sung.",
    [2918718528] = "Mảnh Kính Vỡ",
    [2918945897] = "Cho Thợ Hớt Tóc Xem Một Mảnh Ectoplasm",
    [2919257746] = "Khối Giếng",
    [2919340776] = "Vùng Đất Cháy",
    [2919627472] = "Về Việc Tìm Thêm Dân Làng",
    [2920743598] = "Đèn Gắn Tường Thép",
    [2920839463] = "Một phần của Giáp Chúa Tể U Ám.",
    [2920855807] = "Ta không thể để đàn dê của mình đi lang thang với những con quái vật một mắt này ở gần đây.\n\nTa không biết cái hang chết tiệt của chúng ở đâu, nhưng ta chỉ hy vọng chúng sẽ ở yên đó. Ta không thể chịu đựng được việc mất thêm một con dê nữa... nguồn cung thịt đang cạn kiệt, và ta sẽ không quay lại ăn chuột!",
    [2921164805] = "Sau nhiều tuần nghiên cứu sâu rộng, tôi đã tìm thấy những điểm tương đồng giữa các ký tự ngữ âm cổ xưa được đơn giản hóa với nguồn gốc lịch sử của chữ viết ngữ âm của con người. \nTôi đưa ra giả thuyết rằng hệ thống chữ cái hiện đại có thể bắt nguồn từ hệ thống âm tiết cổ đại. Thật không may, cuộc điều tra không thể tiếp tục do một mùi hôi thối và kỳ lạ phát ra từ một lối mở gần đó... Nó đã làm mờ tâm trí các nhà nghiên cứu của tôi và gây ra đau đầu cho mọi người. Giống như chữ viết cổ đại, nhưng tệ hơn. \n\nTại sao người xưa không đơn giản tạo ra một bảng chữ cái truyền thống thay vì dựa vào nhiều ký hiệu độc đáo, phức tạp quá mức cho mọi âm tiết? Biểu tượng cũng có thể làm được công việc đó. —<lorename>Loraine Crim</lorename>",
    [2921174466] = "Những chú chim hót líu lo. Một ngày tốt lành!",
    [2921930167] = "Nghĩa Địa Gai Rậm chứa các Khối Đá Phong Hóa đặc biệt. <b>Khám phá địa điểm và tìm các khối đá</b> để mở rộng kho vũ khí xây dựng căn cứ của bạn!",
    [2921950040] = "Thủy tinh đen như mực, hình thành từ nhiều thế kỷ trước. Nó để lại các cạnh sắc khi bị vỡ, làm cho nó trở nên thú vị cho việc rèn và chế tạo.",
    [2922095194] = "Hộp Trang Trí Xanh Dương",
    [2922269611] = "Nơi Trú Ẩn",
    [2922583085] = "Cậu Bé Người Tuyết",
    [2922623272] = "Đó là tất cả sao?",
    [2922690897] = "Ta phải xem xét lại các nghiên cứu của mình! Trước đây, ta tin rằng ngọn núi này của Trụ Cột Sáng Tạo là một <b>núi lửa đang hoạt động</b>... hố dung nham là bằng chứng! Ta cho rằng đỉnh của khối núi này đã bị xé toạc trong một vụ phun trào thời tiền sử, định hình vùng đất như chúng ta biết! \n\nCòn <i>cấu trúc kỳ lạ</i>, ừm — có lẽ là một nơi cầu nguyện và an ủi, được xây dựng bởi người xưa ở một thời đại trước đó. Thật không may, ta không phải là người đầu tiên nhìn thấy nó. Một đoàn thám hiểm khác đã đến trước ta. Người phương Đông, dẫn đầu bởi một \"Nala\". Họ tin rằng đó là \"một cánh cổng\" nào đó... thật thú vị. Ta sẽ suy nghĩ lại các giả thuyết của mình!\n\n— Caspian",
    [2922691857] = "Bộ Trang Phục Thợ Săn Hải Tặc",
    [2922805828] = "Phím Tắt Bàn Phím & Chuột",
    [2923088431] = "Giữ vững tinh thần.",
    [2923583422] = "Mã Tấu Đỉnh Cao",
    [2924344417] = "Giữ gìn",
    [2925517746] = "Dấu Vết Của Hoa Hồng Lửa",
    [2925704765] = "Rìu Rợn Gáy",
    [2926283170] = "Quần Đạo Tặc",
    [2926307872] = "Ghi Chú Của Đồn Lính Balefire \"Windward\"",
    [2926437075] = "Một Cuộc Phục Kích Bất Ngờ",
    [2926474680] = "Trợ Lý",
    [2927233571] = "Đã đến một ngọn tháp cổ xưa ở Vùng Đất Mùa Xuân.",
    [2927432666] = "Tìm thấy trong Sương độc Cao nguyên Du mục",
    [2927753015] = "Nhiệm Vụ Embervale Bị Bỏ Lỡ",
    [2928998250] = "Giải Thoát",
    [2929573938] = "Đạo Cụ Rương Gian Lận II",
    [2929723443] = "Đuôi Bóng Tối",
    [2929829504] = "Áo Giáp Cung Thủ",
    [2930868792] = "Ghế Đẩu Tiệm Salon",
    [2932155289] = "Chờ một chút và tôi sẽ đến ngay với bạn!",
    [2932317179] = "Dựng một <b>Bàn Thờ Ngọn lửa để thiết lập căn cứ.</b> Bạn có thể chế tạo Bàn Thờ Ngọn lửa trong tab Chế Tạo Thủ Công của mình. Thả Bàn Thờ Ngọn lửa vào thanh công cụ của bạn, chọn nó và đặt nó vào thế giới.\n\nBàn Thờ Ngọn lửa đã đặt sẽ <b>chiếu sáng phạm vi xây dựng hiện tại.</b> Tại đây, bạn có thể xây dựng nơi trú ẩn cho bản thân và những người sống sót khác. Cảnh quan trong phạm vi xây dựng sẽ được giữ nguyên. Mở rộng phạm vi xây dựng bằng cách củng cố Ngọn lửa tại Bàn Thờ Ngọn lửa.",
    [2932333525] = "Cơm nấu chín này rất ngon và có mùi thơm thoang thoảng. Nó sẽ là một món ăn kèm tuyệt vời.",
    [2933027973] = "Hữu ích cho các vết thương phần mềm.",
    [2933528920] = "Cơ Hội Chí Mạng Phép Thuật",
    [2933566534] = "Sau khi đặt một Người Sống Sót, bạn có thể điều chỉnh phạm vi di chuyển của họ.",
    [2933568978] = "Kho Nhà Máy",
    [2933855666] = "Khanh đã tìm thấy ngôi mộ bị lãng quên mà Người Sưu Tầm đã đề cập.\n\n<b>Hạ xuống ngôi mộ</b> để tìm \"cuống của vực thẳm\" làm hoen ố ký ức của những người đã khuất!",
    [2933889873] = "Cánh Đồng Gió",
    [2934137983] = "Tìm Lò Rèn Đá Quý",
    [2934170679] = "Mũi Tên Chướng Khí I",
    [2934825723] = "Quần Nanh Sói",
    [2935027252] = "Quyền Máy Chủ Của Bạn",
    [2935036208] = "Người Chiêm Tinh Rừng Revel",
    [2935227327] = "Tủ Gỗ Đánh Bóng Lớn",
    [2935407821] = "Hàng Rào Nghĩa Trang Hỏng II",
    [2935586520] = "Chiếc nhẫn của Emily Fray có thể được tìm thấy. Cô ấy sẽ rất vui khi nhận được nó.",
    [2935880390] = "Một Tháp Hướng Tới Các Vì Sao",
    [2936069384] = "Sổ Tay Trồng Trọt",
    [2936169718] = "Cát lấp đầy cổ họng tôi... phổi tôi nặng trĩu bụi. Cơn bão vẫn gào thét bên ngoài, thổi những đụn cát thành cồn cát, và cồn cát thành những cơn lốc xoáy bụi. Ôi, tôi khao khát được cảm nhận cái lạnh một lần nữa... Bờ biển xanh ngọc, những con sóng lướt qua lấp lánh dưới ánh mặt trời... Trẻ em chia sẻ quả cây yucca phơi nắng trong võng lụa... những ký ức tra tấn, quá rực rỡ để giữ gần gũi... cổ họng tôi đau nhói. \n\nTại sao người xưa lại bỏ rơi chúng ta sau tất cả...?",
    [2936327947] = "Mồi Thức Ăn Cho Dê",
    [2936445450] = "Đũa Phép Cháy Xém",
    [2936960153] = "Những Người Sống Sót Hạnh Phúc",
    [2937007587] = "Kaori Conway cần bạn lấy lại những chiếc mũ trang điểm bị mất của cô ấy để bảo vệ danh tiếng. Nếu bạn tìm thấy chúng, cô ấy sẽ cho phép bạn giữ chúng. \n\nĐiều tra điểm dừng chân đầu tiên trên tuyến đường vận chuyển của cô ấy để tìm chiếc mũ đầu tiên!",
    [2937091158] = "Thế giới nở rộ.",
    [2937470724] = "Người Sưu Tầm <npc> Cần Nơi Trú Ẩn",
    [2937572506] = "Đầu của một thủ lĩnh bộ lạc Drak'Dal. Khanh đã chặt nó khỏi cổ nó, nhưng thay vào đó, hai cái đầu mới sẽ mọc lên — nói theo nghĩa bóng.\n\nThu thập nhiều Đầu Hydrak'Dal để chế tạo Cúp.",
    [2938223844] = "Một nguyên liệu thơm giúp làm dịu cơ thể, cung cấp một luồng SP tức thời cho người dùng.",
    [2939346731] = "Bạn nhận ít sát thương hơn từ đòn đánh tiếp theo và tạo ra một vụ nổ băng.",
    [2940036271] = "Dụng Cụ Mở Khóa",
    [2940041224] = "Thuộc Tính",
    [2940693409] = "Rèn Một Găng Tay Lửa",
    [2940927141] = "Người Chăn Dắt Linh Hồn",
    [2940931348] = "Bản Alpha Kín",
    [2941170924] = "Ta đã nhìn thấu mọi thứ!",
    [2941433575] = "Phục Hồi",
    [2941593644] = "Con quái vật tồi tệ đã bắt Galen tội nghiệp — ngay trước mặt chúng ta! Chúng tôi dừng lại nghỉ ngơi, giải khát và có một cuộc trò chuyện vui vẻ trên đường ra chợ thì bầu trời đen kịt bởi những sinh vật bay lượn! Mọi người đều nói hãy ẩn nấp khi bạn nhìn thấy một bóng đen lượn trên đầu, nhưng không có nơi nào để ẩn nấp! Galen rút <b>cung</b> của mình ra, sẵn sàng săn lùng chúng — nhưng chúng tấn công từ hướng mặt trời mọc! Anh ấy bị chói mắt, bất ngờ, dễ bị tổn thương — và rồi, anh ấy biến mất.\n\nCuộc tấn công diễn ra quá nhanh... nhưng tôi thấy con quái vật đã đưa Galen đi đâu. <i>Tổ của chúng không còn xa.</i>",
    [2941849499] = "Đoàn Tụ Với Con Gái",
    [2942559323] = "Gói Tài Nguyên I",
    [2943109261] = "Việc <b>Tăng cường</b> vũ khí của bạn sẽ khiến chúng trở nên chết chóc hơn. Bạn còn chờ gì nữa?",
    [2943239867] = "Mảnh Vỡ Linh Thể",
    [2943459563] = "Khanh đã để ý thấy một chiếc rương gần đó, bị bỏ lại bởi Người Lữ Hành Bí Ẩn <lorename>. Hãy tìm chiếc rương và cướp lấy nó!",
    [2943559724] = "PRT",
    [2943597648] = "Bào Tử Chướng Khí",
    [2943685955] = "Giếng Thuốc Tiên",
    [2943687036] = "Sắc Thái Xám",
    [2945061301] = "Phản Đòn",
    [2945356423] = "Đất Nóng Lưu Vực Vực Nước",
    [2945910956] = "Thanh Tẩy",
    [2946467283] = "Găng Tay Sát Thủ Băng Giá",
    [2946541611] = "Chiếc đũa phép này bắn ra các vật thể gây ST Sương độc.\n\n<b>Quá tải:</b>\nChiếc đũa phép này có cơ hội khuếch đại sát thương đầu ra của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.\n\n<b>Nhân đôi Tinh linh:</b>\nPhép thuật độc đáo của chiếc đũa phép cho nó cơ hội 30% tạo ra một vật thể bổ sung.\n\n<b>Đa mục tiêu:</b> \nBắn nhiều vật thể nhưng với sát thương giảm.",
    [2946699424] = "Về Học Giả Và Bẫy Rập",
    [2946947577] = "Dép Kẻ Săn Mỹ Nhân Ngư",
    [2946952132] = "Một chiếc búa hùng mạnh, bị ăn mòn tận gốc. Sức mạnh của Sương độc được truyền dẫn trong vũ khí này.",
    [2947466762] = "Kẻ Đâm Xiên Fell",
    [2947845559] = "Tàn tích <location>Netherton</location>",
    [2948166061] = "Sự Sống Còn Phụ Thuộc Vào Ta",
    [2948753826] = "Bảo Vệ Ma Thuật",
    [2948952897] = "Đèn Treo Xanh Dương II",
    [2949066574] = "Giày Sát Thủ Băng Giá",
    [2949079796] = "Chế tạo và đặt một Bàn Thờ Ngọn lửa để bắt đầu xây dựng",
    [2949125654] = "Tìm chúng để mở rộng khả năng chế tạo cho căn cứ của bạn.",
    [2949453238] = "Chúng ta đã tiến thêm một bước để chọn cái tên cuối cùng cho mèo cưng. Ở vòng trước, chúng ta đã loại bỏ <i>\"Fred\"</i> và <i>\"Cục Cưng\"</i>. Vâng, tôi biết. Tôi cũng thích \"Fred\". \n\nNhững cái tên lọt vào vòng cuối là <i>\"Thuyền Trưởng\" và \"Miu Miu\"</i>. Sếp rất thích \"Thuyền Trưởng\" vì ông ấy muốn một cái tên đáng ngưỡng mộ, đầy uy quyền, vương giả và mạnh mẽ! Tôi thích \"Miu Miu\" vì nó dễ thương và hay hơn nhiều! Vì vậy, ngày mai tất cả chúng ta sẽ bỏ phiếu. Nhưng đừng có ý tưởng gì cả! Chúng ta không phải là \"Dân Chủ\" hay gì cả! \n\nVà vâng, nếu hết đồ dự trữ, kế hoạch B vẫn còn hiệu lực. Chúng ta sẽ ăn Thuyền Trưởng Miu Miu. Tôi xin trước cái đuôi!",
    [2949554644] = "Cây Giống Cà Chua",
    [2949733172] = "Hy Vọng Của Thợ Rèn",
    [2949746849] = "Quần Chiến Binh Quật Khởi",
    [2949988007] = "Cột Tổ Tiên Đá Drak IV",
    [2950396418] = "Nhìn xem kìa! Ngươi đã mang về một chú Hổ con, phải không? Hổ Hổ, cháy sáng rực rỡ, Trong rừng đêm; Bàn tay hay mắt nào của thần linh,\nCó thể tạo nên sự đối xứng đáng sợ của ngươi?",
    [2950939705] = "Trang %k / %k ",
    [2951031707] = "<b>Ngấm Sương độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương độc.\n\n<b>Tượng Đầu Fell Bọ Cạp Sắt</b>",
    [2951988064] = "Tìm Đàn Bò Yak",
    [2952103366] = "Lệnh mới quy định chúng ta phải để mắt đến cây cầu này. Một hang ổ của người Cyclops đã được tìm thấy gần đó, vì vậy chúng ta phải <i>\"bảo vệ tuyến đường thương mại!\"</i>\n\nTôi không lo lắng. Bộ não của một người Cyclops chỉ bằng hạt đậu. Chắc chắn, sức mạnh của chúng rất đáng gờm — nhưng tôi có 4 chàng trai ở đây, và mỗi người trong số họ to lớn như một ngôi nhà gạch. Tốt hơn nữa: họ cũng không thông minh lắm, nên họ dễ bị sai khiến!\nKết luận: Việc này sẽ dễ như ăn cháo. <i>Trừ khi đám lính của tôi nổi loạn...</i> Bây giờ nghĩ lại, tôi đã không trả lương cho chúng một thời gian rồi.\n\nThôi kệ. Nếu bộ não bé nhỏ, trơn nhẵn của chúng không thể nhận ra rằng tôi đã giấu tiền công của chúng trong một cái rương ngay dưới mũi chúng, thì đó là lỗi của chúng.",
    [2952392619] = "Thủ đô \"<location><lorename>Pikemead</lorename>'s Reach</location>\" đã thất thủ, nhưng không có dấu hiệu của ánh sáng mà <npc>Thợ Rèn</npc> đã báo cáo. <npc>Thợ Rèn</npc> cũng đề cập đến một lâu đài, dường như nằm ngay phía sau thành phố. Hãy đi xuyên qua thị trấn để vào lâu đài và xem điều gì đang chờ đợi bạn ở đó.",
    [2952507833] = "Bàn thờ không thể kích hoạt lại do có quá nhiều Bàn thờ Ngọn lửa đang hoạt động.",
    [2952956744] = "Công thức <craftingstation>Trạm Thuộc Da</craftingstation>",
    [2952972665] = "Không thể xây dựng ở đây",
    [2953239842] = "Có Thứ Gì Đó Đang Thối Rữa Bên Dưới",
    [2953461138] = "Tôi rất muốn chia sẻ sở thích âm nhạc của mình với ai đó không bị gánh nặng cứu vớt thế giới làm phiền.",
    [2953966619] = "Khi trang bị Khiên hoặc vũ khí Cận chiến, nhấn <b>%k để đỡ đòn</b>. Một cú đỡ đòn đúng lúc sẽ <b>phản đòn</b> đòn tấn công. ",
    [2954882674] = "Chân",
    [2955233775] = "Cờ Lệnh Hành Lang Khô Cốt Hỏng",
    [2955384917] = "Bộ Quỷ Vương U Ám",
    [2955738573] = "Một cây Gậy phép mạnh mẽ có khả năng dẫn đường cho những người không có sự bảo vệ.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các lượt niệm phép và MP. Trang bị <b>lượt niệm phép</b> để niệm.",
    [2956442882] = "Lều Tạm Tồi Tàn",
    [2956972468] = "Tiếng Động!",
    [2957573631] = "Mũi Tên Đồng Thiếc Tẩm Độc",
    [2957586795] = "Gặp người sống sót đầu tiên.",
    [2958595230] = " <npc>Người Sưu tầm</npc> đã tiết lộ vị trí của Sảnh Hollow ở Kindlewastes. Để vào, bạn sẽ cần một chiếc chìa khóa. \n\n<b>Chế tạo Chìa khóa với Người Sưu tầm</b> để tiếp tục.",
    [2959144996] = "Ngũ Cốc",
    [2959177136] = "Cảm Hứng Bùng Cháy",
    [2960332697] = "Mocha Ngọt Ngào",
    [2960629283] = "Thực hiện chuyển động máy ảnh lướt theo kiểu điện ảnh khi ở trạng thái chờ.",
    [2960980280] = "Hồ Luma",
    [2961072256] = "Một công thức sản xuất đá đã thất lạc từ lâu. Phương pháp này bảo vệ bề mặt của khối đá và mang lại cho nó một màu trắng trang nhã, khiến nó rất phổ biến.",
    [2961197776] = "Đảo Ngược Camera",
    [2962403150] = "Orville",
    [2962546960] = "Trồng",
    [2962807864] = "Điều Tra Tàn Tích Ngôi Đền",
    [2962895202] = "Hiếm",
    [2963970719] = "Một vật liệu chắc chắn được dệt từ vải lanh. Nó đã cách mạng hóa ngành công nghiệp quần áo nhờ tính linh hoạt và độ bền. Nó cũng trông đẹp hơn.",
    [2964550347] = "Lò nung tiên tiến này có thể tạo ra nhiệt lượng đáng kinh ngạc! Nó được sử dụng để nấu chảy các vật liệu chất lượng cao hơn.",
    [2964628877] = "Thử thách Thủy Quái",
    [2965100447] = "Đền Thờ Ngọn lửa Ẩn Giấu",
    [2965214948] = "Cuốn sách cũ kỹ bụi bặm này tỏa ra một sự căm ghét thầm lặng, bị kiềm chế bởi những xiềng xích sắt dày. Cứ hai tuần một lần, mỗi khi cuốn sách này ở gần, một tiếng leng keng của dây xích vang lên trong không khí nửa đêm, và các trang bên trong co giật. Cứ như thể có thứ gì đó đang cố gắng nhảy ra khỏi giấy da để biến từ mực thành thịt và máu.",
    [2965303956] = "Chiếc Mũ Lính Đánh Thuê chắc chắn này bảo vệ mắt bạn và che giấu biểu cảm của bạn, khiến bạn trông không sợ hãi và đáng sợ.",
    [2965421105] = "Ngọn Lửa",
    [2966326959] = "Không một nét cọ, không một giai điệu, và không một cảnh hoàng hôn nào có thể sánh được với vẻ đẹp của vùng đất hoang dã này. Màu xanh tươi tốt của dây leo gợi cho tôi nhớ về quê hương trước hạn hán.\n\nNếu không có các Tiền Nhân dẫn đường, tôi chắc chắn sẽ bị lạc. Tôi biết ơn sự dẫn dắt của họ, nhưng trái tim tôi đau đớn cho tất cả những người tôi đã bỏ lại phía sau... Than ôi, nhiệm vụ này rất quan trọng. Dù sao thì, nhiệm vụ của chúng ta là rải các Bình Chứa Tro Củi khắp \nEmbervale cho mọi linh hồn không thể đến Vùng Đất Suối kịp thời.\n\nCác Tiền Nhân muốn \"gửi một tín hiệu đến những người xứng đáng\" khi công việc hoàn thành, nhưng tôi tự hỏi ý họ là gì... Ngay cả khi đi bên cạnh nhau, họ vẫn háo hức giữ bí mật của mình.\n\n— Nữ Hoàng Jezmina",
    [2966828804] = "Cây Trang Trí Nhỏ",
    [2967062883] = "Chậu Cây Trống",
    [2967755367] = "Những điều kỳ diệu nhỏ bé ẩn mình giữa đám cỏ biển ven bờ, chờ đợi được giải thoát bởi những bàn tay khéo léo. Hôm nay bạn sẽ tìm thấy gì giữa những bụi lau sậy? Một cạnh sắc bén bị cùn, một ngôi sao rơi trên cát, một lời ước của nàng tiên cá trong chai? Sóng biển có một cách thay đổi mọi thứ chúng chiếm hữu, vì vậy hãy cẩn thận khi tìm kiếm!",
    [2968302163] = "<b>Hồi Ức Của Ony:</b>\n<i>Ta bay cao, ta có thể không bao giờ hạ cánh\nTa nhảy múa trên mặt trời, toàn thân rực cháy\nCốc của ta luôn đầy, ta sẽ uống đến chết đuối\nTrong ánh sáng lỏng và sự mê đắm, cho đến khi ta cảm thấy choáng váng</i>",
    [2968695683] = "Giảm Tốc Độ Di Chuyển.",
    [2969277509] = "Nơi An Nghỉ Của Những Kiến Trúc Sư Vĩ Đại Nhất Đêm Kinh Hoàng",
    [2969415336] = "Luống Cày",
    [2970852106] = "Găng Tay Pháp Sư",
    [2971235245] = "Ta Sẽ Bảo Vệ Ngôi Nhà Của Ta!",
    [2971424770] = "Thách Đấu Quái Vật Trên Đỉnh Sóng Gió",
    [2971552185] = "Lõi Ngô Nướng",
    [2971613955] = "Hàng Rào Hầm Mộ",
    [2971623883] = "Xây Một Chiếc Giường Che Chắn Cho Cade Hawthorn",
    [2971994206] = "Đuốc",
    [2972011645] = "Các Nút Riêng Lẻ",
    [2972510460] = "Sảnh Hollow",
    [2972734871] = "Đầu của những con dao găm này đã bị đóng băng vĩnh viễn sau khi đâm xuyên trái tim lạnh lẽo như băng của một người Cyclops. Hoặc có ai đó đã thử câu cá bằng giáo và để lưỡi dao của họ trong vùng nước đóng băng quá lâu.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi phản đòn. ",
    [2973305001] = "Một công cụ để tạo ra các vật phẩm liên quan đến than củi từ gỗ.",
    [2973845708] = "Một phần của Bộ Giáp Huyền Bí.",
    [2974136764] = "Mảnh Khảm Ngọn Lửa III",
    [2974356899] = "Một bức tượng khổng lồ, nặng vô số cân. Treo bức tượng này lên tường không phải là việc dễ dàng.\n\nThu thập nhiều Đầu Khổng lồ Fell để chế tạo Tượng.",
    [2975254971] = "Tự Đào Mồ Chôn Của Mình",
    [2975269247] = "Chế tạo Bát và Giường Cho Mèo",
    [2975269740] = "Màu sắc của những con đường khô cằn và những ngôi mộ cát.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Vùng Đất Khô Cằn.",
    [2975542741] = "Tìm Kiếm Quán Rượu",
    [2976120189] = "Linh Hồn Làng Mất Tích",
    [2976540223] = "Pháo Kích Đối Kháng",
    [2976630938] = "Chồng chất",
    [2976670016] = "Cây Giống Hoa Loa Kèn Ngày",
    [2976796087] = "Bồn Rửa Đá",
    [2978491193] = "Giáp Ngực Vệ Binh",
    [2978696946] = "Bao Chướng Khí Bị Nguyền",
    [2978748858] = "Đã cắm: ",
    [2979774258] = "Hào Quang Mặt Trời",
    [2979970030] = "Một phần của Bộ Giáp Hiền Triết.",
    [2980072048] = "Nó không chỉ là một chiếc khiên — nó là một bức tường thành của đức tin, một nơi trú ẩn cuối cùng trong cuộc chiến.",
    [2980225055] = "Hoa Calla Luna",
    [2980297115] = "Máy Chủ Sẵn Sàng",
    [2980374940] = "Quả Mọng U Ám",
    [2980959470] = "Các bộ phận kim loại trên những chiếc găng tay gia cố này bị cong vênh do quá nhiều cú vung vẩy liều lĩnh.",
    [2981589769] = "Một chiếc mũ trùm đầu u ám, che giấu một ánh nhìn còn tối tăm hơn. Vành mũ quanh trán đổ bóng lên mắt người đeo, che giấu ý định của họ.",
    [2981767496] = "Sử dụng bệ trưng bày này để tập hợp lại ghi chép của nhà giả kim. Hoàn thành bộ sưu tập sẽ mở khóa các công thức mới.",
    [2982317384] = "Áo Chẽn Giáo Sĩ Sinh Ra Từ Sóng",
    [2982317823] = "Cột Đá Cổ Đại",
    [2982616494] = "Làm phẳng",
    [2983369474] = "Tường Gỗ IV",
    [2983383207] = "Chùy Thịnh Nộ",
    [2983593067] = "Sinh Trưởng",
    [2983748097] = "Nhà Báo đã kể một câu chuyện về việc bị bắn bởi một mũi tên dường như bị phù phép. Hãy điều tra khu vực và tìm những mũi tên để sử dụng phép thuật của chúng cho mục đích tốt đẹp!",
    [2984102274] = "Dao găm",
    [2984340878] = "Đèn Tường Đom Đóm",
    [2984520768] = "Chủ nhà",
    [2984989574] = "Tăng lượng kinh nghiệm nhận được khi khai thác tài nguyên.",
    [2985349658] = "Bàn Lâu Đài Vừa",
    [2985379739] = "Đá Vôi",
    [2985397895] = "Một bó hoa tươi xinh đẹp. Chúng nở rộ bất chấp đau khổ và tàn lụi. Chúng ta cũng nên làm vậy.",
    [2986726173] = "Hãy nâng cấp vũ khí ưa thích của bạn với một số trang bị bạn đã thu thập! Chúng ta cần phải <b>tái chế</b> một hoặc hai vũ khí trước đã... đừng ngại làm bẩn tay nhé!",
    [2987394833] = "Chiếc <craftingstation>Vạc Đen</craftingstation> này sẽ là vật phù hợp hoàn hảo cho một <craftingstation>Trạm Giả Kim</craftingstation>! Đây là vật <b>thiết yếu</b> để pha chế một <b>cơ sở giả kim</b>. Hãy cân nhắc nhé?",
    [2987620547] = "Nếu bạn nghĩ chúng ta bất lực, đừng lo lắng. Với <craftingstation>Con Thoi Tay</craftingstation> của tôi, tôi có thể chế tạo <b>giáp tốt hơn</b> cho chúng ta và tăng cơ hội sống sót! Tôi đã làm mất nó trong cuộc trốn thoát qua Rừng Rậm vào những ngày xa xưa... gần <b><location>Westcott</location></b> khi tôi nằm nghỉ. Đừng chờ đợi. Tôi sẽ lo cho bạn.",
    [2988927721] = "Vào Sảnh Hollow Revelwood",
    [2989031414] = "<b>+2</b> SP\n<b>+2</b> Nhanh nhẹn\n<b>+5</b> Hồi phục thể lực\n<b>+5%</b> Tỷ lệ chí mạng\n<b>+5%</b> ST Chí mạng ",
    [2990117479] = "Đạt cấp 5.",
    [2990152026] = "Cửa Tầng Hầm Giả",
    [2990309027] = "Một chiếc chùy cân bằng hoàn hảo, mỗi mặt trước đối xứng với mặt sau.",
    [2990590582] = "Tăng SP ở đòn đánh tiếp theo.",
    [2990845940] = "Chìm Hoàn Toàn",
    [2991045388] = "Kích hoạt một đòn tấn công đặc biệt trong khi nhảy hoặc nhảy đôi với <b>%k</b>. Đòn này sẽ tấn công tất cả kẻ địch trong phạm vi 15 mét với 5 ST Cắt mỗi trí tuệ.\nChi phí: 10 MP mỗi trí tuệ",
    [2991116721] = "Tăng SP tối đa của người chơi.",
    [2991124465] = "Một ly sinh tố lạnh làm từ dừa và chuối. Ngon nhất khi dùng kèm một chiếc ô nhỏ trang trí, một chỗ ngồi ấm cúng trên bãi biển và hai ống hút xoắn.",
    [2991255300] = "Riêng tư",
    [2991780137] = "Ngay cả với trang bị mới, bạn cũng không nên cảm thấy quá an toàn ngoài kia. <b>Nghỉ ngơi và ăn uống đầy đủ</b> trước khi bạn ra ngoài... một ngọn lửa, một mái nhà che đầu và một ít thịt trong bụng sẽ chuẩn bị cho bạn đối mặt với mọi thứ.",
    [2992220494] = "Cổng Gỗ Thô Sơ I",
    [2992221054] = "Gửi tất cả",
    [2993443167] = "Rương Phép Thuật Nhỏ",
    [2993469917] = "Bạn bị tắt tiếng.",
    [2993503046] = "Cột Đá Cổ Đại",
    [2993802589] = "Một luống cày sẽ cho ra Dâu Tây",
    [2993927280] = "Nướng Cá Và Ăn",
    [2994191986] = "Bạn đã thấy bất kỳ động vật thuần hóa dễ thương nào ở Tỉnh Lẻ Albaneve chưa? Nào, chúng sẽ hữu ích! Thu thập len từ Bò Yak cho phép thợ săn làm bộ đệm ấm áp cho giáp ấm áp! Ồ, và món hầm thịt sẽ tuyệt vời! Đó là lý do tại sao chúng ta cần Bò Yak. Tôi không chỉ muốn âu yếm chúng, tôi thề!",
    [2994316054] = "Kiếm Tìm Thấy",
    [2994914437] = "Sát thương vũ khí cận chiến tăng <b>10%</b>.",
    [2995575684] = "Giày Nhà Thám Hiểm",
    [2995710939] = "Lớp giáp này được làm từ xác côn trùng khổng lồ. Nó không chắc chắn như sắt, nhưng nhẹ hơn đáng kể. Lý tưởng cho giáp cung thủ.",
    [2996271277] = "Đòn Đánh Kỹ Năng",
    [2996676552] = "Bình Nước Pha Lê",
    [2996967426] = "Tiếng Đức",
    [2997818418] = "Nhà Giả Kim đã tiết lộ vị trí của một số \"Sảnh Đường Rỗng\" gần đó, những hầm mộ ngầm rộng lớn phục vụ cho việc giam giữ \"Hollow\", những bộ xương biết đi. Khám phá vị trí của Sảnh Đường Rỗng ở Vùng Đất Mùa Xuân và làm sáng tỏ những bí mật chúng ẩn giấu!",
    [2998506190] = "Một thiết bị chưng cất quan trọng làm bằng thủy tinh.",
    [2998594413] = "Tiếng Nga",
    [2999503212] = "Kẻ Nhảy Sóng",
    [2999689780] = "Ong Chích",
    [2999906782] = "Cột Tổ Tiên Đá Drak III",
    [3000351441] = "Ngọn Lửa sẽ không còn bảo vệ khu vực này nữa. Nó sẽ bị Sương độc nuốt chửng sau một thời gian, hoặc khi trò chơi được tải lại. \n\nCác vật phẩm đã đặt sẽ bị mất!",
    [3000440061] = "Bình Đất Sét III",
    [3000902259] = "Đây là vật liệu đường làm từ đá vôi vỏ sò, thường được tìm thấy ở Lưu Vực Nước Lặng.",
    [3000909644] = "Vật Liệu",
    [3001415770] = "Tinh thần",
    [3001437934] = "Thứ gì đó, hoặc ai đó, đã bị giam cầm sau một bức tường đá vụn tại một hầm mỏ của Scavenger. <b>Tìm đường vào hầm mỏ</b> và thu thập những gì bên trong!",
    [3001485696] = "%k xác nhận",
    [3001621326] = "Bà Gertrude sẽ không nhượng bộ. Bà ấy muốn ở lại ngôi nhà nơi bà và mẹ tôi đã lớn lên. Không quan trọng là thị trấn đã chết, mọi người đã đi hết, bà ấy cô đơn... Bà ấy muốn sống và chết ở đó. Thật là một bà già đáng thương... bà ấy thà ở với đám chó hoang của mình còn hơn là với phần còn lại của gia đình! \n\nTôi không thể chịu đựng được những con chó mà bà ấy cho vào nhà. Chúng luôn mang thai và đầy bọ chét, giống như \"Pompom\" mà bà ấy yêu quý. Tôi bỏ cuộc. Hãy nói với con cái bạn đừng lang thang đến <location>Shorewatch</location>, nếu không chúng có thể bị bệnh dại! Hoặc tệ hơn, bọ chét!",
    [3001644379] = "Vào Lâu Đài",
    [3001778257] = "Các Cổ Vật bạn thu được từ việc tái chế có thể được đầu tư vào <b>ưu đãi tại <npc>Thợ Rèn</npc></b>. <b>Nâng cấp</b> một vũ khí tại <npc>Thợ Rèn</npc> bằng cách chi tiêu <b>Cổ Vật</b> của bạn.",
    [3002081489] = "Một vũ khí được chế tạo thô sơ nhưng tàn bạo, đang chờ đợi con mồi tiếp theo.",
    [3002715801] = "Cơn sốc đường này sẽ hồi phục SP!",
    [3003149248] = "Đừng lo lắng!",
    [3003649438] = "Du Hành Nhanh Đến Cột Đá Cổ Đại Ở Vùng Đất Mùa Xuân",
    [3004238824] = "Một loại thảo mộc kiên cường, mọc trong khí hậu khắc nghiệt của Kindlewastes. Các nhà tâm linh được biết đến là đã sử dụng nó cho các mục đích huyền bí.",
    [3004679262] = "Các chi tiết trang trí vàng định hình bộ trang phục này — và tất nhiên, găng tay cũng không ngoại lệ.",
    [3005127928] = "Để chơi nhạc, bạn cần biết các bài hát. Học cách chơi các bài hát bằng cách tìm <b>bản nhạc</b> rải rác khắp các thị trấn và quán rượu!\n\nBạn có thể tìm thấy một bản nhạc ở Vùng Đất Mùa Xuân, một ở Rừng Rậm, hai ở Cao Nguyên Du Mục và hai ở Kindlewastes.",
    [3005129475] = "Biển Hiệu Tiệm Salon",
    [3005399899] = "Đặt/Xóa Bộ Lọc",
    [3007029252] = " <npc>Thợ Rèn</npc> tin rằng có những người sống sót khác có thể được hồi sinh.",
    [3007697398] = "Giá Treo Vũ Khí Cận Chiến Một Tay",
    [3009586422] = "Lưỡi Dao Ghép Bông Tuyết",
    [3009940288] = "Chúng ta xong việc ở đây chưa?",
    [3009957321] = "Độc Tố Hemoglobin",
    [3010036049] = "So Sánh Đạn Dược",
    [3011526866] = "Bụi Axit Sunfuric Xanh",
    [3011593454] = "Ghi chép từ nhà nghiên cứu <lorename>Loraine Crim</lorename> chi tiết vị trí của các cột đá ở Rừng Rậm, Cao Nguyên Du Mục và Kindlewastes.\n\nĐọc cột đá ở Kindlewastes để tiếp tục!\n\nĐọc tất cả các cột đá đã đề cập ở trên để hoàn thành nhiệm vụ!",
    [3011712810] = "Elio Ricci",
    [3011985306] = "Ra lệnh tôn trọng với Mũ Bảo Hiểm Cận Vệ này.",
    [3012455953] = "Báo Cáo Vây Hãm — Ngày 3",
    [3012696497] = "Chuột Rừng Rậm",
    [3012764443] = "Chế Tạo Trang Bị Đầu Tiên",
    [3013276678] = "15% Kháng ST Sương độc",
    [3013423099] = "Bền Bỉ",
    [3013471848] = "Xin chào, Hỏa Thần!",
    [3013561115] = "Vũ khí cơ bản nhất, được nâng cấp để hiệu quả và bền bỉ hơn.",
    [3014021066] = "<craftingstation>Bàn Thợ</craftingstation>",
    [3014064924] = "Lại là chuyện gì?",
    [3014095665] = "Tôi không biết bộ đồ lặn mà lực lượng đặc biệt của chúng ta sở hữu là gì, nhưng tôi cá là nó sẽ hữu ích.",
    [3014813600] = "Mũ Giáp Mắt Đại Bàng",
    [3014896536] = "Sử dụng Công Cụ Quá Phát Triển để áp dụng cái này lên các cấu trúc trong căn cứ của bạn.",
    [3015351300] = "Vũ Khí Cận Chiến 1H",
    [3015992210] = "Vảy Cá",
    [3016051239] = "Hoàn Thành",
    [3017986073] = "Máy Ép Linh Thể",
    [3018106861] = "Cây Tre",
    [3018116389] = "Đèn Lặn Rễ Phát Sáng",
    [3018145111] = "Hãy vững vàng khi đánh bại kẻ thù từ xa với đôi ủng pháp sư đáng gờm này.",
    [3018395320] = "Chiến Thắng Cánh",
    [3018457435] = "Nấm hương có tác dụng tuyệt vời trong việc làm đậm đà hương vị của mọi món ăn.",
    [3018536113] = "Một chiếc áo choàng tối màu được giữ lại bằng những bộ xương \"giả\". Chúng kêu lạch cạch như xương thật vậy. Thật đáng ngờ!",
    [3018670009] = "Cửa Đền Bí Mật",
    [3018785356] = "Tội Ác Của <location>Nơi Nghỉ Ngơi Của Surat</location>",
    [3018828923] = "Giỏ III",
    [3018955442] = "Một Lời Đề Nghị",
    [3019023235] = "Găng tay Hoàng gia, xứng đáng với một hiệp sĩ danh dự đích thực.",
    [3019090187] = "<b>Búa Của Tiền Nhân:</b> Một công cụ xây dựng cổ xưa được cung cấp năng lượng bởi Ngọn Lửa, có khả năng <b>dựng lên nhiều công trình</b> xung quanh nhà bạn một cách nhanh chóng.\n\nChỉ có thể sử dụng <b>trong phạm vi của Bàn Thờ Lửa</b>.",
    [3019789624] = "Bạn có chắc chắn muốn xóa thế giới này không?\nThế giới đã xóa không thể phục hồi!",
    [3019923496] = "Một mối đe dọa cổ xưa đã trở lại... và ta sẽ không để nó lang thang trên quê hương ta.",
    [3020484897] = "Xây Dựng L",
    [3020994212] = "Một chiếc khăn trùm đầu màu trắng sữa giúp giữ tóc bạn không bị vướng víu khi làm việc.",
    [3021072948] = "Sương độc bao phủ",
    [3021091997] = "Tái Chế",
    [3021100654] = "Gậy phép Tết Nguyên Đán",
    [3022822646] = "Áo Khoác Đôi Hoàng Gia",
    [3022916580] = "Ô Slot Thanh Hành Động 10",
    [3023060992] = "Tăng %k MP cho mỗi Điểm Thuộc Tính.",
    [3023258801] = "Giữ để nấu",
    [3023410308] = "Giáp Vật Lý",
    [3023528518] = "Cấp Độ Vật Phẩm Truyền Thuyết Có Thể Chế Tạo",
    [3024150275] = "Di Chuyển",
    [3024617097] = "Khoác Lên Sự Đố Kỵ",
    [3024636770] = "Nữ hiệp sĩ tập sự, Gabrielle Fairburn, đã đề cập đến một kẻ thù bất tử ám ảnh <location>Brightwich</location>, một ngôi làng mà cô từng cố gắng giải phóng.\n\nCô ấy đã giao cho bạn nhiệm vụ tiêu diệt kẻ thù này một lần và mãi mãi. Đầu tiên, bạn sẽ phải <b>tiếp cận <location>Brightwich</location>.</b>",
    [3024664037] = "Chữa Lành",
    [3025292900] = "Một chiếc ngòi hữu cơ sắc nhọn. Đừng để bị chích, nếu không nọc độc sẽ chạy khắp huyết quản của bạn!",
    [3025372797] = "Áo Giáp Thợ Săn Quetzal",
    [3025998578] = "Lõi Gỗ Đầm Lầy Đen",
    [3026168164] = "Một chiếc bình vàng với những họa tiết chạm khắc tinh xảo hình đầu lâu kỳ dị. Các chi tiết bên hông giống như răng nanh hoặc móng vuốt.",
    [3026989532] = "Lá cọ rực rỡ mang lại bóng râm rộng rãi dưới ánh mặt trời chói chang. Chúng có thể được sử dụng làm nguyên liệu chế tạo.",
    [3027331569] = "Bể Phế Liệu II",
    [3027480428] = "Bạn đã có cơ hội tìm kiếm một cối xay tốt hơn chưa?",
    [3027703591] = "Thịt của nó Rất Mạnh",
    [3027740205] = "Wildlife Cao nguyên Du mục",
    [3028387470] = "Chiến Dịch Đặc Biệt – Nhật Ký Thợ Lặn – Mục 033 – Chết Tiệt!",
    [3028808123] = "Đầm Đen",
    [3029080832] = "Cửa Đôi Gỗ",
    [3030902762] = "Bạn đã tìm thấy 4 mảnh bản đồ kho báu, nhưng chúng rất khó đọc ở trạng thái hiện tại.\n\n<b>Sử dụng chúng để chế tạo một bản đồ kho báu được phục dựng!</b>",
    [3031039214] = "Một vũ khí tiêu chuẩn với các phép đo chính xác và khả năng xử lý hoàn hảo. Chúng phổ biến trong quân đội Albaneve Summits trong nỗ lực bành trướng của lãnh chúa của họ.",
    [3031384462] = "Tăng",
    [3031860290] = "Hoa Cúc Nửa Đêm",
    [3032023381] = "Khối xây dựng này được làm từ vật liệu bền vững, đặc biệt là tre. Nó mang lại cảm giác bãi biển.",
    [3032024941] = "Thí Nghiệm Vĩnh Hằng",
    [3032155322] = "Ma-nơ-canh \"Chiến Thắng\"",
    [3032294327] = "Một nguồn sáng có thể ném để <b>đánh dấu một địa điểm</b> cho những người chơi khác, và để chiếu sáng những khu vực tối tăm phía trước.\n\n",
    [3032908453] = "Người chơi đã mời bạn có phiên bản cũ hơn. Vui lòng đảm bảo cả hai bạn đều có phiên bản mới nhất của trò chơi để sử dụng các tính năng trực tuyến.",
    [3033159559] = "Băng Gạc",
    [3033432388] = "Lại đây nào Hỏa Thần, ta muốn xây dựng cái gì đó mới!",
    [3034656214] = "Nếu bật, kẻ địch sẽ không tấn công người chơi cho đến khi họ bị tấn công.",
    [3035111746] = "Thời Gian Kháng Băng",
    [3035609732] = "Một vòng xoáy năng lượng rực rỡ cần thiết để gắn đá quý vào vũ khí.\n\nBan đầu được người Cổ đại sử dụng, nó đã bị lũ Fell chiếm giữ để cung cấp năng lượng cho bầy của chúng cho đến khi bạn giải thoát nó khỏi nhà tù hữu cơ mới của chúng.\n\nPhiên bản này có thể được tìm thấy ở Cao nguyên Du mục.",
    [3036305499] = "Vị Trí Tờ Nhạc",
    [3036728631] = "Bạn của ta: Ta cần cái <craftingstation>Cối Xay</craftingstation> cũ của ta. Những lọ thuốc ta có thể pha chế với nó... chắc chắn sẽ giúp ngươi. Làm ơn. Tìm nó cho ta.",
    [3036840776] = "Bạn đã bắt đầu tìm kiếm kiến thức giả kim thuật mới chưa?",
    [3036852018] = "Bàn Tiệc Gỗ Phương Bắc",
    [3036949361] = "Rời khỏi Sương độc!",
    [3037321638] = "Cây Giống Ngô",
    [3038275522] = "Mật khẩu cho [ %k ]",
    [3038555737] = "Tăng trưởng Tối đa",
    [3038581157] = "Lò Nướng",
    [3040027110] = "Tốc Độ Bình Thường",
    [3040161382] = "Bắt Dính: Tắt",
    [3040478745] = "<location>Zephyr</location>",
    [3041345689] = "Miếng Phi Lê từ một con cá tuyệt hảo, đừng lo về xương cá, chúng đã được loại bỏ hoàn toàn.",
    [3041596483] = "Bạn có thực sự muốn tái chế vật phẩm này không? Nó không thể phục hồi!",
    [3041746379] = "Chiếc mũ bảo hiểm này cho phép bạn thể hiện một ánh nhìn đặc biệt kiên nhẫn và tính toán.",
    [3042628645] = "Một chiếc nhẫn cổ xưa mang lại cho bạn SP.",
    [3042663735] = "Tủ Ly Gỗ Đánh Bóng Nhỏ",
    [3042695223] = "Đá Quý Hiện Tại",
    [3043530402] = "Dây Thần Kinh Điện",
    [3043940726] = "Tăng sát thương gây ra bằng Gậy phép.",
    [3044314739] = "Đo hai lần, cắt một lần!",
    [3044316429] = "Sương độc bao phủ vẫn đang trong quá trình phát triển cho bản phát hành EARLY ACCESS.\n\n- HÌNH ẢNH, HIỆU SUẤT và ĐỘ ỔN ĐỊNH không phải là chất lượng cuối cùng.\n- Đặc biệt trên GPU AMD và không phải RTX, ánh sáng GI động chưa hoàn thiện.\n\nVui lòng ỦNG HỘ chúng tôi và BÁO CÁO CÁC SỰ CỐ bạn có thể gặp phải. Chỉ cần nhấn [F1] khi đang trong trò chơi để báo cáo sự cố.\n\nChúng tôi dự định gỡ bỏ bản demo vào ngày 22 tháng 10.\n\nCẢM ƠN và hãy tận hưởng bản demo và LÀM ƠN THÊM VÀO DANH SÁCH ƯU TIÊN, nếu bạn thích Sương độc bao phủ!",
    [3044990259] = "Sự thối rữa dập dềnh bên cạnh chiếc mũ trùm đầu màu nâu này, giống như một làn sóng dịch bệnh đổ bộ vào bờ.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [3045094727] = "Nhím biển này nằm trên một bệ nhỏ và quá mỏng manh để cố gắng lấy ra.\n\nBộ sưu tập này được tìm thấy ở Vùng Đất Mùa Xuân.",
    [3045181714] = "Kiếm dài Fell Sấm Sét khổng lồ — thu nhỏ cho tiện lợi của bạn.",
    [3045189094] = "Nhận một điểm Tinh Thần cho mỗi hai cấp độ của Ngọn Lửa.",
    [3046077836] = "Hũ Đồng Đỏ Mở",
    [3046950849] = "Bạn đã lấy được cối xay được cải tiến. Với nó, bạn có thể <b>chế tạo một cối xay.</b>\n\nCối xay chỉ hoạt động khi có <b>máy phát lực gần đó</b>. Máy phát lực có thể là một bánh xe nước, được đặt trong dòng nước, hoặc cánh cối xay gió. Cả hai đều có thể được chế tạo tại Thợ Giả Kim.",
    [3047581596] = "Khi bạn đánh trúng một kẻ địch không cảnh giác, sát thương sẽ nhân đôi.",
    [3048126262] = "Có điều gì đó khủng khiếp đang xảy ra tại <location><lorename>Phạm Vi Pikemead</lorename></location>... Ta biết điều đó trong xương tủy.",
    [3048132666] = "Bạn đã tìm thấy tàn tích của đội cận vệ hoàng gia chưa?",
    [3048568094] = "Cái Chết Ở Vịnh Stillwater",
    [3049293229] = "Cây Giống Gỗ Thông",
    [3049545225] = "Ngư Phủ",
    [3049645436] = "Da",
    [3049748966] = "Lưới Gỗ",
    [3049903283] = "Thuyền trưởng Melville Fontane là một ngư phủ và doanh nhân cung cấp đồ câu cá.",
    [3050573575] = "Khối Đá Đánh Bóng Kỹ",
    [3050907793] = "Loại đất hoàn hảo để trồng những bông hoa xinh đẹp.\n\n<b>Thoát nước</b>\nChất liệu này <b>thoát một lượng nhỏ nước</b> khi bị tràn.",
    [3050941006] = "À, ta có thể thấy cơn khát trong mắt ngươi! Ngươi đã chạm vào Viên Máu Khát Máu, phải không? Ngươi đã cảm thấy đói khát chưa? Trên thang điểm từ một đến mười, ngươi sẽ mô tả sự thôi thúc hủy diệt của mình như thế nào? Ồ, ta chưa nói với ngươi sao? \"Thử nghiệm\" mà ta muốn thực hiện đều liên quan đến ngươi. Ngươi là trợ lý của ta, cũng là đối tượng thử nghiệm của ta. Hãy cho ta biết nếu ngươi gặp bất kỳ tác dụng phụ nào, chẳng hạn như mắt đỏ ngầu, cơn thịnh nộ không kiểm soát được và ham muốn phạm tội.",
    [3051072726] = "Một Bản Song Ca Của Nghệ Sĩ Đường Phố",
    [3052204428] = "Thu Thập Lông Cừu Ở Cao Nguyên Albaneve",
    [3052921537] = "Dao Găm Sói",
    [3053203028] = "Rìu Mang Lời Nguyền",
    [3053299971] = "Cúp Danh Năng Quái Vật Mắt Một Sa Ngã Bằng Vàng",
    [3054023726] = "Găng Tay Mắt Đại Bàng",
    [3054925746] = "Bạn có để ý không? Người giỏi nhất của chúng ta, Emily, dường như sợ Sinh vật Fell. Tôi ngạc nhiên khi nghe điều đó... Ở <location><lorename>Pikemead</lorename>'s Reach</location>, tôi thấy nhiều trẻ em chơi với đồ chơi nhồi bông giống chúng! Chắc chắn, đó là lúc đầu, trước cơn bão, có thể nói, và có lẽ chúng ta là những kẻ quê mùa lạc hậu... nhưng bạn phải thừa nhận: Chúng khá dễ thương! Một món đồ chơi nhồi bông như vậy có thể làm dịu nỗi sợ hãi của Emily không?",
    [3054966953] = "Sợi Cây",
    [3055247590] = "Thịt sống, không ăn được. Phải nấu trên lửa trại.",
    [3055348699] = "Hầm Mộ Vỏ Sò Hồng",
    [3056116885] = "Giày Lông Thú",
    [3056487961] = "Những chiếc ủng này dường như từng thuộc về một vị vua mà tên tuổi đã bị thời gian lãng quên. Nó chìm vào quên lãng, chỉ còn lại một danh hiệu và một lời nguyền dai dẳng.",
    [3056987606] = "Axit Gỗ",
    [3057167009] = "Trích Đoạn Từ Những Câu Chuyện Dũng Cảm Của Val",
    [3058117146] = "Bóng Ma",
    [3058528279] = "Lừa gạt những kẻ khác đang tìm kiếm lối đi bí mật trong căn cứ của bạn bằng cánh cửa bí mật giả này.",
    [3058716789] = "Vũ Khí Thất Lạc",
    [3059166073] = "Thợ Săn <npc>Thợ Săn</npc> tuyên bố rằng người sống sót mới, Alden Crowley, bốc mùi thối rữa. Cô ấy có vẻ cảnh giác với họ và rùng mình khi nhìn thấy họ.",
    [3059252193] = "Chùy Gai Được Gia Cố",
    [3059778556] = "Quần Xạ Thủ",
    [3059956607] = "Thực Đơn Biểu Cảm",
    [3060103145] = "Bàn Thờ Ngọn lửa đã được xây dựng, nhưng vùng đất vẫn còn xa lạ và chưa quen thuộc. Nói chuyện với Ngọn lửa trong căn cứ mới của bạn để biết cách tiến hành.",
    [3060532763] = "Sức Mạnh Chặt Gỗ",
    [3060548710] = "Cú Lướt Tóe Nước",
    [3060567028] = "Im lặng nào! Đêm đang gọi.",
    [3060864733] = "Phóng to",
    [3061407321] = "Tấn công khi đang trên không sẽ tạo ra %k quả cầu bay theo mục tiêu và gây %k ST Xuyên.",
    [3061435199] = "Đèn Lồng Mặt Đất (Chưa Cháy)",
    [3061456655] = "Nghệ Thuật",
    [3062199599] = "Những con cừu nhỏ bé nhút nhát, các ngươi nên biết không được nghi ngờ Chúa tể Vorgoth và sứ mệnh thánh thiện của Người. Các vị thần gió đã nghe thấy những lo ngại của các ngươi, và họ đáp lại bằng bạo lực nhanh chóng.\n\nKẻ nào gieo rắc nghi ngờ sẽ bị phán xét bởi bầu trời\nKẻ nào tỏ ra sợ hãi sẽ bị gió Bắc cuốn đi\nKẻ nào hạ vũ khí sẽ bị một tia sét trời giáng xuyên thủng, như Raphael đã từng\n\nCa ngợi tuyết! Vinh quang thay Chúa tể Vorgoth, Vệ Binh Phương Bắc!",
    [3062438245] = "Yêu cầu ít SP hơn. Có thể kích hoạt ở phạm vi lớn hơn.",
    [3062603318] = "Quá xa vị trí hồi sinh của người sống sót.",
    [3063247798] = "Ghế Dài Gỗ Đánh Bóng",
    [3063453604] = "Bạn đã trở về. Bên ngoài, bạn không thay đổi - nhưng bên trong, bạn thân mến, bạn đã có được thứ mà bạn ước gì mình không có.",
    [3063728156] = "Bạn đã chế tạo một lọ thuốc sẽ cho phép di chuyển dưới nước thoải mái hơn.\n\n<b>Hãy tiêu thụ lọ thuốc</b> và tự mình thử hiệu quả để tiếp tục!",
    [3064006613] = "Đối Mặt Ta Lúc Trưa",
    [3065481536] = "Nói Chuyện Với Ngọn lửa",
    [3065530057] = "Máy chủ này cung cấp một vai trò có ít quyền hơn và không yêu cầu mật khẩu.",
    [3065917987] = "Tôi đã bảo hắn bỏ nó đi!! Tôi đã nói vậy, phải không?\n\nLời nguyền gia tộc sẽ lấy đi mạng sống của họ, và nó đã làm vậy! Không phải tôi, mà là lời nguyền! Nó đã lấy đi Wyllma theo thời gian, và bây giờ cả Kasper nữa! Tôi đã bảo hắn bỏ <b>THANH KIẾM RA!</b>\n\nMột cuộc chiến, một tia sáng — và sau cuộc ẩu đả, Kasper đã ngã xuống đất một cách lặng lẽ. Tôi đã lắc hắn. Không có phản ứng. Hắn yên nghỉ <b>dưới gốc cây gia đình</b>, bên cạnh Wyllma... <b>cầm chặt thứ bị nguyền rủa</b>. Tôi không bao giờ muốn nhìn thấy nó nữa!",
    [3066018955] = "Hy Vọng Mới Thức Tỉnh",
    [3066233735] = "Ngôi mộ này dành riêng cho tất cả những người đã khuất mà không có gia đình để chôn cất họ.\n\nNhững linh hồn lạc lối không tên tuổi, những câu chuyện chưa kể, những di chúc không ký tên.\nNhững người già đã hóa thành tro bụi, chỉ còn lại tro tàn nơi lẽ ra phải có sự huy hoàng và trí tuệ.\nNhững lữ khách không có bạn bè để hát ca ngợi hay lau khô nước mắt.\nNhững đứa trẻ đã bị tước đoạt hơi thở trước khi tiếng cười của chúng có thể thắp sáng bầu trời.\n\nChúng ta khắc ghi tên viết tắt của họ vào tâm trí, đóng dấu lên bản thân thay cho họ. Chúng ta mang gánh nặng của họ trên lưng, bị đánh đập và tổn thương. Chúng ta nhớ về những người đã mất, sống lại nỗi đau của quá khứ - nỗi đau vang vọng của một vết thương đang lành - để bùng phát trở lại, tái phát và chìm trong u sầu mỗi khi trăng xanh.\n\nNhững ký ức thật đau đớn, nhưng chúng ta mang chúng trong tim mãi mãi, vì không có nỗi đau nào cháy bỏng hơn sự phai nhạt thành bóng tối.",
    [3067149902] = "Tìm thấy trong Sảnh Đường Hollow của Cao Nguyên Du Mục",
    [3068011921] = "Căn cứ %k",
    [3068112013] = "Khe Xây Dựng Hình Dạng 5",
    [3068341143] = "Đạn Băng Vĩnh Cửu II",
    [3068605549] = "Tìm Thấy Viên Đá Sói",
    [3068845135] = "Thức Ăn",
    [3069485730] = "Ta cảm thấy thôi thúc muốn hút lấy một linh hồn từ lòng đất. Xương cốt vô hồn và lạnh lẽo này có ích gì? Hãy lấp đầy chúng bằng một mục đích.",
    [3069726052] = "Bánh Xe Nước Nhỏ",
    [3070011421] = "Ta biết nghe có vẻ ngớ ngẩn, nhưng một chiếc <keyitem>Ấm Đun Nước</keyitem> ngon lành trên một <craftingstation>Trạm Chế Tạo</craftingstation> ấm áp sẽ làm nơi này có cảm giác \"như ở nhà\" hơn. Ôi, biết bao bữa ăn chúng ta có thể làm...!",
    [3070642630] = "Nhận Kiếm Tết Nguyên Đán",
    [3070911806] = "Mất công ngươi tìm ta quá! Nhìn ngươi kìa - yếu ớt và còi cọc. Và họ gọi ngươi là Flameborn? Việc đầu tiên ngươi cần là trang bị... may mắn là ngươi đã đánh thức ta trước. Chế tạo một <b>Kiếm Rác Rưởi, một Chùy Gai hoặc một bộ giáp</b> sẽ phục vụ tốt cho chúng ta!",
    [3071074383] = "Găng Tay Khô Cốt Tinh Nhuệ",
    [3071200117] = "Băng Gạc",
    [3071301629] = "Lại Đây Nào",
    [3071512450] = "Quan Trọng",
    [3071746587] = "Hãy xuống Sảnh Đường Hollow và dấn thân vào nơi ta không thể!",
    [3072180639] = "Hoa Ly Màu Hồng",
    [3072546907] = "Hỡi Con của Ngọn lửa, con đã có được công cụ phù hợp để tự bảo vệ mình khỏi cái lạnh. Hãy xem con có thể chịu đựng được bao lâu - thử thách bằng Ngọn lửa, thử thách bằng tuyết. Một thử thách bằng máu tìm thấy sâu bên dưới.",
    [3072757059] = "Khải Huyền Cạnh Hồ",
    [3073046300] = "Tăng Cường Ngọn lửa",
    [3073196326] = "Một thợ cắt tóc giỏi đáng giá vàng!",
    [3073477469] = "Nhảy Múa!",
    [3073493399] = "Drak'Ari",
    [3073808281] = "Không Khí",
    [3074745731] = "Thoát",
    [3075978115] = "Nhiều binh lính đã ngã xuống trong chiến tranh. Những người trở về được ca ngợi và được tặng vàng bạc, quà cáp; được ban cho vũ khí xứng đáng với một cựu binh được tôn vinh... nhưng đối với một số người, những món quà đó chỉ đơn thuần là lời nhắc nhở về quá khứ kinh hoàng của họ.",
    [3076043456] = "Chào Hỏi!",
    [3076127097] = "Quần Thợ Săn Quetzal",
    [3077248337] = "Đạt cấp 45.",
    [3077364344] = "Một thanh kiếm cơ bản, được rèn cho những chiến binh mới bắt đầu.",
    [3077512877] = "ST Sương độc Ma thuật",
    [3078000318] = "Rễ Sương độc là nguồn gốc của nỗi khổ của chúng ta. Hãy phá hủy nó bằng một <b>rìu chặt cây</b> và phát triển.",
    [3078248018] = "Bạn hiện không có nhiệm vụ Flameborn nào chưa hoàn thành",
    [3078374050] = "Giày Tuyết",
    [3079362938] = "Thí nghiệm cuối cùng của pháp sư đã tạo ra một phép thuật tia băng vĩnh cửu. Ông tin rằng mình có thể sử dụng nó để đóng băng bản thân và, bằng cách đó, đạt được sự bất tử - theo một cách nào đó.\n\n<b>Hãy quay lại gặp Nhà Giả Kim và kể cho ông ấy nghe về những gì bạn tìm thấy.</b>",
    [3079523733] = "Thợ Rèn Cần Một Cửa Hàng",
    [3079871129] = "Một ngọn pháo sẽ bám vào bất kỳ bề mặt nào. Bạn có thể sử dụng nó để đánh dấu và ping một khu vực.",
    [3080646492] = "Đã phát hiện các liên kết sử dụng cùng các đầu vào theo thứ tự khác nhau. Chúng tôi khuyên bạn không nên sử dụng chúng.",
    [3080773885] = "Viên Đá được gắn khe cũng sẽ bị phá hủy! Hãy gỡ nó ra tại Lò Rèn Đá trước để giữ lại.",
    [3081928933] = "Hạt Lúa Mì",
    [3083240641] = "Cơn Thịnh Nộ Của Mặt Trời",
    [3083724080] = "Đốt cháy những ngọn lửa rực cháy thiêu rụi kẻ thù nhanh chóng.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên tới phần trăm <i>quá tải</i>.",
    [3083823074] = "Tắt Tiếng Micrô",
    [3084021479] = "Chuông Trang Trí III",
    [3084276092] = "Dấn Thân Ra Ngoài",
    [3084432699] = "Tìm Kiếm Thang Máy Hàng Hóa",
    [3084527606] = "Mỗi lần vung chiếc rìu này sẽ tạo ra một vết rách trên bức màn ngăn cách người sống với thế giới bên kia.\n\n<b>Tiếng vọng Hollow:</b>\nVũ khí giải phóng một tiếng vọng bất thánh, kéo dài tầm tấn công một cách kỳ diệu.",
    [3084535926] = "Không đủ SP!",
    [3084593689] = "Sức Mạnh Của Vukah",
    [3084646895] = "Nó không còn vươn tới những kẻ đau khổ và bị nguyền rủa nữa. Cơn đói trong bóng tối đã bị dập tắt. Giấc mơ và tâm trí của chúng ta an toàn, ít nhất là bây giờ.\n\nThu thập nhiều Đầu Quái Vật Fell để chế tạo Cúp Sắt.",
    [3084820459] = "Bạn đã đốt cháy những ngọn núi - tốt lắm. Nhưng lửa của bạn không phải là ngọn lửa duy nhất sưởi ấm những đêm lạnh giá! Những người lính phương Bắc, hoặc những gì còn sót lại của họ, đang thống trị trên Đỉnh Albaneve! Họ đã mở rộng ra đó để xây dựng Giếng Tinh Hoa, nấu chảy đá vỏ chai và thép để bảo vệ chúng... có lẽ là trong một lò rèn gần đó. Một nơi như vậy chắc chắn có những công cụ tuyệt vời bên trong... những công cụ mà chúng ta có thể sử dụng cho một lò cao!",
    [3085937288] = "Cắt Giáp",
    [3086066174] = "Đèn Gắn Tường Tím II",
    [3086686938] = "Sau khi tinh chỉnh Lọ Thuốc Hồi HP, các thành phần đã được điều chỉnh, ngay lập tức phục hồi một lượng lớn HP khi tiêu thụ.",
    [3086888516] = "Nhắm mục tiêu vào kẻ địch trong vài giây khi ngắm hoặc chặn sẽ đặt một dấu <img gemeffect_focusedlight> lên kẻ địch. Tấn công kẻ địch bị đánh dấu sẽ gây thêm %k ST Hỏa. Dấu ấn có thể cộng dồn tối đa 3 lần bằng cách nhắm mục tiêu liên tục, tăng sát thương cộng thêm lên %k ở 2 dấu và %k ở 3 dấu.",
    [3087007019] = "Hướng Dẫn Mới",
    [3087615254] = "Tìm Đàn Lyre Hiếm",
    [3087878709] = "Elio Ricci",
    [3088658258] = "HP Kẻ Địch",
    [3090117575] = "Xây Dựng M",
    [3090149396] = "Đuốc Gắn Tường Hầm Mộ",
    [3090320456] = "Xương",
    [3090498808] = "Bụi Xương Hóa Thạch",
    [3090726748] = "Đấng Cứu Rỗi",
    [3090849663] = "Nâng Cấp",
    [3090999546] = "Máy quay này có thể tinh chế len và hiệu quả hơn trong việc sản xuất sợi và vải lanh.",
    [3092135516] = "Cái Chết, Sự Tái Sinh Và Vật Phẩm Thất Lạc",
    [3092453066] = "Móc Đu Dưới Nước",
    [3092596110] = "Tái thiết",
    [3093053714] = "Thanh hành động - ô trước",
    [3093500920] = "Chế tạo một phòng thí nghiệm",
    [3093548857] = "Cánh Lượn",
    [3093720192] = "Ngọn lửa đã mách bảo cho ngươi về một con đường mới dẫn đến những ngọn núi phủ tuyết. Để đến được vùng đất biên cương mới này, trước tiên ngươi phải đi qua một lối đi trong hang động.\n\nDu hành qua lối đi trong hang động và tiến vào núi để lan tỏa ngọn lửa của ngươi và kêu gọi một bình minh mới!",
    [3093814676] = "Thợ mỏ",
    [3093924771] = "Tấn công tàn nhẫn",
    [3094531229] = "Ngươi đã đến nhà tù nơi Anton Godwin bị giam giữ. Hãy lục soát nhà tù để tìm bất kỳ dấu vết nào của Anton và giải cứu linh hồn của hắn để làm hài lòng người anh em họ của hắn, Oscar!",
    [3094804786] = "Tìm <keyitem>Lưỡi cưa tròn</keyitem> trong Trại Scavenger",
    [3095475762] = "Menu",
    [3096024783] = "Kho: Thế giới",
    [3096506248] = "Quần Khô Cốt Tinh Nhuệ",
    [3096568106] = "Cà phê, Lợi ích Tuyệt vời Nhất",
    [3096793785] = "Độ khó chỉ có thể thay đổi trước khi bắt đầu một phiên chơi. Để thay đổi độ khó của máy chủ, hãy chọn nó trong danh sách thế giới và nhấp vào \"Chỉnh sửa\".",
    [3097264715] = "Khai thác địa hình lần đầu tiên.",
    [3097947868] = "Cuộc đời của Valory",
    [3097992879] = "Móc Đu",
    [3098696879] = "Những chiếc găng tay này cho phép những ngón tay khéo léo băng bó vết thương khi cần kíp.",
    [3099143085] = "Những tân binh được trang trí đẹp đẽ và thành công nhất đôi khi được tặng vũ khí nhúng vàng. Chúng không sắc bén hơn những món đồ kém ấn tượng hơn, nhưng đóng vai trò là biểu tượng địa vị trong nhóm.",
    [3099198908] = "Xác nhận mật khẩu",
    [3100573551] = "Tranh khảm",
    [3102532590] = "Trái tim bùng cháy",
    [3102767419] = "Nhàn rỗi",
    [3102890654] = "Điều tra điểm dừng thứ ba trên tuyến đường vận chuyển của Kaori để tìm chiếc mũ tiếp theo!",
    [3102927581] = "Đất Nông Trại Nhiễm Chướng Khí",
    [3103040149] = "Cung Của Người Giữ Đền",
    [3103045346] = "Khám phá một cách dễ dàng hơn để cày cuốc vật liệu",
    [3103305719] = "Trở về bình an",
    [3103349914] = "Một cây chùy đã được tìm thấy tại một địa điểm của Vukah.",
    [3103462096] = "Băng Đô Kẻ Săn Mỹ Nhân Ngư",
    [3104090470] = "Cái Bóng Có Cánh",
    [3104506503] = "Tắt",
    [3104601659] = "Số lượng...",
    [3104720071] = "Đâm",
    [3104871307] = "Phù Điêu Drak IV",
    [3104958683] = "Móc Đu",
    [3105005098] = "Bạn khỏe không?",
    [3105902477] = "Khối Đền Drak",
    [3106491165] = "???",
    [3106543333] = "Lô hàng Sương độc bao phủ",
    [3106693721] = "Anh em chia cắt",
    [3107002261] = "Một cây chùy khổng lồ có khả năng gây sát thương ngay cả cho kẻ địch có bộ giáp cứng nhất. Nơi lưỡi kiếm thất bại, cây chùy có thể là một người bạn cần đến.",
    [3107083635] = "Vành kim loại quanh chiếc mũ trùm đầu này tạo thành một chiếc vương miện thanh lịch, lởm chởm ra khỏi hộp sọ của người đội. Hình dáng của các đầu nhọn gợi nhớ đến đôi cánh.",
    [3107386475] = "Một cây Gậy phép tuyệt mỹ mang vẻ ngoài kỳ lạ và ánh mắt trống rỗng. Khuôn mặt của nó dường như đang nhìn lên bạn từ dưới mặt nước đen lặng im của một đầm lầy.",
    [3108063541] = "Hiệu ứng tăng cường tạm thời",
    [3108095507] = "Một bát trái cây tươi mát với lợi ích HP tích cực.\n\nTăng cường HP và SP khi tiêu thụ.",
    [3108117479] = "Trò chuyện",
    [3108220903] = "Tượng Đầm Lầy Đen III",
    [3108236579] = "\"<lorename>Thuyền trưởng Arkwright</lorename>\" được khắc trên kim loại. Tặng cho những chỉ huy trung thành nhất.",
    [3108297681] = "Nhìn xem cái gì dạt vào bờ! Một con cá nhỏ với một con mồi lớn, có vẻ vậy! Những chiếc Vảy Drak trông chắc chắn và tươi ngon... Chúng là của một con non. Chết tiệt! Điều đó có nghĩa là chúng đã có đủ thời gian để sinh sản, đẻ vô số trứng, nở... và nuôi đàn con của chúng bằng đất đai của chúng ta! Để giết con quái vật, hãy chặt đầu nó - nhưng trước khi chúng ta có thể thách thức thủ lĩnh của chúng, chúng ta phải gửi cho chúng một thông điệp mà chúng sẽ hiểu!",
    [3108321517] = "Lõi Ngô",
    [3109445543] = "Khối đá sa thạch hỗn hợp",
    [3110103775] = "Một thanh kiếm thường được các tiểu thư mang theo, đủ mảnh mai để có thể giấu dưới váy nếu cần.",
    [3110148435] = "Hầm tro tàn",
    [3110506407] = "Chế tạo <craftingstation>Trạm giả kim</craftingstation>",
    [3110627127] = "Hào quang nước",
    [3111141369] = "Răng sắt mới giờ đây lấp đầy nụ cười đáng sợ của nó.\n\nThu thập nhiều Đầu Hollow Cyclops để chế tạo Cúp Sắt.",
    [3111159906] = "Chất lượng cài sẵn",
    [3111221590] = "Lò Sưởi",
    [3111818414] = "Cái gì mọc trong bóng tối",
    [3111848857] = "Toàn màn hình",
    [3112134036] = "Sữa Hươu Tiên Sống",
    [3112189546] = "Đồng bằng cho căn cứ đầu tiên",
    [3112410457] = "Một ngày nữa trôi qua. Tuyết làm dịu thế giới bên ngoài, và trái tim tôi nặng trĩu hơn với mỗi nhịp đập. Mỗi đêm mới cạnh tranh với đêm trước để trở thành đêm lạnh nhất. Tôi ước gì em ở bên cạnh tôi để sưởi ấm cho tôi.\n\nAmelie, hôm nay ghế của em bị gãy. Anh đã cố gắng sửa nó, nhưng lưng già của anh đã phản đối. Tuy nhiên, anh cũng không thể vứt nó đi. Nó nằm đó, những mảnh vụn của quá khứ không có tác dụng gì ngoài việc gây đau đớn khi nhớ lại. Thật là một ngày tồi tệ.\nNếu em ở đây, em sẽ làm anh vui lên. Anh sẽ tìm thấy em trong vườn hoa tím mà em yêu thích, mái tóc em đung đưa trong gió như những cánh hoa. Em sẽ quay lại, và ánh sáng trong mắt em sẽ lấp đầy trái tim anh đang mờ mịt, chậm rãi bằng sự tươi sáng.\n\nAnh khao khát chỉ nhớ về em như cơn lốc màu hoa cà đó. Nhìn thấy em khi anh nhìn những bông hoa mùa đông, không phải những gì còn sót lại của một chiếc ghế ọp ẹp.\nNhưng thật khó vì em ở khắp mọi nơi. Trong cái tốt, và cái xấu.\nTuy nhiên, nếu anh có thể bỏ trốn cùng em một lần nữa, anh sẽ làm. Anh sẽ luôn chọn em, viên ngọc thạch tím bé nhỏ của anh.",
    [3112495642] = "Quần từng được mặc bởi binh lính của Chúa <lorename>Vorgoth</lorename>, con trai cả của Nữ hoàng <lorename>Pikemead</lorename>. Truyền thuyết kể rằng ông đã bị Sương độc nuốt chửng sau khi Người Cổ đại đẩy ông khỏi đỉnh Howling Peak.",
    [3112515179] = "Trở nên nghỉ ngơi",
    [3112606640] = "Đầy ắp Tia lửa bùng cháy của Ngọn lửa, nó là một tài sản quý giá trong cuộc chiến chống lại Sương độc. Nó làm tăng thời gian bạn có thể chịu đựng Sương độc.",
    [3112724992] = "Một chiếc túi rỗng. Nó có thể được đổ đầy tại một cái giếng hoặc bất kỳ nguồn nước nào khác.",
    [3112771300] = "Thuốc nhìn xuyên Sương độc",
    [3112849066] = "<location>Thornhold</location> đã rơi vào tay Scavenger. Thị trấn đã bị cướp bóc, và không tìm thấy <keyitem>Lưỡi cưa tròn</keyitem> nào. Có lẽ có những manh mối ở gần đó.",
    [3113425309] = "Sậy nước",
    [3113430318] = "Ngày nay hiếm khi tìm thấy động vật giáp xác, hóa đá hoặc còn sống. Khi cua còn nhiều, chúng được bắt lấy thịt và sau đó ném trở lại biển như những chiếc vỏ rỗng để xoa dịu thủy triều. Truyền thống này đã không bảo vệ được vùng biển khỏi bị Sương độc làm ô nhiễm, vì vậy nó sớm mất đi sự liên quan về văn hóa.\n\nBộ sưu tập này được tìm thấy ở Kindlewastes.",
    [3113851476] = "Tê Tê Cát",
    [3114197243] = "Roostnook",
    [3114205756] = "Một cây đũa phép được khắc từ xương. Vô hồn và lạnh lẽo, nó bắn ra những viên đạn băng ma thuật.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương cộng thêm lên đến phần trăm <i>quá tải</i>.",
    [3114253247] = "Nhà Vệ Sinh Của Thủy Thủ",
    [3114677229] = "Thợ cắt tóc bị cuốn hút bởi Hollow và ánh mắt ghen tị trong đôi mắt chết chóc của chúng. Ông ta đã đề cập đến một nghĩa địa gần thủ đô mà ông ta thường lui tới khi còn trẻ và gợi ý bạn khám phá hầm mộ.\n\n<b>Tiếp cận Hầm mộ Hollow ẩn để tiếp tục!</b>",
    [3114707549] = "<lorename>Lupa</lorename>",
    [3114835742] = "Thịt Cua",
    [3115215488] = "Hãy nghĩ về tất cả sức mạnh bạn có thể sử dụng nếu vũ khí của bạn được trang bị đá quý!",
    [3115501444] = "Truy tìm dấu vết của đoàn lữ hành",
    [3115826194] = "Tia Sáng Hồi Máu Vĩnh Cửu",
    [3116897389] = "Mũi Tên Sắt",
    [3116918967] = "Mảnh tượng <lorename>Pikemead</lorename>",
    [3116965837] = "Tính toán giả kim thuật và kền kền",
    [3117080675] = "Đạt cấp 25.",
    [3117241004] = "Hố dập tắt",
    [3117278103] = "Cơ hội kích hoạt khi tiêu diệt",
    [3118105980] = "Một dạng độc yếu hơn, nhưng vẫn có độc.",
    [3118258031] = "Rìu đốn gỗ gây sát thương <b>30%</b> tăng thêm đối với gỗ, bao gồm cả cây cối.",
    [3118412780] = "Khi một con drakling nở ra từ vỏ của nó, cơ thể thuôn dài, thấp của nó trông gần giống rắn. Tuy nhiên, chúng sớm thích nghi với tư thế thẳng đứng và nhe răng - quá trình này được thể hiện qua thiết kế của cây chùy này.",
    [3119429393] = "Kệ Gỗ Cọ",
    [3119456181] = "25 m × 25 m",
    [3119571053] = "Một luống đất sẽ cho ra Sợi gai dầu.",
    [3119640059] = "<i>(Chữ viết thô kệch, và các dấu hiệu được viết bằng những nét cào ngắn, thờ ơ. Một tấm bảng ghi: Ví dụ về chữ viết Drak sơ khai, được tìm thấy bởi những người đánh cá nạo vét gần quần đảo. Tuổi ước tính: Gần đây.)</i>\n\nDrak'Mer yếu. Tại sao lại sinh sản dưới nước? Đẻ trứng trong ao? Lãng phí thời gian.\nDalszul sẽ không bao giờ làm vậy. Sẽ xây đền thờ. Trang trí bằng vàng. Sẽ ép buộc con người, từng viên gạch một.\n\nDrak trẻ nên nở ra và giậm chân! Nên cắm giáo vào đất thuộc về chúng! Không phải splish và splash!\nĐó là lý do tại sao Drak'Dal mạnh mẽ! Cơ bắp to! Nâng đá! Đổ máu!\nHail Dalszul! Rah Rah!",
    [3120015266] = "Tấn công chém lên",
    [3120095163] = "Thời gian trong Sương độc",
    [3120594517] = "Giữ nhịp sẽ dễ dàng hơn nếu có ai đó chơi trống!",
    [3120612525] = "Tiếp cận và cướp tổ kền kền Draconian",
    [3120618107] = "Cơm",
    [3121042493] = "<lorename>Kẻ Lãng Du Bí Ẩn</lorename> Rương",
    [3121229884] = "Khu vực <location><lorename>Pikemead</lorename>'s Reach</location> đã bị tàn phá. Người bạn của <npc>Nông Dân</npc>, <lorename>Raúl</lorename>, hẳn đang ẩn náu ở một nơi an toàn giữa hiểm nguy. Có lẽ <keyitem>Ấm Nước</keyitem> vẫn còn ở đâu đó.",
    [3121915565] = "Người Hydrak'Dal chắc chắn sẽ phẫn nộ khi bạn phủ đồng lên các đồ trang trí bằng vàng của hắn. May mắn thay, hắn không thể phàn nàn nữa.\n\nThu thập nhiều Đầu Hydrak'Dal để chế tạo Cúp Đồng.",
    [3121961243] = "Nhẹ, có đệm và sẵn sàng chịu vài đòn tấn công — bộ giáp ngực hoàn hảo cho người mới bắt đầu.",
    [3121981132] = "Di chuyển một phần",
    [3121988276] = "Đài Lửa Phế Liệu Đánh Bóng",
    [3122039504] = "Quần Giao Ước Lửa",
    [3122681791] = "Một cặp dao găm màu xám sẫm được tô điểm bằng một viên ngọc màu xanh lá cây tươi sáng như màu của sự ghen tị.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3123540663] = "Tìm kiếm Vũng Than",
    [3123800673] = "Capybara",
    [3123940701] = "Tủ Ly Hầm Mộ Lớn",
    [3124053760] = "Đầu rơi xuống đất, mắt nhắm nghiền vì kinh hoàng. Nạn nhân thà đối mặt với bóng tối còn hơn là đối mặt với Máy Chém.",
    [3124236904] = "Kiếm Ngắn",
    [3124416580] = "Nữ thi sĩ Valory muốn bạn tìm kiếm hóa thạch khắp Embervale. Có bốn hóa thạch trong Revelwood và Blackmire cộng lại. Mỗi hóa thạch có thể tìm thấy nhiều lần ở các địa điểm khác nhau. Nữ thi sĩ khuyên nên tìm kiếm trong các mỏ, khu vực khai quật và mỏ quặng để tìm tất cả hóa thạch.",
    [3125227980] = "Lực Bất Khả Kháng",
    [3125391677] = "Ta tin rằng Sương độc là <i>bào tử</i>. Những mảnh vụn nhỏ bé, gần như li ti lan truyền trong không khí... giờ đã cô đặc, nặng nề và mạnh mẽ. Chúng bám vào đường thở, mắt, lông và da. Chúng lan rộng.\n\n<i>Nấm giải phóng những bào tử này khi tiếp xúc</i>, nhưng rễ của chúng có thể đã bám rễ sâu dưới lòng đất từ lâu... Chúng ta đã đánh thức một căn bệnh đang ngủ yên ở lõi trái đất khi chúng ta <i>xây dựng Giếng Thuốc Đầu Tiên, chưng cất Thuốc Đầu Tiên. <lorename>Kẻ Lãng Du Bí Ẩn</lorename></i> đã mở ra cánh cửa dẫn đến sự hủy diệt.\n\n— Balthazar",
    [3125564178] = "Vũ khí tầm trung",
    [3125797477] = "Sát thương Bùng Nổ Băng",
    [3126242968] = "Con Đường Tăm Tối",
    [3126433033] = "Quần Kẻ Phá Phép",
    [3126491091] = "Một nhạc cụ bằng thép chơi bằng tay, có âm thanh nhẹ nhàng lan tỏa như những gợn sóng trên mặt nước tĩnh lặng.",
    [3127058058] = "Vây Hay Tưởng Tượng?",
    [3127276217] = "Một đôi ủng của chiến binh từng lấp lánh ánh vàng. Chúng đã xỉn màu do sự phát triển quá mức của nấm.\n\nCung cấp sự bảo vệ kéo dài chống lại Sương độc.",
    [3127334285] = "Cơ Bản",
    [3127542323] = "Ta muốn có một chú Bò Yak nhỏ xinh làm bạn mới...",
    [3128461742] = "<b>Thời gian trong Sương độc</b> tăng thêm <b>2</b> phút, cho phép bạn khám phá lâu hơn.\n\n<b>Thời gian trong Sương độc</b>\nNếu thời gian này hết, Sương độc sẽ nuốt chửng bạn.",
    [3128504794] = "Lái",
    [3128654914] = "Một chiếc mũ vừa thực tế vừa thú vị với lớp lông mềm mại.",
    [3129066666] = "Tỷ lệ chí mạng",
    [3129788191] = "Sương độc, Thuốc và Giếng Thuốc",
    [3129793382] = "Găng tay gia cố với lớp giáp chitin tự chế.",
    [3129970303] = "Cảm ơn bạn đã chơi!",
    [3130259637] = "Nhập vai",
    [3130895028] = "Tìm Khối Xây Dựng",
    [3131056025] = "Một vũ khí tổ tiên từ dòng dõi kiêu hãnh của nhà Galeforth, lần cuối cùng được nắm giữ bởi Virgil Galeforth. Ông ta nổi tiếng nói: \"Nếu muốn vũ khí này, ngươi phải giật lấy từ tay ta khi ta đã lạnh ngắt, chết đi.\"",
    [3131078746] = "Tủ Gỗ Phương Bắc Lớn",
    [3131424593] = "<craftingstation>Dụng Cụ Thợ Mộc</craftingstation>",
    [3131856068] = "Một chiếc vương miện kim loại, tràn đầy năng lượng điện giật. Đeo nó khiến lông trên cơ thể bạn dựng đứng.",
    [3132030164] = "Rìu Của Fenrig",
    [3132066890] = "Thợ Săn <npc>Athalan Skree</npc> muốn xem <b>lông thú.</b> Bà ấy sẽ chia sẻ một bí mật với bạn khi bạn mang cho bà ấy một ít.",
    [3132140923] = "Trứng",
    [3132180844] = "Một công cụ tạm thời dùng để cắt nhanh và xấu xí.",
    [3132312522] = "Áo Giáp Đạo Sư Băng Ngọc",
    [3133366426] = "Kích hoạt",
    [3133402759] = "Bản vẽ",
    [3133454155] = "Các cạnh sắc nhọn nhô ra từ rìa lưỡi kiếm: một loạt gai nhọn, đá lửa mài sắc và sừng. Một cú đánh từ cạnh răng cưa này sẽ xé toạc hầu hết mọi thứ.",
    [3133657387] = "Mũi Tên Sắt Tẩm Độc",
    [3133851891] = "Những con dao găm này đánh dấu giai đoạn tiếp theo cho Drak trẻ tuổi sau khi luyện tập với gậy tre. Kích thước nhỏ gọn của chúng giúp chúng dễ dàng sử dụng ngay cả từ khi còn nhỏ.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3134517416] = "Chư vị lãnh chúa, ta cảm thấy thật kinh tởm... nhưng ít nhất ta vẫn còn thở! Tên ta là Kaori Conway, ta vận chuyển hàng hóa cùng với đối tác của mình! Bạn trai ta có ở đâu không? Ta phải thú nhận với chàng rằng ta đã mất một số hàng hóa vì... ờm... một trục bánh xe bị lỗi.",
    [3134706111] = "Tất cả vật phẩm đã sửa chữa",
    [3134868872] = "Chào mừng đến <location>Pháo Đài Kelvin</location>",
    [3135225450] = "Sử thi",
    [3135298843] = "Đánh bại kẻ địch bằng vũ khí cận chiến sẽ khôi phục <b>1</b> độ bền cho vũ khí đó.",
    [3135856987] = "Có ai nhìn thấy những con chó săn mà chúng ta đã tịch thu của tù nhân <lorename>Lupa</lorename> không?\n\nTôi đã để chúng lang thang trong sân, nhưng khi tôi thức dậy vào sáng hôm qua, chúng đã biến mất! Tôi chắc chắn chúng chỉ trốn thoát thôi... nhưng có điều gì đó mách bảo tôi rằng cái lạnh đột ngột của buổi tối hôm đó, và tiếng hú kỳ lạ vào lúc nửa đêm không phải là sự trùng hợp.\n\n<b>Tôi đã thấy dấu vết dẫn đến tòa tháp gần đó</b>, nhưng tôi sẽ là một kẻ ngốc nếu đi theo chúng! Chúng ta không thể nhờ một thực tập sinh kiểm tra thay sao?",
    [3136334568] = "Khi lần đầu tiên nhìn thấy phần thưởng, <lorename>Kẻ Lãng Du Bí Ẩn</lorename> đã hứa với ta, ta đã cảm thấy bị xúc phạm. \nTuy nhiên, ta nhanh chóng nhận ra đây là cách của <i>bóng ma này</i>, bóng ma bóp méo thực tại như thể ta đang bước vào một giấc mơ. \n\nTa đã giấu <b>cây Gậy phép bị hỏng</b> trên đỉnh cấu trúc gỗ để nhìn ra nhà máy chưng cất Thuốc — chỉ ta mới xứng đáng với nó. Những ảo ảnh về bóng người lơ lửng vẫn ám ảnh ta... Ta cảm thấy mình vẫn đang mơ.",
    [3136376212] = "Găng Tay Hoa Hồng Máu",
    [3136391213] = "Hành Trình Của Valory",
    [3136563967] = "Quả Mọng Tím",
    [3137065254] = "Một hạt giống sẽ phát triển thành cây khi gieo vào đất thích hợp. Khi cây trưởng thành hoàn toàn, nó có thể thu hoạch nhiều lần.",
    [3139073540] = "Tìm Thấy Chùy",
    [3139548003] = "Sát thương Đốt mỗi giây",
    [3139571057] = "Thời gian trong Sương độc",
    [3139993907] = "Nhẫn Thể Lực Tuyệt Hảo",
    [3140193247] = "Tủ Đầu Giường Gỗ Chạm Khắc",
    [3140502958] = "Chuột Chũi Thung Lũng Nước Vải",
    [3141216609] = "Độ trễ hồi phục MP",
    [3141398508] = "Không có vật phẩm nào được trang bị.",
    [3141512281] = "Tăng <b>Kháng Sương độc</b> của bạn thêm <b>5%</b>, giúp giảm lượng sát thương <b>Sương độc</b> nhận vào.",
    [3141603861] = "Giáp cung cấp sự bảo vệ dựa trên giá trị Giáp của nó.\nMỗi điểm Giáp giảm sát thương nhận vào đi 1, tối đa là 60% giảm sát thương. Mức tối đa này có thể tăng lên bằng kỹ năng.\n\nCó các loại Giáp vật lý và phép thuật, mỗi loại tương ứng với loại sát thương nhận vào. Kiểm tra giá trị Giáp của vật phẩm trong Kho đồ.",
    [3141698105] = "Khối Gỗ Thông",
    [3141808879] = "Đến Vị Trí Mỏ Sắt",
    [3142390299] = "Đá Vụn Hoang Mạc Lửa",
    [3142926586] = "Nấm Shiitake Nướng",
    [3142975435] = "Thay đổi góc",
    [3143219677] = "Thánh",
    [3143374691] = "Khi hiệu ứng Thuốc đang hoạt động, gây sát thương sẽ kích hoạt hiệu ứng \"Cuồng Chiến Hài Lòng\", mang lại %k hồi HP, %k hồi SP và %k hồi MP trong %k. Mỗi đòn đánh thêm sẽ làm mới thời gian hiệu ứng đó; tuy nhiên, một khi nó hết, hiệu ứng \"Cuồng Chiến Không Hài Lòng\" sẽ tạm dừng mọi sự hồi HP, hồi SP và hồi MP trong %k.",
    [3143526923] = "Vui vẻ",
    [3143570675] = "Săn Tìm Màu Tóc: Xanh Lục Tuyệt Vời Nhất",
    [3143583565] = "Nhìn xem ai đây!",
    [3143586369] = "Những Bài Hát Sưởi Ấm Trái Tim Bạn",
    [3143708429] = "Đá Vụn Cao Nguyên Du Mục",
    [3143786836] = "<h2>11. Thay đổi đối với chính sách bảo mật này</h2>\n\nPhiên bản hiện tại của chính sách bảo mật này luôn có sẵn tại",
    [3143935328] = "Vây Than",
    [3144141133] = "Hồi HP",
    [3145092108] = "Đòn đánh hồi phục một phần sát thương gây ra dưới dạng HP",
    [3145365594] = "Nhật Ký Của Garrick",
    [3146771653] = "Vị Trí Thợ Mộc <npc>",
    [3146971151] = "Bùn mềm, ngậm nước, được kéo lên từ đáy hồ hoặc dòng suối lặng lẽ.",
    [3146998620] = "Ta đang lắng nghe đây.",
    [3147080407] = "(Cá nhân: %k + Được ban phước Ngọn lửa: %k + Tăng cường tạm thời: %k)",
    [3147118758] = "Rương Học Trò Giả Kim Thuật <npc>",
    [3147277454] = "Hãy thử tìm kiếm ở các thị trấn và làng mạc nhỏ — có lẽ người dân ở đó đã để lại những tia lửa cảm hứng.",
    [3147491265] = "Ít",
    [3147682946] = "Kinh nghiệm chiến đấu",
    [3147814482] = "Cúp Danh Năng Thú Sấm Sa Ngã",
    [3148204644] = "Nhà Sưu Tầm <npc>",
    [3148777000] = "Các chi tiết trang trí trên thanh kiếm này dường như lấy cảm hứng từ nghề thủ công phương Đông, nhưng việc lựa chọn vật liệu lại phản bội nguồn gốc của người chế tạo. Vũ khí này rất có thể được rèn bởi một thợ rèn đã đi nhiều nơi hoặc được đặt hàng bởi một quý tộc.",
    [3148873511] = "Neo Móc Đu Đu Đưa",
    [3148966209] = "Một bản nhạc cho bài hát tươi sáng phù hợp với bất kỳ quán rượu sôi động nào.\n\n<b>Bản Nhạc</b>: \nBản nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ bản nhạc trong kho đồ để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát.",
    [3148974865] = "Có thể đặt các bàn thờ Ngọn lửa, dập tắt Ngọn lửa và nâng cấp căn cứ",
    [3150172893] = "Những chiếc ủng vàng này đã đưa \"Học Giả Trẻ Tuổi\" băng qua những con đường rộng lớn của Embervale. Đế giày vẫn còn vương bụi từ những nơi mà bạn chưa khám phá.",
    [3150296484] = "Tôi lại chán màu tóc rồi. Tôi cần thứ gì đó \"tươi mới\" hơn, như một luồng nước lạnh! Nghĩ mà xem... không gì tươi mới hơn băng từ Đỉnh Albaneve! Ở độ cao đó, bạn cũng sẽ gần với các vì sao. Trái tim tôi thôi thúc tôi đi về phía bắc, nhưng nỗi sợ độ cao lại chỉ thị tôi gửi bạn đi thay. Tôi là thợ làm tóc, không phải người leo núi!",
    [3150518896] = "Cà phê được pha thêm một chút sữa. Hương thơm dịu nhẹ giúp dễ dàng thưởng thức!",
    [3151003455] = "Tiêu diệt",
    [3151200301] = "Bia Mộ \"Cho Đến Khi Chúng Ta Gặp Lại\"",
    [3151923226] = "Một cuộc hành trình thú vị bắt đầu! Tôi khởi hành từ <location>Brittlebush</location> nơi tôi đã mặc cả để có được <i>tấm bản đồ này.</i> Tôi tự hỏi liệu <i>Ốc đảo</i> bí ẩn này có thực sự tươi tốt như người bán đã hứa không? \n\nBất kể điều gì, tôi đã bán hết tài sản thế gian và mua đủ lương thực, nước uống để đi và về! Tôi suýt nữa không đủ, nhưng việc bán chiếc Tàu Lượn tin cậy của mình đã lấp đầy túi tôi với đầy tiền xu!\n\n May mắn thay! Tôi dự định cắm trại bên cạnh <i>xương cổ đại ở phía đông.</i>",
    [3152029836] = "Sản phẩm phụ này của Lò Than có nhiều đặc tính hữu ích, có thể dùng trong y học và giả kim thuật.",
    [3152356310] = "Không gì phù hợp hơn cho một cuộc tuần tra dài hơn bộ quần này.",
    [3152859930] = "Tốc độ di chuyển của tất cả kẻ địch trong phạm vi 10 mét bị giảm một nửa.",
    [3153593284] = "Cây Dừa",
    [3154266751] = "Tháp",
    [3154276865] = "Cột Tổ Tiên Đá Drak II",
    [3154361743] = "Búa Khổng Lồ",
    [3154463474] = "Hai Bộ Tộc, Hai Ngọn Lửa",
    [3154496583] = "Một Chân Trong Mộ",
    [3154580102] = "Thợ Săn cần một Máy Quay để tinh chế len thô. Hãy chế tạo Máy Quay cùng cô ấy để tiếp tục!",
    [3154785647] = "Máng Nước",
    [3154878401] = "Anh Em Conway",
    [3155117136] = "Nhím Biển",
    [3155138684] = "Được chế tác để giống với đôi cánh của những sinh vật khét tiếng nhất ở Kindlewastes, Kền Kền Rồng.",
    [3155642218] = "Sức Hút Của Xoáy Ốc",
    [3155722891] = "Mũ Ảo Thuật Gia",
    [3156012468] = "Một loài cây nổi tiếng với hoa và sắc tố hữu cơ màu xanh đậm có thể thu được bằng cách chế biến nó.",
    [3156337639] = "Hào Quang Gió",
    [3156413346] = "Thợ Rèn đã tiết lộ vị trí của một mỏ sắt dưới Sương độc. Địa điểm đã được đánh dấu trên bản đồ.",
    [3156669984] = "Flameborn — Bạn đã khám phá Giếng Thuốc nào ở Kindlewastes chưa? Chúng là những thứ non trẻ nhất! Ồ, chúng khiến tôi rùng mình. Nếu chúng ta lấy được một ít <b>Khối Giếng</b> từ vực sâu của chúng, chúng ta có thể tạo ra một tượng đài thực sự!",
    [3158876455] = "Luồng Khí Lên",
    [3158977408] = "Xem Tôi Tìm Thấy Gì",
    [3159130138] = "Thật khó tin là có một loại thuốc pha chế tốt hơn.\n\nLoại này ngay lập tức phục hồi một lượng lớn HP.",
    [3159282769] = "Những nguyên liệu tìm thấy ở Đỉnh Albaneve khiến tôi cảm thấy đầy cảm hứng. Chúng ta nên cùng nhau nấu một món ăn vùng miền! Một thứ gì đó sẽ giữ ấm và thoải mái cho chúng ta... như thịt, món hầm thịt bò, hoặc súp bí ngô kem!",
    [3159326695] = "Cao",
    [3161277957] = "Fell",
    [3161354835] = "Một tinh thể địa đàng lớn. Các đặc tính của nó cho phép lưu trữ sinh lực trong hàng thế kỷ.",
    [3161357391] = "Costner Meyers",
    [3161369759] = "Âm nhạc nghe hay hơn khi có bạn.",
    [3162045839] = "Áo Giáp Sát Thủ",
    [3162094096] = "Tìm Kiếm Phép Thuật Vĩnh Cửu",
    [3162606317] = "Giỏ Tre Lớn",
    [3162628024] = "Viên đạn ma thuật, khi sử dụng, sẽ giải phóng các luồng Chữa thương liên tục.\n\n<b>Phép Thuật Kênh Dẫn:</b> Giữ nút bấm để kênh dẫn <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép với một <b>gậy phép.</b>",
    [3163053954] = "Obelisk Cổ Đại",
    [3163179967] = "<b>DaryRakiro</b>\nLần cuối nhìn thấy trong một dòng suối\n\n<b>Fox Dũng Cảm</b>\nPhù thủy, Người tình, Kẻ ăn thịt người\n\n<b>Britva</b>\nMẹ, Nhà của Dấu gạch dưới\n\n<b>Bí Ngô Kyie Nassu</b>\nĐào mộ mình, giờ nằm trong đó\n\n<b>Futerko</b>\nNữ hoàng của những đế chế nhỏ\n\n<b>Ngài Frandulin và Phu nhân Petrana</b>\nNếu thời gian kết thúc, vĩnh cửu bắt đầu\n\n<b>Nữ Chủ Sianna</b>\nBạn đồng hành của Chủ nhân Fluffers\n\n<b>Đây là nơi an nghỉ của Ông Bà Gingey</b>\nNhững người yêu nhau từ những nơi khác nhau\n\n<b>Lafondar Kẻ Hèn Hạ</b>\nĐã đóng hộp, giờ được đóng hộp vĩnh cửu\n\n<b>Noveron</b>\nChết cùng nhau ở Leubogdania\n",
    [3163470236] = "Một ngày tốt lành để sống, phải không? Tôi là Chester, và mọi người gọi tôi là Chester Loft \"May Mắn\". Tôi đoán hôm nay không phải may mắn đã cứu tôi, mà là hành động anh hùng dũng cảm của bạn! Ồ, tôi thật cảm hứng! Bạn muốn một bài sonnet hay một vở opera theo tên bạn?",
    [3163881846] = "Bộ Hailcaster",
    [3164459139] = "Búa Dê",
    [3164537393] = "Đĩa Đồng Thiếc",
    [3165248686] = "Mang Hoa Lạc Tiên đến cho Thợ Cắt Tóc",
    [3165773754] = "Bào Tử Chướng Khí Tươi",
    [3165940493] = "Quần Phu Đào Mộ",
    [3166067321] = "Khối Đá Trang Trí",
    [3166230832] = "Đèn Gắn Tường Màu Cam I",
    [3166414647] = "Nhiệm vụ Embervale Bỏ Lỡ đang hoạt động",
    [3166414762] = "Sử dụng muối để bảo quản da để sử dụng tiếp. Đặt gần <npc>Thợ Săn</npc>.",
    [3166523359] = "Khi bạn nhận sát thương <b>Sương độc</b>, tất cả người chơi trong phạm vi <b>20</b> mét nhận <b>15%</b> <b>Kháng Sương độc</b> tăng cường trong <b>30</b> giây.",
    [3166538907] = "Thu Hoạch Trang Trại",
    [3166756089] = "Bao Tải Tiếp Tế I",
    [3167636287] = "Ma-nơ-canh \"Tôi Đến Đây\"",
    [3167750960] = "Mắt Đại Bàng",
    [3167894561] = "Thời gian còn lại: %k %k",
    [3167924810] = "Vũ khí",
    [3168085665] = "Cauterize vết thương. Thanh tẩy vết bẩn đang lan rộng và xóa bỏ mầm bệnh đang hoại tử. Ánh sáng của Ngọn Lửa không thể bị từ chối.\n\nThu thập nhiều Đầu Sấm Sét Fell để chế tạo Tượng Sắt.",
    [3168649865] = "Đã đạt được hiểu biết mới!",
    [3169239905] = "Sự bổ sung mới nhất của Vua <lorename>Gormander</lorename> cho <location><lorename>Pikemead</lorename>'s Reach</location> là, theo ý kiến của tôi, một sự sỉ nhục — và là nỗ lực yếu kém của một người đàn ông có hàm răng gỗ để đạt được sự ngưỡng mộ của mẹ mình.\n\nĐó là một câu chuyện nông cạn hơn cả vùng nước White Wind. Mùa hè năm ngoái, nỗ lực của lãnh chúa chúng ta nhằm đổi tên Vườn Hoàng Gia thành \"Vườn <lorename>Gormander</lorename>\" đã bị chặn lại bởi sự bất ổn dân sự. Thay vào đó, chúng ta đã được ban tặng một bức tượng của ông ta.\n\n<b>Ánh mắt của bức tượng cứng đờ và tê liệt</b> như thái độ của người cai trị chúng ta đối với những rắc rối đang nhen nhóm ở phương Bắc. Điều tuyệt vời nhất về <lorename>Gormander</lorename>, bên cạnh kho bạc của ông ta, là cái răng cửa bằng gỗ của ông ta. — Ramone Jones, biên tập viên của The Pike Weekly.",
    [3169355702] = "Cuộc nói chuyện của bạn với Nhà Giả Kim thật khai sáng, nhưng cũng đáng lo ngại.\n\nBạn đã biết mình bị nguyền rủa trong chuyến thám hiểm cuối cùng vào Sương độc. Căn bệnh này có những hậu quả lâu dài đối với sức sống của bạn, và bạn sẽ phải chịu đựng sự mệt mỏi này cho đến khi tìm được cách chữa trị.\n\n<b>Cách chữa trị có thể được chế tạo</b> từ các nguyên liệu có thể tìm thấy <b>trên Sương độc vào ban đêm,</b> rải rác giữa các nhóm kẻ địch Fell.\n\nThu thập nguyên liệu, chế tạo thuốc chữa và sử dụng nó để thanh tẩy bản thân.",
    [3169489003] = "Trường Kiếm Sắc Bén",
    [3169854567] = "Ý Chí Sắt Đá",
    [3170483830] = "Giải Thoát Khỏi Lửa",
    [3170785402] = "Cây Giống Chuối",
    [3170968162] = "Dụng Cụ Khuấy Bơ",
    [3171014564] = "Chế Tạo hoặc Nhận Bình Tinh Lực Lặn",
    [3171326575] = "Một Bộ Quần Áo Mới",
    [3171498015] = "Một cây Gậy phép ma thuật dễ dàng đan xen các sợi dây số phận với Sương độc.",
    [3171995263] = "Nguy hiểm: Chất nổ",
    [3172194497] = "Khối Sa Thạch Thô",
    [3172652715] = "Những người sống sót có thể nâng cấp trang bị của bạn và cho phép bạn truy cập vào ba lô và công thức chế tạo thủ công của mình.",
    [3174589448] = "Dân Làng",
    [3174601129] = "Fenn, Bầy Sói Phải Đi",
    [3174954965] = "Bắt đầu một trò chơi riêng tư",
    [3175261909] = "Drak",
    [3176769600] = "Một chiếc búa được trang trí bằng một chiếc ngà hóa thạch cổ xưa. Ngà và răng được người Vukah sử dụng cho các mục đích huyền bí.",
    [3177366679] = "Nhà Sưu Tầm đã đề cập rằng các Mảnh Địa Đàng bên trong Sảnh Hollow của Cao Nguyên Du Mục có màu sắc và phẩm chất hoàn hảo để tạo ra một màu xanh lá cây bí ẩn.\nNhà Sưu Tầm có thể chế tạo một chiếc chìa khóa để mở Sảnh cho bạn chỉ khi bạn đã đi qua các Sảnh trước đó.\n\nThu thập Mảnh Địa Đàng trong Sảnh Hollow của Cao Nguyên Du Mục và mang chúng trở lại cho Thợ Cắt Tóc trong kho đồ của bạn!",
    [3177620583] = "Sở hữu các đặc tính ma thuật, xương của người chết thường được sử dụng trong giả kim thuật.",
    [3177858669] = "Trang Trí Tường",
    [3177932123] = "Một Câu Chuyện Về Lửa",
    [3178003058] = "Thịt Nấm Hồng",
    [3178174507] = "Khi thảm họa ập đến, chúng ta đã thích nghi. Vươn lên trên mọi giới hạn, thoát khỏi định kiến và quy ước. Một <i>nhóm nhỏ các cổ nhân</i>, thường ẩn mình trong im lặng và bí ẩn, đã hợp tác với con người để xây dựng <b>Hầm Cinder.</b> Chúng chứa đựng hy vọng duy nhất còn lại của nhân loại, ẩn mình khỏi Sương độc... Ngủ yên, chờ đợi được đánh thức bởi Flameborn.",
    [3179387013] = "Gạch được tạo ra từ đất sét. Tuy nhiên, không phải ai cũng biết rằng nó không chỉ có hình dạng tiện dụng mà còn khá chắc chắn.",
    [3179602994] = "Thú Bông Bọ",
    [3179785336] = "Tìm Đồ Trang Trí Lễ Hội Hollow",
    [3179882385] = "Cấp độ %k",
    [3180062651] = "Một Người Chăn Cừu Đồng Hành",
    [3180399008] = "Địa Đàng Ngoại Hạng",
    [3180482497] = "Điều kiện",
    [3180543282] = "Vẫn còn máu để đổ!",
    [3180863901] = "Tốc độ Chạy Nhanh",
    [3180932029] = "Ngọc Triệu Hồn Thuật Sơ Cấp",
    [3180936002] = "Bình thuốc MP Cải tiến",
    [3181143449] = "Biểu Tượng Tường Hình Khiên I",
    [3181582973] = "Trái tim của Hang Sương độc bị ám bởi một Fell Banshee. Sương độc sẽ tiếp tục lan rộng ở đây và đánh cắp tài nguyên để nuôi dưỡng đàn con của chúng trừ khi Banshee bị tiêu diệt!\n\n<b>Đánh bại Fell Banshee</b> và nhận <b>chiến lợi phẩm</b> của cô ta!",
    [3182260374] = "Khiên Bò Tót Đồng",
    [3182360165] = "Tôi có thể làm được!",
    [3182459822] = "Mồi Câu Cá Thường",
    [3182500345] = "Mục Tiêu Đầy!",
    [3182748915] = "Thánh Địa Đêm",
    [3183285957] = "<craftingstation>Bàn Thợ Mộc</craftingstation>",
    [3183812080] = "Một vật phẩm sức mạnh. Hãy cho Ngọn Lửa để nhận lấy sức mạnh của nó.",
    [3184121499] = "Tạm biệt.",
    [3184934940] = "Giày Hoàng Gia",
    [3185021472] = "Tiếp Cận Lối Đi Hang Núi",
    [3185553293] = "Giải Phóng",
    [3185557239] = "Hai dây đeo da, khóa chặt bằng pha lê ectoplasm bị yểm bùa, niêm phong những lời thì thầm của cuốn sách này. Mặc dù cổ xưa, bìa sách ngọc lục bảo tinh xảo không có dấu hiệu của thời gian hay sự mục nát.",
    [3185638540] = "Cày Cuốc Bất Tận",
    [3185798783] = "Sinh Tồn",
    [3186051258] = "Hội Đạo Tặc",
    [3186411434] = "Cầu Thang",
    [3186633954] = "Chế tạo hoặc nhận được một chiếc dù lượn.",
    [3187021150] = "Chúng Khủng Bố Trên Đường!",
    [3187542089] = "Bọt Biển",
    [3188517896] = "Hành Trang: Ba Lô",
    [3188687342] = "Găng tay nặng có thể vung bất kỳ vũ khí nào với sức mạnh tăng thêm.",
    [3188829927] = "Cúp Danh Năng Hộp Sọ II",
    [3188912415] = "Đền Thờ Ẩn Giấu",
    [3189209085] = "Người <npc>Sưu Tầm</npc> đã nói về những con quái vật Hollow vốn có nguồn gốc từ phương Bắc.\n\nNhững gã khổng lồ một mắt đã bị Ngọn Lửa nguyền rủa và rời bỏ đỉnh núi của chúng để thoát khỏi số phận, nhưng vô ích. Giờ đây, chúng lang thang trong những vực sâu nhất của Sảnh Hollow.",
    [3189394239] = "Phần này hiển thị tổng quan về tất cả các nhiệm vụ bạn đã hoàn thành.",
    [3189395525] = "Chứa đầy các thành phần phục hồi HP, nó ngay lập tức phục hồi một lượng lớn máu.",
    [3189475155] = "Tia Lửa Cao Nguyên Du Mục",
    [3189529076] = "Chuyển Đổi Lựa Chọn Vật Liệu",
    [3189641268] = "Nói Chuyện Với Thợ Mộc Về Chiếc Đèn Lồng",
    [3189982681] = "Tìm tất cả các đền thờ và thánh địa Ngọn lửa trong Vùng Đất Mùa Xuân.",
    [3190882897] = "Chảo Phế Liệu I",
    [3190937606] = "Chọn vật liệu bạn muốn xây dựng.",
    [3191251273] = "Bạn đã đến Tháp Cổ trong Đỉnh Albaneve.\n\nLeo lên đỉnh Tháp Cổ và nói chuyện với Ngọn Lửa để tiếp tục!",
    [3191295395] = "Lễ Kỷ Niệm",
    [3191556388] = "kho báu bị chôn vùi của <lorename>Gormander</lorename>",
    [3191592413] = "Các rãnh xoắn ốc khắc sâu vào thân Đũa phép, tạo thành một kênh để hút máu kẻ thù. Năng lượng của chúng sẽ nuôi dưỡng bạn sau khi chúng đã chết.\n\n<b>Quá Tải:</b>\nĐũa phép này có cơ hội khuếch đại sát thương gây ra. Các đòn tấn công gây thêm sát thương lên đến tỷ lệ <i>quá tải</i>.\n\n<b>Đa Xạ:</b>\nBắn nhiều viên đạn nhưng với sát thương giảm.",
    [3192214616] = "ST Cận chiến Không Vũ Khí",
    [3192490268] = "Tỷ lệ HP của tất cả kẻ địch theo giá trị này.",
    [3192808847] = "Bạn vẫn đang tìm kiếm những nhạc cụ hiếm đó sao? Nếu chúng ta tìm thấy tất cả, có lẽ chúng ta có thể chơi bài hát yêu thích của tôi của Honeydews: Honey Rain Rhapsody!",
    [3192869682] = "Nhạc Cụ Sử Thi Đã Thu Thập",
    [3193268552] = "Đá Bia",
    [3193370166] = "SP",
    [3193644544] = "Chi Phí MP",
    [3194227448] = "Tỷ Lệ Kích Hoạt Khi Hồi Máu",
    [3195039948] = "Tôi làm việc ngày đêm để xây dựng Tiền Đồn Bora. Vậy mà chúng ta vẫn sống trong túp lều khiêm tốn này. Tất cả công sức này, để làm gì?\n\nTôi đã giấu một ít <b>khối đá granite đánh bóng dưới cầu thang ở tiền đồn.</b> Khi màn đêm buông xuống, tôi sẽ mang chúng về nhà và bắt đầu sửa sang cho con của chúng ta. Chúng ta xứng đáng với điều đó.",
    [3195256880] = "Di chuyển xuống",
    [3195357619] = "Thuần Hóa Một Con Yak",
    [3196513468] = "Tỷ Lệ Kích Hoạt Đa Xạ",
    [3196652451] = "\"Tòa Tháp Trong Đêm\"",
    [3196917130] = "Sự Nhanh Nhẹn sẽ kích hoạt ở đòn đánh tiếp theo của bạn",
    [3197300012] = "Bài Hát Uống Rượu",
    [3197819807] = "Màu Sắc Của Đỉnh Pha Lê",
    [3199096055] = "Hào Quang Nước",
    [3199961991] = "Khai thác trong Sương độc Thung lũng Veilwater",
    [3200079039] = "Vinh Quang Lại Trỗi Dậy Từ Vực Sâu!",
    [3200593706] = "Đặt <craftingstation>Dụng Cụ Thợ Mộc</craftingstation>",
    [3200953574] = "Nó Trở Lại",
    [3201507376] = "Áo giáp này bao gồm một lớp áo lót lụa trắng để giữ ấm và một chiếc áo choàng màu xanh lam bay bổng để cách nhiệt thêm và tạo hiệu ứng ấn tượng.",
    [3201636811] = "Một nguyên liệu cơ bản cho tất cả áo giáp tiên tiến. Lớp đệm được thêm vào bên dưới lớp vỏ cứng có thể tạo sự thoải mái và giảm va đập.\n\n<b>Một Khung Cửi</b> là cần thiết để chế tạo cả <b>lớp đệm</b> và áo giáp tiên tiến.",
    [3201985795] = "Những vòng tròn bay lượn quanh đỉnh núi của chúng — Xa, xa lắm\nNhững hình dáng và bóng tối tinh tế, được bao quanh bởi ánh nắng ban mai\n\nNhững đôi cánh rực lửa hướng về mỏ chim phủ bụi — Hãy trốn, hãy ẩn mình\nRút lui khỏi hơi ấm và ánh sáng, khi tia nắng ban trưa đến\n\nCuộn mình lên với cơn gió lốc chói lóa — Khi hoàng hôn, chúng lại trỗi dậy\nXuất hiện mới từ những đám mây tối hơn, bay cao hơn với cơn gió mạnh\n\nNhững đốm bụi bạc li ti — Gần, gần ngay trước mắt chúng ta\nChúng đã đến quá gần, ôi Ngọn Lửa hãy bảo vệ chúng ta khỏi cơn thịnh nộ đang giáng xuống",
    [3202678784] = "Tôi chỉ có thể làm được bấy nhiêu với đôi tay trần của mình, nhưng <keyitem>Ấm Đun Nước</keyitem> cũ của tôi có thể giúp chúng ta có những bữa ăn tuyệt vời khi sử dụng trên <craftingstation>Bếp Nấu</craftingstation>. Bạn đã nói chuyện với bạn của tôi <b><lorename>Raúl</lorename></b> chưa? Anh ấy nên có <keyitem>Ấm Đun Nước</keyitem> của tôi!",
    [3203058019] = "Quần Thợ Rèn",
    [3203369115] = "Một miếng cá áp chảo chỉ có thể chế biến ngon như vậy trong lồng nướng cá. Nó rất đậm đà hương vị.",
    [3203375231] = "Cúp Danh Năng Hộp Sọ IV",
    [3203377692] = "Nơi Sản Xuất",
    [3203744016] = "Đạn Băng II",
    [3204205011] = "Bình Bí Ẩn",
    [3204860482] = "Áo Giáp Khô Cốt Độc Quyền",
    [3205029831] = "Lửa Thanh Tẩy",
    [3205398412] = "Cúp Danh Năng Thú Sấm Sa Ngã Bằng Vàng",
    [3205634853] = "Đánh Bại Quái Vật Lâu Đài",
    [3205803953] = "Giữ để triệu hồi các viên đạn xương tìm kiếm kẻ thù với sức mạnh tàn phá.\n\n<b>Phép Thuật Kênh Dẫn:</b> Giữ nút để kênh dẫn <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [3206056039] = "Một chiếc rìu dùng để đốn cây. Kém hiệu quả hơn một chút khi chống lại sói.",
    [3207124707] = "Khám Phá <location>Pháo Đài Quạ</location>",
    [3207286625] = "Nguồn lực cho các hành động gắng sức về thể chất như chạy nước rút, chặn, né tránh và các hành động khác.",
    [3207596760] = "Thoải Mái",
    [3207617681] = "Chế tạo các khối mái nhà tại <craftingstation>Bàn Chế Tạo</craftingstation>.",
    [3207856803] = "Bậc Thầy Quái Vật",
    [3208111312] = "Quyết Tâm Của Ngư Dân",
    [3209780646] = "Chúng ta đang chuẩn bị. Tốt. Nhưng dù có chuẩn bị kỹ đến đâu, chúng ta cũng không thể đánh bại Drak trong trò chơi của chúng... việc di chuyển dưới nước vẫn sẽ là một thử thách trừ khi chúng ta có thêm không khí trong phổi. Đừng lo lắng. Quân đội của chúng ta có các đội thợ lặn chuyên nghiệp được trang bị công cụ phù hợp cho các nhiệm vụ kéo dài. Tôi sẽ chỉ cho bạn nơi họ được triển khai lần cuối.",
    [3209874891] = "Trọng Kiếm Có Sừng",
    [3211549216] = "Một Thanh Kiếm Đồng Đơn Giản Bị Rỉ Sét, Hư Hỏng Theo Thời Gian. Những Ngày Tốt Đẹp Nhất Đã Qua Xa.",
    [3211619327] = "Mũ Tiệc Vàng",
    [3212000668] = "Nữ Bard Valory cần nơi trú ẩn. Hãy cung cấp cho cô ấy một căn phòng ấm áp, dễ chịu để mở khóa nhiều khả năng chế tạo hơn. Hãy xây một ngôi nhà cho Nữ Bard và cấp cho cô ấy quyền truy cập vào <b>giường trú ẩn gần đó nếu bạn chưa làm!</b>\n\nĐể che chở những người sống sót của bạn, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót trống gần nhất khi được đặt. Nếu bạn muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu Hồi của bạn và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho bạn khi những người sống sót của bạn không còn được che chở.",
    [3212519673] = "Tốc Độ Ban Đêm",
    [3212630052] = "Hang ổ của Scavenger đã mang lại một phát hiện quý giá – Lưỡi Kiếm Than Khóc, được đóng dấu bởi Thợ Rèn bậc thầy của <location><lorename>Pikemead</lorename>'s Reach</location>. Có lẽ ông ta sẽ biết nhiều hơn về nguồn gốc của nó.",
    [3212972185] = "Cúp Danh Năng Quái Vật Sa Ngã Bằng Sắt",
    [3213005664] = "Tấn Công Mảnh Vỡ",
    [3213203081] = "Đừng bao giờ ngừng nhảy múa.",
    [3213344846] = "Những Bức Tường Leo Núi",
    [3213371261] = "Tìm Tờ Nhạc Thứ Hai",
    [3213807655] = "Tủ Ly Gỗ Cọ Nhỏ",
    [3214462369] = "Cửa Gỗ Phương Bắc",
    [3214612876] = "Bạn đã tìm thấy một con Capybara đã chết. Cơ thể nó vẫn còn ấm và mang dấu vết của những vết cắn tàn bạo của Drak'Dal.\n\nCó vẻ như <b>Drak'Dal đã săn lùng và ăn thịt Capybara.</b> Một hành động tồi tệ như vậy không thể không bị phán xét.\n\n<b>Hãy tìm trại địch gần đó và báo thù cho cái chết của con vật!</b> Có lẽ bạn cũng có thể cứu một vài đồng loại của nó trong quá trình này.",
    [3214641649] = "Vẻ sáng bóng của vũ khí này đã bị xỉn màu bởi lớp gỉ sét, che giấu nguồn gốc từng rất cao quý của nó. Chỉ có tay cầm có đệm vẫn gợi ý về vinh quang đã mất.",
    [3214657559] = "Cảnh báo: %k",
    [3214715957] = "Ai đó đã để quên <b>vật liệu xây dựng trên một cây cầu đổ nát</b> ở Cao Nguyên Du Mục. Hãy tìm và thu thập các khối xây dựng để tìm hiểu thêm các công thức chế tạo khối!",
    [3214806641] = "Mũ Giáp Học Giả Thiên Giới",
    [3214923013] = "Hồi Sinh",
    [3215055135] = "Phép thuật vĩnh cửu này được thấm nhuần sức mạnh của ánh sáng. Khi được niệm, một luồng sáng rực rỡ lóe lên trước mặt bạn và đẩy lùi kẻ thù.\n\nNgoài ra, phép thuật này tăng <i>thanh choáng</i> của kẻ thù bị che phủ dựa trên thuộc tính trí tuệ của bạn.\n\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [3215385211] = "Nếu bạn câu cá mà không bắt được gì, bạn vẫn đã học được một bài học.",
    [3216006989] = "Tôi Chưa Từng Biết Vẻ Đẹp Như Vậy",
    [3216184777] = "Ánh Sáng Thánh Thiêng Che Phủ",
    [3216349532] = "Tăng Tốc Độ Hồi Phục SP",
    [3216647939] = "Cơ Hội Kích Hoạt Khi Đánh Trúng Kẻ Địch Bị Ướt",
    [3216922990] = "Sát thương vũ khí phép thuật tăng <b>10%</b>.",
    [3217698011] = "Tìm Tấm Nhạc Thứ Ba",
    [3217735775] = "Mỹ Phẩm",
    [3217867270] = "Súp Linh Thể",
    [3217997667] = "Tìm thấy ở Đỉnh Albaneve, vào ban đêm",
    [3218853563] = "Di chuyển lên một voxel",
    [3218868115] = "ST Tầm xa",
    [3219182173] = "Thư Giới Thiệu",
    [3219272731] = "Một khối đá được khai thác từ lòng đất. Cắt thô vừa vặn để xếp chồng lên nhau. Tuyệt vời để xây móng!",
    [3219758094] = "Tìm Ốc Đảo",
    [3220040359] = "Chết",
    [3220275927] = "<b>Ướt Sũng</b>\nGiảm SP và Tốc Độ Hồi Phục SP <b>30%</b> trong <b>30</b> giây. Đồng thời giảm <b>Kháng Băng và Sốc</b> <b>30%</b> nhưng tăng <b>Kháng Lửa</b> <b>30%</b>.\n<b>Ướt Sũng</b> có thể áp dụng lên kẻ địch.\nThời gian hiệu lực của <b>Ướt Sũng</b> không thể giảm bằng hơi ấm, và chuyển thành hiệu ứng <b>Ướt</b> khi kết thúc.",
    [3220309172] = "Biển Báo Trên Đất",
    [3220794326] = "Vận động viên",
    [3222060702] = "Đòn tấn công tiếp theo của bạn gây hiệu ứng đốt",
    [3222488367] = "Hầm Mộ Bí Mật",
    [3222598712] = "Giày Người Chữa Lành",
    [3223013414] = "Vải Màu Vàng",
    [3223529901] = "Dấu Vết Hoa Hồng Máu",
    [3223596674] = "Một cây được trang trí lộng lẫy và mang không khí lễ hội.",
    [3223754032] = "Cổng Cầu Vồng Bằng Đá Lớn",
    [3223805955] = "Một miếng băng kết hợp với thuốc sát trùng.\n\nMón đồ này giúp Chữa thương tốt hơn nếu được sử dụng lên vết thương.",
    [3224673147] = "Độc",
    [3224788282] = "Khám Phá Nghi Lễ Vukah",
    [3225079285] = "Dầu Bị Phủ Bóng",
    [3225335678] = "Thư Gửi Một Người Bạn Cũ",
    [3225417139] = "Kích thước phiên",
    [3225554412] = "Đòn Đánh Kỹ Năng",
    [3225570654] = "Một mũi tên làm từ xương khổng lồ.\n\nLực của mũi tên này cho phép nó <b>xuyên qua mục tiêu bị đánh</b> để gây sát thương lên nhiều kẻ địch.",
    [3225590682] = "Tìm Đường Vào Phòng Thí Nghiệm",
    [3226107578] = "Chùy Máu Tươi",
    [3226614827] = "Con cá đã trốn thoát.",
    [3226636094] = "Bùn Sương độc",
    [3226735138] = "Rách Rưới",
    [3227187817] = "Một mũi tên cao cấp làm từ Xương Khổng Lồ.\n\nLực của nó cho phép nó xuyên qua mục tiêu và gây sát thương lên nhiều kẻ địch.",
    [3227503644] = "Điều Tra Nơi Nomad Rơi Xuống",
    [3227738951] = "Hầm Ngầm Nắng Hè",
    [3227937960] = "Mũ Của Chúng Ta Đã Mất!",
    [3228085558] = "Hiện vật Sảnh Hollow Trung bình",
    [3228266904] = "Lối Đi Hang Vukah",
    [3228864106] = "Tôi Đã Thấy Gì?",
    [3229099151] = "Sát thương vũ khí bổ sung",
    [3229175967] = "Một bức phù điêu mô tả lịch sử của Drak.\n\nDrak được miêu tả là xây dựng đền thờ dưới ánh mặt trời rực rỡ, giống như Tiền Nhân. Họ coi Tiền Nhân như thần thánh vì sức mạnh vượt trội của họ, và mong muốn giành được sự ưu ái của họ để tự mình đạt đến thần thánh.",
    [3229360388] = "Một vật trưng bày để khoe vũ khí hoặc khiên.",
    [3230216882] = "Hành động",
    [3230454427] = "Ôi, nhìn những chú Capybara đáng yêu kìa! Tim tôi thấy ấm áp và tràn đầy! Chúng ta có nên đào một cái hố nước nhỏ cho chúng không? Tôi sẽ mang xẻng!",
    [3230524567] = "Chiếc rương đã bị đánh cắp và sau đó bị thất lạc bởi Cade Hawthorn. <b>Hãy đến trại cũ của hắn</b> và <b>khai quật chiếc rương</b> để nhận lấy vật phẩm bên trong!",
    [3230848992] = "Cóc Khách Nướng",
    [3230860878] = "Bồn Rửa Của Thủy Thủ",
    [3231352492] = "Chế tạo các khối tại <craftingstation>Bàn Chế Tạo</craftingstation>.",
    [3231608079] = "Rìu Thần Tượng Chạm Khắc",
    [3231938733] = "Bình Năng Lực Của Thợ Lặn",
    [3231946575] = "Ngọn đuốc cơ bản này cung cấp ánh sáng trong một thời gian ngắn. Hãy cẩn thận khi khám phá hang động với nó!",
    [3232130097] = "Truyện Kể <npc>Thợ Rèn</npc>",
    [3232144009] = "Xóa Thế Giới",
    [3232453276] = "Lò Sưởi Gạch",
    [3232502361] = "Túi Chướng Khí",
    [3233667640] = "Bình HP",
    [3234434945] = "Tủ Búp Phê Gỗ Phương Bắc Nhỏ",
    [3234540263] = "Cánh Cửa Bịt Kín Mọi Ánh Sáng",
    [3234819521] = "Một khối đá thường được dùng để xây tường cách âm chắc chắn.",
    [3235183782] = "Yêu cầu:",
    [3236056504] = "Không có bộ lọc nào được đặt",
    [3236422342] = "Một loại bột nhão dính dùng để liên kết các chất hóa học.",
    [3237020213] = "Màu xanh lá cây thật huyền bí, phải không? Nó mang tính lật đổ — là màu của thiên nhiên và sự tái sinh, nhưng cũng là màu của sự bất tử, đố kỵ và ghê tởm. À, tôi nhớ những nguyên liệu tôi đã dùng để làm thuốc nhuộm tóc xanh đại diện cho những khía cạnh này... Ai có thể biết nhiều hơn về sự sống và tái sinh hay sự bất tử và đố kỵ...?",
    [3237037404] = "Tìm kiếm người chơi",
    [3237060815] = "Bạn đã phát hiện một Obelisk Cổ Đại trong khu vực săn bắn. <b>Đọc nó</b> để khám phá thêm các địa điểm ẩn!",
    [3237238806] = "Đũa Phép Xương Sống Rắn",
    [3237550226] = "Nhìn sang trái",
    [3237829515] = "Cung Điện Hầu Như Không",
    [3237962149] = "Bạn thân mến, lại đây nào! Ta có một câu chuyện cho ngươi!",
    [3238184325] = "Qua màn đêm đen tối cho đến khi bình minh nhuộm bầu trời với sắc vàng rực rỡ và đỏ thẫm. Sự kết hợp màu sắc này cũng sẽ trông tuyệt đẹp trên một lá cờ!\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Bồn Tắm Nước Che Phủ.",
    [3238401664] = "Tổ Sinh Vật",
    [3238497404] = "Khoảng Cách Móc Câu",
    [3238801378] = "Chứng minh tôi sai hoặc chứng minh tôi đúng — cuối cùng thì sự tò mò cũng sẽ cám dỗ bạn.",
    [3239011020] = "Sự ồ ạt của những người lạ gần đây khiến cả tôi và những người công nhân đều bất an — và tệ hơn nữa, nó làm gián đoạn công việc kinh doanh.\n\nLiane đã viết thư cho tôi về \"sự cố\" mà cô ấy gặp phải bên bờ sông. Chắc chắn là đáng lo ngại, nhưng tôi đã cố gắng thuyết phục cô ấy tiếp tục làm việc. Nếu không ai dám <i>vào những cánh đồng lầy lội vào ban đêm</i> nữa, thì việc kinh doanh sẽ chìm sâu hơn cả một chiếc ủng bị mắc kẹt trong bùn. Tôi đoán chúng ta vẫn còn một ít <i>quả mọng u ám</i> dự trữ, nhưng đó chỉ là vấn đề thời gian cho đến khi chúng hết. Vậy chúng ta sẽ làm rượu và mứt từ gì đây?\n\nTôi ước gì Liane đã gặp người lạ kia thay thế. Người thợ cắt tóc thì kỳ lạ, đúng vậy — dành phần lớn thời gian trên đỉnh tháp, nhìn chằm chằm vào các chòm sao phía trên — nhưng ít nhất anh ta không <i>điên rồ</i>. Giá như cô ấy gặp anh ta bên bờ sông thay vào đó, thu hoạch quả mọng u ám một cách yên bình vào lúc nửa đêm, thì tôi vẫn sẽ có nhà cung cấp!",
    [3239030100] = "Một chiếc mũ bảo hiểm thời trang với một bộ kính bảo hộ. Chúng bảo vệ mắt người đội khỏi hơi độc và nước, nhưng cũng từng được sử dụng khi lướt trên các luồng gió ngày xưa.",
    [3239102304] = "Chúng ta nên ăn mừng chương mới tuyệt đẹp này. Tôi biết chính xác phải làm gì!",
    [3239817093] = "Trong Vùng",
    [3240035900] = "Khủng bố",
    [3241138990] = "Chị gái! Em gái đã nhận được thư của chị chưa? Em đã rất nhớ chị trong năm qua. Gã <b>Nhà Thầu tồi tệ đó đã cố nhốt em trong hầm ở <location>Quần đảo Jasper</location>,</b> nhưng chị đã đúng. Hắn không thể giữ em bị xiềng xích lâu! Em xin lỗi vì đã mất liên lạc, nhưng em đã cố gắng giữ kín chuyện... \n\nUmber Hollow cũng không tốt hơn hay tệ hơn <location>Surat's Rest</location>. Hai mặt của cùng một đồng xu, giống như chúng ta! <i>Có lẽ nhiều vụ ẩu đả hơn — nhưng em có thể xử lý chúng!</i>\n\nCao nguyên Nomad đang hỗn loạn. Một ngày nào đó, chúng ta phải xóa tan sự hỗn loạn này, chị gái. Chị nghĩ sao?\n\nEm gái của chị,\n<lorename>Lupa</lorename>",
    [3241205648] = "Vũ khí",
    [3241316690] = "Giữ Tất Cả",
    [3241507866] = "Hàng Rào Gỗ Thô Sơ IV",
    [3241566201] = "Nền Móng Vững Chắc",
    [3241742952] = "Tủ Gỗ Thô Sơ",
    [3242798846] = "Nghiêng sang phải",
    [3242887305] = "Triệu Hồi Người Đi Theo Mới Của Bạn",
    [3242894020] = "Mảnh giáp này chỉ cung cấp sự bảo vệ nhỏ chống lại các mũi tên bay tới, nhưng điều đó không quan trọng lắm. Biện pháp phòng ngừa tốt nhất là nhắm vào mắt.",
    [3243363908] = "Bạn cần gì?",
    [3243493963] = "Tham gia thất bại. Mật khẩu không hợp lệ.",
    [3243543095] = "Tìm thấy ở Sảnh Đường Hollow Revelwood",
    [3243824889] = "Cắt Sâu",
    [3244469379] = "Vuk'ahrrrrr",
    [3244679282] = "Thân Mình Quái Vật Một Mắt",
    [3244901071] = "Tìm thấy ở Sảnh Đường Hollow Albaneve",
    [3245146476] = "mỗi",
    [3245918717] = "Chơi lần cuối ",
    [3246866087] = "Ngọn Lửa đã nói về \"Cột Đá Cổ Đại\" tiết lộ thông tin về thế giới. Các Cột Đá cho thấy những sự thật ẩn giấu, và một số có liên quan đến <b>những gì đang mục rữa bên dưới.</b> \n\nVị trí của một Cột Đá như vậy đã được đánh dấu trên bản đồ. Hãy tìm Cột Đá và khám phá những bí mật mà nó nắm giữ. Bí mật của Cột Đá sẽ chỉ được tiết lộ cho những ai tìm kiếm chúng.",
    [3247493173] = "Một chiếc váy xanh lục cho việc nội trợ hoặc làm việc trên nông trại.",
    [3247697971] = "Bộ lông vẫn còn lấm tấm những vệt máu.\n\nThu thập nhiều Đầu Thú Săn Mồi Vukah để chế tạo Cúp.",
    [3248592517] = "Giày Giáo Sĩ Sinh Ra Từ Sóng",
    [3248735758] = "Mầm Tảo Nướng",
    [3248948135] = "Mọi người đều có thể tham gia với tư cách là một [ %k ].",
    [3249180195] = "Vào và Lục Lọi Hầm Rượu",
    [3250329880] = "Tháp Giả Kim",
    [3250350237] = "<b>Thoát nước</b>\nNguyên liệu này <b>thoát một lượng nhỏ nước</b> khi bị tràn.",
    [3250866857] = "Người Nông Dân nói rằng bà muốn nấu một số món ăn mới. Một số công thức nấu ăn sẽ giúp bạn ấm áp khi ở ngoài trời tuyết! \n\n<b>Hãy cân nhắc nấu súp bí ngô, thịt bò béo nướng, hoặc thịt bò hầm. </b>",
    [3250869586] = "Mất Tất Cả",
    [3251205052] = "Thức ăn Capybara bổ dưỡng cho động vật thuần hóa trên nông trại của bạn.\n\nNó phải được đặt vào máng ăn phù hợp.",
    [3251416281] = "Những Giấc Mơ Lạ Về Lâu Đài",
    [3252014647] = "Giày Thợ Tiều Phu",
    [3252117447] = "Gây sát thương bằng vũ khí Ma thuật có <b>15%</b> cơ hội kích hoạt một vụ nổ lửa nhỏ phục hồi <b>30</b> giây <b>Thời gian trong Sương độc</b> cho bạn và đồng minh trong phạm vi <b>20</b> mét.\n\n<b>Thời gian trong Sương độc</b>\nNếu thời gian này hết, Sương độc sẽ nuốt chửng bạn.",
    [3252252039] = "Bộ Hiệp Sĩ",
    [3252547963] = "Mở Khóa",
    [3252613128] = "Đứa Con Của Đàn Lyre",
    [3252673239] = "Rìu Sắt",
    [3253155781] = "Bình Tro Tàn",
    [3253680604] = "Thợ Khai Thác Gỗ",
    [3253724870] = "Bạn đã biết rằng một nhóm người đã chịu một cuộc phục kích của Vukah. Một trong số họ đã đánh rơi <b>một vũ khí.</b> Vukah hẳn đã mang chiến lợi phẩm đến một trại gần đó.",
    [3253826929] = "Đền Drak'Dal",
    [3253847686] = "Đàn Khúc Cầm",
    [3254052819] = "Cảm ơn bạn một lần nữa vì đã cho tôi đi qua, người bạn mới của tôi! Khi tôi nhìn thấy đội tuần tra đáng sợ của bạn, tôi gần như đã lo lắng! Nhưng hóa ra, câu lạc bộ người hâm mộ của The Honeydew có cả thành viên ở đây! Ha! Ai mà biết được?\n\nTôi hy vọng cây đàn lute cũ của tôi sẽ mang lại cho bạn nhiều niềm vui! Hãy nhớ: nếu bạn gảy nhẹ dây đàn, những người khác sẽ không nghe thấy bạn luyện tập. Tôi biết bạn phải giữ gìn hình ảnh, với tư cách là thủ lĩnh Scavenger địa phương. Tôi biết tất cả về điều đó. Tôi cũng đã phải gạt bỏ niềm đam mê thực sự của mình. Này, một khi tôi trở về từ núi non — và một khi tôi đã thiết lập sự nghiệp mới của mình với tư cách là một bậc thầy lượn — tôi sẽ quay lại dạy bạn một vài giai điệu! Tôi cũng sẽ để lại một ở đây cho bạn. Luyện tập tạo nên sự hoàn hảo!\n\nChúng ta hãy song ca sớm nhé!\nGiữ vững phong độ,\n\n— Chester Loft",
    [3254188411] = "Đền Drak'Dal",
    [3254401378] = "Chuyển Đổi Tiến Trình Cá Nhân",
    [3254557782] = "Manocanh E",
    [3254581612] = "Bài hát này sử dụng âm thanh đầy màu sắc để vẽ nên một khu chợ sôi động vào một ngày lạnh giá. Những giai điệu tươi sáng chiếu sáng cảnh vật như đèn thần tiên. Nó khiến bạn muốn làm ấm mình bằng một ly rượu mật ong!\n\n<b>Tờ Nhạc</b>: \nNhạc Tờ dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ tờ nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát.",
    [3254631104] = "Ánh Sáng Chói Lòa, Bóng Tối Bao Trùm",
    [3254989112] = "<location>Glennwood's End</location> đã rơi vào tay Scavenger. Đánh bại Mẫu hậu Scavenger để <b>thanh tẩy thị trấn và nhận tượng của bạn!</b>",
    [3255238638] = "Tất cả sát thương <b>Lửa</b> đều tăng <b>20%</b>.",
    [3255455519] = "Một phần mở rộng cho ba lô của bạn, giúp tăng dung lượng hành trang thêm một hàng.\n\n<b>Lỗi thời</b>\nMón đồ này có thiết kế cũ. Hãy ghé thăm thợ thủ công của bạn để tìm phiên bản ba lô cải tiến với một hàng bổ sung.",
    [3255511455] = "Tôi cuối cùng đã tự do, nhờ bạn, người bạn của tôi. Tất cả các tên gọi đều thoáng qua, chỉ là âm thanh và khói. Tôi có nhiều tên như đồng hồ cát có hạt cát. Đối với bạn, tôi sẽ là \"Alden\".\nTôi là ánh sáng dẫn đường xuôi dòng. Một vì sao đang lụi tàn sau những cơn gió bắc. Một người thu thập và phá vỡ xiềng xích trần thế. Tôi sẽ vén màn cho bạn khi bạn sẵn sàng. Cái giá phải trả rất nhỏ, tôi hứa với bạn, bạn của tôi.",
    [3255732979] = "Hồi Phục",
    [3255825452] = "Người <npc>Thợ Săn</npc> muốn chuẩn bị da và lông thú bằng cách phơi nắng. Bà ấy tự hỏi liệu những người thợ săn ở Cao Nguyên Du Mục có công cụ và kiến thức về việc này không, nhưng bà ấy không biết ai cả.\n\n<b>Có lẽ ai đó khác biết một <npc>Thợ Săn</npc> trong khu vực.</b>",
    [3256308052] = "Chiến Đấu",
    [3256396118] = "Bạn đã tìm thấy ghi chú của tôi! Vâng, tôi từ lâu đã coi mình là một trong những người giỏi nhất... mặc dù dì <lorename>Braelyn</lorename> của tôi sẽ không đồng ý. Tất nhiên, những nghệ sĩ vĩ đại có một <i>chữ ký</i> để đánh dấu tác phẩm của họ! Của tôi là một <b>chiếc rương</b> mà tôi đặt ở móng của Cầu <lorename>Braelyn</lorename>. Ngay bên cạnh <b>trụ giữa</b>! Bất chấp những nỗ lực tốt nhất của tôi, không một linh hồn nào nhận ra, nhưng.",
    [3256763951] = "Người Nông Dân đã làm mất một kỷ vật từ mẹ cô ấy khi cô ấy đi từ nhà thời thơ ấu đến <location>Brittlebush</location>. Hãy tìm chiếc nhẫn bị mất và trả lại cho Emily Fray!",
    [3257367541] = "Mở khóa kỹ năng đầu tiên của bạn.",
    [3257550824] = "Sử dụng",
    [3259100306] = "Bình Của Kẻ Sa Ngã",
    [3259648046] = "Rồng Sương độc Fell",
    [3259664250] = "Đồ Sưu Tầm",
    [3260434419] = "Đầu",
    [3260759250] = "Hiệu suất máy chủ kém. Người chơi trên máy chủ của bạn có thể gặp sự cố về hiệu suất.",
    [3260821791] = "TUR",
    [3261767800] = "Xoay",
    [3261844718] = "Nhanh Chóng Sẵn Sàng",
    [3261874849] = "Khăn Trùm Đầu Người Khôn Ngoan",
    [3261949316] = "Ổ trứng của Gna'Rash phát triển tốt. Nhiều Rồng con mạnh mẽ. Chỉ cần loại bỏ một vài con, nhưng da vẫn còn cứng. Khó cho Rồng con khác ăn, nhưng bổ dưỡng. Làm cho vảy cứng gấp đôi! Vinh quang Mẹ Rồng!\n\nNhưng tại sao chỉ Gna'Rash mới được ở với những cô Rồng Drak'Dal xinh đẹp? Gruul nói thủ lĩnh còn có bạn gái ở Quần đảo, bên ngoài bộ tộc. Kriss'Kah tự hỏi: Giao phối với Rồng cái Drak'Mer thì thế nào? \nTại sao Kriss'Kah không có Rồng cái xinh đẹp? Không công bằng!",
    [3261988053] = "Vị <npc>Giả Kim</npc> tin rằng <npc>Người Thu Thập</npc> đã can thiệp vào năng lượng hoặc phép thuật hắc ám.\n\nÔng ta khuyên nên cẩn thận nhưng dường như cũng tò mò.",
    [3262589793] = "Thuyết của <npc>Giả Kim</npc> II",
    [3263217910] = "Băng Gạc",
    [3263235545] = "Hiệu Ứng Thời Tiết",
    [3263869356] = "Thế giới đã mất, nhưng không cằn cỗi. <b>Những người sống sót của Sương độc</b> đang chờ được đánh thức bởi ngọn lửa bên trong bạn.\n\nTìm người sống sót đang ngủ được đánh dấu trên bản đồ của bạn. Bạn sẽ phải dấn thân qua Sương độc!",
    [3264158959] = "Đòn tấn công lén lút gây thêm %k sát thương.\n\nLén lút đến gần kẻ địch không cảnh giác và kích hoạt Đòn Tấn Công Lén Lút.",
    [3264341747] = "Khối Địa Hình Đơn 0,5m",
    [3264900164] = "Xạ Thủ",
    [3265092495] = "Chiếc đàn pan bằng vàng này đã được người Drak sử dụng. Họ có chơi nó trong các buổi lễ, hiến tế hay đấu tay đôi không? Bạn không thể nói chắc chắn, nhưng bạn biết rằng âm thanh của nó thật kỳ diệu và lôi cuốn.",
    [3265127109] = "Tin Đồn Umber Hollow",
    [3265250621] = "Thợ Lặn Bẩm Sinh",
    [3265426663] = "Cây Sồi Làng",
    [3265506130] = "Một cây Gậy phép đánh thức cơn giận đang ngủ say bên trong người sử dụng. Những gai thạch anh nhô ra giúp truyền cảm xúc về phía kẻ thù.",
    [3265780084] = "Chỉ cá chết mới bơi theo dòng nước.",
    [3265781493] = "<h2>4. Sử dụng ID của bạn</h2>\n\nKhi bạn bắt đầu trò chơi của chúng tôi, trò chơi của bạn sẽ xác thực bằng một ID được gán cho bạn bởi nền tảng tương ứng mà qua đó bạn có được trò chơi của chúng tôi. Chúng tôi chỉ sử dụng nó ở dạng ẩn danh. Cơ sở pháp lý cho việc xác thực và ẩn danh ID của bạn là việc cung cấp và lợi ích hợp pháp của chúng tôi trong việc đánh giá trò chơi của chúng tôi một cách thân thiện với quyền riêng tư, Điều 6(1)(b) và (f) GDPR.\n",
    [3266236756] = "Xin chào!",
    [3266510404] = "Vậy là nó tồn tại! Một mũi tên không bao giờ nghỉ, cũng không bao giờ gãy! Thật tuyệt vời... vẫn còn phép thuật trên thế giới!",
    [3266756074] = "Lấp đầy <i>Thanh choáng</i> của kẻ địch bằng <b>Đỡ đòn</b> được tăng thêm <b>30%</b>.\n\n<b>Đỡ đòn</b>\nKhi trang bị Khiên, một pha chặn đúng lúc sẽ <b>đỡ đòn</b> tấn công.\n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang phòng thủ hoặc đỡ đòn của chúng sẽ lấp đầy <i>Thanh choáng</i> của chúng cho đến khi chúng <b>Bị Áp Đảo</b>.\nKẻ địch <b>Bị Áp Đảo</b> có thể bị Tấn công Tàn nhẫn.",
    [3267116006] = "Tượng Đầm Lầy Đen IV",
    [3267273357] = "Drak",
    [3267394270] = "%k/%kl",
    [3267482498] = "Cung cấp sự bảo vệ và bóng râm chung, chiếc mũ của học việc giả kim thuật hoàn hảo để lang thang khắp thế giới.",
    [3267765696] = "Rơi ra từ các trùm Fell Cao nguyên Du mục",
    [3268280320] = "Quần Huyền Bí",
    [3268369535] = "Chuông trang trí đặc biệt thích hợp cho mùa đông.",
    [3268591645] = "Đã chỉnh sửa",
    [3268912737] = "Giày Thợ Săn Chim",
    [3269283576] = "Chế tạo một <craftingstation>Trạm Nấu Ăn</craftingstation>",
    [3269376709] = "Tìm kiếm Ngôi Nhà ở <location>Netherton</location>",
    [3270946088] = "Máy Pha Cà Phê",
    [3270964429] = "Khe trống khả dụng cho các loại thực phẩm chưa được tiêu hóa.",
    [3271007524] = "Uống từ",
    [3271095801] = "Tùy chỉnh",
    [3271111023] = "1H",
    [3271252869] = "Ngọc Tốc Độ",
    [3271486060] = "Tìm kiếm ở Vịnh Stillwater",
    [3271944577] = "Rễ Sương độc",
    [3272172820] = "Giáp Ngực Lính Canh Phương Bắc",
    [3272492370] = "Ghế Tựa Hầm Mộ",
    [3272556228] = "Một Khối Gỗ Tar. Giờ chỉ còn thiếu ván lợp.",
    [3272866010] = "Mạng Nhện II",
    [3273065513] = "Trò Chuyện Thoại",
    [3273370274] = "Cửa Gỗ Đánh Bóng",
    [3274371085] = "Xe Rùa",
    [3274565178] = "Hệ Sợi Nấm",
    [3274583728] = "Bộ giáp kim loại hoàn chỉnh với những đường nét uốn lượn, quấn quanh chân như những dây leo quấn chặt. Gai của chúng có thể châm chích, xé toạc và làm gãy cô ấy, nhưng <i>hươu bị thương nhảy cao nhất</i>, người ta nói vậy.",
    [3275166813] = "Thịt Sói Nướng",
    [3275792418] = "Tôi thú nhận rằng tôi đã thất bại với anh trai mình khi anh ấy cần tôi nhất.\n\nAnh ấy chưa bao giờ khỏe mạnh, nhưng <i>có điều gì đó đã khiến anh ấy tồi tệ hơn.</i> Đột nhiên, anh ấy cố gắng cào vào mắt tôi. Anh ấy từ chối ăn - nói rằng súp của mẹ lạnh như băng và làm vỡ bát. Tôi nghĩ đó là lời kêu cứu.\n\nAnh ấy biến mất trong nhiều ngày, và khi cuối cùng anh ấy xuất hiện trở lại trong phòng ngủ của chúng tôi vào giữa đêm, anh ấy đánh thức tôi bằng một lời thì thầm.\n\n<i>\"Ở nhà mới của tôi, hoặc giết hoặc bị giết. Tôi sẽ mạnh mẽ vì bạn. Một giọng nói u ám gọi tôi. Ai đó, hoặc thứ gì đó, muốn dập tắt tôi. Nuốt chửng tôi, đánh cắp khuôn mặt và tên của tôi. Nó muốn giải thoát cho tôi.\"</i>\n\nChoáng váng, tôi hỏi ý anh ấy là gì - nhưng anh ấy chỉ thì thầm \"Ngủ tiếp đi\"... và tôi đã ngủ.\n\nĐó là lần cuối cùng tôi nhìn thấy anh trai Alden của mình.",
    [3275792660] = "Khiên Lính Đánh Thuê",
    [3275826825] = "%k trở lên",
    [3277054121] = "Thế giới của chúng ta ngày càng mở rộng! Cảm ơn vì đã chinh phục Ngọn Tháp Cổ Đại đó, Hỡi Hỏa Hồn!",
    [3277179473] = "Cúp Danh Năng Đấu Sĩ Vukah Bằng Đồng",
    [3277431391] = "Ta cứ tưởng nhận vài việc ở đây sẽ dễ dàng thôi... sửa lại cái nhà kho cũ bằng bộ đồ nghề rèn của ta hẳn là đơn giản. Nhưng lão nông dân ở đây, ngài Fanning, khiến ta phát khiếp.\n\nÔng ta đề nghị, không, <i>ép</i> ta ngủ trong phòng của ông ta cho đến khi xong việc. Nếu thế còn chưa đủ tệ, thì cái nhà kho còn tồi tàn hơn nhiều so với lời hứa. Mấy vụ sửa chữa này sẽ tốn nhiều thời gian hơn ta dự kiến! Có lẽ ta nên quay lại <b>nhóm thợ săn ở Vùng Đất Nóng... </b>\nChẳng ích gì. Ta cần tiền để mua vé về nhà, và ta không thể trách ai ngoài chính mình. Lần này ta thực sự đã làm hỏng bét rồi. Liệu cha có muốn nhìn ta không, ngay cả khi ta về đến nơi? Ai mà biết được.\n\nTa đã chuyển chỗ ngủ của mình đến đây. Nếu lão già này dám làm gì - dù chỉ là nhìn ta sai một ly - ta sẽ cho cả cái nơi này nổ tung! Ta sẽ không lơ là cảnh giác!",
    [3277786645] = "Lửa Sương độc",
    [3278063838] = "Nhật ký <location>Thành Cổ Quạ</location>",
    [3278802190] = "Bếp Nướng Hải Sản",
    [3278950401] = "Nhà sưu tập, Alden Crowley, có thể tạo ra các bộ nội thất và món ăn huyền bí, đen tối, được truyền năng lượng tái tạo đặc biệt.",
    [3279488444] = "Tăng cường tên độc",
    [3279774480] = "Berhtolf và Lando Dimweald",
    [3279839239] = "Xây dựng <location>Morwenna</location>",
    [3279870378] = "Này Pablo\nTôi nghe nói cậu được giao nhiệm vụ \"diệt chuột\". Thật xui xẻo cho cậu!\n\nNếu cậu không cảm thấy sẵn sàng, sao không tham gia cùng tôi? Tôi lấy vài tấm da thú từ kho và nghĩ đến việc đi dạo đến Tượng Đài Cổ Đại đó vào ngày mai. Tôi sẽ gọi đó là nhiệm vụ trinh sát. Có lẽ cậu có thể nói chuyện với chỉ huy, và ông ấy sẽ cho cậu tham gia nữa. Chúng ta luôn có thể xử lý lũ chuột sau, phải không?",
    [3280310063] = "Đầu Quái Vật Một Mắt",
    [3280589444] = "Đừng lãng phí hơi thở của ngươi.",
    [3280605850] = "Chữa thương bất kỳ mục tiêu nào bằng phép thuật sẽ kích hoạt một vụ nổ lửa gây <b>50%</b> sát thương bằng <b>Lửa</b> bằng với lượng hồi máu lên kẻ địch <b>Fell</b> ở gần.",
    [3281037813] = "Chủ máy chủ đã cấm bạn khỏi máy chủ. Bạn không thể tham gia lại.",
    [3282717196] = "Cửa Sổ Tre Nhỏ I",
    [3282737989] = "Hình Nhân Tập Luyện II",
    [3282782890] = "Không thể khởi tạo Hệ thống Lưu Dữ Liệu. Vui lòng cài đặt lại trò chơi.",
    [3282930761] = "Sức Mạnh Câu Cá",
    [3283117339] = "Lội nước",
    [3283344649] = "Ta đã trở về từ bên kia lòng chảo với hai bàn tay trắng.\n\nTrang trại ở đó đầy rẫy nhện bò lổm ngổm! Bạn không thể bước một bước mà không dính vào mạng nhện! Ta không quan tâm đến khẩu phần ăn hay <b>chiến lợi phẩm trên gác mái</b>... Ta sẽ không bao giờ đặt chân đến gần lũ nhện đó nữa! Dù nguồn cung cấp của chúng ta có cạn kiệt đến đâu, chúng cũng không thể ép ta quay lại đó.\n\nTa không thể tham gia Đội Trinh Sát Người Khổng Lồ thay thế sao?",
    [3283848590] = "Đầu Ra Khả Dụng",
    [3284024482] = "Nhìn mấy con ếch nhỏ nhảy nhót trên cỏ kia? Tôi từng bắt chúng khi còn nhỏ và mang cho cha tôi. Hồi đó tôi không nhận ra ông ấy dùng chúng làm mồi câu để bắt cá lớn hơn - một nước đi thông minh, thực sự. Nó hiệu quả một cách kỳ diệu nếu bạn có kỹ năng. Nhưng giờ tôi già rồi, không còn bò lổm ngổm được nữa. Bạn có thể bắt vài con cho tôi không?",
    [3284214597] = "Nghi Lễ Vukah Được Khám Phá",
    [3284480824] = "Quần Người Tiên Phong",
    [3284607851] = "Vào Đền Thờ Mặt Trời",
    [3284961880] = "Gửi <lorename>Talion</lorename>,",
    [3285519558] = "Giỏ Trái Cây Lại Rỗng!!",
    [3285649911] = "Tàu lượn cần được chế tạo và trang bị trước khi sử dụng. Để sử dụng Tàu lượn đã trang bị, hãy nhảy khỏi một gờ đá và nhấn %k giữa không trung. Sử dụng Tàu lượn <b>yêu cầu SP.</b> \n\nChế tạo Tàu lượn yêu cầu Gỗ Sương độc. Chặt cây chết Fell trong Sương độc để lấy Gỗ Sương độc.",
    [3285796087] = "Kích hoạt",
    [3286232768] = "Tô màu",
    [3286713918] = "Xác định thời gian cần thiết để hồi sinh đồng minh.",
    [3286943064] = "Một khối xây dựng màu xanh lá cây phát sáng đầy điềm gở, được làm từ thạch ma. Cấu trúc gợi nhớ đến cửa sổ kính màu.",
    [3288028564] = "Hỡi những người dân, hãy nghe câu chuyện của ta! <i>Đúng vậy! Chúng đã trở lại!</i> Ta đã nhìn thấy <b>những đốm sáng</b> bằng chính mắt mình, ở bờ biển Gió Trắng, rực rỡ hơn bao giờ hết! Chúng đã trở lại để mang ánh sáng vinh quang từ vực sâu, đến từ <i>vịnh nhỏ!</i> \n\nĐừng lo lắng! Chúng là những người anh em bò sát của chúng ta! Lưng chúng lấp lánh, vảy lấp lánh nhô lên khỏi mặt nước, sẵn sàng đưa bạn đến những bờ biển an toàn hơn!\n\nMay mắn phải đến với chúng ta!! Cuộc chiến của chúng ta sẽ kết thúc, cơn sốt Thuốc Tiên sẽ lắng xuống! Nước và mưa sẽ trong, và đất sẽ ngừng chua! Điềm lành ở khắp mọi nơi!",
    [3288055770] = "Thợ Mộc",
    [3288092337] = "Vải tinh tế với các chi tiết phức tạp, luôn thay đổi theo góc của mặt trời. Được mặc bởi các Học giả đã theo đuổi kiến thức trên khắp vùng đất này.",
    [3288311019] = "Mũ Giáp Thánh Kỵ Sĩ Rực Rỡ",
    [3288351252] = "Mũi Tên Lửa",
    [3289205821] = "Nhẫn Năng Lượng Lớn",
    [3289250936] = "Bụi Hắc Diên Thạch",
    [3289657726] = "Đũa Phép",
    [3289664748] = "Ngai Vàng Gỗ Đánh Bóng",
    [3289682802] = "Nhiều con chó đã mất tích khỏi <location>Thành Cổ Quạ</location>. Tất cả dấu hiệu đều chỉ ra rằng chúng đã bị đưa đến một tháp canh gần đó. Có lẽ một vài con chó vẫn còn ở đó. Điều tra tháp canh và tìm kiếm chó ở đó!",
    [3289705610] = "Ta đã đến lâu đài, và trong khi chuẩn bị cho bài độc thoại nhỏ của mình, ta không thể không để tâm trí lang thang! \n\nLàm sao ta có thể ghi nhớ lời thoại của mình trong khi mơ mộng dưới kiến trúc lộng lẫy như vậy? Ta đã nghĩ rằng những bức tượng của Chúa chúng ta dọc lối vào thị trấn đã thỏa mãn đôi mắt đói khát của ta, nhưng có vẻ chúng chỉ là món khai vị! Công trình đá ở đây có không gian cho cảnh quan, ta nói:\n\n<i>Những cột này vươn tới mái vòm như những lời cầu nguyện trong đêm mưa, bao phủ thành trì trong một sự thanh bình đầy kinh ngạc. Hãy tưởng tượng một nhà nguyện màu xám trên đỉnh vách đá, rêu phong len lỏi qua những viên gạch hàng thế kỷ. Sấm sét ám ảnh không chỉ thánh đường, mà còn cả dòng suối đang nghẹt thở trên vách đá.\nNhững vòm đá vắt ngang, những con ếch nhảy qua dòng suối gợn sóng. Chúng trải dài quanh các trụ như bộ xương của một chiếc ô, che chở cho chúng ta, những con chiên, khỏi những cơn gió hú.\n\nTa không được quên mình! Khán giả của ta đang đến gần - ta hy vọng Chúa sẽ thưởng thức giọng hát của ta! Nếu không, ta có thể treo mình trên một trong những vòm cung đó sớm thôi... Tập trung, Chester! Những suy nghĩ tăm tối không nên có trong một cái đầu tóc vàng xinh đẹp như của cậu!\n\n- \"May mắn\" Chester Loft",
    [3290577340] = "Mái Nhà Chưa Từng Tồn Tại",
    [3290748546] = "Chúng Ta Bị Khóa Ngoài",
    [3290750108] = "Orpheus",
    [3290838742] = "Cửa Tre",
    [3291249803] = "Oxygen Cấp Tính",
    [3292251343] = "Thay Đổi Âm Lượng",
    [3292330246] = "Đài Lửa Hầm Mộ Bằng Sắt Lớn",
    [3293083344] = "Nghe này lũ lười biếng - Thủ lĩnh của chúng ta, <lorename>Sameth</lorename>, yêu cầu chúng ta đào thêm Giếng Thuốc Tiên! Điều này sẽ cho chúng ta tất cả Thuốc Tiên mà chúng ta có thể cần!!\n\nĐó sẽ là công việc nguy hiểm, nhưng chắc chắn xứng đáng với rủi ro. Đào đi, lũ ngu! Hoặc đối mặt với cơn thịnh nộ của <lorename>Sameth</lorename>!",
    [3293107171] = "Khai Thác",
    [3293585958] = "Trọng Kiếm Lưỡi Đồng Thiếc Đẹp",
    [3294515705] = "Mẫu hậu Scavenger",
    [3294964246] = "Đầm Lầy Nhựa Snapjaw",
    [3294999989] = "Trông bạn tồi tệ quá, bạn ơi. Lại đây gần hơn, để tôi nhìn bạn. Mhh... mắt đỏ ngầu, miệng khô, và hơi thở có mùi phân hủy. Bạn chắc chắn đang bị Lời nguyền Fell hành hạ. Tôi khuyên bạn nên dùng thuốc giải độc ngay lập tức! Bạn có thể chế tạo nó với các nguyên liệu phù hợp, nhưng chúng chỉ được tìm thấy trong số lũ Fell vào lúc nửa đêm, phía trên Sương độc!",
    [3295680527] = "Biểu Tượng Tường Hình Kim Cương I",
    [3295802870] = "Đó là một công thức mà ta không hoàn toàn nắm bắt được, tinh vi đến mức không thể tưởng tượng nổi. Ta không ngạc nhiên khi biết rằng <i>nguồn gốc của công thức này là từ thế giới khác.</i>\n\nĐược tạo ra từ thịt của những loại nấm nhỏ bé, mỏng manh này mọc sâu dưới lòng đất... Nó mang lại sức mạnh. Tuy nhiên, khi ta nhìn vào chiếc bình này, nỗi lo lắng tràn ngập trái tim ta. Đây sẽ không bao giờ là một phương thuốc. Đây sẽ luôn là một vũ khí. Có lẽ <i>Tổ Tiên đã muốn giấu điều này</i> vì một lý do.\n— Balthazar",
    [3295809776] = "Như vẻ ngoài đặc trưng của nó cho thấy, Thornridge là một loài cá huyền thoại mà chỉ những người câu cá rất giỏi mới có thể bắt được.\n\nLoài cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả lại xuống nước và nuôi trong ao.",
    [3296535878] = "Dưới Nhà Nguyện",
    [3296657060] = "Băng Giá",
    [3296804122] = "Thời gian trong Sương độc tăng.",
    [3297037755] = "Tiết Mục Xiếc",
    [3297242431] = "Trái",
    [3297644670] = "Đạn dược ma thuật giải phóng một làn sóng Chữa thương và nhảy sang đồng minh ở gần.\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>Gậy phép.</b>",
    [3297656884] = "Vị <npc>Nhà Giả Kim</npc> viết về việc trải qua cơn đau sau khi kích hoạt <b>nút mở cửa phòng thí nghiệm của ông ta.</b>",
    [3298081679] = "Rìu",
    [3298463086] = "Cây Nghệ Tây",
    [3299663688] = "Kênh Tia Chướng Khí",
    [3299674863] = "Tượng Đồng Lớn \"Rắn\"",
    [3299976701] = "Ngươi là ngọn nến trước gió, người bạn mới của ta. Đến đây - để ta cho ngươi thấy bóng tối mà ngươi không thể thoát khỏi.",
    [3300423216] = "Nhưng từ vực sâu của Giếng, một lời nguyền không lường trước đã bò vào Embervale.",
    [3300502862] = "Bạn không có quyền sử dụng vật phẩm này",
    [3300580697] = "Cây Long Đởm",
    [3300966558] = "Một mảnh vỡ của bức tượng Nữ Hoàng <lorename>Pikemead</lorename>.\nTìm tất cả các mảnh để lắp ráp lại bức tượng.",
    [3300978181] = "Một viên ngọc trai tuyệt đẹp. Sức hút từ ánh sáng lấp lánh của nó chỉ được tăng cường bởi sự hiếm có của nó.",
    [3300984986] = "Những người sống sót cần được đặt trước khi chỉ định giường",
    [3301288091] = "Kính gửi ngài,\n\nCho phép tôi giới thiệu bản thân. Tôi là Costner Meyers, và có lẽ ngài đã từng nghe nói về tôi. Tôi có lý do để tin rằng một nguồn tài nguyên quý giá nằm dưới lòng đất mà ngài sở hữu, và tôi rất sẵn lòng đàm phán một thỏa thuận với ngài. Bởi vì, ngài thấy đấy, điều đó đã được định sẵn.\n\nGần đây, tôi đã bị một thị kiến tấn công khi đang tìm nước. Tôi bị mất phương hướng trong hoang dã, miệng khô như cát - nhưng cuối cùng, tôi đã được ban phước bởi một chuyến viếng thăm từ <i>một loại bóng ma lơ lửng nào đó</i>. Ngài có thể nghĩ đây là ảo giác, nhưng nó đã cho tôi nước và ban cho tôi cái nhìn sâu sắc bất ngờ. Vùng Đất Nóng rất nguy hiểm, nhưng <i><lorename>Kẻ Lữ Hành Bí Ẩn</lorename></i> nói rằng có hy vọng. Vùng đất này ẩn chứa vàng lỏng bên trong!\n\nNgài phải tin tôi. Đừng thử thách đức tin của tôi.\n\nKý tên,\nCostner Meyers",
    [3302005992] = "Liệu có thật là cô ấy không? Mắt ta có lừa dối ta không? Nhân danh lửa, cô ấy thật cao lớn! Ta vẫn coi cô ấy là cô con gái bé bỏng của mình... Không, ta không khóc. Chắc ta bị bồ hóng bay vào mắt. Nhìn đi chỗ khác! Ta cần một chút thời gian!",
    [3302395050] = "Bình Đền Drak III",
    [3302416465] = "Cân bằng MP tối đa của người chơi.",
    [3302889391] = "Những Gì Thế Giới Giữ Kín",
    [3303009258] = "<warning> Các vật phẩm từ ba lô sẽ bị rơi ra</warning> khi bạn chết.\nQuay lại đây để lấy chúng.",
    [3303059610] = "Mỏ Đá Nhỏ",
    [3303076299] = "Ngủ",
    [3304163347] = "Bảo vệ khỏi độc tố",
    [3304242520] = "Chó Ướt",
    [3304752145] = "Tài nguyên",
    [3304753612] = "Tôi lại thấy nó, ở bên ngoài. Nhanh và im lặng, giữa những cái cây.\n\nTôi nghĩ đó là một loại quái vật. Nó đi đi lại lại, rình rập ở ngoại ô thị trấn vào ban đêm. Có lẽ Galvan hoặc Augustus nên dẫn một vài người đàn ông đến <b>hang động đó</b> gần đây. Tôi gần như không ngủ được nữa... đầu tiên là hạn hán, rồi đến bọn cướp, và bây giờ là cái này?\nLạy Chúa, thị trấn này chưa đủ đau khổ sao?",
    [3304896298] = "Đêm Hollow",
    [3304912085] = "Thứ cấp",
    [3304948114] = "Bạn có hai thanh hành động mà bạn có thể chuyển đổi trong trò chơi bằng cách sử dụng %k.",
    [3305090717] = "Bàn Góc Mộc Mạc",
    [3305240923] = "Bạn đã tìm thấy một bảng màu Vùng Đất Nóng! Ôi, thật là rực rỡ!",
    [3305336167] = "Sa Mạc Này Chứa Đựng Kinh Hoàng",
    [3305369491] = "Những Cơn Gió Lạnh Giá Che Giấu Kền Kền Lông Trắng",
    [3306261833] = "Cửa Sắt",
    [3306856074] = "Đèn Sàn Tím I",
    [3308542985] = "Thân yêu! Nhà giả kim đã giao cho ngươi nhiệm vụ tiến vào Sảnh Hollow? Hãy coi chừng những Kẻ Hollow bên trong! Những <b>kẻ trộm</b> này đã âm mưu chiếm lấy một phần của Ngọn Lửa, và bị Cổ Nhân nguyền rủa làm hình phạt! Không bao giờ cảm nhận được hơi ấm của người khác... Ta gần như thương hại chúng.",
    [3308754614] = "Sát Thương Vũ Khí",
    [3308946483] = "Bạn của ta, trông ngươi có vẻ không khỏe. Có lẽ ngươi đã mắc bệnh nhiễm trùng huyết? Ngươi nên cân nhắc chế tạo thuốc giải độc độc tố máu để loại bỏ căn bệnh này. Để ta suy nghĩ... Ta tin rằng ngươi sẽ cần cánh của một con bướm đêm. Chúng khá phổ biến vào ban đêm. Có lẽ ngươi nên đi săn một vài con!",
    [3308984606] = "Tâm trí vặn vẹo của hắn ẩn giấu một bí mật. Ta ngửi thấy mùi thối rữa bên trong dinh thự. Những bức tường. Thi thể. <i>Thối rữa và đổ nát, một vòng tròn đang hoại tử —</i> đâu đó. Ta cảm nhận được nó. Xương cốt của hắn. <i>Nó nằm trong xương cốt của hắn.</i> Bên trong những bức tường — một câu đố, một mê cung — bị khóa sau đôi mắt mệt mỏi của hắn.\n\nTa sẽ đào bới không ngừng nghỉ. Ta biết nó ở đâu đó trong đó...",
    [3309057255] = "Ám khí",
    [3309204860] = "Giờ thì đi khoe mẽ đi!",
    [3310109780] = "Này, ngươi làm ta nhớ đến một bài hát.",
    [3310469783] = "Mhh... Không, không, không phải cái này. Nó gần đúng, nhưng không phải! Nghĩ đi, Elio. Nghĩ, nghĩ, nghĩ... Ta mơ hồ nhớ ra nơi ta từng đến khi mua thuốc nhuộm tóc màu xanh. Có lẽ nguyên liệu ta cần bây giờ được tìm thấy ở gần đó? Tên nó là gì nhỉ...? \"Lâu đài U ám\"? \"Lâu đài Buồn bã\"? Để ta chỉ cho ngươi nơi đó!",
    [3310479678] = "GER",
    [3310781743] = "Linh hồn rực lửa của ngươi cháy sáng hơn cả mặt trời.",
    [3311032326] = "Lò sưởi",
    [3311223183] = "Bạn đã đặt chân thành công đến một khu vực mới — Bồn Địa Sương Khói.\n\nNgọn Lửa đã phán rằng để vượt qua những vùng đất này và chiến đấu với mối đe dọa đang âm ỉ bên trong sẽ cần đến sự trợ giúp. Bạn cảm thấy được kêu gọi để điều tra một khu định cư gần đó tìm kiếm manh mối về một linh hồn thuần khiết có thể dẫn dắt bạn đi đúng đường.",
    [3311261506] = "Hàng Rào Nhà Tù",
    [3312213505] = "Con đường đến Ark Morgo",
    [3312346400] = "Chiếc quần độn này đã được khâu vá vội vàng ở các đường nối. Mặc dù vậy, chúng vẫn giữ được độ bền.",
    [3312680405] = "Chuyến thám hiểm của Darya đến Thánh địa Đêm",
    [3312865864] = "Với khối vật liệu mái nhà lâu đài màu xanh lục này, không gì có thể cản bước những kiệt tác kiến trúc của bạn.",
    [3314177815] = "Trượng Cây Bụi",
    [3314604651] = "\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm phép với một <b>cây Gậy phép.</b>",
    [3314844698] = "Mở rộng ngôi nhà của bạn",
    [3315008683] = "Phù thủy quả thực đã thử nghiệm trong ngôi mộ này, và bạn cũng đã khám phá ra một trong những kết quả của hắn: một quả cầu lửa vĩnh cửu. Tuy nhiên, hắn không hài lòng với sáng tạo của mình và tuyên bố sẽ tiếp tục hành trình đến một ngôi mộ ẩn giấu phía sau tòa tháp lớn trong hồ, gần Yên Ngựa Vàng.\n\nHãy tìm ngôi mộ này và tiếp tục tìm kiếm các thí nghiệm phép thuật của phù thủy.",
    [3315254631] = "Giờ thì ngươi đã sẵn sàng để câu con cá đầu tiên rồi! Hãy tìm một vùng nước và thả câu. Đừng quên mồi câu. Quay lại và cho ta xem ngươi đã câu được gì nhé!",
    [3316314531] = "Găng Tay Thành Lũy Hoàng Kim",
    [3316897216] = "Ngươi đã gục ngã...",
    [3317164329] = "<location>Lapis phía Đông</location> đang nhanh chóng trở thành một thành phố hoang tàn... Nạn đói và hạn hán hoành hành chúng ta. May mắn thay, <b>Bác Dreadbane</b>, như Sadie gọi ông ấy, đã cưu mang chúng ta trong thời gian này... mặc dù ân huệ này có thể là một lời nguyền trá hình.\n\nÔng ấy mang theo <b>chiếc búa</b> đó đi khắp mọi nơi, khom lưng vì sức nặng. Ta luôn nghe thấy ông ấy đi lại trong hành lang, kéo lê nó, thở hổn hển. \"Đó là để bảo vệ,\" ông ấy nói. \"Chúng bò bên dưới. Ta nghe thấy chúng. Từ lõi Hollow...\" Thật là rợn người. Chúng ta cần hy vọng, không phải những câu chuyện kinh dị!\n\nÔng ấy đi lấy nước từ giếng gần đó, nhưng đã nhiều giờ trôi qua, và ta lo lắng. Ta muốn đi kiểm tra, nhưng ta nghĩ... Ta ghét phải thừa nhận, nhưng ta nghĩ ta cũng nghe thấy nó. Tiếng bò bên dưới...",
    [3317729683] = "Xuyên thủng",
    [3317998334] = "Chuyến thăm của ta đến <location>Brittlebush</location>",
    [3318452043] = "Bị ảnh hưởng bởi Độc tố máu",
    [3319408725] = "Đỡ",
    [3319693121] = "Tức thời hồi phục lượng lớn HP, và liên tục hồi HP trong 10 giây.",
    [3320428464] = "Một chất lỏng trong suốt, sền sệt. Nó lấp lánh với ánh sáng kỳ lạ và có đặc tính phục hồi và bảo vệ.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Kẻ Sống Sâu Sương độc, ban đầu tìm thấy ở Cao nguyên Du mục.",
    [3320501080] = "Chuỗi đòn đánh",
    [3320990356] = "Quần Đại Pháp Sư",
    [3321348131] = "Cái hàm của nó đang ôm lấy một viên ngọc phát sáng khi lời nguyền được nói ra, khiến kẻ địch yếu đi khi nó tự nuôi dưỡng bản thân.",
    [3321905019] = "Xây dựng một chiếc giường có mái che cho Elio",
    [3322122511] = "Trại Vukah",
    [3322382461] = "Miếng bảo vệ cánh tay bằng da tối màu được quấn bằng dây màu xám tro. Lớp đệm len lộ ra bên dưới khi bạn vung vũ khí một cách mạnh mẽ.",
    [3322574306] = "Một chiếc mũ giáp xích, được đội vương miện bằng vòng hoa hồng và gai. Vẻ đẹp và nỗi đau, khoái lạc và tuyệt vọng — tất cả đều hòa quyện trong vầng hào quang của nàng.",
    [3322940073] = "Những người sống sót được giải cứu",
    [3323616756] = "Giày da che chân",
    [3323713888] = "Con trai ta — hãy để ta kể cho con nghe một câu chuyện về sự sáng tạo. Câu chuyện này đã được truyền lại qua nhiều thế hệ của dân tộc ta, vì vậy hãy lắng nghe cẩn thận. Khi ta kể xong, câu chuyện sẽ thuộc về con để truyền lại cho con cháu.\n\n<i>Hồ của chúng ta đã Fell từ các vì sao.</i> Dân tộc các con vốn là những kẻ du mục và khi chúng ta đến những vùng đất này, chúng khô cằn và hoang vu. Chúng ta không thể tìm thấy đường đến nguồn nước, vì vậy chúng ta đã hướng giọng nói của mình lên trời — hướng về những người Cổ đại. Và họ đã trả lời! Bầu trời nứt ra, gửi một ánh sáng rực rỡ đến đúng nơi này. Ánh sáng gặp vùng đất khô cằn và tạo ra hồ nước này, nhanh chóng đầy nước để nuôi sống dân tộc chúng ta.\n\nVà bây giờ, con hỏi, tại sao những người Cổ đại không còn ở đây để gột rửa Sương độc khỏi những vùng đất này? Nước, huyết mạch của dân tộc chúng ta, đã đi đâu?\n\nCon trai ta — tất cả chúng ta đều đang hỏi những câu hỏi giống nhau.",
    [3323983603] = "Đại Chùy",
    [3324893101] = "Tăng tốc độ bơi khi cạn kiệt SP",
    [3325291824] = "Giá Treo Gắn Tường Trượng",
    [3325822549] = "Một chiếc quần da nâu đơn giản, kết hợp tốt với quần áo lót tương ứng cho phần thân.",
    [3326060782] = "Linh hồn lạc lối — Trợ lý Giả kim",
    [3326329242] = "Tượng đài",
    [3326982645] = "Một vực thẳm nguy hiểm. Bạn sẽ cần một Móc leo để vượt qua.",
    [3327552842] = "Các công thức chế tạo đã khám phá được lưu ở đây.",
    [3328022130] = "Tất cả vũ khí của ta — cây Gậy phép, thanh kiếm, cây cung. Cùng nhau, chúng tạo thành một bộ ba đáng sợ, giống như gió, nước và tia lửa tạo nên một cơn bão. Cảm ơn ngươi đã trả chúng về cho sự chăm sóc của chúng ta. Sức mạnh của chúng là của ngươi để sử dụng.",
    [3328345577] = "Chiếc khiên cơ bản này cho phép bạn <b>Đỡ</b> các đòn tấn công vật lý. Đỡ sẽ tiêu hao SP.",
    [3329373792] = "Công cụ này chỉ có thể được sử dụng bên trong khu vực xây dựng xung quanh Bàn thờ Ngọn lửa. Nó có thể giúp bạn nhanh chóng xây dựng căn cứ mong muốn với các cấu trúc được xác định trước.",
    [3329626739] = "Nhẫn Năng Lượng",
    [3329741897] = "Manocanh",
    [3330346223] = "Kháng Sốc",
    [3330364856] = "Áo Giáp Bóng Của Núi",
    [3330641592] = "Một ngày đẹp trời để câu cá, phải không?",
    [3330748362] = "Mang hoa chuông của người làm vườn đến",
    [3330783219] = "Những chiếc găng tay huyền bí được trang trí bằng những viên đá aquamarine lấp lánh.",
    [3330831367] = "Giáp Ngực Thánh Kỵ Sĩ Rực Rỡ",
    [3331223456] = "<keyitem>Dụng cụ Khoa học</keyitem>",
    [3331309854] = "Mũ Giáp Binh Lính",
    [3331406402] = "Trang Phục Nông Dân",
    [3333238063] = "Tôi không thể tin vào mắt mình",
    [3333385918] = "Kẻ Đập Nát Băng Giá",
    [3333503475] = "Được lấp đầy bởi sức mạnh của sự sống, miếng băng này sẽ tăng cường HP cho người sử dụng.",
    [3333925958] = "<npc>Nhà giả kim</npc>",
    [3333943387] = "Hồi phục SP",
    [3334054101] = "Tìm hóa thạch",
    [3334140691] = "Tàn tích Drak'Dal",
    [3334289347] = "Không có liên kết đạn dược",
    [3334789871] = "Chà... ngươi làm việc này tốt hơn ta nghĩ.",
    [3335388536] = "Chiếm một vị trí cho căn cứ của bạn",
    [3335596683] = "Một ngọn nến trong gió",
    [3336191979] = "Tinh chế len để có trang bị tốt hơn",
    [3336546079] = "Chuối và mật ong kết hợp với nhau tạo ra vị ngọt mịn và kem. Một món ngon cho bất kỳ Flameborn nào hảo ngọt!",
    [3336650821] = "Cuồng Nộ Máu",
    [3336966912] = "Điều chỉnh độ phân giải hiển thị nội bộ và các tính năng hình ảnh của nước trong trò chơi. Tăng chất lượng ảnh hưởng đến hiệu suất.",
    [3338048888] = "Đạn dược tiếp theo",
    [3338317838] = "Khi được bao bọc trong đồng nguyên khối, đầu của nó trông còn đáng sợ hơn trước.\n\nThu thập nhiều Đầu Cyclops Hollow để chế tạo Cúp Đồng.",
    [3338660514] = "Ta sẽ giữ ngươi trong suy nghĩ của mình.",
    [3339626576] = "<location>Đấu trường Vukah</location>",
    [3341044128] = "Vũ khí 2H",
    [3341707607] = "Gieo nhân nào gặt quả ấy",
    [3342118258] = "Vải Màu Tím",
    [3342269239] = "Hôm nay chúng ta đã an táng thêm một người nữa. Tội nghiệp. Họ đã đi một quãng đường dài tìm kiếm sự nghỉ ngơi, chỉ để tìm thấy tàn tích và những mảnh vụn. Nhà thờ này sẽ không trụ vững, Helên đã nói vậy. Gió rít lên và tạo ra những con đường mới vào sảnh của chúng ta mỗi đêm. Mái nhà của chúng ta đã bị bão xé toạc, và chúng ta quá bận rộn chăm sóc người của đoàn lữ hành để sửa chữa nó. Tuy nhiên, chúng ta phải ở lại. Chúng ta cần thiết ở đây, và khó có thể tìm được nơi trú ẩn nào khác.\n\nChôn cất những kẻ lang thang này <i>cạnh các di tích và cổ vật</i> có vẻ sai trái với ta, nhưng có lẽ Helên đã đúng. Có lẽ những điều cũ kỹ phải nhường chỗ cho phong tục và nghi lễ mới.",
    [3342419888] = "Ô hành động 4",
    [3342543327] = "Thức ăn dê bổ dưỡng cho động vật được thuần hóa trong trang trại của bạn. Nó có thể được cho cả Dê Thông thường và Dê Xù ăn.\n\nNó phải được đặt vào máng ăn phù hợp.",
    [3342757039] = "Bạn đã có đủ tố chất, Hỡi Hồn Lửa. Tôi sẽ cho bạn biết một điều: <b>quặng sắt</b> tốt nhất có thể thu thập tại Mỏ Ridgeback, sâu bên dưới Sương độc. Đừng lo lắng! Với <b>Cấp độ Vượt Sương độc</b> đủ cao, nó sẽ không cản được bạn!",
    [3343482343] = "Ta cần một ít <keyitem>Dụng cụ Khoa học</keyitem>, bạn ơi! Để làm khoa học gì, bạn hỏi ư...? Ta e là ta không thể cho ngươi biết.",
    [3343546966] = "Đèn Treo Tím I",
    [3343623386] = "Một chiếc cuốc bằng sắt hiệu suất cao, hữu ích trong mọi môi trường. Một công cụ thực sự tiện dụng để có.",
    [3343825075] = "Tia sét nhảy sang kẻ địch vừa bị đánh trúng",
    [3343956129] = "Dụng cụ leo núi",
    [3344768617] = "Người <npc>Nông dân</npc> cần <b>nơi trú ẩn</b> để làm đồ thủ công. Hãy xây một ngôi nhà cho Nông dân và cho cô ấy tiếp cận <b>một chiếc giường có mái che gần đó nếu bạn chưa làm!</b>\n\nĐể che chở cho những người sống sót của bạn, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót miễn phí gần nhất khi được đặt. Nếu bạn muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu hồi của bạn và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho bạn khi những người sống sót của bạn không còn được che chở nữa.",
    [3344945939] = "Ràng buộc này chồng lên một hoặc nhiều ràng buộc khác.",
    [3344950270] = "Cốc Gỗ",
    [3345034823] = "Trang trại Vinebrook",
    [3345132390] = "Người chơi %k đã rời đi.",
    [3345329518] = "Scavenger",
    [3345402720] = "Vũ Khí Đã Chọn",
    [3345569302] = "Chào người lạ.",
    [3345612842] = "Ngày Đẹp Để Câu Cá",
    [3345992221] = "CHÚNG TA CÓ GÌ",
    [3346700947] = "Bình Năng Lượng Lớn",
    [3347102747] = "Ngọn Lửa đã chỉ dẫn ngươi chuẩn bị một lễ kỷ niệm để vinh danh sự thức tỉnh đầu tiên của Hỏa Thần.\n\nĐể làm được điều đó, ngươi nên có một bộ trang phục ăn mừng! Hãy đến địa điểm được đánh dấu trên bản đồ để tiếp cận một bộ trang phục mới!",
    [3348702979] = "Thư Từ <lorename>Rochelle Anders</lorename>",
    [3348725023] = "Ta ngạc nhiên khi thấy Willie lại \"bảo vệ\" mấy cái <b>hũ màu mà ta lấy từ Nomad's Drop.</b> Ta chưa bao giờ biết nó là một nghệ sĩ - trừ khi ngươi muốn gọi tất cả những bức vẽ bằng ngón tay của nó là \"nghệ thuật\"...\n\nChà, chúng cũng không đáng bao nhiêu, nên chẳng có lý do gì để giữ lại cả. Chúng ta có thể chơi khăm Willie một chút!\n\nTa đã lấy một vài bưu kiện quý giá từ chuyến hàng cuối cùng và <b>đặt chúng lên trên.</b>\nCó lẽ điều đó sẽ khiến Willie ngừng vẽ bằng ngón tay và tập trung lại vào việc trở thành một tên cướp máu lạnh không sợ đâm, trộm cắp và buôn lậu.",
    [3348991685] = "Tiến Lên",
    [3349863862] = "Loại",
    [3350109094] = "Sẵn Sàng Thu Hoạch",
    [3350648093] = "Một chiếc cuốc làm bằng đồng. Chỉ gặp khó khăn với những tảng đá cứng nhất, nó có thể được coi là rất hiệu quả.",
    [3351043803] = "Bình Gốm",
    [3351480650] = "Chi phí thay đổi ngoại hình:",
    [3351560612] = "Một biển báo có thể dùng để gắn các biển chỉ hướng.",
    [3351581974] = "Như Vesztah Đã Nói:",
    [3351615844] = "Ướt",
    [3351715748] = "Giáp Ngực Hiệp Sĩ",
    [3351818573] = "Một mảnh giáp cực kỳ chắc chắn, thường được các tướng lĩnh hoặc các thành viên ưu tú của cận vệ hoàng gia mặc. Nó mang lại nỗi sợ hãi cũng như sự kính trọng.",
    [3351834741] = "Giới Quý Tộc và Lịch Sử",
    [3352137116] = "Phòng Thủ Ma Thuật",
    [3352424417] = "Tham Vọng Của Balthazar",
    [3353669730] = "Bộ Bài Tarot Chính",
    [3353979182] = "Deep Learning Super Sampling (DLSS) là một công nghệ NVIDIA RTX sử dụng mạng nơ-ron học sâu và Tensor Cores trên GPU RTX để mang lại tốc độ khung hình nhanh hơn, chất lượng hình ảnh tốt hơn và khả năng phản hồi tuyệt vời.",
    [3354350349] = "Khối Đá Vôi Vỏ Sò Nửa Gỗ",
    [3354687729] = "Trại Du Mục",
    [3354861288] = "Nhận Lợi Ích Toàn Cầu",
    [3355233235] = "Bí Ngô Đêm Khô Cốt Nhỏ II",
    [3355563565] = "Hôm nay không gặp được ngươi\nPhòng cảng đã đăng thông báo về chúng ta. Ngươi đã thấy chưa?\n\nĐừng lo\nTa sẽ hoạt động ở bến cảng, ồn ào và đổ mồ hôi - trông có vẻ vất vả và làm việc chăm chỉ - sẽ che đậy cho chúng ta khoảng một tuần.\n\nTrong lúc đó, hãy lấy cà phê từ lô hàng Seascaper trước khi chúng ta chất hàng lên! Ta có máy xay cà phê ở nhà đâu đó. Một ít cà phê chắc chắn sẽ làm cho những giờ nghỉ ngơi của chúng ta ngọt ngào hơn nhiều!\n\nDAVE",
    [3355571851] = "Một vật phẩm được <npc>Thợ Săn</npc> sử dụng để tạo ra dây cung tốt hơn.",
    [3356551271] = "Một bình sữa dê sủi bọt thơm ngon. Uống nó sẽ mang lại cho bạn SP và khả năng hồi phục SP.",
    [3356572679] = "Âm Thanh",
    [3356678944] = "Một bức phù điêu mô tả lịch sử của Drak.\n\nBức phù điêu này khắc họa hai hình ảnh. Hình trên cho thấy một Thánh Địa Đêm do con người tạo ra, và mọi người mang sách và cuộn giấy làm cống vật cho các Cổ Thần.\n\nHình dưới cho thấy Drak nổi giận. Chúng không cho phép nhân loại giành được sự ưu ái của các Cổ Thần, và tấn công.",
    [3357160330] = "Ngư Dân đã cung cấp cho ngươi tất cả những thứ cần thiết để bắt được con cá sử thi đầu tiên của mình. Một địa điểm thích hợp với khả năng bắt được cá sử thi cao đã được đánh dấu, nhưng chúng có thể được tìm thấy ở bất cứ đâu trong Lưu Vực Nước Lặng.\n\n<b>Hãy thử vận may với Cần Câu Tuyệt Hảo mới có được và mồi Ếch, sau đó mang chiến lợi phẩm của ngươi đến cho Ngư Dân.</b>\n",
    [3357607369] = "Một bông hoa ăn được dùng để tăng cường hiệu quả của một số món ăn nhất định. Nó chỉ nở vào ban đêm ở Vùng Đất Mùa Xuân.",
    [3357628507] = "<npc>Thợ Rèn</npc>",
    [3357918721] = "Trang trí Lễ hội Hollow",
    [3358120088] = "Lưỡi Dao Độc Dược",
    [3358863956] = "Cổng Lưới Gỗ I",
    [3359119311] = "Đến Đồng Bằng",
    [3359649565] = "Tháp Hỗ Trợ",
    [3360280465] = "Bộ Lông Mượt",
    [3360738697] = "Cade Hawthorn đã chia sẻ một số hiểu biết về việc xây dựng <location>Morwenna</location>. Nó đã bị phá hủy bởi wildlife và sâu bệnh, vì vậy anh ấy quyết định tiếp tục và tập trung nhiều hơn vào việc xây dựng tương lai thay vì sửa chữa hiện tại.",
    [3361257051] = "Làm Tốt Lắm!",
    [3362337756] = "Những viên đá lửa hình chữ nhật vươn ra từ lõi lưỡi kiếm, một số lớn bằng nắm tay của ngươi. Các đỉnh và thung lũng của chúng tạo nên hình ảnh một chiếc xương sống khổng lồ xứng đáng với một kẻ săn mồi đỉnh cao - do đó có tên gọi liên quan đến vị thần drakian đã phấn đấu thống trị lục địa.",
    [3362357734] = "Anh trai tôi luôn là người xấc xược. <i>Quyền của con trưởng nam</i>, anh ta sẽ tuyên bố khi lao thẳng vào trận chiến. Sảnh Hollow này chế giễu anh ta, và được sự khuyến khích của đoàn tùy tùng, tôi sợ anh ta sẽ bác bỏ sự chế nhạo của nó.\n\nThan ôi, anh ta đã chọn kéo mình và quân đội của mình vào những hang động tối tăm... trong khi tôi ở lại chờ đợi sự trở về của anh ta trong hơi thở gấp gáp.\nTôi đã tập hợp những người đàn ông của mình; những kẻ ồn ào với nhu cầu cấp thiết về tiền bạc trong túi. Lòng trung thành của họ đã được trả giá, nhưng không thể biết được các ngục tối có thể thử thách mối liên kết này như thế nào.\n\nKhông còn thời gian để lãng phí. Berhtolf có thể đã bị nắm giữ ở lưỡi kiếm, hoặc bị chôn vùi dưới băng và đá vụn.\n\nMỗi phút đều có giá trị.\nLando Dimweald",
    [3362806272] = "Rìu Của Đao Phủ",
    [3363784797] = "Giường Không Thể Tiếp Cận",
    [3364093667] = "Một chiếc mũ trông như thể nó bảo vệ đôi tai quý giá của ngươi khỏi cái lạnh. Tuy nhiên, nó chỉ mang tính thẩm mỹ.",
    [3364147165] = "Đèn Lồng Thất Lạc",
    [3364185860] = "Bị cấm trong hầu hết các vòng tròn huyền bí, phép thuật này phục vụ như một nguồn axit vô tận để đầu độc kẻ thù. Vết cắn của nó là chết người nhất, vì vậy hãy sử dụng nó một cách cẩn thận.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [3364310478] = "Kỹ năng Cứu Rỗi có thể được sử dụng để hồi sinh những người chơi đã gục ngã trong Sương độc xung quanh bạn. Cả hai người chơi sẽ chia sẻ thời gian còn lại của họ trong Sương độc cho nhau.\nPhạm vi: 5 mét quanh người thi triển",
    [3364432679] = "MP Người Chơi",
    [3364588103] = "Một Màn Sương Nuốt Chửng Tất Cả",
    [3364652850] = "Cầu Lửa Vĩnh Cửu II",
    [3365351343] = "Bình Phế Liệu",
    [3365536695] = "Người Ngắm Sao Vùng Đất Mùa Xuân",
    [3366334940] = "Dao găm được tắm trong ánh nắng mặt trời trong quá trình rèn. Cạnh sắc nhọn của chúng có thể gây ra nhiều sát thương!\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3366749308] = "Dịch Nhầy Dễ Cháy",
    [3366831214] = "Một Khối Đá Thô được chế tạo theo cách cơ bản nhất.",
    [3366877851] = "Vô Hiệu Hóa",
    [3367158684] = "Chọn Bản Thiết Kế",
    [3367707097] = "Hai dòng máu đã bao vây vùng đất này.\n\nMột dòng lạnh lẽo và tím như mận mùa đông, bao bọc trong những chiếc lá xanh như vảy. Dòng còn lại đỏ và ấm áp như một bài hát được chia sẻ bên lò sưởi.\n\nMột cuộc đụng độ bị bỏ rơi, do sự ưu ái của chúng ta dành cho lửa. Khi chúng ta nâng đỡ nhân loại, chúng ta đã hạ thấp mọi thứ khác... giẫm đạp lên một hạt giống nghĩ rằng chúng ta là mặt trời, là thần của nó. Nhưng hạt giống đã lớn lên trong im lặng và căm ghét, và nơi một cánh hoa tím Fell, rễ của nó đã bám sâu.",
    [3368701221] = "Cung Quét Hắc Ín",
    [3370155513] = "Tất cả sát thương <b>Xuyên Thấu</b> cận chiến được tăng thêm <b>10%</b>.",
    [3370550468] = "Từ Myrtle",
    [3370807784] = "Vườn Hoàng Gia",
    [3371291858] = "Số lượng của chúng ta tăng lên mỗi ngày! Nơi nào than hồng còn cháy, lửa có thể bùng cháy!",
    [3371906869] = "Lưỡi Kiếm Hỏa Thiêu",
    [3371949858] = "Đôi khi, các cơ xung quanh mắt vẫn giật. Điều đó là tự nhiên và không đáng lo ngại. Hầu hết là vậy.\n\nThu thập nhiều Đầu Fell Sicklescythe để chế tạo Tượng.",
    [3372087001] = "Cánh Tay Trái Của Quái Vật Mắt Một",
    [3372216528] = "Thu thập 5 Thịt Cua",
    [3372256680] = "Giày Pháp Sư",
    [3372662217] = "Tìm Kiếm Manh Mối Ở Riverreach",
    [3372975762] = "Xô Sắt",
    [3373290610] = "Thông Tin Vật Phẩm",
    [3373331778] = "Mở Rộng Ba Lô",
    [3373865171] = "Những bức tường cũ không thể xuyên thủng vào thời <lorename>Pikemead</lorename>... giờ đây, chúng đang sụp đổ.\n\nMỗi ca gác, ta lại thấy khói bay đến gần hơn... gió bấc mang theo một mùi hương ngọt ngào nồng nặc. Sự mục rữa và Thối Rữa... chúng sẽ sớm phá tan bức tường ngoài.\n<b>Ngay cả Khe Nứt Khai Thác ở phía đông bắc</b> cũng không thể mang lại đủ đá để khôi phục lại lá chắn hoàng gia trước cuộc bao vây đang đến.",
    [3373885597] = "Một <npc>Nhà Giả Kim</npc> sẽ không là gì nếu không có <b>vạc của ông ta!</b> Của ta đã bốc cháy từ lâu... nhưng Emily Fray thân mến của chúng ta đã lấp đầy ta bằng hy vọng. Cô ấy kể những câu chuyện về <b><lorename>Ikora</lorename>,</b> một pháp sư đáng chú ý từ Cao Nguyên Du Mục... cô ấy hẳn đã bị thời gian lãng quên, nhưng chúng ta có thể sử dụng <craftingstation>Vạc Đen</craftingstation> của cô ấy để tạo ra một <craftingstation>Trạm Giả Kim</craftingstation>! Emily Fray có thể cho ngươi biết thêm.",
    [3374061050] = "Chính",
    [3374429470] = "Cây Cảnh Tết Nguyên Đán",
    [3374506268] = "Quần Điềm Báo",
    [3374514309] = "Chỉ cần nhìn vào đôi mắt đó là kẻ thù của ngươi sẽ muốn quay đi. Đó là tuyến phòng thủ đầu tiên của ngươi, và ngươi không cần phải nhấc một ngón tay.",
    [3374876076] = "Một chiếc rìu với hai lưỡi thép tròn trịa, cân bằng hoàn hảo. Chúng gần như tạo thành hình dạng của mặt trăng tròn.",
    [3375270932] = "Trong khi điều tra pháo đài, bạn đã phát hiện ra một ghi chú đề cập đến một cánh đồng \"quả mọng u ám\" gần đó. Cách viết trong văn bản khiến bạn tin rằng quả mọng chỉ có thể tìm thấy vào ban đêm.\n\nHãy đến cánh đồng quả mọng u ám vào ban đêm để thu thập quả mọng u ám!\nBạn cũng có thể <b>thu thập nguyên liệu ở những nơi khác trong Rừng Rộn Ràng</b> và trả lại cho Thợ Cắt Tóc trong khi <b>có chúng trong kho đồ của bạn.</b>",
    [3375309616] = "Nắm Đấm Không Vũ Khí",
    [3375816510] = "Bụi Bọ",
    [3375930114] = "Cưỡi cùng cơn gió.",
    [3376043542] = "Sách",
    [3376356076] = "Mọi chuyển động đều được làm mềm và im lặng khi mặc bộ giáp thân trên này.",
    [3376869216] = "Người Lùn Làm Vườn",
    [3377116895] = "Khiên Bóng Của Núi",
    [3377300604] = "Gậy phép Tìm Thấy",
    [3378081119] = "Người Chữa Lành II",
    [3378110123] = "Bẫy Cầu Lửa",
    [3379632687] = "Đuốc Đầu Lâu Gắn Tường Hầm Mộ",
    [3379922932] = "Xám Thanh Lịch",
    [3380075572] = "Loại Bỏ Địa Hình M",
    [3380594520] = "Đến Địa Điểm Trang Phục Lễ Hội",
    [3380962803] = "Cuộn Hoa Bóng Tối",
    [3381101596] = "Hàng Rào Cọc Gỗ Cao I",
    [3381527867] = "Hàng Rào Thép",
    [3381969039] = "Hồi đó, khi con gái tôi Marianne còn nhỏ, chúng tôi đã bỏ chạy khỏi ngôi nhà cũ khi có dấu hiệu mục nát đầu tiên. Tôi ôm con gái bé bỏng, một túi ngũ cốc, chất cả hai lên xe và không bao giờ ngoái lại. Tôi bỏ lại mọi thứ khác, chôn một nửa tài sản của mình dưới tầng hầm đang mục ruỗng... Nếu bạn đủ dũng cảm để đến đó, có lẽ bạn sẽ tìm thấy thứ gì đó hữu ích. Đáng tiếc, đó là tất cả những gì tôi có thể cho bạn.",
    [3383672486] = "Tủ Ly Gỗ Phương Bắc Nhỏ",
    [3384003364] = "Một đôi bốt của hiệp sĩ. Chúng đã trải qua nhiều hiểm nguy và đau khổ.",
    [3384176594] = "<b>Vukah</b> trong phạm vi <b>50</b> mét sẽ không tấn công bạn trừ khi bị khiêu khích.",
    [3384200475] = "Mũ Pháp Sư",
    [3384286281] = "Một nguyên liệu được sử dụng trong các công thức chế tạo.",
    [3384431762] = "Tình Yêu Tranh Giận",
    [3384450417] = "Cây Giống Lô Hội",
    [3384935582] = "Rìu Mặt Trăng Thép",
    [3385150813] = "Cá Nướng Phi Lê",
    [3385606839] = "Bụi Cây Mọng Tím",
    [3385629201] = "Tắt",
    [3385714086] = "Không có máy phát điện trong phạm vi (%km).",
    [3385740604] = "Ăn",
    [3385922085] = "Sảnh Hollow",
    [3386131401] = "Gác Mái Bí Mật",
    [3386482946] = "Trên hành trình của mình, bạn sẽ gặp những <b>cánh cửa và rương khóa</b>. Để mở chúng, <b>hãy chế tạo dụng cụ mở khóa</b> trong tab Chế tạo Thủ công của bạn. Dụng cụ mở khóa sẽ được <b>sử dụng tự động</b> khi tương tác với cửa hoặc rương bị khóa.\n\nChế tạo dụng cụ mở khóa yêu cầu Mảnh Kim Loại.",
    [3386736770] = "Một món ngon của thế giới biển, giòn bên ngoài và mềm mại, đầy hương vị bên trong. Đây là bữa ăn hoàn hảo cho những nhà thám hiểm mệt mỏi.",
    [3387139068] = "Miễn Nhiễm",
    [3387372154] = "Một Mẻ Lưới Bị Nguyền Rủa",
    [3388046284] = "Không bao giờ nghĩ rằng tôi sẽ chứng kiến một cuộc chiến — không, một cuộc xâm lược trực tiếp — trong những ngày cuối đời mệt mỏi của mình.\n\nTôi đã chôn cất quá nhiều người. Tôi thú nhận điều này an ủi tôi. Dẫn dắt mọi người trên chuyến hành trình cuối cùng của họ. Quá nhiều lời tạm biệt cuối cùng. Hôm nay là của tôi.\n\nQuân đội phương Bắc đã vượt qua cổng thành. <b>Chúng ta không thể tìm nơi trú ẩn trong lâu đài... <lorename>Gormander</lorename> đã khóa tất cả các cửa, hạ tất cả các cổng. Điều đó sẽ không ngăn được đám đông. Chúng sẽ tìm đường vào. </b> Các vị Thần Cổ đại phù hộ cho chúng con, Sương độc đang len lỏi vào bên trong. Có thứ gì đó nhỏ giọt từ trên cao.\n\nNếu ai đó tìm thấy điều này, nếu còn ai sót lại\nTôi muốn được chôn cất bên cạnh vợ và con trai tôi dưới gốc cây sồi già\nHãy để bia mộ trống\nTôi không còn gì để nói",
    [3388114089] = "Vách Ngăn Phòng I",
    [3388151980] = "Âm Nhạc",
    [3388167385] = "Chào Mừng!",
    [3388806439] = "Bạn cung cấp cho đoàn của mình khả năng Chữa thương.",
    [3389404615] = "Đang cân nhắc một vài cú va chạm, phải không?",
    [3389456631] = "Thưa Đức Vua Vĩ Đại của tôi — Tôi viết thư này với tin tức đáng lo ngại. <location>Glennwood's End</location> đang sụp đổ. Cứ như thể một đám mây lớn của bệnh tật và mục nát đã bao phủ lên công quốc. Người dân đã để nhà cửa, đường sá và cách sống hàng ngày của họ tan hoang... tất cả là do một chất họ tiêu thụ gọi là \"Thuốc Tiên\". \n\nTôi đã lấy mẫu từ một nhà máy chưng cất bất hợp pháp và hiện đang nghiên cứu chúng. Loại Thuốc Tiên này dường như biến con người thành quái vật, vì vậy tôi đã khóa chặt cửa vào ban đêm.",
    [3390352614] = "Tăng Cường",
    [3390446739] = "Dừng Lại",
    [3390937962] = "Mọi bài hát đều phải có hồi kết.",
    [3391310707] = "Rễ cây ăn được của một loài thực vật rừng. Không quá bổ dưỡng khi ăn một mình. Có lẽ tốt như một nguyên liệu?",
    [3391327907] = "Công Cụ",
    [3392079081] = "Giám Sát",
    [3392276507] = "Xem Công Thức",
    [3392377264] = "Học Việc Pháp Sư",
    [3392694132] = "Sấm Sét Của Người Chăn Cừu",
    [3393113364] = "Bạn đã đi đến mỏ đá vì tôi chưa? Những viên đá ở đó thật đẹp, bạn sẽ không hối tiếc đâu!",
    [3393126194] = "Vũ Khí Tầm Xa",
    [3393296127] = "Làn Nước Ngọc Lam",
    [3393334354] = "Sử Dụng Hết",
    [3393431252] = "Thời Gian Độc Tố",
    [3393586515] = "Máng Ăn Cho Dê",
    [3393660298] = "Giếng Thuốc Tiên Đã Được Làm Sạch",
    [3394128803] = "Nâng cấp hoàn toàn vũ khí để mở Khóa Ngọc.",
    [3394338834] = "Một chiếc rìu 1H mạnh mẽ, nhuốm máu của những kẻ đã ngã xuống.",
    [3394442598] = "Bạn nên thấy con cá tôi bắt được ngày hôm kia!",
    [3394529442] = "Mũi Tên Đồng Thiếc",
    [3394763498] = "Đổi Tên Nhân Vật",
    [3395379735] = "Giờ thì quay lại đó đi!",
    [3395431217] = "Đá Đền Thờ",
    [3395511755] = "Cúp Danh Năng Rồng Con Sa Ngã Bằng Vàng",
    [3395882309] = "<b>Thợ Săn Tiền Thưởng</b> Và Sương độc",
    [3395908105] = "Chúng tôi nhận thấy rằng một số cá nhân đã cố gắng tự mình loại bỏ các vật cản trong máy nghiền khi <b>máy móc vẫn đang hoạt động.</b> Chúng tôi phải nhấn mạnh rằng việc này là <b>nghiêm cấm tuyệt đối do rủi ro an toàn nghiêm trọng,</b> bao gồm khả năng mất chi, hoặc tệ hơn, mất việc làm.\n\nTuyệt đối không được đặt bất kỳ bộ phận nào của cơ thể gần hoặc bên trong thiết bị đang chuyển động. \nNếu việc tiếp cận đá nghiền là hoàn toàn cần thiết, <b>tất cả dòng nước phải được dừng hoàn toàn trước bất kỳ sự can thiệp nào.</b> Để dừng dòng nước, <b>hãy đóng các cửa nước trong bể bánh xe nước.</b> Điều này sẽ đảm bảo bánh xe nước bên ngoài ngừng hoạt động và tất cả các máy móc liên quan bị vô hiệu hóa hoàn toàn.\n\nVui lòng coi trọng vấn đề này. An toàn của bạn là ưu tiên hàng đầu của chúng tôi.\n\nTrân trọng,\n<i>Timberwolf Logging & Co.</i>\nĐội An toàn & Vận hành",
    [3396350508] = "Kiếm dài Đỉnh Cao",
    [3397513321] = "Phòng Thủ",
    [3397668910] = "Hút Máu",
    [3398139330] = "Được tặng bởi %k",
    [3398315305] = "Nữ Hầu Rồng Lộng Lẫy, Chương 2: Nữ Thần Sông",
    [3398431124] = "Bảo Vệ",
    [3398636824] = "Trượng Trăng Khuyết Nham Hiểm",
    [3398788895] = "Một cuộc theo đuổi tầm thường, giờ đây khi ta đã nếm trải sự vĩnh cửu... nhưng ta đã không đi mà không có kế hoạch, cũng không có một <i>lập luận thuyết phục.</i>\n\nChỉ một giọt Thuốc Tiên để làm ngọt rượu vang. Đó là tất cả những gì Gormander, tên ngốc già, cần để triệu tập các cố vấn và kỹ sư của mình. Ban đầu họ có thể cảnh báo ông ta chống lại việc xây dựng Giếng Thuốc Tiên, nhưng lời nói của họ sẽ sớm lụi tàn.\n\nTuy nhiên, Jezmina chỉ có thể bị bịt miệng bằng một cái tát nhanh. Con nhóc vẫn tin rằng các Vị Thần Cổ đại có lý do chính đáng để che giấu thứ sức mạnh này... Một nhà thầu tư nhân sẽ xây dựng Giếng thay thế cho cô ta, nếu cô ta không tuân lệnh. Một khi tiếng lải nhải của cô ta tan biến thành tiếng khóc, ta đã ép cô ta mở mắt và nói cho cô ta sự thật giữa những lời dối trá.\n\nCác Vị Thần Cổ đại đã <i>GIẤU</i> điều này khỏi chúng ta!\nChúng là những con rắn đang ngủ, và tất cả trừ ta đều quá sợ hãi để đánh thức chúng! Lũ hèn nhát, ta nói vậy! Chuột trước Rồng cải trang, ta nói với ngươi!\n\nChúng ta đúng khi tự vệ. Đào sâu hơn một chút — Còn gì nữa ẩn giấu bên dưới?\nTrái Đất sẽ tuôn trào bí mật của mình nếu chúng ta xẻ lưỡi nó, làm nứt nó ra, để nó chảy máu?\n\nTa chỉ tin vào màn sương dưới mũ của kẻ lang thang, cái giật mình của bóng tối của hắn, cái há hốc của trăm miệng hắn \nHắn có thể khiến chúng ta trỗi dậy\nCó thể khiến chúng ta bay lên\nCó thể biến chuột thành người\n\n— Lãnh chúa <lorename>Vorgoth</lorename>, Vệ binh phương Bắc",
    [3398813645] = "Xương",
    [3399817798] = "Một chiếc mũ bảo hiểm xa hoa với lông vũ màu đỏ, theo truyền thống được các chỉ huy quân đội cấp cao đội.",
    [3400042986] = "Tìm Kiếm Manh Mối Về <lorename>Loraine Crim</lorename>",
    [3400326633] = "Tìm Kho Báu Của <lorename>Gormander</lorename>",
    [3400384358] = "Bạn đã đi được một chặng đường dài, nhưng chúng ta phải đi xa hơn nữa. Nỗi sợ hãi ngon lành thoát ra khỏi chúng và du hành từ bên kia bức màn đến tai ta. Hãy đến vùng cát mệt mỏi ở phía Đông. Tàn phá chúng hơn nữa. <i>Lướt. Thu thập. Giành lấy.</i>",
    [3400468073] = "Một đôi bốt thoải mái, hoàn hảo cho những ngày tuyết rơi.",
    [3400639303] = "Niềm Vui Kỳ Lạ Của Olric",
    [3400812099] = "Vảy dài bằng thời gian ban ngày. Giá trị nhỏ hơn tương đương với thời gian ban ngày ngắn hơn.",
    [3400930938] = "Khi Thủy Triều Dâng Cao",
    [3401000185] = "Tháp canh cũ ở <location>Surat's Rest</location> giấu những vật có giá trị. <b>Hãy lên đỉnh tháp</b> và nhận lấy <b>kho báu</b> ở đó!",
    [3401363214] = "Trông bạn có vẻ đang bị bệnh, Hỡi Người Lửa! Xin hãy bước lại gần hơn để tôi có thể kiểm tra bạn!",
    [3402039244] = "Đài Lửa Phòng Ngai Vàng Lớn",
    [3402053602] = "Những khởi đầu mới đang chờ đợi.",
    [3402100918] = "Khung Cửa Sổ Bằng Đá Tròn Lớn",
    [3402274952] = "Một",
    [3402556964] = "Súp Bí Ngô",
    [3402871556] = "Nhìn xem sự thanh bình của màu ngọc lam này! Nó thật yên bình và thanh thản, như một dòng suối trên núi băng giá...",
    [3403019207] = "Cung",
    [3403570810] = "Triệu hồi một tia sét điện tử lượn lờ xung quanh bạn và bắn ra các tia năng lượng.",
    [3404015626] = "Xây Giường Che Chắn Cho Emily Fray",
    [3404227960] = "Bạn đã tìm thấy một ghi chú về một chiếc máy pha cà phê bị hỏng.\nNếu họ rang và pha cà phê ở đây, công thức của họ chắc hẳn phải ở đâu đó xung quanh.\n\n<b>Hãy tìm công thức, để bạn có thể tái tạo chúng theo cách riêng của mình!</b>",
    [3404772575] = "Bạn có thể sử dụng Móc Câu để kéo kẻ địch nhỏ và trung bình về phía bạn. Kẻ địch bị choáng trong 1 giây.\nChi phí: 50 SP",
    [3405238022] = "DLSS",
    [3405793317] = "Trang Phục Nữ Hầu",
    [3405858492] = "Kẻ Nhảy Sóng Nướng",
    [3406355146] = "Bình Hồn Drak",
    [3407307323] = "Lực phản đòn",
    [3408359643] = "Những Chú Lùn Nhỏ",
    [3408931043] = "Tên Lửa Tím",
    [3408934552] = "Cồng Kẻ Thu Lượm",
    [3409058614] = "Rượu Và Máu",
    [3409109637] = "Chúng Ta Đã Đào Quá Sâu",
    [3409288634] = "Một đôi bốt sáng bóng. Chúng nặng đến mức bạn gần như không thể di chuyển khi mang chúng.",
    [3409295559] = "Mảnh giáp bị lãng quên này được bao phủ bởi máu khô và bao trùm trong bóng tối. Có lẽ nó nên được giữ nguyên trạng thái bị mất.",
    [3409309407] = "Nhẫn Bão Sấm Sét",
    [3409420495] = "Hãy để chân nghỉ ngơi một chút nào.",
    [3409457142] = "Về Dao Găm Và Rượu Vang",
    [3409527462] = "Bạn không có đạn tương thích.",
    [3409530773] = "Bạn đã khám phá ra một người sống sót mới trong Sảnh Đường Hollow Tuếch. \n\n<b>Đặt họ vào nhà của bạn với một cây Gậy phép triệu hồi</b> để tiếp tục.",
    [3411091421] = "Hiển thị chi tiết",
    [3412319343] = "Tạo Đánh Dấu Tùy Chỉnh",
    [3412878200] = "Tàn tích của một kẻ lặn chưng cất không may đã bị chà xát dưới ván sàn của <location>Xưởng Ép Willow</location> <b>. Tìm địa điểm và đào bới kho báu!</b>",
    [3413797753] = "Chỉnh sửa Bố cục Điều khiển",
    [3414370025] = "Nắp Quan Tài Hầm Mộ Lớn",
    [3414450601] = "Bàn Tiệc Gỗ Đánh Bóng",
    [3414593962] = "Bạn có chắc chắn muốn xóa <b>\"%k\"</b> khỏi mục yêu thích của mình không?",
    [3415106472] = "Xác nhận",
    [3415335046] = "Một loại cây thú vị, kích thích vị giác của mọi người. Việc sử dụng trong trà đã trở thành một phong tục.",
    [3415687257] = "Ghi Chép Của Ramone",
    [3415758833] = "Chậu Cây Dài",
    [3415868375] = "Sự Phát Triển Phát Sáng Dưới Nước",
    [3415964847] = "The <npc>Người Thu Thập</npc>, người tự giới thiệu là Alden Crowley, cần nơi trú ẩn. Họ sẽ có thể chế tạo thêm khi được trú ẩn. Xây dựng một ngôi nhà cho <npc>Người Thu Thập</npc> và cấp cho họ quyền truy cập vào một <b>giường trú ẩn gần đó nếu bạn chưa có!</b>\n\nĐể trú ẩn cho những người sống sót của bạn, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót miễn phí gần nhất khi được đặt. Nếu bạn muốn chỉ định lại giường, hãy trang bị Cây Gậy phép Triệu Hồi của bạn và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho bạn khi những người sống sót của bạn không còn được trú ẩn nữa.",
    [3416256560] = "Một sinh vật cô độc đã đến quán rượu khi tôi đang đóng cửa. Họ yêu cầu ngồi uống một ly với tôi và bắt đầu kể về một nguồn tài nguyên chưa được khai thác dưới lòng đất. Nếu chúng ta đào đủ sâu, người lạ mặt trùm đầu này đã thông báo cho tôi, chúng ta sẽ mở khóa một tiềm năng mới cho toàn nhân loại. Tôi bị cuốn hút...",
    [3416444519] = "DLAA",
    [3417692650] = "Đỡ Đòn Mạnh Mẽ",
    [3418112656] = "Làm Bát Ăn Cho Chó Và Giường Cho Chó",
    [3418147751] = "Những Cây Cầu Và Mối Quan Hệ Tan Vỡ",
    [3418273222] = "Chà, nhìn kìa! Chân tôi hoạt động, và mũi tôi không bị gãy! Tôi còn sống và khỏe mạnh, và tôi thích một cú đá hay! Hãy xắn tay áo lên và xây dựng lại nơi này!",
    [3418289893] = "Số Lượng Vị Trí Xuất Hiện",
    [3419677464] = "Bắn Vũ Khí Tầm Xa",
    [3419756268] = "Chết Đuối",
    [3419762830] = "Đèn Chùm Hầm Mộ Bằng Sắt",
    [3420803696] = "Đôi quần này có lớp đệm dày bên trong, cho phép bạn di chuyển trong thời gian dài hơn ở những vùng đất bị băng giá bao phủ. Theo truyền thống, da từ động vật Tinh thần của người mặc được sử dụng để tạo lớp đệm, nhưng len cũng có thể dùng tạm.",
    [3421470348] = "Giường",
    [3421699116] = "Bạn đã trở về từ hành trình của mình! Cảm ơn bạn đã khám phá bí ẩn của lá thư đó. Bây giờ tôi có thể làm cho bạn mạnh mẽ hơn - hãy cân nhắc chế tạo áo giáp mới!",
    [3421752584] = "Dưới Chân Vòng Xoắn Ốc",
    [3421888085] = "Nhạc Cụ Sử Thi",
    [3422097835] = "Mang Những Linh Hồn Thuần Khiết Trở Lại",
    [3422193079] = "Tượng Chú Lùn Sân Vườn Cầm Đèn",
    [3422255023] = "Bạn đã khám phá ra rằng một thị trấn gần đó, <location>Shorewatch</location>, trước đây là nhà của một bà lão đã cho nhiều chó hoang ăn. Có lẽ vẫn còn một vài con chó ở đó. Hãy đến thị trấn và tìm một con chó có thể thuần hóa!",
    [3422382056] = "<lorename>Jezmina</lorename>, có thật không? Các Cổ Nhân kêu gọi bạn <i>ở lại trong khi những người còn lại của chúng ta ngủ say?</i> Bạn sẽ ở đó khi tôi thức dậy chứ? Làm ơn, bạn không thể rời xa tôi! Bạn là tất cả của tôi! \n\nTại sao chúng ta phải thay đổi? Tôi nhớ những ngày xưa khi chúng ta còn đi du lịch... cùng nhau, sát cánh bên nhau. Bạn để tôi lảng vảng bên cạnh bạn. Bạn nắm tay tôi. Và bây giờ? Tất cả bí mật này, để làm gì? Tôi nghĩ bạn có thể tâm sự với tôi. Tôi không muốn các Cổ Nhân chia rẽ chúng ta! Tôi sẽ mất hết niềm tin!\n\n Nếu bạn phải đi, ít nhất hãy cho tôi một nụ hôn tạm biệt.\n\nBằng cả trái tim,\n— Emily",
    [3422454089] = "Chúng suýt chút nữa đã thổi bay tôi thành trăm mảnh, lũ khốn nạn đó!\n\n\"Dieter, đi mà xem! Chúng tôi đã phát hiện ra một chiếc rương trong đường hầm mới, tôi thề đấy! Không, Dieter, đây không phải là trò đùa, hãy tự mình quan sát!\"\n\nMồm tôi đầy bụi, và tay tôi tê cóng vì đào bới! Móng tay tôi gãy... Tôi đói lả.\n\nLũ chó săn độc ác! Cầu mong Sương độc nuốt chửng tất cả các ngươi!",
    [3422723915] = "Bình Nhỏ Nhất",
    [3422851708] = "Một bảng màu sống động với màu xanh lam rực rỡ, đỏ rực và trắng tinh khiết — sắc nét, táo bạo và tràn đầy năng lượng, như một lá cờ tung bay trong gió. \n\nBảng màu này có thể được tạo bằng vật liệu từ Bồn Rửa Mặt Veilwater.",
    [3423061714] = "Số Phận Của <lorename>Raúl</lorename>",
    [3423071825] = "Giày Mắt Đại Bàng",
    [3423378462] = "+ Cận Chiến",
    [3424057087] = "Phù Thủy",
    [3425494552] = "Tôi nghĩ chúng ta sẽ cần một không gian mới để chứa Thuốc Tiên... các thùng bị rò rỉ và một lớp màng đã bắt đầu hình thành trên nền hầm. Nó ẩm ướt và oi bức... đi vào các hang động bên dưới khu chợ khiến người ta chóng mặt.\n\nNgoài ra, tôi đã cho Remy đi. Con chuột lén lút đó đã liếm sạch Thuốc Tiên bị đổ trên sàn... thật đáng xấu hổ.",
    [3425507225] = "Một nắm hạt cà phê rang. Chúng có mùi sô cô la và đậm đà, với một chút hương hoa ngọt ngào. Chúng phải được xay trước khi pha.",
    [3426261851] = "Một Đêm Không Ngủ",
    [3426431698] = "Đao Chặt Axit",
    [3426657919] = "Đầu Lâu Kẻ Thù Của Chúng Ta",
    [3427091853] = "Máu Drak",
    [3427139986] = "Với đôi găng tay có đệm này, bạn có thể dễ dàng leo lên bất kỳ vách đá nào để tiếp cận những linh hồn bị mắc kẹt trong tuyết đang cần giúp đỡ.",
    [3427175724] = "Một cây cần câu cơ bản được làm từ những nguyên liệu đơn giản nhất. Đừng kéo quá mạnh, nếu không nó có thể bị gãy. Nó cũng không nằm vừa tay lắm, nên không thể câu cá lâu với nó.",
    [3427228081] = "Tìm Nhà Của Thợ Dệt Ở <location>East Lapis</location>",
    [3427315632] = "<npc>Thợ Săn</npc> Từ Cao Nguyên Du Mục",
    [3427431329] = "Những Bức Tường Còn Sống!",
    [3428203575] = "Tin Đồn Về Hang Rồng",
    [3428744036] = "Hàng Rào Sân Vườn Gỗ Phương Bắc I",
    [3428969872] = "Những Tấm Kim Loại Được Nung Chảy Từ Mảnh Vụn Kim Loại Để Làm Cho Chúng Dễ Gia Công Hơn Và Mở Ra Các Lựa Chọn Để Chế Biến Thêm.",
    [3429435545] = "Việc trinh sát trước có thể khá thử thách, đặc biệt là trong bóng tối. <b>Mũi tên đặc biệt</b> này để lại một ngọn lửa tại điểm va chạm, tỏa ra một chút ánh sáng.",
    [3430180887] = "Tấn Công Tàn Nhẫn",
    [3431085348] = "Một lượng lớn ectoplasm kết tinh. Bên trong ẩn chứa bản chất của sức sống.",
    [3431687451] = "Trại Scavenger có Hầm mỏ",
    [3431691163] = "Vịnh Skimmer",
    [3431713612] = "Rìu Gỗ Tối",
    [3431775565] = "Găng Tay Thầy Thuốc",
    [3431790624] = "Một chiếc bình vàng góc cạnh. Để phù hợp với giá trị tình cảm của tro cốt, gia đình tang quyến đã trang trí chiếc bình này bằng những viên ngọc bích đỏ rực. Khi lắc bình, một hành động có khả năng vô thần và tồi tệ nhất, bạn có thể nghe thấy tiếng lạch cạch bên trong...",
    [3431804049] = "Lò Nướng",
    [3432076870] = "Vị Trí Bản Nhạc",
    [3432157443] = "Không có động vật trang trại nào có sẵn.",
    [3432517977] = "Cây Giống Khoai Môn",
    [3432617693] = "Giếng Thuốc Tiên",
    [3432832248] = "Bước Đi Lặng Lẽ",
    [3433111205] = "Rau Củ",
    [3433408926] = "Mũi Tên Nổ III",
    [3434204560] = "Bàn Thờ Hoạt Động",
    [3434756280] = "Di Chuyển: Thanh Hành Động <img arrow_left_right> Ba Lô",
    [3434932225] = "Đất Nóng Vùng Đất Mùa Xuân",
    [3435131839] = "Cuồng Nộ Máu",
    [3435323644] = "Đôi găng tay cung thủ truyền thống này được làm không đối xứng bởi nhiều chiếc ngà quái vật và những mảnh xương nhô ra bên ngoài.",
    [3435347481] = "Tăng Tốc Độ Lén Lút",
    [3435493478] = "Thanh Kiếm Rồng Nổi Tiếng",
    [3435680490] = "Chất Lượng Mô Phỏng (chỉ với tư cách chủ nhà)",
    [3435790005] = "Rêu",
    [3436142882] = "Đến, cùng chia sẻ một bữa ăn và một câu chuyện!",
    [3436265149] = "Cung Của Kẻ Đào Trộm Mộ",
    [3436559198] = "Đọc tất cả các bia đá ở Cao Nguyên Du Mục.",
    [3437404416] = "Hôm Qua, Sông Đã Lũ Lụt",
    [3438339836] = "Những cánh hoa mỏng manh bị Sương độc làm ô nhiễm. Bề mặt của chúng được phủ một lớp cặn độc hại mờ nhạt. Mặc dù mỏng manh khi đứng một mình, chúng lại có khả năng phục hồi đáng ngạc nhiên khi được dệt vào giáp.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Dây leo Tinh ranh Fell, ban đầu tìm thấy ở Revelwood.",
    [3438554707] = "Phòng lưu trữ cho 16 vật phẩm.",
    [3438624309] = "Khối Sắt Cực Kỳ Đáng Tin Cậy Và Thêm Một Lớp Trang Trí Cho Bất Kỳ Tòa Nhà Nào.",
    [3438875135] = "Mở Rộng Khu Vực Xây Dựng Lên 125m × 125m.",
    [3439686350] = "Đồn Lính Balefire \"Rimerock\"",
    [3440133122] = "Nhận một điểm Nhanh nhẹn cho mỗi hai cấp độ của Ngọn Lửa.",
    [3440719558] = "Một Màu Xanh Lá Đại Diện Cho Sự Ghen Tị Và Bất Tử",
    [3440851682] = "Thắp Sáng Các Đỉnh Núi Tuyết",
    [3441888545] = "Hệ Số Sát Thương",
    [3442070648] = "Đến <location>Glennwood's End</location>",
    [3442507368] = "Sự Dại Dột Của Đứa Con Đầu Lòng",
    [3442736793] = "Chỉ báo mức độ khó của Minigame Câu Cá.",
    [3443794221] = "Giày Nanh Sói",
    [3443953774] = "Áo Rách Nát",
    [3444073872] = "Tái Chế",
    [3444202132] = "Bột bạc mịn, lấp lánh. Đừng làm rơi, nếu không bạn sẽ thấy những đốm bạc trên sàn nhà trong nhiều tuần tới.",
    [3444514355] = "Tăng cường mũi tên khi cắt",
    [3444621872] = "Trang trí căn cứ của bạn để tăng <b>Sự thoải mái.</b> Một căn cứ được trang trí với mức độ thoải mái cao hơn sẽ tăng thời gian hiệu lực của hiệu ứng <b>Đã nghỉ ngơi.</b>",
    [3444795981] = "Nằm trong Vương quốc Rơi Sao. Một vực thẳm sâu đến nỗi nội dung của nó đã vượt khỏi tầm hiểu biết của chúng ta trong hàng thiên niên kỷ.\n\nKhông bí mật nào có thể chống lại ánh sáng của Ngọn lửa vĩnh cửu. Một thứ tà ác cổ xưa, đang ấp ủ... đang lớn dần...\n\nNó phải bị chôn vùi, nhấn chìm và niêm phong. Nhân loại không bao giờ nên chạm vào những sợi tua tủa của sự hỗn loạn này.",
    [3445083817] = "Kháng xuyên thủng ",
    [3445939213] = "Hành trình của Jezmina đến Đầm lầy Đen",
    [3446392302] = "Bạn chưa mở khóa vật phẩm Twitch Drop này và không thể sử dụng nó.",
    [3446477342] = "Thiêu đốt",
    [3448598207] = "Mũ Giáp Chiến Binh Quật Khởi",
    [3448999977] = "Tiền đồn Scavenger bị đột kích",
    [3449210759] = "Chế tạo <craftingstation>Máy cưa bàn</craftingstation>",
    [3449552028] = "Rèn Ngọc vũ khí",
    [3449840994] = "Kháng đập",
    [3450590961] = "MP",
    [3450627461] = "Trong một cõi truyện chưa kể,\nNơi bóng tối nhảy múa, bí ẩn hé mở.\nSinh vật bay, tấn công từ bầu trời,\nBóng cảnh báo của chúng, nhanh và cao.\n\nHãy cẩn thận với tinh linh cánh tối tăm,\nSự hiện diện của chúng mang đến nỗi sợ hãi lạnh lẽo.\nHãy lắng nghe những lời thì thầm xưa cũ,\nNhững bí mật được chia sẻ, câu chuyện của chúng hé mở.\n\nCác con, hãy học hỏi từ truyền thuyết cổ xưa,\nHãy canh giữ bước chân của mình, mãi mãi.\nTrong xứ sở của những giấc mơ và sự kỳ diệu,\nHãy chú ý đến bóng tối, đừng bao giờ sai lầm.",
    [3451051807] = "Bảo vệ chống lại cái lạnh và hạ thân nhiệt",
    [3451597529] = "Tăng sát thương với các đòn tấn công không vũ trang.",
    [3452317123] = "Rơi ra từ nấm trong Sương độc Revelwood",
    [3453078316] = "<keyitem>Lưỡi cưa tròn</keyitem>",
    [3453289634] = "Viên Thuốc Súng Nổ",
    [3454104322] = "Chiếc quần dày và đáng tin cậy. Không thoáng khí lắm, thật không may.",
    [3454598808] = "Bạn đã chế tạo mồi cho chó cần thiết để thuần hóa một con chó hoang. Bây giờ hãy đến <location>Thornhold</location> và tìm chó để thuần hóa ở đó!",
    [3454738107] = "Công Cụ Phá Dỡ Khối 4x4",
    [3455753064] = "Một bảng treo tường cho phép bạn trưng bày tất cả thành tích câu cá của mình.",
    [3456211130] = "Bộ Đồ Sát Thủ",
    [3457008286] = "Mũ Trùm Trinh Sát",
    [3457724519] = "Đèn Chùm Sắt",
    [3457866933] = "Tốc độ tấn công",
    [3458003416] = "Sự ra đời của các vị thần mới - Dalszul",
    [3458101713] = "Nhập Tên + Xác nhận",
    [3458170387] = "Công thức hiện tại",
    [3458271961] = "Đủ để chống chọi với điều tồi tệ nhất, cho đến khi áo giáp tốt hơn xuất hiện.",
    [3458379167] = "Bạn có %k cơ hội nhận sát thương bạn gây ra dưới dạng Hồi HP.",
    [3458841306] = "Các Tiền nhân đã cứu tôi, có lẽ còn những người khác... có một kho báu mà tôi biết. Bạn có thể xem qua.",
    [3459169051] = "Kho báu cổ đại — <npc>Thợ săn</npc>",
    [3459206606] = "Một viên gạch đỏ sáng bóng được chế tạo bằng cách làm cứng Cục đất sét dưới sức nóng mà ngay cả một Người sinh ra từ Lửa cũng gặp khó khăn.",
    [3459744074] = "ST Cận chiến 2H",
    [3460640820] = "Động vật hoang dã",
    [3461042776] = "Cung Chỉ Huy Sa Ngã",
    [3461373988] = "Đầu của một con Khổng lồ bị Sương độc xâm nhiễm. Nó có hơi thở khá tệ, ngay cả bây giờ.\n\nThu thập nhiều Đầu Khổng lồ Fell để chế tạo Tượng.",
    [3461499932] = "Một chiếc khăn trùm đầu trắng như tuyết.",
    [3461945059] = "Một chiếc rìu 2H tích điện, có khả năng giải phóng tia lửa vào bầu trời u ám khi tấn công. Nó bị sét đánh khi ở trong một cơn bão tố thảm khốc và sống sót, không giống như chủ nhân trước đó của nó.",
    [3462525100] = "Hoa Loa Kèn Ngày Cho Emily",
    [3463286768] = "Quần Kẻ Gọi Thủy Triều",
    [3463576911] = "Vĩnh cửu bị bắt giữ",
    [3463762373] = "Cung cong theo hình zig-zag ở cả hai bên, nắm bắt tầm nhìn về chiếc đuôi rắn đuôi chuông đang chuyển động.",
    [3463900229] = "Drak'Dal đã đi quá lâu.\n\nTất cả đền thờ của chúng ta đều sụp đổ thành tro bụi!\nDrak'Dal sẽ cho Tiền nhân thấy sức mạnh thực sự! Sẽ cho thấy Tiền nhân đã sai lầm với loài người bằng xương bằng thịt! Drak'Dal sẽ không xây dựng trong bóng tối của bất kỳ ai!\n\nXây dựng một ngôi nhà mới! Xây dựng cho Dalszul! Xây dựng, hoặc Mẹ Broodmother Vesztah sẽ chặt đầu bạn!\n\nRah Rah!",
    [3464252587] = "Một cơn gió độc hại",
    [3464267517] = "Tăng thuộc tính Thể lực của bạn lên 1.\n\nTăng HP thêm %k cho mỗi Điểm thuộc tính.",
    [3464525504] = "Một vài quả mọng",
    [3464722848] = "Hang Lumenlight",
    [3464727669] = "Nụ Hôn Độc",
    [3464878743] = "Vũ khí phép thuật",
    [3465329742] = "Triệu hồi <npc>Thợ cắt tóc</npc>",
    [3465856315] = "Âm nhạc kỳ lạ",
    [3466274974] = "Hoa Địa Lan Vàng",
    [3466595171] = "Đến Nhà thợ mỏ",
    [3467304764] = "Lưỡi Kiếm Xám",
    [3467601026] = "Xuyên giáp",
    [3467848688] = "À, vậy là lò rèn đã sử dụng ống thổi để đạt được nhiệt độ cao... tất nhiên rồi, tại sao tôi không nghĩ đến điều đó?",
    [3468293480] = "Bọ Ba Thùy",
    [3468929019] = "Một chiếc búa mạnh mẽ, gia bảo của gia tộc Dimweald. Vũ khí này thuộc về Berhtolf, con trai cả. Lòng dũng cảm là sự sụp đổ của anh ta.",
    [3469151724] = "Gunther Galeforth",
    [3469267685] = "Trọng Kiếm Dòng Tu Cũ",
    [3469877875] = " <npc>Nhà sưu tập</npc> đã tiết lộ vị trí của các Sảnh đường Hollow trong Đỉnh Albaneve.\nHãy đi xuống đó và đến cuối để làm hài lòng <npc>Nhà sưu tập</npc>.\n\n<b>Đây sẽ không phải là một nhiệm vụ dễ dàng. Hãy tập hợp sức mạnh và đồng minh của bạn, nếu có, để chuẩn bị cho bản thân một cách thích hợp.</b>",
    [3470465571] = "Một ngọn lửa bùng cháy nhảy múa trên mái nhà của <location>Nơi nghỉ ngơi của Surat</location>. Chúng ta đã quá muộn.\n\nHọ đến từ <location>Lâu đài Quạ</location> — đã trốn thoát. Bây giờ, <location>Nơi nghỉ ngơi của Surat</location> là một đống lửa điên cuồng. Tôi run rẩy khi nhìn thấy. <i>Mẹ</i> sẽ làm gì?\n\nMẹ sẽ di chuyển trước khi mặt trời mọc. Bỏ lại mọi hành lý — nhanh chóng và lặng lẽ, được gió mang đi. Con đường đến <location>Longkeep</location> đầy rẫy nguy hiểm... Chúng ta phải đi.\nVinh quang cho <lorename>Pikemead</lorename>. Cầu phúc cho các Tiền nhân.\n— <lorename>Jezmina</lorename>",
    [3470615899] = "Tìm hang Rồng",
    [3470666058] = "Đang chạy...",
    [3471461828] = "Vương Miện Quý Tộc",
    [3471481223] = "Đến Tàn tích Drak'Dal",
    [3471612060] = "CHỖ TRỐNG CĂN CỨ CHÍNH",
    [3472154387] = "Bàn Lâu Đài Nhỏ",
    [3472214887] = "Tàn tích của những loài sâu bọ sinh sống dưới Sương độc.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Sinh vật Fell, ban đầu tìm thấy ở Springlands.",
    [3472652190] = "Chúng ta có thể nâng cấp Ngọn lửa hơn nữa với thái độ đúng đắn! Tại sao không thử xem?",
    [3472764767] = "Dễ sử dụng và khá chết người. Các lưỡi dao sắc bén ở hai bên cho phép xuyên thủng áo giáp dễ dàng hơn.",
    [3473505813] = "Này, Người sinh ra từ Lửa, tôi đã giúp xây dựng \"<location>Morwenna</location>.\" Đặt tên nó theo tên dì hiền lành nhất của tôi! Tôi đã xây dựng nhiều thị trấn quanh đây. Bạn đã bao giờ thấy <location>Diadwyn</location> chưa? Tôi nghĩ tôi đã để lại một số Khối gỗ nửa cây ở đó. Tại sao không kiểm tra? Ai tìm thấy người đó giữ.",
    [3473536859] = "Một con Dê thông thường bé nhỏ dễ thương. Chúng có xu hướng dụi đầu vào chân bạn để được chú ý.",
    [3473889419] = "Săn Capybara Trại Drak'Dal",
    [3474007724] = "Người nông dân muốn bạn tìm và thuần hóa một con Capybara ở Thung lũng Veilwater. Lông của loài vật này có thể được sử dụng trong chế tạo.\n\n<b>Để thuần hóa một con Capybara, trước tiên bạn phải chế tạo mồi. Chế tạo hoặc thu thập ít nhất 3 mồi Capybara để tiếp tục.</b>",
    [3474105257] = "Bạn đã khám phá ra những dòng chữ từ một người đàn ông tên là Ramone Jones. Ông ấy là một nhà văn từ thủ đô và là biên tập viên của The Pike Weekly. Hãy điều tra nơi ở hiện tại của ông ấy và cố gắng tìm ông ấy!",
    [3474868939] = "Hơi Chướng Khí",
    [3475221625] = "Hàng Rào Hầm Mộ",
    [3476276149] = "Một <craftingstation>Nồi đen</craftingstation> cho <npc>Nhà giả kim</npc>",
    [3476291432] = "Không có Máy chủ nào được chọn",
    [3476694611] = "Thuốc nhuộm xanh",
    [3477297884] = "Sát thương cơ bản ở 3 Tích lũy",
    [3477302126] = "Mong muốn sâu sắc nhất",
    [3477402103] = "Cấp độ Kháng Sương độc",
    [3477849104] = "Độ sắc bén",
    [3478333759] = "Chúng tôi hy vọng bạn thích chuyến thăm của mình đến Embervale.\n\nThời gian chờ của bản demo Sương độc bao phủ đã kết thúc. Chúng tôi sẽ gỡ bỏ bản demo vào ngày 22 tháng 10.\n\nNếu bạn thích những gì đã thấy cho đến nay, hãy thêm Sương độc bao phủ vào danh sách yêu thích của bạn để được cập nhật về bản phát hành Truy cập sớm và các tin tức khác!\n\nChúng tôi hy vọng sẽ gặp lại bạn, Người sinh ra từ Lửa, khi Sương độc bao phủ được phát hành Truy cập sớm.",
    [3478867049] = "Thép",
    [3479077966] = "Cuộn giấy này được phù phép với sức mạnh của Sao băng Sương độc. Nó giải phóng một cơn mưa Sao băng Sương độc lên tối đa năm kẻ địch xung quanh người niệm phép. Nhưng hãy cẩn thận với việc sử dụng nó, vì nó làm cạn kiệt khả năng sống sót trong sương mù của bạn khi sử dụng.",
    [3479674497] = "Cửa Tròn Gắn Sắt",
    [3479706779] = "Được rèn để đạt hiệu quả tàn nhẫn, Cung Fell Chỉ huy Tìm thấy mục đích của nó trong hộp sọ của những kẻ Scavenger dám cản đường nó.",
    [3479990033] = "Lỗi",
    [3480212038] = "Hang động yên tĩnh",
    [3480426546] = "Ony",
    [3480452669] = "Tên: Thrasher",
    [3481180656] = "Thức ăn giữ ấm",
    [3481384265] = "Thương nhân Mei đã bán một bộ cây cho người dân <location>Pháo đài Kelvin</location>, nhưng vẻ đẹp của chúng sẽ phai nhạt khi không có ai chiêm ngưỡng. \n\nHãy lấy lại cây của cô ấy từ những người chủ trước để chúng có thể nở rộ trong căn cứ của bạn! Có tổng cộng ba cây, và tất cả chúng đều được tìm thấy ở <location>Pháo đài Kelvin</location>.",
    [3481736063] = "Một cơ hội lưu trữ lớn hơn cho các vật phẩm số lượng lớn.",
    [3482052091] = "Nhu cầu",
    [3482064741] = "Tôi không nghĩ mình sẽ bao giờ nhớ lại thời thơ ấu của mình một cách trìu mến — nhưng giờ đây, sau bao năm phiêu lưu, giữa sự mục nát và suy tàn... Tôi phải nói rằng tôi nhớ nó!\n\nChắc chắn, những ngày đó thật đơn giản và buồn tẻ. Cày ruộng (hoặc giả vờ làm vậy). Trò chuyện ở quảng trường chợ khi tôi lẽ ra phải bán nông sản. Khắc sáo thay vì gieo hạt. Lén lút ra khỏi trang trại để nhảy múa suốt đêm tại quán rượu...!\n\nNhưng giờ đây, nhiều thập kỷ sau, tôi ở đây — Theo một ánh sáng rực rỡ trên bầu trời đêm đã xé toạc màn sương mù của Sương độc từ rất lâu trước đây! Chỉ còn lại một vài người sống sót, nhưng không ai tôi gặp từng nhìn thấy ánh sáng tương tự trên bầu trời. Hy vọng rằng, họ sẽ không coi tầm nhìn của tôi chỉ là một trong những <i>Câu chuyện Dũng cảm của Val</i> khác để kể bên đống lửa trại!\n\n<i>Valory</i>",
    [3482607024] = "Giày Binh Lính",
    [3482818680] = "Người <npc>Thợ mộc</npc> quen biết một <npc>Thợ săn</npc> đáng sợ từ Cao nguyên Du mục. Bà ta to lớn như núi và có khả năng thuần hóa động vật.\nBà ta đã được gửi đến <location>Pháo đài Quạ</location> sau một trận chiến tàn khốc.\n\nNgười <npc>Thợ săn</npc> này có thể đã sở hữu một <craftingstation>Trạm thuộc da</craftingstation>.",
    [3483071904] = "Tiếp cận Sảnh Hollow Kindlewastes",
    [3483209486] = "Một chiếc mũ Phù thủy. Thường được đội trong các nghi lễ mặt trăng và bói toán.",
    [3483643107] = "Đài Phun Nước Vàng",
    [3483758324] = "Thịt Cuộn",
    [3484653524] = "Nó làm Nước Đỏ Độc",
    [3484852644] = "Hai vỏ ốc hóa thạch này đã tồn tại hàng thế kỷ — cùng nhau. Người ta có thể hy vọng rằng những sinh vật bên trong chúng đã bầu bạn với nhau, nhưng một số phận cô độc có khả năng xảy ra hơn.\n\nBộ sưu tập này được tìm thấy ở Rừng Khải Hoàn.",
    [3485065950] = "Phần hàm của cây Gậy phép mở ra về phía bầu trời như cái miệng của một con quái vật háu ăn, tìm cách kéo con mồi xuống vực sâu của đầm lầy... Phép thuật mạnh mẽ được thi triển qua vũ khí này có thể đày đọa bất kỳ ai vào bóng tối.",
    [3486594655] = "Không Ai Có Thể Lừa Dối Ta! ",
    [3487030645] = "Truy Lùng Dấu Chân",
    [3488148967] = "Ta biết ngươi có thể làm được! Ngươi thực sự là một anh hùng đẹp trai, phải không?",
    [3489133916] = "Hang Sương độc",
    [3489174731] = "Hiển thị HUD",
    [3489637964] = "Chiếc quần này ngắn chẳng khác nào tuổi thọ của kẻ thù khi có mặt ngươi.",
    [3489782624] = "Cơ hội",
    [3490019737] = "Đá Rừng Revel",
    [3490431827] = "Tiền đồn Thương mại \"Điểm Dừng Du mục\"",
    [3490581877] = "Một cuốn sách. Phương tiện truyền tải tư tưởng, nền tảng của sự tiến bộ và ngọn lửa của trí tưởng tượng.",
    [3490854258] = "<b>Kế hoạch mới:</b> Bạn nhớ thị trấn bị ngập lụt mà chúng ta tìm thấy, phải không? Vâng, lối vào tầng dưới bị chặn, và để phá vỡ rào cản, chúng ta sẽ cần một <b>Móc câu dưới nước.</b> \n\nTôi đã thấy những con quái vật Drak lớn đôi khi mang chúng, nhưng không chắc tôi có muốn đi theo con đường đó không. Đã bảo Mack chế tạo một cái thay thế, nhưng sẽ mất một thời gian.\n\nTrong thời gian chờ đợi, hãy tiếp tục trinh sát khu vực. Chúng ta nên để mắt đến những con <b>cua</b> mà bạn đã phát hiện; chúng có thể trở thành vấn đề nếu chúng ta không cẩn thận.\nÍt nhất thì <b>tàn tích không còn xa,</b> vì vậy nếu một trong số chúng ta bị bắn tỉa, chúng ta không phải đợi lâu để băng bó vết thương.",
    [3490950136] = "<npc>Thợ săn</npc> Trở thành Con mồi",
    [3491257853] = "Xuyên Qua Bão Cát",
    [3491755809] = "Gánh Nặng Thời Gian",
    [3492069939] = "Ghi đè",
    [3492204011] = "Ồ, bụi cưa!",
    [3492593959] = "Mắt Quái Vật Mắt Một Bị Phủ Bóng",
    [3492652861] = "Không tìm thấy thiết bị đồ họa tương thích.",
    [3492683064] = "Thu Thập Tia Lửa",
    [3492764682] = "Chúng không đủ. Chỉ là bản sao của hắn, chưa hoàn chỉnh, không bị ràng buộc bởi xương thịt. Ta phải thử lại, có được một vật chứa khác. Lần này, <i>sống.</i>\n\nTa sẽ mang hắn trở lại — nguyên vẹn, không xương xẩu và gãy vỡ. Không bị lộn trái. Không gào thét và la hét. Chỉ nguyên vẹn, như trước đây. <i>Nỗ lực tiếp theo của ta phải thành công.</i>\nVật chứa <i>sống</i> mới nhất thật tuyệt vời. Bộ lông hoàn hảo để lột bỏ và lộ ra một cái vỏ sẵn sàng mang linh hồn hắn. Lần này, nó sẽ hiệu quả. Nó đơn giản là phải vậy. Ta sẽ lấy lại Ikko của mình.",
    [3493330016] = "Người <npc>Sưu tầm</npc>, Alden Crowley, đã bị nhốt trong Sảnh Hollow quá lâu đến nỗi họ vẫn chưa biết về Flameborn.\n\nHọ tự nhận là \"chạm vào Ngọn lửa\" nhưng không giải thích thêm.",
    [3493452053] = "Cát Chướng Khí",
    [3493492285] = "Mọi đóa hồng đều có gai — và đôi khi, thiên nhiên có thể là nguồn cảm hứng cho vũ khí và thiết kế!",
    [3493567926] = "Khăn Trùm Đầu",
    [3493898864] = "Tiếp cận Công trường Xây dựng Bị Nguyền Rủa",
    [3494705903] = "Đặt lại Thay đổi",
    [3494878774] = "Một chiếc khiên có một viên thạch anh ở giữa. Khung kim loại bao quanh các cạnh làm cho nó bền hơn.",
    [3495479106] = "Chúng ta nên đổ máu của chúng và uống như rượu vang.",
    [3495563734] = "Hạt giống kỳ diệu này tôi đã mua — Nó bén rễ và nảy mầm nhanh chóng! Tôi thấy mình mơ về nó vào ban đêm — ánh sáng mờ ảo, soi sáng khu vườn và tâm hồn tôi. Tôi phải trồng thêm. Cả làng nên biết về vinh quang của nó!\n\n— Hemming",
    [3496351521] = "Sự Xâm Lấn Dưới Lòng Đất ",
    [3496451228] = "Cửa Sổ Tre Nhỏ II",
    [3496461919] = "Quán rượu \"Trận Chiến Xa Xôi\"",
    [3496582704] = "Ngươi đã lấp đầy túi bằng mồi câu cần thiết. Giờ là lúc tìm một con Capybara để thuần hóa!\n\n<b>Một địa điểm lý tưởng để thuần hóa đã được đánh dấu trên bản đồ,</b> nhưng bất kỳ đâu cũng có thể. Nhiệm vụ chỉ cập nhật sang trang tiếp theo khi ngươi đến khu vực được chỉ định, nhưng ngươi có thể hoàn thành nhiệm vụ bằng cách thuần hóa bất kỳ con Capybara nào.",
    [3496675157] = "Ngươi đã đánh thức con quái vật bằng cách thắp sáng tất cả các ngọn lửa độc ác! Đã đến lúc kết thúc mọi chuyện. Tái chiếm Đỉnh Albaneve và <b>nâng cấp Ngọn lửa</b> bằng <b>đầu của con quái vật</b> sẽ cho phép ngươi <b>xây dựng an toàn trong giá lạnh!</b>\n\nTiếp cận đỉnh Núi Hú và thách đấu con quái vật! Sinh vật này mạnh mẽ, nhưng không bất khả chiến bại. Một số đòn tấn công của nó có thể <b>đỡ đòn.</b>\n\nNúi Hú tốt nhất nên đi qua Pháo đài Everfrore.",
    [3496853957] = "Găng Tay Xạ Thủ",
    [3497035457] = "Cỏ dại Rừng Khải Hoàn",
    [3497444137] = "Phiên bản xây dựng: ",
    [3497726820] = "Lưỡi của Sicklescythe đã đóng băng khi bị đánh gục, quá yếu để niệm lời nguyền cuối cùng mắc kẹt trong cổ họng.\n\nThu thập nhiều Đầu Fell Sicklescythe để chế tạo Tượng Đồng.",
    [3498912788] = "Người ta phải cẩn thận khi thu hoạch loại thảo mộc này, nhưng phần thưởng chắc chắn xứng đáng.",
    [3499205087] = "Đèn Lồng Giấy I",
    [3499336005] = "Địa điểm: Ngươi biết ở đâu!!\nThời gian lặn ước tính: Quá lâu\n\n<b>Phát hiện sau khi lặn</b>\n\nThời gian: Trời tối rồi. Không có ánh sáng.\nĐịa điểm: Không thấy Edd.\n\nLần cuối nhìn thấy: Hắn đã đến chốt kiểm soát đầu tiên, những tấm lưới kim loại gần sân thượng um tùm, vượt qua thời gian. Trông có vẻ mệt mỏi, nhưng vững vàng. Tôi đã nghĩ đến việc kéo hắn ra. Lẽ ra tôi nên dừng nhiệm vụ lúc đó. Cạy mở những thanh chắn. Nâng hắn lên và ra khỏi vùng nước nguy hiểm đó.\n\nTôi đã không làm.\n\nMặt trời đã lặn, nghĩa là Edd sẽ gặp khó khăn trong việc tìm các điểm nổi lên theo lịch trình.\nThời gian lặn ước tính đã vượt quá.\n\nTôi nghĩ hắn còn không khí cho... có lẽ thêm ba mươi phút nữa, nếu hắn không hoảng sợ. Nó sẽ không đủ cho đường về.\n\nChúng tôi chạy từ chốt này sang chốt khác, thắp đuốc, gọi tên hắn, cố gắng báo hiệu một điểm an toàn để nổi lên. Nhưng bên dưới, mọi thứ đều tối đen như mực. Vực sâu nuốt chửng cả âm thanh và ánh sáng.\n\nTôi tự hỏi liệu hắn có còn phân biệt được đâu là trên, đâu là dưới không. Tôi tự hỏi liệu hắn có sợ hãi không. Cô đơn. Lạnh lẽo. Tôi tự hỏi liệu hắn có biết mình sẽ chết không... Tôi tự hỏi liệu hắn có còn cố gắng đến cuối cùng không.",
    [3500267069] = "Ta cần nhìn thấy xương trắng của chúng dưới ánh sáng ban ngày! Mang chúng đến cho ta!",
    [3500505639] = "Chuối Nướng Mật Ong",
    [3500705102] = "Khu vực tìm kiếm Tháp Giả kim",
    [3501068686] = "Găng Tay Pháp Sư",
    [3501211103] = "Sát thương Dao găm",
    [3501798810] = "Những Mảnh Ghép Quá Khứ",
    [3501903659] = "Rương Phép thuật",
    [3502554847] = "Bàn thờ Ngọn lửa Cấp 4",
    [3502631786] = "Chọn Vật phẩm",
    [3502927068] = "Bộ Sưu Tập Bí Mật",
    [3503096259] = "Mảnh Thảm Treo Tường",
    [3503686231] = "Bát Đồng Đỏ",
    [3503947378] = "Truyền thuyết Sao băng",
    [3504732704] = "Ngươi đã tìm thấy một ghi chú bên trong một nhà nguyện ở Đỉnh Albaneve. Ghi chú mô tả những diễn biến kỳ lạ trong hầm mộ của nhà nguyện và kế hoạch trốn thoát của một người.\n\nHọ định đi qua <b>lối đi bí mật</b> ra khỏi nhà nguyện, xuống con đường dốc. Người viết đã mang theo <b>cây gậy</b> của mình đề phòng bất kỳ ai, hoặc bất cứ thứ gì, dám đi theo.\n\nĐi theo dấu chân của họ xuống vách đá và lấy lại cây gậy!",
    [3505639430] = "Thảm Treo Tường IV",
    [3506699792] = "Bụi Bạc",
    [3507275113] = "Vàng Dưới Nước",
    [3507461892] = "Khung Cửa Sổ Bằng Sắt Tròn Lớn",
    [3507790749] = "Ngọn lửa bất tử... Tôi đã nghĩ mình sắp khám phá ra điều gì đó ở đây, nhưng tất cả những gì nó làm là biến sinh vật thành tro và xương. Có lẽ là sự vĩnh cửu ở thế giới bên kia, nhưng hoàn toàn không phải là điều tôi dự định.\n\nNằm cạnh hồ lớn có tòa tháp là Yên Ngựa Đá Vàng, ngay phía đông của đó một ngôi mộ khác nên được giấu kín, đất đá vòm lên trên nó.",
    [3508379504] = "Ấm vào mùa đông, thoải mái vào mùa hè. Một nguồn tài nguyên đa năng rất phổ biến và có thể được sử dụng cho nhiều việc.",
    [3508645723] = "Ngươi đã đi được một chặng đường dài. Ta đã đúng khi đặt niềm tin vào ngươi, ân nhân của ta.\n\nTại sao lại bị ràng buộc bởi những xiềng xích trần thế? Sợi chỉ đỏ của định mệnh quấn quanh cổ và cổ tay ngươi, cắt vào da thịt ngươi. Ngươi bị xé toạc bởi những chiếc móc của số phận, neo giữ giữa lồng ngực ngươi.\n\nGiải thoát bản thân. Tìm ta trong biển linh hồn này, và cùng ta trốn thoát. Hãy vươn tới.\n\nChỉ còn một chút nữa thôi. Chúng ta hãy cùng nhau thăng hoa.\n\n<i>Ngươi biết ai đã viết điều này.</i>",
    [3509031228] = "Sắp xếp các vật phẩm từ kho đồ của bạn vào các chồng vật phẩm hiện có trong kho mục tiêu.",
    [3509048732] = "Cảm giác lạnh lẽo của gió đêm quá mê hoặc đến nỗi không thể ngủ được. Bảng màu này tràn đầy năng lượng thôi miên và nhuốm màu điên rồ.\n\nBảng màu này có thể được tạo bằng vật liệu từ Đỉnh Albaneve.",
    [3509229072] = "Một phần của bộ Giáp Kiểm lâm.",
    [3509384197] = "Đang trong quá trình phát triển. Chưa có sẵn trong Closed Beta.",
    [3509961096] = "Nhìn Thấy Màu Đỏ",
    [3510173982] = "Một bộ dao găm bị đầu độc một cách xảo quyệt, uốn lượn như thân rắn của một con rắn lục Diamondback Kindlewastes.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3510985626] = "Kiếm Đồng Thiếc",
    [3511032283] = "Bạn đã đến <location>Thornhold</location>, nhưng thị trấn đã bị Scavenger chiếm đóng. Hãy nhìn xung quanh để tìm con chó đi lạc!",
    [3512014477] = "Khi chế biến một bữa ăn, bạn có 10% cơ hội nhận thêm một bữa ăn.",
    [3512418210] = "Lượn",
    [3512467257] = "Chúng tôi đã có ý định giải mã ngôn ngữ cổ trên chuyến thám hiểm của mình. Những phát hiện của tôi cho đến nay:\n\nBiểu tượng nhỏ trông giống như một con Hươu Tiên đang ngủ có nghĩa là \"lửa\". Hoặc đại loại thế. Tôi khiêm tốn đề xuất rằng những biểu tượng này được xây dựng theo cách vô cùng phản cảm để cố tình chế nhạo các nhà nghiên cứu.\nCó lẽ đúng như những gì dân làng nói, và Người Cổ đại thực sự có ý định giữ bí mật của họ mãi mãi. Tôi tự hỏi họ đang cố gắng che giấu điều gì?\n\n—<lorename>Loraine Crim</lorename>",
    [3512613336] = "Để thưởng cho nỗ lực của ngươi, ta sẽ kể cho ngươi một câu chuyện. Ngày xửa ngày xưa, ngoài khơi Đá Vàng, ta bị đắm tàu trên một tảng đá bạc mà không thấy đất liền đâu cả! Ta đã cầu nguyện với Người Cổ đại, và kìa, một nàng tiên cá hiện ra từ vực sâu, và với một món quà từ đôi môi xinh đẹp của nàng, ta đã mọc vây và bơi về bờ! Không tin ta ư? Ha ha ha! Hãy tự mình đi kiểm chứng!",
    [3512926154] = "Chèn",
    [3512977178] = "Tăng cường Ngọn lửa để nhận Bảo vệ Sương giá trong căn cứ",
    [3513019105] = "Vẫn còn nhiều người sống sót cần giải cứu. Đừng đứng đó!",
    [3513064960] = "Con mèo này đen như bầu trời đêm và những yêu cầu chú ý quyến rũ của nó không bao giờ bị bỏ qua. Nó kêu gừ gừ lớn mỗi khi bạn ở gần!\n\nNhững kẻ Scavenger nuôi con mèo này không chắc nên gọi nó là \"Thuyền trưởng\" hay \"Râu\" không.",
    [3513093921] = "Chúng ta đang <i>rất sâu, bạn của ta.</i> Có lẽ ngươi cảm thấy như ta:\n\nSức mạnh vô biên. Cuộc sống bất tận. Một ánh sáng vĩnh cửu, âm ỉ trong im lặng, được niêm phong trong các ngọn tháp và thánh địa — Nó có ích gì ở đó, ta hỏi ngươi?\n<i>Nó đang khao khát được chia sẻ.</i>\n\nTại sao chúng ta không cùng nhau vươn tới, người giữ lửa đồng hành? Vực sâu đang gọi. Lại gần hơn, và nắm lấy tay ta. Ta sẽ kéo ngươi vào.\n\n<i>— Người bạn mới của ngươi</i>",
    [3513598661] = "Các dải vải gắn vào mặt nạ này lướt nhẹ trong gió, giúp phân biệt hướng và tốc độ gió.",
    [3513620404] = "Chùy có cánh",
    [3513756997] = "Tìm Và Vào Gác Xép Ẩn",
    [3513788244] = "Tìm Trại Xe Ngựa Bỏ Hoang",
    [3514653670] = "Nâng Cao Trang Bị",
    [3515036010] = "Chữa thương",
    [3515393136] = "Khám phá Obelisk Ngọn lửa",
    [3515631679] = "Giày Học Giả Thiên Giới",
    [3515702317] = "Ngươi sẽ không tin vào cuộc ẩu đả mà ngươi đã bỏ lỡ!! Chúng ta đã xem những con chó chiến đấu khi người phụ nữ này — không, cô gái này bước vào đấu trường, ánh sáng vàng phản chiếu trên các tấm giáp của cô ấy, và giơ kiếm lên với nữ chủ nhân!\n<i>\"Ta là Gabrielle Fairburn\"</i> Cô ấy nói. \"<i>Và nếu ta đánh bại ngươi trong một trận đấu tay đôi, ngươi phải rời khỏi thị trấn này và trả lại nó cho người dân!\"</i>\n\nTất nhiên, nữ chủ nhân đã chấp nhận bằng cách phun ra một dòng mật lớn vào cô gái! Tôi đã nghĩ mình sẽ thấy khuôn mặt tái nhợt của cô ấy tan chảy, nhưng đột nhiên, một ánh sáng chói lòa làm tôi mù mắt! Ánh sáng nhảy múa phản chiếu từ cô gái khi cô ấy né tránh và né tránh, và khi sự mù lòa tan biến, cô ấy đã ở phía sau nữ chủ nhân, sẵn sàng tấn công!\n\nGiận dữ, chúng tôi nhảy xuống từ xà nhà — chống lại tất cả chúng tôi, cô ấy không có cơ hội! Sau đó, tôi kéo thi thể cô ấy ra khỏi vũng bùn nơi cô ấy nằm để thả xuống dưới. Bạn lẽ ra phải thấy đầu cô ấy rơi xuống sàn! Đừng bỏ lỡ trận đấu tiếp theo!",
    [3515969992] = "Tan biến như bụi trong gió.",
    [3516331618] = "<craftingstation>Trục quay tay</craftingstation>",
    [3516636691] = "Nhiều lớp kim loại nung chảy trong những con dao găm này khiến chúng trông giống như sừng nhiều tầng của động vật, thuôn nhọn ở các cạnh.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3516781672] = "À, ngươi đã mang về một người mới! Thật thú vị. Ngôi nhà này cuối cùng cũng tràn ngập ánh sáng và sự sống.",
    [3516897346] = "Gỡ ghim",
    [3517398259] = "Một mảnh vải bị rách, mô tả sự khôn ngoan giả kim thuật. Ai đó có thể giải mã nó nếu bạn có nửa còn lại!",
    [3517406878] = "Cung Kẻ Phóng Hỏa",
    [3517621637] = "Đạn ma thuật tạo ra một tia băng duy nhất, gây sát thương cho kẻ địch khi va chạm và làm chậm chúng sau đó.\n\n<b>Phép thuật: Cạn kiệt</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [3517984952] = "Một ghi chú tại Hầm mộ Cổ của <npc>Nhà giả kim</npc> tiết lộ rằng những Scavenger đã giấu những vật dụng đặc biệt khỏi phần còn lại của nhóm. Kho chứa bí mật không nên ở quá xa.",
    [3518154736] = "Bí ngô được yêu thích vì hương vị ngọt ngào, đậm đà trong nấu ăn và lớp vỏ Hollow, chắc chắn cho các đồ thủ công lễ hội.",
    [3518543974] = "Điều tra Công trường Xây dựng Bị Nguyền Rủa",
    [3518934684] = "Đến Lâu Đài!",
    [3519189115] = "Một trong những ngôi nhà xuống cấp ở khu Vườn Hoàng gia của <location><lorename>Pikemead</lorename>'s Reach</location> giấu những vật có giá trị ở tầng trên cùng! Tìm cách vào gác mái và tìm kiếm kho báu ẩn giấu ở đó!",
    [3519583989] = "Embervale có thể được giành lại! Thu thập Tinh hoa và dâng chúng tại Bàn thờ Lửa để củng cố Ngọn lửa! Tinh hoa nằm rải rác khắp thế giới trong <b>Thánh địa Lửa</b> và <b>Đền thờ Lửa</b>.",
    [3519686216] = "Mũi Tên Nổ I",
    [3520079641] = "Bột mì có thể được tạo ra bằng cách nghiền Lúa mì thành bột.",
    [3520443666] = "MP",
    [3520637720] = "Đất là vàng của người nông dân!",
    [3520832878] = "Nhổ cỏ ở Bồn chứa Veilwater",
    [3520955543] = "Trẻ con đồn rằng những người bị cây Chùy này giết sẽ bị đày linh hồn vào quả cầu. Những tàn dư này sẽ vang vọng vô định mãi mãi trong nhà tù hình cầu của chúng, va chạm giữa các bức tường cong và khoảng không.",
    [3521799116] = "Thuần hóa Động vật",
    [3521822880] = "Thanh hành động",
    [3521845491] = "Cánh Lượn",
    [3522112722] = "Những chiếc sừng băng giá làm từ ectoplasm không tan chảy gần lửa lò sưởi. Chúng hẳn là ma thuật!",
    [3522615013] = "Chữ S Mịn",
    [3522644183] = "Ngọn lửa của ngươi cháy mãi, hỡi con của Lửa — nhưng ngay cả ngươi cũng không thể đốt cháy qua những cơn gió đông lạnh giá và những con đường núi phủ tuyết. Đỉnh Howling gọi tên ngươi, chờ đợi để thử thách ngọn lửa của ngươi. Hãy đáp lại lời kêu gọi đó. Giành lại những đỉnh núi bị ô nhiễm. Giành lấy sự tôn trọng của ngươi.",
    [3523219010] = "Quá xa",
    [3524206721] = "Tùy chỉnh",
    [3524643258] = "Bồn chứa Veilwater",
    [3524676275] = "SP",
    [3524904530] = "Để làm tốt nhất công việc của mình, tôi thực sự cần một <craftingstation>Lò nung</craftingstation>, nhưng chế tạo một <craftingstation>Lò nung</craftingstation> yêu cầu một <keyitem>Lò nung</keyitem>! Tôi từng có một cái... Tôi cá là những Scavenger đã lấy nó. Nó có lẽ ở <b>mỏ của chúng, ở phía bắc xa xôi trong Rừng Revelwood</b>.",
    [3525641573] = "Bắt Cá May Mắn",
    [3525676796] = "Giếng Tinh chất",
    [3525844623] = "Đến Trại Scavenger Gần đó",
    [3525888005] = "Vết bỏng Sương độc",
    [3526006505] = "Liên tục",
    [3526067319] = "Găng tay đơn giản làm từ da hữu cơ có nguồn gốc đạo đức.",
    [3526078607] = "Trại Lụi tàn",
    [3526357043] = "Trang phục Thợ rừng Lụi tàn",
    [3526945098] = "Tìm Khối Xây dựng tại Tháp ở Biên giới Fawnsong",
    [3527817573] = "Cửa Hầm Chứa",
    [3528556552] = "Nhảy đến Vấn đề Liên quan",
    [3529184152] = "Đòn Tấn Công Tàn Nhẫn gây thêm %k sát thương thưởng cho kẻ địch đang bị <b>Bị Áp Đảo</b>.\n\nĐể <b>Áp Đảo</b> kẻ địch, hãy lấp đầy thanh choáng của chúng bằng cách tấn công khi chúng đang đỡ đòn, hoặc bằng cách đỡ đòn tấn công của chúng.",
    [3529280872] = "Một con chim hải âu mỏ tròn non, chưa thể bay do hình dáng quá tròn và đôi cánh nhỏ.",
    [3529995960] = "Không thể xây dựng ở đây",
    [3530285671] = "Kỹ năng",
    [3530416090] = "Thu thập Linh hồn",
    [3530988903] = "Tại Giếng Tinh chất, Suối nguồn Tinh chất",
    [3531038021] = "Vải nhuộm màu cam dùng để may quần áo.",
    [3531276449] = "Tháp Lửa Thiêng \"1000 Dặm\"",
    [3531549489] = "Tường Gỗ III",
    [3531681256] = "Chọn một cài đặt sẵn để đặt lại các thay đổi của bạn thành:",
    [3533512847] = "Pháp sư Chiến đấu",
    [3534084895] = "Tôi có thể làm được.",
    [3535210531] = "Hiển thị",
    [3535421532] = "Khi bạn cần nghỉ ngơi, bạn có thể dịch chuyển nhanh về nhà bằng cách mở bản đồ. Điều hướng đến bản đồ bằng <b>%k</b> và chọn nhà của bạn.",
    [3535964910] = "Một cặp quần mục rữa, được giữ lại với nhau bằng lớp vỏ kitin ổn định.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [3536252873] = "Một loại vật liệu chắc chắn được sử dụng trong may đo xa hoa.",
    [3536431952] = "Công cụ này vẽ lên vẻ ngoài hao mòn và rách ở các cạnh và góc ngoài của các công trình xây dựng.",
    [3536549666] = "Tinh thể, lạnh như băng và trơn trượt.",
    [3537756267] = "Khối Gỗ Tre",
    [3538177878] = "Săn bắn tốt.",
    [3538364227] = "Dưới Lửa",
    [3539180162] = "Tôi cảm thấy thoải mái hơn nhiều với chiếc giường trú ẩn mới của mình. Cảm ơn bạn! Bây giờ, hãy cùng nhau trang trí nó cho đẹp và ấm cúng nhé!",
    [3539186981] = "...thì hãy đến Ol' Salt 'N Pepper!\n\nChúng tôi có tất cả — cá đánh bắt tự túc, bia vàng óng như mặt trời hoặc đậm như hổ phách, và nhiều câu chuyện cho những lữ khách mệt mỏi!\n\nGiá của chúng tôi rất hợp lý — và những cô hầu bàn cũng vậy!\n\nTìm chúng tôi tại 44 Clearwater Street, ngay trên đường đi! Chúng tôi sẽ rất vui lòng chào đón bạn!",
    [3540232724] = "Thợ mộc <npc>Cade Hawthorn</npc> giải thích rằng ông đã tự tay xây dựng <location>Diadwyn</location>, một thị trấn nằm trong Rừng Revelwood. Ông ấy có thể đã để lại một số Khối Gỗ Nửa Dầm của mình ở đó.",
    [3540824714] = "Sự ra đời của các vị thần mới - Merphisz",
    [3541016495] = "Chọn Bài hát Tiếp theo",
    [3541490794] = "Đôi khi một con non của Drak sinh ra quá yếu để phá vỡ vỏ trứng. Trong những trường hợp như vậy, các Broodwarden sử dụng lưỡi dao tẩm độc này để cắt mở trứng. Những con non mang một dấu ấn từ ngày đó trở đi — một biểu tượng của sự yếu đuối, đóng dấu chúng suốt đời, mãi mãi dưới những kẻ nở ra mà không cần giúp đỡ.\n\n<b>Khéo léo:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính khéo léo của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3541826397] = "Của Chúng Ta Tự Khắc",
    [3541856369] = "Cần <keyitem>Lò nung</keyitem> để chế tạo",
    [3543363663] = "Mỏ Obsidian",
    [3543596354] = "Khối Đá Granite Đánh Bóng",
    [3543996043] = "Mae",
    [3543999348] = "Chiếc áo choàng nghi lễ này thuộc về một \"Học giả của Thiên đường\" danh dự, được mặc trong các buổi dâng lễ thiêng liêng tại Thánh địa Đêm. Hãy mặc món đồ này với niềm tự hào như chủ nhân trước đã từng.",
    [3544295734] = "Bình Sinh Tồn Chướng Khí",
    [3544401948] = "Búa Đánh Lửa",
    [3545768909] = "Dân làng Hạnh phúc",
    [3546009299] = "Mũ Giáp Giáo Sĩ Sinh Ra Từ Sóng",
    [3546303085] = "Một lượng nhỏ ectoplasm đông lạnh hoặc kết tinh. Nó chứa một chút năng lượng sống.",
    [3546446581] = "Một loại vật liệu kỳ lạ được chiết xuất từ các mảnh ectoplasm. Nó đã được lọc qua vải và than nhưng vẫn có mùi lạ.",
    [3546512994] = "Hannah Reed, một trong những dân làng của bạn, đã đề cập đến việc để lại hầu hết tài sản của mình để chạy trốn về <location>Pháo đài Kelvin</location>. Có lẽ một số vật có giá trị vẫn có thể được thu hồi từ trang trại cũ của cô ấy.\n\nHannah Reed cho phép bạn đi tìm. Bạn có thể giữ lại mọi thứ bạn tìm thấy!",
    [3546558447] = "Những cuộc phiêu lưu mới đang chờ đợi!",
    [3546950846] = "Một khối đá bị nhiễm bào tử Sương độc.",
    [3547020011] = "Không thể dịch chuyển nhanh khi đang rơi.",
    [3547070665] = "Các vật phẩm Twitch Drop mới đã được mở khóa",
    [3547869521] = "Tôi cảm thấy vinh dự. Thật sự.\n\nĐược là người đầu tiên trong làng tôi được chọn làm Học giả là… <i>thay đổi cuộc đời</i>. Ai mà ngờ được một kỳ tích như vậy từ tôi, con trai của một người tiều phu bình thường? Từ một ngôi làng chậm chạp và đổ nát như hồ nước ôi thiu, không kém!\n\nTôi mặc bộ đồng phục Học giả với niềm tự hào. Tôi đang quen dần với những ánh nhìn, những lời thì thầm, những người dân cúi chào. Tuy nhiên, một số khía cạnh của nghề nghiệp của tôi tiếp tục khuấy động tôi.\n\n<i>Hành lang của Thánh địa Đêm đầy rẫy cạm bẫy.</i> Khi các Cổ nhân Thiên đường hướng dẫn tôi cách vô hiệu hóa các cạm bẫy, tôi đã ghi nhớ mọi chi tiết — và khi cố gắng vô hiệu hóa lần đầu tiên, tôi đã kiểm tra kỹ lưỡng từng cái gai và lưỡi dao vung vẩy, tỉ mỉ luồn lách qua cỗ máy.\n\nTôi không thể tưởng tượng được việc vượt qua những hành lang này theo cách khác. Một điều chắc chắn: những cỗ máy này ngăn chặn bất kỳ ai không dũng cảm hoặc ngu ngốc đến mức tiếp tục.",
    [3547870479] = "Hỡi Hỏa Sinh, ta đã cạn lời. Chúng ta đã khám phá gần như mọi nguyên liệu và hỗn hợp trong vùng đất này... Ta sợ rằng chúng ta phải tìm kiếm sự khôn ngoan vượt ra ngoài biên giới của mình. Ngọn lửa cũng nghĩ vậy. Nó không nói với ta, nhưng ta thấy bóng dáng của một tòa tháp rực lửa khi ta nhìn vào lửa của nó... phía sau là núi non, và một hồ nước lạnh như băng.",
    [3548096830] = "Rất Khó",
    [3548309040] = "Thế giới của bạn cần một cái tên.",
    [3548702416] = "Ừ, nhớ lấy cho tôi một ít <craftingstation>Dụng cụ Xây dựng</craftingstation> nhé. Tôi sẽ trả lại cho bạn! Hứa danh dự, được chứ?",
    [3548808032] = "Kẻ Nhìn Trộm Sương Độc",
    [3549199271] = "Mảnh Khăn Liệm Giòn Mỏng",
    [3549201992] = "Tiếp tục hành trình của bạn",
    [3549212470] = "Chúng ta là một vòng xoáy",
    [3549487037] = "Tìm kiếm Kênh đào ở <location>Netherton</location>",
    [3549857933] = "Trò chơi",
    [3550504404] = "Cây Aureolin",
    [3550824552] = "Sát thương SP",
    [3551307330] = "Mũ Pháp Sư Băng Mưa",
    [3551374783] = "Bạn đã tìm thấy Yên Ngựa Đá Vàng. \n\nHãy nhìn quanh và khám phá một công cụ để bơi nhanh hơn, như lời ngư dân gợi ý!",
    [3551728166] = "Không có Mật Ong!",
    [3551729781] = "Ngọc Mắt Bão",
    [3552394181] = "Bạn đã đến Tàn Tích Drak'Dal. Giờ hãy tìm bất kỳ manh mối nào về cách Drak'Dal tạo ra các màu ánh sáng khác nhau.",
    [3552647074] = "Găng Tay Mạ Đồng bảo vệ đôi tay mềm mại của người mặc trong cuộc ẩu đả.",
    [3552859080] = "Phòng Thuốc",
    [3553100996] = "Một thùng chứa nước mưa.",
    [3554017173] = "(Giữ) Mượt mà",
    [3554086460] = "Cổng Lưới Gỗ II",
    [3554816202] = "Cần Nơi Trú Ẩn",
    [3554971656] = "Chúng ta mạnh mẽ hơn khi ở bên nhau.",
    [3556261240] = "Không có",
    [3556682381] = "Yolanda vẫn còn yếu. \n\nCô ấy gần như không thể nhấc cơ thể mình khỏi giường... Cô ấy ngủ, đêm đến thì nóng lạnh thất thường. Tôi bịt tiếng rên đau đớn của cô ấy bằng gối. Chúng ta không thể để chúng biết chúng ta ở đây. \n\nChúng luôn lảng vảng bên ngoài, rình rập, la hét trong đêm. Chúng ta bị bao vây. Tôi không muốn chúng là kết cục của chúng ta... Tôi muốn hòa bình. Tôi sẽ ở bên cạnh em mãi mãi. Tôi hứa. \n\nAnh yêu em, Yolanda. \n\n— Alienor",
    [3558135606] = "Nâng Cấp Ngọn Lửa",
    [3558291078] = "Ghế Bành Thanh Lịch Thấp",
    [3558388262] = "Giường Trú Ẩn",
    [3559186651] = "Chậu Rửa Nước Màn",
    [3559625685] = "Thấy Nhà Tiên Tri",
    [3559632519] = "Cần sửa gì?",
    [3560502248] = "Người Giữ Lửa, ngươi biết ta sưu tầm nhiều thứ... sao không cùng ta tận hưởng niềm vui này? Hãy để mắt tới - Sảnh Đường Hollow Giấu những chiếc bình vàng, những cuốn sách cấm, và những viên pha lê mê hoặc! Ồ, ta đã dọn sạch Lò Xo, nhưng các vùng đất khác vẫn còn giấu những kho báu nhỏ...",
    [3560972203] = "Để thay đổi cài đặt độ khó của máy chủ chuyên dụng, vui lòng sử dụng giao diện máy chủ của nhà cung cấp hoặc cập nhật tệp cấu hình enshrouded_server.json.",
    [3561049531] = "Một số Khối Gỗ Nửa Tường có thể tìm thấy ở <location>Diadwyn</location>. <npc>Thợ Mộc</npc> chắc hẳn sẽ hài lòng.",
    [3561093169] = "Trang Phục Mặc Nhà Ngày Nắng",
    [3561160877] = "Cửa Sổ Tre III",
    [3561196783] = "Nhận một điểm Sức Mạnh cho mỗi hai cấp độ của Ngọn Lửa.",
    [3561347273] = "Áo Giáp Đêm Khô Cốt",
    [3561440129] = "Bạn đã đến Giếng Tinh Hoa chính. \n\nHãy đi sâu vào lòng nó và <b>chặt đầu những con quái vật một mắt</b> bên trong để chống lại Sương độc!",
    [3561526200] = "Khúc Gỗ Tre",
    [3561716687] = "Thợ Săn giải thích rằng cô ấy muốn móc đom đóm vào dây câu để bắt cá. Cô ấy cũng chỉ cho bạn cách chế tạo một cần câu cơ bản. \n\n<b>Hãy chế tạo một cần câu, sau đó quay lại gặp cô ấy.</b>",
    [3562011947] = "Bào tử Sương độc tươi, dùng để chế tạo thuốc chữa lời nguyền Sương độc.\n\nChúng xuất hiện lần đầu ở Springlands vào ban đêm, giữa các nhóm kẻ địch Fell ở trên Sương độc.",
    [3562098021] = "Trụ Sở Thuyền Trưởng Râu",
    [3562411711] = "Trà",
    [3562656399] = "Di chuyển",
    [3562798447] = "Mũ Thợ Tiều Phu",
    [3562850990] = "Giày Đạo Tặc",
    [3563026632] = "Điều tra những con đường xung quanh <location>Thornhold</location>",
    [3563117671] = "Cuộc Đào Thoát Của Người Lặn Ngọc",
    [3563421942] = "%k bắt đầu nhảy múa",
    [3563667169] = "Bọ Bò Nổ",
    [3563969578] = "Biển Chỉ Đường",
    [3564499425] = "Trượng Hắc Ám",
    [3565637992] = "Bật + Tăng Cường",
    [3565695531] = "Lò Rèn Đá Quý",
    [3565894613] = "Vẫn còn một ánh sáng yếu ớt phía sau đôi mắt nó. Hy vọng chúng sẽ không theo dõi mọi hành động của bạn.",
    [3566316912] = "Kệ Gỗ Thô Sơ Thấp",
    [3566632365] = "Bộ Hoàng Gia",
    [3566664366] = "Chiếc khiên thánh này được thánh hiến bởi Ngọn Lửa cho phép bạn <b>Đỡ</b> các đòn tấn công vật lý. Đỡ làm tiêu hao SP.",
    [3566724730] = "Sát thương lên kẻ địch bay ",
    [3567150728] = "Một ống sắt dài, Hollow. Đối với những thợ thủ công có kỹ năng cao, nó mang lại khả năng làm việc với thủy tinh.",
    [3567329726] = "Lời Thú Tội Của Ta",
    [3567391766] = "Giường Và Nơi Trú Ẩn",
    [3567580205] = "Bạn đã mang về một số <keyitem>Lưỡi Cưa Tròn</keyitem>! Hửm? Scavenger làm phiền ngươi à? ...Vậy là <location>Thornhold</location> đã không giữ vững. Thật đáng tiếc. Thôi nào, hãy <b>chế tạo <craftingstation>Máy Cưa Bàn</craftingstation></b> để vinh danh chúng. <b>Đặt nó</b> ở nơi ta có thể nhìn thấy!",
    [3567586107] = "Ta đã nói trước rồi, nhưng chúng ta nên lập một ban nhạc... Ta biết bắt đầu từ đâu!",
    [3567836723] = "Tăng ST Băng",
    [3567837512] = "Thay đổi",
    [3569081262] = "Bạn đã đến tháp của Nhà Giả Kim. Tìm kiếm một con mèo đi lạc bên trong!",
    [3569493243] = "Cây Trang Trí Lớn",
    [3569702403] = "Trang Trại Củ Dền",
    [3570276834] = "Thợ Mộc",
    [3570287842] = "Thức Ăn Tê Tê Cát",
    [3570534454] = "Nhà <npc>Giả Kim</npc> đã đề cập đến vị trí của một <b>Lượn Lờ huyền thoại.</b> Địa điểm đã được đánh dấu trên bản đồ.",
    [3570623063] = "Hết Hoa Chuông",
    [3570751570] = "Bảo vệ Khí Độc",
    [3570859605] = "Đoàn Kết",
    [3571001085] = "Tăng Lực Sống",
    [3571015926] = "Bạn đã trở về với cây Gậy phép và thanh kiếm của ta. Bạn đã kiếm được lòng biết ơn của ta, và quan trọng hơn, sự tôn trọng của ta. Có lẽ ta có thể tin tưởng bạn với một nhiệm vụ khác... nhưng trước tiên, ta cần chắc chắn rằng bạn đã sẵn sàng để chống chọi với Sương độc của Nomad Highlands. Hãy trở lại với ta sau khi bạn đã nâng cấp Ngọn Lửa của mình.",
    [3571449865] = "Rất vui được giúp đỡ!",
    [3571524413] = "Các biện pháp phòng ngừa sau đây chống lại Sương độc phải được thực hiện mọi lúc: \n\n— Không đi vào các thung lũng hoặc gần lưu vực sông. Sương độc có thể bao trùm bạn nhanh chóng.\n— Tránh tiếp xúc. KHÔNG hít nó, và hãy chắc chắn che mắt bạn.\n— Sau khi tiếp xúc, hãy dùng thuốc ngay lập tức với các phương thuốc đã được phê duyệt và cách ly.\n\nLàm ơn, <b>CHỈ dùng thuốc theo toa! Tránh xa Tinh Hoa</b>. Tác dụng lâu dài của nó chưa được biết đến!\n— Balthazar",
    [3571803986] = "Tê Tê Cát",
    [3572085406] = "Những Cột Trụ Cổ Đại",
    [3572677804] = "Khi tạo khiên, tất cả người chơi trong vòng 20 mét sẽ nhận được một khiên.\nChi phí: 50 MP cho mỗi khiên\nThời gian hồi: 60 giây",
    [3572688021] = "Một ghi chú tiết lộ rằng một nhân viên văn phòng bực bội đã ném một chiếc rương đồ thất lạc từ ban công của mình. Hãy xuống đó và đào chiếc rương lên!",
    [3572690653] = "SP Tối Đa",
    [3573104133] = "Tiếp cận Lăng Mộ Hollow Ẩn Giấu",
    [3573141579] = "Khoảng %k",
    [3573254944] = "Chất lỏng đóng băng, bị Sương độc bao phủ, lạnh khi chạm vào.\n\nThường được tìm thấy trong quần xã sinh vật Albaneve Summits của Sương độc.\n\nNó không thể sử dụng được một mình, nhưng có thể được chế biến thành các vật liệu khác nhau trong quá trình chế tạo.",
    [3573281504] = "Màu Sắc",
    [3573527279] = "Ngươi đã tìm thấy thứ gì đó lấp lánh đẹp như ánh nắng trên mặt nước chưa?",
    [3573566301] = "Chữ Viết Obelisk",
    [3573582547] = "Tò Mò Là Khởi Đầu Của Vòng Xoáy",
    [3573716251] = "Quản trị",
    [3573862915] = "Gần đây",
    [3574452718] = "Tăng ST Hỏa.",
    [3575881654] = "Cung Huýt Sáo Drak",
    [3576178031] = "Đồ uống Drak",
    [3576943273] = "Bạn đã tìm thấy một ghi chú, đầy ám ảnh về những Khối Obsidian đen tối, mê hoặc. Cơn thèm khát cũng đã xâm chiếm bạn! \n\nTìm kiếm khu vực phía trên hồ dung nham trong Lò Rèn Obsidia.",
    [3577387425] = "Những chỉ dẫn dẫn đến một căn phòng bí mật. Căn phòng chứa hài cốt người, được chiếu sáng bởi ánh nến.",
    [3577439856] = "Nhà Vệ Sinh Đá Granite",
    [3577613325] = "Nhà Thợ Mỏ",
    [3578118792] = "Quần Thánh Kỵ Sĩ Rực Rỡ",
    [3578609544] = "Tham gia người chơi thất bại",
    [3578718486] = "Người giữ bí mật của Cao Nguyên Albaneve",
    [3578890732] = "Công cụ tuyệt vời để trinh sát — đặc biệt là nhờ độ bám và lớp đệm của chúng.",
    [3579633382] = "Khi tiêu diệt kẻ địch bằng vũ khí cận chiến, tất cả người chơi trong phạm vi <b>15</b> mét tính từ mục tiêu sẽ hồi phục <b>20</b> MP.",
    [3579910304] = "Sẵn Sàng Gậy phép Triệu Hồi",
    [3579961061] = "Cổ Ngữ Huyền Thoại",
    [3579969909] = "8 quả ớt chuông rưỡi mà chúng ta được cấp mỗi hai tuần thì không đủ. Ớt chuông có phải là trái cây không?",
    [3579974009] = "Một chiếc búa nặng đập chính xác, như chim săn mồi.",
    [3580319368] = "Bạn sẽ chết khi HP của bạn về 0.",
    [3580609515] = "Tuyến này chứa một chất cô đặc có thể dùng để thuộc da lông.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Nấm Khổng Lồ Bị Sương Độc Ăn Mòn, ban đầu tìm thấy ở Revelwood.",
    [3581033961] = "Đoạn Dốc Thấp 2m",
    [3581064723] = "Cờ Chiến Tranh",
    [3581166603] = "Tái Chế",
    [3581512125] = "Cây Yucca Tẩm Gia Vị Nướng ",
    [3581539085] = "Dây Leo Từ Vực Thẳm",
    [3581553066] = "Gác Xép Chester Tại Cromville",
    [3582276803] = "Sắc Tố Đá Nghiền",
    [3583440562] = "Sinh vật lông lá này mọc bộ lông dày để chống chọi với khí hậu khắc nghiệt của Đỉnh Albaneve. Nó có thể được cạo lấy lông.",
    [3583571326] = "Gửi Vật Phẩm",
    [3583960354] = "<b>Bàn Thờ Ngọn lửa</b> sẽ <b>đánh dấu vị trí căn cứ của bạn.</b> Tại căn cứ, bạn sẽ có thể <b>chế tạo và xây dựng nơi trú ẩn.</b> Hãy chế tạo <b>Bàn Thờ Ngọn lửa và đặt nó</b> để thiết lập căn cứ của bạn.\n\nBạn không nhất thiết phải đặt Bàn Thờ của mình ở đồng bằng. Bạn có thể chọn bất kỳ khu vực nào phía trên Sương độc để thiết lập Căn cứ của mình.",
    [3584027976] = "Chi Phí Trích Xuất và Chèn",
    [3584339405] = "Khả năng bay luôn là một đặc điểm đáng mơ ước. Nhấn <b>%k</b> khi đang ở trên không để mở Dù Lượn. Sử dụng luồng gió và độ cao của điểm xuất phát, nó có thể được dùng để di chuyển quãng đường xa ngay lập tức.",
    [3584451950] = "Nếu không đánh bại được chúng, hãy gia nhập chúng. <b>Mũi tên đặc biệt</b> này sử dụng sức mạnh của Sương độc và phân tán một đám mây của nó khi va chạm.",
    [3584466788] = "<u+2022> %k + %k",
    [3584814760] = "Cây Chà Là Giống",
    [3585290054] = "Rìu \"Kẻ Săn Rồng\"",
    [3585633507] = "Người Bạn Được Chạm Bởi Ngọn lửa Của Ta",
    [3586293545] = "Ba Lô Nhỏ",
    [3586438475] = "Tất cả sát thương <b>Băng</b> được tăng thêm <b>20%</b>.",
    [3586690706] = "Cờ Lệnh Gắn Tường",
    [3586951504] = "Mệt Mỏi Sương độc",
    [3587302242] = "Điều Tra Trại <npc>Thợ Săn</npc>",
    [3587871843] = "Một phần của Giáp Diều Hâu.",
    [3588432875] = "Giày Khô Cốt Độc Quyền",
    [3588722821] = "Hào Quang Mặt Trời",
    [3589593636] = "Tăng <b>Kháng Độc</b> của bạn thêm <b>10%</b>, giúp giảm lượng sát thương <b>Độc</b> nhận vào.\n\nBạn cũng có <b>25%</b> cơ hội tránh bị nhiễm độc.",
    [3590217298] = "Ma-nơ-canh \"Nhìn Tôi Này\"",
    [3590399311] = "Ngày xửa ngày xưa, Orpheus, một con rồng hắc ám, đã giáng xuống từ núi để tàn phá mùa màng của người dân. Với quyết tâm, những người nông dân đã đặt lưỡi hái của họ xuống để tham gia vào cuộc thập tự chinh chính nghĩa chống lại sinh vật, buộc nó phải rút lui chỉ với một đòn đánh.\nTrong khi tên của họ đã bị lãng quên, lưỡi kiếm huyền thoại của họ đã trở thành nguồn cảm hứng cho nhiều người học việc rèn.",
    [3590717815] = "Mục Tiêu Khó Bắt",
    [3591005493] = "Trang Trại Fanning",
    [3591146256] = "$$ARG0$$ khối. Nguyên liệu có sẵn:",
    [3591728473] = "Làn Nước Tàn Khốc",
    [3591827472] = "Đôi găng tay tối này lý tưởng cho việc đi xin kẹo!",
    [3593169874] = "Hầm Tro Tàn",
    [3593517586] = "Rương Khổng Lồ",
    [3594766434] = "Mưa Than Hồng",
    [3594958421] = "Tìm Kiếm Trong Tiệm Cắt Tóc",
    [3595831449] = "%k đang chờ xử lý",
    [3596176572] = "Emily Fray",
    [3596195119] = "Thùng Hàng",
    [3596401175] = "Bảng màu này trình bày nhiều tông màu vàng, rực rỡ như một quả bóng vàng được đánh bóng hoặc vương miện của một nàng công chúa.\n\nBảng màu này có thể được tạo bằng nguyên liệu từ Bể Nước Lớn.",
    [3597321061] = "Con đường này bị chặn. Cần có <b>Móc Leo</b> để vượt qua.",
    [3598007966] = "Di chuyển đến ô Hành Động hiện tại",
    [3598919956] = "Tìm tất cả các đền thờ và thánh địa Ngọn lửa trong Bể Nước Lớn.",
    [3598951073] = "Mũ Trùm Sừng Núi Tuyết",
    [3599471102] = "Găng Tay Lính Đánh Thuê. Chúng đáng giá vàng.",
    [3599507313] = "Tươi mát như một cơn gió biển mặn mòi.\n\nBảng màu này có thể được tạo bằng nguyên liệu từ Rừng Revel.",
    [3599891711] = "Vậy là bạn đã lên đỉnh Tháp Cổ xưa đó, phải không? Ta biết vài người sẽ sẵn sàng trả bất cứ giá nào để có được một tầm nhìn như vậy. Mặc dù bây giờ... có lẽ có ít hoạt động để quan sát hơn trước.",
    [3601123935] = "Nạp đầy các chồng vật phẩm vào kho đồ",
    [3601284809] = "Thịt Nấm Bạc Hà có thể dùng để nhuộm mọi loại vải màu xanh lá cây. Tên gọi gợi ý hương vị bạc hà tươi mát, nhưng việc tiêu thụ bị nghiêm cấm.",
    [3601662984] = " <npc>Nhà Sưu Tập</npc> đã tiết lộ vị trí của Sảnh Hollow tại Cao Nguyên Du Mục. Hãy xuống đó và đi đến cuối để làm hài lòng <npc>Nhà Sưu Tập</npc>.\n\n<b>Đây sẽ không phải là một nhiệm vụ dễ dàng. Hãy tập hợp sức mạnh và đồng minh của bạn, nếu có, để chuẩn bị sẵn sàng.</b>",
    [3601663951] = "Tăng cường phép thuật Sương độc",
    [3602486297] = "Linh Thể Thượng Hạng",
    [3602969065] = "Một vũ khí hạng nặng, phù hợp để đi xuống bất kỳ vực thẳm nào - cả theo nghĩa đen và nghĩa bóng.\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n",
    [3603280663] = "Thả neo! Cập bến!",
    [3603608120] = "Trại Conway",
    [3603874535] = "Hiển thị Biểu tượng cho Độ hiếm Vật phẩm",
    [3603958938] = "Được sử dụng trong <craftingstation>Lò Luyện</craftingstation> để nấu chảy quặng và tạo hợp kim.",
    [3604128452] = "Chơi Nhạc",
    [3604556077] = "Chỉnh sửa Lưu Thế Giới",
    [3604850236] = "Phòng Thủ",
    [3605333360] = "Một chiếc rương lớn và nặng, cung cấp không gian lưu trữ tuyệt vời cho vô số vật phẩm.",
    [3606398111] = "Bảng màu này có thể được tạo bằng nguyên liệu từ Rừng Revel.",
    [3606472500] = "Lấy độc trị độc!",
    [3606836841] = "Lưỡi Titan",
    [3607151043] = "Màu Sắc Buôn Lậu",
    [3607226589] = "Đặt Mèo Vào Nhà Của Bạn",
    [3607604030] = "Lén lút tiếp cận một con vật và ném mồi nhử trước mặt chúng.",
    [3607742388] = "%k chồng có thể chế tạo",
    [3607776461] = "Vảy Bọ Khổng Lồ",
    [3608049500] = "Giấc Mơ Ngọc Xanh Biển",
    [3610416788] = "Nồi Phế Liệu III",
    [3611410857] = "Quan Tài Hầm Mộ Lớn I",
    [3611887497] = "Thanh kiếm này, sáng chói và rực rỡ, bùng nổ trên chiến trường để giải phóng ánh sáng rực rỡ ban đầu của Ngọn lửa.",
    [3611924678] = "Thay Đổi Bản Vẽ",
    [3612437177] = "Một cuốn sách lịch sử đã được định đoạt, được trình bày trên giá sắt.",
    [3613338004] = "Chuẩn bị Trình Xây Dựng Nhanh",
    [3613380126] = "Lửa Chính Nghĩa",
    [3613769807] = "Mọi người đều có thể tham gia phiên của bạn với tư cách là %k.",
    [3613922144] = "Thu nhỏ",
    [3614158563] = "Nấu Thức Ăn Nóng",
    [3614513264] = "Dalszul",
    [3615074237] = "Người Nông Dân lo lắng cho sự an toàn của bạn trong chiến đấu dưới nước. Đối mặt với kẻ thù dưới nước sẽ vô hiệu hóa khả năng tự vệ. Lựa chọn duy nhất của bạn là né tránh và trốn thoát.\n\n<b>Chế tạo một loại thuốc tăng khả năng di chuyển dưới nước sẽ tăng cơ hội sống sót của bạn.</b>\n\n<b>Bạn có thể tìm thấy công thức tại xưởng của Nhà Giả Kim.</b>",
    [3615379293] = "Bình Đền Drak IV",
    [3615601056] = "Yêu Cầu",
    [3615754791] = "Bạn biết tôi là một <npc>Nhà Giả Kim</npc> — nhưng tôi sinh ra là một học giả, bạn thân mến! Với một vài <keyitem>Dụng Cụ Khoa Học</keyitem>, chúng ta có thể chế tạo một <b>Phòng Thí Nghiệm và tạo ra các loại thuốc chữa bệnh tốt hơn!</b> Một người bạn của tôi, <lorename>Loraine Crim</lorename>, đã nghiên cứu các Cột Đá Cổ xưa ở phía đông và chắc chắn đã sử dụng <keyitem>Dụng Cụ Khoa Học</keyitem> cho công việc của cô ấy! Tôi tin rằng cô ấy sẽ không phiền lòng cho mượn chúng!",
    [3615919760] = "Arisztar",
    [3616079886] = "Pháo Hoa",
    [3616144767] = "Cúp Danh Năng Khổng Lồ Khô Cốt",
    [3616291581] = "Động Vật Chân Bụng",
    [3616609592] = "Sách Đóng Cũ",
    [3616847137] = "Tìm Đầu Người Khổng Lồ",
    [3617050334] = "Tốc Độ Lén Lút",
    [3617423997] = "Đừng quên những gì ta đã nói với ngươi, người bạn được chạm bởi Ngọn lửa. Hãy mang đầu của con quái vật một mắt đến cho ta!",
    [3617468686] = "Giữ Tiến Trình",
    [3617621446] = "Giỏ V",
    [3617770001] = "Mang lại khả năng miễn nhiễm với Hiệu Ứng Độc Tố.",
    [3618241844] = "<craftingstation>Tổ Ong Mật</craftingstation>",
    [3618518668] = "Người Chiêm Tinh Bể Nước Lớn",
    [3618978106] = "Đang sử dụng",
    [3619544876] = "Bạn đang bay ngược dòng.",
    [3619607455] = "Thung lũng Nước Màn",
    [3619720485] = "Ngày 147. Số tù nhân: 53. Lại một cuộc nổi loạn nữa hôm nay. Tù nhân <lorename>Lupa</lorename> kích động chúng. Phun nước bọt vào mặt Quản lý Quân nhu trong bữa trưa. Để lại một vết bỏng trên má hắn. ...Sương độc đang đến gần hơn... không biết lính canh còn muốn ở lại bao lâu nếu sự lạm dụng này tiếp diễn.",
    [3619721102] = "Bạn nghe thấy một tiếng thì thầm yếu ớt trong đầu; đồng nhất về lời nói, nhưng được thốt ra từ một tá giọng nói. Một dàn đồng ca ma quái cầu xin bạn.\n\n<i>\"Xuống những ngục tối này là việc ngu ngốc, bạn không thấy sao? Quay lại khi bạn vẫn còn có thể.\"</i>",
    [3619877644] = "Nhận một vũ khí có Khe Cắm Ngọc và nâng cấp hoàn chỉnh nó để cắm ngọc.",
    [3619937923] = "Sát thương lên Drak",
    [3621784775] = "Tôi đã định xây mái nhà đẹp nhất trong thành phố của chúng ta. Ngói dốc, xà nhà chắc chắn, thậm chí có một chút nhô ra để che nắng thêm. Đã tính toán hết cả rồi.\nNhưng rồi Jora nói mái nhà bằng tốt hơn ở đây. Nói rằng mái dốc chỉ tích tụ cát.\nThế là chúng nằm đây. Kéo chúng đến tận đây mà chẳng để làm gì. Tôi nghĩ tôi sẽ giữ chúng - phòng khi cô ấy đổi ý.",
    [3621880909] = "2H",
    [3622000609] = "Mồi nhử",
    [3622180251] = "Mũ Giáp Hiệp Sĩ",
    [3622919872] = "Bạn có nhớ cuốn <craftingstation>Sổ Tay Cây Cối và Cây Con</craftingstation> mà tôi đã nói với bạn không? Tôi vẫn muốn nó lại, làm ơn!",
    [3622970937] = "Galen Yager",
    [3623011530] = "Thế Giới Mở Ra",
    [3623312474] = "Đi Săn",
    [3623584959] = "Nhà Cấp 1",
    [3624003465] = "Trong hoang dã, mỗi hơi thở bạn hít vào có thể là hơi thở cuối cùng. Chúng ta sẽ khá hơn với <b>áo giáp đệm</b>, và tôi có thể làm một ít với <b>bộ đệm</b> nếu tôi có một <craftingstation>Khung Cửi</craftingstation>. Đây là thông tin của tôi: Những thợ dệt giỏi nhất đến từ <location>Lapis phía Đông</location>, và thị trấn phần lớn đã tránh được chiến tranh. Đừng hỏi câu hỏi. Thông tin rất quan trọng trong nghề nghiệp trước đây của tôi. Tôi không biết vị trí chính xác, nhưng <b>nhà của thợ dệt được trang trí bằng nhiều biểu ngữ.</b>",
    [3624804741] = "Chưa phân loại",
    [3625213920] = "Bộ Fowler",
    [3625593264] = "Tấm Bạt Lò Xo (Nhảy Vừa)",
    [3625790570] = "Tiện ích nước",
    [3625848679] = "Vật phẩm Sản xuất",
    [3626528034] = "Một cây rìu có thể chém xuyên qua kẻ thù bất kể điều gì. Vung nó một cách không sợ hãi khiến nó nhẹ như lông vũ.",
    [3627064334] = "Sát thương lên kẻ địch cận chiến",
    [3627115812] = "Thế là bắt đầu",
    [3627620031] = "Giếng Nước",
    [3627626609] = "Hồi phục SP",
    [3627805045] = "Ngày 2 — Mọi người đâu cả rồi?",
    [3627913964] = "Trở về từ <location>Pháo đài Kelvin</location>",
    [3628371635] = "Mở cửa trong Sảnh Hollow Kindlewastes.",
    [3628559701] = "Sát thương Kiếm dài",
    [3628767663] = "Đặt Cuốn <craftingstation>Sổ Tay Cây Cối và Cây Con</craftingstation>",
    [3629119889] = "Áo Diềm Xếp Nếp",
    [3629123563] = "Tấn công mạnh hơn khi đang bay, được nâng đỡ bởi đôi cánh rồng",
    [3629950229] = "Xoay (nhỏ)",
    [3629956446] = "Một thiết bị cho ăn giữ thức ăn cho dê. Nó có thể được sử dụng cho cả Dê Thông thường và Dê Xù\n\nNó sẽ cho động vật của bạn ăn khi được đổ đầy thức ăn tương ứng.",
    [3630474953] = "Vị trí dao găm",
    [3630532219] = "Bậc thầy ám sát",
    [3630912061] = "Báo thù",
    [3630944652] = "Dọn sạch Cao nguyên Du mục khỏi tất cả rễ Sương độc.",
    [3631451068] = "Những ngôi nhà ở <location>Netherton</location> đang đổ nát. Có lẽ một con mắt tinh tường có thể phát hiện ra <b>khối xây dựng</b> còn sót lại giữa đống đổ nát!",
    [3632074232] = "Sinh vật hung dữ",
    [3633142723] = "Tăng thời gian hiệu lực của buff thức ăn.",
    [3633603736] = "Khối Gỗ Tinh Chế",
    [3633925902] = "Găng Tay Lông Xù",
    [3634187703] = "Vây Râu",
    [3634396248] = "Thung lũng Nước Màn đầy màu sắc — cách bầu trời xanh trong phản chiếu trên mặt nước thật kỳ diệu. Tôi khá chắc rằng những người từng sống ở đây trước đây đã sử dụng những gì họ tìm thấy để nhuộm quần áo của họ. Bạn nên ra ngoài và xem liệu có còn sắc tố nào của họ còn sót lại không.",
    [3634636377] = "Thợ mộc <npc>Cade Hawthorn</npc> có thể chế tạo mọi thứ bằng gỗ.",
    [3636163331] = "Đồ tể",
    [3636205654] = "Cơ hội nhận thêm đạn",
    [3636404207] = "Một loại thuốc ngọt ngào sẽ thêm 5 phút vào hiệu ứng buff \"ngủ ngon\" của bạn.",
    [3637123499] = "Loại bánh cuốn này là một lựa chọn tốt thay thế cho bánh cuốn thịt thường thấy hơn. Nó vẫn tăng HP của bạn, và ngoài ra, thân cây bóng tối rất no và kéo dài Thời gian của bạn trong Sương độc.",
    [3637180942] = "Rìu Bửa Sọ",
    [3637592243] = "Bộ Sơ Khai Giả Kim",
    [3638192149] = "Nước Lấp Lánh",
    [3638746812] = "Bình Đền Drak V",
    [3638935073] = "Cắm Ngọc",
    [3639114748] = "Cờ Lệnh Chiến Tranh Của Gormander II",
    [3639131900] = "Một khối ngói lợp cần thiết để xây dựng mái nhà lợp vảy cá, thường thấy trong xây dựng.\n\nSử dụng <b>Búa Xây Dựng</b> để xây dựng <b>cấu trúc</b> xung quanh Bàn Thờ Ngọn lửa với khối xây dựng này.",
    [3639203631] = "Dùng để xây dựng mái nhà tranh. Một giải pháp cơ bản và đáng tin cậy để bảo vệ bạn khỏi các yếu tố.\n\nSử dụng <b>Búa Xây Dựng</b> để xây dựng <b>cấu trúc</b> xung quanh Bàn Thờ Ngọn lửa với khối xây dựng này.",
    [3639657393] = "Một loại vải nhuộm lộng lẫy, thường được dành để tạo ra những bộ quần áo đẹp nhất.",
    [3639992234] = "Chế tạo tại Xưởng xay",
    [3640103259] = "Gỗ thông nguyên liệu và chưa qua xử lý từ cây lá kim. Chúng lấp đầy không khí bằng mùi hương tươi mát của lá thông và nhựa cây ngọt ngào.",
    [3640312930] = "Muốn nghe một câu chuyện của ngư dân không?",
    [3640503061] = "Áo Khoác Thợ Tiều Phu",
    [3640579270] = "Một hình nộm thân thiện làm từ tuyết.",
    [3640779442] = "Đến được Ngọn Tháp Cổ trong Đỉnh Albaneve",
    [3641311584] = "Món đồ đội đầu của pháp sư này viền khuôn mặt người mặc bằng một đường viền vàng lộng lẫy.",
    [3641643698] = "Giày Kẻ Lang Thang",
    [3641831615] = "Bầy sói ở đây! Tôi bị bao vây! CỨU TÔI! ...Thở chậm thôi, Fenrig... Bạn không còn ở trong hang động đó nữa... bạn kia, bạn đã cứu tôi phải không? Vinh quang thay! Phép màu gì vậy! Bạn đã đưa tôi ra khỏi bóng tối gầm rú, và mang tôi đến đây! Ồ, tôi sẽ cày ruộng của bạn, tưới cây của bạn... Cuối cùng, tôi có thể đặt rìu xuống và cầm liềm!",
    [3643221691] = "Búa Ô Nhiễm Chướng Khí",
    [3643620056] = "Giường Mộc Mạc",
    [3644417488] = "Nhiệm vụ hoàn thành!",
    [3644485484] = "Cây cung gỗ sồi chắc chắn này có tốc độ bắn cao và tiết kiệm năng lượng của bạn, nhưng đánh đổi bằng sát thương.",
    [3645202718] = "Ophidian",
    [3645226698] = "Khối Nửa Gỗ",
    [3645293029] = "Đá Mài",
    [3646218510] = "Bất cứ điều gì bạn muốn?",
    [3646291171] = "Tăng HP tối đa",
    [3646692714] = "Không thể xây dựng trong Sương độc",
    [3646910586] = "Ôi, chiếc nhẫn thất lạc của tôi! Cảm ơn, Hỏa Hồn! Điều này có ý nghĩa rất lớn đối với tôi, vì bạn thấy đấy, chiếc nhẫn này là một cổ vật mạnh mẽ! Đó là một phước lành được truyền lại theo truyền thống trong gia đình Fray. Bây giờ khi tôi nghĩ về nó, tôi sẽ khó có thể tiếp tục truyền thống đó... Bên cạnh đó, khi tôi nhìn vào chiếc nhẫn, tôi thấy <i>đôi mắt mệt mỏi của mẹ tôi...</i> bà ấy chưa bao giờ rời khỏi Hầm Mỏ Vỏ Sò Hồng. Giữ lấy nó! Hãy để nó nhìn ngắm thế giới!",
    [3647026100] = "Làm tốt lắm! Giờ thì không gì cản trở việc đạt được món hải sản chiên hoàn hảo mọi lúc.",
    [3647094833] = "Một vật liệu tuyệt vời được thu thập với số lượng lớn ở Kindlewastes.",
    [3647184549] = "Cây Huệ Tây",
    [3648099066] = "Ikko #3",
    [3648682205] = "Một khu trưng bày chứa các mảnh của một bức phù điêu theo chủ đề Drak. Thu thập tất cả các mảnh để hoàn thành khu trưng bày này và mở khóa các công thức cúp đặc biệt.",
    [3648934346] = "Cánh Lượn Cao Cấp",
    [3649070736] = "Bảo vệ vật lý",
    [3649162556] = "+ Cắt",
    [3649275862] = "Người phụ trách <npc>Người Sưu tầm</npc> đã tiết lộ vị trí của Sảnh Hollow ở Kindlewastes. Hãy xuống đó và đi đến cuối để làm hài lòng <npc>Người Sưu tầm</npc>.\n\n<b>Bạn sẽ cần Cấp độ Vượt Sương độc rất cao để kiên trì. Bạn nên mang theo dù lượn tốt nhất của mình.\nĐây sẽ không phải là một nhiệm vụ dễ dàng. Hãy tập hợp sức mạnh và đồng minh của bạn, nếu có, để chuẩn bị cho phù hợp.</b>",
    [3649444939] = "Nói chuyện",
    [3649549842] = "Hàng Rào Nghĩa Trang",
    [3649841634] = "Một bộ trang phục truyền thống từng được các pháp sư chiến đấu uy tín mặc. Giờ đây, bản chất nghi lễ của chúng chỉ còn là một ký ức mờ nhạt.",
    [3650058058] = "Đầu dê được in trên chiếc khiên kim loại này trông thật ấn tượng, nhìn xuống kẻ thù bằng ánh mắt kiên định.",
    [3650481773] = "Điều chỉnh tầm nhìn và thính giác của kẻ địch đối với người chơi.",
    [3650578467] = "Cánh Tay Phải Của Quái Vật Mắt Một",
    [3651311155] = "Ghi chú của Giám sát viên Drak con non",
    [3651614201] = "Bạn đã đến đền thờ của trợ lý Người Sưu tầm.\n\n<b>Hãy dấn thân vào bên trong và mang theo trợ lý ra ngoài</b> để làm hài lòng Người Sưu tầm.\n",
    [3651907592] = "Một thanh kiếm có cạnh được gia cố, nhọn có thể cắt xuyên qua mọi thứ phát triển trong bụi rậm. Lưỡi kiếm cũng hữu ích cho việc săn bắt wildlife.",
    [3652158312] = "ST Chí mạng của vũ khí cận chiến tăng 20%.",
    [3652308471] = "Harper đã phàn nàn trong một bức thư rằng một trong những bạn cùng ban nhạc cũ của cô ấy, Daniel the Damned, đã phá hỏng buổi biểu diễn cuối cùng của họ bằng cách làm khán giả sợ hãi và gây náo loạn. Qua mô tả của cô ấy, bạn cho rằng Daniel đang mắc một căn bệnh làm thay đổi hành vi của anh ta. Anh ta đã tách khỏi nhóm và đi về phía tây bắc.\n\nĐiều tra địa điểm được đánh dấu trên bản đồ của bạn để tìm nhạc cụ quý hiếm của Daniel và thêm manh mối!",
    [3652738029] = "Làng Bỏ Hoang",
    [3652778785] = "\n<b>Phép Thuật Tích Trữ:</b> Giữ nút để tích trữ <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép với <b>gậy phép.</b>",
    [3653680497] = "Vukah Tụ Tập",
    [3653694917] = "Thảm Thực Vật Nhỏ",
    [3654061080] = "Cắt",
    [3654244679] = "Một bộ đệm ấm áp và cách nhiệt tốt hơn. Khi dùng để chế tạo giáp, nó sẽ bảo vệ bạn khỏi cái lạnh thấu xương.",
    [3654779415] = "Xem Chi Tiết",
    [3655304110] = "Xây Dựng",
    [3655386310] = "Một công cụ ma thuật có khả năng <b>thêm và bớt các loại cây cối mọc um tùm</b> trên tường căn cứ của bạn. \n\nNó chỉ có thể được sử dụng <b>trong phạm vi Lò Ngọn lửa</b> và yêu cầu <b>vật liệu cây cối mọc um tùm</b>.",
    [3655678774] = "Một vũ khí sáng và mạnh mẽ tỏa ra sức mạnh.",
    [3655730521] = "Tìm Kiếm Dấu Vết Tại Mỏ Đá",
    [3655852663] = "Ba Lô Đầy",
    [3656950153] = "Bảng Màu Của Kẻ Buôn Lậu Giấu Kín",
    [3657195538] = "Một loại vật liệu lợp mái được chế tác từ đá vôi vỏ sò. Chúng mang lại vẻ sang trọng cho bất kỳ không gian nào.",
    [3657729675] = "Đón Chào Năm Mới",
    [3658899268] = "Một cây đũa phép bị Sương độc làm ô nhiễm, tỏa ra bóng tối. Bạn cảm thấy rằng việc sử dụng nó sẽ mở rộng một vực thẳm ẩn giấu bên dưới Embervale, từ từ phát triển trong bóng tối, nuốt chửng mọi thứ xung quanh... nhưng có lẽ sử dụng nó một hoặc hai lần sẽ không hại gì?\n\n<b>Tẩm Sương Độc</b>: \nVũ khí này đã bị Sương độc bao phủ và gây ra ST Sương độc nặng. Nó chỉ có thể được tìm thấy bên trong Hang Sương Độc.\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương bổ sung lên đến tỷ lệ <i>quá tải</i>.\n\n<b>Nhân đôi Tinh linh:</b>\nPhép thuật độc đáo của cây đũa phép cho nó 30% cơ hội tự động tạo ra một viên đạn bổ sung.\n\n<b>Đa phát bắn:</b> \nBắn nhiều viên đạn nhưng với sát thương giảm.\n\n",
    [3659466532] = "Tối Thiểu",
    [3659778886] = "MP",
    [3659898717] = "Săn Tóc: Xanh Ngọc Bình Yên",
    [3660307011] = "<i>Không Phải Tin Đồn, Mà Là Sự Thật:\nKhông chỉ biên giới của chúng ta không an toàn — thị trấn của chúng ta cũng đang gặp rắc rối! Người cung cấp tin tức của tôi từ <location>Pháo Đài Kelvin</location> báo cáo có tiếng động từ bên trong núi! Hang động của họ rung chuyển vào ban đêm như thể có thứ gì đó sắp phá vỡ! \nLiệu Gormander có cử quân tiếp viện? Bắt đầu một cuộc điều tra? Có lẽ thông qua một dự luật cơ sở hạ tầng? Rất có thể là không, nhưng người ta có thể mơ ước. Nếu tôi là một người thích cá cược, tôi sẽ nói rằng ông ta sẽ đợi cho đến khi các mối quan tâm tự giải quyết, dù tốt hay xấu!\n— Ramone Jones, biên tập viên của The Pike Weekly.</i>\n\nĐó là bản nháp duy nhất được phê duyệt. Tôi không thể đưa thông tin của bạn về vụ biển thủ... nếu nó quá gây tranh cãi, họ sẽ không <i>chính thức</i> cho phép tôi in nó. Tuy nhiên, tôi sẽ tìm cách. Hãy cẩn thận, Jakes!",
    [3661028093] = "Cọc Hàng Rào Nghĩa Trang",
    [3661049406] = "Sát thương đũa phép lặp lại được tăng thêm <b>20%</b>. ",
    [3661174254] = "Quần Cung Thủ",
    [3661229402] = "Chạm Đỉnh",
    [3662480000] = "Một Căn Phòng Mới Để Lưu Trữ",
    [3662781233] = "+ Phép Thuật",
    [3662907500] = "Khi nấu chín, Trái Cây Yucca trở nên rất ngọt. Làm chảy nước miếng và phục hồi SP.",
    [3662939060] = "Bắn mũi tên tuyệt hảo này từ cung và xem mục tiêu của bạn co rúm lại vì sợ hãi.",
    [3663095217] = "Loại Trò Chuyện Thoại",
    [3663383197] = "Bộ Trang Phục Học Giả Mỹ Thuật Của Thanh Niên Ngọn lửa",
    [3664482818] = "Tiêu Diệt Rễ Sương độc",
    [3664768025] = "Những cánh buồm cối xay gió này nhỏ bé, nhưng chúng vẫn tạo ra đủ lực để cung cấp năng lượng cho một cối xay.\n\n<b>Phải đặt gần cối xay.</b>",
    [3664929736] = "Khối Mái Ngói Đá Granite",
    [3665431256] = "Mũ Trùm Kẻ Mang Dịch Bệnh",
    [3666101412] = "Bạn đã bơi trong vùng nước của Hồ Veilwater chưa? Thật êm dịu… nếu chỉ không có kẻ thù ở khắp mọi nơi. Tôi rất muốn nhuộm tóc bạn một màu giống như làn nước trong vắt đó, nhưng nước thì không đủ — đứa trẻ nào cũng biết nó trong suốt! Bạn có thể mang cho tôi một loại bột màu xứng đáng với nó không?",
    [3666221236] = "Thức Ăn",
    [3666315624] = "Còn gì nữa?",
    [3667172664] = "Chậu Cây Trống I",
    [3667542478] = "Một chiếc mũ tối màu giúp bạn hòa mình vào cảnh quan rừng cây dễ dàng hơn. Một mảnh vải đỏ che miệng, khiến bạn cảm thấy như một tên cướp.",
    [3667650062] = "Rương Lưu Trữ",
    [3668325596] = "<keyitem>Đe</keyitem>",
    [3668584302] = "Dao Găm",
    [3668593506] = "Chọn vẻ ngoài, quay lại vì trải nghiệm.",
    [3669840925] = "Thợ Thủ Công",
    [3670342385] = "Thưởng ST Tầm xa.",
    [3671035448] = "Mannequin B",
    [3671218441] = "Một Sàng Lọc Khai Khoáng",
    [3671276013] = "Hỡi Hậu Duệ Lửa, ta có một ý tưởng quà tặng, nhưng ta cần sự giúp đỡ của con!",
    [3672722704] = "Viên đạn ma thuật liên tục truyền các đòn sét mạnh mẽ. Nó làm kẻ địch choáng váng bằng cách nhảy giữa chúng và gây <b>sát thương SP.</b>\n\nSát thương SP lấp đầy <b>thanh choáng</b> của kẻ địch.\n\n<b>Phép Thuật Tích Trữ:</b> Giữ nút để tích trữ <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm phép với <b>gậy phép.</b>",
    [3672853937] = "Điều Tồi Tệ Nhất Đã Xảy Ra!",
    [3673649835] = "Tìm Kiếm <craftingstation>Dụng Cụ Thợ Mộc</craftingstation>",
    [3673781397] = "Tỷ lệ sát thương của mọi kẻ địch.",
    [3674679466] = "Đòn Chí Mạng bằng vũ khí Tầm xa hồi phục <b>5</b> SP.",
    [3675127693] = "Một <craftingstation>Trạm Thuộc Da</craftingstation>",
    [3675250888] = "Trang Trại Dê Đá Nhỏ",
    [3675531029] = "Cấp Độ Ngọn lửa",
    [3676295538] = "Tìm Một Chú Lùn Vườn ",
    [3676690308] = "Một con drone vô tri, Ám khí được làm từ mai của sinh vật. Sau khi triển khai, con bò sẽ tìm kẻ địch gần nhất và phát nổ.",
    [3676843054] = "Tiệm Cận",
    [3676875917] = "Đã làm người canh đèn biển bao đời nay. Sinh ra và lớn lên trên những bờ biển này, và tự hào về điều đó.\n\nBiển cả biết tôi rõ hơn cả mẹ tôi. Qua bao năm tháng, những gợn sóng trên mặt nước đã in dấu lên khuôn mặt tôi, khắc những đường nét khao khát lên làn da khi tôi già đi. Diện mạo và câu chuyện của tôi không gì khác hơn là một tấm bản đồ của vùng biển xanh rộng lớn.\n<i>Nhưng hôm nay, tôi nghĩ mình đã nhìn thấy thứ gì đó... mới.</i>\n\nĐó là một buổi tối tươi sáng, trong trẻo như mọi khi. Mặt biển lặng sóng dưới ánh mặt trời lặn, nhưng tôi biết không nên tin tưởng chúng. Những đám mây đen tụ lại trên đường chân trời, báo trước một cơn bão... và bên dưới chúng, chỉ trong một khoảnh khắc ở phía xa, tôi thấy thứ gì đó trồi lên từ dưới.\nMột bóng hình đơn độc trên nền cảnh vật thay đổi, vươn lên như kính tiềm vọng, quan sát bờ biển. Quan sát <i>chúng tôi.</i>\nRồi nó lặn xuống, biến mất khỏi tầm nhìn của ống nhòm của tôi.\n\nCó thể đó là gỗ trôi. Vâng, chắc chắn là vậy...",
    [3678080799] = "Mùa Xuân Pastel",
    [3678934821] = "Đá Quý",
    [3679414929] = "Kiếm Tết Nguyên Đán",
    [3679621292] = "Thế giới đầy những điều kỳ diệu!",
    [3679844395] = "Thức ăn Hophare bổ dưỡng cho động vật được thuần hóa trên trang trại của bạn.\n\nPhải đặt vào máng ăn phù hợp.",
    [3679988613] = "Thợ Rèn",
    [3680028579] = "Những sắc cam ấm áp này gợi lên mùi hương của hoa huệ, sự ấm áp của lửa lò sưởi và hình ảnh chia sẻ một buổi bình minh với người bạn yêu.\n\nBảng màu này có thể được tạo ra từ vật liệu của Hồ Veilwater.",
    [3680608823] = "Thợ săn nhớ nơi một Hầm Cổ khác đã được xây dựng, và tin rằng nó chứa một người sống sót khác đang ngủ. Thu hồi người sống sót này sẽ hỗ trợ sản xuất lương thực và canh tác.",
    [3680636129] = "Khối Amethyst",
    [3681336069] = "Chiến Thuật Đại Não",
    [3682121205] = "Cột",
    [3682324936] = "Nếu bạn có thể giương cung, bạn có thể chơi đàn luýt!",
    [3682615921] = "Sở hữu máy chủ của riêng bạn:",
    [3683404934] = "Phát Quang",
    [3683859768] = "Một chiếc rìu có nguồn gốc ghê rợn. Nó đã chứng kiến nhiều cái đầu rơi xuống và vẫn hoàn thành nhiệm vụ của mình cho đến ngày nay.",
    [3684780186] = "Đá Quý Đã Chọn",
    [3684793793] = "Ít nhất một vai trò bị chặn.",
    [3685034113] = "Tìm Kiếm Bộ Sưu Tập Cúp Của Chúa Tể",
    [3685260795] = "Mọi người đều lo lắng về Sương độc, nhưng những con kền kền khủng khiếp đó mới là mối nguy hiểm thực sự... Chúng ta nên tự bảo vệ mình khỏi chúng, nhưng tôi nửa là lính, nửa là hèn nhát! Nếu chúng ta có vũ khí của cha tôi, chúng ta có thể tự vệ. Nhưng ông ấy đã mang nó theo xuống địa ngục... Tôi có thể chỉ cho bạn thấy nơi nào!",
    [3685561780] = "Găng Tay Kẻ Mang Dịch Bệnh",
    [3685714202] = "Doanh Trại Lính",
    [3686890483] = "Đĩa Đất Sét",
    [3686895684] = "Vâng?",
    [3687212215] = "Một phần của Bộ Giáp Xạ Thủ.",
    [3687303024] = "Ban Nhạc Đã Lịch Sử",
    [3688279010] = "Tìm Mảnh Thảm Treo Tường Đầu Tiên",
    [3688902057] = "Nâng Cấp",
    [3689347565] = "Dọn sạch mọi rễ Sương độc khỏi Hồ Veilwater.",
    [3689882323] = "Quần được đệm để giảm thiểu sát thương khi rơi trong các buổi tập chiến đấu.",
    [3690291561] = "Tìm Kiếm",
    [3690710334] = "Cấp Độ Tiếp Theo",
    [3690987108] = "Ghi Chú Cuối Cùng Của Thuyền Trưởng",
    [3691320113] = "Rương của <npc>Thợ Rèn</npc>",
    [3691531000] = "Hang Sói",
    [3691735181] = "Găng Tay Đêm Khô Cốt",
    [3691784007] = "Nhận Một Vật Kỷ Niệm Từ Kẻ Thù Mới Của Bạn",
    [3692031391] = "Nhạc sĩ Valory muốn bạn tìm kiếm tất cả hóa thạch ở Embervale. Có năm hóa thạch ở Springlands. Mỗi hóa thạch có thể được tìm thấy nhiều lần ở những nơi khác nhau. Nhạc sĩ khuyên nên tìm kiếm trong các mỏ, khu vực khai quật và các mỏ quặng để tìm tất cả hóa thạch.",
    [3692334646] = "Vảy Drak tươi và lấp lánh, lung linh và thay đổi trong ánh vàng của mặt trời.",
    [3692763475] = "Nạp lại bằng Vật liệu Xây dựng Đá.",
    [3692838819] = "Một vật phẩm trang trí có thể đặt trong bất kỳ tòa nhà nào.\nCung cấp <b>sự thoải mái</b>, tăng thời gian hiệu lực của buff nghỉ ngơi.",
    [3692959657] = "Một thiết bị cho ăn giữ thức ăn cho chim.\n\nNó sẽ cho động vật của bạn ăn khi được đổ đầy thức ăn tương ứng.",
    [3694234913] = "Một hỗn hợp các vật liệu đặc trưng cho từng quần xã sinh vật, chủ yếu là đá và đất.",
    [3694382217] = "Chế độ Phản xạ",
    [3694514716] = "Những màu sắc rực rỡ này — xanh lơ đậm, hồng tươi và đen tuyền — tự nó đã tạo nên một tuyên bố. Với bảng màu này, bạn sẽ không bị lu mờ.\n\nBảng màu này có thể được tạo bằng vật liệu từ Bồn tắm Nước Màn.",
    [3695165334] = "Khoảnh khắc trước khi lời nguyền cuối cùng được nói ra bị đóng băng mãi mãi trong chiếc cúp vàng này. May mắn thay, sức mạnh phi thường của ngọn lửa luôn hiện hữu.\n\nThu thập nhiều Đầu Lưỡi Hái Bệnh Tật Fell để chế tạo Cúp Vàng.",
    [3695253364] = "Mũ Hề của Anton Godwin",
    [3695375076] = "Nhẫn Sinh Lực Lớn",
    [3695649757] = "Tốt lắm vì đã đưa cô bé Mei trở về! Ta biết ngươi có thể làm được! Đúng vậy, ta có một chút mục đích riêng... Ta khao khát văn hóa! Dù sao thì ta cũng là một người bảo trợ nghệ thuật! Ta ước gì mình vẫn còn giữ chiếc đèn ta mua từ cô bé. Ta đã quên nó ở <location>Morwenna</location> trong quá trình tái thiết.",
    [3695884516] = "Một phiên bản vĩnh cửu của Băng Giá I. Phép thuật gây sát thương lên kẻ địch khi va chạm và làm chậm chúng sau đó.\n\n<b>Phép Thuật Vĩnh Cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [3696380102] = "Thợ Mỏ Scavenger",
    [3697526057] = "Rắn Ăn Thịt",
    [3698099692] = "Vì Giá Hợp Lý",
    [3698478338] = "Một <craftingstation>Nồi Hắc Ám</craftingstation> sẽ rất hữu ích — làm ơn, Hỏa Sinh, hãy tìm một cái cho ta.",
    [3698888758] = "Trang phục",
    [3698999624] = "Để Ngủ, Ăn và Nghỉ Ngơi",
    [3699084104] = "Những chiếc lông vũ màu thạch anh tím rực rỡ tô điểm cho chiếc mũ bảo hiểm này, cho thấy người đội trước đó có thể là một chỉ huy hoàng gia.",
    [3699964412] = "Thỏi Đồng Thiếc",
    [3700078172] = "Bạn đã tìm thấy một phần trang phục ngoại trang Học Giả Thiên Giới trong một Thánh Địa Đêm Cao Nguyên Du Mục. \n\nCó lẽ những phần khác cũng nằm rải rác ở các Thánh Địa Đêm khác trong khu vực. \n\nTìm kiếm các Thánh Địa Đêm ở Cao Nguyên Du Mục để lấy tất cả các bộ phận của trang phục Học Giả! ",
    [3700158988] = "Bộ Giao Ước Ngọn lửa",
    [3700542353] = "Bùn Sâu",
    [3700826718] = "Thịt tăng thêm <b>15%</b> HP. ",
    [3701044519] = "Buồn cười khi ngươi hỏi! Dì <lorename>Morwenna</lorename> của ta quen biết một <npc>Thợ Săn</npc> đáng sợ, to lớn như núi! \"<lorename>Lupa</lorename>\". Bà ta vật lộn với Vukah, thuần hóa rồng... và uống rượu. Thực ra — bà ta đã làm nghẹt thở dì kia của ta, <lorename>Dwyn Già</lorename>, trong cơn say! HAHA! ...họ đã đưa bà ta đến <location>Raven's Keep</location> vì chuyện đó. Theo ta biết, bà ta không bao giờ nhìn thấy ánh sáng ban ngày nữa.",
    [3701067847] = "Thú Bông Lạc Lõng",
    [3701413547] = "Cánh Lượn",
    [3702003501] = "Rễ cây đóng băng quấn quanh lõi băng của cây đũa phép này xoắn ốc như tiếng gió rít của cơn bão tuyết.\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sức sát thương của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.\n\n<b>Đa Sát Thương:</b> \nBắn nhiều loạt đạn nhưng với sát thương giảm.\n",
    [3702293351] = "Đường Ván Tre II",
    [3702597829] = "Đôi bốt da tối màu buộc dây với các phần vải chần bông. Chúng cao đến đầu gối người mang, bảo vệ ống chân khỏi tuyết dày.",
    [3702611004] = "Ghi Chép Thực Địa — Ngày 19\n\nTin hay không tùy bạn, nước từng rất dồi dào ở Vùng Đất Cháy. Vậy mà khi tôi hỏi một vài người dân địa phương chuyện gì đã xảy ra với những vùng đất này, tôi không nhận được câu trả lời nhất quán nào từ bất kỳ ai. Từ một vị thần mặt trời bí ẩn hút nước lên trời cho đến mặt đất nứt ra và toàn bộ lòng hồ rút cạn như một cái bát cá... không có điều gì có vẻ hợp lý. Sự thật là — một ngày nọ, Đập Eldermere ngừng cấp nước, ngay cả khi các cửa xả đã được mở hoàn toàn.\n\nTôi đã nghe những lời thì thầm từ những góc xa của Embervale về một dịch bệnh đang trỗi dậy từ lòng đất, một kẻ hủy diệt thế giới. Liệu hai thảm họa môi trường này có liên quan đến nhau không?\n\n—<lorename>Loraine Crim</lorename>",
    [3702812758] = "Một Lõi Thối Rữa",
    [3703154564] = "Ngươi đang bị thiêu đốt!",
    [3703375047] = "Với đôi bốt này, \"Các Học Giả Thiên Giới\" đã có thể vượt qua các hành lang bị chặn của Thánh Địa Đêm. Đế giày của họ, thường bị mòn mỏng, đã được thay thế vô số lần. Hy vọng rằng, chúng sẽ đưa bạn đi xa trên hành trình của riêng bạn.",
    [3703453414] = "Làm Dịu Kẻ Thù",
    [3703566870] = "Du Khách Mệt Mỏi — <location>Pháo Đài Kelvin</location> là thành trì hòa bình cuối cùng và là nơi dành cho tất cả những người sống sót. The Sương độc là kẻ thù của mọi người ở Embervale, và các Cuộc Chiến Elixir đã tàn phá các vùng đất xa gần. Vui lòng đến gặp Jakes ở chợ để nhận một phần bữa ăn thịnh soạn cũng như một chiếc giường ấm áp, khô ráo để bạn nghỉ ngơi.",
    [3703714711] = "Mhh, miệng ta có vị bùn và đồng... nhưng ta không còn ở trung tâm của bộ tộc Vukah mà ta nghiên cứu nữa! Tuy nhiên, ta không thể nghỉ ngơi cho đến khi hiểu rõ các nghi lễ của họ... Ta nợ dân tộc ta! Ngươi đã làm rất nhiều, nhưng nếu ngươi muốn giúp ta thêm, hãy tìm hố hiến tế của họ gần <location>Pháo Đài Kelvin</location>! Ta đã nhìn thấy nó từ xa... Người ta bị đẩy xuống vực sâu. Tiếng hét ám ảnh ta... Ta cần sự kết thúc!",
    [3703986816] = "Trợ lý Nhạc Công, Chester Loft, muốn bạn tìm một cây đàn handpan huyền thoại.\n\nAnh ta đã nghe Drak chơi những giai điệu bằng một nhạc cụ như vậy trước đây. \n<b>Vị trí ngôi đền của họ đã được đánh dấu trên bản đồ của bạn.</b>",
    [3704042356] = "Một <style=mutedItalic>Giếng Elixir</style> khác được xây dựng trên lưng của những người lao động, làm việc không mệt mỏi để đào một đường hầm vào lòng đất. Kế hoạch cho công trình này là... phi thường.\n\nHố sâu phun ra khói với mỗi nhát cuốc. Lớp sương mỏng gây đau đầu và kích ứng mắt... Tất cả vì \"Elixir\". Tôi hy vọng không khí hôi thối này sẽ không lan sang <location>Lone Thistle</location>.\n— Balthazar",
    [3704253161] = "Tấn công kẻ địch đang phòng thủ gây thêm %k sát thương SP và đẩy lùi mạnh hơn.",
    [3704522172] = "Ta tin tưởng ở ngươi!",
    [3705365378] = "Lén Lút",
    [3705372246] = "Rồng trỗi dậy",
    [3705580007] = "Hải Sâm Thạch Anh Tím",
    [3705630732] = "Chế tạo tại Trạm Chế Tạo",
    [3706932279] = "Tên: Thịt Chết",
    [3707157432] = "Cát Chướng Khí",
    [3707300730] = "Bạn đã tìm thấy một ghi chú ở Nơi Trú Ẩn của Du Mục đề cập đến bọn cướp và những kẻ buôn lậu thường xuyên đột kích tiền đồn. \n\nTrại của chúng ở gần đây. <b>Đến trại buôn lậu</b> và tìm thêm manh mối hoặc bảng màu ở đó!",
    [3707940083] = "Chị Gái Của Em Đâu Rồi?",
    [3708009033] = "Tôi đang ghi lại điều này với trái tim đập thình thịch! Nếu ai đó tìm thấy điều này — hãy đọc câu chuyện của tôi cho con cháu của bạn trước lò sưởi, và nâng ly chúc HP và lòng dũng cảm của tôi!\n\nTôi chèo thuyền qua những vách đá của một thung lũng đá, khẽ ngân nga một giai điệu khi tôi thấy những bong bóng sủi lên từ dưới mặt nước bùn! Ban đầu, tôi nghĩ đó có thể là dấu hiệu của kho báu bị chìm — có lẽ một trong những chiếc thuyền bị lật gần tôi đã chở những kho báu vô giá? Thật không may, tôi đã nhanh chóng nhận ra mình đã sai!\n\nMột con Snapjaw đáng sợ đột nhiên lao về phía mặt tôi, không nghi ngờ gì nữa khi bị giọng hát du dương của tôi triệu hồi! Thân hình nó giống như một con rồng thực thụ, thậm chí còn giống một con rồng, với tấm lưng lấp lánh tối như màn đêm! Nó cắm răng vào thuyền của tôi, vì vậy tôi đã đâm dao vào cổ nó!\n\nTôi trốn thoát mà không hề hấn gì, nhưng con dao của tôi đã mất... và nếu không có đôi bốt cũ của mình, tôi sẽ bị mắc kẹt trong bùn nếu cố gắng lấy lại nó! Ha, thật là một tình huống khó xử. Theo đúng nghĩa đen!",
    [3708091757] = "Chiếc khiên tự chế này cho phép bạn <b>Đỡ</b> các đòn tấn công vật lý. Đỡ làm tiêu hao SP.",
    [3708919851] = "Một <b>mũi tên đặc biệt</b> tẩm độc, làm cho nó càng chết chóc hơn.\n\n<b>Mũi tên tẩm độc</b>: Wildlife và Quái thú hoang dã bị trúng mũi tên này sẽ bị nhiễm độc và nhận 8 sát thương mỗi giây trong 5 giây.",
    [3709360057] = "Lan Can Gỗ VI",
    [3711038213] = "Một chiếc áo khoác da bình thường. Một loại nấm đã phát triển trên bề mặt vân phẳng.\n\nCung cấp sự bảo vệ mở rộng chống lại The Sương độc.",
    [3711083516] = "Một vũ khí từng thanh lịch, phát ra âm thanh như tiếng hát khi chém xuyên qua Fell.",
    [3711698580] = "Mở Khóa",
    [3711914555] = "Mở thông báo",
    [3711964703] = "Chỉ có thể sử dụng khi đang rơi tự do",
    [3712007940] = "Thợ <npc>Mộc</npc> cần một máy cưa bàn để mở rộng khả năng của mình. Một <craftingstation>Máy Cưa Bàn</craftingstation> cần <keyitem>Lưỡi Cưa Tròn</keyitem> để chế tạo, và ông ta nghĩ rằng chúng có thể được tìm thấy ở một thị trấn tên là <b><location>Thornhold</location></b>. ",
    [3712601150] = "Do người chơi tổ chức",
    [3712685099] = "Ngươi đang đói.",
    [3712806808] = "Phát hiện xung đột phím. Chúng tôi đặc biệt khuyến nghị giải quyết chúng trước khi sử dụng sơ đồ điều khiển tùy chỉnh.",
    [3713176087] = "Đôi khi, chết còn tốt hơn.",
    [3713637442] = "Kẻ Đốt Phá",
    [3713855500] = "Vải Màu Xanh Lá Cây",
    [3714162672] = "Hẻm Núi Vukah",
    [3716030259] = "Cầu Thang Tre",
    [3716048352] = "Một công cụ cho phép bạn thêm và bớt nước trong căn cứ của mình. Nó cũng có thể được sử dụng để tưới tiêu và áp dụng hiệu ứng Giảm Giáp Ướt hoặc Ngấm Nước cho kẻ địch. Đổ đầy nước từ giếng hoặc hồ trước khi bắt đầu hoạt động.\n\n<b>Ướt</b> \nGiảm SP và Hồi phục SP xuống <b>30%</b> trong <b>15</b> phút. Nhiệt độ làm giảm thời lượng còn lại.\n\n<b>Ngấm Nước</b> \nGiảm SP và Hồi phục SP xuống <b>30%</b> trong <b>30</b> giây. Cũng giảm <b>Kháng Băng và Sốc</b> xuống <b>30%</b> nhưng tăng <b>Kháng Lửa</b> lên <b>30%</b>.\n<b>Ngấm Nước</b> có thể được áp dụng cho kẻ địch.\nThời lượng <b>Ngấm Nước</b> không thể giảm bằng nhiệt độ, và chuyển thành hiệu ứng <b>Ướt</b> khi kết thúc.",
    [3716135035] = "Găng Tay Thiện Xạ",
    [3716425867] = "Vảy Drak",
    [3716547586] = "Thưởng Thuộc Tính",
    [3716750011] = "Cửa đã mở",
    [3717007201] = "Hãy bắt đầu buổi biểu diễn!",
    [3718070248] = "Rừng Ngọc Lục Bảo",
    [3718187840] = "%k <style=mutedItalic>(Không hoạt động)</style>",
    [3718300939] = "Trò Nghịch Ngợm ở Vũng Lặn",
    [3719231698] = "Để <npc>Thợ Rèn</npc> có thể nâng cấp vũ khí, một số vũ khí cũ cần được tháo dỡ từ <b>Kho đồ</b>. <b>Tháo dỡ</b> một vũ khí có độ hiếm cao hơn để nhận <b>Nguyên Tố</b>.",
    [3719297841] = "Hào Quang Đất",
    [3719383660] = "Bạn đã khám phá ra Lò Rèn Đá Quý!\n\nBạn có thể sử dụng sức mạnh của nó để truyền năng lượng (Tinh Hoa Cổ Đại) vào đá quý hoặc chiết xuất năng lượng từ chúng.\nNhững viên đá quý này có thể được gắn vào vũ khí để mở khóa các hiệu ứng mạnh mẽ!",
    [3719395299] = "Tương phản",
    [3719601957] = "<b>Nghề nghiệp:</b> Công nhân xây dựng\n\n<b>Nơi cư trú:</b> Công trường xây dựng \"Maelstrom\" (hiện tại).\nYêu cầu chuyển công tác đang chờ xử lý.\n\n<b>Tiền sử bệnh:</b> Đĩa đệm bị thoát vị, đau lưng\n\n<b>Sự cố:</b> Báo cáo trải qua cơn đau nhói đột ngột khi đi xuống cầu thang đến tầng dưới của khu khai quật. Ngã 2 tầng cầu thang, bị gãy xương sườn và nhiều vết thương khác. Các công nhân khác làm chứng rằng họ đã thấy Tongs đột ngột nhắm chặt mắt ngay trước vụ tai nạn như thể để tránh một ánh sáng chói lòa.\n\n<b>Ghi chú của bác sĩ:</b> <i>Bệnh nhân từ chối mở mắt cho đến khoảng 48 giờ sau khi ngã. Anh ấy đã thở phào nhẹ nhõm khi nhận ra mình không bị mất thị lực. Vui lòng cho phép nghỉ ngơi hoàn toàn tại giường ngay lập tức.</i>",
    [3719789313] = "Giảm SP Đỡ Đòn",
    [3719965515] = "Làm cho bước chân của bạn im lặng và nhanh nhẹn.",
    [3720269682] = "Trang phục Chân",
    [3721041685] = "Trạm Thuộc Da",
    [3721251071] = "Cung Nhanh Nhẹn",
    [3721739659] = "Tăng ST Băng",
    [3721841539] = "Cúp Danh Năng Hộp Sọ III",
    [3722084975] = "Rìu Xé Rách Tấm Màn",
    [3722392883] = "<lorename>Vanora</lorename>",
    [3722416828] = "Tăng 100% sát thương gây ra với đặc quyền Dao găm <b>Lưỡi Dao Độc Dược</b>. ",
    [3722481317] = "Không có Nhiệm vụ Hoàn thành",
    [3722561025] = "Khách Thăm",
    [3723074100] = "Một thanh kiếm bạc bóng bẩy, mỏng và phản chiếu như một mảnh băng tinh khiết.",
    [3723134361] = "Các chi tiết trên bộ phận giáp thân trên này được lấy cảm hứng rất nhiều từ lông cánh.",
    [3723162190] = "Những chiếc gai làm gián đoạn bề mặt nhẵn nhụi và nhô ra như lưỡi dao cạo. Chúng bật ra từ trung tâm tĩnh lặng, từ mắt bão, như cơn mưa tím tàn khốc trong một đêm sấm sét — sau đó mọi yếu đuối sẽ bị thanh tẩy, và chỉ những kẻ mạnh nhất mới có thể trỗi dậy từ vùng đất bị nhấn chìm. Theo truyền thuyết, điều này tượng trưng cho nguồn gốc của Broodmother Vesztah của loài drakian.",
    [3724060060] = "Cyclops Hollow chắc chắn sẽ hài lòng với hàm răng mạ vàng của hắn, với chúng hắn sẽ cười nham hiểm với ngươi.\n\nThu thập nhiều Đầu Cyclops Hollow để chế tạo Cúp Vàng.",
    [3724069235] = "Hồi sinh người chơi với <b>25%</b> HP thay vì <b>10%</b>. ",
    [3724144291] = "Khối 0.5m",
    [3724183065] = "Giường Đá",
    [3724414084] = "Bảo vệ chống lại The Sương độc",
    [3724654416] = "Đến Nhà Cũ của Hannah Reed",
    [3724966879] = "Nhân danh các Cổ nhân, ta đã làm được! Cân bằng. Đối tượng ngủ, nhưng có thể được đánh thức. Họ đã chết, nhưng vẫn sống! Đối tượng không bị phân hủy — không bị ảnh hưởng bởi dòng chảy thời gian thô tục. Một linh hồn Ngọn lửa trong cơ thể phàm trần — Igni là bằng chứng. \nChúng ta có thể tồn tại! Chúng ta có thể chịu đựng. Những <i>Bình Tro này sẽ là cơ hội duy nhất của chúng ta giữa The Sương độc. Chúng ta không còn lựa chọn nào khác.</i>\n\nBalthazar",
    [3725568336] = "Ta muốn vuốt ve một con Dê Thông Thường! Nào, ngươi nên thuần hóa một con đi!",
    [3725668997] = "Mũ Trùm Xạ Thủ",
    [3725760271] = "Quần Binh Lính",
    [3726515991] = "Khiên Xuyên Dương",
    [3726878854] = "ESP",
    [3727041763] = "Một chất lỏng trong suốt có mùi hăng. Dùng để tăng cường các phản ứng giả kim.",
    [3727044685] = "Xây dựng căn cứ",
    [3727122698] = "Một cây Gậy phép hoang dã và héo úa, có khả năng giải phóng sức mạnh của đất.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các vật phẩm niệm phép và MP. Trang bị <b>vật phẩm niệm phép</b> để niệm.",
    [3727410625] = "Hàng Rào Sân Vườn Gỗ Phương Bắc II",
    [3728105806] = "Cổng Tưới Tiêu Lớn",
    [3728325457] = "Rơi ra từ nấm trong Sương độc Kindlewastes",
    [3729151657] = "Một cây rìu sáng nhất vào lúc bình minh, bám víu vào hy vọng bất kể điều gì.",
    [3729609956] = "Hỡi Kẻ Mang Lửa, ta cảm nhận được một phép thuật vĩ đại gần đây. Bất khuất, <i>vĩnh cửu.</i> Một phép thuật có thể được niệm đi niệm lại mà không bị hủy diệt trong quá trình đó. Nó đang chờ đợi ngươi, ẩn mình dưới lòng đất. Hãy tìm nó.",
    [3729815874] = "<location>Lapis phía Đông</location>",
    [3730348589] = "Một khối gỗ ấm cúng, tối màu được làm từ khúc gỗ cây lá kim. Nó khiến bạn muốn đi săn trên núi hoặc uống trà nóng bên lửa.",
    [3730469232] = "Nói chuyện với Ngư dân",
    [3730682098] = "Hãy nhớ, mọi người: Các ván gỗ cần được xếp đúng chỗ! ĐỪNG làm sai vị trí — <craftingstation>Trạm thuộc da</craftingstation> phải được xây dựng chính xác như yêu cầu của bà mẹ! \n\nCần xem lại? Đây là hướng dẫn. Nếu lũ khốn các ngươi không biết đọc, hãy gọi Amar. Hắn sẽ giải thích cho!\n",
    [3731270865] = "Chăn nuôi",
    [3731875966] = "Tinh Hoa Cổ Xưa",
    [3731898836] = "Nhật ký Thuyền trưởng, Ngày Một",
    [3732155325] = "Cát Lưu Vực Vực Nước",
    [3732265297] = "Bộ giáp tấm này nổi bật với đường viền kim loại màu vàng óng và tông màu rực rỡ bên dưới. Màu tím hoàng gia được đạt được bằng cách thu hoạch và đun nóng chất nhầy ốc biển trong quá khứ, và sự tuyệt chủng của wildlife dưới nước càng làm tăng thêm sự độc quyền của nó.",
    [3732609104] = "Tốc độ phát triển cây trồng",
    [3732633745] = "Chiếc quần này di chuyển cùng bạn qua bụi rậm, tăng cường SP khi bạn rình mồi.",
    [3733273717] = "ST Cận chiến 2H",
    [3734335559] = "Mục Tiêu Đứng",
    [3734524366] = "Nữ nhạc sĩ muốn bạn lấy lại chiếc trống tay mà cô ấy đã đánh mất khi chạy trốn khỏi Vukah. Hãy đến khu định cư gần đó của họ và xem xét xung quanh!",
    [3734544637] = "Cảnh quan bên trong <b>căn cứ được thực hiện bằng Búa Xây Dựng</b>.\n\nBên ngoài căn cứ hoặc khu vực xây dựng, bạn có thể tạm thời định hình môi trường bằng cách sử dụng <b>công cụ cảnh quan (như cuốc) và chất nổ (để ném hoặc kích nổ từ xa).</b> Tuy nhiên, hãy cẩn thận: Những thay đổi được thực hiện <b>bên ngoài khu vực xây dựng</b> trong căn cứ của bạn sẽ <b>được hoàn nguyên</b> sau một thời gian. Những thay đổi được thực hiện <b>bên trong khu vực xây dựng của bạn sẽ còn nguyên.</b>\n\nĐịnh hình Embervale theo bất kỳ cách nào bạn muốn bằng cách đào đường hầm, san bằng các tòa nhà hoặc đắp đồi!",
    [3735655815] = "Về Drak và Cổ nhân",
    [3736006725] = "Hồi Máu Liên Chuyền I",
    [3737097920] = "Ta đã đụng độ một toán tuần tra, đúng như ta lo sợ! Tuy nhiên, may mắn lại một lần nữa mỉm cười với ta. Ta đã thuyết phục toán lính rằng ta đến từ bộ phận khai thác gỗ bằng cách cho họ thấy những vết chai trên tay ta từ nhiều năm chơi đàn lute. Họ đã tin!\n<i>\"Tuyển dụng Loft\"</i>, họ gọi ta. Ta không bận tâm đặt tên giả. Ta nghĩ rằng họ sẽ không biết về quá khứ âm nhạc của ta, dù sao đi nữa. Âm nhạc có được phép ở những vùng xa xôi của phương Bắc không? Ai mà biết.\n\nTa được giao nhiệm vụ sửa chữa tòa tháp, nhưng ta đã lẻn đi làm việc để ngắm nhìn khung cảnh tuyệt đẹp này. Khi ta hét \"echo!\", những ngọn núi phản hồi lại tiếng gọi của ta bằng những tiếng vọng nhẹ nhàng. Thật sự rất đáng kinh ngạc. Ta <i>nhất định</i> phải khám phá thêm về những ngọn núi. Có lẽ ta sẽ yêu cầu cấp trên điều ta đến nơi khác.",
    [3737201289] = "Chuối Khô Phơi",
    [3737414202] = "Chế tạo tại Bàn cưa",
    [3737578626] = "Uff… cái này đã chống cự dữ dội. Nhanh như chớp, chúng ta lao qua hầm mộ. Để tôn vinh hắn, ta đã dựng một ngôi mộ ngay nơi hắn trút hơi thở cuối cùng…\nVà bây giờ… một Phép thuật Sét?! Ta tưởng ta đã gần tới rồi. Ta đang mệt mỏi với điều này. Ta tin rằng chỉ còn một ngôi mộ cuối cùng, gần Vịnh Stillwater về phía chân đồi...",
    [3737748193] = "<location>Cuộc săn cáo</location>",
    [3738782226] = "Làm đầy bằng Vật liệu địa hình mái nhà",
    [3738793421] = "Bạn có thể ghim công thức để nhận thông báo khi đã thu thập đủ nguyên liệu để chế tạo công thức đã ghim.",
    [3739343195] = "Thánh địa Ngọn lửa",
    [3739741915] = "Ta sẽ giữ cảnh giác ở ngoài đó. Vũ khí đó có thể mạnh hơn, nhưng Sương độc ẩn chứa nhiều nỗi kinh hoàng.",
    [3740287189] = "Triệu hồi và Nói chuyện với Fenrig",
    [3740326590] = "Món giáp này được làm từ sự kết hợp giữa vật liệu mềm và lớp giáp cứng, giống vảy để đảm bảo sự uyển chuyển và bảo vệ tối đa. Nó có những chiến tích săn bắn nhỏ gắn ở nhiều vị trí.",
    [3740478000] = "Thịt Nạc Nướng",
    [3740707181] = "Giá Để Vũ Khí Đũa Phép",
    [3740796161] = "<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương thưởng lên đến phần trăm <i>quá tải</i>.",
    [3740849514] = "Độ bền trang bị",
    [3741028696] = "Vải nhuộm vàng dùng để may quần áo.",
    [3741413433] = "Hãy để ta xem thứ gì đã lọt vào lưới của ngươi!",
    [3741455915] = "Đài Lửa Thép Nhỏ",
    [3742454097] = "Mũi Tên Hắc Diên Thạch",
    [3742766610] = "Xương Khổng Lồ",
    [3743397364] = "Khiên Ánh Sáng",
    [3744142676] = "Giáp thân trên",
    [3744370756] = "Ngôi đền ẩn",
    [3744460033] = "Tấm Bạt Lò Xo (Nhảy Cao)",
    [3744987687] = "Cung Ngắn Gỗ Thông",
    [3745304975] = "Lại phiêu lưu nữa à? Ta thấy ngươi tìm được vài \"Khối Giếng\"! Để ta xem nào... Ta chưa bao giờ thấy một viên đá nào giống như vậy. Mịn màng và bóng bẩy, lớp vỏ đen tuyền gần như đáng sợ. Nó khiến ta rùng mình! Ngươi nên tận dụng chúng, Kẻ Mang Lửa!",
    [3745650332] = "Cà Ri Chuối Tây",
    [3745731930] = "Đặt động vật nông trại vào căn cứ của bạn",
    [3746010700] = "Vận may đang chờ đợi.",
    [3746401303] = "Bậc thầy đũa phép",
    [3746853733] = "Vẫn không có gì để ăn. Vẫn không có gì để dọn. Xương, vụn bánh mì và súp nước lã... Khi nào chúng ta sẽ gặp kết cục của mình?\n\nMột lữ khách mới đã đến, đói và mệt mỏi. Cô ấy muốn ta để xương trong món hầm của cô ấy. Một sự tức giận thầm lặng ẩn chứa trong mắt cô ấy - sự quyết tâm hoang dã, như một con sói đói. Ta đã mời cô ấy một căn phòng, nhưng cô ấy từ chối với một tiếng gầm gừ. <b>Cô ấy đã đi thẳng vào rừng, lên phía bắc,</b> để ngủ trên nền đất lạnh lẽo. Một kẻ vũ phu... dù sao cô ấy cũng thuộc về nơi hoang dã.",
    [3747215584] = "Cống thoát nước hồ bị tắc",
    [3748118374] = "Mũi Tên Choáng",
    [3748120175] = " <npc>Scavenger</npc> đã chỉ cho bạn một trại Cướp bóc lớn ở Vùng Đất Nhen Nhóm. <b>Hãy đến trại</b> và khám phá hoặc tiêu diệt kẻ địch ở đó!",
    [3748259915] = "Đặt lại hoàn toàn",
    [3748553052] = "Đừng đi",
    [3748830662] = "Hệ Sợi Nấm",
    [3748987302] = "Gửi Nữ hoàng yêu dấu của ta,",
    [3749147801] = "Chưa được chỉ định",
    [3749155797] = "Gối",
    [3749986917] = "Gửi Caleb: Găng tay đã xong",
    [3750161681] = "Một bộ dao găm làm từ thép sẫm màu, phản chiếu ánh trăng trên các cạnh nứt vỡ của nó.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [3750962864] = "Ta cảm ơn ngươi rất, rất nhiều Kẻ Mang Lửa. Con gái ta và ta là những người dân giản dị. Chúng ta không thể giúp nhiều về săn bắn và phép thuật, nhưng chúng ta sẽ luôn biết ơn ngươi! Ngươi đã chứng minh rằng vẫn còn hy vọng! Rằng thế giới có thể được xây dựng lại, và định hình theo ý chí của ngươi! Chúng ta mãi mãi mắc nợ ngươi, và ta chắc chắn rằng những người dân khác trong thị trấn cũng sẽ cảm thấy như vậy!",
    [3751000267] = "Dự trữ nhà máy",
    [3751327348] = "Hộp Trang Trí Màu Cam",
    [3751327543] = "Hồi phục HP, SP và MP.",
    [3751492455] = "Chọn Lưu game",
    [3752495479] = "Ta không thể ngừng nhìn cái lấp lánh đó! Ta không biết đá Aquamarine có thể đẹp đến vậy - cảm ơn ngươi đã cho ta thấy chúng!",
    [3753366913] = "Tủ Gỗ Đánh Bóng Nhỏ",
    [3753371512] = "Ngồi",
    [3753438736] = "Thư của Athalan gửi <lorename>Talion</lorename>",
    [3753768788] = "Khó",
    [3753881579] = "Sách III",
    [3753972035] = "Trường Kiếm Sa Ngã",
    [3754050043] = "Được tạo ra trong <b>lò nung</b> dưới nhiệt độ cao.\n\nGỗ cháy trộn với Oxygen tạo ra vật liệu dễ cháy, rất tiện lợi và cần thiết để đi sâu vào thế giới chế tạo.",
    [3754597032] = "Sát thương chí mạng",
    [3754864157] = "Mìn nổ",
    [3755093533] = "\n<b>Phép thuật: Cạn kiệt</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>Gậy phép.</b>",
    [3755093778] = "Trời lạnh quá! Ước gì ta có thể cuộn tròn trong một chiếc giường ấm áp, được che chở một lúc!",
    [3755331281] = "Thay đổi hình dạng",
    [3755411955] = "Đã mở khóa",
    [3755485720] = "Rìu Thiên Thể",
    [3755750702] = "Thuần hóa Capybara",
    [3756418078] = "Chiếc ba lô cung cấp không gian rộng rãi để cất giữ các loại thực vật chưa biết hoặc các cổ vật mới được khám phá trong các cuộc phiêu lưu!",
    [3756988263] = "Đặt thức ăn vào thanh hành động của bạn, chọn nó và nhấn %k để nấu.",
    [3757338997] = "Trang bị tất cả như Giáp",
    [3757374694] = "Khối Tường Đơn 0,5m",
    [3757717237] = "Cuộc đấu buổi sáng",
    [3758303970] = "Mũ Đạo Sư Băng Ngọc",
    [3758946621] = "<i>Văn bản được viết nguệch ngoạc bằng bút chì, với những vết dầu mờ trên các cạnh.</i>\n\nNước ngày càng đục. Không chỉ bẩn - mà là sai. Mùi như kim loại và sự thối rữa đã sinh ra một đứa con.\n\nLệnh cuối cùng từ cấp trên là \"giảm rò rỉ\" <i>chất lỏng huỳnh quang</i> vào bể chứa. Nghe không giống một kế hoạch mà giống một lời cầu nguyện... và sau khi xong việc đó, chúng ta sẽ rời khỏi đây mãi mãi. Không thang máy, không việc làm, không lương. Chỉ có sự im lặng và mùi thối rữa.\n\nCho đến lúc đó, chúng ta đang lắp đặt lưới và xếp bao lúa mì. Cảm giác như chúng ta đang đổ hết một nửa kho để vá một lỗ hổng. Tất cả đều là tạm bợ. Tạm thời. Và sâu thẳm trong lòng, ta không nghĩ ai tin rằng nó sẽ giữ được.\n\nTa biết một người nông dân ở Driftwood Wake. Đủ xa khỏi mớ hỗn độn này. Nước ở đó vẫn sạch... cho đến bây giờ. Ta sẽ thử vận may ở đó. Có lẽ ở gần thiên nhiên sẽ giúp ích cho cơn ho khó chịu này của ta.\n\n—J",
    [3759417778] = "Kẻ Săn Lùng Mộ",
    [3759470778] = "The Vukah",
    [3759494516] = "Nhà Giả Kim cần kiến thức mới về các cõi để tiếp tục hành trình giả kim của mình! Ngọn Lửa đã cho ông ta thấy một nguồn trí tuệ mới vượt ra ngoài dãy núi — một ngọn hải đăng trước hồ nước.\n\nTìm đường vào núi với sự giúp đỡ của Ngọn Lửa và tìm kiếm thị trấn!\n\nThu thập trí tuệ giả kim mới sẽ tiết lộ thêm công thức chế tạo và cho phép chế tạo áo giáp pháp sư tốt hơn!",
    [3759507852] = "2m ",
    [3760074044] = "+ 10",
    [3760203124] = "Phụ Kiện",
    [3760595618] = "Đánh bại kẻ bảo vệ giếng tiên dược đầu tiên.",
    [3760597015] = "Triệu Hồi Và Nói Chuyện Với Thuyền Trưởng",
    [3760803355] = "SP Kẻ Địch",
    [3761281425] = "Không có kết quả nào khớp với bộ lọc máy chủ",
    [3762150298] = "Bí Ngô Đêm Khô Cốt Vừa III",
    [3762376607] = "Luôn có một con cá lớn hơn!",
    [3762504055] = "Sáo Tinh Xảo",
    [3762640349] = "Khi tấn công từ cú nhảy đôi, <b>Đập Sập</b> gây thêm <b>20%</b> sát thương vũ khí.",
    [3762784883] = "Chúc may mắn!",
    [3763318478] = "Thư Giãn",
    [3763455759] = "Mở một ổ khóa.",
    [3763791319] = "Nhận sức mạnh của rồng với vũ khí huyền thoại này.",
    [3763921258] = "Mái Vòm Lăng Kính",
    [3763975640] = "Tham gia cùng chúng tôi!",
    [3764013410] = "Học lại",
    [3765141799] = "Ngôn ngữ:",
    [3765151882] = "Người Nông Dân đã đề cập rằng một con Bò Yak sẽ hữu ích để sản xuất len. Len có thể được sử dụng để chế tạo bộ đệm ấm hơn và áo giáp bảo vệ chống lại gió lạnh.\n\n<b>Để thuần hóa Bò Yak, trước tiên bạn phải chế tạo mồi nhử. Hãy chế tạo hoặc thu thập ít nhất 3 mồi nhử Bò Yak để tiếp tục.</b>",
    [3765510373] = "Găng Tay Ảo Thuật Gia",
    [3766210410] = "Giày Thành Lũy Hoàng Kim",
    [3767188245] = "Quần Quý Tộc",
    [3767325298] = "Cây Giống Cỏ Nến",
    [3767556665] = "Một phần của bộ Giáp Sát Thủ.",
    [3768272022] = "Mọi thứ đang dần thành hình",
    [3768371021] = "Khám Phá Thánh Địa Ngọn lửa Tại Cột Tạo Hóa",
    [3768377276] = "Vật phẩm này hồi 40% HP trong 10 giây nếu được bôi lên vết thương.\n\nNhận bất kỳ sát thương nào sẽ làm gián đoạn hiệu ứng Chữa thương.",
    [3768483189] = "Ngày xửa, khi tôi ở gần Thành Phố Chìm, có kẻ đã bắn một mũi tên vào tôi và ghim áo choàng của tôi vào một cái cây! Tôi đến để rút mũi tên ra, nhưng BÙM! Nó tan biến vào không khí! Tôi có thể chỉ cho bạn biết nơi đó ở đâu... có lẽ bạn sẽ tìm thấy thứ gì đó kỳ diệu, hoặc ít nhất là một câu chuyện hay để kể!",
    [3768689586] = "Xác định lượng sát thương bổ sung mà một đòn tấn công chí mạng sẽ gây ra.",
    [3768758827] = "Tăng Cường Bàn Đạp",
    [3769034305] = "Cúp Danh Năng Lưỡi Hái Sa Ngã Bằng Vàng",
    [3769078792] = "Hàng Rào Đồng Đỏ",
    [3769230109] = "Chế Tạo",
    [3769282934] = "Ikko #2",
    [3770328126] = "Cuộc Đột Kích Đoàn Xe",
    [3770617700] = "Cờ Lệnh Đêm Khô Cốt",
    [3771524727] = "Chất Lượng Bóng Đổ Khối",
    [3771554646] = "Nặng",
    [3771858199] = "Nhập mật khẩu",
    [3774206925] = "Tôi muốn nói chuyện với bạn về lý thuyết màu sắc! Bạn không muốn làm nổi bật đôi mắt của mình hơn sao?",
    [3774358574] = "Xin hãy nghỉ ngơi một chút!",
    [3774872783] = "Cột Đá",
    [3775678109] = "Áo Giáp Điềm Báo",
    [3775695533] = "Rất ít kẻ địch có thể chống đỡ được một đòn đánh không vũ trang bằng đôi găng tay này.",
    [3775841024] = "\"Chim Đuôi Đỏ Không Thể Bay Đứng Một Chân\"",
    [3775883066] = "Bà Braelyn đã chuyển đến một ngôi đền ẩn khác. Hãy tìm điểm đến tiếp theo của bà ấy và tìm kiếm bà ấy ở đó!",
    [3775936078] = "Thư Giới Thiệu Của Darya",
    [3776361357] = "Một chiếc rương lớn và nặng, cung cấp không gian lưu trữ tuyệt vời cho vô số vật phẩm.\n\nCác vật phẩm được lưu trữ ở đây có thể được sử dụng cho mục đích chế tạo từ bất kỳ đâu trong căn cứ!",
    [3776688967] = "Ammonites",
    [3776855229] = "Gamma",
    [3777174789] = "Tia Chớp",
    [3778344851] = "<lorename>Irvetta</lorename>",
    [3778589524] = "Thêm %k bằng %k sát thương cơ bản",
    [3778797336] = "Bạn đã thắp lên ngọn lửa đầu tiên, nhưng hành trình của bạn chỉ mới bắt đầu. Để dụ quái vật ra, tất cả các ngọn lửa phải được thắp sáng.\n\nHãy nhìn xung quanh bạn. Từ vị trí của mỗi ngọn lửa, bạn sẽ có thể nhìn thấy các công trình khác ở phía xa. Mỗi công trình mới sẽ chứa một ngọn lửa.\nNgọn lửa cuối cùng nằm trên núi, rất cao, trong một thị trấn gọi là Pháo Đài Everfrore.\n\n<b>Tổng cộng có 8 ngọn lửa, và bạn phải thắp sáng tất cả để tiếp tục.</b>",
    [3778900924] = "Trượng",
    [3779532365] = "Đất đai giàu khoáng sản. <b>Khai thác</b> các mạch quặng bằng <b>cuốc chim</b> để thu thập chúng. Một số quặng chỉ có thể tìm thấy bên trong Sương độc.",
    [3779812906] = "Hồi Phục MP",
    [3780236058] = "Đi Theo Giai Điệu",
    [3780598982] = "Một Biên Giới Mới Trong Giả Kim",
    [3780899748] = "Tăng Cường Hồi Phục HP",
    [3781308878] = "Chiến Binh",
    [3782054045] = "Trại Thợ Mộc",
    [3782334725] = "Cây Giáo",
    [3782588798] = "Thỏ Nhảy",
    [3783098569] = "Cốc Phế Liệu",
    [3783440500] = "Hãy dành một chút thời gian để chiêm ngưỡng bông hoa hấp dẫn này và màu hồng tuyệt đẹp của nó.",
    [3784099713] = "Tuyết Rơi",
    [3784317662] = "Tiệm Hớt Tóc",
    [3784419811] = "Điều Tra Rào Cản",
    [3785223979] = "Thành Trì Vàng",
    [3785263476] = "Bạn đã đánh thức Ngọn Lửa trên Đỉnh Tháp Cổ - Blackmire! Nó cảm nhận được sự hiện diện bên dưới một Thành Phố Cổ gần đó đã bị bùn đất nuốt chửng. Khám phá tàn tích và tìm người sống sót đang ngủ để tiếp tục!",
    [3785975807] = "Cây cung này được chế tác theo hình dáng của Drak'Dal, ngay cả khi họ không sử dụng loại vũ khí này. Một mũi tên bắn ra từ cây cung này sẽ xé toạc không khí như tiếng huýt sáo sắc bén của ngôn ngữ drakian.",
    [3786223808] = "Một túi hữu cơ chứa bào tử Sương độc cô đặc cao.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Dây leo Tàn ác Fell, ban đầu tìm thấy ở Revelwood.",
    [3786266097] = "Tab Trước",
    [3786802969] = "Dập tắt các cuộc nổi dậy chống phong kiến <i>thật phong cách</i> với đôi giày thời trang và được chế tác tinh xảo này!",
    [3788841038] = "Găng tay rực cháy với lửa ma thuật thuần khiết. Sử dụng chúng để thiêu rụi kẻ thù của bạn!",
    [3789083520] = "Ngọn Lửa Không Ngừng",
    [3789773617] = "Tiện Ích",
    [3789868551] = "Những bàn tay cầm cây bút này thô kệch và chai sần vì cày cấy ruộng đất của gia đình. Vai tôi rộng, thân tôi rắn chắc. Đó là số phận của dòng dõi tôi, sinh ra để làm việc trên đất cho đến khi gục ngã. Than ôi, tôi không bao giờ thoát khỏi sức hấp dẫn của cuộc phiêu lưu.\n\nMột lần khi còn trẻ và đang gieo hạt gần rìa thửa ruộng, tôi nghe thấy tiếng huýt sáo từ rừng. Tôi lẻn qua hàng rào ọp ẹp và đi theo giai điệu. Cuối cùng, tôi tìm thấy một nhạc công trẻ tuổi dựa vào gốc cây, huýt sáo và khắc một cây sáo. Khi tôi trở về những cánh đồng trống trải vào đêm khuya, tôi đã gặp sự không hài lòng của cha mình.\n\nÔng ấy có thể bắt tôi quay lại làm việc, nhưng ông ấy không thể ngăn tôi ngân nga giai điệu mê hoặc đó...\n\n<i>Valory</i>",
    [3790196582] = " <npc>Người Sưu Tầm</npc> đã tiết lộ vị trí của Hang Động Hollow trong Rừng Revel. Hãy đến địa điểm đó và đi xuống để tiêu diệt <b>sinh vật một mắt</b> bên trong, và lấy đầu của nó để mở khóa các tùy chọn chế tạo mới.\n\n<b>Hãy tập hợp sức mạnh và đồng minh của bạn, nếu có, để chuẩn bị cho phù hợp.</b>",
    [3790263738] = "Muôi Phế Liệu",
    [3790506455] = "Bạn được Ngọn Lửa ban phước.",
    [3790591118] = "Nghỉ Ngơi Cấp 2",
    [3790855908] = "Được chế tạo thông qua sự kết hợp giữa sét và băng. Hai nguyên tố mạnh mẽ va chạm vào nhau, giải phóng một đòn tấn công mạnh mẽ.\n\n<b>Quá Tải:</b>\nCây đũa phép này có cơ hội khuếch đại sức mạnh sát thương của nó. Các đòn tấn công gây thêm sát thương lên đến tỷ lệ <i>quá tải</i>.",
    [3790881156] = "Chất Lượng Mạng",
    [3791168875] = "Miếng Vá Lông Thú",
    [3791314045] = "Không thể tương tác khi đang di chuyển",
    [3791666502] = "FSR2",
    [3791792976] = "...Cái gì? T-Tôi đang ở đâu? ...Tôi là ai?",
    [3791966894] = "Tấn công với lực và để lại vết thương tàn khốc. Một vũ khí thực sự xứng đáng với tên gọi của nó.",
    [3792581938] = "Làn Sóng Thần Thánh",
    [3792659443] = "Truyện Người Câu Cá",
    [3793159103] = "Cổng Gỗ Thô Sơ II",
    [3793436469] = "Bếp Nướng Hải Sản",
    [3793450409] = "Điều chỉnh lượng Rune được trả lại cho bạn khi phân rã vũ khí đã nâng cấp.",
    [3793923643] = "Hãy nhìn xem, một tia sáng của sức mạnh, Flameborn. Việc đánh bại Rễ Sương Độc đã ban cho bạn <b>Điểm Kỹ Năng</b>. Hãy sử dụng chúng trong <b>Cây Kỹ Năng</b> để mở khóa những sức mạnh mới, kỳ diệu. Hãy quên đi con đường của Chiến binh, Kiểm lâm và Pháp sư. Bạn phải tự rèn luyện con đường của mình nếu muốn sống sót.",
    [3794034122] = "Cài đặt này kiểm soát thời gian trạng thái đói trước khi suy dinh dưỡng xảy ra.",
    [3794207232] = "Đánh bại rồng Sương độc.",
    [3794248164] = "Ôi, tôi muốn thấy Kindlewastes như xưa... tươi tốt, xinh đẹp và hoang dã!",
    [3794545318] = "Giáp Ngực Xuyên Dương",
    [3794722763] = "Dao Găm Drak Nhỏ Trang Trí",
    [3794775993] = "Tăng ST Hỏa",
    [3795323760] = "Bạn đã tìm thấy một công thức chế tạo bí mật bên trong Sảnh Hollow.\n\nThu thập tất cả công thức nằm rải rác khắp Sảnh trong mỗi quần xã sinh vật để trang trí ngôi nhà của bạn với một nét quyến rũ bí ẩn mới!",
    [3795817154] = "Đây có thể gọi là áo không?",
    [3796293897] = "Hạt cà phê xay, sẵn sàng để pha thành một tách cà phê đầy năng lượng!",
    [3796638373] = "Những Cột Cổ Đại này mở ra các điểm Du Lịch Nhanh trên khắp thế giới, và tiết lộ <b>kiến thức cổ xưa</b> về Embervale. Hãy tiến lên, đứa trẻ. Vùng đất phải được giành lại.",
    [3796715524] = "Điều tra Điểm Thứ Ba Trên Tuyến Vận Chuyển",
    [3796877832] = "Tượng Đầm Lầy Đen I",
    [3797192517] = "Chữa thương Mỗi Giây",
    [3797341642] = "Bắt Đầu Canh Gác",
    [3797367131] = "Bình Đồng Đỏ",
    [3797464785] = "Thùng Chắp Vá",
    [3798107439] = "Tủ Trưng Bày Hành Lang Khô Cốt (2 Khe Vừa)",
    [3798211748] = "Sinh Lực",
    [3798302144] = "Microphone Mở",
    [3798670640] = "Một vũ khí sinh ra từ sự hợp nhất của xương, đất và lửa lỏng. Khi mắt bạn lướt qua nó, mớ sụn và rêu ở chuôi dao nhường chỗ cho lưỡi dao obsidian nuốt chửng ánh sáng.",
    [3798879858] = "Nạp đầy các vật phẩm từ kho đồ",
    [3798952211] = "Có sẵn",
    [3799082373] = "Chất Lượng Môi Trường",
    [3800090925] = "Yêu cầu nâng cấp",
    [3800378905] = "Đũa Phép Drak Cổ Đại",
    [3800598238] = "Nhân danh các Cổ Nhân! Trong cơn mưa bão tuần trước, chính mắt tôi đã chứng kiến một cảnh tượng vô cùng bí ẩn. Một bóng người trùm mũ trên con đường đến <location>Điểm Kết Thúc Của Glennwood</location> với vẻ ngoài như bóng ma. Họ có lơ lửng trên mặt đất, hay ký ức đã phản bội tôi?",
    [3801006883] = "Mhh, còn gì màu xanh nữa nhỉ? Argh, tôi không nghĩ ra được! Sao tôi lại phải đập cái đầu xinh đẹp của mình chứ? Ước gì tôi đã gãy cả hai chân thì hơn. Tôi hầu như không cần chúng!",
    [3802721009] = "Thu thập Lông Capybara",
    [3802766420] = "Phản đòn thành công một đòn tấn công của kẻ địch sẽ hồi phục <b>30</b> SP.\n\n<b>Phản Đòn</b>\nKhi trang bị Khiên, một pha đỡ đòn đúng lúc sẽ <b>phản đòn</b> tấn công.",
    [3802832620] = "Kho đồ Scavenger",
    [3803302343] = "Hồ sơ của bạn không có quyền truy cập các tính năng trực tuyến.",
    [3803321891] = " <npc>Nông Dân</npc> xác nhận rằng Đền Thờ Mặt Trời ở <location>Brittlebush</location> thực sự bị ám ảnh! Một Tinh thần tà ác đã ám ảnh các sảnh đường thánh thiện kể từ khi Sương độc tràn ngập vùng đất. Nó phải bị trục xuất!",
    [3803451678] = "Găng Tay Pháp Sư Băng Mưa",
    [3804307049] = "Một loại cây thảo dược quý hiếm có thể tìm thấy ở những khu vực nóng trên thế giới.",
    [3805602486] = "Cột Cờ V",
    [3805825231] = "Tôi đã sống đủ lâu để biết khi nào có những người giống mình... chúng ta cần làm nhiều hơn là kiên trì. Chúng ta phải ổn định, <b>trồng trọt, phục hồi vùng đất.</b> Có một nơi tôi nhớ. Một Hầm Cổ Đại khác đã được xây dựng. Bạn nên tìm kiếm nó.",
    [3805956484] = "Một loài cá mảnh mai, có thể nhận dạng bởi những sọc đen đặc trưng chạy dọc cơ thể.\n\nLoài cá này có thể nướng hoặc dùng trong công thức.\nNó cũng có thể được thả lại xuống nước và nuôi trong ao.",
    [3806136239] = "Ngọc Bốc Cháy",
    [3806385723] = "Một vật liệu màu xanh lá cây phát sáng đã được thanh tẩy để loại bỏ các đặc tính độc hại của nó.",
    [3806795742] = "Đôi bốt phù thủy truyền thống bảo vệ chân và cho phép người mặc giẫm đạp lên xác kẻ thù.",
    [3806820922] = "Mượt M",
    [3806985164] = "Bạn đã đến tháp của Nhà Giả Kim! Hãy lục soát tầng hầm của ông ta để tìm phòng thí nghiệm của ông ta!",
    [3807324342] = "Điều tra <location>Brightwich</location>",
    [3807608245] = "Eryn",
    [3807757398] = "Bạn đã đến địa điểm cuối cùng được biết đến của Rochelle: Một trang trại. Tuy nhiên, có điều gì đó không ổn về nó. Một nhà kho đặc biệt có vẻ đang trong tình trạng đổ nát. Hãy tìm kiếm tàn tích trên khu đất trang trại để tìm Rochelle!",
    [3807768871] = "Hàng Rào Hầm Mộ Cao",
    [3807796435] = "Thu hoạch và <b>ăn quả mọng</b> để bổ sung <b>HP</b> của bạn theo thời gian. Nó sẽ chuẩn bị cho bạn đối mặt với những nguy hiểm phía trước!",
    [3808186077] = "Quý Bà Leclair",
    [3808190102] = "Một thiết bị cho ăn giữ thức ăn cho Capybara.\n\nNó sẽ cho động vật của bạn ăn khi được đổ đầy thức ăn tương ứng.",
    [3808378345] = "Tinh Thần",
    [3808685350] = "<b><craftingstation>Bàn Thợ</craftingstation></b> có thể được sử dụng để chế tạo nhiều vật phẩm thô sơ.\n\nSử dụng nó để chế tạo <b>Khối Gỗ Thô</b> hoặc <b>Khối Đá Thô</b> cho <npc>Thợ Rèn</npc>.\n\nNhững khối xây dựng này là cần thiết để xây dựng một <b>cửa hàng cho <npc>Thợ Rèn</npc>.</b>",
    [3809300840] = "Vì đã lấy đi tất cả. Vì đã hủy hoại gia đình tôi, cuộc đời tôi, địa vị của tôi — và vì đã <i>hủy hoại tôi.</i>\n\nCuộc đời tôi tan nát, bị thiêu rụi bởi những luật lệ và hạn chế ngu ngốc của các ngươi. Chúng sẽ không còn trói buộc ta nữa!\n\nTa chối bỏ các Cổ Nhân! Ta <i>nhổ</i> vào Ngọn Lửa! Bất cứ ai cản đường ta, dám có nhịp đập, sẽ bị nghiền nát và vỡ vụn! Dòng máu quý giá đổ ra sẽ làm ta ấm áp cuối cùng!\n\nDARIUS",
    [3809357837] = "Sét",
    [3809380252] = "Bão Tuyết",
    [3809658423] = "Những Thánh địa Đêm này không giống bất cứ điều gì tôi từng nghĩ... và có lẽ tệ hơn, <i>không giống bất cứ điều gì viện nghiên cứu hay các tướng lĩnh đã nói về chúng.</i>\n\nTôi sợ mình không nên ở đây, nhưng cảm giác này thật mới lạ. Nó khác với việc lảng vảng trong thư viện cấm, lẻn ra khỏi viện sau giờ giới nghiêm, hay đánh bạc tiền tiêu vặt ở sòng bạc.\nTôi đang làm hoen ố một thứ gì đó thuần khiết khi ở đây, như thể sự hiện diện của tôi làm xáo trộn sự thanh bình của chính màn đêm.\n\nVà tệ hơn nữa, tôi đang thất bại. Thất bại trong việc nhìn thấy điều gì đó mà cấp trên muốn tôi tìm thấy. Tôi nghe thấy mệnh lệnh của họ vang vọng trong đầu, ra lệnh cho tôi đào sâu hơn... tìm kiếm một mối đe dọa. Một vũ khí. Một lời biện minh cho nhiều cuộc tấn công sơ bộ hơn, hoặc sự báng bổ. Và tôi chỉ không biết liệu <i>thứ đó</i> có tồn tại hay không.\n\nĐiều gì sẽ xảy ra nếu chúng ta tính toán sai tỷ lệ cược và đọc sai đối thủ của mình? Điều gì sẽ xảy ra nếu tất cả những điều này là sai?\n\n<i>Darya</i>",
    [3809866917] = "Con mắt pha lê của nó dõi theo chiến trường, và những kẻ nó nhắm tới hiếm khi thấy bình minh thứ hai.",
    [3810064161] = "Dừng sản xuất và dọn kho để nhặt",
    [3810490509] = "Bạn đang làm được, Hỏa Thần! Bạn đang Chữa thương Vùng Đất Suối! Nhưng thế giới của chúng ta thật rộng lớn... tin tôi đi, tôi đã đi khắp nơi. Hãy nhắm vào Cột Cổ Đại ở Rừng Khải Hoàn. Nó sẽ mở rộng thế giới của chúng ta hơn nữa! Chúng tôi luôn sát cánh cùng bạn!",
    [3810720345] = "Tối Thượng",
    [3810803654] = "Thần Thoại Hay Thực Tế?",
    [3810842502] = "Bạn đã chết đuối...",
    [3811321488] = "Cung",
    [3811546556] = "Cửa Đền Giả",
    [3811556630] = "Lớp da trên món đồ giáp gắn liền với thiên nhiên này được xếp lớp để giống như lá của một khu rừng đang nở rộ.",
    [3812036505] = "Biến Chất",
    [3812285095] = "Mũ Giáp Đỡ Đòn",
    [3812470171] = "Tấn Công Đồng Thời Kẻ Địch",
    [3812504941] = "Tinh Chế Len Thô",
    [3813070346] = "Nói chuyện với %k",
    [3813128756] = "Sát thương chống lại Fell",
    [3813155432] = "Khi bạn kích hoạt một đòn tấn công khi đang chạy nước rút, bạn gây thêm 30% sát thương trong đòn đánh đầu tiên.",
    [3813245517] = "Bột Vỏ Sừng",
    [3813724151] = "Tương tác Lưu trữ",
    [3814231244] = "Phao không thể kéo lại gần.",
    [3814428900] = "Ngọc Ma Sói",
    [3815150770] = "Đĩa Đựng Thức Ăn Tròn",
    [3815556422] = "Canh Gác Đêm",
    [3816623231] = "Đũa Phép Hội Tụ",
    [3817130262] = "Kẻ địch chỉ ngăn chặn 80% ST Tầm xa khi đang phòng thủ.",
    [3818362057] = "Phù Điêu Drak I",
    [3818439966] = "Tăng",
    [3819031392] = "Đường Ván Tre I",
    [3819174266] = "Mắt Bão",
    [3819290930] = "Vào Hầm Mộ Lãng Quên",
    [3819685305] = "Bản Nhạc",
    [3820022214] = "Khai Thác",
    [3820467734] = "Một gương mặt thân thiện nữa! Người này sẽ là một bổ sung tuyệt vời cho đội hình của chúng ta.",
    [3820526324] = "Xoay 90°",
    [3820723937] = "Vảy cứng của động vật hoang dã. Một số người nói chúng cứng như đá.",
    [3820950305] = " <npc>Thợ Săn</npc>'s <craftingstation>Trục Quay Tay</craftingstation>",
    [3821391375] = "Giới Hạn Tốc Độ Khung Hình Khi Chạy Nền",
    [3821711164] = "Họ sẽ hát về câu chuyện của bạn trong nhiều năm tới!",
    [3821953188] = "Chân Nến Gắn Tường",
    [3821969113] = "Nhẫn Sinh Lực Tối Thượng",
    [3822004986] = "Chiếc quần lộng lẫy, được mặc bởi những pháp sư dày dạn chiến trường và thông thái nhất.",
    [3822113491] = "Bẫy Cá",
    [3822220893] = "Đầu Khổng Lồ Fell bạn đã thu thập có thể được sử dụng để <b>nâng cấp Ngọn Lửa.</b>\n\nHãy truyền năng lượng của nó trở lại ngọn lửa để chiến thắng Albaneve Summits và tiến sâu hơn vào núi!",
    [3822324779] = "Ta sẽ nghỉ ngơi khi ta chết. Còn gì nữa?",
    [3822434735] = "Tăng ST Lôi",
    [3822557263] = "Anh trai — Ngay cả bây giờ tôi vẫn cảm nhận được sức mạnh của nó đang chảy trong tôi! Thuốc Tiên là một phép màu — ôi, tôi bắt đầu cảm thấy như một người mới! Tham gia cùng tôi trong một cuộc đột kích vào Hầm Chưng Cất Thuốc Tiên tối nay?\n\nNhững người khác sẽ không biết ai đã làm điều đó và chúng ta sẽ có Thuốc Tiên dùng trong nhiều tháng. Nếu anh còn chút lòng trung thành nào với tôi, hãy gặp tôi tại <i>hầm bí mật</i> của tôi lúc nửa đêm.\n\nChúc sức khỏe, Samuel.",
    [3823493139] = "Nói chuyện với Nhạc sĩ Valory",
    [3823504650] = "Khung Cửa Sổ Đánh Bóng Tròn",
    [3823628255] = "Ánh sáng của Tiền nhân mang đến không phải sự mù lòa, mà là tầm nhìn. Khi màu trắng bao trùm lấy chúng ta, những tia sáng rực rỡ của họ chiếu xuống và đưa ta vào giấc ngủ sâu. Và ở đó, ta đã có một giấc mơ.\n\nTa thấy mình ở vùng đất của huynh đệ, vào thời điểm trước khi sự mục ruỗng lan tràn. Những cánh đồng tươi tốt, nép mình trong lòng thung lũng, được biển cả vỗ về. Từ đại dương vọng đến một lời kêu gọi. Đó là một dấu hiệu. Chúng ta phải đặt những Bình tro cốt vượt ra ngoài bờ cõi của mình, bất kể giá nào.\nKhi chia sẻ tầm nhìn của mình với Tiền nhân, ta biết rằng lời nói là vô ích. Họ đã hiểu chúng ta phải đi đâu. Thế là chúng ta đã đi, những vệt sáng mờ ảo vẫn nhảy múa giữa các vì sao.\n\nCây cầu này tạo điều kiện cho con đường nhanh nhất đến Thung lũng Veilwater, nhưng nó đang trong tình trạng hỗn loạn. Những người đồng hành của ta cho rằng có thể đi bộ về phía đông rồi vòng quanh rìa khu rừng rậm cho đến khi chúng ta đến được bờ biển. Ta rùng mình khi nghĩ đến điều đó.\n\nBây giờ, Huynh trưởng Lãnh chúa Vorgoth của ta hẳn đã khởi hành đến những Hòn đảo nổi dậy... quê hương của Tiền nhân. Mặc dù vậy, ta sợ phải nhìn thấy huynh ấy. Sau một bụi cây, trong bóng tối xoắn vặn của chiếc lá Monstera, như một phản chiếu của chính mình khi lặn xuống hồ, trong giấc ngủ sâu nhất của ta...\n\nHuynh ấy và ta cùng chung dòng máu. Đôi khi ta sợ rằng chúng ta còn thân thiết hơn ta mong muốn.\nTa cầu nguyện rằng giấc mơ của ta sẽ không biến thành cơn ác mộng.\n\n— Nữ hoàng Jezmina",
    [3823874822] = "Trông thật sắc sảo!",
    [3824112392] = "Chú ý",
    [3824357418] = "Thương nhân Tết Nguyên Đán",
    [3825121140] = "Khối băng này thật hoàn hảo để pha trà đá —...nhưng nó không truyền cảm hứng cho ta! Chết tiệt, ta đúng là đồ ngốc! Ta đã nghĩ \"mẹo trà\" sẽ lại có tác dụng, nhưng khối băng này quá...\"trong veo\"? Nó cần một sự không hoàn hảo, một chút màu sắc, ngươi biết đấy? Nếu chúng ta không leo lên đỉnh núi, mà thay vào đó đi xuống những thung lũng Sương độc bao phủ thì sao? Xin lỗi, \"chúng ta\" ý là \"ngươi\". Ta sẽ suy nghĩ về cách diễn đạt trong khi ngươi leo xuống những vách đá phủ tuyết.",
    [3825131045] = "À, cảnh tượng huy hoàng! Một màn phô diễn sự giàu có và quyền lực tuyệt vời — làm tốt lắm, Người giữ Lửa!",
    [3825289913] = "Tinh chế",
    [3825716901] = "Khối Sa Thạch Tiêu Chuẩn",
    [3825780010] = "Tiếng Tây Ban Nha",
    [3826368380] = "Giới hạn tăng trưởng đã đạt",
    [3826444625] = "Cắn Axit Vĩnh Cửu",
    [3826568394] = "Một luống đất sẽ cho ra Lô hội.",
    [3826676662] = "Một bộ giáp ngực bằng kim loại với các họa tiết tinh tế. Họa tiết gợi nhớ đến những dây leo vàng rối rắm, giờ đây đang đâm chồi với địa y mỏng manh.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [3826727585] = "Sát thương cơ bản ở 1 cộng dồn",
    [3826965117] = "Chúng ta cần một cách để chế biến len. Chỉ khi đó chúng ta mới có thể chuẩn bị cho cái lạnh khắc nghiệt.",
    [3826972623] = "Một khối băng vĩnh cửu rắn chắc. Nó không bao giờ tan chảy, bất kể ngọn lửa bên trong ngươi cháy sáng đến đâu.",
    [3827022370] = "ST Định hướng",
    [3827338759] = "Khúc Cường Âm Gió Lốc",
    [3827586283] = "Chiếu Chỉ Hoàng Gia",
    [3827820280] = "Đã đặt NPC",
    [3827831065] = "Nước",
    [3828402695] = "Đây là một ít dâu tây ",
    [3828704722] = "Với các Đỉnh Albaneve mở cửa đón chúng ta, ta tự hỏi chúng ta sẽ tìm thấy những loại nhạc nào ở đó? Ta nghe nói núi non thiếu các quán rượu và lễ hội nhưng đừng lo! Ta biết ít nhất một nhạc sĩ đủ dũng cảm để mang giày đi tuyết của mình! Đi theo bước chân của anh ta có thể dẫn chúng ta đến những giai điệu vàng!",
    [3828712680] = "Những tấm che chân này bảo vệ hai bên người mặc khỏi các đòn tấn công tới.",
    [3828882656] = "Giá Treo Vũ Khí Cận Chiến Hai Tay",
    [3829438711] = "Ngai Vàng Lâu Đài",
    [3829650953] = "Các sơ đồ điều khiển đặt trước không thể thay đổi.\n\nBạn có muốn sao chép %k sang Tùy chỉnh để tùy chỉnh thêm không?\nCảnh báo: các ràng buộc tùy chỉnh hiện có sẽ bị ghi đè!",
    [3829752211] = "Ngọn hải đăng",
    [3829779925] = "Búa Mặt Trời",
    [3830163062] = "Mỏ đá ở đâu? Ta đã được cứu, được giải thoát khỏi xiềng xích của mình? Thật tuyệt vời, ta đã TỰ DO! Cuối cùng cũng được tự do! Ngươi có thể cứu cả anh họ Anton của ta không? Thằng ngốc đó đã tự giam mình, còn ta thì bị nô dịch... nhưng anh ấy là người thân duy nhất ta còn lại! Ta không nghĩ thằng ngốc đó có thể trụ được lâu sau song sắt... ngươi có thể đoàn tụ chúng ta không?",
    [3830368836] = "Cận chiến",
    [3830370126] = "Bức Tường Rộng",
    [3831074513] = "Sát thương vũ khí lửa bổ sung",
    [3831215890] = "Vải nhuộm xanh dùng để may quần áo.",
    [3831639446] = "Đặt điểm dịch chuyển",
    [3832003222] = "Búa Mặt trời Bình minh",
    [3832288633] = "Rochelle",
    [3832306139] = "Thịt cá huyền thoại nướng",
    [3832644831] = "Thuốc Tiên ban cho <b>sức mạnh to lớn, nhưng có tác dụng phụ khủng khiếp về lâu dài.</b> Nhà giả kim nói rằng Thuốc Tiên này đã <b>gây ra nhiều vấn đề</b> cho thế giới và con người. Nó đã gây ra Cuộc chiến Thuốc Tiên.",
    [3832751883] = "Một mũi tên đã được vĩnh cửu ôm lấy. Nó lạnh buốt khi chạm vào.\n\n<b>Mũi tên Vĩnh cửu:</b> Mũi tên vĩnh cửu <b>không bị cạn kiệt.</b> Trang bị mũi tên vĩnh cửu và sử dụng <b>MP</b> để bắn nó bằng <b>cung.</b>",
    [3833871533] = "Mồi câu làm tăng cơ hội bắt được cá không phổ biến.",
    [3833876108] = "Sức mạnh Sụp đổ:",
    [3834003269] = "Xuyên thủng",
    [3834400317] = "Gửi trả về Ngọn lửa",
    [3834488167] = "Thợ rèn đã nhờ bạn tìm kiếm con gái của ông ấy. Cô bé sẽ rất tuyệt vời với vai trò trợ lý thợ rèn!\n\nSau khi bạn giúp thu hồi một lô hàng cho Thợ rèn từ Umber Hollow, rõ ràng là người gửi chỉ có thể là một người — con gái đã ly thân của Oswald Anders. Lô hàng đó đã đi qua Nomad Highlands vào thời điểm đó, vì vậy người gửi chắc hẳn đến từ đó hoặc xa hơn.\n\nĐiều tra khu vực được đánh dấu trên bản đồ của bạn để tìm con gái của Thợ rèn!",
    [3835233420] = "Gió hú lên.",
    [3835307684] = "Thông qua một bức thư từ người thổi sáo của nhóm Honeydews, ngươi đã phát hiện ra rằng một thành viên, Harper, đã rời <location>Nơi trú ẩn của Surat</location> một cách vội vã để bắt đầu sự nghiệp solo của mình. Cô ấy đã đi về hướng một tòa thành gần đó.\n\nKhám phá tòa thành và tìm kiếm nhạc cụ quý hiếm của Harper, cũng như những manh mối về các thành viên khác!",
    [3835482912] = "Truyện kể",
    [3835968616] = "%k gọi ai đó",
    [3836010051] = "Chế tạo Chìa khóa Sảnh Hollow Nomad Highlands",
    [3836280955] = "<lorename>Người lữ hành bí ẩn</lorename>",
    [3837231998] = "Lửa chứng tỏ là một vũ khí tuyệt vời chống lại các sinh vật của Sương độc. \n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương thưởng lên đến phần trăm <i>quá tải</i>.",
    [3837267546] = "Luôn giữ tinh thần lạc quan.",
    [3837295390] = " <npc>Nhà giả kim</npc> đã nghe tin đồn về những sự kiện kỳ lạ ở Springlands. Một nhóm Scavenger đang lạm dụng Tinh Hoa và tiến hành các thí nghiệm tàn nhẫn và bất thường.\n\nHãy tìm trại của chúng và tiêu diệt chúng để mở khóa một <b>công cụ cải tiến</b>.",
    [3837410877] = "Tăng trưởng bị đình trệ - Mức nước không phù hợp",
    [3837828355] = "Dâng một lời cầu nguyện cho Vukah cổ đại. Nếu được đáp lại, người dùng sẽ gây thêm sát thương lên Scavenger và được củng cố chống lại độc tố của chúng.",
    [3838652164] = "Đặt <craftingstation>Cối xay</craftingstation>",
    [3838659445] = "Thực hiện một <b>Đòn Tấn Công Tàn Nhẫn</b> bằng cách nhấn <b>%k</b> để gây thêm <b>+500%%</b> sát thương cho kẻ địch đang bị <b>Bị Áp Đảo</b>. \n\n<b>Áp Đảo</b> \nTấn công kẻ địch đang đỡ đòn hoặc đỡ đòn tấn công của chúng sẽ lấp đầy <i>Thanh Choáng</i> của chúng cho đến khi chúng bị <b>Bị Áp Đảo</b>.\nKẻ địch <b>Bị Áp Đảo</b> sẽ mở cho Đòn Tấn Công Tàn Nhẫn. ",
    [3839651650] = "<i>\"Chim chóc có thể bay đi bất cứ đâu chúng muốn. Tại sao ta không thể?\"</i>\n\nNhững suy nghĩ đó lướt qua đầu ta khi ta đẽo củi theo nhiệm vụ cha ta giao. Lạc trong suy nghĩ, ta bắt đầu ngân nga giai điệu yêu thích của mình.\n\nKhi ngẩng đầu lên, ta thấy một con chim ác là đã đậu gần chân ta.\n<i>\"Tại sao ngươi không bay đi, bé con? Nếu ta là ngươi, ta sẽ đi.\"</i> Ta nói. Con chim chỉ nghiêng đầu, như thể bối rối. Ta nhìn xuống tay mình, nhìn vào gỗ. Nếu đôi tay nông dân này có thể đẽo sáo, thì chúng còn có thể làm gì nữa?\n\nCó lẽ ngươi tự khắc họa số phận của mình. Có lẽ ngươi chọn gia đình mình, và người mình yêu. Khi nào làm việc, và khi nào nhảy múa. Cách để trưởng thành, và khi nào cảm thấy như một đứa trẻ. Ta biết đó chỉ là một \"có lẽ\", nhưng \"có lẽ\" là đủ đối với ta. Ta đặt dao khắc và sáo vào túi, đứng dậy và rời khỏi nông trại, vừa huýt sáo vừa đi. Ta chưa bao giờ nhìn lại.\n\n<i>Valory</i>",
    [3840908693] = "Giày Sừng Núi Tuyết",
    [3841053360] = "Kế thừa sức mạnh của Ngọn lửa, cây búa này có thể dễ dàng xuyên thủng hàng ngũ kẻ địch.",
    [3841247822] = "%k / %k Trang đã tìm thấy",
    [3841291085] = "Sử dụng Gậy phép Triệu hồi để chỉ định cho một Người sống sót.",
    [3841349343] = "Vảy Mặt Trời",
    [3841842663] = "Chế tạo và đặt Vỉ nướng hải sản",
    [3842209936] = "Hoa Gentian",
    [3843955720] = "Chim Thiên đường",
    [3844033640] = "<b>Hút HP:</b>\nHút HP có cơ hội (liệt kê ở trên) kích hoạt với mỗi đòn đánh.\nKhi được kích hoạt, đòn đánh hút HP sẽ hồi phục 50% sát thương gây ra dưới dạng HP.",
    [3844530068] = "Cảm ơn ngươi đã che chở cho ta!",
    [3844560260] = "Ngươi có chắc chắn muốn gỡ bỏ lệnh cấm đối với %k không?",
    [3844644738] = "Một bình sữa Fae Deer thơm ngon. Uống nó sẽ ban cho ngươi SP và giúp hồi phục thể lực nhanh hơn!",
    [3844781908] = "Đĩa Đựng Thức Ăn",
    [3845519667] = "Drak'Mer",
    [3846016487] = "Một loại axit giả kim được sử dụng để tạo ra các chất nổ.",
    [3846383014] = "Giảm",
    [3846812653] = "Nước",
    [3847042243] = "Thách đấu Thủ lĩnh Drak",
    [3847450923] = "Vật phẩm hiện tại",
    [3847501653] = "Một vết cắt mới là một khởi đầu mới.",
    [3847516215] = "Người nông dân ở <location>Woodgard</location> đã <b>chôn giấu một kho báu trong cánh đồng đầy bùn của mình.</b> Đào chiếc rương lên và nhận lấy sự giàu có của ông ta!",
    [3847631289] = "Tốc độ hồi phục SP cơ bản tăng thêm <b>10%</b>.\n\nCho phép các trận chiến kéo dài với cá bị mắc câu.",
    [3848118224] = "Thức Ăn Cho Chim",
    [3848695449] = "Một bàn làm việc dệt sợi lanh thành vải lanh hiệu quả hơn nhiều.",
    [3849392104] = "Một phần của bộ giáp Lính.",
    [3849873271] = "Những khuôn mặt xoắn vào nhau, và tất cả thở như một\nMột số có sẹo, khối u và sốt\nMắt điên cuồng hoặc giọng nói la hét\nNhưng tất cả đều là hắn, và hắn là tất cả bọn họ\nVà trong một khoảnh khắc, ta nghĩ ta cũng sẽ trở thành hắn. Hoặc hắn sẽ trở thành ta. \nĐể hình thành một vòng xoắn mới. Nằm dưới mặt nước chờ đợi, miệng há hốc. Bị lãng quên, và trồi lên để ăn thịt thế giới một lần nữa. \n\nPhản chiếu của phản chiếu\nMột đứa trẻ đuổi theo một đám mây trên mặt một ao nước lặng\nNhầm lẫn một hình ảnh với một hình ảnh khác, và một hình ảnh khác, và một hình ảnh khác\nKý ức về một bóng ma, gần như bị lãng quên, nhưng luôn ám ảnh\nMột phần của những gì đã từng, một cái bóng của bản thân được định hình lại và làm lại\n\nMỗi lần đẩy và kéo đều tạo ra một tiếng rên rỉ nhẹ nhàng, một vết rách lấp lánh, một giọt mồ hôi. \nVòng xoắn tự hành hạ mình để đối mặt với ta như một thể thống nhất. Vòng xoắn hành hạ thế giới.\nVòng xoắn là khuôn mặt của những cơ thể dưới đáy biển. Vòng xoắn là những gì nở rộ bên dưới.\nVòng xoắn là sự sống, là con rắn, là cơn lốc xoáy, là cái miệng, là sự tò mò ăn thịt chúng ta. Nó chờ đợi chúng ta, giăng bẫy, nhai, nuốt chửng, và tái sinh chúng ta.\n\n<i>Vòng xoắn là sự kết thúc của chúng ta, và là khởi đầu mới của chúng ta</i>",
    [3849957755] = "Một cây búa mạnh mẽ được tìm thấy làm từ ngà Vukah nghi lễ.",
    [3850015270] = "Nhận nuôi",
    [3850979806] = "Một chiếc trống đẹp với lớp da có hoa văn, nổi tiếng thuộc sở hữu của Daniel Kẻ Bị Nguyền Rủa, cựu thành viên của nhóm Honeydews. Người hâm mộ đồn rằng mặt sau của trống được khắc những chữ rune khiến Daniel chơi nhanh hơn, như một người bị quỷ ám.\n\nBây giờ khi ngươi đang cầm nó, những tin đồn đó hóa ra là sai - nhưng lời nguyền rủa của hắn ít nhất là rất thật!",
    [3851133826] = "Phát nhạc",
    [3851195517] = "Sự Dũng Cảm",
    [3851779739] = "Súp Calla Luna",
    [3851825342] = "Không còn chỗ để hoàn tiền",
    [3851977745] = "Tăng 30% Sức bền câu cá của ngươi.\n\nCho phép các trận chiến kéo dài với cá bị mắc câu.",
    [3852152668] = "Nhỏ và hình cầu, nhím biển này trông có vẻ không đáng chú ý. Tuy nhiên, một con mắt tinh tường sẽ nhận thấy sự đối xứng năm lần.\n\nBộ sưu tập này được tìm thấy ở Vùng đất Mùa xuân.",
    [3853405219] = "Giày Học Giả Ngọn Lửa Trẻ",
    [3854080820] = "Hãy tự nhiên như ở nhà!",
    [3854236812] = "Chỉ có thể mở vào ban đêm",
    [3854378272] = "Kẻ xâm lược đã chiếm Quảng trường",
    [3854432665] = "Hạt Phỉ",
    [3854545249] = "Bạn có thể nấu thức ăn tại lửa trại và các trạm nấu ăn. <b>Chế tạo một lửa trại</b> và đặt nó hoặc tìm kiếm các lửa trại để sử dụng. Tương tác với lửa trại để bắt đầu quá trình nấu ăn.\n\n<b>Thức ăn nấu chín mang lại lợi ích đáng kể</b> cho HP, SP và MP. Các loại thực phẩm khác nhau có tác dụng khác nhau tùy thuộc vào danh mục thực phẩm của chúng (thịt, rau, trái cây, v.v.).",
    [3854569477] = "Có thể ném để tạo ra Đám Mây Pheromone làm bối rối kẻ địch Fell, chúng sẽ chạy tán loạn khi bị ảnh hưởng.",
    [3854690268] = "Nụ Hôn Của Nàng Tiên Cá",
    [3854957476] = "Bạn đã khám phá ra một ngôi đền lớn ở Kindlewastes. Vượt qua tất cả các thử thách và đến căn phòng cuối cùng của ngôi đền để tìm kho báu đặc biệt!",
    [3854987290] = "Tặng Trà Gia Vị Cho Người Thợ Hớt Tóc",
    [3855026265] = "Quần Thuật Sĩ Hắc Ám",
    [3855079331] = "Cây Giống Hoa Bả Sói",
    [3855433441] = "Một chiếc vỉ nướng chắc chắn, hoàn hảo để chuẩn bị các món hải sản cao cấp. Với nó, thức ăn của bạn sẽ giòn tan và đầy hương vị.",
    [3855529966] = "Thiếu nơi trú ẩn cho giường",
    [3855637456] = "Cột Đá Cổ Đại",
    [3855975849] = "Một chiếc khiên vàng khổng lồ được khắc hình khuôn mặt gầm gừ của một sinh vật cổ đại. Tương truyền, khuôn mặt đầy răng nanh của nó có thể xua đuổi tà ma và gieo rắc nỗi sợ hãi vào kẻ thù trên chiến trường.",
    [3856193590] = "Umber Hollow",
    [3856847524] = "Đánh bại kẻ địch bị ám bởi Sương độc bằng vũ khí cận chiến sẽ khôi phục <b>5</b> giây <b>Thời Gian Trong Sương độc</b>.\n\n<b>Thời Gian Trong Sương độc</b>\nNếu thời gian này hết, Sương độc sẽ nuốt chửng bạn.",
    [3857210070] = "Cứ làm như tôi nói và bạn sẽ sớm bắt được con cá lớn nhất!",
    [3857278588] = "Chế tạo tại Bàn Quay Tay",
    [3857363615] = "Tấn Công Đập Xuống",
    [3857383084] = "Nơi đó. Hầm Kho Cổ Đại. Cậu đã xem xét nó chưa? Không còn thời gian để lãng phí.",
    [3857543452] = "Bảo Vệ Phép Thuật",
    [3857608443] = "Trang Trí Cơ Bản",
    [3858068770] = "<location>Đồi Nhỏ</location>",
    [3858478789] = "Da Bò Sát Nước",
    [3858507846] = "Kẻ Lưu Vong",
    [3858550089] = "Rìu Ô Nhiễm",
    [3858576931] = "Nếu không có mật khẩu, phiên của bạn sẽ công khai và mọi người có thể tham gia với quyền của vai trò này.",
    [3860025919] = "Cột Tổ Tiên Đá Drak V",
    [3860463452] = "Chất Lượng",
    [3860523636] = "Dây Ruy Băng Lụa Satin",
    [3860782050] = "Lãnh Địa Sương Mù",
    [3861314476] = "Tìm Nhà Phù Thủy",
    [3861393308] = "Giường Gỗ Phương Bắc",
    [3861781228] = "Một bình chưng cất, có liên hệ chặt chẽ với Alembic. Một trong những công cụ quan trọng nhất đối với một <npc>Nhà Giả Kim</npc>.",
    [3862468814] = "<keyitem>Ấm Đun Nước</keyitem>",
    [3862732526] = "Khác",
    [3863066712] = "Một cây đàn Handpan huyền thoại dành cho Trợ Lý Nhạc Công",
    [3863263957] = "Drak — Cấu trúc bộ lạc",
    [3864466932] = "Fenrig Mills, Jr.",
    [3864529671] = "Con Gái Mất Tích",
    [3864702110] = "Một Ngày May Mắn",
    [3865285747] = "Khám Phá Bộ Xương",
    [3865618660] = "Không Có Trạng Thái Hoạt Động",
    [3865798764] = "Nó thật đáng sợ và không trung thực... vì vậy khi những chú chim dẫn đường cho tôi đột nhiên ngừng hót, và khi tiếng gió xào xạc lá cây dâng lên thành một bản nhạc dồn dập êm dịu, tôi đã dừng lại. Rồi, khi tôi bắt gặp một tia sáng từ trên cao — một phản chiếu nhảy múa trên đầu ngọn giáo trong tán cây — tôi biết mình đã mắc bẫy.\n\nNhững ngọn giáo Vukah mưa xuống tôi như lửa độc trên <location><lorename>Pikemead</lorename>'s Reach</location> vào cái ngày nó sụp đổ. Nhưng tôi đã nhìn thấy đủ thế giới này để biết khi nào nên cúi đầu và chạy trốn! <i>Hãy giữ đầu bạn thấp khi rìu đang vung.</i> Tôi đã học được điều đó tại triều đình của các vị vua! Vì vậy, tôi đã chạy về phía mặt trời lặn, để ánh sáng làm lóa mắt những kẻ tấn công tôi.\n\nTôi đã trốn thoát, và Vukah sẽ không theo tôi đến đây. Tôi tự hỏi tại sao... Có lẽ vì tôi đang ở gần ánh sáng kỳ diệu đó đã xé toạc bầu trời từ rất lâu trước đây. Nếu các vì sao thẳng hàng, tôi sẽ hoàn thành chương này của hành trình.\n\n<i>Valory</i>",
    [3866115026] = "...Chúng tôi hết cà phê, vì vậy nếu bạn muốn đến và thư giãn, thứ tốt nhất chúng tôi có thể cung cấp là trà.\n\nChúng tôi có thể có một chiếc máy dự phòng ở gác mái, nhưng các tầng trên của tòa tháp cần sửa chữa, vì vậy không an toàn để đi lên. Tất nhiên, nếu có ai đó ngoài kia sẵn sàng mạo hiểm mạng sống của mình vì nó, chúng tôi sẽ hứa cà phê miễn phí trong tương lai gần.\n\nChúc may mắn!",
    [3866213687] = "Ngà Cá Voi Xanh, thường được gọi là ngà của biển, được nghiền thành bột màu sáng. Nổi tiếng về sức mạnh và khả năng phục hồi, nó thậm chí có thể được sử dụng làm thành phần trong hợp kim kim loại, mang lại cho chúng độ bền đặc biệt.",
    [3866483624] = "Sương độc",
    [3867706478] = "HP Người Chơi",
    [3867832857] = "Trọng Kiếm Megalodon",
    [3868063540] = "Bạn có thể mở khóa các loại Người Sống Khác Nhau.\nThợ Thủ Công cung cấp các nhiệm vụ quan trọng và nhiều xưởng chế tạo khác nhau.\n\nTrợ Lý lý tưởng để có các xưởng của bạn có sẵn ở nhiều căn cứ.\n\nCư Dân Thị Trấn làm cho căn cứ của bạn sống động hơn và cũng có thể đưa ra các nhiệm vụ nhỏ hơn.",
    [3868154543] = "Một phần mở rộng cho ba lô của bạn, giúp tăng dung lượng kho đồ lên hai hàng.",
    [3868167557] = "Cầu Thang Bí Mật",
    [3868491855] = "Say Đắm Màu Chàm",
    [3868743912] = "Tăng thuộc tính SP của bạn lên 1.\n\nTăng Thể Lực thêm %k mỗi Điểm Thuộc Tính.",
    [3869010057] = "Ngói Đá Vôi Vỏ Sò",
    [3869263945] = "Cây Giống Nấm Penny Bun",
    [3869731193] = "Ngay cả trong cái chết, nữ hoàng cũng đoàn kết những người tìm kiếm sự bảo vệ sau chiếc khiên của bà.",
    [3869863298] = "Một chiếc áo dài thoáng khí với không gian rộng rãi để đựng băng gạc, thảo mộc và khăn giấy.",
    [3870783941] = "Ốc đảo mà lữ khách đang tìm kiếm không còn xa. Sử dụng tàu lượn hoặc các phương tiện khác để đến ốc đảo và khai quật kho báu ở đó!",
    [3870809538] = "Tìm Kho Báu Trong Bãi Rác Tại <location>Cuối Glennwood</location>",
    [3870995998] = "Conway",
    [3871322847] = "Chữ Khắc Vukah",
    [3872086047] = "Nước ngọc lam lấp lánh, cát vàng\nMột ốc đảo như mơ trải dài khắp vùng đất\nBầu trời xanh vô tận với bầu trời trong vắt\nKhông khí ấm áp kể từ lúc mặt trời mọc\n\nĐộ sâu ngọc lam lấp lánh và rực rỡ,\nMột tấm gương lỏng, một giấc mơ sống động\nSóng vỗ nhẹ nhàng, êm ái như cơn gió,\nMột đại dương xanh với sự hoàn hảo dễ dàng",
    [3872525985] = "Đôi giày đặc biệt này giúp bạn không bị chậm lại bởi tuyết.",
    [3872580471] = "Tôi phát điên rồi, tôi biết. Những năm tháng cô độc đã làm tâm trí tôi trở nên giòn tan.\n\n<i>Vực thẳm. Cái miệng đó. Bên trong <craftingstation>Nồi Hắc Ám</craftingstation>, lẩn quất, chờ đợi.</i> Quay cuồng. Che mờ tâm trí tôi bằng mùi hương ngọt ngào, hôi thối của nó...\n\nNó gọi tôi, thì thầm. Tôi không hiểu nó nói gì, nhưng... nó biết. Nó biết tôi trống rỗng.\nNó cũng trống rỗng. Đói khát.\nChúng ta giống nhau.\n— <lorename>Ikora</lorename>",
    [3872843518] = "Cade Hawthorn",
    [3873143441] = "Vesztah",
    [3873242133] = "Vị Trí <keyitem>Dụng Cụ Rèn</keyitem>",
    [3873539525] = "Một nơi để gọi là nhà",
    [3873970308] = "The <npc>Farmer</npc> đã yêu cầu một <craftingstation>Cuốn Sách Cây Cối và Cây Giống</craftingstation> để <b>trồng cây mới.</b> Cuốn sách cũ của bà đã bị mất trong chuyến hành trình qua Cao Nguyên Du Mục khi bà phải bỏ lại một trại. <craftingstation>Cuốn Sách Cây Cối và Cây Giống</craftingstation> của bà nên ở nơi bà và <b>đoàn lữ hành đã dựng trại.</b>",
    [3874350476] = "Thuộc Tính",
    [3874502618] = "Chế Tạo Cần Câu Cá Tuyệt Vời",
    [3874509852] = "Quần Rách Nát",
    [3874840071] = "Đệm Thô Sơ",
    [3875654199] = "Máy Nghiền Thủ Công",
    [3876006210] = "Một con chó! Thật là một phát hiện. Con chó này có thể canh gác vào ban đêm cho chúng ta!",
    [3876636361] = "Bản Vẽ Khối",
    [3877277791] = "Bộ Sưu Tập",
    [3877797691] = "Áo Chẽn Người Chữa Lành",
    [3877804494] = "Phần thưởng nhiệm vụ",
    [3878346530] = "Bạn đã tìm thấy một ghi chú từ một thợ mỏ từng mơ ước về một ngành nghề mới: bán bụi tinh thể aquamarine. \n\n<b>Tìm kiếm Mỏ Aquamarine gần đó để xem liệu còn sót lại bất kỳ dấu vết vật liệu nào của anh ta không.</b>",
    [3879156465] = "Kiếm Lính Canh Phương Bắc",
    [3879287123] = "Cầu Lửa IV",
    [3879589587] = "Cột Đá Cổ Đại I",
    [3880155853] = "ST Tầm xa",
    [3880394205] = "The <npc>Collector</npc> đã tiết lộ vị trí của các Sảnh Hollow ở Cao Nguyên Du Mục. Để vào, bạn sẽ cần một chiếc chìa khóa. \n\n<b>Chế tạo Chìa Khóa với Collector</b> để tiếp tục.",
    [3880796254] = "Gối Ôm Hình Chó",
    [3881052179] = "Bình Đền Drak I",
    [3881501661] = "Một số <keyitem>Dụng Cụ Rèn</keyitem> đã được tìm thấy ở <location>Quần Đảo Jasper</location>. Chúng chắc hẳn là dành cho <npc>Thợ Rèn</npc>. Đặt <keyitem>Dụng Cụ Rèn</keyitem> vào căn cứ để mở khóa thêm công thức chế tạo.\n\n<keyitem>Dụng Cụ Rèn</keyitem> sẽ cho phép bạn <b>chế tạo áo giáp tiên tiến.</b>",
    [3881851481] = "Một bộ công cụ dành cho Thợ Xây. Cho phép các tùy chọn chế tạo nâng cao hơn khi được đặt.",
    [3882041332] = "Một Góc Nhìn Mới Về Cuộc Sống",
    [3882091681] = "Mỗi khi có bão tố, tôi cảm thấy những đám mây lơ lửng trên tàn tích Drak'Dal gần đó... một hiện tượng kỳ lạ. Cứ như thể mưa và sấm sét bị hút về đó, do từ trường hoặc phép thuật của tôi.\n\nTôi luôn nghĩ sét không bao giờ đánh hai lần, nhưng có lẽ tôi đã sai.\n\nSét đánh vào những cây cột cũ kỹ ở đó thường xuyên hơn, có vẻ vậy. Ngôi nhà lụp xụp um tùm đó có chứa bất kỳ cổ vật nào đáng để khám phá không? Hay nó chỉ nằm giữa một thung lũng kỳ lạ nhất? Ai biết, ai biết...",
    [3882879628] = "Quầy Rượu Gỗ",
    [3883295111] = "Ghế Băng",
    [3883768730] = "Chất liệu này phát sáng với ánh sáng trắng ấm áp. Đó là một phép màu giả kim!",
    [3884076297] = "Một thanh kiếm nặng được sử dụng bởi Fell mặc giáp.",
    [3884110912] = "Một khối băng vĩnh cửu bị phù phép, đóng băng vĩnh viễn trong thời gian.",
    [3884262933] = "Đi nào! Truyền cảm hứng cho tôi!",
    [3884617561] = "Kháng Băng",
    [3885214406] = "Tìm Nhà Của Phu Nhân Leclair",
    [3885526760] = "Bảo vệ bổ sung chống lại phép thuật loại sốc, ngoài khả năng kháng phép nói chung.",
    [3886000562] = "Kẻ Sát Nhân",
    [3886267970] = "Hang Sương Độc",
    [3886792070] = "Tất cả sát thương cận chiến <b>Chùy</b> đều tăng thêm <b>10%</b>.",
    [3887077752] = "Ta phải trốn thoát trước khi chúng bắt được ta\nNhưng ta cứ quên hết mọi thứ, chúng bay khỏi đầu ta vào màn đêm\nTa sẽ quên, nhưng ta không thể quên <i>thứ này</i>, nên ta phải viết nó ra, thật nhanh!\n\nCái hang phía sau chúng ta đã sập, ta nhớ tiếng đổ nát và bụi bặm, những viên đá rơi xuống, cơn đau, cơn nhức đầu\nVà lũ quái vật đã bắt ta khỏi anh em ta vào đêm trăng tròn\nNhưng <i>thứ này</i> sẽ giúp chúng ta về nhà, sẽ giúp ta trốn thoát. Nếu ta nhớ cách Vukah tạo ra nó, ta cũng có thể làm được\n\nTa thấy Vukah làm nó từ giữa song sắt\nĐúng vậy, ta đã ở trong lồng\nBởi vì chúng kéo ta đến đây vào ban đêm khi trăng tròn, hoặc trăng khuyết, có lẽ?\nTa đập đầu, ta nghĩ vậy. Những viên đá đập vào đầu ta. Và giờ ta ở đây, ta quên mất lý do\nTa phải trốn thoát trước khi chúng bắt được ta",
    [3887220598] = "Móc Leo Núi",
    [3888068431] = "Một cây Gậy phép hấp thụ năng lượng từ đất. Nó tràn đầy tiềm năng.\nGậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng điểm niệm phép và MP. Trang bị <b>điểm niệm phép</b> để niệm.",
    [3888295769] = "Một lưỡi kiếm thần thoại từ những ngày xa xưa. Truyền thuyết kể rằng nó đã được truyền lại cho Embervale bởi một Tinh thần khôn ngoan giáng thế từ các vì sao vào năm của loài rồng.",
    [3888660903] = "Cuộc chạm trán Drak: Một con tàu Sương độc bao phủ",
    [3888748290] = "Elixir và máu, một giọt đổi một giọt.",
    [3889737411] = "Quần Nông Dân",
    [3889960709] = "Điểm Giáp Vật Lý",
    [3890102477] = "XeSS",
    [3890354434] = "Viên đạn phép thuật giải phóng một luồng sáng, đủ sáng để đẩy lùi kẻ địch xung quanh người niệm phép.\n\nNgoài ra, phép thuật này còn tăng <i>thanh choáng</i> của kẻ địch bị che phủ dựa trên thuộc tính trí tuệ của bạn.\n\n\n<b>Phép thuật: Tiêu hao</b> sau khi sử dụng. Trang bị phép thuật và sử dụng <b>MP</b> để niệm bằng <b>Gậy phép.</b>",
    [3890496670] = "Trong Vùng Đất Nở Rộ",
    [3890676312] = "Không có đá quý nào có sẵn.\nTìm đá quý và chèn chúng vào vũ khí đã được nâng cấp đầy đủ để mở khóa các hiệu ứng mạnh mẽ.",
    [3891247840] = "<keyitem>Lò Luyện Kim</keyitem>",
    [3892111318] = "Đầm Nhỏ",
    [3892121981] = "Đũa Phép Lõi Đóng Băng",
    [3892652656] = "Dao Găm Trái Tim Dũng Cảm",
    [3892750300] = "Ảo Ảnh",
    [3893030833] = "Ống Bể Phổi",
    [3893148233] = "Tất cả sát thương <b>Sốc</b> đều tăng thêm <b>20%</b>.",
    [3893348928] = "Nguồn Gốc Của Ngọn Lửa",
    [3893650590] = "Ngay cả những sinh vật ghê tởm nhất cũng phải cúi mình trước Ngọn Lửa, bất kể kích thước của chúng. Ít nhất thì những âm thanh sột soạt bên trong vòm của nó đã lắng xuống.\n\nThu thập nhiều Đầu Fell Thunderbrute để chế tạo Cúp Đồng.",
    [3893905002] = "Những cánh cửa này sẽ vẫn đóng cho đến khi Drak'Dal được đánh thức.",
    [3894982551] = "Hầm Cổ — <npc>Thợ Mộc</npc>",
    [3895555719] = "Nhà Cổ Của Bà Phù Thủy",
    [3895958327] = "Hugo Vanderhall",
    [3896539558] = "Lửa",
    [3896711405] = "Không Bao Giờ Đủ",
    [3896911981] = "Người Câu Cá đã chia sẻ những câu chuyện về kỹ thuật câu cá khéo léo của cha mình. Ông ấy muốn bạn thu thập một số Ếch đang nhảy nhót trong đám cỏ của Thung Lũng Nước Vải và mang chúng về cho ông ấy.",
    [3896998830] = "Dân Làng",
    [3897953249] = "Báo cáo là đúng\n\"Drak\" đang ở gần đây\nTa chưa từng thấy thứ gì như thế này\nChúng đang chờ trong bụi rậm, chảy nước miếng\n\nJoshua và Powell đang tập hợp những người thợ lặn và một vài đứa trẻ có thể nín thở\nLối thoát duy nhất là qua nước\nKhông thể dừng lại lấy không khí — chúng có thể phát hiện ra chúng ta\n\nChúng ta ẩn náu trong <i>xác tàu</i> ven bờ\nPowell đang mang theo Rây Khai Khoáng\nĐủ sắc bén trong trường hợp khẩn cấp\nCầu mong các Tiền Nhân phù hộ\n\n- Rolf",
    [3898085717] = "Một chiếc búa thông thường có thể đã từng được các thành viên bộ lạc Drak'Dal cổ đại sử dụng. Thiết kế đơn giản của nó nói lên bản chất tiện dụng của nó.",
    [3898261302] = "Mũi Tên Dây Leo",
    [3898276234] = "Chả Cua",
    [3898607462] = "Tái Chế",
    [3898844004] = "Chuột Nhảy",
    [3899072551] = "Bàn Gỗ Thô Sơ",
    [3899403669] = "Một chiếc khiên chắc chắn do Fell mang. Nó đã tồn tại qua bao thế kỷ.",
    [3900193562] = "Chiếc cuốc này có thể giúp bạn đào sâu hơn và xa hơn do lưỡi cuốc được rèn từ thép. Lên nào!",
    [3901115407] = "Bộ Xương Khổng Lồ \"Polaris\"",
    [3901132256] = "Khối Băng Vĩnh Cửu",
    [3901556103] = "Chúc bạn gãy chân. Hoặc vài cái.",
    [3902214038] = "Bộ Thaumaturge",
    [3902369720] = "ST Đập Xa Bằng Chùy",
    [3902393512] = "Để che chở cho những người sống sót của bạn, <b>hãy chế tạo một chiếc giường phù hợp.</b> Đặt giường ở khu vực được bảo vệ, dễ dàng tiếp cận bởi những người sống sót. Nó sẽ tự động được chỉ định cho người sống sót trống gần nhất khi được đặt. Nếu bạn muốn chỉ định lại giường, hãy trang bị Gậy phép Triệu Hồi của bạn và sử dụng nó khi nhắm vào giường.\n\nNhiệm vụ này sẽ mở lại để thông báo cho bạn khi những người sống sót của bạn không còn được che chở.",
    [3902555140] = "Drak'Dal",
    [3902682313] = "Quần Sát Thủ",
    [3902891869] = "Về <npc>Nhà Sưu Tầm</npc>",
    [3903028592] = "Mơ Màng",
    [3903206810] = "Một lưỡi kiếm dường như được rèn từ băng.",
    [3903441593] = "Nhân loại sẽ phai tàn, như mọi sinh vật. Ánh sáng của họ sẽ lập lòe và tắt lịm, không chạm tới bởi Ngọn Lửa vĩnh cửu.\n\nVô nghĩa và nhỏ bé trước cái nhìn sâu sắc gần như vô tận, cháy sáng rực rỡ.\n\nBiến thành bụi khi chúng ta biến thành lửa. Một chu kỳ hủy diệt và hỗn loạn không ngừng.",
    [3904344487] = "Các nhà nghiên cứu đang điều tra các Trụ Sáng Tạo và đề cập đến một <b>khu vực khai quật</b> trong ghi chú của họ. Tìm trại của họ và khám phá!",
    [3904749289] = "Đầu Ma-nơ-canh \"Tóc Đuôi Ngựa Hanfu\"",
    [3905604092] = "Công Cụ",
    [3905994384] = "Tiền Đồn Cổng \"Drifa\"",
    [3907120525] = "Cụm Pha Lê Tối Máu",
    [3907389042] = "Lông Thú",
    [3908091582] = "Mặc lên Ma Nơ Canh",
    [3908376113] = "Tấn Công Phép Thuật",
    [3908464503] = "Vũ Khí Cận Chiến 1H",
    [3908780847] = "Bình Nước Gỗ Thô Sơ",
    [3909523872] = "Găng Tay Hắc Vệ",
    [3909785775] = "Bạn đã đến Hố Tar. Khám phá thung lũng và tìm con dao găm của Nghệ Nhân để trả lại cho bà ấy!\n\nVì Valory đã làm mất con dao găm khi chống trả <b>quái vật</b>, việc tìm kiếm ở các tầng thấp hơn nơi sinh sống của sinh vật có thể là một ý tưởng hay.",
    [3910353190] = "Ta đã chôn nó thật sâu",
    [3910689526] = "Gây Sát Thương và Các Loại Sát Thương",
    [3910728369] = "Giày Drak",
    [3910772302] = "Có thứ gì đó đã thức tỉnh, ta e rằng.\n\nCàng ngày càng có nhiều người mất tích mỗi tối... ban đầu, chỉ là những kẻ liều lĩnh đi xa hơn vịnh. Nhưng giờ đây, bất kỳ ai ở quá gần các con kênh vào đêm không trăng đều bị nước cuốn đi.\n\nTa cảm thấy như có thứ gì đó đang thử thách chúng ta... cắn xuống để xem chúng ta có nao núng, chiến đấu hay bỏ chạy không. Nhưng chúng ta có thể làm gì trước một bóng ma vô danh đã đến với một lời thách thức? Không còn lính canh, không còn lãnh chúa nào để bảo vệ chúng ta... Họ đã lên đường chiến đấu trong một cuộc chiến thánh và bỏ rơi chúng ta, gần những vùng nước tối tăm ẩn chứa những số phận độc ác.\n\nMột số người đã chọn di chuyển sâu vào đất liền. Ngay cả người canh đèn biển cũng đã bỏ trốn, hoặc ít nhất ta nghe nói vậy. Một ông già đã dành cả đời mình bên bờ biển này... Ta tự hỏi ông ấy đã nhìn thấy gì đêm qua, trong cơn bão không ánh sáng... và chúng ta còn bao lâu nữa cho đến khi nó lộ diện.",
    [3910947377] = "Bạn không thể đọc kinh thư thánh nếu không nhìn thấy, nhưng sự hiểu biết thực sự đến từ bên trong, dù sao đi nữa.",
    [3912305479] = "Nơi này khá ổn đấy, nhưng có thể cải thiện một chút, hả? Cửa, rương, và những thứ tương tự? Cung cấp cho ta một chiếc giường tử tế và ta có thể giúp ngươi xây dựng những thứ \"tinh xảo\" đó. Ta có con mắt tinh tường, vì vậy đừng làm ta thất vọng!",
    [3912417426] = "Đòn chí mạng với phép thuật có <b>50%</b> cơ hội tạo ra hai Quả Cầu HP, MP và/hoặc SP.\n\nThu thập một Quả Cầu sẽ hồi phục <b>10%</b> tài nguyên tương ứng.",
    [3913142074] = "Bạn có thể nghĩ rằng tôi đã gặp khó khăn, bị con kền kền đó bắt và tất cả... nhưng ít nhất thì con quái vật chết tiệt đó đã không xé xác tôi ra từng mảnh! Tôi đã từng chứng kiến điều đó xảy ra khi một số Kẻ Cướp tấn công những người Scavenger của tôi khi đi ngang qua <location>Brittlebush</location>. Chỉ vì đôi giày và quần áo của họ... Tôi sẽ chỉ cho bạn biết nếu bạn hứa sẽ bắt chúng trả giá!",
    [3913238100] = "Một ghi chú tiết lộ rằng những kẻ Scavenger đã mang về nhà một số chiến lợi phẩm bổ sung bên cạnh cuốn lịch nông dân. Hãy đến <location>Surat's Rest</location> và khám phá nơi có thể cất giữ thêm chiến lợi phẩm!",
    [3913344056] = "Nhẫn Ngọn Lửa",
    [3913584299] = "Một cây đàn hạc xuất sắc với những sợi dây bạc tinh xảo. Hình dáng của thân đàn và gỗ nhẹ làm cho nhạc cụ này hoàn hảo để học chơi dây đàn. Cầm nó lên khiến bạn cảm thấy hơi u sầu.",
    [3914318907] = "Suy Tàn",
    [3914323739] = "Chúng ta cần đẩy nhanh tiến độ. <lorename>Sameth</lorename> muốn chúng ta tham gia cùng ông ấy trong mỏ — Dấu ấn của <lorename>Sameth</lorename> — càng sớm càng tốt! Đi đường tắt nếu cần thiết — ông ấy không chấp nhận bất kỳ ai đến muộn! <i>Liệu vài sợi dây leo tầm thường có thể gây ra bao nhiêu thiệt hại?</i>",
    [3915367263] = "Gậy 2H",
    [3915395905] = "Một khối obsidian đặc, đen tuyền. Xây dựng bằng vật liệu này sẽ mang lại một hào quang huyền bí cho ngôi nhà của bạn!",
    [3916112830] = "Bạn đã đến địa điểm của người sống sót! Tìm và đánh thức họ.",
    [3917160009] = "Phản Chiếu",
    [3917944226] = "Hươu Tiên",
    [3918236378] = "Trưng Bày D",
    [3918376932] = " <npc>Nhà Giả Kim</npc> cần một số <keyitem>Dụng Cụ Khoa Học</keyitem> để xây dựng một Phòng Thí Nghiệm. Điều này sẽ cho phép các công thức chế tạo mới và khả năng chữa bệnh tốt hơn. \n\nBạn của ông ấy, <lorename>Loraine Crim</lorename>, đã sử dụng <keyitem>Dụng Cụ Khoa Học</keyitem> cho nghiên cứu của mình. Cuộc thám hiểm cuối cùng được biết đến của bà ấy đã dẫn bà ấy đến điều tra một Đài Thiên Văn Cổ Đại. Địa điểm đó đã được đánh dấu trên bản đồ.",
    [3918846407] = "Nỗi Lo Của Người Mẹ",
    [3919801355] = "Một phần mở rộng cho ba lô của bạn, làm tăng kho đồ của bạn thêm một hàng.",
    [3919812493] = "Tranh Khảm Ngọn lửa",
    [3920024825] = "Khối Xây Dựng",
    [3920189644] = "Tìm Hiện Vật Của Sảnh Hollow",
    [3920268446] = "Phước Lành Của Ngọn Lửa",
    [3920471391] = "Chế tạo tại Trạm thuộc da",
    [3920529436] = "Mảnh Cẩm Thạch Đỏ",
    [3920867501] = "Găng Tay Mùa Đông",
    [3920906537] = "Sống lại — thật là một món quà! Ta khóc thương cho thế giới cũ, nhưng có lẽ ngươi và ta có thể gieo mầm cho thế giới mới. Chúng ta phải cố gắng, phải không?",
    [3921526680] = "Bạn đã đến gần hơn một bước để tìm thấy ốc đảo nhỏ Kindlewastes. Hãy đi theo con đường của lữ khách để tìm ốc đảo và bất kỳ kho báu nào ẩn giấu ở đó!",
    [3922155040] = "Carlos! Tôi đã nhận được thư của cậu — và thật đúng lúc. Các cuộc tuần tra ở đây kiểm tra mọi lô hàng rất kỹ lưỡng. Tin đồn về Umber Hollow mà cậu nói là sai — ngay hôm qua chúng tôi đã tổ chức tang lễ cho một cô gái trẻ bị sát hại <i>ở trên đó tại <location>Surat's Rest</location>!</i> Nhưng tôi cũng cảm thấy giống như cậu khi nói chuyện với cậu ở chợ... tò mò muốn tìm một người bình thường, tử tế giữa tất cả các tội ác xảy ra ở nơi cậu sống. Mọi thứ từ tống tiền đến các tòa án và cảnh sát tham nhũng đến gian lận lan tràn. Có lẽ cả hai chúng ta đều đang trở thành nạn nhân của hàng thập kỷ lời nói sai lầm. Chúng ta không giống nhau sao, cậu và tôi?\n\nTrân trọng,\nEmma",
    [3922638669] = "Thảo Mộc",
    [3922917036] = "Quan Tài Hầm Mộ Lớn II",
    [3922978879] = "Chiếc quần ma quái cho những kẻ ma quái!",
    [3923117694] = "Vực Thẳm",
    [3923319154] = "Ăn Uống Và Nghỉ Ngơi",
    [3923830123] = "Cầu Nguyện Với Ngọn Lửa",
    [3923998004] = "Hiệu Quả",
    [3924063005] = "Rương Nhỏ",
    [3924081519] = "Không thể khởi tạo Hệ Thống Đồ Họa.",
    [3924346225] = "Ta đã gặp một pháp sư khi điều tra <i>nghĩa địa xương</i>. Lặng lẽ, không muốn nói hay trả lời những câu hỏi của ta. Một kẻ sống ở Kindlewastes khác thường. Có lẽ là một lời thề im lặng? \n\nCó lẽ ông ta sống giữa những hóa thạch, vì ông ta dường như tôn kính chúng theo một cách mà ta không hiểu. Khi ta buông ra một câu hỏi khác, ông ta chỉ vẽ <i>một chữ rune</i> lên cát... những chữ tượng hình cổ xưa. Ta đã bị cuốn hút. \n\nTa trở về <location>East Lapis</location> nơi kho lưu trữ có một cuốn sách cổ bụi bặm về những chữ rune mà pháp sư đã viết. Ta nhận ra ngay chữ rune ông ta đã vẽ, và bản dịch của nó đã khiến ta sốc:\n\n<i>RỒNG</i>",
    [3925982957] = "Liều Thuốc Chữa Độc Tố",
    [3926179316] = "Quặng quý được giấu trong lòng đất Embervale. Chế tạo và <b>trang bị một cây cuốc</b> để khai thác các mỏ quặng. \n\nCác quần xã sinh vật khác nhau sẽ cung cấp nhiều loại quặng. Tiến bộ qua thế giới để gặp gỡ các vật liệu tốt hơn và tiên tiến hơn. Các <b>quặng có giá trị hơn</b> có thể được tìm thấy <b>bên dưới Sương độc</b>.",
    [3926324759] = "Cây cung dài tuyệt hảo này sử dụng rất tốn sức, nhưng nó tấn công với sự hung dữ của một con sói.",
    [3926387727] = "Thịt Nấm",
    [3926720356] = "Một giá đỡ chiến tích, dùng để chống đỡ bộ xương của một gã Khổng Lồ.",
    [3926802994] = "Đã tìm thấy <craftingstation>Máy Xông Ong</craftingstation>. Nó phải được đặt trong căn cứ để mở khóa <craftingstation>Tổ Ong Mật</craftingstation>, cho phép cung cấp mật ong đều đặn.",
    [3927246117] = "Chế Tạo Mồi Câu Cá Mèo",
    [3927309581] = "Găng Tay Huyền Bí",
    [3928213629] = "Không thể đọc nếu không có Bình Flask Bảo Vệ Linh Hồn Drak",
    [3928482930] = "Cây Giống Hoa Cúc Chamomile",
    [3928741338] = "Quay Lại",
    [3929515142] = "Mạng Nhện IV",
    [3929628837] = "Thiết Bị Lặn",
    [3929830316] = "Bình Máu Lớn +",
    [3929869331] = "Một vật che đầu đơn giản để thấm bớt mồ hôi khó chịu. Giữ cho đôi tai quý giá của bạn tránh xa những thanh sắt nóng bỏng!",
    [3930044555] = "Tìm <keyitem>Ấm Nước</keyitem> Trong <location><lorename>Phạm Vi Pikemead</lorename></location>",
    [3930393712] = "Tìm Hiểu Kẻ Xâm Nhập Đến Từ Đâu",
    [3930573097] = "Hồi HP Khi Nhặt Quả Cầu",
    [3932365329] = "Giảm tốc độ di chuyển. Bạn đang chìm trong nhựa đường!",
    [3932535709] = "Một chiếc băng đô màu vàng giữ cho tóc bạn không bay vào mặt khi săn bắn hoặc đốn gỗ.",
    [3932711393] = "Một Cái Nhìn Cổ Xưa, Được Tái Khám Phá",
    [3933103802] = "Trông đẹp đấy.",
    [3933845572] = "Tủ Búp Phê Lâu Đài Nhỏ",
    [3934650307] = "Trở Lại Với Nhà Giả Kim",
    [3934700257] = "Đổi Trang",
    [3934847117] = "Giày Thợ Săn",
    [3934980882] = "Con cá màu đỏ rực này được đánh dấu bằng các sọc đen. Vảy lấp lánh của nó giống như than hồng đang nguội dần, mang lại cho nó cái tên \"Cá Than Hồng\".\n\nCon cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [3935388248] = "Thùng Da Lớn",
    [3935509066] = "Anh hùng của chúng ta!",
    [3935990180] = "Con thú chạy trong huyết quản của bạn! Bạn gây thêm sát thương lên Scavenger và được củng cố chống lại độc tố của chúng.",
    [3936212160] = "Người Giúp Đỡ",
    [3936512637] = "Ly Bạc",
    [3936869571] = "Một phiên bản được đánh bóng cao của khối đá granit. Những khiếm khuyết có thể có đã được loại bỏ phần lớn, tạo ra một lớp hoàn thiện liền mạch hơn.",
    [3936930802] = "Một <b>mũi tên đặc biệt</b> mang đến một bất ngờ bùng nổ.",
    [3937514996] = "Mồi Nhử Sinh Vật",
    [3938991857] = "Bạn đã đến The Pike! Đã dọn sạch nỗi kinh hoàng đó, tôi hy vọng? Một tinh thần thép tuyệt vời bạn có! Tôi cảm thấy một gánh nặng lớn trút bỏ khỏi tâm hồn mình.",
    [3939025880] = "Đi Theo Con Mèo Đến <location>Bãi Biển Sapphire</location>",
    [3939183937] = "Theo Nông Dân, nướng cá làm chúng bổ dưỡng hơn nhiều — chúng thậm chí có thể tăng mức Oxygen của bạn. \n\n<b>Nấu một con cá tại lửa trại, sau đó ăn nó để thấy hiệu quả.</b>",
    [3939471419] = "Bình Cốt Vàng Điềm Báo Bất Thường",
    [3939587859] = "Các Loại Giáp",
    [3939822214] = "Phục hồi SP tăng.",
    [3940509354] = "Đèn Sàn Phòng Ngai Vàng",
    [3940992715] = "Thợ Săn <npc>Athalan Skree</npc> giúp bạn chế tạo giáp và tạo ra trang bị để sinh tồn.",
    [3941001707] = "Găng Tay Thợ Săn Hươu",
    [3941326742] = "Cay, ngọt và đầy sức mạnh — gừng tẩm đường này là một món ăn nhẹ tuyệt vời cho bất kỳ ai không sợ hương vị mạnh mẽ.",
    [3941414861] = "Được cho là sinh ra từ sét đánh vào mặt nước, Cá Sốc được tích điện năng lượng điện. Hãy cẩn thận khi cố gắng kéo nó ra khỏi nước.\n\nCon cá này có thể được nướng hoặc sử dụng trong công thức nấu ăn.\nNó cũng có thể được thả trở lại nước và nuôi trong ao.",
    [3941928895] = "Nếu bất kỳ linh hồn nào tìm thấy điều này, hãy lưu ý: <location>Pháo Đài Kelvin</location> đã thất thủ trước Vukah. Chúng ta đã chiến đấu dũng cảm, nhưng lũ quái vật tỏ ra quá mạnh mẽ — chúng có một hào quang sức mạnh phi thường. \n\nNếu bạn phải đối mặt với chúng, tôi cầu xin bạn hãy tìm ra nguồn gốc sức mạnh siêu nhiên của chúng, bức tượng nơi chúng hiến tế cho các vị thần khốn khổ của chúng. Liệu điều đó có đủ để xoay chuyển tình thế hay không, tôi không thể nói...",
    [3942225866] = "Hồi phục %k MP mỗi 5 giây.",
    [3942503694] = "Khu Vực Nghiên Cứu Cột Trụ Sáng Tạo",
    [3942584753] = "Bàn Thờ Ngọn Lửa",
    [3942667062] = "Nghiên cứu Cột Đá Cổ Đại Bắt Đầu",
    [3942826167] = "Hình dạng tòa nhà chung",
    [3943180204] = "Lên Cấp Ngọn lửa",
    [3943291961] = "Mũ trùm đầu bắn cung này cho phép bạn quan sát các đỉnh núi và thung lũng như một con diều hâu. Không gì có thể thoát khỏi ánh mắt cảnh giác của bạn!",
    [3944010327] = "Khối Gỗ Thô",
    [3944537745] = "Điều Tra Địa Điểm Biểu Diễn Cuối Cùng Của Ban Nhạc Honeydew",
    [3945586955] = "Dao Găm Phủ Băng",
    [3945791731] = "Băng Gạc Sạch",
    [3946283797] = "Đây là một ý tưởng khác...",
    [3946382312] = "Một lò sưởi sẽ cung cấp đủ hơi ấm. Hơi ấm cần thiết để có được hiệu ứng Nghỉ Ngơi.",
    [3946863399] = "Tỷ lệ chí mạng vũ khí tầm xa tăng <b>10%</b>.",
    [3947720138] = "Bàn Hầm Mộ Lớn",
    [3947857778] = "Mũ Nông Dân",
    [3947994969] = "Sinh tồn là một chuyện, Hỏa Sinh. Phát triển thịnh vượng là một câu chuyện hoàn toàn khác! Và tin tôi đi, tôi biết tất cả về những câu chuyện! Chúng ta có thể chơi những giai điệu thật hay cùng nhau, đặc biệt là nếu bạn trả lại chiếc trống tay cho tôi! Tôi đã đánh rơi nó khi chạy trốn khỏi Vukah... có lẽ bạn có thể tìm kiếm trong các khu định cư của chúng?",
    [3948337055] = "Giữ bí mật của bạn! Tôi sẽ giữ bí mật của tôi.",
    [3948347432] = "Chiếc quần phơi nắng, được vá cẩn thận và khâu bằng chỉ thừa. Vải đã sờn ở một số chỗ...",
    [3948767572] = "Cây sa mạc này chứa một chất lỏng nhờn, được biết là có ứng dụng y học. Dùng trong giả kim thuật.",
    [3949074721] = "\"Hỏa Sinh\"... bạn có biết tại sao họ gọi bạn như vậy không? Bạn được tôi luyện từ một <b>sự kết hợp hiến tế giữa Người Cổ Đại và con người.</b> Linh hồn Ngọn lửa cổ đại cho phép bạn bước vào Sương độc mà không bị tổn hại, nhưng ánh sáng của nó không kéo dài mãi mãi. Với sức mạnh này, bạn có thể xây dựng lại thế giới, bất kể điều gì xảy ra.",
    [3949641311] = "Vai Trò Máy Chủ",
    [3950315097] = "Một vị khách kỳ lạ đã ghé qua hôm nay. \n\nMột người đàn ông khắc khổ, cao lớn và u sầu. Một hiệp sĩ hay lính đánh thuê, mặc dù tôi chưa bao giờ thấy phù hiệu của anh ta ở đây trước đây. Rõ ràng, anh ta đã uống quá nhiều rượu vang — hoặc rượu mạnh, tôi nghi ngờ.\nAnh ta không có vàng, vì vậy tôi đã cố gắng đuổi anh ta đi, nhưng vô ích. Anh ta tiếp tục nói lắp, mắt mở to và đỏ ngầu, chỉ vào chai rượu rum trên kệ cao nhất bằng bàn tay đeo găng của mình, gần như không thể giữ thẳng.\n\nCánh tay anh ta cứ chùng xuống quầy giữa chừng, chao đảo như thể cơ thể anh ta không theo kịp yêu cầu của anh ta, hoặc như thể chân tay anh ta được làm từ những bao tải ngũ cốc ướt.\nBực bội vì sự yếu ớt và thiếu rượu của mình, anh ta giật phăng đôi găng tay và ném chúng qua phòng, gầm gừ. \nTôi nép mình dưới quầy. Khi tôi thấy bàn tay trần của anh ta vươn qua quầy từ bên dưới và nắm lấy cạnh bàn, tôi sợ anh ta sẽ lao về phía tôi... nhưng thay vào đó, anh ta trườn qua, ngã xuống sàn và lết đến giá rượu.\nAnh ta đã đưa chai rượu lên môi trước khi bước qua ngưỡng cửa và lảo đảo trở ra ngoài.\n\nĐôi găng tay của anh ta là dấu vết duy nhất anh ta để lại. Chúng có vẻ có giá trị. Tôi đã cất chúng trên gác mái cho đến bây giờ, phòng khi anh ta quay lại với đầu óc tỉnh táo hơn và túi tiền đầy hơn.",
    [3950700462] = "Chiến Tranh",
    [3950892567] = "Nó phải được đặt bên trong bộ nạp phù hợp.",
    [3951018757] = "Di chuyển đến đây",
    [3951157881] = "Bước Vào Bóng Tối",
    [3951335247] = "Lối Đi Cổ Đại",
    [3951855762] = "Tăng sát thương lên Hollow.",
    [3952203607] = "Chùy Nhỏ Lưới",
    [3952469420] = "Thắp sáng các Cột Đá Cổ Đại sẽ mở khóa các điểm Du Hành Nhanh của chúng.\n\nSau khi điểm Du Hành Nhanh của chúng được mở khóa, Ngọn Lửa trên đỉnh tháp sẽ mang đến cho bạn kiến thức về khu vực xung quanh.\n\nMở bản đồ và chọn Cột Đá Cổ Đại để Du Hành Nhanh đến địa điểm này.",
    [3952566945] = "Trại Drak'Dal",
    [3953292241] = "Không có đạn",
    [3953752243] = "Nhẫn Tham Lam",
    [3953914210] = "Tìm Các Khối Đá Granite",
    [3954188198] = "Cây sáo cũ của Miles Rapore, dùng để trang trí âm thanh cho nhiều buổi biểu diễn âm nhạc của The Honeydews. Ông thường được ghi nhận là người giữ cho ban nhạc gắn kết, nhưng thái độ sống ẩn dật với đám đông và sự tập trung nghiêm ngặt vào khả năng tiếp thị đã mang lại cho ông một danh tiếng xấu.",
    [3954297810] = "Vứt Bỏ và Đóng",
    [3954680898] = "Lời Thề Của Chúng Ta",
    [3954798729] = "Hệ Sợi Nấm Hoạt Động",
    [3955223721] = "Khám Phá Chiến Trường Bên Cầu Cổ Đại",
    [3955234491] = "Một lưỡi kiếm được rèn từ thép đánh cắp của những người lính đã ngã xuống. Nó lan tỏa sự hối tiếc và đau khổ.\n\n<b>Tiếng Vọng Hollow:</b>\nVũ khí giải phóng một tiếng vọng bất thánh, kéo dài phạm vi tấn công một cách kỳ diệu.",
    [3956448704] = "Phép Lát Gạch",
    [3956544914] = "Chất Lượng Siêu Cao",
    [3956687447] = "Chiếc khiên phép thuật này cho phép bạn <b>Đỡ</b> các đòn tấn công vật lý. Đỡ làm tiêu hao SP.",
    [3956846214] = "Quần áo của bạn bị ướt. Hãy làm khô mình bên lửa.",
    [3956921894] = "Cơn bão cuối cùng cũng ập đến, những con sóng sủi bọt đầy căm thù và đánh vào bờ biển của chúng ta.\n\nĐứng trên bệ đèn biển, tôi cảm thấy những cơn gió giật xé toạc bộ râu và áo khoác của tôi. Tôi vẫn còn muối bám trên da từ những cơn gió đêm đó.\n\nNgọn lửa bên trong chiếc đèn dầu có mui của tôi lập lòe, bị khóa trong một điệu nhảy sợ hãi, xoay chuyển và dịch chuyển để không bị dập tắt... một lời cầu xin lặp đi lặp lại mà không có ai lắng nghe, một hành động nhuốm màu vô ích, không khác gì của chính tôi.\n\nThắp lửa. Nhen nhóm ngọn lửa. Lau sạch ống nhòm. Nhìn ra ngoài. Thắp lửa lại. Thật vô ích. Cơn bão dập tắt mọi ánh sáng.\nTôi bất lực bám vào lan can, nhìn ra màn đêm. Đó là lúc tôi nhìn thấy nó.\nNhững ngọn đồi nhấp nhô, không phải làm bằng nước, mà làm bằng vô số cơ thể, nhô lên và hạ xuống theo nhịp điệu của cơn bão. Một con sóng để kết liễu chúng ta. Một con sóng để nghiền nát chúng ta. Một con sóng để nhuộm đỏ đại dương. Một con sóng của Drak.\n\nTôi đánh rơi ống nhòm và nhặt đôi ủng của mình. Nếu đây là bản án tử hình của chúng ta, tôi sẽ không chết với tư cách là người canh đèn biển.",
    [3957293391] = "Phù Điêu Drak V",
    [3957725540] = "Một Tinh Linh Ánh Sáng bị giam cầm. Mở chiếc bình sẽ giải phóng một tinh linh phát sáng để soi sáng bóng tối.",
    [3958437497] = "Các kỹ năng của nhân vật có thể có tính chủ động hoặc bị động và phải được mở khóa từ <b>menu kỹ năng.</b> Để mở khóa một kỹ năng, hãy chọn nó trong cây kỹ năng. Một số kỹ năng yêu cầu các kỹ năng trước đó phải được sở hữu trước khi chúng có thể được mở khóa. Hãy làm theo các kết nối trong cây kỹ năng để đạt được các kỹ năng nâng cao hơn.\n\nĐể có được kỹ năng, cần có <b>điểm kỹ năng</b>. Nhận điểm kỹ năng bằng cách <b>lên cấp hoặc bằng cách đánh bại Rễ Sương Độc</b>.",
    [3958668682] = "Kẻ Đập Huyết Trận",
    [3958948774] = "Mỏ Aquamarine",
    [3959152003] = "Flameborn, sức mạnh của chúng ta vẫn đang phát triển. Nhờ bạn, ánh sáng của chúng ta vươn xa hơn cõi trần. Nó nhảy múa ở ranh giới giữa sự sống và cái chết, tìm kiếm những linh hồn đã mất chưa bị Sương độc hoặc Tinh hoa chạm tới. Hãy tìm một linh hồn như vậy và mang nó về! Xây dựng lại thế giới này và cai trị một cách công bằng!",
    [3959457340] = "Quảng Trường Lừa Gạt",
    [3959720977] = "Giày Thợ Săn Quetzal",
    [3960361111] = "Một lưỡi kiếm gãy, được nhặt từ đống đổ nát và tro tàn của thế giới cũ. Nó vẫn có thể gây sát thương đáng kể khi rơi vào tay kẻ xấu.",
    [3960687980] = "Ư! Tôi mệt quá... và chán quá! Tôi cần một tách cà phê để tỉnh táo! Không đồ lặt vặt, không thứ gì cầu kỳ — chỉ một ly espresso tinh khiết, tuyệt đẹp. Bạn không thể mang cho tôi một ly sao? Tôi thậm chí còn chỉ cho bạn biết phải tìm ở đâu! Hạt cà phê ngon nhất đến từ Vịnh Stillwater, thấy chưa? Họ hẳn phải có văn hóa về cà phê. Họ biết cách sống, tôi nói cho bạn biết!",
    [3960847617] = "Bạn bị ngập một phần, khiến bạn chậm lại.",
    [3961085984] = "Leo lên những tầm cao mới",
    [3961193426] = "Máy Bơm Nước Di Động",
    [3961197406] = "A, vẻ đẹp không gì sánh bằng của ta: những viên ngọc sáng này ta đeo!",
    [3961449341] = "Bảng màu tím điện này có cùng sức sống với một viên thạch anh tím nguyên sơ.\n\nBảng màu này có thể được tạo ra với vật liệu từ Đỉnh Albaneve.",
    [3961664999] = "Thêm sát thương <b>chí mạng</b> vào đòn tấn công tiếp theo",
    [3961856565] = "Tìm Bộ Trang Phục Thẩm Mỹ Của Vị Khách",
    [3962412474] = "Tăng cường Chữa thương <b>Hào Quang Nước</b> lên <b>2</b> HP mỗi <b>2</b> điểm Trí Tuệ.",
    [3962605444] = "Đang sản xuất",
    [3962677495] = "Điều tra Hang Động Gần Đó",
    [3962749052] = "Khối Sa Thạch Tinh Chế",
    [3963054774] = "Mỗi hơi thở sâu chúng ta hít vào đều nhuộm không khí lạnh lẽo thành một lớp bụi lấp lánh. \nÂm thanh răng rắc theo chúng ta đến mọi nơi chúng ta đặt chân. Những viễn cảnh về sự khốn khổ và mất mát khiến tôi rùng mình. Mỗi bước tiến về phía trước giống như nhảy vào sự hủy diệt, và thế nhưng, chúng ta vẫn tiếp tục.\n\nBerhtolf có thể vẫn đang cầm cự, chờ đợi sự giúp đỡ của chúng ta, đâu đó phía sau làn sóng kẻ thù và những rào cản pha lê. Hoặc ông ấy có thể đã đi xa.\n\nSự đảm bảo duy nhất của tôi là chúng ta đang đi đúng hướng. Dấu chân và xương cốt đánh dấu con đường của những người đã đi qua đây trước chúng ta. Tôi cầu nguyện rằng những vết nứt trên băng phía trước sẽ không dẫn chúng ta đi sai đường.\n\nLando Dimweald",
    [3963372848] = "Bạn đã tìm thấy ngôi đền Drak mà người Thợ Mộc đã đề cập. Bây giờ bạn phải tìm cách vào bên trong.\n\nHãy mở mắt ra! Nếu bạn gặp khó khăn trong việc tìm lối vào, hãy cân nhắc áp dụng một góc nhìn khác —<i> có lẽ là từ dưới lên?</i>",
    [3963694326] = "Một mảnh vụn lông thú nhỏ.",
    [3963918648] = "Một Cái Nhìn Thoáng Qua Vĩnh Hằng",
    [3964129544] = "Rơi ra từ kẻ địch Sảnh Hollow Revelwood",
    [3964168390] = "Bò Tây Tạng Con",
    [3964884685] = "Khung Cửa Sổ Bằng Sắt Tròn",
    [3965013671] = "Sử dụng Kẹp",
    [3965508101] = "Trang Trại Dê Nhện",
    [3965997277] = "\"Vật Tư Nhà Trẻ\"",
    [3966035244] = "Tất cả chúng ta đều mệt mỏi và thiếu ngủ — nhưng tôi đảm bảo với bạn, tôi sẽ sớm có thêm thuốc và phương thuốc, xin hãy kiên nhẫn. <i>Bạn có thể đến lấy chúng tại tòa tháp.</i>\n\nTôi nhận thấy một số bạn đang hướng tới những phương tiện bảo vệ không lành mạnh. Tôi cầu xin bạn kiềm chế những biện pháp cực đoan như vậy. Các giải pháp chợ đen cực kỳ nguy hiểm và không ổn định và tôi không muốn ai bị thương! <i>Bạn không thể biết việc tiêu thụ những loại thuốc tiên này có thể gây ra điều gì!</i>\n\n— Balthazar",
    [3966916380] = "Kho Báu Đền Thờ",
    [3967233434] = "Tìm hiện vật Sảnh Hollow Revelwood",
    [3967277362] = "Đạn Cung",
    [3967384758] = "Áo Giáp Mùa Đông",
    [3967512927] = "Bạn không thể tiếp tục nếu không có Móc leo ở đây. Hãy tìm một con đường khác qua Sương độc.",
    [3967784213] = "Một khối xây dựng thường được người Drak sử dụng, đặc biệt là Drak'Dal.",
    [3967842804] = "Màu Tím Bí Ẩn",
    [3968223786] = "XP Nhiệm Vụ & Khám Phá",
    [3968777985] = "Tăng cường tên lửa cùn",
    [3968857487] = "Một món súp bí ngô ngon tuyệt. Nó béo ngậy và đậm đà hương vị. Nó cũng sẽ giữ ấm cho bạn. Còn gì tuyệt hơn nữa?",
    [3968906997] = "Cài đặt sẵn:",
    [3970340885] = "Một vật liệu đường để xây dựng những con đường núi đá.",
    [3970390962] = "Cuối cùng, chỉ có vài người có thể được cứu khỏi Hầm Lò Tro Tàn. Phần còn lại của nhân loại đã bị Sương độc nuốt chửng, bị Ám Ảnh ăn mòn, thứ đã làm ô nhiễm vùng đất. Mặc dù thành trì cuối cùng của nhân loại có thể đã suy yếu, nhưng vẫn có hy vọng rằng Hỏa Sinh vẫn có thể mang ánh sáng đến Embervale một lần nữa.",
    [3970543888] = "Xem Truyện Tham Khảo",
    [3970667115] = "Tìm Kiếm Chó",
    [3970696688] = "Trên đường đi",
    [3970763195] = "Đó là ngày của Lễ Tuyển Chọn. Các Cổ Nhân đến lúc hoàng hôn, khoác áo choàng, và khuôn mặt của họ ẩn dưới những chiếc mũ vàng. \nCon trai bé bỏng của tôi, Ethan, đã hoàn toàn tập trung.\nKhi câu đố được đưa ra, nó đã trả lời trước khi bất kỳ ai khác kịp nắm bắt. Tôi nghĩ tôi thậm chí còn cảm nhận được một chút ngạc nhiên từ các Cổ Nhân trước tốc độ câu trả lời của nó.\n\nNó luôn khác biệt—dịu dàng, tò mò, không thích đấu kiếm, không hứng thú với trò nghịch ngợm. Trong khi những đứa trẻ khác mang về những vết xước đầu gối, nó mang về những câu hỏi. Những bà mẹ khác gọi nó là kẻ mơ mộng, hoặc nói \"Sách vở sẽ không cho bạn mái nhà để ở.\" Nhưng tôi thấy tiềm năng của nó.\nVà vào ngày này, các Cổ Nhân cũng đã thấy điều đó.\n\nHọ đã chọn nó làm \"Học Giả của Thiên Giới\".\nMột trong số ít người thánh thiện—những người bảo vệ tri thức, những người giữ gìn sự thật.\nBây giờ họ thì thầm tên nó với sự kính trọng. Ngay cả những người từng chế giễu nó cũng cúi đầu khi nó đi qua.\nNhưng tôi không quan tâm đến những người khác—đó là ánh sáng trong mắt nó, mục đích trong từng bước chân của nó hướng về Thánh Địa Đêm.\nNó có thể đi cùng các học giả bây giờ, nhưng đối với tôi, nó sẽ luôn là cậu bé tò mò đó. Và tôi chưa bao giờ tự hào hơn thế.",
    [3970771012] = "Mất Tất Cả Tiến Trình",
    [3970788042] = "Cột Tổ Tiên Gỗ Drak V",
    [3970908852] = "Cần triệu hồi <npc>Thợ Săn</npc> tại căn cứ để cô ấy có thể bước vào cõi này một lần nữa! Triệu hồi yêu cầu một Gậy phép Triệu Hồi.",
    [3971128288] = "Quyến Rũ Vĩnh Cửu",
    [3971214576] = "Xây, uống, ngủ. Xây, uống, ngủ. Lén lút đi uống thêm. Bị bắt. <i>Xây.</i>\n\nChúng tôi đã đứng trên chân từ khi nhặt được những <b>Khối Đá Cát Hỗn Hợp</b> này. Tôi đã lê bước khỏi giường và làm việc không ngừng nghỉ dưới ánh mặt trời chói chang trong nhiều ngày... và <i>tỉnh táo,</i> không kém! \n\nÔng chủ sẽ không cho phép nghỉ ngơi hay vui chơi cho đến khi <b>tòa tháp của ông ta hoàn thành...</b> ông ta tỏ ra nghiêm khắc và đúng mực, nhưng tôi biết ông ta cũng lén lút bỏ việc để lười biếng trong <b>tầng hầm bí mật của mình,</b> quá!",
    [3971410884] = "Những điều nhỏ nhặt mới thực sự quan trọng.",
    [3971611198] = "Đũa Phép",
    [3971720003] = "Ngọc Áp Đảo",
    [3971988777] = "Đừng bao giờ nhìn lại.",
    [3971997270] = "Tăng sát thương lên Scavenger ",
    [3972143794] = "Nghe Kế Hoạch Của Ta, Huynh Đệ",
    [3972364219] = "Thời Gian Độc Tố",
    [3972538449] = "Chất Gelatin Chướng Khí",
    [3972556125] = "Đôi găng tay đệm làm từ vải trắng dày và bảo vệ cánh tay bằng da màu xanh đậm. Một chiếc khóa nhỏ và dây màu xanh lam giữ chúng lại với nhau. Đầu ngón tay được để hở, vì vậy bạn vẫn có thể cảm nhận được nhịp đập của cuộc săn.",
    [3972591743] = "Phát hiện lỗi GPU",
    [3973102970] = "Kẻ địch bị tiêu diệt",
    [3973852681] = "Chi Phí Rút lui",
    [3974162519] = "Đài Lửa Hầm Mộ",
    [3974212821] = "Thực Vật",
    [3975324570] = "Đừng sợ — ta không bị thương. Ta cảm thấy thôi thúc phải đi trước đoàn lữ hành đến <location>Brittlebush</location>! Vâng, ta biết điều đó không phổ biến... có lẽ nguy hiểm, như ngươi nói, thân yêu <lorename>Cyrus</lorename>, nhưng không gì có thể giữ chân ta!\n\nTa đã nói để truyền cảm hứng cho đám đông đang gặp khó khăn! Nhiều người trong số họ đã tận mắt chứng kiến cánh đồng và gia súc của họ bị héo úa. Ta sợ rằng sẽ khó để thu hút sự chú ý của họ, nhưng họ đã bám lấy lời ta như mật vàng. Một trong số họ — một cô gái tóc nâu nổi bật tự giới thiệu là nông dân và đầu bếp — đã lên tiếng và kịch liệt đồng ý với ta. \"Chúng ta phải đi cùng Nữ Hoàng của chúng ta!\" cô ấy hét lên khi đám đông reo hò.\n\nTa lại tràn đầy hy vọng. Ta không thể làm họ thất vọng, <lorename>Cyrus</lorename>, ngay cả khi cuộc hành trình đến <location>Longkeep</location> dài và đầy nguy hiểm.\n\n— <lorename>Jezmina</lorename>",
    [3975373591] = "Một tuyến nội tạng lớn chứa đầy chất độc chết người. Hãy cẩn thận khi xử lý!",
    [3975563168] = "Một chiếc quần. Chúng thoáng khí hơn vẻ ngoài của chúng, cho phép bạn cảm nhận được gió.",
    [3975828399] = "Dì Braelyn",
    [3975854686] = "Một Tình Huống Dính",
    [3975940165] = "Tìm Kiếm Trong Nhà Weaver Để Lấy <craftingstation>Khung Cửi</craftingstation>",
    [3976234986] = "Tạm biệt.",
    [3977404604] = "Búa Diệt Trừ Khai Phát Hiện",
    [3977693311] = "Mũ Giáp Lính Đánh Thuê",
    [3977758851] = "Ánh sáng vàng rực rỡ của chiếc mũ này gợi nhớ đến tinh thần sáng chói của chủ nhân trước đó. Ở Embervale, chiếc mũ này chỉ dành cho những người có tư duy sắc bén nhất, những người có trí tuệ soi đường.",
    [3977942051] = "Vua Lập Quốc",
    [3978373211] = "Bóng Tuyết",
    [3978438687] = "Bà tôi, Hama yêu quý, thường kể cho tôi nghe những câu chuyện về <b>Ngôi Đền Lửa Cổ Xưa ẩn mình trên núi</b> đâu đó về phía đông nam từ đây. Ngay trước khi tôi chìm vào giấc ngủ, bà sẽ ru tôi bằng những lời hứa về những cuộn giấy thiêng, những cuốn sách bị lãng quên và những lời cầu nguyện... một minh chứng khô héo cho sự sùng đạo của con người! Những kỷ vật và đồ trang sức, những lễ vật lấp lánh trong ánh sáng ấm áp của ngọn lửa.\n\nNếu thực sự đúng là một ngôi đền nổi tiếng như vậy đã bị lãng quên... có lẽ tôi có thể tìm thấy nó! <i>Thu phí vào cửa!</i> Thu thập một phần trăm! Một đồng cho mỗi lời cầu nguyện nghe có vẻ không tệ, phải không? Không đảm bảo! <i>Đó là tinh thần Conway, tôi nói vậy!</i>",
    [3978635547] = "Nhấn Để Nói",
    [3978684667] = "Nhẫn Thể Lực Lớn",
    [3979147667] = "Tìm Tất Cả Vật Phẩm Trang Phục Thợ Khai Thác Gỗ",
    [3979383288] = "Đừng quên lấp đầy bụng bằng thức ăn ấm trước khi bạn ra ngoài!",
    [3979561273] = "Một cây Gậy phép đã được tìm thấy ở <location>Low Tide</location>. Nó thuộc về một người tên là <b><lorename>Kẻ Lang Thang Bí Ẩn</lorename>.</b>",
    [3979872644] = "Người Câu Cá có thể chế tạo cho bạn một Cần Câu Tuyệt Hảo. Với đó, và Ếch làm Mồi Câu, bạn sẽ có thể câu được những con cá tuyệt epic — nếu kỹ năng của bạn đủ. \n\n<b>Hãy để Người Câu Cá cung cấp cho bạn một Cần Câu Tuyệt Hảo, sau đó nói chuyện lại với ông ta.</b>",
    [3980400039] = "Lăng Mộ Hollow Ẩn Giấu",
    [3980453661] = "Mặc dù không còn rực lửa nhưng thanh kiếm ma thuật từng này vẫn còn lưỡi sắc bén.",
    [3980555175] = "Chó Ướt Sũng",
    [3980558256] = "Lông Cứng Chuột Lang Nước",
    [3981827201] = "Một vật liệu đường bằng đá trông gồ ghề được làm từ những tảng đá lởm chởm. Hãy cẩn thận nơi bạn bước chân!",
    [3981910789] = "Vinh Quang Cho <lorename>Pikemead</lorename>!",
    [3982085488] = "Tôi nghĩ Vùng Đất Mùa Xuân an toàn, nhưng đồng ruộng của chúng tôi trống rỗng. Mọi người đã đi đâu? Trước khi tôi kết thúc sớm, <location>Pháo Đài Kelvin</location> là thành trì hy vọng của chúng tôi. Bạn đã đến đó chưa? Còn ai không? Có lẽ ai đó giống tôi, một linh hồn lạc lối vẫn đang bám víu..?",
    [3982157125] = "Một Con Gấu Bông Cho Emily",
    [3982346611] = "Cây Giống Ớt Chuông",
    [3982363898] = "Cống Thoát Nước Sàn",
    [3982523415] = "Sản xuất",
    [3982772139] = "Mũ Trùm Nanh Sói",
    [3982867717] = "Một Cái Chết Vinh Quang",
    [3983480508] = "<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.",
    [3983512646] = "Một cánh cổng đơn giản để kiểm soát dòng chảy của nước.",
    [3983604796] = "To Lớn Hơn Cuộc Sống!",
    [3983681487] = "ST Phép Lửa khi bị Sương độc bao phủ",
    [3983951852] = "Nếu bạn không tìm thấy máy chủ mình đang tìm kiếm, vui lòng thêm người chơi đang host làm bạn bè trên Steam.",
    [3984095609] = "Khiên Tâm Linh",
    [3984107868] = "Kẻ Thu Thập tin rằng bạn quá ngây thơ để đối mặt với những nỗi kinh hoàng của Hư Không, sự vắng mặt của sự sống. Theo họ, việc bảo tồn những ký ức về Embervale là vô vọng, vì mọi thứ cuối cùng đều chìm vào bóng tối.\n\nĐể chứng minh hắn sai, bạn cần đến các Đỉnh Albaneve và đánh bại thứ mà Kẻ Thu Thập mô tả là \"xúc tu của vực thẳm\".\n\nĐầu tiên, bạn phải <b>đến ngôi mộ</b> mà hắn đã đề cập.",
    [3984248293] = "Ngọn Lửa Không Ngừng",
    [3984578273] = "Khối Tết Nối",
    [3985059684] = "Một đôi quần có lớp lông cừu bên trong.",
    [3985126499] = "Hỡi Hỏa Sinh, ta thấy ngươi đang trò chuyện với Ngọn Lửa. Có vẻ như ngươi đang hướng tới những vùng đất mới... nếu vậy, xin hãy để mắt tới. Cơ thể già nua của ta đau nhức khi ta nghiền nguyên liệu... Không phải ai cũng có thể trẻ mãi và khỏe mạnh mãi mãi! Có lẽ chúng ta có thể nghĩ ra một cách hiệu quả để phân tách các nguyên liệu mà không cần lao động chân tay...",
    [3985155259] = "Giải Mã Câu Đố Để Nhận Kho Báu",
    [3985203246] = "Mũi Tên",
    [3985484997] = "Mũ Nữ Vắt Sữa",
    [3986709820] = "Bạn đã tìm thấy 3 nhạc cụ sử thi, nhưng vẫn còn thiếu một cái. Nói chuyện với Hugo Vanderhall về những gì bạn tìm thấy!",
    [3986764261] = "Băng Gạc Tốt Hơn",
    [3986895702] = "Người Chơi",
    [3987081298] = "Tháp Phải Vươn Tới Bầu Trời!",
    [3987268312] = "Valory, thi sĩ với nhiều danh hiệu, đã giao nhiệm vụ cho bạn tìm lại những con dao găm bị mất của cô ấy. Cô ấy đã làm mất chúng khi phiêu lưu qua một thung lũng rộng lớn đầy bùn gọi là Vũng Tar.\n\nHãy đến Vũng Tar và khám phá khu vực!",
    [3987333697] = "Cho phép bạn hồi sinh bản thân tại Bệ Thờ Ngọn lửa.",
    [3987341644] = "Trọng Kiếm Hoàng Tử",
    [3987440574] = "Như Trên Trời Thì Dưới Đất",
    [3987615792] = "Chi tiết trong Nhật Ký",
    [3987747333] = "Khối Hắc Diên Thạch",
    [3989076164] = "Dù Tinh thần bạn đi về đâu, xin hãy biết rằng bạn đã tỏa sáng hơn Ngọn Lửa Cổ Xưa khi bạn ban phước cho cuộc đời chúng tôi.",
    [3989693657] = "Sấm Sét",
    [3989769149] = "Bình Thuốc SP",
    [3990039676] = "Một viên đá với nhiều dấu hóa thạch ốc anh vũ lớn. Có một hình xoắn ốc đầy mê hoặc ở mỗi mặt của nó.\n\nBộ sưu tập này được tìm thấy ở Vùng Đất Mùa Xuân.",
    [3990305410] = "Bóng Đổ Ánh Sáng Điểm",
    [3990361791] = "Một Ngọn Hải Đăng Trên Biển Không Ánh Sáng",
    [3990561510] = "Hoàng Tử Ếch",
    [3991319004] = "Cho phép bạn tấn công nhanh hơn với vũ khí 2H.",
    [3991524268] = "Ghế Đẩu Gỗ Thô Sơ",
    [3991858617] = "Cổ Ngữ",
    [3991888751] = "Hồi Máu",
    [3992059665] = "Bộ Pháp Thuật",
    [3992166519] = "Tiệm Hớt Tóc",
    [3992179612] = "Một phần của Giáp Trưởng Lão.",
    [3992285725] = "Hãy chiêm ngưỡng những vùng đất hoang vu đóng băng này, vì những đỉnh núi trắng ngần yên bình đã bị làm tối bởi hơi thở và tro tàn của binh lính. Chúng đã làm mờ bầu trời bằng những đôi cánh cổ xưa và triệu hồi một con mắt ác quỷ bên trong suối nguồn sâu nhất của chúng... Nhiệm vụ của bạn là dập tắt cả hai. Hãy chuẩn bị. Một cái lạnh im lìm bao trùm khắp nơi. Bạn sẽ cần bảo vệ ngọn lửa bên trong mình bằng quần áo ấm, đuốc và thức ăn.",
    [3992948069] = "Thật là một bất ngờ thú vị!",
    [3993059463] = "Cúp Danh Năng Quái Vật Mắt Một Sắt",
    [3993080718] = "Ta đã kêu lên. Hư Không đã đáp lại.",
    [3993873903] = "Bạn đã giải cứu một linh hồn thuần khiết. Triệu hồi họ tại căn cứ của bạn bằng một cây Gậy phép Triệu Hồi.\n\nTrong menu Gậy phép Triệu Hồi, bạn có thể chuyển đổi giữa các danh mục khác nhau. <b>Truy cập danh mục \"Trợ Thủ\"</b> và triệu hồi Fenrig. Nói chuyện với anh ta sau đó!",
    [3994046145] = "Cờ Lệnh Gắn Tường Tinh Xảo",
    [3994206546] = "Tối Đa MP",
    [3995705743] = "Sushi",
    [3997181797] = "Một cây rìu được tìm thấy trên hộp sọ của bộ xương rồng khổng lồ. Truyền thuyết kể rằng nó đã được sử dụng để giết rồng mẹ, nhưng nó không bị cắm vào hộp sọ của bà khi bạn tìm thấy nó.\n\nCó lẽ vậy là tốt. Các bà mẹ đã đủ đau đầu rồi.",
    [3997278952] = "Vây Sốc Nướng",
    [3998866000] = "Kết Hợp Các Mảnh Bản Đồ Kho Báu Thông Qua Chế Tạo",
    [3999100539] = "Tôi xin lỗi, nhưng tôi cảm thấy quá sợ hãi để quay lại cánh đồng lần nữa. Không phải bóng tối hay làn nước gợn sóng của con lạch. Đó là <i>người đánh cá.</i>\n\nHôm qua, tôi thấy ông ta lướt xuôi dòng. Bộ râu bạc phơ, quần áo tả tơi, và con thuyền chậm rãi nhưng vững chắc khiến ông ta trông có vẻ vô hại. Khi ông ta nhìn thấy tôi bên bờ, ông ta dừng thuyền lại để nói chuyện, đôi găng tay sờn cũ của ông ta nhuốm màu xanh lam từ việc hái những quả mọng u ám tại chỗ của chúng tôi. Tôi hỏi ông ta có sợ rơi xuống cái hố bùn bao quanh cánh đồng không. Đêm tối, và mặt đất nguy hiểm, sau tất cả.\nÔng ta nói <i>\"Không, các vị thần của vực sâu đã ban cho ta may mắn! Họ sẽ trỗi dậy trong ánh sáng, để khiêu vũ với người phàm một điệu waltz cuối cùng!\"</i>, đôi bàn tay xanh của ông ta run rẩy dữ dội. Tôi lịch sự gật đầu.\n\nKhi con sông cuốn ông ta đi, tôi thề sẽ không bao giờ đặt chân lên cánh đồng mọng u ám nữa. <i>Nếu chúng nở vào ban ngày,</i> tôi sẽ không bận tâm - nhưng gặp một người lạ bị bao phủ bởi ánh trăng và sự điên rồ là một chuyện khác! Tôi hy vọng bạn hiểu.",
    [3999485222] = "Tôi không muốn tọc mạch, nhưng tôi nghe loáng thoáng về \"Drak\"? Tôi tưởng chúng đã bị trục xuất khỏi Thung Lũng! Nếu những sinh vật này thực sự trở lại, chúng sẽ khủng bố vùng đất cho đến khi không còn gì cả! Tệ hơn nữa, bạn sẽ quá chậm chạp dưới nước để chống lại chúng! Có lẽ một số loại cây địa phương có thể cho bạn một chút tăng cường?",
    [3999551649] = "Chế tạo một vật phẩm đơn giản.",
    [3999685665] = "Trượng Rễ Cây",
    [3999800919] = "Heo Rừng",
    [4000093711] = "Bạn đã đến đồn bốt lửa. Chắc chắn phải có một căn phòng bí mật nơi có thể tìm thấy mảnh thảm treo tường! Tìm kiếm căn phòng ẩn để lấy mảnh ghép!",
    [4000933863] = "Vầng Hào Quang Nửa Sáng",
    [4001001781] = "Một lớp vỏ bảo vệ phần thịt mềm bên dưới của sinh vật.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Sinh vật Fell, ban đầu tìm thấy ở Albaneve Summits.",
    [4001089721] = "Thanh Tẩy Vũ Khí",
    [4001155615] = "Quả Cầu Xanh Dương",
    [4001228777] = "Bát Gỗ",
    [4001969253] = "Bí Ẩn Đã Được Giải Đáp",
    [4002418863] = "Tối đen như màn đêm nuốt chửng cả những giấc mơ êm đềm nhất. Các điểm nhấn màu tím hoa cà nhạt tượng trưng cho màu sắc của trà hoa oải hương.\n\nBảng màu này có thể được tạo ra bằng vật liệu từ Đỉnh Albaneve.",
    [4002966304] = "Tìm Quán Rượu Của Emily",
    [4003221274] = "Bạn không cần một chiếc lưỡi câu lớn để bắt một con cá lớn.",
    [4004887224] = "Độc Yếu",
    [4005272827] = "Một giọng nói vang vọng qua tủy xương của bạn mỗi khi bạn nắm lấy tay cầm của thanh Kiếm dài.\n\n<i>\"Vua của những kẻ ngu ngốc, hãy nghe số phận đã được báo trước của ngươi: Đầu lâu của ngươi sẽ vỡ vụn, và từ bên trong vòm sọ Hollow, ngươi sẽ nhìn lên qua đôi mắt lật ngược vào linh hồn của mình; một dòng suối rực lửa, phun trào từ những vết nứt.\"</i>",
    [4005824592] = "Đũa Phép Của Darya",
    [4005842108] = "Anh trai — Thuốc Elixir vẫn còn tràn đầy. Sẽ không ai nhận ra tôi đã lấy một ít, phải không? Lại đây và chúng ta cùng uống! \n\nChúc sức khỏe, Samuel.",
    [4006361830] = "Sáo",
    [4006671593] = "Một túi da căng phồng đã được đổ đầy nước. Ném nó để làm người khác Ướt và Sũng Nước!\n\n<b>Ướt</b> \nGiảm 30% SP và Hồi Phục SP trong 15 phút. Nhiệt độ làm giảm thời lượng còn lại.\n\n<b>Sũng Nước</b> \nGiảm 30% SP và Hồi Phục SP trong 30 giây. Cũng giảm 30% Kháng Băng và Sốc nhưng tăng 30% Kháng Lửa.\n<b>Sũng Nước</b> có thể áp dụng cho kẻ địch.\nThời lượng <b>Sũng Nước</b> không thể giảm bằng nhiệt độ, và chuyển thành hiệu ứng <b>Ướt</b> khi kết thúc.",
    [4006900961] = "Cây chùy này gieo rắc nỗi sợ hãi vào lòng kẻ thù với mỗi cú vung.",
    [4006978126] = "Ngươi là ai? Ngươi là bạn, hay thù? Một \"Hỏa Sinh\"? Dù ngươi là ai, ta khuyên ngươi đừng biến ta thành kẻ thù! Ta là Gabrielle Fairburn, một chiến binh và người bảo vệ! Hãy cho ta biết nếu ngươi cần một đối thủ tập luyện. Chỉ cần giữ cho công bằng, được chứ?",
    [4007090875] = "Lông Thú",
    [4007156597] = "Triệu Hồi <npc>Nhà Giả Kim</npc>",
    [4007606806] = "Hình Khối Vừa",
    [4008113253] = "Sử dụng <b>Búa Xây Dựng</b> để xây dựng <b>cấu trúc</b> xung quanh một Bệ Thờ Ngọn lửa bằng khối xây dựng này.",
    [4008369439] = "Báo cáo lỗi",
    [4008476204] = "Cầu",
    [4009273059] = "Ta đã sống lại! Cảm ơn ngươi rất nhiều, Hỏa Sinh!",
    [4009501307] = "Một phần của Giáp Sát Thủ.",
    [4010238239] = "Của tôi <craftingstation>Sổ Tay Cây Cối và Hạt Giống</craftingstation>! Tuyệt vời! Có... có một chút đất trên đó, nhưng không sao! Tôi không ngại làm bẩn tay. Hãy bắt đầu trồng trọt!",
    [4010693344] = "Mật Khẩu Vai Trò",
    [4010712276] = "Tấn công chí mạng bằng đòn đánh lén lên kẻ địch sẽ gây <img gemeffect_poison> độc trong %k giây, gây %k sát thương độc mỗi giây.",
    [4011269241] = "Một người đã bảo vệ ngôi nhà của họ khỏi Scavenger đề cập rằng họ đã giấu một <b>chiếc rương ở đâu đó trong nhà của họ dưới cầu thang.</b> Có lẽ chiếc rương vẫn còn ở đó.",
    [4011535377] = "Đến Giếng Thuốc Elixir",
    [4011704931] = "Bạn đã tìm thấy một thị trấn tên là Riverreach.\n\nNơi này sử dụng nước để cung cấp năng lượng cho một khu phức hợp chế biến gỗ lớn và một nhà máy.\n\n<b>Hãy đến nhà máy và quan sát cách nó hoạt động để tiếp tục!</b>",
    [4012665318] = "Bạn đã tìm thấy một ghi chú và bản đồ chi tiết vị trí của một \"ốc đảo\" gần đó. Hãy đi theo lộ trình của người lữ hành đang tìm kiếm ốc đảo để tìm hiểu thêm!",
    [4012708975] = "Bạn có lý do để tin rằng một trong những ngôi nhà trong Vườn Hoàng Gia của <location><lorename>Pikemead</lorename>'s Reach</location> có một gác xép bí mật, được sử dụng để thực hiện các nghi lễ ma thuật.\n\nTìm cách vào gác xép và điều tra nó!",
    [4013075211] = "Bỏng Ngô",
    [4013237002] = "Từ giờ trở đi, tôi sẽ cần một sự theo dõi để tăng cường sức mạnh của mình. Một nhóm tín đồ lớn hơn, sẵn sàng xây dựng lại và chia sẻ năng lượng, kiến thức, hy vọng của họ. Hãy đi và lan tỏa ánh sáng của chúng ta!",
    [4013265466] = "ST Chí mạng",
    [4013565746] = "Sát Thương Không Vũ Khí",
    [4013966624] = "<craftingstation>Máy Xông Ong</craftingstation> Đã Thu Hồi",
    [4014206914] = "Giày Kẻ Mang Dịch Bệnh",
    [4014248727] = "Găng Tay Người Khôn Ngoan",
    [4015956841] = "Cối Xay",
    [4017000471] = "Kỵ Sĩ Gió",
    [4017696127] = "Ngồi / Che Chắn",
    [4018097198] = "Khối Đá Granite",
    [4018241937] = "Tất cả sát thương <b>Xuyên Thấu</b> cận chiến đều tăng <b>20%</b>.",
    [4018892054] = "Giảm SP của cá bằng cách lái ngược hướng di chuyển của nó với <b>%k</b> và <b>%k</b>.\n\nKhi một phần SP của nó bị tiêu hao, bạn có thể kéo cá lại gần hơn với <b>%k</b>.\n\nLàm cạn kiệt SP của nó trước khi dây câu của bạn bị đứt!",
    [4019139908] = "Nồi Phế Liệu I",
    [4019438735] = "Gửi Kẻ Quấy Nhiễu <location>Brightwich</location>:\n\nNhững ngày tháng ám ảnh của ngươi sắp kết thúc rồi. \nHãy đến đối mặt ta bên ngoài làng vào đúng ngọ ngày mai.\n\n<b>Kẻ nào thua sẽ không bao giờ thấy ánh sáng ban ngày nữa.</b>\n\n<i>Fairburn</i>",
    [4020082579] = "Ngươi bò ra từ một cái mộ à?",
    [4020702205] = "Một hỗn hợp rau củ lành mạnh. Nếu xử lý cẩn thận, nó không chỉ lấp đầy dạ dày.",
    [4021059043] = "Ngươi đã thu thập đủ đom đóm cho ta chưa?",
    [4021502338] = "Tiến Hóa",
    [4021742168] = "Trông Không Tốt Lắm Cho Ta",
    [4021771196] = "Tìm Tất Cả Vật Phẩm Trang Phục Lông Xù",
    [4022966127] = "Đường Ván Tre Nhỏ",
    [4023786686] = "Thư Giãn Đi!",
    [4024349777] = "Xây Dựng",
    [4024463572] = "Những tảng đá phong hóa, hoặc do người Vukah xây dựng hoặc chiếm giữ. Lớp rêu vàng trong các rãnh đá cho thấy tuổi đời của chúng.",
    [4024532994] = "Một mảng rêu xanh mướt tuyệt đẹp. Nó có thể được sử dụng để làm băng gạc hiệu quả.",
    [4024683857] = "Người Chơi Bị Cấm",
    [4024783128] = "Đòn Tấn Công Lén",
    [4024783416] = "Một cây cung tự chế làm từ vật liệu cơ bản. Thật không may, dây cung khá lỏng.",
    [4024881180] = "Cầu Bị Phá Hủy",
    [4025351306] = "Dreadbane, một chiếc búa mạnh mẽ bị Sương độc làm ô uế, được tìm thấy dưới đáy một cái giếng đầy rẫy côn trùng. ",
    [4026021682] = "Một đôi găng tay của pháp sư, được ràng buộc bằng sợi chỉ vàng tẩm ma thuật.",
    [4026220423] = "Cài Đặt",
    [4026430282] = "Cốc Pha Lê",
    [4026520762] = "Leo Núi Tiêu Hao SP",
    [4026658000] = "Nhận một điểm Trí Tuệ cho mỗi hai cấp độ của Ngọn Lửa.",
    [4026883177] = "Thuộc Tính",
    [4027184723] = "Một bản nhạc cho một bài hát kịch tính phù hợp với những đêm ma quỷ.\n\n<b>Bản Nhạc</b>: \nBản nhạc dạy bạn một bài hát mới khi nhặt được. Bạn không cần giữ bản nhạc trong hành trang để chơi bài hát. Tặng nó cho người khác cũng sẽ cho phép họ học bài hát.",
    [4027348030] = "Tìm Tất Cả Thực Vật",
    [4027531889] = "Hồi Phục SP",
    [4027879087] = "Tiến Độ Thế Giới",
    [4028463693] = "Chế Tạo",
    [4028811230] = "Bạn chưa mở khóa những người sống sót thuộc danh mục này",
    [4030092807] = "Cuộn Giấy Vukah Linh Thiêng",
    [4030754181] = "Thay Đổi Danh Mục",
    [4031310741] = "Bạn đã phục dựng lại bản đồ kho báu, và giờ đây bạn có thể nhìn rõ các chi tiết. Bạn có thể thấy một hồ nước có đảo, một con sông, một tháp đá obelisk và các bộ phận của một bộ xương khổng lồ. Toàn bộ dòng chữ ở mặt sau giờ đọc là:\n\n<b>Hồi Ức Của Mae:</b>\n<i>Ngày đầu tiên của mùa xuân không giống những ngày khác\nNhững đỉnh núi nằm yên, liếm vết thương mùa đông\nKhi ánh mặt trời lặn ở phía tây xa xôi\nTrên những cánh đồng nơi nụ hoa đang ngủ say thức giấc nở rộ</i>\n\n<b>Hồi Ức Của Polaris:</b>\n<i>Ta là một vì sao sáng, trôi dạt cao trên bầu trời\nĐể tìm đường đi, ngươi chỉ cần nhìn vào ta\nNhìn xuống thế giới, khó có thể phủ nhận\nKhông có ai bên cạnh khiến tâm hồn ta cô đơn</i>\n\n<b>Hồi Ức Của Orpheus:</b>\n<i>Từng sinh ra là một kẻ lang thang, ta tìm kiếm sự rực rỡ và hạnh phúc\nGiờ ta bị đóng băng trong thời gian, thân thể bị xiềng xích\nQuen với biển bóng tối, sâu trong vực thẳm\nMắt ta đau đớn trong ánh sáng, nên không còn ánh sáng nào có thể tồn tại</i>\n\n<b>Hồi Ức Của Ony:</b>\n<i>Ta bay cao quá, có lẽ ta sẽ không bao giờ hạ cánh\nTa nhảy múa trên mặt trời, toàn thân rực cháy\nCốc của ta luôn đầy, ta sẽ uống cho đến khi chết đuối\nTrong ánh sáng lỏng và sự mê đắm, cho đến khi ta cảm thấy choáng váng</i>",
    [4031743929] = "Quái Vật Hung Tợn",
    [4031845992] = "Săn Tóc Màu: Sắc Xanh Rực Rỡ",
    [4033619223] = "<craftingstation>Cối Giã</craftingstation>",
    [4033970856] = "Thỉnh thoảng",
    [4034339696] = "Búa",
    [4034491755] = "Một vật liệu đường đất đơn giản cho phép bạn trang trí căn cứ của mình bằng những con đường trông tự nhiên.",
    [4034532357] = "Đến Giếng Thuốc Tiên",
    [4035269692] = "Tốc Độ Phát Triển",
    [4035352091] = "Dạo gần đây, cuộc sống thật tẻ nhạt. Nếu chúng ta có một <craftingstation>Lò Xông Ong</craftingstation>, chúng ta có thể <b>chế tạo một <craftingstation>Tổ Ong</craftingstation></b> và làm ngọt ngào ngày của mọi người! Trước khi rời nhà ở <location>Brittlebush</location>, tôi đã đặt hàng một <craftingstation>Lò Xông Ong</craftingstation> và một ít mật ngọt vàng óng, nhưng lô hàng của tôi chưa bao giờ đến! Có lẽ ngươi có thể lấy lại nó cho chúng tôi?",
    [4035626558] = "Tìm Thấy Trong Sảnh Đường Hollow",
    [4035705354] = "Cade Hawthorn",
    [4035843068] = "Bật bóng nhỏ. Tắt chúng giúp cải thiện hiệu suất.",
    [4036484127] = "Tìm Kiếm Chó Ở <location>Shorewatch</location>",
    [4036766355] = "Trang Trại Dê Sương độc bao phủ",
    [4036806418] = "Dây",
    [4037144630] = "Dây Xích Trần",
    [4037284873] = "Bí Ngô Đêm Khô Cốt Nhỏ III",
    [4037390975] = "Bộ Trang Phục Kiểm Lâm",
    [4037794755] = "Làm Phẳng",
    [4038153896] = "Với sáng tạo này, pháp sư đã tiến rất gần đến mục tiêu của mình. Thật không may, ông ta đã tạo ra một chùm tia hồi máu — một chùm tia ban sự sống cho người khác, không phải cho bản thân. Trong tâm trí ích kỷ của mình, đây là một thảm họa. Ông ta đề cập rằng ngôi mộ tiếp theo không còn xa. Ông ta nghe nói nó giống một mê cung, và một số người chạy đua qua đó như một thử thách. Ông ta vui mừng với ý nghĩ rằng nhiều học trò sẽ có mặt ở đó.\n\nNgôi mộ được cho là gần Hẻm Núi Khai Thác về phía Đầm Lầy Đen.",
    [4039776655] = "Bạn đã tìm thấy một ghi chú từ một trại lữ hành ở Vùng Đất Mùa Xuân.\n\nTrước đây, đoàn lữ hành đến từ phía bên kia Trụ Cột Sáng Tạo và có lẽ đã dừng lại nhiều lần trong suốt hành trình. Nếu bạn lần theo dấu vết của họ ở Vùng Đất Mùa Xuân, bạn có thể tìm thấy thứ gì đó có giá trị.",
    [4040219381] = "Một màu xám mát lạnh gợi nhớ đến những bức tường nhà thờ, vĩnh cửu trong vẻ duyên dáng và tĩnh lặng của nó.\n\nBảng màu này có thể được tạo bằng vật liệu từ Kindlewastes.",
    [4040594342] = "Một chiếc lông vũ của một loài chim hoặc sinh vật nào đó. Cân nặng gần như bằng không, nó chắc hẳn phải hữu ích cho việc gì đó.",
    [4040776354] = "Khát Vọng Của Trái Tim",
    [4040817758] = "Một mảnh giáp ngực cân bằng tốt cho phép người mặc phục hồi năng lượng nhanh hơn.",
    [4040970682] = "Đất Đỉnh Albaneve",
    [4041232676] = "Chế Tạo ×%k",
    [4041525894] = "Đôi ủng này được làm cho những người muốn rón rén bước đi trong bụi rậm.",
    [4041860286] = "Muối phủ khắp vách đá khốn kiếp. Nó lấp đầy không khí và biến rượu rum thành nước muối.\nVà thế mà, ta có thể nếm được nó — có thứ gì đó đang chờ đợi ta ở đây. Ta cảm nhận nó sâu trong lòng đá. Một rung động trên đầu ngón tay ta, một nhịp đập. Cùng một cơn giật mà ta cảm thấy trước khi rút ra một quân Át. Ta biết rõ nó.\n\n<i>Một sự phấn khích để phá vỡ chuỗi bất hạnh của ta. Cuối cùng cũng gặp may mắn.</i>\n\nBERTRAM",
    [4042915707] = "Fenny, ta gần như phát điên rồi. SUỐT TUẦN NAY ta đã phàn nàn về lũ sói. Chúng ngày càng táo tợn, lảng vảng quanh nhà vào ban đêm!\n\nTa thề bằng tất cả những gì thánh thiện và tốt đẹp rằng ta sẽ bỏ ngươi lại phía sau, chỉ còn lại súp lúa mạch đen và đậu! <i>Hãy cầm lấy rìu và xua đuổi lũ sói này ngay lập tức!</i>",
    [4043182903] = "Lượng HP nhận được từ phép Chữa thương sẽ tăng lên tổng cộng 300 điểm HP.\nChi phí: 130 MP\nThời gian hồi: 3 giây",
    [4043280988] = "Cựu Binh",
    [4043921037] = "Cuối cùng thì, bớt đi một vài con cũng chỉ là giọt nước tràn ly... nhưng chúng ta phải bắt đầu từ đâu đó, phải không?",
    [4044200131] = "Một chất lỏng đặc, sệt thu hoạch từ Kẻ Lột Xác Sương độc. Đặc tính kết dính dai của nó làm cho nó trở nên thiết yếu để chế tạo áo giáp và gắn kết các vật liệu lại với nhau một cách chắc chắn trong các công thức chế tạo khác nhau.\n\n<b>Nguồn gốc</b>: Rơi ra từ Kẻ Lột Xác Sương độc, lần đầu tiên tìm thấy ở Cao Nguyên Du Mục.",
    [4044327145] = "Rìu Rễ Sâu",
    [4044379342] = "Cho phép lặn nước nhanh hơn khi ở dưới nước.",
    [4044470493] = "Đặt Vào",
    [4044858236] = "Bạn bị nhiễm độc. Bạn nhận sát thương định kỳ.",
    [4044908348] = "Lọc Tên Máy Chủ",
    [4045203080] = "Đèn Treo Xanh Dương I",
    [4045257686] = "Mọi người đều xứng đáng có cơ hội tỏa sáng!",
    [4045404069] = "Đất màu mỡ, tốt cho sức khỏe, giúp tăng đáng kể tốc độ phát triển của cây trồng.\n\n<b>Thoát nước</b>\nVật liệu này <b>thoát một lượng nhỏ nước</b> khi bị tràn.",
    [4045772863] = "Bàn Tay Giúp Đỡ",
    [4045786602] = "Chuột4",
    [4045919079] = "Những con dao găm này được trang trí bằng các khảm pha lê hình mắt, một lời nhắc nhở liên tục cho những người sử dụng rằng Nữ Hoàng Mẹ Vesztah luôn dõi theo họ. Người ta tin rằng bà hướng dẫn bàn tay của họ — đảm bảo rằng chỉ những người mạnh nhất mới có thể nở ra, trong khi những kẻ yếu đuối bị lưỡi kiếm đánh gục.\n\n<b>Sự Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với thuộc tính Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [4046077554] = "Ahh, ta luôn tiếp đất bằng chân, phải không? Ta là \"May Mắn\" Chester Loft! Nhà thám hiểm, nhạc sĩ và bậc thầy của gió!",
    [4046972470] = "Một đôi sandal dây giúp cảm nhận cát và biển dễ dàng.",
    [4047074812] = "Bạn đã cứu được một người sống sót. Đặt họ vào nhà của bạn bằng một <b>Gậy phép Triệu Hồi</b>.",
    [4047106583] = "Yêu Cầu Cấp Độ Trước",
    [4047119882] = "Giày Thuật Sĩ",
    [4047217022] = "Liên Kết Điều Khiển",
    [4048198566] = "Chất Nhờn Chướng Khí",
    [4048451710] = "Khối này được làm từ các mảnh đá cẩm thạch đỏ được đánh bóng mang một vẻ ngoài bí ẩn nhưng duyên dáng.",
    [4049159978] = "Tìm Bản Nhạc Ở Đỉnh Albaneve",
    [4049314015] = "Kháng Băng Thấp",
    [4049452226] = "Chạy nước rút giảm SP",
    [4049504304] = "Bạn đã nhập quá nhiều mật khẩu sai. Hãy đợi một chút trước khi thử lại.",
    [4050122220] = "Giày Bò Tót Đồng",
    [4050513041] = "Cân Bằng",
    [4051333394] = "Một cây Gậy phép khai thác sức mạnh của mặt trời bị che khuất. Nó hoạt động tốt nhất khi chỉ còn lại một phần tư ánh sáng.",
    [4051581448] = "Chặn hoặc nhắm mục tiêu trong một thời gian ngắn mang lại %k kháng vật lý và %k kháng phép, nhưng làm chậm chuyển động đi %k. Bị tấn công hoặc tấn công khi đang được cường hóa sẽ tạo ra một vụ nổ băng gây %k ST Băng và làm chậm kẻ địch, sau đó hiệu ứng cường hóa sẽ bị gỡ bỏ.",
    [4051899279] = "Một khối đá được tinh chế với trình độ thủ công cao nhất, hiếm khi thấy ngay cả trong thời cổ đại.",
    [4052220605] = "Hoa Loa Kèn Ngày",
    [4052359665] = "Trái Tim Sa Ngã Bùng Nổ",
    [4052535591] = "Bạn có thể sử dụng <b>nhảy nước rút</b> để di chuyển xa hơn. <b>Chạy nước rút</b> và lấy đà trước khi nhảy để đáp xuống những bệ đỡ dường như không thể tiếp cận.",
    [4052684211] = "Sát Thương Sét Trên Sét Lan Truyền",
    [4053277446] = "Chiến đấu chai lỳ và hung tợn, những con quái vật Vukah đã tạo ra những Kẻ Đấu Sĩ của chúng thông qua những cuộc đụng độ liên tục. Chỉ những kẻ mạnh nhất mới sống sót.\n\nThu thập nhiều Đầu Kẻ Đấu Sĩ Vukah để chế tạo Cúp Đồng.",
    [4053901041] = "Nữ thi sĩ Valory đã đề cập rằng có những bộ giáp mỹ phẩm rải rác khắp thế giới. Có lẽ bạn sẽ tìm thấy một vài món ở Vùng Đất Mùa Xuân nếu bạn quay lại những địa điểm quen thuộc.",
    [4054750259] = "Mê Cung Obscura",
    [4054777302] = "Bộ Trang Bị Thám Hiểm",
    [4055060732] = "Ta chắc chắn có thể giúp!",
    [4055387792] = "Cuốc Sắt",
    [4055611138] = "Bạn có thể kiểm tra người buôn bán mà tôi đã đề cập không? Mei là một người bạn cũ và đồng nghiệp nghệ sĩ! Bạn sẽ không hối tiếc đâu!",
    [4055885098] = "Tay Chính",
    [4055922217] = "Tạm biệt!",
    [4056090039] = "Máy Lọc Nước Tự Nhiên",
    [4056192790] = "Mang Một Cây Indigo Đến Cho Thợ Cắt Tóc",
    [4056514038] = "Ngọc Trai Và Vàng",
    [4058589598] = "Ngọc Linh Thể",
    [4059265815] = "Hỡi Kẻ Mang Lửa, ta nghe thấy một tiếng vọng xa lạ vang vọng khắp Rừng Thú Vui. Những cành cây quanh co của nó đã nhường chỗ cho ánh sáng xuyên qua. Một con đường mới đã mở ra, nhưng những gì nằm ngoài tầm nhìn bị che khuất bởi rễ cây cổ thụ và dây leo xanh mướt. Hãy phá tan bụi rậm và thắp lên ngọn lửa của ta giữa chốn hoang dã. Hãy đi theo giai điệu!",
    [4060357918] = "Nhà Sưu Tầm",
    [4060495345] = "Chà, nơi này ấm cúng thật đấy! Một mái nhà tốt sẽ cho phép ta làm việc đàng hoàng. Hãy xem ta có thể chế tạo gì cho ngươi!",
    [4060606637] = "Nâng Cấp Vũ Khí",
    [4060998993] = "Đặt Bàn thờ Lửa này phía trên Sương độc để đánh dấu nhà của bạn. Xây dựng bên trong khu vực được đánh dấu xung quanh Bàn thờ Lửa.",
    [4061183015] = "Nút Chuột Phải",
    [4061409582] = "Thoạt nhìn, màu tím hoa cà mờ nhạt bao bọc người mặc trong sự tầm thường. Chỉ có con mắt tinh tường mới có thể nhận ra màu xanh lá cây lừa dối, độc địa ẩn nấp bên dưới.\n\nBảng màu này có thể được tạo bằng vật liệu từ Cao nguyên Du mục.",
    [4062116991] = "Hoa Lạc Tiên",
    [4062531958] = "Xong rồi. Bình Tro Tàn là một cấu trúc tinh vi, vẫn còn dễ bay hơi, nhưng lại tràn đầy tiềm năng và hy vọng. Người phàm đầu tiên bước vào sẽ là nguyên mẫu thực sự của chúng ta, mồi lửa cho một tia sáng mới.\n\nMay mắn thay, <b>Thợ Rèn đã tình nguyện.</b> Ông ấy phải bước vào bình... và ngủ cho đến khi được đánh thức lại, nếu không ông ấy sẽ trượt vào cõi vĩnh hằng.\n\nNguyện cho tro tàn của một thời đại nuôi dưỡng hạt giống của thời đại tiếp theo.\n\nBalthazar",
    [4062711014] = "Chiếc mũ phép thuật này được trang trí bằng những gai kim loại tinh xảo vươn tới các vì sao. Nó chỉ dành cho những bộ óc sáng giá nhất ở Embervale!",
    [4062849602] = "(hát) <i>Ồ, bạn có tìm thấy những bài hát không? Tôi chỉ hát thôi, tôi không tọc mạch đâu. Ồ, đừng hiểu lầm tôi. Hãy tìm những bài hát đó, nếu không tôi sẽ khóc.</i>",
    [4063012665] = "Thợ Mộc đã nói với bạn về khả năng của Drak trong việc tạo ra các màu ánh sáng khác nhau. Ông ấy muốn bạn tìm kiếm nơi ở của chúng và hiểu cách chúng làm được điều đó.\n\nKhi đến thăm các địa điểm của Drak, tốt nhất bạn nên mang theo một Bình Rượu Linh Hồn Drak.",
    [4063098764] = "Có chuyện gì trong đầu sao?",
    [4063289654] = "Khám Phá Trại",
    [4063373087] = "Một cặp dao găm dài với vải quấn quanh cán.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [4064613727] = "Bảng Yêu Cầu Công Dân Công Cộng của Pháo Đài Everfrore",
    [4064798985] = "Di Chuyển",
    [4065063035] = " \"Bóng tối trên Umber Hollow — <lorename>Lupa</lorename>\" được khắc ở mặt bên.",
    [4065527708] = "Tha Thứ Cho Ta, Ngọn lửa Thiêng",
    [4065685618] = "Tìm thêm Lò Rèn Đá Quý để tinh luyện đá quý của bạn thêm nữa.",
    [4065776765] = "Làm Phẳng Mặt Đất M",
    [4065873656] = "Một cặp dao găm đôi tinh xảo được chế tạo để đâm xuyên động mạch với độ chính xác và duyên dáng.\n\n<b>Nhanh nhẹn:</b>\nSát thương gây ra bởi vũ khí này tỷ lệ thuận với chỉ số Nhanh nhẹn của bạn. Bạn có thể thực hiện một đòn tấn công độc đáo sau khi đỡ đòn.",
    [4066004476] = "Cây Brittlebush",
    [4066571854] = "<craftingstation>Cối</craftingstation> Đã Trả Lại",
    [4066771074] = "Hãy thử một phong cách khác...",
    [4066967950] = "Nhầy Nhụa",
    [4067117262] = "Rời Đi",
    [4067208933] = "Ối, tôi đã lỡ nhịp đó rồi…",
    [4067584275] = "Vật Phẩm Truyện Kể",
    [4067897970] = "Chất Lượng XeSS",
    [4068018102] = "Gậy phép có thể niệm <b>phép thuật</b> bằng cách sử dụng các điểm niệm phép và MP. Trang bị <b>điểm niệm phép</b> để niệm phép.",
    [4068346878] = "Mẫu Cúp Dọn Dẹp Mẫu Hệ Đồng Thiếc",
    [4068616609] = "Trượng Trưởng Lão",
    [4068960084] = "Cao Nguyên Du Mục",
    [4069162615] = "Tìm Kiếm Lăng Mộ Bí Ẩn",
    [4069221997] = "Sảnh Hollow Kindlewastes",
    [4069702324] = "datenschutz@keengames.com",
    [4069738062] = "Bên trong mũ bảo hiểm có một chút ẩm ướt kỳ lạ. Có cặn dính ở khắp mọi nơi.\n\nThu thập nhiều Mũ bảo hiểm Mẫu Scavenger để chế tạo Cúp Đồng.",
    [4070542144] = "Ta từng đối mặt với một gã Cyclops lạnh lùng, tai đóng băng! Hãy quây quần bên lửa để nghe câu chuyện rùng rợn này!\n\nTa đã chơi một giai điệu nhỏ đáng yêu tại triều đình của <lorename>Vorgoth</lorename>, làm tan chảy trái tim ông ta thành rượu vang dâu tây đỏ như hồng ngọc! Tuy nhiên, nghệ sĩ giải trí chính của bữa tiệc lại là một gã Cyclops \"đã được thuần hóa\"! Nó bị xích và buộc phải nhảy múa với than hồng nóng hổi từ chính bếp lửa đang nướng bụng lợn và bánh hạnh nhân của chúng ta!\n\n<i>\"Tội nghiệp\"</i> ta nghĩ, đầu óc quay cuồng vì rượu. Khi mọi người ngủ say, ta đã tập hợp lòng dũng cảm mới tìm được và lẻn vào phòng của Người Thuần Hóa Quái Vật, tay cầm đồ mở khóa. Khi ta giải thoát cho gã khổng lồ, nó nhìn vào khuôn mặt xinh đẹp của ta với ánh mắt gào thét <i>\"Ta để mắt đến ngươi!\"</i> trước khi thổi bay một lỗ trên tường ngục!\n\nKhông cần phải nói, ta đã không còn được mời đến triều đình hoàng gia nữa.",
    [4070736528] = "Lời chào từ cối xay. Tôi hy vọng thư của tôi đến tay bạn tốt. Tôi viết thư này để theo dõi một yêu cầu trước đó của tôi liên quan đến danh sách tất cả các tân binh hiện đang bị trưng dụng trong bộ phận gỗ. Vui lòng xác nhận đã nhận được thư của tôi. Chúng tôi có thể đã tìm thấy một trong những chàng trai của bạn.**\n\n**Lưu ý: Xin thứ lỗi cho những hình thức trang trọng. Bạn có biết Steph đã trở về từ chuyến thám hiểm của cô ấy không? Hãy cho tôi biết mọi thứ ở Pháo Đài Everfrore thế nào, bạn già. Cuộc sống văn phòng ra sao?\nNếu bạn có thời gian rảnh, hãy ghé qua. Chúng tôi có một chỗ nhỏ xinh ở đây - đừng nói với thiếu tá - để ủ bia đặc biệt. Nó khá là... bí mật, bạn hiểu chứ. Bạn vẫn uống được nhiều hơn tôi chứ? Tôi nghi ngờ. Hãy chứng minh tôi sai!\n- Trân trọng, Tướng Kent",
    [4070774837] = "Bắt đầu lướt",
    [4070996350] = "Vải Xanh Dương",
    [4071654625] = "Việc \"xây dựng lại thế giới\" thì tuyệt vời đấy, nhưng chúng ta có thể chia sẻ nó với ai? Bạn không cảm thấy trống rỗng khi thiếu đi một người đặc biệt sao? Tôi từng có vợ, bạn biết đấy. Ồ không, tôi không có ý nói về cô ấy. Cô ấy cấm tôi có những chú lùn làm vườn, và một thế giới không có lùn thì không đáng để xây dựng lại. Tôi không đùa đâu. Tôi cần một chú lùn.",
    [4071817504] = "Tìm Kiếm Linh Hồn Thuần Khiết",
    [4071856480] = "Một bảng màu khiến bạn cảm thấy như một học giả, lang thang qua những mái vòm đầy hoa tử đằng để lấy mẫu thực vật.\n\nBảng màu này có thể được tạo bằng vật liệu từ Đỉnh Albaneve.",
    [4072200416] = "Bàn Tiện Nghi",
    [4072237728] = "Khối Linh Thể",
    [4072389935] = "Một loại mồi dùng để câu cá thông thường. Nó có mùi lạ.",
    [4072864022] = "Bụi Cây Sợi",
    [4072896271] = "<craftingstation>Lò Luyện Kim</craftingstation>",
    [4073162822] = "Tắt Micro",
    [4073314550] = "Alden Crowley",
    [4073563646] = "Một máy dệt phức tạp cho phép sản xuất vải. ",
    [4073639752] = "Thảm Rơm Lớn",
    [4074082548] = "Giàu protein và ngon miệng, nhưng chỉ là một bữa ăn nhẹ.\n\nTăng nhẹ HP cho người dùng.",
    [4074156500] = "Nhật Ký Emily Fray, Mục 3",
    [4074180872] = "Tử Đằng",
    [4074527235] = "Ô Lá Cọ Bằng Tre",
    [4074831746] = "Mei-Yin Chen là một thương nhân dịp Tết Nguyên Đán bán các mặt hàng theo mùa.",
    [4074961341] = "Một công cụ ma thuật có khả năng <b>thêm và bớt các dấu hiệu mục nát</b> trên tường trong căn cứ của bạn.\n\nNó chỉ có thể được sử dụng <b>trong phạm vi Bàn Thờ Ngọn lửa</b>.",
    [4074990674] = "Trang Bị",
    [4075117505] = "Tủ Ly Gỗ Đánh Bóng Lớn",
    [4075168756] = "Tìm Vũ Khí Trong Trại Vukah",
    [4075240463] = "Tiếp Tục Chỉnh Sửa",
    [4075268568] = "Dây Buộc",
    [4075360715] = "Cung",
    [4075538768] = "Nghệ Thuật Nướng Thịt",
    [4075580300] = "Tăng ST Băng.",
    [4075749811] = "Hãy Quay Lại Với Ta",
    [4076730625] = "Xác định khả năng bị ảnh hưởng bởi lời nguyền.",
    [4077130382] = "Vật Liệu Mái Nhà",
    [4077325949] = "Mũ Học Việc <npc>Nhà Giả Kim</npc>",
    [4078349083] = "Sự pha trộn giữa đá lửa và đá bazan, với một chút oải hương phai màu.\n\nBảng màu này có thể được tạo bằng vật liệu từ Rừng Thú Vui.",
    [4078384024] = "Mũi Tên",
    [4078679501] = "Bộ lọc Sương Độc",
    [4078934194] = "Vượt Ngục",
    [4079134965] = "Giỏ I",
    [4079788091] = "Hoa Gắn Tường Trắng",
    [4079812408] = "Có một tòa nhà lớn ở trung tâm Thành Phố Cổ Xưa Chìm Đắm. Khám phá khu vực và tìm cách vào bên trong để tìm người sống sót!",
    [4079812498] = "Bình Thường",
    [4080100912] = "Hàng Rào Cọc Gỗ Cao III",
    [4080125408] = "Một Khởi Đầu Mới!",
    [4080159255] = "Chậu Cây Vừa",
    [4080226624] = "Tham Gia Phiên Chơi",
    [4080695096] = "Có thứ gì đó thối rữa đang ủ bệnh bên dưới tàn tích này, và lần này tôi không nghĩ đó là Sương độc. Mùi hôi ở các tầng dưới thật kinh tởm. Các nhà vệ sinh ở đó chỉ tồn tại để chế nhạo tôi bằng những luồng khí khủng khiếp, bốc lên.\n\nKhi đối mặt với một cái, mùi hôi đã chiếm lấy tôi và ra lệnh cho cơ thể tôi quay lại, chạy lên cầu thang tầng hầm và hít thở không khí trong lành bên ngoài.\nTôi đã phải giải tỏa bản thân trong bụi rậm.\nThật kỳ lạ. Tôi nghĩ tôi đã nhìn thấy thứ gì đó <i>lấp lánh ở dưới đó,</i> nhưng có lẽ thị lực của tôi bị mờ đi bởi làn khói. Tôi đang bị cám dỗ để đi xuống một lần nữa — Có những con kênh bên dưới không? Nước thải cho phép chất độc phân hủy và mục nát? Kho báu ẩn giấu, bị cuốn trôi, nhưng không bao giờ bị xỉn màu? — Nhưng tôi buồn nôn khi nghĩ đến điều đó.\n\nMặt trời đang lặn. Tôi sẽ mạo hiểm ở lại qua đêm. Trên mặt đất có ít chỗ che chắn, nhưng nó cách xa mùi hôi!",
    [4081503593] = "Sản phẩm cuối cùng của các thí nghiệm hóa học, những tinh thể lấp lánh như bọt biển lung linh.",
    [4081581713] = "Ngừng cái hàm răng run rẩy của ngươi lại và nghe đây. Ta có một kế hoạch để lấy lại phước lành của Ngọn lửa Thiêng và dỡ bỏ lời nguyền khủng khiếp này!\n\n<b>Đầu tiên, chúng ta sẽ làm một cái lư hương thật đẹp, một cái đèn chùm</b>, và vô số nến. Thứ hai, chúng ta tìm một kẻ yếu đuối xương xẩu, kẻ đã không uống đủ sữa khi còn nhỏ. Thứ ba, chúng ta đập nát hắn. Thứ tư, ném xương cốt tội nghiệp, mỏng manh của hắn vào hố Ngọn lửa như một lễ vật thánh và NHẢY CHO ĐẾN KHI Ngọn lửa Thiêng tha thứ cho chúng ta!\n\nChúng ta có thể tụng kinh, nhưng bài hát duy nhất ta biết là \"Ode to Pikemead\". Nếu bạn biết một vài giai điệu của nhạc sĩ Val, hãy tham gia cùng nhé!",
    [4081929133] = "Phụ Kiện 1",
    [4082148332] = "Lối Chơi Chung",
    [4082313639] = "Lũ Hollow điên loạn bị thúc đẩy bởi sự oán giận. Chúng phải được giải thoát, trả về với vòng xoay của số phận. Chém tan cơn giận rực lửa của chúng! Bẻ gãy những ngón tay nhợt nhạt của chúng như xương ước! Giật lấy những chiếc răng vàng trên hàm chúng, và mang cho ta cái đầu của <b>quái vật một mắt</b> ẩn mình giữa chúng để chúng ta có thể uống từ hộp sọ của nó! Hãy tập hợp sức mạnh của ngươi và chế tạo chiếc chìa khóa để tiến xuống.",
    [4082399721] = "Ta biết chúng ta đã chia tay không mấy tốt đẹp. Và ngươi biết ta không giỏi ăn nói.\n\nKhi ta nhìn lên bầu trời, ta nhớ lại cách ngươi dạy ta lượn. Nhớ lại xem ta đã sợ hãi thế nào khi nhảy, khi buông mình khỏi mép cảng? Ngươi đã ở đó. Ngươi đã nắm tay ta. Hướng dẫn đòn đánh của ta khi ta rèn chiếc đinh sắt đầu tiên, những tia lửa bay tung tóe. Ngươi chưa bao giờ nao núng.\n\n...Ta không cố ý san phẳng lò rèn của ngươi và đốt cháy tất cả... Ta đã tức giận. Nổi điên. Ta có tính khí của một người mẹ, như ngươi vẫn nói. Ta gửi cho ngươi <keyitem>Dụng Cụ Rèn Đúc</keyitem> mới. Chúng rất tốt! Thật sự rất tốt. Ta đã thử chúng... Được rồi. Ta đang lề mề.\nChúng ta đều biết ta không giỏi nói lời tạm biệt. Một Anders đích thực trong tim, giống mẹ.\n\n— Rochelle",
    [4082861709] = "Những chiếc quần như thế này ban đầu được các tay săn chim ưng nổi tiếng từ thời xa xưa làm cho trở nên thời trang.",
    [4082872476] = "Yến Tiệc",
    [4083199636] = "Ta còn có thể giúp gì cho ngươi?",
    [4083204758] = "Giải phóng để hoàn thành",
    [4083570911] = "Cuộc Săn Tóc Đỏ: Chuộc Tội Đỏ",
    [4083606732] = "Một khối thạch anh tím nguyên chất không có tì vết rõ ràng. Nhìn chằm chằm vào nó mang lại cảm giác mê hoặc, và làm dịu tâm trí.",
    [4083810717] = "Trao Đổi Chất Tốt",
    [4084285288] = "Ba Lô Lớn",
    [4084637033] = "Tìm Muối",
    [4084868611] = "Máu Thối Rữa",
    [4084901564] = "Tăng cơ hội chí mạng đối với kẻ địch bị ướt",
    [4084901779] = "Cuộc Thi Lượn!",
    [4085664234] = "Báo Thù Cho Capybara",
    [4085831523] = "Cột Cờ VI",
    [4085974864] = "Ay, ngươi đã tìm thấy <keyitem>Lò Nung</keyitem> của ta! Hả? Chuyến đi đó quá khó khăn với ngươi sao? Đừng có rên rỉ nữa, Hỡi Kẻ Bùng Cháy! Thắp lại ngọn lửa cần thời gian và sự kiên nhẫn. Ngay bây giờ, chỉ cần <b>chế tạo <craftingstation>Lò Luyện</craftingstation></b> là đủ. Bắt tay vào việc nào!",
    [4085987468] = "HP",
    [4086383655] = "Giảm <b>50%</b> thời gian cần thiết để Quyền Trượng tích tụ phép thuật.",
    [4087317806] = "Thời Gian Trong Sương độc",
    [4087501944] = "Chiếc Dù Lượn này nhẹ hơn và cho phép ngươi di chuyển quãng đường xa hơn.",
    [4087637248] = "Hỗ Trợ Mộc",
    [4087822753] = "Đèn Chùm",
    [4087840087] = "Tìm thấy trong các Đền Thờ và Thánh Địa Ngọn lửa",
    [4087934750] = "<lorename>Morwenna</lorename>",
    [4088474630] = "Tia Lửa",
    [4088829915] = "FSR2 là một kỹ thuật khử răng cưa tiên tiến. Giảm chất lượng sẽ tăng hiệu suất.",
    [4088871842] = "Rafa,",
    [4089064218] = "Cuốc chim gây thêm <b>30%</b> sát thương lên đá, bao gồm cả các mạch tài nguyên.",
    [4089206154] = "Suối Băng Giá",
    [4089246750] = "Tiếp Cận Sảnh Đường Hollow Của Các Đỉnh Núi Albaneve",
    [4089670066] = "Sau khi được kích hoạt, lớp da sẽ hạn chế lượng không khí xung quanh than, khiến nó cháy chậm hơn. Điều này sẽ giữ ấm cho ngươi một lúc lâu.",
    [4089884376] = "Thợ Đá",
    [4090533906] = "Chúng tôi sẽ sớm quay lại để lắng nghe yêu cầu của ngươi.",
    [4090822189] = "Rương Gian Lận (làm đầy lại)",
    [4090946225] = "Rễ Phát Sáng",
    [4091107708] = "Giày Giao Ước Lửa",
    [4091387415] = "Galen Yager, một Scavenger trong trại của ngươi, đã đề nghị ngươi tiêu diệt một nhóm Kẻ Cướp Bóc ở <location>Brittlebush</location> để lấy lại quần áo săn bắn của đồng đội hắn!\n\nTiếp cận địa điểm và tiêu diệt kẻ địch ở đó để tìm 4 vật phẩm trang phục!",
    [4091496230] = "Tìm thấy trong Sương độc Albaneve Summits",
    [4091523834] = "Chăn Nuôi Gia Súc",
    [4091810268] = "Pháo Đài Hóa",
    [4093065518] = "Đầu Khổng Lồ Khô Cốt",
    [4093171177] = "Sữa Lắc Dâu Tây",
    [4093607319] = "Chậu Cây Trống III",
    [4093730927] = "Chế Tạo Lò Nung Cao Tần",
    [4094006766] = "Hãy tưởng tượng niềm vui khi được đeo đầy trang sức... Ta không thực sự biết cảm giác đó thế nào, nhưng ta đoán nó thật tuyệt vời!",
    [4094353031] = "Cây Giống Cây Bám Leo",
    [4094800603] = "Lại đây",
    [4094847197] = "Giày Pháp Sư",
    [4095588322] = "Thông Tin Dung Lượng Thế Giới",
    [4095778380] = "Một <craftingstation>Vạc Đen</craftingstation>",
    [4095824878] = "Tăng cường phép thuật Sốc",
    [4095909581] = "Một Lò Nung Cao Tần Cho Thợ Rèn",
    [4095991224] = "Một bình được ủ từ các vật liệu dưới nước quý hiếm, giúp giảm bớt gánh nặng cho mỗi cú quạt chèo mạnh mẽ.\n\n<b>Giảm tiêu hao SP khi bơi nước rút hoặc lặn nước rút.</b>",
    [4096285488] = "Sự Sụp Đổ Của Fenrig",
    [4096404850] = "Cảm ơn vì đã chơi Alpha Kín của chúng tôi!",
    [4096726301] = "Găng tay chắc chắn, đen như bầu trời đêm. Chúng được trang trí bằng sừng động vật thu thập được trong cuộc săn.",
    [4096776992] = "Tìm thấy trong Sảnh Đường Hollow Của Kindlewastes",
    [4096907214] = "Tượng Nữ Hoàng <lorename>Pikemead</lorename> Mảnh",
    [4097264558] = "Có thể trang bị",
    [4097629876] = "Bình Nước Đất Sét",
    [4097687706] = "Quần Hiệp Sĩ",
    [4098180572] = "Vương Miện Sét",
    [4098297293] = "Mắt Mẹ",
    [4098662854] = "Tham gia một trò chơi trực tuyến",
    [4099606140] = "Thợ Săn cho rằng ngươi phải đổ máu và uống cùng loại máu với Drak để đánh bại chúng trong trò chơi thống trị của chính chúng.\n\n<b>Chế tạo hoặc nhận được Bình Nước Giải Độc Drak để tăng cường sức mạnh chống lại kẻ thù mới!</b> Ngươi có thể tìm thấy công thức tại <b>xưởng của Nhà Giả Kim.</b>\n\nKhi chịu ảnh hưởng của bình thuốc, ngươi cũng sẽ có khả năng <b>hiểu ngôn ngữ viết của chúng.</b>",
    [4100069647] = "Sau khi chạy nước rút trong một thời gian ngắn, các đòn tấn công gây thêm %k sát thương ST Cắt trong %k. Thời lượng được làm mới mỗi khi gây sát thương.",
    [4100202230] = "<b>Wordslinger</b>\nThế là người ta du hành đến các vì sao\n\n<b>InSaint</b>\nMắc kẹt trong vòng lặp tử thần\n\n<b>dietutnix</b>\nCô ấy thực sự không làm gì sao?\n\n<b>Phillychick</b>\nĐỡ đứng di sản\n\n<b>Cloogshycer và Jackpotgal</b>\nĐược chiếu sáng bởi sự hỗn loạn và các tòa tháp bình thường\n\n<b>Chillpaka</b>\nBất khả chiến bại vĩnh viễn!",
    [4100457888] = "Phản Đòn",
    [4100477627] = "Hẹn gặp lại.",
    [4100517107] = "Ngươi có thể liên hệ với cán bộ bảo vệ dữ liệu của chúng tôi theo địa chỉ email sau:",
    [4100562138] = "Chúng ta nói chuyện đi! Ngươi và ta.",
    [4100634465] = "Đã đến ngọn tháp cổ kính ở Kindlewastes.",
    [4100706045] = "Máu Lấy Cảm Hứng",
    [4100712696] = "Argh, nó ở đâu vậy? Ta từng có một cái <b>rương</b> chứa vật liệu có thể tái chế, nhưng nó đã bị lấy mất! Ta nói cho ngươi biết, ai đó đã lấy nó khi ta đang ngủ trong cái kén chết tiệt đó... Hỏi xung quanh giúp ta, được không? Ai đó ở đây là một tên trộm bẩn thỉu!",
    [4101235531] = "Một loài cây trắng gọi là \"Calla Luna\". Đối với một số người, chúng đại diện cho sự trong trắng và chung thủy, trong khi đối với người khác, chúng là biểu tượng của sự gợi cảm.\nTuy nhiên, mọi người đều đồng ý về vẻ đẹp của chúng và việc ánh sáng xanh lục ban đêm của chúng khiến chúng khác biệt với những bông hoa khác ở Nomad Highlands.",
    [4101844898] = "Cặp quần này có đủ không gian để mang theo lưỡi dao lộ ra và chất độc giấu kín.",
    [4101875821] = "Một thiết lập đơn giản cho công việc mài cơ bản. Đặc biệt tốt cho các nguyên liệu cứng.",
    [4101957318] = "Kháng Vật Lý",
    [4102138025] = "Một chiếc áo dài nặng có lót lông.",
    [4102276554] = "Duu, duu, duu, du-du-du, duu, duu, duu...",
    [4102565722] = "Ngươi hiện diện trong từng hơi thở của ta, trong mỗi giọt nước mắt ta rơi, và trong mọi giấc mơ khi ta thức.",
    [4102633378] = "Được rèn từ phế liệu kim loại cũ, nó cho thấy dấu hiệu cải thiện về hiệu suất nhưng vẫn chưa xứng đáng được gọi là một công cụ hữu ích.",
    [4103149523] = "Vị Trí Giày Bùn",
    [4103636540] = "Dao Găm Dịch Chuyển",
    [4103917725] = "Khiên Ngọn lửa",
    [4104014295] = "Phần Thưởng",
    [4104017163] = "Một chiếc bếp sắt chắc chắn làm ấm ngôi nhà ấm cúng của ngươi theo phong cách!",
    [4104754074] = "Trả Lại Quả Mọng U Ám Cho Thợ Cắt Tóc",
    [4104909325] = "Cây đũa phép nghi lễ này thường được sử dụng khi cầu nguyện cho mưa lớn khi hạn hán bắt đầu. Mặc dù điều đó không hiệu quả, bạn vẫn có thể sử dụng nó để gọi sét đánh xuống kẻ thù của mình!\n\n<b>Quá tải:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây sát thương thưởng lên đến phần trăm <i>quá tải</i>. \n\n<b>Đa đạn:</b> \nBắn nhiều viên đạn nhưng với sát thương giảm.",
    [4105321535] = "Áo Giáp Nanh Sói",
    [4105909326] = "Tìm Kiếm Trợ Lý Nhạc Công Ở Cromville",
    [4106705872] = "Gửi Bố,",
    [4107020286] = "Cửa Gỗ Tròn",
    [4107163916] = "Khám Phá Trang Trại Dê Gần Bể Chứa",
    [4107374898] = "Khối Nhà Khung Gỗ",
    [4107687444] = "Cửa Đôi Gỗ Thô Sơ",
    [4108439925] = "Ngươi có muốn hủy bỏ các thay đổi của mình không? Tất cả các thay đổi chưa lưu sẽ bị mất.",
    [4108545628] = "Được Bảo Vệ Bởi Ngọn Lửa",
    [4109031695] = "Dấu ấn của <lorename>Sameth</lorename>",
    [4109194089] = "Dù hỗn hợp có phần kỳ lạ, nó vẫn trông hấp dẫn. Đây là một trong những thứ không ăn được, nhưng bạn vẫn muốn cắn một miếng.",
    [4109304053] = "Một hình dạng Hollow, trống Hollow như bầu trời đêm không trăng, tô điểm cho tay cầm của vũ khí này. Lưỡi kiếm đã bị vấy bẩn, nhưng vẫn từ chối rũ bỏ vẻ sáng bóng như bạc của nó.",
    [4109338963] = "Thợ săn tin rằng bạn có thể kéo dài thời gian lặn sâu hơn với những công cụ phù hợp. Bà ấy tiết lộ rằng quân đội phương Bắc từng huấn luyện các thợ lặn chuyên nghiệp và trang bị cho họ những công cụ phù hợp cho các nhiệm vụ kéo dài.\n\nCác thợ lặn cuối cùng đã được triển khai tại một ngôi đền Drak, nơi đã bị bỏ hoang vào thời điểm đó.\n\n<b>Hãy đến ngôi đền Drak để tiếp tục!</b>",
    [4109560581] = "Tăng tất cả ST Lôi Phép",
    [4109595488] = "Bạn đã phát hiện ra một hố hiến tế tàn khốc dưới chân vách đá gần <location>Pháo đài Kelvin</location>. Tại đó, bạn đã tìm thấy những con dao găm và một bài báo tập trung vào việc nhà vua xử lý sai lầm các mối lo ngại về an toàn của thị trấn.\n\nNói chuyện với Marianne Reed về những phát hiện của bạn!",
    [4109747544] = "ST Cận chiến",
    [4110251903] = "Một cây đàn lute tuyệt vời với những đường trang trí tinh nghịch được đặt cẩn thận. Chúng bật lên như những giai điệu vui tươi trong một ngày hè nắng đẹp.",
    [4110360228] = "Cột Tổ Tiên Gỗ Drak II",
    [4110659923] = "Bảo vệ tăng cường chống lại phép thuật băng giá, ngoài khả năng kháng phép nói chung.",
    [4110846711] = "Đạn dược ma thuật triệu hồi một Thiên thạch Sương độc thảm khốc giáng xuống tối đa năm kẻ địch. Các thiên thạch gây ST Sương độc nặng.\n\n<b>Phép Sương độc</b>: Phép này tạo ra một hiệu ứng làm giảm Thời gian của bạn trong Sương độc.\n\n<b>Phép: Tiêu hao</b> sau khi sử dụng. Trang bị phép và sử dụng <b>MP</b> để niệm phép bằng <b>Gậy phép.</b>",
    [4110889869] = "Sự tàn sát mà bạn đã gây ra cho lũ Drak không hề bị bỏ qua. Bạn đã thu hút sự chú ý của thủ lĩnh chúng. Đã đến lúc thách thức chúng!\n\nBạn có thể tìm thấy thủ lĩnh Drak ở nhiều nơi, <b>nhưng một địa điểm thuận tiện đã được đánh dấu trên bản đồ.</b>",
    [4111138312] = "Đài Lửa Đỉnh Albaneve Vừa",
    [4112389018] = "Ngọc Điềm Tĩnh Lạnh Lẽo",
    [4112729052] = "Phóng to",
    [4112971216] = "Nhiệm vụ Embervale",
    [4113345044] = "Ngồi",
    [4113902315] = "Có lẽ Ngọn Lửa đã bị vấy bẩn suốt đời. Bị chói lòa bởi chính ánh sáng của nó - hoặc có lẽ, đó là chúng ta. \n\nKhiếm khuyết cuối cùng, được nâng lên quá cao so với phần còn lại. Một sự sụp đổ sâu sắc, tàn khốc đến mức sánh ngang với vực thẳm của Vương quốc Starfall. Một thất bại đã xé toạc chúng ta. \n\nChia rẽ, tan hoang. Những người trẻ của chúng ta chìm trong chiến tranh, những người già của chúng ta bị nhốt trong các vì sao. Một tính toán sai lầm. Tro bụi giữa lửa sao, sau tất cả. Chúng ta phải bắt đầu lại.\n\n— Manathor",
    [4114084693] = "Tinh Thần Bình Yên",
    [4114111290] = "Bị đầu độc",
    [4114742801] = "Bộ Trang Phục Quý Tộc",
    [4114988983] = "Cấu trúc đáng ngại — ...chúng ta không thể giải mã ý nghĩa của nó. Caspian, tên khốn đó, đã hỏi về tiến độ của chúng ta — tôi chỉ lắp bắp và bịa ra điều gì đó. Nói rằng đó là <i>cánh cổng dẫn đến các vì sao</i> — rằng Người Cổ đại đã xây dựng nó để mở ra con đường lên bầu trời, được cung cấp năng lượng từ lửa. Tôi nghĩ hắn đã tin. Tôi không muốn Caspian phát hiện ra điều này trước chúng ta... Tôi đã cướp <b>công cụ xây dựng của hắn và giấu chúng trong trại của chúng ta.</b>\n\n Nếu <lorename>Loraine Crim</lorename> ở đây, bà ấy sẽ phán xét tôi, nhưng thôi kệ. Chắc con đập đang bận bà ấy. \n— Nala",
    [4115096937] = "Bạn đã thu thập được một ít len, tôi thấy. Chúng ta có thể dùng nó để chế tạo lớp đệm ấm hơn và áo giáp tốt hơn... hoàn hảo cho những cơn gió buốt giá, tin tôi đi. Để tinh chế len, chúng ta cần một máy quay sợi! Tôi có thể chỉ bạn cách chế tạo nó.",
    [4115686962] = "Trượng",
    [4116755374] = "Một viên pha lê lớn với hào quang đe dọa.",
    [4117828755] = "Chuột Đồng Vùng Đất Mùa Xuân",
    [4118027477] = "Chứa nồng độ Sương độc cao hơn so với bào tử.\n\n<b>Nguồn gốc</b>: Rơi ra từ Fell thông thường, bắt đầu ở quần xã sinh vật Nomad Highlands.",
    [4118553893] = "Chậu Dương Xỉ Trống",
    [4119099381] = "Nhà Giả Kim Của Wickmouth",
    [4119153185] = "Đôi ủng này cung cấp khả năng chống chịu và độ bám khi bị mắc kẹt trong cơn bão tuyết dữ dội.",
    [4119261481] = "Chúng tôi đã đặt chân vào Thánh địa Đêm của nhân loại, vượt qua ngưỡng cửa của nó với niềm vui và sự dễ dàng, chia sẻ kiến thức và tiếng nói của mình.\n\nTuy nhiên, khi những con Drak hung bạo xây dựng đền thờ của chúng trên những bộ xương vỡ nát, những lễ vật của chúng không khiến chúng tôi hứng thú, vì vậy chúng tôi đã ngoảnh mặt đi.\n\nMột trò hề, một thất bại, một bước đi sai lầm định mệnh — vì những sinh vật đã coi đây là một thử thách, và là ân huệ để giành chiến thắng trong trận chiến. Khi chúng tấn công nhân loại để giành lấy sự chú ý của chúng tôi, chúng tôi đã co rúm lại... và thề sẽ không bao giờ chọn phe nữa, ngay cả khi Sương độc xuất hiện.",
    [4119320408] = "Đừng tự lừa dối mình, Flameborn yếu đuối. Bạn vẫn còn gặp nguy hiểm ngoài kia trong Sương độc, vì vậy hãy chắc chắn rằng bạn đến gặp tôi để nâng cấp vũ khí của mình.",
    [4119563664] = "Khám phá Sảnh Đường Hollow",
    [4119604815] = "Nhật ký",
    [4119638524] = "Cổng Dẫn Đến Các Trụ Cột Sáng Tạo",
    [4119932466] = "Những viên đá thô ráp này lấp lánh nhẹ và có phong cách rất mộc mạc.",
    [4120082160] = "SP mỗi giây",
    [4120982421] = "<craftingstation>Niên Giám Thực Vật và Cây Con</craftingstation> Dành cho <npc>Nông Dân</npc>",
    [4122322551] = "Cung Bắn Bạc",
    [4122386302] = "Hiển thị Sản xuất",
    [4122687252] = "Tăng sát thương lên Wildlife và Wildbeasts ",
    [4122778497] = "Giảm HP, nhưng tăng sát thương và hút HP lên Sinh vật Hollow.",
    [4122898226] = "Eureka!",
    [4122989026] = "Chân Nến Đặt Sàn",
    [4124166300] = "Tăng HP tối đa.",
    [4124400867] = "Móc Sát Quái Vật Khổng Lồ",
    [4124574740] = "Bạn đã tìm thấy một ghi chú kể chi tiết về việc chôn cất một người đàn ông bị ám ảnh bởi lưỡi kiếm của mình. Ông ta sở hữu một thanh kiếm Fell từ các vì sao, và cảm thấy như một phần của mình đã mất đi kể từ đó.\n\nÔng ta đã được chôn cất cùng với vũ khí của mình. Hãy tìm nơi an nghỉ của ông ta và lấy lại nó!",
    [4124711985] = "Chuẩn bị Trang Bị Của Bạn",
    [4125307802] = "Bàn Thờ Ngọn Lửa",
    [4125372359] = "Bây giờ bạn đã có mồi nhử thức ăn cho Bò Yak, bạn phải tìm một con Bò Yak! \n\n<b>Có một địa điểm được đánh dấu trên bản đồ nơi có thể tìm thấy Bò Yak,</b> nhưng bất kỳ đâu cũng có thể. Nhiệm vụ sẽ chỉ cập nhật sang trang tiếp theo khi bạn đến khu vực được chỉ định, nhưng bạn có thể hoàn thành nhiệm vụ bằng cách thuần hóa bất kỳ con Bò Yak nào.",
    [4125388474] = "Đòn tấn công của bạn gây thêm sát thương <b>Chém</b>",
    [4125629712] = "Tức thì phục hồi 1 phút thời gian còn lại của bạn trong Sương độc.",
    [4126680669] = "Chọn các tab để điều hướng các kích thước và danh mục hình dạng khác nhau.",
    [4127054386] = "Lò Nung",
    [4127236605] = "Một viên đá cổ xưa đã tồn tại hàng thế kỷ. Nó khiến người ta tự hỏi nó đã chứng kiến những điều gì.",
    [4127618622] = "Cửa Đôi Đồng Đỏ",
    [4127996592] = "Túi này có thể được đổ đầy tại giếng hoặc hồ. Một ngụm nước giúp nạp lại sức mạnh của bạn!",
    [4128231230] = "Dấu chân không rõ trên bùn luôn là điềm xấu, dù người ta có mê tín hay không.\n\nCung cấp sự bảo vệ mở rộng chống lại Sương độc.",
    [4128288737] = "Lô Hội",
    [4128339121] = "Hành động phụ",
    [4128503565] = "Cột Tổ Tiên Gỗ Drak III",
    [4128525303] = "Một chiếc nhẫn tinh xảo với biểu tượng Song Tử — rung động với sự căm ghét dưới ánh trăng.\n\n<b>Hút HP</b>: \nHút HP có cơ hội (được liệt kê ở trên) kích hoạt với mỗi đòn đánh.\nKhi kích hoạt, đòn đánh hút HP sẽ phục hồi 50% sát thương gây ra dưới dạng HP.",
    [4128529030] = "Mảnh Khảm Ngọn Lửa IV",
    [4128910537] = "Runes là những tạo tác huyền bí thu hút và lưu trữ năng lượng ma thuật từ môi trường. Khi được khắc vào vũ khí, chúng <b>tăng cường</b> khả năng của vũ khí, cung cấp nhiều phần thưởng và hiệu ứng khác nhau.\n\nNếu bạn quyết định tháo dỡ một vũ khí, một phần <b>runes có thể được thu hồi</b>, cho phép bạn tái sử dụng chúng và tùy chỉnh kho vũ khí của mình hơn nữa.",
    [4128997334] = "Dừng lại",
    [4129009044] = "Nhiệm vụ mới",
    [4129110137] = "Bí mật! Kho báu! CỬA!",
    [4129352996] = "Hành động",
    [4130585688] = "Hoa Dây Leo",
    [4131070543] = "Sáo Tuyệt Hảo",
    [4131588063] = "Fell Sấm Sét",
    [4132141287] = "Bụi sắt mịn, dùng cho các mục đích chế tạo khác nhau.",
    [4132486009] = "Người ta nói rằng một trong những người dì của <npc>Thợ mộc</npc>, <lorename>Elin</lorename>, đã bị nguyền rủa trong một Đền Thờ Mặt Trời Kindlewastes. Không rõ liệu câu chuyện có bị phóng đại hay không. <npc>Nông Dân</npc>, Emily Fray, đến từ Kindlewastes và có thể có cái nhìn sâu sắc về Đền Thờ Mặt Trời bị ám ảnh.",
    [4133044541] = "Di chuyển Camera tại Lửa Trại",
    [4133377499] = "Kiếm dài",
    [4133792732] = "Bàn Đầu Giường Bằng Tre",
    [4134256696] = "Khiên",
    [4134580337] = "Không có",
    [4135447065] = "Cẩn Thận Với Lô Hàng Này!",
    [4135481963] = "Một cây gậy được chạm khắc từ gỗ. Không nhiều, nhưng tốt hơn là không có gì.",
    [4135785951] = "\"Chữ ký\" của Thợ mộc",
    [4136720914] = "Khối Mái Đá Granite Trang Trí",
    [4137091954] = "Khi bị Ướt hoặc Sũng nước, gây sát thương lên kẻ địch sẽ áp dụng hiệu ứng Sũng nước lên chúng trong %k giây. Gây sát thương lên kẻ địch bị Sũng nước có cơ hội %k gây thêm %k ST Lôi.\n\n<b>Ướt</b> \nGiảm SP và Hồi phục SP <b>30%%</b> trong <b>15</b> phút. Nhiệt độ làm giảm thời gian còn lại.\n\n<b>Sũng nước</b> \nGiảm SP và Hồi phục SP <b>30%%</b> trong <b>30</b> giây. Cũng giảm <b>Kháng băng và Sốc</b> thêm <b>30%%</b> nhưng tăng <b>Kháng lửa</b> thêm <b>30%%</b>.\n<b>Sũng nước</b> có thể áp dụng lên kẻ địch.\nThời gian <b>Sũng nước</b> không thể giảm bằng nhiệt độ, và chuyển thành hiệu ứng <b>Ướt</b> khi kết thúc.",
    [4137260699] = "Phần trăm Hồi máu Hồi sinh",
    [4137346993] = "Trước khi tôi nhận công việc sửa nhà kho, tôi đã đi cùng một nhóm thợ săn. Thật thú vị nhưng không kiếm được đồng nào... Có lẽ hãy kiểm tra trại của họ nếu bạn vẫn đang tìm kiếm người giúp đỡ. Sẽ rất tốt nếu có thêm hỏa lực ở đây!",
    [4137364753] = "Bạn đã tìm thấy một ghi chú đề cập đến một Cột Đá Cổ xưa gần đó. Hãy đến khu vực được đánh dấu trên bản đồ để tìm Cột Đá!",
    [4138090700] = "Nếu ai đó tìm thấy cái này, hãy giao nó trực tiếp cho <lorename>Gormander</lorename>. Tôi và đám của tôi đã XONG và chúng tôi sẽ không quay lại.\n\nLúc đầu, tôi tưởng mình nghe thấy tiếng quân đội phương Bắc hành quân. Dù ý nghĩ đó đáng sợ đến đâu, những gì tôi thấy còn kinh hoàng hơn nhiều.\n\nNhững gã khổng lồ một mắt đang từ trên đỉnh núi của chúng lao xuống, và chúng mang theo mùi thịt cháy và sự thối rữa! Tôi có thể nghe thấy chúng di chuyển như một thể qua thung lũng bên dưới!\n\nKhông biết chúng đang đi đâu, nhưng tôi sẽ không ở lại để tìm hiểu!",
    [4138807975] = "Giáp thiếc lộng lẫy. Vẻ sáng bóng khơi dậy niềm hy vọng.",
    [4139151348] = "Bảo vệ đầu đơn giản. Nó sẽ không bảo vệ được nhiều, nhưng tốt hơn là không có gì.",
    [4139200664] = " <npc>Thợ săn</npc> Athalan Skree đã nói với bạn về đội cận vệ hoàng gia của cựu Nữ hoàng <lorename>Pikemead</lorename>, được gọi là Hoa Hồng Máu.\nMột nhóm nhỏ đã nổi dậy chống lại Lãnh chúa <lorename>Vorgoth</lorename>. Bà ấy không biết chuyện gì đã xảy ra với họ, chỉ biết nơi họ được nhìn thấy lần cuối.\n\nHãy tìm kiếm ở đó những dấu vết về cuộc nổi dậy của họ.",
    [4139334495] = "Tủ Trưng Bày Hành Lang Khô Cốt (1 Khe Lớn)",
    [4139395041] = "Tất cả Thuộc tính...",
    [4139484562] = "Gửi:",
    [4139584401] = "Đến Vị trí Được cho là của Rochelle",
    [4139748784] = "Tất cả mọi người",
    [4140025191] = "Chế tạo Khối Xây dựng",
    [4140083404] = "Rèn Vũ khí hoặc Giáp",
    [4140787128] = "À, không khí trong lành tràn ngập lồng ngực mệt mỏi của ta... Ta chào ngươi, người bạn mới. Ta là người lái đò. Kẻ canh giữ linh hồn, người dẫn đường trong đêm. Thật may mắn cho ngươi, kẻ vô định. Ta sẽ soi sáng con đường của ngươi.",
    [4141106756] = "Tường Rào Gỗ VII",
    [4141144710] = "Một cây đũa phép nguyên thủy nói về sự thống trị trước đây của Drak. Khi Drak'Dal bị đẩy lùi về quần đảo sau khi tấn công loài người, kỹ nghệ của chúng đã suy thoái đáng kể, do đó mất đi khả năng tái tạo các thiết kế như thế này.\n\n<b>Tăng cường:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên tới phần trăm <i>tăng cường</i>.\n\n<b>Đa mục tiêu:</b> \nBắn nhiều loạt đạn nhưng với sát thương giảm.",
    [4141638976] = "Đánh bại Rồng.",
    [4142140054] = "Tất cả sát thương <b>Sương độc</b> tăng thêm <b>10%</b>.",
    [4142266586] = "Quả Ngọc Giá Nướng",
    [4142360482] = "Ốc đảo",
    [4143062140] = "Nhạc cụ",
    [4143698817] = "Chiêu Mộ Dân Làng Hạnh Phúc Và Nâng Cấp Ngọn Lửa",
    [4143820212] = "Những sắc xanh trầm giúp bạn hòa mình vào thiên nhiên, gần như vô hình khi bạn đuổi theo những chú ếch nhỏ trong cỏ.\n\nBảng màu này có thể được chế tạo bằng vật liệu từ Bồn Nước Veil.",
    [4144000481] = "Bình",
    [4144396179] = "Ôi, trái tim ta đau khổ vì thiếu vắng những điều ngọt ngào trong cuộc sống! Con có thể giúp ta được không, làm ơn đi?",
    [4144871115] = "Cung",
    [4145584927] = "Được tạo ra để tóm và xé con mồi, những móng vuốt này vẫn sắc bén như ngày nào.",
    [4145951539] = "Tăng sát thương lên Vukah",
    [4146044350] = "Giả Kim Thuật Đậu Và Nước",
    [4146239606] = "Trượng Gây Bão",
    [4146683732] = "Một chú bọ nhỏ, còn gọi là bọ cuốn chiếu. Nó có thể được tìm thấy ở Đỉnh Albaneve và dùng làm mồi câu cá, đặc biệt được ưa chuộng bởi các loại cá hiếm.",
    [4146827375] = "Khe Hình Dạng Công Trình 6",
    [4146994954] = "Búa Xây Dựng",
    [4147391810] = "Nhảy đến Vấn Đề",
    [4147594697] = "Mũ Trùm Thợ Săn Hươu",
    [4148119863] = "Nhạc Sĩ đã kể cho bạn về ban nhạc yêu thích của cô ấy, The Honeydews, và những nhạc cụ quý hiếm của họ. Ban nhạc đã tan rã, nhưng nếu bạn điều tra buổi biểu diễn cuối cùng của họ, bạn có thể tìm thấy manh mối về nơi ở của các thành viên.\n\nĐiều tra địa điểm biểu diễn cuối cùng của ban nhạc để bắt đầu cuộc tìm kiếm nhạc cụ quý hiếm của bạn!",
    [4148147095] = "Người bạn mới của bạn đang vui vẻ đi dạo quanh căn cứ của bạn. Họ sẽ còn hạnh phúc hơn nữa nếu bạn làm một <b>bát ăn cho chó và một chiếc giường cho chó</b> cho họ!\n\nChế tạo và đặt cả hai vật phẩm để tiếp tục!",
    [4148969938] = "Sai phiên bản",
    [4149058033] = "Một loại thuốc giải độc cải tiến sẽ chữa khỏi bệnh ngộ độc khi sử dụng.\n\nCũng áp dụng hiệu ứng tăng cường ngăn người chơi bị ngộ độc.",
    [4149142474] = "Giới hạn Giảm Sát Thương Tăng Thêm từ Giáp Vật Lý",
    [4149264350] = "Được trang trí bằng pha lê và viền vàng, đôi găng tay này cho phép bạn nắm chắc dao găm của mình — lý tưởng cho các đòn tấn công từ phía sau.\n\nBộ giáp này có thể được tìm thấy trong các lăng mộ ở Bồn Nước Veil.",
    [4150080821] = "Kẻ canh giữ ánh sáng trở lại.",
    [4150124379] = "Với đôi giày này, bạn lướt qua lùm cây một cách dễ dàng, hầu như không đổ mồ hôi.",
    [4150551180] = "Đã đến địa điểm",
    [4151233863] = "Chế tạo Cần Câu Cá",
    [4151573555] = "Không thể dịch chuyển nhanh dưới nước.",
    [4151641540] = "Các Tượng Cổ Chứa đựng những câu chuyện về thế giới. Sau khi đọc chúng, bạn sẽ có cái nhìn sâu sắc về vị trí của <b>Các Đền Thờ Lửa ẩn và Rễ Sương độc.</b> \n\nCác Đền Thờ Lửa có thể được thu hoạch để lấy Tinh Lửa.\nTinh Lửa cần thiết để củng cố Ngọn Lửa.\n\nRễ Sương độc phải bị phá hủy để nhận Điểm Kỹ Năng.",
    [4152005973] = "Thang máy bị hỏng. <i>Lại nữa.</i>\nTôi đã bảo người giám sát sửa chữa đúng cách vô số lần. Đây là nơi nó đưa tôi đến. Mắc kẹt trong thang máy, không còn ai khác làm ca.\n\nLần cuối cùng điều này xảy ra, mọi người bị mắc kẹt trong 2 ngày, nhưng chuyến hàng họ mắc kẹt lại chứa đủ thức ăn và một tấm da hổ răng kiếm để ngủ. Có vẻ như tôi không chia sẻ vận may của họ. Tất cả những gì tôi có là một đống sách, giấy da và một chiếc xe ngựa ọp ẹp để nằm.\n\nÍt nhất thì tôi cũng sẽ không phải đợi lâu để được cứu.",
    [4152184226] = "Một sự an ủi ngọt ngào trong những giờ phút mệt mỏi:\n\nNghiền hạt và ngâm chúng trong nước —\nthêm đường, để hương vị đầy đủ và êm dịu\n\nMột <b>Mokka Ngọt Ngào</b> đã được chuẩn bị.",
    [4152539713] = "Bể Phế Liệu I",
    [4152566589] = "Cửa Đá",
    [4152872183] = "Bạn đã tìm thấy một ghi chú mô tả những loài thực vật phát sáng vàng mọc sâu bên trong Hang Sương độc. Ánh sáng của chúng thật quyến rũ, nhưng hang động còn chứa nhiều điều hơn là sự kỳ diệu.\n\nTiếp cận Hang Sương độc để khám phá những gì tác giả đã thấy.",
    [4153002911] = "Một chú Thỏ Hóp đáng yêu. Đôi mắt nó quét môi trường xung quanh một cách điên cuồng khi bạn nhặt nó lên, nhưng nó nhanh chóng bình tĩnh lại.",
    [4153239783] = "Mồi Câu Cá Khôn Ngoan",
    [4153849028] = "Chậu Hoa Trống IV",
    [4154291341] = "Một phần của Giáp Đại Pháp Sư.",
    [4154354290] = "Mía",
    [4154367444] = "Găng Tay Lính Canh Phương Bắc",
    [4154986703] = "Vậy là bạn đã lên đỉnh Tháp Cổ, hả? Tôi biết vài người sẽ cho bất cứ thứ gì để có được cảnh tượng đó. Mặc dù bây giờ... có lẽ có ít sự nhộn nhịp để quan sát hơn trước đây.",
    [4155337792] = "Lỗi dữ liệu lưu. Tạo dữ liệu lưu thất bại.",
    [4155701380] = "Ngón tay ta khao khát chơi những giai điệu mới! Những giai điệu êm dịu trên làn gió bạc! Làm ơn, chúng ta hãy tìm một vài thứ đi!",
    [4156080778] = "Bạn có chắc chắn muốn giải nén %k không?",
    [4156288895] = "Thợ mộc nói rằng chiếc đèn lồng ở <location>Morwenna</location>, một thị trấn mà ông ấy từng sinh sống.\n\nĐi đến <location>Morwenna</location> và tìm kiếm chiếc đèn lồng!",
    [4156302473] = "Dung Môi Giả Kim",
    [4158153568] = "Lò Rèn Của Các Đỉnh Núi",
    [4158377370] = "Các đòn tấn công xuyên thấu gây nhiều sát thương hơn cho bạn.",
    [4158705505] = "Dừng Lại Để Mua Sắm",
    [4159061977] = "Thuốc Mỡ",
    [4159811477] = "Cây Giống Cà Phê",
    [4160111834] = "SP",
    [4160505102] = "<h2>2. Đối tượng của việc bảo vệ dữ liệu</h2>\n\nChính sách bảo mật này áp dụng cho dữ liệu cá nhân. Dữ liệu cá nhân là bất kỳ thông tin nào liên quan đến một cá nhân tự nhiên đã được xác định hoặc có thể được xác định; điều này bao gồm, ví dụ, tên hoặc số định danh.\n",
    [4160588638] = "Sự Lựa Chọn",
    [4161120579] = "Đĩa Pha Lê",
    [4161262831] = "Bình Máu Siêu Cấp",
    [4161293333] = "Mũ Trùm Lông Thú",
    [4161933375] = "Đồng Cỏ Thấp",
    [4162015233] = "Gạch Bùn",
    [4162562300] = "Mộ Ikko",
    [4162596470] = "Lưỡi Hái Tạm Thời",
    [4162737564] = "Bình Năng Lượng Tối Thượng",
    [4163166633] = "Đó là một chiếc áo khoác màu xanh lam được xếp lớp tinh xảo với viền lông trắng. Vải chần và da cung cấp sự bảo vệ tốt hơn trong cận chiến. Phần vỏ vàng gần trái tim mang một viên đá quý cắt giác và giống như một con mắt màu xanh hoa ngô, tìm kiếm linh hồn cần giúp đỡ trên chiến trường.",
    [4163427067] = "Cùng Mắt, Khác Mặt",
    [4163700063] = "Ánh Đèn Lồng",
    [4163755681] = "Các Giác Quan Của Ta, Sắc Bén Như Mọi Khi!",
    [4163886443] = "Anton Godwin",
    [4164017683] = "Không có mảnh giáp nào được rèn ngày hôm nay có thể chịu được sự tàn bạo tuyệt đối của cây chùy này.",
    [4164079268] = "Pháo hoa để ăn mừng chiến thắng của bạn!",
    [4164635599] = "Ghi Chú Chuồng Chó",
    [4164723372] = "Bạn đã tìm thấy kho báu chưa?",
    [4164886164] = "Đánh bại kẻ địch bằng <b>Đòn Tấn Công Lén</b> hoặc <b>Đòn Tấn Công Tàn Nhẫn</b> sẽ tạo ra một Quả Cầu HP.\n\nThu thập một Quả Cầu sẽ hồi phục <b>10%</b> tài nguyên tương ứng.",
    [4164892303] = "Mũ Trùm Đêm Khô Cốt",
    [4165677351] = "Một loại rau củ thơm ngon phải được nấu chín trước khi có thể thưởng thức hương vị ngọt ngào và dịu nhẹ của nó.",
    [4166441472] = "Vị ngọt nhẹ của cơm dừa rất hợp với cá phi lê hun khói. Thật tiếc là bạn không thể thêm một chút chanh hoặc tắc!",
    [4166696154] = "Người Khổng Lồ Hollow",
    [4166784414] = "Bùn Chướng Khí",
    [4167030451] = "Thời gian cho đến khi chết đói",
    [4167154192] = "Góc Hàng Rào Nhà Tù",
    [4167241424] = "Áo Giáp Bò Tót Đồng",
    [4167486284] = "Không tốn kém - khôi phục màu gốc",
    [4167671984] = "Kiếm Thép Phạm Thượng",
    [4167888750] = "Thợ Săn đã nói về \"Trò Chơi Vĩ Đại Nhất\" và tiết lộ vị trí của một trại địch trong Vùng Đất Cháy. Nó sẽ là một thử thách tốt!",
    [4168007925] = "Đừng sợ!",
    [4168277140] = "Bắt Ít Nhất 5 Đom Đóm",
    [4168879588] = "Bạn nghĩ gì về bản nháp của tôi?",
    [4168942112] = "<b>Hồi Ký của Orpheus:</b>\n<i>Từng sinh ra là kẻ lang thang, ta tìm kiếm sự rực rỡ và hạnh phúc\nGiờ ta bị đóng băng trong thời gian, thân xác bị xiềng xích\nQuen với biển bóng tối, sâu trong vực thẳm\nMắt ta đau đớn trong ánh sáng, nên không còn ánh sáng nào có thể tồn tại</i>",
    [4168989464] = "Làm Chủ Các Sảnh Đường Hollow của Vùng Đất Cháy",
    [4169323137] = "Chơi Lựa Chọn",
    [4169536762] = "NVIDIA Reflex",
    [4169537625] = "Đừng bắt tôi nói lại lần nữa - dọn sạch Giếng Tinh Hoa đó.",
    [4169891387] = "Robert Gibson",
    [4169978088] = "Tất cả sát thương <b>Đâm Lén</b> tăng thêm <b>30%</b>.",
    [4170043202] = "Thế giới người sống lại gọi ta. Ta là một thợ săn - ta có thể giúp ngươi sinh tồn. Đừng lãng phí thời gian của chúng ta.",
    [4170062951] = "Những cư dân của <location>Pháo Đài Quạ</location> đã trốn thoát. Họ đã chiến đấu qua vô số Vukah để thoát ra, dẫn đầu bởi nữ thần mới của họ. Họ dường như đã di chuyển đến <location><lorename>Hang Lupa</lorename></location>.\n\nCó lẽ <craftingstation>Trạm Da Thuộc</craftingstation> có thể thu được ở đó.",
    [4170488007] = "Một tách cà phê mới pha. Hương vị đậm đà, mạnh mẽ và hơi chua. Còn cách nào tốt hơn để bắt đầu ngày mới?",
    [4170581914] = "Chết tiệt! Cơn gió đêm qua đã làm tan hoang nhà thờ của chúng ta - hoặc bất cứ thứ gì còn sót lại. Everett đã đúng. Lẽ ra chúng ta nên gia cố mái nhà bằng <b>những khối xây dựng đó.</b> Ông ta cũng sẽ thích điều đó! Bây giờ tôi phải vá những lỗ hổng, nhưng tôi không thể nhớ mình đã đặt <b>những khối đó</b> ở đâu lần cuối... Tôi nghĩ tôi đã thấy chúng gần nhà thờ, nhưng tôi không thể tìm thấy chúng ở đâu cả! Mắt tôi có mờ đi vì tuổi tác không?",
    [4170630197] = "Ma Thuật Vĩnh Cửu",
    [4171085564] = "Đó là cái gì...? Một loại bệnh dịch nào đó đang ăn mòn từng thớ thịt. Lớp da sần sùi và lỗ chỗ... đã biến đổi rồi. Cuối cùng, Sương độc sẽ bao trùm tất cả. <i>Động vật, chiến binh, vua chúa...</i> Tất cả xương cốt của chúng ta đều sẽ nứt vỡ như nhau... Đây. <b>Ta sẽ chia sẻ lãnh địa săn bắn</b> của mình với ngươi. Ta sẽ đánh dấu nó trong Nhật Ký của ngươi. Hãy đi theo dấu chân ta, và giải thoát cho họ thay ta, Hỡi Hỏa Nhi.",
    [4171754192] = "Vách Ngăn Phòng \"Hoa\"",
    [4172022912] = "Một lưỡi kiếm được chế tác tinh xảo, cân bằng và sắc bén. Cắt xuyên kẻ địch như tiếng than khóc xé toạc màn đêm. Nó mang dấu ấn của một <b>thợ rèn</b> lừng danh từ <location><lorename>Pikemead</lorename>'s Reach</location>.",
    [4172153011] = "Nala",
    [4172214840] = "Không có vật phẩm phù hợp.",
    [4172273197] = "Mời",
    [4172309152] = "Nơi trú ẩn",
    [4172604163] = "Tìm kiếm các nhạc cụ sử thi trong Trái Tim Đại Dương",
    [4172619011] = "Ngọc Dòng Chảy",
    [4173236774] = "Bàn thờ Ngọn lửa và Cải thiện Móng",
    [4173394781] = "Chiếu Chỉ Hoàng Gia",
    [4173469274] = "Một Ngôi Nhà Cho Tương Lai",
    [4173589953] = "Được Băng Giá Che Chở",
    [4174455920] = "Điều tra Vách Đá Gần <location>Pháo Đài Kelvin</location>",
    [4174614553] = "Tiếp Cận Ngọn Lửa Đầu Tiên",
    [4174628738] = "Tiền xử lý",
    [4174989322] = "Thời gian hồi sinh",
    [4175699756] = "Hàng Rào Cọc Gỗ Cao II",
    [4175921473] = "Bình minh và Hoàng hôn",
    [4176139816] = "Không vũ trang",
    [4176365975] = "Rơi ra từ kẻ địch ở Bồn Địa Nước Lạ",
    [4176412677] = "Cung Cấu Tạo Phức Hợp",
    [4176432398] = "Sử dụng Bình Tăng Sức Bền Thợ Lặn",
    [4177196171] = "Khối Bạc",
    [4178017642] = "Trọng Kiếm Tinh Xảo",
    [4178058290] = "Một luống cày sẽ cho ra Lúa Mì.",
    [4178290966] = "Đến Cromville",
    [4178736887] = "Con mắt duy nhất của nó vẫn đảo quanh vô định trong hốc mắt trước khi bị chặt đầu. Cuối cùng, nó cũng trào ra ngoài.",
    [4178969233] = "Cúp Danh Năng Dọn Dẹp Mẫu Hệ Sắt",
    [4179487215] = "Trước mặt chúng ta là Bồn Địa Nước Lạ... một cõi đất mọc lên từ một hạt giống độc địa. Tán lá ở đây vươn xa và rộng, nhưng rễ của nó đã xé toạc những vết sẹo của quá khứ. Một thế lực cổ xưa đã đến để trả thù, và để nhuốm lưỡi kiếm cùng lưỡi môi của chúng một lần nữa bằng máu.",
    [4180171148] = "Lỗi: %k",
    [4180489388] = "Trở lại Thợ Mộc",
    [4180644589] = "Quần Pháp Sư",
    [4181091321] = "Bất cứ thứ gì cũng có thể được thuần hóa với đủ sự kiên nhẫn. Dùng để sản xuất mật ong và sáp.",
    [4181150471] = "Đánh bại Kẻ Đánh Lộn Vukah",
    [4181157544] = "Trại Nghiên Cứu",
    [4181264754] = "Cúp Danh Năng Rồng Ma Trác Sa Ngã Bằng Đồng",
    [4181517759] = "Scavenger",
    [4181543268] = "Mẹ tôi từng kể rằng thuyền trưởng già luôn có một câu chuyện để kể... với một cái giá. \nĐêm qua, tôi lững thững bước dọc bờ biển, kiệt sức vì công việc. Khi tôi dạo bước bên bờ nước, tôi ngửi thấy một mùi hương trong gió — và khi ngẩng đầu lên, tôi thấy mình đang đứng ngay bên ngoài cửa quán của Lão Muối.\n\nTôi nhớ lời mẹ dặn, và bị cuốn hút bởi lời hứa về bia và niềm vui của quán rượu, tôi bước vào. Lão thủy thủ già đang lau một chiếc ly khi tôi bước vào. Tôi nói với ông ta rằng tôi hết tiền, nhưng tôi đã ném cho ông ta một viên ngọc trai từ Orville. Ông ta đã chuẩn bị ngay một cốc bia và một câu chuyện.\n\nVới giọng nói thì thầm, ông ta hồi tưởng về tuần lễ ông ta đã trải qua trong cái hàm của một con rồng biển mắc cạn khi bị mắc kẹt ở nơi xa xôi, giọng ông ta thô ráp như làn nước bên ngoài cửa sổ. Ông ta nói ông ta đã ẩn mình giữa những chiếc răng ngọc trai và ngủ dưới lưỡi của nó, dựng một đống lửa trên hộp sọ của nó để ra hiệu cho người cứu hộ.\n\nRồi, ông ta đột ngột dừng lại. Tôi hỏi ông ta câu chuyện kết thúc thế nào, và ông ta lặng lẽ đưa tay ra đòi thêm tiền. Tôi sẽ sớm quay lại để nghe phần còn lại!",
    [4182077979] = "Chỉ Hỏi Khi Bạn Có Thể Chấp Nhận Câu Trả Lời",
    [4182099228] = "Đá",
    [4182609636] = "Lò Nướng",
    [4183062685] = "Tôi thông cảm với sự e dè của Marsha. Thật sự, tôi có. Bản chất của cô ấy là cẩn trọng, cô ấy là một \"Thỏ Nhảy\" trong tim — luôn chỉ cách một hơi thở là sẽ nhảy dựng lên, lao đi tìm sự an toàn và thoải mái.\n\nChà, về động vật, tôi giống một con Kền kền Cánh Trắng hơn... <i>Tôi bị ràng buộc với bầu trời!</i> Đó là định mệnh của tôi để lượn trên những thung lũng băng giá này!\n\nLàm sao Marsha có thể <i>không</i> cảm thấy tò mò về những dòng chảy phía trên bên ngoài cabin của chúng ta? Về địa điểm hạ cánh ngay bên kia những cơn gió?\nTôi tự hỏi chúng sẽ đưa tôi lên cao đến mức nào? <i>Có lẽ đủ xa để đến được bộ xương khổng lồ bên sườn núi?</i> ...Nếu tôi phạm sai lầm, cú ngã sẽ dốc đến mức nào?\n\nThan ôi, suy ngẫm về nó cũng vô ích. Tôi không muốn làm tan trái tim của chú thỏ tuyết nhỏ bé của mình. Hoặc xương cốt của tôi.\n",
    [4183162980] = "Làm Chủ Tháp Cổ Đại Blackmire",
    [4184053364] = "Trốn thoát!",
    [4184089473] = "Đài Lửa Đá Nhỏ",
    [4184332008] = "Găng Tay Vệ Binh",
    [4184335223] = "Tìm thấy trong Sương độc Kindlewastes",
    [4184669074] = "Chúng ta không thể vào",
    [4185529738] = "<location>Lone Thistle</location>",
    [4185634236] = "Ngay cả khi đã chết, sự hỗn loạn xoáy tròn bên trong cái hàm há hốc vẫn khiến người ta mê mẩn. Đừng đến quá gần.\n\nThu thập nhiều Đầu Fell Monstrosity để chế tạo Tượng Đồng.",
    [4185891318] = "Một chất dính và dễ cháy. Cẩn thận khi xử lý!",
    [4186364785] = "Một chiếc mũ bảo vệ xương sọ nhạy cảm của bạn khỏi bị tổn thương khi lao vào trận chiến.",
    [4186415322] = "Nhật ký Cảng — Tàu Bỏ Neo!!",
    [4186470379] = "Ngươi đã kiếm được xu nào chưa? Ta biết chủ nghĩa tư bản là xấu xa, nhưng ta không thấy có hại gì khi mang nó về nếu nó mang lại lợi ích cho riêng ta.",
    [4186962295] = "Hugo giải thích rằng các nhạc cụ sử thi có thể thuộc về các hoàng gia đã chôn cất. Ông ta không biết nhạc cụ cuối cùng ở đâu, nhưng gợi ý hỏi Nghệ Sĩ Valory, còn được gọi là \"người hát rong của các vị vua.\"\n\nNói chuyện với Nghệ Sĩ về những gì bạn tìm thấy và hỏi bà ấy về nhạc cụ sử thi cuối cùng!",
    [4187007183] = "Đạn phép thuật không giới hạn liên tục truyền sức mạnh sét đánh. Nó làm kẻ địch bị sốc bằng cách nhảy giữa chúng và gây <b>sát thương SP.</b>\n\nSát thương SP lấp đầy <b>thanh choáng</b> của kẻ địch.\n\n<b>Phép thuật Kênh:</b> Giữ nút để kênh <b>theo thời gian.</b> Trang bị phép thuật và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>\n\n<b>Phép thuật Vĩnh cửu:</b> <b>Không cạn kiệt.</b> Trang bị phép thuật vĩnh cửu và sử dụng <b>MP</b> để niệm nó bằng <b>gậy phép.</b>",
    [4187273034] = "Một phần của Giáp Vệ Binh.",
    [4187597224] = "Tăng chỉ số Nhanh nhẹn của bạn lên 1.\n\nTăng sát thương Cung và Dao găm thêm 5% cho mỗi Điểm Chỉ số.",
    [4187613258] = "Này! Ngươi giúp mọi người, đúng không? Miễn phí, phải không? Để được biết đến? Ta hỏi vì ta cần giúp đỡ việc kinh doanh của gia đình! Chúng ta chuyên vận chuyển hàng hóa, nhưng chúng ta gặp một số vấn đề về vận chuyển, nên tất cả các gói hàng đều bị mất. Bây giờ những chiếc mũ chúng ta đang vận chuyển đã bị phân tán khắp nơi! Ta không thể để chuyện này lộ ra — đó là tai tiếng, ngay cả trong ngày tận thế. Nếu ngươi thu hồi những chiếc mũ, ngươi có thể giữ chúng. Đồng ý chứ?",
    [4187833821] = "Thời gian trong Sương độc",
    [4187926657] = "Bình Năng Lượng Lớn +",
    [4187931066] = "<location>Raven's Keep</location>",
    [4188007199] = "Thu hồi <keyitem>Lò Nung</keyitem>",
    [4188286197] = "Thức ăn để thu hút và thuần hóa dê. Nó có thể được cho cả Dê Thông Thường và Dê Xù.\n\nĐể thuần hóa một con vật, hãy tiếp cận nó cẩn thận trong khi lén lút. Ném thức ăn mồi nhử gần con vật để thu hút sự chú ý của nó. Vuốt ve con vật khi nó đang ăn, và lặp lại quá trình cho đến khi nó trở nên hiền lành. Khi đã thuần hóa, con vật có thể được nhặt lên.",
    [4188525107] = "HP tối đa",
    [4188831663] = "Cuốn <craftingstation>Sổ Tay Thực Vật và Cây Con</craftingstation> đã được tặng cho một \"bà mẹ\" ở <location>Surat's Rest</location>. Bà mẹ phải bị đánh bại để <craftingstation>Sổ Tay Thực Vật và Cây Con</craftingstation> có thể được trả lại cho <npc>Người Làm Vườn</npc>.",
    [4188906063] = "Đinh làm từ Mảnh Kim Loại. Vật sắc nhọn có thể dùng làm công cụ hoặc để cải thiện vũ khí.",
    [4188970509] = "Bộ giáp của người lính hoàng gia này tượng trưng cho lòng hiệp sĩ, vinh quang và sự dũng cảm.",
    [4189003425] = "Máng Ăn Tê Tê Cát",
    [4189194559] = "Đạt cấp 20.",
    [4189423009] = "Quần Học Giả Thiên Giới",
    [4189642632] = "Lựa chọn bài hát",
    [4189760225] = "Bộ Trang Phục Học Giả Thiên Giới Mỹ Lệ",
    [4190048228] = "Găng Tay Giáo Sĩ Sinh Ra Từ Sóng",
    [4190284913] = "Cúp Danh Năng Khổng Lồ Khô Cốt Bằng Đồng",
    [4190304107] = "Hai lệnh ràng buộc có thể chia sẻ cùng một phím hoặc nút bằng cách sử dụng một trong các cặp sau:",
    [4190596505] = "Sửa chữa Trang bị",
    [4190903899] = "Mũi tên Đặc biệt",
    [4191020304] = "Máy chủ đầy hoặc không khả dụng.",
    [4191783154] = "Giàn Phơi",
    [4192213909] = "Cúp Danh Năng Mẫu Hệ Dọn Dẹp",
    [4192630409] = "Một cây rìu được rèn trong ánh sáng thuần khiết. Ít người đã chứng kiến vinh quang của nó, và những người đã thấy đều bị chói mắt trong một khoảnh khắc.",
    [4192671611] = "Gậy Tâm Linh",
    [4192768905] = "Chọn hai thuộc tính từ danh sách. Chúng sẽ được tăng thêm $$arg0$$ cấp mỗi loại.",
    [4192992064] = "Sát thương Gậy Phép",
    [4193355988] = "Đừng bao giờ để than hồng lụi tàn.",
    [4193367922] = "Rương Bạc",
    [4193434764] = "Cơ hội xuất hiện Quả cầu HP",
    [4193461567] = "Nhẫn Sinh Lực",
    [4194470333] = "Đài Lửa Đá Vừa",
    [4194525343] = "Dao Găm Nhỏ Gọn",
    [4195282717] = "Vẻ đẹp phai tàn khỏi cõi này. Chúng ta phải mang nó trở lại!",
    [4195456779] = "Bạn có thể chế tạo trang bị mới tại <b><npc>Thợ Rèn</npc></b>. Chế tạo với ông ta để tạo ra <b>Kiếm Rác, Chùy Gai hoặc bất kỳ bộ phận giáp nào</b>.\n \nChế tạo vũ khí yêu cầu <b>Mảnh Kim Loại</b>, có thể tìm thấy trong thế giới hoặc rơi ra từ Scavenger. <b>Một điểm thu thập Mảnh Kim Loại đã được đánh dấu trên bản đồ.</b>\n\nNhiệm vụ này cũng sẽ hoàn thành nếu bạn đánh bại Giếng Thuốc Tiên.",
    [4195561418] = "Mỗi kẻ địch bị trúng <b>Mũi tên Nổ</b> có <b>20%</b> cơ hội kích hoạt một vụ nổ thứ cấp gây <b>50%</b> sát thương trong một phạm vi nhỏ.",
    [4195574968] = "Kẻ địch",
    [4196463722] = "Cánh Tay Chiến Binh",
    [4196465023] = "Sóng xung kích",
    [4197071164] = "Chu kỳ khóa mục tiêu (trái)",
    [4197287497] = "Một người phụ nữ dũng cảm",
    [4197685985] = "Mồi Câu Cá Đơn Giản",
    [4197903000] = "Một chiếc móng vuốt khổng lồ, sắc như dao cạo.\n\n<b>Nguyên liệu chế tạo:</b> Chủ yếu dùng để chế tạo giáp.\n<b>Nguồn gốc</b>: Rơi ra từ Kê khổng lồ bị Sương độc bao phủ, ban đầu tìm thấy ở Kindlewastes.",
    [4198237128] = "Ngươi đã tìm thấy cảm hứng mới cho màu mắt chưa? Đừng nghĩ quá nhiều về cách nó hoạt động. Hãy nghĩ về thời trang, darling!",
    [4198357503] = "Thằng nhóc đó lại trêu chọc ta nữa rồi! Ta đã bảo Phil mang một ít Khối Đá Thường để sửa cầu... đúng là nó không vui, nhưng nó còn trẻ và nhanh nhẹn! Mang mấy thứ đó với nó đâu có khó! Vậy mà nó chỉ quăng xuống rồi chạy mất!! “Tự ông tìm lấy nhé, Pop. Đừng gãy lưng đấy!” Đúng là một thằng gây rối... rốt cuộc đống đá đâu rồi?",
    [4198677342] = "Ôi nhìn kìa! Một bảng màu toàn xám! Nó khiến ta nhớ đến khối đá granite tuyệt đẹp ta từng có khi còn nhỏ!",
    [4198718359] = "Một Giấc Ngủ Bình Yên",
    [4199300301] = "Giày Thợ Săn",
    [4199681010] = "Anh em nhà Conway đã băng qua Umber Hollow, nơi họ bị tấn công. Có vẻ như Thợ Rèn được định nhận một món đồ, nhưng nó đã bị bỏ lại tại thị trấn Jasper Isles khi nhà Conway tháo chạy. Ghi chú mà Thợ Rèn nhận được dường như là giả mạo, bởi bản gốc đã thất lạc cùng với món quà.",
    [4199926268] = "Giữ để gây ST Sương độc liên tục theo chùm tia có phạm vi lên đến 20 mét.\n\n<b>Phép Sương độc</b>: Phép này tạo ra một hiệu ứng làm giảm Thời gian của bạn trong Sương độc.\n\n<b>Phép Dẫn truyền:</b> Giữ nút để dẫn truyền <b>theo thời gian.</b> Trang bị phép và sử dụng <b>MP</b> để niệm phép bằng <b>Gậy phép.</b>",
    [4199990991] = "Chảy máu được là giết được!",
    [4200247319] = "Khi kẻ địch trong phạm vi 10 mét bị giết bởi vũ khí cận chiến, bạn rơi vào trạng thái Cuồng Huyết.\n\nCuồng Huyết\nTăng sát thương vũ khí cận chiến thêm 20% trong 10 giây.",
    [4200463505] = "Một vũ khí tinh xảo được trang trí bằng những chiếc sừng quý hiếm, có lẽ là chiến lợi phẩm từ những cuộc săn. Người Drak từng hiến tế cho các vị thần tại Ark Morgo để dẫn truyền sức mạnh nguyên tố. Vì vậy, chiếc rìu của tù trưởng này được ban cho sức mạnh sét để hỗ trợ hành trình của họ.",
    [4200493163] = "Thiết bị chứa thức ăn cho Yak.\n\nSẽ tự động cho thú ăn khi được nạp đúng loại thức ăn.",
    [4201365888] = "Thế giới vẫn còn thở, và ta cũng vậy! Người ta gọi ta là Valory của Dây Bạc, Khúc Ca Gió Bắc, Thi Sĩ của Vua, Tiếng Nói Nhân Dân, và Nhà Thám Hiểm Vĩ Đại! Nhưng cứ gọi ta là “Val” là đủ. Hay ta nên thêm “Kẻ Tái Sinh” vào danh hiệu nhỉ...?",
    [4201466932] = "Quần Rách Rưới",
    [4201682464] = "Chỉ Điểm",
    [4201718264] = "Mỗi Lò Rèn Ngọc yêu cầu tài nguyên riêng để nâng cấp và gắn ngọc.\nCấp độ ngọc bị giới hạn theo từng lò. Hãy tìm những lò ở khu vực nguy hiểm hơn để mở khóa cấp cao.",
    [4201759490] = "Những nhà thám hiểm mang đôi giày đáng sợ này không nên bị xem thường.",
    [4202043751] = "Khối Tường Đá Lâu Đài",
    [4202365559] = "Ngươi đang đói.",
    [4203454775] = "Quần Người Chữa Lành",
    [4203656851] = "Cây Licuala",
    [4203882623] = "Chế tạo tại Cối Xay Tay",
    [4204260804] = "Tuyến Amoniac",
    [4204338149] = "Đất màu mỡ giúp tăng tốc độ sinh trưởng của cây trồng.\n\nThoát nước\nVật liệu này thoát một lượng nước nhỏ khi bị tràn.",
    [4204392973] = "Sử Dụng Tà Lượn",
    [4205247967] = "Đặt",
    [4205566806] = "Bộ trang phục lộng lẫy, gần như tỏa sáng hơn cả Tinh thần người mặc.",
    [4205984308] = "%k tuyên bố chiến thắng",
    [4206112908] = "Yêu Thích",
    [4206539823] = "Nạp lại tại hồ và giếng",
    [4206637990] = "Cung Tết Âm Lịch",
    [4206719757] = "Công Cụ Đa Năng",
    [4207864085] = "Tâm Trí Giải Thoát",
    [4208204051] = "Hôm qua có một Lữ Khách ghé qua — giúp chúng ta lên kế hoạch xây dựng Giếng Elixir... (đã lược bớt cho gọn nhưng vẫn giữ văn phong RPG)\nTa nhận ra vết sẹo ngay — sâu và kéo dài ngang mặt.\n\nNhưng hôm nay, khi hắn quay lại, vết sẹo đã biến mất. Như chưa từng tồn tại.\nTa không biết nên nghĩ gì. Có lẽ ta không muốn biết.",
    [4208329055] = "Cửa Thép",
    [4208698969] = "Cây Cúc La Mã",
    [4208811543] = "Ta không thể quên “Huyền Thoại Diệt Long”...\n\nCó thật không? Hay tất cả chỉ là dối trá?",
    [4209129706] = "Sinh vật chiếm giữ phép thuật đã khiến pháp sư phải chiến đấu kịch liệt...",
    [4209631631] = "Ngươi đã tìm được bảng màu đó thật tốt. Ta biết vẫn còn những tâm hồn sáng tạo nơi đây.",
    [4209689344] = "Chỉ lấy phần ngọn thôi à?",
    [4209889953] = "Ếch Sương độc",
    [4210097833] = "Một khuôn mặt cau có của một vật tổ trang trí cây đũa phép này, theo dõi mọi hành động của bạn... đôi khi, nó tăng cường phép thuật của bạn. Đôi khi, bạn cảm thấy nó đang chờ đợi sự sụp đổ của bạn.\n\n<b>Tăng cường:</b>\nCây đũa phép này có cơ hội khuếch đại sản lượng sát thương của nó. Các đòn tấn công gây thêm sát thương lên tới phần trăm <i>tăng cường</i>.",
    [4210101806] = "%k đã đánh dấu.",
    [4210104223] = "Dao Găm Tự Chế",
    [4210465820] = "Đi Kindlewastes à? Coi chừng đấy! Dì Elin của ta bị nguyền ở đó...",
    [4210637611] = "Sát Thương Độc",
    [4210747707] = "Khối xây dựng mới có thể đặt bằng Búa Xây Dựng...",
    [4211034760] = "Gel Banshee Sục Khí",
    [4211429209] = "Mũ Giáp Thành Lũy Hoàng Kim",
    [4211646073] = "Ranh giới giữa sống và chết đang mỏng dần...",
    [4212609998] = "Găng Tay Khô Cốt Độc Quyền",
    [4212799338] = "Truyền thuyết kể rằng một con rồng bị hạ bởi một nhát rìu vào đầu...",
    [4214531387] = "Thế Giới Mới Đã Tạo",
    [4215279162] = "Tỷ Lệ Kích Hoạt Khi Chặn",
    [4215583993] = "Ngọn Lửa",
    [4215834561] = "Dư Âm Ikko",
    [4216138975] = "Đôi giày này được thiết kế để lao lên không do dự...",
    [4216996263] = "Chúng tôi đã bị giam giữ ba ngày nay. Yếu ớt, vật lộn không có thức ăn hay nước uống. Đây có thể là lời chứng cuối cùng của tôi. Nhưng lũ Scavenger đang tạo ra những nỗi kinh hoàng mới mà tôi không thể quên được.\n\nNữ hoàng Scavenger béo phì vì tham lam đang biến phòng thí nghiệm tối tăm trong trại này thành của chính chúng bằng cách truyền một lượng lớn Thuốc vào thẳng tim chúng! Những <b>Kẻ Tham ăn</b> này sẽ nhổ độc và ném các lọ Thuốc bị ô nhiễm vào con mồi của chúng - hãy tránh xa chúng bằng mọi giá!\n\nNếu tôi không sống sót ở đây, hãy coi chừng.",
    [4217295453] = "Luôn Bên Nhau",
    [4217375297] = "Đã phát hiện bí mật",
    [4217573171] = "Dùng Bình Linh Hồn Drak",
    [4218576693] = "Ngươi đã tìm lại chiếc trống tay của ta! Tuyệt vời!",
    [4218917261] = "Giày Cai Ngục",
    [4219441619] = "Cùng Một Dòng Máu",
    [4219773144] = "Mũi Tên Đồng Đỏ",
    [4219818589] = "Ferndale",
    [4220070215] = "Ngươi đã tìm thấy ghi chú về xác Cyclops...",
    [4220762914] = "Bột Xương",
    [4220782755] = "+Tối đa (%k)",
    [4220795372] = "Khắc Tinh Đại Bàng",
    [4221246091] = "Tìm, Cho Ăn Và Thuần Hóa Dê",
    [4221400761] = "Tìm Hóa Thạch Cao Nguyên Du Mục",
    [4221474328] = "Cá nhân:%k + Ngọn lửa:%k",
    [4221484704] = "Rượu Đã Thuộc Về Ta!",
    [4221677273] = "Khe Nứt Khai Mỏ",
    [4221777380] = "Phục vụ: ",
    [4221890981] = "Động Vật Chân Bụng",
    [4222027829] = "Phong phú như cỏ ba lá...",
    [4222054828] = "Nông dân Fenrig được giao nhiệm vụ tiêu diệt lũ sói...",
    [4222269617] = "Máy Lọc Nước",
    [4223036886] = "Thoải Mái - Ghế",
    [4223110399] = "Trang bị một <b>cung và chọn đạn</b> từ kho đồ của bạn để tham gia chiến đấu tầm xa. Nhắm vào <b>đầu hoặc điểm yếu của kẻ địch</b> để gây thêm sát thương. Bạn có thể <b>làm nổ các vật phẩm nổ từ xa</b> bằng mũi tên, hoặc ném <b>lựu đạn nổ khi va chạm.</b>\n\nTrang bị gậy phép hoặc đũa phép để giải phóng sức mạnh ma thuật. Đũa phép không yêu cầu đạn dược và có thời gian niệm phép ngắn. <b>Gậy phép cần vật phẩm niệm phép hoặc kênh dẫn</b> làm đạn dược và yêu cầu MP. Phép thuật chỉ có thể được niệm bằng gậy phép.",
    [4223500301] = "Leo Tháp Cổ Ở Revelwood",
    [4224009240] = "Tới địa điểm và tìm tàn tích Vệ Binh Hoàng Gia",
    [4224631799] = "Ta Nghe Thấy Tiếng Nứt",
    [4224939152] = "Một <b>mũi tên đặc biệt</b> tẩm độc, khiến nó càng trở nên chết chóc hơn.\n\n<b>Mũi tên tẩm độc</b>: Wildlife và Quái thú Hoang dã trúng mũi tên này sẽ bị nhiễm độc và nhận 12 sát thương mỗi giây trong 5 giây.",
    [4225125167] = "Bộ não nó đã bị nấm thay thế...",
    [4225396161] = "Phím Tìm Kiếm",
    [4226385060] = "Giúp cây mầm nảy nở an toàn.",
    [4226484301] = "Gỡ cấm",
    [4227066430] = "Động Vật Chân Bụng Đơn Độc",
    [4227306808] = "Sẽ cho thú ăn khi có thức ăn phù hợp.",
    [4227419228] = "Hỗn hợp đất và đá...",
    [4227521953] = "Một linh hồn cô đơn, bị Sương độc đè nén — và được lưỡi kiếm của bạn giải thoát.\n\nThu thập nhiều Đầu Rồng Con Fell để chế tạo Tượng.",
    [4227703206] = "Cúp Danh Năng Thú Sấm Sa Ngã Bằng Đồng",
    [4227817139] = "Có thêm túi để chứa chìa khóa...",
    [4227947201] = "Súng Phun Lửa",
    [4228072220] = "Mầm Tảo",
    [4228260890] = "Chân Nến",
    [4228394268] = "Sát Thương Kẻ Địch",
    [4228593513] = "Bộ Dược Sư",
    [4229240949] = "Thanh Hành Động Ô Tiếp",
    [4229709722] = "Máu Trên Tuyết",
    [4230139961] = "Mỏ Ridgeback",
    [4232000131] = "Hơi Ấm",
    [4232175971] = "Một cây đàn lute chế tác tinh xảo...",
    [4232486675] = "Hiếm",
    [4232642521] = "Bình Triệu Hồi Đầu Lâu Lớn",
    [4233498597] = "Dọn sạch và điều tra Lò Ngọc",
    [4234097765] = "Khi hết HP, MP sẽ thay thế...",
    [4234762334] = "Ngươi có thấy côn trùng bay ban đêm không?",
    [4235198317] = "Thuần Hóa Động Vật",
    [4235245641] = "Đất",
    [4235260009] = "Thợ Cắt Tóc muốn nhớ cách pha màu xanh hoàn hảo...",
    [4235559174] = "Trang trí vàng tạo cảm giác uy quyền...",
    [4235569968] = "Chỉnh sửa",
    [4235693884] = "Kền kền Fell",
    [4235696162] = "Tìm Con Mèo",
    [4235837185] = "Này nhóc, ta có thứ kỳ lạ ở đây. Lại xem thử không?",
    [4235895211] = "Thoải Mái - Thảm",
    [4235907848] = "Ngươi đang cầm cái gì vậy? Một cái sàng khai mỏ à? Theo ta biết, ngươi có thể dùng nó dưới nước để đãi vàng và những thứ tương tự. Sao không thử xem?",
    [4236499881] = "Cuối Cùng Cũng Xứng Đáng",
    [4236505918] = "Sự hoàn hảo đòi hỏi sự tận tâm.",
    [4237232408] = "Đã Tìm Thấy Khiên",
    [4237374503] = "Giật Sét",
    [4237578939] = "Khối Thảm Đỏ",
    [4237874113] = "Một mũi tên Sương độc mạnh hơn, còn chết chóc hơn cả mũi tên trước. Phân tán một đám mây Sương độc khi va chạm.",
    [4238518304] = "Dọn Sạch Giếng Elixir",
    [4238641032] = "Trái tim phai tàn của một sinh vật sa ngã. Tinh chất mạnh mẽ của nó là chìa khóa để chế tạo giáp bền bỉ và phép Chữa thương cường đại.\n\nNguyên Liệu Chế Tạo: Chủ yếu dùng để rèn giáp.\nNguồn: Rơi từ Fell Sporehead, thường thấy tại Kindlewastes.",
    [4238873843] = "Pháo Đài Everfrore",
    [4239782849] = "Khát Khao Lang Thang",
    [4240418848] = "Không thể đặt thêm Bàn Thờ",
    [4240742757] = "Kindlewastes ẩn chứa vô vàn bí mật — nhưng bí ẩn nhất chính là những hóa thạch khổng lồ của sinh vật đã tuyệt chủng từ lâu...\n\n—Loraine Crim",
    [4240902570] = "Hạt cà phê thô này cần được rang và xay trước khi bộc lộ trọn vẹn hương vị!",
    [4241218838] = "Khám Phá Westcott",
    [4241229795] = "Giáp Ngực Hoa Hồng Máu",
    [4241356409] = "Ắt hẳn có một hầm ngầm bị chôn đâu đó tại Mayfair Lot. Hãy đào xuống và chiếm lấy thứ bên dưới!",
    [4241501539] = "Găng Tay Học Giả Thiên Giới",
    [4242057485] = "Thắp Lửa Balefire",
    [4242350947] = "Một cây chùy đáng sợ mang lại tai ương cho mọi kẻ đối đầu.",
    [4243687689] = "Khối Phủ Hệ Sợi Nấm",
