    [4244827606] = "Thoải Mái - Phòng Tắm",
    [4245080589] = "Ánh Sáng Thánh",
    [4245341126] = "125 m × 125 m",
    [4245604386] = "Kỹ Năng",
    [4245687062] = "Thời Gian Ban Đêm",
    [4245750444] = "Sát thương Đũa phép",
    [4245854444] = "Kháng Lửa",
    [4245948502] = "Tỷ Lệ Hút Máu",
    [4246604593] = "Sử dụng Móc Kéo để kéo kẻ địch bay về phía bạn trong chiến đấu.\n\nTiêu hao: 50 SP",
    [4246680604] = "Luôn luôn di chuyển.",
    [4246715687] = "Cúp Danh Năng Rồng Ma Trác Sa Ngã Bằng Sắt",
    [4246879320] = "Cầu Thang",
    [4246905656] = "Cây trồng trong phạm vi căn cứ sẽ cho sản lượng gấp đôi.",
    [4246908523] = "Những Kẻ Săn Tìm Trái Tim Hoang Dã",
    [4247965511] = "Ta nói cho ngươi biết, Will — xâm nhập Ocean's Heart sẽ là sai lầm cuối cùng của ngươi!!...",
    [4248114409] = "Trượng Sậy",
    [4248431799] = "Ngươi đã đánh bại Cyclops Hollow đáng sợ tại Revelwood Hollow Halls...\n\nHãy lấy đầu của nó và chế tạo Máy Ép Ectoplasm.",
    [4248435135] = "Cọc Gỗ Đơn Giản",
    [4248581723] = "Nơi Ẩn Náu",
    [4248709861] = "Về Tân Binh Mới",
    [4249009132] = "Một phần ST Cận chiến nhận vào sẽ phản lại kẻ tấn công",
    [4249277756] = "Quái Nhện",
    [4249547154] = "Thịt cá huyền thoại nướng thơm lừng. Nhắm mắt lại và thưởng thức — ngươi sẽ cảm nhận được đại dương bao la.",
    [4249638198] = "Tạo một bàn thờ Ngọn lửa.",
    [4250172870] = "Gỗ chất lượng cực cao, được chế tác tỉ mỉ.",
    [4250810391] = "Đòn Né Tránh",
    [4251037847] = "Trượng Dẫn Đường",
    [4251125874] = "Quần Lông Huyết",
    [4251579126] = "Giá Treo Vũ Khí Cung",
    [4251635058] = "Những báu vật của thế giới cũ sẽ bị chôn vùi nếu ta không tìm lại!",
    [4251637539] = "Tài nguyên cần thiết để tạo Thỏi Sắt — vật liệu quan trọng cho mọi nhà thám hiểm.",
    [4251987220] = "Sát thương vũ khí 2H tăng 20%.",
    [4252126181] = "Bát Đồng Thiếc",
    [4252274521] = "Giá Treo Khiên Gắn Tường",
    [4252437837] = "Bát thức ăn nhỏ cho mèo.\n\nSẽ cho thú ăn khi có thức ăn phù hợp.",
    [4252962922] = "Nấm Chướng Khí",
    [4255390879] = "Đũa Phép Tử Thần",
    [4256082111] = "Kho Đồ: Kỹ Năng",
    [4256752833] = "Thịt mềm mọng, giúp no bụng và tăng kháng lạnh.",
    [4256956529] = "Tháp Cổ — Blackmire",
    [4257557146] = "Vỏ Bọ Giáp",
    [4257999214] = "Đài Lửa Phòng Ngai Vàng Nhỏ",
    [4258123476] = "Ngươi bắn rất giỏi, Flameborn... nhưng ngươi có đủ lạnh lùng không?",
    [4258249521] = "Ẩn HUD",
    [4259490334] = "Hàng Rào Granite",
    [4259684910] = "Chọn",
    [4260130329] = "Dịch Nhầy",
    [4260628619] = "Chiếc nhẫn ôm lấy ngón tay như hơi lạnh... tăng kháng băng.",
    [4261255102] = "Nhẫn Sinh Lực Siêu Cấp",
    [4261738742] = "Cục Đất Sét",
    [4261814469] = "50%",
    [4261985341] = "Bạn đã tìm thấy một ghi chú chi tiết về trường hợp kỳ lạ của những tia sét đánh liên tiếp trong một trại Drak'Dal gần đó.\n\nTìm trại và điều tra nó!",
    [4262090997] = "Trang Phục",
    [4262377343] = "Tai Ương Bị Lưu Đày",
    [4262720312] = "Cá nướng giòn ngon, tăng HP và thời gian lặn.",
    [4263265751] = "Cụm cầu gai biển kỳ lạ...",
    [4263381453] = "Đòn Tàn Phá",
    [4264139431] = "Giày chắc chắn để chặt gỗ...",
    [4264620953] = "Khối mái granite đẹp mắt.",
    [4264801863] = "Hang Sương độc",
    [4265102355] = "Găng Tay Giao Ước Lửa",
    [4265576492] = "So Sánh Trang Bị",
    [4265665800] = "Hình Khối Nhỏ",
    [4266479011] = "Công Trình Thử Thách",
    [4267076808] = "Hệ Sợi Nấm Axit",
    [4267400072] = "Chỉ có vài cách để trốn tránh một lời hứa mà ngươi không định giữ. Và ít nhất một trong số đó liên quan đến giết chóc.\n\nTinh Xảo:\nSát thương của vũ khí này tăng theo chỉ số nhanh nhẹn. Ngươi có thể tung ra một đòn phản công đặc biệt sau khi đỡ đòn.",
    [4267713086] = "Bộ Phá Pháp",
    [4268376699] = "Chùy Của Vesztah",
    [4268522310] = "Bộ Thợ Săn",
    [4268649646] = "Hoàn Thành",
    [4268774147] = "Quan Sát Xung Quanh",
    [4268842910] = "Dội Ngược",
    [4269137592] = "Chúng ta có thể cải tiến vũ khí yêu thích của ngươi bằng các cường hóa, và tận dụng toàn bộ trang bị mà ngươi đã thu thập. Thấy chưa? Ta cũng có ích mà!",
    [4269721016] = "Bắn một viên đạn gây ST Sương độc.\n\n<b>Nhân đôi Tinh linh:</b>\nPhép thuật độc đáo của chiếc đũa phép mang lại cho nó 30% cơ hội tự động tạo ra một viên đạn bổ sung.\n\n<b>Quá tải:</b>\nChiếc đũa phép này có cơ hội khuếch đại sát thương đầu ra của nó. Các đòn tấn công gây thêm sát thương lên đến phần trăm <i>quá tải</i>.",
    [4269874355] = "Vô Hiệu Hóa",
    [4269931646] = "Nghiên cứu của ta đã dẫn đến một giả thuyết táo bạo: Người Cổ Đại từng có sự liên kết với “ngọc” và dùng chúng để “cường hóa”. Có lẽ Flameborn không phù hợp để cường hóa — nhưng vũ khí của ngươi thì có! Nếu tìm được một Lò Ngọc Cổ Đại... và một nguồn năng lượng thích hợp... chúng ta có thể chiếm lấy sức mạnh của ngọc!",
    [4270144475] = "Mũ Kẻ Phá Phép",
    [4270503544] = "Một Bí Ẩn Mới Hé Mở",
    [4271038874] = "Màu Râu",
    [4271421042] = "Mở Khóa Cửa Và Rương",
    [4271790650] = "Tăng lượng Rune cần để nâng cấp vũ khí.",
    [4271830045] = "Mũ Trùm Sát Thủ",
    [4271910316] = "Cuộn Trái",
    [4272143316] = "Cúp Danh Năng Quái Vật Mắt Một Vàng",
    [4272236389] = "Chưa Chọn Vũ Khí",
    [4272424831] = "Sợi sậy giấy này có thể dùng trong nhiều công thức chế tạo như sợi thực vật khác.",
    [4272551697] = "Quần Chiến Binh Rắn",
    [4273495742] = "Đầu Hydrak'Dal bị chặt, đội vương miện uy nghi. Ngay cả lúc này, nó vẫn toát ra quyền uy và ý chí thống trị.\n\nThu thập nhiều đầu Hydrak'Dal để chế tạo chiến tích.",
    [4274062885] = "Súp Ectoplasm Thượng Hạng",
    [4274597204] = "Mật Ong",
    [4275192466] = "Ký Ức Phai Mờ",
    [4275430901] = "Ma-nơ-canh A",
    [4275511410] = "Sét Không Đánh Hai Lần",
    [4275519607] = "Chim Đuôi Đỏ Mỏ Tròn",
    [4276064218] = "Một chiếc nhẫn với những hình khắc màu xanh lam phát sáng đọc rằng:\n\n\"Mong Sương độc không bao giờ đánh gục bạn - Balthazar\"",
    [4276312388] = "Gương Tiệm Salon Lớn",
    [4276791463] = "Cảm ơn ngươi đã cho ta mượn tầng hầm, Henry...\n\nHãy hứa với ta rằng ngươi sẽ quay trở lại. Đây là một giao kèo với bóng tối!",
    [4276865163] = "Aster, đồ nhát gan! Nếu muốn chứng tỏ bản thân với Myrtle, hãy dẫn cô ấy ra mép nông trại...",
    [4276939392] = "Hộp Sọ Quái Vật Một Mắt",
    [4277545785] = "Những Ngôi Nhà Cũ Mục Nát",
    [4277782927] = "Ngọn Lửa đã tiết lộ vị trí của một phép vĩnh cửu mạnh mẽ bị chôn gần đây...\n\nVị trí đã được đánh dấu trên bản đồ.",
    [4277802901] = "Chiếc quần nâu có phần đầu gối được gia cố chắc chắn.",
    [4278291052] = "Cầu Lửa III",
    [4278500563] = "Valory của Dây Bạc",
    [4278973745] = "Khung Cửa",
    [4279102532] = "Chế Tạo Móc Kéo Nâng Cấp",
    [4279203616] = "Ngươi đã đến Nhà Thợ Mỏ. Giờ có thể tìm sách cổ hoặc vật phẩm cảm hứng.",
    [4279252497] = "Băng gạc đơn giản.\n\nDùng để Chữa thương khi bị thương.",
    [4279553113] = "Chung",
    [4279794509] = "Khối Đá Cắt Thô",
    [4279965879] = "Nền Móng",
    [4280330595] = "Trại Săn Bắn",
    [4280498436] = "Một cây cung mạnh mẽ với hai đầu hình miệng rắn...\nHãy để mũi tên của ngươi tấn công như rắn độc rình mồi!",
    [4280689063] = "Nghỉ Ngơi Của Thuyền Trưởng",
    [4281463680] = "Kaori Conway yêu cầu ngươi tìm một bộ trang phục mới...\n\nHãy theo dấu trên bản đồ.",
    [4281909523] = "Thiết kế đôi giày này mô phỏng da Wyvern...",
    [4282025413] = "Trà gừng này mang hương vị của HP hoàn hảo.",
    [4282246907] = "Tiếp",
    [4282876662] = "Ngươi đã tiêu diệt Sương độc Root và dọn sạch Giếng Elixir... nhưng như vậy chưa đủ để trở thành anh hùng!",
    [4282997781] = "Có nhiều bản nhạc rải rác tại Albaneve Summits...",
    [4283647694] = "Khởi Đầu Của Học Giả",
    [4283835502] = "Thợ Rèn nói rằng leo lên Tháp Cổ sẽ mở ra thêm vùng đất...",
    [4285963513] = "Khi bị bao vây bởi 3 kẻ địch trở lên, một kẻ ngẫu nhiên sẽ bị đẩy lùi mỗi 3 giây.",
    [4286477352] = "Tháng này, chúng ta mất nhiều tàu hơn bao giờ hết...\n\nNhững đám mây giông đang che giấu điều gì đó...",
    [4286588614] = "Đũa Phép Dòng Máu",
    [4286718377] = "Ván gỗ được cắt từ khúc gỗ, rất hữu ích trong xây dựng.",
    [4286913798] = "Vẫn còn nhiều nông trại bí ngô...",
    [4287205883] = "Kích Hoạt Đang Hồi",
    [4287470574] = "Chiếc rìu này sinh ra để tiêu diệt thú hoang.",
    [4287583656] = "Sa Mạc Ngủ",
    [4287602036] = "Khối Đường Đá Rubble Granite",
    [4287661644] = "Chúng ta đáng lẽ phải đón sứ giả từ hai đêm trước...\n\nNếu giám sát đọc được điều này, ta sẽ mất đầu mất!",
    [4287775951] = "Bộ Chiến Binh",
    [4288392554] = "Đuốc Treo Tường Hầm Mộ Bằng Sắt",
    [4288756414] = "Cổ Vật Sảnh Hollow Nhỏ",
    [4288793205] = "Rìu Tay",
    [4288983007] = "Tàn tích Scavenger",
    [4289834835] = "Quan Tài Lớn",
    [4290669449] = "Ấm Đun",
    [4290799491] = "Đọc Bia Đá Cổ",
