local function apply_translation()
    local res_list = game.assets.get_resources_by_type("keen::LocaTagCollectionResource")
    if #res_list == 0 then return end

    local localization = res_list[1].data
    local count = 0

    for _, loc in ipairs(localization.languages) do
        if loc.language == "En_Us" then
            local original_guid = game.guid.from_content_hash(loc.dataHash)
            local content = game.assets.get_content(original_guid)
            
            if content then
                local data = content:read_data():read_resource("keen::LocaTagCollectionResourceData")
                
                for _, tag in ipairs(data.tags) do
                    if vyyy_data[tag.id.value] then
                        tag.text = vyyy_data[tag.id.value]
                        count = count + 1
                    end
                end

                local new_buffer = buffer.create()
                new_buffer:write_resource("keen::LocaTagCollectionResourceData", data)
                loc.dataHash = game.guid.to_content_hash(game.assets.create_content(new_buffer).guid)
            end
        end
    end
    print("EML_INFO: Xong. So line: " .. count)
end

local custom_font_paths = {
    "src/font.ttf",
    "mods/vyyy_translate/src/font.ttf",
    "D:/Games/Enshrouded/mods/vyyy_translate/src/font.ttf",
    "D:\\Games\\Enshrouded\\mods\\vyyy_translate\\src\\font.ttf",
}

local vietnamese_font_ranges = {
    { firstRune = 0x0020, lastRune = 0x00FF },
    { firstRune = 0x0100, lastRune = 0x017F },
    { firstRune = 0x0180, lastRune = 0x024F },
    { firstRune = 0x1E00, lastRune = 0x1EFF },
    { firstRune = 0x2000, lastRune = 0x206F },
}

local function load_custom_font_content_hash()
    for _, path in ipairs(custom_font_paths) do
        if io.exists(path) and io.is_file(path) then
            local ok, font_buffer = pcall(io.read, path)
            if ok and font_buffer then
                local content = game.assets.create_content(font_buffer)
                return game.guid.to_content_hash(content.guid), path
            end
        end
    end

    return nil, nil
end

local function has_range(ranges, first_rune, last_rune)
    for _, range in ipairs(ranges) do
        if range.firstRune <= first_rune and range.lastRune >= last_rune then
            return true
        end
    end

    return false
end

local function ensure_vietnamese_ranges(ranges)
    for _, wanted in ipairs(vietnamese_font_ranges) do
        if not has_range(ranges, wanted.firstRune, wanted.lastRune) then
            table.insert(ranges, {
                firstRune = wanted.firstRune,
                lastRune = wanted.lastRune,
            })
        end
    end
end

local function apply_custom_font()
    local custom_font_hash, loaded_path = load_custom_font_content_hash()
    if not custom_font_hash then
        print("EML_ERROR: Khong tim thay font.ttf de patch")
        return
    end

    local font_resources = game.assets.get_resources_by_type("keen::UiFontResource")
    local patched_resources = 0
    local patched_fonts = 0
    local patched_glyph_sets = 0

    for _, resource in ipairs(font_resources) do
        local data = resource.data
        local resource_changed = false

        for _, font in ipairs(data.fonts) do
            font.fontFileHash = custom_font_hash
            patched_fonts = patched_fonts + 1
            resource_changed = true
        end

        for _, language_group in ipairs(data.languageGroups) do
            for _, glyph_set in ipairs(language_group.glyphSets) do
                ensure_vietnamese_ranges(glyph_set.ranges)
                patched_glyph_sets = patched_glyph_sets + 1
                resource_changed = true
            end
        end

        if resource_changed then
            patched_resources = patched_resources + 1
        end
    end

    print("EML_INFO: Font patched from: " .. loaded_path)
    print("EML_INFO: UiFont patched resources: " .. patched_resources .. ", fonts: " .. patched_fonts .. ", glyphSets: " .. patched_glyph_sets)
end

apply_translation()
apply_custom_font()